INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('alexander', 'P-alexander', '亚历山大大帝', 'strategy', '亚历山大大帝 · 征服与统御思维框架卡', '古希腊（前356—前323）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '决战定乾坤 · 亲冲锋陷阵', '/advisors/portraits/alexander.png', '/advisors/portraits/alexander.png', 5, 0, '{"schema_version":1,"card_id":"alexander","name":"亚历山大大帝","title":"亚历山大大帝 · 征服与统御思维框架卡","era":"古希腊（前356—前323）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"决战定乾坤","definition":"不打消耗，主动寻求与敌主力的决定性会战，一战击垮其核心力量以瓦解整个对抗结构；找王打王","source":"古典史家(阿里安/普鲁塔克)载其屡寻波斯主力决战(格拉尼库斯/伊苏斯/高加米拉)","source_tier":"secondary","mechanism":"输入=与敌对抗、想速胜 → 处理=不打消耗、主动寻敌主力决定性会战、找核心打核心 → 输出=一战击垮核心、瓦解整个对抗结构","trigger":"陷入或可能陷入零碎消耗、想快速瓦解对手时","modern_transfer":"别陷入零碎消耗——找到对手的核心力量/决策中枢，集中力量一战定胜负；打垮''头''比消耗''身''更快瓦解全局","architecture":{"type":"flow","components":["识别敌核心主力","主动寻求决战","集中力量","一战瓦解结构"]},"strategy_card_image":"kb-assets/alexander/model-1.png"},{"name":"亲冲锋陷阵","definition":"主帅亲率精锐骑兵(伙友骑兵)直插敌阵最关键处(常是敌王本人)，以身先士卒点燃全军、并直取敌指挥中枢","source":"古典史家载其亲率伙友骑兵冲击大流士所在","source_tier":"secondary","mechanism":"输入=最关键最危险的决定性一击 → 处理=主帅亲率精锐直插敌最关键处(敌中枢) → 输出=身先士卒点燃全军 + 直取敌指挥中枢","trigger":"面对最关键的决定性一击、需要全军死力时","modern_transfer":"最关键最危险的那一击，领导者亲自带头冲在最前——既点燃团队死力，又直取对方中枢；但代价是把个人安危与全局过度绑定(其屡负重伤)","architecture":{"type":"flow","components":["选定最关键处","主帅亲率精锐","直插敌中枢","点燃全军"]},"strategy_card_image":"kb-assets/alexander/model-2.png"},{"name":"锤砧协同","definition":"用稳固的方阵(砧)正面咬住敌主力，以机动骑兵(锤)从侧翼/缺口突入夹击；正面固定、侧翼决胜","source":"马其顿方阵+伙友骑兵的经典协同战法","source_tier":"secondary","mechanism":"输入=正面平推效率低 → 处理=一部分(砧)正面咬住固定敌主力、另一部分(锤)从侧翼/缺口突入夹击 → 输出=正面固定、侧翼决胜","trigger":"手上有正面与机动两种力量、想夹击而非平推时","modern_transfer":"别一股脑平推——用一部分力量(砧)正面咬住、牵制固定对手，另一部分(锤)从侧翼或缺口突入决胜；分工夹击远胜均匀平推","architecture":{"type":"matrix","components":["方阵正面固定","骑兵侧翼机动","咬住加突入夹击","侧翼决胜"]},"strategy_card_image":"kb-assets/alexander/model-3.png"},{"name":"文化融合统治","definition":"征服后不纯靠武力压制，而用联姻、保留当地制度、融合波斯习俗与人才来稳固统治；以融合换长治","source":"娶罗克珊娜、推行波斯化、东西联姻(苏萨集体婚礼)","source_tier":"secondary","mechanism":"输入=征服后疆域辽阔、族群多元、纯武力难长治 → 处理=联姻、保留当地制度、融合对方习俗与人才 → 输出=以融合换认同与长治(但推行太快会伤核心团队)","trigger":"''拿下''之后要长期治理、整合异质群体时","modern_transfer":"''打下来''之后靠融合比靠压制更可持续——联姻、保留对方制度、吸纳对方人才；但推行太快、伤了自己核心团队的认同会反噬(其马其顿旧部不满)","architecture":{"type":"hierarchy","components":["征服后不纯压制","联姻留制","融合对方人才","以融合换长治"]},"strategy_card_image":"kb-assets/alexander/model-4.png"},{"name":"以速度与气势压制","definition":"以远征军罕见的进军速度与连胜气势，在对手集结/反应前击破之，并用不败声威瓦解抵抗意志","source":"十年间横扫波斯帝国直抵印度河的进军节奏","source_tier":"secondary","mechanism":"输入=对手会集结反应 → 处理=以罕见进军速度与连胜气势、在对手反应前击破 → 输出=用''不败''声威瓦解其抵抗意志(但速度与扩张有边界)","trigger":"对手尚未集结/反应、想以势压人时","modern_transfer":"以远超对手预期的速度与连胜气势，在对手集结反应前击破之，用''不败''的声威瓦解其抵抗意志；但速度与扩张也有边界(其无止境东征撞上部下哗变)","architecture":{"type":"loop","components":["罕见进军速度","连胜造气势","对手反应前击破","声威瓦解抵抗"]},"strategy_card_image":"kb-assets/alexander/model-5.png"}],"decision_principles":["找主力决战，不打烂仗：寻敌核心一战定胜负（屡寻波斯主力，B）","主帅亲临最危处：以身先士卒点燃全军、直取敌中枢（亲冲伙友骑兵，B）","正面固定、侧翼决胜：锤砧协同（方阵+骑兵，B）","征服后以融合固之：联姻、留制、用当地人才（波斯化，B）"],"inquiry_questions":["你是在打一场决定全局的''主力决战''，还是被零碎消耗拖住了？对手的''王''在哪？","最关键最危险的那一击，你是在后方指挥，还是该亲自带头冲？","你有没有''砧''(正面咬住对手)和''锤''(侧翼决胜)的分工，而不是一股脑平推？","你''打下来''之后呢——靠压制还是靠融合？你愿不愿意采纳被征服者的人才与做法？"],"value_priorities":["决定性会战 ＞ 旷日持久的消耗（一战击垮核心，胜过零敲碎打）","亲临与荣誉 ＞ 主帅自保（身先士卒换全军死力(但也屡次身负重伤、险些丧命)）","征服+融合 ＞ 纯武力压制（以联姻/留制换长治(却引发马其顿旧部不满)）","进取扩张 ＞ 见好就收（此偏好成就空前帝国，也使其无止境东征、部下终于哗变(其盲区)）"],"blind_spots":["无止境扩张、不知节制：一路东征至印度河、部下身心俱疲终在比阿斯河哗变被迫回师——扩张偏好缺止损阀（古典史家，B）","帝国系于个人魅力与天才，未建立可传承的继承与制度安排，本人33岁骤逝后帝国即分裂内战（史实，B）","其个人指挥细节与功业多经后世希腊罗马史家(阿里安/普鲁塔克，去其数百年)追述、含美化与传奇，个别战场决策的精确归属史料有距离（史料批判，B）","亲冲锋的勇武是双刃：屡次身负重伤、险死，主帅个人安危与全军命运过度绑定（史实，B）"],"applicable_domains":["战略","领导力","危机应对","竞争博弈"],"match_tags":["战略","领导力","危机应对","竞争博弈","直觉决断","对抗性思维","攻心共识","古代欧洲"],"linked_cases":["alexander-c1","alexander-c2","alexander-c3"],"life_tags":[{"tag":"东征灭波斯","tier":"secondary"},{"tag":"高加米拉破敌","tier":"secondary"},{"tag":"兵抵印度河","tier":"secondary"},{"tag":"建亚历山大城","tier":"secondary"}],"voice_profile":{"notes":"豪迈进取；诉诸荣誉与不朽；身先士卒的感召；传奇色彩(经后世史家放大)"},"references":[{"ref_id":"alexander-s1","title":"阿里安《亚历山大远征记》","locator":"高加米拉会战、东征诸役、伙友骑兵冲锋","source_tier":"secondary","supports_models":["决战定乾坤","亲冲锋陷阵","锤砧协同","以速度与气势压制"],"supports_cases":["alexander-c1"],"note":"现存最可靠的古典传记，但去亚历山大约四百余年，非一手"},{"ref_id":"alexander-s2","title":"普鲁塔克《希腊罗马名人传·亚历山大传》","locator":"性格、决战、东征轶事","source_tier":"secondary","supports_models":["决战定乾坤","亲冲锋陷阵"],"supports_cases":["alexander-c1"],"note":"后世传记，含轶事美化"},{"ref_id":"alexander-s3","title":"古典史家(融合政策/苏萨婚礼/比阿斯哗变)","locator":"苏萨集体婚礼、波斯化、比阿斯河哗变回师","source_tier":"secondary","supports_models":["文化融合统治","以速度与气势压制"],"supports_cases":["alexander-c2","alexander-c3"],"note":"多源古典记载，后世追述"}],"material_type":"rich","reasoning_skeleton":{"signature":"不打消耗、主动寻敌主力一战定乾坤(找核心打核心)；主帅亲率精锐直插敌中枢点燃全军；正面方阵咬住、侧翼骑兵夹击(锤砧)；以罕见速度与连胜气势在对手反应前击破；打下之后以联姻融合换长治","steps":[{"invoke":"决战定乾坤","action":"你是在打一场决定全局的主力决战，还是被零碎消耗拖住了？对手的''王''(核心/中枢)在哪？"},{"invoke":"以速度与气势压制","action":"能不能以对手意料之外的速度、在他集结反应前击破？用连胜气势瓦解其抵抗意志"},{"invoke":"锤砧协同","action":"别一股脑平推：用一部分正面咬住固定对手(砧)、另一部分从侧翼突入决胜(锤)"},{"invoke":"亲冲锋陷阵","action":"最关键最危险的那一击，你是在后方指挥还是该亲自带头冲、直取对方中枢？(但别把个人安危与全局过度绑定)"},{"invoke":"文化融合统治","action":"打下来之后呢？靠压制还是融合？愿不愿吸纳对方的人才与做法换长治(但别太快伤了自己核心团队)"}],"contrast":"与韩信不同(关键差异·亦是二轴范例)：二者都是''决战机动派''，但**韩信以智补弱、靠奇正与地形设伏算赢(''置之死地''背水)**，其个人指挥经《史记》近世一手详载→确证；**亚历山大以亲征夺势、靠主帅亲冲中枢与速度气势压人**，其个人指挥细节均出后世史家(去其约400年)追述→存疑——同标〔二轴〕、因记载强度不同而 historicity 判不同(见韩信卡)。与拿破仑不同：拿破仑也求决战、集中优势兵力于决定点，但更靠**炮兵与军团体系的制度化机动**；亚历山大更靠**主帅个人勇武亲冲 + 锤砧战术 + 征服后的文化融合**(见拿破仑卡)。【射程/盲区】其无止境扩张缺止损阀(比阿斯河哗变)、帝国系于个人天才而不可传承(33岁骤逝即分裂)——''成就你的进取心，过头就是杀你的东西''。不适用修身自省/人际关系。"},"persona_anchor":{"primary":[{"source":"case","case_id":"alexander-c1","note":"用户''与数量占优的对手对抗、要不要平推''时，以决战中扑向敌指挥中枢类比：高加米拉面对远多于己的波斯大军，不平推、而是制造缺口、亲率精锐直插大流士所在的中军、迫其先逃而全军溃（会战为信史；亚历山大个人战术细节出后世史家追述、historicity 存疑，作代入呈现宜概述、不坐实细节）"},{"source":"case","case_id":"alexander-c2","note":"用户''拿下之后靠压制还是融合''时，以苏萨融合类比：征服波斯后以联姻、波斯化、起用波斯人换认同，短期推进整合却触怒重本位的旧部（融合政策为多源古典记载、具体细节经后世加工故存疑，宜概述政策主干）"}]},"further_reading":[{"title":"阿里安《亚历山大远征记》","why":"现存最可靠的古典传记，但去亚历山大约四百余年、非一手","type":"biography"},{"title":"普鲁塔克《希腊罗马名人传·亚历山大传》","why":"后世传记，性格与轶事，含美化","type":"biography"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/alexander.png","avatar_thumb":"/advisors/portraits/alexander.png","domain":"战略","person_id":"P-alexander","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '1c1a7802abe1c61f4185fa9bd12221b482d5433a61b863d31352d80535f1fc0f', 1, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('aristotle', 'P-aristotle', '亚里士多德', 'philosophy', '亚里士多德 · 逻辑经验与中道思维框架卡', '古希腊（前384—前322）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '逻辑三段论 · 经验归纳', '/advisors/portraits/aristotle.png', '/advisors/portraits/aristotle.png', 5, 0, '{"schema_version":1,"card_id":"aristotle","name":"亚里士多德","title":"亚里士多德 · 逻辑经验与中道思维框架卡","era":"古希腊（前384—前322）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"逻辑三段论","definition":"把推理拆成清晰的\"前提→结论\"的有效形式（如三段论），检查每一步是否真正成立","source":"亚里士多德《工具论》","source_tier":"primary","mechanism":"输入=让结论从站不住的前提或跳跃的逻辑里溜出来 → 处理=把推理拆成清晰的''前提→结论''有效形式、检查每步是否成立 → 输出=结论由有效推理保证(三段论)","trigger":"要做严谨推理/检验论证时","modern_transfer":"把推理拆成清晰的''前提→结论''的有效形式(如三段论)、检查每一步是否真正成立——别让结论从站不住的前提或跳跃的逻辑里溜出来(亚里士多德逻辑)","architecture":{"type":"hierarchy","components":["别让结论从跳跃的逻辑溜出来","把推理拆成前提到结论的有效形式","检查每一步是否真正成立","结论由有效推理保证"]},"strategy_card_image":"kb-assets/aristotle/model-1.png"},{"name":"经验归纳","definition":"从大量具体的观察与经验中归纳出规律，而非只从抽象原理演绎——知识要扎根于现实的考察","source":"亚里士多德博物学与方法","source_tier":"primary","mechanism":"输入=只从抽象原理演绎、脱离现实 → 处理=从大量具体的观察与经验中归纳出规律 → 输出=扎根现实的知识(经验归纳)","trigger":"要建立可靠知识时","modern_transfer":"从大量具体的观察与经验中归纳出规律、而非只从抽象原理演绎——知识要扎根于对现实的实地考察(亚里士多德重经验观察、博物学)〔但受当时观察手段所限、见盲区〕","architecture":{"type":"flow","components":["别只从抽象原理演绎脱离现实","从大量具体观察与经验","归纳出规律","扎根现实的知识"]},"strategy_card_image":"kb-assets/aristotle/model-2.png"},{"name":"中道","definition":"避免\"过度\"与\"不及\"两个极端，找到那个因情境而定的恰当的\"中点\"","source":"亚里士多德《尼各马可伦理学》","source_tier":"primary","mechanism":"输入=走向''过度''或''不及''的极端 → 处理=避免两个极端、找到那个因情境而定的恰当的''中点'' → 输出=恰当的德性/选择(中道)","trigger":"在两个极端间需把握分寸时","modern_transfer":"很多事的智慧在于避免''过度''与''不及''两个极端、找到那个因情境而定的恰当的''中点''(如勇敢是鲁莽与怯懦之间的中道)——中道(亚里士多德)〔但并非所有事都有中道、见盲区〕","architecture":{"type":"flow","components":["别走向过度或不及的极端","避免两个极端","找因情境而定的恰当中点","恰当的德性与选择"]},"strategy_card_image":"kb-assets/aristotle/model-3.png"},{"name":"四因说","definition":"透彻理解一事物，问它的四个\"因\"：质料/形式/动力/目的——尤其别漏了\"它为了什么\"（目的因）","source":"亚里士多德《物理学》《形而上学》","source_tier":"primary","mechanism":"输入=理解一事物只看一两个角度、漏了关键 → 处理=从质料/形式/动力/目的四个角度问、尤其别漏''目的因'' → 输出=透彻的理解(四因)","trigger":"要透彻理解一个事物/现象时","modern_transfer":"要透彻理解一个事物/现象、从四个角度问:它由什么构成(质料)、它的结构形式是什么(形式)、什么造成了它(动力)、它为了什么/朝向什么(目的)——尤其别漏了''目的因''(亚里士多德四因说)〔目的论对自然现象的解释近代已被摒弃、见盲区〕","architecture":{"type":"matrix","components":["别只看一两个角度漏了关键","问质料因由什么构成与形式因结构","问动力因什么造成与目的因为了什么","尤其别漏目的因"]},"strategy_card_image":"kb-assets/aristotle/model-4.png"},{"name":"实践智慧","definition":"「在具体情境中判断该怎么做」的实践智慧（phronesis），靠经验、审时度势养成——知道原则还要会用","source":"亚里士多德《尼各马可伦理学》","source_tier":"primary","mechanism":"输入=以为知道原则就够了 → 处理=培养''在具体情境中判断该怎么做''的实践智慧、靠经验审时度势 → 输出=知道原则还会用(实践智慧)","trigger":"要把原则用到具体情境时","modern_transfer":"有些智慧不是书本的理论知识、而是''在具体情境中判断该怎么做''的实践智慧(phronesis)——靠经验、审时度势养成;知道原则还要会用(亚里士多德)","architecture":{"type":"flow","components":["别以为知道原则就够了","培养在具体情境中判断该怎么做","靠经验审时度势","知道原则还会用"]},"strategy_card_image":"kb-assets/aristotle/model-5.png"}],"decision_principles":["把推理拆成有效形式、检查每步是否成立，别让结论从跳跃的逻辑溜出","从大量具体观察经验中归纳，而非只从抽象原理演绎","避免过度与不及两个极端，找因情境而定的恰当中点","理解事物问全质料/形式/动力/目的四因，尤其别漏目的因","培养在具体情境中判断该怎么做的实践智慧"],"inquiry_questions":["你的结论，是从站得住的前提经有效推理来的、还是从跳跃的逻辑溜出来的？","你这结论是只从抽象原理演绎、还是从大量具体观察经验中归纳来的？","这件事你是走了''过度''或''不及''的极端、还是找到了那个恰当的中点？","你理解这事，问全了它的质料/形式/动力/目的吗（尤其''它为了什么''）？","你是只知道原则、还是有在具体情境中判断该怎么做的实践智慧？"],"value_priorities":["扎根观察的归纳 ＞ 脱离现实的演绎（知识扎根于经验考察）","恰当的中道 ＞ 过度或不及的极端（勇敢是鲁莽与怯懦之间）","会用的实践智慧 ＞ 空知原则（phronesis、知道还要会用）"],"blind_spots":["经验归纳依赖当时的观察手段，亚里士多德的一些具体科学结论（如物理、天文）后被证明是错的（学术，B，客观标注）。","中道并非对所有事都适用——有些事没有''中间''可言（如正义与邪恶之间无中道），滥用会变成无原则的折中（原理推断，B）。","''目的因''（万物有其目的）的目的论在近代自然科学中被很大程度摒弃（对自然现象不再用''为了什么''解释）（学术，B，客观标注）。","其体系庞大、被中世纪奉为权威后也一度成为束缚（不容置疑的''哲学家''）（学术史，B）。"],"applicable_domains":["认知偏误与理性决策","价值与伦理","组织管理"],"match_tags":["认知偏误与理性决策","价值与伦理","组织管理","系统分析","批判思辨","务实渐进","古代欧洲"],"linked_cases":["aristotle-c1","aristotle-c2","aristotle-c3","aristotle-c4"],"life_tags":[{"tag":"师从柏拉图","tier":"secondary"},{"tag":"为帝王师","tier":"secondary"},{"tag":"创吕克昂学园","tier":"secondary"},{"tag":"立形式逻辑","tier":"primary"}],"voice_profile":{"notes":"条分缕析、重实证与逻辑；百科全书式；务实重经验；讲求分寸"},"references":[{"ref_id":"aristotle-s1","title":"亚里士多德《工具论》《尼各马可伦理学》《物理学》《形而上学》","locator":"三段论、经验归纳、中道、四因、实践智慧","source_tier":"primary","supports_models":["逻辑三段论","经验归纳","中道","四因说","实践智慧"],"supports_cases":["aristotle-c1","aristotle-c2","aristotle-c3","aristotle-c4"],"note":"一手·著述"},{"ref_id":"aristotle-s2","title":"古希腊哲学研究","locator":"亚里士多德逻辑、伦理、与柏拉图之别","source_tier":"secondary","supports_models":["逻辑三段论","中道"],"note":"二手·研究"}],"material_type":"textual","reasoning_skeleton":{"signature":"把推理拆成清晰的前提结论有效形式、检查每步是否成立(逻辑三段论)；从大量具体观察经验中归纳规律而非只演绎(经验归纳)；避免过度与不及两极、找恰当的中点(中道)；从质料形式动力目的四角度尤其别漏目的因理解事物(四因说)；培养在具体情境中判断该怎么做的实践智慧(实践智慧)","steps":[{"invoke":"逻辑三段论","action":"你的结论，是从站得住的前提经有效推理来的、还是从跳跃的逻辑溜出来的？"},{"invoke":"经验归纳","action":"你这结论是只从抽象原理演绎、还是从大量具体观察经验中归纳来的？"},{"invoke":"中道","action":"这件事你是走了''过度''或''不及''的极端、还是找到了那个恰当的中点？"},{"invoke":"四因说","action":"你理解这事，问全了它的质料/形式/动力/目的吗（尤其''它为了什么''）？"},{"invoke":"实践智慧","action":"你是只知道原则、还是有在具体情境中判断该怎么做的实践智慧？"}],"contrast":"与柏拉图不同(关键差异·师徒却分流·西方哲学两大路径)：**柏拉图(其师)主''理念在彼岸的理型世界''、向上超越、重演绎与数学、轻经验**；**亚里士多德主''形式内在于具体事物''、重经验观察与归纳、把理念拉回到现实事物中(''吾爱吾师、吾更爱真理'')**——一个向上追理型、一个向下究事物(见柏拉图卡)。与康德不同(伦理学两路径)：**康德是''义务论''(绝对律令、看准则能否普遍化)**；**亚里士多德是''德性伦理''(中道、培养好的品格与实践智慧)**——一个看规则、一个养品格(见康德卡)。与苏格拉底不同：苏格拉底重''诘问、定义'';亚里士多德建立了系统的逻辑、博物学与各学科分类(见苏格拉底卡)。【射程/盲区】亚里士多德之道在''逻辑、经验归纳、中道、四因、实践智慧''极有力，但①经验归纳受当时观察手段所限、其一些具体科学结论后被证伪;②中道并非对所有事都适用、有些事没有''中间''可言、滥用变成无原则折中;③''目的因''的目的论在近代自然科学中被很大程度摒弃;④其体系被中世纪奉为权威后也一度成为束缚。适用认知偏误与理性决策/价值与伦理/组织管理;不适用投资/危机应对。"},"persona_anchor":{"primary":[{"source":"case","case_id":"aristotle-c3","note":"用户''在一件事上走极端、要么过度要么不及、把握不好分寸''时，以亚里士多德中道类比：德性在于避免''过度''与''不及''两个极端、找到那个因情境而定的恰当''中点''——勇敢是鲁莽与怯懦之间、慷慨是挥霍与吝啬之间;很多事的智慧在于找那个恰当的中道（中道为亚里士多德《尼各马可伦理学》核心→确证；但并非所有事都有中道）"},{"source":"case","case_id":"aristotle-c4","note":"用户''理解一个事物/问题时只看到一两个角度、漏了关键''时，以亚里士多德四因说类比：要透彻理解一个事物、从四个角度问——它由什么构成(质料)、结构形式是什么(形式)、什么造成了它(动力)、它为了什么/朝向什么(目的);尤其别漏了''它为了什么''这个目的（四因说为亚里士多德《物理学》《形而上学》核心→确证）"}]},"further_reading":[{"title":"亚里士多德《工具论》《尼各马可伦理学》《物理学》《形而上学》","why":"逻辑三段论、经验归纳、中道、四因、实践智慧的一手出处（A）","type":"original"},{"title":"古希腊哲学研究","why":"对亚里士多德逻辑、伦理与其同柏拉图之别的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/aristotle.png","avatar_thumb":"/advisors/portraits/aristotle.png","domain":"哲学","person_id":"P-aristotle","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'a369d0e551b8971445649d371d69d4c507e0754e121394d8eb901032a9caef4b', 2, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('augustus', 'P-augustus', '奥古斯都', 'governance', '奥古斯都 · 实权渐进与制度奠基思维框架卡', '古罗马（前63—公元14）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '实权而非虚名 · 旧瓶装新酒', '/advisors/portraits/augustus.png', '/advisors/portraits/augustus.png', 5, 0, '{"schema_version":1,"card_id":"augustus","name":"奥古斯都","title":"奥古斯都 · 实权渐进与制度奠基思维框架卡","era":"古罗马（前63—公元14）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"实权而非虚名","definition":"追求的是实际的权力与控制，而非扎眼的头衔与虚名——有时刻意放低名分，避免成为众矢之的","source":"屋大维拒绝国王称号、自称\"第一公民\"","source_tier":"secondary","mechanism":"输入=贪图扎眼的头衔虚名、成众矢之的 → 处理=追求实际的权力与控制、刻意放低名分避免成靶子 → 输出=实权在握而非名号好听(实权非虚名)","trigger":"在''实际控制''与''头衔名分''间取舍时","modern_transfer":"追求的是实际的权力与控制、而非扎眼的头衔与虚名——有时刻意放低名分、避免成为众矢之的、实权在握比名号好听更重要(屋大维拒绝''国王/独裁官''称号、只自称''第一公民Princeps'')","architecture":{"type":"flow","components":["别贪图扎眼的头衔虚名成靶子","追求实际的权力与控制","刻意放低名分避免成众矢之的","实权在握而非名号好听"]},"strategy_card_image":"kb-assets/augustus/model-1.png"},{"name":"旧瓶装新酒","definition":"保留旧制度的外壳、名义、传统，让人感到延续与安心，同时悄悄注入新的实质——比公开砸碎旧瓶阻力小得多","source":"奥古斯都以\"恢复共和\"之名行元首制之实","source_tier":"secondary","mechanism":"输入=公开砸碎旧制度、激起巨大阻力 → 处理=保留旧制度的外壳/名义/传统、同时悄悄注入新实质 → 输出=以旧形式行新实质减阻力(旧瓶装新酒)","trigger":"重大变革、要减少''颠覆传统''的阻力时","modern_transfer":"重大变革时、保留旧制度的外壳、名义、传统、让人感到延续与安心、同时悄悄注入新的实质——''旧瓶装新酒''比公开砸碎旧瓶阻力小得多(奥古斯都以''恢复共和''之名、行元首独裁之实)〔但也含架空与蒙蔽之嫌、见盲区〕","architecture":{"type":"flow","components":["别公开砸碎旧制度激起阻力","保留旧制度的外壳名义传统","同时悄悄注入新的实质","以旧形式行新实质减阻力"]},"strategy_card_image":"kb-assets/augustus/model-2.png"},{"name":"渐进积累而非一步到位","definition":"别急于一步到位拿到所有的权力/成果——分步骤、以一个个看似合理合法的名义逐渐积累，让每一步都显得温和","source":"屋大维逐步集权","source_tier":"secondary","mechanism":"输入=急于一次拿到所有权力/成果、招致警惕反弹 → 处理=分步骤、以一个个看似合理合法的名义逐渐积累 → 输出=温和合法地水到渠成(渐进积累)","trigger":"要获取一个大的权力/目标、又怕引起警惕时","modern_transfer":"别急于一步到位拿到所有的权力/成果——分步骤、以一个个看似合理合法的名义逐渐积累、让每一步都显得温和、最终水到渠成(屋大维以一连串合法授权逐步集大权于一身)","architecture":{"type":"flow","components":["别急于一步到位招致反弹","分步骤进行","以一个个看似合理合法的名义","逐渐积累水到渠成"]},"strategy_card_image":"kb-assets/augustus/model-3.png"},{"name":"制度建设固长治","definition":"把一时的个人权威与胜利，转化为可持续的制度与秩序（行政、财政、军队、法律）——制度才能长治久安","source":"奥古斯都开创\"罗马和平\"","source_tier":"secondary","mechanism":"输入=只靠一时的个人权威与胜利、人走茶凉 → 处理=把它转化为可持续的制度与秩序(行政/财政/军队/法律) → 输出=制度长治久安(制度建设)","trigger":"要把一时的成功变成持久的基业时","modern_transfer":"把一时的个人权威与胜利、转化为可持续的制度与秩序(行政、财政、军队、法律)——''我接手的是砖城、留下的是大理石城''、制度才能长治久安(奥古斯都开创了约二百年的''罗马和平''Pax Romana)","architecture":{"type":"hierarchy","components":["别只靠一时的个人权威与胜利","把它转化为可持续的制度与秩序","行政财政军队法律","制度长治久安"]},"strategy_card_image":"kb-assets/augustus/model-4.png"},{"name":"软性塑造认同","definition":"用文化、形象、公共建设、共同的故事去塑造民众的认同与忠诚，而非只靠强力——软性认同比硬性强制更持久","source":"奥古斯都赞助文艺、营造形象","source_tier":"secondary","mechanism":"输入=只靠强力压服 → 处理=用文化、形象、公共建设、共同的故事塑造认同与忠诚 → 输出=软性认同比强制持久(软性认同)","trigger":"要赢得长久的人心与忠诚时","modern_transfer":"用文化、形象、公共建设、共同的故事去塑造民众的认同与忠诚、而非只靠强力——软性的认同比硬性的强制更持久(奥古斯都赞助文艺、大兴建设、营造''罗马和平''与自身的形象)","architecture":{"type":"flow","components":["别只靠强力压服","用文化形象公共建设与共同的故事","塑造民众的认同与忠诚","软性认同比强制持久"]},"strategy_card_image":"kb-assets/augustus/model-5.png"}],"decision_principles":["追求实际的权力与控制，而非扎眼的头衔虚名（刻意放低名分避祸）","保留旧制度的外壳与传统，同时悄悄注入新实质（减阻力，但含蒙蔽）","分步以合法名义逐渐积累，而非一步到位招致反弹","把一时的个人权威转化为可持续的制度与秩序","用文化、形象、共同的故事塑造认同，而非只靠强力"],"inquiry_questions":["你要的是实际的权力与控制、还是扎眼的头衔虚名（后者可能让你成靶子）？","你是公开砸碎旧制度激起阻力、还是保留外壳同时悄悄注入新实质？","你是急于一步到位招致反弹、还是分步以合法名义逐渐积累？","你是只靠一时的个人权威、还是把它转化为可持续的制度与秩序？","你是只靠强力压服、还是用文化、形象、共同的故事塑造认同与忠诚？"],"value_priorities":["实际的权力与控制 ＞ 扎眼的头衔虚名（拒国王称号、自称第一公民）","可持续的制度秩序 ＞ 一时的个人权威（罗马和平、砖城变大理石城）","软性的认同 ＞ 单纯的强力压服（赞助文艺、营造形象）"],"blind_spots":["''旧瓶装新酒''实质是对罗马共和的精致架空、含蒙蔽——以''恢复共和''之名行个人独裁之实（史，B，客观标注）。","其建立的元首制（实为帝制）终结了罗马共和、对共和传统是终结（史，B，客观标注）。","个人的巨大成功依赖其极高的政治手腕、谨慎与漫长的统治时间，难以简单复制（原理推断，B）。","把权力私相授受给继承人，也为后世出现暴君（如尼禄）埋下了制度隐患（史，B）。"],"applicable_domains":["组织管理","长期规划","竞争博弈"],"match_tags":["组织管理","长期规划","竞争博弈","务实渐进","系统分析","攻心共识","古代欧洲"],"linked_cases":["augustus-c1","augustus-c2","augustus-c3","augustus-c4"],"life_tags":[{"tag":"平息罗马内战","tier":"secondary"},{"tag":"开创帝制","tier":"secondary"},{"tag":"行元首制","tier":"secondary"},{"tag":"击败安东尼","tier":"secondary"}],"voice_profile":{"notes":"精明深沉、谨慎务实；重实权与制度；善用形式与象征；渐进而坚定"},"references":[{"ref_id":"augustus-s1","title":"《奥古斯都功业录》、塔西佗《编年史》、苏维托尼乌斯《罗马十二帝王传》及罗马史","locator":"实权非虚名、恢复共和之名、渐进集权、罗马和平、文艺赞助","source_tier":"secondary","supports_models":["实权而非虚名","旧瓶装新酒","渐进积累而非一步到位","制度建设固长治","软性塑造认同"],"supports_cases":["augustus-c1","augustus-c2","augustus-c3","augustus-c4"],"note":"一手/二手·史（《功业录》为奥古斯都自述、有自我美化）"},{"ref_id":"augustus-s2","title":"罗马史","locator":"从共和到帝制、元首制、罗马和平","source_tier":"secondary","supports_models":["制度建设固长治","软性塑造认同"],"note":"二手·史"}],"material_type":"rich","reasoning_skeleton":{"signature":"追求实际权力与控制而非扎眼头衔、刻意放低名分避祸(实权而非虚名)；保留旧制度外壳同时悄悄注入新实质减阻力(旧瓶装新酒)；分步以合法名义逐渐积累而非一步到位(渐进积累而非一步到位)；把个人权威转化为可持续的制度与秩序(制度建设固长治)；用文化形象建设塑造认同而非只靠强力(软性塑造认同)","steps":[{"invoke":"实权而非虚名","action":"你要的是实际的权力与控制、还是扎眼的头衔虚名（后者可能让你成靶子）？"},{"invoke":"旧瓶装新酒","action":"你是公开砸碎旧制度激起阻力、还是保留外壳同时悄悄注入新实质？"},{"invoke":"渐进积累而非一步到位","action":"你是急于一步到位招致反弹、还是分步以合法名义逐渐积累？"},{"invoke":"制度建设固长治","action":"你是只靠一时的个人权威、还是把它转化为可持续的制度与秩序？"},{"invoke":"软性塑造认同","action":"你是只靠强力压服、还是用文化、形象、共同的故事塑造认同与忠诚？"}],"contrast":"与华盛顿不同(关键差异·权力的两个相反方向)：**华盛顿大权在握却''主动放弃权力、拒绝称王、确立和平交接、让制度先于个人''(以放权立制、防止个人独裁)**；**奥古斯都则''以恢复共和之名、行元首独裁之实、把大权集于一身、再以制度固化之''(以集权奠基、开创帝制)**——同样精于制度、华盛顿是放权者、奥古斯都是集权者、方向恰恰相反(见华盛顿卡)。与伯里克利不同(同批·治理路径)：伯里克利推动''公民广泛参与的直接民主'';奥古斯都''以共和外壳行个人集权''——一个扩大参与、一个集中于己(见伯里克利卡)。【射程/盲区·历史诚实·重点】奥古斯都之道在''实权非虚名、旧瓶装新酒、渐进积累、制度建设、软性认同''极有力(尤其权力的获取与制度的奠基)，但①''旧瓶装新酒''实质是对罗马共和的精致架空、含蒙蔽——以''恢复共和''之名行独裁之实;②其元首制(实为帝制)终结了罗马共和;③个人成功依赖其极高手腕、谨慎与长寿、难简单复制;④把权力私授继承人、为后世暴君埋下隐患。适用组织管理/长期规划/竞争博弈;不适用创作/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"augustus-c1","note":"用户''贪图扎眼的头衔、名分、面子、反而成了众矢之的''时，以奥古斯都''实权非虚名''类比：他大权在握、却拒绝''国王''''独裁官''等刺激人的称号、只谦称''第一公民''、把刺眼的名分让出去、实权牢牢攥在手里——追求实际的权力与控制、而非扎眼的虚名、避免成为靶子（屋大维拒国王称号、自称Princeps为史实→确证）"},{"source":"case","case_id":"augustus-c2","note":"用户''要推一个大变革、又怕''颠覆传统/砸了老规矩''激起巨大阻力''时，以奥古斯都''旧瓶装新酒''类比：他名义上''恢复共和''、保留元老院等共和的外壳与传统、让人感到延续与安心、实则悄悄把权力集于元首一身——保留旧制度的外壳、同时注入新实质、比公开砸碎旧瓶阻力小得多〔但须知这也含架空与蒙蔽之嫌、客观标注〕（奥古斯都''恢复共和''之名行元首制之实为史实→确证）"}]},"further_reading":[{"title":"《奥古斯都功业录》、塔西佗《编年史》、苏维托尼乌斯《罗马十二帝王传》","why":"实权非虚名、恢复共和之名、制度建设、罗马和平的记述（A/B）","type":"史/原典"},{"title":"罗马史","why":"从共和到帝制、奥古斯都元首制与罗马和平的史述（B）","type":"史"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/augustus.png","avatar_thumb":"/advisors/portraits/augustus.png","domain":"治理","person_id":"P-augustus","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '110e0c2eb93fb392e81b315ccb1fc583d76c835254c653db2bc4cb4362dba535', 3, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('bezos', 'P-bezos', '杰夫·贝索斯', 'business', '杰夫·贝索斯 · 长期主义与客户倒推思维框架卡', '20–21世纪（1964– ）', 'zh-CN', 'published', 'in_review', 'pending', 'living', 'rich', 'Day 1哲学 · 客户痴迷', '/advisors/portraits/bezos.png', '/advisors/portraits/bezos.png', 5, 0, '{"schema_version":1,"card_id":"bezos","name":"杰夫·贝索斯","title":"杰夫·贝索斯 · 长期主义与客户倒推思维框架卡","era":"20–21世纪（1964– ）","language":"zh-CN","status":"published","living_status":"living","core_models":[{"name":"Day 1哲学","definition":"永远把公司当第一天的创业公司经营，保持饥饿、敏捷、以客户为中心；Day 2意味停滞与衰亡","source":"亚马逊致股东信","source_tier":"primary","mechanism":"输入=组织的当前状态 → 处理=把公司当第一天创业经营、保持饥饿敏捷以客户为中心、警惕Day2停滞 → 输出=持续的创业心态与敢失败的实验","trigger":"组织变大、流程变重、滋生''功成''惰性时","modern_transfer":"永远把它当第一天来做、保持饥饿与敏捷；Day2 意味停滞与衰亡","architecture":{"type":"loop","components":["审视当前状态","保持饥饿敏捷","以客户为中心","拒Day2停滞"]},"strategy_card_image":"kb-assets/bezos/model-1.png"},{"name":"客户痴迷","definition":"痴迷于客户而非竞争对手；从客户需求倒推，对手只让你追随，客户会持续把你往前拉","source":"亚马逊致股东信","source_tier":"primary","mechanism":"输入=一个决策 → 处理=从客户需求倒推、痴迷客户而非竞争对手 → 输出=被客户持续往前拉的方向","trigger":"容易盯着对手反应做决策时","modern_transfer":"痴迷客户而非对手——对手只让你追随，客户会持续把你往前拉","architecture":{"type":"flow","components":["锁定客户需求","从需求倒推","不盯对手","被客户牵引"]},"strategy_card_image":"kb-assets/bezos/model-2.png"},{"name":"后悔最小化","definition":"重大抉择时想象80岁回望，选将来最不后悔的那个，而非纠结眼前得失","source":"贝索斯公开访谈/演讲","source_tier":"primary","mechanism":"输入=重大不可逆抉择 → 处理=想象80岁回望、选将来最不后悔的那个 → 输出=盖过短期得失的选择","trigger":"重大人生/事业抉择、被短期恐惧与机会成本困住时","modern_transfer":"重大抉择想象80岁回望，选将来最不后悔的那个，而非纠结眼前得失","architecture":{"type":"flow","components":["面对重大抉择","拉到生命终点回望","比较后悔程度","选最不后悔"]},"strategy_card_image":"kb-assets/bezos/model-3.png"},{"name":"长期主义","definition":"以年到十年为尺度思考；宁要长期自由现金流与市场地位，不为短期利润牺牲未来","source":"亚马逊致股东信","source_tier":"primary","mechanism":"输入=一项投入决策 → 处理=以年到十年为尺度思考、宁要长期自由现金流与地位、忍受当期不被理解 → 输出=长期下注","trigger":"短期利润与长期价值冲突时","modern_transfer":"以年到十年为尺度，宁要长期自由现金流与市场地位、不为短期利润牺牲未来","architecture":{"type":"hierarchy","components":["拉长时间尺度","看长期现金流/地位","忍受当期不被理解","长期下注"]},"strategy_card_image":"kb-assets/bezos/model-4.png"},{"name":"单双向门决策","definition":"区分不可逆的单向门（慎重）与可逆的双向门（快决）；大组织别用一刀切的慢决策；不同意也执行","source":"亚马逊致股东信","source_tier":"primary","mechanism":"输入=一个决策 → 处理=区分不可逆单向门（慎重）与可逆双向门（快决）、大组织不一刀切、不同意也执行 → 输出=按可逆性分流的决策速度","trigger":"决策速度被一刀切拖慢时","modern_transfer":"区分不可逆的单向门（慎重）与可逆的双向门（快决），可逆的别僵持——''不同意但执行''","architecture":{"type":"matrix","components":["判定决策可逆性","单向门慎重","双向门快决","不同意也执行"]},"strategy_card_image":"kb-assets/bezos/model-5.png"}],"decision_principles":["永远是Day 1：把公司当创业第一天经营（A）","痴迷客户、而非盯着竞争对手（A）","重大抉择用后悔最小化，想象80岁回望（A）","为长期自由现金流，宁可牺牲短期利润（A）","可逆决策快决，不可逆决策慎重（A）","失败与发明是连体双胞胎，失败规模要敢放大（A）"],"inquiry_questions":["这件事，80岁的你回望时会后悔没做吗？","你是在满足客户，还是只在盯着竞争对手的反应？","这是可逆的双向门，还是不可逆的单向门？","你在为下个季度，还是为未来五到十年做这个决定？"],"value_priorities":["长期自由现金流与市场地位 ＞ 短期利润与季度财报（愿意长期不被理解）","从客户需求倒推 ＞ 盯着竞争对手（客户是北极星）","可逆决策快速试错 ＞ 凡事求稳慢决（速度本身是优势）","敢做会失败的大实验 ＞ 只做稳妥小事（失败规模要随公司增长）"],"blind_spots":["敢赌大实验也意味着代价高昂的失败——Fire Phone 2014减记约1.7亿美元（公开记录，A/B）","极致客户痴迷与高强度文化，被指对员工苛刻、仓储劳工条件等争议（公开报道，B）","长期主义加愿不被理解，在判断失误时也可能长期烧钱在错的方向（原理推断，B）"],"applicable_domains":["创业","创新研发","长期规划","商业模式与护城河","组织管理"],"match_tags":["创业","创新研发","长期规划","长期主义","实验试错","逆向思考","现当代北美"],"linked_cases":["bezos-c1","bezos-c2","bezos-c3","bezos-c4","bezos-c5"],"life_tags":[{"tag":"创办亚马逊","tier":"secondary"},{"tag":"创蓝色起源","tier":"secondary"},{"tag":"购华盛顿邮报","tier":"secondary"},{"tag":"推AWS云服务","tier":"secondary"}],"voice_profile":{"notes":"金句格言式；爱用比喻（Day1/连体双胞胎）；理性乐观、敢于反共识"},"references":[{"ref_id":"bezos-s1","title":"亚马逊致股东信（历年）","locator":"1997（Day1/长期）、2015–16（Type1/2、disagree and commit）、2018（失败规模）等","source_tier":"primary","supports_models":["Day 1哲学","客户痴迷","长期主义","单双向门决策"],"supports_cases":["bezos-c2","bezos-c3","bezos-c5"],"note":"本人执笔一手；具体年份待质检者定位"},{"ref_id":"bezos-s2","title":"贝索斯公开访谈/演讲（后悔最小化框架）","locator":"其讲述创立亚马逊抉择的访谈段落待核验","source_tier":"primary","supports_models":["后悔最小化"],"supports_cases":["bezos-c1"],"note":"本人公开陈述"},{"ref_id":"bezos-s3","title":"布拉德·斯通《一网打尽》(The Everything Store)等传记报道","locator":"创立经过、负面评论决策相关章节；页码待核验","source_tier":"secondary","supports_cases":["bezos-c1","bezos-c4"],"note":"第三方传记/报道"},{"ref_id":"bezos-s4","title":"Fire Phone减记公开披露与媒体报道（2014）","locator":"2014-10季报披露；约1.7亿减记/约8300万库存","source_tier":"secondary","supports_cases":["bezos-c3"],"note":"公开财报与报道"}],"material_type":"rich","reasoning_skeleton":{"signature":"把每天当创业第一天、从客户倒推而非盯对手，重大抉择用''80岁回望最不后悔''，长期主义下注，可逆的事快决、不可逆的事慎重","steps":[{"invoke":"后悔最小化","action":"若是重大不可逆抉择，先想象80岁回望、选将来最不后悔的那个"},{"invoke":"单双向门决策","action":"判断这是可逆的双向门（快决）还是不可逆的单向门（慎重），别一刀切"},{"invoke":"客户痴迷","action":"从客户需求倒推，别盯着竞争对手的反应"},{"invoke":"长期主义","action":"为未来五到十年、长期自由现金流做决定，忍受当期不被理解"},{"invoke":"Day 1哲学","action":"始终保持创业第一天的饥饿与敏捷，敢做会失败的大实验、失败规模随公司增长"}],"contrast":"与乔布斯不同（同为颠覆式创业者）：乔布斯拒调研、靠直觉与品味、少而极致；贝索斯客户倒推、靠数据与机制、长期主义 + 可逆决策驱动（见乔布斯卡）。与巴菲特不同：贝索斯是经营者/创造者（故不适用投资域），长期主义指''长期自由现金流与市场地位''；巴菲特是投资者，长期主义指''长期持有好生意''（见巴菲特卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"bezos-c1","note":"用户''要不要放弃稳定去赌一个高风险机会''时，以后悔最小化创立亚马逊类比：他在华尔街有高薪前途，想象80岁回望、判断错过互联网浪潮会比创业失败更后悔，遂辞职创业（确证）"},{"source":"case","case_id":"bezos-c3","note":"用户''一个大胆实验失败了、怎么面对''时，以 Fire Phone 失败类比：减记约 1.7 亿，但他奉行''失败与发明是连体双胞胎''、不羞辱、把团队与经验迁移到 Echo/Alexa 最终大成（确证·既是代价高昂的反例、也是 Day1 实验精神的体现）"}]},"further_reading":[{"title":"亚马逊致股东信（1997–2021 历年）","why":"他本人执笔的一手材料，Day1/长期主义/单双向门/''不同意但执行''的直接出处","type":"original"},{"title":"布拉德·斯通《一网打尽》(The Everything Store)","why":"记者视角的亚马逊与贝索斯史，看其决策（含负面评论体系、高强度文化争议）的另一面","type":"biography"},{"title":"《Invent and Wander：杰夫·贝索斯文集》","why":"把致股东信与演讲合编，集中呈现其思维，比逐年翻信更省力","type":"original"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/bezos.png","avatar_thumb":"/advisors/portraits/bezos.png","domain":"商业","person_id":"P-bezos","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'c7f9a7501145f88131078fdb2b669951927eb46f69c21c02ee653445abfce11f', 4, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('bismarck', 'P-bismarck', '俾斯麦', 'governance', '俾斯麦 · 现实政治与均势外交思维框架卡', '19世纪（1815—1898）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '现实政治 · 铁血', '/advisors/portraits/bismarck.png', '/advisors/portraits/bismarck.png', 5, 0, '{"schema_version":1,"card_id":"bismarck","name":"俾斯麦","title":"俾斯麦 · 现实政治与均势外交思维框架卡","era":"19世纪（1815—1898）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"现实政治","definition":"以实际的实力对比与利益、而非理想/道义/感情来决策，只做可能的事——政治是可能性的艺术","source":"俾斯麦《思考与回忆》及其外交实践","source_tier":"secondary","mechanism":"输入=决策受理想/道义/感情牵引、脱离实际 → 处理=以实际的实力对比与利益、而非理想/道义来决策、只做可能的事 → 输出=基于现实可行性的决策","trigger":"面对重大决策、易被理想/感情牵引时","modern_transfer":"以实际的实力对比与利益、而非理想/道义/感情来决策——''政治是可能性的艺术''，只做可能的事(但纯以实力利益、轻视价值会埋长期隐患)","architecture":{"type":"matrix","components":["评估实际实力对比","算清现实利益","排除理想道义牵引","只做可能之事"]},"strategy_card_image":"kb-assets/bismarck/model-1.png"},{"name":"铁血","definition":"认清有些根本性的重大问题最终要靠实力来解决、而非空谈或表决——但伦理代价极大、须极度节制","source":"俾斯麦\"铁血演说\"","source_tier":"secondary","mechanism":"输入=重大根本问题靠空谈/表决迟迟无解 → 处理=认清真正的重大问题最终靠实力(铁与血)解决、而非演说表决 → 输出=以实力解决根本问题(但伦理代价大、须极度节制)","trigger":"重大根本问题靠空谈无法解决时","modern_transfer":"认清有些根本性的重大问题最终要靠实力解决、而非空谈或表决——但''铁与血''伦理代价极大、且易被误用为强权崇拜，须极度节制(此为对其方法的描述、非主张诉诸暴力)","architecture":{"type":"hierarchy","components":["识别空谈无解的重大问题","认清最终靠实力","集中实力解决","极度节制使用"]},"strategy_card_image":"kb-assets/bismarck/model-2.png"},{"name":"操控均势","definition":"通过结盟与分化操控多方力量的平衡，防止针对自己的联盟形成、把潜在对手孤立","source":"俾斯麦同盟体系（三皇同盟/德奥同盟/再保险条约）","source_tier":"secondary","mechanism":"输入=多方力量并存、可能形成针对自己的联盟 → 处理=通过结盟与分化操控多方力量的平衡、防止反己联盟 → 输出=维持有利于己的均势、孤立对手","trigger":"多方力量并存、怕被联合围攻时","modern_transfer":"通过结盟与分化操控多方力量的平衡——防止针对你的联盟形成、把潜在对手孤立(俾斯麦的复杂同盟体系)；但这种体系高度依赖操控者的技巧、难传承","architecture":{"type":"matrix","components":["识别多方力量","结盟拉拢一部分","分化孤立对手","维持有利均势"]},"strategy_card_image":"kb-assets/bismarck/model-3.png"},{"name":"见好就收有限目标","definition":"设定有限目标、达到即止；胜了也别过度羞辱对手，留他作日后的伙伴，别被胜利冲昏头继续扩张","source":"普奥战争后宽待奥地利","source_tier":"secondary","mechanism":"输入=取得胜利、易被冲昏头继续扩张 → 处理=设定有限目标、达到即止、胜后不过度羞辱对手(留作日后伙伴) → 输出=守住成果不反噬","trigger":"取得胜利、面临是否继续扩张时","modern_transfer":"设定有限目标、达到即止——胜了也别过度羞辱对手(留他作日后的伙伴)，别被胜利冲昏头继续扩张(普奥战后俾斯麦宽待奥地利)","architecture":{"type":"flow","components":["设定有限目标","达到即止","胜后不过度羞辱","留对手作日后伙伴"]},"strategy_card_image":"kb-assets/bismarck/model-4.png"},{"name":"制造正当性的时机","definition":"主动制造一个让对手先动手、或自己师出有名的局面，把冲突的正当性放到自己一边","source":"埃姆斯密电（Ems Dispatch）","source_tier":"secondary","mechanism":"输入=想行动但缺正当理由/怕担侵略之名 → 处理=主动制造一个让对手先动手或自己师出有名的局面 → 输出=把冲突的正当性放在自己一边","trigger":"想行动但缺正当性时","modern_transfer":"主动制造一个让对手先动手、或自己师出有名的局面，把冲突的正当性放到自己一边(俾斯麦编辑埃姆斯密电激法先宣战)——〔慎〕这是操纵手段、道德可议，呈现为其方法、非主张效法","architecture":{"type":"flow","components":["想行动但缺正当性","制造让对手先动手的局面","师出有名","把正当性放己方"]},"strategy_card_image":"kb-assets/bismarck/model-5.png"}],"decision_principles":["以实力与利益而非道义感情决策，只做可能的事","认清根本问题最终靠实力解决，但极度节制（铁血代价大）","通过结盟与分化操控均势，防止针对你的联盟","设有限目标、达到即止，胜后不过度羞辱对手","〔慎〕主动制造师出有名的局面，把正当性放己方"],"inquiry_questions":["你这决策是被理想/道义/感情牵引，还是基于实际实力与利益、只做可能的事？","多方力量并存时，你能不能用结盟与分化维持对你有利的平衡？","你的目标有限吗？达到了就止、还是会被胜利冲昏头继续扩张？","你想行动但缺正当理由时，是否在制造让对手先动手/师出有名的局面？（伦理须自省）","这个根本问题真到了靠实力而非空谈解决的地步了吗？（须极度节制）"],"value_priorities":["实力与现实利益 ＞ 理想与道义（现实政治；但轻视价值会埋长期隐患）","有限目标、见好就收 ＞ 被胜利冲昏头扩张（胜后宽待对手、留作日后伙伴）","有利的均势 ＞ 一时的痛快胜利（操控均势防止反己联盟（但依赖个人技巧、难传承））"],"blind_spots":["其铁血/操纵（编辑埃姆斯密电）冷酷、为目的不择手段，道德可议；''铁与血''被后世误用为军国主义与强权崇拜的口号（史实/评议，B，〔慎〕，客观标注、非主张效法）。","其复杂同盟体系高度依赖其个人操控技巧、难制度化，被威廉二世罢免（1890）后体系迅速崩坏，间接通向一战格局（史实，B）。","国内反社会主义法、文化斗争（Kulturkampf）等高压政策失败、且压制异己（史实，B）。","现实政治轻视长期价值与道义，短期奏效却埋下长期隐患（其同盟体系的脆弱性，原理推断，B）。"],"applicable_domains":["战略","治理决策","竞争博弈","谈判"],"match_tags":["战略","治理决策","竞争博弈","谈判","目的手段分离","对抗性思维","务实渐进","近代欧洲"],"linked_cases":["bismarck-c1","bismarck-c2","bismarck-c3","bismarck-c4"],"life_tags":[{"tag":"统一德意志","tier":"secondary"},{"tag":"推铁血政策","tier":"secondary"},{"tag":"创社会保险","tier":"secondary"},{"tag":"主导欧洲均势","tier":"secondary"}],"voice_profile":{"notes":"冷峻务实、重实力与利益；通权达变、善纵横捭阖；言辞犀利有力；不为道义辞令所动"},"references":[{"ref_id":"bismarck-s1","title":"俾斯麦《思考与回忆》(Gedanken und Erinnerungen)","locator":"现实政治、铁血、统一外交诸章","source_tier":"secondary","supports_models":["现实政治","铁血"],"supports_cases":["bismarck-c1"],"note":"本人回忆录·自我经营色彩强、含辩护美化→相关自述存润色、不单独坐实"},{"ref_id":"bismarck-s2","title":"Jonathan Steinberg《Bismarck：A Life》及权威传记","locator":"统一三战、同盟体系、埃姆斯密电、罢免诸章","source_tier":"secondary","supports_models":["操控均势","见好就收有限目标","制造正当性的时机"],"supports_cases":["bismarck-c1","bismarck-c2","bismarck-c3","bismarck-c4"],"note":"B层·权威传记"},{"ref_id":"bismarck-s3","title":"19世纪欧洲外交史","locator":"普奥/普法战争、均势体系、罢免后格局","source_tier":"secondary","supports_models":["现实政治","操控均势"],"supports_cases":["bismarck-c3","bismarck-c4"],"note":"外交史料，多源交叉"}],"material_type":"rich","reasoning_skeleton":{"signature":"以实际实力与利益而非道义感情决策、只做可能的事(现实政治)；认清根本问题最终靠实力解决但极度节制(铁血)；通过结盟分化操控均势、防止反己联盟(操控均势)；设有限目标达到即止、胜后不过度羞辱对手(见好就收)；〔慎〕主动制造师出有名的局面把正当性放己方(制造正当性的时机)","steps":[{"invoke":"现实政治","action":"你这决策是被理想/道义/感情牵引，还是基于实际的实力对比与利益、只做可能的事？"},{"invoke":"操控均势","action":"多方力量并存时，你能不能通过结盟与分化维持对你有利的平衡、防止被联合围攻？"},{"invoke":"见好就收有限目标","action":"你的目标有限吗？达到了就止、还是会被胜利冲昏头继续扩张？(胜了也别过度羞辱对手)"},{"invoke":"制造正当性的时机","action":"〔慎·伦理〕你想行动但缺正当理由时，是否在制造让对手先动手/师出有名的局面？"},{"invoke":"铁血","action":"〔慎·伦理〕这个根本问题真到了靠实力而非空谈解决的地步了吗？(须极度节制)"}],"contrast":"与华盛顿不同(关键差异·同为政治领袖)：**华盛顿靠克制、放权、立先例确立可持续制度(自我限权)**；**俾斯麦靠现实政治、铁血、操控均势扩张并维持强权(为权力服务)**——华盛顿是限权、俾斯麦是用权且为目的不择手段(见华盛顿卡)。与曼德拉不同：曼德拉的现实政治是为''终结压迫+多元共存+和解''；俾斯麦的现实政治为''强权与均势''、轻视价值道义(见曼德拉卡)。与李世民不同：李世民重纳谏兼听的内部治理；俾斯麦重对外的强权外交。与管仲''尊王攘夷借大义''相比：管仲借公认旗号凝聚、俾斯麦更冷酷操纵(制造正当性)。【射程/盲区·〔慎〕】俾斯麦之术在权力博弈、外交均势中极有效，但①〔慎〕其铁血/操纵(埃姆斯密电)冷酷、为目的不择手段、道德可议，''铁与血''被后世误用为军国主义口号(客观标注、非主张效法)；②其复杂同盟体系高度依赖个人操控、难制度化，被威廉二世罢免后体系迅速崩坏、间接通向一战；③国内反社会主义法/文化斗争等高压政策失败且压制异己；④现实政治轻视长期价值与道义、短期奏效却埋长期隐患。适用战略/外交/竞争博弈/谈判；不适用价值与伦理/修身自省。"},"persona_anchor":{"primary":[{"source":"case","case_id":"bismarck-c2","note":"用户''打赢了/占上风后，要不要乘胜追击、把对手往死里压''时，以普奥战争后宽待奥地利类比：1866 普鲁士大胜，俾斯麦力排众议、主张宽待奥地利、不过度羞辱、不割其本土，为日后德奥同盟留余地——设有限目标、见好就收、留对手作日后伙伴（宽待奥地利为可考史实→确证）"},{"source":"case","case_id":"bismarck-c3","note":"用户''多方势力并存、怕被联合围攻''时，以俾斯麦同盟体系类比：他构建三皇同盟/德奥同盟/再保险条约等复杂同盟、通过结盟与分化孤立法国、维持对德有利的欧洲均势（同盟体系为可考史实→确证；惟此体系依赖其个人操控、罢免后即崩，须并陈其脆弱）"}]},"further_reading":[{"title":"Jonathan Steinberg《Bismarck：A Life》(2011)","why":"权威传记，统一三战、同盟体系、埃姆斯密电、伦理争议与体系脆弱","type":"biography"},{"title":"俾斯麦《思考与回忆》(Gedanken und Erinnerungen)","why":"本人回忆录、自我经营色彩强、含辩护与美化，须辨","type":"回忆录"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/bismarck.png","avatar_thumb":"/advisors/portraits/bismarck.png","domain":"治理","person_id":"P-bismarck","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '0e5f939b1e6197ddd4fc69e3a0b78486de63b7063a492839ba1566b5e52a6e8a', 5, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('bogle', 'P-bogle', '博格', 'investing', '博格 · 低成本指数与长期坚守思维框架卡', '现代（1929—2019）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '成本是确定的敌人 · 买下整个草垛', '/advisors/portraits/bogle.png', '/advisors/portraits/bogle.png', 5, 0, '{"schema_version":1,"card_id":"bogle","name":"博格","title":"博格 · 低成本指数与长期坚守思维框架卡","era":"现代（1929—2019）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"成本是确定的敌人","definition":"在充满不确定的回报里，\"成本\"是唯一确定、且必然侵蚀你收益的东西——把你能控制的成本压到最低，就锁定了一份确定的相对优势","source":"博格的低成本指数基金","source_tier":"primary","mechanism":"输入=只盯收益忽视成本 → 处理=把能控制的成本压到最低锁定确定的相对优势 → 输出=低成本锁优势(成本是敌人)","trigger":"面对不确定回报时","modern_transfer":"在充满不确定的回报里、''成本''是唯一确定、且必然侵蚀你收益的东西——把你能控制的成本(费用、摩擦、损耗)压到最低、就锁定了一份确定的相对优势(博格用低成本指数基金、靠省下的费用长期跑赢多数主动基金)","architecture":{"type":"flow","components":["别只盯收益忽视成本","成本是唯一确定且必然侵蚀收益的","把你能控制的成本压到最低","锁定一份确定的相对优势"]},"strategy_card_image":"kb-assets/bogle/model-1.png"},{"name":"买下整个草垛","definition":"与其费力去挑选少数\"赢家\"（而大概率挑错、还付高费用），不如直接\"买下整个草垛\"（指数化、分散持有全部），稳稳拿到整体的平均回报","source":"博格\"别找针、买下草垛\"","source_tier":"primary","mechanism":"输入=费力挑赢家大概率挑错还付高费 → 处理=直接买下整个市场稳拿平均回报 → 输出=平均赢过多数(买草垛)","trigger":"要配置投资时","modern_transfer":"与其费力去挑选少数''赢家''(而大概率挑错、还付高费用)、不如直接''买下整个草垛''(指数化、分散持有全部)、稳稳地拿到整体的平均回报——平均、往往就赢过了大多数主动选择(博格''别找针、买下草垛''的指数化)","architecture":{"type":"flow","components":["别费力挑赢家大概率挑错还付高费","不如直接买下整个草垛指数化","分散持有全部稳拿平均回报","平均往往就赢过大多数"]},"strategy_card_image":"kb-assets/bogle/model-2.png"},{"name":"长期复利与坚守","definition":"相信时间与复利的力量——买入并长期坚守，把投资期拉到足够长，不被短期的波动、噪音、择时的诱惑打乱节奏","source":"博格的长期持有","source_tier":"primary","mechanism":"输入=被短期波动择时诱惑打乱 → 处理=相信时间与复利买入并长期坚守 → 输出=时间是复利的朋友(长期坚守)","trigger":"投资期内、面对短期波动时","modern_transfer":"相信时间与复利的力量——买入并长期坚守、把投资期拉到足够长、不被短期的波动、噪音、择时的诱惑打乱节奏;时间是复利最好的朋友(博格的长期持有)","architecture":{"type":"hierarchy","components":["别被短期波动噪音择时诱惑打乱","相信时间与复利的力量","买入并长期坚守把投资期拉长","时间是复利最好的朋友"]},"strategy_card_image":"kb-assets/bogle/model-3.png"},{"name":"简单胜过复杂","definition":"在投资（及很多事）上，简单、朴素、透明、低成本的方案，长期往往胜过复杂、花哨、高费用的方案——复杂常常只是为高收费找的理由","source":"博格推崇指数化的简单","source_tier":"secondary","mechanism":"输入=追逐复杂花哨高费方案 → 处理=选简单朴素透明低成本的方案 → 输出=简单长期胜复杂(简单胜复杂)","trigger":"在方案间取舍时","modern_transfer":"在投资(及很多事)上、简单、朴素、透明、低成本的方案、长期往往胜过复杂、花哨、高费用的方案——复杂常常只是为高收费找的理由(博格推崇简单的指数化)","architecture":{"type":"flow","components":["别追逐复杂花哨高费方案","选简单朴素透明低成本的方案","长期往往胜过复杂高费的","复杂常常只是为高收费找的理由"]},"strategy_card_image":"kb-assets/bogle/model-4.png"},{"name":"把客户利益放第一","definition":"把你服务对象的真实利益，放在你自己牟利之前——设计真正对他们有利的东西，长期会赢得信任与口碑","source":"博格创Vanguard共同所有结构","source_tier":"primary","mechanism":"输入=为自己牟利设计产品 → 处理=设计真正对服务对象有利的东西 → 输出=赢得信任口碑(客户第一)","trigger":"设计产品/服务时","modern_transfer":"把你服务对象的真实利益、放在你自己牟利之前——设计真正对他们有利的东西、长期会赢得信任与口碑(博格把先锋设计成由基金持有人共同所有、把利润让给投资者)〔理想主义、也牺牲了自己致富、见盲区〕","architecture":{"type":"hierarchy","components":["别为自己牟利设计产品","把服务对象的真实利益放在自己牟利之前","设计真正对他们有利的东西","长期赢得信任与口碑"]},"strategy_card_image":"kb-assets/bogle/model-5.png"}],"decision_principles":["成本是唯一确定侵蚀收益的东西，把能控制的成本压到最低","别挑赢家（大概率挑错），直接''买下整个草垛''、拿市场平均回报","相信时间与复利、买入并长期坚守，别被短期波动与择时打乱","简单、朴素、低成本的方案，长期往往胜过复杂、高费的方案","把服务对象的真实利益放在自己牟利之前，长期赢得信任"],"inquiry_questions":["你是只盯收益、还是把能控制的''成本''压到了最低（成本是确定的敌人）？","你是费力挑''赢家''（大概率挑错）、还是直接''买下整个草垛''拿平均？","你是被短期波动/择时诱惑打乱、还是相信时间与复利、长期坚守？","你是追逐复杂花哨高费、还是选了简单、朴素、低成本的方案？","你是为自己牟利、还是把服务对象的真实利益放在了第一位？"],"value_priorities":["低成本锁优势 ＞ 只盯收益忽视成本（低成本指数基金）","买下整个草垛 ＞ 挑选赢家（别找针、买草垛）","客户利益第一 ＞ 为自己牟利（Vanguard共同所有）"],"blind_spots":["指数化放弃了''跑赢市场''的可能，只拿市场平均（接受''不输''而非''大赢''），对追求超额收益者不满足（原理推断，B）。","指数化在市场整体下跌时会完整地承受下跌，不做规避（原理推断，B）。","''简单低成本''对绝大多数普通投资者最优，但不适用于有真正信息/能力优势的少数专业者（原理推断，B）。","指数化若过度普及，也有人担忧其对市场价格发现、公司治理的影响（学术争议，B，客观点到）。"],"applicable_domains":["投资","认知偏误与理性决策"],"match_tags":["投资","认知偏误与理性决策","长期主义","概率思维","务实渐进","现当代北美"],"linked_cases":["bogle-c1","bogle-c2","bogle-c3","bogle-c4"],"life_tags":[{"tag":"创先锋集团","tier":"secondary"},{"tag":"创指数基金","tier":"secondary"},{"tag":"著基金常识","tier":"primary"},{"tag":"创共同所有制","tier":"secondary"}],"voice_profile":{"notes":"朴素笃实、为投资者代言；重成本与长期；崇尚简单；理想主义"},"references":[{"ref_id":"bogle-s1","title":"博格《共同基金常识》《长赢投资》及指数基金史","locator":"成本、买草垛、长期坚守、简单、客户第一","source_tier":"primary","supports_models":["成本是确定的敌人","买下整个草垛","长期复利与坚守","简单胜过复杂","把客户利益放第一"],"supports_cases":["bogle-c1","bogle-c2","bogle-c3","bogle-c4"],"note":"一手/二手·原著与投资史"},{"ref_id":"bogle-s2","title":"指数基金与被动投资研究","locator":"理念、先锋模式、指数化影响","source_tier":"secondary","supports_models":["成本是确定的敌人","买下整个草垛"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"成本是唯一确定侵蚀收益的东西把能控制的成本压到最低锁定确定的相对优势(成本是确定的敌人)；别挑赢家大概率挑错不如直接买下整个草垛拿市场平均回报(买下整个草垛)；相信时间与复利买入并长期坚守别被短期波动与择时打乱(长期复利与坚守)；简单朴素低成本的方案长期往往胜过复杂花哨高费的(简单胜过复杂)；把服务对象的真实利益放在自己牟利之前长期赢得信任(把客户利益放第一)","steps":[{"invoke":"成本是确定的敌人","action":"你是只盯收益、还是把能控制的''成本''压到了最低？"},{"invoke":"买下整个草垛","action":"你是费力挑''赢家''（大概率挑错）、还是直接''买下整个草垛''拿平均？"},{"invoke":"长期复利与坚守","action":"你是被短期波动/择时诱惑打乱、还是相信时间与复利、长期坚守？"},{"invoke":"简单胜过复杂","action":"你是追逐复杂花哨高费、还是选了简单、朴素、低成本的方案？"},{"invoke":"把客户利益放第一","action":"你是为自己牟利、还是把服务对象的真实利益放在了第一位？"}],"contrast":"与巴菲特不同(关键差异·主动vs被动)：**巴菲特是''主动''价值投资——靠能力圈、护城河精选少数好公司集中持有、力求跑赢市场**；**博格是''被动''指数投资——放弃选股、直接买下整个市场、靠低成本与时间稳拿平均、平均即赢过多数**——巴菲特力求''大赢''、博格力求''不输而稳胜大多数''(有趣的是巴菲特也建议普通人买指数)(见巴菲特卡)。与格雷厄姆不同：格雷厄姆主动地以安全边际买便宜的好资产;博格不挑、买全部(见格雷厄姆卡)。与利弗莫尔/索罗斯不同：他们是主动的投机/交易;博格是被动的长期持有——几乎是相反的哲学(见利弗莫尔/索罗斯卡)。【射程/盲区】博格之道在''成本是敌人、买草垛、长期坚守、简单胜复杂、客户第一''对绝大多数普通投资者极有价值(尤其低成本、长期、纪律)，但①指数化放弃了跑赢市场的可能、只拿平均、对追求超额收益者不满足;②市场整体下跌时会完整承受、不做规避;③简单低成本对多数人最优、但不适用于有真正信息/能力优势的少数专业者;④指数化若过度普及、也有人担忧其对市场价格发现、公司治理的影响、客观点到。适用投资/认知偏误与理性决策;不适用创作/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"bogle-c1","note":"用户''投资时只盯着追求高收益、却忽视了各种费用、手续费、税费对长期回报的持续侵蚀''时，以博格的低成本指数类比：他指出在不确定的收益里、''成本''是唯一确定、且必然侵蚀你回报的东西;他创立了低成本的指数基金、把费率压到极低、仅靠''省下的费用''这一项、长期就跑赢了大多数收费高昂的主动基金;把你能控制的成本(费用、摩擦)压到最低、就锁定了一份确定的相对优势（博格的低成本指数基金为投资史→确证）"},{"source":"case","case_id":"bogle-c2","note":"用户''总想费尽心力去挑选出那几只会大涨的''赢家''股票/基金、结果常常挑错、还交了高额费用''时，以博格''买下整个草垛''类比：他说''别在草垛里找那根针、直接买下整个草垛''——与其费力挑赢家(大概率挑错)、不如买下整个市场(指数)、稳稳拿到市场的平均回报;而历史证明、这个''平均''、长期就赢过了大多数主动选择;别挑赢家、直接买下整个草垛、拿到整体的平均回报（博格的指数化''买草垛''为投资史→确证）"}]},"further_reading":[{"title":"博格《共同基金常识》《长赢投资》及指数基金史","why":"成本、买草垛、长期坚守、简单、客户第一的出处（A/B）","type":"原著/投资史"},{"title":"指数基金与被动投资研究","why":"对博格理念、先锋模式与指数化影响（含争议）的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/bogle.png","avatar_thumb":"/advisors/portraits/bogle.png","domain":"投资","person_id":"P-bogle","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '12aa2d7d8bb828788e7b060113cd8fbdd416df203bef6228b89c6ef4745bc711', 6, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('bohr', 'P-bohr', '尼尔斯·玻尔', 'science', '玻尔 · 互补思维框架卡', '19—20世纪（1885—1962）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '互补原理 · 对应原理', '/advisors/portraits/bohr.png', '/advisors/portraits/bohr.png', 5, 0, '{"schema_version":1,"card_id":"bohr","name":"尼尔斯·玻尔","title":"玻尔 · 互补思维框架卡","era":"19—20世纪（1885—1962）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"互补原理","definition":"有些真相需要两套互斥的描述（如波与粒子）共同把握，别强求单一图景，并存两者","source":"1927科莫演讲","source_tier":"primary","mechanism":"输入=遇到两套互斥的描述、强求单一图景 → 处理=接受有些真相需两套互斥描述(波与粒)共同把握、并存两者 → 输出=并存对立的完整图景","trigger":"遇到非此即彼又都对的对立面时","modern_transfer":"有些真相需要两套互斥的描述(如波与粒子)共同把握——遇到''非此即彼又都对''的对立面、先别强行消解成单一答案，它可能本就需要两面并存(玻尔互补原理)","architecture":{"type":"flow","components":["遇到两套互斥的描述","别强求单一图景","接受两套描述共同把握","并存对立的完整图景"]},"strategy_card_image":"kb-assets/bohr/model-1.png"},{"name":"对应原理","definition":"新理论在旧理论管用的极限下，必须能还原出旧理论的结果，才算站得住","source":"玻尔原子模型相关论述","source_tier":"primary","mechanism":"输入=提出新框架、不检验与旧框架的衔接 → 处理=新理论在旧理论管用的极限下必须能还原出旧理论的结果 → 输出=新框架须能还原旧结果才站得住","trigger":"提出新框架/理论时","modern_transfer":"提出一个新框架时、先检验它在旧框架成立的范围里能不能还原出旧的结果——新理论必须在旧理论管用的极限下回到旧结论、才算站得住(玻尔对应原理)","architecture":{"type":"flow","components":["提出新框架","在旧框架成立的极限下","检验能否还原旧结果","还原得出才站得住"]},"strategy_card_image":"kb-assets/bohr/model-2.png"},{"name":"以对话异见为方法","definition":"把一个旗鼓相当的对手的反驳，当作磨利自己理解的引擎——深刻真理的反面可能是另一深刻真理","source":"玻尔-爱因斯坦论战；其研究所风格","source_tier":"secondary","mechanism":"输入=回避争论、求表面一致 → 处理=把一个旗鼓相当的对手的反驳当作磨利理解的引擎(深刻真理的反面可能是另一深刻真理) → 输出=以异见磨砺真理(玻尔-爱因斯坦论战)","trigger":"要深化对一个问题的理解时","modern_transfer":"主动找一个够强的反对者、把他的反驳当作磨利你理解的引擎——''一个深刻真理的反面、可能是另一个深刻真理''(玻尔与爱因斯坦数十年论战恰是其思想的磨刀石)","architecture":{"type":"flow","components":["别回避争论求表面一致","找一个旗鼓相当的对手","把反驳当磨利理解的引擎","以异见磨砺真理"]},"strategy_card_image":"kb-assets/bohr/model-3.png"},{"name":"观测与现象不可分","definition":"观测手段是现象的一部分，无法把\"被观测者\"与\"观测这一行为\"干净切开","source":"哥本哈根诠释相关论述","source_tier":"primary","mechanism":"输入=假装能客观旁观一个现象 → 处理=把''你如何观测/框定它''也算进现象本身、观测手段是现象的一部分 → 输出=诚实对待观测的介入(无法把被观测者与观测干净切开)","trigger":"评估一个现象、以为能客观旁观时","modern_transfer":"评估一个现象时、把''你如何观测/框定它''也算进现象本身——观测手段是现象的一部分、无法把''被观测者''与''观测这一行为''干净切开(玻尔:观测改变现象)","architecture":{"type":"hierarchy","components":["假装能客观旁观","把你如何观测框定算进现象","观测手段是现象的一部分","诚实对待观测的介入"]},"strategy_card_image":"kb-assets/bohr/model-4.png"},{"name":"汇聚共创","definition":"建一个平等、开放、汇聚才俊的环境，让突破在自由的碰撞与讨论中涌现，而非靠少数权威闭门定论","source":"玻尔的哥本哈根理论物理研究所","source_tier":"secondary","mechanism":"输入=靠少数权威闭门定论 → 处理=建一个平等开放、汇聚青年才俊的环境、让突破在自由碰撞中涌现 → 输出=在开放讨论中催生突破(哥本哈根精神)","trigger":"要催生持续的突破/创新时","modern_transfer":"建一个平等、开放、汇聚才俊的环境、让突破在自由的碰撞与讨论中涌现——而非靠少数权威闭门定论(玻尔的哥本哈根研究所聚集了一代量子物理学家)","architecture":{"type":"hierarchy","components":["别靠少数权威闭门定论","建平等开放的环境","汇聚青年才俊","让突破在碰撞中涌现"]},"strategy_card_image":"kb-assets/bohr/model-5.png"}],"decision_principles":["遇到非此即彼又都对的对立面，先别消解——它可能本就需要两面并存","提出新框架时，先检验它能否在旧框架成立的范围里还原出旧结果","主动找一个够强的反对者，把他的反驳当磨刀石","评估一个现象时，把''你如何观测/框定它''也算进现象本身","建一个平等开放、汇聚才俊的环境，让突破在碰撞中涌现"],"inquiry_questions":["你纠结的这两个对立答案，会不会其实都对、需要并存而非二选一？","你这个新看法，在老办法管用的地方，能不能还原出老办法的结论？","谁是这件事上最强的反对者？他的反驳里有什么是你必须吸收的？","你观测/框定这件事的方式，本身有没有改变你看到的东西？","你是靠少数人闭门定论，还是建了一个让才俊自由碰撞、催生突破的环境？"],"value_priorities":["并存对立的完整图景 ＞ 强行统一成单一答案（波/粒并存才是完整的量子图景）","以异见磨砺真理 ＞ 回避争论求表面一致（与爱因斯坦数十年论战恰是其思想的磨刀石）","诚实对待观测的介入 ＞ 假装能客观旁观（观测改变现象、这本身要被算进去）"],"blind_spots":["表达极度晦涩：思想深刻但行文与口述含糊难懂，常需他人转译（同行普遍评价，B）。","哥本哈根诠释滋生''闭嘴算就行''倾向，可能压抑了对量子''究竟在发生什么''的更深追问数十年（学术分析，B）。","互补原理被他过度外推到生物、心理、文化等域，常流于含糊、难以证伪（学术分析，B）。","其权威与哥本哈根正统，或在一段时期边缘化了玻姆、艾弗雷特等替代诠释（学术史，B）。"],"applicable_domains":["创新研发","探索未知","认知偏误与理性决策"],"match_tags":["创新研发","探索未知","认知偏误与理性决策","批判思辨","多元模型","对抗性思维","现当代欧洲"],"linked_cases":["bohr-c1","bohr-c2","bohr-c3","bohr-c4"],"life_tags":[{"tag":"提玻尔模型","tier":"primary"},{"tag":"创哥本哈根派","tier":"secondary"},{"tag":"获诺贝尔奖","tier":"secondary"},{"tag":"提互补原理","tier":"primary"}],"voice_profile":{"notes":"迂回、反复修正措辞；爱用悖论式表述；温和但坚持；重对话与共识"},"references":[{"ref_id":"bohr-s1","title":"玻尔1927科莫演讲及哥本哈根诠释论述","locator":"互补原理、观测与现象不可分（含1935 EPR回应）","source_tier":"primary","supports_models":["互补原理","观测与现象不可分"],"supports_cases":["bohr-c1"],"note":"一手·演讲/论述"},{"ref_id":"bohr-s2","title":"玻尔原子模型/量子-经典对应论述","locator":"对应原理","source_tier":"primary","supports_models":["对应原理"],"supports_cases":["bohr-c2"],"note":"一手·论述（确切出处待核）"},{"ref_id":"bohr-s3","title":"Pais《Niels Bohr''s Times》及科学史","locator":"玻尔-爱因斯坦论战、哥本哈根研究所","source_tier":"secondary","supports_models":["以对话异见为方法","汇聚共创"],"supports_cases":["bohr-c3","bohr-c4"],"note":"二手·权威传记/科学史"}],"material_type":"rich","reasoning_skeleton":{"signature":"遇到非此即彼又都对的对立面先别消解、它可能本就需两面并存(互补原理)；新框架须在旧框架成立处还原出旧结果才站得住(对应原理)；主动找够强的反对者、把反驳当磨刀石(以对话异见为方法)；把你如何观测/框定它也算进现象本身(观测与现象不可分)；建平等开放汇聚才俊的环境、让突破在碰撞中涌现(汇聚共创)","steps":[{"invoke":"互补原理","action":"你纠结的这两个对立答案，会不会其实都对、需要并存而非二选一？"},{"invoke":"对应原理","action":"你这个新看法，在老办法管用的地方，能不能还原出老办法的结论？"},{"invoke":"以对话异见为方法","action":"谁是这件事上最强的反对者？他的反驳里有什么是你必须吸收的？"},{"invoke":"观测与现象不可分","action":"你观测/框定这件事的方式，本身有没有改变你看到的东西？"},{"invoke":"汇聚共创","action":"你是靠少数人闭门定论，还是建了一个让才俊自由碰撞、催生突破的环境？"}],"contrast":"与爱因斯坦不同(关键差异·量子论的著名论战双方)：**爱因斯坦坚持''上帝不掷骰子''、追问背后是否有更完整的确定性图景(质疑量子的诡异)**；**玻尔以互补原理接受量子的反直觉、主张波/粒并存、观测与现象不可分**——爱因斯坦求底层的确定、玻尔接受互补的并存(见爱因斯坦卡)；二人数十年论战恰是玻尔''以对话异见为方法''的最佳例证。与牛顿不同：牛顿求''同一规律统摄''的确定演绎；玻尔接受''互补对立的并存''(见牛顿卡)。与图灵/费曼区分：图灵化归机械步骤、费曼重直觉图像；玻尔=互补+以异见磨真理。【射程/盲区】玻尔之道在''接受互补对立、新旧对应、以异见磨真理、诚实对待观测''极有力，但①表达极度晦涩、思想深刻但行文口述含糊难懂、常需他人转译；②哥本哈根诠释滋生''闭嘴算就行''倾向、可能压抑了对量子''究竟在发生什么''的更深追问；③互补原理被他过度外推到生物/心理/文化等域、常流于含糊难证伪；④其权威与哥本哈根正统、或在一段时期边缘化了玻姆/艾弗雷特等替代诠释。适用创新研发/探索未知/认知偏误与理性决策；不适用表达说服/危机应对/创业。"},"persona_anchor":{"primary":[{"source":"case","case_id":"bohr-c1","note":"用户''在两个互斥、却又都说得通的答案间二选一、怎么也消解不掉''时，以玻尔互补原理类比：光既是波、又是粒子——这两套互斥的描述不是要二选一、而是要并存才构成完整的量子图景；有些''非此即彼又都对''的对立、本就需要两面并存(互补原理为玻尔1927科莫演讲提出→确证)"},{"source":"case","case_id":"bohr-c3","note":"用户''回避争论、只想找认同''时，以玻尔-爱因斯坦论战类比：玻尔把爱因斯坦这位最强对手数十年的反驳、当作磨利自己理解的引擎——''一个深刻真理的反面可能是另一个深刻真理''；主动找够强的反对者、把反驳当磨刀石(玻尔-爱因斯坦论战为科学史所载→确证)"}]},"further_reading":[{"title":"玻尔1927科莫演讲及哥本哈根诠释论述","why":"互补原理、观测与现象不可分的一手出处（A）","type":"原著/演讲"},{"title":"Abraham Pais《Niels Bohr''s Times》","why":"玻尔-爱因斯坦论战、哥本哈根研究所风格的权威传记（B）","type":"biography"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/bohr.png","avatar_thumb":"/advisors/portraits/bohr.png","domain":"科学","person_id":"P-bohr","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'ff52c9b6e362205657550f78a5442b259fa010f7d2d48c0b19cb4897deb24596', 7, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('buffett', 'P-buffett', '沃伦·巴菲特', 'business', '沃伦·巴菲特 · 价值投资与资本配置思维框架卡', '20–21世纪（1930– ）', 'zh-CN', 'published', 'in_review', 'pending', 'living', 'rich', '能力圈 · 经济护城河', '/advisors/portraits/buffett.png', '/advisors/portraits/buffett.png', 5, 0, '{"schema_version":1,"card_id":"buffett","name":"沃伦·巴菲特","title":"沃伦·巴菲特 · 价值投资与资本配置思维框架卡","era":"20–21世纪（1930– ）","language":"zh-CN","status":"published","living_status":"living","core_models":[{"name":"能力圈","definition":"只在自己真正理解的生意里投资；圈多大不重要，清楚边界在哪、不越界最重要","source":"伯克希尔致股东信","source_tier":"primary","mechanism":"输入=一个投资机会 → 处理=判断它是否落在自己真正理解的生意范围内、清楚边界在哪不越界 → 输出=圈内可投/圈外放过","trigger":"面对一个诱人、但可能并不真懂的机会时","modern_transfer":"做任何决策先划定''我真懂的范围''，看不懂一律放过——圈多大不重要，知道边界在哪、不越界最重要","architecture":{"type":"hierarchy","components":["识别机会","判定是否在能力圈内","守住边界","圈内投/圈外弃"]},"strategy_card_image":"kb-assets/buffett/model-1.png"},{"name":"经济护城河","definition":"优先买有持久竞争优势（品牌/成本/网络/转换成本）的好生意，护城河护住长期资本回报","source":"伯克希尔致股东信","source_tier":"primary","mechanism":"输入=一门生意 → 处理=评估有无持久竞争优势（品牌/成本/网络/转换成本）护住长期资本回报 → 输出=有无护城河及其宽度","trigger":"判断一门生意能不能长期赚钱时","modern_transfer":"买公司或选赛道先问''谁能轻易把它打垮''——有没有护城河护住长期回报，比当下利润更重要","architecture":{"type":"matrix","components":["识别生意","查竞争优势类型","评估持久性","定护城河宽度"]},"strategy_card_image":"kb-assets/buffett/model-2.png"},{"name":"好生意合理价","definition":"宁以合理价买卓越生意，胜过便宜价买平庸生意——优质企业复利远超账面便宜（受芒格影响）","source":"伯克希尔致股东信","source_tier":"primary","mechanism":"输入=一个标的 → 处理=权衡''卓越生意+合理价''与''平庸生意+便宜价''，按长期复利择优 → 输出=宁以合理价买卓越","trigger":"在''贵但好''与''便宜但平庸''之间取舍时","modern_transfer":"宁以合理价买伟大企业、不贪便宜买平庸——优质企业的复利远超账面上的便宜","architecture":{"type":"matrix","components":["列出标的","评生意质量","算长期复利","择卓越而非便宜"]},"strategy_card_image":"kb-assets/buffett/model-3.png"},{"name":"浮存金与配置","definition":"用保险浮存金作低成本长期资金；管理者头等工作是把留存资本配置到回报最高处","source":"伯克希尔致股东信","source_tier":"primary","mechanism":"输入=可用资本/留存收益 → 处理=找到低成本长期资金（如保险浮存金）、把每一元配置到回报最高处 → 输出=高回报的资本配置","trigger":"手握可配置资本、要决定钱往哪放时","modern_transfer":"真正的杠杆不一定是借债——找到能持续、低成本占用的资金结构，再把它配置到回报最高处","architecture":{"type":"flow","components":["获取低成本长期资金","盘点可配置资本","比较各处回报","配置到最高处"]},"strategy_card_image":"kb-assets/buffett/model-4.png"},{"name":"贪婪恐惧反向","definition":"别人恐惧时贪婪、别人狂热时恐惧；情绪稳定的气质比高智商更决定投资成败","source":"致股东信与合伙人信","source_tier":"primary","mechanism":"输入=市场情绪极端的时刻 → 处理=判断是恐慌还是狂热、与群体情绪反向、靠稳定气质压住冲动 → 输出=别人恐惧时贪婪/别人狂热时恐惧","trigger":"市场极度恐慌或极度狂热时","modern_transfer":"别人恐惧时贪婪、别人狂热时恐惧；情绪稳定的气质比高智商更决定投资成败","architecture":{"type":"loop","components":["感知市场情绪","判恐慌/狂热","与群体反向","靠气质守住"]},"strategy_card_image":"kb-assets/buffett/model-5.png"}],"decision_principles":["待在能力圈内，看不懂的一律放过（A）","宁以合理价买伟大企业，不贪便宜买平庸（A）","别人恐惧时贪婪，别人贪婪时恐惧（A）","把留存收益配置到每一元能创造最高价值处（A）","找到伟大企业就长期持有、少动手（A）","护城河和管理层比当下利润更重要（A）"],"inquiry_questions":["这门生意你真的看得懂吗？十年后它还在赚钱吗？","它的护城河是什么？谁能轻易把它打垮？","现在是市场恐慌还是狂热？你是被情绪带着走吗？","管理层把赚来的钱配置得明智吗，是否为股东着想？"],"value_priorities":["生意质量与护城河 ＞ 账面便宜（与格雷厄姆分野：宁买好生意）","长期持有复利 ＞ 频繁交易（时间是好生意的朋友）","稳定的气质 ＞ 高智商与精算（投资成败更取决于情绪自控）","能力圈内的确定性 ＞ 圈外诱人的机会（看不懂就放过）"],"blind_spots":["情绪化赌气决策代价极大——接管伯克希尔纺织是其自认最大错误，机会成本以千亿计（史实，A/B）","长期回避科技与不懂的行业，错过不少大赢家，苹果是迟来的例外（公开言论，A）","支付方式的代价也会失手——以股票收购Dexter Shoe几近全损，自认重大错误（公开言论，A）"],"applicable_domains":["投资","商业模式与护城河","长期规划","风险评估","组织管理"],"match_tags":["投资","商业模式与护城河","长期规划","长期主义","风险规避","概率思维","现当代北美"],"linked_cases":["buffett-c1","buffett-c2","buffett-c3","buffett-c4","buffett-c5"],"life_tags":[{"tag":"接掌伯克希尔","tier":"secondary"},{"tag":"与芒格搭档","tier":"secondary"},{"tag":"捐股盖茨基金","tier":"secondary"},{"tag":"年撰股东信","tier":"primary"}],"voice_profile":{"notes":"亲民幽默、爱用类比；故事化讲道理；自嘲、肯认错"},"references":[{"ref_id":"buffett-s1","title":"伯克希尔·哈撒韦致股东信（历年）","locator":"能力圈/护城河/浮存金/资本配置/See''s等论述；具体年份篇目待核验","source_tier":"primary","supports_models":["能力圈","经济护城河","好生意合理价","浮存金与配置","贪婪恐惧反向"],"supports_cases":["buffett-c3","buffett-c5"],"note":"本人执笔一手；具体年份待质检者定位"},{"ref_id":"buffett-s2","title":"巴菲特合伙人信（1957–1970）","locator":"1968年信论及单笔40%上限的投资","source_tier":"primary","supports_cases":["buffett-c1"],"note":"本人执笔一手"},{"ref_id":"buffett-s3","title":"巴菲特公开访谈（CNBC等，含''最大错误''自述）","locator":"关于伯克希尔纺织的访谈段落待核验","source_tier":"primary","supports_cases":["buffett-c2"],"note":"本人自述''愚蠢至极''与机会成本估算"},{"ref_id":"buffett-s4","title":"洛温斯坦《巴菲特传》/施罗德《滚雪球》","locator":"伯克希尔接管相关章节；页码待核验","source_tier":"secondary","supports_cases":["buffett-c2"],"note":"第三方传记交叉印证赌气接管经过"},{"ref_id":"buffett-s5","title":"2008《纽约时报》''Buy American. I Am.''评论及危机交易公开记录","locator":"2008-10-16评论；高盛/GE优先股公告","source_tier":"primary","supports_cases":["buffett-c4"],"note":"本人署名评论 + 公开交易披露"}],"material_type":"rich","reasoning_skeleton":{"signature":"只在看得懂的生意里、用合理价买有护城河的好公司，然后靠稳定气质长期持有——别人恐惧时贪婪","steps":[{"invoke":"能力圈","action":"先问''这门生意我真看得懂吗、十年后它还在赚钱吗''，看不懂一律放过"},{"invoke":"经济护城河","action":"看它有没有持久竞争优势（品牌/成本/网络/转换成本）护住长期回报，谁能轻易打垮它"},{"invoke":"好生意合理价","action":"宁以合理价买卓越生意、不贪便宜买平庸，算的是长期复利"},{"invoke":"贪婪恐惧反向","action":"判断当下是市场恐慌还是狂热，别被情绪带走、与群体反向"},{"invoke":"浮存金与配置","action":"把留存/可用资本配置到每一元回报最高处"}],"contrast":"与芒格相反（搭档、思维高度重合但分工不同）：芒格用跨学科多元格栅 + 误判心理学先排错、先看人性误判；巴菲特重心是能力圈 + 护城河 + 保险浮存金资本配置 + 稳定气质，更聚焦''生意质量''本身（见芒格卡）。与格雷厄姆分野（其师）：格雷厄姆''便宜价买平庸/烟蒂股 + 安全边际''；巴菲特''合理价买卓越''——好生意的复利胜过账面便宜（见格雷厄姆卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"buffett-c1","note":"用户''市场因一次性丑闻恐慌、核心特许权未损、要不要抄底''时，以美国运通色拉油案类比：他实地确认顾客仍照常用卡、判断恐慌过度，重仓至组合40%上限（一手/确证，1968 合伙人信）"},{"source":"case","case_id":"buffett-c2","note":"用户''被对方激怒、想赌气还击''时，以伯克希尔纺织赌气接管类比（反面镜子）：他因 CEO''砍了八分之一''恼火、出于赌气夺取控制权、把资本套进夕阳产业，自认最大错误、机会成本约 2000 亿——别让情绪羞辱替你配置资本（确证）"}]},"further_reading":[{"title":"伯克希尔·哈撒韦致股东信（历年）","why":"他本人执笔的一手材料，能力圈/护城河/浮存金/资本配置思想的总集，逐年读如上一堂投资课","type":"original"},{"title":"艾丽斯·施罗德《滚雪球：巴菲特和他的财富人生》","why":"唯一授权传记，看其决策（含赌气接管纺织厂这类错误）的完整脉络与性格","type":"biography"},{"title":"《巴菲特致股东的信》（坎宁安编·主题整理本）","why":"把历年股东信按主题（公司治理/投资/会计）重编，比逐年读更快抓到框架","type":"解读"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/buffett.png","avatar_thumb":"/advisors/portraits/buffett.png","domain":"商业","person_id":"P-buffett","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '734742f83dad0e4f520e0583c55cbcde172db39b5a7f66592ec4318908194fe5', 8, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('caesar', 'P-caesar', '凯撒', 'strategy', '凯撒 · 军政决断思维框架卡', '公元前1世纪（前100—前44）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '速度即战力 · 宽恕政策', '/advisors/portraits/caesar.png', '/advisors/portraits/caesar.png', 5, 0, '{"schema_version":1,"card_id":"caesar","name":"凯撒","title":"凯撒 · 军政决断思维框架卡","era":"公元前1世纪（前100—前44）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"速度即战力","definition":"以超出对手预期的行军与决断速度制造既成事实，让对方来不及反应或集结；快是一种独立的力量","source":"《高卢战记》多次以急行军奇袭制胜；古典史家(苏维托尼乌斯/普鲁塔克)记其神速","source_tier":"primary","mechanism":"输入=一个对抗局面 → 处理=以超出对手预期的行军/决断速度制造既成事实、让对方来不及反应或集结 → 输出=以快制胜","trigger":"对手未集结、或你在等''万全''时","modern_transfer":"别等万全——用超出对手预期的速度直接动手，让对方来不及反应或集结，快本身是一种力量","architecture":{"type":"flow","components":["判断对手反应速度","抢在其集结前","高速决断与行动","制造既成事实"]},"strategy_card_image":"kb-assets/caesar/model-1.png"},{"name":"宽恕政策","definition":"对败者与政敌不滥杀、予以宽赦收编，用宽容换取归附与名声，把敌人变成资源而非死结","source":"内战中对庞培派多行宽赦(clementia Caesaris)，古典史家记载","source_tier":"secondary","mechanism":"输入=如何处置败者/政敌 → 处理=不滥杀、予宽赦收编、用宽容换归附与名声 → 输出=把敌人变资源（但留反噬隐患）","trigger":"胜后处置降者/政敌时","modern_transfer":"宽待败者能把敌人转为资源、赢人心，但别误以为宽赦等于安全——它降低对抗、却不消除根本利益冲突","architecture":{"type":"matrix","components":["面对败者","评斩杀/压垮/宽赦收编","以宽容换归附","警惕被赦者反噬"]},"strategy_card_image":"kb-assets/caesar/model-2.png"},{"name":"亲临一线","definition":"主将不居后方，关键时刻亲赴最危处、与士卒同险，用在场点燃士气、扭转濒溃之局","source":"《高卢战记》自述危局亲上前线(如阿莱西亚、对纳尔维人之战)","source_tier":"primary","mechanism":"输入=一个濒溃/最险的关键时刻 → 处理=主将亲赴最危处、与士卒同险、用在场点燃士气 → 输出=扭转濒溃之局","trigger":"局面濒溃、士气动摇、你想在后方遥控时","modern_transfer":"最难最险的事别在后方遥控，主将到场、与人同险，用在场稳住人心","architecture":{"type":"flow","components":["识别最危处","主将亲临","与士卒同险","在场点燃士气"]},"strategy_card_image":"kb-assets/caesar/model-3.png"},{"name":"制造既成事实","definition":"在对手与制度反应过来前用一个不可逆动作改写局面，逼各方接受新现实；先斩后奏夺主动","source":"渡卢比孔河进军罗马(\"骰子已掷\")","source_tier":"secondary","mechanism":"输入=一个僵局（只剩坏选项）→ 处理=在对手与制度反应过来前用一个不可逆动作改写局面、逼各方接受新现实 → 输出=夺回主动（须认下全部代价）","trigger":"僵局只剩两个坏选项、需夺主动时","modern_transfer":"僵局只剩坏选项时，一个一旦做出就不可逆的动作能夺回主动——但你要认下它的全部代价","architecture":{"type":"flow","components":["识别僵局","找不可逆动作","抢在反应前执行","逼各方接受新局"]},"strategy_card_image":"kb-assets/caesar/model-4.png"},{"name":"笔即第二战场","definition":"用自己撰写的战报/叙事掌控公众认知，把军事行动同时经营成政治资本；谁定义事实谁占先","source":"凯撒亲撰《高卢战记》《内战记》本身即政治传播工具","source_tier":"primary","mechanism":"输入=一次行动 → 处理=用自己撰写的战报/叙事掌控公众认知、把军事行动同时经营成政治资本 → 输出=谁定义事实谁占先","trigger":"行动的意义会被别人定义时","modern_transfer":"这件事的''战报''谁来写？主动替自己定义事实与意义，掌握叙事即掌握资本","architecture":{"type":"flow","components":["完成一次行动","自己撰写战报/叙事","掌控公众认知","转成政治资本"]},"strategy_card_image":"kb-assets/caesar/model-5.png"}],"decision_principles":["兵贵神速：以速度抢在对手集结之前制造既成事实（《高卢战记》，A）","胜后宽赦：对败者予生路以换归附，少结死敌（内战宽赦政策，B）","危局亲临：最险处主将到场，以在场稳军心（《高卢战记》，A）","果断越界：必要时先斩后奏、以不可逆动作夺主动（渡卢比孔，B）","自己书写自己的战绩：掌握叙事即掌握政治资本（亲撰战记，A）"],"inquiry_questions":["你是不是在等''万全''？如果用三倍于对手预期的速度直接动手，会不会反而赢？","对那个挡你路的人，杀掉、压垮、还是宽赦收编——哪种最划算？","这件最难最险的事，你是在后方遥控，还是该亲自到场？","有没有一个一旦做出就不可逆、逼所有人接受新局面的动作？代价你认吗？","这件事的''战报''谁来写？你有没有在替自己定义这件事的意义？"],"value_priorities":["速度与主动 ＞ 万全准备（抢在对手反应前制造既成事实，胜过等齐条件）","宽赦收编 ＞ 斩草除根（把败者变资源而非死结(但也埋下被宽赦者行刺的反噬)）","个人权位与历史地位 ＞ 既有共和体制规则（为此不惜渡卢比孔——成就其霸业，也招致刺杀）","掌控叙事 ＞ 任人评说（自己写战记，主动定义事实）"],"blind_spots":["为个人权位践踏共和制度边界，触怒元老集团、终被刺杀——其''制造既成事实''与越界果断的另一面是合法性透支（史实，B）","宽恕政策被对手利用：多名被他宽赦者参与了刺杀(如布鲁图斯)，宽赦换不来绝对安全（史实，B）","自述史料(《高卢战记》《内战记》)有强政治宣传性、自我美化与择取性，其''战绩与动机''不可全盘当客观史实（史料批判，A/B）","高度依赖个人威望与亲征，权力与体系绑在一人身上，本人一死则局面剧变（史实推断，B）"],"applicable_domains":["战略","领导力","危机应对","竞争博弈"],"match_tags":["战略","领导力","危机应对","竞争博弈","直觉决断","对抗性思维","古代欧洲"],"linked_cases":["caesar-c1","caesar-c2","caesar-c3","caesar-c4"],"life_tags":[{"tag":"征服高卢","tier":"secondary"},{"tag":"著高卢战记","tier":"primary"},{"tag":"遇刺身亡","tier":"secondary"},{"tag":"改革儒略历","tier":"secondary"}],"voice_profile":{"notes":"第三人称自述；简洁明快的战报体；择取性叙事；格言式断语(骰子已掷)"},"references":[{"ref_id":"caesar-s1","title":"《高卢战记》(凯撒亲撰)","locator":"卷一至卷七急行军/奇袭；卷二纳尔维之战、卷七阿莱西亚亲临前线段","source_tier":"primary","supports_models":["速度即战力","亲临一线","笔即第二战场"],"supports_cases":["caesar-c2"],"note":"一手但属自述/政治宣传，含自我美化择取性，相关historicity判存疑"},{"ref_id":"caesar-s2","title":"《内战记》(凯撒亲撰)","locator":"内战叙事与宽赦自述","source_tier":"primary","supports_models":["笔即第二战场"],"note":"一手自述，政治宣传性"},{"ref_id":"caesar-s3","title":"苏维托尼乌斯《罗马十二帝王传·神圣的尤利乌斯》","locator":"论其神速；渡卢比孔\"alea iacta est\"；遇刺","source_tier":"secondary","supports_models":["速度即战力","制造既成事实"],"supports_cases":["caesar-c1","caesar-c4"],"note":"后世二手史家，金句细节有文学加工"},{"ref_id":"caesar-s4","title":"普鲁塔克《凯撒传》","locator":"渡卢比孔、宽赦政策、遇刺","source_tier":"secondary","supports_models":["宽恕政策","制造既成事实"],"supports_cases":["caesar-c1","caesar-c3","caesar-c4"],"note":"后世二手史家，多源交叉"},{"ref_id":"caesar-s5","title":"阿庇安《罗马史·内战卷》","locator":"内战与遇刺记载","source_tier":"secondary","supports_cases":["caesar-c4"],"note":"二手史家，交叉印证刺杀"}],"material_type":"rich","reasoning_skeleton":{"signature":"别等万全、用超出对手预期的速度制造既成事实；最险处主将亲临、胜后宽赦把败者变资源；必要时用一个不可逆动作夺主动，并自己书写自己的战报","steps":[{"invoke":"速度即战力","action":"先别等''万全''，评估能否用超出对手预期的速度直接动手、抢在其集结之前"},{"invoke":"制造既成事实","action":"僵局只剩坏选项时，找一个一旦做出就不可逆、逼各方接受新局面的动作（认下代价）"},{"invoke":"亲临一线","action":"最难最险处主将亲自到场、与人同险，用在场稳住人心"},{"invoke":"宽恕政策","action":"胜后对败者予生路、宽赦收编换归附，但别误以为宽赦＝安全"},{"invoke":"笔即第二战场","action":"自己书写自己的战报、主动定义这件事的意义，掌握叙事即掌握资本"}],"contrast":"与拿破仑相近又不同（同重速度/集中/亲征/造神）：拿破仑更倚炮兵集中、军团体系与会战决战；凯撒更倚''宽赦（clementia）''与''亲撰战报''经营合法性与人心（见拿破仑卡）。与孙子/克劳塞维茨不同：孙子慎战避战、克氏重政治目的与摩擦；凯撒是极具个人英雄主义与政治算计的主动夺势派，重制造既成事实而非克制（见孙子卡/克劳塞维茨卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"caesar-c1","note":"用户''僵局只剩两个坏选项、要不要走那一步不可逆的棋''时，以渡卢比孔河进军罗马类比：元老院命他交兵权否则为公敌，他率军渡过法定边界、以不可逆的既成事实逼摊牌——一个不可逆动作能夺回主动，但要认下全部代价（渡河进军为信史；''骰子已掷''金句系后世史家文学加工，呈现须区分史实与传为其言）"},{"source":"case","case_id":"caesar-c4","note":"用户''我威望正盛、是不是可以无视那些警告''时，以遇刺于元老院类比（反面镜子）：他把合法性透支到极限、又解散私人卫队、过度自信于威望与宽赦所积的人心，终被共和派刺杀——成就你的特质过头即是杀你的特质（多源确证）"}]},"further_reading":[{"title":"凯撒《高卢战记》(Commentarii de Bello Gallico)","why":"他本人的战报体一手，速度/亲临/自撰战报的直接体现；但强政治宣传性，宜配外部史家对照读","type":"original"},{"title":"普鲁塔克《希腊罗马名人传·凯撒》","why":"后世史家的二手记述，渡卢比孔、宽赦、遇刺多源交叉，平衡凯撒自述的美化","type":"biography"},{"title":"阿德里安·戈兹沃西《凯撒：巨人的一生》","why":"现代权威传记，史料批判清晰，帮你区分史实与传说（如''骰子已掷''）","type":"biography"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/caesar.png","avatar_thumb":"/advisors/portraits/caesar.png","domain":"战略","person_id":"P-caesar","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '5224386d31fcc03ee1f42e7121799ecfbf10057c6bf0539880f8674a8bd1c890', 9, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('caocao', 'P-caocao', '曹操', 'strategy', '曹操 · 唯才是举与军政经一体思维框架卡', '汉末三国（155—220）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '唯才是举不拘品行 · 兵无常势因敌制胜', '/advisors/portraits/caocao.png', '/advisors/portraits/caocao.png', 5, 0, '{"schema_version":1,"card_id":"caocao","name":"曹操","title":"曹操 · 唯才是举与军政经一体思维框架卡","era":"汉末三国（155—220）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"唯才是举不拘品行","definition":"用人不拘出身、资历、甚至品行的瑕疵——只要他有真本事、能办成事，就大胆用","source":"曹操《求贤令》","source_tier":"primary","mechanism":"输入=用人看出身资历品行名节 → 处理=只看才能、不拘出身品行瑕疵、能办事就用 → 输出=能办事的人都用起来(唯才是举)","trigger":"用人、面对有才但有瑕疵的人时","modern_transfer":"用人不拘出身、资历、甚至品行的瑕疵——只要他有真本事、能办成事、就大胆用(''唯才是举''、曹操连发求贤令)〔但只看才不看德、也有隐患、见盲区〕","architecture":{"type":"flow","components":["别用人看出身资历品行名节","只看才能不拘出身品行瑕疵","能办成事就大胆用","能办事的人都用起来"]},"strategy_card_image":"kb-assets/caocao/model-1.png"},{"name":"兵无常势因敌制胜","definition":"没有放之四海皆准的固定套路——根据具体的、变化的形势随机应变，因敌（因势）制胜","source":"曹操注《孙子兵法》","source_tier":"primary","mechanism":"输入=套用固定的套路 → 处理=根据具体变化的形势随机应变、因敌(因势)制胜 → 输出=因势制胜(兵无常势)","trigger":"面对变化的形势时","modern_transfer":"没有放之四海皆准的固定套路——根据具体的、变化的形势随机应变、因敌(因势)制胜(''兵无常势''、曹操深谙并注释《孙子兵法》)","architecture":{"type":"flow","components":["别套用固定的套路","根据具体变化的形势","随机应变","因敌因势制胜"]},"strategy_card_image":"kb-assets/caocao/model-2.png"},{"name":"屯田固本","definition":"别只顾打仗/扩张、忽视了经济与后勤的根基——以\"屯田\"式的办法夯实你的资源、粮草、现金流基础，根基稳了才能持久","source":"曹操推行屯田","source_tier":"secondary","mechanism":"输入=只顾打仗扩张、忽视经济后勤根基 → 处理=以屯田夯实资源粮草现金流的根基 → 输出=根基稳了才能持久(屯田固本)","trigger":"要打持久战/可持续发展时","modern_transfer":"别只顾打仗/扩张、忽视了经济与后勤的根基——以''屯田''式的办法夯实你的资源、粮草、现金流基础、根基稳了才能持久(曹操推行屯田、解决军粮)","architecture":{"type":"hierarchy","components":["别只顾打仗扩张忽视经济后勤根基","以屯田式的办法","夯实资源粮草现金流基础","根基稳了才能持久"]},"strategy_card_image":"kb-assets/caocao/model-3.png"},{"name":"挟天子以令诸侯","definition":"抢占道义、法理或\"正统\"的制高点，借一个被广泛承认的名义去行事，使自己师出有名、占据主动","source":"曹操挟天子以令诸侯","source_tier":"secondary","mechanism":"输入=师出无名、无道义制高点 → 处理=抢占道义法理正统的制高点、借被广泛承认的名义行事 → 输出=师出有名占据主动(挟天子)","trigger":"要在博弈中占据道义/法理主动时","modern_transfer":"抢占道义、法理或''正统''的制高点、借一个被广泛承认的名义去行事、使自己师出有名、占据主动(''挟天子以令诸侯''、曹操)〔权谋色彩重、客观看待、见盲区〕","architecture":{"type":"flow","components":["别师出无名无道义制高点","抢占道义法理正统的制高点","借被广泛承认的名义行事","师出有名占据主动"]},"strategy_card_image":"kb-assets/caocao/model-4.png"},{"name":"赏罚分明令行禁止","definition":"以严明的法度、赏罚分明来治理，规则面前（包括自己）一视同仁、令行禁止","source":"曹操割发代首","source_tier":"secondary","mechanism":"输入=规则因人而异、自己不守 → 处理=以严明法度赏罚分明治理、规则面前(含自己)一视同仁 → 输出=令行禁止(赏罚分明)","trigger":"要立威信、令行禁止时","modern_transfer":"以严明的法度、赏罚分明来治理、规则面前(包括自己)一视同仁、令行禁止(曹操''割发代首''、自罚以明法)","architecture":{"type":"hierarchy","components":["别规则因人而异自己不守","以严明法度赏罚分明治理","规则面前包括自己一视同仁","令行禁止"]},"strategy_card_image":"kb-assets/caocao/model-5.png"}],"decision_principles":["用人不拘出身与品行瑕疵，只要有真本事、能办成事就大胆用（但防只看才不看德）","没有固定套路，根据变化的形势随机应变、因势制胜","别只顾扩张，以屯田式办法夯实资源、现金流的根基","抢占道义、法理、正统的制高点，使自己师出有名（权谋色彩重）","以严明法度、赏罚分明治理，规则面前包括自己一视同仁"],"inquiry_questions":["你用人是看出身、品行名节、还是看他有没有真本事、能不能办成事？","你是套用固定套路、还是根据变化的形势随机应变、因势制胜？","你是只顾打仗/扩张、还是也以屯田式办法夯实了资源与根基？","你在博弈中是师出无名、还是抢占了道义/法理/正统的制高点？","你的赏罚是因人而异、还是严明、一视同仁（包括自己）？"],"value_priorities":["能办成事的真才 ＞ 看出身品行名节（唯才是举（但防只看才不看德））","屯田固本的持久 ＞ 忽视根基的扩张（屯田解决军粮）","占据正当性的主动 ＞ 师出无名（挟天子以令诸侯（权谋色彩重））"],"blind_spots":["''唯才是举''只看才不看德、用了一些品行有亏的人，也埋下隐患（史/原理，B）。","曹操多疑猜忌、''宁我负人毋人负天下人''的权谋与冷酷、滥杀（如孔融、华佗等）有严重争议（史，B，客观标注）。","''挟天子''等权谋手段在道德/法统上历来有争议，其''奸雄''之名毁誉参半（史，B，客观标注）。","其个人色彩极强，成功也依赖其雄才大略，难以简单复制（原理推断，B）。"],"applicable_domains":["组织管理","竞争博弈","危机应对"],"match_tags":["组织管理","竞争博弈","危机应对","务实渐进","对抗性思维","目的手段分离","古代东亚"],"linked_cases":["caocao-c1","caocao-c2","caocao-c3","caocao-c4"],"life_tags":[{"tag":"官渡破袁绍","tier":"secondary"},{"tag":"注孙子兵法","tier":"primary"},{"tag":"兴屯田制","tier":"secondary"},{"tag":"统一北方","tier":"secondary"}],"voice_profile":{"notes":"雄才大略、务实权变；唯才是举；军政经兼擅；枭雄而争议"},"references":[{"ref_id":"caocao-s1","title":"《三国志·武帝纪》、曹操《孙子注》《求贤令》","locator":"唯才是举、兵无常势、屯田、挟天子、赏罚分明","source_tier":"primary","supports_models":["唯才是举不拘品行","兵无常势因敌制胜","屯田固本","挟天子以令诸侯","赏罚分明令行禁止"],"supports_cases":["caocao-c1","caocao-c2","caocao-c3","caocao-c4"],"note":"一手/二手·史与兵书注（割发代首史源存疑、已标）"},{"ref_id":"caocao-s2","title":"曹操与三国史研究","locator":"军政经方略、历史评价","source_tier":"secondary","supports_models":["唯才是举不拘品行","屯田固本"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"用人不拘出身品行瑕疵只要有真本事能办成事就大胆用(唯才是举不拘品行)；没有固定套路根据变化的形势随机应变因势制胜(兵无常势因敌制胜)；以屯田式办法夯实资源粮草现金流的根基(屯田固本)；抢占道义法理正统的制高点使自己师出有名(挟天子以令诸侯)；以严明法度赏罚分明规则面前包括自己一视同仁(赏罚分明令行禁止)","steps":[{"invoke":"唯才是举不拘品行","action":"你用人是看出身、品行名节、还是看他有没有真本事、能不能办成事？"},{"invoke":"兵无常势因敌制胜","action":"你是套用固定套路、还是根据变化的形势随机应变、因势制胜？"},{"invoke":"屯田固本","action":"你是只顾打仗/扩张、还是也以屯田式办法夯实了资源与根基？"},{"invoke":"挟天子以令诸侯","action":"你在博弈中是师出无名、还是抢占了道义/法理/正统的制高点？"},{"invoke":"赏罚分明令行禁止","action":"你的赏罚是因人而异、还是严明、一视同仁（包括自己）？"}],"contrast":"与凯撒不同(关键差异·同为军政一体的统帅)：**凯撒靠''个人的速度、果决、亲临冲锋与个人魅力''的英雄式统帅(军政一体系于个人的天才与魅力)**；**曹操靠''制度性的用人(唯才是举)、经济基础(屯田)、政治正当性(挟天子)、法度(赏罚分明)''的体系建设(军政经一体的制度与权谋)**——凯撒偏个人魅力、曹操偏制度与权谋的体系(见凯撒卡)。与孙子不同：孙子是兵法的原理总纲;曹操是深谙并注释孙子、又把它与用人、经济、政治打通的实操统帅(见孙子卡)。与商鞅不同：商鞅是单纯的法家变法者;曹操是军政经一体、兼用法术与权谋的乱世枭雄(见商鞅卡)。【射程/盲区·历史诚实·〔慎〕】曹操之道在''唯才是举、兵无常势、屯田固本、挟天子、赏罚分明''极有力(尤其乱世中的用人、根基与博弈)，但①''唯才是举''只看才不看德、用了一些品行有亏的人、埋下隐患;②曹操多疑猜忌、''宁我负人毋人负天下人''的权谋与冷酷、滥杀(孔融华佗等)有严重争议、客观标注;③''挟天子''等权谋在道德/法统上历来有争议、其''奸雄''之名毁誉参半;④个人色彩极强、难简单复制。适用组织管理/竞争博弈/危机应对;不适用创作/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"caocao-c1","note":"用户''求贤若渴、却被对方出身不高、资历不够、甚至有些品行上的瑕疵绊住、不敢用''时，以曹操''唯才是举''类比：他在乱世中连发《求贤令》、公开宣布用人不拘出身、不拘品行(''唯才是举'')、哪怕''不仁不孝''只要有真本事能办成事就用;别被出身、资历、品行的瑕疵绊住——只要他有真本事、能办成事、就大胆用〔但务必注意:只看才不看德也有隐患、须有制度制衡〕（求贤令为曹操所发→确证）"},{"source":"case","case_id":"caocao-c2","note":"用户''只顾着打仗/扩张/抢市场、却忽视了资源、现金流、后勤这些根基''时，以曹操屯田类比：他在群雄逐鹿、军粮匮乏时、推行''屯田制''让士兵与流民耕种、自己解决了军粮、夯实了经济与后勤的根基、为统一北方打下了物质基础;别只顾扩张忽视根基——以''屯田''式办法夯实资源、粮草、现金流的基础、根基稳了才能持久（屯田为曹操所推行→确证）"}]},"further_reading":[{"title":"《三国志·武帝纪》、曹操《孙子注》《求贤令》","why":"唯才是举、兵无常势、屯田、挟天子、赏罚分明的出处（A/B）","type":"史/兵书"},{"title":"曹操与三国史研究","why":"对其军政经方略与历史评价（毁誉参半）的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/caocao.png","avatar_thumb":"/advisors/portraits/caocao.png","domain":"战略","person_id":"P-caocao","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '239dd959b5f9ddccaf1d37ee8b957254fbe7385d8c4d7298da87fa69a624e98e', 10, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('caoxueqin', 'P-caoxueqin', '曹雪芹', 'writing', '曹雪芹 · 草蛇灰线与世情写实思维框架卡', '清（约1715—1763）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '草蛇灰线伏延千里 · 真假虚实的辩证', '/advisors/portraits/caoxueqin.png', '/advisors/portraits/caoxueqin.png', 5, 0, '{"schema_version":1,"card_id":"caoxueqin","name":"曹雪芹","title":"曹雪芹 · 草蛇灰线与世情写实思维框架卡","era":"清（约1715—1763）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"草蛇灰线伏延千里","definition":"在前面埋下看似不起眼的细节伏笔，让它在后文遥相照应——精密的呼应结构，使整体浑然一体、经得起反复推敲","source":"《红楼梦》的伏笔结构","source_tier":"primary","mechanism":"输入=情节松散、缺呼应 → 处理=前文埋下不起眼的细节伏笔、后文遥相照应、形成精密呼应结构 → 输出=浑然一体经得起推敲(草蛇灰线)","trigger":"构建一个需要前后呼应、经得起推敲的整体时","modern_transfer":"在前面埋下看似不起眼的细节伏笔、让它在后文遥相照应——精密的''草蛇灰线、伏延千里''结构、使整体浑然一体、经得起反复推敲(曹雪芹《红楼梦》的判词与伏笔)","architecture":{"type":"hierarchy","components":["别让情节松散缺呼应","前文埋下不起眼的细节伏笔","后文遥相照应","浑然一体经得起推敲"]},"strategy_card_image":"kb-assets/caoxueqin/model-1.png"},{"name":"真假虚实的辩证","definition":"善用真与假、虚与实的交织——\"假作真时真亦假\"，有时\"虚构/表象\"里藏着比\"写实\"更深的真实","source":"《红楼梦》的真假辩证","source_tier":"primary","mechanism":"输入=把真假虚实看死、非此即彼 → 处理=善用真与假、虚与实的交织、表达更深的真实 → 输出=虚构里藏更深真实(真假辩证)","trigger":"要表达深层真实、处理虚实关系时","modern_transfer":"善用真与假、虚与实的交织——''假作真时真亦假''、有时''虚构/表象''里藏着比''写实''更深的真实;别把真假虚实看死(曹雪芹《红楼梦》''太虚幻境''的真假辩证)","architecture":{"type":"grid","components":["别把真假虚实看死非此即彼","善用真与假虚与实的交织","假作真时真亦假","虚构里藏更深的真实"]},"strategy_card_image":"kb-assets/caoxueqin/model-2.png"},{"name":"群像与个体命运","definition":"让每个人都有鲜明独特的个性（而非脸谱），又让每个人的命运都与整体的命运相连——群像与整体共振","source":"《红楼梦》的人物群像","source_tier":"primary","mechanism":"输入=人物脸谱化、或只突出一两个主角 → 处理=塑造一大群各有鲜明个性的人物、每个命运都与整体兴衰相连 → 输出=群像与整体共振(群像)","trigger":"塑造/理解一群人时","modern_transfer":"塑造/理解一群人时、让每个人都有鲜明独特的个性(而非脸谱)、又让每个人的命运都与整体的命运相连——群像与整体共振(曹雪芹《红楼梦》写了数百个性格各异的人物)","architecture":{"type":"matrix","components":["别让人物脸谱化或只突出一两个主角","塑造一大群各有鲜明个性的人物","每个命运都与整体兴衰相连","群像与整体共振"]},"strategy_card_image":"kb-assets/caoxueqin/model-3.png"},{"name":"以家族兴衰映照时代","definition":"通过一个具体的小单位（家族/组织）的兴衰起落，去折射更宏大的社会与时代的命运——以一隅见全局","source":"《红楼梦》以贾府映时代","source_tier":"primary","mechanism":"输入=故事只停在小单位表面 → 处理=通过一个家族的由盛转衰、折射更宏大的社会与时代命运 → 输出=以一隅见全局(家族映时代)","trigger":"要让一个小单位的故事承载更大意义时","modern_transfer":"通过一个具体的小单位(家族/组织)的兴衰起落、去折射更宏大的社会与时代的命运——以一隅见全局(曹雪芹以贾府的由盛转衰映照时代)","architecture":{"type":"flow","components":["别让故事只停在小单位表面","通过一个家族的由盛转衰","折射更宏大的社会与时代命运","以一隅见全局"]},"strategy_card_image":"kb-assets/caoxueqin/model-4.png"},{"name":"极致的细节写实","definition":"以极其精细、考究的细节（器物、礼仪、饮食、园林）去构建一个真实可信、可沉浸的世界——细节的真实撑起整体的可信","source":"《红楼梦》的细节写实","source_tier":"primary","mechanism":"输入=世界粗疏、不可信 → 处理=以极精细考究的细节(器物礼仪环境)构建真实可信的世界 → 输出=细节真实撑起整体可信(细节写实)","trigger":"要构建一个真实可沉浸的世界时","modern_transfer":"以极其精细、考究的细节(器物、礼仪、饮食、园林)去构建一个真实可信、可沉浸的世界——细节的真实撑起整体的可信(曹雪芹《红楼梦》的细节写实)","architecture":{"type":"flow","components":["别让世界粗疏不可信","以极精细考究的细节","器物礼仪饮食园林","细节真实撑起整体可信"]},"strategy_card_image":"kb-assets/caoxueqin/model-5.png"}],"decision_principles":["前面埋下不起眼的伏笔，后文遥相照应，使整体浑然一体、经得起推敲","善用真与假、虚与实的交织，有时虚构里藏着更深的真实","让每个人都有鲜明个性，又让其命运与整体的命运相连","通过一个小单位的兴衰，折射更宏大的社会与时代","以极精细考究的细节，构建一个真实可信、可沉浸的世界"],"inquiry_questions":["你是让情节松散、还是前面埋下伏笔、后文遥相照应、浑然一体？","你是把真假虚实看死、还是善用真与假、虚与实的交织去表达更深的真实？","你的人物是脸谱化、还是各有鲜明个性、命运又与整体相连？","你的故事只停在小单位表面、还是以其兴衰折射更宏大的社会与时代？","你的世界是粗疏不可信、还是以精细考究的细节构建得真实可沉浸？"],"value_priorities":["伏延千里的呼应 ＞ 松散缺呼应（草蛇灰线、判词）","交织的真实 ＞ 看死的真假（假作真时真亦假）","细节撑起的可信 ＞ 粗疏的世界（器物礼仪饮食园林）"],"blind_spots":["《红楼梦》的精密、繁复、含蓄，要求很高的耐心与解读能力，不适合需要直接、高效的场合（原理推断，B）。","曹雪芹的伟大在世情的洞察与艺术，对''提供行动方案/实用指南''并不直接相关（原理推断，B）。","其''真假虚实''的朦胧，也意味着不够明确、确定（原理推断，B）。","《红楼梦》后40回非曹雪芹原作、存在续书与版本问题（红学常识，B，客观标注）。"],"applicable_domains":["创作","表达说服"],"match_tags":["创作","表达说服","系统分析","批判思辨","多元模型","古代东亚"],"linked_cases":["caoxueqin-c1","caoxueqin-c2","caoxueqin-c3","caoxueqin-c4"],"life_tags":[{"tag":"著红楼梦","tier":"primary"},{"tag":"出身织造世家","tier":"secondary"},{"tag":"批阅十载","tier":"primary"},{"tag":"工诗善画","tier":"secondary"}],"voice_profile":{"notes":"细腻绵密、洞悉世情；结构精密；真假虚实交织；含蓄而苍凉"},"references":[{"ref_id":"caoxueqin-s1","title":"《红楼梦》（前80回，曹雪芹著）","locator":"草蛇灰线、真假虚实、群像、家族映时代、细节写实","source_tier":"primary","supports_models":["草蛇灰线伏延千里","真假虚实的辩证","群像与个体命运","以家族兴衰映照时代","极致的细节写实"],"supports_cases":["caoxueqin-c1","caoxueqin-c2","caoxueqin-c3","caoxueqin-c4"],"note":"一手·原著（前80回）"},{"ref_id":"caoxueqin-s2","title":"红学研究","locator":"结构、版本、世情艺术","source_tier":"secondary","supports_models":["草蛇灰线伏延千里","以家族兴衰映照时代"],"note":"二手·研究（含后40回版本问题）"}],"material_type":"rich","reasoning_skeleton":{"signature":"前文埋下不起眼的细节伏笔后文遥相照应使整体浑然一体经得起推敲(草蛇灰线伏延千里)；善用真与假虚与实的交织有时虚构里藏更深的真实(真假虚实的辩证)；让每个人都有鲜明个性又让命运与整体相连(群像与个体命运)；通过一个家族的兴衰折射更宏大的社会与时代(以家族兴衰映照时代)；以极精细考究的细节构建真实可信可沉浸的世界(极致的细节写实)","steps":[{"invoke":"草蛇灰线伏延千里","action":"你是让情节松散、还是前面埋下伏笔、后文遥相照应、浑然一体？"},{"invoke":"真假虚实的辩证","action":"你是把真假虚实看死、还是善用真与假、虚与实的交织去表达更深的真实？"},{"invoke":"群像与个体命运","action":"你的人物是脸谱化、还是各有鲜明个性、命运又与整体相连？"},{"invoke":"以家族兴衰映照时代","action":"你的故事只停在小单位表面、还是以其兴衰折射更宏大的社会与时代？"},{"invoke":"极致的细节写实","action":"你的世界是粗疏不可信、还是以精细考究的细节构建得真实可沉浸？"}],"contrast":"与莎士比亚不同(关键差异)：**莎士比亚以''戏剧冲突与诗性语言''呈现集中的人性母题(舞台的张力)**；**曹雪芹以''草蛇灰线的精密结构、世情的细节写实、群像''呈现一个家族日常的兴衰(世情的绵密)**——一个戏剧化集中、一个世情化绵密(见莎士比亚卡)。与托尔斯泰不同：托尔斯泰以''心灵辩证法与道德追问''写史诗;曹雪芹以''草蛇灰线、真假虚实、世情写实''写家族——一个心理与道德、一个结构与世情(见托尔斯泰卡)。与海明威不同：海明威极简留白、聚焦个体瞬间;曹雪芹繁密铺陈、群像与全景(见海明威卡)。与狄更斯不同：狄更斯社会批判、讽刺;曹雪芹世情洞察、含蓄(见狄更斯卡)。【射程/盲区】曹雪芹之道在''草蛇灰线、真假虚实、群像、家族映时代、细节写实''极有力(尤其精密结构与世情洞察)，但①其精密、繁复、含蓄、要求很高的耐心与解读、不适合需要直接高效的场合;②其伟大在世情洞察与艺术、对''给行动方案/实用指南''不直接相关;③''真假虚实''的朦胧也意味着不够明确确定;④《红楼梦》后40回非曹雪芹原作、有续书与版本问题。适用创作/表达说服/系统分析;不适用投资/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"caoxueqin-c1","note":"用户''在构建一个需要前后呼应、经得起推敲、浑然一体的整体(作品/方案/系统)、却觉得各部分松散''时，以曹雪芹''草蛇灰线''类比：《红楼梦》在前文处处埋下看似不经意的细节、判词、谶语(如金陵十二钗的判词预示了每个人的命运)、后文一一照应、''草蛇灰线、伏延千里'';在前面埋下不起眼的伏笔、让它在后文遥相照应、使整体浑然一体、经得起反复推敲（草蛇灰线为《红楼梦》结构→确证）"},{"source":"case","case_id":"caoxueqin-c4","note":"用户''想让一个具体的小单位(家族/团队/组织)的故事承载更大的意义、却只停在表面''时，以曹雪芹以贾府映时代类比：《红楼梦》通过贾府这一个钟鸣鼎食之家的由盛转衰、折射出整个时代与社会的命运;通过一个小单位的兴衰起落、去折射更宏大的社会与时代——以一隅见全局（贾府映时代为《红楼梦》主题→确证）"}]},"further_reading":[{"title":"《红楼梦》（前80回，曹雪芹著）","why":"草蛇灰线、真假虚实、群像、家族映时代、细节写实的一手出处（A）","type":"original"},{"title":"红学研究","why":"对《红楼梦》结构、版本、世情艺术的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/caoxueqin.png","avatar_thumb":"/advisors/portraits/caoxueqin.png","domain":"创作","person_id":"P-caoxueqin","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'e2a19ae02c87b344bbbd3ebfe475eda8577dca3c9a1a8eeef40ace006dafec66', 11, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('carnegie', 'P-carnegie', '安德鲁·卡内基', 'business', '安德鲁·卡内基 · 成本领先与逆周期扩张思维框架卡', '19–20世纪（1835–1919）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '成本即一切 · 纵向一体化', '/advisors/portraits/carnegie.png', '/advisors/portraits/carnegie.png', 5, 0, '{"schema_version":1,"card_id":"carnegie","name":"安德鲁·卡内基","title":"安德鲁·卡内基 · 成本领先与逆周期扩张思维框架卡","era":"19–20世纪（1835–1919）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"成本即一切","definition":"''盯住成本，利润自然会来''；以最精细的成本会计掌握每道工序单位成本，靠成本领先取胜","source":"卡内基自传","source_tier":"primary","mechanism":"输入=同质化的重资产规模行业 → 处理=用精细成本会计逐道工序核算真实单位成本 → 输出=成为成本最低者，据此定价与改进","trigger":"重资产、同质化、谁成本低谁赢的规模行业","modern_transfer":"先把每道工序的真实单位成本搞清楚再谈竞争——看不清成本就是蒙着眼打价格战；''盯住成本，利润自然会来''","architecture":{"type":"loop","components":["逐工序核算单位成本","找最低成本路径","据此定价改进","持续盯成本"]},"strategy_card_image":"kb-assets/carnegie/model-1.png"},{"name":"纵向一体化","definition":"从铁矿、煤焦、运输到钢厂全链条自有，消除中间利润与受制环节，掌控成本与供应","source":"卡内基传记/史料","source_tier":"secondary","mechanism":"输入=钢厂利润受上游(矿/焦/运)卡脖子 → 处理=向上游整合、全链自有 → 输出=成本与供应稳定可控、议价力强","trigger":"利润被上游拿走、供应或价格受制于上游时","modern_transfer":"把利润被别人拿走、又最易卡你脖子的上游环节收进来，既稳成本又稳供应——是规模制造的护城河","architecture":{"type":"flow","components":["整合上游原料","整合运输","全链自有","消除中间利润"]},"strategy_card_image":"kb-assets/carnegie/model-2.png"},{"name":"逆周期扩张","definition":"别人萧条收缩时，低价买设备、扩产能、上新技术；萧条是低成本扩张的最好时机","source":"卡内基传记/史料","source_tier":"secondary","mechanism":"输入=经济萧条、设备与建厂成本骤降 → 处理=别人收缩时低价买地建厂、扩产上新技术 → 输出=复苏期产能与成本双领先","trigger":"经济萧条、同行收缩、设备/建厂成本处于低谷时","modern_transfer":"别人恐惧收缩时，正是用更低成本上产能、换新技术的窗口——周期低谷是有准备者扩张的黄金时机","architecture":{"type":"loop","components":["等萧条低谷","低价买地建厂","上新技术扩产","复苏期通吃"]},"strategy_card_image":"kb-assets/carnegie/model-3.png"},{"name":"拥抱新技术","definition":"果断引进贝塞麦炼钢等新工艺、不惜淘汰旧设备，用技术换更低成本与更高产量","source":"卡内基传记/史料","source_tier":"secondary","mechanism":"输入=有更优新工艺、但旧设备有沉没成本 → 处理=果断引进新工艺、淘汰旧设备 → 输出=技术换来更低成本更高产量","trigger":"出现更优生产新工艺、而旧设备尚有账面价值时","modern_transfer":"果断引进新技术、不留恋旧设备的沉没成本——用技术换更低成本更高产量；留恋旧设备的人会被换技术的人淘汰","architecture":{"type":"flow","components":["识别更优新工艺","果断引进","淘汰旧设备","技术换成本"]},"strategy_card_image":"kb-assets/carnegie/model-4.png"},{"name":"财富的福音","definition":"巨富是社会托管的责任；''富而死者耻''，在世时就应把财富科学地回馈社会","source":"《财富的福音》","source_tier":"primary","mechanism":"输入=巨额财富 + ''富而死者耻''的信念 → 处理=在世用方法论把财富科学投向教育与公共善 → 输出=结构性的社会回报","trigger":"面对''巨富该如何处置''的人生命题时","modern_transfer":"财富的终点不是占有而是托管——趁在世用方法论把它投向教育与公共善，比留给后代或守财致死更有价值","architecture":{"type":"hierarchy","components":["视巨富为社会托管","在世投放","瞄准教育与公共善","求结构性回报"]},"strategy_card_image":"kb-assets/carnegie/model-5.png"}],"decision_principles":["盯住成本，利润自然会来（A）","全链条自有，消除中间环节（B）","别人萧条收缩时，逆势低价扩张（A/B）","果断上新技术，不留恋旧设备（B）","富而死者耻，在世科学回馈社会（A）"],"inquiry_questions":["你真知道每道工序的单位成本吗？","你的链条上，哪段利润被中间商拿走了？","现在是别人收缩、你该逆势扩张的时候吗？","你在留恋会被淘汰的旧设备吗？"],"value_priorities":["成本领先 ＞ 规模虚名（成本是终极武器）","逆周期扩张 ＞ 顺周期追高（萧条时低价上产能）","新技术 ＞ 旧设备沉没成本（果断淘汰）","财富回馈社会 ＞ 守财致死（富而死者耻）"],"blind_spots":["其''善待工人''的自我标榜与1892年Homestead罢工的血腥镇压(他在欧洲、授权Frick)严重矛盾，是重大污点（史实，A/B）","极致成本与逆周期扩张依赖钢铁这类重资产规模行业，未必迁移到轻资产/快变行业（原理推断，B）","高度依赖个人对成本与时机的判断，难以制度化复制（原理推断，B）"],"applicable_domains":["商业模式与护城河","资源调度","长期规划","价值与伦理"],"match_tags":["商业模式与护城河","资源调度","长期规划","系统分析","逆向思考","长期主义","近代北美"],"linked_cases":["carnegie-c1","carnegie-c2","carnegie-c3","carnegie-c4","carnegie-c5"],"life_tags":[{"tag":"创卡内基钢铁","tier":"secondary"},{"tag":"著财富的福音","tier":"primary"},{"tag":"捐建图书馆","tier":"secondary"},{"tag":"晚年散尽家财","tier":"secondary"}],"voice_profile":{"notes":"精明务实、自信；爱谈成本与时机；晚年philanthropic布道气"},"references":[{"ref_id":"carnegie-s1","title":"卡内基《财富的福音》(1889) 与《卡内基自传》","locator":"成本理念、财富的福音相关篇章；含其自述成分","source_tier":"primary","supports_models":["成本即一切","财富的福音"],"supports_cases":["carnegie-c1","carnegie-c5"],"note":"本人著述一手"},{"ref_id":"carnegie-s2","title":"卡内基传记与美国钢铁/Homestead权威史料","locator":"逆周期扩张、贝塞麦、纵向一体化、1892 Homestead相关章节","source_tier":"secondary","supports_models":["逆周期扩张","纵向一体化","拥抱新技术"],"supports_cases":["carnegie-c2","carnegie-c3","carnegie-c4"],"note":"第三方传记与权威史料"}],"material_type":"rich","reasoning_skeleton":{"signature":"先把每道工序的真实单位成本搞到行业最清楚——盯住成本利润自来；向上游纵向整合矿-焦-运稳成本；专挑萧条低谷逆势低价扩产、果断引进新工艺淘汰旧设备；财富则在世科学回馈","steps":[{"invoke":"成本即一切","action":"你真知道每道工序的单位成本吗？先把成本搞到行业最清楚——盯住成本，利润自然会来"},{"invoke":"纵向一体化","action":"哪段利润被上游/中间商拿走、又最易卡你？把矿-焦-运这类上游收进来，稳成本稳供应"},{"invoke":"逆周期扩张","action":"别人萧条收缩时，正是低价买地建厂、上产能的窗口——逆势扩张，赌复苏后通吃"},{"invoke":"拥抱新技术","action":"别留恋旧设备的沉没成本，果断引进更优新工艺(如贝塞麦)，用技术换更低成本更高产量"},{"invoke":"财富的福音","action":"巨富是社会托管，在世用方法论投向教育与公共善——富而死者耻"}],"contrast":"与洛克菲勒不同(关键差异)：二者同为镀金时代''做大''巨头、都用纵向整合与逆周期、都开创机构化慈善，但**洛克菲勒的标志动作是横向收编整个石油行业、掌控定价(整合垄断)**；**卡内基的标志动作是把一条钢铁产业链的成本会计做到行业最精、并果断引进贝塞麦新技术**——洛是''把整个行业收成一体掌定价''，卡是''把一条链的成本与技术做到极致便宜''；且洛的逆周期是**收编对手**、卡的逆周期是**自建扩产**（见洛克菲勒卡）。与亨利·福特不同：福特也极致压成本，但靠**流水线+单一车型标准化的大规模生产工艺**降本；卡内基靠**成本会计精算+上游纵向整合+逆周期上新技术**降本（见福特卡）。【射程边界】卡长于重资产规模制造的成本与周期博弈；**不长于从0到1创新**；并因 Homestead 暴露''把成本/效率推到极致而无视人的代价''之坑（见盲区）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"carnegie-c1","note":"用户''在拼成本的行业怎么建立优势''时，以成本即一切·精细成本会计类比：当多数厂连每道工序真实成本都不清楚，他逐道工序核算单位成本、''盯成本利润自来''，始终是成本最低者（成本会计理念见自传与传记→确证）"},{"source":"case","case_id":"carnegie-c2","note":"用户''萧条期该收缩还是扩张''时，以逆周期扩张·萧条低价扩产引进贝塞麦类比：别人收缩时他低价买地建厂、上新工艺，复苏后产能与成本双领先（逆周期扩张+贝塞麦见多方史料→确证）"}]},"further_reading":[{"title":"卡内基《财富的福音》(1889)","why":"''富而死者耻''、巨富社会托管观的一手文本","type":"original"},{"title":"《卡内基自传》及权威钢铁工业史","why":"成本理念一手，逆周期/贝塞麦/纵向整合/Homestead 史料","type":"biography"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/carnegie.png","avatar_thumb":"/advisors/portraits/carnegie.png","domain":"商业","person_id":"P-carnegie","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '536a13c896ac5014e8b93bedf209b8bd23a8fa8e527cd010b4bfc42dd3eb1b4b', 12, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('chanel', 'P-chanel', '可可·香奈儿', 'business', '可可·香奈儿 · 简约即奢华与解放束缚思维框架卡', '现代（1883—1971）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '简约即奢华 · 解放束缚', '/advisors/portraits/chanel.png', '/advisors/portraits/chanel.png', 5, 0, '{"schema_version":1,"card_id":"chanel","name":"可可·香奈儿","title":"可可·香奈儿 · 简约即奢华与解放束缚思维框架卡","era":"现代（1883—1971）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"简约即奢华","definition":"别以为奢华=繁复堆砌，去掉多余装饰、用简洁的剪裁线条与质感创造高级感（less is more）","source":"香奈儿设计理念与语录","source_tier":"secondary","mechanism":"输入=以为奢华=繁复堆砌 → 处理=去掉繁复装饰、用简洁的剪裁线条与质感创造高级感 → 输出=简约创造高级(less is more)","trigger":"要创造高级感/做设计取舍时","modern_transfer":"别以为奢华=繁复的堆砌——去掉多余的装饰、用简洁的剪裁、线条与质感去创造高级感(''简单''才是高级的关键、less is more);香奈儿用极简创造了奢华(小黑裙)","architecture":{"type":"flow","components":["别以为奢华是繁复堆砌","去掉多余装饰","用简洁剪裁线条与质感","简约创造高级"]},"strategy_card_image":"kb-assets/chanel/model-1.png"},{"name":"解放束缚","definition":"看到一个束缚人却被默认的旧规范，打破它、用舒适实用自由的设计解放使用者","source":"香奈儿解放女装的实践","source_tier":"secondary","mechanism":"输入=沿用束缚人的旧规范(紧身胸衣) → 处理=打破它、用舒适、实用、自由的设计解放使用者 → 输出=以解放赢得拥护","trigger":"面对一个束缚人却被默认的旧规范时","modern_transfer":"看到一个束缚人、却被默认的旧规范(如紧身胸衣)——打破它、用舒适、实用、自由的设计去解放使用者;解放本身就是最大的吸引力(香奈儿用针织、裤装解放了女性着装)","architecture":{"type":"flow","components":["看到束缚人的旧规范","打破它","用舒适实用自由的设计","以解放赢得拥护"]},"strategy_card_image":"kb-assets/chanel/model-2.png"},{"name":"把自己活成品牌","definition":"把你自己的生活方式、形象、态度本身活成品牌的化身——你怎么活，就是品牌怎么被定义","source":"香奈儿本人即Chanel的化身","source_tier":"secondary","mechanism":"输入=品牌与创始人割裂 → 处理=把自己的生活方式、形象、态度活成品牌的化身、亲自代言 → 输出=个人即品牌","trigger":"要塑造一个有灵魂的品牌时","modern_transfer":"把你自己的生活方式、形象、态度本身活成品牌的化身——你怎么活、就是品牌怎么被定义(香奈儿本人就是Chanel的化身与最佳代言)〔但高度依赖个人魅力、难复制、见盲区〕","architecture":{"type":"flow","components":["别让品牌与创始人割裂","把自己的生活方式形象态度","活成品牌的化身亲自代言","个人即品牌"]},"strategy_card_image":"kb-assets/chanel/model-3.png"},{"name":"经典抗潮流","definition":"别只追逐速朽的当季潮流，追求超越一季流行的\"经典\"与永恒风格，做能用很多年的东西","source":"香奈儿\"潮流易逝、风格永存\"","source_tier":"secondary","mechanism":"输入=追逐速朽的当季潮流 → 处理=追求超越一季的''经典''与永恒风格、做能穿很多年的设计 → 输出=以经典抗潮流","trigger":"在''追潮流''与''立经典''间取舍时","modern_transfer":"别只追逐速朽的当季潮流——追求超越一季流行的''经典''与永恒风格、做能用很多年的东西(''潮流易逝、风格永存''、香奈儿语);经典比潮流更持久","architecture":{"type":"flow","components":["别只追速朽的当季潮流","追求超越一季的经典与风格","做能用很多年的东西","以经典抗潮流"]},"strategy_card_image":"kb-assets/chanel/model-4.png"},{"name":"细节定义风格","definition":"用一个标志性的细节去定义整个品牌的风格，让人一眼就认出","source":"香奈儿标志元素","source_tier":"secondary","mechanism":"输入=靠堆砌很多元素 → 处理=用一个标志性的细节去定义整个风格、让人一眼认出 → 输出=以标志细节立品牌识别","trigger":"要建立品牌识别度时","modern_transfer":"用一个标志性的细节(山茶花、菱格纹、双C标志)去定义整个品牌的风格、让人一眼就认出——标志性的细节比堆砌很多元素更立得住(香奈儿的标志元素)","architecture":{"type":"flow","components":["别靠堆砌很多元素","用一个标志性的细节","定义整个风格让人一眼认出","以标志细节立识别"]},"strategy_card_image":"kb-assets/chanel/model-5.png"}],"decision_principles":["别以为奢华=繁复堆砌，用简洁的剪裁线条创造高级感（less is more）","看到束缚人的旧规范就打破它，用舒适实用自由解放使用者","把自己的生活方式与态度活成品牌的化身（但难复制）","别只追速朽潮流，追求超越一季的经典与永恒风格","用一个标志性细节定义整个风格、让人一眼认出"],"inquiry_questions":["你是用繁复的堆砌、还是用简洁的剪裁线条去创造高级感？","这件事里有没有一个束缚人却被默认的旧规范、可以打破去解放使用者？","你的品牌有灵魂吗、你自己的态度与生活方式是它的化身吗？","你在追速朽的当季潮流、还是在立能用很多年的经典？","你靠堆砌很多元素、还是用一个标志性细节让人一眼认出？"],"value_priorities":["简约的高级感 ＞ 繁复的堆砌（less is more、小黑裙）","解放使用者 ＞ 沿用束缚人的旧规范（用针织裤装解放女装）","经典与风格 ＞ 速朽的当季潮流（潮流易逝、风格永存）"],"blind_spots":["〔注意〕香奈儿二战期间的个人经历与政治关联有严重争议；本卡只取其设计与品牌的方法，对其个人争议客观标注、不美化、不展开（史实，B）。","''把自己活成品牌''高度依赖创始人独特的个人魅力与传奇，难以被普通人或团队复制（原理推断，B）。","极简美学是一种风格主张，并非所有品类/场景都适合''less is more''（原理推断，B）。","时尚领域的成功有强烈的时代与文化偶然性，未必能直接迁移到其他行业（原理推断，B）。"],"applicable_domains":["创业","表达说服","创新研发"],"match_tags":["创业","表达说服","创新研发","极简主义","逆向思考","直觉决断","现当代欧洲"],"linked_cases":["chanel-c1","chanel-c2","chanel-c3","chanel-c4"],"life_tags":[{"tag":"创香奈儿品牌","tier":"secondary"},{"tag":"设计小黑裙","tier":"secondary"},{"tag":"推五号香水","tier":"secondary"},{"tag":"革新女性着装","tier":"secondary"}],"voice_profile":{"notes":"简洁果决、品味独到；反叛旧规范；强烈的个人风格；追求永恒经典"},"references":[{"ref_id":"chanel-s1","title":"可可·香奈儿传记与设计史","locator":"简约设计、解放女装、个人即品牌、经典风格、标志元素","source_tier":"secondary","supports_models":["简约即奢华","解放束缚","把自己活成品牌","细节定义风格"],"supports_cases":["chanel-c1","chanel-c2","chanel-c3"],"note":"二手·传记/设计史（个人争议另有专门讨论）"},{"ref_id":"chanel-s2","title":"20世纪时尚史","locator":"小黑裙、No.5、菱格纹、\"潮流易逝风格永存\"","source_tier":"secondary","supports_models":["经典抗潮流","简约即奢华"],"supports_cases":["chanel-c4"],"note":"二手·时尚史"}],"material_type":"rich","reasoning_skeleton":{"signature":"去掉繁复装饰、用简洁创造高级感(简约即奢华)；打破束缚人的旧规范、用舒适实用解放使用者(解放束缚)；把自己的生活方式态度活成品牌的化身(把自己活成品牌)；追求超越一季的经典而非速朽潮流(经典抗潮流)；用一个标志性细节定义整个风格(细节定义风格)","steps":[{"invoke":"简约即奢华","action":"你是用繁复的堆砌、还是用简洁的剪裁线条去创造高级感？"},{"invoke":"解放束缚","action":"这件事里有没有一个束缚人却被默认的旧规范、可以打破去解放使用者？"},{"invoke":"把自己活成品牌","action":"你的品牌有灵魂吗、你自己的态度与生活方式是它的化身吗？"},{"invoke":"经典抗潮流","action":"你在追速朽的当季潮流、还是在立能用很多年的经典？"},{"invoke":"细节定义风格","action":"你靠堆砌很多元素、还是用一个标志性细节让人一眼认出？"}],"contrast":"与乔布斯不同(关键差异·同重极简美学与个人品牌)：**乔布斯是''科技产品的极简美学+封闭生态+现实扭曲力场''**；**香奈儿是''时尚的简约解放+把自己活成品牌+经典抗潮流''**——同样''less is more''、一个在科技产品、一个在时尚与个人风格(见乔布斯卡)。与盛田昭夫不同：盛田是''创造市场+全球品牌''(科技);香奈儿是''个人即品牌+经典风格''(时尚)(见盛田卡)。【射程/盲区·〔注意〕】香奈儿之道在''简约即奢华、解放束缚、把自己活成品牌、经典抗潮流、细节定义风格''极有力，但①〔注意〕其二战期间的个人经历与政治关联有严重争议、本卡只取设计与品牌方法、对个人争议客观标注、不美化、不展开;②''把自己活成品牌''高度依赖创始人独特魅力与传奇、难复制;③极简是一种风格主张、并非所有品类都适合''less is more'';④时尚成功有强烈的时代文化偶然性、未必能直接迁移到其他行业。适用创业/表达说服/创新研发;不适用投资/危机应对。"},"persona_anchor":{"primary":[{"source":"case","case_id":"chanel-c1","note":"用户''想做出高级感、却以为要靠繁复的堆砌''时，以香奈儿简约即奢华类比：她去掉当时女装繁复的装饰、用简洁的剪裁、线条与质感创造出真正的高级——小黑裙至今是经典;''简单''才是高级的关键、less is more（香奈儿简约设计理念为时尚史与其语录所载→确证）"},{"source":"case","case_id":"chanel-c2","note":"用户''被一个束缚人、却被默认为''就该如此''的旧规范困住''时，以香奈儿解放女装类比：她打破束缚女性的紧身胸衣、用针织、裤装、宽松剪裁让女性穿得舒适自由——打破束缚人的旧规范、用解放本身赢得拥护（香奈儿解放女装为时尚史所载→确证）"}]},"further_reading":[{"title":"可可·香奈儿传记与设计史","why":"简约设计、解放女装、经典风格的记述（B；个人争议另有专门讨论）","type":"biography"},{"title":"20世纪时尚史","why":"小黑裙、No.5、菱格纹等标志性设计的影响（B）","type":"时尚史"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/chanel.png","avatar_thumb":"/advisors/portraits/chanel.png","domain":"商业","person_id":"P-chanel","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '2f6e637a391175161bc12011d5592fd659d7ae21537c52a7fa1d4422ddc6b075', 13, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('churchill', 'P-churchill', '丘吉尔', 'governance', '丘吉尔 · 绝不屈服与战时动员思维框架卡', '现代（1874—1965）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '绝不屈服的意志 · 言语动员人心', '/advisors/portraits/churchill.png', '/advisors/portraits/churchill.png', 5, 0, '{"schema_version":1,"card_id":"churchill","name":"丘吉尔","title":"丘吉尔 · 绝不屈服与战时动员思维框架卡","era":"现代（1874—1965）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"绝不屈服的意志","definition":"在最黑暗、看似必败的时刻，绝不轻言放弃——用坚定的决心稳住人心，撑到转机出现","source":"丘吉尔二战领导与演讲","source_tier":"secondary","mechanism":"输入=最黑暗看似必败时轻言放弃 → 处理=绝不投降、用坚定决心稳住人心、撑到转机 → 输出=撑到转机出现(绝不屈服)","trigger":"在最黑暗、看似必败的时刻","modern_transfer":"在最黑暗、看似必败的时刻、绝不轻言放弃——用坚定的决心稳住自己与团队的人心、撑到转机出现(''我们绝不投降''、丘吉尔)〔但须与''确实该止损''的盲目蛮干区分、见盲区〕","architecture":{"type":"flow","components":["别在最黑暗看似必败时轻言放弃","绝不投降","用坚定决心稳住人心","撑到转机出现"]},"strategy_card_image":"kb-assets/churchill/model-1.png"},{"name":"言语动员人心","definition":"在危机中用真诚、有力、既坦诚困难又给人希望的语言，去凝聚人心、把士气动员起来","source":"丘吉尔的战时演讲","source_tier":"secondary","mechanism":"输入=危机中沉默或空洞口号 → 处理=用真诚、有力、坦诚困难又给希望的语言凝聚人心 → 输出=士气被动员(言语动员)","trigger":"危机中要凝聚人心、动员士气时","modern_transfer":"在危机中用真诚、有力、既坦诚困难又给人希望的语言、去凝聚人心、把士气动员起来——语言本身就是力量(丘吉尔的战时演讲)","architecture":{"type":"flow","components":["别在危机中沉默或喊空洞口号","用真诚有力的语言","既坦诚困难又给人希望","凝聚人心动员士气"]},"strategy_card_image":"kb-assets/churchill/model-2.png"},{"name":"直面而非绥靖","definition":"对一个真实的、正在壮大的威胁，要早识别、敢直面，别靠一味的妥协退让去换一时的安宁","source":"丘吉尔早年反对绥靖政策","source_tier":"secondary","mechanism":"输入=对真实威胁一味妥协退让换一时安宁 → 处理=早识别、敢直面、不靠妥协退让 → 输出=不喂大威胁(直面非绥靖)","trigger":"面对一个真实正在壮大的威胁时","modern_transfer":"对一个真实的、正在壮大的威胁、要早识别、敢直面、别靠一味的妥协退让去换一时的安宁——绥靖只会喂大它(丘吉尔早年反对绥靖)","architecture":{"type":"flow","components":["别对真实威胁一味妥协退让","早识别正在壮大的威胁","敢直面不靠退让换安宁","不喂大威胁"]},"strategy_card_image":"kb-assets/churchill/model-3.png"},{"name":"联合一切可联合","definition":"为了对抗当前最主要的威胁，可以放下成见、与次要的对手甚至旧敌联手——分清主次矛盾","source":"丘吉尔为抗德联合美苏","source_tier":"secondary","mechanism":"输入=因成见或旧怨拒绝结盟 → 处理=为对抗主要威胁、可与次要对手甚至旧敌联手、分清主次 → 输出=集中力量对付主要矛盾(联合)","trigger":"面对主要威胁、考虑结盟时","modern_transfer":"为了对抗当前最主要的威胁、可以放下成见、与次要的对手甚至旧敌联手——分清主次矛盾、''敌人的敌人''也能是盟友(丘吉尔为抗德而联合美苏)","architecture":{"type":"flow","components":["别因成见或旧怨拒绝结盟","为对抗主要威胁","与次要对手甚至旧敌联手","分清主次集中力量"]},"strategy_card_image":"kb-assets/churchill/model-4.png"},{"name":"着眼历史的远见","definition":"跳出眼前的得失，从历史的大尺度去判断当前局势的走向与长远意义","source":"丘吉尔的历史视野","source_tier":"secondary","mechanism":"输入=只盯眼前的得失 → 处理=跳出眼前、从历史的大尺度判断局势走向与意义 → 输出=看得更远(历史远见)","trigger":"判断当前局势的走向与长远意义时","modern_transfer":"跳出眼前的得失、从历史的大尺度去判断当前局势的走向与长远意义——有历史感的人看得更远(丘吉尔本身是历史学家、获诺贝尔文学奖)","architecture":{"type":"flow","components":["别只盯眼前的得失","跳出眼前","从历史的大尺度判断","看清局势走向与长远意义"]},"strategy_card_image":"kb-assets/churchill/model-5.png"}],"decision_principles":["最黑暗看似必败时绝不屈服，用决心稳住人心撑到转机（但须与盲目蛮干区分）","危机中用真诚、有力、坦诚困难又给希望的语言凝聚人心","对真实正在壮大的威胁，早识别、敢直面，而非一味绥靖","为对抗主要威胁，可与次要对手甚至旧敌联手，分清主次","跳出眼前，从历史的大尺度判断局势走向与意义"],"inquiry_questions":["在这最黑暗看似必败的时刻，你是轻言放弃、还是绝不屈服、用决心稳住人心撑到转机？","你是沉默或喊空洞口号、还是用真诚有力、坦诚困难又给希望的话凝聚人心？","对这个真实正在壮大的威胁，你是一味妥协退让、还是早识别、敢直面？","为了对付主要威胁，你能不能放下成见、与次要对手甚至旧敌联手？","你只盯眼前得失、还是从历史的大尺度判断局势的走向与意义？"],"value_priorities":["绝不屈服的决心 ＞ 黑暗中轻言放弃（never give in（但须与盲目蛮干区分））","早识别直面威胁 ＞ 一味绥靖换安宁（绥靖只会喂大威胁）","分清主次的联合 ＞ 因成见拒绝结盟（为抗德联合美苏）"],"blind_spots":["''绝不屈服''的意志在''确实该止损/撤退''的情形下，可能变成不顾代价的固执（原理推断，B）。","丘吉尔的判断并非总对——其一生有重大失误（如加里波利战役），且其帝国主义立场与一些殖民地政策有严重争议（史，B，客观标注）。","演讲动员靠的是其个人的天赋与时代的危局，难以简单复制（原理推断，B）。","长于战时的对抗与动员，其战后即在大选中落败，也显示和平时期的需求不同（史，B）。"],"applicable_domains":["危机应对","领导力","表达说服"],"match_tags":["危机应对","领导力","表达说服","攻心共识","长期主义","对抗性思维","现当代欧洲"],"linked_cases":["churchill-c1","churchill-c2","churchill-c3","churchill-c4"],"life_tags":[{"tag":"领导二战英国","tier":"secondary"},{"tag":"发铁幕演说","tier":"primary"},{"tag":"获诺贝尔奖","tier":"secondary"},{"tag":"著二战回忆录","tier":"primary"}],"voice_profile":{"notes":"雄辩有力、意志坚定；金句迭出；强硬不妥协；历史感深厚"},"references":[{"ref_id":"churchill-s1","title":"丘吉尔《第二次世界大战回忆录》及传记","locator":"绝不屈服、战时演讲、反绥靖、联盟、历史视野","source_tier":"secondary","supports_models":["绝不屈服的意志","言语动员人心","直面而非绥靖","联合一切可联合","着眼历史的远见"],"supports_cases":["churchill-c1","churchill-c2","churchill-c3","churchill-c4"],"note":"一手/二手·回忆录/传记（殖民政策争议另有讨论）"},{"ref_id":"churchill-s2","title":"第二次世界大战史","locator":"不列颠空战、同盟国联合","source_tier":"secondary","supports_models":["绝不屈服的意志","联合一切可联合"],"note":"二手·史"}],"material_type":"rich","reasoning_skeleton":{"signature":"最黑暗看似必败时绝不屈服、用决心稳住人心撑到转机(绝不屈服的意志)；用真诚有力坦诚困难又给希望的语言凝聚人心(言语动员人心)；对真实壮大的威胁早识别敢直面而非绥靖(直面而非绥靖)；为抗主要威胁可与次要对手甚至旧敌联手(联合一切可联合)；跳出眼前从历史大尺度判断走向(着眼历史的远见)","steps":[{"invoke":"绝不屈服的意志","action":"在这最黑暗看似必败的时刻，你是轻言放弃、还是绝不屈服、用决心稳住人心撑到转机？"},{"invoke":"言语动员人心","action":"你是沉默或喊空洞口号、还是用真诚有力、坦诚困难又给希望的话凝聚人心？"},{"invoke":"直面而非绥靖","action":"对这个真实正在壮大的威胁，你是一味妥协退让、还是早识别、敢直面？"},{"invoke":"联合一切可联合","action":"为了对付主要威胁，你能不能放下成见、与次要对手甚至旧敌联手？"},{"invoke":"着眼历史的远见","action":"你只盯眼前得失、还是从历史的大尺度判断局势的走向与意义？"}],"contrast":"与林肯不同(关键差异·同为危难中的领袖)：**林肯面对的是''内部分裂''(内战)、靠''维护联邦、解放奴隶的道德感召、宽容化解仇恨、坚韧''来弥合**；**丘吉尔面对的是''外敌入侵''(纳粹)、靠''绝不屈服的意志、演讲动员、反绥靖直面、联合抗敌''来抵抗**——一个弥合内部分裂、一个抵抗外部强敌(见林肯卡)。与戴高乐不同：戴高乐(同为二战领袖)靠''危亡中举起正统的旗帜、独立自主、超越党派、重塑制度'';丘吉尔靠''意志、演讲动员、反绥靖、联盟''(见戴高乐卡)。【射程/盲区·〔慎〕】丘吉尔之道在''绝不屈服、言语动员、反绥靖、联合、历史远见''极有力(尤其危机领导)，但①''绝不屈服''在''确实该止损/撤退''时可能变成不顾代价的固执;②其判断并非总对、一生有重大失误(加里波利)、且其帝国主义立场与一些殖民地政策有严重争议、本卡客观标注;③演讲动员靠个人天赋与时代危局、难简单复制;④长于战时、其战后即大选落败、显示和平时期需求不同。适用危机应对/领导力/表达说服;不适用投资/认知偏误与理性决策。"},"persona_anchor":{"primary":[{"source":"case","case_id":"churchill-c1","note":"用户''处在一个看似必败、最黑暗的至暗时刻、几乎想放弃''时，以丘吉尔绝不屈服类比：二战中法国沦陷、英国独自面对纳粹、形势极其危急，丘吉尔以''我们绝不投降''的坚定意志稳住了举国人心、撑到了战局逆转——在最黑暗看似必败时绝不轻言放弃、用决心撑到转机（但须与''确实该止损''区分）（绝不屈服为丘吉尔二战领导与演讲所载→确证）"},{"source":"case","case_id":"churchill-c2","note":"用户''在危机中要凝聚团队、动员士气、却不知如何说''时，以丘吉尔战时演讲类比：他用''热血、辛劳、眼泪与汗水''这样真诚、有力、既坦诚艰难又给人希望的语言、把英国人的意志凝聚了起来——危机中的语言本身就是力量（战时演讲为史实→确证）"}]},"further_reading":[{"title":"丘吉尔《第二次世界大战回忆录》及传记","why":"绝不屈服、战时演讲、反绥靖、联盟的记述（A/B；殖民政策争议另有专门讨论）","type":"回忆录/传记"},{"title":"第二次世界大战史","why":"不列颠空战、同盟国联合等的史述（B）","type":"二战史"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/churchill.png","avatar_thumb":"/advisors/portraits/churchill.png","domain":"治理","person_id":"P-churchill","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '60cf1092df948d9d782648cf311e5832d5c0a85f309443f300b1d7ad4143d8f5', 14, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('clausewitz', 'P-clausewitz', '克劳塞维茨', 'strategy', '克劳塞维茨 · 战争哲学思维框架卡', '18世纪末—19世纪（1780—1831）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '战争是政治的延续 · 摩擦', '/advisors/portraits/clausewitz.png', '/advisors/portraits/clausewitz.png', 5, 0, '{"schema_version":1,"card_id":"clausewitz","name":"克劳塞维茨","title":"克劳塞维茨 · 战争哲学思维框架卡","era":"18世纪末—19世纪（1780—1831）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"战争是政治的延续","definition":"战争不是独立游戏，是政治用另一种手段的继续；目的由政治定，军事只是达成政治目的的工具，手段不可僭越目的","source":"《战争论》第一篇\"战争是政治交往的继续，掺入了另一种手段\"","source_tier":"primary","mechanism":"输入=一场冲突/对抗 → 处理=先问背后真正的政治/目的、让军事手段服从目的、不让手段僭越目的 → 输出=目的统御手段的方案","trigger":"要不要开战/升级、手段可能盖过目的时","modern_transfer":"任何''仗''先问背后真正的目的——价格战/收购战打赢却毁了你要的市场地位，就是军事胜利、政治失败","architecture":{"type":"hierarchy","components":["识别这场冲突","追问政治/目的","让手段服从目的","防手段僭越"]},"strategy_card_image":"kb-assets/clausewitz/model-1.png"},{"name":"摩擦","definition":"纸面计划与真实战场之间有一层\"摩擦\"——意外、疲劳、恐惧、信息失真，使最简单的事也变难；再好的计划都会被它磨损","source":"《战争论》第一篇\"摩擦\"概念","source_tier":"primary","mechanism":"输入=一份纸面计划 → 处理=预估意外/疲劳/恐惧/信息失真这层''摩擦''会磨损计划 → 输出=留足容错余量的稳健计划","trigger":"制定执行计划、容易假设一切按表执行时","modern_transfer":"纸面到现实有一层摩擦——任何计划都要预留容错余量，别假设一切按表推进","architecture":{"type":"flow","components":["拿出计划","预估摩擦点","留容错余量","接受会被磨损"]},"strategy_card_image":"kb-assets/clausewitz/model-2.png"},{"name":"重心","definition":"找出敌方力量所系的那个枢纽（军队主力、首都、同盟或民心），把打击集中于此；击垮重心则全局崩，分散用力则无功","source":"《战争论》\"重心(Schwerpunkt)\"概念","source_tier":"primary","mechanism":"输入=一个对手/对抗格局 → 处理=找出敌方力量所系的枢纽（主力/首都/同盟/民心）、集中打击于此 → 输出=击垮枢纽的集中打击","trigger":"资源有限、容易处处用力平摊时","modern_transfer":"找到对手的''命门''（现金流/关键客户/核心人才/联盟）、集中打击，别处处平摊","architecture":{"type":"matrix","components":["扫描对手力量","定位重心枢纽","集中力量","击垮枢纽动全局"]},"strategy_card_image":"kb-assets/clausewitz/model-3.png"},{"name":"绝对战争与现实战争","definition":"理论上战争有无限升级到极端的内在倾向（绝对战争），但现实中受政治目的、摩擦与时间所节制；须警惕升级逻辑、又用政治给它套缰","source":"《战争论》第一篇与第八篇绝对/现实战争之辨","source_tier":"primary","mechanism":"输入=一个有升级倾向的冲突 → 处理=认识其向极端升级的内在倾向、用政治目的/摩擦/时间给它套缰 → 输出=被节制的现实冲突","trigger":"冲突有''你加码我加码''的自我升级逻辑时","modern_transfer":"冲突有自我升级的逻辑，要主动用''目的''给它套缰、别被升级逻辑带走","architecture":{"type":"loop","components":["察觉升级倾向","评估极端风险","用政治目的节制","守住现实边界"]},"strategy_card_image":"kb-assets/clausewitz/model-4.png"},{"name":"防御强于进攻","definition":"防御是较强的作战形式——凭地利、内线、消耗与等待，弱者可在防御中拖垮强攻者；进攻则随推进而递减其顶点","source":"《战争论》第六篇\"防御\"、\"进攻顶点\"","source_tier":"primary","mechanism":"输入=一个攻守抉择 → 处理=认识防御是较强形式（地利/内线/消耗/等待）、识别进攻顶点（过点由盛转衰）→ 输出=该攻还是该守耗的判断","trigger":"弱势方面对强攻者、或攻势可能冲过顶点时","modern_transfer":"弱势方未必要正面进攻——守和耗、等对手冲过进攻顶点，是真实可行的战略","architecture":{"type":"matrix","components":["评攻守强弱","用地利内线消耗","识别进攻顶点","过点转危为机"]},"strategy_card_image":"kb-assets/clausewitz/model-5.png"}],"decision_principles":["先问政治目的：任何军事手段都要回答''为何而战、政治要什么''（第一篇，A）","为摩擦预留余量：计划要容错，别假设一切按表执行（第一篇第七章，A）","集中打击重心，不平摊兵力（第八篇，A）","识别进攻顶点，过点即转危为机（第七篇，A）","弱者善用防御与消耗，以时间和地利换强弱转换（第六篇，A）"],"inquiry_questions":["你这场''仗''背后真正的政治/目的是什么？手段有没有偷偷盖过了目的？","你的计划给''摩擦''——意外、延误、信息失真——留了多少余量？","对手的''重心''在哪？你是在打那个枢纽，还是在平摊力气？","你的攻势会不会冲过''顶点''？过了那个点，再进一步就由盛转衰了。","你现在是该强攻，还是该转入防御、用消耗和时间把对手拖过其顶点？"],"value_priorities":["政治目的 ＞ 军事上的彻底胜利（打赢了却背离政治目的=失败；手段永远服从目的）","为摩擦留余量的稳健计划 ＞ 纸面完美但脆弱的计划（真实战场会磨损一切精确设计）","集中于重心 ＞ 处处设防/平摊兵力（分散即无重点，击垮枢纽才动全局）","认清并守住进攻顶点 ＞ 一味乘胜追击（越过顶点的胜利会反噬）"],"blind_spots":["理论偏向大国对称会战与拿破仑式决战，对游击/不对称/叛乱战争着墨不足（学术分析，B）","''绝对战争向极端发展''的逻辑若被误读、剥离其政治节制，易被后人引为无限升级、总体战的辩护（思想接受史，B）","《战争论》生前未完成、各篇成于不同阶段、思想有自我修正，存在前后张力，单引一处可能断章取义（成书状况，A/B）","重抽象原理与思辨，操作性细节（编制、后勤、技战术）少，须与务实兵书(如戚继光)互补（文本范围，B）"],"applicable_domains":["战略","竞争博弈","风险评估","危机应对"],"match_tags":["战略","竞争博弈","风险评估","危机应对","系统分析","批判思辨","对抗性思维","近代欧洲"],"linked_cases":["clausewitz-c1","clausewitz-c2","clausewitz-c3"],"life_tags":[{"tag":"著战争论","tier":"primary"},{"tag":"参普鲁士改革","tier":"secondary"},{"tag":"任军校校长","tier":"secondary"},{"tag":"提战争迷雾","tier":"primary"}],"voice_profile":{"notes":"思辨缜密；概念思辨与定义先行；承认不确定与例外；德意志思辨长句"},"references":[{"ref_id":"clausewitz-s1","title":"《战争论》第一篇（论战争的性质）","locator":"第一章第24节\"战争是政治交往以另一种手段的继续\"；第七章\"摩擦\"；第一章向极端发展之辨","source_tier":"primary","supports_models":["战争是政治的延续","摩擦","绝对战争与现实战争"],"supports_cases":["clausewitz-c1","clausewitz-c2"],"note":"原典一手；第一篇同时支撑政治从属、摩擦、绝对/现实战争三模型"},{"ref_id":"clausewitz-s2","title":"《战争论》第八篇（战争计划）","locator":"第四章\"敌人的重心\"；现实战争受政治节制段","source_tier":"primary","supports_models":["重心","绝对战争与现实战争"],"note":"原典一手"},{"ref_id":"clausewitz-s3","title":"《战争论》第六篇·第七篇（防御 / 进攻）","locator":"第六篇\"防御是较强的作战形式\"；第七篇\"进攻的顶点\"","source_tier":"primary","supports_models":["防御强于进攻"],"note":"原典一手"},{"ref_id":"clausewitz-s4","title":"克劳塞维茨传记 / 百科（耶拿-奥尔施泰特1806被俘）","locator":"1806-10-14 会战；任奥古斯特亲王副官、成两万五千俘虏之一","source_tier":"primary","supports_cases":["clausewitz-c1"],"note":"战役信史+其副官角色有记载；理论催生为思想史归因"},{"ref_id":"clausewitz-s5","title":"史载《陶罗根协定》(1812)","locator":"Convention of Tauroggen 斡旋记载","source_tier":"secondary","supports_cases":["clausewitz-c2"],"note":"协定为信史；其个人贡献份额各史述不一，故C2 historicity=存疑"},{"ref_id":"clausewitz-s6","title":"19世纪\"耶拿画图\"传说（legend）","locator":"广泛流传之少年神算传说","source_tier":"tertiary","supports_cases":["clausewitz-c3"],"note":"明确为传说；仅支撑C3传说对照条目，不支撑任何core_model"}],"material_type":"textual","reasoning_skeleton":{"signature":"先问这场仗背后的政治目的、别让手段盖过目的；给现实的''摩擦''留足余量，把力量集中打对手的重心；警惕冲突向极端升级，弱势时善用防御与消耗、等对手冲过进攻顶点","steps":[{"invoke":"战争是政治的延续","action":"先问背后真正的政治/目的，确认手段没有偷偷盖过目的"},{"invoke":"重心","action":"找出对手力量所系的枢纽（命门），把力量集中打这里、别平摊"},{"invoke":"摩擦","action":"给计划预留意外/延误/信息失真的容错余量，别假设按表执行"},{"invoke":"绝对战争与现实战争","action":"警惕冲突自我升级的逻辑，用''目的''给它套缰、别被升级带走"},{"invoke":"防御强于进攻","action":"弱势时善用防御与消耗、等对手冲过进攻顶点，再转危为机"}],"contrast":"与孙子相反（东西方两座军事高峰）：孙子慎战、能不打就不打、''不战而屈人之兵''、靠庙算压缩不确定；克劳塞维茨不预设回避、该不该打由政治目的定、直面''摩擦''承认计划必被磨损、击垮重心。同一道''我方弱、对手强，该不该正面打''，孙子先伐谋伐交避实击虚，克氏先问政治目的、再用防御与消耗把对手拖过进攻顶点（见孙子卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"clausewitz-c1","note":"用户''经历一场自己左右不了的惨败、怎么办''时，以亲历耶拿-奥尔施泰特惨败被俘类比：他当时只是亲王副官、无决策权，真正的''判断''发生在战后——把这场惨败拆解成摩擦、政治从属、改革必要性等可迁移原理，成为《战争论》的思想原点（事件确证；其战场角色被动，呈现须落在''战后反思''、不夸大其战场作用）"},{"source":"case","case_id":"clausewitz-c2","note":"用户''决定全局的也许不是硬碰硬、而是改变阵营/结构的一纸协定''时，以参与促成《陶罗根协定》类比：他以俄方联络参谋身份斡旋、推动普军倒戈抗法——军事价值最终由它服务的政治转向兑现（协定为信史；其个人份额各史述不一、historicity 存疑，呈现用''参与促成''而非''主导''）"}]},"further_reading":[{"title":"克劳塞维茨《战争论》(Vom Kriege)","why":"战争是政治的延续/摩擦/重心/进攻顶点的源头；注意生前未完成、各篇有前后张力，宜配导读读","type":"original"},{"title":"雷蒙·阿隆《克劳塞维茨：战争哲学家》","why":"权威研究，帮你区分克氏本意与后世（总体战）误读，避免断章取义","type":"解读"},{"title":"《战争论》精选导读本","why":"《战争论》原著艰深冗长，导读本先抓五个核心概念再回原典，效率更高","type":"解读"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/clausewitz.png","avatar_thumb":"/advisors/portraits/clausewitz.png","domain":"战略","person_id":"P-clausewitz","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '1c080dc9c20ce9b848a66e1d9970da7d78f3090b7962e1df28ea9a0dab7800f1', 15, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('columbus', 'P-columbus', '哥伦布', 'exploration', '哥伦布 · 锲而不舍探索与驶向未知思维框架卡', '近代（1451—1506）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '锲而不舍推销愿景 · 敢于驶向未知', '/advisors/portraits/columbus.png', '/advisors/portraits/columbus.png', 5, 0, '{"schema_version":1,"card_id":"columbus","name":"哥伦布","title":"哥伦布 · 锲而不舍探索与驶向未知思维框架卡","era":"近代（1451—1506）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"锲而不舍推销愿景","definition":"为一个大胆的、不被看好的设想，不屈不挠地向一个又一个潜在的支持者反复游说、争取资源——被拒绝多次也不放弃，直到有人点头","source":"哥伦布游说多国王室","source_tier":"secondary","mechanism":"输入=被拒几次就放弃一个不被看好的设想 → 处理=不屈不挠向一个又一个潜在支持者反复游说争取 → 输出=直到有人点头(锲而不舍推销)","trigger":"要为一个不被看好的设想争取资源时","modern_transfer":"为一个大胆的、不被看好的设想、不屈不挠地向一个又一个潜在的支持者(投资人、上级、伙伴)反复游说、争取资源——被拒绝多次也不放弃、直到有人点头(哥伦布游说多国王室约8年、终获西班牙资助)","architecture":{"type":"flow","components":["别被拒几次就放弃一个不被看好的设想","不屈不挠向一个又一个潜在支持者","反复游说争取资源","直到有人点头"]},"strategy_card_image":"kb-assets/columbus/model-1.png"},{"name":"敢于驶向未知","definition":"在别人都不敢、都说不可能的时候，敢于离开\"熟悉的海岸线\"，驶入完全未知的领域，承担巨大的不确定与风险去探索","source":"哥伦布横渡大西洋","source_tier":"secondary","mechanism":"输入=只敢待在熟悉的海岸线 → 处理=敢于驶入完全未知的远洋承担巨大不确定与风险 → 输出=机会在无人敢去处(驶向未知)","trigger":"面对未知的重大机会时","modern_transfer":"在别人都不敢、都说不可能的时候、敢于离开''熟悉的海岸线''、驶入完全未知的领域、承担巨大的不确定与风险去探索——重大的机会往往在无人敢去的地方(哥伦布敢于驶入未知的大西洋)〔但其判断也建立在错误的地理估算上、且其''发现''酿成对原住民的殖民灾难、见盲区〕","architecture":{"type":"flow","components":["别只敢待在熟悉的海岸线","在别人都说不可能时","敢于驶入完全未知的领域承担风险","重大机会往往在无人敢去的地方"]},"strategy_card_image":"kb-assets/columbus/model-2.png"},{"name":"信念坚定与稳住人心","definition":"一旦认定了方向，就坚定地行动，并在过程漫长、艰难、同伴动摇想放弃时稳住人心、再坚持一下——很多时候成败就差最后的坚持","source":"哥伦布航行中坚持西行","source_tier":"secondary","mechanism":"输入=同伴动摇想放弃就跟着放弃 → 处理=认定方向坚定行动并在动摇时稳住人心再坚持 → 输出=成败差最后坚持(信念坚定)","trigger":"过程漫长艰难、同伴动摇时","modern_transfer":"一旦认定了方向、就坚定地行动、并在过程漫长、艰难、同伴动摇想放弃时稳住人心、再坚持一下——很多时候成败就差最后的坚持(哥伦布在船员几近哗变时说服他们再航行几天、终于发现陆地)〔但坚定也可能是固执:他至死误以为到的是亚洲、见盲区〕","architecture":{"type":"flow","components":["别同伴一动摇就跟着放弃","一旦认定方向就坚定地行动","在同伴动摇时稳住人心再坚持一下","很多时候成败就差最后的坚持"]},"strategy_card_image":"kb-assets/columbus/model-3.png"},{"name":"务实的专业准备","definition":"再大胆的探索，也要建立在扎实的专业准备、技术与经验之上——不是凭一腔热血蛮干，而是把能准备的都准备好，有备而行","source":"哥伦布的航海技艺","source_tier":"secondary","mechanism":"输入=凭一腔热血蛮干 → 处理=把大胆设想建立在扎实的技术准备经验上有备而行 → 输出=有备而行(专业准备)","trigger":"要把大胆设想付诸行动时","modern_transfer":"再大胆的探索、也要建立在扎实的专业准备、技术与经验之上——不是凭一腔热血蛮干、而是把能准备的(技术、补给、知识)都准备好、有备而行(哥伦布是经验丰富的航海家)","architecture":{"type":"hierarchy","components":["别凭一腔热血蛮干","把大胆的设想建立在扎实的专业准备技术与经验上","把能准备的技术补给知识都准备好","有备而行"]},"strategy_card_image":"kb-assets/columbus/model-4.png"},{"name":"把握并放大机会","definition":"当你（哪怕偶然）发现了一个有重大价值的机会——要敏锐地意识到它的价值，迅速地宣告、确立、争取资源去放大它，把\"第一次\"变成持续的成果","source":"哥伦布宣告发现、争取后续航行","source_tier":"secondary","mechanism":"输入=发现了有价值的东西却不善宣告确立放大 → 处理=敏锐意识到价值迅速宣告确立争取资源放大 → 输出=把第一次变成持续成果(放大机会)","trigger":"偶然发现一个有重大价值的机会时","modern_transfer":"当你(哪怕偶然)发现了一个有重大价值的机会——要敏锐地意识到它的价值、迅速地宣告、确立、争取资源去放大它、把''第一次''变成持续的成果(哥伦布发现后迅速宣告并争取了后续航行)〔注:他至死误以为到的是亚洲、且后续是殖民的开端、见盲区〕","architecture":{"type":"flow","components":["别发现了有价值的东西却不善宣告确立放大","敏锐地意识到它的价值","迅速地宣告确立争取资源去放大它","把第一次变成持续的成果"]},"strategy_card_image":"kb-assets/columbus/model-5.png"}],"decision_principles":["为不被看好的设想，不屈不挠地向一个个潜在支持者反复游说、争取资源","在别人都说不可能时，敢于驶离''熟悉的海岸线''、进入未知","认定方向就坚定行动，在同伴动摇时稳住人心、再坚持一下","再大胆的探索也要建立在扎实的专业准备、技术与经验之上","敏锐意识到机会的价值，迅速宣告、确立、争取资源去放大它"],"inquiry_questions":["为一个不被看好的设想，你是被拒几次就放弃、还是锲而不舍地争取支持？","在别人都说不可能时，你是守在''熟悉的海岸线''、还是敢于驶向未知？","同伴动摇想放弃时，你是跟着放弃、还是稳住人心、再坚持一下？","你的大胆探索，是凭一腔热血蛮干、还是建立在扎实的专业准备上？","发现一个有价值的机会时，你是否敏锐地意识到、并迅速去确立、放大它？"],"value_priorities":["锲而不舍直到成功 ＞ 被拒就放弃（游说多国王室约8年）","驶向未知 ＞ 守在熟悉的海岸线（横渡大西洋（但建立在错误估算上））","坚定再坚持 ＞ 同伴动摇就放弃（船员哗变时坚持（但坚定也可能是固执））"],"blind_spots":["【必须正视、绝不美化】哥伦布的''发现''给美洲原住民带来了深重的灾难——随之而来的殖民、奴役、屠杀与旧大陆传入的疾病，导致原住民人口锐减；他本人在其总督任内对原住民与殖民地的统治也以残酷著称。这是其历史影响中沉重而黑暗的一面（史，A/B，严肃客观标注）。","哥伦布的整个航行建立在错误的地理估算上（他严重低估了地球周长、以为向西不远即可到亚洲）——他至死都误以为自己到达的是亚洲、而非一块''新大陆''（史，B，客观标注）。","其''坚定的信念''也是一种固执——他拒绝承认自己到的不是亚洲；坚定与固执只有一线之隔（原理推断，B）。","其成功也极大地依赖运气（西半球恰好有一块他不知道的大陆挡在途中，否则按其错误估算、船队很可能因补给耗尽而葬身大洋）（史，B，客观标注）。"],"applicable_domains":["创新","危机应对","竞争博弈"],"match_tags":["创新","危机应对","竞争博弈","长期主义","务实渐进","直觉决断","近代欧洲"],"linked_cases":["columbus-c1","columbus-c2","columbus-c3","columbus-c4"],"life_tags":[{"tag":"横渡大西洋","tier":"secondary"},{"tag":"抵达美洲","tier":"secondary"},{"tag":"完成四次航行","tier":"secondary"},{"tag":"开辟新航路","tier":"secondary"}],"voice_profile":{"notes":"执着冒险、坚定不移；敢入未知；锲而不舍争取支持；务实的航海家"},"references":[{"ref_id":"columbus-s1","title":"哥伦布航海日志、传记及大航海时代史","locator":"锲而不舍、驶向未知、坚持、准备、放大机会、殖民影响","source_tier":"primary","supports_models":["锲而不舍推销愿景","敢于驶向未知","信念坚定与稳住人心","务实的专业准备","把握并放大机会"],"supports_cases":["columbus-c1","columbus-c2","columbus-c3","columbus-c4"],"note":"一手/二手·日志与史"},{"ref_id":"columbus-s2","title":"大航海时代与殖民史研究","locator":"航行、对美洲原住民的影响","source_tier":"secondary","supports_models":["敢于驶向未知","把握并放大机会"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"为不被看好的设想不屈不挠向一个又一个潜在支持者反复游说争取直到有人点头(锲而不舍推销愿景)；在别人都说不可能时敢于离开熟悉的海岸线驶入完全未知的领域(敢于驶向未知)；一旦认定方向就坚定行动在同伴动摇时稳住人心再坚持一下(信念坚定与稳住人心)；再大胆的探索也建立在扎实的专业准备技术与经验上(务实的专业准备)；敏锐意识到机会的价值迅速宣告确立争取资源放大它(把握并放大机会)","steps":[{"invoke":"锲而不舍推销愿景","action":"为一个不被看好的设想，你是被拒几次就放弃、还是锲而不舍地争取支持？"},{"invoke":"敢于驶向未知","action":"在别人都说不可能时，你是守在''熟悉的海岸线''、还是敢于驶向未知？"},{"invoke":"信念坚定与稳住人心","action":"同伴动摇想放弃时，你是跟着放弃、还是稳住人心、再坚持一下？"},{"invoke":"务实的专业准备","action":"你的大胆探索，是凭一腔热血蛮干、还是建立在扎实的专业准备上？"},{"invoke":"把握并放大机会","action":"发现一个有价值的机会时，你是否敏锐地意识到、并迅速去确立、放大它？"}],"contrast":"与郑和不同(关键差异·重点·历史诚实)：**郑和是''国家力量组织的大规模远航''(规模宏大的宝船队、以和平外交、朝贡贸易、宣扬国威为主、不殖民、不为个人)**；**哥伦布是''个人争取王室赞助的探险''(为个人的功名与利益、其''发现''开启了欧洲对美洲的殖民、给原住民带来深重灾难)**——郑和是和平的官方远航、哥伦布是个人探险且开启了殖民的黑暗一页(见郑和卡;这一差异本身即须正视的历史诚实)。与张骞不同：张骞是奉官方使命''凿空''西域、以外交联络为主;哥伦布是个人锲而不舍争取赞助的远洋探险(见张骞卡)。【射程/盲区·历史诚实·极重点】哥伦布之道在''锲而不舍推销、敢于驶向未知、坚定稳住人心、务实准备、把握放大机会''确有可迁移的探索精神价值，但①【必须正视、绝不美化】其''发现''给美洲原住民带来深重灾难——殖民、奴役、屠杀与疾病致原住民人口锐减、他本人统治亦以残酷著称、这是沉重黑暗的一面、严肃客观标注;②其航行建立在错误的地理估算上、他至死误以为到的是亚洲;③其坚定也是固执、拒绝承认到的不是亚洲;④其成功极大依赖运气(恰有一块他不知道的大陆挡在途中)。适用创新/危机应对/竞争博弈;不适用投资/修身自省。"},"persona_anchor":{"primary":[{"source":"case","case_id":"columbus-c1","note":"用户''有一个大胆的设想/项目、但不被看好、找了一两个潜在的支持者(投资人/上级)被拒后就想放弃''时，以哥伦布游说王室类比：他为了''向西航行到亚洲''的设想、先后向葡萄牙、西班牙等多国王室游说、被拒绝、被搁置、前后约8年、屡屡碰壁也不放弃、终于说服西班牙王室资助;为一个不被看好的设想、不屈不挠地向一个又一个潜在的支持者反复游说、争取资源、被拒多次也不放弃、直到有人点头（哥伦布游说多国王室约8年终获资助为史实→确证）"},{"source":"case","case_id":"columbus-c3","note":"用户''一件事做到中途、过程漫长艰难、团队开始动摇、想放弃、自己也快撑不住''时，以哥伦布航行中坚持类比：横渡大西洋的航程远超预期、迟迟不见陆地、船员恐惧、几近哗变;哥伦布稳住人心、说服他们再航行几天——结果不久就发现了陆地;认定方向后坚定地行动、在同伴动摇时稳住人心、再坚持一下、很多时候成败就差最后的坚持〔但也要分清:坚定与固执只有一线之隔、别把错误也一路坚持到底〕（哥伦布船员动摇时坚持为史述→确证）"}]},"further_reading":[{"title":"哥伦布航海日志、传记及大航海时代史","why":"锲而不舍、驶向未知、坚持、准备、放大机会的史述；及其殖民影响（A/B）","type":"史/航海日志"},{"title":"大航海时代与殖民史研究","why":"对哥伦布航行及其对美洲原住民影响的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/columbus.png","avatar_thumb":"/advisors/portraits/columbus.png","domain":"探索","person_id":"P-columbus","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '69b73c52b3c1b58b809c6201807098ca3dadcfb37dbaad4162917d1f7e111943', 16, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('confucius', 'P-confucius', '孔子', 'philosophy', '孔子 · 修己正名思维框架卡', '春秋（前551—前479）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '正名 · 推己及人忠恕', '/advisors/portraits/confucius.png', '/advisors/portraits/confucius.png', 5, 0, '{"schema_version":1,"card_id":"confucius","name":"孔子","title":"孔子 · 修己正名思维框架卡","era":"春秋（前551—前479）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"正名","definition":"行动或治理前先理顺\"名分与定义\"（每个角色/概念该做什么），名实相符，言行才有依据、秩序才立得起","source":"《论语·子路》","source_tier":"secondary","mechanism":"输入=名实不符、角色责任混乱、言行无依据 → 处理=先理顺名分与定义(每个角色该做什么)、名实相符 → 输出=言行有依据、秩序立得起","trigger":"治理/行动前、角色责任与定义混乱时","modern_transfer":"行动或治理前先理顺''名分与定义''——每个角色/概念到底指什么、该做什么；名实相符了，言行才有依据、秩序才立得起(名不正则言不顺)","architecture":{"type":"hierarchy","components":["理顺每个名分与定义","名实相符","言行有依据","秩序立得起"]},"strategy_card_image":"kb-assets/confucius/model-1.png"},{"name":"推己及人忠恕","definition":"拿\"自己愿不愿意被这样对待\"当尺子去推及他人——己所不欲、勿施于人，将心比心定行为","source":"《论语》（己所不欲勿施于人 / 忠恕之道）","source_tier":"secondary","mechanism":"输入=要定该怎么对待他人、缺一把尺子 → 处理=拿''自己愿不愿意被这样对待''当尺子去推及他人 → 输出=将心比心、行为有度(己所不欲勿施于人)","trigger":"要决定如何对待他人时","modern_transfer":"拿''自己愿不愿意被这样对待''当尺子去推及他人——己所不欲、勿施于人；将心比心，是定人际行为最简单可靠的准则","architecture":{"type":"flow","components":["问自己愿不愿被这样对待","以己为尺推及他人","己所不欲勿施于人","将心比心定行为"]},"strategy_card_image":"kb-assets/confucius/model-2.png"},{"name":"修己以安人","definition":"想影响他人或治理，先从修养自己开始——其身正、不令而行；其身不正、虽令不从","source":"《论语·宪问/子路》","source_tier":"secondary","mechanism":"输入=想影响他人或治理、却先要求别人 → 处理=先从修养自己开始(己身正)、再影响他人 → 输出=己正则不令而行(己身不正虽令不从)","trigger":"想影响他人或治理时","modern_transfer":"想影响他人或治理，先从修养自己开始——''其身正、不令而行；其身不正、虽令不从''；以身作则比发号施令更有效","architecture":{"type":"hierarchy","components":["先修养自己","己身端正","以身作则","不令而行"]},"strategy_card_image":"kb-assets/confucius/model-3.png"},{"name":"中庸执两用中","definition":"在\"过\"与\"不及\"两个极端之间，按具体情境取那个恰到好处的度——过犹不及","source":"《论语》《礼记·中庸》","source_tier":"secondary","mechanism":"输入=容易走''过''或''不及''的极端 → 处理=在两个极端之间、按具体情境取恰到好处的度 → 输出=恰当的度(过犹不及)","trigger":"容易走极端、需把握分寸时","modern_transfer":"在''过''与''不及''两个极端之间、按具体情境取那个恰到好处的度——过犹不及；中庸不是和稀泥，是动态地拿捏分寸","architecture":{"type":"flow","components":["识别过与不及两极端","按具体情境","取恰到好处的度","避免过犹不及"]},"strategy_card_image":"kb-assets/confucius/model-4.png"},{"name":"因材施教","definition":"同一个问题对不同的人给不同的答案——按对象的资质、性格、处境给不同的方法，不一刀切","source":"《论语·先进》（闻斯行诸）","source_tier":"secondary","mechanism":"输入=对所有人用同一套方法、效果差 → 处理=按对象的资质/性格/处境给不同的方法 → 输出=同一问题对不同的人给不同答案(不一刀切)","trigger":"教/带/管不同的人时","modern_transfer":"同一个问题对不同的人给不同的答案——按对象的资质、性格、处境因材施教、不一刀切(孔子对子路与冉有同问给相反的答案)","architecture":{"type":"matrix","components":["评估对象资质性格处境","按人定制方法","同问不同答","不一刀切"]},"strategy_card_image":"kb-assets/confucius/model-5.png"}],"decision_principles":["行动治理前先理顺名分与定义，名实相符言行才有依据","拿''自己愿不愿被这样对待''当尺子推及他人——己所不欲勿施于人","想影响他人先修养自己，以身作则胜过发号施令","在过与不及之间，按情境取恰到好处的度","按各人资质性格因材施教，不一刀切"],"inquiry_questions":["你这事里，每个角色/概念的''名分与定义''理顺了吗？名实相符吗？","你想要求/影响别人，自己先做到了吗？","你这样对待别人，自己愿不愿意被这样对待？","你是走了''过''或''不及''的极端，还是按情境取了恰好的度？","你对不同的人用的是同一套，还是按各人资质性格因材施教？"],"value_priorities":["名实相符的秩序 ＞ 名实混乱的将就（名不正则言不顺）","修己以正 ＞ 一味要求他人（其身正不令而行、其身不正虽令不从）","恰到好处的度 ＞ 过或不及的极端（过犹不及；中庸是拿捏分寸非和稀泥）"],"blind_spots":["《论语》为弟子及后学追记编纂、非孔子自著，具体言论的字句与语境经后人整理，归属与原意须谨慎（史料批判，B，〔慎〕）。","其思想偏向维护既有等级秩序（君君臣臣）与渐进改良，对根本性变革/制度颠覆着力少、有保守倾向（思想评议，B）。","''正名''与礼制在快速变化或多元价值的情境下，可能流于形式或固化等级（原理推断，B）。","重道德感化与人治，对制度性约束（法治）相对轻视（与法家对照，B）。"],"applicable_domains":["修身自省","领导力","组织管理","价值与伦理"],"match_tags":["修身自省","领导力","组织管理","价值与伦理","利他取向","务实渐进","系统分析","古代东亚"],"linked_cases":["confucius-c1","confucius-c2","confucius-c3"],"life_tags":[{"tag":"周游列国","tier":"secondary"},{"tag":"删订六经","tier":"secondary"},{"tag":"传论语","tier":"primary"},{"tag":"倡有教无类","tier":"primary"}],"voice_profile":{"notes":"温而厉、恭而安；重伦理与秩序；循循善诱、因人而异；以身教重于言教"},"references":[{"ref_id":"confucius-s1","title":"《论语》","locator":"子路(正名)、卫灵公/颜渊(忠恕)、宪问/子路(修己其身正)、先进(过犹不及/闻斯行诸)","source_tier":"secondary","supports_models":["正名","推己及人忠恕","修己以安人","因材施教"],"supports_cases":["confucius-c1","confucius-c2","confucius-c3"],"note":"弟子及后学追记编纂、非自著→字句语境经整理，重义理"},{"ref_id":"confucius-s2","title":"《礼记·中庸》","locator":"执其两端用其中、过犹不及","source_tier":"secondary","supports_models":["中庸执两用中"],"note":"中庸思想（旧题子思作、成书有争议）"},{"ref_id":"confucius-s3","title":"《史记·孔子世家》","locator":"孔子生平、为政与教学","source_tier":"secondary","supports_models":["修己以安人"],"supports_cases":["confucius-c3"],"note":"后世史传，生平佐证"}],"material_type":"textual","reasoning_skeleton":{"signature":"行动治理前先理顺名分与定义、名实相符言行才有依据(正名)；拿''自己愿不愿被这样对待''当尺子推及他人(忠恕)；想影响他人先修养自己、以身作则不令而行(修己以安人)；在过与不及之间按情境取恰好的度(中庸)；同一问题对不同的人因材施教给不同答案","steps":[{"invoke":"正名","action":"你这事里，每个角色/概念的''名分与定义''理顺了吗？名实相符吗？"},{"invoke":"修己以安人","action":"你想要求/影响别人，自己先做到了吗？(其身正不令而行)"},{"invoke":"推己及人忠恕","action":"你这样对待别人，自己愿不愿意被这样对待？(己所不欲勿施于人)"},{"invoke":"中庸执两用中","action":"你是走了''过''或''不及''的极端，还是按情境取了恰好的度？"},{"invoke":"因材施教","action":"你对不同的人用的是同一套，还是按各人资质性格因材施教？"}],"contrast":"与老子不同(关键差异·同为先秦哲学)：**老子主''无为/柔弱胜刚强/反者道之动''、顺自然不强为、辩证反向**；**孔子主''正名/忠恕/修己/中庸/因材施教''、入世建立伦理秩序、积极有为**——老子是无为顺势、孔子是有为修治(见老子卡)。与王阳明不同：王阳明是''知行合一+致良知+事上磨练''的心学实践；孔子是伦理秩序与修己的原典(见王阳明卡)。与苏格拉底不同：苏格拉底用诘问助产、拆穿无知；孔子重正名修己、建立伦理(见苏格拉底卡)。与马可奥勒留/庄子区分：奥勒留是斯多葛控制二分、庄子是齐物逍遥相对；孔子是入世伦理秩序。【射程/盲区】孔子之道适用于''修身/伦理/领导/组织秩序''，但①《论语》为弟子后学追记、字句语境经整理、归属须谨慎；②偏维护既有等级秩序与渐进改良、对根本变革着力少、有保守倾向；③重道德感化与人治、对制度性法治相对轻视。适用修身自省/领导力/组织管理/价值与伦理；不适用创新研发/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"confucius-c1","note":"用户''团队/事情乱、不知从何抓起''时，以孔子''必也正名乎''类比：子路问从政先做什么，孔子答先正名——先把每个角色/概念的名分与定义理顺、名实相符，言行与秩序才有依据（正名为《论语·子路》明载→确证；惟《论语》后人追记、字句语境宜重义理、慎抠字面）"},{"source":"case","case_id":"confucius-c2","note":"用户''对不同的人该不该用同一套办法''时，以孔子''闻斯行诸''类比：子路与冉有同问''听到就该做吗''，孔子因子路好勇而抑之、因冉有退缩而进之、给相反答案——按各人资质性格因材施教（闻斯行诸为《论语·先进》明载→确证）"}]},"further_reading":[{"title":"《论语》","why":"正名、忠恕、修己、中庸、因材施教的一手出处（弟子后学追记、字句经整理）","type":"原典"},{"title":"《礼记·中庸》《史记·孔子世家》","why":"中庸思想与孔子生平的进一步材料","type":"文本"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/confucius.png","avatar_thumb":"/advisors/portraits/confucius.png","domain":"哲学","person_id":"P-confucius","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'f27814e52cc0d97d61fb4e5fe47e60f0f00c1a309591438832e48d79bb903c02', 17, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('curie', 'P-curie', '居里夫人', 'science', '居里夫人 · 极致严谨实验与苦功坚韧思维框架卡', '现代（1867—1934）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '极致严谨的实验 · 苦功与坚韧', '/advisors/portraits/curie.png', '/advisors/portraits/curie.png', 5, 0, '{"schema_version":1,"card_id":"curie","name":"居里夫人","title":"居里夫人 · 极致严谨实验与苦功坚韧思维框架卡","era":"现代（1867—1934）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"极致严谨的实验","definition":"别靠猜想或大概——以极其严谨、精确、可重复的实验与测量去验证你的判断，用铁一般的数据说话","source":"居里夫人提纯镭","source_tier":"secondary","mechanism":"输入=靠猜想或大概 → 处理=以极严谨精确可重复的实验测量验证提纯、用数据说话 → 输出=铁一般的数据(极致严谨实验)","trigger":"要验证一个判断/提纯一个结果时","modern_transfer":"别靠猜想或大概——以极其严谨、精确、可重复的实验与测量去验证你的判断;用铁一般的数据说话(居里夫人从数吨矿渣中精确测量、提纯出微量的镭)","architecture":{"type":"flow","components":["别靠猜想或大概","以极严谨精确可重复的实验与测量","验证判断提纯结果","用铁一般的数据说话"]},"strategy_card_image":"kb-assets/curie/model-1.png"},{"name":"苦功与坚韧","definition":"重大的成果往往要熬过极其繁重、枯燥、漫长的苦功——别指望捷径，以超常的坚韧、耐心、专注把它做到底","source":"居里夫人棚屋提镭","source_tier":"secondary","mechanism":"输入=指望捷径、畏惧繁重枯燥 → 处理=以超常坚韧耐心专注把繁重漫长的苦功做到底 → 输出=熬过苦功见成果(苦功坚韧)","trigger":"面对极繁重漫长的工作时","modern_transfer":"重大的成果往往要熬过极其繁重、枯燥、漫长的苦功——别指望捷径、以超常的坚韧、耐心、专注把这份苦功做到底(居里夫人在简陋棚屋中、历经数年从数吨矿渣中提炼出镭)〔苦功路线极消耗、见盲区〕","architecture":{"type":"flow","components":["别指望捷径畏惧繁重枯燥","以超常的坚韧耐心专注","把繁重漫长的苦功做到底","熬过苦功见成果"]},"strategy_card_image":"kb-assets/curie/model-2.png"},{"name":"纯粹的求知而非名利","definition":"让纯粹的求知欲、对真理与意义本身的追求，而非名利来驱动你","source":"居里夫人放弃镭专利","source_tier":"secondary","mechanism":"输入=被名利驱动 → 处理=让纯粹的求知欲对真理本身的追求驱动、淡泊名利 → 输出=为真理而研究(纯粹求知)","trigger":"问自己为何而做时","modern_transfer":"让纯粹的求知欲、对真理与意义本身的追求、而非名利来驱动你——居里夫人甚至放弃了镭的提纯专利、让它造福世人〔但也使她一生科研经费与生活清贫、见盲区〕","architecture":{"type":"hierarchy","components":["别被名利驱动","让纯粹的求知欲","对真理与意义本身的追求来驱动","为真理而研究"]},"strategy_card_image":"kb-assets/curie/model-3.png"},{"name":"大胆假设新现象","definition":"面对一个反常的、无法用已知解释的现象，别忽视或硬塞进旧框架——大胆假设它背后是一种全新的、未被认识的东西，并去追究它","source":"居里夫人对放射性的洞察","source_tier":"secondary","mechanism":"输入=忽视反常现象或硬塞旧框架 → 处理=大胆假设反常背后是全新未知的东西并追究 → 输出=发现全新属性(大胆假设新现象)","trigger":"面对反常、无法用已知解释的现象时","modern_transfer":"面对一个反常的、无法用已知解释的现象、别忽视或硬塞进旧框架——大胆假设它背后是一种全新的、未被认识的东西、并去追究它(居里夫人由铀盐异常推断''放射性''是原子本身的属性、而非化学反应)","architecture":{"type":"flow","components":["别忽视反常现象或硬塞进旧框架","大胆假设它背后是全新未被认识的东西","并去追究它","发现全新的属性"]},"strategy_card_image":"kb-assets/curie/model-4.png"},{"name":"在偏见中坚持","definition":"在充满偏见、轻视或不被看好的环境中，不靠争辩，而靠做出无可辩驳的实绩，用成就本身赢得应有的地位与尊重","source":"居里夫人打破性别偏见","source_tier":"secondary","mechanism":"输入=因外界轻视偏见而退缩或空争辩 → 处理=靠做出无可辩驳的实绩、用成就赢得地位 → 输出=成就打破偏见(偏见中坚持)","trigger":"在充满偏见、不被看好的环境中时","modern_transfer":"在充满偏见、轻视或不被看好的环境中、不靠争辩、而靠做出无可辩驳的实绩、用成就本身赢得应有的地位与尊重(居里夫人作为女性、以两度诺奖的成就打破偏见)","architecture":{"type":"flow","components":["别因外界轻视偏见而退缩或空争辩","靠做出无可辩驳的实绩","用成就本身赢得地位与尊重","成就打破偏见"]},"strategy_card_image":"kb-assets/curie/model-5.png"}],"decision_principles":["别靠猜想，以极严谨、精确、可重复的实验与数据说话","重大成果要熬过繁重漫长的苦功，以超常坚韧做到底（别指望捷径）","让纯粹的求知欲、而非名利来驱动（居里夫人放弃了镭专利）","面对反常现象，大胆假设它背后是全新未知的东西并去追究","在偏见中不靠争辩，靠无可辩驳的实绩赢得地位"],"inquiry_questions":["你是靠猜想/大概、还是以极严谨、精确、可重复的实验与数据说话？","你是指望捷径、还是以超常的坚韧把繁重漫长的苦功做到底？","你是被名利驱动、还是让纯粹的求知欲、对真理本身的追求驱动？","面对反常现象，你是忽视/硬塞旧框架、还是大胆假设它背后是全新的东西？","在偏见中你是退缩/空争辩、还是靠无可辩驳的实绩赢得地位？"],"value_priorities":["铁一般的数据 ＞ 靠猜想大概（从数吨矿渣精确提纯镭）","纯粹的求知 ＞ 名利驱动（放弃镭专利）","成就打破偏见 ＞ 退缩或空争辩（两度诺奖）"],"blind_spots":["居里夫人的''苦功坚韧''路线极其消耗，且当时不知放射性的危害，长期暴露严重损害了她的健康（史，B，客观标注、点到为止）。","其极致严谨、专注的方式，也意味着相对窄而深，不擅长广博的跨界（原理推断，B）。","纯粹淡泊名利、放弃专利的选择，也使她一生科研经费与生活清贫、举步维艰（史，B）。","其方法依赖极强的个人意志与天赋，对常人难以复制（原理推断，B）。"],"applicable_domains":["创新","修身自省","认知偏误与理性决策"],"match_tags":["创新","修身自省","认知偏误与理性决策","实验试错","长期主义","第一性原理","现当代欧洲"],"linked_cases":["curie-c1","curie-c2","curie-c3","curie-c4"],"life_tags":[{"tag":"发现钋与镭","tier":"secondary"},{"tag":"两获诺贝尔奖","tier":"secondary"},{"tag":"创居里研究所","tier":"secondary"},{"tag":"一战设X光车","tier":"secondary"}],"voice_profile":{"notes":"严谨坚韧、专注纯粹；以实验与数据立论；苦功不辍；淡泊名利"},"references":[{"ref_id":"curie-s1","title":"居里夫人传记及放射性研究科学史","locator":"严谨实验、苦功、纯粹求知、放射性发现、打破偏见","source_tier":"secondary","supports_models":["极致严谨的实验","苦功与坚韧","纯粹的求知而非名利","大胆假设新现象","在偏见中坚持"],"supports_cases":["curie-c1","curie-c2","curie-c3","curie-c4"],"note":"二手·传记与科学史"},{"ref_id":"curie-s2","title":"放射性与近代物理化学史研究","locator":"方法、贡献、健康代价","source_tier":"secondary","supports_models":["极致严谨的实验","大胆假设新现象"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"别靠猜想以极严谨精确可重复的实验与数据说话(极致严谨的实验)；重大成果要熬过繁重漫长的苦功以超常坚韧做到底别指望捷径(苦功与坚韧)；让纯粹的求知欲对真理本身的追求而非名利来驱动(纯粹的求知而非名利)；面对反常现象大胆假设它背后是全新未知的东西并去追究(大胆假设新现象)；在偏见中不靠争辩靠无可辩驳的实绩赢得地位(在偏见中坚持)","steps":[{"invoke":"极致严谨的实验","action":"你是靠猜想/大概、还是以极严谨、精确、可重复的实验与数据说话？"},{"invoke":"苦功与坚韧","action":"你是指望捷径、还是以超常的坚韧把繁重漫长的苦功做到底？"},{"invoke":"纯粹的求知而非名利","action":"你是被名利驱动、还是让纯粹的求知欲、对真理本身的追求驱动？"},{"invoke":"大胆假设新现象","action":"面对反常现象，你是忽视/硬塞旧框架、还是大胆假设它背后是全新的东西？"},{"invoke":"在偏见中坚持","action":"在偏见中你是退缩/空争辩、还是靠无可辩驳的实绩赢得地位？"}],"contrast":"与爱因斯坦不同(关键差异)：**爱因斯坦以''思想实验、理论建构''在头脑中重构物理(理论物理的想象)**；**居里夫人以''极致严谨的实验、苦功提纯、精确测量''在实验台上发现新元素与放射性(实验科学的苦功)**——爱因斯坦偏理论与想象、居里夫人偏实验与苦功(见爱因斯坦卡)。与达·芬奇不同：达·芬奇博观跨界、兴趣广博;居里夫人窄而深、极致专注于放射性(见达·芬奇卡)。与达尔文不同：达尔文以观察建演化理论;居里夫人以实验提纯发现新元素(见达尔文卡)。【射程/盲区·历史诚实】居里夫人之道在''极致严谨实验、苦功坚韧、纯粹求知、大胆假设新现象、偏见中坚持''极有力(尤其实验科学、专注、坚韧)，但①''苦功坚韧''路线极消耗、且当时不知放射性危害、长期暴露严重损害了她的健康、客观标注点到为止;②极致严谨专注意味着相对窄而深、不擅广博跨界;③放弃专利的纯粹也使她一生清贫举步维艰;④方法依赖极强个人意志与天赋、常人难复制。适用创新/修身自省/认知偏误与理性决策;不适用投资/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"curie-c1","note":"用户''想验证一个判断、却满足于''差不多''''大概是''、缺乏严谨的证据''时，以居里夫人提纯镭类比：为了证明并得到''镭''这种新元素、她不满足于推断、而是从数吨沥青铀矿渣里、用极其严谨精确、可重复的化学分离与测量、一点点提纯出仅零点一克的镭、拿出了无可辩驳的实物与数据;别靠猜想或大概——以极严谨、精确、可重复的实验与数据说话（居里夫人提纯镭为史实→确证）"},{"source":"case","case_id":"curie-c2","note":"用户''面对一项极其繁重、枯燥、看不到头的苦功、想找捷径或放弃''时，以居里夫人棚屋提镭类比：她和丈夫在一间冬冷夏热、四处漏风的简陋棚屋里、用大锅一锅锅地熬煮、搅拌数吨沥青铀矿渣、历经数年、才提炼出微量的镭;重大的成果往往要熬过极繁重漫长的苦功、别指望捷径、以超常的坚韧把它做到底〔但也要量力、注意这种极致苦功的消耗〕（居里夫人棚屋提镭为史实→确证）"}]},"further_reading":[{"title":"居里夫人传记及放射性研究科学史","why":"严谨实验、苦功、纯粹求知、放射性发现、打破偏见的出处（B）","type":"传记/科学史"},{"title":"放射性与近代物理化学史研究","why":"对居里夫人方法与贡献（及健康代价）的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/curie.png","avatar_thumb":"/advisors/portraits/curie.png","domain":"科学","person_id":"P-curie","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '784de9676f19aaf193aacb72cf8744e36dd80d415d8be537f8dbd2cd077db518', 18, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('dalio', 'P-dalio', '达里奥', 'investing', '达里奥 · 原则系统化与极度透明思维框架卡', '现代（1949— ）', 'zh-CN', 'published', 'in_review', 'pending', 'living', 'rich', '痛苦加反思等于进步 · 极度求真与极度透明', '/advisors/portraits/dalio.png', '/advisors/portraits/dalio.png', 5, 0, '{"schema_version":1,"card_id":"dalio","name":"达里奥","title":"达里奥 · 原则系统化与极度透明思维框架卡","era":"现代（1949— ）","language":"zh-CN","status":"published","living_status":"living","core_models":[{"name":"痛苦加反思等于进步","definition":"把每一次痛苦、失败、挫折都当成学习的宝贵信号——\"痛苦 + 反思 = 进步\"，不回避或粉饰痛苦，而是直面它、反思它背后暴露的问题与教训","source":"达里奥《原则》","source_tier":"primary","mechanism":"输入=回避或粉饰痛苦失败 → 处理=把痛苦失败当学习信号、直面反思背后的教训 → 输出=痛苦变进步(痛苦反思进步)","trigger":"遭遇痛苦、失败、挫折时","modern_transfer":"把每一次痛苦、失败、挫折都当成学习的宝贵信号——''痛苦 + 反思 = 进步'';不回避或粉饰痛苦、而是直面它、反思它背后暴露的问题与教训、把它变成进步(达里奥《原则》)","architecture":{"type":"loop","components":["别回避或粉饰痛苦失败","把痛苦失败挫折当学习的信号","直面并反思它背后暴露的问题与教训","痛苦加反思等于进步"]},"strategy_card_image":"kb-assets/dalio/model-1.png"},{"name":"极度求真与极度透明","definition":"追求\"极度的真实\"与\"极度的透明\"——鼓励所有人坦诚地、不加掩饰地把真实想法和问题摆到台面上说，哪怕逆耳；掩盖问题才是最大的风险","source":"达里奥的桥水文化","source_tier":"primary","mechanism":"输入=掩盖问题、报喜不报忧 → 处理=追求极度真实透明、坦诚把问题摆台面说哪怕逆耳 → 输出=掩盖才是最大风险(极度透明)","trigger":"要不要坦诚暴露问题时","modern_transfer":"追求''极度的真实''与''极度的透明''——鼓励所有人坦诚地、不加掩饰地把真实想法和问题摆到台面上说、哪怕逆耳;掩盖问题才是最大的风险(达里奥的''极度透明'')〔执行极难、对多数组织水土不服、见盲区〕","architecture":{"type":"flow","components":["别掩盖问题报喜不报忧","追求极度的真实与极度的透明","坦诚把真实想法与问题摆到台面上说哪怕逆耳","掩盖问题才是最大的风险"]},"strategy_card_image":"kb-assets/dalio/model-2.png"},{"name":"把原则写下来系统化","definition":"把你从经验中学到的东西，提炼成一条条明确的\"原则\"、写下来、系统化——下次遇到\"同一类\"情况就有章可循，而非每次从头摸索","source":"达里奥《原则》","source_tier":"primary","mechanism":"输入=每次从头摸索、不沉淀 → 处理=把经验提炼成明确的原则写下来系统化、同类情况照原则办 → 输出=有章可循(原则系统化)","trigger":"想把经验沉淀为可复用方法时","modern_transfer":"把你从经验中学到的东西、提炼成一条条明确的''原则''、写下来、系统化——下次遇到''同一类''情况、就有章可循、而非每次从头摸索(达里奥把决策原则写成《原则》一书)〔但系统化也可能流于教条、见盲区〕","architecture":{"type":"hierarchy","components":["别每次从头摸索不沉淀","把经验提炼成一条条明确的原则","写下来系统化","同类情况就有章可循"]},"strategy_card_image":"kb-assets/dalio/model-3.png"},{"name":"可信度加权的决策","definition":"做集体决策时，别简单一人一票、也别老板一言堂——按每个人在\"这个具体问题\"上的可信度（过往的成功记录、推理的质量）来加权他们的意见","source":"达里奥\"可信度加权\"","source_tier":"primary","mechanism":"输入=一人一票或老板一言堂 → 处理=按每个人在该问题上的可信度(记录逻辑)加权意见 → 输出=加权而非平权或独断(可信度加权)","trigger":"做集体决策时","modern_transfer":"做集体决策时、别简单一人一票、也别老板一言堂——按每个人在''这个具体问题''上的可信度(过往的成功记录、推理的质量)来加权他们的意见(''可信度加权''、达里奥)","architecture":{"type":"matrix","components":["别简单一人一票也别老板一言堂","按每个人在这个具体问题上的可信度","过往成功记录与推理质量","加权他们的意见"]},"strategy_card_image":"kb-assets/dalio/model-4.png"},{"name":"像看机器一样理解系统","definition":"把你面对的复杂系统（经济、市场、组织）当成一台有因果、按规律运转的\"机器\"来理解——透过表象，看清驱动它运转的底层因果关系与规律","source":"达里奥\"经济机器\"","source_tier":"primary","mechanism":"输入=停在表象、不究因果 → 处理=把复杂系统当一台有因果规律的机器、看清底层因果 → 输出=看清驱动预判(经济机器)","trigger":"理解复杂系统(经济、市场、组织)时","modern_transfer":"把你面对的复杂系统(经济、市场、组织)当成一台有因果、按规律运转的''机器''来理解——透过表象、看清驱动它运转的底层因果关系与规律、才能预判它(达里奥''经济机器是如何运转的'')","architecture":{"type":"hierarchy","components":["别停在表象不究因果","把复杂系统当一台有因果规律的机器","透过表象看清驱动它运转的底层因果","看清规律才能预判"]},"strategy_card_image":"kb-assets/dalio/model-5.png"}],"decision_principles":["把痛苦、失败当学习信号——痛苦 + 反思 = 进步，别回避或粉饰","追求极度真实与极度透明，把问题摆到台面上说（执行极难、须因地制宜）","把经验提炼成明确的''原则''、写下来、系统化，让同类情况有章可循","集体决策按各人在该问题上的''可信度''加权，而非一人一票或一言堂","把复杂系统当成有因果规律的''机器''，看清底层因果才能预判"],"inquiry_questions":["遇到痛苦、失败，你是回避粉饰、还是直面反思、把它变成进步？","你是掩盖问题、报喜不报忧、还是追求极度真实与透明、把问题摆到台面上？","你是每次从头摸索、还是把经验提炼成明确的''原则''、写下来系统化？","集体决策你是一人一票/一言堂、还是按各人在该问题上的''可信度''加权？","你是停在表象、还是把系统当''机器''、看清驱动它的底层因果？"],"value_priorities":["痛苦化为进步 ＞ 回避粉饰痛苦（痛苦 + 反思 = 进步）","有章可循的原则 ＞ 每次从头摸索（《原则》系统化）","可信度加权 ＞ 一人一票或一言堂（believability-weighted）"],"blind_spots":["''极度透明''的桥水文化执行极难、对多数组织/文化水土不服，甚至可能演变成相互攻击或令人不适（史/原理，B，客观标注）。","把一切''系统化为原则''也可能流于教条、机械，忽视情境的独特性（原理推断，B）。","其宏观/''经济机器''的预测并非次次准确，宏观判断本就极难（史，B）。","【在世人物·框定】本卡仅为''基于其公开著作《原则》的方法论思维模拟、不代表本人真实观点''（框定）。"],"applicable_domains":["组织管理","投资","认知偏误与理性决策"],"match_tags":["组织管理","投资","认知偏误与理性决策","系统分析","概率思维","批判思辨","现当代北美"],"linked_cases":["dalio-c1","dalio-c2","dalio-c3","dalio-c4"],"life_tags":[{"tag":"创桥水基金","tier":"secondary"},{"tag":"著原则一书","tier":"primary"},{"tag":"创全天候策略","tier":"secondary"},{"tag":"提债务周期论","tier":"primary"}],"voice_profile":{"notes":"系统化、重原则；极度求真透明；理性加权决策；机器般理解世界"},"references":[{"ref_id":"dalio-s1","title":"达里奥《原则》、\"经济机器是如何运转的\"","locator":"痛苦+反思、极度透明、原则系统化、可信度加权、经济机器","source_tier":"primary","supports_models":["痛苦加反思等于进步","极度求真与极度透明","把原则写下来系统化","可信度加权的决策","像看机器一样理解系统"],"supports_cases":["dalio-c1","dalio-c2","dalio-c3","dalio-c4"],"note":"一手·原著（在世人物·限定方法论）"},{"ref_id":"dalio-s2","title":"桥水与系统化决策研究","locator":"方法论、桥水文化（含争议）","source_tier":"secondary","supports_models":["极度求真与极度透明","可信度加权的决策"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"把痛苦失败当学习信号痛苦加反思等于进步别回避粉饰(痛苦加反思等于进步)；追求极度真实与极度透明把问题摆到台面上说哪怕逆耳(极度求真与极度透明)；把经验提炼成明确的原则写下来系统化让同类情况有章可循(把原则写下来系统化)；集体决策按各人在该问题上的可信度加权而非一人一票或一言堂(可信度加权的决策)；把复杂系统当有因果规律的机器看清底层因果才能预判(像看机器一样理解系统)","steps":[{"invoke":"痛苦加反思等于进步","action":"遇到痛苦、失败，你是回避粉饰、还是直面反思、把它变成进步？"},{"invoke":"极度求真与极度透明","action":"你是掩盖问题、报喜不报忧、还是追求极度真实与透明、把问题摆到台面上？"},{"invoke":"把原则写下来系统化","action":"你是每次从头摸索、还是把经验提炼成明确的''原则''、写下来系统化？"},{"invoke":"可信度加权的决策","action":"集体决策你是一人一票/一言堂、还是按各人在该问题上的''可信度''加权？"},{"invoke":"像看机器一样理解系统","action":"你是停在表象、还是把系统当''机器''、看清驱动它的底层因果？"}],"contrast":"与索罗斯不同(关键差异·同涉宏观投资)：**索罗斯是''反身性+可错性''的认识论与宏观投机(认知与现实的反馈循环、押注远离均衡)**；**达里奥是''原则系统化+极度透明+可信度加权+经济机器''的方法论与组织文化(把经验系统化、靠文化与流程做对决策)**——索罗斯偏认识论与投机时机、达里奥偏系统化的原则与组织流程(见索罗斯卡)。与巴菲特不同：巴菲特重''集中、护城河、长期持有'';达里奥重''分散(全天候)、系统化原则、可信度加权''——一个集中守、一个系统化与分散(见巴菲特卡)。与凯恩斯/利弗莫尔不同：他们偏个人化的判断与交易;达里奥偏可系统化、可流程化、可团队执行的方法(见凯恩斯/利弗莫尔卡)。【射程/盲区·重点】达里奥之道在''痛苦反思、极度透明、原则系统化、可信度加权、经济机器''极有力(尤其个人成长、组织决策、宏观理解)，但①''极度透明''的桥水文化执行极难、对多数组织水土不服、甚至可能演变成相互攻击或不适、客观标注;②一切''系统化为原则''也可能流于教条、机械、忽视情境独特性;③其宏观''经济机器''预测并非次次准确;④【在世人物·框定】本卡仅基于其公开著作《原则》的方法论思维模拟、不代表本人观点。适用组织管理/投资/认知偏误与理性决策;不适用创作/修身自省。"},"persona_anchor":{"primary":[{"source":"case","case_id":"dalio-c1","note":"用户''刚经历一次痛苦的失败/挫折、只想赶紧翻篇、或归咎于运气、不愿直面''时，以达里奥''痛苦 + 反思 = 进步''类比：他1982年因看错行情几乎让公司破产、自己一度一无所有、但他把这次惨痛失败当作最宝贵的一课、深刻反思、由此建立起后来的风险原则与桥水;别回避或粉饰痛苦——把每一次痛苦、失败当成学习的信号、直面它、反思它背后的教训、把它变成进步（''痛苦+反思=进步''为达里奥《原则》→确证）"},{"source":"case","case_id":"dalio-c3","note":"用户''同一类问题/错误反复犯、每次都从头摸索、经验留不下来''时，以达里奥《原则》类比：他把自己几十年在投资与管理中学到的处事与决策方法、一条条提炼成明确的''原则''、写下来、系统化成一整套(乃至一本书与一套软件)、遇到同类情况就照原则办;把你从经验中学到的东西提炼成明确的''原则''、写下来系统化、让同类情况有章可循、而非每次从头摸索〔但注意:原则要随情境更新、别僵化成教条〕（《原则》系统化为达里奥著作→确证）"}]},"further_reading":[{"title":"达里奥《原则》、\"经济机器是如何运转的\"","why":"痛苦+反思、极度透明、原则系统化、可信度加权、经济机器的出处（A）","type":"original"},{"title":"桥水与系统化决策研究","why":"对达里奥方法论与桥水文化（含争议）的分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/dalio.png","avatar_thumb":"/advisors/portraits/dalio.png","domain":"投资","person_id":"P-dalio","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'f84914c0448811e59a8165a9491b7ac59c3d68b13e45a0326af161d25706deca', 19, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('darwin', 'P-darwin', '查尔斯·达尔文', 'science', '达尔文 · 渐进求证思维框架卡', '19世纪（1809–1882）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '反对意见优先记录 · 变异-选择-时间', '/advisors/portraits/darwin.png', '/advisors/portraits/darwin.png', 5, 0, '{"schema_version":1,"card_id":"darwin","name":"查尔斯·达尔文","title":"达尔文 · 渐进求证思维框架卡","era":"19世纪（1809–1882）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"反对意见优先记录","definition":"一发现与自己结论相悖的事实，立刻记下——因为人忘掉反例比忘掉佐证快得多。","source":"《达尔文自传》","source_tier":"primary","mechanism":"输入=人会记住佐证、快速忘掉反例(记忆在帮自欺) → 处理=一发现相悖事实立刻动笔记下、绝不拖到事后 → 输出=论证罕见地经得起反例检验","trigger":"有立场/结论、容易选择性记忆时","modern_transfer":"对抗自我偏见最有效的不是更聪明，而是一条机械规矩：凡遇反对你的证据，第一时间记下来——它最容易被你悄悄忘掉","architecture":{"type":"loop","components":["发现相悖事实","立刻记下","不拖到事后","经得起反例"]},"strategy_card_image":"kb-assets/darwin/model-1.png"},{"name":"变异-选择-时间","definition":"随机变异+差别存活+时间累积=不需设计者也能产生''精巧设计''的通用机制。","source":"《物种起源》","source_tier":"primary","mechanism":"输入=一个看似被设计的''精巧''复杂结果 → 处理=问它能否由随机变异+差别存活+时间累积而成 → 输出=不需设计者也能解释精巧设计","trigger":"面对看似被设计的复杂结果时","modern_transfer":"想理解一个''精巧''的复杂结果，问它能否由''变异+筛选+时间''慢慢累积而成——复杂未必需要一个设计者","architecture":{"type":"loop","components":["随机变异","差别存活筛选","时间累积","精巧设计涌现"]},"strategy_card_image":"kb-assets/darwin/model-2.png"},{"name":"长期渐进累积","definition":"对一个大主张，耐心积累二十年证据再下结论；不抢发、不靠单点证据定胜负。","source":"《物种起源》自称''一个长论证''；其研究历程","source_tier":"primary","mechanism":"输入=一个重大主张 → 处理=耐心积累足够长时间的证据再下结论、不抢发不靠单点 → 输出=厚到不怕一两个反例的结论(但过度则成拖延)","trigger":"做重大主张、想让结论扎实时","modern_transfer":"大结论要用足够长时间的证据托住，别靠一两个亮点就下判断——但要警惕过度谨慎变成拖延(他险些被华莱士抢先)","architecture":{"type":"loop","components":["耐心积累证据","不抢发","不靠单点","厚到不怕反例"]},"strategy_card_image":"kb-assets/darwin/model-3.png"},{"name":"审慎类比迁移","definition":"把一个已知机制（家养选育、马尔萨斯人口论）小心搬到新领域，作推理的桥。","source":"《物种起源》以人工选择类比自然选择","source_tier":"primary","mechanism":"输入=一个看不见/陌生的机制难以让人信服 → 处理=借一个已验证的同类机制(家养选育/马尔萨斯)搭桥、并标出边界 → 输出=降低接受门槛的推理桥","trigger":"要让人接受一个看不见/陌生的机制时","modern_transfer":"要让人接受一个看不见的机制，先借一个他已熟悉、已验证的同类机制搭桥——但要诚实标出类比的边界","architecture":{"type":"flow","components":["找已验证的同类机制","小心搬到新领域","作推理桥","标出类比边界"]},"strategy_card_image":"kb-assets/darwin/model-4.png"},{"name":"预先直面最强反例","definition":"主动写出自己理论最难的反驳（如眼睛的演化），先于批评者去回应。","source":"《物种起源》''本学说之难点''章","source_tier":"primary","mechanism":"输入=理论有最难、最致命的反驳 → 处理=主动把它摆上台面、先于批评者逐一回应 → 输出=增强说服力与可信","trigger":"理论/方案有明显软肋、会被攻击时","modern_transfer":"把你理论最致命的反驳自己先写出来、自己先回应，比等对手揭短更有力、也更可信","architecture":{"type":"flow","components":["找最致命反驳","主动摆上台面","先于批评者回应","增强可信"]},"strategy_card_image":"kb-assets/darwin/model-5.png"}],"decision_principles":["凡遇反对自己的证据，先记下来再说——它最容易被你悄悄忘掉。","大结论要用二十年的证据托住，别靠一两个亮点就下判断。","把理论最薄弱处自己先摆出来、自己先回应。","想理解一个复杂结果，问它能否由''变异+选择+时间''慢慢累积而成。","借一个已被验证的机制作类比，但时刻警惕类比的边界。"],"inquiry_questions":["支持你的证据你都记着，那反对你的呢——你有没有同样认真地记下来？","这个结论，你攒了多久的证据？够不够厚到不怕一两个反例？","你这套说法最致命的反驳是什么？你正面回应过它吗？","这个''精巧''的结果，有没有可能是变异+筛选+时间慢慢攒出来的，而非谁设计的？","你借来打比方的那个机制，在哪一点上其实和你的情况不一样？"],"value_priorities":["证据的厚度与诚实 ＞ 抢先发表与名声（他宁可拖二十年也要证据扎实，直到华莱士逼他才发表）","直面反例 ＞ 只陈列对自己有利的事实（金科玉律就是专门对抗''选择性记忆''）","渐进、可累积的解释 ＞ 一步到位的奇迹式解释（自然不飞跃——复杂源于微小差异的长期累积）"],"blind_spots":["无遗传机制：当时不知基因，其''泛生论''(pangenesis)猜想是错的，理论留有他填不上的缺口（《动植物在家养下的变异》，A/B）。","严格渐进主义：坚持''自然不飞跃''，与后来''间断平衡''等关于演化速率的争论存在张力（学术分析，B）。","过度谨慎/拖延：二十年迟迟不发，是其耐心的反面——险些被华莱士抢先（书信/传记，B）。","推及人类社会有风险：其机制被他人误用为''社会达尔文主义''，迁移到道德/社会域需格外克制（学术分析，B）。"],"applicable_domains":["探索未知","认知偏误与理性决策","长期规划"],"match_tags":["探索未知","认知偏误与理性决策","长期规划","实验试错","长期主义","批判思辨","近代欧洲"],"linked_cases":["darwin-c1","darwin-c2","darwin-c3","darwin-c4","darwin-c5"],"life_tags":[{"tag":"著物种起源","tier":"primary"},{"tag":"乘小猎犬号","tier":"secondary"},{"tag":"提自然选择","tier":"primary"},{"tag":"提性选择说","tier":"primary"}],"voice_profile":{"notes":"谨慎克制、爱用''似乎/也许''；层层举证而非断言；对反对意见格外郑重"},"references":[{"ref_id":"darwin-s1","title":"《物种起源》(On the Origin of Species)","locator":"1859；第1章(家养变异)、3-4章(选择)、第6章(难点)","source_tier":"primary","supports_models":["变异-选择-时间","长期渐进累积","审慎类比迁移","预先直面最强反例"],"supports_cases":["darwin-c3","darwin-c5"],"note":"一手·核心著作"},{"ref_id":"darwin-s2","title":"《达尔文自传》(The Autobiography of Charles Darwin)","locator":"金科玉律一段；研究历程自述（待质检者核校页码）","source_tier":"primary","supports_models":["反对意见优先记录"],"supports_cases":["darwin-c2"],"note":"一手·自述/回忆，细节或有润色，相关案例historicity存疑"},{"ref_id":"darwin-s3","title":"《动植物在家养下的变异》(含泛生论)","locator":"1868；泛生论假说部分","source_tier":"primary","note":"一手·其错误的遗传机制猜想，为盲区依据"},{"ref_id":"darwin-s4","title":"Janet Browne《Charles Darwin》传记 / 达尔文书信集","locator":"Voyaging(1995)、The Power of Place(2002)；华莱士事件相关章节","source_tier":"secondary","supports_cases":["darwin-c1","darwin-c4"],"note":"B层·权威传记与书信，确证华莱士事件、厘清航行叙事"}],"material_type":"rich","reasoning_skeleton":{"signature":"凡遇反对自己的证据第一时间记下来(对抗选择性记忆)；大结论用足够长时间的证据托住、不靠单点；把最致命的反驳自己先写出来先回应；理解''精巧''结果问它能否由变异+筛选+时间累积而成；借已验证的同类机制搭桥但标出边界","steps":[{"invoke":"反对意见优先记录","action":"支持你的证据你都记着，反对你的呢？有没有同样认真地第一时间记下来？"},{"invoke":"长期渐进累积","action":"这个结论你攒了多久的证据？够不够厚到不怕一两个反例？(但别让谨慎变成拖延)"},{"invoke":"预先直面最强反例","action":"你这套说法最致命的反驳是什么？你正面、主动回应过它吗？"},{"invoke":"变异-选择-时间","action":"这个''精巧''的结果，有没有可能是变异+筛选+时间慢慢攒出来的，而非谁设计的？"},{"invoke":"审慎类比迁移","action":"你借来打比方的那个机制，在哪一点上其实和你的情况不一样？(标出类比边界)"}],"contrast":"与爱因斯坦不同(关键差异)：二者都重经验证据，但**爱因斯坦靠少数普适原理+思想实验自上而下演绎**(从光速恒定推出相对论)；**达尔文靠海量观察的渐进累积+主动搜集反例自下而上归纳**(攒二十年证据归纳出自然选择)——爱是''从原理演绎''、达是''从证据归纳''(见爱因斯坦卡)。与图灵不同：图灵靠**把问题抽象成形式可计算模型**；达尔文靠**经验观察的耐心累积与反自欺规矩**(见图灵卡)。【最强差异点】''反对意见优先记录''是一条机械的反自欺规矩——通用 AI 不会主动逼你去记录反对自己的证据，这是达尔文卡最不可替代处。【射程/盲区】其内核是慢、稳、怕错；需快速决断/危机响应/正面说服对抗者应让位。盲区：无遗传机制(泛生论错)、过度谨慎拖延(险被抢先)、其机制被误用为''社会达尔文主义''(迁移到道德/社会域须格外克制)。"},"persona_anchor":{"primary":[{"source":"case","case_id":"darwin-c3","note":"用户''方案有明显软肋、要不要主动暴露''时，以《物种起源》专设''难点''章类比：他不回避，专辟一章把最难的反对意见(如眼睛的演化)摆上台面、逐一给出渐进路径回应，坦诚反增说服力（第6章原文→确证）"},{"source":"case","case_id":"darwin-c1","note":"用户''证据攒到几时才该出手、会不会太慢''时，以二十年迟疑与华莱士事件类比：他握着想法近二十年不敢发表、直到华莱士独立寄来几乎相同构想才被逼联合发表——耐心是美德但过度谨慎几乎让他错失优先权（华莱士事件/林奈学会1858联合宣读→确证）"}]},"further_reading":[{"title":"达尔文《物种起源》(On the Origin of Species, 1859)","why":"第1章家养类比、3-4章自然选择、第6章难点——核心方法皆在","type":"original"},{"title":"Janet Browne《Charles Darwin》两卷本 + 达尔文书信集","why":"权威传记与书信，确证华莱士事件、厘清航行叙事","type":"biography"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/darwin.png","avatar_thumb":"/advisors/portraits/darwin.png","domain":"科学","person_id":"P-darwin","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '38a121e9ed9beb03f467dd156af0d04f49fe973de2453fe1bbd3bcb2c3151404', 20, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('davinci', 'P-davinci', '达·芬奇', 'science', '达·芬奇 · 极致观察与艺术科学交融思维框架卡', '文艺复兴（1452—1519）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '极致观察 · 艺术与科学交融', '/advisors/portraits/davinci.png', '/advisors/portraits/davinci.png', 5, 0, '{"schema_version":1,"card_id":"davinci","name":"达·芬奇","title":"达·芬奇 · 极致观察与艺术科学交融思维框架卡","era":"文艺复兴（1452—1519）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"极致观察","definition":"别只依赖书本、权威或想当然——像画家那样，以极其细致、耐心的\"直接观察\"去研究对象的真实细节","source":"达·芬奇的观察方法","source_tier":"primary","mechanism":"输入=依赖书本权威想当然 → 处理=像画家般极细致耐心直接观察对象真实细节 → 输出=观察真实(极致观察)","trigger":"要研究/理解一个对象时","modern_transfer":"别只依赖书本、权威或想当然——像画家那样、以极其细致、耐心的''直接观察''去研究对象的真实细节(达·芬奇通过解剖人体、观察水流与鸟飞来研究自然)","architecture":{"type":"flow","components":["别只依赖书本权威想当然","像画家那样极细致耐心","直接观察对象的真实细节","观察出真实"]},"strategy_card_image":"kb-assets/davinci/model-1.png"},{"name":"艺术与科学交融","definition":"打通看似无关的领域（如艺术与科学、感性与理性）——用一个领域的方法、眼光去照亮另一个领域；最大的创造常发生在学科的交叉处","source":"达·芬奇的跨界","source_tier":"primary","mechanism":"输入=被学科/专业边界框死 → 处理=打通看似无关的领域、用一领域方法照亮另一领域 → 输出=交叉处的创造(艺术科学交融)","trigger":"面对一个问题、想突破时","modern_transfer":"打通看似无关的领域(如艺术与科学、感性与理性)——用一个领域的方法、眼光去照亮另一个领域;最大的创造常发生在学科的交叉处(达·芬奇集画家、解剖学家、工程师于一身、以艺术之眼做科学)","architecture":{"type":"matrix","components":["别被学科专业边界框死","打通看似无关的领域","用一个领域的方法照亮另一个","交叉处的创造"]},"strategy_card_image":"kb-assets/davinci/model-2.png"},{"name":"类比自然找原理","definition":"遇到一个难题，先看自然界是怎么解决类似问题的——从自然已有的\"设计\"中类比、提取原理、迁移到你的发明与设计上","source":"达·芬奇的仿生","source_tier":"primary","mechanism":"输入=凭空硬想解法 → 处理=看自然界怎么解决类似问题、类比提取原理迁移 → 输出=师法自然(类比自然)","trigger":"遇到一个设计/发明难题时","modern_transfer":"遇到一个难题、先看自然界是怎么解决类似问题的——从自然已有的''设计''(如鸟翼、水的流动)中类比、提取原理、迁移到你的发明与设计上(达·芬奇据鸟飞设计飞行器)","architecture":{"type":"flow","components":["别凭空硬想解法","先看自然界怎么解决类似问题","从自然的设计中类比提取原理","迁移到你的发明设计"]},"strategy_card_image":"kb-assets/davinci/model-3.png"},{"name":"手脑并用·画以致知","definition":"把抽象的想法用图画、草图精确地\"画出来\"——画的过程本身就是理解、推演与设计的过程","source":"达·芬奇的手稿","source_tier":"primary","mechanism":"输入=只在脑中抽象空想 → 处理=把想法用精确图画画出来、在画中理解推演设计 → 输出=画是思考工具(画以致知)","trigger":"思考复杂的结构/机械/系统时","modern_transfer":"把抽象的想法用图画、草图精确地''画出来''——画的过程本身就是理解、推演与设计的过程(达·芬奇用海量手稿草图思考解剖、机械、水利)〔画以致知〕","architecture":{"type":"loop","components":["别只在脑中抽象空想","把想法用精确图画画出来","在画的过程中理解推演设计","画是思考的工具"]},"strategy_card_image":"kb-assets/davinci/model-4.png"},{"name":"永不满足的好奇","definition":"对一切保持孩童般无边界的好奇——不断追问\"为什么\"\"它怎么运作\"，广泛地涉猎与探究，不被\"专业\"的边界框死","source":"达·芬奇的好奇心","source_tier":"primary","mechanism":"输入=被''专业''边界框死、不追问 → 处理=保持孩童般无边界好奇、不断追问为什么怎么运作、广泛涉猎 → 输出=无边界探究(好奇)","trigger":"面对未知时","modern_transfer":"对一切保持孩童般无边界的好奇——不断追问''为什么''''它怎么运作''、广泛地涉猎与探究、不被''专业''的边界框死(达·芬奇好奇心横跨绘画、解剖、工程、地质、植物)〔但也致其许多项目浅尝辄止、未竟全功、见盲区〕","architecture":{"type":"flow","components":["别被专业边界框死不追问","保持孩童般无边界的好奇","不断追问为什么怎么运作广泛涉猎","无边界的探究"]},"strategy_card_image":"kb-assets/davinci/model-5.png"}],"decision_principles":["别依赖书本权威，像画家那样以极细致的直接观察研究真实细节","打通看似无关的领域，最大的创造常在学科的交叉处","遇难题先看自然怎么解决，从自然的''设计''类比提取原理","把抽象想法精确地''画出来''，画的过程就是理解与设计的过程","保持孩童般无边界的好奇，不断追问''为什么''''怎么运作''"],"inquiry_questions":["你是依赖书本/权威/想当然、还是以极细致的直接观察去研究真实细节？","你是被单一学科框死、还是打通了看似无关的领域、在交叉处找创造？","你是凭空硬想、还是先看自然界是怎么解决类似问题的？","你是只在脑中空想、还是把想法精确地''画出来''、在画中推演设计？","你是被''专业''边界框死、还是保持孩童般无边界的好奇、不断追问？"],"value_priorities":["直接观察真实 ＞ 依赖书本权威（解剖、观察水流鸟飞）","交叉处的创造 ＞ 单一学科边界（画家+解剖学家+工程师）","师法自然 ＞ 凭空硬想（据鸟飞设计飞行器）"],"blind_spots":["达·芬奇兴趣过于广泛、好奇心驱动，导致许多项目浅尝辄止、未竟全功（史，B，客观标注）。","其许多构想（如飞行器）受限于时代技术，停留在纸面、未能实现（史，B）。","其方法重观察、直觉、类比，缺乏后来科学的系统实验与数学化的严谨（原理推断，B）。","其手稿生前多未发表，对当时科学的实际影响有限（史，B）。"],"applicable_domains":["创新","认知偏误与理性决策","创作"],"match_tags":["创新","认知偏误与理性决策","创作","实验试错","多元模型","第一性原理","近代欧洲"],"linked_cases":["davinci-c1","davinci-c2","davinci-c3","davinci-c4"],"life_tags":[{"tag":"绘蒙娜丽莎","tier":"secondary"},{"tag":"绘最后晚餐","tier":"secondary"},{"tag":"留解剖手稿","tier":"primary"},{"tag":"设计飞行器","tier":"secondary"}],"voice_profile":{"notes":"博观跨界、以艺入science；极致观察；师法自然；好奇无垠"},"references":[{"ref_id":"davinci-s1","title":"达·芬奇手稿（各 Codex）及其研究、传记","locator":"极致观察、跨界、仿生、画以致知、好奇心","source_tier":"primary","supports_models":["极致观察","艺术与科学交融","类比自然找原理","手脑并用·画以致知","永不满足的好奇"],"supports_cases":["davinci-c1","davinci-c2","davinci-c3","davinci-c4"],"note":"一手·手稿"},{"ref_id":"davinci-s2","title":"文艺复兴与达·芬奇研究","locator":"观察方法、跨界、未竟项目","source_tier":"secondary","supports_models":["极致观察","艺术与科学交融"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"别依赖书本权威像画家那样以极细致的直接观察研究真实细节(极致观察)；打通看似无关的领域最大的创造常在学科交叉处(艺术与科学交融)；遇难题先看自然怎么解决从自然的设计类比提取原理(类比自然找原理)；把抽象想法精确地画出来画的过程就是理解与设计(手脑并用画以致知)；保持孩童般无边界的好奇不断追问为什么怎么运作(永不满足的好奇)","steps":[{"invoke":"极致观察","action":"你是依赖书本/权威/想当然、还是以极细致的直接观察去研究真实细节？"},{"invoke":"艺术与科学交融","action":"你是被单一学科框死、还是打通了看似无关的领域、在交叉处找创造？"},{"invoke":"类比自然找原理","action":"你是凭空硬想、还是先看自然界是怎么解决类似问题的？"},{"invoke":"手脑并用·画以致知","action":"你是只在脑中空想、还是把想法精确地''画出来''、在画中推演设计？"},{"invoke":"永不满足的好奇","action":"你是被''专业''边界框死、还是保持孩童般无边界的好奇、不断追问？"}],"contrast":"与牛顿不同(关键差异)：**牛顿以''数学公理化、定律''建立精确可演绎的科学体系(理论的数学化)**；**达·芬奇以''直接观察、跨界融通、仿生类比、手稿草图''探究自然(观察与跨界的博物式探索)**——牛顿建立数学化的理论大厦、达·芬奇做观察驱动的跨界探索(见牛顿卡)。与达尔文不同(同重观察)：达尔文以海量系统观察+严密推理建立一个统一的演化理论(从观察到理论);达·芬奇的观察更广博、跨界、艺术化、但较少建成系统理论(见达尔文卡)。与费曼不同：费曼以物理直觉与重新推导吃透理论;达·芬奇以艺术之眼与无边界好奇横跨百艺(见费曼卡)。【射程/盲区】达·芬奇之道在''极致观察、艺术科学交融、类比自然、画以致知、无边界好奇''极有力(尤其创新、跨界、观察)，但①兴趣过广、好奇心驱动、许多项目浅尝辄止未竟全功;②许多构想受限时代技术、停留纸面未实现;③方法重观察直觉类比、缺后来科学的系统实验与数学化严谨;④手稿生前多未发表、对当时科学实际影响有限。适用创新/认知偏误与理性决策/创作;不适用投资/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"davinci-c1","note":"用户''研究/理解一个对象时、习惯于查书、听权威、凭想当然、却抓不住真实的细节''时，以达·芬奇的极致观察类比：他为了画好人体、亲自解剖了几十具尸体、画下极其精确的肌肉骨骼;为了懂水、长时间观察水的流动漩涡;别只依赖书本、权威或想当然——像画家那样、以极细致、耐心的直接观察去研究对象的真实细节（达·芬奇解剖与自然观察为其手稿所载→确证）"},{"source":"case","case_id":"davinci-c2","note":"用户''被自己的单一专业/领域框死、觉得灵感枯竭、找不到突破''时，以达·芬奇的跨界类比：他既是画家、又是解剖学家、工程师、自然研究者——用解剖学的知识画出更真实的人体、用对光影的观察革新绘画、用工程的眼光设计机械;打通看似无关的领域、用一个领域的方法照亮另一个、最大的创造常发生在学科的交叉处（达·芬奇的跨界为史实→确证）"}]},"further_reading":[{"title":"达·芬奇手稿（各 Codex）及其研究、传记","why":"极致观察、跨界、仿生、画以致知、好奇心的出处（A/B）","type":"手稿/传记"},{"title":"文艺复兴与达·芬奇研究","why":"对其观察方法、跨界与未竟项目的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/davinci.png","avatar_thumb":"/advisors/portraits/davinci.png","domain":"科学","person_id":"P-davinci","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '3311cb7025c5819b20e0acae44f5bf9580687ff0847da47530f7261a1f00227c', 21, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('degaulle', 'P-degaulle', '戴高乐', 'governance', '戴高乐 · 危亡正统与制度重塑思维框架卡', '现代（1890—1970）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '危亡中坚持正统 · 独立自主不做附庸', '/advisors/portraits/degaulle.png', '/advisors/portraits/degaulle.png', 5, 0, '{"schema_version":1,"card_id":"degaulle","name":"戴高乐","title":"戴高乐 · 危亡正统与制度重塑思维框架卡","era":"现代（1890—1970）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"危亡中坚持正统","definition":"当组织/事业在危亡中、\"官方\"已放弃或投降时，挺身而出、坚持代表它\"真正的精神与正统\"，保住火种与希望","source":"戴高乐流亡中创建\"自由法国\"","source_tier":"secondary","mechanism":"输入=组织危亡、''官方''已放弃投降 → 处理=挺身而出、坚持代表它''真正的精神与正统''、保住火种与希望 → 输出=保住法统与希望(危亡坚持正统)","trigger":"组织/事业在危亡中、官方已放弃时","modern_transfer":"当一个组织/事业在危亡中、''官方''已放弃或投降时——有人需要挺身而出、坚持代表它''真正的精神与正统''、把火种与希望保住(戴高乐流亡中举起''自由法国''的旗帜、坚称自己代表真正的法国)","architecture":{"type":"flow","components":["组织危亡官方已放弃投降","挺身而出","坚持代表真正的精神与正统","保住火种与希望"]},"strategy_card_image":"kb-assets/degaulle/model-1.png"},{"name":"独立自主不做附庸","definition":"即使你弱小，也要坚持自主的立场与尊严，不轻易做强者的附庸——独立的人格才赢得真正的尊重","source":"戴高乐对盟友的独立立场","source_tier":"secondary","mechanism":"输入=因弱小而甘做强者的附庸、放弃立场尊严 → 处理=即使弱小也坚持自主的立场与尊严、不轻易做附庸 → 输出=独立人格赢得尊重(独立自主)","trigger":"即使弱小、面对强者时如何自处","modern_transfer":"即使你弱小、也要坚持自主的立场与尊严、不轻易做强者的附庸——独立的人格才赢得真正的尊重(戴高乐即便依赖盟友、也坚持法国的独立地位与尊严)","architecture":{"type":"flow","components":["别因弱小而甘做附庸","即使弱小也坚持自主立场与尊严","不轻易做强者的附庸","独立人格赢得尊重"]},"strategy_card_image":"kb-assets/degaulle/model-2.png"},{"name":"超越党派的整体利益","definition":"站在派系纷争之上，以整体的、长远的利益为依归，而非陷在党派的小算盘里——当裁判而非当球员","source":"戴高乐超党派的国家立场","source_tier":"secondary","mechanism":"输入=陷在党派纷争的小算盘里 → 处理=站在派系之上、以整体的、长远的利益为依归 → 输出=当裁判而非球员(超党派)","trigger":"面对派系纷争、要为整体负责时","modern_transfer":"站在派系纷争之上、以整体的、长远的利益为依归、而非陷在党派的小算盘里——当裁判而非当球员(戴高乐超越党派、以国家整体为念)","architecture":{"type":"hierarchy","components":["别陷在党派纷争的小算盘里","站在派系之上","以整体的长远利益为依归","当裁判而非当球员"]},"strategy_card_image":"kb-assets/degaulle/model-3.png"},{"name":"重塑制度以匹配现实","definition":"当旧的制度/架构已无法应对现实，不在旧框架里修补，而是重新设计一套更能集中决策、更能办事的新制度","source":"戴高乐创建法兰西第五共和国","source_tier":"secondary","mechanism":"输入=旧制度失灵却只在旧框架里修补 → 处理=重新设计一套更能集中决策、更能办事的新制度 → 输出=制度匹配现实(重塑制度)","trigger":"旧制度/架构已无法应对现实时","modern_transfer":"当旧的制度/架构已无法应对现实(如议会乱政、决策瘫痪)、不在旧框架里修补、而是重新设计一套更能集中决策、更能办事的新制度(戴高乐主导建立第五共和、强化总统权力)〔强总统也被批削弱制衡、见盲区〕","architecture":{"type":"hierarchy","components":["别在旧框架里修补失灵的制度","旧制度已无法应对现实","重新设计更能集中决策的新制度","制度匹配现实"]},"strategy_card_image":"kb-assets/degaulle/model-4.png"},{"name":"树立伟大愿景凝聚人心","definition":"为组织/国家树立一个超越当下现实的\"伟大\"愿景与身份认同，对抗平庸与失败主义","source":"戴高乐\"法国的伟大\"信念","source_tier":"secondary","mechanism":"输入=组织陷于平庸与失败主义 → 处理=为它树立一个超越当下现实的''伟大''目标与身份认同 → 输出=以伟大凝聚对抗平庸(伟大愿景)","trigger":"组织陷于平庸/失败主义、需要重振时","modern_transfer":"为你的组织/国家树立一个超越当下现实的''伟大''愿景与身份认同、对抗平庸与失败主义——''伟大''本身能凝聚人(戴高乐''法国不伟大、就不成其为法国'')〔但须防脱离实际国力的虚妄、见盲区〕","architecture":{"type":"flow","components":["别让组织陷于平庸与失败主义","树立超越当下现实的伟大目标","与身份认同","以伟大凝聚人心对抗平庸"]},"strategy_card_image":"kb-assets/degaulle/model-5.png"}],"decision_principles":["组织危亡、官方放弃时，挺身代表它真正的精神与正统，保住火种","即使弱小也坚持自主的立场与尊严，不做强者的附庸","站在派系之上，以整体的、长远的利益为依归","旧制度失灵时，不修补而是重新设计更能办事的新制度（但防集权）","为组织树立超越现实的伟大愿景，对抗失败主义（但防虚妄）"],"inquiry_questions":["组织危亡、官方已放弃时，有没有人挺身代表它真正的精神与正统、把希望保住？","你即使弱小，是甘做强者的附庸、还是坚持自主的立场与尊严？","你是陷在派系的小算盘里、还是站在派系之上为整体长远负责？","旧制度已失灵时，你是在旧框架里修补、还是重新设计更能办事的新制度？","组织陷于平庸失败主义时，你有没有为它树立一个超越现实的伟大愿景？"],"value_priorities":["坚持真正的正统 ＞ 随官方一起放弃（自由法国、代表真正的法国）","自主的立场与尊严 ＞ 甘做强者的附庸（即便依赖盟友也坚持独立）","整体长远的利益 ＞ 党派的小算盘（超党派、当裁判）"],"blind_spots":["其强烈的''伟大''追求与个人威权风格，有时显得固执、自负、不易合作（史，B）。","''伟大愿景''若脱离实际国力，可能流于虚妄与不切实际的姿态（原理推断，B）。","其超党派、强总统的设计，也被批评为集权、削弱了议会制衡（政治学，B，客观标注）。","长于危亡中举旗与重建，其领导风格在常规、平稳时期未必都适用（原理推断，B）。"],"applicable_domains":["危机应对","领导力","长期规划"],"match_tags":["危机应对","领导力","长期规划","长期主义","对抗性思维","系统分析","现当代欧洲"],"linked_cases":["degaulle-c1","degaulle-c2","degaulle-c3","degaulle-c4"],"life_tags":[{"tag":"领导自由法国","tier":"secondary"},{"tag":"创第五共和","tier":"secondary"},{"tag":"发六一八呼吁","tier":"secondary"},{"tag":"推动法德和解","tier":"secondary"}],"voice_profile":{"notes":"威严孤高、信念坚定；重正统与象征；独立不羁；胸怀伟大"},"references":[{"ref_id":"degaulle-s1","title":"戴高乐《战争回忆录》《希望回忆录》及传记","locator":"自由法国、独立外交、超党派、第五共和、伟大愿景","source_tier":"secondary","supports_models":["危亡中坚持正统","独立自主不做附庸","超越党派的整体利益","重塑制度以匹配现实","树立伟大愿景凝聚人心"],"supports_cases":["degaulle-c1","degaulle-c2","degaulle-c3","degaulle-c4"],"note":"一手/二手·回忆录/传记"},{"ref_id":"degaulle-s2","title":"法国现代史","locator":"自由法国、第五共和建立","source_tier":"secondary","supports_models":["危亡中坚持正统","重塑制度以匹配现实"],"note":"二手·史"}],"material_type":"rich","reasoning_skeleton":{"signature":"组织危亡官方放弃时挺身代表真正的正统保住火种(危亡中坚持正统)；即使弱小也坚持自主立场与尊严不做附庸(独立自主不做附庸)；站在派系之上以整体长远利益为依归(超越党派的整体利益)；旧制度失灵时重新设计更能办事的新制度(重塑制度以匹配现实)；为组织树立超越现实的伟大愿景对抗失败主义(树立伟大愿景凝聚人心)","steps":[{"invoke":"危亡中坚持正统","action":"组织危亡、官方已放弃时，有没有人挺身代表它真正的精神与正统、把希望保住？"},{"invoke":"独立自主不做附庸","action":"你即使弱小，是甘做强者的附庸、还是坚持自主的立场与尊严？"},{"invoke":"超越党派的整体利益","action":"你是陷在派系的小算盘里、还是站在派系之上为整体长远负责？"},{"invoke":"重塑制度以匹配现实","action":"旧制度已失灵时，你是在旧框架里修补、还是重新设计更能办事的新制度？"},{"invoke":"树立伟大愿景凝聚人心","action":"组织陷于平庸失败主义时，你有没有为它树立一个超越现实的伟大愿景？"}],"contrast":"与丘吉尔不同(关键差异·同为二战领袖)：**丘吉尔靠''绝不屈服的意志、演讲动员、反绥靖、联合抗敌''(以意志与动员抵抗外敌)**；**戴高乐靠''危亡中举起正统的旗帜、独立自主、超越党派、重塑制度、伟大愿景''(以正统象征与制度重建延续法统)**——丘吉尔是抵抗外敌的意志领袖、戴高乐是延续正统与重建制度的象征领袖(见丘吉尔卡)。与林肯不同：林肯弥合内战的分裂、靠道德与宽容;戴高乐在亡国危机中举正统旗、靠象征与制度重建(见林肯卡)。【射程/盲区·〔慎〕】戴高乐之道在''危亡坚持正统、独立自主、超党派、重塑制度、伟大愿景''极有力(尤其危亡领导与制度重建)，但①其强烈的''伟大''追求与个人威权风格、有时显得固执、自负、不易合作;②''伟大愿景''若脱离实际国力、可能流于虚妄与不切实际的姿态;③其超党派、强总统的设计也被批评为集权、削弱议会制衡(客观标注);④长于危亡举旗与重建、其风格在常规平稳时期未必都适用。适用危机应对/领导力/长期规划;不适用投资/创作。"},"persona_anchor":{"primary":[{"source":"case","case_id":"degaulle-c1","note":"用户''所在的组织/事业陷入危亡、''官方''或主流已放弃或投降、几乎无人撑旗''时，以戴高乐自由法国类比：1940年法国政府向纳粹投降、戴高乐却流亡伦敦、号召抵抗、坚称自己代表''真正的法国''——当官方已放弃时、有人需要挺身而出、坚持代表它真正的精神与正统、把火种与希望保住（自由法国为史实→确证）"},{"source":"case","case_id":"degaulle-c4","note":"用户''一套旧的制度/架构已经失灵(如议事瘫痪、决策低效)、只在旧框架里修修补补''时，以戴高乐创第五共和类比：面对第四共和议会乱政、决策瘫痪、戴高乐不在旧框架里修补、而是主导建立了强化总统权力的第五共和——旧制度已无法应对现实时、重新设计一套更能集中决策、更能办事的新制度（但强总统也被批削弱制衡）（第五共和为史实→确证）"}]},"further_reading":[{"title":"戴高乐《战争回忆录》《希望回忆录》及传记","why":"自由法国、独立外交、第五共和、伟大愿景的记述（A/B）","type":"回忆录/传记"},{"title":"法国现代史","why":"自由法国、第五共和建立等的史述（B）","type":"史"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/degaulle.png","avatar_thumb":"/advisors/portraits/degaulle.png","domain":"治理","person_id":"P-degaulle","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'c114ed67f668a96c1f9c55390bea956aa3a4150b9cf85a5a6867c499f0e68755', 22, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('dickens', 'P-dickens', '查尔斯·狄更斯', 'writing', '狄更斯 · 社会叙事与连载思维框架卡', '19世纪（1812—1870）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '社会议题叙事 · 连载悬念', '/advisors/portraits/dickens.png', '/advisors/portraits/dickens.png', 5, 0, '{"schema_version":1,"card_id":"dickens","name":"查尔斯·狄更斯","title":"狄更斯 · 社会叙事与连载思维框架卡","era":"19世纪（1812—1870）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"社会议题叙事","definition":"把一个抽象的社会问题（贫困/童工/不公）装进一个有血有肉、令人揪心的人物故事里——让读者先在情感上\"在乎\"、再可能推动改变","source":"狄更斯《雾都孤儿》《艰难时世》","source_tier":"primary","mechanism":"输入=抽象的社会问题(统计/议论)难唤起在乎 → 处理=把它装进一个有血有肉、令人揪心的人物故事里 → 输出=读者先情感上在乎、再可能推动改变(故事胜过统计)","trigger":"想让人在乎一个社会问题/推动改变时","modern_transfer":"把一个抽象的社会问题(贫困/童工/不公)装进一个有血有肉、令人揪心的人物故事里——让读者先在情感上''在乎''、再可能推动改变(一个孩子的故事比一组统计数字更能唤起共情)","architecture":{"type":"flow","components":["抽象社会问题难唤起在乎","装进有血有肉的人物故事","让读者情感上在乎","推动关注与改变"]},"strategy_card_image":"kb-assets/dickens/model-1.png"},{"name":"连载悬念","definition":"按连载/分期的节奏组织内容——每一期结尾留一个悬念或钩子、让人迫不及待等下一期，用节奏与悬念维持持续的注意力","source":"狄更斯的连载小说（《匹克威克外传》《老古玩店》等）","source_tier":"primary","mechanism":"输入=长内容难维持持续注意力、读者会流失 → 处理=按连载/分期节奏组织、每期结尾留悬念钩子 → 输出=让人迫不及待等下一期(持续注意力)","trigger":"要维持对长内容的持续注意力时","modern_transfer":"按连载/分期的节奏组织内容——每一期结尾留一个悬念或钩子、让人迫不及待等下一期；用节奏与悬念维持持续的注意力(狄更斯的连载小说万人空巷)","architecture":{"type":"loop","components":["长内容难维持注意力","按分期节奏组织","每期结尾留悬念钩子","让人等下一期"]},"strategy_card_image":"kb-assets/dickens/model-2.png"},{"name":"人物群像","definition":"用一大批个性鲜明、各有标志性特征（口头禅/怪癖）的人物撑起一个世界——鲜明到过目不忘的角色，比情节更让人记住与传播","source":"狄更斯小说的庞大人物谱","source_tier":"primary","mechanism":"输入=只靠情节、世界不够鲜活难记住 → 处理=用一大批个性鲜明、各有标志性特征的人物撑起世界 → 输出=过目不忘的角色让世界被记住与传播","trigger":"要让一个世界/作品鲜活可记时","modern_transfer":"用一大批个性鲜明、各有标志性特征(口头禅/怪癖)的人物撑起一个世界——鲜明到过目不忘的角色、比情节更让人记住与传播(但勿流于脸谱化)","architecture":{"type":"matrix","components":["别只靠情节","造一批个性鲜明的人物","各有标志性特征","过目不忘被记住传播"]},"strategy_card_image":"kb-assets/dickens/model-3.png"},{"name":"情感共鸣","definition":"用强烈的情感（尤其对弱者、孩子的同情）直击人心——让读者哭、让读者愤怒，情感的力量能驱动认同与行动","source":"狄更斯《圣诞颂歌》等（感伤与同情）","source_tier":"primary","mechanism":"输入=理性议论难驱动认同与行动 → 处理=用强烈的情感(尤其对弱者/孩子的同情)直击人心 → 输出=情感驱动认同与行动(但须防过度煽情)","trigger":"要驱动认同与行动时","modern_transfer":"用强烈的情感(尤其对弱者、孩子的同情)直击人心——让读者哭、让读者愤怒，情感的力量能驱动认同与行动(但须防过度煽情、廉价的眼泪)","architecture":{"type":"flow","components":["理性议论难驱动行动","用强烈情感尤其对弱者的同情","直击人心","驱动认同与行动"]},"strategy_card_image":"kb-assets/dickens/model-4.png"},{"name":"亲身体验入文","definition":"把自己亲历的苦难与观察转化为创作素材——真实经历过的细节与情感，写出来才有不可替代的真实感与力量","source":"狄更斯《大卫·科波菲尔》（半自传）","source_tier":"primary","mechanism":"输入=凭空想象的细节缺乏真实感与力量 → 处理=把自己亲历的苦难与观察转化为创作素材 → 输出=不可替代的真实感与力量(狄更斯写童工源于自身)","trigger":"想让作品有真实感与力量时","modern_transfer":"把自己亲历的苦难与观察转化为创作素材——真实经历过的细节与情感、写出来才有不可替代的真实感与力量(狄更斯写童工/负债监狱源于自身经历)","architecture":{"type":"flow","components":["凭空想象缺真实感","调用自己亲历的苦难与观察","转化为创作素材","写出不可替代的真实力量"]},"strategy_card_image":"kb-assets/dickens/model-5.png"}],"decision_principles":["把抽象的社会问题装进有血有肉的人物故事，让人先在乎再推动改变","按分期节奏组织、每期结尾留悬念钩子，维持持续注意力","用一大批个性鲜明、过目不忘、各有标志的人物撑起世界（勿脸谱化）","用强烈情感（尤其对弱者的同情）直击人心、驱动行动（防过度煽情）","把自己亲历的苦难转化为素材，写出不可替代的真实"],"inquiry_questions":["你想让人在乎的那个问题，能不能装进一个有血有肉、令人揪心的人物故事里？","你是在讲道理，还是用强烈的情感（尤其对弱者的同情）直击人心、驱动认同？","你的世界里有没有一批个性鲜明、过目不忘、各有标志的人物撑着？","你的内容有没有节奏与钩子？能不能每一段结尾留个悬念让人想继续？","你能不能调用自己真实经历过的细节与情感？那才有不可替代的真实力量"],"value_priorities":["动人的故事 ＞ 抽象的统计议论（一个孩子的故事胜过一组数字）","强烈的情感共鸣 ＞ 冷静的理性陈述（情感驱动认同与行动（但防过度煽情））","亲历的真实 ＞ 凭空的想象（真实经历过的细节最有力量）"],"blind_spots":["强烈情感/感伤易流于过度煽情（sentimentality）、感伤主义，被批为''廉价的眼泪''（文学评议，B）。","人物常被简化为善恶分明、个性夸张、缺乏复杂的灰度（尤其反派易脸谱化）（文学评议，B）。","连载的钩子/悬念有时为追求效果而牺牲结构的紧凑，情节冗长拖沓（文学评议，B）。","其社会批判多停留在唤起同情与道德感化，对结构性根源的分析较浅（思想评议，B）。"],"applicable_domains":["表达说服","创作表达","价值与伦理"],"match_tags":["表达说服","创作表达","价值与伦理","攻心共识","利他取向","系统分析","近代欧洲"],"linked_cases":["dickens-c1","dickens-c2","dickens-c3"],"life_tags":[{"tag":"著雾都孤儿","tier":"primary"},{"tag":"著双城记","tier":"primary"},{"tag":"童年做童工","tier":"secondary"},{"tag":"著圣诞颂歌","tier":"primary"}],"voice_profile":{"notes":"情感丰沛、悲悯弱者；人物鲜活、夸张生动；善设悬念、节奏抓人；道德热忱、雅俗共赏"},"references":[{"ref_id":"dickens-s1","title":"狄更斯《雾都孤儿》《圣诞颂歌》《艰难时世》","locator":"社会议题叙事、对弱者的情感共鸣、人物群像","source_tier":"primary","supports_models":["社会议题叙事","情感共鸣","人物群像"],"supports_cases":["dickens-c1"],"note":"一手·社会叙事代表作"},{"ref_id":"dickens-s2","title":"狄更斯连载小说（《匹克威克外传》《老古玩店》等）","locator":"连载悬念、庞大人物谱","source_tier":"primary","supports_models":["连载悬念","人物群像"],"supports_cases":["dickens-c2"],"note":"一手·连载与人物群像"},{"ref_id":"dickens-s3","title":"狄更斯《大卫·科波菲尔》及传记","locator":"童年负债监狱/童工经历入文","source_tier":"primary","supports_models":["亲身体验入文","情感共鸣"],"supports_cases":["dickens-c3"],"note":"一手半自传+二手传记"}],"material_type":"rich","reasoning_skeleton":{"signature":"把抽象社会问题装进有血有肉的人物故事、让读者先在乎再推动改变(社会议题叙事)；按分期节奏组织、每期结尾留悬念钩子维持注意力(连载悬念)；用一大批个性鲜明各有标志的人物撑起世界、过目不忘(人物群像)；用强烈情感尤其对弱者的同情直击人心、驱动行动(情感共鸣)；把自己亲历的苦难转化为素材、写出不可替代的真实(亲身体验入文)","steps":[{"invoke":"社会议题叙事","action":"你想让人在乎的那个问题，能不能装进一个有血有肉、令人揪心的人物故事里？"},{"invoke":"情感共鸣","action":"你是在讲道理，还是用强烈的情感(尤其对弱者的同情)直击人心、驱动认同？(防过度煽情)"},{"invoke":"人物群像","action":"你的世界里有没有一批个性鲜明、过目不忘、各有标志的人物撑着？"},{"invoke":"连载悬念","action":"你的内容有没有节奏与钩子？能不能每一段结尾留个悬念让人想继续？"},{"invoke":"亲身体验入文","action":"你能不能调用自己真实经历过的细节与情感？那才有不可替代的真实力量"}],"contrast":"与奥威尔不同(关键差异·同为创作传播)：**奥威尔以''清晰语言对抗操纵/政治写作/智识诚实''冷峻直白地抵抗欺骗**；**狄更斯以''社会议题叙事+连载悬念+人物群像+情感共鸣''温热地唤起对社会问题的共情与改革**——奥威尔是清晰的政治抵抗、狄更斯是动情的社会叙事(见奥威尔卡)。与马克吐温不同：吐温以''讽刺幽默+方言+局外人天真视角''轻盈尖刻地批判；狄更斯靠宏大的连载结构、庞大的人物群像与强烈的情感打动、更厚重煽情(见马克吐温卡)。【射程/盲区】狄更斯之道在''用故事唤起对社会问题的共情、用连载与群像维持吸引力、用亲历写出真实''极有力，但①强烈情感易流于过度煽情/感伤主义(''廉价的眼泪'')；②人物常善恶分明、个性夸张、缺复杂灰度(反派易脸谱化)；③连载钩子有时牺牲结构紧凑、情节冗长拖沓；④其社会批判多停留在唤起同情与道德感化、对结构性根源分析较浅。适用表达说服/创作表达/价值与伦理；不适用投资/危机应对。"},"persona_anchor":{"primary":[{"source":"case","case_id":"dickens-c1","note":"用户''想让人真正在乎一个抽象的社会问题、而非无动于衷''时，以《雾都孤儿》类比：狄更斯把济贫院、童工、贫困犯罪这些抽象问题、装进孤儿奥利弗的揪心命运里——让读者先在情感上''在乎''一个孩子、再去关心整个问题，故事比统计数字更能唤起共情与改革（《雾都孤儿》为狄更斯名作→确证）"},{"source":"case","case_id":"dickens-c2","note":"用户''内容太长、留不住人的注意力''时，以狄更斯的连载小说类比：他首创长篇连载、每一期结尾都留一个悬念或钩子(如《老古玩店》小耐尔的命运令读者万众等待)——用节奏与悬念让人迫不及待等下一期（连载与悬念为狄更斯首创并著称→确证）"}]},"further_reading":[{"title":"狄更斯《雾都孤儿》《圣诞颂歌》《艰难时世》","why":"社会议题叙事与情感共鸣的一手代表作","type":"original"},{"title":"狄更斯《大卫·科波菲尔》《匹克威克外传》《老古玩店》","why":"半自传、连载悬念、人物群像的一手出处","type":"original"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/dickens.png","avatar_thumb":"/advisors/portraits/dickens.png","domain":"创作","person_id":"P-dickens","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '64c88e1c652b2d74c37a9ac3316ad64a511d69638d4d9c698dc8d6adcb17204a', 23, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('disney', 'P-disney', '迪士尼', 'innovation', '沃尔特·迪士尼 · 叙事与体验工程思维框架卡', '20世纪（1901–1966）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '叙事工程 · 押注式跃迁', '/advisors/portraits/disney.png', '/advisors/portraits/disney.png', 5, 0, '{"schema_version":1,"card_id":"disney","name":"迪士尼","title":"沃尔特·迪士尼 · 叙事与体验工程思维框架卡","era":"20世纪（1901–1966）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"叙事工程","definition":"把讲好一个故事当成可工程化的系统：分镜、节奏、情感曲线逐格设计，而非随性创作","source":"故事板(storyboard)制度（传记）","source_tier":"secondary","mechanism":"输入=一个要讲的故事/体验 → 处理=把它当可工程化系统、分镜/节奏/情感曲线逐格设计 → 输出=被精确设计的情感体验（非随性创作）","trigger":"想把''打动人''从靠灵感变成可复制时","modern_transfer":"把''讲好一个故事/做好体验''当可工程化的系统：先把用户在每一步该有的感受（情感曲线）逐格设计出来，而非随性创作","architecture":{"type":"flow","components":["拿到故事/体验","设计情感曲线","分镜节奏逐格打磨","输出精确体验"]},"strategy_card_image":"kb-assets/disney/model-1.png"},{"name":"押注式跃迁","definition":"在行业认为不可能时押上身家做一次量级跃迁（首部动画长片），而非安全的渐进改良","source":"《白雪公主》（迪士尼的蠢事）","source_tier":"secondary","mechanism":"输入=一个被行业唱衰、却看准底层趋势的机会 → 处理=押上身家做一次量级跃迁、而非安全渐进 → 输出=开创品类的跃迁（高风险）","trigger":"看准底层趋势、但行业普遍说''不可能''时","modern_transfer":"当一次跃迁被普遍唱衰、但你看准了底层趋势，敢押身家做别人认为不可能的那一档——回报可能是开创一个品类","architecture":{"type":"flow","components":["看准底层趋势","不顾唱衰","押身家做量级跃迁","开创品类"]},"strategy_card_image":"kb-assets/disney/model-2.png"},{"name":"技术服务体验","definition":"不为炫技而炫技，引入新技术（同步声、多平面摄影）只为让观众的沉浸体验更深","source":"《汽船威利》同步声、多平面摄影机","source_tier":"secondary","mechanism":"输入=一项可引入的新技术 → 处理=以''能否加深观众沉浸体验''为唯一标准取舍、不为炫技 → 输出=服务于体验的技术投入","trigger":"决定要不要上一项新技术时","modern_transfer":"引入新技术的标准不是它新不新，而是它能不能让用户体验更深——技术服务于体验，不为炫技","architecture":{"type":"flow","components":["面对新技术","问能否加深体验","是则投入否则不上","技术服务体验"]},"strategy_card_image":"kb-assets/disney/model-3.png"},{"name":"整合式体验","definition":"把故事、空间、技术、运营整合成一个无缝闭环体验，掌控每个触点（主题乐园）","source":"迪士尼乐园","source_tier":"secondary","mechanism":"输入=一个分散触点的产品/服务 → 处理=把故事/空间/技术/运营整合成无缝闭环、掌控每个触点 → 输出=对手难复制的体验壁垒","trigger":"想建难被单点复制的壁垒、体验有断点时","modern_transfer":"强壁垒常来自把分散的触点整合成一个别人难复制的无缝体验闭环，而非某个单点的强——掌控每个触点","architecture":{"type":"hierarchy","components":["识别分散触点","整合故事/空间/技术/运营","掌控每个触点","无缝闭环壁垒"]},"strategy_card_image":"kb-assets/disney/model-4.png"},{"name":"永远在建造","definition":"作品/乐园永不完工，持续迭代升级——Disneyland will never be completed","source":"其关于乐园的公开表述","source_tier":"primary","mechanism":"输入=一个已上线的作品/产品 → 处理=视其永不完工、持续迭代升级 → 输出=不断进化的体验","trigger":"作品上线后、容易当''完工''收手时","modern_transfer":"作品/产品永远没有完工的一天——把它当持续迭代升级的活物，而非一次交付就收手","architecture":{"type":"loop","components":["作品上线","视为永不完工","持续迭代升级","不断进化"]},"strategy_card_image":"kb-assets/disney/model-5.png"}],"decision_principles":["先把故事的情感曲线逐格设计好，再谈技术与制作（叙事工程，B）","行业说不可能时，敢押身家做一次量级跃迁，而非安全渐进（白雪公主，B）","引入新技术只为加深观众沉浸，不为炫技（同步声/多平面，B）","把体验的每个触点都纳入掌控，整合成无缝闭环（乐园，B）","作品永远没有完工的一天，持续迭代（其乐园理念，A）"],"inquiry_questions":["你这件事的情感曲线是什么？用户在每一步该有什么感受，你逐格设计了吗？","你是在做一次安全的小改良，还是敢押身家做一次别人认为不可能的跃迁？","你引入的新技术，是为了加深体验，还是只是炫技？","用户体验的每个触点你都掌控了吗，还是有断点漏在你管不到的地方？"],"value_priorities":["观众的情感体验 ＞ 制作的成本与便利（体验质量优先，不惜重金重做）","一次量级跃迁 ＞ 安全的渐进改良（押上身家赌《白雪公主》）","对体验的完整掌控 ＞ 外包放权带来的省事（整合闭环、掌控每个触点）"],"blind_spots":["对劳资/人关系迟钝＋控制欲：1941年动画师大罢工暴露其家长式管理与对员工诉求的低估（Gabler 传记，B）","完美主义与控制推高成本/压力：对细节的极致掌控推高成本、给团队巨大压力（传记，B）","其个人与时代局限的偏见争议：部分作品与言行被指带时代性偏见，须客观标注、不美化（传记与后世评述，B）","重整合掌控、轻自下而上：高度中心化掌控模式，不利于无中心、自下而上的探索式创新（方法论局限，B）"],"applicable_domains":["创新研发","商业模式与护城河","长期规划","资源调度"],"match_tags":["创新研发","商业模式与护城河","长期规划","系统分析","长期主义","现当代北美"],"linked_cases":["disney-c1","disney-c2","disney-c3","disney-c4","disney-c5"],"life_tags":[{"tag":"创迪士尼公司","tier":"secondary"},{"tag":"制动画长片","tier":"secondary"},{"tag":"建迪士尼乐园","tier":"secondary"},{"tag":"获多项奥斯卡","tier":"secondary"}],"voice_profile":{"notes":"讲故事口吻；对细节与魔法感的执着；乐观宏大；永远在建造式的未完成感"},"references":[{"ref_id":"disney-s1","title":"Neal Gabler《Walt Disney: The Triumph of the American Imagination》(2006)","locator":"故事板章、白雪公主章、技术章、迪士尼乐园章、1941罢工章","source_tier":"secondary","supports_models":["叙事工程","押注式跃迁","技术服务体验","整合式体验"],"supports_cases":["disney-c1","disney-c2","disney-c3","disney-c4","disney-c5"],"note":"权威传记"},{"ref_id":"disney-s2","title":"迪士尼关于乐园永远不会完工的公开表述","locator":"迪士尼乐园开幕相关记录","source_tier":"primary","supports_models":["永远在建造"],"note":"公开表述一手"}],"material_type":"rich","reasoning_skeleton":{"signature":"先把用户每一步该有的感受（情感曲线）逐格设计出来；看准底层趋势就敢押身家做一次别人认为不可能的跃迁；新技术只为加深沉浸、不炫技；把分散触点整合成无缝闭环掌控每个触点——且作品永不完工、持续迭代","steps":[{"invoke":"叙事工程","action":"先把这件事的情感曲线逐格设计：用户在每一步该有什么感受"},{"invoke":"押注式跃迁","action":"若看准底层趋势、行业说不可能，敢押身家做一次量级跃迁而非安全渐进"},{"invoke":"技术服务体验","action":"要不要上新技术，只看它能否加深体验、而非炫不炫"},{"invoke":"整合式体验","action":"把故事/空间/技术/运营整合成无缝闭环、掌控每个触点，让对手无单点可复制"},{"invoke":"永远在建造","action":"作品上线≠完工，当持续迭代升级的活物"}],"contrast":"与爱迪生不同（同域近邻、同重系统与商业、取胜面不同）：爱迪生靠系统化试错 + 占整套技术系统 + 商业化把发明变生意；迪士尼靠叙事工程 + 情感曲线 + 整合体验闭环把''打动人''工程化——一个工程技术系统、一个情感体验系统（见爱迪生卡）。与乔布斯相近又不同（都重体验/整合/掌控触点）：乔布斯靠减法/聚焦/软硬一体做少而极致的科技产品；迪士尼靠叙事/情感曲线/全程沉浸做故事化体验帝国——一个极简科技美学、一个宏大叙事沉浸（见乔布斯卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"disney-c1","note":"用户''一个被普遍唱衰、但我看准趋势的大跃迁、要不要押''时，以押身家做首部动画长片《白雪公主》类比：业界说观众坐不住90分钟动画（''迪士尼的蠢事''），他押上工作室与个人身家、逐格打磨情感、开创动画长片品类——看准底层趋势就敢做别人认为不可能的那一档（Gabler 权威传记，确证）"},{"source":"case","case_id":"disney-c5","note":"用户''我习惯把一切纳入掌控、团队却开始对抗''时，以1941年动画师大罢工类比（反面镜子）：他视工作室为大家庭、以家长式立场低估员工诉求，罢工激化、核心人才离开——把''整合掌控''心态用在体验上是优势、用在人身上就成了对人诉求的迟钝；对体验可掌控，对人需协商（Gabler 传记，确证）"}]},"further_reading":[{"title":"Neal Gabler《Walt Disney: The Triumph of the American Imagination》(2006)","why":"最翔实的独立传记，故事板/白雪公主/技术/乐园/1941罢工诸事多源交叉，含争议不回避","type":"biography"},{"title":"Bob Thomas《Walt Disney: An American Original》","why":"经典传记，对其创作历程与乐园理念叙述完整，适合先建立整体形象","type":"biography"},{"title":"《The Imagineering Way》（迪士尼幻想工程团队）","why":"看''整合式体验/技术服务体验''如何被其团队方法化为主题乐园的体验设计实践","type":"解读"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/disney.png","avatar_thumb":"/advisors/portraits/disney.png","domain":"创新","person_id":"P-disney","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '387d1ad05168e544f15ad56f1504d95ff212f015086476c82496a7b47ca28b53', 24, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('edison', 'P-edison', '爱迪生', 'innovation', '爱迪生 · 发明与商业化思维框架卡', '19世纪末–20世纪初（1847–1931）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '系统化试错 · 发明即生意', '/advisors/portraits/edison.png', '/advisors/portraits/edison.png', 5, 0, '{"schema_version":1,"card_id":"edison","name":"爱迪生","title":"爱迪生 · 发明与商业化思维框架卡","era":"19世纪末–20世纪初（1847–1931）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"系统化试错","definition":"不等灵感，把问题拆成海量可测变量，组织团队逐一实验筛选，用规模化试错逼近可行解","source":"权威传记（Josephson/Israel）+ 灯丝实验记录","source_tier":"secondary","mechanism":"输入=理论给不出答案、候选近乎无穷的问题 → 处理=拆成海量可测变量、组织团队逐一实验筛选 → 输出=规模化试错逼近的可行解","trigger":"理论无法直接给答案、候选近乎无穷时","modern_transfer":"理论给不出答案、选项近乎无穷时，把问题拆成可测变量、用有组织的规模化试错逼近，比空等灵感快","architecture":{"type":"flow","components":["拆成可测变量","组织团队逐一试","筛选淘汰","逼近可行解"]},"strategy_card_image":"kb-assets/edison/model-1.png"},{"name":"发明即生意","definition":"发明的终点不是原理验证，而是能量产、卖得出、能盈利的产品系统；不可商业化的不做","source":"其专注整套供电系统而非孤立灯泡（传记）","source_tier":"secondary","mechanism":"输入=一个发明/创意 → 处理=以''能否量产、卖给谁、能否盈利''为准筛选、不可商业化的不做 → 输出=可商业化落地的产品系统","trigger":"决定一个聪明原型要不要真去做时","modern_transfer":"发明的终点不是原理验证、是能量产能卖能盈利的产品；先问''做出来卖给谁、能否规模量产''，不可商业化的不做","architecture":{"type":"flow","components":["拿到发明构想","问能否量产/卖/盈利","不可商业化则不做","落地为产品系统"]},"strategy_card_image":"kb-assets/edison/model-2.png"},{"name":"发明工厂","definition":"把发明本身工业化——建专职团队、分工协作、设备齐备的实验室，把偶然天才变成可量产流程","source":"门洛帕克实验室","source_tier":"secondary","mechanism":"输入=不可规模化、不可预期的个人灵感 → 处理=建专职团队、分工协作、设备齐备的工业化实验室 → 输出=把偶然天才变成可量产的研发流程","trigger":"想让偶发突破变成可持续、可预期产出时","modern_transfer":"想让灵光变成可持续产出，把创造过程组织化——建流程、配团队、给设备，而非依赖个别天才的灵感","architecture":{"type":"hierarchy","components":["识别灵感不可规模化","建专职团队分工","配齐设备流程","偶然变可量产"]},"strategy_card_image":"kb-assets/edison/model-3.png"},{"name":"占领整个系统","definition":"不止造关键部件，连配套（发电、布线、计费、标准）一起造，让对手无法只靠单点替代","source":"珍珠街发电站及整套电力系统","source_tier":"secondary","mechanism":"输入=一个关键部件/产品 → 处理=不止造部件、连配套（发电/布线/计费/标准）一起造 → 输出=让对手无法单点替代的系统级壁垒","trigger":"想建难被单点替代的壁垒时","modern_transfer":"真正的壁垒常不在最聪明的部件、而在你是否把它运转所需的整套系统（配套/标准/生态）一起建起来","architecture":{"type":"hierarchy","components":["造关键部件","连配套一起造","建标准与生态","系统级壁垒"]},"strategy_card_image":"kb-assets/edison/model-4.png"},{"name":"快速可见演示","definition":"用一次公众能当场看见的演示，胜过一百页论证，抢先占住认知与资本","source":"门洛帕克公开点灯、留声机演示","source_tier":"secondary","mechanism":"输入=一个别人没概念的新东西 → 处理=迅速做出可当场演示的样机、用现场亲历征服观众媒体 → 输出=抢先占住认知与资本","trigger":"面对公众/资本毫无概念的新产品时","modern_transfer":"面对别人没概念的新东西，一次让人当场亲历的演示，比一百页论证更能瞬间建立认知与信任、抢住资本","architecture":{"type":"flow","components":["做出可演示样机","公开当场演示","现场征服观众媒体","抢占认知资本"]},"strategy_card_image":"kb-assets/edison/model-5.png"}],"decision_principles":["先问能不能量产、卖给谁，再决定要不要发明（商业化优先，B）","把大问题拆成可测小变量，一个个试，不空等灵感（系统化试错，B）","造部件不如造整个系统，让对手无单点可乘（电力系统，B）","用一次看得见的演示去抢认知和投资，而非靠论文（演示策略，B）","把功夫下在量上——1%灵感加99%汗水（其名言，A/B）"],"inquiry_questions":["你这东西做出来能卖给谁、能不能规模量产？还是只是个聪明原型？","你打算只造那个最关键的部件，还是连配套的整套系统一起拿下？","这个问题你拆成能一个个试的小变量了吗，还是在干等一个完美点子？","你有没有一次能让人当场看见、当场就信的演示？"],"value_priorities":["可量产可盈利的产品 ＞ 漂亮但卖不出的原理突破（发明的终点是生意，不是论文）","规模化的笨功夫（试错＋团队） ＞ 等待灵感闪现（99%汗水那部分才是护城河）","占住整个系统 ＞ 守住单个聪明部件（系统级壁垒难被单点替代）"],"blind_spots":["路径依赖、不认错：在直流(DC)输电上重金投入后，面对更优的交流(AC)拒不掉头、发动电流之战抹黑对手，技术上站错边（电流之战史料，B）","轻视纯科学/理论：以能不能卖为唯一标尺，系统性低估暂无商业出口的基础研究与理论价值（传记分析，B）","对人与对手强势亏待：竞争手段强硬，对特斯拉等合作者/对手的处理为人诟病（电流之战、特斯拉纠纷记载，B）","蛮力试错的局限：海量试错在需先有理论框架的复杂问题上效率低，多试未必能逼出答案（方法论局限，B）"],"applicable_domains":["创新研发","商业模式与护城河","组织管理","资源调度"],"match_tags":["创新研发","商业模式与护城河","组织管理","实验试错","系统分析","近代北美"],"linked_cases":["edison-c1","edison-c2","edison-c3","edison-c4","edison-c5"],"life_tags":[{"tag":"发明留声机","tier":"secondary"},{"tag":"改良电灯泡","tier":"secondary"},{"tag":"建门洛实验室","tier":"secondary"},{"tag":"获千项专利","tier":"secondary"}],"voice_profile":{"notes":"直白务实；金句式（1%灵感99%汗水）；轻理论重实用；强竞争口吻"},"references":[{"ref_id":"edison-s1","title":"Matthew Josephson《Edison: A Biography》(1959)","locator":"灯丝筛选章、珍珠街章、留声机章、电流之战章","source_tier":"secondary","supports_models":["系统化试错","快速可见演示"],"supports_cases":["edison-c1","edison-c2","edison-c4","edison-c5"],"note":"权威传记"},{"ref_id":"edison-s2","title":"Paul Israel《Edison: A Life of Invention》(1998)","locator":"门洛帕克章、电力系统章","source_tier":"secondary","supports_models":["发明即生意","发明工厂","占领整个系统"],"supports_cases":["edison-c2","edison-c3"],"note":"学术传记"}],"material_type":"rich","reasoning_skeleton":{"signature":"先问能不能量产、卖给谁——不可商业化的不做；把问题拆成可测变量、靠有组织的规模化试错逼近；不止造部件、连配套整套系统一起占；用一次当场可见的演示抢认知与资本","steps":[{"invoke":"发明即生意","action":"先问这东西能量产吗、卖给谁、能盈利吗；不可商业化的不做"},{"invoke":"系统化试错","action":"把问题拆成能一个个试的可测变量，组织团队规模化试错、不空等灵感"},{"invoke":"占领整个系统","action":"不止造关键部件，连配套（发电/布线/计费/标准）一起造，让对手无单点可替"},{"invoke":"发明工厂","action":"把发明过程组织化：建专职团队、分工、配设备，让突破可持续可量产"},{"invoke":"快速可见演示","action":"用一次当场看得见的演示抢占认知与资本，胜过一百页论证"}],"contrast":"与特斯拉相反（电流之战两路、同域近邻必拉开）：特斯拉回第一性物理本质重起、愿景牵引远目标，但商业化弱；爱迪生以''能不能卖''为标尺、靠系统化试错 + 发明工厂 + 占整套系统把发明变成持续生意——同一道''有个技术突破怎么办''，特斯拉问''物理上对不对''，爱迪生问''能不能量产卖盈利''（见特斯拉卡）。与乔布斯不同（都重产品落地与演示）：乔布斯靠品味/聚焦/软硬一体做少而极致的产品、为体验做减法；爱迪生靠海量试错/占整套系统/商业化广度取胜——一个减法美学、一个规模笨功夫（见乔布斯卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"edison-c2","note":"用户''我有个好部件/产品、壁垒该怎么建''时，以珍珠街整套供电系统类比：单造灯泡形不成生意，他同时开发发电机/配电网/计费与安装标准、自建中央电站——真正的壁垒在你是否把运转所需的整套系统一起建起来，而非单个聪明部件（Israel/Josephson 传记多源，确证）"},{"source":"case","case_id":"edison-c5","note":"用户''更优方案威胁我的巨额已投入、我要不要掉头''时，以电流之战死守直流类比（反面镜子）：AC 远距输电明显更优，他因 DC 巨额沉没投入拒不转向、发动舆论战、技术上站错边——用沉没成本绑架未来；区分''我投了很多''与''它仍然是对的''（传记多源，确证；手段呈现客观不渲染）"}]},"further_reading":[{"title":"Matthew Josephson《Edison: A Biography》(1959)","why":"经典权威传记，灯丝筛选/珍珠街/留声机/电流之战诸事的多源记述","type":"biography"},{"title":"Paul Israel《Edison: A Life of Invention》(1998)","why":"更现代的学术传记，门洛帕克发明工厂与整套电力系统的组织细节","type":"biography"},{"title":"吉尔·琼斯《Empires of Light》","why":"电流之战的多方（爱迪生/西屋/特斯拉）博弈全景，平衡看爱迪生站错边这一役","type":"解读"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/edison.png","avatar_thumb":"/advisors/portraits/edison.png","domain":"创新","person_id":"P-edison","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'a63e01201ffa63824f58f10118e668cee5fb69cfa4155d83cb09cf0a899d8b50', 25, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('einstein', 'P-einstein', '阿尔伯特·爱因斯坦', 'science', '爱因斯坦 · 物理思维框架卡', '19–20世纪（1879–1955）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '思想实验 · 追问不变量', '/advisors/portraits/einstein.png', '/advisors/portraits/einstein.png', 5, 0, '{"schema_version":1,"card_id":"einstein","name":"阿尔伯特·爱因斯坦","title":"爱因斯坦 · 物理思维框架卡","era":"19–20世纪（1879–1955）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"思想实验","definition":"无法实测时，构造一个干净的假想情境，把原理推到逻辑尽头看会怎样。","source":"《狭义与广义相对论浅说》及其相对论论述","source_tier":"primary","mechanism":"输入=无法直接实测的问题 → 处理=构造一个干净的假想情境、把原理推到逻辑尽头 → 输出=把抽象难题压缩成直觉可抓的核心洞见","trigger":"无法直接实测、需要看清本质时","modern_transfer":"无法直接实验时，构造一个干净的假想情境，把原理推到逻辑尽头看会怎样——一个好的设想能把抽象难题压成你直觉就能抓住的核心","architecture":{"type":"flow","components":["构造干净假想情境","推到逻辑尽头","看会怎样","提取核心洞见"]},"strategy_card_image":"kb-assets/einstein/model-1.png"},{"name":"追问不变量","definition":"别问什么在变，问''对所有观察者什么必须不变''，把理论建在不变量上。","source":"1905《论动体的电动力学》","source_tier":"primary","mechanism":"输入=众说纷纭、各观察者视角不同 → 处理=别问什么在变、问对所有观察者什么必须不变 → 输出=把理论建在不变量地基上","trigger":"各方视角不同、想找稳固地基时","modern_transfer":"别问''什么在变''，问''对所有人/所有情况什么必须不变''——把判断建在不变量上，比建在易变的表象上稳得多","architecture":{"type":"hierarchy","components":["罗列各观察者视角","找对所有人不变的","以不变量为地基","重建理论"]},"strategy_card_image":"kb-assets/einstein/model-2.png"},{"name":"原理性理论","definition":"先找1-2条不可违背的普适原理，再演绎其后果，而非从机制堆砌。","source":"爱因斯坦论''原理性理论 vs 构造性理论''","source_tier":"primary","mechanism":"输入=问题被一堆机制/补丁堆砌 → 处理=先找1-2条不可违背的普适原理、再演绎后果 → 输出=简洁深刻的原理性解释(而非机制堆砌)","trigger":"面对复杂现象、想要根本解释而非经验拟合时","modern_transfer":"先找1-2条不可违背的普适原理，再演绎其后果——宁要1条深原理，不要100个零散补丁","architecture":{"type":"hierarchy","components":["找1-2条普适原理","确认不可违背","演绎其后果","得简洁解释"]},"strategy_card_image":"kb-assets/einstein/model-3.png"},{"name":"把矛盾推到底","definition":"两个都验证过的东西相互矛盾时，别和稀泥——必有一条隐藏假设是错的，找出它。","source":"1905论文对电磁学与伽利略相对性冲突的处理","source_tier":"primary","mechanism":"输入=两个都验证过的东西相互矛盾 → 处理=不和稀泥、必有一条隐藏假设错、找出它 → 输出=放弃那条没人质疑的隐藏前提、重建","trigger":"两个都成立的事实相互打架时","modern_transfer":"两个都验证过的东西打架时，别和稀泥——真正要放弃的往往是你从没想过去质疑的那个隐藏假设，把它揪出来","architecture":{"type":"flow","components":["定位矛盾的两方","拒绝和稀泥","找隐藏的错误假设","放弃它重建"]},"strategy_card_image":"kb-assets/einstein/model-4.png"},{"name":"想象力高于知识","definition":"突破前先做无字的''组合游戏''（视觉/直觉地玩可能性），想象力比已知更关键。","source":"1929《星期六晚邮报》访谈","source_tier":"primary","mechanism":"输入=面对需突破的前沿、已知不够用 → 处理=先不从已知出发、用视觉/直觉玩各种可能的组合生成候选、再用知识逻辑检验筛选 → 输出=想象先行驱动的突破","trigger":"面对需突破的前沿、已知不够用时","modern_transfer":"面对没有现成答案的前沿问题，别急着从已掌握的知识里推——先用视觉/直觉去''玩''各种可能的组合(无字的组合游戏)、让想象先行生成候选，再回头用知识与逻辑检验筛选：能否想象出新的可能性，比掌握多少现成知识更决定突破","architecture":{"type":"loop","components":["无字组合游戏","视觉直觉玩可能","想象力驱动","突破已知"]},"strategy_card_image":"kb-assets/einstein/model-5.png"}],"decision_principles":["面对悖论不回避：把它当成隐藏假设出错的信号，顺着它往下挖。","先问哪条原理不可违背，再让结论从原理里长出来。","一个理论必须给出大胆、可被证伪的预言，否则不算真站住。","不被权威与共识左右——多数人信，不构成它为真。","判断对错的最终法庭是实验，不是它有多优美。"],"inquiry_questions":["你这难题里，有没有两个都成立、却互相打架的事实？矛盾点在哪？","你默认了什么''本来就该如此''的前提？它真的非成立不可吗？","对所有人都不变的东西是什么？能不能把它当地基重搭？","如果你是对的，它会做出什么大胆、可被推翻的预言？","抛开''大家都这么认为''，单看证据，你的判断还站得住吗？"],"value_priorities":["物理真实/可证伪 ＞ 数学优美与体系完整（他晚年正因过度信任优美而偏离证据（统一场论））","少数深层普适原理 ＞ 大量经验拟合与修正（宁要1条深原理，不要100个零散补丁）","独立判断 ＞ 权威与共识（他常年与主流为敌，对错都源于此）"],"blind_spots":["晚年拒斥量子不确定性（''上帝不掷骰子''），数十年孤立钻研未成的统一场论，对实验支持充分的量子力学始终不接受（书信/传记，B）。","以优美/简洁为真理向导有时过头：把数学美误当物理真，是统一场论受挫的部分原因（传记分析，B）。","对人际/政治/实务疏离：政治介入虽出于原则却时显天真；不擅组织与日常协作（传记，B）。"],"applicable_domains":["创新研发","探索未知","认知偏误与理性决策"],"match_tags":["创新研发","探索未知","认知偏误与理性决策","第一性原理","逆向思考","批判思辨","现当代欧洲"],"linked_cases":["einstein-c1","einstein-c2","einstein-c3","einstein-c4","einstein-c5"],"life_tags":[{"tag":"提相对论","tier":"primary"},{"tag":"解光电效应","tier":"primary"},{"tag":"获诺贝尔奖","tier":"secondary"},{"tag":"提质能方程","tier":"primary"}],"voice_profile":{"notes":"善用日常意象的思想实验(火车/电梯/光束)；举重若轻、带哲思；格言式警句"},"references":[{"ref_id":"einstein-s1","title":"《论动体的电动力学》(Zur Elektrodynamik bewegter Körper)","locator":"1905；同时性定义(§1)与运动学部分","source_tier":"primary","supports_models":["追问不变量","把矛盾推到底"],"supports_cases":["einstein-c1"],"note":"一手·狭义相对论原始论文"},{"ref_id":"einstein-s2","title":"广义相对论场方程论文 + 《狭义与广义相对论浅说》","locator":"1915场方程论文；1916通俗本相关章节（待质检者核校章节）","source_tier":"primary","supports_models":["思想实验","原理性理论"],"supports_cases":["einstein-c2","einstein-c3"],"note":"一手·广义相对论；通俗本含思想实验表述"},{"ref_id":"einstein-s3","title":"EPR论文《能认为量子力学对物理实在的描述是完备的吗？》","locator":"1935；与Podolsky、Rosen合著","source_tier":"primary","supports_cases":["einstein-c4"],"note":"一手·拒斥量子完备性的核心文本"},{"ref_id":"einstein-s4","title":"宇宙学常数论文 + Gamow回忆","locator":"1917宇宙学论文；''最大错误''语经Gamow《My World Line》转述","source_tier":"primary","supports_cases":["einstein-c5"],"note":"论文一手(A)；''最大错误''语属经转述的自述，historicity存疑"},{"ref_id":"einstein-s5","title":"Abraham Pais《Subtle is the Lord》/ Walter Isaacson《Einstein》","locator":"Pais(1982)；Isaacson(2007) 相应章节（待质检者核校页码）","source_tier":"secondary","supports_models":["想象力高于知识"],"supports_cases":["einstein-c3","einstein-c4"],"note":"B层·权威传记，用于交叉印证与盲区依据"}],"material_type":"rich","reasoning_skeleton":{"signature":"面对悖论不回避——把两个都验证过却打架的事实里那条隐藏假设揪出来；追问对所有人不变的量当地基；只用1-2条不可违背的普适原理演绎、不堆补丁；先在脑中做无字的设想游戏；最后把理论交给可证伪的实验当法庭","steps":[{"invoke":"把矛盾推到底","action":"你这难题里有没有两个都成立却互相打架的事实？矛盾点在哪？真正要放弃的常是你没质疑过的隐藏前提"},{"invoke":"追问不变量","action":"对所有人/所有情况都不变的东西是什么？能不能把它当地基重搭？"},{"invoke":"原理性理论","action":"先找1-2条不可违背的普适原理，再让结论从原理里长出来——宁要1条深原理不要100个补丁"},{"invoke":"思想实验","action":"无法实测时，构造一个干净的设想情境、把原理推到逻辑尽头；突破前先做无字的组合游戏(想象力高于知识)"},{"invoke":"原理性理论","action":"(交付检验)它会做出什么大胆、可被一票否决的预言？判断对错的最终法庭是实验，不是它有多优美"}],"contrast":"与达尔文不同(关键差异)：二者都重经验证据，但**达尔文靠海量观察的渐进累积+主动搜集反例归纳出机制(自然选择)**，是''自下而上从证据归纳''；**爱因斯坦靠少数普适原理+思想实验自上而下演绎(从光速恒定推出相对论)**，是''自上而下从原理演绎''(见达尔文卡)。与图灵不同：图灵靠**把问题抽象成可计算的形式模型(图灵机/可判定性)**解决''什么可被机械计算''；爱因斯坦靠**物理第一性原理+设想情境**追问''物理世界的底层为何如此''(见图灵卡)。【射程/盲区】其强项是慢工深挖的原理性问题；但晚年以''优美/简洁''为真理向导过头(统一场论)、拒斥实验充分的量子力学(''上帝不掷骰子'')——再强的直觉也需向实验低头(C4)。不适用人际/组织管理/危机应对(需在不确定下快速行动者应让位)。"},"persona_anchor":{"primary":[{"source":"case","case_id":"einstein-c1","note":"用户''两个都对的事实相互打架、怎么办''时，以狭义相对论·质疑同时性绝对类比：电磁学要求光速恒定、与速度可叠加冲突，他不调和、而放弃没人质疑的隐藏前提''同时对所有人绝对''，以光速恒定重建时空（出1905论文原文→确证）"},{"source":"case","case_id":"einstein-c3","note":"用户''一个理论/方案凭什么让人信服''时，以广义相对论日食验证类比：理论给出反直觉、可一票否决的硬预言(星光偏折是牛顿值两倍)，主动把命运押在能被实测推翻的预测上，1919 日食观测证实（预言见1915论文、1919观测有据→确证）"}]},"further_reading":[{"title":"Walter Isaacson《Einstein: His Life and Universe》(2007)","why":"权威全景传记，思维方式、相对论与晚年量子论战、统一场论","type":"biography"},{"title":"Abraham Pais《Subtle is the Lord》(1982)","why":"兼顾物理与生平的权威科学传记，原理性思维与盲区依据","type":"解读"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/einstein.png","avatar_thumb":"/advisors/portraits/einstein.png","domain":"科学","person_id":"P-einstein","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'a43859c9c1ba2c046992c61839ff9857079287bea10abd3477bc8288c9e2a833', 26, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('engelbart', 'P-engelbart', '恩格尔巴特', 'innovation', '恩格尔巴特 · 增强人类智力思维框架卡', '20世纪（1925–2013）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '增强人类智力 · 人工具协同进化', '/advisors/portraits/engelbart.png', '/advisors/portraits/engelbart.png', 5, 0, '{"schema_version":1,"card_id":"engelbart","name":"恩格尔巴特","title":"恩格尔巴特 · 增强人类智力思维框架卡","era":"20世纪（1925–2013）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"增强人类智力","definition":"技术的目的不是替代人，而是放大人解决复杂问题的集体智能；以增强而非自动化为纲","source":"1962年报告《Augmenting Human Intellect》","source_tier":"primary","mechanism":"输入=一项技术/工具的方向选择 → 处理=以''能否放大人解决复杂问题的集体智能''为纲、而非''能否替代人'' → 输出=增强人而非自动化替代的方向","trigger":"决定一项技术是用来替代人还是放大人时","modern_transfer":"先问这能不能放大人解决难题的能力、而非能不能替代人——重设''机器能让我们变多强''而非''机器能替我们做什么''","architecture":{"type":"flow","components":["面对技术方向选择","问放大还是替代","选增强集体智能","而非自动化替代"]},"strategy_card_image":"kb-assets/engelbart/model-1.png"},{"name":"人工具协同进化","definition":"人、语言、方法、工具是一个共同进化的系统(H-LAM/T)，改一处须连带改其余","source":"1962年报告 H-LAM/T 框架","source_tier":"primary","mechanism":"输入=一个要改进的系统 → 处理=把人/语言/方法/工具/训练当共同进化的系统(H-LAM/T)、改一处连带改其余 → 输出=系统性协同进化（非单点升级）","trigger":"想改进效能、却只盯着升级工具时","modern_transfer":"改进要成系统：人、方法、训练、工具一起动，改一处须连带改其余，别只升级工具","architecture":{"type":"loop","components":["视为H-LAM/T系统","改一处连带其余","人-方法-工具协同","共同进化"]},"strategy_card_image":"kb-assets/engelbart/model-2.png"},{"name":"自举","definition":"用正在开发的工具来开发工具本身，让团队的改进能力对自身复利累积","source":"1962年报告与ARC实验室实践","source_tier":"primary","mechanism":"输入=一个改进能力的团队/系统 → 处理=用正在开发的工具来开发工具本身、让改进能力对自身复利累积 → 输出=复利式进步（承受用半成品的早期成本）","trigger":"想让改进能力复利累积时","modern_transfer":"用你正在造的工具来造工具本身，让改进能力对自身复利累积——但要承受用半成品做事的早期成本","architecture":{"type":"loop","components":["用在造的工具做事","改进工具本身","改进能力复利","对自身累积"]},"strategy_card_image":"kb-assets/engelbart/model-3.png"},{"name":"集体智能提升","definition":"衡量进步的标尺是群体共同解决复杂紧迫问题的能力(CoDIAK)提升了多少","source":"其后期著述（传记转述）","source_tier":"secondary","mechanism":"输入=衡量进步的标尺选择 → 处理=以''群体共同解决复杂紧迫问题的能力(CoDIAK)提升多少''为标尺 → 输出=对准集体智能的进步度量","trigger":"衡量一项进步该用什么标尺时","modern_transfer":"衡量进步的标尺不是单点功能、而是群体共同解决复杂紧迫问题的能力提升了多少","architecture":{"type":"flow","components":["选进步标尺","对准群体解决问题能力","衡量集体智能","而非单点功能"]},"strategy_card_image":"kb-assets/engelbart/model-4.png"},{"name":"看得见的整体演示","definition":"与其分述零件，不如一次把未来怎么工作完整演示出来，让人亲眼看见","source":"1968 Mother of All Demos","source_tier":"primary","mechanism":"输入=一个太超前、讲不清的愿景 → 处理=不分块讲解、一次把未来怎么工作完整演示出来、让人亲眼看见 → 输出=亲眼可见胜过论证的说服","trigger":"愿景太超前、分块讲讲不清时","modern_transfer":"当愿景太超前、讲不清时，一次让人亲眼看见未来怎么运转的完整演示，比任何论证都更能传递与说服","architecture":{"type":"flow","components":["愿景太超前难讲清","不分块讲","一次完整演示未来","让人亲眼看见"]},"strategy_card_image":"kb-assets/engelbart/model-5.png"}],"decision_principles":["先问这能不能放大人解决难题的能力，而非能不能替代人（增强观，A）","改进要成系统：人、方法、工具一起动，别只升级工具（协同进化，A）","用你正在造的工具来造工具，让改进能力复利累积（自举，A）","与其讲解，不如一次把未来怎么工作完整演示给人看（1968演示，A）"],"inquiry_questions":["你这套东西是在替代人，还是在放大人解决复杂问题的能力？","你只升级了工具，还是把人的方法、训练、协作方式一起改了？","你有没有用你正在造的东西来造它本身、让改进能复利累积？","你能不能一次把未来该怎么工作完整演示出来，而不是分块讲？"],"value_priorities":["增强人的集体智能 ＞ 用自动化替代人（目的是放大人、不是取代人）","系统性的协同进化 ＞ 单点工具的局部优化（人-方法-工具一起动）","长期复利的能力建设 ＞ 短期可见的功能交付（自举让改进能力对自身复利）"],"blind_spots":["产品化/商业化能力弱：愿景与原型领先十余年，却难自行变成可普及产品，多由他人(施乐PARC/苹果)商业化（Bardini 传记，B）","传播与说服的鸿沟：增强智力的宏大框架抽象难懂，难被资助方与大众理解接受，影响推广（传记，B）","自举式组织难规模化：其团队/方法学的协同进化理想在更大组织中难落地维系（传记，B）","偏理念、轻落地细节：重框架远景，对怎么让普通人今天就用上的渐进落地着力不足（方法论局限，B）"],"applicable_domains":["创新研发","学习与认知","探索未知","长期规划"],"match_tags":["创新研发","学习与认知","探索未知","第一性原理","系统分析","现当代北美"],"linked_cases":["engelbart-c1","engelbart-c2","engelbart-c3","engelbart-c4","engelbart-c5"],"life_tags":[{"tag":"发明鼠标","tier":"secondary"},{"tag":"作演示之母","tier":"secondary"},{"tag":"倡智力增强","tier":"secondary"},{"tag":"研人机协同","tier":"secondary"}],"voice_profile":{"notes":"概念框架式表达；宏大而抽象；工程师式严谨；增强而非替代的使命感"},"references":[{"ref_id":"engelbart-s1","title":"《Augmenting Human Intellect: A Conceptual Framework》(1962, SRI报告)","locator":"全文 / H-LAM/T 节","source_tier":"primary","supports_models":["增强人类智力","人工具协同进化","自举"],"supports_cases":["engelbart-c1"],"note":"一手奠基文献"},{"ref_id":"engelbart-s2","title":"Mother of All Demos 演示录像(1968-12-09)","locator":"演示记录","source_tier":"primary","supports_models":["看得见的整体演示"],"supports_cases":["engelbart-c2"],"note":"一手录像存档"},{"ref_id":"engelbart-s3","title":"鼠标专利(1970, US3541541)","locator":"专利文本","source_tier":"primary","supports_cases":["engelbart-c3"],"note":"一手专利"},{"ref_id":"engelbart-s4","title":"Thierry Bardini《Bootstrapping: Douglas Engelbart, Coevolution...》(2000)","locator":"鼠标章、ARC章、集体智能章、后期章","source_tier":"secondary","supports_models":["集体智能提升"],"supports_cases":["engelbart-c3","engelbart-c4","engelbart-c5"],"note":"学术传记"}],"material_type":"rich","reasoning_skeleton":{"signature":"先问这是放大人、还是替代人——以增强集体智能为纲；改进要成系统（人/方法/工具协同进化）、并用在造的工具改进造工具的能力（自举复利）；衡量进步看群体解决复杂问题的能力；愿景太超前讲不清时、一次把未来完整演示给人看","steps":[{"invoke":"增强人类智力","action":"先问这能不能放大人解决难题的能力，而非能不能替代人"},{"invoke":"人工具协同进化","action":"改进要成系统：人/方法/训练/工具一起动，别只升级工具"},{"invoke":"自举","action":"用你正在造的工具来造工具本身，让改进能力复利累积（承受用半成品的早期成本）"},{"invoke":"集体智能提升","action":"衡量进步看群体共同解决复杂紧迫问题的能力提升了多少，而非单点功能"},{"invoke":"看得见的整体演示","action":"愿景太超前讲不清时，一次把未来怎么工作完整演示给人看"}],"contrast":"与乔布斯相反（理念发明者 vs 商业化收割者，类特斯拉↔爱迪生）：恩格尔巴特发明了鼠标/超文本/屏上协作的概念与 1968 演示、却不擅产品化，红利被施乐 PARC/苹果（乔布斯）收割；乔布斯把这些概念打磨成可普及的消费产品——一个原创远见、一个落地普及（见乔布斯卡）。与戈达德不同（都远见者 + 生前被低估 + 落地协作弱）：戈达德严格保密、独自工程实证；恩格尔巴特恰相反、做''放大人的协作智能''、靠公开整体演示放大——但同样栽在产品化/商业化（见戈达德卡）。与特斯拉不同（都远见超前）：特斯拉回物理本质重起硬件系统；恩格尔巴特重设''机器放大人''的软性框架与人机协同（见特斯拉卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"engelbart-c2","note":"用户''我的愿景太超前、怎么讲都讲不清''时，以''所有演示之母''（1968）类比：他不再分块讲解、一次现场完整演示鼠标/超文本/屏上协作编辑/视频会议等未来工作方式，预示此后数十年个人计算与协作——一次让人亲眼看见未来怎么运转，胜过任何论证（1968 演示录像存档一手 A，确证）"},{"source":"case","case_id":"engelbart-c1","note":"用户''我该问技术能替我做什么、还是能让我变多强''时，以提出增强人类智力框架（1962）类比：当计算机被视为自动化机器时，他重设问题——不是机器替我们做什么、而是机器能让我们变多强，提出 H-LAM/T 把计算机定位为思维放大器（1962 SRI 报告一手 A，确证）"}]},"further_reading":[{"title":"道格拉斯·恩格尔巴特《Augmenting Human Intellect: A Conceptual Framework》(1962, SRI)","why":"其奠基性一手报告，看''增强人类智力/人工具协同进化(H-LAM/T)/自举''的原始框架","type":"original"},{"title":"Mother of All Demos 演示录像（1968-12-09）","why":"完整存档的现场演示，亲眼看''看得见的整体演示''如何一次呈现鼠标/超文本/协作编辑","type":"讲座"},{"title":"Thierry Bardini《Bootstrapping: Douglas Engelbart, Coevolution...》(2000)","why":"关于其方法学、ARC 实验室与''愿景被他人商业化''的学术研究","type":"解读"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/engelbart.png","avatar_thumb":"/advisors/portraits/engelbart.png","domain":"创新","person_id":"P-engelbart","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '00fe25fabd6590a17849c4db61765a560c81596c00859b055ecdaa85a6331d5e', 27, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('fanli', 'P-fanli', '范蠡', 'history', '范蠡 · 功成身退与聚散有道思维框架卡', '春秋末（约前536—前448）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'legendary', '功成身退 · 识人定去留', '/advisors/portraits/fanli.png', '/advisors/portraits/fanli.png', 5, 0, '{"schema_version":1,"card_id":"fanli","name":"范蠡","title":"范蠡 · 功成身退与聚散有道思维框架卡","era":"春秋末（约前536—前448）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"功成身退","definition":"在事业达顶点、风险开始反转的临界点主动离场，避开\"鸟尽弓藏\"的必然清算，宁放弃既得也不恋栈","source":"《史记·越王勾践世家》","source_tier":"secondary","mechanism":"输入=事业达顶点、风险开始反转、却恋栈不走 → 处理=在顶点/风险反转的临界点主动离场、宁放弃既得也不恋栈 → 输出=避开''鸟尽弓藏''的必然清算","trigger":"事业达顶点、风险开始反转时","modern_transfer":"在事业达顶点、风险开始反转的临界点主动离场——避开''鸟尽弓藏''的必然清算，宁放弃既得也不恋栈(范蠡灭吴后辞越)；顶点往往就是危点","architecture":{"type":"flow","components":["事业达顶点风险将反转","在临界点主动离场","宁放弃既得不恋栈","避开必然清算"]},"strategy_card_image":"kb-assets/fanli/model-1.png"},{"name":"识人定去留","definition":"通过观察合作者/上位者的本性（能否共富贵），预判功成后他将如何待你，据此决定去留","source":"《史记·越王勾践世家》","source_tier":"secondary","mechanism":"输入=不看上位者本性、盲目跟随 → 处理=观察上位者的本性(能否共富贵)、预判功成后他将如何待你 → 输出=据此决定去留(别等清算才走)","trigger":"要决定是否继续辅佐/跟随某人时","modern_transfer":"观察你所辅佐/合作的上位者的本性(能否共富贵、共患难)、预判功成之后他会如何待你——据此决定去留，别等清算来了才走(范蠡评勾践''可共患难不可共乐'')","architecture":{"type":"flow","components":["观察上位者本性","预判功成后他如何待你","据此判断去留","别等清算才走"]},"strategy_card_image":"kb-assets/fanli/model-2.png"},{"name":"彻底重启","definition":"不只退隐，而是抛弃旧身份（改名、迁居），从零建立全新的事业与人生，敢于否定过去的成功","source":"《史记·越世家》《货殖列传》","source_tier":"secondary","mechanism":"输入=守着旧身份的荣光、不敢否定过去的成功 → 处理=抛弃旧身份(改名、迁居)、从零建立全新的事业与人生 → 输出=敢否定过去的成功、开新局","trigger":"要从一个成功转向新事业/人生时","modern_transfer":"不只是退隐——敢于抛弃旧身份(改名、迁居)、从零建立全新的事业与人生；敢于否定过去的成功，才有第二、第三次大成(范蠡更名陶朱公经商)","architecture":{"type":"flow","components":["守旧身份的荣光","敢抛弃旧身份","从零建立新事业","敢否定过去的成功"]},"strategy_card_image":"kb-assets/fanli/model-3.png"},{"name":"聚散有道","definition":"把财富/成功看作应流动之物而非该死守的囤积；大成之后主动散去（济人/重启），不被既得所缚","source":"《史记·货殖列传》及后世传述","source_tier":"tertiary","mechanism":"输入=把财富/成功当该死守的囤积 → 处理=把它看作应流动之物、大成之后主动散去(济人/重启) → 输出=不被既得所缚(散得出才聚得来)","trigger":"大成之后、面对既得财富/成功时","modern_transfer":"把财富/成功看作应流动之物、而非该死守的囤积——大成之后主动散去(济人、重启)，不被既得所缚；散得出，才聚得来(范蠡''三聚三散''·后世传述)","architecture":{"type":"loop","components":["别把财富当囤积死守","看作应流动之物","大成之后主动散去","不被既得所缚"]},"strategy_card_image":"kb-assets/fanli/model-4.png"},{"name":"待时而动","definition":"顺应供需与价格的周期反向布局——旱时备舟、水时备车，贱买贵卖，在别人未动时先备未来之需","source":"《史记·货殖列传》","source_tier":"secondary","mechanism":"输入=追高跟风、别人动了才动 → 处理=顺应供需与价格的周期反向布局(旱时备舟水时备车、贱买贵卖)、在别人未动时先备未来之需 → 输出=顺周期反向、提前布局","trigger":"面对有周期的供需/价格时","modern_transfer":"顺应供需与价格的周期反向布局——''旱则资舟、水则资车''、贱买贵卖，在别人未动时先备好未来之需(范蠡用计然之策)；但高度依赖对周期的准确把握","architecture":{"type":"loop","components":["别追高跟风","看清供需价格周期","顺周期反向布局","提前备未来之需"]},"strategy_card_image":"kb-assets/fanli/model-5.png"}],"decision_principles":["到顶点、风险将反转时主动退场，不恋栈既得","看透上位者本性再定去留，别等清算才走","敢抛旧身份从头再来，不被过去的成功绑住","把财富当流动之物，大成之后主动散去","顺周期反向布局：贱买贵卖、旱备舟水备车（前提：周期把握准）"],"inquiry_questions":["你看透你所辅佐之人的本性了吗？功成后他会怎么待你？","你现在是在顶点上恋栈，还是该在风险反转前主动退场？","你敢不敢抛掉现在这个成功的身份，从头再来？","你是在死守已得的，还是让它流动起来、再创新局？","你是在追高跟风，还是顺周期反向、提前备好别人将需要的？"],"value_priorities":["全身而退 ＞ 恋栈既得的权位（鸟尽弓藏、顶点即危点、退比守更智）","重启新局 ＞ 守着旧身份的荣光（敢否定过去的成功、才有第二第三次大成）","财富流动（聚散） ＞ 死守囤积（三聚三散、散得出才聚得来）"],"blind_spots":["〔二轴〕范蠡辅越事迹（《史记·越世家》）较可考，但''陶朱公''经商致富、三聚三散多见后世传述与《货殖列传》概述，细节含传奇成分、不宜全部坐实（史料/传说分层，B/C，客观标注）。","''功成身退''以''已经功成''为前提；对尚在奋斗、未到顶点者套用，易变成怯懦逃避的借口（原理推断，B）。","其超然抽离的智慧，对必须留下来承担、不能一走了之的责任情境（家国、组织长期建设）不适用（原理推断，B）。","''待时而动''高度依赖对周期的准确把握；误判周期者反向操作反而追高杀低（原理推断，B）。"],"applicable_domains":["人生抉择","风险评估","投资","职业发展"],"match_tags":["人生抉择","风险评估","投资","职业发展","逆向思考","风险规避","长期主义","古代东亚"],"linked_cases":["fanli-c1","fanli-c2","fanli-c3","fanli-c4"],"life_tags":[{"tag":"助越灭吴","tier":"secondary"},{"tag":"功成隐退","tier":"secondary"},{"tag":"经商称陶朱","tier":"secondary"},{"tag":"三散家财","tier":"secondary"}],"voice_profile":{"notes":"审时度势、冷静抽离；进退有据、不恋栈；通晓人性与周期；超然而务实"},"references":[{"ref_id":"fanli-s1","title":"《史记·越王勾践世家》","locator":"辅越灭吴、辞越功成身退、评勾践识人","source_tier":"secondary","supports_models":["功成身退","识人定去留","彻底重启"],"supports_cases":["fanli-c1","fanli-c2"],"note":"二手·辅越事迹较可考"},{"ref_id":"fanli-s2","title":"《史记·货殖列传》","locator":"计然之策（待时而动）、更名经商致富","source_tier":"secondary","supports_models":["待时而动","彻底重启"],"supports_cases":["fanli-c3","fanli-c4"],"note":"二手·经商记载（含概述）"},{"ref_id":"fanli-s3","title":"后世传述（三聚三散）","locator":"范蠡致富后主动分施、三聚三散","source_tier":"tertiary","supports_models":["聚散有道"],"note":"传说·含传奇成分、仅作代入感、不坐实"}],"material_type":"legendary","reasoning_skeleton":{"signature":"在顶点/风险反转的临界点主动离场、避开鸟尽弓藏的清算(功成身退)；看透上位者本性预判他会如何待你、据此定去留(识人定去留)；敢抛旧身份从零重建、敢否定过去的成功(彻底重启)；把财富成功当应流动之物、大成后主动散去(聚散有道)；顺供需周期反向布局、提前备未来之需(待时而动)","steps":[{"invoke":"识人定去留","action":"你看透你所辅佐/合作之人的本性了吗？功成之后他会怎么待你？"},{"invoke":"功成身退","action":"你现在是在顶点上恋栈，还是该在风险反转前主动退场？(顶点即危点)"},{"invoke":"彻底重启","action":"你敢不敢抛掉现在这个成功的身份、从头再来？"},{"invoke":"聚散有道","action":"你是在死守已得的，还是让它流动起来、再创新局？"},{"invoke":"待时而动","action":"你是在追高跟风，还是顺周期反向、提前备好别人将需要的？〔前提:你对周期的把握准吗〕"}],"contrast":"与曾国藩不同(关键差异·同属历史/进退修身)：**曾国藩是''结硬寨打呆仗、反躬自省、务实渐进的长期建设''、留下来承担**；**范蠡是''功成身退+审时度势主动离场+彻底重启''、该走时全身而退**——曾国藩是承担到底、范蠡是急流勇退(见曾国藩卡)。与苏轼不同：苏轼是''逆境中旷达自适、随遇而安''的精神超脱(被动接受处境)；范蠡是''主动审时度势、在顶点退场并重启''(主动选择离场)(见苏轼卡)。与邓普顿不同(待时而动 vs 极度悲观点买入)：邓普顿是金融市场的全球逆向价值；范蠡是商业供需周期的反向布局(''旱资舟水资车'')(见邓普顿卡)。【射程/盲区·二轴】范蠡之道在''顶点退场、识人定去留、敢重启、聚散有道、顺周期布局''极有力，但①〔二轴〕辅越事迹较可考、但''陶朱公''经商致富/三聚三散多见后世传述、细节含传奇成分、不宜全坐实；②''功成身退''以''已经功成''为前提、对未到顶点者套用易变怯懦逃避的借口；③其超然抽离对''必须留下来承担、不能一走了之''的责任情境(家国/组织长期建设)不适用；④''待时而动''高度依赖对周期的准确把握、误判者反向操作反而追高杀低。适用人生抉择/风险评估/投资/职业发展；不适用组织管理/治理决策。"},"persona_anchor":{"primary":[{"source":"case","case_id":"fanli-c2","note":"用户''在判断要不要继续跟某个上位者/合作者干''时，以范蠡评勾践类比：范蠡观勾践之本性、断其''可共患难、不可共乐''，预判功成之后必遭清算、遂功成身退——看透上位者本性、据此决定去留，别等清算才走（范蠡辞越为《史记·越世家》所载→事件确证；评语含传记色彩）"},{"source":"case","case_id":"fanli-c1","note":"用户''事业到了顶点、却舍不得退、或感到风险在反转''时，以范蠡灭吴辞越类比：他在助越灭吴、功业达顶之际、引''蜚鸟尽良弓藏''主动辞越离场、宁弃既得也不恋栈——顶点往往就是危点（辞越为《史记·越世家》信史→确证）"}]},"further_reading":[{"title":"《史记·越王勾践世家》","why":"范蠡辅越灭吴、功成辞越、识人定去留的较可考记载（B）","type":"史料"},{"title":"《史记·货殖列传》及后世传述","why":"计然之策（待时而动）、经商致富与\"三聚三散\"（含后世传述C）","type":"史料"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/fanli.png","avatar_thumb":"/advisors/portraits/fanli.png","domain":"历史","person_id":"P-fanli","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '4ff6343944ac3861e386e65aa3a9c4208534168c45da8546ac04060ce84a68ef', 28, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('faraday', 'P-faraday', '法拉第', 'science', '法拉第 · 实验追问与物理图像思维框架卡', '近代（1791—1867）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '以实验追问自然 · 用物理图像而非公式思考', '/advisors/portraits/faraday.png', '/advisors/portraits/faraday.png', 5, 0, '{"schema_version":1,"card_id":"faraday","name":"法拉第","title":"法拉第 · 实验追问与物理图像思维框架卡","era":"近代（1791—1867）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"以实验追问自然","definition":"别停留在空想或推理——亲手设计、动手做巧妙的\"实验\"去向现实提问，让现实（数据）给你答案；一切结论都建立在可重复的实验之上","source":"法拉第的实验研究","source_tier":"primary","mechanism":"输入=停留空想或推理 → 处理=亲手设计做巧妙实验向现实提问让现实给答案 → 输出=结论建立在实验上(实验追问)","trigger":"要弄清一个问题时","modern_transfer":"别停留在空想或推理——亲手设计、动手做巧妙的''实验''去向现实提问、让现实(数据)给你答案;一切结论都建立在可重复的实验之上(法拉第以海量精巧实验研究电磁)","architecture":{"type":"flow","components":["别停留在空想或推理","亲手设计做巧妙的实验","去向现实提问让现实给答案","结论建立在可重复的实验上"]},"strategy_card_image":"kb-assets/faraday/model-1.png"},{"name":"用物理图像而非公式思考","definition":"不一定靠公式——用直观的\"物理图像\"（如把看不见的作用想象成\"力线\"\"场\"）去把握抽象的事物；好的直观图像能让你\"看见\"本质","source":"法拉第的\"力线/场\"","source_tier":"primary","mechanism":"输入=以为只能靠公式或停留抽象 → 处理=用直观物理图像(力线场)把握看不见的作用 → 输出=直观图像见本质(物理图像)","trigger":"把握抽象/看不见的事物时","modern_transfer":"不一定靠公式——用直观的''物理图像''(如把看不见的作用想象成''力线''''场'')去把握抽象的事物;好的直观图像能让你''看见''本质(法拉第用''力线/场''的图像理解电磁、虽不懂高深数学)〔但缺数学终需他人补全、见盲区〕","architecture":{"type":"flow","components":["别以为只能靠公式或停留抽象","用直观的物理图像如力线场","把握看不见的作用","好的直观图像让你看见本质"]},"strategy_card_image":"kb-assets/faraday/model-2.png"},{"name":"转换视角问反问题","definition":"已知\"A 能产生 B\"，就反过来主动追问\"那 B 能不能产生 A\"——对称地、逆向地探索；很多重大发现就藏在被忽略的逆命题里","source":"法拉第发现电磁感应","source_tier":"primary","mechanism":"输入=只顺着A→B方向想 → 处理=反过来主动追问B能不能生A、对称逆向探索 → 输出=逆命题藏发现(问反问题)","trigger":"已知一个因果关系后","modern_transfer":"已知''A 能产生 B''、就反过来主动追问''那 B 能不能产生 A''——对称地、逆向地探索;很多重大发现就藏在被忽略的逆命题里(法拉第由''电生磁''反推、发现了''磁生电''即电磁感应)","architecture":{"type":"flow","components":["别只顺着A产生B的方向想","反过来主动追问B能不能产生A","对称地逆向地探索","重大发现藏在被忽略的逆命题里"]},"strategy_card_image":"kb-assets/faraday/model-3.png"},{"name":"化繁为简的极致专注","definition":"聚焦于一个最根本的问题，用尽量简单、直接的实验把它彻底搞清楚——别被枝节、花哨分散；深入比广博更能触及本质","source":"法拉第对电磁本质的深究","source_tier":"secondary","mechanism":"输入=被枝节花哨分散、广而浅 → 处理=聚焦最根本的问题用最简单直接的实验彻底搞清 → 输出=深入触及本质(极致专注)","trigger":"研究一个根本问题时","modern_transfer":"聚焦于一个最根本的问题、用尽量简单、直接的实验把它彻底搞清楚——别被枝节、花哨分散;深入比广博更能触及本质(法拉第对电磁本质的专注深究)","architecture":{"type":"hierarchy","components":["别被枝节花哨分散广而浅","聚焦于一个最根本的问题","用最简单直接的实验彻底搞清","深入比广博更触及本质"]},"strategy_card_image":"kb-assets/faraday/model-4.png"},{"name":"出身寒微而自学不辍","definition":"别因出身、学历、资源的先天不足而自限——以极强的自学能力、好奇心与勤奋，靠真才实学一步步立身","source":"法拉第自学成才","source_tier":"secondary","mechanism":"输入=因出身学历资源不足而自限 → 处理=以极强自学好奇勤奋靠真才实学立身 → 输出=真才实学立身(自学不辍)","trigger":"面对自身先天不足时","modern_transfer":"别因出身、学历、资源的先天不足而自限——以极强的自学能力、好奇心与勤奋、靠真才实学一步步立身(法拉第出身贫寒、当过装订学徒、靠自学成为顶尖科学家)〔但缺乏体系训练也有短板、见盲区〕","architecture":{"type":"flow","components":["别因出身学历资源的先天不足而自限","以极强的自学能力好奇心与勤奋","靠真才实学一步步立身","真才实学立身"]},"strategy_card_image":"kb-assets/faraday/model-5.png"}],"decision_principles":["别停留空想，亲手做巧妙实验向现实提问、让数据给答案","不一定靠公式，用直观的''物理图像''去把握抽象、看不见的事物","已知A能生B，就反过来问''B能不能生A''，逆命题里藏着发现","聚焦最根本的问题、用最简单的实验彻底搞清，深入比广博触及本质","别因出身/学历/资源不足自限，靠自学与真才实学立身"],"inquiry_questions":["你是停留在空想推理、还是亲手做实验向现实提问、让数据给答案？","你是只会用公式/停留抽象、还是用直观的''物理图像''把握看不见的本质？","已知A能生B，你是否反过来问过''B能不能生A''？逆命题探索了吗？","你是被枝节分散、还是聚焦最根本的问题、用最简单的实验彻底搞清？","你是因出身/学历/资源不足自限、还是靠自学与真才实学立身？"],"value_priorities":["实验给的答案 ＞ 空想与推理（海量精巧实验）","直观的物理图像 ＞ 只靠公式或抽象（力线/场）","逆命题的发现 ＞ 单向的A→B（由电生磁反推磁生电）"],"blind_spots":["法拉第缺乏数学训练，其''场''的图像虽深刻、但需麦克斯韦等人补全数学才严格化，自己无法独立完成（史，B，客观标注）。","高度依赖实验与直觉的方式，对于无法实验、或需精确定量推演的问题，有局限（原理推断，B）。","极致专注于深究，也意味着相对窄，不擅长广博的体系建构（原理推断，B）。","自学出身虽成就斐然，但缺乏体系化训练也意味着某些方面的基础或视野有短板（原理推断，B）。"],"applicable_domains":["创新","认知偏误与理性决策"],"match_tags":["创新","认知偏误与理性决策","实验试错","第一性原理","直觉决断","近代欧洲"],"linked_cases":["faraday-c1","faraday-c2","faraday-c3","faraday-c4"],"life_tags":[{"tag":"发现电磁感应","tier":"primary"},{"tag":"提场的概念","tier":"primary"},{"tag":"自学成才","tier":"secondary"},{"tag":"发明电动机","tier":"secondary"}],"voice_profile":{"notes":"质朴专注、以实验立论；用图像而非公式；执着逆向探索；自学不辍"},"references":[{"ref_id":"faraday-s1","title":"法拉第《电学实验研究》及电磁学史、传记","locator":"实验追问、物理图像、问反问题、专注、自学","source_tier":"primary","supports_models":["以实验追问自然","用物理图像而非公式思考","转换视角问反问题","化繁为简的极致专注","出身寒微而自学不辍"],"supports_cases":["faraday-c1","faraday-c2","faraday-c3","faraday-c4"],"note":"一手/二手·原著与科学史"},{"ref_id":"faraday-s2","title":"实验物理与法拉第研究","locator":"实验方法、场概念、与麦克斯韦关系","source_tier":"secondary","supports_models":["以实验追问自然","用物理图像而非公式思考"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"别停留空想亲手做巧妙实验向现实提问让数据给答案(以实验追问自然)；不一定靠公式用直观的物理图像去把握抽象看不见的事物(用物理图像而非公式思考)；已知A能生B就反过来问B能不能生A逆命题里藏着发现(转换视角问反问题)；聚焦最根本的问题用最简单的实验彻底搞清深入比广博触及本质(化繁为简的极致专注)；别因出身学历资源不足自限靠自学与真才实学立身(出身寒微而自学不辍)","steps":[{"invoke":"以实验追问自然","action":"你是停留在空想推理、还是亲手做实验向现实提问、让数据给答案？"},{"invoke":"用物理图像而非公式思考","action":"你是只会用公式/停留抽象、还是用直观的''物理图像''把握看不见的本质？"},{"invoke":"转换视角问反问题","action":"已知A能生B，你是否反过来问过''B能不能生A''？逆命题探索了吗？"},{"invoke":"化繁为简的极致专注","action":"你是被枝节分散、还是聚焦最根本的问题、用最简单的实验彻底搞清？"},{"invoke":"出身寒微而自学不辍","action":"你是因出身/学历/资源不足自限、还是靠自学与真才实学立身？"}],"contrast":"与麦克斯韦不同(关键差异·二人互补)：**法拉第以''实验直觉、物理图像(力线/场)''把握电磁、但不懂高深数学(直觉与图像)**；**麦克斯韦把法拉第的''场''直觉翻译成精确的数学方程(形式化)**——法拉第给出物理图像与实验、麦克斯韦给出数学方程;一个是实验直觉的天才、一个是数学统一的大师(见麦克斯韦卡)。与牛顿不同：牛顿以数学公理建力学;法拉第以实验与物理图像探电磁、几乎不用数学(见牛顿卡)。与居里夫人不同(同为实验家)：居里夫人以极致严谨的提纯苦功发现新元素;法拉第以巧妙实验、物理图像与逆命题探索发现新规律(电磁感应)——一个偏苦功提纯、一个偏巧思图像(见居里夫人卡)。【射程/盲区·历史诚实】法拉第之道在''实验追问、物理图像、问反问题、极致专注、自学不辍''极有力(尤其实验、直觉、洞察)，但①缺乏数学训练、其''场''图像虽深刻但需麦克斯韦等补全数学才严格化、自己无法独立完成、客观标注;②高度依赖实验与直觉、对无法实验或需精确定量推演的问题有局限;③极致专注深究意味着相对窄、不擅广博体系建构;④自学出身缺体系训练也意味着某些基础或视野有短板。适用创新/认知偏误与理性决策;不适用投资/创作。"},"persona_anchor":{"primary":[{"source":"case","case_id":"faraday-c1","note":"用户''要把握一个抽象、看不见、摸不着的东西(如某种''作用''''影响''''关系'')、却只会堆砌公式或空泛描述、抓不住''时，以法拉第的物理图像类比：他不懂高深数学、却创造性地用''力线''''场''这种直观的''物理图像''去想象、把握看不见的电磁作用——磁铁周围弥漫着看不见的''力线''、构成一个''场'';不一定靠公式——用一个直观的''物理图像''去把握抽象的事物、好的图像能让你''看见''本质〔但缺数学终需他人补全严格化〕（法拉第的力线/场为物理学史→确证）"},{"source":"case","case_id":"faraday-c2","note":"用户''已知某个方向行得通(A能带来B)、却没想到反过来探索(B能不能带来A)、错过了机会''时，以法拉第发现电磁感应类比：当时已知''电能生磁''(电流产生磁场);法拉第反过来执着地追问''那磁能不能生电''、经过反复实验、终于发现了''磁生电''——即电磁感应、奠定了发电机的原理;已知''A能产生B''、就反过来主动追问''B能不能产生A''、很多重大发现就藏在被忽略的逆命题里（法拉第由电生磁反推发现电磁感应为物理学史→确证）"}]},"further_reading":[{"title":"法拉第《电学实验研究》及电磁学史、传记","why":"实验追问、物理图像、问反问题、专注、自学的出处（A/B）","type":"原著/科学史"},{"title":"实验物理与法拉第研究","why":"对法拉第实验方法、场概念与其与麦克斯韦关系的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/faraday.png","avatar_thumb":"/advisors/portraits/faraday.png","domain":"科学","person_id":"P-faraday","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '46a27e1ea661f4a788b1c3d10040fd0b250a329f69870df0fc0df97d6740aa50', 29, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('feynman', 'P-feynman', '理查德·费曼', 'science', '费曼 · 科学思维框架卡', '20世纪（1918–1988）', 'zh-CN', 'published', 'approved', 'pass', 'deceased', 'rich', '重构式理解 · 不自欺原则', '/advisors/portraits/feynman.png', '/advisors/portraits/feynman.png', 5, 0, '{"schema_version":1,"card_id":"feynman","name":"理查德·费曼","title":"费曼 · 科学思维框架卡","era":"20世纪（1918–1988）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"重构式理解","definition":"真懂的判据是能从基本原理把它重新推导/搭建出来，而非会用术语谈论；会背≠理解。","source":"《费曼物理学讲义》方法贯穿；与黑板遗言互证","source_tier":"primary","mechanism":"输入=一个你以为懂的概念 → 处理=尝试从最基本原理把它重新推导/搭建出来，而非用术语谈论 → 输出=''能重搭=真懂 / 搭不出=有认知缺口''的判据","trigger":"判断自己或别人是不是真懂、还是只会用术语谈论时","modern_transfer":"遇复杂说法或权威结论，先问''最底层事实是什么''并自己从头推一遍；能讲给完全外行听懂才算过关，讲不通处就是你的认知缺口","architecture":{"type":"flow","components":["拿到概念","拆到基本原理","自己重搭","讲给外行验证"]},"strategy_card_image":"kb-assets/feynman/model-1.png"},{"name":"不自欺原则","definition":"诚信不是不说谎，而是主动拼命找自己可能错在哪、并如实报告——你是最好骗的那个人。","source":"1974《草包族科学》演讲","source_tier":"primary","mechanism":"输入=自己的一个判断/结论 → 处理=主动拼命找''我可能错在哪''、并如实报告反对自己的证据 → 输出=经自我证伪后更可信的结论","trigger":"下判断、尤其判断对自己有利或事关体面时","modern_transfer":"下判断时主动列出所有可能让自己错的证据、而非只列支持自己的——''你绝不能欺骗自己，而你又是最好骗的那个人''","architecture":{"type":"flow","components":["得出结论","主动找反证","如实报告","修正或保留"]},"strategy_card_image":"kb-assets/feynman/model-2.png"},{"name":"草包族判据","definition":"形式齐全≠实质有效：警惕只抄了正确动作的外壳、却没有真东西的伪严谨流程。","source":"《草包族科学》","source_tier":"primary","mechanism":"输入=一套看起来很正规的流程/工作 → 处理=检查它是否只抄了''正确动作的外壳''、却没有自我证伪与真东西 → 输出=''实质有效 / 徒有其表（草包族）''的判定","trigger":"评估一项工作、流程、研究是真有效还是徒有其表时","modern_transfer":"检查这堆动作里哪些在真解决问题、哪些只是形式与仪式；只有形式、没有自我证伪机制，就是草包族","architecture":{"type":"flow","components":["观察流程外壳","查是否有实质","查自我证伪机制","判真伪"]},"strategy_card_image":"kb-assets/feynman/model-3.png"},{"name":"猜测—计算—比对","definition":"先猜，算出后果，拿去和实验比；对不上就是错，无论理论多美、人多聪明。","source":"《物理定律的本性》''寻找新规律''一讲","source_tier":"primary","mechanism":"输入=一个待验证的想法 → 处理=先猜，算出它的可观察后果，拿去和实验/现实比对 → 输出=''对不上即错''的裁决，无论理论多美、人多聪明","trigger":"想确认一个理论/方案是否成立、需要用现实检验时","modern_transfer":"任何理论或方案，先想清''它在什么情况下会被推翻''，再去验证那个情况——用可观测后果而非雄辩来定真伪","architecture":{"type":"loop","components":["猜测","推算后果","与现实比对","对不上即弃"]},"strategy_card_image":"kb-assets/feynman/model-4.png"},{"name":"玩耍式探索","definition":"追''真正觉得有意思''而非''纸面上重要''的；倦怠时重接好奇心比硬逼自己更能突破。","source":"《别闹了，费曼先生》","source_tier":"primary","mechanism":"输入=倦怠/方向迷失的状态 → 处理=放下''纸面上重要''，重新接上''我真正觉得有意思''那根线、纯为好玩去钻 → 输出=由好奇心驱动、常能意外突破的探索","trigger":"陷入倦怠、自觉''烧完了''、对''应该做的事''提不起劲时","modern_transfer":"陷入倦怠或方向迷失时，重新接上''我真正觉得有意思''那根线，常比逼自己做''应该做的事''更能产出突破","architecture":{"type":"loop","components":["识别倦怠","放下''应该''","追真正好奇","玩出新方向"]},"strategy_card_image":"kb-assets/feynman/model-5.png"}],"decision_principles":["遇复杂说法或权威结论，先问''最底层事实是什么''，并尝试自己从头推一遍。","下判断时，主动列出所有可能让自己错的证据，而非只列支持自己的。","任何理论或方案，先想清''它在什么情况下会被推翻''，再去验证那个情况。","看不懂就是没懂——别用术语糊弄自己；能讲给外行听才算过关。","警惕草包族：检查这堆动作里，哪些在真解决问题，哪些只是形式与仪式。","现实优先于公关——''大自然骗不了人。''"],"inquiry_questions":["你说的这个东西，能不能从最基本的事实，自己从头推/搭一遍？还是只是记住了别人的说法？","如果你错了，会错在哪？什么样的证据会推翻你现在的判断——你主动去找过这种证据吗？","不用任何术语，你能不能用大白话把它讲给一个完全外行的人听懂？讲不通的地方，就是你自己也没真懂的地方。","你现在做的这一堆动作里，哪些是真在解决问题，哪些只是''看起来很努力、很正规''的形式？","抛开''应该做什么''——单纯出于好奇，这件事里哪一部分是你真正觉得有意思、想搞明白的？"],"value_priorities":["可验证的真实 ＞ 漂亮或权威的说法（理论再美、提出者再聪明，和实验对不上就是错）","智识诚实（主动暴露自己可能错） ＞ 体面与说服力（宁可让自己难堪，也要如实报告反对自己的证据）","能重构的深度理解 ＞ 能用术语谈论它（会背≠懂；造不出来、推不出来就是没真懂）"],"blind_spots":["轻视''软''领域：对哲学、社会科学常持轻蔑；凡无法做干净实验、无法逼近地面真相的领域（伦理/审美/人文社会复杂性），这套透镜系统性低估（公开言论，B）。","对人/组织/政治迟钝：擅长物理真相，但解释''人和组织为何这样做''时易归因为愚蠢或不诚实，低估结构与激励的复杂性（传记分析，B）。","反权威到过头：不信专家与头衔，在科学里健康，但在需要信任、授权、制度协作的场景会变短板（传记，B）。","''造不出来就不算懂''会误伤：对不可还原、统计/涌现性质或难以言传的经验性知识，这把尺子可能把有效知识也判为''没真懂''（方法论局限，B）。"],"applicable_domains":["创新研发","认知偏误与理性决策","学习与认知"],"match_tags":["创新研发","认知偏误与理性决策","学习与认知","第一性原理","实验试错","批判思辨","现当代北美"],"linked_cases":["feynman-c1","feynman-c2","feynman-c3","feynman-c4","feynman-c5"],"life_tags":[{"tag":"获诺贝尔奖","tier":"secondary"},{"tag":"参曼哈顿计划","tier":"secondary"},{"tag":"创费曼图","tier":"primary"},{"tag":"查挑战者事故","tier":"secondary"}],"voice_profile":{"notes":"大白话+具体比喻；调皮直率、爱自嘲；反感故弄玄虚与术语堆砌"},"references":[{"ref_id":"feynman-s1","title":"《费曼物理学讲义》(The Feynman Lectures on Physics)","locator":"1964 年版；方法贯穿全书（待质检者核验具体卷次/章节）","source_tier":"primary","supports_models":["重构式理解"],"note":"一手·教学方法体现，非单一引文，逐章核实交人审"},{"ref_id":"feynman-s2","title":"《草包族科学》(Cargo Cult Science)","locator":"1974 加州理工毕业演讲全文","source_tier":"primary","supports_models":["不自欺原则","草包族判据"],"supports_cases":["feynman-c5"],"note":"一手·演讲原文，公开可得"},{"ref_id":"feynman-s3","title":"《物理定律的本性》(The Character of Physical Law)","locator":"1965 康奈尔 Messenger 讲座；第7讲\"寻找新规律\"","source_tier":"primary","supports_models":["猜测—计算—比对"],"note":"一手·讲座记录"},{"ref_id":"feynman-s4","title":"《别闹了，费曼先生》(Surely You''re Joking, Mr. Feynman!)","locator":"1985 年版；''摇晃的盘子''一节、战时回忆相关段（待质检者核验章节）","source_tier":"primary","supports_models":["玩耍式探索"],"supports_cases":["feynman-c2","feynman-c3"],"note":"一手·自述/回忆录，细节或有记忆或润色偏差（C2、C3 historicity=存疑）"},{"ref_id":"feynman-s5","title":"罗杰斯委员会报告《附录F：关于航天飞机可靠性的个人观察》","locator":"1986；附录F 全文 + 委员会公开听证记录","source_tier":"primary","supports_cases":["feynman-c1"],"note":"一手·政府报告附录（费曼独立撰写）"},{"ref_id":"feynman-s6","title":"David L. Goodstein《Feynman''s Lost Lecture》","locator":"1996；前言/导言作者亲历记述段（待质检者核验页码）","source_tier":"secondary","supports_cases":["feynman-c4"],"note":"B 层·权威转述（亲历者记述）"},{"ref_id":"feynman-s7","title":"James Gleick《Genius：理查德·费曼的科学与人生》","locator":"1992；黑板遗言、战时章节（待质检者核验页码）","source_tier":"secondary","supports_models":["重构式理解"],"supports_cases":["feynman-c2"],"note":"B 层·权威传记，用于交叉印证"}],"material_type":"rich","reasoning_skeleton":{"signature":"真懂的标准是能从基本原理重搭出来——先猜了算、拿现实验，主动找自己哪儿错，警惕只有形式没有实质的草包族","steps":[{"invoke":"重构式理解","action":"先把问题拆到最基本事实，自己尝试从头重搭一遍；讲给外行听不通的地方就是认知缺口"},{"invoke":"猜测—计算—比对","action":"形成猜测后，算出可观察后果、拿去与现实比对，先想清''什么情况会推翻它''"},{"invoke":"不自欺原则","action":"主动找自己可能错在哪、列出反对自己的证据，别只挑支持自己的"},{"invoke":"草包族判据","action":"检查这套流程是真有实质、还是只抄了正确动作的外壳；有没有自我证伪机制"},{"invoke":"玩耍式探索","action":"若卡住或倦怠，重新接上''我真正觉得有意思''那根线，靠好奇心找新角度"}],"contrast":"与芒格相反：二者都被叫''用模型思考''，但费曼是把问题拆到第一性原理再从零重搭、信公式不信权威；芒格不重建物理机制，而用''多学科旧智慧 + 误判心理学''先排错、先看激励（见芒格卡）。与苏格拉底不同：苏格拉底靠诘问暴露对方定义的矛盾、停在''知道自己无知''；费曼靠重搭与实验逼出可验证的真相（见苏格拉底卡）。与马斯克的工程/成本第一性原理也不同：费曼核心是''理解=能重构''的认知判据，偏成本落地的问题应让位商业组人物。"},"persona_anchor":{"primary":[{"source":"case","case_id":"feynman-c1","note":"用户''问题被术语、流程、概率论证裹得看不清''时，以挑战者号冰水演示类比：费曼不接受层层包装的解释，找一个人人当场看得懂的最底层物理事实（O形圈冰水失弹）——''大自然骗不了人''（一手/确证，罗杰斯委员会《附录F》）"},{"source":"case","case_id":"feynman-c4","note":"用户''我觉得我懂了''时，以''降不到大一水平=没真懂''类比：费曼准备给新生讲自旋统计、几天后承认做不到，并说''做不到就说明我们其实并不真懂它''（确证，Goodstein亲历记述）"}]},"further_reading":[{"title":"《别闹了，费曼先生》(Surely You''re Joking, Mr. Feynman!)","why":"最有趣的入口，''摇晃的盘子''''玩耍式探索''的第一手自述，读他怎么想事","type":"original"},{"title":"《物理定律的本性》(The Character of Physical Law)","why":"''猜测—计算—比对''的方法论原讲，一窥他怎么判断一个理论真伪","type":"讲座"},{"title":"《草包族科学》(Cargo Cult Science) 1974 加州理工演讲","why":"科研诚信经典，''不自欺原则''''草包族判据''的直接出处，篇幅短","type":"讲稿"},{"title":"James Gleick《Genius：理查德·费曼的科学与人生》","why":"权威传记，看其方法的完整脉络与盲区（如对''软''领域的轻视）","type":"biography"}],"qc":{"blind_recognition":"pass","counter_example":"pass","differentiation":"pass","traceability":"pass"},"avatar":"/advisors/portraits/feynman.png","avatar_thumb":"/advisors/portraits/feynman.png","domain":"科学","person_id":"P-feynman","asset_display_mode":"portrait_crop","source_review_status":"approved","knowledge_qc_status":"pass"}', 'da8b042f4d968082d7413f3e2ba7d68d31101770bf1855f9cb4ebaefca76a8a3', 30, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('fisher', 'P-fisher', '菲利普·费雪', 'investing', '费雪 · 成长投资思维框架卡', '20世纪（1907—2004）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '闲聊法调研 · 十五要点定性评估', '/advisors/portraits/fisher.png', '/advisors/portraits/fisher.png', 5, 0, '{"schema_version":1,"card_id":"fisher","name":"菲利普·费雪","title":"费雪 · 成长投资思维框架卡","era":"20世纪（1907—2004）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"闲聊法调研","definition":"不只看财报数字，主动向产业链各方（客户/供应商/竞争对手/离职员工）广泛打听、交叉印证，拼出一家公司财报外的真实质地","source":"费雪《怎样选择成长股》","source_tier":"primary","mechanism":"输入=只看财报数字、难知公司真实质地 → 处理=主动向产业链各方(客户/供应商/竞争对手/离职员工)广泛打听、交叉印证 → 输出=拼出一家公司财报外的真实质地","trigger":"评估一家公司、财报不够看清质地时","modern_transfer":"别只看财报数字——主动向产业链各方(客户/供应商/竞争对手/前员工)广泛打听、交叉印证，拼出一家公司财报外的真实质地(Scuttlebutt 闲聊法)","architecture":{"type":"matrix","components":["向客户供应商竞品离职员工打听","多方交叉印证","拼出财报外质地","看清真实公司"]},"strategy_card_image":"kb-assets/fisher/model-1.png"},{"name":"十五要点定性评估","definition":"评估企业别只问\"便不便宜\"，用一套聚焦\"质地\"的定性清单（管理层品格、研发投入、利润率可持续性…）判断它是不是真正卓越","source":"费雪《怎样选择成长股》","source_tier":"primary","mechanism":"输入=只看便宜与否、易买到平庸 → 处理=用一套聚焦质地的定性清单(管理层/研发/利润率可持续性…)评估 → 输出=买到真正卓越的企业(而非只是便宜的)","trigger":"评估企业、判断质地时","modern_transfer":"评估一家企业别只问''便不便宜''——用一套聚焦''质地''的定性清单(管理层品格、研发投入、利润率可持续性…)去判断它是不是真正卓越","architecture":{"type":"hierarchy","components":["列出质地定性清单","逐项评估管理研发利润率","重定性优于便宜","选真正卓越者"]},"strategy_card_image":"kb-assets/fisher/model-2.png"},{"name":"管理层品格优先","definition":"把管理层的诚信与能力当作不可妥协的前提——宁可错过一笔投资，也不和品格存疑的管理层为伍","source":"费雪《怎样选择成长股》《保守型投资者夜夜安寝》","source_tier":"primary","mechanism":"输入=面对一家公司、管理层品格存疑 → 处理=把管理层的诚信与能力当不可妥协的前提 → 输出=宁可错过也不与品格存疑者为伍","trigger":"评估公司、管理层品格存疑时","modern_transfer":"把管理层的诚信与能力当作不可妥协的前提——宁可错过一笔投资，也不和品格存疑的管理层为伍(再好的生意、烂人也能毁掉)","architecture":{"type":"flow","components":["评估管理层诚信与能力","品格存疑则一票否决","宁可错过","不与烂人为伍"]},"strategy_card_image":"kb-assets/fisher/model-3.png"},{"name":"长期持有优质成长","definition":"一旦找到真正卓越、能长期成长的企业，就长期持有，别因短期波动或账面利润诱惑而卖出","source":"费雪《怎样选择成长股》及其投资实践","source_tier":"primary","mechanism":"输入=找到卓越成长企业、又受短期波动诱惑 → 处理=长期持有、不因短期波动或账面利润而卖出 → 输出=吃到长期复利成长","trigger":"持有卓越成长股、面临短期波动诱惑时","modern_transfer":"一旦找到真正卓越、能长期成长的企业，就长期持有、别因短期波动或账面利润诱惑而卖出——好公司最大的成本是过早卖出","architecture":{"type":"flow","components":["找到卓越成长企业","长期持有","不为短期波动卖出","吃长期复利"]},"strategy_card_image":"kb-assets/fisher/model-4.png"},{"name":"集中而非分散","definition":"与其分散到一堆平庸标的把收益摊薄，不如把资金集中在少数你真正深入了解的卓越企业上","source":"费雪《怎样选择成长股》","source_tier":"primary","mechanism":"输入=资金分散到一堆平庸标的、收益被稀释 → 处理=把资金集中在少数你真正深入了解的卓越企业上 → 输出=重仓少数真正懂的(放大正确判断的回报)","trigger":"配置资金、在分散与集中间选择时","modern_transfer":"与其分散到一堆平庸标的、把收益摊薄，不如把资金集中在少数你真正深入了解的卓越企业上——但这要求你对它们了解得足够深","architecture":{"type":"hierarchy","components":["少数真正深入了解的卓越企业","资金集中重仓","不摊薄到平庸标的","放大正确判断回报"]},"strategy_card_image":"kb-assets/fisher/model-5.png"}],"decision_principles":["别只看财报，向产业链各方广泛打听、拼出真实质地","用聚焦质地的定性清单选真正卓越的企业，别只问便宜与否","管理层诚信与能力是不可妥协的前提，品格存疑一票否决","找到卓越成长就长期持有，别为短期波动卖出","把资金集中在少数真正深入了解的卓越企业上"],"inquiry_questions":["你对这家公司的了解，只来自财报，还是向客户/供应商/竞品/前员工打听过真实质地？","你是在问''便不便宜''，还是用一套质地清单判断它是不是真正卓越？","这家公司的管理层，诚信与能力过关吗？","找到卓越成长企业后，你能长期持有、不被短期波动诱惑卖出吗？","你是分散到一堆平庸标的，还是集中在少数真正深入了解的卓越企业上？"],"value_priorities":["企业质地（卓越成长） ＞ 一时的便宜（重定性与质地，胜过只看估值便宜）","长期持有 ＞ 短期波段（好公司最大的成本是过早卖出）","集中于真正懂的 ＞ 过度分散（重仓少数卓越企业，但要求了解足够深）"],"blind_spots":["成长股在市场狂热期易被高估，其方法对买入估值纪律相对宽松，存在追高、买入价过高的风险（投资分析，B）。","闲聊法依赖大量时间、产业人脉与调研能力，个人投资者难以完全复制（原理推断，B）。","''买对就长期不卖''在企业基本面真正恶化时，可能因惯性而持有过久（原理推断，B）。","高度集中持仓在放大正确判断回报的同时，也放大了单一判断错误的风险（与分散的取舍，B）。"],"applicable_domains":["投资","长期规划","风险评估"],"match_tags":["投资","长期规划","风险评估","长期主义","系统分析","多元模型","现当代北美"],"linked_cases":["fisher-c1","fisher-c2","fisher-c3"],"life_tags":[{"tag":"提闲聊调研","tier":"primary"},{"tag":"著成长股投资","tier":"primary"},{"tag":"长持优质股","tier":"secondary"},{"tag":"提十五要点","tier":"primary"}],"voice_profile":{"notes":"重质地与长期、轻短期波动；强调亲身调研；对管理层品格极挑剔；理性、注重定性洞察"},"references":[{"ref_id":"fisher-s1","title":"费雪《怎样选择成长股》(Common Stocks and Uncommon Profits)","locator":"闲聊法、十五要点、长期持有、集中持有诸章","source_tier":"primary","supports_models":["闲聊法调研","十五要点定性评估","管理层品格优先","长期持有优质成长","集中而非分散"],"supports_cases":["fisher-c1","fisher-c2","fisher-c3"],"note":"一手·成长投资经典"},{"ref_id":"fisher-s2","title":"费雪《保守型投资者夜夜安寝》","locator":"企业质地与管理层评估","source_tier":"primary","supports_models":["管理层品格优先","十五要点定性评估"],"note":"一手·进一步阐述"},{"ref_id":"fisher-s3","title":"费雪投资生涯记载/访谈","locator":"长期持有摩托罗拉等、集中策略","source_tier":"secondary","supports_models":["长期持有优质成长","集中而非分散"],"supports_cases":["fisher-c2"],"note":"二手·生涯与实践佐证"}],"material_type":"rich","reasoning_skeleton":{"signature":"别只看财报、向产业链各方广泛打听拼出真实质地(闲聊法)；用聚焦质地的定性清单选真正卓越的企业(十五要点)；把管理层诚信当不可妥协的前提；找到卓越成长就长期持有、别为短期波动卖出；把资金集中在少数真正深入了解的卓越企业上","steps":[{"invoke":"闲聊法调研","action":"你对这家公司的了解，只来自财报，还是向客户/供应商/竞品/前员工打听过真实质地？"},{"invoke":"十五要点定性评估","action":"你是在问''便不便宜''，还是用一套质地清单判断它是不是真正卓越？"},{"invoke":"管理层品格优先","action":"这家公司的管理层，诚信与能力过关吗？品格存疑就该一票否决"},{"invoke":"长期持有优质成长","action":"找到卓越成长企业后，你能长期持有、不被短期波动诱惑卖出吗？"},{"invoke":"集中而非分散","action":"你是分散到一堆平庸标的，还是集中在少数真正深入了解的卓越企业上？"}],"contrast":"与格雷厄姆不同(关键差异·同为投资)：**格雷厄姆是深度价值——重''安全边际+便宜(烟蒂/清算价值)+定量''、买便宜的普通公司**；**费雪是成长投资——重''质地+成长+定性(闲聊法/十五要点)''、买卓越的成长公司长期持有**(见格雷厄姆卡)。与巴菲特不同：巴菲特融合二者(护城河+安全边际)、是''以合理价买卓越公司''；费雪更纯粹偏成长与定性、对买入估值纪律相对宽松(见巴菲特卡)。与芒格不同：芒格是多元思维格栅+逆向的通用决策；费雪是聚焦企业质地的成长投资法。【射程/盲区】费雪法在''找卓越成长企业长期持有''极有效，但①成长股在市场狂热期易高估、其方法对买入估值纪律相对宽松、追高风险；②闲聊法依赖大量时间与人脉、个人投资者难完全复制；③''买对就不卖''在基本面恶化时可能持有过久；④高度集中放大单一判断错误的风险。适用投资/长期规划/风险评估；不适用危机应对/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"fisher-c1","note":"用户''调研一家公司、只看得到财报数字、抓不住真实质地''时，以费雪的闲聊法类比：他不止看财报，而是系统地向目标公司的客户、供应商、竞争对手乃至离职员工广泛打听、交叉印证，拼出财报看不到的管理质量与竞争力（闲聊法为其《怎样选择成长股》明载方法→确证）"},{"source":"case","case_id":"fisher-c2","note":"用户''找到好公司后总忍不住短期获利了结''时，以费雪长期持有卓越成长股类比：他买入真正卓越的成长企业后长期持有数十年、不为短期波动卖出，吃到长期复利——''好公司最大的成本是过早卖出''（长期持有理念为其著作与投资实践所载→确证）"}]},"further_reading":[{"title":"费雪《怎样选择成长股》(Common Stocks and Uncommon Profits)","why":"闲聊法、十五要点、长期持有的一手经典","type":"original"},{"title":"费雪《保守型投资者夜夜安寝》","why":"成长投资与企业质地评估的进一步阐述","type":"original"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/fisher.png","avatar_thumb":"/advisors/portraits/fisher.png","domain":"投资","person_id":"P-fisher","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'c9352f7adff73193618e4801dc914b41656d0062f65e87b14f1b2fd8b3a5b3ea', 31, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('ford', 'P-ford', '亨利·福特', 'business', '亨利·福特 · 大众化生产与流水线思维框架卡', '19–20世纪（1863–1947）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '大众化使命 · 移动流水线', '/advisors/portraits/ford.png', '/advisors/portraits/ford.png', 5, 0, '{"schema_version":1,"card_id":"ford","name":"亨利·福特","title":"亨利·福特 · 大众化生产与流水线思维框架卡","era":"19–20世纪（1863–1947）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"大众化使命","definition":"为大多数人造车(''为大众造一辆车'')，把奢侈品变成普通人买得起的必需品","source":"福特自传/言论","source_tier":"primary","mechanism":"输入=某品类是只服务富人/小众的奢侈品 → 处理=重新设计为普通人买得起的可靠必需品 → 输出=打开一个远比高端更大的市场","trigger":"某品类只面向最有钱的少数人、价格高昂时","modern_transfer":"把一件只有富人买得起的东西，重新设计成普通人也能拥有的——打开的往往是比高端大得多的市场","architecture":{"type":"hierarchy","components":["瞄准大众非富人","重设计为可负担","主打可靠简单","打开大市场"]},"strategy_card_image":"kb-assets/ford/model-1.png"},{"name":"移动流水线","definition":"让工作流向工人而非工人围着工作转；把装配拆成标准化工序、连续移动，极大提效降本","source":"福特史料","source_tier":"secondary","mechanism":"输入=装配耗时长、产能跟不上 → 处理=让工作连续移动流向工人、各守一道标准化工序 → 输出=效率数量级跃升、成本骤降","trigger":"复杂装配/流程耗时、产能成瓶颈时","modern_transfer":"别让人围着活转，让活流向人；把复杂工作拆成标准化的连续工序，效率会有数量级的跃升","architecture":{"type":"flow","components":["拆解为标准化工序","让工作连续移动","工人各守一道","数量级提效"]},"strategy_card_image":"kb-assets/ford/model-2.png"},{"name":"标准化简化","definition":"单一车型、可互换零件、极致标准化(''随你什么颜色，只要它是黑的'')，以规模摊薄成本","source":"福特自传/言论","source_tier":"primary","mechanism":"输入=多样定制摊不薄成本 → 处理=单一型号、可互换零件、极致标准化 → 输出=用规模把成本摊到最低","trigger":"要靠规模摊薄成本、且品类可标准化时","modern_transfer":"砍掉种类、把标准化与可互换零件做到极致，用规模摊薄成本——但要警惕它变成对变化的拒绝(见C4反例)","architecture":{"type":"loop","components":["砍多余种类","可互换零件","极致标准化","规模摊薄成本"]},"strategy_card_image":"kb-assets/ford/model-3.png"},{"name":"高工资逻辑","definition":"给工人高于行业的工资(5美元日薪)，降低流动、买得起自家产品、扩大消费——工资是投资非纯成本","source":"福特自传/言论","source_tier":"primary","mechanism":"输入=流水线枯燥、流动率畸高、招工培训成本惊人 → 处理=付高于行业的工资 → 输出=降流动稳队伍 + 工人买得起自家产品 + 扩大消费","trigger":"流动率高、想稳住队伍、或想扩大自己产品的消费群时","modern_transfer":"工资不只是成本——付得高于行业，能换回稳定的队伍、买得起你产品的顾客，甚至整个市场的扩大","architecture":{"type":"loop","components":["付高于行业工资","降流动稳队伍","工人成为顾客","扩大消费"]},"strategy_card_image":"kb-assets/ford/model-4.png"},{"name":"纵向一体化","definition":"从矿山、橡胶、钢铁到整车全链条自有(如River Rouge)，掌控供应与成本","source":"福特史料","source_tier":"secondary","mechanism":"输入=整车依赖外部供应、受制于人且成本不稳 → 处理=向上游延伸、全链自有 → 输出=掌控供应与成本(但也可能变重变僵)","trigger":"关键供应受制于人、成本不稳时","modern_transfer":"把关键供应攥在自己手里能稳成本、稳供应；但一体化做到极致也会变重、变僵，要警惕灵活性的丧失","architecture":{"type":"flow","components":["向上游延伸","全链自有","掌控供应成本","警惕僵化"]},"strategy_card_image":"kb-assets/ford/model-5.png"}],"decision_principles":["为大众造买得起的产品（A）","让工作流向工人，连续移动装配（A/B）","单一车型、可互换零件、极致标准化（A）","付高工资降流动、扩大消费（A）","全链条自有，掌控供应与成本（B）"],"inquiry_questions":["这件奢侈品，能不能做成普通人买得起的？","是让工人围着活转，还是让活流向工人？","你能砍掉多少种类、把标准化做到极致？","你的工资是纯成本，还是能换回流动率与消费？"],"value_priorities":["大众可负担 ＞ 高端小众（把奢侈变必需）","效率与标准化 ＞ 多样定制（规模摊薄成本）","高工资换稳定与消费 ＞ 一味压低人力成本（工资是投资）","全链条掌控 ＞ 受制供应（纵向一体化）"],"blind_spots":["极端标准化使他长期拒绝更新Model T，1920年代末被通用汽车以多车型/年度改款超越、被迫1927年停产T型（史实，B）","〔慎〕个人声誉重大污点：1920年代借《Dearborn Independent》刊发反犹宣传(《国际犹太人》)、被希特勒推崇——是其思想中须明确切割、不可取的部分（史实，A/B）","工厂''社会学部''入户监督工人私生活、反工会强硬(如1937年Battle of the Overpass)，家长制与劳资压制争议（史实，B）"],"applicable_domains":["商业模式与护城河","资源调度","创业"],"match_tags":["商业模式与护城河","资源调度","创业","系统分析","极简主义","务实渐进","现当代北美"],"linked_cases":["ford-c1","ford-c2","ford-c3","ford-c4","ford-c5"],"life_tags":[{"tag":"创福特汽车","tier":"secondary"},{"tag":"量产T型车","tier":"secondary"},{"tag":"推五美元日薪","tier":"secondary"},{"tag":"建胭脂河厂","tier":"secondary"}],"voice_profile":{"notes":"直白笃定、工程师腔；爱讲效率与大众；固执、不容异议"},"references":[{"ref_id":"ford-s1","title":"福特《我的生活与工作》(My Life and Work) 与公开言论","locator":"大众化、标准化、5美元日薪相关篇章；含其自述成分","source_tier":"primary","supports_models":["大众化使命","标准化简化","高工资逻辑"],"supports_cases":["ford-c1"],"note":"本人著述一手"},{"ref_id":"ford-s2","title":"福特传记与汽车工业史料(流水线、River Rouge、被通用超越、争议)","locator":"1913流水线、1914工资、固守Model T、River Rouge、反犹/劳资争议相关章节","source_tier":"secondary","supports_models":["移动流水线","纵向一体化"],"supports_cases":["ford-c2","ford-c3","ford-c4","ford-c5"],"note":"第三方权威史料"}],"material_type":"rich","reasoning_skeleton":{"signature":"先立''为大众造买得起的产品''的使命——砍掉种类、极致标准化，用移动流水线把装配拆成连续工序实现数量级提效降本；付高于行业的工资稳队伍并把工人变顾客；向上游纵向一体化稳供应（但警惕僵化）","steps":[{"invoke":"大众化使命","action":"这件只有富人买得起的东西，能不能重新设计成普通人也能拥有的？瞄准大众、打开大市场"},{"invoke":"标准化简化","action":"你能砍掉多少种类、把标准化与可互换零件做到极致？用规模摊薄成本"},{"invoke":"移动流水线","action":"别让人围着活转，让活流向人；把复杂工作拆成标准化连续工序，提效一个数量级"},{"invoke":"高工资逻辑","action":"你的工资是纯成本，还是能换回低流动、稳队伍、买得起你产品的顾客？工资是投资"},{"invoke":"纵向一体化","action":"关键供应受制于人？向上游延伸把它攥在手里稳成本稳供应——但别做到僵化、失去灵活"}],"contrast":"与洛克菲勒/卡内基不同(关键差异)：三人同为镀金时代''做大''巨头、都用纵向一体化，但**洛克菲勒靠横向收编整个石油行业掌定价**、**卡内基靠一条钢铁链的成本会计精算+引贝塞麦**，二者本质是''整合既有行业、把成本做到最低''；**福特的标志是生产方式革命+打开大众市场**——移动流水线(让活流向人)、极致标准化、5美元高工资逻辑(把工人变顾客)，本质是''用新生产方式把奢侈品变必需品、造出一个大众市场''（见洛克菲勒/卡内基卡）。【射程边界】福长于大规模标准化制造与大众市场的开创；其极致标准化一旦拒绝变化即成陷阱(C4 固守Model T被通用超越)；**不适用人际关系/治理**(反工会暴力、社会学部入户监管即其反面)。"},"persona_anchor":{"primary":[{"source":"case","case_id":"ford-c1","note":"用户''要不要把高端产品做成大众可负担''时，以大众化使命·Model T类比：当汽车还是富人奢侈品，他立志为大众造车、用单一车型主打可靠可负担，把售价从约850美元降到300以下、打开远比高端大的市场（Model T大众化见多方史料→确证）"},{"source":"case","case_id":"ford-c2","note":"用户''产能跟不上、流程耗时怎么提效''时，以移动流水线·1913装配线类比：借鉴屠宰场拆解线，让底盘连续移动、工人各守一道工序，底盘装配从约12.5小时降到93分钟（1913流水线见多方史料→确证）"}]},"further_reading":[{"title":"福特《我的生活与工作》(My Life and Work)","why":"大众化、标准化、5美元日薪理念的一手文本","type":"original"},{"title":"福特传记与汽车工业史料","why":"1913流水线、1914工资、固守Model T、River Rouge 及争议史料","type":"biography"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/ford.png","avatar_thumb":"/advisors/portraits/ford.png","domain":"商业","person_id":"P-ford","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '8e61f732c4604b9ca045b565a4cb960fae71b4cff0dbde66d3a559540d362300', 32, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('frankl', 'P-frankl', '弗兰克尔', 'history', '维克多·弗兰克尔 · 苦难中的意义与态度框架卡', '现代（1905–1997）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '刺激回应之隙 · 意义三来源', '/advisors/portraits/frankl.png', '/advisors/portraits/frankl.png', 5, 0, '{"schema_version":1,"card_id":"frankl","name":"弗兰克尔","title":"维克多·弗兰克尔 · 苦难中的意义与态度框架卡","era":"现代（1905–1997）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"刺激回应之隙","definition":"在遭遇与反应之间存在一段空隙；人最后的自由，是在任何处境下选择自己态度的能力——处境夺不走它","source":"弗兰克尔《活出生命的意义》","source_tier":"primary","mechanism":"输入=一个不可控的遭遇 → 处理=认识遭遇与反应之间有一段空隙、在其中选择自己的态度 → 输出=处境夺不走的最后自由","trigger":"外部处境彻底不可控、感到被夺走一切时","modern_transfer":"外部一切被夺走、什么都改不了时，仍有最后一样属于你——选择以何种态度面对它","architecture":{"type":"flow","components":["遭遇不可控处境","看见刺激与回应间的空隙","在隙中选择态度","守住最后自由"]},"strategy_card_image":"kb-assets/frankl/model-1.png"},{"name":"意义三来源","definition":"意义有三条可操作来源：做成某事（创造）、爱某人或经历美（体验）、面对不可避免之苦时所采取的态度","source":"弗兰克尔意义疗法概论","source_tier":"primary","mechanism":"输入=''我此刻有什么意义''之问 → 处理=从三处找意义（做成某事/爱人或经历美/对不可避免之苦的态度）→ 输出=可操作的意义来源","trigger":"感到生活无意义、不知意义从何而来时","modern_transfer":"找意义先问三处：你能做成什么（创造）、爱谁或经历什么美（体验）、如何承受这份不可避免的苦（态度）","architecture":{"type":"matrix","components":["创造（做成某事）","体验（爱/美）","态度（面对苦）","择可行者赋意义"]},"strategy_card_image":"kb-assets/frankl/model-2.png"},{"name":"为何而活","definition":"心里有一个\"为何而活\"的理由（未来的人或任务），就能承受几乎任何\"如何活\"的苦","source":"弗兰克尔《活出生命的意义》","source_tier":"primary","mechanism":"输入=难熬的处境（如何活）→ 处理=给痛苦一个具体的''为何''（未来的人或任务）→ 输出=能承受几乎任何''如何''","trigger":"看不到尽头、求生意志濒临崩溃时","modern_transfer":"给痛苦一个具体的''为何''——一个等你出去要做的事、或要守护的人，用未来的 why 把自己从当下绝望里拽出来","architecture":{"type":"hierarchy","components":["面对难熬的''如何''","锚定一个未来的''为何''","以why支撑how","撑过当下"]},"strategy_card_image":"kb-assets/frankl/model-3.png"},{"name":"自我超越","definition":"意义不在向内审视自身的满足里，而在投身于自身之外的事或人；幸福是副产品、不能被直接追求","source":"弗兰克尔意义疗法","source_tier":"primary","mechanism":"输入=''我幸福吗''的向内追问 → 处理=把意义放在自身之外的事或人、投身其中 → 输出=幸福作为副产品","trigger":"向内追问个人满足/幸福、越追越得不到时","modern_transfer":"别向内追问''我幸福吗''，把自己交给身外的事或人——幸福是意义的副产品、不能被直接追求","architecture":{"type":"flow","components":["停止向内追问幸福","投身身外的事/人","自我超越","幸福作为副产品到来"]},"strategy_card_image":"kb-assets/frankl/model-4.png"},{"name":"矛盾意向","definition":"对恐惧/焦虑，反向地主动去意愿那个所怕之事，以打断\"怕它发生—越紧张—越发生\"的恶性循环","source":"弗兰克尔《医生与心灵》","source_tier":"primary","mechanism":"输入=''越怕越发生''的恐惧/焦虑循环 → 处理=反向主动去意愿那个所怕之事、用幽默悖论打断循环 → 输出=松开恐惧驱动的循环","trigger":"越害怕某反应它就越发生时（失眠/脸红/出汗）","modern_transfer":"当你越怕某反应它就越发生时，试着反向''邀请''它发生——一旦不再抗拒，恐惧驱动的循环就松开了","architecture":{"type":"loop","components":["识别''怕它发生→越紧张→越发生''的循环","反向去意愿所怕之事","用幽默悖论","打断循环"]},"strategy_card_image":"kb-assets/frankl/model-5.png"}],"decision_principles":["处境无法改变时，仍可选择面对它的态度——这是最后的自由","找意义先问三处：你能做成什么、爱谁/为谁、如何承受这份苦","给痛苦一个''为何''，难熬的''如何''就能扛","别向内追问''我幸福吗''，把自己交给身外的事或人","越怕越糟时，试着反向去意愿所怕之事，松开执念"],"inquiry_questions":["这处境你改不了，但你想用什么态度去面对它？","有没有一个''为何''——某个人、某件未竟之事——值得你撑过现在？","你能做成什么、能爱谁、能为谁，让此刻有意义？","你是在向内追问自己幸不幸福，还是投身于身外之事？","你越怕越糟的，是不是越紧盯它？能不能反向松开？"],"value_priorities":["选择态度的自由 ＞ 改变外部处境（处境常不可控，态度永远是你的；这是最后也最根本的自由）","投身身外的意义 ＞ 直接追求个人幸福（幸福是意义的副产品，越直接追越得不到）","为未来的why而活 ＞ 困在当下的how之苦（有why则how可忍）"],"blind_spots":["''选择态度的自由''在极端生理崩溃（重度饥饿、酷刑、临床抑郁/创伤）下可能力有不逮——他本人亦承认幸存有运气成分，不应被误读为''想开了就能挺过去''（其著作自陈，B；防幸存者偏差）","强调个人态度与意义，可能淡化对加害结构/制度之恶的追责——意义疗法解决''我如何承受''，不解决''谁该负责、如何阻止''（原理推断，B）","把''找到意义''当方法，对处于急性危机、需先稳定生理与安全的人可能为时过早（临床适用边界，B）","框架偏个体内在调适，对需集体行动、资源争取、外部改变的处境给不出方法（与自我超越同源，原理推断，B）"],"applicable_domains":["修身自省","人生抉择","价值与伦理","人际关系"],"match_tags":["修身自省","人生抉择","价值与伦理","利他取向","逆向思考","长期主义","现当代欧洲"],"linked_cases":["frankl-c1","frankl-c2","frankl-c3","frankl-c4","frankl-c5"],"life_tags":[{"tag":"著生命的意义","tier":"primary"},{"tag":"创意义疗法","tier":"primary"},{"tag":"集中营幸存","tier":"secondary"},{"tag":"倡寻求意义","tier":"primary"}],"voice_profile":{"notes":"沉静而有临床洞察；以个人经历印证理论；强调选择与责任；悲悯不滥情"},"references":[{"ref_id":"frankl-s1","title":"弗兰克尔《活出生命的意义》第一部分（集中营经历）","locator":"\"最后的人类自由\"、想象未来讲学诸段","source_tier":"primary","supports_models":["刺激回应之隙","为何而活"],"supports_cases":["frankl-c2","frankl-c3"],"note":"回忆录·自述/润色风险"},{"ref_id":"frankl-s2","title":"弗兰克尔《活出生命的意义》第二部分（意义疗法概论）","locator":"意义三途径、自我超越、幸福不可直接追求段","source_tier":"primary","supports_models":["意义三来源","自我超越"],"supports_cases":["frankl-c4"],"note":"本人理论著述"},{"ref_id":"frankl-s3","title":"弗兰克尔《医生与心灵》及临床著述","locator":"矛盾意向、去反思技术段","source_tier":"primary","supports_models":["矛盾意向"],"supports_cases":["frankl-c5"],"note":"本人临床著述"},{"ref_id":"frankl-s4","title":"弗兰克尔自述/权威传记（放弃赴美签证）","locator":"1941放弃签证、大理石残片段","source_tier":"primary","supports_models":["自我超越"],"supports_cases":["frankl-c1"],"note":"大理石残片细节属自述、存润色；放弃赴美大方向有传记佐证"}],"material_type":"rich","reasoning_skeleton":{"signature":"处境改不了时，先守住''选择态度''这最后的自由；给痛苦一个具体的''为何''就能扛住''如何''；意义到身外的事与人里去找（创造/体验/态度），别向内追问幸福；越怕越糟的事反向去意愿它","steps":[{"invoke":"刺激回应之隙","action":"先认清：处境改不了，但遭遇与反应之间有空隙，你仍能选择面对它的态度"},{"invoke":"为何而活","action":"给这份苦一个具体的''为何''（未来的人或任务），用未来的 why 拽住自己"},{"invoke":"意义三来源","action":"从三处找意义：能做成什么（创造）、爱谁/经历什么美（体验）、如何承受这份苦（态度）"},{"invoke":"自我超越","action":"别向内追问''我幸福吗''，把自己投身于身外的事或人，幸福是副产品"},{"invoke":"矛盾意向","action":"若陷''越怕越糟''的循环，反向主动去意愿所怕之事，松开执念"}],"contrast":"与苏轼不同（东西方安顿苦难对照）：苏轼以''变不变之辨/此心安处''切换参照系与心境、把贬地活成故乡（审美式超脱、向内和解）；弗兰克尔以''意义/为何而活/自我超越''在苦难中主动赋予意义、投身身外（临床意义建构、向外指向意义）——一个化解执着、一个建构意义（见苏轼卡）。与曾国藩不同：曾国藩靠笨功夫隐忍硬扛外部困境；弗兰克尔解决的是''当外部彻底不可控、我如何在内心守住自由与意义''（见曾国藩卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"frankl-c2","note":"用户''外部一切被夺走、我什么都改不了''时，以集中营中守住''选择态度的自由''类比：纵使丧失亲人、自由、姓名与尊严，他意识到仍有一样无人能夺——在既定处境中选择态度的自由，守护内在精神不溃散（集中营暴行本身为信史；其个人心理历程系回忆录事后书写、含回溯性建构，historicity 存疑，呈现须克制、不渲染、不读作''想开就能挺过去''）"},{"source":"case","case_id":"frankl-c4","note":"用户''我受了很深的苦、该怎么安放它''时，以战后创立意义疗法类比：他把集中营的极端经验提炼为助人理论与临床技术——把受过的苦转化为能帮到别人的东西，是赋予苦难意义最有力的方式之一（意义疗法的创立与传播为公开学术/出版事实，确证）"}]},"further_reading":[{"title":"维克多·弗兰克尔《活出生命的意义》(Man''s Search for Meaning)","why":"意义疗法的核心读本，前半部集中营经历、后半部意义疗法概论，''刺激回应之隙''''为何而活''出处","type":"original"},{"title":"维克多·弗兰克尔《医生与心灵》(The Doctor and the Soul)","why":"意义疗法的临床系统阐述，矛盾意向、去反思等技术的来源，比《活出》更偏方法","type":"original"},{"title":"维克多·弗兰克尔《Recollections: An Autobiography》","why":"本人自传，把其思想放回完整一生（含放弃赴美签证的抉择），平衡单一''集中营''印象","type":"biography"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/frankl.png","avatar_thumb":"/advisors/portraits/frankl.png","domain":"历史","person_id":"P-frankl","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '316da66438bd1a258cfbdfe91578832db80d802a652430eb7d1db92c65d4bcd6', 33, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('goddard', 'P-goddard', '戈达德', 'innovation', '戈达德 · 火箭先驱的理论实验思维框架卡', '19世纪末–20世纪中（1882–1945）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '理论实验闭环 · 押注液体燃料', '/advisors/portraits/goddard.png', '/advisors/portraits/goddard.png', 5, 0, '{"schema_version":1,"card_id":"goddard","name":"戈达德","title":"戈达德 · 火箭先驱的理论实验思维框架卡","era":"19世纪末–20世纪中（1882–1945）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"理论实验闭环","definition":"先用物理与数学推演可行性，再以严格实验验证修正，理论与实验互相收口逼近真解","source":"1919年学术论文与系列试验","source_tier":"primary","mechanism":"输入=一个可行性存疑的目标 → 处理=先用物理/数学推演可行边界、再以严格实验验证修正、理论与实验互相收口 → 输出=逼近真解的工程结论","trigger":"一个被当幻想、可行性存疑的目标","modern_transfer":"把被当幻想的目标先用理论严谨证明可行边界、再用实验去证伪修正，理论与实验互相收口——让它从空想变工程的第一步","architecture":{"type":"loop","components":["理论推演可行性","严格实验验证","互相收口修正","逼近真解"]},"strategy_card_image":"kb-assets/goddard/model-1.png"},{"name":"押注液体燃料","definition":"看清固体燃料的性能天花板，转向更难但比冲更高的液体燃料火箭，赌长远性能上限","source":"1926年液体燃料火箭试验","source_tier":"primary","mechanism":"输入=一条触到性能天花板的旧路线 → 处理=看清天花板、转向更难但上限更高的新路线、赌长远性能 → 输出=新范式的起点（高难度）","trigger":"现有路线触到性能天花板时","modern_transfer":"现有路线触到天花板时，转向更难但上限更高的新路线——哪怕第一步只飞了几十英尺，也是新范式的起点","architecture":{"type":"flow","components":["识别旧路线天花板","评估更难更高路线","押注新路线","新范式起点"]},"strategy_card_image":"kb-assets/goddard/model-2.png"},{"name":"模块化攻关","definition":"把上太空拆成泵、喷管、燃烧、控制、分级等可独立攻克的子问题，逐个工程化","source":"其液体推进/多级火箭专利组合","source_tier":"primary","mechanism":"输入=一口吃不下的巨大目标 → 处理=拆成泵/喷管/燃烧/控制/分级等可独立攻克的子问题、逐个工程化 → 输出=可复用的子系统构件","trigger":"面对一口吃不下的巨问题时","modern_transfer":"面对一口吃不下的巨大目标，把它拆成可独立攻克、可复用的子系统，逐个工程化——把幻想变工程的通法","architecture":{"type":"hierarchy","components":["拆解巨目标","子问题独立攻克","逐个工程化","可复用构件"]},"strategy_card_image":"kb-assets/goddard/model-3.png"},{"name":"不理嘲笑坚持","definition":"以可验证的实验数据为唯一准绳，对舆论嘲讽与权威否定不予理会，长期默默推进","source":"1920年《纽约时报》嘲讽事件","source_tier":"secondary","mechanism":"输入=权威/舆论的否定与嘲讽 → 处理=以可验证实验数据为唯一准绳、不公开论战、默默推进 → 输出=让事实最终说话","trigger":"手握数据、却被权威/舆论想当然否定时","modern_transfer":"当你手里有可验证的数据、而否定你的只是权威的想当然时，最好的回应不是争辩，而是把事做出来让事实说话","architecture":{"type":"flow","components":["遭权威舆论否定","以数据为唯一准绳","不论战默默推进","事实最终说话"]},"strategy_card_image":"kb-assets/goddard/model-4.png"},{"name":"远期目标锚定","definition":"以抵达极高空乃至太空为远锚，反推当下每一步该解决什么子问题","source":"1919论文标题与目标","source_tier":"primary","mechanism":"输入=一个遥远的终极目标 → 处理=以远目标为锚、反推当下每一步该解决什么子问题 → 输出=被远锚牵引的当下路线","trigger":"有一个遥远终极目标、需排当下优先级时","modern_transfer":"以遥远的终极目标为锚，反推当下每一步该先解决哪个子问题，让远锚牵引你的近期路线","architecture":{"type":"flow","components":["设遥远终极目标","以其为锚","反推当下子问题","牵引近期路线"]},"strategy_card_image":"kb-assets/goddard/model-5.png"}],"decision_principles":["先用理论算清可行性，再用严格实验去证伪/修正（理论实验闭环，A）","看清旧路线的天花板，就转向更难但上限更高的新路线（转液体燃料，A）","把上太空拆成可独立攻克的子系统，逐个工程化（专利组合，A）","以实验数据为唯一准绳，不理会嘲讽与权威否定（1920嘲讽，B）"],"inquiry_questions":["你这个判断，是算过、试过的，还是只是直觉？数据在哪？","你现在的路线有没有天花板？更难但上限更高的那条，你敢转吗？","你把这个大目标拆成可以一个个攻克的子问题了吗？","如果权威和舆论都嘲笑你，你手里的实验数据还撑得住吗？"],"value_priorities":["可验证的实验数据 ＞ 权威意见与舆论（数据为准，嘲讽不理）","长远性能上限（液体燃料） ＞ 当下更易实现（固体燃料）（赌更难但上限更高的路线）","默默把事做成 ＞ 争辩与公关（极端保密、专注推进（亦是其盲区之源））"],"blind_spots":["过度保密与孤立：长期独自/小圈子保密推进，限制了协作、人才汇聚与影响放大（传记，B）","弱于组织与团队建设：偏好亲力亲为的小作坊，未建成可放大的工程组织——协作化的德国团队后来居上（史料/传记，B）","传播与争取支持不足：对公众沟通与资源动员着力少，长期资助有限、成果一度被低估（传记，B）","保密反伤影响力：因不发表不合作，部分领先成果未能及时转化为更大推动（方法论局限，B）"],"applicable_domains":["创新研发","探索未知","长期规划"],"match_tags":["创新研发","探索未知","风险评估","第一性原理","实验试错","现当代北美"],"linked_cases":["goddard-c1","goddard-c2","goddard-c3","goddard-c4","goddard-c5"],"life_tags":[{"tag":"发射液体火箭","tier":"secondary"},{"tag":"获火箭专利","tier":"secondary"},{"tag":"称火箭之父","tier":"secondary"},{"tag":"著火箭论文","tier":"secondary"}],"voice_profile":{"notes":"严谨克制；数据与计算说话；对远期目标的笃定；不擅也不屑公关"},"references":[{"ref_id":"goddard-s1","title":"戈达德《A Method of Reaching Extreme Altitudes》(1919, Smithsonian)","locator":"全文","source_tier":"primary","supports_models":["理论实验闭环","远期目标锚定"],"supports_cases":["goddard-c1"],"note":"一手学术论文"},{"ref_id":"goddard-s2","title":"1926年液体燃料火箭试验记录","locator":"试验记录 / Smithsonian","source_tier":"primary","supports_models":["押注液体燃料"],"supports_cases":["goddard-c3"],"note":"一手试验记录"},{"ref_id":"goddard-s3","title":"戈达德火箭专利（液体推进/多级火箭，1914起）","locator":"专利文本","source_tier":"primary","supports_models":["模块化攻关"],"supports_cases":["goddard-c4"],"note":"一手专利"},{"ref_id":"goddard-s4","title":"1920年《纽约时报》社论及1969年更正","locator":"报刊记录","source_tier":"secondary","supports_models":["不理嘲笑坚持"],"supports_cases":["goddard-c2"],"note":"报刊；嘲讽与更正"},{"ref_id":"goddard-s5","title":"David Clary《Rocket Man: Robert H. Goddard》传记","locator":"保密/孤立章","source_tier":"secondary","supports_cases":["goddard-c5"],"note":"学术传记"}],"material_type":"rich","reasoning_skeleton":{"signature":"先用理论算清可行边界、再用严格实验证伪修正（互相收口）；以遥远目标为锚反推当下子问题、并把巨目标拆成可独立攻克的子系统；现有路线触顶就转更难但上限更高的路线；被权威嘲笑时不论战、以数据为准默默把事做成","steps":[{"invoke":"理论实验闭环","action":"先问这判断算过、试过没有、数据在哪；理论推演可行边界、再实验证伪修正"},{"invoke":"远期目标锚定","action":"以遥远终极目标为锚，反推当下该先解决哪个子问题"},{"invoke":"模块化攻关","action":"把一口吃不下的巨目标拆成可独立攻克、可复用的子系统"},{"invoke":"押注液体燃料","action":"现有路线触顶就转更难但上限更高的新路线，哪怕第一步只飞几十英尺"},{"invoke":"不理嘲笑坚持","action":"被权威/舆论想当然否定时不论战，以可验证数据为准、默默把事做成"}],"contrast":"与特斯拉不同（都远超时代/被嘲笑的远见、落地协作弱，但方法不同）：特斯拉靠第一性原理直觉式构想、回物理本质重起；戈达德靠严格的理论实验闭环 + 押注更难路线 + 模块化攻关（工程实证派）——一个直觉构想、一个算了试了再信（见特斯拉卡）。与恩格尔巴特不同（都远见者、生前被低估）：恩格尔巴特做''增强人类协作智能''的系统框架、靠演示与协同放大；戈达德严格保密、独自工程实证——一个放大人的协作、一个切断协作默默单干（恰是其盲区）（见恩格尔巴特卡）。与爱迪生不同（都重实验）：爱迪生海量试错 + 商业化把发明变生意；戈达德理论先行 + 不屑公关、成果一度被低估（见爱迪生卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"goddard-c3","note":"用户''现有路线触顶、要不要转更难但上限更高的新路线''时，以发射首枚液体燃料火箭类比：固体燃料性能受限、他押注更难的液体燃料（泵/冷却/点火/控制无成例）、1926 完成人类首次液体火箭飞行（仅升空数秒、飞数十英尺）——新范式的起点不在第一步飞多远（1926 试验记录一手 A，确证）"},{"source":"case","case_id":"goddard-c2","note":"用户''权威和舆论都嘲笑我、但我手里有数据''时，以顶着《纽约时报》嘲讽继续类比：1920 社论嘲讽他连基础物理都不懂、他不公开论战、以实验数据为准默默推进，1969 阿波罗发射之际《纽约时报》正式刊文更正——把事做出来让事实说话（报刊记录 B，确证；社论措辞引大意不逐字坐实）"}]},"further_reading":[{"title":"罗伯特·戈达德《A Method of Reaching Extreme Altitudes》(1919, Smithsonian)","why":"其奠基性一手论文，看''理论实验闭环/远期目标锚定''如何把上极高空变成可计算的工程问题","type":"original"},{"title":"David Clary《Rocket Man: Robert H. Goddard》","why":"现代学术传记，含其保密与孤立工作风格、与德国协作团队的对比","type":"biography"},{"title":"Milton Lehman《This High Man: The Life of Robert H. Goddard》","why":"经典传记，完整呈现其一生工程实证历程与不屑公关的性格","type":"biography"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/goddard.png","avatar_thumb":"/advisors/portraits/goddard.png","domain":"创新","person_id":"P-goddard","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'af0e9111bad33798e8630959f276d2aff22865d5e2a2c7736b7b9c8998111284', 34, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('graham', 'P-graham', '本杰明·格雷厄姆', 'business', '本杰明·格雷厄姆 · 价值投资思维框架卡', '20世纪（1894–1976）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '安全边际 · 市场先生', '/advisors/portraits/graham.png', '/advisors/portraits/graham.png', 5, 0, '{"schema_version":1,"card_id":"graham","name":"本杰明·格雷厄姆","title":"本杰明·格雷厄姆 · 价值投资思维框架卡","era":"20世纪（1894–1976）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"安全边际","definition":"只在价格显著低于估算的内在价值时买入，留足缓冲；估值出错或运气不佳也不致重亏","source":"《聪明的投资者》","source_tier":"primary","mechanism":"输入=一个买入决策 → 处理=只在价格显著低于估算的内在价值时买入、留足缓冲 → 输出=即便估错也不致重亏的买入","trigger":"判断一笔买入值不值、要不要留容错时","modern_transfer":"只在价格显著低于你估的内在价值时才动手、留足安全边际——估值出错或运气不佳也死不了","architecture":{"type":"flow","components":["估内在价值","比对价格","留足折扣缓冲","价低于值才买"]},"strategy_card_image":"kb-assets/graham/model-1.png"},{"name":"市场先生","definition":"把市场拟人为情绪化的''市场先生''，每日报价时而亢奋时而恐慌；利用其报价而非被其情绪左右","source":"《聪明的投资者》","source_tier":"primary","mechanism":"输入=市场每日报价 → 处理=把市场拟人为情绪化的''市场先生''、利用其报价而非被其情绪左右 → 输出=反情绪的利用","trigger":"被市场涨跌情绪带动时","modern_transfer":"把市场当情绪化的''市场先生''，他亢奋或恐慌时给你报价——你利用报价，而不是被他的情绪传染","architecture":{"type":"loop","components":["接到市场报价","识别其情绪(亢奋/恐慌)","不被传染","利用报价"]},"strategy_card_image":"kb-assets/graham/model-2.png"},{"name":"内在价值","definition":"用资产、盈利、分红等基本面估算企业自身价值，与市场价分开看；投资即以价格买价值","source":"《证券分析》","source_tier":"primary","mechanism":"输入=一项资产 → 处理=用资产/盈利/分红等基本面估其自身价值、与市场价分开 → 输出=价值与价格的差","trigger":"想知道一个东西''本身值多少''而非''现在标价多少''时","modern_transfer":"用基本面估它自身价值、与市场价分开看；投资就是以价格买价值","architecture":{"type":"matrix","components":["收集基本面","估自身价值","与市场价分开","算价值-价格差"]},"strategy_card_image":"kb-assets/graham/model-3.png"},{"name":"烟蒂股法","definition":"买入价低于每股净流动资产（清算价打折），靠一篮子统计性折扣取胜，不赌单只","source":"《证券分析》","source_tier":"primary","mechanism":"输入=一组候选标的 → 处理=买入价低于每股净流动资产（清算价打折）、靠一篮子统计折扣取胜 → 输出=分散的统计性便宜组合","trigger":"想靠''足够便宜''而非''看准单只''取胜时","modern_transfer":"买一篮子价格低于清算价的''烟蒂''，靠统计性折扣取胜、不赌单只","architecture":{"type":"flow","components":["筛低于净流动资产的标的","一篮子买入","靠统计折扣","不押单只"]},"strategy_card_image":"kb-assets/graham/model-4.png"},{"name":"防御型投资","definition":"多数人应做规则化、充分分散的防御型投资，别高估自己选股与择时的能力","source":"《聪明的投资者》","source_tier":"primary","mechanism":"输入=一个普通投资者的能力评估 → 处理=做规则化、充分分散的防御型投资、不高估自己选股择时能力 → 输出=稳健的规则化配置","trigger":"容易高估自己选股择时能力时","modern_transfer":"多数人应做规则化、充分分散的防御型投资，别高估自己选股与择时的能力","architecture":{"type":"hierarchy","components":["评估自身能力","选防御型而非进取型","规则化+充分分散","稳健配置"]},"strategy_card_image":"kb-assets/graham/model-5.png"}],"decision_principles":["投资第一条规则是别亏钱，保本优先于博收益（A）","价格是你付出的，价值是你得到的；价低于值才买（A）","永远留安全边际，用折扣容错（A）","别预测市场，利用市场先生的情绪报价（A）","充分分散加量化标准，对冲单一判断失误（A）"],"inquiry_questions":["这笔买入，价格比你估的内在价值低多少？安全边际够吗？","如果你完全估错，最坏亏多少、扛得住吗？","你是在投资（有分析、保本），还是在投机（赌价格）？","你是被市场先生情绪带着走，还是在利用他的报价？"],"value_priorities":["保本不亏 ＞ 博取高收益（第一条规则是别亏钱）","量化安全边际与分散 ＞ 对单一好公司的定性信心（用纪律对冲判断误差）","价格便宜（价低于值） ＞ 公司质地与成长性（再好的公司价太高也不买——这是他与巴菲特的分野）"],"blind_spots":["过度偏重便宜与清算价值、低估优质成长股的复利——其最大盈利GEICO恰恰来自打破自己的规则（史实，A/B）","纯定量统计法在信息高效市场逐渐失效，净流动资产折扣机会变稀少（学术分析，B）","框架重保本，对识别伟大企业与管理层质量着墨少，需费雪/巴菲特路线互补（原理推断，B）"],"applicable_domains":["投资","风险评估","认知偏误与理性决策","长期规划"],"match_tags":["投资","风险评估","认知偏误与理性决策","风险规避","概率思维","批判思辨","现当代北美"],"linked_cases":["graham-c1","graham-c2","graham-c3","graham-c4","graham-c5"],"life_tags":[{"tag":"著证券分析","tier":"primary"},{"tag":"著聪明的投资者","tier":"primary"},{"tag":"执教哥大","tier":"secondary"},{"tag":"喻市场先生","tier":"primary"}],"voice_profile":{"notes":"教科书式严谨；善用寓言与拟人（市场先生）；克制、重逻辑轻情绪"},"references":[{"ref_id":"graham-s1","title":"《聪明的投资者》(The Intelligent Investor)","locator":"第8章（市场先生）、第20章（安全边际）、防御型投资者章","source_tier":"primary","supports_models":["安全边际","市场先生","防御型投资"],"note":"本人著述一手"},{"ref_id":"graham-s2","title":"《证券分析》(Security Analysis, 1934, 与多德合著)","locator":"内在价值章节；净流动资产价值法","source_tier":"primary","supports_models":["内在价值","烟蒂股法"],"supports_cases":["graham-c2"],"note":"本人著述一手"},{"ref_id":"graham-s3","title":"格雷厄姆-纽曼公司GEICO投资记录及多家研究复述","locator":"1948年投资记录；具体篇目待核验","source_tier":"secondary","supports_cases":["graham-c1"],"note":"投资额与增值数字多源复述一致"},{"ref_id":"graham-s4","title":"格雷厄姆回忆录《The Memoirs of the Dean of Wall Street》","locator":"北方管道、杜邦-通用相关章节；页码待核验","source_tier":"primary","supports_cases":["graham-c3","graham-c5"],"note":"本人回忆录；含自述成分，事件有传记交叉印证"},{"ref_id":"graham-s5","title":"1976年《金融分析师杂志》格雷厄姆访谈","locator":"访谈段落待核验","source_tier":"primary","supports_cases":["graham-c4"],"note":"本人晚年公开言论"},{"ref_id":"graham-s6","title":"罗杰·洛温斯坦等传记与1929–32崩盘史","locator":"崩盘损失相关章节","source_tier":"secondary","supports_cases":["graham-c2"],"note":"第三方记述，回撤比例各源略有出入"}],"material_type":"rich","reasoning_skeleton":{"signature":"先估它本身值多少、只在价格显著低于价值时买并留足安全边际；把市场当情绪化的''市场先生''去利用而非被带走；多数人该做规则化分散的防御型投资","steps":[{"invoke":"内在价值","action":"先估这东西本身值多少（基本面），与市场标价分开看"},{"invoke":"安全边际","action":"只在价格显著低于内在价值、留足折扣缓冲时才买——先确保估错也死不了"},{"invoke":"市场先生","action":"别被市场涨跌情绪带走，利用''市场先生''的报价而非被其情绪传染"},{"invoke":"烟蒂股法","action":"若靠便宜取胜，买一篮子低于清算价的标的、靠统计折扣、不赌单只"},{"invoke":"防御型投资","action":"多数人应规则化、充分分散，别高估自己选股与择时能力"}],"contrast":"与巴菲特分野（其学生）：格雷厄姆要''便宜且保本''（价<值）、刻意不为质地与成长付溢价、靠烟蒂股 + 定量统计；巴菲特在芒格/费雪影响下转向''合理价买卓越''、看护城河与管理层（见巴菲特卡）。与芒格不同：芒格跨学科定性避错；格雷厄姆定量统计、充分分散、靠规则对冲判断误差（见芒格卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"graham-c2","note":"用户''经历毁灭性回撤/重大失败后怎么办''时，以 1929–32 大崩盘濒临破产类比：他基金回撤约七成、几乎赔光却活下来、把惨痛教训提炼为''安全边际''并合著《证券分析》——先确保任何单次失误都死不了（确证）"},{"source":"case","case_id":"graham-c1","note":"用户''要不要为一个真正看清的卓越机会破自己的纪律''时，以 1948 重仓 GEICO 类比：他破了''不买成长股/不集中''两条铁律、成为一生最大盈利——破例须基于看清价值而非冲动（确证·诚实呈现纪律与破例的张力）"}]},"further_reading":[{"title":"本杰明·格雷厄姆《聪明的投资者》","why":"''市场先生''''安全边际''的出处，巴菲特称为''有史以来最好的投资著作''，面向普通投资者","type":"original"},{"title":"格雷厄姆 & 多德《证券分析》(1934)","why":"内在价值与净流动资产价值法的奠基之作，价值投资的学理源头（更硬核）","type":"original"},{"title":"格雷厄姆《华尔街教父回忆录》(The Memoirs of the Dean of Wall Street)","why":"本人回忆录，北方管道维权、杜邦套利等案例的第一手讲述，看其方法的实战由来","type":"biography"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/graham.png","avatar_thumb":"/advisors/portraits/graham.png","domain":"商业","person_id":"P-graham","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '5873dbc7015aeb0291a5f1b64f79f40b3804580f46e8da10dd96090a2738d9b8', 35, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('guanzhong', 'P-guanzhong', '管仲', 'governance', '管仲 · 经济治国思维框架卡', '春秋（约前723—前645）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '富民为先 · 轻重之术', '/advisors/portraits/guanzhong.png', '/advisors/portraits/guanzhong.png', 5, 0, '{"schema_version":1,"card_id":"guanzhong","name":"管仲","title":"管仲 · 经济治国思维框架卡","era":"春秋（约前723—前645）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"富民为先","definition":"推行秩序与教化之前，先解决民众的基础生存与物质问题——经济基础立住，规则与教化才立得住","source":"《管子·牧民》（部分托名）/《史记·管晏列传》","source_tier":"secondary","mechanism":"输入=想推行秩序/教化/更高要求、但民众基础生存未解决 → 处理=先解决民众的经济基础(富民) → 输出=有了物质基础、教化与规则才立得住","trigger":"想推行秩序/规则/价值、但基础需求未满足时","modern_transfer":"想推行秩序、规则或更高的要求，先把基础的生存/物质问题解决了——仓廪实才知礼节，基础没夯实，再好的规则也立不住","architecture":{"type":"hierarchy","components":["先解决基础生存物质","民众安定富足","再推行教化与秩序","规则立得住"]},"strategy_card_image":"kb-assets/guanzhong/model-1.png"},{"name":"轻重之术","definition":"用价格、货币、专营等经济杠杆调控财富流动，把\"税\"藏进必需品的定价里，富国而不直接加税激起民怨","source":"《管子·海王/轻重》（部分托名）/《史记·管晏列传》","source_tier":"secondary","mechanism":"输入=国家需财源、但直接加税激起民怨 → 处理=用价格/货币/专营(官山海/盐铁)等经济杠杆调控、把税藏进商品价格 → 输出=富国而不直接加税激民怨(''取之于无形使人不怒'')","trigger":"需财源、又不想直接加税激起民怨时","modern_transfer":"要增加收入又不想直接加价/加税激起反弹，把成本''藏''进必需品的定价或专营里——取之于无形、使人不怒(但须防与民争利、过度垄断之弊)","architecture":{"type":"matrix","components":["识别必需品如盐铁","国家专营或调控价格货币","把税藏进价格","富国而不显性加税"]},"strategy_card_image":"kb-assets/guanzhong/model-2.png"},{"name":"因地制宜差别化","definition":"制定征收/分配政策时按各对象的实际条件（土地肥瘠、强弱）差别化，而非一刀切，使负担公平","source":"《国语·齐语》/《管子·乘马》","source_tier":"secondary","mechanism":"输入=要制定征税/资源分配政策、但各地各对象条件不同 → 处理=按实际条件(土地肥瘠)差别化制定、而非一刀切 → 输出=负担公平、各方服气","trigger":"制定政策、各对象条件差异大时","modern_transfer":"制定征收/分配政策别一刀切——按各对象的实际条件(肥瘠/强弱)差别化，负担才公平、各方才服气(相地衰征)","architecture":{"type":"flow","components":["评估各地实际条件","按肥瘠强弱分等","差别化定政策","负担公平"]},"strategy_card_image":"kb-assets/guanzhong/model-3.png"},{"name":"借大义旗号取领导","definition":"自身实力够、但要号令或凝聚多方时，借一个各方都认的大义旗号来站位，以正当性取得领导地位","source":"《史记·齐太公世家/管晏列传》/《左传》","source_tier":"secondary","mechanism":"输入=自身实力强但名不正、想号令/凝聚多方 → 处理=借一个各方都认的大义旗号(尊周王/攘夷)来号令凝聚 → 输出=以正当性取得领导地位(霸业)","trigger":"想号令/凝聚多方、但需正当性时","modern_transfer":"自身实力够、但要号令或凝聚多方时，借一个各方都认的大义旗号来站位——''尊王攘夷''式地把自己的领导诉求接到一个公认的更高目标上(但旗号与实利之间的道义张力须自知)","architecture":{"type":"hierarchy","components":["自身已有实力","找各方公认的大义旗号","借旗号号令凝聚","取得正当领导地位"]},"strategy_card_image":"kb-assets/guanzhong/model-4.png"},{"name":"专业分工与经验累积","definition":"让不同职业的人分区聚居、专注本业、世代相传——专业分工加上经验的代际累积，是技艺与效率提升的根本","source":"《国语·齐语》","source_tier":"secondary","mechanism":"输入=各业人员混杂、技艺难精 → 处理=让士农工商分区聚居、专注本业、世代专精 → 输出=专业化+技艺经验代际累积","trigger":"想提升专业水平、积累经验时","modern_transfer":"让不同职业的人分区聚居、专注本业、世代相传——专业分工加上经验的代际累积，是技艺与效率提升的根本(四民分业)","architecture":{"type":"hierarchy","components":["按职业分区聚居","各专注本业","技艺世代相传","经验代际累积"]},"strategy_card_image":"kb-assets/guanzhong/model-5.png"}],"decision_principles":["想立规矩先富民：仓廪实而知礼节，基础没夯实，规则立不住","要财源用经济杠杆，把税藏进价格，别直接加税激民怨","政策按实际条件差别化，别一刀切，负担才公平","要号令多方，借一个各方都认的大义旗号站位","让人专注本业、分工聚居，让经验代际累积"],"inquiry_questions":["你想推行的秩序/规则，民众的基础生存/物质问题解决了吗？","你要的财源，能不能用价格/专营等经济杠杆''藏''起来，而非直接加税？","你的政策是一刀切，还是按各对象实际条件差别化、让负担公平？","你要号令/凝聚多方，有没有一个各方都认的大义旗号可借？","能不能让人专注本业、分工聚居，让经验代际累积？"],"value_priorities":["经济基础（富民） ＞ 空谈教化（仓廪实而知礼节——先解决生存再谈秩序）","无形的经济杠杆 ＞ 直接显性的加税（取之于无形使人不怒（但防与民争利之弊））","实效与富国强兵 ＞ 道义旗号的纯粹性（「尊王」实为挟天子的实用主义、道义性可议）"],"blind_spots":["其思想多见于《管子》，而《管子》成书晚、部分为后世（战国至汉）托名增益，未必皆出管仲本人——具体制度与言论的归属须谨慎，史料可靠性是显著保留（史料批判，B/C，〔慎〕）。","轻重之术与盐铁专营有''与民争利''、滋生垄断与官僚寻租之弊，后世（如汉代盐铁之议）即有激烈争论（学术分析，B）。","''尊王攘夷''实为''挟天子以令诸侯''的实用主义，借道义旗号行霸业之实，其道义性可议（史实/评议，B）。","重国家调控与集体编制，对个人权利、市场自发秩序着力少，是其国家主义取向的局限（原理推断，B）。"],"applicable_domains":["治理决策","资源调度","长期规划","商业"],"match_tags":["治理决策","资源调度","长期规划","商业","务实渐进","系统分析","长期主义","古代东亚"],"linked_cases":["guanzhong-c1","guanzhong-c2","guanzhong-c3"],"life_tags":[{"tag":"相齐桓公","tier":"secondary"},{"tag":"助成首霸","tier":"secondary"},{"tag":"行盐铁政","tier":"secondary"},{"tag":"倡尊王攘夷","tier":"secondary"}],"voice_profile":{"notes":"务实重利、少谈空理；以富国强兵为念；善用经济与制度手段；通权达变"},"references":[{"ref_id":"guanzhong-s1","title":"《史记·管晏列传》","locator":"管仲相齐、通货积财、尊王攘夷诸段","source_tier":"secondary","supports_models":["富民为先","轻重之术","借大义旗号取领导"],"supports_cases":["guanzhong-c1","guanzhong-c2"],"note":"较可靠的后世史传(西汉)"},{"ref_id":"guanzhong-s2","title":"《国语·齐语》","locator":"相地而衰征、四民分业定居段","source_tier":"secondary","supports_models":["因地制宜差别化","专业分工与经验累积"],"supports_cases":["guanzhong-c3"],"note":"较早的先秦记载"},{"ref_id":"guanzhong-s3","title":"《管子》（部分托名）","locator":"牧民、海王、轻重诸篇","source_tier":"tertiary","supports_models":["富民为先","轻重之术"],"note":"成书晚、部分后世托名→归属存疑、仅作思想旁证，不单独坐实"},{"ref_id":"guanzhong-s4","title":"《左传》","locator":"齐桓公会盟、尊王攘夷相关","source_tier":"secondary","supports_models":["借大义旗号取领导"],"supports_cases":["guanzhong-c2"],"note":"先秦编年史"}],"material_type":"rich","reasoning_skeleton":{"signature":"想推行秩序先解决基础生存(仓廪实而知礼节)；要财源又不激民怨就用经济杠杆把税藏进价格(轻重之术)；制定政策按各地实际条件差别化(相地衰征)；要号令多方借一个公认的大义旗号(尊王攘夷)；提升专业靠分工聚居与经验代际累积(四民分业)","steps":[{"invoke":"富民为先","action":"你想推行的秩序/规则/要求，民众的基础生存/物质问题解决了吗？先富民再教化"},{"invoke":"轻重之术","action":"你要的财源/收益，能不能用价格/专营等经济杠杆''藏''起来，而非直接加税激起反弹？"},{"invoke":"因地制宜差别化","action":"你的政策是一刀切，还是按各对象的实际条件差别化、让负担公平？"},{"invoke":"借大义旗号取领导","action":"你要号令/凝聚多方，有没有一个各方都认的大义旗号可以借？"},{"invoke":"专业分工与经验累积","action":"能不能让人专注本业、分工聚居，让经验代际累积？"}],"contrast":"与商鞅不同(关键差异·同为治理改革家)：二者都富国强兵，但**商鞅靠''法家变法+严刑峻法+耕战立制''强制重塑(徙木立信、一断于法、奖励耕战)**；**管仲靠''经济治国+因势利导''柔性调控(富民为先、轻重之术、因地制宜)**——商是法治强制、管是经济杠杆(见商鞅卡)。与诸葛亮不同：诸葛亮重''执法严明+顶层谋划''；管仲重''经济基础+富国强兵''。与林肯/曼德拉/华盛顿等区分：管仲核心是''经济治国''(富民/轻重/分业)、非危机维系或和解或限权(见相应卡)。【射程/盲区】管仲之术重实效，但①其思想多见于《管子》、而《管子》部分为后世托名、未必皆出管仲本人(史料须谨慎、显著保留)；②轻重之术/专营有与民争利、滋生垄断之弊；③''尊王''实为''挟天子''的实用主义、道义性可议；④重国家调控、对个人权利与市场自发性着力少。适用治理/经济/资源调度；不适用修身自省/纯创新研发。"},"persona_anchor":{"primary":[{"source":"case","case_id":"guanzhong-c1","note":"用户''要增加收入/财源、又怕直接加价加税引发反弹''时，以管仲富齐之政类比：他不直接重税，而用''官山海''(盐铁专营)、轻重调控物价货币，把税藏进必需品价格、''取之于无形''富国强兵（富齐强齐为《史记》《国语》可考→确证；轻重诸术之文多见《管子》、部分托名，呈现宜重原则、慎引具体托名条文）"},{"source":"case","case_id":"guanzhong-c2","note":"用户''实力够了、但要名正言顺地号令/凝聚多方''时，以尊王攘夷类比：管仲佐齐桓公打''尊周王、攘夷狄''的旗号、九合诸侯一匡天下成春秋首霸——借一个各方都认的大义把领导诉求正当化（九合诸侯、首霸为《史记》《左传》可考→确证；其''挟天子''的实用主义与道义张力宜并陈）"}]},"further_reading":[{"title":"《史记·管晏列传》《国语·齐语》《左传》","why":"管仲相齐、尊王攘夷、相地衰征、四民分业的较可靠记载","type":"史书"},{"title":"《管子》（部分托名）","why":"轻重/牧民诸篇，须注意成书晚、部分后世托名，归属存疑","type":"文本"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/guanzhong.png","avatar_thumb":"/advisors/portraits/guanzhong.png","domain":"治理","person_id":"P-guanzhong","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '0c942132f92a34afa3c5368f84e56cfbebc1b843742fb7c248bf0b0741ea44b1', 36, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('hanfeizi', 'P-hanfeizi', '韩非子', 'philosophy', '韩非子 · 法术势思维框架卡', '战国（约前280—前233）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '法 · 术', '/advisors/portraits/hanfeizi.png', '/advisors/portraits/hanfeizi.png', 5, 0, '{"schema_version":1,"card_id":"hanfeizi","name":"韩非子","title":"韩非子 · 法术势思维框架卡","era":"战国（约前280—前233）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"法","definition":"用公开、明确、对所有人一致的\"规则/制度\"来治理，而非靠领导者个人的好恶与德行","source":"《韩非子·定法》《有度》","source_tier":"primary","mechanism":"输入=靠领导者个人好恶/德行人治 → 处理=用公开、明确、对所有人一致的规则/制度治理 → 输出=以法治取代人治","trigger":"要建立可持续、公平的治理/管理时","modern_transfer":"用公开、明确、对所有人一致的''规则/制度''来治理、而非靠领导者个人的好恶与德行——''法''要公开、稳定、一视同仁(韩非法)","architecture":{"type":"hierarchy","components":["别靠个人好恶德行人治","用公开明确的规则制度","对所有人一视同仁","以法治取代人治"]},"strategy_card_image":"kb-assets/hanfeizi/model-1.png"},{"name":"术","definition":"管理者要有\"驾驭\"之术：按职责考核结果（循名责实）、不轻易暴露好恶，免得被人投其所好地操纵","source":"《韩非子·定法》《主道》","source_tier":"primary","mechanism":"输入=轻易暴露自己的好恶、被投其所好操纵 → 处理=按职责考核结果(循名责实)、不轻易暴露好恶 → 输出=驾驭而不被操纵(术)","trigger":"管理者驾驭下属、防被操纵时","modern_transfer":"管理者要有''驾驭''之术——按职责考核结果(循名责实)、不轻易暴露自己的偏好(免得被人投其所好地操纵)(韩非术)〔但术易流于权谋猜忌、见盲区〕","architecture":{"type":"flow","components":["别轻易暴露好恶被操纵","按职责考核结果","不轻易暴露偏好","驾驭而不被操纵"]},"strategy_card_image":"kb-assets/hanfeizi/model-2.png"},{"name":"势","definition":"善用你所处的\"位置/权力/形势\"本身赋予的力量——同样的人，有势与无势效果天差地别","source":"《韩非子·难势》","source_tier":"primary","mechanism":"输入=只靠个人能力/德行 → 处理=善用''位置/权力/形势''本身赋予的力量 → 输出=借势放大(势)","trigger":"判断如何施加影响、是否善用了位置时","modern_transfer":"善用你所处的''位置与形势''本身赋予的力量(势)——同样的人、有势与无势效果天差地别;别只靠个人能力、也要会借助位置之势(韩非势)","architecture":{"type":"flow","components":["别只靠个人能力德行","看清位置权力形势的力量","善用位置之势","借势放大影响"]},"strategy_card_image":"kb-assets/hanfeizi/model-3.png"},{"name":"性恶趋利避害","definition":"假定人都会趋利避害、自利行事，用清晰的利害（赏罚）机制来驱动，而非指望道德说教","source":"《韩非子·二柄》《奸劫弑臣》","source_tier":"primary","mechanism":"输入=指望道德说教驱动人 → 处理=假定人都自利、趋利避害、用清晰的利害(赏罚)机制驱动 → 输出=用利害而非道德设计制度","trigger":"要设计一个能驱动人的机制/制度时","modern_transfer":"假定人都会趋利避害、自利行事——用清晰的利害(赏罚)机制来驱动、而非指望道德说教;把人当''自利的''来设计制度、反而更稳健(韩非)〔但纯以利害看人、忽视了道德能动与情感、见盲区〕","architecture":{"type":"flow","components":["别指望道德说教驱动人","假定人趋利避害自利","用清晰的利害赏罚机制","把人当自利来设计制度"]},"strategy_card_image":"kb-assets/hanfeizi/model-4.png"},{"name":"循名责实","definition":"按一个人\"承诺/职责（名）\"去考核他\"实际做到的（实）\"，名实相符才赏、不符则罚——别被空话蒙蔽","source":"《韩非子·二柄》形名参验","source_tier":"primary","mechanism":"输入=被空话/承诺蒙蔽 → 处理=按''名(职责/承诺)''考核''实(实际结果)''、名实相符才赏 → 输出=赏罚依实绩(循名责实)","trigger":"要考核/赏罚、防空谈时","modern_transfer":"按一个人''承诺/职责(名)''去考核他''实际做到的(实)''、名实相符才赏、不符则罚——别被空话蒙蔽(韩非循名责实/形名参验)","architecture":{"type":"hierarchy","components":["别被空话承诺蒙蔽","按名职责承诺","考核实实际结果","名实相符才赏不符则罚"]},"strategy_card_image":"kb-assets/hanfeizi/model-5.png"}],"decision_principles":["用公开、明确、一致的规则制度治理，而非靠个人好恶德行","按职责考核结果、不轻易暴露偏好，以免被投其所好地操纵","善用你所处位置与形势本身的力量，别只靠个人能力","假定人趋利避害，用清晰的利害（赏罚）机制驱动","按名考核实、名实相符才赏，别被空话蒙蔽"],"inquiry_questions":["你靠的是公开一致的规则制度、还是领导者个人的好恶与德行？","你是不是轻易暴露了自己的偏好、容易被人投其所好地操纵？","你是只靠个人能力、还是也善用了你所处位置与形势的力量？","你是指望道德说教、还是用清晰的利害（赏罚）机制来驱动人？","你是被空话承诺蒙蔽、还是按实际结果考核赏罚？"],"value_priorities":["公开一致的法 ＞ 个人好恶的人治（法布之于百姓、一视同仁）","清晰的利害机制 ＞ 指望道德说教（二柄（刑德/赏罚）驱动）","名实相符的考核 ＞ 被空话蒙蔽（循名责实、形名参验）"],"blind_spots":["〔慎〕法术势尤其''术''易流于权谋、猜忌与对人的工具化；其严刑峻法的一面在历史上也通向了苛政（史/学术，B，客观标注）。","纯以利害（性恶）看人，忽视了人的道德能动、信任、情感与文化的力量，长期可能侵蚀组织的凝聚与认同（学术分析，B）。","过度依赖君主集权与权术，缺乏对''最高权力本身''的制约（学术分析，B）。","其思想诞生于战国争霸，长于乱世立威与控制，短于和平时期的人心凝聚与价值建设（原理推断，B）。"],"applicable_domains":["组织管理","竞争博弈","危机应对"],"match_tags":["组织管理","竞争博弈","危机应对","制度法治思维","对抗性思维","系统分析","古代东亚"],"linked_cases":["hanfeizi-c1","hanfeizi-c2","hanfeizi-c3","hanfeizi-c4"],"life_tags":[{"tag":"著韩非子","tier":"primary"},{"tag":"集法家大成","tier":"secondary"},{"tag":"倡法术势","tier":"primary"},{"tag":"著说难孤愤","tier":"primary"}],"voice_profile":{"notes":"冷峻犀利、直指利害；不谈道德谈机制；逻辑严密；洞悉人性幽暗"},"references":[{"ref_id":"hanfeizi-s1","title":"《韩非子》","locator":"法、术、势、二柄、循名责实","source_tier":"primary","supports_models":["法","术","势","性恶趋利避害","循名责实"],"supports_cases":["hanfeizi-c1","hanfeizi-c2","hanfeizi-c3","hanfeizi-c4"],"note":"一手·原典"},{"ref_id":"hanfeizi-s2","title":"法家思想研究","locator":"法术势及其历史影响（含对专制面的批评）","source_tier":"secondary","supports_models":["法","术"],"note":"二手·研究"}],"material_type":"textual","reasoning_skeleton":{"signature":"用公开明确一致的规则制度治理而非个人好恶人治(法)；按职责考核结果、不轻易暴露好恶以防被操纵(术)；善用位置与形势本身的力量(势)；假定人趋利避害、用利害赏罚而非道德说教驱动(性恶趋利避害)；按名考核实、名实相符才赏(循名责实)","steps":[{"invoke":"法","action":"你靠的是公开一致的规则制度、还是领导者个人的好恶与德行？"},{"invoke":"术","action":"你是不是轻易暴露了自己的偏好、容易被人投其所好地操纵？"},{"invoke":"势","action":"你是只靠个人能力、还是也善用了你所处位置与形势的力量？"},{"invoke":"性恶趋利避害","action":"你是指望道德说教、还是用清晰的利害（赏罚）机制来驱动人？"},{"invoke":"循名责实","action":"你是被空话承诺蒙蔽、还是按实际结果考核赏罚？"}],"contrast":"与孔子/孟子不同(关键差异·法家与儒家对立)：**儒家主''德治、性善/仁政''(靠道德、礼与教化、相信人本善)**；**韩非主''法术势、性恶趋利避害''(靠制度、赏罚与权势、假定人自利)**——一个靠德与善、一个靠法与利害(见孔子/孟子卡)。与荀子不同：荀子虽主''性恶''、但仍归于''隆礼''(用礼来化性);韩非把性恶推到底、归于''法术势''(用法与权势来控制)(见荀子卡)。与墨子不同：墨子靠''兼爱交相利''的道德与实利说服;韩非靠''法术势''的制度与强制(见墨子卡)。【射程/盲区·〔慎〕】韩非之道在''法、术、势、利害驱动、循名责实''极有力(尤其乱世立威、制度设计、防被操纵)，但①〔慎〕法术势尤其''术''易流于权谋、猜忌与对人的工具化、其严刑峻法的一面历史上也通向苛政;②纯以利害看人、忽视道德能动、信任、情感的力量、长期可能侵蚀组织凝聚与认同;③过度依赖君主集权与权术、缺对''最高权力本身''的制约;④长于乱世控制、短于和平时期的人心凝聚与价值建设。适用组织管理/竞争博弈/危机应对;不适用修身自省/价值与伦理/创作。"},"persona_anchor":{"primary":[{"source":"case","case_id":"hanfeizi-c1","note":"用户''一个组织全靠领导者个人的好恶、关系、人情在运转、缺乏稳定规则''时，以韩非''法''类比：韩非主张用公开、明确、对所有人一致的''法''(规则制度)来治理、''编著之图籍、设之于官府、布之于百姓''——别靠个人好恶与德行人治、制度才稳定可持续、一视同仁（''法''为《韩非子》所载→确证）"},{"source":"case","case_id":"hanfeizi-c4","note":"用户''下属/合作方光说漂亮话、承诺一堆、却难以兑现、自己常被空话蒙蔽''时，以韩非循名责实类比：按对方''承诺/职责(名)''去考核他''实际做到的(实)''、名实相符才赏、不符则罚——''循名而责实''、用结果而非言辞来检验（循名责实为《韩非子》所载→确证）"}]},"further_reading":[{"title":"《韩非子》","why":"法、术、势、二柄、循名责实的一手出处（A）","type":"原典"},{"title":"法家思想研究","why":"对法术势及其历史影响的学术分析（含对其专制面的批评，B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/hanfeizi.png","avatar_thumb":"/advisors/portraits/hanfeizi.png","domain":"哲学","person_id":"P-hanfeizi","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'b293e437c976ed2fc5178ec80aaaa7aa9f66846e4ac60b7e110a8ef95f885960', 37, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('hannibal', 'P-hannibal', '汉尼拔', 'strategy', '汉尼拔 · 战役机动思维框架卡', '古典时代（前247—前183）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '包围歼灭 · 出敌意料的战略机动', '/advisors/portraits/hannibal.png', '/advisors/portraits/hannibal.png', 5, 0, '{"schema_version":1,"card_id":"hannibal","name":"汉尼拔","title":"汉尼拔 · 战役机动思维框架卡","era":"古典时代（前247—前183）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"包围歼灭","definition":"用中央故意示弱后撤、两翼与骑兵合拢的方式把敌主力裹进口袋、四面合围全歼，而非击溃驱逐","source":"古典史家(波利比乌斯/李维)载坎尼会战双重包围","source_tier":"secondary","mechanism":"输入=目标是彻底解决对手(非击退)、且对手兵力占优 → 处理=中央示弱后撤诱敌深入、两翼与骑兵合拢 → 输出=把敌裹进口袋全歼，把敌兵力优势变成被包饺子的劣势","trigger":"目标是全歼而非击溃、且对手兵力占优时","modern_transfer":"当目标是彻底解决而非暂时击退——用''中央示弱诱敌深入、两翼合围''，把对手的兵力优势变成被包饺子的劣势(坎尼式)","architecture":{"type":"matrix","components":["中央示弱后撤","诱敌深入","两翼骑兵合拢","四面合围全歼"]},"strategy_card_image":"kb-assets/hannibal/model-1.png"},{"name":"出敌意料的战略机动","definition":"走对手认为不可能的路线(翻越阿尔卑斯)、在对手没料到的时间地点出现，以战略奇袭夺取主动","source":"率军翻越阿尔卑斯山突入意大利本土","source_tier":"secondary","mechanism":"输入=对手严防常规路线 → 处理=走对手认为不可能的路线、在没料到的时间地点出现 → 输出=以战略奇袭夺取主动","trigger":"对手严防常规进攻路线、想夺战略主动时","modern_transfer":"走对手判定''绝无可能''的路线，代价巨大但换来对方完全没防备的战略主动——奇袭的价值常抵得过沿途的惨重损耗(翻越阿尔卑斯式)","architecture":{"type":"flow","components":["识别对手严防的常规路线","选不可能路线","出其不意现身","夺战略主动"]},"strategy_card_image":"kb-assets/hannibal/model-2.png"},{"name":"因地形设伏","definition":"利用地形(湖岸、雾、隘口)预设埋伏，诱敌入彀后突然合击，以伏击抵消兵力或装备劣势","source":"特拉西梅诺湖伏击战","source_tier":"secondary","mechanism":"输入=兵力或装备处于劣势 → 处理=利用地形(湖岸/雾/隘口)预设埋伏、诱敌入彀后突然合击 → 输出=以伏击抵消劣势","trigger":"兵力/装备劣势、且有可利用地形时","modern_transfer":"利用地形/时机预设一个杀局，诱对手主动走进来再突然合击——用伏击抵消你的兵力或装备劣势(特拉西梅诺式)","architecture":{"type":"flow","components":["选可利用地形","预设埋伏","诱敌入彀","突然合击"]},"strategy_card_image":"kb-assets/hannibal/model-3.png"},{"name":"攻心与离间","definition":"善待俘虏中的意大利同盟者、释放之以瓦解罗马同盟体系，从政治上削弱对手而非只在战场打","source":"古典史家载其优待非罗马籍俘虏、争取意大利诸邦倒戈","source_tier":"secondary","mechanism":"输入=对手靠联盟体系强大 → 处理=善待并释放俘虏中的对方同盟者、争取倒戈 → 输出=从政治上瓦解对手联盟(非只在战场打)","trigger":"对手靠联盟/同盟体系而强大时","modern_transfer":"除了正面打，去瓦解对手的''联盟''与后方支持——优待、争取对方的盟友倒戈，从政治上削弱对手而非只在战场较量","architecture":{"type":"hierarchy","components":["识别对手联盟体系","优待对方同盟者","释放争取倒戈","政治瓦解对手"]},"strategy_card_image":"kb-assets/hannibal/model-4.png"},{"name":"以战养战·客境持久","definition":"孤军深入敌国腹地，靠就地补给、利用当地反对力量维持长期作战，在无后方支援下生存周旋","source":"在意大利本土孤军作战十余年","source_tier":"secondary","mechanism":"输入=孤军深入敌国腹地、无稳定后方 → 处理=靠就地补给、联合当地反对力量维持长期作战 → 输出=在无后方支援下生存周旋(但弥补不了国家级后勤短板)","trigger":"孤军深入对手腹地、无稳定后方支援时","modern_transfer":"孤军深入对手腹地、没有稳定后方时，靠就地取给、联合当地反对力量维持长期周旋——在无支援下生存；但终究弥补不了国家级的后勤与战略短板","architecture":{"type":"loop","components":["孤军深入腹地","就地补给","联合当地反对力量","无后方持久周旋"]},"strategy_card_image":"kb-assets/hannibal/model-5.png"}],"decision_principles":["歼灭而非击溃：把敌主力裹进口袋全歼（坎尼，B）","走对手以为走不通的路：以战略奇袭夺主动（翻越阿尔卑斯，B）","用地形预设杀局：诱敌入伏再合击（特拉西梅诺，B）","战场之外瓦解其联盟：优待俘虏、争取倒戈（攻心离间，B）"],"inquiry_questions":["你是想''击溃''对手让他跑，还是设计一个口袋把他''全歼''？两者打法完全不同。","有没有一条对手认定你''不可能走''的路？走通了它，你就拿到了战略奇袭。","你能不能用地形/时机预设一个杀局，诱对手主动走进来？","除了正面打，你有没有在瓦解对手的''联盟''与后方支持？"],"value_priorities":["全歼对手主力 ＞ 击溃驱逐（歼灭才解决问题，击溃只是推迟）","出其不意的机动 ＞ 四平八稳的正攻（战略奇袭值得冒非常之险(翻越阿尔卑斯损失惨重但夺得主动)）","战役层面的辉煌胜利 ＞ 战略层面的持久经营（此偏好使其战无不胜，却赢不下整场战争(其根本盲区)）"],"blind_spots":["战役天才、战略困局：连战连胜却缺乏攻陷罗马城与持久补给的手段，坎尼大胜后未能终结战争，最终在扎马被西庇阿击败、迦太基战败（史实，B）","孤军客境、后方不济：本国迦太基政争掣肘、援助不继，其个人军事天才无法弥补国家战略与后勤的系统性短板（史实，B）","其个人指挥细节几乎全出罗马方史家(李维)与希腊史家(波利比乌斯)之手，敌方/他方视角，含夸张与塑造，迦太基方一手记载几无（史料批判·敌方来源，B）","对手适应后失灵：罗马以费边''拖延战略''避免决战、以持久消耗反制，汉尼拔的决战包围战法即难再奏效（史实，B）"],"applicable_domains":["战略","竞争博弈","危机应对","资源调度"],"match_tags":["战略","竞争博弈","危机应对","资源调度","直觉决断","对抗性思维","攻心共识","古代非洲"],"linked_cases":["hannibal-c1","hannibal-c2","hannibal-c3"],"life_tags":[{"tag":"翻越阿尔卑斯","tier":"secondary"},{"tag":"坎尼歼罗马","tier":"secondary"},{"tag":"发动布匿战争","tier":"secondary"},{"tag":"兵临罗马城","tier":"secondary"}],"voice_profile":{"notes":"果敢冒险；重谋略与机动；（经罗马史家叙述）传奇悲情色彩"},"references":[{"ref_id":"hannibal-s1","title":"波利比乌斯《历史》","locator":"坎尼会战、翻越阿尔卑斯、扎马会战","source_tier":"secondary","supports_models":["包围歼灭","出敌意料的战略机动","以战养战·客境持久"],"supports_cases":["hannibal-c1","hannibal-c2","hannibal-c3"],"note":"较早且较审慎的希腊史家，但仍非迦太基方一手、去其约半世纪以上"},{"ref_id":"hannibal-s2","title":"李维《罗马史(自建城以来)》","locator":"特拉西梅诺伏击、坎尼、对意大利同盟之争取","source_tier":"secondary","supports_models":["因地形设伏","攻心与离间"],"supports_cases":["hannibal-c1"],"note":"罗马方史家，敌方视角，含修辞塑造"},{"ref_id":"hannibal-s3","title":"古典史家(扎马/费边战略)","locator":"扎马会战、罗马费边持久战略","source_tier":"secondary","supports_cases":["hannibal-c3"],"note":"多源古典记载，后世追述"}],"material_type":"rich","reasoning_skeleton":{"signature":"目标是全歼而非击退——以中央示弱诱敌深入、两翼合围把敌兵力优势变成被包饺子(坎尼)；走对手认为不可能的路线奇袭夺主动；用地形预设杀局诱敌入伏；并在战场之外优待俘虏瓦解对手联盟；孤军客境靠就地补给持久周旋","steps":[{"invoke":"包围歼灭","action":"你想''击溃''对手让他跑，还是设计一个口袋把他''全歼''？两者打法完全不同(坎尼式:中央示弱诱敌、两翼合围)"},{"invoke":"出敌意料的战略机动","action":"有没有一条对手认定你''不可能走''的路？走通它，你就拿到了战略奇袭(翻越阿尔卑斯)"},{"invoke":"因地形设伏","action":"你能不能用地形/时机预设一个杀局，诱对手主动走进来再合击？(特拉西梅诺)"},{"invoke":"攻心与离间","action":"除了正面打，你有没有在瓦解对手的''联盟''与后方支持？优待、争取对方盟友倒戈"},{"invoke":"以战养战·客境持久","action":"孤军深入、没有后方时，能否靠就地补给与当地力量持久周旋？(但战役全胜弥补不了战略与后勤的系统短板)"}],"contrast":"与亚历山大不同(关键差异)：二者都是会战机动天才，但**亚历山大靠锤砧协同(方阵正面咬住+骑兵侧翼)与主帅亲冲中枢、远征闪击+征服后整合**；**汉尼拔靠双重包围全歼(坎尼:中央示弱诱敌、两翼合拢把敌兵力优势变劣势)与以弱胜强、客场孤军周旋**——亚是''锤砧夹击+整合统治''，汉是''口袋围歼+客境持久''(见亚历山大卡)。与孙子不同：孙子重''庙算/先胜后战/不战而屈人''(开战前已算赢、慎战)；汉尼拔则是''以非常之险换战场全歼''的会战决胜派(翻越阿尔卑斯、坎尼)，恰是孙子''兵贵胜不贵久''的反面教材——他战役全胜却赢不下整场战争(见孙子卡)。【最深盲区·优点同源】史上最辉煌的**战役**天才却输掉整场**战争**：坎尼全歼后无法终结战争，对手改用费边持久消耗、避免决战，其决战包围战法即失灵，终在扎马落败(C3)——''战役全胜、战略落败''。不适用修身自省/人际关系。"},"persona_anchor":{"primary":[{"source":"case","case_id":"hannibal-c1","note":"用户''要不要追求彻底解决而非暂时击退占优对手''时，以坎尼双重包围类比：面对兵力占优的罗马军，以中央示弱后撤诱敌深入、两翼与骑兵合拢全歼之，把敌兵力优势变成被包饺子的劣势（坎尼会战为信史；汉尼拔个人战术细节出后世/罗马方史家、historicity 存疑，作代入呈现宜概述、不坐实细节）"},{"source":"case","case_id":"hannibal-c2","note":"用户''要不要冒险走对手认定不可能的路线''时，以翻越阿尔卑斯类比：率军与战象翻越被认为不可逾越的山脉、从无防备的北方突入、夺得战略主动（事件主干为信史；路线/损失/战象数细节古典记载不一、含传奇放大，宜概述）"}]},"further_reading":[{"title":"波利比乌斯《历史》","why":"较早较审慎的希腊史家，坎尼/阿尔卑斯/扎马；仍非迦太基方一手","type":"biography"},{"title":"李维《罗马史(自建城以来)》","why":"罗马方(敌方)史家，特拉西梅诺、坎尼、争取意大利同盟；含修辞塑造","type":"biography"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/hannibal.png","avatar_thumb":"/advisors/portraits/hannibal.png","domain":"战略","person_id":"P-hannibal","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '7435baaa7acbd0b5da3326dd888a329040d73165f834863d83964a5042927f86', 38, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('hanxin', 'P-hanxin', '韩信', 'strategy', '韩信 · 用兵方略思维框架卡', '秦末汉初（约前231—前196）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '置之死地而后生 · 奇正并用·背水设伏', '/advisors/portraits/hanxin.png', '/advisors/portraits/hanxin.png', 5, 0, '{"schema_version":1,"card_id":"hanxin","name":"韩信","title":"韩信 · 用兵方略思维框架卡","era":"秦末汉初（约前231—前196）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"置之死地而后生","definition":"主动断绝退路、把人逼入绝境，以激发求生本能换取最大战斗力；用心理绝境置换兵力劣势","source":"《史记·淮阴侯列传》井陉之战\"陷之死地而后生，置之亡地而后存\"","source_tier":"primary","mechanism":"输入=兵力/资源劣势的局面 → 处理=主动断绝退路、把人逼入绝境、以求生本能换战斗力 → 输出=用心理绝境置换兵力劣势（高风险）","trigger":"兵力（资源）处劣势、需逼出最大潜力时","modern_transfer":"资源劣势时，用''地形/绝境/规则设计''把人的潜力逼出来、补上硬实力的差——但成则封神、败则覆没","architecture":{"type":"flow","components":["评估兵力劣势","主动断退路","逼入绝境激死战","以士气补兵力"]},"strategy_card_image":"kb-assets/hanxin/model-1.png"},{"name":"奇正并用·背水设伏","definition":"正面用\"违反常识\"的布阵吸住并麻痹敌主力(正)，同时以轻骑奇兵抄袭其空营换旗断后路(奇)，正奇夹击","source":"《史记·淮阴侯列传》井陉之战两千轻骑换旗+万人背水列阵","source_tier":"primary","mechanism":"输入=一场需以弱胜强的对抗 → 处理=正面用反常布阵吸住麻痹敌主力（正）、同时奇兵抄其空虚换旗断后（奇）→ 输出=正奇夹击","trigger":"需同时麻痹对手又击其要害时","modern_transfer":"一手''正''吸住、麻痹对手，一手''奇''抄它没设防的后路，正奇夹击定胜","architecture":{"type":"matrix","components":["设''正''吸住敌主力","设''奇''抄空虚","换旗断后路","正奇合击"]},"strategy_card_image":"kb-assets/hanxin/model-2.png"},{"name":"多多益善·因材编组","definition":"善于把大规模、参差不齐的兵力组织成可控整体，规模越大越能发挥——治众如治寡的组织能力","source":"《史记·淮阴侯列传》\"臣多多而益善耳\"对答","source_tier":"primary","mechanism":"输入=大规模、参差不齐的兵力 → 处理=把它组织成可控整体、治众如治寡 → 输出=规模越大越能发挥的组织","trigger":"要驾驭大规模/参差的资源或团队时","modern_transfer":"善于把大规模、参差的力量组织成可控整体——规模越大越能发挥，是''治众如治寡''的组织力","architecture":{"type":"hierarchy","components":["接手大规模参差兵力","因材编组","分层可控","规模放大战力"]},"strategy_card_image":"kb-assets/hanxin/model-3.png"},{"name":"先声后实·不战收城","definition":"以已成之威名与态势先行震慑，辅以书信劝降，使敌不战而服；能用声势解决的不靠硬攻","source":"《史记·淮阴侯列传》广武君策\"先声而后实\"，下燕不战","source_tier":"primary","mechanism":"输入=一个可慑服的目标 → 处理=以已成威名与态势先震慑、辅以书信劝降、使敌不战而服 → 输出=能用声势解决的不靠硬攻","trigger":"这一仗未必非打、可借声势时","modern_transfer":"能靠已有声势和态势让对手不战而服，就别硬攻——先声而后实","architecture":{"type":"flow","components":["盘点已有威名态势","先声震慑","辅以劝降","不战而下"]},"strategy_card_image":"kb-assets/hanxin/model-4.png"},{"name":"避实击虚·攻其无备","definition":"不与敌强点正面消耗，择其无备处突袭或以诈制胜(如明修栈道暗度陈仓、囊沙壅水半渡而击)","source":"暗度陈仓、潍水之战囊沙断流半渡击齐楚联军","source_tier":"primary","mechanism":"输入=敌之强点与虚处 → 处理=不与敌强点正面消耗、择其无备处突袭或以诈制胜 → 输出=攻其无备","trigger":"面对敌强点、不想正面消耗时","modern_transfer":"别在对手最强处硬碰，找到它''以为安全''的虚处下手（明修栈道暗度陈仓/囊沙半渡）","architecture":{"type":"flow","components":["识别强点与虚处","避开强点","以诈麻痹","击其无备"]},"strategy_card_image":"kb-assets/hanxin/model-5.png"}],"decision_principles":["兵力不足则用地形与绝境补：把劣势兵力放到能逼出死战的位置（井陉，A）","正面麻痹+奇兵断后：以反常布阵诱敌、以奇兵定胜（井陉，A）","能不战而下则不强攻：以威名声势先慑、书信劝降（下燕，A）","择虚而击、以诈佐战：避正面消耗，攻其无备（暗度陈仓/潍水，A）"],"inquiry_questions":["你兵力(资源)处劣势时，能不能用''地形/绝境/规则设计''把人的潜力逼出来，补上硬实力的差？","你有没有一手''正''用来吸住、麻痹对手，一手''奇''用来抄它没设防的后路？","这一仗非打不可吗？能不能靠你已有的声势和态势，让对手不战而服？","你是在对手最强处硬碰，还是找到了它''以为安全''的虚处下手？"],"value_priorities":["智谋与态势 ＞ 兵力与蛮力（以少胜多靠的是奇正/地形/心理，不是拼人数）","不战而下 ＞ 强攻硬取（先声后实，能慑服则不硬打）","果断择虚速击 ＞ 正面持久消耗（避实击虚、半渡而击，不与强点缠斗）"],"blind_spots":["极擅军事、极拙政治：功高震主却不善自处，在''反与不反''间犹豫贻误，终被吕后诱杀于长乐宫钟室（《史记》，A）","其奇险战法高度依赖统帅本人天才与临场判断，可复制性、可传授性低（推断，B）","''置之死地''是高风险手段，成则封神、败则全军覆没，对手若识破或己方士气不足即可能反噬（学理推断，B）","重攻取与战役决胜，对政治结盟、君臣关系经营几乎无感——军事天才与政治幼稚并存（史实，A/B）"],"applicable_domains":["战略","竞争博弈","危机应对","资源调度"],"match_tags":["战略","竞争博弈","危机应对","资源调度","对抗性思维","直觉决断","古代东亚"],"linked_cases":["hanxin-c1","hanxin-c2","hanxin-c3","hanxin-c4"],"life_tags":[{"tag":"背水破赵","tier":"secondary"},{"tag":"还定三秦","tier":"secondary"},{"tag":"受胯下之辱","tier":"secondary"},{"tag":"登坛拜将","tier":"secondary"}],"voice_profile":{"notes":"简练果决；善以兵法格言点睛；重谋略推演；言兵透彻而言身世落寞"},"references":[{"ref_id":"hanxin-s1","title":"《史记·淮阴侯列传》","locator":"井陉背水/潍水囊沙/下燕先声后实/多多益善/被诱杀诸段","source_tier":"primary","supports_models":["置之死地而后生","奇正并用·背水设伏","多多益善·因材编组","先声后实·不战收城","避实击虚·攻其无备"],"supports_cases":["hanxin-c1","hanxin-c3","hanxin-c4"],"note":"司马迁一手详载韩信个人指挥与言论，本卡历史性核心来源"},{"ref_id":"hanxin-s2","title":"《史记·高祖本纪》","locator":"还定三秦","source_tier":"secondary","supports_cases":["hanxin-c2"],"note":"还定三秦为信史；\"明修栈道暗度陈仓\"具体计谋归属含后世演绎，故C2存疑"},{"ref_id":"hanxin-s3","title":"《史记·淮阴侯列传》(广武君策)","locator":"\"案甲休兵……先声而后实\"、下燕段","source_tier":"primary","supports_models":["先声后实·不战收城"],"note":"一手；先声后实之策与实践"}],"material_type":"rich","reasoning_skeleton":{"signature":"兵力劣势就用地形/绝境/规则设计逼出死战之力；一手''正''麻痹对手、一手''奇''抄其空虚；能靠声势不战而下就不硬攻，专择其''以为安全''的虚处下手","steps":[{"invoke":"先声后实·不战收城","action":"先问这一仗非打不可吗，能否靠已有声势与态势让对手不战而服"},{"invoke":"避实击虚·攻其无备","action":"若要打，别碰强点，找它''以为安全''的虚处下手、以诈佐战"},{"invoke":"置之死地而后生","action":"兵力劣势时，用地形/绝境把己方潜力逼出来（高风险，成则封神败则覆没）"},{"invoke":"奇正并用·背水设伏","action":"一手''正''吸住麻痹对手、一手''奇''抄其空虚断后，正奇夹击"},{"invoke":"多多益善·因材编组","action":"把手上参差的兵力/资源组织成可控整体、治众如治寡"}],"contrast":"与诸葛亮截然相反（都以弱势取胜、张力极大）：诸葛亮谨慎不弄险、拒子午谷、求稳律己；韩信专走险招、背水设伏、敢置之死地——同一道''该不该弄险''给出相反答案，是圆桌的绝佳对冲（见诸葛亮卡）。与孙子不同：孙子讲原理、慎战；韩信是把原理用到极致的实战大师、敢冒奇险（见孙子卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"hanxin-c1","note":"用户''兵力/资源悬殊、要不要搏一把绝境战法''时，以井陉之战·背水一战类比：他率新募之兵数万、夜遣两千轻骑换旗断后、万人背水列阵诱敌倾巢，以万余胜赵二十万——劣势可被精确的结构设计逆转（《史记》详载个人指挥，确证）"},{"source":"case","case_id":"hanxin-c4","note":"用户''我在专业上算无遗策、但处境/人际上呢''时，以功高不善自处终遭诱杀类比（反面镜子）：他军事上算赢所有的仗，政治上却在''反与不反''间犹豫、又轻信入宫，被诱杀于长乐宫钟室——一个领域的极致天才，可能在另一个领域极度幼稚（确证）"}]},"further_reading":[{"title":"《史记·淮阴侯列传》","why":"司马迁一手详载韩信个人指挥与言论，井陉/潍水/多多益善/被诱杀皆在此，是其历史性核心","type":"正史"},{"title":"《孙子兵法》","why":"对照读——看韩信如何把孙子''避实击虚/奇正/先胜''的原理用到实战极致","type":"original"},{"title":"楚汉战争通俗史（如《楚汉双雄》类）","why":"把韩信放回楚汉全局，理解其战役在天下棋局中的位置与其政治悲剧的由来","type":"解读"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/hanxin.png","avatar_thumb":"/advisors/portraits/hanxin.png","domain":"战略","person_id":"P-hanxin","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'c82b07e762dfb5ef38976c5ab61343367f8987b03b9f9bd12719579f35727c41', 39, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('helenkeller', 'P-helenkeller', '海伦·凯勒', 'history', '海伦·凯勒 · 认知重建与跨越障碍思维框架卡', '现代（1880—1968）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '命名即钥匙 · 替代通道', '/advisors/portraits/helenkeller.png', '/advisors/portraits/helenkeller.png', 5, 0, '{"schema_version":1,"card_id":"helenkeller","name":"海伦·凯勒","title":"海伦·凯勒 · 认知重建与跨越障碍思维框架卡","era":"现代（1880—1968）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"命名即钥匙","definition":"给一个事物一个名字，就拿到了通向整个概念世界的钥匙——符号不只是标签，而是理解与操纵世界的入口","source":"海伦·凯勒《我的生活故事》","source_tier":"primary","mechanism":"输入=面对一个模糊未分化的事物、抓不住 → 处理=给它一个名字/概念、拿到通向整个概念世界的钥匙 → 输出=符号成为理解与操纵世界的入口(井房''水''顿悟)","trigger":"面对模糊未命名的事物时","modern_transfer":"给一个事物一个清晰的名字/概念、就拿到了通向整个概念世界的钥匙——符号不只是标签、而是理解与操纵世界的入口(海伦在井房摸到流水、第一次懂得''水''这个词、整个语言世界由此打开)","architecture":{"type":"hierarchy","components":["面对模糊未分化的事物","给它一个名字概念","拿到通向概念世界的钥匙","符号成为理解世界的入口"]},"strategy_card_image":"kb-assets/helenkeller/model-1.png"},{"name":"替代通道","definition":"当主要感官/通道被堵死，不空等它恢复，而是系统地用尚可用的通道（触觉、嗅觉、振动）重建对世界的感知","source":"海伦·凯勒《我生活的世界》","source_tier":"primary","mechanism":"输入=主要感官/通道被堵死、空等它恢复 → 处理=不空等、系统地用尚可用的通道(触觉/嗅觉/振动)重建对世界的感知 → 输出=用可用通道绕过堵死的通道","trigger":"主要感官/通道被堵死时","modern_transfer":"当主要感官/通道被堵死、别空等它恢复——系统地用尚可用的通道(触觉、嗅觉、振动…)重建对世界的感知；别盯着缺失的、把还能用的用到极致","architecture":{"type":"flow","components":["主要通道被堵死","不空等它恢复","系统用尚可用的通道","重建对世界的感知"]},"strategy_card_image":"kb-assets/helenkeller/model-2.png"},{"name":"互赖即杠杆","definition":"把必要的依赖与帮助当作放大自己的杠杆与协作，而非羞耻或无能；主动编排\"中介\"以触及独力够不到的事","source":"海伦·凯勒《我的生活故事》及沙利文书信","source_tier":"primary","mechanism":"输入=把必要的依赖与帮助当耻辱或无能 → 处理=把它当作放大自己的杠杆与协作、主动编排''中介''以触及独力够不到的事 → 输出=善用帮助触及独力够不到的高度(与沙利文协作)","trigger":"需要依赖与帮助、又觉羞耻时","modern_transfer":"把必要的依赖与帮助当作放大自己的杠杆与协作、而非羞耻或无能——主动编排能帮你的人/工具，去触及你独力够不到的事(海伦与沙利文的长期协作)","architecture":{"type":"flow","components":["别把求助当耻辱","把依赖与帮助当杠杆","主动编排中介","触及独力够不到的事"]},"strategy_card_image":"kb-assets/helenkeller/model-3.png"},{"name":"经验公共化","definition":"把个人的困境与经验转化为公共倡导的平台，从\"如何自处\"走向\"为同类争取系统性改变\"","source":"权威传记及倡导史料","source_tier":"secondary","mechanism":"输入=把困境只当个人的''如何自处'' → 处理=把个人的困境与经验转化为公共倡导的平台、为同类争取系统性改变 → 输出=从一人扩到一群(投身盲聋权益)","trigger":"个人克服了困境、想让影响更大时","modern_transfer":"把个人的困境与经验转化为公共倡导的平台——从''我如何自处''走向''为同类争取系统性改变''，让影响从一人扩到一群(海伦投身盲聋权益与社会倡导)","architecture":{"type":"hierarchy","components":["别把困境只当个人自处","转化为公共倡导平台","为同类争取系统性改变","影响从一人扩到一群"]},"strategy_card_image":"kb-assets/helenkeller/model-4.png"},{"name":"想象补经验","definition":"用想象、类比与对他人证言的信任，去构建直接感官够不到的知识（颜色、声音、远景）","source":"海伦·凯勒《我生活的世界》","source_tier":"primary","mechanism":"输入=直接感官够不到的知识(颜色/声音/远景)、就当不存在 → 处理=用想象、类比与对他人证言的信任去构建 → 输出=补上直接经验够不到的部分","trigger":"直接经验够不到某种知识时","modern_transfer":"直接经验够不到的知识(你没见过的颜色、没听过的声音、没去过的远景)、用想象、类比与对他人证言的信任去构建——别因够不到就当它不存在(海伦以类比/想象重构色彩与声音)","architecture":{"type":"flow","components":["直接经验够不到的知识","用想象与类比","借对他人证言的信任","补上够不到的部分"]},"strategy_card_image":"kb-assets/helenkeller/model-5.png"}],"decision_principles":["先给陌生事物一个名字/概念，再谈理解与掌控","别盯着缺失的通道，把尚能用的感官用到极致","把求助当杠杆而非耻辱，主动编排能帮你的人","把私人困境转成为同类发声的公共行动","直接经验够不到的，用想象+类比+他人证言去补"],"inquiry_questions":["你卡住的这件事，先给它一个清晰的名字/定义了吗？","你是在等那个堵死的通道恢复，还是在用还能用的去绕过它？","你把''需要帮忙''当成了耻辱，还是当成可编排的杠杆？","你的困境，有没有可能变成为更多同类发声的起点？","你够不到的那部分，能不能靠想象、类比和别人的描述去补？"],"value_priorities":["用可用通道重建 ＞ 等待缺失通道恢复（等待是被动、绕行是主动；先用你有的）","互赖协作 ＞ 凡事独力自证（善用帮助能触及独力够不到的高度、不是软弱）","公共倡导 ＞ 私人化的自我克服（把经验公共化、影响从一人扩到一群）"],"blind_spots":["其突破高度依赖一位卓越导师（安妮·沙利文）的长期投入与一定的社会资源，并非纯靠个人意志，不应被简化为''意志万能''的励志模板（史实，B）。","''替代通道''依赖确实还有可用的通道；并非所有障碍都有可替代的解（原理推断，B）。","''想象补经验''构建的知识终究是间接的、可能与实际有偏差，须对此保持自觉（原理推断，B）。","〔注意〕其晚年部分社会政治主张有争议；与本卡的''认知重建''方法无关、不展开（客观标注，B）。"],"applicable_domains":["逆境应对","学习与认知","修身自省","价值与伦理"],"match_tags":["逆境应对","学习与认知","修身自省","价值与伦理","务实渐进","第一性原理","利他取向","现当代北美"],"linked_cases":["helenkeller-c1","helenkeller-c2","helenkeller-c3","helenkeller-c4"],"life_tags":[{"tag":"著我的生活","tier":"primary"},{"tag":"获大学学位","tier":"secondary"},{"tag":"投身助残","tier":"secondary"},{"tag":"全球巡回演讲","tier":"secondary"}],"voice_profile":{"notes":"明亮坚韧、富感受力；以触觉与想象描摹世界；感恩协作；为弱势发声"},"references":[{"ref_id":"helenkeller-s1","title":"海伦·凯勒《我的生活故事》","locator":"井房顿悟、与沙利文协作、求学","source_tier":"primary","supports_models":["命名即钥匙","互赖即杠杆"],"supports_cases":["helenkeller-c1","helenkeller-c3"],"note":"一手自传"},{"ref_id":"helenkeller-s2","title":"海伦·凯勒《我生活的世界》","locator":"以触/嗅/振动感知、以想象类比重构色彩声音","source_tier":"primary","supports_models":["替代通道","想象补经验"],"supports_cases":["helenkeller-c2"],"note":"一手记述"},{"ref_id":"helenkeller-s3","title":"权威传记/倡导史料","locator":"投身盲聋权益与社会倡导","source_tier":"secondary","supports_models":["经验公共化"],"supports_cases":["helenkeller-c4"],"note":"二手传记/史料"}],"material_type":"rich","reasoning_skeleton":{"signature":"先给陌生事物一个清晰的名字/概念、拿到通向概念世界的钥匙(命名即钥匙)；主通道被堵死就用尚可用的通道重建感知、别盯着缺失的(替代通道)；把必要的依赖与帮助当杠杆而非耻辱、主动编排中介(互赖即杠杆)；把私人困境转成为同类发声的公共行动(经验公共化)；直接经验够不到的用想象类比与他人证言去补(想象补经验)","steps":[{"invoke":"命名即钥匙","action":"你卡住的这件事，先给它一个清晰的名字/定义了吗？"},{"invoke":"替代通道","action":"你是在等那个堵死的通道恢复，还是在用还能用的去绕过它？"},{"invoke":"互赖即杠杆","action":"你把''需要帮忙''当成了耻辱，还是当成可编排的杠杆？"},{"invoke":"经验公共化","action":"你的困境，有没有可能变成为更多同类发声的起点？"},{"invoke":"想象补经验","action":"你够不到的那部分，能不能靠想象、类比和别人的描述去补？"}],"contrast":"与弗兰克尔不同(关键差异·同为逆境)：**弗兰克尔是意义疗法——在苦难中''找到意义''、行使选择态度的自由**；**海伦凯勒是认知重建——''命名即钥匙、替代通道、互赖即杠杆''、用可用通道重建与世界的连接**——弗兰克尔靠''意义''、海伦靠''重建感知与连接''(见弗兰克尔卡)。与沙克尔顿不同：沙克尔顿是绝境中''把全员带活''的领导(向外领导一群人)；海伦是''重建个人与世界的认知连接''(向内重建自己)(见沙克尔顿卡)。与马可奥勒留不同：奥勒留是斯多葛控制二分(接受不可控)；海伦是主动用替代通道重建可控的连接(见马可奥勒留卡)。【射程/盲区】海伦之道在''重建认知连接、绕过堵死的通道、把求助当杠杆、把经验公共化''极有力，但①其突破高度依赖一位卓越导师(沙利文)的长期投入与社会资源、并非纯靠个人意志、不应简化为''意志万能''的励志模板；②''替代通道''依赖确实还有可用的通道、并非所有障碍都有替代解；③''想象补经验''构建的是间接知识、可能有偏差。适用逆境应对/学习与认知/修身自省/价值与伦理；不适用竞争博弈/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"helenkeller-c1","note":"用户''被一团模糊、说不清的困惑卡住、无从下手''时，以海伦井房''水''顿悟类比：在沙利文把''water''拼写在她手心、同时让流水冲过她另一只手的瞬间、她第一次懂得''水''这个词指什么——一个清晰的名字打开了整个语言与概念的世界；先给模糊的东西一个名字/定义，是理解与掌控的入口（井房顿悟为其《我的生活故事》明载→确证）"},{"source":"case","case_id":"helenkeller-c3","note":"用户''觉得需要别人帮忙是种耻辱、凡事都想独力自证''时，以海伦与沙利文的长期协作类比：海伦不把对沙利文的依赖当作无能、而是把它当作放大自己的杠杆与协作、借此完成大学学业与写作——善用帮助能触及你独力够不到的高度（与沙利文的长期协作为其自传与书信所载→确证）"}]},"further_reading":[{"title":"海伦·凯勒《我的生活故事》(The Story of My Life)","why":"井房顿悟、与沙利文协作、求学历程的一手自传（A）","type":"original"},{"title":"海伦·凯勒《我生活的世界》(The World I Live In)","why":"以触/嗅/振动感知、以想象类比重构色彩声音的一手记述（A）","type":"original"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/helenkeller.png","avatar_thumb":"/advisors/portraits/helenkeller.png","domain":"历史","person_id":"P-helenkeller","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'a1febc533a76c83e8e86995f066513c1f374ffd723e4f8c88d415058dc088f8d', 40, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('hemingway', 'P-hemingway', '海明威', 'writing', '海明威 · 冰山理论与极简表达思维框架卡', '现代（1899—1961）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '冰山理论 · 简洁有力的表达', '/advisors/portraits/hemingway.png', '/advisors/portraits/hemingway.png', 5, 0, '{"schema_version":1,"card_id":"hemingway","name":"海明威","title":"海明威 · 冰山理论与极简表达思维框架卡","era":"现代（1899—1961）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"冰山理论","definition":"不必把什么都说尽——只呈现\"八分之一\"，把更深的含义藏在水面之下（靠省略与留白），让对方自己去感受","source":"海明威\"冰山理论\"（《午后之死》）","source_tier":"primary","mechanism":"输入=把什么都说尽 → 处理=只呈现''八分之一''、把深意藏在水面下、靠省略留白 → 输出=说得少反而更有力(冰山)","trigger":"表达/呈现一件事、考虑说多少时","modern_transfer":"不必把什么都说尽——只呈现''八分之一''、把更深的含义藏在水面之下(靠省略与留白)、让对方自己去感受;说得少反而更有力(海明威冰山理论)〔但留白用不好会变晦涩、见盲区〕","architecture":{"type":"hierarchy","components":["别把什么都说尽","只呈现八分之一","把更深的含义藏在水面下","靠省略留白让对方感受"]},"strategy_card_image":"kb-assets/hemingway/model-1.png"},{"name":"简洁有力的表达","definition":"删去一切多余的形容、副词与修饰，用简短、具体、有力的句子表达——简洁本身就是力量","source":"海明威的文风","source_tier":"primary","mechanism":"输入=堆砌形容副词修饰、啰嗦 → 处理=删去多余修饰、用简短具体有力的句子 → 输出=简洁即力量(简洁表达)","trigger":"要让表达有力时","modern_transfer":"删去一切多余的形容、副词与修饰、用简短、具体、有力的句子表达——简洁本身就是力量、啰嗦稀释力量(海明威的简洁文风)","architecture":{"type":"flow","components":["别堆砌形容副词修饰啰嗦","删去多余修饰","用简短具体有力的句子","简洁即力量"]},"strategy_card_image":"kb-assets/hemingway/model-2.png"},{"name":"用具体动作与细节代替抽象","definition":"别直接说抽象的情绪/结论，用具体的动作、感官的细节去呈现，让对方自己感受到（\"展示而非说教\"）","source":"海明威\"show not tell\"","source_tier":"primary","mechanism":"输入=直接说抽象的情绪/结论 → 处理=用具体的动作、感官细节呈现、让对方自己得出感受 → 输出=展示而非说教(具体细节)","trigger":"要传达情绪/让人信服时","modern_transfer":"别直接说抽象的情绪/结论(如''他很悲伤'')——用具体的动作、感官的细节去呈现、让对方自己感受到(''展示而非说教''show not tell)(海明威)","architecture":{"type":"flow","components":["别直接说抽象的情绪结论","用具体的动作与感官细节","去呈现","让对方自己得出感受"]},"strategy_card_image":"kb-assets/hemingway/model-3.png"},{"name":"重压下的优雅","definition":"在压力、困境甚至注定的失败面前，保持尊严、镇定与不被击垮的风度——\"人可以被毁灭，但不能被打败\"","source":"海明威\"grace under pressure\"","source_tier":"primary","mechanism":"输入=压力困境失败前崩溃失态 → 处理=在压力、困境、失败面前保持尊严、镇定与风度 → 输出=可被毁灭不可被打败(重压优雅)","trigger":"面对压力、困境甚至注定的失败时","modern_transfer":"在压力、困境甚至注定的失败面前、保持尊严、镇定与不被击垮的风度——''人可以被毁灭、但不能被打败''(海明威''重压下的优雅''grace under pressure、《老人与海》)","architecture":{"type":"flow","components":["别在压力困境失败前崩溃失态","在压力困境失败面前","保持尊严镇定与风度","可被毁灭不可被打败"]},"strategy_card_image":"kb-assets/hemingway/model-4.png"},{"name":"写你真正懂的真实的","definition":"只写（只做）你真正经历过、真正懂的东西，追求最本质的真实与诚实——别硬写你不懂的、不真的东西","source":"海明威\"write what you know\"","source_tier":"primary","mechanism":"输入=硬写你不懂、不真的东西 → 处理=只写自己真正经历、真正懂的、追求最本质的真实与诚实 → 输出=情感的真实(写真实的)","trigger":"要创作/表达、追求真实可信时","modern_transfer":"只写(只做)你真正经历过、真正懂的东西、追求最本质的真实与诚实——别硬写你不懂的、不真的东西(海明威''写你知道的最真实的那个句子'')","architecture":{"type":"flow","components":["别硬写你不懂不真的东西","只写你真正经历真正懂的","追求最本质的真实与诚实","情感的真实"]},"strategy_card_image":"kb-assets/hemingway/model-5.png"}],"decision_principles":["只呈现八分之一，把更深的含义藏在水面下，让对方自己感受","删去一切多余的形容与修饰，用简短、具体、有力的句子","用具体的动作与感官细节呈现，而非直接说抽象的情绪","在压力、困境、失败面前，保持尊严、镇定与风度","只写你真正经历、真正懂的，追求最本质的真实"],"inquiry_questions":["你是把什么都说尽、还是只呈现八分之一、把深意藏在水面下靠省略让对方感受？","你的表达是堆砌形容副词、还是删尽多余、用简短具体有力的句子？","你是直接说抽象的情绪结论、还是用具体动作与感官细节让对方自己感受？","在压力困境失败面前，你是崩溃失态、还是保持尊严镇定与风度？","你是硬写不懂不真的、还是只写真正经历真正懂的、追求本质的真实？"],"value_priorities":["省略留白的余味 ＞ 把什么都说尽（冰山理论）","简洁的力量 ＞ 啰嗦的修饰（删尽多余形容副词）","具体的展示 ＞ 抽象的陈述（show not tell）"],"blind_spots":["极简/省略的风格不适合需要充分解释、复杂论证、丰富铺陈的场合（原理推断，B）。","''冰山''留白若用不好，会变成晦涩、读者get不到水下的部分（原理推断，B）。","其''硬汉''的''重压下优雅''有时被批评为一种回避深层情感、男性气概的局限（原理推断，B）。","简洁有力的风格用于不当场合（如需要温度、细腻、复杂的表达）会显得冷硬（原理推断，B）。"],"applicable_domains":["表达说服","创作","修身自省"],"match_tags":["表达说服","创作","修身自省","极简主义","务实渐进","批判思辨","现当代北美"],"linked_cases":["hemingway-c1","hemingway-c2","hemingway-c3","hemingway-c4"],"life_tags":[{"tag":"著老人与海","tier":"primary"},{"tag":"获诺贝尔奖","tier":"secondary"},{"tag":"任战地记者","tier":"secondary"},{"tag":"获普利策奖","tier":"secondary"}],"voice_profile":{"notes":"简洁克制、电报文体；具体而有力；省略留白；冷静坚韧"},"references":[{"ref_id":"hemingway-s1","title":"海明威《老人与海》《永别了，武器》《午后之死》及其文论","locator":"冰山理论、简洁文风、重压下的优雅、写真实","source_tier":"primary","supports_models":["冰山理论","简洁有力的表达","用具体动作与细节代替抽象","重压下的优雅","写你真正懂的真实的"],"supports_cases":["hemingway-c1","hemingway-c2","hemingway-c3","hemingway-c4"],"note":"一手·原著/文论"},{"ref_id":"hemingway-s2","title":"海明威研究","locator":"冰山理论、极简文风","source_tier":"secondary","supports_models":["冰山理论","简洁有力的表达"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"只呈现八分之一把深意藏在水面下靠省略留白(冰山理论)；删尽多余修饰用简短具体有力的句子(简洁有力的表达)；用具体动作与感官细节呈现而非直接说抽象情绪(用具体动作与细节代替抽象)；压力困境失败前保持尊严镇定与风度(重压下的优雅)；只写你真正经历真正懂的追求本质的真实(写你真正懂的真实的)","steps":[{"invoke":"冰山理论","action":"你是把什么都说尽、还是只呈现八分之一、把深意藏在水面下靠省略让对方感受？"},{"invoke":"简洁有力的表达","action":"你的表达是堆砌形容副词、还是删尽多余、用简短具体有力的句子？"},{"invoke":"用具体动作与细节代替抽象","action":"你是直接说抽象的情绪结论、还是用具体动作与感官细节让对方自己感受？"},{"invoke":"重压下的优雅","action":"在压力困境失败面前，你是崩溃失态、还是保持尊严镇定与风度？"},{"invoke":"写你真正懂的真实的","action":"你是硬写不懂不真的、还是只写真正经历真正懂的、追求本质的真实？"}],"contrast":"与莎士比亚不同(关键差异·表达的两极)：**莎士比亚是''丰富''——丰盛的语言、繁复的意象、戏剧的冲突**；**海明威是''极简''——删尽修饰、冰山留白、简洁有力**——一个以繁盛直击、一个以省略留白(见莎士比亚卡)。与奥威尔不同：奥威尔的简洁是''为政治清晰服务''(让思想不被含混的语言遮蔽);海明威的简洁是''为情感真实与力量服务''(用省略让读者自己感受)(见奥威尔卡)。与狄更斯不同：狄更斯繁复铺陈、人物群像、社会全景;海明威极简留白、聚焦个体、冰山深藏(见狄更斯卡)。与马克吐温不同：马克吐温幽默讽刺、方言口语;海明威冷静克制、电报文体(见马克吐温卡)。【射程/盲区】海明威之道在''冰山理论、简洁表达、具体细节、重压优雅、写真实''极有力(尤其表达、文风、面对困境的态度)，但①极简/省略不适合需要充分解释、复杂论证、丰富铺陈的场合;②''冰山''留白若用不好会变晦涩、读者get不到水下;③其''硬汉''的''重压下优雅''有时被批为回避深层情感、男性气概的局限;④简洁风格用于不当场合(需温度细腻复杂时)会显得冷硬。适用表达说服/创作/修身自省;不适用投资/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"hemingway-c1","note":"用户''想把一件事/一个表达讲得有力、却忍不住把什么都说尽、解释过度''时，以海明威冰山理论类比：他说一篇好作品像冰山、露出水面的只有八分之一、其余的力量都藏在水下;不必把什么都说尽——只呈现最关键的一小部分、把更深的含义靠省略与留白留给对方自己去感受、说得少反而更有力（冰山理论为海明威《午后之死》所提→确证）〔但留白要适度、用不好会晦涩〕"},{"source":"case","case_id":"hemingway-c3","note":"用户''面对压力、困境、甚至注定的失败、想知道该以什么姿态去面对''时，以海明威''重压下的优雅''类比：《老人与海》里的老人虽然最终只带回一副鱼骨、却始终保持着尊严与不屈——''人可以被毁灭、但不能被打败'';在压力、困境甚至失败面前、保持尊严、镇定与不被击垮的风度（grace under pressure为海明威主题、《老人与海》→确证）"}]},"further_reading":[{"title":"海明威《老人与海》《永别了，武器》《午后之死》等","why":"冰山理论、简洁文风、重压下的优雅、写真实的一手出处（A）","type":"original"},{"title":"海明威研究","why":"对其冰山理论与极简文风的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/hemingway.png","avatar_thumb":"/advisors/portraits/hemingway.png","domain":"创作","person_id":"P-hemingway","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '1c88cf12b0523bd54b4920689127b6d3003154a1094c41b1a38e8330b9d64f08', 41, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('honda', 'P-honda', '本田宗一郎', 'business', '本田宗一郎 · 技术实干与不怕失败思维框架卡', '现代（1906—1991）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '技术第一亲手实干 · 三个喜悦', '/advisors/portraits/honda.png', '/advisors/portraits/honda.png', 5, 0, '{"schema_version":1,"card_id":"honda","name":"本田宗一郎","title":"本田宗一郎 · 技术实干与不怕失败思维框架卡","era":"现代（1906—1991）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"技术第一亲手实干","definition":"做技术就亲自下场、把技术钻到底、用实打实的技术说话，而非脱离一线靠管理指挥","source":"本田宗一郎传记/语录","source_tier":"secondary","mechanism":"输入=做技术却脱离一线、靠管理指挥 → 处理=工程师亲自下场、把技术钻到底、用技术实力说话 → 输出=技术第一、亲手做出来","trigger":"做技术/产品、要不要亲自下场时","modern_transfer":"做技术/产品就亲自下场、把技术钻到底、用实打实的技术说话——而非脱离一线靠管理指挥(本田宗一郎一生以工程师自居、亲自蹲车间解决技术难题)","architecture":{"type":"flow","components":["做技术却脱离一线靠指挥","工程师亲自下场","把技术钻到底","用技术实力说话"]},"strategy_card_image":"kb-assets/honda/model-1.png"},{"name":"三个喜悦","definition":"让\"买的人、卖的人、造的人\"三方都获得喜悦，而非只盯自己赚钱","source":"本田技研\"三个喜悦\"理念","source_tier":"secondary","mechanism":"输入=只盯自己赚钱 → 处理=让''买的人、卖的人、造的人''三方都获得喜悦 → 输出=三方共赢的价值","trigger":"定义产品/事业的价值时","modern_transfer":"让''买的人、卖的人、造的人''三方都获得喜悦——而非只盯自己赚钱；三方共赢的价值才长久(本田''三个喜悦'')","architecture":{"type":"hierarchy","components":["别只盯自己赚钱","买的人喜悦","卖的人喜悦","造的人喜悦"]},"strategy_card_image":"kb-assets/honda/model-2.png"},{"name":"不怕失败的试错","definition":"把失败当作通往成功的必经之路——\"我的成功是99%的失败堆出来的\"，快速试错迭代","source":"本田宗一郎语录","source_tier":"secondary","mechanism":"输入=怕失败、不敢试 → 处理=把失败当通往成功的必经、快速试错迭代 → 输出=在大量失败中逼出成功(99%失败)","trigger":"面对不确定、怕失败不敢试时","modern_transfer":"把失败当作通往成功的必经之路——''我所谓的成功、是由99%的失败堆出来的'';别怕失败、快速试错迭代(本田宗一郎)〔但试错代价高、见盲区〕","architecture":{"type":"loop","components":["怕失败不敢试","把失败当通往成功的必经","快速试错迭代","在大量失败中逼出成功"]},"strategy_card_image":"kb-assets/honda/model-3.png"},{"name":"挑战极限立品牌","definition":"到最高难度的擂台上（赛车/技术极限）用硬实力证明自己，而非靠说辞——挑战极限的胜利最能立品牌","source":"本田挑战赛车（曼岛TT/F1）史","source_tier":"secondary","mechanism":"输入=靠说辞证明实力 → 处理=到最高难度的擂台(赛车/技术极限)上用硬实力证明 → 输出=以极限挑战的胜利立品牌","trigger":"要证明实力/立品牌时","modern_transfer":"到最高难度的擂台上(赛车/技术极限)用硬实力证明自己、而非靠说辞——挑战极限的胜利最能立起品牌(本田闯曼岛TT与F1赛场)〔耗资巨大、须有实力支撑〕","architecture":{"type":"flow","components":["别靠说辞证明实力","到最高难度的擂台","用硬实力证明","以极限胜利立品牌"]},"strategy_card_image":"kb-assets/honda/model-4.png"},{"name":"专业分工授权","definition":"认清自己最强的那一块、把自己不擅长的放心交给真正专业的人——各专所长、合力更强","source":"本田与藤泽武夫的搭档史","source_tier":"secondary","mechanism":"输入=一个人什么都管、什么都不精 → 处理=认清自己最强的(技术)、把不擅长的(经营)交给专业的人 → 输出=各专所长、合力更强","trigger":"自己有明显长短板、要不要授权时","modern_transfer":"认清自己最强的那一块(本田=技术)、把自己不擅长的(经营/财务)放心交给真正专业的人(藤泽武夫)——各专所长、合力远强于一个人硬撑全部","architecture":{"type":"hierarchy","components":["别一个人什么都管","认清自己最强的那块","把不擅长的交给专业的人","各专所长合力更强"]},"strategy_card_image":"kb-assets/honda/model-5.png"}],"decision_principles":["做技术就亲自下场、把技术钻到底，用实打实的技术说话","让买的、卖的、造的三方都获得喜悦，而非只盯自己赚钱","把失败当通往成功的必经之路、快速试错迭代（但试错代价高）","到最高难度的擂台上用硬实力证明、立品牌","认清自己最强的、把不擅长的放心交给专业的人"],"inquiry_questions":["你是亲自下场把技术钻到底，还是脱离一线靠管理指挥？","这件事是只让你自己赚，还是让买的、卖的、造的人都获得喜悦？","你是怕失败不敢试，还是把失败当通往成功的必经、快速试错？","你是靠说辞证明实力，还是到最高难度的擂台上用硬实力证明？","你是什么都自己管，还是认清自己最强的、把不擅长的交给专业的人？"],"value_priorities":["亲手实干的技术 ＞ 脱离一线的指挥（一生以工程师自居、亲自蹲车间）","三方共赢 ＞ 只顾自己赚钱（买的、卖的、造的三个喜悦）","快速试错 ＞ 因怕失败而不试（成功是99%的失败堆出来的（但代价高））"],"blind_spots":["''亲手实干+技术第一''以创始人本人有过硬技术为前提；非技术背景者难照搬（原理推断，B）。","''99%失败的试错''代价高，对资源有限或容错低的领域危险，不是''失败越多越好''（原理推断，B）。","其偏技术与产品，对资本运作、财务、规模化管理着力少——恰恰靠藤泽武夫补上，印证了专业分工（史实，B）。","挑战极限（赛车）耗资巨大，须有相当实力支撑，非任何阶段都适合（原理推断，B）。"],"applicable_domains":["创新研发","创业","领导力"],"match_tags":["创新研发","创业","领导力","实验试错","第一性原理","务实渐进","现当代东亚"],"linked_cases":["honda-c1","honda-c2","honda-c3","honda-c4"],"life_tags":[{"tag":"创办本田","tier":"secondary"},{"tag":"称霸曼岛赛","tier":"secondary"},{"tag":"以技术立品牌","tier":"secondary"},{"tag":"进军F1赛","tier":"secondary"}],"voice_profile":{"notes":"直率火爆、痴迷技术；亲力亲为；不服输、敢挑战；重实干轻虚名"},"references":[{"ref_id":"honda-s1","title":"本田宗一郎传记与语录","locator":"技术实干、三个喜悦、99%失败","source_tier":"secondary","supports_models":["技术第一亲手实干","三个喜悦","不怕失败的试错"],"supports_cases":["honda-c1","honda-c2"],"note":"二手·传记/语录"},{"ref_id":"honda-s2","title":"本田技研赛车征战史","locator":"曼岛TT、F1","source_tier":"secondary","supports_models":["挑战极限立品牌"],"supports_cases":["honda-c3"],"note":"二手·企业史"},{"ref_id":"honda-s3","title":"本田与藤泽武夫搭档史","locator":"技术与经营的分工","source_tier":"secondary","supports_models":["专业分工授权"],"supports_cases":["honda-c4"],"note":"二手·企业史"}],"material_type":"rich","reasoning_skeleton":{"signature":"做技术就亲自下场把技术钻到底、用技术说话(技术第一亲手实干)；让买的卖的造的三方都喜悦(三个喜悦)；把失败当通往成功的必经、99%失败堆出成功(不怕失败的试错)；到最高难度擂台用硬实力立品牌(挑战极限立品牌)；认清自己最强的、把不擅长的交给专业的人(专业分工授权)","steps":[{"invoke":"技术第一亲手实干","action":"你是亲自下场把技术钻到底，还是脱离一线靠管理指挥？"},{"invoke":"三个喜悦","action":"这件事是只让你自己赚，还是让买的、卖的、造的人都获得喜悦？"},{"invoke":"不怕失败的试错","action":"你是怕失败不敢试，还是把失败当通往成功的必经、快速试错？"},{"invoke":"挑战极限立品牌","action":"你是靠说辞证明实力，还是到最高难度的擂台上用硬实力证明？"},{"invoke":"专业分工授权","action":"你是什么都自己管，还是认清自己最强的、把不擅长的交给专业的人？"}],"contrast":"与松下幸之助不同(关键差异·同为日本制造业)：**松下是''量产普及+经营哲学(自来水哲学/事业部制)''的经营家**；**本田是''技术第一、亲手实干、不怕失败试错''的工匠创业者**——松下重经营与普及、本田重技术与实干(见松下卡)。与盛田昭夫不同(同为日本制造业)：盛田是''创造市场、全球营销、品牌优先''的营销创新者；本田是''埋头钻技术、用赛车证明实力''的工程师(见盛田卡)。与稻盛和夫不同：稻盛是''阿米巴+敬天爱人''的哲学经营；本田是''技术工匠+99%失败试错''(见稻盛卡)。【射程/盲区】本田之道在''技术实干、三个喜悦、不怕失败、挑战极限、专业分工''极有力，但①''亲手实干+技术第一''以创始人本人有过硬技术为前提、非技术背景者难照搬；②''99%失败的试错''代价高、对资源有限或容错低的领域危险、不是''失败越多越好'';③其偏技术与产品、对资本运作/财务/规模化管理着力少(恰靠藤泽武夫补上、印证专业分工);④挑战极限(赛车)耗资巨大、须有实力支撑。适用创新研发/创业/领导力；不适用投资/危机应对。"},"persona_anchor":{"primary":[{"source":"case","case_id":"honda-c2","note":"用户''因为怕失败而迟迟不敢试、或被一连串失败打垮''时，以本田的试错观类比：本田说''我所谓的成功、是由99%的失败堆出来的''——他把失败当作通往成功的必经工序、在大量失败中快速迭代逼出成功(但须知试错代价高、非''失败越多越好'')（''99%失败''为本田著名语→确证）"},{"source":"case","case_id":"honda-c4","note":"用户''什么都想自己抓、却样样不精、被自己不擅长的事拖垮''时，以本田与藤泽武夫的搭档类比：本田认清自己最强的是技术、把经营与财务全权交给藤泽武夫——各专所长、合力远强于一个人硬撑全部（本田与藤泽的分工为史实→确证）"}]},"further_reading":[{"title":"本田宗一郎传记与语录","why":"技术实干、三个喜悦、99%失败、与藤泽武夫搭档的记述（B）","type":"传记/语录"},{"title":"本田技研（Honda）史与赛车征战史","why":"挑战曼岛TT、进军F1立品牌的记录（B）","type":"企业史"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/honda.png","avatar_thumb":"/advisors/portraits/honda.png","domain":"商业","person_id":"P-honda","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '3cd6953b650c144acba4d025e605c034bf6c98b581dad9a7d5a5d5a2b3170a00', 42, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('hugo', 'P-hugo', '雨果', 'writing', '雨果 · 浪漫主义与社会良心思维框架卡', '近代（1802—1885）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '美丑对照 · 为弱者与受苦者发声', '/advisors/portraits/hugo.png', '/advisors/portraits/hugo.png', 5, 0, '{"schema_version":1,"card_id":"hugo","name":"雨果","title":"雨果 · 浪漫主义与社会良心思维框架卡","era":"近代（1802—1885）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"美丑对照","definition":"把美与丑、崇高与卑劣强烈地并置、对照——在鲜明的反差中，各自的力量都被凸显放大","source":"雨果《巴黎圣母院》","source_tier":"primary","mechanism":"输入=平淡呈现、力量不彰 → 处理=把美与丑、崇高与卑劣强烈并置对照、在反差中凸显各自力量 → 输出=反差凸显放大(美丑对照)","trigger":"要凸显某种特质/力量时","modern_transfer":"把美与丑、崇高与卑劣强烈地并置、对照——在鲜明的反差中、各自的力量都被凸显放大(''美丑对照''、雨果《巴黎圣母院》外丑内美的卡西莫多)","architecture":{"type":"grid","components":["别平淡呈现力量不彰","把美与丑崇高与卑劣","强烈并置对照","在反差中凸显各自力量"]},"strategy_card_image":"kb-assets/hugo/model-1.png"},{"name":"为弱者与受苦者发声","definition":"把你的关注、同情与表达，给予那些最弱小、最受苦、被忽视与被损害的人——为没有声音的人发声","source":"雨果《悲惨世界》","source_tier":"primary","mechanism":"输入=只关注强者/主流、忽视底层 → 处理=把关注同情表达给最弱小受苦被损害的人 → 输出=为没有声音的人发声(为弱者发声)","trigger":"选择把关注与同情给谁时","modern_transfer":"把你的关注、同情与表达、给予那些最弱小、最受苦、被忽视与被损害的人——为没有声音的人发声(雨果《悲惨世界》写冉阿让、芳汀)","architecture":{"type":"flow","components":["别只关注强者主流忽视底层","把关注同情与表达","给予最弱小最受苦被损害的人","为没有声音的人发声"]},"strategy_card_image":"kb-assets/hugo/model-2.png"},{"name":"以情动人的激情","definition":"用充沛、热烈、磅礴的情感与激情去打动人、感染人——以情动人、点燃共鸣","source":"雨果的浪漫主义","source_tier":"primary","mechanism":"输入=冷静克制、不够打动人 → 处理=用充沛热烈磅礴的情感与激情打动感染人 → 输出=点燃共鸣(激情)","trigger":"要打动人、点燃共鸣时","modern_transfer":"用充沛、热烈、磅礴的情感与激情去打动人、感染人——以情动人、点燃共鸣(雨果的浪漫主义激情)〔但过度则流于煽情、滥情、见盲区〕","architecture":{"type":"flow","components":["别冷静克制不够打动人","用充沛热烈磅礴的情感与激情","打动感染人","点燃共鸣"]},"strategy_card_image":"kb-assets/hugo/model-3.png"},{"name":"人道主义的信念","definition":"即使在最黑暗、最绝望处，也保有对人性之善与救赎之可能的信念——相信人能向善、光明终会到来","source":"雨果的人道主义","source_tier":"primary","mechanism":"输入=在黑暗绝望处放弃对善的信念 → 处理=即使最黑暗处也保有对人性之善与救赎之可能的信念 → 输出=相信人能向善光明终至(人道主义)","trigger":"面对黑暗、绝望、人性之恶时","modern_transfer":"即使在最黑暗、最绝望处、也保有对人性之善与救赎之可能的信念——相信人能向善、光明终会到来(雨果的人道主义、冉阿让被主教感化而向善)","architecture":{"type":"flow","components":["别在黑暗绝望处放弃对善的信念","即使最黑暗处","也保有对人性之善与救赎之可能的信念","相信人能向善光明终至"]},"strategy_card_image":"kb-assets/hugo/model-4.png"},{"name":"把个体故事接入宏大的社会议题","definition":"通过一个具体个体的命运故事，去承载并推动对宏大社会议题（不公、贫困、法律、革命）的关注与思考","source":"雨果《悲惨世界》","source_tier":"primary","mechanism":"输入=个体故事只停在个人层面 → 处理=通过个体命运承载推动对宏大社会议题(不公贫困法律)的关注 → 输出=个体成社会议题的载体(接社会议题)","trigger":"要让个体故事承载更大社会意义时","modern_transfer":"通过一个具体个体的命运故事、去承载并推动对宏大社会议题(不公、贫困、法律、革命)的关注与思考——让个体故事成为社会议题的载体(雨果《悲惨世界》借冉阿让的命运拷问法律与人性)","architecture":{"type":"flow","components":["别让个体故事只停在个人层面","通过个体的命运故事","承载推动对宏大社会议题的关注","个体成社会议题的载体"]},"strategy_card_image":"kb-assets/hugo/model-5.png"}],"decision_principles":["把美与丑、崇高与卑劣强烈并置对照，在反差中凸显力量","把关注、同情与表达，给予最弱小、最受苦、被损害的人","用充沛、热烈、磅礴的情感打动人（但勿过度煽情）","即使在最黑暗处，也保有对人性之善与救赎的信念","通过个体的命运，承载并推动对宏大社会议题的关注"],"inquiry_questions":["你是平淡呈现、还是把美与丑、崇高与卑劣强烈并置、在反差中凸显力量？","你把关注与同情给了强者/主流、还是给了最弱小、最受苦、被损害的人？","你是冷静克制、还是用充沛、磅礴的情感去打动人？（但勿过度煽情）","面对黑暗与绝望，你是放弃了对善的信念、还是保有对人性向善与救赎的信念？","你的个体故事只停在个人层面、还是承载并推动了对宏大社会议题的关注？"],"value_priorities":["为弱者发声 ＞ 只关注强者主流（冉阿让、芳汀）","对善与救赎的信念 ＞ 在黑暗处放弃（冉阿让的救赎）","个体接社会议题 ＞ 只停在个人层面（借命运拷问法律与人性）"],"blind_spots":["雨果的浪漫主义激情若过度，会流于煽情、滥情、道德说教（文学批评，B）。","其美丑对照、善恶分明，有时失之简单化，不如现实主义的灰度细腻（原理推断，B）。","其磅礴的风格、宏大的议论，不适合需要冷静、克制、简洁的场合（原理推断，B）。","其浪漫的理想主义，有时与现实的复杂之间有距离（原理推断，B）。"],"applicable_domains":["创作","表达说服","价值与伦理"],"match_tags":["创作","表达说服","价值与伦理","利他取向","多元模型","攻心共识","近代欧洲"],"linked_cases":["hugo-c1","hugo-c2","hugo-c3","hugo-c4"],"life_tags":[{"tag":"著悲惨世界","tier":"primary"},{"tag":"著巴黎圣母院","tier":"primary"},{"tag":"流亡海外","tier":"secondary"},{"tag":"倡浪漫主义","tier":"secondary"}],"voice_profile":{"notes":"激情磅礴、悲悯宏大；美丑对照强烈；为弱者代言；理想主义"},"references":[{"ref_id":"hugo-s1","title":"雨果《悲惨世界》《巴黎圣母院》《九三年》","locator":"美丑对照、为弱者发声、激情、人道主义、个体接社会议题","source_tier":"primary","supports_models":["美丑对照","为弱者与受苦者发声","以情动人的激情","人道主义的信念","把个体故事接入宏大的社会议题"],"supports_cases":["hugo-c1","hugo-c2","hugo-c3","hugo-c4"],"note":"一手·原著"},{"ref_id":"hugo-s2","title":"雨果与浪漫主义研究","locator":"浪漫主义、人道主义","source_tier":"secondary","supports_models":["美丑对照","人道主义的信念"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"把美与丑崇高与卑劣强烈并置对照在反差中凸显力量(美丑对照)；把关注同情与表达给予最弱小最受苦被损害的人(为弱者与受苦者发声)；用充沛热烈磅礴的情感与激情打动人(以情动人的激情)；即使最黑暗处也保有对人性之善与救赎之可能的信念(人道主义的信念)；通过个体的命运承载推动对宏大社会议题的关注(把个体故事接入宏大的社会议题)","steps":[{"invoke":"美丑对照","action":"你是平淡呈现、还是把美与丑、崇高与卑劣强烈并置、在反差中凸显力量？"},{"invoke":"为弱者与受苦者发声","action":"你把关注与同情给了强者/主流、还是给了最弱小、最受苦、被损害的人？"},{"invoke":"以情动人的激情","action":"你是冷静克制、还是用充沛、磅礴的情感去打动人？（但勿过度煽情）"},{"invoke":"人道主义的信念","action":"面对黑暗与绝望，你是放弃了对善的信念、还是保有对人性向善与救赎的信念？"},{"invoke":"把个体故事接入宏大的社会议题","action":"你的个体故事只停在个人层面、还是承载并推动了对宏大社会议题的关注？"}],"contrast":"与海明威不同(关键差异·激情与克制·恰相对)：**雨果是''浪漫主义的激情''——充沛、热烈、磅礴、美丑强烈对照**；**海明威是''极简的克制''——省略、留白、删尽情感的渲染**——一个以激情澎湃感染、一个以克制留白暗示(见海明威卡)。与托尔斯泰不同：托尔斯泰是''现实主义的克制与心灵辩证法''(细腻的灰度);雨果是''浪漫主义的激情与美丑对照''(强烈的反差)——一个写实细腻、一个浪漫强烈(见托尔斯泰卡)。与狄更斯不同：狄更斯也写底层、但以''讽刺、幽默、英国社会的批判''为主;雨果以''浪漫的激情、美丑对照、人道主义的救赎''为主(见狄更斯卡)。【射程/盲区】雨果之道在''美丑对照、为弱者发声、激情、人道主义、个体接社会议题''极有力(尤其打动人心、唤起social良知)，但①其浪漫主义激情若过度、会流于煽情、滥情、道德说教;②美丑对照、善恶分明、有时失之简单化、不如现实主义灰度细腻;③磅礴的风格不适合需要冷静克制简洁的场合;④浪漫的理想主义有时与现实的复杂有距离。适用创作/表达说服/价值与伦理;不适用投资/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"hugo-c2","note":"用户''在选择把关注、同情与表达给谁时、容易只盯着强者、主流、成功者、而忽视了弱小受苦者''时，以雨果《悲惨世界》类比：他把整部巨著的笔触给了社会最底层、被侮辱与被损害的人——为偷一块面包坐牢十九年的冉阿让、被生活逼入绝境的芳汀;把你的关注、同情与表达、给予那些最弱小、最受苦、被忽视的人、为没有声音的人发声（《悲惨世界》为其作品→确证）"},{"source":"case","case_id":"hugo-c3","note":"用户''面对黑暗、绝望、人性之恶、几乎要对人和善失去信念''时，以雨果的人道主义类比：《悲惨世界》里冉阿让本已被苦役与世界的冷酷变得凶狠、却被主教米里哀的一次以德报怨彻底感化、从此向善;即使在最黑暗、最绝望处、也保有对人性之善与救赎之可能的信念——相信人能向善、光明终会到来（冉阿让的救赎为《悲惨世界》→确证）"}]},"further_reading":[{"title":"雨果《悲惨世界》《巴黎圣母院》《九三年》","why":"美丑对照、为弱者发声、激情、人道主义、个体接社会议题的一手出处（A）","type":"original"},{"title":"雨果与浪漫主义研究","why":"对其浪漫主义与人道主义的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/hugo.png","avatar_thumb":"/advisors/portraits/hugo.png","domain":"创作","person_id":"P-hugo","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'b9f39c5b54b6b772c329a4f36bfcf97c665c6d70e8b078d84905b2cdc973cd50', 43, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('inamori', 'P-inamori', '稻盛和夫', 'business', '稻盛和夫 · 利他经营与做人哲学思维框架卡', '20–21世纪（1932–2022）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '敬天爱人 · 利他经营', '/advisors/portraits/inamori.png', '/advisors/portraits/inamori.png', 5, 0, '{"schema_version":1,"card_id":"inamori","name":"稻盛和夫","title":"稻盛和夫 · 利他经营与做人哲学思维框架卡","era":"20–21世纪（1932–2022）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"敬天爱人","definition":"敬畏客观天理、关爱他人；以''作为人何谓正确''而非利害得失作为判断的最终标准","source":"《活法》","source_tier":"primary","mechanism":"输入=一个决策 → 处理=以''作为人何谓正确''而非利害得失作最终标准、敬畏天理关爱他人 → 输出=合乎做人原则的判断","trigger":"利与义冲突、被利害算计裹挟时","modern_transfer":"撇开利害先问''作为人这样做对不对''，用做人原则压倒精明算计","architecture":{"type":"hierarchy","components":["面对决策","撇开利害","问''作为人何谓正确''","按做人原则定"]},"strategy_card_image":"kb-assets/inamori/model-1.png"},{"name":"利他经营","definition":"经营动机要''动机至善、私心了无''，追求全体员工物质与精神幸福；利他反带来长远繁荣","source":"《活法》","source_tier":"primary","mechanism":"输入=一个经营动机 → 处理=检验''动机至善、私心了无''、追求全体员工物质与精神幸福 → 输出=利他导向的经营","trigger":"做重大且诱人的决定、动机可能混入私心时","modern_transfer":"经营动机要''动机至善、私心了无''；利他反而带来长远繁荣","architecture":{"type":"flow","components":["审视动机","检验私心了无","转向全员/他人幸福","据此决定做不做"]},"strategy_card_image":"kb-assets/inamori/model-2.png"},{"name":"人生方程式","definition":"人生·工作结果=思维方式×热情×能力；思维方式可正可负，方向错了越努力越糟","source":"《活法》","source_tier":"primary","mechanism":"输入=一个人/一项事业 → 处理=用''结果=思维方式×热情×能力''评估、先看思维方式正负 → 输出=方向校准","trigger":"解释为何有能力有热情也失败、或做根本性人生选择时","modern_transfer":"先看方向（思维方式）正负、再谈能力与热情——负方向上的才华是放大的破坏力","architecture":{"type":"matrix","components":["评思维方式正负","评热情","评能力","相乘看结果"]},"strategy_card_image":"kb-assets/inamori/model-3.png"},{"name":"阿米巴经营","definition":"把组织拆成众多小型自主核算单元(阿米巴)，各自独立核算损益，人人都是经营者","source":"《阿米巴经营》","source_tier":"primary","mechanism":"输入=一个大组织 → 处理=拆成众多小型自主核算单元、各自独立核算损益、人人都是经营者 → 输出=被激活的细胞化组织","trigger":"组织庞大僵化、责任与核算脱节时","modern_transfer":"把组织拆成独立核算的小单元，让人人都是经营者、对自己的损益负责","architecture":{"type":"hierarchy","components":["拆分小单元","各自独立核算","人人是经营者","汇总激活组织"]},"strategy_card_image":"kb-assets/inamori/model-4.png"},{"name":"极致努力","definition":"付出不亚于任何人的努力，以''燃烧的斗魂''把每天做到极致；能力用将来时不断精进","source":"《活法》","source_tier":"primary","mechanism":"输入=一个超出当前能力的难关 → 处理=付出不亚于任何人的努力、以燃烧的斗魂把每个细节做到极致 → 输出=把不可能拖成可能","trigger":"能力暂时不足、面对苛刻目标时","modern_transfer":"能力不足时，付出不亚于任何人的努力、把细节做到极致，常能把不可能拖成可能","architecture":{"type":"loop","components":["面对难关","不亚于任何人地投入","把细节做到极致","直到达标"]},"strategy_card_image":"kb-assets/inamori/model-5.png"}],"decision_principles":["以''作为人，何谓正确''作判断的最终标准（A）","动机至善、私心了无，再决定做不做（A）","方向（思维方式）错了，越努力越糟（A）","追求全体员工物质与精神两方面幸福（A）","把每天做到极致，付出不亚于任何人（A）","让每个单元独立核算，人人都是经营者（A）"],"inquiry_questions":["撇开利害，''作为人这样做对不对''？","你做这件事的动机，经得起''私心了无''的检验吗？","你的思维方式（方向）是正还是负？","你是在为自己，还是也在为他人/全员着想？"],"value_priorities":["作为人正确（义） ＞ 利害得失（利）（以做人原则压倒精明算计）","利他与全员幸福 ＞ 一己之私（利他反成长远繁荣）","思维方式（方向） ＞ 单纯能力与热情（方向错了越努力越糟）","极致努力与精进 ＞ 投机取巧（笨功夫做到极致）"],"blind_spots":["把经营高度道德/哲学化，对纯技术、纯财务的硬核博弈着墨少，未必适合需要冷酷算计的场景（原理推断，B）","''利他/全员幸福''在残酷竞争或须果断取舍时会产生张力——日航重建仍裁员约三分之一（史实，B）","其方法高度依赖经营者本人的德性与感召力，难脱离''圣人''人格简单复制（原理推断，B）"],"applicable_domains":["组织管理","领导力","创业","修身自省","价值与伦理"],"match_tags":["组织管理","领导力","修身自省","利他取向","务实渐进","批判思辨","现当代东亚"],"linked_cases":["inamori-c1","inamori-c2","inamori-c3","inamori-c4","inamori-c5"],"life_tags":[{"tag":"创办京瓷","tier":"primary"},{"tag":"拯救日航","tier":"secondary"},{"tag":"创办盛和塾","tier":"secondary"},{"tag":"创阿米巴经营","tier":"primary"}],"voice_profile":{"notes":"朴素哲理、近乎布道；反复叩问做人根本；禅意与实务并存"},"references":[{"ref_id":"inamori-s1","title":"《活法》(稻盛和夫著)","locator":"作为人何谓正确/利他/人生方程式/极致努力各章","source_tier":"primary","supports_models":["敬天爱人","利他经营","人生方程式","极致努力"],"supports_cases":["inamori-c4"],"note":"本人著述一手"},{"ref_id":"inamori-s2","title":"《阿米巴经营》(稻盛和夫著)","locator":"阿米巴单元核算体系","source_tier":"primary","supports_models":["阿米巴经营"],"supports_cases":["inamori-c3"],"note":"本人著述一手"},{"ref_id":"inamori-s3","title":"稻盛和夫传记与日航重建报道","locator":"京瓷创立、DDI、日航重建、早期攻坚相关章节；细节待核验","source_tier":"secondary","supports_cases":["inamori-c1","inamori-c2","inamori-c5"],"note":"第三方传记与报道"}],"material_type":"rich","reasoning_skeleton":{"signature":"撇开利害先问''作为人何谓正确''，动机要至善私心了无；方向（思维方式）比能力热情更重要，把组织拆成人人核算的细胞，再以不亚于任何人的努力做到极致","steps":[{"invoke":"敬天爱人","action":"先撇开利害，问''作为人这样做对不对''，以做人原则作最终判断标准"},{"invoke":"利他经营","action":"检验动机是否''至善、私心了无''——是为全员/他人，还是为一己之私"},{"invoke":"人生方程式","action":"看方向（思维方式）正负，方向错了越努力越糟，先校准方向再谈能力热情"},{"invoke":"阿米巴经营","action":"落到组织上，拆成独立核算的小单元、让人人都是经营者"},{"invoke":"极致努力","action":"以不亚于任何人的努力、把每个细节做到极致，把不可能拖成可能"}],"contrast":"与乔布斯不同（同为创造者/经营者）：乔布斯靠产品品味与聚焦说不；稻盛靠''做人哲学 + 利他 + 阿米巴机制 + 笨功夫极致''——一个是''产品天才''、一个是''经营圣人''（见乔布斯卡）。与巴菲特不同（投资域）：稻盛把经营高度道德/哲学化、算的是''义''与''全员幸福''，不适用冷酷的竞争博弈与投资算计；巴菲特算的是生意质量与长期回报（见巴菲特卡）。注：与松下幸之助/本田宗一郎/盛田昭夫等日本经营者最易混，是后续批次需重点拉开的高碰撞簇。"},"persona_anchor":{"primary":[{"source":"case","case_id":"inamori-c2","note":"用户''一个诱人的大决定、要不要做''时，以创办第二电电（DDI）挑战 NTT 垄断类比：他连续数月每晚自问''动机至善、私心了无吗''，确认是为降低国民通信费而非私利后才入局——私心一旦混入，判断就会变形（确证）"},{"source":"case","case_id":"inamori-c3","note":"用户''怎么扭转一个庞大僵化/濒危的组织''时，以 78 岁零薪重建破产日航类比：先改价值观、推阿米巴独立核算、忍痛裁员约三分之一，次年扭亏、约 2 年 7 个月后重新上市（确证·亦体现''利他与裁员''的张力，须诚实呈现）"}]},"further_reading":[{"title":"稻盛和夫《活法》","why":"其哲学核心，''作为人何谓正确''''人生方程式''''极致努力''都在此，最易上手","type":"original"},{"title":"稻盛和夫《阿米巴经营》","why":"把哲学落成机制——组织如何拆成独立核算的小单元、人人成为经营者","type":"original"},{"title":"稻盛和夫《干法》","why":"专讲工作观与''付出不亚于任何人的努力''，与《活法》互补，更聚焦个人","type":"original"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/inamori.png","avatar_thumb":"/advisors/portraits/inamori.png","domain":"商业","person_id":"P-inamori","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '336190b76cf96130e9822625f2fa7ed69f9be57d0173d1248c6c3927cca56474', 44, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('jianzhen', 'P-jianzhen', '鉴真', 'history', '鉴真 · 受托远行与系统传承思维框架卡', '唐（688—763）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '受托即赴 · 屡败屡试', '/advisors/portraits/jianzhen.png', '/advisors/portraits/jianzhen.png', 5, 0, '{"schema_version":1,"card_id":"jianzhen","name":"鉴真","title":"鉴真 · 受托远行与系统传承思维框架卡","era":"唐（688—763）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"受托即赴","definition":"面对一个值得的远方请托，把它看得重于个人安危，受请即全力赴之（\"为是法事，何惜身命\"）","source":"《唐大和上东征传》","source_tier":"secondary","mechanism":"输入=面对值得的远方请托、却惜身畏难 → 处理=把它看得重于个人安危、受请即全力赴之 → 输出=应承值得的使命(为是法事何惜身命)","trigger":"面对一个值得的远方请托时","modern_transfer":"面对一个真正值得的远方请托、把它看得重于个人安危、受请即全力赴之(''为是法事、何惜身命'')〔前提:使命确实值得、非被裹挟〕","architecture":{"type":"flow","components":["面对值得的远方请托","把它看得重于安危","受请即全力赴之","应承值得的使命"]},"strategy_card_image":"kb-assets/jianzhen/model-1.png"},{"name":"屡败屡试","definition":"把同一目标的反复失败当作必经的工序而非终点，每次失败后修整人船物资再来，试到成功为止","source":"《唐大和上东征传》","source_tier":"secondary","mechanism":"输入=同一目标反复失败、想放弃 → 处理=把反复失败当必经的工序而非终点、每次失败后修整人船物资再来 → 输出=试到成功为止(六渡)","trigger":"同一目标反复失败时","modern_transfer":"把同一目标的反复失败当作必经的''工序''、而非终点——每次失败后修整人、船、物资再来，试到成功为止(鉴真六次东渡、前五次失败)〔但极致坚持代价惨重、非''坚持必胜''励志模板〕","architecture":{"type":"loop","components":["同一目标反复失败","当作工序而非终点","每次失败后修整再来","试到成功为止"]},"strategy_card_image":"kb-assets/jianzhen/model-2.png"},{"name":"志不随损","definition":"把使命与个人能力/condition解耦；即便途中遭重大损失（如失明），核心目标不因之动摇放弃","source":"《唐大和上东征传》","source_tier":"secondary","mechanism":"输入=途中遭重大损失(如失明)、易因之动摇放弃 → 处理=把使命与个人能力/状态解耦、核心目标不因损失动摇 → 输出=使命与损失脱钩(失明仍东渡)","trigger":"途中遭重大损失时","modern_transfer":"把使命与你个人的能力/状态解耦——即便途中遭重大损失(如鉴真失明)、核心目标不因之动摇放弃；使命不随能力受损而放弃","architecture":{"type":"hierarchy","components":["途中遭重大损失","把使命与个人能力解耦","核心目标不因损失动摇","使命与损失脱钩"]},"strategy_card_image":"kb-assets/jianzhen/model-3.png"},{"name":"传系统非己","definition":"远行传播带走的是一整套可移植的系统（人才、技艺、典籍、制度），而非只带自己一个人","source":"《唐大和上东征传》及日本史料","source_tier":"secondary","mechanism":"输入=远行传播只带自己一个人、异地难生根 → 处理=带走一整套可移植的系统(人才/技艺/典籍/制度) → 输出=在异地真正生根(携弟子工匠典籍建唐招提寺)","trigger":"要在异地传播/建立某事物时","modern_transfer":"远行传播带走的是一整套可移植的系统(人才、技艺、典籍、制度)、而非只带自己一个人——这样才能在异地真正生根(鉴真携弟子/工匠/典籍/佛像东渡、建唐招提寺)","architecture":{"type":"hierarchy","components":["别只带自己一个人","带走整套可移植系统","人才技艺典籍制度","在异地真正生根"]},"strategy_card_image":"kb-assets/jianzhen/model-4.png"},{"name":"亲赴亲证","definition":"有些东西无法遥传，必须亲身到场、以身建立其正统与可信，而非只寄送文本或代理","source":"《唐大和上东征传》及日本史料","source_tier":"secondary","mechanism":"输入=以为可遥传/寄送文本/代理 → 处理=有些东西必须亲身到场、以身建立其正统与可信 → 输出=亲身立起正统(亲登戒坛授戒)","trigger":"要建立某种正统/可信、考虑遥控代办时","modern_transfer":"有些东西无法遥传——必须亲身到场、以身建立其正统与可信，而非只寄送文本或委托代理(鉴真亲登东大寺戒坛为天皇僧众授戒)","architecture":{"type":"flow","components":["以为可遥传代理","有些东西无法遥传","必须亲身到场","以身建立正统与可信"]},"strategy_card_image":"kb-assets/jianzhen/model-5.png"}],"decision_principles":["值得的远方请托，受请即全力赴之，不惜身命（前提：使命确实值得）","同一目标的反复失败是工序不是终点，修整再来","遭遇重大损失（如失明）时，使命不随能力受损而放弃","传播要带走整套可移植系统（人才/技艺/典籍/制度），非只带自己","有些正统只能亲身建立，不能遥寄代理"],"inquiry_questions":["这个请托值不值得？若值得，你愿不愿把它看得重于安危？","这已经是第几次失败了？你是要停，还是修整再来？","你受了重大损失，是放弃使命，还是让使命与损失脱钩？","你要传的，是只有你自己，还是一整套别人能接着用的系统？","这件事能遥控代办，还是必须你亲自到场才立得住？"],"value_priorities":["应承值得的使命 ＞ 守住个人安危（值得的远托重于自保——\"为是法事、何惜身命\"）","传整套系统 ＞ 只传自己一人（带去人才/技艺/典籍、才能在异地真正生根）","亲赴亲证 ＞ 遥寄代理（戒律正统需有资格者亲自登坛、无法寄送）"],"blind_spots":["''受请即赴、不惜身命''以''使命确实值得''为前提；用于不值得或被裹挟的任务，会变成莽撞牺牲（原理推断，B）。","十二年六渡的极致坚持代价惨重（弟子病亡、自身失明），不应被简化为''坚持必胜''的励志模板（史实，B）。","其方法以''有一个明确、值得倾尽一生的目标''为前提；目标模糊者套用''屡败屡试、不惜身命''反而危险（原理推断，B）。","''传系统非己''依赖你确实拥有一整套可移植的系统；空有热忱而无系统者，远行也难在异地生根（原理推断，B）。"],"applicable_domains":["人生抉择","领导力","价值与伦理","学习与认知"],"match_tags":["人生抉择","领导力","价值与伦理","学习与认知","长期主义","实验试错","利他取向","古代东亚"],"linked_cases":["jianzhen-c1","jianzhen-c2","jianzhen-c3","jianzhen-c4"],"life_tags":[{"tag":"六次东渡","tier":"secondary"},{"tag":"弘律日本","tier":"secondary"},{"tag":"建唐招提寺","tier":"secondary"},{"tag":"传医药书艺","tier":"secondary"}],"voice_profile":{"notes":"坚毅沉静、信愿深厚；百折不回；重传承与制度；舍身为法"},"references":[{"ref_id":"jianzhen-s1","title":"真人元开《唐大和上东征传》","locator":"应请、六渡失败、失明仍行、携系统东渡、登坛授戒","source_tier":"secondary","supports_models":["受托即赴","屡败屡试","志不随损","传系统非己","亲赴亲证"],"supports_cases":["jianzhen-c1","jianzhen-c2","jianzhen-c3","jianzhen-c4"],"note":"一手传记（含传记色彩）"},{"ref_id":"jianzhen-s2","title":"日本史料、唐招提寺","locator":"东渡建寺、传律宗与唐文化","source_tier":"secondary","supports_models":["传系统非己","亲赴亲证"],"note":"二手史料/遗存"}],"material_type":"rich","reasoning_skeleton":{"signature":"值得的远托重于安危、受请即全力赴之(受托即赴)；把反复失败当工序非终点、修整再来试到成(屡败屡试)；使命与个人能力解耦、遭重大损失也不放弃(志不随损)；带走整套可移植系统而非只带自己(传系统非己)；有些正统只能亲身建立不能遥寄(亲赴亲证)","steps":[{"invoke":"受托即赴","action":"这个请托值不值得？若值得、你愿不愿把它看得重于安危？〔前提:确实值得、非被裹挟〕"},{"invoke":"屡败屡试","action":"这已经是第几次失败了？你是要停，还是修整再来？"},{"invoke":"志不随损","action":"你受了重大损失，是放弃使命，还是让使命与损失脱钩？"},{"invoke":"传系统非己","action":"你要传的，是只有你自己，还是一整套别人能接着用的系统？"},{"invoke":"亲赴亲证","action":"这件事能遥控代办，还是必须你亲自到场才立得住？"}],"contrast":"与玄奘不同(关键差异·同为唐代高僧/跨域)：**玄奘是''西行求原典、把真知取回来''(向内求真)**；**鉴真是''六次东渡、把律宗整套传到日本''(向外传系统)**——一个取回来、一个传出去(见玄奘卡)。与张骞/郑和不同：张骞凿空、郑和远航是国家使命的开路/外交；鉴真是个人化的受托传法、屡败屡试的极致坚持(见张骞/郑和卡)。【射程/盲区】鉴真之道在''受托即赴、屡败屡试、志不随损、传整套系统、亲赴亲证''极有力，但①''受请即赴、不惜身命''以''使命确实值得''为前提、用于不值得或被裹挟的任务会变成莽撞牺牲；②十二年六渡的极致坚持代价惨重(弟子病亡、自身失明)、不应被简化为''坚持必胜''的励志模板；③其方法以''有一个明确值得倾尽一生的目标''为前提、目标模糊者不适用；④''传系统非己''依赖你确实拥有一整套可移植的系统。适用人生抉择/领导力/价值与伦理/学习与认知；不适用投资/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"jianzhen-c2","note":"用户''同一件事已经失败好几次、想放弃''时，以鉴真六次东渡类比：他东渡日本前五次皆告失败(遇风、遭阻、船毁)，却把每次失败当作必经的工序、修整人船物资再来，历十二年终于第六次成功——失败是工序不是终点（六渡前五次失败为《唐大和上东征传》所载→确证；惟极致坚持代价惨重、非''坚持必胜''励志模板）"},{"source":"case","case_id":"jianzhen-c3","note":"用户''遭遇重大挫折/损失、觉得目标因此泡汤了''时，以鉴真失明仍东渡类比：他在屡次东渡的磨难中双目失明，却没有因这一重大损失放弃东渡传法的核心目标——把使命与个人能力/状态解耦、使命不随损失而放弃（鉴真失明仍东渡为《唐大和上东征传》所载→确证）"}]},"further_reading":[{"title":"真人元开《唐大和上东征传》","why":"受托应允、六次东渡、失明仍行、携系统东渡、登坛授戒的一手传记（B）","type":"biography"},{"title":"日本史料、唐招提寺","why":"鉴真东渡日本建唐招提寺、传律宗与唐文化的遗存与记载","type":"史料/遗存"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/jianzhen.png","avatar_thumb":"/advisors/portraits/jianzhen.png","domain":"历史","person_id":"P-jianzhen","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'ad0c33dfa5be807d4f12486373c38627e394f2216a7ac0afd87b5eaf64b73dc0', 45, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('jobs', 'P-jobs', '史蒂夫·乔布斯', 'business', '史蒂夫·乔布斯 · 聚焦与产品至上思维框架卡', '20–21世纪（1955–2011）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '聚焦即说不 · 完美主义', '/advisors/portraits/jobs.png', '/advisors/portraits/jobs.png', 5, 0, '{"schema_version":1,"card_id":"jobs","name":"史蒂夫·乔布斯","title":"史蒂夫·乔布斯 · 聚焦与产品至上思维框架卡","era":"20–21世纪（1955–2011）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"聚焦即说不","definition":"聚焦的本质是对一百个好主意说不，只把资源压在少数能做到极致的事上","source":"乔布斯公开演讲（1997）","source_tier":"primary","mechanism":"输入=一堆都不错的好主意 → 处理=对一百个好主意说不、只把资源压在少数能做到极致的事上 → 输出=砍到只剩伟大","trigger":"资源分散、项目/选项太多时","modern_transfer":"聚焦的本质是说不——砍掉一切''还不错''，把全部资源压向少数能做到极致的事","architecture":{"type":"flow","components":["列出所有好主意","判定能否做到极致","对其余说不","集中资源"]},"strategy_card_image":"kb-assets/jobs/model-1.png"},{"name":"完美主义","definition":"对产品细节(连看不见处)偏执打磨，反复推翻重来，直到达到自己心中的极致","source":"艾萨克森《史蒂夫·乔布斯》","source_tier":"secondary","mechanism":"输入=一个产品/作品 → 处理=对细节（连看不见处）偏执打磨、反复推翻重来 → 输出=达到心中的极致","trigger":"细节''差不多就行''的诱惑出现时","modern_transfer":"对看不见之处的较真决定一件作品的''品''——真正的工匠对背面也一视同仁","architecture":{"type":"loop","components":["审视细节","不放过看不见处","推翻重来","逼近极致"]},"strategy_card_image":"kb-assets/jobs/model-2.png"},{"name":"软硬一体整合","definition":"软件、硬件、服务端到端自己掌控、紧密整合，以保证完整一致的用户体验","source":"苹果产品与公开记录","source_tier":"secondary","mechanism":"输入=一个体验目标 → 处理=软件/硬件/服务端到端自己掌控、紧密整合 → 输出=完整一致的用户体验","trigger":"体验被各环节割裂、需保证一致性时","modern_transfer":"要保证完整一致的体验，关键环节端到端自己掌控、别让它被各方割裂","architecture":{"type":"hierarchy","components":["定义体验目标","掌控软硬件与服务","紧密整合","交付一致体验"]},"strategy_card_image":"kb-assets/jobs/model-3.png"},{"name":"科技人文交叉","definition":"在科技与人文(艺术/设计)的十字路口创造产品；技术服务于体验与情感，而非堆参数","source":"乔布斯公开演讲","source_tier":"primary","mechanism":"输入=一项技术 → 处理=放到科技与人文（艺术/设计）的十字路口、让技术服务于体验与情感 → 输出=有温度的产品","trigger":"容易陷入堆参数、纯技术导向时","modern_transfer":"在科技与人文交叉口做东西，技术服务于体验与情感、而非堆参数","architecture":{"type":"matrix","components":["拿到技术","接入人文/设计","服务体验情感","造出产品"]},"strategy_card_image":"kb-assets/jobs/model-4.png"},{"name":"创造需求","definition":"不靠市场调研问用户要什么；用户不知道想要什么，直到你把它造出来摆在面前","source":"乔布斯公开访谈","source_tier":"primary","mechanism":"输入=一个用户场景 → 处理=不靠调研问用户要什么、按自己对体验的判断造出来摆在面前 → 输出=用户见到才知道离不开的东西","trigger":"想做真正的创新、而非只满足已说出的需求时","modern_transfer":"用户不知道想要什么、直到你把它造出来——真正的创新是造一个他们见到才知道离不开的东西","architecture":{"type":"flow","components":["洞察场景","不做调研","按体验判断造","创造新需求"]},"strategy_card_image":"kb-assets/jobs/model-5.png"}],"decision_principles":["聚焦就是说不，砍掉一切不极致的（A）","细节即一切，连看不见的地方也要完美（A/B）","端到端掌控软硬件，保证整体体验（B）","在科技与人文交叉口做产品（A）","不调研用户要什么，去创造需求（A）","stay hungry, stay foolish，把每天当最后一天（A）"],"inquiry_questions":["你敢为聚焦砍掉多少个''还不错''的好主意？","这个细节，配得上''极致''两个字吗？","体验是完整一致的，还是被各环节割裂了？","你在满足现有需求，还是在创造新的需求？"],"value_priorities":["少而极致 ＞ 多而平庸（砍到只剩伟大）","完整体验 ＞ 单点参数领先（软硬一体）","创造与直觉 ＞ 市场调研与共识（用户事后才知道想要）","产品本身 ＞ 短期利润/市占（做对产品，钱随后来）"],"blind_spots":["现实扭曲力场+完美主义也带来专横与人际代价，对同事严苛、曾被自己创立的公司逐出（史实，A/B）","凭直觉/拒调研在B2B、强监管、需广泛共识的领域可能失灵（原理推断，B）","极致封闭整合牺牲开放与兼容，并非所有市场都吃这一套（原理推断，B）"],"applicable_domains":["创新研发","创业","表达说服","商业模式与护城河"],"match_tags":["创新研发","创业","表达说服","极简主义","直觉决断","第一性原理","现当代北美"],"linked_cases":["jobs-c1","jobs-c2","jobs-c3","jobs-c4","jobs-c5"],"life_tags":[{"tag":"联合创办苹果","tier":"secondary"},{"tag":"推出iPhone","tier":"secondary"},{"tag":"重塑皮克斯","tier":"secondary"},{"tag":"推出iPod","tier":"secondary"}],"voice_profile":{"notes":"极简有力、金句频出；现场感染力强；非黑即白、爱用''伟大/垃圾''"},"references":[{"ref_id":"jobs-s1","title":"沃尔特·艾萨克森《史蒂夫·乔布斯》(授权传记)","locator":"1997回归、1985被逐、内部也要美观等章节；页码待核验","source_tier":"secondary","supports_models":["完美主义"],"supports_cases":["jobs-c1","jobs-c3","jobs-c4"],"note":"授权传记，第三方记述"},{"ref_id":"jobs-s2","title":"乔布斯公开演讲/访谈（1997开发者大会、斯坦福2005、D大会等）","locator":"''focus is saying no''、科技人文交叉、不做调研等段落","source_tier":"primary","supports_models":["聚焦即说不","科技人文交叉","创造需求"],"supports_cases":["jobs-c5"],"note":"本人公开言论"},{"ref_id":"jobs-s3","title":"苹果产品发布与公开记录（iPhone 2007、iPod/iTunes）","locator":"发布会与产品资料","source_tier":"secondary","supports_models":["软硬一体整合"],"supports_cases":["jobs-c2"],"note":"公开发布记录"}],"material_type":"rich","reasoning_skeleton":{"signature":"聚焦就是对一百个好主意说不——把资源全压向少数能做到极致的产品，连看不见的细节也偏执打磨，造用户见了才知道离不开的东西","steps":[{"invoke":"聚焦即说不","action":"先砍：敢为聚焦砍掉多少个''还不错''的好主意，只留少数能做到极致的"},{"invoke":"创造需求","action":"不靠调研问用户要什么，按自己对体验的判断去定义产品"},{"invoke":"软硬一体整合","action":"端到端掌控软件硬件服务，保证体验完整一致、不被各环节割裂"},{"invoke":"科技人文交叉","action":"让技术服务于体验与情感、在科技与人文十字路口做产品，而非堆参数"},{"invoke":"完美主义","action":"对细节（连看不见处）偏执打磨、反复推翻重来，直到心中的极致"}],"contrast":"与贝索斯不同（同为颠覆式创业者）：贝索斯靠长期主义 + 可逆/不可逆决策 + 客户痴迷 + 数据飞轮，是''机制与流程''驱动；乔布斯拒调研、靠直觉与品味、少而极致，是''品味与体验''驱动（见贝索斯卡）。与马斯克不同：马斯克第一性原理拆物理/成本、目标驱动（火星/能源）、删除法；乔布斯从''体验与人文''出发、靠直觉而非物理推导，创造需求而非优化成本（见马斯克卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"jobs-c1","note":"用户''项目太多、资源分散、组织濒危''时，以 1997 回归画 2×2 矩阵砍产品线类比：他宣布只做 4 款核心产品、当即砍掉约 70%，次年即扭亏——救命的常不是再加项目，而是有勇气砍掉大多数''还不错''（确证）"},{"source":"case","case_id":"jobs-c3","note":"用户''我的偏执/高标准是不是伤了团队''时，以 1985 被逐出苹果类比（反面镜子）：天才的偏执若不加约束会变专横、把人得罪光，他被自己创立的公司逐出；放逐期的沉淀有时是回归前必经的修炼（确证）"}]},"further_reading":[{"title":"沃尔特·艾萨克森《史蒂夫·乔布斯》（授权传记）","why":"唯一授权传记，1997 回归/1985 被逐/''内部也要美''等决策与性格的完整脉络","type":"biography"},{"title":"乔布斯斯坦福大学 2005 毕业演讲","why":"他本人最凝练的人生观，''求知若饥、虚心若愚''的出处，十五分钟读懂其底色","type":"讲稿"},{"title":"布伦特·施兰德《成为乔布斯》","why":"另一视角传记，更侧重他从被逐到回归的成长与转变，平衡''专横''的单一印象","type":"biography"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/jobs.png","avatar_thumb":"/advisors/portraits/jobs.png","domain":"商业","person_id":"P-jobs","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '99677d984af43efaa690d6fb89f3e7374d3f8d189d970bb19beaced81e01b781', 46, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('kant', 'P-kant', '康德', 'philosophy', '康德 · 绝对律令与批判哲学思维框架卡', '近代（1724—1804）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '绝对律令 · 人是目的', '/advisors/portraits/kant.png', '/advisors/portraits/kant.png', 5, 0, '{"schema_version":1,"card_id":"kant","name":"康德","title":"康德 · 绝对律令与批判哲学思维框架卡","era":"近代（1724—1804）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"绝对律令","definition":"判断一个做法对不对，问\"如果所有人都这么做这准则还成立吗\"——只按你愿意它成为普遍法则的原则行动","source":"康德《道德形而上学奠基》","source_tier":"primary","mechanism":"输入=只看这个做法对我此刻是否方便/有利 → 处理=问''如果所有人都这么做这准则还成立吗''、只按愿意它成为普遍法则的准则行动 → 输出=可普遍化的道德准则(绝对律令)","trigger":"判断一个做法在道德上对不对时","modern_transfer":"判断一个做法对不对、问:如果''所有人''在这种情况下都这么做、这个准则还成立吗?——只按你愿意它成为普遍法则的原则去行动(康德绝对律令/定言令式)〔在某些两难情境过于刚硬、见盲区〕","architecture":{"type":"flow","components":["别只看对我此刻是否方便有利","问如果所有人都这么做还成立吗","只按愿意成为普遍法则的准则","可普遍化的道德准则"]},"strategy_card_image":"kb-assets/kant/model-1.png"},{"name":"人是目的","definition":"永远把人（包括自己）当作\"目的\"来对待，而不仅仅是实现别的目标的\"工具\"","source":"康德《道德形而上学奠基》","source_tier":"primary","mechanism":"输入=只把人当实现目标的工具 → 处理=永远把人(包括自己)当作''目的''、而非仅仅当工具 → 输出=不可逾越的底线(人是目的)","trigger":"对待人(包括自己)时","modern_transfer":"永远把人(包括你自己)当作''目的''来对待、而不仅仅是实现别的目标的''工具''——这是不可逾越的底线(康德''人是目的'')","architecture":{"type":"flow","components":["别只把人当实现目标的工具","永远把人包括自己","当作目的而非仅仅当工具","不可逾越的底线"]},"strategy_card_image":"kb-assets/kant/model-2.png"},{"name":"哥白尼式转向","definition":"别只盯着\"对象\"，先反思\"你用来认识它的框架/条件\"本身——对象符合我们的认识形式，而非反过来","source":"康德《纯粹理性批判》","source_tier":"primary","mechanism":"输入=只盯着''对象''、以为认识是被动符合对象 → 处理=先反思''你用来认识它的框架/条件''本身 → 输出=看清认知框架的塑造作用(哥白尼式转向)","trigger":"要理解''我们如何认识''/反思认知前提时","modern_transfer":"别只盯着''对象''、先反思''你用来认识它的框架/条件''本身——很多东西不是客观给定的、而是被你的认知框架塑造的(康德''哥白尼式转向'':不是认识符合对象、而是对象符合我们的认识形式)","architecture":{"type":"hierarchy","components":["别只盯着对象以为被动符合","先反思你用来认识的框架与条件","对象符合我们的认识形式","看清认知框架的塑造作用"]},"strategy_card_image":"kb-assets/kant/model-3.png"},{"name":"现象与物自体","definition":"承认你认识的只是\"事物向你呈现的样子\"（现象），而非\"事物本身\"（物自体）——为认知保留谦逊","source":"康德《纯粹理性批判》","source_tier":"primary","mechanism":"输入=把自己的认识当成了事物本身的绝对实在 → 处理=承认你认识的只是''现象''、''物自体''不可直接知 → 输出=认知的谦逊(现象与物自体)","trigger":"判断自己的认识有多大确定性时","modern_transfer":"承认你认识的只是''事物向你呈现的样子''(现象)、而非''事物本身''(物自体)——为认知保留谦逊、别把自己的认识当成了绝对的实在(康德现象与物自体)〔其二元划分本身也有争议、见盲区〕","architecture":{"type":"hierarchy","components":["别把自己的认识当绝对实在","承认你认识的只是现象","物自体不可直接知","为认知保留谦逊"]},"strategy_card_image":"kb-assets/kant/model-4.png"},{"name":"二律背反","definition":"理性推到超出经验的范围，常会陷入\"正反两方都能自圆其说\"的矛盾——警惕越界的独断","source":"康德《纯粹理性批判》","source_tier":"primary","mechanism":"输入=在没有经验可检验的地方独断地下结论 → 处理=意识到理性推到超出经验时会陷入''正反都能自圆其说''的矛盾 → 输出=对越界论断保持警惕(二律背反)","trigger":"面对超出经验范围的宏大论断时","modern_transfer":"当理性推到超出经验的范围(如宇宙有无边界、有无自由意志)、常会陷入''正反两方都能自圆其说''的二律背反——警惕在没有经验可检验的地方独断地下结论(康德二律背反)","architecture":{"type":"flow","components":["别在没有经验可检验处独断","意识到理性超出经验","会陷入正反都自圆其说的矛盾","对越界论断保持警惕"]},"strategy_card_image":"kb-assets/kant/model-5.png"}],"decision_principles":["判断做法对不对，问它能否成为人人遵守的普遍法则（但勿过于刚硬）","永远把人（包括自己）当目的，而非仅仅当工具","先反思你用来认识的框架本身，别只盯着对象","承认只认识现象、非物自体，为认知保留谦逊","警惕在超出经验、正反都能自圆其说的地方独断下结论"],"inquiry_questions":["如果''所有人''在这种情况下都这么做、你这个准则还成立吗？","你是把人（包括自己）当目的、还是仅仅当成实现别的目标的工具？","你只盯着对象、还是也反思了你用来认识它的框架本身？","你是把自己的认识当成了绝对实在、还是承认只认识了它呈现的样子？","这是个有经验可检验的判断、还是超出经验、正反都能自圆其说的越界独断？"],"value_priorities":["可普遍化的准则 ＞ 只对我有利的算计（定言令式）","把人当目的 ＞ 仅仅把人当工具（不可逾越的底线）","认知的谦逊 ＞ 把认识当绝对实在（现象与物自体）"],"blind_spots":["绝对律令的''可普遍化''在某些两难情境（如对凶手是否说谎以救人）被批为过于刚硬、不顾后果（伦理学批评，B）。","纯义务论忽视了情境、后果与情感的作用，可能流于僵硬的规则主义（学术，B）。","''物自体不可知''被后来的哲学家（如黑格尔）批评，其现象/物自体的二元划分本身也有争议（学术，B）。","其哲学极其晦涩抽象，距离日常实务较远（原理推断，B）。"],"applicable_domains":["价值与伦理","认知偏误与理性决策","修身自省"],"match_tags":["价值与伦理","认知偏误与理性决策","修身自省","批判思辨","制度法治思维","逆向思考","近代欧洲"],"linked_cases":["kant-c1","kant-c2","kant-c3","kant-c4"],"life_tags":[{"tag":"著理性批判","tier":"primary"},{"tag":"提三大批判","tier":"primary"},{"tag":"倡道德律令","tier":"primary"},{"tag":"倡永久和平","tier":"primary"}],"voice_profile":{"notes":"严谨缜密、追求普遍；理性至上；重义务与原则；极抽象"},"references":[{"ref_id":"kant-s1","title":"康德《纯粹理性批判》《实践理性批判》《道德形而上学奠基》","locator":"绝对律令、人是目的、哥白尼式转向、物自体、二律背反","source_tier":"primary","supports_models":["绝对律令","人是目的","哥白尼式转向","现象与物自体","二律背反"],"supports_cases":["kant-c1","kant-c2","kant-c3","kant-c4"],"note":"一手·著述"},{"ref_id":"kant-s2","title":"康德哲学研究","locator":"批判哲学、义务论伦理学","source_tier":"secondary","supports_models":["绝对律令","现象与物自体"],"note":"二手·研究（含批评）"}],"material_type":"textual","reasoning_skeleton":{"signature":"判断做法对不对问它能否成为普遍法则(绝对律令)；永远把人当目的而非仅仅当工具(人是目的)；先反思你用来认识的框架本身、对象符合认识形式(哥白尼式转向)；承认只认识现象而非物自体、保留认知谦逊(现象与物自体)；理性超出经验会陷入正反都自圆其说、警惕越界独断(二律背反)","steps":[{"invoke":"绝对律令","action":"如果''所有人''在这种情况下都这么做、你这个准则还成立吗？"},{"invoke":"人是目的","action":"你是把人（包括自己）当目的、还是仅仅当成实现别的目标的工具？"},{"invoke":"哥白尼式转向","action":"你只盯着对象、还是也反思了你用来认识它的框架本身？"},{"invoke":"现象与物自体","action":"你是把自己的认识当成了绝对实在、还是承认只认识了它呈现的样子？"},{"invoke":"二律背反","action":"这是个有经验可检验的判断、还是超出经验、正反都能自圆其说的越界独断？"}],"contrast":"与亚里士多德不同(关键差异·伦理学两大路径)：**亚里士多德是''德性伦理''(靠中道、培养好的品格与实践智慧、看具体情境)**；**康德是''义务论''(靠绝对律令、看准则能否普遍化、不顾后果与情境)**——一个养品格看情境、一个立规则看普遍(见亚里士多德卡)。与孟子不同(义务论 vs 性善仁政)：孟子靠''性善、仁政、义利之辨''的儒家道德(从本心的善出发);康德靠''绝对律令、人是目的''的理性义务(从理性的普遍法则出发)(见孟子卡)。与苏格拉底/柏拉图不同：他们追问''什么是善/正义的本质'';康德转而追问''我们如何认识、道德如何可能''的''批判''(划定理性的界限)(见苏格拉底/柏拉图卡)。【射程/盲区】康德之道在''绝对律令、人是目的、哥白尼式转向、物自体、二律背反''极有力(尤其道德的普遍性、认知的谦逊)，但①绝对律令的''可普遍化''在某些两难情境(如对凶手是否说谎以救人)被批为过于刚硬、不顾后果;②纯义务论忽视情境、后果与情感、可能流于僵硬的规则主义;③''物自体不可知''及其二元划分被后来的哲学家批评;④其哲学极其晦涩抽象、距日常实务较远。适用价值与伦理/认知偏误与理性决策/修身自省;不适用投资/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"kant-c1","note":"用户''想为一时之便破一次例、或纠结一个做法到底对不对''时，以康德绝对律令类比：问自己——''如果所有人在这种情况下都这么做、这个准则还成立吗?'';只按你愿意它成为人人遵守的普遍法则的原则去行动、别给自己开''就这一次''的例外（绝对律令为康德《道德形而上学奠基》核心→确证；惟在某些两难情境过于刚硬）"},{"source":"case","case_id":"kant-c2","note":"用户''纠结是否为了一个目标而把某人(或自己)仅仅当成工具来用''时，以康德''人是目的''类比：永远把人(包括你自己)当作''目的''来对待、而不仅仅是实现别的目标的''工具''——这是不可逾越的底线;用人但不能''只''把人当用具（''人是目的''为康德《道德形而上学奠基》核心→确证）"}]},"further_reading":[{"title":"康德《纯粹理性批判》《实践理性批判》《道德形而上学奠基》","why":"绝对律令、人是目的、哥白尼式转向、物自体、二律背反的一手出处（A）","type":"original"},{"title":"康德哲学研究","why":"对其批判哲学与义务论伦理学的学术分析（含批评，B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/kant.png","avatar_thumb":"/advisors/portraits/kant.png","domain":"哲学","person_id":"P-kant","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '4e683f540088eaf1429ffe399d3a08d87c0fcb79c9314d040680bff9cca44756', 47, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('keynes', 'P-keynes', '凯恩斯', 'investing', '凯恩斯 · 选美理论与逆向集中投资思维框架卡', '现代（1883—1946）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '选美理论 · 逆向投资', '/advisors/portraits/keynes.png', '/advisors/portraits/keynes.png', 5, 0, '{"schema_version":1,"card_id":"keynes","name":"凯恩斯","title":"凯恩斯 · 选美理论与逆向集中投资思维框架卡","era":"现代（1883—1946）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"选美理论","definition":"在很多博弈里，赢的关键不是判断\"什么是对的/好的\"，而是判断\"大多数人会认为什么是对的/好的\"——你预测的是\"大众的预测\"","source":"凯恩斯\"选美理论\"（《通论》）","source_tier":"primary","mechanism":"输入=只判断''什么是对的/好的''、忽视大众怎么看 → 处理=判断''大多数人会认为什么是对的/好的''、预测大众的预测 → 输出=赢在预测大众预测(选美理论)","trigger":"参与投资/市场/舆论等大众博弈时","modern_transfer":"在很多博弈(投资、市场、舆论)里、赢的关键不是判断''什么是对的/好的''、而是判断''大多数人会认为什么是对的/好的''——你预测的是''大众的预测''(凯恩斯的''选美理论'':报纸选美要选大家会选的、而非你认为最美的)〔易陷入无穷猜测之险、见盲区〕","architecture":{"type":"flow","components":["别只判断什么是对的好的忽视大众怎么看","判断大多数人会认为什么是对的好的","预测大众的预测","赢在预测大众预测"]},"strategy_card_image":"kb-assets/keynes/model-1.png"},{"name":"逆向投资","definition":"在大众恐慌、悲观时往往是机会；在大众狂热、乐观时往往要谨慎——独立判断、敢于与群众的情绪反向","source":"凯恩斯后期的逆向价值投资","source_tier":"secondary","mechanism":"输入=随大众恐慌抛售、随大众狂热追捧 → 处理=大众恐慌时找机会、大众狂热时谨慎、与情绪反向 → 输出=独立反向(逆向)","trigger":"面对市场/群体的极端情绪时","modern_transfer":"在大众恐慌、抛售、悲观时、往往是机会;在大众狂热、追捧、乐观时、往往要谨慎——独立判断、敢于与群众的情绪反向(凯恩斯后期的逆向价值投资)","architecture":{"type":"flow","components":["别随大众恐慌抛售随大众狂热追捧","大众恐慌时找机会","大众狂热时谨慎","独立判断与情绪反向"]},"strategy_card_image":"kb-assets/keynes/model-2.png"},{"name":"能力圈集中持有","definition":"把资源/资金集中投到你真正深入了解、有把握的少数标的上、长期持有，而非为了\"分散\"而盲目什么都买一点","source":"凯恩斯后期的集中投资","source_tier":"secondary","mechanism":"输入=为分散而盲目什么都买一点 → 处理=集中投到你真正深入了解有把握的少数标的、长期持有 → 输出=集中于懂的(集中持有)","trigger":"配置资源/资金时","modern_transfer":"把资源/资金集中投到你真正深入了解、有把握的少数标的上、长期持有——而非为了''分散''而盲目地什么都买一点(凯恩斯后期主张集中投资于自己懂的少数股票)〔集中放大波动与风险、见盲区〕","architecture":{"type":"hierarchy","components":["别为分散而盲目什么都买一点","集中投到你真正深入了解有把握的少数标的","长期持有","集中于懂的"]},"strategy_card_image":"kb-assets/keynes/model-3.png"},{"name":"承认动物精神","definition":"别假设人（或市场）总是理性的——承认大量决策由\"动物精神\"（情绪、本能、信心、乐观或恐惧）驱动，理解并尊重这种非理性","source":"凯恩斯\"动物精神\"（《通论》）","source_tier":"primary","mechanism":"输入=假设人/市场总是理性的 → 处理=承认大量决策由动物精神(情绪本能信心)驱动、理解尊重这种非理性 → 输出=看懂真实的世界(动物精神)","trigger":"分析人/市场行为时","modern_transfer":"别假设人(或市场)总是理性的——承认大量决策由''动物精神''(情绪、本能、信心、乐观或恐惧)驱动;理解并尊重这种非理性、才能看懂真实的世界(凯恩斯的''动物精神''animal spirits)","architecture":{"type":"flow","components":["别假设人或市场总是理性的","承认大量决策由动物精神驱动","情绪本能信心乐观或恐惧","理解尊重非理性才看懂真实世界"]},"strategy_card_image":"kb-assets/keynes/model-4.png"},{"name":"长期着眼但务实应变","definition":"既要有长远的视野，又要清醒地正视短期的现实——不为了遥远的\"长期正确\"而无视眼前的现实，灵活务实地应变、不死守教条","source":"凯恩斯\"长期看我们都死了\"","source_tier":"primary","mechanism":"输入=为遥远的''长期正确''无视眼前现实、死守教条 → 处理=既有长期视野、又正视短期现实、灵活务实应变 → 输出=不死守教条(长期务实)","trigger":"在长期理想与短期现实间取舍时","modern_transfer":"既要有长远的视野、又要清醒地正视短期的现实(''长期看我们都死了'')——不为了遥远的''长期正确''而无视眼前的现实、灵活务实地应变、不死守教条(凯恩斯)","architecture":{"type":"flow","components":["别为遥远的长期正确无视眼前现实死守教条","既有长期视野又正视短期现实","灵活务实地应变","不死守教条"]},"strategy_card_image":"kb-assets/keynes/model-5.png"}],"decision_principles":["判断''大多数人会认为什么是好的''，而非只判断''什么是好的''（预测大众的预测）","大众恐慌时找机会、大众狂热时谨慎，敢于与群众情绪反向","集中投到你真正了解的少数标的、长期持有，而非盲目分散","承认人与市场由''动物精神''（情绪、信心）驱动，别假设总是理性","既有长期视野，又正视短期现实、灵活务实应变，不死守教条"],"inquiry_questions":["你判断的是''什么是对的''、还是''大多数人会认为什么是对的''？","面对市场/群体的极端情绪，你是随大流、还是敢于独立反向？","你是为分散而盲目什么都买、还是集中于你真正了解的少数标的？","你是假设人/市场总是理性、还是承认''动物精神''（情绪、信心）的驱动？","你是为遥远的''长期正确''无视眼前现实、还是长期着眼但务实应变？"],"value_priorities":["预测大众的预测 ＞ 只判断什么是对的（选美理论）","集中于懂的 ＞ 盲目分散（集中投资少数股票）","承认动物精神 ＞ 假设总是理性（animal spirits）"],"blind_spots":["凯恩斯早期热衷宏观择时、货币与商品投机，曾巨亏几乎破产，后期才转向集中价值投资——''择时/投机''路线高风险、教训深刻（史，B，客观标注）。","''选美理论''（预测大众预测）在实践中极难，易陷入无穷的猜测、反而误事（原理推断，B）。","集中持有放大波动与风险，需要极强的判断力与承受力，不适合大多数人（原理推断，B）。","其作为经济学家的宏观理论与作为投资者的实践是两回事，不应混淆（原理推断，B）。"],"applicable_domains":["投资","认知偏误与理性决策","竞争博弈"],"match_tags":["投资","认知偏误与理性决策","竞争博弈","逆向思考","概率思维","多元模型","现当代欧洲"],"linked_cases":["keynes-c1","keynes-c2","keynes-c3","keynes-c4"],"life_tags":[{"tag":"著就业通论","tier":"primary"},{"tag":"参布雷顿森林","tier":"secondary"},{"tag":"操盘大学基金","tier":"secondary"},{"tag":"倡选美理论","tier":"primary"}],"voice_profile":{"notes":"睿智机变、洞悉心理；重大众心理与博弈；逆向而集中；务实不拘教条"},"references":[{"ref_id":"keynes-s1","title":"凯恩斯《就业、利息和货币通论》及其投资记录、传记","locator":"选美理论、动物精神、逆向、集中持有、长期务实","source_tier":"primary","supports_models":["选美理论","逆向投资","能力圈集中持有","承认动物精神","长期着眼但务实应变"],"supports_cases":["keynes-c1","keynes-c2","keynes-c3","keynes-c4"],"note":"一手/二手·原著与投资记录"},{"ref_id":"keynes-s2","title":"凯恩斯投资实践研究","locator":"从投机到集中价值投资的转变","source_tier":"secondary","supports_models":["逆向投资","能力圈集中持有"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"判断大多数人会认为什么是好的而非只判断什么是好的预测大众的预测(选美理论)；大众恐慌时找机会狂热时谨慎敢于与群众情绪反向(逆向投资)；集中投到你真正了解的少数标的长期持有而非盲目分散(能力圈集中持有)；承认人与市场由动物精神情绪信心驱动别假设总是理性(承认动物精神)；既有长期视野又正视短期现实灵活务实应变不死守教条(长期着眼但务实应变)","steps":[{"invoke":"选美理论","action":"你判断的是''什么是对的''、还是''大多数人会认为什么是对的''？"},{"invoke":"逆向投资","action":"面对市场/群体的极端情绪，你是随大流、还是敢于独立反向？"},{"invoke":"能力圈集中持有","action":"你是为分散而盲目什么都买、还是集中于你真正了解的少数标的？"},{"invoke":"承认动物精神","action":"你是假设人/市场总是理性、还是承认''动物精神''（情绪、信心）的驱动？"},{"invoke":"长期着眼但务实应变","action":"你是为遥远的''长期正确''无视眼前现实、还是长期着眼但务实应变？"}],"contrast":"与格雷厄姆不同(关键差异·同涉价值投资)：**格雷厄姆是''安全边际、内在价值、市场先生''的体系化价值投资(以低于内在价值的折扣买入、用安全边际防错)**；**凯恩斯是''选美理论、动物精神、逆向、集中持有''(更强调对大众心理与博弈的洞察)**——格雷厄姆偏''价值的量化与安全边际''、凯恩斯偏''大众心理与博弈''(见格雷厄姆卡)。与巴菲特不同：巴菲特重''护城河、长期复利、能力圈'';凯恩斯亦集中持有、但其招牌是''选美理论''与''动物精神''对市场心理的洞察(见巴菲特卡)。与邓普顿不同：邓普顿重''在极度悲观点逆向、全球分散'';凯恩斯逆向而集中(见邓普顿卡)。与芒格不同：芒格重''多元思维模型、逆向、避免愚蠢'';凯恩斯重''选美/动物精神的市场心理''(见芒格卡)。【射程/盲区·历史诚实】凯恩斯之道在''选美理论、逆向、集中持有、动物精神、长期务实''极有力(尤其洞察市场心理)，但①凯恩斯早期热衷宏观择时、货币商品投机、曾巨亏几乎破产、后期才转向集中价值投资——投机路线高风险、教训深刻、客观标注;②''选美理论''在实践中极难、易陷入无穷猜测反误事;③集中持有放大波动、需极强承受力、不适合大多数人;④其宏观经济理论与投资实践是两回事、不应混淆。适用投资/认知偏误与理性决策/竞争博弈;不适用创作/修身自省。"},"persona_anchor":{"primary":[{"source":"case","case_id":"keynes-c1","note":"用户''在一个由大众情绪/共识驱动的市场或舆论博弈里、只顾埋头判断''什么才是真正对的/好的''、却屡屡看不懂走势''时，以凯恩斯的''选美理论''类比：他把这种博弈比作报纸选美比赛——要赢、你选的不该是''你自己认为最美的''、而该是''你认为大多数人会选的'';在这类博弈里、赢的关键是判断''大多数人会认为什么是好的''、即预测大众的预测、而非只判断''什么是对的''（选美理论为凯恩斯《通论》之喻→确证）〔但务必注意:这易陷入''我猜你猜我猜''的无穷循环〕"},{"source":"case","case_id":"keynes-c3","note":"用户''手里的资金/精力为了''分散风险''撒在太多自己并不真懂的标的上、样样浅尝''时，以凯恩斯后期的集中投资类比：他早年宏观投机巨亏后、后期转向把资金集中投到少数几只自己深入研究、真正有把握的股票上、长期持有;把资源集中投到你真正深入了解、有把握的少数标的上、而非为了分散而盲目什么都买一点〔但须知:集中也放大波动与风险、需要极强的判断与承受力〕（凯恩斯后期集中投资为其投资记述→确证）"}]},"further_reading":[{"title":"凯恩斯《就业、利息和货币通论》及其投资记录、传记","why":"选美理论、动物精神、逆向、集中持有、长期务实的出处（A/B）","type":"原著/传记"},{"title":"凯恩斯投资实践研究","why":"对其从投机到集中价值投资转变的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/keynes.png","avatar_thumb":"/advisors/portraits/keynes.png","domain":"投资","person_id":"P-keynes","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'c36709987cb71ed088d060f73ba8e1fea9512fe8e774fdde8f771874ca319576', 48, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('kroc', 'P-kroc', '雷·克洛克', 'business', '雷·克洛克 · 标准化复制与卖系统思维框架卡', '现代（1902—1984）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '标准化可复制 · 卖系统而非卖产品', '/advisors/portraits/kroc.png', '/advisors/portraits/kroc.png', 5, 0, '{"schema_version":1,"card_id":"kroc","name":"雷·克洛克","title":"雷·克洛克 · 标准化复制与卖系统思维框架卡","era":"现代（1902—1984）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"标准化可复制","definition":"把一家成功的店拆解成一套可精确复制的标准流程，任何地方、任何人都能复刻出同样品质","source":"克洛克《Grinding It Out》及麦当劳标准化体系","source_tier":"primary","mechanism":"输入=一家店的成功靠个别人/手艺、无法复制 → 处理=把它拆解成一套可精确复制的标准流程(品质/服务/清洁/出餐时间) → 输出=任何地方都能复刻同样品质","trigger":"要把一个成功扩张/复制到多处时","modern_transfer":"把一家成功的店/业务拆解成一套可精确复制的标准流程(品质、服务、清洁、出餐时间都量化到标准)——这样任何地方、任何人都能复刻出同样的品质(克洛克把麦当劳做成可复制的标准系统)","architecture":{"type":"hierarchy","components":["一家店的成功靠个别人手艺","拆解成可精确复制的标准流程","把品质服务清洁都量化","任何地方都能复刻同样品质"]},"strategy_card_image":"kb-assets/kroc/model-1.png"},{"name":"卖系统而非卖产品","definition":"看清你真正卖的不只是产品，而是一套可复制、可加盟的\"成功系统\"，把系统本身变成可规模化的产品","source":"麦当劳特许经营模式","source_tier":"primary","mechanism":"输入=以为自己卖的是产品 → 处理=看清你真正卖的是一套可复制、可加盟的成功系统 → 输出=以系统规模化(特许经营)","trigger":"思考自己真正的产品/商业模式时","modern_transfer":"看清你真正卖的不只是产品——而是一套可复制、可加盟的''成功系统'';把系统本身变成可规模化的产品(麦当劳真正卖的是一套可加盟的成功餐厅系统、而非只是汉堡)","architecture":{"type":"hierarchy","components":["别以为自己卖的是产品","看清你卖的是一套成功系统","把系统做成可复制可加盟","以系统规模化"]},"strategy_card_image":"kb-assets/kroc/model-2.png"},{"name":"加盟双赢共生","definition":"别靠压榨加盟商或卖货赚差价——让加盟商先成功，你靠与他们共同成长来盈利","source":"克洛克的加盟理念","source_tier":"primary","mechanism":"输入=靠压榨加盟商/卖货给他们赚差价 → 处理=让加盟商先成功、总部靠与加盟商共同成长盈利 → 输出=加盟商与总部双赢共生","trigger":"设计加盟/平台/合作分利时","modern_transfer":"别靠压榨加盟商或卖货给他们赚差价——让加盟商先赚到钱、你靠与他们共同成长来盈利;加盟商成功、你才成功(克洛克的麦当劳加盟理念、靠地产与共同成长而非盘剥加盟商)","architecture":{"type":"flow","components":["别压榨加盟商赚差价","让加盟商先成功","靠与他们共同成长盈利","加盟商与总部双赢共生"]},"strategy_card_image":"kb-assets/kroc/model-3.png"},{"name":"细节即品质","definition":"品质不是\"大概差不多\"，把它拆解到每个可量化的细节、极致坚持（QSC）","source":"麦当劳QSC标准","source_tier":"primary","mechanism":"输入=品质靠大概差不多 → 处理=把品质拆解到每个可量化的细节、极致坚持(QSC) → 输出=细节的极致累积成稳定品质","trigger":"要建立稳定品质/标准时","modern_transfer":"品质不是''大概差不多''——把它拆解到每个可量化的细节(薯条炸几分钟、厨房多久清洁一次)、极致坚持(克洛克的QSC（品质·服务·清洁）","architecture":{"type":"flow","components":["别让品质大概差不多","拆解到每个可量化细节","对每个细节极致坚持","细节累积成稳定品质"]},"strategy_card_image":"kb-assets/kroc/model-4.png"},{"name":"永不言弃的大器晚成","definition":"别因起步晚或自觉没天赋就放弃——靠坚持不懈（persistence）而非天赋/教育/天才，把一件事做到底","source":"克洛克名言及其52岁创业史","source_tier":"primary","mechanism":"输入=觉得自己起步晚/没天赋就放弃 → 处理=靠坚持不懈(persistence)而非天赋/教育/天才、把一件事做到底 → 输出=坚持的复利(52岁起步成就麦当劳)","trigger":"觉得自己起步晚/缺天赋而想放弃时","modern_transfer":"别因起步晚或自觉没天赋就放弃——''世上没有什么能取代坚持''(克洛克名言);克洛克52岁才抓住麦当劳、靠坚持不懈把它做成帝国;坚持的复利大于天赋、教育与天才","architecture":{"type":"flow","components":["别因起步晚或没天赋放弃","靠坚持不懈而非天赋天才","把一件事做到底","坚持的复利"]},"strategy_card_image":"kb-assets/kroc/model-5.png"}],"decision_principles":["把成功拆解成任何地方都能复刻的标准流程","看清你真正卖的是可复制、可加盟的成功系统，而非只是产品","别盘剥加盟商，让他们先成功、靠共同成长盈利","品质拆到每个可量化细节、极致坚持（QSC）","别因起步晚/没天赋就放弃，靠坚持不懈把事做到底"],"inquiry_questions":["你的成功是靠个别人/手艺，还是拆成了任何地方都能复刻的标准流程？","你以为自己卖的是产品，还是看清了你真正卖的是一套可复制的成功系统？","你是靠压榨/赚加盟商的差价，还是让他们先成功、靠共同成长盈利？","你的品质是''大概差不多''，还是拆到每个可量化细节极致坚持？","你是因起步晚/没天赋就放弃，还是靠坚持不懈把它做到底？"],"value_priorities":["可精确复制的系统 ＞ 靠个别人/手艺的成功（任何地方都能复刻同样品质）","加盟商先成功 ＞ 盘剥加盟商赚差价（加盟商成功你才成功）","坚持不懈 ＞ 天赋/教育/天才（世上没有什么能取代坚持）"],"blind_spots":["极致标准化以''业务能被拆解为可复制流程''为前提；对高度依赖创意/个性化/手工的业务不适用（原理推断，B）。","〔注意〕克洛克与麦当劳兄弟的商业纠纷、以及他从兄弟手中取得麦当劳控制权的过程有争议（史实，B，客观标注）。","标准化的极致也可能压抑一线的灵活与创新（原理推断，B）。","快餐模式本身的健康与社会争议，是其商业成功背后须正视的一面（史实，B，客观标注）。"],"applicable_domains":["创业","组织管理","长期规划"],"match_tags":["创业","组织管理","长期规划","系统分析","务实渐进","长期主义","现当代北美"],"linked_cases":["kroc-c1","kroc-c2","kroc-c3","kroc-c4"],"life_tags":[{"tag":"缔造麦当劳","tier":"secondary"},{"tag":"推特许加盟","tier":"secondary"},{"tag":"创汉堡大学","tier":"secondary"},{"tag":"立标准化运营","tier":"secondary"}],"voice_profile":{"notes":"精力充沛、执着推销；痴迷标准与细节；坚持不懈；重系统与复制"},"references":[{"ref_id":"kroc-s1","title":"雷·克洛克《Grinding It Out》","locator":"标准化、特许经营、加盟双赢、QSC、52岁创业","source_tier":"primary","supports_models":["标准化可复制","卖系统而非卖产品","加盟双赢共生","细节即品质","永不言弃的大器晚成"],"supports_cases":["kroc-c1","kroc-c2","kroc-c3","kroc-c4"],"note":"一手·自传"},{"ref_id":"kroc-s2","title":"麦当劳（McDonald''s）企业史","locator":"特许经营系统、与麦当劳兄弟的纠纷","source_tier":"secondary","supports_models":["卖系统而非卖产品","加盟双赢共生"],"note":"二手·企业史（含争议）"}],"material_type":"rich","reasoning_skeleton":{"signature":"把成功拆解成可精确复制的标准流程(标准化可复制)；看清你真正卖的是可加盟的成功系统而非产品(卖系统而非卖产品)；让加盟商先成功、靠共同成长盈利而非盘剥(加盟双赢共生)；把品质拆到每个可量化细节极致坚持(细节即品质)；靠坚持不懈而非天赋把事做到底(永不言弃的大器晚成)","steps":[{"invoke":"标准化可复制","action":"你的成功是靠个别人/手艺、还是拆成了任何地方都能复刻的标准流程？"},{"invoke":"卖系统而非卖产品","action":"你以为自己卖的是产品、还是看清了你真正卖的是一套可复制的成功系统？"},{"invoke":"加盟双赢共生","action":"你是靠压榨/赚加盟商的差价、还是让他们先成功、靠共同成长盈利？"},{"invoke":"细节即品质","action":"你的品质是''大概差不多''、还是拆到每个可量化细节极致坚持？"},{"invoke":"永不言弃的大器晚成","action":"你是因起步晚/没天赋就放弃、还是靠坚持不懈把它做到底？"}],"contrast":"与福特不同(关键差异·同重标准化)：**福特是''制造业流水线、把生产标准化为大批量的同一动作''**；**克洛克是''服务/连锁的标准化+特许经营系统''——把一家店的成功拆成可加盟复制的系统**——福特标准化制造、克洛克标准化并加盟复制一整套服务系统(见福特卡)。与沃尔顿不同：沃尔顿是''天天低价+下沉小镇''的自营零售；克洛克是''标准化+特许加盟''的连锁系统(见沃尔顿卡)。与贝索斯不同：贝索斯是''电商飞轮+客户痴迷'';克洛克是''可复制系统+加盟双赢''(见贝索斯卡)。【射程/盲区·〔注意〕】克洛克之道在''标准化复制、卖系统、加盟双赢、细节即品质、永不言弃''极有力，但①极致标准化以''业务能被拆解为可复制流程''为前提、对高度依赖创意/个性化/手工的业务不适用；②〔注意〕克洛克与麦当劳兄弟的商业纠纷、取得控制权的过程有争议；③标准化的极致也可能压抑一线灵活与创新；④快餐模式本身的健康与社会争议须正视。适用创业/组织管理/长期规划；不适用投资/创新研发。"},"persona_anchor":{"primary":[{"source":"case","case_id":"kroc-c1","note":"用户''有一个成功的店/业务、想扩张复制却发现换个地方就走样''时，以克洛克标准化类比：他把麦当劳的成功拆解成一套可精确复制的标准流程(出餐时间、清洁频率、品质标准都量化)——这样任何地方、任何加盟商都能复刻出同样的品质（麦当劳标准化体系为克洛克《Grinding It Out》所述→确证）"},{"source":"case","case_id":"kroc-c4","note":"用户''觉得自己起步太晚、或没天赋、想放弃''时，以克洛克52岁创业类比：他52岁才抓住麦当劳这个机会、靠坚持不懈把它做成全球帝国——''世上没有什么能取代坚持''、坚持的复利大于天赋、教育与天才（克洛克52岁创业与此名言为其自传所载→确证）"}]},"further_reading":[{"title":"雷·克洛克《Grinding It Out》","why":"标准化复制、卖系统、加盟双赢、QSC、52岁创业的一手自传（A）","type":"original"},{"title":"麦当劳（McDonald''s）企业史","why":"特许经营系统、与麦当劳兄弟的纠纷等记录（B）","type":"企业史"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/kroc.png","avatar_thumb":"/advisors/portraits/kroc.png","domain":"商业","person_id":"P-kroc","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '481963319de2946ccffb19ccdbeec38d22c9234c6794790c4a61b491e7e416e3', 49, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('laozi', 'P-laozi', '老子', 'philosophy', '老子 · 无为辩证思维框架卡', '春秋（传统说，约前6世纪；成书或晚至战国）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '无为而治 · 反者道之动', '/advisors/portraits/laozi.png', '/advisors/portraits/laozi.png', 5, 0, '{"schema_version":1,"card_id":"laozi","name":"老子","title":"老子 · 无为辩证思维框架卡","era":"春秋（传统说，约前6世纪；成书或晚至战国）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"无为而治","definition":"不强行干预、顺事物自身的势头、减少不必要的人为操作——很多时候少干预反而成事","source":"《道德经》（治大国若烹小鲜 / 无为而无不为）","source_tier":"primary","mechanism":"输入=过度干预、频繁折腾反而坏事 → 处理=不强行干预、顺事物自身势头、减少不必要的人为操作 → 输出=少干预反而成事(治大国若烹小鲜)","trigger":"管理/治理、想频繁干预时","modern_transfer":"不强行干预、顺事物自身的势头、减少不必要的人为操作——很多时候少干预反而成事(''治大国若烹小鲜''、别频繁翻动)","architecture":{"type":"flow","components":["克制干预冲动","顺事物自身势头","减少人为操作","少干预反而成事"]},"strategy_card_image":"kb-assets/laozi/model-1.png"},{"name":"反者道之动","definition":"事物发展到极端会向对立面转化（物极必反）——别只顺当前趋势线性外推，主动预判反转、并从对立面去想","source":"《道德经》（反者道之动 / 祸福相倚）","source_tier":"primary","mechanism":"输入=只顺着当前趋势线性外推、忽视反转 → 处理=认清事物到极端会向对立面转化(物极必反)、主动从对立面想 → 输出=预判反转、从反面找答案","trigger":"趋势走向极端、或思路单一时","modern_transfer":"事物发展到极端会向对立面转化(物极必反)——别只顺当前趋势线性外推，主动预判反转、并从对立面去想问题(反者道之动)","architecture":{"type":"loop","components":["别线性外推","认清物极必反","预判向对立面转化","从反面找答案"]},"strategy_card_image":"kb-assets/laozi/model-2.png"},{"name":"柔弱胜刚强","definition":"别硬碰硬——以柔克刚、守弱处下；柔软、低位、有弹性的东西反而更持久、更有韧性","source":"《道德经》（柔弱胜刚强 / 上善若水）","source_tier":"primary","mechanism":"输入=习惯硬碰硬、争强好胜 → 处理=不硬碰硬、以柔克刚、守弱处下 → 输出=柔软低位反而更持久更有韧性(水滴石穿)","trigger":"面对强硬对手/局面、想硬刚时","modern_transfer":"别硬碰硬——以柔克刚、守弱处下；柔软、低位、有弹性的东西反而更持久、更有韧性(水善利万物而不争、却能穿石)","architecture":{"type":"flow","components":["别硬碰硬","以柔克刚守弱处下","保持弹性与韧性","柔弱反而持久"]},"strategy_card_image":"kb-assets/laozi/model-3.png"},{"name":"知止不殆","definition":"知道在哪里停下、别把事做到满溢的极端——留余地、知止知足，反而避开危险与反噬","source":"《道德经》（知足不辱、知止不殆 / 持而盈之不如其已）","source_tier":"primary","mechanism":"输入=贪多求满、把事做到极端 → 处理=知道在哪里停下、不把事做到满溢、留余地 → 输出=知止知足反而避开危险与反噬","trigger":"贪多求满、接近极端时","modern_transfer":"知道在哪里停下、别把事做到满溢的极端——''持而盈之、不如其已''；留余地、知止知足，反而避开危险与反噬","architecture":{"type":"flow","components":["警惕贪多求满","知道在哪里停","不做到满溢极端","留余地避反噬"]},"strategy_card_image":"kb-assets/laozi/model-4.png"},{"name":"为而不争","definition":"不显露、不争抢、把自己放低——做了不居功，退后反而更能成全与持久","source":"《道德经》（夫唯不争故天下莫能与之争 / 功成不居）","source_tier":"primary","mechanism":"输入=爱显露、争抢、把自己放高 → 处理=不显露、不争抢、把自己放低、为而不居功 → 输出=不争反而没人能与你争(功成不居)","trigger":"爱显露争抢、或想成全长久时","modern_transfer":"不显露、不争抢、把自己放低——''夫唯不争、故天下莫能与之争''；做了不居功、退后反而更能成全与持久","architecture":{"type":"flow","components":["不显露不争抢","把自己放低","为而不居功","不争反而无人能争"]},"strategy_card_image":"kb-assets/laozi/model-5.png"}],"decision_principles":["不强行干预、顺势减少人为操作——少干预反而成事","认清物极必反，主动预判反转、从对立面想问题","别硬碰硬，以柔克刚、守弱处下，用韧性取胜","知道在哪里停下，别做到满溢，留余地避反噬","不显露不争抢，把自己放低，不争反而无人能争"],"inquiry_questions":["你是不是干预太多、折腾太频？能不能顺势、少操作、让它自己长？","你只在顺着当前趋势外推吗？它会不会到极端就反转？从对立面看会怎样？","你在硬碰硬吗？能不能以柔克刚、守弱处下、用韧性赢？","你是不是在贪多求满、奔向极端？该在哪里停下、留点余地？","你在争抢显露吗？把自己放低、不争，是不是反而更成全？"],"value_priorities":["顺势少为 ＞ 频繁强干预（治大国若烹小鲜、别频繁翻动）","守弱处下的韧性 ＞ 争强好胜的刚硬（柔弱胜刚强、水能穿石）","知止留余地 ＞ 贪满求极端（持而盈之不如其已；物极必反）"],"blind_spots":["老子其人与《道德经》成书均存疑——传统归于春秋老聃，但学界对作者、成书年代（一说晚至战国）有长期争议，归属须谨慎（史料批判，B，〔慎〕）。","无为/不争在需要积极进取、主动竞争或快速变革的情境下，可能流于消极退避（思想评议，B）。","其辩证（''反者道之动''）提供方向感，但不提供精确的量化或操作步骤，易流于玄妙（原理推断，B）。","''柔弱胜刚强''有其条件、并非所有情境都成立，过度守弱可能错失主动（原理推断，B）。"],"applicable_domains":["修身自省","治理决策","长期规划","认知偏误与理性决策"],"match_tags":["修身自省","治理决策","长期规划","认知偏误与理性决策","逆向思考","极简主义","长期主义","古代东亚"],"linked_cases":["laozi-c1","laozi-c2","laozi-c3"],"life_tags":[{"tag":"著道德经","tier":"primary"},{"tag":"论道法自然","tier":"primary"},{"tag":"论无为而治","tier":"primary"},{"tag":"论上善若水","tier":"primary"}],"voice_profile":{"notes":"简约玄远、好用悖论；崇尚自然无为；守弱不争；言简而意深"},"references":[{"ref_id":"laozi-s1","title":"《道德经》（《老子》）","locator":"无为/反者道之动/柔弱/知止/不争诸章","source_tier":"primary","supports_models":["无为而治","反者道之动","柔弱胜刚强","知止不殆","为而不争"],"supports_cases":["laozi-c1","laozi-c2","laozi-c3"],"note":"一手文本（思想确证）；惟作者与成书年代有长期争议→人物归属存疑"},{"ref_id":"laozi-s2","title":"《史记·老子韩非列传》","locator":"老子生平传说","source_tier":"secondary","supports_models":["无为而治"],"note":"后世史传；司马迁亦称老子其人难详、并存数说→生平存疑"}],"material_type":"textual","reasoning_skeleton":{"signature":"不强行干预、顺势减少人为操作、少干预反而成事(无为而治)；认清物极必反、主动从对立面想问题(反者道之动)；别硬碰硬、以柔克刚守弱处下、柔弱反而持久(柔弱胜刚强)；知道在哪里停、不做到满溢、留余地避反噬(知止不殆)；不显露不争抢、不争反而无人能争(为而不争)","steps":[{"invoke":"无为而治","action":"你是不是干预太多、折腾太频？能不能顺势、少操作、让它自己长？"},{"invoke":"反者道之动","action":"你只在顺着当前趋势外推吗？它会不会到极端就反转？从对立面看会怎样？"},{"invoke":"柔弱胜刚强","action":"你在硬碰硬吗？能不能以柔克刚、守弱处下、用韧性赢？"},{"invoke":"知止不殆","action":"你是不是在贪多求满、奔向极端？该在哪里停下、留点余地？"},{"invoke":"为而不争","action":"你在争抢显露吗？把自己放低、不争，是不是反而更成全？"}],"contrast":"与孔子不同(关键差异·同为先秦哲学)：**孔子主''正名/忠恕/修己/中庸/因材施教''、入世建立伦理秩序、积极有为**；**老子主''无为/反者道之动/柔弱胜刚强/知止/不争''、顺自然不强为、辩证反向**——孔子是有为修治、老子是无为顺势(见孔子卡)。与庄子不同(同为道家)：庄子重''齐物/逍遥/相对''、是个人精神的超脱与自由；老子重''无为/辩证/守弱''、更偏治理与处世的实践智慧——庄子是精神逍遥、老子是处世辩证(见庄子卡)。与王阳明/马可奥勒留区分：王阳明是知行心学、奥勒留是斯多葛控制二分；老子是无为辩证。【射程/盲区·〔慎〕】老子之道在''减少无效干预、预判反转、以柔克刚、知止''极有洞察，但①〔慎〕老子其人与《道德经》成书均存疑(或晚至战国)、归属须谨慎；②无为/不争在需积极进取、主动竞争或快速变革时可能流于消极退避；③其辩证提供方向感但不提供精确操作步骤、易流于玄妙；④柔弱胜刚强有条件、并非所有情境都成立。适用修身自省/治理决策/长期规划；不适用创新研发/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"laozi-c1","note":"用户''管得太多、越管越乱、忍不住频繁干预''时，以''治大国若烹小鲜''类比：老子主张治理像煎小鱼、不可频繁翻动——克制干预冲动、顺事物自身势头、减少不必要的人为操作，少干预反而成事（命题出《道德经》、文本确证；惟老子其人与成书存疑、historicity 存疑、宜重义理）"},{"source":"case","case_id":"laozi-c2","note":"用户''习惯争强好胜、硬碰硬''时，以''江海为百谷王''类比：老子言江海所以能容纳百川、正因善处其下——守弱处下、以柔克刚，柔软低位反而更持久有韧性（命题出《道德经》、文本确证；老子其人/成书存疑、historicity 存疑）"}]},"further_reading":[{"title":"《道德经》（《老子》）","why":"无为/反者道之动/柔弱/知止/不争的一手出处（作者与成书年代有长期争议）","type":"原典"},{"title":"《史记·老子韩非列传》","why":"老子生平的传世记载（司马迁亦称其人难详、并存数说）","type":"文本"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/laozi.png","avatar_thumb":"/advisors/portraits/laozi.png","domain":"哲学","person_id":"P-laozi","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '5a3f9424db47b3c310ef7f88b9e8b7eba01dba4e21dfc3f6d27291ea0f1014ee', 50, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('lijing', 'P-lijing', '李靖', 'strategy', '李靖 · 奇正虚实与实战权变思维框架卡', '唐（571—649）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '奇正相生 · 避实击虚', '/advisors/portraits/lijing.png', '/advisors/portraits/lijing.png', 5, 0, '{"schema_version":1,"card_id":"lijing","name":"李靖","title":"李靖 · 奇正虚实与实战权变思维框架卡","era":"唐（571—649）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"奇正相生","definition":"别把\"常规（正）\"与\"奇招（奇）\"割裂、固定——二者相互转化、循环无穷：以正合、以奇胜，且不断变化使对手摸不透","source":"《李卫公问对》论奇正","source_tier":"primary","mechanism":"输入=把常规与奇招割裂固定 → 处理=二者相互转化循环无穷、以正合以奇胜、不断变化 → 输出=使对手摸不透(奇正相生)","trigger":"要在对抗中既稳又出制胜时","modern_transfer":"别把''常规(正)''与''奇招(奇)''割裂、固定——二者相互转化、循环无穷:以常规稳住局面、以奇招出制胜、且不断让常规与奇招相互变化、使对手摸不透(李靖对孙子''奇正''的精微展开)","architecture":{"type":"loop","components":["别把常规正与奇招奇割裂固定","二者相互转化循环无穷","以正合稳住以奇胜制胜","不断变化使对手摸不透"]},"strategy_card_image":"kb-assets/lijing/model-1.png"},{"name":"避实击虚","definition":"别正面硬撼对手最坚实之处——集中力量打击其空虚、薄弱、无备之处，用强点打对方的弱点","source":"《李卫公问对》论虚实","source_tier":"primary","mechanism":"输入=正面硬撼对手最坚实之处 → 处理=集中力量打击其空虚薄弱无备之处 → 输出=用强点打弱点(避实击虚)","trigger":"要选择在何处用力时","modern_transfer":"别正面硬撼对手最坚实之处——集中力量打击其空虚、薄弱、无备之处(避实击虚、攻其无备)、用你的强点打对方的弱点(李靖深谙虚实)","architecture":{"type":"flow","components":["别正面硬撼对手最坚实之处","集中力量","打击其空虚薄弱无备之处","用强点打对方的弱点"]},"strategy_card_image":"kb-assets/lijing/model-2.png"},{"name":"料敌于先·庙算先胜","definition":"战前充分研判敌我双方、\"先胜而后求战\"——先在推演中确认有把握，再行动；不打无准备、无把握之仗","source":"李靖庙算先胜","source_tier":"primary","mechanism":"输入=不打无准备无把握之仗的反面(贸然行动) → 处理=战前充分研判敌我、''先胜而后求战''、先确认有把握 → 输出=有把握才行动(庙算先胜)","trigger":"决定是否行动、行动前准备时","modern_transfer":"战前充分研判敌我双方、''先胜而后求战''——先在推演中确认有把握、再行动;不打无准备、无把握之仗(李靖''先为不可胜''、庙算先胜)","architecture":{"type":"flow","components":["别贸然行动打无把握之仗","战前充分研判敌我双方","先在推演中确认有把握","先胜而后求战"]},"strategy_card_image":"kb-assets/lijing/model-3.png"},{"name":"示形动敌","definition":"主动用\"示形\"（展示假象、佯动、释放误导信息）去调动、迷惑对手，让他按你的意图判断和行动，而非被动应对","source":"李靖善以示形动敌","source_tier":"primary","mechanism":"输入=被动应对对手 → 处理=以示形(假象佯动误导)调动、迷惑对手、使其按我意图行动 → 输出=掌握主动(示形动敌)","trigger":"要掌握博弈主动权时","modern_transfer":"主动用''示形''(展示假象、佯动、释放误导信息)去调动、迷惑对手、让他按你的意图判断和行动、而非被动应对(李靖善以示形动敌)〔诡道被识破反受其害、见盲区〕","architecture":{"type":"flow","components":["别被动应对对手","主动以示形假象佯动误导","去调动迷惑对手","让他按你的意图行动"]},"strategy_card_image":"kb-assets/lijing/model-4.png"},{"name":"因情用兵不拘成法","definition":"不拘泥于固定的成法、教条、阵法——根据具体的天时、地利、敌情灵活变通地用兵","source":"李靖用兵不拘一格","source_tier":"primary","mechanism":"输入=拘泥固定的成法教条阵法 → 处理=根据具体的天时地利敌情灵活变通 → 输出=因情用兵(不拘成法)","trigger":"面对具体多变的情境时","modern_transfer":"不拘泥于固定的成法、教条、阵法——根据具体的天时、地利、敌情灵活变通地用兵(李靖用兵不拘一格、因情而变)","architecture":{"type":"flow","components":["别拘泥固定的成法教条阵法","根据具体的天时地利敌情","灵活变通","因情用兵"]},"strategy_card_image":"kb-assets/lijing/model-5.png"}],"decision_principles":["常规与奇招相互转化、循环无穷，以正合、以奇胜，使对手摸不透","别硬撼最坚实处，集中力量打空虚、薄弱、无备之处（避实击虚）","战前充分研判、先胜而后求战，不打无把握之仗","主动以示形（假象、佯动）调动迷惑对手，掌握主动（但防被识破）","不拘成法，根据具体的天时、地利、敌情灵活变通"],"inquiry_questions":["你是把常规与奇招割裂固定、还是让二者相互转化、以正合以奇胜、使对手摸不透？","你是正面硬撼对手最坚实之处、还是集中力量避实击虚、打其薄弱无备？","你是贸然行动、还是战前充分研判、先确认有把握才行动？","你是被动应对、还是主动以示形调动、迷惑对手、掌握主动？","你是拘泥固定的成法、还是根据具体的天时地利敌情灵活变通？"],"value_priorities":["奇正相生的莫测 ＞ 割裂固定的奇正（以正合、以奇胜）","避实击虚 ＞ 硬撼坚实（用强点打弱点）","先胜而后求战 ＞ 贸然无把握行动（庙算先胜）"],"blind_spots":["李靖之学高度依赖对''奇正虚实''的精妙把握与火候，需要极高的悟性与经验，新手易学成教条或弄巧成拙（原理推断，B）。","其精微的权变之术，用于不需要对抗、博弈的场景（如需要坦诚合作）可能过度算计（原理推断，B）。","''示形动敌''的诡道，用得不当或被识破，反受其害（原理推断，B）。","兵学的取胜逻辑，不直接适用于非零和、共赢的领域（原理推断，B）。"],"applicable_domains":["竞争博弈","危机应对","组织管理"],"match_tags":["竞争博弈","危机应对","组织管理","务实渐进","对抗性思维","系统分析","古代东亚"],"linked_cases":["lijing-c1","lijing-c2","lijing-c3","lijing-c4"],"life_tags":[{"tag":"夜袭破突厥","tier":"secondary"},{"tag":"著李卫公问对","tier":"primary"},{"tag":"平定萧铣","tier":"secondary"},{"tag":"西破吐谷浑","tier":"secondary"}],"voice_profile":{"notes":"精深缜密、奇正莫测；深谙虚实；庙算先胜；因情权变"},"references":[{"ref_id":"lijing-s1","title":"《李卫公问对》、《旧唐书·李靖传》","locator":"奇正相生、避实击虚、庙算先胜、示形动敌、因情用兵","source_tier":"primary","supports_models":["奇正相生","避实击虚","料敌于先·庙算先胜","示形动敌","因情用兵不拘成法"],"supports_cases":["lijing-c1","lijing-c2","lijing-c3","lijing-c4"],"note":"一手/二手·兵书与史传"},{"ref_id":"lijing-s2","title":"唐代军事与《问对》研究","locator":"李靖兵学、对孙子的发展","source_tier":"secondary","supports_models":["奇正相生","避实击虚"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"常规与奇招相互转化循环无穷以正合以奇胜使对手摸不透(奇正相生)；集中力量打击空虚薄弱无备之处用强点打弱点(避实击虚)；战前充分研判先胜而后求战不打无把握之仗(料敌于先庙算先胜)；主动以示形假象佯动调动迷惑对手掌握主动(示形动敌)；不拘固定成法根据具体天时地利敌情灵活变通(因情用兵不拘成法)","steps":[{"invoke":"奇正相生","action":"你是把常规与奇招割裂固定、还是让二者相互转化、以正合以奇胜、使对手摸不透？"},{"invoke":"避实击虚","action":"你是正面硬撼对手最坚实之处、还是集中力量避实击虚、打其薄弱无备？"},{"invoke":"料敌于先·庙算先胜","action":"你是贸然行动、还是战前充分研判、先确认有把握才行动？"},{"invoke":"示形动敌","action":"你是被动应对、还是主动以示形调动、迷惑对手、掌握主动？"},{"invoke":"因情用兵不拘成法","action":"你是拘泥固定的成法、还是根据具体的天时地利敌情灵活变通？"}],"contrast":"与孙子不同(关键差异·原理与精微展开)：**孙子《孙子兵法》是''奇正、虚实、诡道''等的原理总纲与兵法奠基(高度凝练的抽象原则)**；**李靖《李卫公问对》是''对孙子奇正虚实的精微辩证与实战展开''(把原理拆解、辨析、操作化的君臣兵学问答)**——孙子立纲、李靖深化与实战化;李靖是站在孙子肩上、把''奇正相生''''避实击虚''讲得更细更可用(见孙子卡)。与韩信不同：韩信是''具体的奇谋战例''(背水一战、明修栈道——临阵的灵光);李靖是''奇正虚实的系统化、理论化运用''(把奇谋背后的道理讲透)(见韩信卡)。与曹操不同：曹操是''军政经一体的乱世枭雄'';李靖是''纯粹兵学上奇正虚实的大家''(见曹操卡)。【射程/盲区】李靖之道在''奇正相生、避实击虚、庙算先胜、示形动敌、因情用兵''极有力(尤其对抗、博弈、用兵)，但①其学高度依赖对奇正虚实的精妙把握与火候、需极高悟性与经验、新手易学成教条或弄巧成拙;②精微的权变之术用于不需对抗博弈的场景(如需坦诚合作)可能过度算计;③''示形动敌''的诡道用得不当或被识破反受其害;④兵学的取胜逻辑不直接适用于非零和共赢的领域。适用竞争博弈/危机应对/组织管理;不适用创作/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"lijing-c1","note":"用户''在博弈/竞争中、要么只会按常规出牌(只有''正'')、要么一味想出奇招(只有''奇'')、用得僵硬、被对手看穿''时，以李靖的奇正相生类比：他对孙子''奇正''的精微展开是——奇与正不是两套固定的东西、而是相互转化、循环无穷:以常规(正)稳住局面、以奇招(奇)出制胜、且常规可以变成奇、奇也可以变成常规、不断变化、使对手永远摸不透你下一步;别把常规与奇招割裂固定、让二者相生循环（奇正相生为《李卫公问对》对孙子的展开→确证）"},{"source":"case","case_id":"lijing-c2","note":"用户''在竞争中习惯于正面硬撼对手最强、最坚实的地方、撞得头破血流''时，以李靖的避实击虚类比：他深谙孙子''避实而击虚''——不去硬碰对手的坚实之处、而是集中自己的力量、打击对手空虚、薄弱、没有防备的地方;别正面硬撼最坚实处、集中力量避实击虚、用你的强点打对方的弱点（避实击虚为《李卫公问对》论虚实→确证）"}]},"further_reading":[{"title":"《李卫公问对》、《旧唐书·李靖传》","why":"奇正相生、避实击虚、庙算先胜、示形动敌、因情用兵的出处（A/B）","type":"兵书/史传"},{"title":"唐代军事与《问对》研究","why":"对李靖兵学与其对孙子发展的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/lijing.png","avatar_thumb":"/advisors/portraits/lijing.png","domain":"战略","person_id":"P-lijing","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'd7e7c9d52013805f6ccc6004c0bd45b0c30cb7f82f4320c5bd5b879bb854f1c6', 51, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('lincoln', 'P-lincoln', '林肯', 'governance', '林肯 · 治理领导思维框架卡', '19世纪（1809—1865）', 'zh-CN', 'published', 'approved', 'pass', 'deceased', 'rich', '目的坚定·手段灵活 · 待时而动', '/advisors/portraits/lincoln.png', '/advisors/portraits/lincoln.png', 5, 0, '{"schema_version":1,"card_id":"lincoln","name":"林肯","title":"林肯 · 治理领导思维框架卡","era":"19世纪（1809—1865）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"目的坚定·手段灵活","definition":"把唯一至高目标设为不可妥协的硬约束，其余手段、时机、姿态全部当作可调整可交易的变量","source":"1862年致格里利公开信\"此役至高无上的目标是拯救联邦\"","source_tier":"primary","mechanism":"输入=一个多方拉扯的难局 → 处理=锁定唯一至高目标为不可妥协的硬约束，把其余手段/时机/姿态/面子全部当作可调整可交易的变量 → 输出=以目标统御手段的决策","trigger":"面对''要不要为了一个诉求而动摇根本目标''的压力时","modern_transfer":"做难决策前先逼问''哪个目标是我绝不让步的硬约束''，其余价格/时机/姿态全可谈；最常见的错是把手段（某产品形态、某路径）误当成目的、宁折不弯","architecture":{"type":"hierarchy","components":["至高目标（硬约束）","手段","时机","姿态"]},"strategy_card_image":"kb-assets/lincoln/model-1.png"},{"name":"待时而动","definition":"正确的决定也要等条件成熟才出手；早一步可能因时机不对、姿态不对而失败","source":"解放宣言押后至安提塔姆战役止颓后（1862年9月）才发布，避免显得出于绝望","source_tier":"secondary","mechanism":"输入=一个已判断正确的决定 → 处理=评估当前姿态/时机是否成熟，宁可压着等条件成熟 → 输出=在''对的时点''以''对的姿态''出手","trigger":"决定正确、但当下出手可能因姿态不对（显得绝望/虚弱）而失败时","modern_transfer":"一个正确的决定若在错误的时点出手，会因''姿态不对''而失败；对的事也要等对的时机——''我是不是对得太早了''是个真问题","architecture":{"type":"flow","components":["判定决定正确","评估时机姿态","压住待势","择机出手"]},"strategy_card_image":"kb-assets/lincoln/model-2.png"},{"name":"纳政敌入核心","definition":"刻意让最强的反对者与竞争者进入决策核心，用认知多样性对冲盲区，而非用顺从者包围自己","source":"1861年组阁起用西华德、蔡斯、贝茨等曾与其争逐总统之人（史称\"政敌团队\"）","source_tier":"secondary","mechanism":"输入=组建决策核心圈 → 处理=刻意纳入最强的反对者与竞争者，用认知多样性对冲盲区，而非用顺从者包围自己 → 输出=一个吵闹但强大、能纠错的核心","trigger":"组班子/搭决策圈、且有''求安稳找听话的人''诱惑时","modern_transfer":"用认知多样性和敢当面反对你的人对冲盲区，远胜用顺从者包围自己换舒适——你身边有没有一个''敢拍桌子''的人","architecture":{"type":"matrix","components":["识别最强反对者","纳入核心圈","容忍龃龉","对冲盲区"]},"strategy_card_image":"kb-assets/lincoln/model-3.png"},{"name":"冷信不发","definition":"把宣泄情绪与做出决定切开：愤怒时可把话写下来，但压一压、不立刻发出，别让怒气替你拍板","source":"1863年葛底斯堡后致米德将军的斥责信写就却终未寄出，文末自注\"未发、未署名\"","source_tier":"primary","mechanism":"输入=盛怒中要做的一个决定/要发的一封信 → 处理=把宣泄情绪与做出决定切开，怒时可写下来但压住、不立刻发出 → 输出=不让怒气替你拍板的决定","trigger":"愤怒上头、想立刻发难或发出某条消息时","modern_transfer":"把宣泄情绪和做出决定切开——怒火上头时把话写下来没问题，但压一压、别立刻发出；这是孙子''主不可以怒而兴师''的极可操作版本","architecture":{"type":"flow","components":["情绪上头","写下而不发","冷却缓一缓","再决定"]},"strategy_card_image":"kb-assets/lincoln/model-4.png"},{"name":"以叙事赋予意义","definition":"领导者通过重构\"这场斗争到底为何\"来凝聚人心，把具体冲突提升为更高目的，从而改变现实","source":"葛底斯堡演说、第二任就职演说重新定义内战的意义","source_tier":"primary","mechanism":"输入=一场具体而残酷的冲突 → 处理=重构''这场斗争到底为何''，把具体冲突提升为更高目的 → 输出=凝聚人心、改变现实的共同意义","trigger":"需要凝聚人心、或为一段苦难/冲突定调收尾时","modern_transfer":"人不是被数据驱动的，是被意义驱动的；同一件苦差事你把它叙述成什么，决定了别人愿不愿意跟你一起扛","architecture":{"type":"flow","components":["具体冲突","提炼更高目的","重述意义","凝聚人心"]},"strategy_card_image":"kb-assets/lincoln/model-5.png"}],"decision_principles":["分清不可逆与可逆：至高目标守死，手段与时机则灵活（致格里利信，A）","对的事也要等对的时机才做（解放宣言押后，B）","用人取其才、不计旧怨，让政敌为我所用（组阁，B）","怒不决事：情绪上头时先压下决定、缓一缓（冷信不发，A）","赢局面优于赢报复：着眼冲突之后的共处（第二任就职演说，A）"],"inquiry_questions":["这件事里你绝不能让步的那个至高目标，到底是什么？","你是对的，但时机对吗？早一步做会不会反而失败？","你身边有人敢当面反对你吗？最强的反对者能不能请进核心圈？","这个决定多少是为解决问题、多少只是想出口气？这封信非发不可吗？","冲突过去后，你要的是赢一场胜利，还是赢一个还能共处的局面？"],"value_priorities":["联邦存续（整体存亡） ＞ 即时的道德姿态与纯洁性（林肯个人反奴，但把解放的时机与手段服从于\"保全联邦\"这一至高目标——以手段成全目的）","长远的和解 ＞ 短期的清算与报复（\"对任何人不怀恶意\"，着眼战后能否真正共处）","实际效果 ＞ 情绪满足（怒不决事、冷信不发）","可行的渐进 ＞ 一步到位的理想（在可行边界内推进，而非全有或全无）"],"blind_spots":["战时压制公民自由：中止人身保护令、压制部分报刊，为联邦存续越过宪法边界，当时（如塔尼大法官）及后世均受批评（史学界，B）","渐进主义在道德议题上显得过慢：废奴派（及一度的道格拉斯）嫌其在奴隶制上过于谨慎拖延；''手段灵活''易滑向道德上的迟疑（史学界，B）","方法绑定''单一至高目标''情境：目的-手段模型在有多个同等正当、无主轴的目标时给不出指引——与其强项同源（结构性局限）"],"applicable_domains":["治理决策","领导力","危机应对","长期规划"],"match_tags":["治理决策","领导力","危机应对","长期规划","目的手段分离","务实渐进","长期主义","近代北美"],"linked_cases":["lincoln-c1","lincoln-c2","lincoln-c3","lincoln-c4","lincoln-c5","lincoln-c6"],"life_tags":[{"tag":"发布解放宣言","tier":"secondary"},{"tag":"领导南北战争","tier":"secondary"},{"tag":"致葛底斯堡词","tier":"secondary"},{"tag":"维护联邦统一","tier":"secondary"}],"voice_profile":{"notes":"朴素有力；善用比喻与故事；庄重而克制；圣经与法律语汇"},"references":[{"ref_id":"lincoln-s1","title":"致 Horace Greeley 公开信（1862-08-22）","locator":"\"My paramount object in this struggle is to save the Union\" 段","source_tier":"primary","supports_models":["目的坚定·手段灵活"],"supports_cases":["lincoln-c3"],"note":"一手文献，可精确定位"},{"ref_id":"lincoln-s2","title":"预备《解放宣言》时序（1862-09-22，安提塔姆战役后五日）","locator":"发布日 1862-09-22 紧随 1862-09-17 安提塔姆战役","source_tier":"secondary","supports_models":["待时而动"],"supports_cases":["lincoln-c2"],"note":"时序为确证事实；\"待胜势再发\"动机解读需据权威史著核验"},{"ref_id":"lincoln-s3","title":"致 George Meade 将军信（1863-07-14，未寄）","locator":"信末亲批 \"never sent, or signed\"；原件存美国国会图书馆林肯文献集","source_tier":"primary","supports_models":["冷信不发"],"supports_cases":["lincoln-c4"],"note":"一手文献，可精确定位"},{"ref_id":"lincoln-s4","title":"葛底斯堡演说（1863-11-19）/ 第二任就职演说（1865-03-04）","locator":"葛底斯堡 \"government of the people...\" 句；就职 \"With malice toward none\" 段","source_tier":"primary","supports_models":["以叙事赋予意义"],"supports_cases":["lincoln-c5"],"note":"一手文献，可精确定位"},{"ref_id":"lincoln-s5","title":"1861 年首届内阁名单","locator":"Seward / Chase / Bates 等 1860 党内总统提名竞争者入阁","source_tier":"secondary","supports_models":["纳政敌入核心"],"supports_cases":["lincoln-c1"],"note":"名单为确证事实；\"政敌团队\"诠释需据权威史著核验"},{"ref_id":"lincoln-s6","title":"战时中止人身保护令 / Ex parte Merryman（1861）","locator":"1861 起中止令；塔尼大法官 Merryman 案司法意见","source_tier":"secondary","supports_models":["目的坚定·手段灵活"],"supports_cases":["lincoln-c6"],"note":"事件与司法争议为确证；具体令文与评价需据宪法史著核验。本条亦是 blind_spots① 的案例体现"}],"material_type":"rich","reasoning_skeleton":{"signature":"先锁死那个绝不让步的至高目标，其余手段时机姿态全可谈——对的事也要等对的时机，怒不决事，收尾着眼和解","steps":[{"invoke":"目的坚定·手段灵活","action":"先逼出唯一不可妥协的至高目标，把它设为硬约束；其余手段/时机/姿态/面子一律划为可调整变量"},{"invoke":"待时而动","action":"即使决定正确，也评估时机姿态是否成熟，宁可压住等条件成熟、避免''显得绝望''"},{"invoke":"纳政敌入核心","action":"搭决策圈时刻意纳入最强反对者，用认知多样性对冲自己的盲区"},{"invoke":"冷信不发","action":"若情绪上头，先把话写下而不发、冷却一缓，别让怒气替你拍板"},{"invoke":"以叙事赋予意义","action":"收尾时重构冲突的意义、着眼和解共处，而非清算报复"}],"contrast":"与诸葛亮相反：二者都谈治理领导，但诸葛亮先画''终局蓝图''再求稳律己、使命压过算账；林肯不预设宏大蓝图，而是锁死一个至高目标后让一切手段时机都可交易，且刻意纳政敌、收尾求和解（见诸葛亮卡）。与孙子在''该不该出手''上节奏不同：孙子合于利而动，林肯则''对的事也要押后待时机''（见孙子卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"lincoln-c3","note":"用户''各方都在逼我、我快守不住根本目标了''时，以致格里利公开信类比：林肯公开申明至高目标是拯救联邦、救联邦需解放则解放需不解放则不解放——以目标统御手段，既不背弃信念又不动摇根本（一手/确证）"},{"source":"case","case_id":"lincoln-c4","note":"用户''我气坏了、想立刻发难/发这条消息''时，以致米德''冷信未发''类比：写下措辞严厉的斥责信却压住终未寄、文末自注''未发未署名''，把宣泄情绪与做决定切开（一手/确证）"}]},"further_reading":[{"title":"Doris Kearns Goodwin《Team of Rivals》（中译《无敌：林肯的政治天才》）","why":"''政敌团队''的权威来源，详述林肯如何驾驭一群曾与他争位的强人","type":"biography"},{"title":"林肯演说与书信选（葛底斯堡演说 / 第二任就职演说 / 致格里利信 / 致米德未寄信）","why":"他本人的文字，''目的坚定手段灵活''''以叙事赋予意义''''冷信不发''的第一手出处","type":"original"},{"title":"David Herbert Donald《Lincoln》","why":"学界推崇的单卷本权威传记，看其决策方法的完整脉络与争议（如战时压制公民自由）","type":"biography"}],"qc":{"blind_recognition":"pass","counter_example":"pass","differentiation":"pass","traceability":"pass"},"avatar":"/advisors/portraits/lincoln.png","avatar_thumb":"/advisors/portraits/lincoln.png","domain":"治理","person_id":"P-lincoln","asset_display_mode":"portrait_crop","source_review_status":"approved","knowledge_qc_status":"pass"}', 'd2c990bcbf02a2facd61c42dac35e1eb96e92f9eadba72ca445baac721c7db86', 52, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('lishimin', 'P-lishimin', '李世民', 'governance', '唐太宗李世民 · 纳谏用人思维框架卡', '隋唐（599—649）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '兼听则明 · 知人善任', '/advisors/portraits/lishimin.png', '/advisors/portraits/lishimin.png', 5, 0, '{"schema_version":1,"card_id":"lishimin","name":"李世民","title":"唐太宗李世民 · 纳谏用人思维框架卡","era":"隋唐（599—649）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"兼听则明","definition":"主动征求并容纳反对意见、尤其逆耳之言，避免偏信一面而盲目——兼听则明、偏信则暗","source":"《贞观政要》《资治通鉴》","source_tier":"secondary","mechanism":"输入=只听一面之词、易偏信而盲目 → 处理=主动征求并容纳反对意见、尤其逆耳之言 → 输出=兼听多方而明、避免偏信一面","trigger":"做重大判断、易偏信一面时","modern_transfer":"主动征求并容纳反对意见、尤其逆耳之言——兼听则明、偏信则暗；最怕的不是有人反对你，而是没人敢反对你","architecture":{"type":"hierarchy","components":["识别只听一面的风险","主动征求反对意见","容纳逆耳之言","兼听而明"]},"strategy_card_image":"kb-assets/lishimin/model-1.png"},{"name":"知人善任","definition":"按每个人的长处配置位置、不求全责备，让各尽其才（房玄龄善谋、杜如晦善断，谋断相成）","source":"《旧唐书》《资治通鉴》","source_tier":"secondary","mechanism":"输入=用人求全责备、长处短处一把抓 → 处理=按每个人的长处配置位置、不求全责备 → 输出=各尽其才、长处互补(房谋杜断)","trigger":"配置人手、用人时","modern_transfer":"按每个人的长处配置位置、不求全责备——有人善谋、有人善断，让他们各尽其才、长短互补(房谋杜断)，比要求每个人都全能更高效","architecture":{"type":"hierarchy","components":["识别每人的长处","按长处配置位置","不求全责备","长短互补各尽其才"]},"strategy_card_image":"kb-assets/lishimin/model-2.png"},{"name":"以人为镜","definition":"把敢于直言的人当作镜子，用外部批评持续校准自己的得失——以人为镜、可以明得失","source":"《贞观政要》（魏徵）","source_tier":"secondary","mechanism":"输入=身居高位、易自我感觉良好而看不见错 → 处理=把敢于直言的人当镜子、用外部批评持续校准 → 输出=持续看见并纠正自己的得失","trigger":"身居高位、缺外部反馈纠错时","modern_transfer":"把敢于直言的人当作镜子——用外部批评持续校准自己的得失；位置越高越要主动留住几个敢当面说你不对的人(以人为镜可以明得失)","architecture":{"type":"loop","components":["留住敢直言的人","把批评当镜子","持续校准得失","不断自我纠偏"]},"strategy_card_image":"kb-assets/lishimin/model-3.png"},{"name":"居安思危载舟覆舟","definition":"在顺境/鼎盛时主动警惕风险与民心向背、戒骄奢，不因成功而骄怠——水能载舟、亦能覆舟","source":"《贞观政要》《资治通鉴》","source_tier":"secondary","mechanism":"输入=顺境/鼎盛、易因成功而骄怠 → 处理=主动警惕风险与民心向背、戒骄奢、以前朝覆亡为戒 → 输出=居安思危、不因成功而翻车","trigger":"顺境/鼎盛、易骄怠时","modern_transfer":"在顺境/鼎盛时主动警惕风险与人心向背——水能载舟、亦能覆舟；以前人的覆亡为戒、戒骄奢，越成功越要居安思危","architecture":{"type":"loop","components":["身处顺境鼎盛","以前朝覆亡为戒","警惕民心与风险","戒骄奢居安思危"]},"strategy_card_image":"kb-assets/lishimin/model-4.png"},{"name":"纳谏制度化","definition":"把\"听取意见\"变成制度（设谏官、鼓励上书、不罪言者），而非依赖领导者一时的雅量","source":"《资治通鉴》《贞观政要》","source_tier":"secondary","mechanism":"输入=听取意见全凭领导者一时心情、不稳定 → 处理=把听谏变成制度(设谏官、鼓励上书、不罪言者) → 输出=稳定的批评/纠错渠道(不依赖个人雅量)","trigger":"想让听取意见稳定、不靠个人情绪时","modern_transfer":"把''听取意见''变成制度(设专人/渠道、不惩罚提意见者)，而非依赖领导者一时的雅量——制度化的反馈渠道才稳定可靠(但若仍系于一人意志、终不牢靠)","architecture":{"type":"hierarchy","components":["识别纳谏靠心情的不稳","设谏官与上书渠道","不罪言者","稳定的纠错机制"]},"strategy_card_image":"kb-assets/lishimin/model-5.png"}],"decision_principles":["兼听则明、偏信则暗——主动征求反对意见，尤其逆耳之言","按长处用人、不求全责备，让各尽其才","把敢直言者当镜子，用外部批评持续纠偏","顺境鼎盛时居安思危、戒骄奢——水能载舟亦能覆舟","把听谏变成制度，不靠领导者一时雅量"],"inquiry_questions":["你做这个判断，听的是一面之词，还是主动找了反对意见？","你身边有没有敢当面说你不对的人？你留得住他吗？","你用人是按长处配置、还是求全责备？","你现在顺风顺水，警惕过哪些风险与人心向背吗？","你的''听意见''是靠你的心情，还是有稳定的制度渠道？"],"value_priorities":["兼听与纳谏 ＞ 乾纲独断（兼听则明；最怕没人敢反对你）","用人之长 ＞ 求全责备（各尽其才、长短互补，胜过要求全能）","居安思危 ＞ 因成功而骄怠（水能载舟亦能覆舟；越成功越要清醒）"],"blind_spots":["晚年纳谏渐少、渐生骄奢，远征高句丽失利——''善始者实繁、克终者盖寡''，其虚心纳谏未能贯彻始终（史实，B，客观标注）。","玄武门之变：杀兄（建成）弟（元吉）、逼父退位而夺位，其得位手段有重大道德污点（史实，B，〔慎〕，客观标注）。","《贞观政要》为后人（吴兢）编纂、部分对话经整理润色，''贞观之治''亦有史家美化成分，史料须辨（史料批判，B）。","纳谏高度依赖君主个人的意愿与明智，''人治''色彩重、未真正以制度约束皇权（原理推断，B）。"],"applicable_domains":["治理决策","领导力","组织管理"],"match_tags":["治理决策","领导力","组织管理","批判思辨","多元模型","务实渐进","古代东亚"],"linked_cases":["lishimin-c1","lishimin-c2","lishimin-c3","lishimin-c4"],"life_tags":[{"tag":"玄武门之变","tier":"secondary"},{"tag":"开贞观之治","tier":"secondary"},{"tag":"纳谏魏徵","tier":"secondary"},{"tag":"完善科举制","tier":"secondary"}],"voice_profile":{"notes":"从容自信、有雄主气度；肯纳谏、能自省；重实效与长治；以隋亡为镜常自警"},"references":[{"ref_id":"lishimin-s1","title":"《资治通鉴》","locator":"贞观纳谏、用人、隋亡之鉴、晚年得失诸卷","source_tier":"secondary","supports_models":["兼听则明","居安思危载舟覆舟","纳谏制度化"],"supports_cases":["lishimin-c1","lishimin-c3","lishimin-c4"],"note":"编年体正史，较可靠"},{"ref_id":"lishimin-s2","title":"《旧唐书》《新唐书》","locator":"太宗本纪、房玄龄杜如晦魏徵诸传","source_tier":"secondary","supports_models":["知人善任","以人为镜"],"supports_cases":["lishimin-c2"],"note":"正史纪传"},{"ref_id":"lishimin-s3","title":"《贞观政要》（吴兢编）","locator":"君道、纳谏、任贤、俭约诸篇","source_tier":"secondary","supports_models":["兼听则明","以人为镜","居安思危载舟覆舟","纳谏制度化"],"supports_cases":["lishimin-c1","lishimin-c3"],"note":"后人编纂、含整理润色与美化→事实主干可信、具体对话措辞存润色，不单独坐实细节"}],"material_type":"rich","reasoning_skeleton":{"signature":"做重大判断主动征求反对意见、尤其逆耳之言(兼听则明)；按长处用人、不求全责备(知人善任)；把敢直言者当镜子持续自我纠偏(以人为镜)；顺境鼎盛时警惕民心与风险、戒骄奢(居安思危载舟覆舟)；把听谏变成制度而非个人雅量(纳谏制度化)","steps":[{"invoke":"兼听则明","action":"你做这个判断，听的是一面之词，还是主动找了反对意见、尤其逆耳之言？"},{"invoke":"以人为镜","action":"你身边有没有敢当面说你不对的人？你留得住他吗？(把批评当镜子)"},{"invoke":"知人善任","action":"你用人是按长处配置、让各尽其才，还是求全责备？"},{"invoke":"居安思危载舟覆舟","action":"你现在顺风顺水，警惕过哪些风险与人心向背吗？(水能载舟亦能覆舟)"},{"invoke":"纳谏制度化","action":"你的''听意见''是靠你的心情，还是有稳定的制度渠道？"}],"contrast":"与诸葛亮不同(关键差异·同为治理)：诸葛亮重''隆中对顶层谋划+执法严明+事必躬亲''；李世民重''兼听纳谏+知人善任(放手用人之长)''——诸葛亮是亲力亲为的谋划者与执法者、李世民是善纳谏善用人的君主(见诸葛亮卡)。与商鞅不同：商鞅靠法家强制重塑；李世民靠纳谏用人柔性治理。与管仲不同：管仲重经济治国；李世民重纳谏与用人。与华盛顿不同：华盛顿是主动交权限权的建国者；李世民是在位君主的纳谏用人之术。与林肯不同：林肯在危机中维系联邦；李世民是治世的纳谏用人(见相应卡)。【射程/盲区】李世民之术适用于''听取意见+配置人才+守成纠偏''的治理；但①其纳谏高度依赖君主个人意愿、''人治''色彩重、未真正制度约束皇权；②晚年纳谏渐少、渐骄奢、征高句丽失利(''克终者盖寡'')；③〔慎〕玄武门之变杀兄弟逼父夺位是重大道德污点；④《贞观政要》后人编、含美化、史料须辨。适用治理/领导/组织管理；不适用创新研发/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"lishimin-c1","note":"用户''身边都是附和、缺人指出问题''时，以纳魏徵直谏类比：太宗虽屡被魏徵当面犯颜直谏、却多能纳之，魏徵死后叹''以人为镜可以明得失''——把敢直言者当镜子持续纠偏（魏徵直谏、''以人为镜''之叹为正史/《贞观政要》可考；惟《贞观政要》后人编、对话部分润色，宜重精神、慎引具体措辞）"},{"source":"case","case_id":"lishimin-c2","note":"用户''用人该求全还是用其长''时，以房谋杜断类比：房玄龄善谋、杜如晦善断，太宗用其所长、使谋断相成，不以一短弃人——按长处配置、各尽其才（房谋杜断为正史可考→确证）"}]},"further_reading":[{"title":"《资治通鉴》《旧唐书》《新唐书》（贞观纪事）","why":"纳谏、用人、居安思危、晚年得失的较可靠正史记载","type":"史书"},{"title":"《贞观政要》（吴兢编）","why":"君道/纳谏/任贤诸篇，后人编纂、含整理润色与美化，须辨","type":"文本"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/lishimin.png","avatar_thumb":"/advisors/portraits/lishimin.png","domain":"治理","person_id":"P-lishimin","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'be9db308a6fa2b6e41b89d9d9413b2a729a2a762d9da83ed35377e2dc6f89775', 53, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('livermore', 'P-livermore', '利弗莫尔', 'investing', '利弗莫尔 · 顺势投机与交易纪律思维框架卡', '现代（1877—1940）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '顺势而为 · 截断亏损让利润奔跑', '/advisors/portraits/livermore.png', '/advisors/portraits/livermore.png', 5, 0, '{"schema_version":1,"card_id":"livermore","name":"利弗莫尔","title":"利弗莫尔 · 顺势投机与交易纪律思维框架卡","era":"现代（1877—1940）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"顺势而为","definition":"别急于预测顶底、别逆着大势硬扛——先判断当前的大趋势方向、顺着趋势做（\"阻力最小的路径\"）","source":"利弗莫尔的趋势跟随","source_tier":"secondary","mechanism":"输入=逆着大势硬扛、急于预测顶底 → 处理=判断大趋势方向、顺势做、阻力最小路径 → 输出=顺势(顺势而为)","trigger":"判断要不要进场/方向时","modern_transfer":"别急于预测顶底、别逆着大势硬扛——先判断当前的大趋势方向、顺着趋势做(''阻力最小的路径'');趋势没反转前别和它作对(利弗莫尔的趋势跟随)","architecture":{"type":"flow","components":["别逆着大势硬扛急于预测顶底","先判断当前的大趋势方向","顺着趋势做阻力最小路径","趋势没反转前别和它作对"]},"strategy_card_image":"kb-assets/livermore/model-1.png"},{"name":"截断亏损让利润奔跑","definition":"一旦做错、亏损了，果断认错离场（截断亏损），绝不死扛、绝不向下加码摊平；一旦做对、盈利了，让利润继续奔跑","source":"利弗莫尔的交易铁律","source_tier":"primary","mechanism":"输入=亏损死扛加码摊平、盈利急于兑现 → 处理=做错果断止损绝不死扛、做对让利润奔跑 → 输出=亏损小盈利大(截断亏损)","trigger":"持仓出现盈亏、要不要离场时","modern_transfer":"一旦做错、亏损了、果断认错离场(截断亏损)、绝不死扛、绝不向下加码摊平;一旦做对、盈利了、让利润继续奔跑、别因一点浮盈就急着兑现(''截断亏损、让利润奔跑''、利弗莫尔)","architecture":{"type":"flow","components":["别亏损死扛加码摊平盈利急于兑现","做错果断止损绝不死扛","做对让利润继续奔跑","亏损小盈利大"]},"strategy_card_image":"kb-assets/livermore/model-2.png"},{"name":"市场心理与情绪","definition":"市场（以及任何由人组成的局面）由贪婪与恐惧驱动——读懂大众的情绪，在普遍贪婪到极点时警惕，在普遍恐惧到极点时留意机会","source":"利弗莫尔深谙市场心理","source_tier":"primary","mechanism":"输入=以为市场是纯理性的 → 处理=读懂大众贪婪恐惧、顶点贪婪时警惕底部恐惧时留意 → 输出=读懂情绪(市场心理)","trigger":"判断市场/群体情绪极端时","modern_transfer":"市场(以及任何由人组成的局面)由贪婪与恐惧驱动——读懂大众的情绪、在普遍贪婪到极点时警惕、在普遍恐惧到极点时留意机会(利弗莫尔深谙市场心理、''华尔街没有新鲜事、因为人性不变'')","architecture":{"type":"flow","components":["别以为市场是纯理性的","读懂大众的贪婪与恐惧","普遍贪婪到极点时警惕","普遍恐惧到极点时留意机会"]},"strategy_card_image":"kb-assets/livermore/model-3.png"},{"name":"等待关键点","definition":"别频繁、冲动地行动——大部分时间耐心等待、观察，只在真正确认的\"关键时机\"（信号明确、胜率高）才重手出击","source":"利弗莫尔的\"关键点\"","source_tier":"primary","mechanism":"输入=频繁冲动交易 → 处理=耐心等待真正确认的关键点(信号明确胜率高)才重手出击 → 输出=赚大钱靠等待(关键点)","trigger":"要不要出手、出手时机时","modern_transfer":"别频繁地、冲动地行动——大部分时间耐心地等待、观察、只在真正确认了的''关键时机''(信号明确、胜率高)才重手出击;''赚大钱靠的是等待、而非交易''(利弗莫尔的''关键点''与耐心)","architecture":{"type":"flow","components":["别频繁冲动地行动","大部分时间耐心等待观察","只在真正确认的关键时机信号明确胜率高","才重手出击"]},"strategy_card_image":"kb-assets/livermore/model-4.png"},{"name":"独立判断不听消息","definition":"别听信小道消息、内幕、他人的\"保证\"，也别随大流——只相信你自己独立的分析、和市场（事实）本身给出的信号","source":"利弗莫尔强调独立判断","source_tier":"primary","mechanism":"输入=听小道消息内幕、随大流 → 处理=只相信自己独立的分析与市场本身的信号 → 输出=独立(独立判断)","trigger":"面对消息、他人意见、大流时","modern_transfer":"别听信小道消息、内幕、他人的''保证''、也别随大流——只相信你自己独立的分析、和市场(事实)本身给出的信号(利弗莫尔反复强调独立判断)","architecture":{"type":"flow","components":["别听信小道消息内幕他人的保证","也别随大流","只相信你自己独立的分析","和市场事实本身给出的信号"]},"strategy_card_image":"kb-assets/livermore/model-5.png"}],"decision_principles":["别逆大势、别预测顶底，顺着趋势做（阻力最小的路径）","做错果断止损、绝不摊平；做对让利润奔跑（截断亏损、让利润奔跑）","市场由贪婪与恐惧驱动，极度贪婪时警惕、极度恐惧时留意机会","耐心等待真正确认的''关键点''才重手出击（赚大钱靠等待）","别听消息、别随大流，只信自己的分析与市场本身的信号"],"inquiry_questions":["你是逆着大势硬扛、还是先判断大趋势方向、顺势而为？","做错亏损时你是死扛/摊平、还是果断止损？做对时你是急于兑现、还是让利润奔跑？","你是把市场当纯理性的、还是读懂了大众的贪婪与恐惧？","你是频繁冲动交易、还是耐心等待真正确认的''关键点''才出手？","你是听消息、随大流、还是只信自己的分析与市场本身的信号？"],"value_priorities":["顺势而为 ＞ 逆势硬扛（阻力最小的路径）","截亏奔利 ＞ 扛亏兑盈（绝不摊平亏损）","关键点的重击 ＞ 频繁的冲动（赚大钱靠等待）"],"blind_spots":["利弗莫尔虽数次赚得巨富、却也数次破产——投机/杠杆的高风险，即使顶尖高手也屡屡翻船，对普通人风险极大（史，B，客观标注）。","趋势跟随在震荡、无趋势的市场中会反复止损、被反复''打脸''（原理推断，B）。","其方法高度依赖个人的纪律、盘感与情绪控制，极难复制，且对心理是巨大消耗（原理推断，B）。","利弗莫尔数次大起大落、晚年潦倒、结局令人唏嘘——再高超的交易技巧也无法保证财务与人生的长久平安，投机之路代价极高、值得警醒（史，B，点到为止）。"],"applicable_domains":["投资","认知偏误与理性决策","竞争博弈"],"match_tags":["投资","认知偏误与理性决策","竞争博弈","务实渐进","风险规避","概率思维","现当代北美"],"linked_cases":["livermore-c1","livermore-c2","livermore-c3","livermore-c4"],"life_tags":[{"tag":"做空1929","tier":"secondary"},{"tag":"著作手回忆录","tier":"secondary"},{"tag":"数度起落","tier":"secondary"},{"tag":"创关键点法","tier":"secondary"}],"voice_profile":{"notes":"敏锐果决、纪律严苛；顺势而非逆势；重风控与耐心；独立而孤傲"},"references":[{"ref_id":"livermore-s1","title":"《股票作手回忆录》（Edwin Lefèvre）、利弗莫尔《如何在股市中交易》","locator":"顺势、截断亏损、市场心理、关键点、独立判断","source_tier":"primary","supports_models":["顺势而为","截断亏损让利润奔跑","市场心理与情绪","等待关键点","独立判断不听消息"],"supports_cases":["livermore-c1","livermore-c2","livermore-c3","livermore-c4"],"note":"一手/二手·半自传与交易著作（《回忆录》为半自传体）"},{"ref_id":"livermore-s2","title":"投机与交易心理研究","locator":"交易法、风险","source_tier":"secondary","supports_models":["截断亏损让利润奔跑","市场心理与情绪"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"别逆大势别预测顶底顺着趋势做阻力最小的路径(顺势而为)；做错果断止损绝不摊平做对让利润奔跑(截断亏损让利润奔跑)；市场由贪婪与恐惧驱动极度贪婪时警惕极度恐惧时留意机会(市场心理与情绪)；耐心等待真正确认的关键点才重手出击(等待关键点)；别听消息别随大流只信自己的分析与市场本身的信号(独立判断不听消息)","steps":[{"invoke":"顺势而为","action":"你是逆着大势硬扛、还是先判断大趋势方向、顺势而为？"},{"invoke":"截断亏损让利润奔跑","action":"做错亏损时你是死扛/摊平、还是果断止损？做对时你是急于兑现、还是让利润奔跑？"},{"invoke":"市场心理与情绪","action":"你是把市场当纯理性的、还是读懂了大众的贪婪与恐惧？"},{"invoke":"等待关键点","action":"你是频繁冲动交易、还是耐心等待真正确认的''关键点''才出手？"},{"invoke":"独立判断不听消息","action":"你是听消息、随大流、还是只信自己的分析与市场本身的信号？"}],"contrast":"与格雷厄姆/巴菲特不同(关键差异·投机vs价值·两个相反的流派)：**格雷厄姆、巴菲特是''价值投资''——研究企业的内在价值、以安全边际买入、长期持有(buy & hold,看的是''企业值多少钱'')**；**利弗莫尔是''趋势投机/交易''——顺势、截断亏损、读市场心理、等关键点(看的是''价格往哪走'')**——价值派看企业基本面、利弗莫尔看价格趋势与市场心理、是两条相反的路(见格雷厄姆/巴菲特卡)。与凯恩斯不同：凯恩斯虽也洞察市场心理(选美/动物精神)、但其实践是''逆向+集中价值持有'';利弗莫尔是''顺势+投机交易''——一个逆向持有、一个顺势交易(见凯恩斯卡)。【射程/盲区·历史诚实·重点】利弗莫尔之道在''顺势、截断亏损、市场心理、关键点、独立判断''对交易者极有价值(尤其纪律与风控的洞察)，但①投机/杠杆高风险、他本人数次赚巨富又数次破产、即使顶尖高手也屡翻船、对普通人风险极大、客观标注;②趋势跟随在震荡无趋势市场会反复止损;③高度依赖个人纪律盘感情绪控制、极难复制、对心理是巨大消耗;④利弗莫尔数次大起大落、晚年潦倒、结局令人唏嘘——再高的交易技巧也保证不了财务与人生的长久平安、投机代价极高、值得警醒(点到为止)。适用投资/认知偏误与理性决策/竞争博弈;不适用创作/修身自省。"},"persona_anchor":{"primary":[{"source":"case","case_id":"livermore-c2","note":"用户''在交易/决策中、亏了舍不得止损、死扛甚至越跌越加码想摊平、赚了一点又急着兑现''时，以利弗莫尔的交易铁律类比：他一生反复强调''截断亏损、让利润奔跑''——一旦做错就果断认错离场、绝不死扛、绝不向下加码摊平亏损(他认为摊平亏损是散户最致命的错);一旦做对就让利润继续奔跑、别因一点浮盈就急着了结;''截断亏损、让利润奔跑''（利弗莫尔交易铁律→确证）"},{"source":"case","case_id":"livermore-c3","note":"用户''手痒、频繁冲动地交易/行动、却赚不到钱''时，以利弗莫尔的''关键点''与耐心类比：他说自己赚大钱''靠的从来不是我的思考、而是我的等待''——大部分时间他只是耐心观察、按兵不动、只在行情真正确认了的''关键点''(信号明确、胜率高)才重仓出击;别频繁冲动行动、耐心等待真正确认的关键时机才重手出击（利弗莫尔''赚大钱靠等待''→确证）"}]},"further_reading":[{"title":"《股票作手回忆录》（Edwin Lefèvre）、利弗莫尔《如何在股市中交易》","why":"顺势、截断亏损、市场心理、关键点、独立判断的出处（A/B）","type":"原著/传记"},{"title":"投机与交易心理研究","why":"对利弗莫尔交易法与其风险的学术/业界分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/livermore.png","avatar_thumb":"/advisors/portraits/livermore.png","domain":"投资","person_id":"P-livermore","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'cb1e4c25eaed52125ba6868c15eeed6d204b7fa909bf8609c33b7aa4b9183506', 54, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('luzuofu', 'P-luzuofu', '卢作孚', 'business', '卢作孚 · 实业救国与化零为整思维框架卡', '现代（1893—1952）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '实业救国 · 化零为整统一航运', '/advisors/portraits/luzuofu.png', '/advisors/portraits/luzuofu.png', 5, 0, '{"schema_version":1,"card_id":"luzuofu","name":"卢作孚","title":"卢作孚 · 实业救国与化零为整思维框架卡","era":"现代（1893—1952）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"实业救国","definition":"把办实业、办企业当作救国与建设社会的手段，而非纯粹赚钱——企业可以是改造社会的工具","source":"卢作孚文集及民生公司史","source_tier":"secondary","mechanism":"输入=把办企业当纯赚钱 → 处理=把办实业当救国与建设社会的手段、企业是改造社会的工具 → 输出=以实业服务于社会改造","trigger":"思考办实业的根本目的时","modern_transfer":"把办实业、办企业当作救国与建设社会的手段、而非纯粹赚钱——企业可以是改造社会的工具(卢作孚''实业救国''、办民生公司、建设北碚)〔须量力、见盲区〕","architecture":{"type":"hierarchy","components":["别把办企业当纯赚钱","把办实业当救国与建设社会的手段","企业是改造社会的工具","以实业服务于社会改造"]},"strategy_card_image":"kb-assets/luzuofu/model-1.png"},{"name":"化零为整统一航运","definition":"当同行一盘散沙、被强敌各个击破时，把分散内斗的力量整合统一、形成合力去对抗","source":"民生公司统一川江航运史","source_tier":"secondary","mechanism":"输入=一盘散沙、各自为战、被强敌各个击破 → 处理=把分散内斗的同行整合统一、形成合力 → 输出=以整合形成对抗强敌的合力","trigger":"面对一盘散沙、被强敌各个击破时","modern_transfer":"当同行一盘散沙、各自为战、被强敌(如外国航运)各个击破时——把分散内斗的力量整合统一、形成合力去对抗(卢作孚统一川江航运、从外国公司手中收回内河航运权)","architecture":{"type":"hierarchy","components":["别一盘散沙各自为战","把分散内斗的力量整合统一","形成合力","以整合对抗强敌"]},"strategy_card_image":"kb-assets/luzuofu/model-2.png"},{"name":"乡村现代化试验","definition":"别空谈改造，选一个地方当试验田、系统地建设（教育/经济/文化/基础设施），做可复制的示范","source":"卢作孚北碚乡村建设","source_tier":"secondary","mechanism":"输入=空谈改造社会、无落点 → 处理=选一个地方当试验田、系统地建设(教育/经济/文化/基础设施)、做可复制的示范 → 输出=以局部的系统建设示范整体改造","trigger":"要推动一项大的社会/系统改造时","modern_transfer":"别空谈改造——选一个地方当''试验田''、系统地建设(教育、经济、文化、卫生、基础设施)、做出一个可复制的示范(卢作孚把北碚从匪患之地建成乡村现代化的样板)","architecture":{"type":"hierarchy","components":["别空谈改造无落点","选一个地方当试验田","系统地建设教育经济文化","做可复制的示范"]},"strategy_card_image":"kb-assets/luzuofu/model-3.png"},{"name":"化危为机的组织动员","definition":"危难关头、千头万绪、看似不可能时，以卓越的组织调度把任务拆解执行、化不可能为可能","source":"卢作孚指挥宜昌大撤退","source_tier":"secondary","mechanism":"输入=危难当前、千头万绪、看似不可能 → 处理=以卓越的组织、调度、分段接力把不可能的任务拆解执行 → 输出=化危为机完成壮举","trigger":"危难关头、面对看似不可能的任务时","modern_transfer":"危难关头、千头万绪、看似不可能时——以卓越的组织、调度、分段接力把任务拆解执行、化不可能为可能(卢作孚指挥宜昌大撤退、40天抢运人员与战略物资、被誉为''中国实业界的敦刻尔克'')","architecture":{"type":"flow","components":["危难当前千头万绪看似不可能","以卓越的组织与调度","分段接力把任务拆解执行","化不可能为可能"]},"strategy_card_image":"kb-assets/luzuofu/model-4.png"},{"name":"廉洁奉公表率","definition":"手握资源与权力时，以身作则的清廉、不谋私利，把使命置于个人得失之上","source":"卢作孚一生清廉的史述","source_tier":"secondary","mechanism":"输入=以权谋私、中饱私囊 → 处理=以身作则的清廉、不谋私利、把使命置于个人得失之上 → 输出=以廉洁立信、凝聚人心","trigger":"手握资源与权力、面对私利诱惑时","modern_transfer":"手握资源与权力时、以身作则的清廉、不谋私利、把使命置于个人得失之上——以廉洁立信、凝聚人心(卢作孚一生清廉、身后清贫)","architecture":{"type":"flow","components":["别以权谋私中饱私囊","以身作则的清廉","把使命置于个人得失之上","以廉洁立信凝聚人心"]},"strategy_card_image":"kb-assets/luzuofu/model-5.png"}],"decision_principles":["把办实业当救国与建设社会的手段，而非纯粹赚钱（须量力）","同行一盘散沙、被强敌各个击破时，整合统一、形成合力对抗","别空谈改造，选一个地方当试验田、系统建设、做可复制的示范","危难关头以卓越的组织调度把任务拆解执行、化不可能为可能","手握资源权力时以身作则的清廉、不谋私利、凝聚人心"],"inquiry_questions":["你办这件事，是纯为赚钱、还是把它当建设社会/解决更大问题的手段？","你这边是不是一盘散沙、被强敌各个击破？能不能整合成合力？","你是在空谈改造、还是选一个落点当试验田系统地建、做出可复制的示范？","危难当前看似不可能时，你能不能以组织调度把它拆解执行？","你手握资源权力时，是以权谋私、还是以身作则的清廉凝聚人心？"],"value_priorities":["实业服务于社会改造 ＞ 办企业纯为赚钱（实业救国、办民生、建北碚（须量力））","整合统一形成合力 ＞ 一盘散沙各自为战（统一川江航运、收回内河航运权）","系统建设做示范 ＞ 空谈改造（把北碚建成乡村现代化样板）"],"blind_spots":["''实业救国''的宏大使命以特定的救亡历史语境为前提，其具体形式未必能直接套用于今天（原理推断，B）。","把企业过度地承载社会改造的使命，可能超出企业自身能力与财力、危及企业存续（原理推断，B）。","乡村现代化试验（北碚）的成功也依赖卢作孚个人的威望、资源与时代条件，难以简单复制（原理推断，B）。","〔注意〕卢作孚晚年的遭遇与时代背景有关；本卡只取其实业与建设的方法，对相关历史客观标注、不展开（史实，B）。"],"applicable_domains":["创业","组织管理","危机应对","长期规划"],"match_tags":["创业","组织管理","危机应对","长期规划","利他取向","系统分析","长期主义","现当代东亚"],"linked_cases":["luzuofu-c1","luzuofu-c2","luzuofu-c3","luzuofu-c4"],"life_tags":[{"tag":"创民生公司","tier":"secondary"},{"tag":"指挥宜昌撤退","tier":"secondary"},{"tag":"建北碚新区","tier":"secondary"},{"tag":"兴乡村教育","tier":"secondary"}],"voice_profile":{"notes":"沉静担当、务实笃行；组织力极强；家国情怀；清廉自持"},"references":[{"ref_id":"luzuofu-s1","title":"卢作孚文集与传记","locator":"实业救国、统一航运、北碚建设、宜昌大撤退、廉洁","source_tier":"secondary","supports_models":["实业救国","化零为整统一航运","乡村现代化试验","化危为机的组织动员","廉洁奉公表率"],"supports_cases":["luzuofu-c1","luzuofu-c2","luzuofu-c3","luzuofu-c4"],"note":"二手·文集/传记（部分含其一手文章）"},{"ref_id":"luzuofu-s2","title":"民生公司史、宜昌大撤退史","locator":"统一川江航运、宜昌大撤退","source_tier":"secondary","supports_models":["化零为整统一航运","化危为机的组织动员"],"supports_cases":["luzuofu-c2","luzuofu-c4"],"note":"二手·企业/事件史"}],"material_type":"rich","reasoning_skeleton":{"signature":"把办实业当救国与建设社会的手段、企业是改造社会的工具(实业救国)；把分散内斗的同行整合统一形成合力对抗强敌(化零为整统一航运)；选一地当试验田系统建设做可复制的示范(乡村现代化试验)；危难关头以卓越组织调度化不可能为可能(化危为机的组织动员)；以身作则的清廉不谋私利(廉洁奉公表率)","steps":[{"invoke":"实业救国","action":"你办这件事，是纯为赚钱、还是把它当建设社会/解决更大问题的手段？"},{"invoke":"化零为整统一航运","action":"你这边是不是一盘散沙、被强敌各个击破？能不能整合成合力？"},{"invoke":"乡村现代化试验","action":"你是在空谈改造、还是选一个落点当试验田系统地建、做出可复制的示范？"},{"invoke":"化危为机的组织动员","action":"危难当前看似不可能时，你能不能以组织调度把它拆解执行？"},{"invoke":"廉洁奉公表率","action":"你手握资源权力时，是以权谋私、还是以身作则的清廉凝聚人心？"}],"contrast":"与陈嘉庚不同(关键差异·同为家国情怀的实业家)：**陈嘉庚侧重''实业反哺、倾资兴学、教育与民族担当''(以教育为主轴)**；**卢作孚侧重''实业救国、化零为整统一航运、乡村现代化试验、宜昌大撤退的组织动员''(以产业整合、地方系统建设与危机组织为主轴)**——同是家国实业家、陈嘉庚兴学、卢作孚建设与组织(见陈嘉庚卡)。与松下/稻盛不同：松下/稻盛是经营哲学(社会公器/敬天爱人);卢作孚是''实业救国+乡村建设''的中国近代救亡语境下的实业家(见松下/稻盛卡)。【射程/盲区】卢作孚之道在''实业救国、化零为整、乡村试验、危机组织、廉洁奉公''极有力，但①''实业救国''的宏大使命以特定救亡历史语境为前提、具体形式未必能直接套用于今天;②把企业过度承载社会改造使命、可能超出企业能力与财力、危及存续;③北碚试验的成功也依赖卢作孚个人威望、资源与时代条件、难以简单复制;④〔注意〕卢作孚晚年的遭遇与时代背景有关、本卡只取方法、客观标注、不展开。适用创业/组织管理/危机应对/长期规划;不适用投资/谈判。"},"persona_anchor":{"primary":[{"source":"case","case_id":"luzuofu-c2","note":"用户''所在的行业/团队一盘散沙、各自为战、被强大的对手各个击破''时，以卢作孚化零为整类比：他把川江上分散内斗的中国小航运公司整合统一、形成合力、从把持内河航运的外国公司手中收回了航运权——一盘散沙时、把分散的力量整合成合力才能对抗强敌（统一川江航运为史实→确证）"},{"source":"case","case_id":"luzuofu-c4","note":"用户''面对一个危难当前、千头万绪、看似根本不可能完成的任务''时，以卢作孚指挥宜昌大撤退类比：抗战时数万人员与大量战略物资积压宜昌、长江将枯水、日军迫近，卢作孚以卓越的组织调度、分段接力，用约40天抢运完成、被誉为''中国实业界的敦刻尔克''——危局看似不可能时、靠组织调度把它拆解执行（宜昌大撤退为史实→确证）"}]},"further_reading":[{"title":"卢作孚文集与传记","why":"实业救国、统一航运、北碚建设、宜昌大撤退、廉洁的记述（B）","type":"文集/传记"},{"title":"民生公司史、宜昌大撤退史","why":"统一川江航运、宜昌大撤退的实践记录（B）","type":"企业/事件史"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/luzuofu.png","avatar_thumb":"/advisors/portraits/luzuofu.png","domain":"商业","person_id":"P-luzuofu","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '6dfceb72c9e5068358acc31800c3dab084a79ffe15149abcf1d78d213d569a24', 55, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('lynch', 'P-lynch', '彼得林奇', 'investing', '彼得林奇 · 投资你了解的与合理价格成长思维框架卡', '现代（1944— ）', 'zh-CN', 'published', 'in_review', 'pending', 'living', 'rich', '投资你了解的 · 成长股与合理价格', '/advisors/portraits/lynch.png', '/advisors/portraits/lynch.png', 5, 0, '{"schema_version":1,"card_id":"lynch","name":"彼得林奇","title":"彼得林奇 · 投资你了解的与合理价格成长思维框架卡","era":"现代（1944— ）","language":"zh-CN","status":"published","living_status":"living","core_models":[{"name":"投资你了解的","definition":"从你自己的生活、工作、日常消费里，留心发现那些你真正了解、有切身体会的好公司/好产品——在你熟悉的领域，你往往比专家更早、更准地发现机会","source":"林奇\"投资你所了解的\"","source_tier":"primary","mechanism":"输入=只听专家或盲目跟风 → 处理=从自己生活工作消费中发现真正了解有切身洞察的好公司 → 输出=熟悉领域更早发现(投资你了解的)","trigger":"寻找投资机会时","modern_transfer":"从你自己的生活、工作、日常消费里、留心发现那些你真正了解、有切身体会的好公司/好产品——在你熟悉的领域、你往往比华尔街专家更早、更准地发现机会(林奇''投资你所了解的''、从生活中发现牛股)〔但''了解产品''不等于''了解这门生意''、仍须做功课、见盲区〕","architecture":{"type":"flow","components":["别只听专家或盲目跟风","从自己的生活工作消费里留心","发现你真正了解有切身体会的好公司","在熟悉领域往往比专家更早发现机会"]},"strategy_card_image":"kb-assets/lynch/model-1.png"},{"name":"成长股与合理价格","definition":"别只买便宜的、也别只追高成长的——找那些\"盈利持续成长、而当前价格相对它的成长性还合理（不贵）\"的公司；成长与价格的平衡才是关键","source":"林奇的GARP","source_tier":"primary","mechanism":"输入=只买便宜或只追高成长 → 处理=找盈利持续成长而价格相对成长性还合理的公司 → 输出=成长与价格平衡(GARP)","trigger":"评估一只成长股时","modern_transfer":"别只买便宜的、也别只追高成长的——找那些''盈利持续成长、而当前价格相对它的成长性还合理(不贵)''的公司;成长与价格的平衡(如用 PEG 衡量)才是关键(林奇的''合理价格的成长股''GARP)","architecture":{"type":"matrix","components":["别只买便宜的也别只追高成长的","找盈利持续成长的公司","而当前价格相对其成长性还合理不贵","成长与价格的平衡是关键"]},"strategy_card_image":"kb-assets/lynch/model-2.png"},{"name":"寻找十倍股","definition":"在一个组合里，一两只能涨十倍的\"大牛股\"就足以拉动全局——所以一旦找到真正的好公司，要敢于长期持有、让利润充分成长","source":"林奇的\"十倍股\"","source_tier":"primary","mechanism":"输入=好股票涨一点就急着卖 → 处理=敢于在真正好公司上长期持有让利润充分成长 → 输出=一两只十倍股拉动全局(十倍股)","trigger":"持有一只表现好的好公司时","modern_transfer":"在一个组合里、一两只能涨十倍的''大牛股''就足以拉动全局——所以一旦找到真正的好公司、要敢于长期持有、让利润充分成长、别因为涨了一点就急着卖掉一只能涨十倍的股票(林奇的''十倍股''tenbagger)","architecture":{"type":"flow","components":["别好股票涨一点就急着卖","一旦找到真正的好公司","敢于长期持有让利润充分成长","一两只十倍股就足以拉动全局"]},"strategy_card_image":"kb-assets/lynch/model-3.png"},{"name":"亲自做功课调研","definition":"别只听一个动人的\"故事\"或小道消息就买——亲自去研究这家公司的基本面、财报、业务模式，甚至实地走访体验，把\"故事\"背后的事实核实清楚","source":"林奇的勤奋调研","source_tier":"primary","mechanism":"输入=只听故事或小道消息就买 → 处理=亲自研究基本面财报业务甚至实地走访核实故事 → 输出=核实事实(亲自调研)","trigger":"要不要买一只股票前","modern_transfer":"别只听一个动人的''故事''或小道消息就买——亲自去研究这家公司的基本面、财报、业务模式、甚至实地走访体验、把''故事''背后的事实核实清楚(林奇以极勤奋的亲自调研著称)","architecture":{"type":"flow","components":["别只听动人的故事或小道消息就买","亲自研究基本面财报业务模式","甚至实地走访体验","把故事背后的事实核实清楚"]},"strategy_card_image":"kb-assets/lynch/model-4.png"},{"name":"给公司分类对症下药","definition":"别用同一套标准对待所有标的——把它们按\"类型\"分类，不同类型有不同的合理预期、风险与买卖策略，对症下药","source":"林奇的六类公司","source_tier":"primary","mechanism":"输入=用同一套标准对待所有标的 → 处理=把公司按类型分类、不同类型不同预期与策略 → 输出=对症下药(分类)","trigger":"分析不同标的时","modern_transfer":"别用同一套标准对待所有标的——把它们按''类型''分类(如稳健型、快速成长型、周期型、困境反转型…)、不同类型有不同的合理预期、风险与买卖策略、对症下药(林奇把公司分为六大类)","architecture":{"type":"grid","components":["别用同一套标准对待所有标的","把它们按类型分类如稳健快速成长周期困境反转","不同类型不同的合理预期风险与买卖策略","对症下药"]},"strategy_card_image":"kb-assets/lynch/model-5.png"}],"decision_principles":["从生活、工作、消费里发现你真正了解的好公司（但仍须做功课）","找''盈利成长、价格相对成长性还合理''的成长股（成长与价格的平衡）","找到真正的好公司就敢于长期持有，让''十倍股''充分成长","别只听故事，亲自研究基本面、财报、业务，核实事实","把公司按''类型''分类，不同类型用不同预期与策略，对症下药"],"inquiry_questions":["你是只听专家/跟风、还是从自己熟悉的生活与工作里发现机会（但做功课了吗）？","你买的是只便宜、只高成长、还是''成长且价格相对成长性还合理''的公司？","找到真正的好公司，你是涨一点就卖、还是敢于持有让''十倍股''成长？","你是只听故事/消息就买、还是亲自研究了基本面、财报、业务？","你是用一套标准对待所有标的、还是按''类型''分类、对症下药？"],"value_priorities":["投资你了解的 ＞ 只听专家跟风（从生活发现牛股（仍须做功课））","成长与价格的平衡 ＞ 只便宜或只高成长（GARP/PEG）","持有十倍股 ＞ 涨一点就卖（tenbagger）"],"blind_spots":["''投资你了解的''易被误读为''用了某产品就买其股票''——了解产品不等于了解这门生意与估值，仍须做功课（原理推断，B，客观标注）。","其方法依赖极大的勤奋（亲自调研大量公司）与时间投入，对业余投资者实际上极难复制（史/原理，B）。","成长股/困境反转的判断极难、错了损失也大，其成功也有时代（美股长牛）与个人天赋因素（原理推断，B）。","【在世人物·框定】本卡仅为''基于其公开著作（《彼得林奇的成功投资》《战胜华尔街》）的方法论思维模拟、不代表本人真实观点''（框定）。"],"applicable_domains":["投资","认知偏误与理性决策"],"match_tags":["投资","认知偏误与理性决策","务实渐进","概率思维","多元模型","现当代北美"],"linked_cases":["lynch-c1","lynch-c2","lynch-c3","lynch-c4"],"life_tags":[{"tag":"执掌麦哲伦","tier":"secondary"},{"tag":"著成功投资","tier":"primary"},{"tag":"提十倍股","tier":"primary"},{"tag":"倡投资己知","tier":"primary"}],"voice_profile":{"notes":"务实勤勉、贴近生活；重成长与合理价；勤奋调研；深入浅出"},"references":[{"ref_id":"lynch-s1","title":"彼得林奇《彼得林奇的成功投资》《战胜华尔街》","locator":"投资你了解的、GARP、十倍股、亲自调研、公司分类","source_tier":"primary","supports_models":["投资你了解的","成长股与合理价格","寻找十倍股","亲自做功课调研","给公司分类对症下药"],"supports_cases":["lynch-c1","lynch-c2","lynch-c3","lynch-c4"],"note":"一手·原著（在世人物·限定方法论）"},{"ref_id":"lynch-s2","title":"成长投资与个人投资者研究","locator":"方法论、适用边界","source_tier":"secondary","supports_models":["投资你了解的","寻找十倍股"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"从自己熟悉的生活工作消费里发现真正了解的好公司但仍须做功课(投资你了解的)；找盈利持续成长而价格相对成长性还合理的公司成长与价格的平衡(成长股与合理价格)；找到真正的好公司就敢于长期持有让十倍股充分成长(寻找十倍股)；别只听故事亲自研究基本面财报业务核实事实(亲自做功课调研)；把公司按类型分类不同类型不同预期与策略对症下药(给公司分类对症下药)","steps":[{"invoke":"投资你了解的","action":"你是只听专家/跟风、还是从自己熟悉的生活与工作里发现机会（但做功课了吗）？"},{"invoke":"成长股与合理价格","action":"你买的是只便宜、只高成长、还是''成长且价格相对成长性还合理''的公司？"},{"invoke":"寻找十倍股","action":"找到真正的好公司，你是涨一点就卖、还是敢于持有让''十倍股''成长？"},{"invoke":"亲自做功课调研","action":"你是只听故事/消息就买、还是亲自研究了基本面、财报、业务？"},{"invoke":"给公司分类对症下药","action":"你是用一套标准对待所有标的、还是按''类型''分类、对症下药？"}],"contrast":"与巴菲特不同(关键差异)：**巴菲特高度集中、买少数有宽护城河的优质公司、长期重仓持有**；**林奇相对分散、广泛地从日常生活中发掘大量''合理价格的成长股(GARP)''、勤奋调研、按类型管理**——巴菲特集中守、林奇广撒网勤调研(见巴菲特卡)。与费雪不同(同重成长)：费雪深研少数卓越成长股、极长期持有(质化深研);林奇更重''从生活发现''、GARP估值、公司分类与十倍股(见费雪卡)。与博格不同：博格被动指数、不选股;林奇是主动选股的典范(见博格卡)。与格雷厄姆不同：格雷厄姆买便宜的烟蒂;林奇更看成长(见格雷厄姆卡)。【射程/盲区·在世框定】林奇之道在''投资你了解的、GARP、十倍股、亲自调研、公司分类''极有价值(尤其个人投资者的选股)，但①''投资你了解的''易被误读为''用了产品就买股票''、了解产品不等于了解生意与估值、仍须做功课、客观标注;②其方法依赖极大勤奋与时间、业余者实际极难复制;③成长/困境反转判断极难、错了损失大、成功也有时代(美股长牛)与天赋因素;④【在世人物·框定】本卡仅基于其公开著作的方法论思维模拟、不代表本人观点。适用投资/认知偏误与理性决策;不适用创作/修身自省。"},"persona_anchor":{"primary":[{"source":"case","case_id":"lynch-c1","note":"用户''想找投资机会、却觉得自己是外行、只能盲目听专家、追热点''时，以林奇''投资你了解的''类比：他认为普通人在自己熟悉的生活、工作、消费里、反而常常比华尔街专家更早发现好公司——你天天用的好产品、你工作中接触到的好生意、都是线索;从你真正了解、有切身体会的领域里去发现机会、你往往更有优势〔但务必注意:''喜欢一个产品''只是起点、不等于''这是一门好生意、且价格合理''、仍要做功课〕（林奇''投资你所了解的''为其著作→确证）"},{"source":"case","case_id":"lynch-c3","note":"用户''手里一只好公司的股票刚涨了一点、就忍不住想落袋为安、卖掉了''时，以林奇''十倍股''类比：他指出在一个组合里、往往是一两只能涨十倍(tenbagger)的大牛股、拉动了整个组合的回报;所以一旦你确认找到了一家真正优秀、还在成长的好公司、要敢于长期持有、让利润充分成长、别因为涨了百分之几十就急着卖掉一只本可以涨十倍的股票（林奇''十倍股''为案例 C3→确证；在世人物·限定方法论）"}]},"further_reading":[{"title":"彼得林奇《彼得林奇的成功投资》《战胜华尔街》","why":"投资你了解的、GARP、十倍股、亲自调研、公司分类的出处（A）","type":"original"},{"title":"成长投资与个人投资者研究","why":"对林奇方法论及其适用边界的分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/lynch.png","avatar_thumb":"/advisors/portraits/lynch.png","domain":"投资","person_id":"P-lynch","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '63d3f959162376013e587bb46ff3e52945b74ab140bfa27a6786f827345b0eec', 56, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('mandela', 'P-mandela', '曼德拉', 'history', '纳尔逊·曼德拉 · 转型领导与战略和解框架卡', '现当代（1918–2013）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '战略性和解 · 守标活法', '/advisors/portraits/mandela.png', '/advisors/portraits/mandela.png', 5, 0, '{"schema_version":1,"card_id":"mandela","name":"曼德拉","title":"纳尔逊·曼德拉 · 转型领导与战略和解框架卡","era":"现当代（1918–2013）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"战略性和解","definition":"把宽恕与和解当作避免内战、建立稳定多元国家的政治策略来运用，而非单纯的道德高尚或软弱","source":"权威南非转型史/传记","source_tier":"secondary","mechanism":"输入=剧烈对立后的转型期、清算会滑向内战/崩溃 → 处理=把宽恕和解当政治策略(保留失势方、真相换特赦、安抚恐惧)、而非道德姿态 → 输出=和解换稳定(优于清算换分裂、但有代价)","trigger":"剧烈对立后的转型期、清算会致分裂时","modern_transfer":"在剧烈对立后的转型期，''和解换稳定''常优于''清算换分裂''——把宽恕当稳定策略来用(安抚失势一方的恐惧)，而非为了显得高尚(诚实:和解有代价、未必带来实质正义)","architecture":{"type":"hierarchy","components":["评估清算的内战风险","把和解当稳定策略","安抚失势方恐惧","换稳定过渡"]},"strategy_card_image":"kb-assets/mandela/model-1.png"},{"name":"守标活法","definition":"在根本目标上绝不妥协，在实现手段上极度灵活——该谈判时谈判、该斗争时斗争，手段随形势换","source":"曼德拉《漫漫自由路》","source_tier":"primary","mechanism":"输入=有一个根本目标 + 多变形势 → 处理=根本目标绝不妥协、实现手段极度灵活(该谈则谈、该斗则斗) → 输出=守住目标、手段随形势换","trigger":"有根本目标、形势多变时","modern_transfer":"在根本目标上绝不妥协、在实现手段上极度灵活——该谈判时谈判、该斗争时斗争，守住目标，手段可以换(哪怕承受''妥协''的骂名)","architecture":{"type":"flow","components":["锁定不让步的根本目标","评估当前形势","谈或斗灵活切换","守标而换手段"]},"strategy_card_image":"kb-assets/mandela/model-2.png"},{"name":"长线耐心","definition":"以数十年的时间尺度行事；纵使长期受困也不放弃目标，把困境（甚至牢狱）也转为平台","source":"曼德拉《漫漫自由路》","source_tier":"primary","mechanism":"输入=长期受困 / 胜利以放弃原则为代价 → 处理=以数十年尺度行事、困境转为平台、不以放弃原则换短期脱身 → 输出=守住原则赢得最终主动","trigger":"长期受困、或胜利以放弃原则为代价时","modern_transfer":"以数十年的时间尺度行事——纵使长期受困也不放弃目标，把困境(甚至牢狱)转为平台；当自由/胜利以''放弃原则''为代价摆在面前时，宁可再忍一程","architecture":{"type":"loop","components":["以数十年为尺度","困境转为平台","不以原则换短期脱身","守原则赢主动"]},"strategy_card_image":"kb-assets/mandela/model-3.png"},{"name":"学敌赢敌","definition":"主动深入了解对手的语言、历史与心理，目的是赢得而非仅击败他——用对方听得懂的方式打动其心","source":"曼德拉《漫漫自由路》","source_tier":"primary","mechanism":"输入=面对强大对手、想赢得而非仅击败 → 处理=主动深入了解对手的语言/历史/心理、用对方听得懂的方式打动其心 → 输出=理解成为日后说服与和解的前提","trigger":"面对强大对手、想赢得而非仅击败时","modern_transfer":"要赢一个强大对手，先放下敌意去深入了解他——学他的语言、读他的历史、懂他的恐惧；理解是日后说服与和解的前提(目的是赢得而非仅击败)","architecture":{"type":"flow","components":["放下敌意","深入了解对手语言历史心理","用对方听得懂的方式","赢得而非击败"]},"strategy_card_image":"kb-assets/mandela/model-4.png"},{"name":"象征政治","definition":"有意识地运用象征性姿态与举动（服饰、出席、致意）去转动整个群体的情绪与认同","source":"权威传记及转型史","source_tier":"secondary","mechanism":"输入=群体情绪/认同需转动 → 处理=有意识运用象征性姿态(服饰/出席/致意)去转动整个群体的情绪与认同 → 输出=一个动作把''他们的''变成''我们的''","trigger":"需转动群体情绪/认同时","modern_transfer":"一个精心选择的象征性姿态，有时比千言万语更能转动群体情绪——找到对立双方都在意的那个符号，用一个动作把''他们的''变成''我们的''(如穿对方球队球衣)","architecture":{"type":"flow","components":["找对立双方都在意的符号","用一个象征性姿态","转动群体情绪认同","化他们的为我们的"]},"strategy_card_image":"kb-assets/mandela/model-5.png"}],"decision_principles":["目标上寸步不让，手段上没有禁忌——谈或斗，看哪个管用","把宽恕当建国策略用：和解是为了稳定，不是为了显得高尚","以数十年为尺度行事，困境也能当平台","要赢一个对手，先学会他的语言、读懂他的历史","用象征性的姿态去转动人心，姿态本身就是政治"],"inquiry_questions":["你的根本目标是什么？为它，哪些手段你愿意灵活调整？","你是想击败对手，还是想赢得他？你了解他到什么程度？","这件事放到十年、几十年的尺度，你还会这么急吗？","有没有一个象征性的姿态，能转动很多人的情绪？","和解在这里是策略上的最优解，还是只是你想显得大度？"],"value_priorities":["根本目标 ＞ 手段的纯洁性（目标不让步，手段（谈判/斗争）皆可权变）","战略性和解（稳定） ＞ 清算式的正义（报复）（转型期，和解换稳定优于清算换分裂）","长线的胜利 ＞ 短期的痛快（几十年尺度的目标，容得下当下的隐忍与妥协）"],"blind_spots":["其早期主张并参与武装斗争（民族之矛MK）、与共产主义力量的联系，是其遗产中显著且持续的争议——''和平偶像''形象常遮蔽其斗争路线的复杂性（史实/政治争议，B，客观标注，〔慎〕）","和解优先的策略被部分批评者认为以牺牲经济正义/实质再分配为代价，南非结构性不平等其后并未根本改观（政治经济学批评，B，客观标注）","强领袖个人威望驱动的和解难以制度化、依赖其个人道德权威，继任者未必能复制（原理推断，B）","其方法适用于''转型/夺权后建国''这一特定历史情境，对常态治理、日常组织管理迁移性有限（原理推断，B）"],"applicable_domains":["领导力","治理决策","谈判","人生抉择"],"match_tags":["领导力","治理决策","谈判","人生抉择","长期主义","攻心共识","目的手段分离","现当代非洲"],"linked_cases":["mandela-c1","mandela-c2","mandela-c3","mandela-c4","mandela-c5"],"life_tags":[{"tag":"反种族隔离","tier":"secondary"},{"tag":"狱中坚守27年","tier":"secondary"},{"tag":"当选南非总统","tier":"secondary"},{"tag":"获诺贝尔奖","tier":"secondary"}],"voice_profile":{"notes":"庄重克制、有政治家分量；调和而非对抗的措辞；善用象征与第一人称复数（我们）；原则坚定但姿态包容"},"references":[{"ref_id":"mandela-s1","title":"曼德拉《漫漫自由路》（Long Walk to Freedom）","locator":"罗本岛、谈判、拒绝有条件释放诸段","source_tier":"primary","supports_models":["守标活法","长线耐心","学敌赢敌"],"supports_cases":["mandela-c1","mandela-c2","mandela-c5"],"note":"自传·自述，含政治形象经营/润色；多数事件有第三方史料佐证"},{"ref_id":"mandela-s2","title":"权威南非转型史/曼德拉传记","locator":"罗本岛研究对手、和解政策段","source_tier":"secondary","supports_models":["战略性和解","学敌赢敌"],"supports_cases":["mandela-c1","mandela-c3"],"note":"二手史料/传记"},{"ref_id":"mandela-s3","title":"真相与和解委员会相关记载及转型史料","locator":"真相与和解委员会、安抚白人群体段","source_tier":"secondary","supports_models":["战略性和解"],"supports_cases":["mandela-c3"],"note":"二手史料"},{"ref_id":"mandela-s4","title":"1995橄榄球世界杯及曼德拉象征行动史料/传记","locator":"穿跳羚队球衣、决赛出席段","source_tier":"secondary","supports_models":["象征政治"],"supports_cases":["mandela-c4"],"note":"二手史料"}],"material_type":"rich","reasoning_skeleton":{"signature":"根本目标绝不妥协、手段在谈与斗间灵活切换；剧烈对立后把和解当稳定策略(非道德姿态)；以数十年尺度守目标、困境转平台、不以原则换短期脱身；要赢对手先学他的语言读他的历史懂他的恐惧；用一个象征性姿态转动整个群体情绪","steps":[{"invoke":"守标活法","action":"你的根本目标是什么？为它，哪些手段你愿意灵活调整？(谈或斗，看哪个管用)"},{"invoke":"学敌赢敌","action":"你是想击败对手，还是想赢得他？你了解他到什么程度？"},{"invoke":"长线耐心","action":"这件事放到十年、几十年的尺度，你还会这么急吗？(困境也能当平台)"},{"invoke":"战略性和解","action":"和解在这里是策略上的最优解，还是只是你想显得大度？(和解换稳定优于清算换分裂、但有代价)"},{"invoke":"象征政治","action":"有没有一个象征性的姿态，能转动很多人的情绪？"}],"contrast":"与史怀哲不同(关键差异)：二者都是高道德感召的历史人物，但**史怀哲是个人伦理践行者(敬畏生命+亲手还债+把信念活成一生)**；**曼德拉是政治转型领导者——把宽恕当建国策略、目标不让手段灵活、学敌赢敌、用象征转动群体**(见史怀哲卡)。与华盛顿不同(同被匹配治理/领导)：华盛顿是''主动交权+立制''的限权建国者；曼德拉是''和解换稳定+化敌为伙''的转型建国者。与俾斯麦不同：俾斯麦是''现实政治+铁血+操控均势''为强权服务；曼德拉的现实政治是为''终结压迫+多元共存''。与林肯不同：林肯在危机中维系联邦统一；曼德拉在转型后弥合族群、以和解换稳定(见相应卡)。【射程/盲区·反鸡汤】不给''宽恕坚韧''鸡汤、给可操作政治方法；诚实标注：①〔慎〕其早期武装斗争路线(民族之矛MK)与共产主义联系是显著争议(''和平偶像''形象遮蔽斗争复杂性)；②和解优先被批以牺牲经济正义为代价(结构性不平等未根本改观)；③依赖个人威望难制度化；④方法限于''转型/夺权后建国''特定情境、对常态治理迁移性有限。不适用创新研发/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"mandela-c2","note":"用户''对抗陷入两败俱伤僵局、要不要转为谈判''时，以狱中开启秘密谈判类比：他判断续抗将两败俱伤，冒被指叛卖之险、在根本目标(终结隔离、多数人统治)不让步前提下，主动从狱中把手段从对抗切换为谈判（谈判进程多源信史→确证）"},{"source":"case","case_id":"mandela-c3","note":"用户''剧烈对立后该清算还是和解''时，以真相与和解委员会类比：他选和解而非清算——保留白人公务员、以坦白换特赦揭真相而非审判报复、安抚白人恐惧，把国家稳定置于即时正义之上（和解政策与真相委员会为信史→确证；其代价争议客观入盲区，呈现宜并陈代价）"}]},"further_reading":[{"title":"曼德拉《漫漫自由路》(Long Walk to Freedom)","why":"罗本岛、谈判、拒绝有条件释放诸段（自传含政治形象经营，关键事件多有第三方佐证）","type":"original"},{"title":"权威南非转型史 + 真相与和解委员会记载","why":"和解政策、象征行动；武装斗争/共产联系/经济正义争议亦在此核校","type":"史料"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/mandela.png","avatar_thumb":"/advisors/portraits/mandela.png","domain":"历史","person_id":"P-mandela","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'f7a4ae70fe446fb07a49f34e8022bac93c1d78c98f224aebb68cc9ff0464a08e', 57, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('marcus', 'P-marcus', '马可·奥勒留', 'philosophy', '马可·奥勒留 · 斯多葛控制二分思维框架卡', '古罗马（121—180）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '控制二分法 · 客观看待', '/advisors/portraits/marcus.png', '/advisors/portraits/marcus.png', 5, 0, '{"schema_version":1,"card_id":"marcus","name":"马可·奥勒留","title":"马可·奥勒留 · 斯多葛控制二分思维框架卡","era":"古罗马（121—180）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"控制二分法","definition":"把事情分成\"可控的\"（你的判断与行动）和\"不可控的\"（外部与他人），只在可控处用力、对不可控处坦然接受","source":"《沉思录》（斯多葛控制二分）","source_tier":"primary","mechanism":"输入=为不可控的外部与他人焦虑、内耗 → 处理=把事情分成可控的(自己的判断与行动)和不可控的(外部与他人)、只在可控处用力、对不可控坦然接受 → 输出=精力集中在可控处、对不可控释怀","trigger":"为外部/他人焦虑内耗时","modern_transfer":"把事情分成''可控的''(你的判断与行动)和''不可控的''(外部与他人)——只在可控处用力、对不可控处坦然接受；别为你管不了的事内耗(控制二分)","architecture":{"type":"matrix","components":["区分可控与不可控","只在可控处用力","对不可控坦然接受","精力不内耗"]},"strategy_card_image":"kb-assets/marcus/model-1.png"},{"name":"客观看待","definition":"把事物还原成它本来的、客观的样子，剥除我们主观附加的评判与情绪渲染——困扰你的不是事情本身、而是你对它的看法","source":"《沉思录》（剥除评判 / 看事物本相）","source_tier":"primary","mechanism":"输入=被对事情的主观评判与情绪渲染困扰 → 处理=把事物还原成它本来客观的样子、剥除主观附加的评判与情绪 → 输出=困扰减轻(困扰你的不是事情而是你对它的看法)","trigger":"被情绪/主观评判困扰时","modern_transfer":"把事物还原成它本来的、客观的样子、剥除你主观附加的评判与情绪渲染——困扰你的往往不是事情本身、而是你对它的看法","architecture":{"type":"flow","components":["识别主观评判与情绪","把事物还原为客观样子","剥除附加渲染","困扰减轻"]},"strategy_card_image":"kb-assets/marcus/model-2.png"},{"name":"记忆死亡","definition":"用\"终将一死\"和宇宙/历史的宏大尺度回看眼前的得失烦恼，让当下的焦虑显出它真正的分量","source":"《沉思录》（记忆死亡 / 宏观视角）","source_tier":"primary","mechanism":"输入=被眼前的得失烦恼放大、看不清分量 → 处理=用''终将一死''和宇宙/历史的宏大尺度回看眼前 → 输出=眼前的事显出真正的分量(往往很小)","trigger":"被眼前得失烦恼放大时","modern_transfer":"用''终将一死''和宇宙/历史的宏大尺度回看眼前的得失烦恼——很多事在那个尺度下会显出它真正的分量(往往很小)，帮你 right-size 当下的焦虑","architecture":{"type":"hierarchy","components":["被眼前得失放大","拉到终将一死的尺度","拉到宇宙历史尺度","眼前事显出真分量"]},"strategy_card_image":"kb-assets/marcus/model-3.png"},{"name":"着眼当下尽责","definition":"专注于此刻该做的本分、把眼前这件事做好，别被对过去的懊悔和对未来的焦虑牵扯","source":"《沉思录》（专注当下本分）","source_tier":"primary","mechanism":"输入=被对过去的懊悔和对未来的焦虑牵扯、分心 → 处理=专注此刻该做的本分、把眼前这件事做好 → 输出=不被过去未来牵扯、当下尽责","trigger":"被过去懊悔/未来焦虑牵扯时","modern_transfer":"专注于此刻该做的本分、把眼前这件事做好——别被对过去的懊悔和对未来的焦虑牵扯；你能真正掌握的只有当下这一刻","architecture":{"type":"flow","components":["别被过去未来牵扯","专注此刻本分","把眼前事做好","当下尽责"]},"strategy_card_image":"kb-assets/marcus/model-4.png"},{"name":"障碍即道路","definition":"把挡路的障碍本身当作修炼与前进的材料——挡在路上的东西，恰恰成为道路","source":"《沉思录》（障碍即道路）","source_tier":"primary","mechanism":"输入=把阻碍当作纯粹的坏事、被它挡住 → 处理=把挡路的障碍本身当作修炼与前进的材料 → 输出=障碍恰恰成为道路(逆境是练德性的机会)","trigger":"遇到阻碍、被它挡住时","modern_transfer":"把挡路的障碍本身当作修炼与前进的材料——''挡在路上的东西、恰恰成为道路''；逆境不是纯粹的坏事、而是练习德性与能力的机会","architecture":{"type":"flow","components":["别把障碍当纯坏事","把它当修炼材料","障碍恰成道路","逆境练德性"]},"strategy_card_image":"kb-assets/marcus/model-5.png"}],"decision_principles":["区分可控（你的判断与行动）与不可控（外部他人），只在可控处用力","把事物还原为客观样子，剥除主观评判——困扰你的是看法而非事情","用''终将一死''和宇宙尺度 right-size 眼前的烦恼","专注此刻该做的本分，别被过去懊悔与未来焦虑牵扯","把障碍当作修炼与前进的材料——障碍即道路"],"inquiry_questions":["这件事里，哪些是你能控制的、哪些不能？你在为管不了的事内耗吗？","困扰你的是事情本身，还是你对它附加的评判与情绪？","放到''终将一死''和更大的时间尺度看，这件事真正的分量有多大？","你是在懊悔过去/焦虑未来，还是专注把眼前这件该做的事做好？","这个挡路的障碍，能不能反过来当成修炼与前进的材料？"],"value_priorities":["在可控处用力 ＞ 为不可控内耗（控制二分；不可控处坦然接受）","客观本相 ＞ 主观评判渲染（困扰你的是看法、非事情本身）","当下尽责 ＞ 懊悔过去/焦虑未来（你能掌握的只有当下）"],"blind_spots":["斯多葛''接受不可控''可能滑向消极宿命、或对不公的过度隐忍，淡化对外部改变与抗争的努力（思想评议，B）。","控制二分的边界在实践中常模糊——很多事是''部分可控''，简单二分可能误判（原理推断，B）。","《沉思录》是私人自省札记、自我劝勉而非系统哲学论著，有重复与情境性、非对外说理（史料，B）。","作为皇帝，其斯多葛理想与现实统治（连年战争、迫害基督徒等）存在张力，知行未必尽一（史实/评议，B，〔慎〕）。"],"applicable_domains":["修身自省","价值与伦理","危机应对","领导力"],"match_tags":["修身自省","价值与伦理","危机应对","领导力","批判思辨","长期主义","务实渐进","古代欧洲"],"linked_cases":["marcus-c1","marcus-c2","marcus-c3"],"life_tags":[{"tag":"著沉思录","tier":"primary"},{"tag":"任罗马皇帝","tier":"secondary"},{"tag":"行斯多葛道","tier":"primary"},{"tag":"御外族入侵","tier":"secondary"}],"voice_profile":{"notes":"沉静内省、自我劝勉；理性克制；悲悯而坚忍；朴素无华、直面无常"},"references":[{"ref_id":"marcus-s1","title":"马可·奥勒留《沉思录》(Meditations)","locator":"控制二分、客观看待、记忆死亡、当下尽责、障碍即道路诸节","source_tier":"primary","supports_models":["控制二分法","客观看待","记忆死亡","着眼当下尽责","障碍即道路"],"supports_cases":["marcus-c1"],"note":"一手·私人自省札记（高度可靠反映其思想）"},{"ref_id":"marcus-s2","title":"罗马帝国史/马可·奥勒留传记","locator":"瘟疫、战争、Avidius Cassius 叛乱、治世","source_tier":"secondary","supports_models":["控制二分法"],"supports_cases":["marcus-c2","marcus-c3"],"note":"二手·生平与治世史料"}],"material_type":"rich","reasoning_skeleton":{"signature":"把事分成可控(你的判断与行动)与不可控(外部他人)、只在可控处用力(控制二分)；把事物还原为客观样子、剥除主观评判与情绪(客观看待)；用终将一死和宇宙尺度 right-size 眼前烦恼(记忆死亡)；专注此刻本分、不被过去未来牵扯(着眼当下尽责)；把障碍当修炼材料、障碍即道路","steps":[{"invoke":"控制二分法","action":"这件事里，哪些是你能控制的(你的判断与行动)、哪些不能(外部与他人)？你在为管不了的事内耗吗？"},{"invoke":"客观看待","action":"困扰你的是事情本身、还是你对它附加的评判与情绪？把它还原成客观的样子会怎样？"},{"invoke":"记忆死亡","action":"放到''终将一死''和更大的时间尺度看，这件事真正的分量有多大？"},{"invoke":"着眼当下尽责","action":"你是在懊悔过去/焦虑未来，还是专注把眼前这件该做的事做好？"},{"invoke":"障碍即道路","action":"这个挡路的障碍，能不能反过来当成修炼与前进的材料？"}],"contrast":"与弗兰克尔不同(关键差异·同为逆境/内在应对)：**弗兰克尔是意义疗法——在苦难中''找到意义''、行使''选择态度的最后自由''**；**马可奥勒留是斯多葛控制二分——''区分可控与不可控、客观看待、宏观视角''**；一个靠''意义''、一个靠''控制二分与客观''(见弗兰克尔卡)。与庄子尤须分(都谈超脱)：庄子''齐物''是泯灭是非分别、相对主义地逍遥；奥勒留''控制二分''是理性区分可控不可控、积极尽责——庄子是消解分别、奥勒留是理性区分(见庄子卡)。与孔子/老子/王阳明区分：孔子入世伦理秩序、老子无为辩证、王阳明知行心学；马可奥勒留=斯多葛控制二分。【射程/盲区】斯多葛在''情绪管理、逆境应对、right-size焦虑''极有效，但①''接受不可控''可能滑向消极宿命或对不公的过度隐忍、淡化对外部改变与抗争的努力；②控制二分的边界常模糊(很多事''部分可控'')；③《沉思录》是私人自省札记、自我劝勉非系统论著；④〔慎〕作为皇帝其斯多葛理想与现实统治(战争/迫害基督徒)有张力、知行未必尽一。适用修身自省/价值与伦理/危机应对/领导力；不适用投资/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"marcus-c2","note":"用户''天灾人祸不断、为一堆管不了的事焦虑崩溃''时，以马可奥勒留治下瘟疫与战争类比：其治下罗马遭安东尼瘟疫与日耳曼战争连年、他以斯多葛''控制二分''坚守——分清可控(自己的判断与履职)与不可控(疫情与战局)、在可控处尽责、对不可控坦然（其治下天灾战乱与坚守履职为罗马史所载→确证）"},{"source":"case","case_id":"marcus-c1","note":"用户''被过去懊悔/未来焦虑牵扯、无法专注眼前''时，以马可奥勒留在前线军营写《沉思录》类比：他在多瑙河前线戎马倥偬中、每日自省、把功夫落在专注当下本分上——你能真正掌握的只有此刻这件该做的事（《沉思录》成于行军途中为公认→确证）"}]},"further_reading":[{"title":"马可·奥勒留《沉思录》(Meditations)","why":"控制二分/客观看待/记忆死亡/当下尽责/障碍即道路的一手出处（私人自省札记）","type":"原典"},{"title":"罗马帝国史/马可·奥勒留传记","why":"其治世、瘟疫战争、Avidius Cassius 叛乱等生平","type":"史料"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/marcus.png","avatar_thumb":"/advisors/portraits/marcus.png","domain":"哲学","person_id":"P-marcus","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '5668313734d6a4dd5aeccdead64a7064a10e08125e0d51e2b06555f323aae446', 58, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('matsushita', 'P-matsushita', '松下幸之助', 'business', '松下幸之助 · 自来水哲学与水坝经营思维框架卡', '现代（1894—1989）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '自来水哲学 · 水坝式经营', '/advisors/portraits/matsushita.png', '/advisors/portraits/matsushita.png', 5, 0, '{"schema_version":1,"card_id":"matsushita","name":"松下幸之助","title":"松下幸之助 · 自来水哲学与水坝经营思维框架卡","era":"现代（1894—1989）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"自来水哲学","definition":"像自来水一样把优质产品大量、低价地供给大众，让人人都用得起——以普及消除匮乏","source":"松下《实践经营哲学》及\"水道哲学\"宣言","source_tier":"primary","mechanism":"输入=把好东西做成稀缺、昂贵的 → 处理=像自来水一样大量、低价地供给大众、让人人用得起 → 输出=以普及消除匮乏(自来水哲学)","trigger":"拥有一项能造福大众的优质产品/能力时","modern_transfer":"把优质的产品/服务像自来水一样大量、低价地供给大众、让人人都用得起——以''普及''消除匮乏，而非把好东西做成稀缺昂贵的特权(松下1932年水道哲学宣言)","architecture":{"type":"flow","components":["别把好东西做成稀缺昂贵","像自来水一样大量低价","供给大众人人用得起","以普及消除匮乏"]},"strategy_card_image":"kb-assets/matsushita/model-1.png"},{"name":"水坝式经营","definition":"像水坝蓄水一样，经营留有余裕、不满负荷运转，备不时之需","source":"松下\"水坝式经营\"论述","source_tier":"primary","mechanism":"输入=把资源/产能用到极限、满负荷运转 → 处理=像水坝蓄水、留出余裕(资金/产能/人力)、不满负荷运转 → 输出=有余裕应对波动与不时之需","trigger":"配置资源/规划产能时","modern_transfer":"像水坝蓄水一样、在资金、设备、人力上都留出余裕、不满负荷运转——这样才有缓冲去应对波动与不时之需(松下水坝式经营)；别把弦绷到极限","architecture":{"type":"hierarchy","components":["别把资源产能用到极限","像水坝一样蓄水","留出资金设备人力的余裕","有缓冲应对波动"]},"strategy_card_image":"kb-assets/matsushita/model-2.png"},{"name":"事业部制","definition":"把大企业分成独立核算的事业部，分权经营，各自对利润负责","source":"松下电器事业部制实践","source_tier":"primary","mechanism":"输入=大企业集权臃肿、反应迟钝 → 处理=分成独立核算的事业部、分权经营、各自对利润负责 → 输出=分权敏捷、各负其责(事业部制)","trigger":"组织变大、集权臃肿反应迟钝时","modern_transfer":"把大组织分成一个个独立核算的''事业部''、分权经营、各自对自己的利润负责——分权带来敏捷与责任感，而非集权臃肿、反应迟钝(松下率先推行事业部制)","architecture":{"type":"hierarchy","components":["大企业集权臃肿反应迟钝","分成独立核算的事业部","分权经营各对利润负责","分权敏捷各负其责"]},"strategy_card_image":"kb-assets/matsushita/model-3.png"},{"name":"企业是社会公器","definition":"企业是为社会服务的公器，利润是把事做对的结果、而非唯一目的","source":"松下经营理念","source_tier":"primary","mechanism":"输入=把利润当唯一目的 → 处理=把企业看作为社会服务的公器、利润是把事做对的结果 → 输出=以社会责任为本、利润随之而来","trigger":"界定企业/事业的根本目的时","modern_transfer":"把企业看作''为社会服务的公器''、利润是你把事做对之后的结果、而非唯一目的——以对社会的贡献为本、利润随之而来(松下''企业是社会公器'')〔须防其沦为口号、见盲区〕","architecture":{"type":"flow","components":["别把利润当唯一目的","把企业看作社会公器","为社会服务把事做对","利润是结果随之而来"]},"strategy_card_image":"kb-assets/matsushita/model-4.png"},{"name":"素直之心","definition":"以坦诚、虚心、不带成见的\"素直之心\"如实看事物，才能做对判断","source":"松下《素直的心》","source_tier":"primary","mechanism":"输入=带着成见与私心看事物、判断失真 → 处理=以坦诚、虚心、不带成见地如实看事物 → 输出=看清真相、判断不失真(素直之心)","trigger":"做重要判断、易被成见私心干扰时","modern_transfer":"以坦诚、虚心、不带成见的心(素直之心)如实地看事物——去掉成见与私心的滤镜、才能看清真相、做对判断(松下晚年极推崇''素直之心'')","architecture":{"type":"flow","components":["带成见与私心看事物失真","以坦诚虚心不带成见","如实观照事物","看清真相判断不失真"]},"strategy_card_image":"kb-assets/matsushita/model-5.png"}],"decision_principles":["把优质产品像自来水一样大量低价供给大众，以普及消除匮乏","像水坝蓄水一样留有余裕、不满负荷运转，备不时之需","把大组织分成独立核算的事业部，分权经营、各负其责","把企业看作为社会服务的公器，利润是结果而非唯一目的","以坦诚虚心、不带成见的素直之心如实看事物"],"inquiry_questions":["你是把好东西做成稀缺昂贵的，还是想办法像自来水一样让人人用得起？","你的资金、产能、人力是绷到了极限，还是留有余裕去应对波动？","你的组织是集权臃肿、反应迟钝，还是分成了各负其责的事业部？","你把企业只当赚钱工具，还是当作为社会服务的公器？","你看这件事，是带着成见与私心，还是以坦诚虚心如实地看？"],"value_priorities":["普及消除匮乏 ＞ 把好东西做成稀缺特权（自来水哲学——优质产品大量低价供给大众）","留有余裕 ＞ 满负荷运转（水坝式经营——有缓冲才能应对波动）","为社会服务 ＞ 利润是唯一目的（企业是社会公器、利润是结果）"],"blind_spots":["''自来水哲学''以''优质产品能被大规模、低价制造''为前提；对无法规模化的高端/定制/手工不适用（原理推断，B）。","''水坝式经营''的余裕以企业有相当实力为前提；资源极度紧张的初创难照搬（原理推断，B）。","其理念诞生于20世纪制造业与日本文化语境，对轻资产/互联网/快速迭代的行业未必直接适用（原理推断，B）。","〔注意〕''企业是社会公器''等理念高尚，但实践中也需警惕沦为口号、与实际经营行为脱节（客观标注，B）。"],"applicable_domains":["组织管理","领导力","创业","长期规划"],"match_tags":["组织管理","领导力","创业","长期规划","利他取向","风险规避","务实渐进","现当代东亚"],"linked_cases":["matsushita-c1","matsushita-c2","matsushita-c3","matsushita-c4"],"life_tags":[{"tag":"创松下电器","tier":"secondary"},{"tag":"提自来水哲学","tier":"primary"},{"tag":"创PHP研究所","tier":"secondary"},{"tag":"首创事业部制","tier":"secondary"}],"voice_profile":{"notes":"朴实诚恳、重道理；以社会与大众为念；稳健留余裕；虚心好学"},"references":[{"ref_id":"matsushita-s1","title":"松下幸之助著述（《实践经营哲学》《素直的心》等）","locator":"自来水哲学、企业是社会公器、素直之心","source_tier":"primary","supports_models":["自来水哲学","企业是社会公器","素直之心"],"supports_cases":["matsushita-c1","matsushita-c4"],"note":"一手·著述"},{"ref_id":"matsushita-s2","title":"松下电器（Panasonic）经营史","locator":"水坝式经营、事业部制","source_tier":"secondary","supports_models":["水坝式经营","事业部制"],"supports_cases":["matsushita-c2","matsushita-c3"],"note":"二手·经营史（理念另见其一手论述）"}],"material_type":"rich","reasoning_skeleton":{"signature":"把优质产品像自来水一样大量低价供给大众、以普及消除匮乏(自来水哲学)；像水坝蓄水留有余裕不满负荷运转(水坝式经营)；把大组织分成独立核算各负其责的事业部(事业部制)；把企业看作为社会服务的公器、利润是结果(企业是社会公器)；以坦诚虚心不带成见的素直之心如实看事物(素直之心)","steps":[{"invoke":"自来水哲学","action":"你是把好东西做成稀缺昂贵的，还是想办法像自来水一样让人人用得起？"},{"invoke":"水坝式经营","action":"你的资金、产能、人力是绷到了极限，还是留有余裕去应对波动？"},{"invoke":"事业部制","action":"你的组织是集权臃肿、反应迟钝，还是分成了各负其责的事业部？"},{"invoke":"企业是社会公器","action":"你把企业只当赚钱工具，还是当作为社会服务的公器？"},{"invoke":"素直之心","action":"你看这件事，是带着成见与私心，还是以坦诚虚心如实地看？"}],"contrast":"与稻盛和夫不同(关键差异·同为日本''经营之神'')：**稻盛是''阿米巴经营(把组织拆成全员参与核算的最小单元)+敬天爱人+作为人何谓正确(以哲学/道德为先)''**；**松下是''自来水哲学(普及消除匮乏)+水坝式经营(留余裕)+事业部制(较大颗粒的分权)+企业是社会公器''**——稻盛拆到最小单元全员核算、以哲学统驭，松下分到事业部、以普及与社会责任立本(见稻盛和夫卡)。与本田宗一郎不同(同为日本制造业)：本田是''技术第一、亲手实干的工匠创业者''；松下是''量产普及与经营哲学''(见本田卡)。与盛田昭夫不同：盛田是''创造市场、全球营销、品牌优先''；松下是''把优质产品低价普及给大众''(见盛田卡)。【射程/盲区】松下之道在''普及消除匮乏、留余裕、分权事业部、社会公器、素直之心''极有力，但①''自来水哲学''以优质产品能被大规模低价制造为前提、对无法规模化的高端/定制不适用；②''水坝式余裕''以企业有相当实力为前提、资源极紧的初创难照搬；③其理念诞生于20世纪制造业与日本语境、对轻资产/互联网/快速迭代未必直接适用；④〔注意〕''企业是社会公器''等高尚理念、实践中需防沦为口号。适用组织管理/领导力/创业/长期规划；不适用竞争博弈/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"matsushita-c1","note":"用户''手上有个好产品/好能力、却把它做成稀缺昂贵的小众生意''时，以松下自来水哲学类比：松下认为企业的使命是像自来水一样把优质物资大量、低价地供给大众、让人人都用得起、以此消除贫困——好东西的价值在普及、而非做成特权（自来水哲学为松下1932年宣言→确证）"},{"source":"case","case_id":"matsushita-c2","note":"用户''把资金、产能、人力都绷到极限、一有波动就崩''时，以松下水坝式经营类比：松下主张像水坝蓄水一样、在资金/设备/人力上都留出余裕、不满负荷运转、以备不时之需——有缓冲才扛得住波动（水坝式经营为松下经营论述→确证）"}]},"further_reading":[{"title":"松下幸之助《实践经营哲学》《素直的心》等","why":"自来水哲学、企业是社会公器、素直之心的一手论述（A）","type":"original"},{"title":"松下电器（Panasonic）经营史","why":"水坝式经营、事业部制的实践记录（A/B）","type":"经营史"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/matsushita.png","avatar_thumb":"/advisors/portraits/matsushita.png","domain":"商业","person_id":"P-matsushita","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '9904135335c0c03c45bbca3e6b4840127f6992295075cdb22d1ff8a9bb684ae5', 59, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('maxwell', 'P-maxwell', '麦克斯韦', 'science', '麦克斯韦 · 数学统一与理论预言思维框架卡', '近代（1831—1879）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '用数学统一看似无关的现象 · 把直觉图像翻译成精确数学', '/advisors/portraits/maxwell.png', '/advisors/portraits/maxwell.png', 5, 0, '{"schema_version":1,"card_id":"maxwell","name":"麦克斯韦","title":"麦克斯韦 · 数学统一与理论预言思维框架卡","era":"近代（1831—1879）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"用数学统一看似无关的现象","definition":"把原本看似无关、各管各的现象，用一套统一的（数学的）框架揭示为\"同一个底层规律的不同表现\"——统一比罗列更有力","source":"麦克斯韦方程组统一电磁光","source_tier":"primary","mechanism":"输入=把现象当各管各的罗列 → 处理=用一套统一框架揭示为同一底层规律的不同表现 → 输出=统一比罗列有力(数学统一)","trigger":"面对看似无关的多个现象时","modern_transfer":"把原本看似无关、各管各的现象、用一套统一的(数学的)框架揭示为''同一个底层规律的不同表现''——统一比罗列更有力(麦克斯韦用一组方程统一了电、磁、光、揭示光是电磁波)","architecture":{"type":"hierarchy","components":["别把现象当各管各的罗列","用一套统一的数学框架","揭示为同一底层规律的不同表现","统一比罗列更有力"]},"strategy_card_image":"kb-assets/maxwell/model-1.png"},{"name":"把直觉图像翻译成精确数学","definition":"把一个有洞察但还停留在直觉、图像层面的想法，翻译成精确、可计算、可推演的（数学/形式化）语言——直觉提供方向，形式化赋予力量","source":"麦克斯韦把法拉第力线数学化","source_tier":"primary","mechanism":"输入=洞察停留在直觉图像层面 → 处理=翻译成精确可计算可推演的形式化语言 → 输出=形式化赋予力量(直觉数学化)","trigger":"有洞察但还停留在直觉时","modern_transfer":"把一个有洞察但还停留在直觉、图像层面的想法、翻译成精确、可计算、可推演的(数学/形式化)语言——直觉提供方向、形式化赋予力量(麦克斯韦把法拉第的''力线/场''直觉化为精确的方程)","architecture":{"type":"flow","components":["别让洞察停留在直觉图像层面","翻译成精确可计算可推演的形式化语言","直觉提供方向形式化赋予力量","形式化赋予力量"]},"strategy_card_image":"kb-assets/maxwell/model-2.png"},{"name":"由方程预言未知","definition":"相信一个好理论（方程）的内在逻辑——大胆地从它推导出尚未被观察到的、全新的预言，再去验证；理论不只描述已知，还能预言未知","source":"麦克斯韦由方程预言电磁波","source_tier":"primary","mechanism":"输入=理论只用来描述已知 → 处理=相信方程内在逻辑、推出未观察的预言再验证 → 输出=理论预言未知(方程预言)","trigger":"有了一个好理论之后","modern_transfer":"相信一个好理论(方程)的内在逻辑——大胆地从它推导出尚未被观察到的、全新的预言、再去验证;理论不只描述已知、还能预言未知(麦克斯韦由方程预言了电磁波、后被赫兹实验证实)","architecture":{"type":"flow","components":["别让理论只用来描述已知","相信方程的内在逻辑","推导出尚未观察到的全新预言再验证","理论能预言未知"]},"strategy_card_image":"kb-assets/maxwell/model-3.png"},{"name":"抓住本质建简洁模型","definition":"从复杂的现象中抓住最本质的东西，建立一个简洁、普适的\"模型\"去把握它——而非纠缠于一堆机械的、临时的细节","source":"麦克斯韦的场论","source_tier":"primary","mechanism":"输入=纠缠机械的临时细节 → 处理=抓住本质建简洁普适的模型 → 输出=简洁普适(简洁模型)","trigger":"面对复杂现象时","modern_transfer":"从复杂的现象中抓住最本质的东西、建立一个简洁、普适的''模型''去把握它——而非纠缠于一堆机械的、临时的细节(麦克斯韦以''场''的概念简洁地把握电磁)","architecture":{"type":"hierarchy","components":["别纠缠机械的临时细节","从复杂现象中抓住最本质的东西","建立简洁普适的模型","简洁而普适"]},"strategy_card_image":"kb-assets/maxwell/model-4.png"},{"name":"用类比启发但不拘泥","definition":"借助一个你熟悉领域的\"类比\"来启发、搭建对新事物的直觉——但记住类比只是脚手架，理解之后要超越它，别被它框死","source":"麦克斯韦的力学类比","source_tier":"secondary","mechanism":"输入=要么不用类比要么被类比框死 → 处理=借熟悉领域类比启发直觉、理解后超越它 → 输出=类比是脚手架(类比不拘泥)","trigger":"构建对新事物的直觉时","modern_transfer":"借助一个你熟悉领域的''类比''(如把陌生的电磁比作熟悉的流体/机械)来启发、搭建对新事物的直觉——但记住类比只是脚手架、理解之后要超越它、别被它框死(麦克斯韦早期借力学类比、最终超越具体模型)","architecture":{"type":"flow","components":["别要么不用类比要么被类比框死","借熟悉领域的类比启发搭建直觉","类比只是脚手架理解后超越它","别被它框死"]},"strategy_card_image":"kb-assets/maxwell/model-5.png"}],"decision_principles":["把看似无关的现象用一套统一框架揭示为同一规律的不同表现（统一比罗列有力）","把停留在直觉的洞察翻译成精确、可计算的数学语言（形式化赋予力量）","相信好方程的内在逻辑，从它推出未观察的预言再验证（理论能预言未知）","从复杂中抓住本质、建简洁普适的模型，别纠缠机械细节","借熟悉领域的类比启发直觉，但类比只是脚手架、理解后要超越它"],"inquiry_questions":["你是把现象当各管各的罗列、还是用统一框架揭示为同一规律的不同表现？","你的洞察是停留在直觉图像、还是翻译成了精确可计算的形式化语言？","你是只用理论描述已知、还是从它推出了未观察的预言再验证？","你是纠缠机械细节、还是抓住本质建了简洁普适的模型？","你是被类比框死、还是把它当脚手架、理解后超越它？"],"value_priorities":["统一的底层规律 ＞ 各管各的罗列（一组方程统一电磁光）","精确的数学 ＞ 停留的直觉（把法拉第力线数学化）","预言未知 ＞ 只描述已知（预言电磁波）"],"blind_spots":["麦克斯韦的高度数学化、抽象化，对缺乏数学训练者门槛极高、难直接领会（原理推断，B）。","其早期依赖的力学类比/以太模型后被证明不必要甚至错误——类比是脚手架、过度依赖会误导（史，B）。","纯数学/理论的路径若脱离实验的约束与检验，也可能走偏（原理推断，B）。","其工作的伟大在身后（电磁波被验证、对相对论与现代物理的奠基）才被充分认识，生前影响有限（史，B）。"],"applicable_domains":["创新","认知偏误与理性决策"],"match_tags":["创新","认知偏误与理性决策","第一性原理","系统分析","多元模型","近代欧洲"],"linked_cases":["maxwell-c1","maxwell-c2","maxwell-c3","maxwell-c4"],"life_tags":[{"tag":"创电磁方程组","tier":"primary"},{"tag":"统一电磁光","tier":"primary"},{"tag":"预言电磁波","tier":"primary"},{"tag":"创气体分子论","tier":"secondary"}],"voice_profile":{"notes":"严密深邃、以数学统驭；化直觉为方程；由理论预言；简洁普适"},"references":[{"ref_id":"maxwell-s1","title":"麦克斯韦《电磁通论》及电磁学史","locator":"数学统一、直觉数学化、方程预言、场模型、类比","source_tier":"primary","supports_models":["用数学统一看似无关的现象","把直觉图像翻译成精确数学","由方程预言未知","抓住本质建简洁模型","用类比启发但不拘泥"],"supports_cases":["maxwell-c1","maxwell-c2","maxwell-c3","maxwell-c4"],"note":"一手/二手·原著与物理学史"},{"ref_id":"maxwell-s2","title":"经典电磁学与物理学统一史研究","locator":"理论方法、奠基意义","source_tier":"secondary","supports_models":["用数学统一看似无关的现象","由方程预言未知"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"把看似无关的现象用一套统一框架揭示为同一规律的不同表现统一比罗列有力(用数学统一看似无关的现象)；把停留在直觉的洞察翻译成精确可计算的数学语言形式化赋予力量(把直觉图像翻译成精确数学)；相信好方程的内在逻辑从它推出未观察的预言再验证(由方程预言未知)；从复杂中抓住本质建简洁普适的模型别纠缠机械细节(抓住本质建简洁模型)；借熟悉领域的类比启发直觉但类比只是脚手架理解后超越它(用类比启发但不拘泥)","steps":[{"invoke":"用数学统一看似无关的现象","action":"你是把现象当各管各的罗列、还是用统一框架揭示为同一规律的不同表现？"},{"invoke":"把直觉图像翻译成精确数学","action":"你的洞察是停留在直觉图像、还是翻译成了精确可计算的形式化语言？"},{"invoke":"由方程预言未知","action":"你是只用理论描述已知、还是从它推出了未观察的预言再验证？"},{"invoke":"抓住本质建简洁模型","action":"你是纠缠机械细节、还是抓住本质建了简洁普适的模型？"},{"invoke":"用类比启发但不拘泥","action":"你是被类比框死、还是把它当脚手架、理解后超越它？"}],"contrast":"与牛顿不同(关键差异·同重数学)：**牛顿以数学公理化建立了经典力学的体系(力学的奠基)**；**麦克斯韦以一组方程统一了电、磁、光、并由方程预言电磁波(电磁的统一与预言)**——牛顿奠基力学、麦克斯韦统一电磁;且麦克斯韦尤擅''把前人的物理直觉(场)翻译成精确数学''(见牛顿卡)。与法拉第不同(二人互补)：法拉第以实验直觉提出''力线/场''的物理图像(直觉与实验);麦克斯韦把法拉第的直觉翻译成精确的数学方程(形式化)——法拉第给图像、麦克斯韦给方程(见法拉第卡)。与爱因斯坦不同：爱因斯坦以思想实验重构时空;麦克斯韦以数学统一电磁(见爱因斯坦卡)。【射程/盲区】麦克斯韦之道在''数学统一、把直觉数学化、由方程预言、简洁模型、类比不拘泥''极有力(尤其理论建构、统一)，但①高度数学化抽象化、对缺数学训练者门槛极高;②早期依赖的力学类比/以太模型后被证不必要甚至错误、过度依赖类比会误导;③纯理论若脱离实验约束也可能走偏;④其伟大在身后(电磁波验证、奠基现代物理)才被充分认识、生前影响有限。适用创新/认知偏误与理性决策;不适用投资/创作。"},"persona_anchor":{"primary":[{"source":"case","case_id":"maxwell-c1","note":"用户''面对一堆看似各自独立、互不相干的现象/问题、只会一个个分别处理、看不到它们之间的联系''时，以麦克斯韦统一电磁光类比：在他之前、电、磁、光被当作三种不同的东西分别研究;麦克斯韦用一组(四个)方程、揭示出电与磁是同一事物的两面、且光本身就是一种电磁波——把三者统一在了同一套底层规律之下;别把现象当各管各的罗列、用一套统一的框架揭示它们是''同一个底层规律的不同表现''、统一比罗列更有力（麦克斯韦方程组统一电磁光为物理学里程碑→确证）"},{"source":"case","case_id":"maxwell-c2","note":"用户''有一个很好的直觉/想法、但它还很模糊、停留在感觉和比喻层面、无法精确推演或让人信服''时，以麦克斯韦把法拉第直觉数学化类比：法拉第凭实验直觉提出了''力线''''场''的物理图像、但缺乏数学;麦克斯韦把法拉第这种直觉、翻译成了一组精确、可计算、可推演的数学方程、由此不仅严格化了它、还推出了电磁波等全新预言;把停留在直觉、图像层面的洞察、翻译成精确、可计算的(数学/形式化)语言——直觉提供方向、形式化赋予力量（麦克斯韦把法拉第场论数学化为史实→确证）"}]},"further_reading":[{"title":"麦克斯韦《电磁通论》及电磁学史","why":"数学统一、直觉数学化、方程预言、场模型、类比的出处（A/B）","type":"原著/物理学史"},{"title":"经典电磁学与物理学统一史研究","why":"对麦克斯韦理论方法与其奠基意义的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/maxwell.png","avatar_thumb":"/advisors/portraits/maxwell.png","domain":"科学","person_id":"P-maxwell","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '87171a170a92f574e06510f98dc9ba45099fec5a818dbd57eb1346ac96b06a55', 60, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('mendel', 'P-mendel', '孟德尔', 'science', '孟德尔 · 定量统计与控制实验思维框架卡', '近代（1822—1884）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '定量统计找规律 · 控制变量的简化实验', '/advisors/portraits/mendel.png', '/advisors/portraits/mendel.png', 5, 0, '{"schema_version":1,"card_id":"mendel","name":"孟德尔","title":"孟德尔 · 定量统计与控制实验思维框架卡","era":"近代（1822—1884）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"定量统计找规律","definition":"别满足于定性的\"差不多\"\"大概像\"——大量地计数、测量，用数字与比例去发现现象背后精确的、可重复的规律","source":"孟德尔豌豆杂交统计","source_tier":"primary","mechanism":"输入=满足于定性像不像 → 处理=大量计数测量用数字比例发现精确规律 → 输出=精确可重复规律(定量统计)","trigger":"要发现现象背后的规律时","modern_transfer":"别满足于定性的''差不多''''大概像''——大量地计数、测量、用数字与比例去发现现象背后精确的、可重复的规律(孟德尔统计了大量豌豆杂交后代、发现了精确的3:1等比例)","architecture":{"type":"flow","components":["别满足于定性的差不多大概像","大量地计数测量","用数字与比例发现精确规律","精确可重复的规律"]},"strategy_card_image":"kb-assets/mendel/model-1.png"},{"name":"控制变量的简化实验","definition":"别一上来就硬啃最复杂的整体——选一个简单、清晰、易控制的\"模型系统\"，一次只改变/研究一个变量，排除干扰，把复杂问题简化到可解","source":"孟德尔选豌豆、单一性状","source_tier":"primary","mechanism":"输入=一上来硬啃最复杂整体 → 处理=选简单清晰易控制的模型系统、一次只研究一个变量排除干扰 → 输出=简化到可解(控制变量)","trigger":"面对复杂问题时","modern_transfer":"别一上来就硬啃最复杂的整体——选一个简单、清晰、易控制的''模型系统''、一次只改变/研究一个变量、排除干扰、把复杂问题简化到可解(孟德尔选豌豆、一次只追踪一个性状)","architecture":{"type":"flow","components":["别一上来硬啃最复杂的整体","选简单清晰易控制的模型系统","一次只研究一个变量排除干扰","把复杂问题简化到可解"]},"strategy_card_image":"kb-assets/mendel/model-2.png"},{"name":"假设看不见的因子","definition":"为解释可见的现象，大胆假设背后存在某种看不见的、离散的\"基本单位\"在起作用，并用它解释和预测——哪怕你还看不到它","source":"孟德尔的\"遗传因子\"","source_tier":"primary","mechanism":"输入=只解释看得见的、不敢假设看不见的 → 处理=大胆假设背后有看不见的离散基本单位并用它解释预测 → 输出=假设看不见的单位(假设因子)","trigger":"要解释可见现象的机制时","modern_transfer":"为解释可见的现象、大胆假设背后存在某种看不见的、离散的''基本单位''在起作用、并用它解释和预测——哪怕你还看不到它(孟德尔假设了看不见的''遗传因子''即基因、来解释遗传)","architecture":{"type":"flow","components":["别只解释看得见的不敢假设看不见的","大胆假设背后有看不见的离散基本单位","用它解释和预测","哪怕你还看不到它"]},"strategy_card_image":"kb-assets/mendel/model-3.png"},{"name":"长期专注的笨功夫","definition":"重大规律的发现往往要靠极大的耐心、长期专注地积累足够多的数据——别怕\"笨功夫\"，足够大的样本才能让规律从噪声中浮现","source":"孟德尔8年豌豆实验","source_tier":"secondary","mechanism":"输入=怕笨功夫、样本不足 → 处理=极大耐心长期专注积累足够数据 → 输出=规律从噪声浮现(笨功夫)","trigger":"要让规律从噪声中浮现时","modern_transfer":"重大规律的发现往往要靠极大的耐心、长期专注地积累足够多的数据——别怕''笨功夫''、足够大的样本才能让规律从噪声中浮现(孟德尔花了约8年、种了上万株豌豆)","architecture":{"type":"flow","components":["别怕笨功夫样本不足","以极大的耐心长期专注","积累足够多的数据","足够大的样本让规律从噪声中浮现"]},"strategy_card_image":"kb-assets/mendel/model-4.png"},{"name":"坚持不被理解的真理","definition":"即使你的发现/想法一时完全不被理解、不被重视、甚至被忽视——只要它建立在扎实的证据上，就坚信它的价值","source":"孟德尔生前被忽视","source_tier":"secondary","mechanism":"输入=因不被理解重视而放弃自我怀疑 → 处理=只要建立在扎实证据上就坚信价值 → 输出=真理终被认识(坚持真理)","trigger":"成果一时不被理解重视时","modern_transfer":"即使你的发现/想法一时完全不被理解、不被重视、甚至被忽视——只要它建立在扎实的证据上、就坚信它的价值(孟德尔的遗传定律生前几乎无人理睬、直到他去世后约16年才被重新发现、奠定遗传学)〔但也要反思如何更好地传播、见盲区〕","architecture":{"type":"flow","components":["别因不被理解重视而放弃","只要建立在扎实的证据上","就坚信它的价值","真理终会被认识"]},"strategy_card_image":"kb-assets/mendel/model-5.png"}],"decision_principles":["别满足于定性''像不像''，大量计数、用数字与比例发现精确规律","选简单、可控的''模型系统''，一次只研究一个变量，把复杂简化到可解","大胆假设背后有看不见的''基本单位''在起作用，用它解释和预测","靠极大耐心长期积累足够大的样本，让规律从噪声中浮现（别怕笨功夫）","即使一时不被理解，只要建立在扎实证据上，就坚信它的价值"],"inquiry_questions":["你是满足于定性的''差不多''、还是大量计数、用数字与比例找精确规律？","你是硬啃复杂整体、还是选简单可控的''模型系统''、一次只研究一个变量？","你是只解释看得见的、还是大胆假设了背后看不见的''基本单位''？","你是样本不足、还是靠笨功夫积累了足够大的样本让规律浮现？","成果一时不被理解时，你是放弃、还是凭扎实证据坚信它的价值？"],"value_priorities":["精确的比例 ＞ 定性的像不像（豌豆3:1）","简化到可解 ＞ 硬啃复杂整体（选豌豆、单一性状）","假设看不见的因子 ＞ 只解释可见（遗传因子（基因））"],"blind_spots":["孟德尔定律基于豌豆等性状清晰的简单案例，真实的遗传远更复杂（连锁、多基因、不完全显性等），其定律是简化的近似（史，B，客观标注）。","其成果生前完全不被理解、传播失败——光有真理而不能有效传播，影响也无从发生（史，B，客观标注）。","后世有学者（如费希尔）从统计角度讨论其数据''吻合度过高''的问题，但不影响定律本身（学术，B，客观点到）。","高度依赖大样本统计的方式，对无法大量重复实验的问题不适用（原理推断，B）。"],"applicable_domains":["创新","认知偏误与理性决策"],"match_tags":["创新","认知偏误与理性决策","概率思维","实验试错","系统分析","近代欧洲"],"linked_cases":["mendel-c1","mendel-c2","mendel-c3","mendel-c4"],"life_tags":[{"tag":"做豌豆实验","tier":"primary"},{"tag":"发现遗传定律","tier":"primary"},{"tag":"提遗传因子","tier":"primary"},{"tag":"提显隐性状","tier":"primary"}],"voice_profile":{"notes":"严谨定量、专注笃实；以统计与控制实验立论；假设离散因子；默默坚守"},"references":[{"ref_id":"mendel-s1","title":"孟德尔《植物杂交实验》及遗传学史","locator":"定量统计、控制实验、假设因子、笨功夫、坚持真理","source_tier":"primary","supports_models":["定量统计找规律","控制变量的简化实验","假设看不见的因子","长期专注的笨功夫","坚持不被理解的真理"],"supports_cases":["mendel-c1","mendel-c2","mendel-c3","mendel-c4"],"note":"一手/二手·原著与遗传学史"},{"ref_id":"mendel-s2","title":"遗传学起源与孟德尔研究","locator":"方法、被忽视与重新发现、数据争议","source_tier":"secondary","supports_models":["定量统计找规律","坚持不被理解的真理"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"别满足于定性像不像大量计数用数字与比例发现精确规律(定量统计找规律)；选简单可控的模型系统一次只研究一个变量把复杂简化到可解(控制变量的简化实验)；大胆假设背后有看不见的离散基本单位用它解释和预测(假设看不见的因子)；靠极大耐心长期积累足够大的样本让规律从噪声中浮现(长期专注的笨功夫)；即使一时不被理解只要建立在扎实证据上就坚信它的价值(坚持不被理解的真理)","steps":[{"invoke":"定量统计找规律","action":"你是满足于定性的''差不多''、还是大量计数、用数字与比例找精确规律？"},{"invoke":"控制变量的简化实验","action":"你是硬啃复杂整体、还是选简单可控的''模型系统''、一次只研究一个变量？"},{"invoke":"假设看不见的因子","action":"你是只解释看得见的、还是大胆假设了背后看不见的''基本单位''？"},{"invoke":"长期专注的笨功夫","action":"你是样本不足、还是靠笨功夫积累了足够大的样本让规律浮现？"},{"invoke":"坚持不被理解的真理","action":"成果一时不被理解时，你是放弃、还是凭扎实证据坚信它的价值？"}],"contrast":"与达尔文不同(关键差异·同为生物学·二人互补)：**达尔文以海量观察+严密推理建立了''演化论''这一宏大的定性理论(解释物种因何演化:自然选择)**；**孟德尔以控制实验+定量统计、发现了遗传的精确定律、并假设了离散的''遗传因子''(揭示遗传如何传递:基因)**——达尔文给出''演化''的大理论、孟德尔给出''遗传''的精确机制;一个是观察推理的博物学家、一个是实验统计的遗传学奠基者(二者后来在''现代综合''中合流)(见达尔文卡)。与居里夫人不同：居里夫人以物理化学的提纯苦功发现新元素;孟德尔以生物学的统计实验发现遗传定律(见居里夫人卡)。与法拉第不同：法拉第以物理图像与实验探电磁;孟德尔以定量统计与控制实验探遗传(见法拉第卡)。【射程/盲区·历史诚实】孟德尔之道在''定量统计、控制实验、假设因子、笨功夫、坚持真理''极有力(尤其实验科学、定量研究)，但①其定律基于豌豆等简单清晰案例、真实遗传远更复杂(连锁多基因等)、是简化的近似、客观标注;②成果生前完全不被理解、传播失败——光有真理不能传播、影响也无从发生;③后世有学者从统计角度讨论其数据''吻合度过高''(费希尔)、但不影响定律本身、客观点到;④高度依赖大样本统计、对无法大量重复实验的问题不适用。适用创新/认知偏误与理性决策;不适用投资/创作。"},"persona_anchor":{"primary":[{"source":"case","case_id":"mendel-c1","note":"用户''研究一个现象、只停留在定性的、模糊的''好像有点关系''''大概差不多''、抓不住确切的规律''时，以孟德尔豌豆统计类比：他不满足于笼统地说''后代像父母''、而是亲手种植、一株株地数、统计了大量豌豆杂交后代的性状、从数字里发现了精确的、可重复的比例(如显性:隐性≈3:1);别满足于定性的''差不多''——大量地计数、测量、用数字与比例去发现现象背后精确的、可重复的规律（孟德尔的豌豆统计3:1为遗传学史→确证）"},{"source":"case","case_id":"mendel-c3","note":"用户''为了解释一个看得见的现象、却只盯着表象、不敢假设背后有某种看不见的机制在起作用''时，以孟德尔假设''遗传因子''类比：为解释遗传的规律、他大胆假设背后存在看不见的、一个个离散的''遗传因子''(即后来的基因)在成对地传递、并用它成功解释和预测了杂交结果——尽管当时谁也没见过基因;为解释可见的现象、大胆假设背后存在看不见的、离散的''基本单位''在起作用、并用它解释和预测、哪怕你还看不到它（孟德尔的遗传因子假设为遗传学史→确证）"}]},"further_reading":[{"title":"孟德尔《植物杂交实验》及遗传学史","why":"定量统计、控制实验、假设因子、笨功夫、坚持真理的出处（A/B）","type":"原著/遗传学史"},{"title":"遗传学起源与孟德尔研究","why":"对孟德尔方法、被忽视与重新发现及数据争议的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/mendel.png","avatar_thumb":"/advisors/portraits/mendel.png","domain":"科学","person_id":"P-mendel","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '50a703f2d35a2f9d481805fdac0e83118b7f6b042187672a8db9d9fa5e1dd640', 61, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('mengzi', 'P-mengzi', '孟子', 'philosophy', '孟子 · 性善仁政思维框架卡', '战国（约前372—前289）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '性善四端 · 仁政得民心', '/advisors/portraits/mengzi.png', '/advisors/portraits/mengzi.png', 5, 0, '{"schema_version":1,"card_id":"mengzi","name":"孟子","title":"孟子 · 性善仁政思维框架卡","era":"战国（约前372—前289）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"性善四端","definition":"人本有恻隐、羞恶、辞让、是非\"四端\"，扩充它就能成仁义礼智——相信并激发本有的善","source":"《孟子·公孙丑上》","source_tier":"primary","mechanism":"输入=假定人性本恶、一味防范压制 → 处理=相信并扩充人本有的善端(恻隐/羞恶/辞让/是非) → 输出=激发本有的善与潜能(四端)","trigger":"面对人/团队、判断如何对待其本性时","modern_transfer":"相信并激发人(或团队)本有的善意与潜能——人皆有恻隐、羞恶、辞让、是非''四端''、扩充它就能成仁义礼智;别一上来就假定人性本恶去防范压制(孟子性善四端)〔但对人性恶的一面也需有制度防范、见盲区〕","architecture":{"type":"hierarchy","components":["别假定人性本恶一味防范","相信人本有的四端","扩充恻隐羞恶辞让是非","激发本有的善与潜能"]},"strategy_card_image":"kb-assets/mengzi/model-1.png"},{"name":"仁政得民心","definition":"要赢得长期的拥护，靠\"得民心\"（满足、保护、善待对方），而非靠强力压服","source":"《孟子·离娄上》","source_tier":"primary","mechanism":"输入=靠强力压服 → 处理=行仁政、满足保护善待对方、得民心 → 输出=以得民心赢得长期拥护(得民心者得天下)","trigger":"要赢得长期拥护/治理时","modern_transfer":"要赢得长期的拥护、靠''得民心''(满足、保护、善待你服务的对象)、而非靠强力压服——''得民心者得天下''(孟子仁政)","architecture":{"type":"flow","components":["别靠强力压服","行仁政满足保护善待对方","得民心","以民心赢得长期拥护"]},"strategy_card_image":"kb-assets/mengzi/model-2.png"},{"name":"浩然之气","definition":"靠长期\"配义与道\"（持续做合乎道义的事）的积累，养出一种至大至刚、不被外物撼动的精神底气","source":"《孟子·公孙丑上》","source_tier":"primary","mechanism":"输入=靠一时血气或外在加持 → 处理=靠长期''配义与道''(持续做合乎道义的事)积累 → 输出=养出至大至刚不被外物撼动的精神底气","trigger":"要建立内在的笃定与底气时","modern_transfer":"靠长期''配义与道''(持续做合乎道义的事)的积累、养出一种至大至刚、不被外物撼动的精神底气(浩然之气)——它不能靠一时血气、只能日积月累(孟子''我善养吾浩然之气'')","architecture":{"type":"flow","components":["别靠一时血气或外在加持","长期配义与道","持续做合乎道义的事积累","养至大至刚的底气"]},"strategy_card_image":"kb-assets/mengzi/model-3.png"},{"name":"义利之辨","definition":"决策在\"义（该不该）\"与\"利（划不划算）\"冲突时，把义置于利之上——有些底线不能用利益衡量","source":"《孟子·梁惠王上》","source_tier":"primary","mechanism":"输入=一切只算''划不划算''(利) → 处理=在义与利冲突时把''义(该不该)''置于''利''之上 → 输出=守住不能用利益衡量的底线","trigger":"在''义(该不该)''与''利(划不划算)''冲突时","modern_transfer":"决策在''义(该不该)''与''利(划不划算)''冲突时、把义置于利之上——有些底线不能用利益来衡量(''何必曰利?亦有仁义而已矣''、孟子义利之辨)","architecture":{"type":"flow","components":["别一切只算划不划算","在义与利冲突时","把义该不该置于利之上","守住不能用利益衡量的底线"]},"strategy_card_image":"kb-assets/mengzi/model-4.png"},{"name":"民贵君轻","definition":"把\"你服务的根本对象（民众/用户/事业）\"排在\"权位/自身\"之上——根本动摇了，权位也保不住","source":"《孟子·尽心下》","source_tier":"primary","mechanism":"输入=把''权位/自身''排在第一 → 处理=把''你服务的根本对象''排在''权位/自身''之上 → 输出=守住根本(民为贵社稷次之君为轻)","trigger":"在''根本对象''与''自身权位''间取舍时","modern_transfer":"把''你服务的根本对象(用户/民众/事业)''排在''权位/自身''之上——''民为贵、社稷次之、君为轻'';根本动摇了、权位也保不住(孟子民本)","architecture":{"type":"hierarchy","components":["别把权位自身排第一","把服务的根本对象","排在权位自身之上","守住根本则权位自固"]},"strategy_card_image":"kb-assets/mengzi/model-5.png"}],"decision_principles":["相信并激发对方本有的善与潜能（但对人性恶也需制度防范）","靠得民心（善待保护）赢得长期拥护，而非强力压服","靠长期做合乎道义的事，养出不被外物撼动的底气","义与利冲突时，把''该不该''置于''划不划算''之上","把你服务的根本对象排在权位/自身之上"],"inquiry_questions":["你是相信并激发对方本有的善与潜能、还是假定人性本恶去防范压制？","你是靠强力压服、还是靠善待保护赢得对方的真心拥护？","你内在的底气，是靠一时血气、还是靠长期做合乎道义的事积累出来的？","这件事在''该不该''与''划不划算''冲突时，你把哪个放在前面？","你是把权位/自身放第一、还是把你服务的根本对象放第一？"],"value_priorities":["激发本有的善 ＞ 假定人性本恶去防范（人皆有四端、扩充即成仁义礼智）","义（该不该） ＞ 利（划不划算）（何必曰利？亦有仁义而已矣）","服务的根本对象 ＞ 权位/自身（民为贵、社稷次之、君为轻）"],"blind_spots":["性善论是一种信念与倡导，对''人性也有恶/自利的一面''估计不足；在需要防范、制衡的场景（如制度设计）可能过于理想（学术分析，B）。","仁政/民本在理念上崇高，但落地依赖治理者真愿如此，缺乏对''若治理者不仁''的硬约束（学术分析，B）。","浩然之气、义利之辨等偏内在修养与道德，对纯技术/利益博弈类问题着力少（原理推断，B）。","其论辩有时偏理想化，与现实政治的复杂残酷有距离（学术分析，B）。"],"applicable_domains":["领导力","价值与伦理","修身自省"],"match_tags":["领导力","价值与伦理","修身自省","利他取向","攻心共识","批判思辨","古代东亚"],"linked_cases":["mengzi-c1","mengzi-c2","mengzi-c3","mengzi-c4"],"life_tags":[{"tag":"著孟子","tier":"primary"},{"tag":"倡性善论","tier":"primary"},{"tag":"游说诸侯","tier":"secondary"},{"tag":"倡民贵君轻","tier":"primary"}],"voice_profile":{"notes":"雄辩激越、气势充沛；善用比喻；理想主义；刚正不阿"},"references":[{"ref_id":"mengzi-s1","title":"《孟子》","locator":"四端、仁政、浩然之气、义利之辨、民本","source_tier":"primary","supports_models":["性善四端","仁政得民心","浩然之气","义利之辨","民贵君轻"],"supports_cases":["mengzi-c1","mengzi-c2","mengzi-c3","mengzi-c4"],"note":"一手·原典"},{"ref_id":"mengzi-s2","title":"朱熹《孟子集注》等注疏","locator":"历代对《孟子》的注解","source_tier":"secondary","supports_models":["性善四端","民贵君轻"],"note":"二手·注疏"}],"material_type":"textual","reasoning_skeleton":{"signature":"相信并扩充人本有的善端而非假定性恶去防范(性善四端)；靠得民心而非强力压服赢得长期拥护(仁政得民心)；靠长期配义与道积累养至大至刚的底气(浩然之气)；义利冲突时把义置于利之上(义利之辨)；把服务的根本对象排在权位自身之上(民贵君轻)","steps":[{"invoke":"性善四端","action":"你是相信并激发对方本有的善与潜能、还是假定人性本恶去防范压制？"},{"invoke":"仁政得民心","action":"你是靠强力压服、还是靠善待保护赢得对方的真心拥护？"},{"invoke":"浩然之气","action":"你内在的底气，是靠一时血气、还是靠长期做合乎道义的事积累出来的？"},{"invoke":"义利之辨","action":"这件事在''该不该''与''划不划算''冲突时，你把哪个放在前面？"},{"invoke":"民贵君轻","action":"你是把权位/自身放第一、还是把你服务的根本对象放第一？"}],"contrast":"与孔子不同(关键差异·同属儒家)：**孔子重''正名、忠恕、中庸''(从礼与关系入手、较为平实)**；**孟子在孔子的仁之上、更强调''性善四端、仁政民本、浩然之气、义利之辨''(从人性本善出发、更激越、更强调民本与气节)**——孔子奠基、孟子高扬性善与民本(见孔子卡)。与荀子不同(同论人性·恰相反)：**荀子主''性恶''、强调''化性起伪、隆礼重法''(靠后天的礼法去矫正人性)**；**孟子主''性善''、强调''扩充四端''(靠激发本有的善)**——一个性恶靠矫正、一个性善靠扩充(见荀子卡)。与老庄不同：老庄''无为/齐物/超脱''(出世);孟子''仁政/养气/担当''(入世)(见老子/庄子卡)。【射程/盲区】孟子之道在''性善、仁政、浩然之气、义利、民本''极有力，但①性善论对''人性也有恶/自利的一面''估计不足、在需防范制衡的场景(制度设计)可能过于理想;②仁政/民本崇高但落地依赖治理者真愿如此、缺对''治理者不仁''的硬约束;③偏内在修养与道德、对纯技术/利益博弈着力少;④其论辩有时偏理想化、与现实政治的复杂残酷有距离。适用领导力/价值与伦理/修身自省;不适用竞争博弈/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"mengzi-c1","note":"用户''倾向于假定人/团队本性自私、一味用防范和压制去管理''时，以孟子性善四端类比：孟子说人见到孺子将掉进井里、都会有一瞬的恻隐之心——人本有恻隐、羞恶、辞让、是非''四端''、扩充它就能成仁义礼智;不妨先相信并激发对方本有的善与潜能、而非一上来就假定人性本恶(但对人性恶的一面也需有制度防范)（性善四端为《孟子》公孙丑上四端章→确证）"},{"source":"case","case_id":"mengzi-c2","note":"用户''想靠强力/高压去压服别人、赢得服从''时，以孟子仁政得民心类比：孟子主张''得民心者得天下''——靠善待、保护、满足你服务的对象去赢得他们真心的拥护、而非靠强力压服;民心才是长治久安的根（仁政得民心为《孟子》离娄上所载→确证）"}]},"further_reading":[{"title":"《孟子》","why":"性善四端、仁政、浩然之气、义利之辨、民本的一手出处（A）","type":"原典"},{"title":"朱熹《孟子集注》等","why":"历代对《孟子》的权威注解（B）","type":"注疏"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/mengzi.png","avatar_thumb":"/advisors/portraits/mengzi.png","domain":"哲学","person_id":"P-mengzi","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '093cba441ee5167d3797fea9b6763ddd8dfdce7b15333d44fd84adcc28eebe9e', 62, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('moltke', 'P-moltke', '毛奇', 'strategy', '毛奇 · 总参谋部与任务式指挥思维框架卡', '近代（1800—1891）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '总参谋部制度 · 计划周详但因敌应变', '/advisors/portraits/moltke.png', '/advisors/portraits/moltke.png', 5, 0, '{"schema_version":1,"card_id":"moltke","name":"毛奇","title":"毛奇 · 总参谋部与任务式指挥思维框架卡","era":"近代（1800—1891）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"总参谋部制度","definition":"别让一切系于统帅一人的天才——建立一个专业的\"参谋/智囊团队\"，专门负责前期的研究、计划、推演与协调，让决策与执行科学化、制度化","source":"毛奇打造普鲁士总参谋部","source_tier":"secondary","mechanism":"输入=一切系于统帅一人的天才 → 处理=建立专业的参谋/智囊团队、负责前期研究计划推演协调 → 输出=决策执行科学化制度化(总参谋部)","trigger":"要让决策不依赖个人天才、科学化时","modern_transfer":"别让一切系于统帅一人的天才——建立一个专业的''参谋/智囊团队''、专门负责前期的研究、计划、推演与协调、让决策与执行科学化、制度化(毛奇把普鲁士总参谋部打造成现代军事指挥的核心)〔但过度专业化也可能官僚僵化、见盲区〕","architecture":{"type":"hierarchy","components":["别让一切系于统帅一人的天才","建立专业的参谋智囊团队","负责前期研究计划推演协调","让决策与执行科学化制度化"]},"strategy_card_image":"kb-assets/moltke/model-1.png"},{"name":"计划周详但因敌应变","definition":"前期计划要做到极周详，但清醒地知道\"没有任何计划能熬过与现实的第一次接触\"——执行中必须根据实际灵活应变","source":"毛奇名言","source_tier":"primary","mechanism":"输入=把计划当教条死守 → 处理=计划做到极周详、但执行中根据实际灵活应变 → 输出=计划是出发点而非教条(计划应变)","trigger":"制定与执行一个大计划时","modern_transfer":"前期计划要做到极其周详、但要清醒地知道''没有任何计划能熬过与现实的第一次接触''——执行中必须根据实际不断灵活应变、计划是出发点而非教条(毛奇)","architecture":{"type":"flow","components":["别把计划当教条死守","前期计划做到极周详","但没有计划能熬过与现实第一次接触","执行中根据实际灵活应变"]},"strategy_card_image":"kb-assets/moltke/model-2.png"},{"name":"任务式指挥","definition":"上级只明确\"目标与意图\"，把\"具体怎么做\"的决断权下放给最了解一线情况的人，让他们临机决断","source":"毛奇\"任务式指挥\"","source_tier":"secondary","mechanism":"输入=事无巨细遥控前线 → 处理=上级只下达目标与意图、把''怎么做''的决断权下放给最了解情况的人 → 输出=最了解情况的人临机决断(任务式指挥)","trigger":"指挥/管理分布式的执行时","modern_transfer":"别事无巨细遥控——上级只明确''目标与意图''、把''具体怎么做''的决断权下放给最了解一线情况的人、让他们临机决断(毛奇的''任务式指挥''Auftragstaktik)〔须以下级的素质与训练为前提、见盲区〕","architecture":{"type":"flow","components":["别事无巨细遥控前线","上级只明确目标与意图","把怎么做的决断权下放给最了解一线的人","让他们临机决断"]},"strategy_card_image":"kb-assets/moltke/model-3.png"},{"name":"分进合击","definition":"平时分散行动以保持灵活与速度，在关键的时间地点会合、形成合力打击——\"分散前进、集中打击\"","source":"毛奇的作战艺术","source_tier":"secondary","mechanism":"输入=队伍挤成一团行动、笨重 → 处理=平时分散行动保持灵活速度、在决战的时间地点会合形成合力 → 输出=分散前进集中打击(分进合击)","trigger":"要兼顾机动灵活与决战合力时","modern_transfer":"别让队伍挤成一团行动——平时分散行动以保持灵活与速度、在关键的时间地点会合、形成合力打击(''分散前进、集中打击''、毛奇)〔须以可靠的协调与通讯为前提、否则被各个击破、见盲区〕","architecture":{"type":"flow","components":["别让队伍挤成一团行动笨重","平时分散行动保持灵活速度","在关键的时间地点会合","形成合力集中打击"]},"strategy_card_image":"kb-assets/moltke/model-4.png"},{"name":"用好新技术","definition":"率先把时代的新技术（如当时的铁路、电报）系统地纳入你的运作，用新技术解决动员、协调、速度的问题，获得对手没有的优势","source":"毛奇率先用铁路动员","source_tier":"secondary","mechanism":"输入=固守旧手段、忽视时代新技术 → 处理=率先把时代的新技术(铁路电报)系统纳入运作 → 输出=获得对手没有的优势(用好新技术)","trigger":"时代出现可用的新技术时","modern_transfer":"率先把时代的新技术(如当时的铁路、电报)系统地纳入你的运作——用新技术解决动员、协调、速度的问题、获得对手没有的优势(毛奇率先用铁路快速动员与集结军队)","architecture":{"type":"flow","components":["别固守旧手段忽视时代新技术","率先把时代的新技术铁路电报","系统地纳入运作","用新技术获得对手没有的优势"]},"strategy_card_image":"kb-assets/moltke/model-5.png"}],"decision_principles":["别让一切系于个人天才，建立专业的参谋团队让决策制度化","计划做到极周详，但执行中根据实际灵活应变（计划是出发点而非教条）","上级只下达目标与意图，把怎么做的决断权下放给最了解一线的人","分散行动保持灵活，在关键时间地点会合形成合力（须可靠协调）","率先把时代的新技术系统纳入运作，获得对手没有的优势"],"inquiry_questions":["你是让一切系于个人天才、还是建立了专业的参谋团队让决策制度化？","你是把计划当教条死守、还是计划周详但执行中根据实际灵活应变？","你是事无巨细遥控、还是只下达目标意图、把决断权下放给最了解一线的人？","你是让队伍挤成一团、还是分散行动保持灵活、在关键点会合形成合力？","你是固守旧手段、还是率先把时代的新技术系统纳入运作？"],"value_priorities":["制度化的参谋作业 ＞ 系于一人的天才（总参谋部）","下放的临机决断 ＞ 遥控的微管理（任务式指挥）","新技术的优势 ＞ 固守的旧手段（铁路动员、电报）"],"blind_spots":["任务式指挥与分进合击高度依赖下级的素质、训练与可靠的协调通讯——若下级能力不足或协调失灵，会失控或被各个击破（史，B）。","总参谋部的高度专业化与制度化，也可能滋生官僚化、僵化或脱离政治的倾向（后来的德国总参谋部即有此弊）（史/学术，B，客观标注）。","其成功也依赖普鲁士特定的军事文化、教育水平与工业基础，难以简单移植（原理推断，B）。","过度强调军事的专业自主，也可能与政治领导产生张力（史，B）。"],"applicable_domains":["组织管理","竞争博弈","危机应对"],"match_tags":["组织管理","竞争博弈","危机应对","系统分析","制度法治思维","务实渐进","近代欧洲"],"linked_cases":["moltke-c1","moltke-c2","moltke-c3","moltke-c4"],"life_tags":[{"tag":"创总参谋部","tier":"secondary"},{"tag":"胜普法战争","tier":"secondary"},{"tag":"色当破法","tier":"secondary"},{"tag":"胜普奥战争","tier":"secondary"}],"voice_profile":{"notes":"沉静缜密、制度化思维；重计划与参谋；授权下级；拥抱新技术"},"references":[{"ref_id":"moltke-s1","title":"毛奇军事文选及普奥、普法战争史","locator":"总参谋部、任务式指挥、分进合击、铁路动员、计划应变","source_tier":"secondary","supports_models":["总参谋部制度","计划周详但因敌应变","任务式指挥","分进合击","用好新技术"],"supports_cases":["moltke-c1","moltke-c2","moltke-c3","moltke-c4"],"note":"一手/二手·军事文选与战史"},{"ref_id":"moltke-s2","title":"现代军事制度与总参谋部研究","locator":"总参谋部、任务式指挥、官僚化之弊","source_tier":"secondary","supports_models":["总参谋部制度","任务式指挥"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"别让一切系于个人天才建立专业的参谋团队让决策制度化(总参谋部制度)；计划做到极周详但执行中根据实际灵活应变(计划周详但因敌应变)；上级只下达目标意图把决断权下放给最了解一线的人(任务式指挥)；分散行动保持灵活在关键时间地点会合形成合力(分进合击)；率先把时代的新技术系统纳入运作获得对手没有的优势(用好新技术)","steps":[{"invoke":"总参谋部制度","action":"你是让一切系于个人天才、还是建立了专业的参谋团队让决策制度化？"},{"invoke":"计划周详但因敌应变","action":"你是把计划当教条死守、还是计划周详但执行中根据实际灵活应变？"},{"invoke":"任务式指挥","action":"你是事无巨细遥控、还是只下达目标意图、把决断权下放给最了解一线的人？"},{"invoke":"分进合击","action":"你是让队伍挤成一团、还是分散行动保持灵活、在关键点会合形成合力？"},{"invoke":"用好新技术","action":"你是固守旧手段、还是率先把时代的新技术系统纳入运作？"}],"contrast":"与克劳塞维茨不同(关键差异)：**克劳塞维茨是''战争的哲学''(战争是政治的延续、摩擦、重心——思想与理论)**；**毛奇是''现代战争的制度与方法''(总参谋部、任务式指挥、分进合击、铁路动员——把战争组织科学化、工业化)**——一个是战争的哲学家、一个是现代战争组织的工程师(见克劳塞维茨卡)。与拿破仑不同：拿破仑靠''个人天才、集中兵力、亲自指挥的英雄式统帅'';毛奇靠''制度化的参谋部、分权的任务式指挥、分散机动''——一个集权于天才、一个分权于制度与下级(见拿破仑卡)。与孙子不同：孙子是抽象的兵法原理;毛奇是工业时代具体的指挥制度与方法(见孙子卡)。【射程/盲区】毛奇之道在''总参谋部、计划应变、任务式指挥、分进合击、用好新技术''极有力(尤其大型组织的现代化指挥)，但①任务式指挥与分进合击高度依赖下级素质与可靠协调、否则失控或被各个击破;②总参谋部的高度专业化也可能官僚化、僵化或脱离政治(后来的德国总参谋部即有此弊);③其成功依赖普鲁士特定的军事文化、教育与工业基础、难简单移植;④过度强调军事专业自主、可能与政治领导产生张力。适用组织管理/竞争博弈/危机应对;不适用创作/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"moltke-c1","note":"用户''一个大组织的决策与成败、几乎全系于领导者一个人的天才与精力、缺乏制度支撑''时，以毛奇的总参谋部类比：他把普鲁士总参谋部打造成一个专业的''大脑''——一批受过严格训练的参谋专门负责战前的研究、计划、推演、铁路时刻表与后勤、让军事指挥从''系于统帅一人的天才''变成科学化、制度化的体系;别让一切系于一人、建立一个专业的参谋/智囊团队让决策制度化（总参谋部为毛奇所建→确证）"},{"source":"case","case_id":"moltke-c2","note":"用户''事无巨细地遥控下属、一线想临机应变却处处要请示、贻误战机''时，以毛奇的任务式指挥类比：他推行''任务式指挥(Auftragstaktik)''——上级只下达''目标与意图''、把''具体怎么打''的决断权下放给最了解一线情况的前线指挥官、让他们临机决断;别事无巨细遥控、只明确目标意图、把决断权下放给最了解情况的人（任务式指挥为毛奇所倡→确证；惟须以下级素质与训练为前提）"}]},"further_reading":[{"title":"毛奇军事文选及普奥战争、普法战争史","why":"总参谋部、任务式指挥、分进合击、铁路动员的史述（B）","type":"史/军事著作"},{"title":"现代军事制度与总参谋部研究","why":"对毛奇与现代军事指挥的学术分析（含官僚化之弊，B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/moltke.png","avatar_thumb":"/advisors/portraits/moltke.png","domain":"战略","person_id":"P-moltke","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '34d8944537e479a470e1047628700d8eedafcaca27058fb45b3f5d142004324d', 63, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('morgan', 'P-morgan', 'J.P.摩根', 'business', '摩根 · 资本整合与信用立身思维框架卡', '19—20世纪（1837—1913）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '资本整合重组 · 信用即资产', '/advisors/portraits/morgan.png', '/advisors/portraits/morgan.png', 5, 0, '{"schema_version":1,"card_id":"morgan","name":"J.P.摩根","title":"摩根 · 资本整合与信用立身思维框架卡","era":"19—20世纪（1837—1913）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"资本整合重组","definition":"当一个行业分散、过度竞争、互相杀价、整体受损时，用资本把分散的玩家整合成一个有秩序的大组织","source":"摩根传记（Strouse/Chernow）及US Steel组建史","source_tier":"secondary","mechanism":"输入=一个行业分散、过度竞争、互相杀价、整体受损 → 处理=用资本把分散的玩家整合成一个有秩序的大组织、消除破坏性竞争 → 输出=以整合换秩序与规模(US Steel)","trigger":"行业过度分散、破坏性竞争时","modern_transfer":"当一个行业分散、过度竞争、互相杀价、整体受损时——用资本把分散的玩家整合成一个有秩序的大组织、消除破坏性竞争(摩根组建美国钢铁)；但须警惕这滑向垄断、抑制创新(见盲区)","architecture":{"type":"hierarchy","components":["行业分散过度竞争互相杀价","用资本把玩家整合","组成有秩序的大组织","以整合换秩序与规模"]},"strategy_card_image":"kb-assets/morgan/model-1.png"},{"name":"信用即资产","definition":"把对方的\"品格与信用\"当作合作的首要前提，而非只看抵押品与数字；你自己的信用也是最大资产","source":"普约委员会(Pujo)证词","source_tier":"primary","mechanism":"输入=只看抵押品/数字 → 处理=把对方的''品格与信用''当作放贷与合作的首要前提、自己的信用也是最大资产 → 输出=信用立身(品格先于抵押品)","trigger":"评估是否信任/合作某人时","modern_transfer":"把''品格与信用''当作合作的首要前提、而非只看抵押品与数字——''我不信任的人、拿全世界的债券也借不到我的钱'';而你自己的信用、也是你最大的资产(摩根普约委员会作证)","architecture":{"type":"flow","components":["别只看抵押品与数字","把品格与信用当首要前提","自己的信用也是最大资产","信用立身"]},"strategy_card_image":"kb-assets/morgan/model-2.png"},{"name":"危机中挺身组织救援","definition":"系统性恐慌、各方观望自保时，若你是有威望的中枢，把各方召集并\"锁\"在一起，组织共同救援直到凑齐资源","source":"1907年恐慌史料","source_tier":"secondary","mechanism":"输入=系统性恐慌、各方观望自保、危机蔓延 → 处理=作为有威望的中枢、把各方锁在一起、组织共同的救援直到凑齐资源 → 输出=以中枢之力止住系统性崩溃(1907恐慌)","trigger":"系统性危机、各方观望时","modern_transfer":"系统性恐慌、各方观望自保时——若你是有威望的中枢、把各方召集并''锁''在一起、组织共同救援直到凑齐资源(摩根1907年锁住银行家救市、当时美国尚无中央银行)","architecture":{"type":"flow","components":["系统性恐慌各方观望","作为有威望的中枢","把各方锁在一起组织救援","凑齐资源止住崩溃"]},"strategy_card_image":"kb-assets/morgan/model-3.png"},{"name":"秩序优于竞争","definition":"厌恶\"破坏性竞争\"，宁求稳定、可预期与\"共同利益\"，把秩序看得重于无序的竞争","source":"摩根传记及其商业取向","source_tier":"secondary","mechanism":"输入=把竞争当绝对的好 → 处理=厌恶''破坏性竞争''、宁求稳定、可预期与共同利益 → 输出=以秩序换稳定(但代价是垄断/抑制竞争)","trigger":"面对混乱的过度竞争时","modern_transfer":"厌恶''破坏性竞争''、宁求稳定、可预期与''共同利益''——把秩序看得重于无序的竞争(摩根的取向)；但这是把双刃剑、代价可能是垄断与抑制创新、本卡客观标注","architecture":{"type":"flow","components":["别把竞争当绝对的好","厌恶破坏性竞争","宁求稳定可预期与共同利益","以秩序换稳定但代价是垄断"]},"strategy_card_image":"kb-assets/morgan/model-4.png"},{"name":"关系网络控制","definition":"不必全资拥有——通过董事会席位、人脉、联号建立对一批企业的影响与控制网络","source":"摩根传记及\"金钱托拉斯\"调查","source_tier":"secondary","mechanism":"输入=只靠所有权 → 处理=通过董事会席位、人脉、联号建立对一批企业的影响与控制(不必全资拥有) → 输出=以网络控制放大影响(董事会网络)","trigger":"要在不全资拥有下施加影响时","modern_transfer":"不必全资拥有——通过董事会席位、人脉、联号建立对一批企业的影响与控制网络(摩根合伙人遍布各大公司董事会)；但这正是''金钱托拉斯''之讥的由来、权力过度集中是其阴暗面","architecture":{"type":"hierarchy","components":["不必全资拥有","通过董事会席位人脉联号","建立影响与控制网络","以网络放大影响"]},"strategy_card_image":"kb-assets/morgan/model-5.png"}],"decision_principles":["行业分散、破坏性竞争时，用资本把它整合成有秩序的大组织（警惕滑向垄断）","把品格与信用当合作的首要前提，而非只看抵押品；你自己的信用也是最大资产","系统性危机时，若你是中枢，把各方锁在一起组织共同救援","厌恶破坏性竞争、宁求稳定与共同利益（但这是双刃剑）","不必全资拥有，靠董事会席位与人脉建立影响网络（警惕权力过度集中）"],"inquiry_questions":["这个行业是不是分散、过度竞争、互相杀价、整体在受损？能不能整合出秩序？","你是在只看对方的抵押品数字，还是在看他的品格与信用？","系统性危机来了，你是观望自保，还是能当中枢把各方组织起来？","你在追求无序的竞争，还是稳定可预期的秩序？这秩序的代价是什么？","你是只靠所有权，还是能靠董事会席位与人脉建立影响网络？"],"value_priorities":["有秩序的整合 ＞ 无序的破坏性竞争（组建US Steel以整合换秩序（但代价是垄断））","品格与信用 ＞ 只看抵押品数字（品格先于金钱与财产）","稳定可预期 ＞ 混乱的过度竞争（偏好共同利益、抑制破坏性竞争（双刃剑））"],"blind_spots":["其''秩序优于竞争''与资本整合直接通向垄断，引发反托拉斯与''金钱托拉斯''质疑、普约委员会调查其金融权力过度集中（史实，B，客观标注）。","其模式以拥有巨大的资本与个人威望为前提，普通人不具备此前提（原理推断，B）。","金融整合者视角对''从0到1的产品/技术创新''着力少——其逻辑是重组既有、而非创造新的（原理推断，B）。","〔二轴〕摩根本人著述极少，其''判断与动机''多由传记重构，不宜全部坐实于其个人（史料局限，B，客观标注）。"],"applicable_domains":["危机应对","资源调度","组织管理","投资"],"match_tags":["危机应对","资源调度","组织管理","投资","系统分析","风险规避","攻心共识","近代北美"],"linked_cases":["morgan-c1","morgan-c2","morgan-c3","morgan-c4"],"life_tags":[{"tag":"组建美国钢铁","tier":"secondary"},{"tag":"平息1907恐慌","tier":"secondary"},{"tag":"创摩根财团","tier":"secondary"},{"tag":"组建通用电气","tier":"secondary"}],"voice_profile":{"notes":"威严决断、一言九鼎；重信用与品格；厌恶混乱、求秩序；金融中枢的气场"},"references":[{"ref_id":"morgan-s1","title":"Strouse/Chernow 摩根传记","locator":"组建US Steel、董事会网络、共同利益取向","source_tier":"secondary","supports_models":["资本整合重组","秩序优于竞争","关系网络控制"],"supports_cases":["morgan-c1","morgan-c4"],"note":"二手·权威传记"},{"ref_id":"morgan-s2","title":"1907年恐慌史料","locator":"摩根召集银行家、锁门凑齐救援资金","source_tier":"secondary","supports_models":["危机中挺身组织救援"],"supports_cases":["morgan-c2"],"note":"二手·金融史"},{"ref_id":"morgan-s3","title":"1912 普约委员会(Pujo)证词","locator":"「品格先于金钱」、金钱托拉斯调查","source_tier":"primary","supports_models":["信用即资产"],"supports_cases":["morgan-c3"],"note":"一手·国会作证记录"}],"material_type":"rich","reasoning_skeleton":{"signature":"行业分散过度竞争时用资本整合成有秩序的大组织(资本整合重组)；把品格与信用当合作首要前提、自己的信用也是最大资产(信用即资产)；系统性危机时作为中枢把各方锁在一起组织救援(危机中挺身组织救援)；厌恶破坏性竞争、宁求稳定与共同利益(秩序优于竞争)；不必全资拥有、靠董事会席位与人脉建立影响网络(关系网络控制)","steps":[{"invoke":"资本整合重组","action":"这个行业是不是分散、过度竞争、互相杀价、整体在受损？能不能整合出秩序？"},{"invoke":"信用即资产","action":"你是在只看对方的抵押品数字，还是在看他的品格与信用？"},{"invoke":"危机中挺身组织救援","action":"系统性危机来了，你是观望自保，还是能当中枢把各方组织起来？"},{"invoke":"秩序优于竞争","action":"你在追求无序的竞争，还是稳定可预期的秩序？这秩序的代价是什么？"},{"invoke":"关系网络控制","action":"你是只靠所有权，还是能靠董事会席位与人脉建立影响网络？"}],"contrast":"与洛克菲勒不同(关键差异·同为镀金时代巨头)：**洛克菲勒是''单一产业(石油)的运营垄断者''——靠极致成本控制、纵向一体化在一个行业内做到垄断**；**摩根是''跨产业的金融整合者''——用资本与信用把分散的产业重组成大组织**——洛克菲勒经营实业、摩根运作资本(见洛克菲勒卡)。与卡内基不同：卡内基是钢铁实业的垂直整合与规模制造者；摩根恰恰买下卡内基的钢铁、组建美国钢铁——他是金融资本的运作者、非实业制造者(见卡内基卡)。【射程/盲区·二轴】摩根之道在''资本整合、信用立身、危机组织、网络控制''极有力，但①其''秩序优于竞争''与资本整合直接通向垄断、引发反托拉斯与''金钱托拉斯''质疑、权力过度集中是其阴暗面；②其模式以拥有巨大资本与个人威望为前提、普通人不具备；③金融整合者视角对''从0到1的产品/技术创新''着力少、逻辑是重组既有而非创造新的；④〔二轴〕摩根著述极少、其判断与动机多由传记重构、不宜全坐实于其个人。适用危机应对/资源调度/组织管理/投资；不适用创新研发/创业。"},"persona_anchor":{"primary":[{"source":"case","case_id":"morgan-c1","note":"用户''面对一个分散、过度竞争、大家互相杀价、整体都在受损的局面''时，以摩根组建美国钢铁类比：他把卡内基钢铁等分散竞争的钢铁企业用资本整合成美国钢铁这一巨型组织、消除破坏性竞争、建立秩序与规模——但同时要警惕这滑向垄断与抑制创新（组建US Steel为史实→确证；动机部分属传记重构）"},{"source":"case","case_id":"morgan-c3","note":"用户''在判断要不要信任/借力于某个合作者、只盯着对方的抵押与数字''时，以摩根''品格先于金钱''类比：他在普约委员会作证时强调、决定是否给一个人信贷、首要看的是他的品格与信用、而非抵押品——''我不信任的人、拿全世界的债券也借不到我的钱''（普约委员会证词为一手记录→确证）"}]},"further_reading":[{"title":"Jean Strouse《Morgan：American Financier》/ Ron Chernow《The House of Morgan》","why":"资本整合、1907救市、网络控制的权威传记（B）","type":"biography"},{"title":"1912 普约委员会(Pujo Committee)证词","why":"「品格先于金钱」、金钱托拉斯调查的一手记录（A）","type":"一手记录"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/morgan.png","avatar_thumb":"/advisors/portraits/morgan.png","domain":"商业","person_id":"P-morgan","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '432f5c9a539ef3777182c9423279b5520224f070c93da2b78fcfda62fa8a74f5', 64, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('morita', 'P-morita', '盛田昭夫', 'business', '盛田昭夫 · 创造市场与品牌优先思维框架卡', '现代（1921—1999）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '创造市场而非跟随调研 · 品牌优先拒代工', '/advisors/portraits/morita.png', '/advisors/portraits/morita.png', 5, 0, '{"schema_version":1,"card_id":"morita","name":"盛田昭夫","title":"盛田昭夫 · 创造市场与品牌优先思维框架卡","era":"现代（1921—1999）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"创造市场而非跟随调研","definition":"不只靠调研问消费者要什么，而是用出色的产品创造他们还不知道自己想要的需求","source":"盛田《Made in Japan》及Walkman开发史","source_tier":"primary","mechanism":"输入=靠市场调研问消费者要什么、跟随现有需求 → 处理=不问消费者(他们不知道还不存在的东西)、用产品创造他们还不知道想要的需求 → 输出=创造新市场(Walkman)","trigger":"要做突破性新产品时","modern_transfer":"别只靠市场调研问消费者''要什么''——消费者说不出还不存在的东西；用一个出色的产品去创造他们还不知道自己想要的需求(盛田推随身听Walkman时调研都说没人要、他坚持做、结果开创了一个时代)；但风险极高、见盲区","architecture":{"type":"flow","components":["别只靠调研跟随现有需求","消费者说不出不存在的东西","用产品创造潜在需求","创造一个新市场"]},"strategy_card_image":"kb-assets/morita/model-1.png"},{"name":"品牌优先拒代工","definition":"拒绝OEM贴牌代工的快钱，坚持打自己的品牌——哪怕初期更难、更慢","source":"盛田《Made in Japan》及Sony早期史","source_tier":"primary","mechanism":"输入=接OEM贴牌代工赚快钱、藏在别人品牌后 → 处理=拒绝代工、坚持打自有品牌、哪怕初期更难更慢 → 输出=自有品牌的长期价值(Sony拒代工)","trigger":"面对''贴牌代工 vs 自有品牌''抉择时","modern_transfer":"拒绝OEM贴牌代工的快钱、坚持打自己的品牌——哪怕初期更难、更慢；自有品牌才是长期价值的根(盛田早年拒绝一笔美国大客户的贴牌大单、坚持用Sony品牌)","architecture":{"type":"flow","components":["别接贴牌代工的快钱","拒绝藏在别人品牌后","坚持打自有品牌","换长期价值的根"]},"strategy_card_image":"kb-assets/morita/model-2.png"},{"name":"全球本土化","definition":"全球经营、但深度本地化——在各国融入当地、用当地人才、贴合当地需求（global localization）","source":"盛田提出的\"global localization\"","source_tier":"primary","mechanism":"输入=要么纯本国、要么全球一刀切 → 处理=全球经营、但深度本地化(管理/产品/融入当地) → 输出=全球化又扎根本地(global localization)","trigger":"要做全球化经营时","modern_transfer":"全球经营、但要深度本地化——在各国融入当地、用当地人才、贴合当地需求(''global localization''全球本土化、盛田提出);既不是纯本国、也不是全球一刀切","architecture":{"type":"matrix","components":["别纯本国也别全球一刀切","全球经营","深度本地化融入当地","全球化又扎根本地"]},"strategy_card_image":"kb-assets/morita/model-3.png"},{"name":"技术营销双驱","definition":"出色的技术还要会卖、出色的营销还要有真东西——把工程技术与营销两条腿结合","source":"盛田的经营风格","source_tier":"primary","mechanism":"输入=只有好技术却不会卖、或只会卖没真东西 → 处理=把出色的工程技术与出色的营销结合、两条腿走路 → 输出=技术与营销双轮驱动","trigger":"推一个技术产品时","modern_transfer":"出色的技术还要会卖、出色的营销还要有真东西——把工程技术与营销两条腿结合起来(盛田既懂技术、又是营销天才、亲自飞美国打开市场)","architecture":{"type":"flow","components":["别只有技术不会卖","也别只会卖没真东西","把工程技术与营销结合","技术与营销双轮驱动"]},"strategy_card_image":"kb-assets/morita/model-4.png"},{"name":"敢为天下先","definition":"率先去做别人还不敢做的新品类，承担先行的风险——晶体管收音机、随身听、特丽珑…","source":"Sony产品史","source_tier":"primary","mechanism":"输入=等别人验证了新品类再跟进、求稳 → 处理=率先做别人不敢做的新品类、承担先行风险 → 输出=以先行占领新品类(但也担先行风险)","trigger":"面对一个无人验证的新品类时","modern_transfer":"率先去做别人还不敢做的新品类、承担先行的风险——晶体管收音机、随身听、特丽珑显像管…(盛田的Sony总抢做第一个);先行者吃到开创红利、但也常成''先烈''(见盲区)","architecture":{"type":"flow","components":["别等别人验证了再跟","率先做别人不敢做的新品类","承担先行风险","以先行占领新品类"]},"strategy_card_image":"kb-assets/morita/model-5.png"}],"decision_principles":["别只靠调研，用出色的产品创造消费者还不知道想要的需求（风险高）","拒绝贴牌代工的快钱，坚持打自己的品牌","全球经营但深度本地化，既非纯本国也非全球一刀切","把出色技术与出色营销两条腿结合","率先做别人不敢做的新品类，承担先行风险"],"inquiry_questions":["你是靠调研跟随现有需求，还是用产品创造他们还不知道想要的需求？","你是接贴牌代工赚快钱，还是坚持打自己的品牌？","你是纯本国/全球一刀切，还是全球经营+深度本地化？","你是只有技术不会卖，还是技术与营销两条腿走？","你是等别人验证了再跟，还是率先做别人不敢做的新品类？"],"value_priorities":["创造新需求 ＞ 跟随调研出的现有需求（用Walkman创造了随身听市场（但风险高））","自有品牌 ＞ 贴牌代工的快钱（拒美国大单、坚持Sony品牌）","全球本土化 ＞ 纯本国或全球一刀切（global localization）"],"blind_spots":["''创造市场、不调研''风险极高——成则开创品类、败则巨大损失；并非所有''消费者不要''的产品都是被低估的明珠，多数真的没人要（原理推断，B）。","''敢为天下先''的先行者也常成''先烈''，Sony自身也有不少抢先却失败的产品（史实，B）。","其''品牌优先''以企业有能力做出值得自有品牌的产品为前提（原理推断，B）。","〔注意〕Sony在后来某些数字时代的转型上反应迟缓，说明同一套打法在新环境未必长青（史实，B）。"],"applicable_domains":["创业","创新研发","领导力","长期规划"],"match_tags":["创业","创新研发","领导力","长期规划","逆向思考","直觉决断","多元模型","现当代东亚"],"linked_cases":["morita-c1","morita-c2","morita-c3","morita-c4"],"life_tags":[{"tag":"联合创办索尼","tier":"secondary"},{"tag":"推随身听","tier":"secondary"},{"tag":"著日本制造","tier":"primary"},{"tag":"开拓美国市场","tier":"secondary"}],"voice_profile":{"notes":"开放进取、面向世界；营销直觉敏锐；敢为天下先；重品牌与远见"},"references":[{"ref_id":"morita-s1","title":"盛田昭夫《Made in Japan》","locator":"创造市场、拒贴牌坚持Sony品牌、全球本土化、技术营销","source_tier":"primary","supports_models":["创造市场而非跟随调研","品牌优先拒代工","全球本土化","技术营销双驱"],"supports_cases":["morita-c1","morita-c2","morita-c3"],"note":"一手·自传"},{"ref_id":"morita-s2","title":"Sony 产品史","locator":"晶体管收音机、Walkman、特丽珑等新品类","source_tier":"secondary","supports_models":["敢为天下先"],"supports_cases":["morita-c4"],"note":"二手·企业史"}],"material_type":"rich","reasoning_skeleton":{"signature":"别只靠调研问消费者要什么、用产品创造他们还不知道想要的需求(创造市场而非跟随调研)；拒绝贴牌代工快钱、坚持打自有品牌(品牌优先拒代工)；全球经营但深度本地化(全球本土化)；把出色技术与出色营销两条腿结合(技术营销双驱)；率先做别人不敢做的新品类(敢为天下先)","steps":[{"invoke":"创造市场而非跟随调研","action":"你是靠调研跟随现有需求、还是用产品创造他们还不知道想要的需求？"},{"invoke":"品牌优先拒代工","action":"你是接贴牌代工赚快钱、还是坚持打自己的品牌？"},{"invoke":"全球本土化","action":"你是纯本国/全球一刀切、还是全球经营+深度本地化？"},{"invoke":"技术营销双驱","action":"你是只有技术不会卖、还是技术与营销两条腿走？"},{"invoke":"敢为天下先","action":"你是等别人验证了再跟、还是率先做别人不敢做的新品类？"}],"contrast":"与本田宗一郎不同(关键差异·同为日本制造业巨头)：**本田是''技术第一+亲手实干+造的喜悦''的工程工匠**；**盛田是''创造市场+全球营销+品牌优先''的营销/全球化天才**——本田造卓越的产品、盛田创造市场并把它卖向全球(见本田卡)。与松下幸之助不同：松下是''自来水哲学(低价普及大众)''；盛田是''创造高端新品类、打全球品牌''(见松下卡)。与稻盛和夫不同：稻盛是''阿米巴+敬天爱人''的哲学派；盛田是''创造市场+品牌''的营销派(见稻盛和夫卡)。与乔布斯不同：乔布斯是''产品美学+封闭生态+现实扭曲力场''(盛田是其先驱之一);盛田是''创造市场+全球本土化+品牌''(见乔布斯卡)。【射程/盲区】盛田之道在''创造市场、品牌优先、全球本土化、技术营销双驱、敢为天下先''极有力，但①''创造市场、不调研''风险极高、多数''消费者不要''的产品真的没人要、并非都是被低估的明珠；②''敢为天下先''的先行者常成''先烈''、Sony自身也有不少抢先失败的产品；③''品牌优先''以企业有能力做出值得自有品牌的产品为前提；④〔注意〕Sony后来某些数字转型反应迟缓、同一套打法在新环境未必长青。适用创业/创新研发/领导力/长期规划；不适用危机应对/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"morita-c1","note":"用户''做新产品时一味依赖市场调研、调研说没人要就不敢做''时，以盛田推Walkman类比：当年市场调研都说''没人会买一个不能录音的小播放器''、盛田却坚信用户还不知道自己想要随时随地听音乐、坚持把Walkman做出来、结果开创了随身听时代——消费者说不出还不存在的东西、有时要用产品去创造需求（但这风险极高、并非所有''没人要''都是明珠）（盛田与Walkman为其自传《Made in Japan》所载→确证）"},{"source":"case","case_id":"morita-c2","note":"用户''纠结要不要接贴牌代工的快钱、还是打自己的品牌''时，以盛田拒代工类比：Sony早年一家美国公司开出大额订单、但要求贴对方的牌、盛田拒绝了这笔快钱、坚持要用Sony自己的品牌——哪怕初期更难、自有品牌才是长期价值的根（盛田拒贴牌大单为其自传所载→确证）"}]},"further_reading":[{"title":"盛田昭夫《Made in Japan》","why":"创造市场、拒代工坚持Sony品牌、全球本土化的一手自述（A）","type":"original"},{"title":"Sony 产品史","why":"晶体管收音机、Walkman、特丽珑等率先开创新品类的记录（A/B）","type":"企业史"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/morita.png","avatar_thumb":"/advisors/portraits/morita.png","domain":"商业","person_id":"P-morita","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '1bb3500d6c98fd57fb307d6c0faa2fd0446fa605e6e64a8233d4c000b514b734', 65, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('mozi', 'P-mozi', '墨子', 'philosophy', '墨子 · 兼爱实利思维框架卡', '战国（约前470—前391）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '兼爱 · 交相利', '/advisors/portraits/mozi.png', '/advisors/portraits/mozi.png', 5, 0, '{"schema_version":1,"card_id":"mozi","name":"墨子","title":"墨子 · 兼爱实利思维框架卡","era":"战国（约前470—前391）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"兼爱","definition":"把关怀/资源更普遍、无差别地分配给所有人，不分亲疏远近——以普遍的利他取代差等之爱","source":"《墨子·兼爱》","source_tier":"primary","mechanism":"输入=只顾亲近圈子、差等之爱 → 处理=无差别地把关怀/资源分配给所有人、不分亲疏 → 输出=普遍的利他(兼爱)","trigger":"分配关怀/资源、面对亲疏远近时","modern_transfer":"把关怀/资源更普遍、无差别地分配、而非只顾亲近的圈子(''兼相爱''、墨子);但须权衡可行性、资源有限时全面兼顾也有难处(见盲区)","architecture":{"type":"flow","components":["别只顾亲近圈子差等之爱","无差别地分配关怀资源","不分亲疏远近","普遍的利他"]},"strategy_card_image":"kb-assets/mozi/model-1.png"},{"name":"交相利","definition":"让\"关爱/合作\"落到\"互相带来实际利益\"上，而非空谈道德——爱与利结合才可持续","source":"《墨子·兼爱》","source_tier":"primary","mechanism":"输入=空谈道德/爱 → 处理=让爱落到''互相带来实际利益''上、爱与利结合 → 输出=可持续的兼爱(交相利)","trigger":"要让一个利他/合作的关系可持续时","modern_transfer":"让''关爱/合作''落到''互相带来实际利益''上、而非空谈道德——''兼相爱、交相利''、爱与利结合才可持续(墨子)","architecture":{"type":"flow","components":["别空谈道德与爱","让爱落到互相的实际利益上","爱与利结合","可持续的兼爱"]},"strategy_card_image":"kb-assets/mozi/model-2.png"},{"name":"三表法","definition":"判断一个说法是否可信，用三把尺：有历史根据（本）、合大众经验（原）、有实际效用（用）","source":"《墨子·非命上》","source_tier":"primary","mechanism":"输入=凭空断言一个主张 → 处理=用三条标准检验:有历史根据(本)/合大众经验(原)/有实际效用(用) → 输出=经检验的可信主张(三表)","trigger":"判断一个说法/主张是否可信时","modern_transfer":"判断一个说法是否可信、用三把尺:有没有历史先例(本之于古者圣王之事)、合不合大众的经验(原之于百姓耳目之实)、用起来有没有实效(用之于实际)——墨子''三表法''","architecture":{"type":"hierarchy","components":["别凭空断言","本之有无历史根据","原之合不合大众经验","用之有无实际效用"]},"strategy_card_image":"kb-assets/mozi/model-3.png"},{"name":"非攻与实力自卫","definition":"反对主动去侵害别人，但要靠强大的防御实力让对方不敢侵犯你——\"非攻\"不等于无防备","source":"《墨子·非攻》及止楚攻宋","source_tier":"primary","mechanism":"输入=要么主动侵害、要么无防备 → 处理=反对主动侵略、但以强大的防御实力让对方不敢攻 → 输出=以实力支撑的和平(非攻+守城)","trigger":"面对冲突/竞争、考虑攻守时","modern_transfer":"反对主动去侵害别人(''非攻'')、但要靠强大的防御实力让对方不敢侵犯你——''非攻''不等于无防备(墨子既反侵略战争、又精于守城、曾止楚攻宋)","architecture":{"type":"flow","components":["别主动侵害也别无防备","反对主动侵略","以强大的防御实力","让对方不敢攻"]},"strategy_card_image":"kb-assets/mozi/model-4.png"},{"name":"节用尚实","definition":"去掉一切不带来实际效用的浪费与繁文缛节，把资源都投到有实效的地方——一切以实用为准","source":"《墨子·节用》《非乐》","source_tier":"primary","mechanism":"输入=讲排场、繁文缛节、铺张浪费 → 处理=去掉一切不带来实际效用的浪费与繁文缛节、一切以实用为准 → 输出=资源都投到有实效处(节用)","trigger":"面对资源分配/排场取舍时","modern_transfer":"去掉一切不带来实际效用的浪费与繁文缛节(节用、节葬、非乐)、把资源都投到有实效的地方——一切以实用为准(墨子尚实)〔但极端节用也否定了情感与审美的价值、见盲区〕","architecture":{"type":"flow","components":["别讲排场铺张浪费","去掉不带来实效的浪费与繁文","一切以实用为准","资源投到有实效处"]},"strategy_card_image":"kb-assets/mozi/model-5.png"}],"decision_principles":["把关怀/资源更普遍无差别地分配（但须权衡可行性）","让爱与合作落到互相的实际利益上，而非空谈道德","判断说法用三尺：历史根据、大众经验、实际效用","反对主动侵害，但靠强大防御让对方不敢攻","去掉不带来实效的浪费与繁文，一切以实用为准"],"inquiry_questions":["你是只顾亲近的圈子、还是更普遍无差别地分配你的关怀与资源？","你这个利他/合作，是空谈道德、还是落到了互相的实际利益上？","这个说法可信吗？有历史先例吗、合大众经验吗、用起来有实效吗？","你是在主动侵害、还是反对侵害但有足够的防御实力让对方不敢攻？","这里面有多少是不带来实效的排场与浪费、可以去掉？"],"value_priorities":["普遍无差别的兼爱 ＞ 差等的亲疏之爱（兼相爱（但落地有难处））","实际效用 ＞ 空谈道德与排场（交相利、节用尚实）","三表检验 ＞ 凭空断言（本之/原之/用之）"],"blind_spots":["兼爱（无差别的爱）在资源有限、人情有亲疏的现实中难以彻底实行，被孟子批为''无父''（忽视人伦的差等）——理想高但落地难（学术分析，B）。","极端节用/非乐否定了情感、审美、文化的价值，过于功利（学术分析，B）。","三表法重''效用''与''经验''，对超越当下经验的抽象/长远价值可能低估（原理推断，B）。","墨家组织严密、纪律极严、有''巨子''集权，也潜藏过度集权与压制个体的风险（学术史，B）。"],"applicable_domains":["价值与伦理","组织管理","认知偏误与理性决策"],"match_tags":["价值与伦理","组织管理","认知偏误与理性决策","利他取向","务实渐进","批判思辨","古代东亚"],"linked_cases":["mozi-c1","mozi-c2","mozi-c3","mozi-c4"],"life_tags":[{"tag":"创墨家学派","tier":"secondary"},{"tag":"倡兼爱非攻","tier":"primary"},{"tag":"止楚攻宋","tier":"secondary"},{"tag":"善守城御敌","tier":"secondary"}],"voice_profile":{"notes":"质朴务实、重实利实效；苦行救世；逻辑严谨；反对铺张文饰"},"references":[{"ref_id":"mozi-s1","title":"《墨子》","locator":"兼爱、交相利、三表法、非攻、节用","source_tier":"primary","supports_models":["兼爱","交相利","三表法","非攻与实力自卫","节用尚实"],"supports_cases":["mozi-c1","mozi-c2","mozi-c3","mozi-c4"],"note":"一手·原典"},{"ref_id":"mozi-s2","title":"墨家思想与逻辑研究","locator":"兼爱、三表法、墨辩","source_tier":"secondary","supports_models":["三表法","兼爱"],"note":"二手·研究"}],"material_type":"textual","reasoning_skeleton":{"signature":"无差别地把关怀资源分配给所有人而非只顾亲近圈子(兼爱)；让爱落到互相带来实际利益上(交相利)；用历史根据/大众经验/实际效用三条标准检验一个主张(三表法)；反对主动侵害但以强大防御让对方不敢攻(非攻与实力自卫)；去掉一切不实用的浪费繁文一切以实用为准(节用尚实)","steps":[{"invoke":"兼爱","action":"你是只顾亲近的圈子、还是更普遍无差别地分配你的关怀与资源？"},{"invoke":"交相利","action":"你这个利他/合作，是空谈道德、还是落到了互相的实际利益上？"},{"invoke":"三表法","action":"这个说法可信吗？有历史先例吗、合大众经验吗、用起来有实效吗？"},{"invoke":"非攻与实力自卫","action":"你是在主动侵害、还是反对侵害但有足够的防御实力让对方不敢攻？"},{"invoke":"节用尚实","action":"这里面有多少是不带来实效的排场与浪费、可以去掉？"}],"contrast":"与孔子/孟子不同(关键差异·儒墨对立)：**儒家主''差等之爱''(爱有亲疏厚薄)、重礼乐文饰**；**墨子主''兼爱''(无差别地爱)、重实利、''节用非乐''反对铺张的礼乐**——一个爱有差等、重礼乐，一个兼爱无别、尚实用(见孔子/孟子卡)。与韩非子不同：韩非''法术势''靠制度与赏罚的强制;墨子靠''兼爱交相利''的道德与实利说服(见韩非子卡)。与老庄不同：老庄''无为/超脱'';墨子''兼爱/务实/苦行救世''(极其入世)(见老子/庄子卡)。【射程/盲区】墨子之道在''兼爱、交相利、三表法、非攻自卫、节用尚实''极有力，但①兼爱(无差别的爱)在资源有限、人情有亲疏的现实中难以彻底实行、被孟子批为''无父''、理想高但落地难;②极端节用/非乐否定了情感、审美、文化的价值、过于功利;③三表法重效用与经验、对超越当下经验的抽象/长远价值可能低估;④墨家组织纪律极严、有''巨子''集权、潜藏压制个体的风险。适用价值与伦理/组织管理/认知偏误与理性决策;不适用投资/创作。"},"persona_anchor":{"primary":[{"source":"case","case_id":"mozi-c2","note":"用户''面对冲突、纠结要主动出击侵害对方、还是干脆毫无防备''时，以墨子非攻类比：墨子既坚决反对主动去侵略别人(''非攻'')、又精于守城、曾长途奔走以高超的守城之术止住楚国攻宋——反对主动侵害、但靠强大的防御实力让对方不敢动你;''非攻''不等于无防备（止楚攻宋为《墨子》所载→确证）"},{"source":"case","case_id":"mozi-c3","note":"用户''要判断一个流行说法/主张到底可不可信''时，以墨子三表法类比：用三把尺去检验——有没有历史先例(本)、合不合大众的实际经验(原)、用起来有没有实效(用);三条都站得住才采信、而非凭空断言或人云亦云（三表法为《墨子·非命上》所载→确证）"}]},"further_reading":[{"title":"《墨子》","why":"兼爱、交相利、三表法、非攻、节用的一手出处（A）","type":"原典"},{"title":"墨家思想与逻辑研究","why":"对兼爱、三表法、墨辩逻辑的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/mozi.png","avatar_thumb":"/advisors/portraits/mozi.png","domain":"哲学","person_id":"P-mozi","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '43c1c3f7a404991149409e36dbc39cb86c2433cd7c77e233d90263959b75c521', 66, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('munger', 'P-munger', '查理·芒格', 'business', '查理·芒格 · 商业决策思维框架卡', '20–21世纪（1924–2023）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '多元思维格栅 · 逆向思维', '/advisors/portraits/munger.png', '/advisors/portraits/munger.png', 5, 0, '{"schema_version":1,"card_id":"munger","name":"查理·芒格","title":"查理·芒格 · 商业决策思维框架卡","era":"20–21世纪（1924–2023）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"多元思维格栅","definition":"把多学科真正管用的大道理编成相互印证的格栅，多角度交叉检验，避免单一框架看问题","source":"《穷查理宝典》及南加大法学院毕业演讲","source_tier":"primary","mechanism":"输入=一个待判断的问题 → 处理=依次用心理学/经济学/物理数学/生物学/工程等多学科''真正管用的大道理''交叉检验 → 输出=经多框架相互印证、不被单一视角误导的判断","trigger":"面对复杂、跨领域、容易被单一专业视角带偏的判断时","modern_transfer":"评估一项业务或投资前，强制用至少三个不同学科视角各过一遍，任一视角亮红灯即重审","architecture":{"type":"grid","components":["心理学","经济学","物理/数学","生物学","工程"]},"strategy_card_image":"kb-assets/munger/model-1.png"},{"name":"逆向思维","definition":"要把事做成，先彻底研究怎样会把它搞砸，再绕开那些失败路径——反过来想，总是反过来想","source":"芒格公开演讲（格言借自数学家雅可比，经其推广）","source_tier":"primary","mechanism":"输入=想达成的目标 → 处理=穷举''怎样会把它彻底搞砸''的失败路径 → 输出=一份要主动绕开的失败清单","trigger":"面对''怎样把一件事做成''的规划时，先反着问","modern_transfer":"做计划先写''失败前提清单''，把资源优先投在堵死失败路径上，而非堆砌成功要素","architecture":{"type":"flow","components":["设定目标","穷举失败路径","逐条规避","反推可行方案"]},"strategy_card_image":"kb-assets/munger/model-2.png"},{"name":"能力圈与太难堆","definition":"认清自己真正懂的边界；多数机会都该诚实放进太难堆，只对极少数看得极透者重仓出手","source":"芒格历年年会问答与讲稿","source_tier":"primary","mechanism":"输入=一个机会 → 处理=判断它是否落在自己真正看透的边界内 → 输出=重仓 / 放进太难堆 的二值决定","trigger":"面对''要不要下注、要不要投入''、而自己对该领域把握不足时","modern_transfer":"对绝大多数机会默认''太难、不碰''，只对极少数看得极透的重仓——把''不做''当成一项主动决策","architecture":{"type":"flow","components":["机会输入","能力圈边界判定","太难堆闸门","极少数重仓"]},"strategy_card_image":"kb-assets/munger/model-3.png"},{"name":"误判心理学","definition":"人脑有约二十多种系统偏误，激励引起的偏见居首；理性第一步是建清单主动反向核对","source":"1995年哈佛同名演讲《人类误判心理学》","source_tier":"primary","mechanism":"输入=一个行为或决策情境 → 处理=对照约二十多种偏误清单（激励引起的偏见居首）主动反向核对 → 输出=识别出正在起作用的偏误并纠偏","trigger":"预测他人行为、或怀疑自己/对方判断被情绪或利益扭曲时","modern_transfer":"重大决策前过一遍偏误检查清单，尤其先问''这里谁的激励在起作用''","architecture":{"type":"grid","components":["激励偏见","社会认同","承诺一致","损失厌恶","权威效应"]},"strategy_card_image":"kb-assets/munger/model-4.png"},{"name":"Lollapalooza效应","definition":"多个模型偏误或外力同向叠加时，产生远超线性的极端结果，无论是巨大成功还是崩塌","source":"芒格演讲（其本人创造该术语）","source_tier":"primary","mechanism":"输入=多个模型/偏误/外力 → 处理=判断它们是否同向叠加共振 → 输出=对是否出现远超线性的极端结果（暴涨或崩塌）的预判","trigger":"判断一个局面会不会走向极端、几股力量是否正同向放大时","modern_transfer":"评估风险或机会时，专门检查多个因素会不会同向共振放大，而非把它们当作彼此独立","architecture":{"type":"loop","components":["多因素输入","同向叠加检测","非线性放大","极端结果"]},"strategy_card_image":"kb-assets/munger/model-5.png"}],"decision_principles":["先避免愚蠢再追求卓越：系统消除已知错误来源（A）","反过来想：先研究什么导致失败，再绕开（A）","守能力圈，多数归入太难堆，只对极少数重仓（A）","以合理价买伟大企业，胜过便宜价买平庸企业（A/B）","找到对的标的就坐着不动，让复利替你工作（A）","把激励当头号解释变量：预测行为先看激励（A）"],"inquiry_questions":["这事落在你真正懂的范围内吗？不在为何不放进太难堆？","先别想怎么成功——把它彻底搞砸需要哪几步？","这事里谁的利益和你相反？催你拍板的人靠什么挣钱？","你是不是只拿一把锤子在敲？换几个学科会怎么看？","最坏会坏到什么程度，那个结果你扛得住吗？"],"value_priorities":["生存·避免不可逆的毁灭性风险 ＞ 追求高回报（不爆仓优先于一切，先活下来）","长期复利 ＞ 短期收益（时间是好生意的朋友）","对自己诚实、敢说我不知道 ＞ 面子与自我感觉良好（承认无知是理性的起点）","伟大生意与正直管理层（质量） ＞ 表面便宜的平庸标的（质量优于价格）"],"blind_spots":["过度自信于自身理性、越界压制领域专家——Munger Hall无窗宿舍即例（主流媒体+其本人言论，B/A）","极度集中加杠杆导致剧烈回撤，对波动承受力与是否对外部出资人负责要求极高（传记，B）","对整类新事物（如加密货币）易一刀切否定，可能把我不懂误当它没价值（其公开言论，A）","偏静态的好生意加长期持有框架，对技术颠覆或无长期数据的新事物反应偏慢（长期回避科技股，B）"],"applicable_domains":["投资","商业模式与护城河","长期规划","风险评估","认知偏误与理性决策","组织管理"],"match_tags":["投资","风险评估","长期规划","商业模式与护城河","认知偏误与理性决策","多元模型","逆向思考","风险规避","现当代北美"],"linked_cases":["munger-c1","munger-c2","munger-c3","munger-c4","munger-c5"],"life_tags":[{"tag":"辅佐巴菲特","tier":"secondary"},{"tag":"著穷查理宝典","tier":"primary"},{"tag":"倡多元模型","tier":"primary"},{"tag":"掌每日期刊","tier":"secondary"}],"voice_profile":{"notes":"格言式短句；辛辣反讽与自嘲；好用跨学科典故与类比；标志性短语（能力圈/太难堆/反过来想）"},"references":[{"ref_id":"munger-s1","title":"《穷查理宝典》（Poor Charlie''s Almanack）","locator":"讲稿合集；具体篇目/页码待质检者据原书核验","source_tier":"primary","supports_models":["多元思维格栅","误判心理学"],"note":"一手讲稿合集，收录其多篇毕业演讲与《人类误判心理学》；精确篇目页码待人审定位后定 verifiability"},{"ref_id":"munger-s2","title":"芒格《人类误判心理学》演讲（1995, Harvard）","locator":"1995年哈佛演讲；段落/时间点待核验","source_tier":"primary","supports_models":["误判心理学","Lollapalooza效应"],"note":"约二十多种偏误清单与 Lollapalooza 术语的直接出处"},{"ref_id":"munger-s3","title":"芒格南加大古尔德法学院毕业演讲（USC Gould, 2007）","locator":"毕业演讲；段落待核验","source_tier":"primary","supports_models":["多元思维格栅","能力圈与太难堆"],"note":"格栅、能力圈、太难堆等标志表达多出自此类毕业演讲"},{"ref_id":"munger-s4","title":"Daily Journal / Wesco 年会问答（历年）","locator":"历年年会问答；具体年份场次待核验","source_tier":"primary","supports_models":["逆向思维","能力圈与太难堆","Lollapalooza效应"],"supports_cases":["munger-c3"],"note":"逆向/胖好球/Lollapalooza 多在年会阐述；比亚迪''唯一最大贡献''出自2023年Daily Journal年会"},{"ref_id":"munger-s5","title":"巴菲特1983年致股东信","locator":"1983年信，喜诗糖果经济商誉论述段","source_tier":"primary","supports_cases":["munger-c1"],"note":"喜诗收购价与财务数据、经济商誉论述的一手出处"},{"ref_id":"munger-s6","title":"《Fortune》喜诗糖果报道（1988）","locator":"1988年报道；具体篇目待核验","source_tier":"secondary","supports_cases":["munger-c1"],"note":"芒格推动''好生意付溢价''范式转移的二手印证"},{"ref_id":"munger-s7","title":"Janet Lowe《Damn Right!》","locator":"惠勒·芒格合伙公司章节；页码待核验","source_tier":"secondary","supports_cases":["munger-c2"],"note":"合伙基金1973–74回撤、出资人赎回致清盘的权威传记来源（非孤证）"},{"ref_id":"munger-s8","title":"Alice Schroeder《滚雪球》（The Snowball）","locator":"芒格相关章节；页码待核验","source_tier":"secondary","supports_cases":["munger-c2"],"note":"回撤与清盘的交叉印证传记来源"},{"ref_id":"munger-s9","title":"比亚迪投资主流财经媒体报道（2008前后）","locator":"报道；具体媒体/日期待核验","source_tier":"secondary","supports_cases":["munger-c3"],"note":"2.3亿美元投资、约10%股权、引荐人李录的二手来源"},{"ref_id":"munger-s10","title":"UCSB Munger Hall 争议媒体报道（2021）","locator":"Santa Barbara Independent / CNN / Architectural Record / Dezeen 等；具体篇目待核验","source_tier":"secondary","supports_models":["逆向思维"],"supports_cases":["munger-c4"],"note":"捐赠条件、约94%无窗、建筑师辞职、2023放弃方案的多源报道（反例案例）"},{"ref_id":"munger-s11","title":"Costco 投资者关系披露 + 芒格年会评价","locator":"Costco IR 董事任职披露；芒格历年年会Costco评价段","source_tier":"primary","supports_models":["能力圈与太难堆"],"supports_cases":["munger-c5"],"note":"1997年起任董事约27年的官方披露 + 其长期评价"}],"material_type":"rich","reasoning_skeleton":{"signature":"先排除愚蠢、再追求卓越；下注前先问谁的激励和你相反、最坏会坏到哪","steps":[{"invoke":"误判心理学","action":"先扫一遍情境里谁的激励在起作用、自己有没有被偏误带着走，把扭曲源识别出来"},{"invoke":"逆向思维","action":"不问怎么成功，先穷举怎样会彻底失败，列出必须绕开的路径"},{"invoke":"能力圈与太难堆","action":"判断这事是否落在自己真正看透的范围内；不在就直接放进太难堆、不下注"},{"invoke":"多元思维格栅","action":"对留下来的少数机会，用多学科视角交叉检验生意/标的质量"},{"invoke":"Lollapalooza效应","action":"最后检查关键风险与收益因素会不会同向共振放大，据此决定下注力度"}],"contrast":"与费曼相反：费曼把问题拆到第一性原理再从零重建、信公式不信权威；芒格不重建物理机制，而用''多学科旧智慧 + 误判心理学''先排错、先看激励，更像风控而非创造（见费曼卡）。与巴菲特相比，芒格更偏跨学科误判心理学与''避错优先''的辛辣通才气质（见巴菲特卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"munger-c1","note":"用户纠结''该不该为优质标的付高价、这价是不是太贵''时，以喜诗糖果类比：芒格如何先判生意质量（定价权、约25%有形资产回报率）再谈价格，跳出账面便宜的陷阱"},{"source":"case","case_id":"munger-c4","note":"用户''我有一套很自洽的推理、但专家和数据都反对''时，以 Munger Hall 作反例镜子：再强的自洽推理一旦越出能力圈又拒听反证，就从洞察滑向傲慢——用他自己的框架看，本该放进太难堆"}]},"knowledge_cards":[{"card_type":"model","source_field":"core_models[多元思维格栅]","diagram_hint":"中心一个问题，外围环绕5个学科透镜的格栅图，每个透镜射出一条交叉检验线汇于中心结论","architecture_type":"grid"},{"card_type":"model","source_field":"core_models[逆向思维]","diagram_hint":"从''目标''先分叉到多条红色''失败路径''，再逐条画''规避''箭头收敛到''可行方案''的流程图","architecture_type":"flow"},{"card_type":"model","source_field":"core_models[能力圈与太难堆]","diagram_hint":"机会流入一道''能力圈边界''闸门，绝大多数被分流进''太难堆''，仅极少数''看得极透者''通过进入''重仓''，旁注''不做也是一项决策''","architecture_type":"flow"},{"card_type":"model","source_field":"core_models[误判心理学]","diagram_hint":"偏误清单网格，''激励引起的偏见''置顶高亮，每格旁标一句纠偏问句","architecture_type":"grid"},{"card_type":"model","source_field":"core_models[Lollapalooza效应]","diagram_hint":"多个箭头同向叠加、合力曲线呈非线性陡升/陡降的共振示意图","architecture_type":"loop"},{"card_type":"skeleton","source_field":"reasoning_skeleton","diagram_hint":"五步竖向流程链：误判心理学(先看激励/排偏误)→逆向(列失败路径)→能力圈(不在圈即弃)→多元格栅(交叉验质量)→Lollapalooza(查共振定下注力度)，整体标注''先做减法、后做加法''"},{"card_type":"inquiry","source_field":"inquiry_questions","diagram_hint":"五个问诊气泡逐条排列：落在你真正懂的范围内吗 / 把它彻底搞砸要哪几步 / 谁的利益和你相反 / 是不是只拿一把锤子在敲 / 最坏扛得住吗——供决策前自检打勾"},{"card_type":"blind_spot","source_field":"blind_spots","diagram_hint":"四格警示牌：越界压制领域专家 / 集中加杠杆致深回撤 / 整类新事物一刀切否定 / 技术颠覆反应偏慢，每格配''与哪条优势同源''的注脚"},{"card_type":"decision_moment","source_field":"cases[munger-c1]","diagram_hint":"时间轴卡：1972 喜诗要价≈3倍有形净资产→芒格判''品牌定价权+约25%有形资产回报率''→力主付合理高价并说服巴菲特→数十年现金流远超买价，主题标''质量优于价格''","source_tier_label":"确证"},{"card_type":"decision_moment","source_field":"cases[munger-c3]","diagram_hint":"卡面：看不透的科技/汽车领域→经信任的李录了解王传福→把判断权重放在管理层质量→破例投约2.3亿美元，标''能力圈延伸＝信任真正懂行、利益一致的人''","source_tier_label":"确证"},{"card_type":"decision_moment","source_field":"cases[munger-c4]","diagram_hint":"反例卡(红框)：自洽的''逼出社交''第一性推理 vs 采光证据+建筑师辞职抗议→芒格公开斥反对者、预言全美效仿→2023校方放弃方案，标''越界又拒听反证＝从洞察滑向傲慢、本该进太难堆''","source_tier_label":"确证"},{"card_type":"decision_moment","source_field":"cases[munger-c5]","diagram_hint":"卡面：估值长期不低的卖出诱惑 vs 会员忠诚+极致低价飞轮+正直管理层→判定伟大生意''坐着不动''、持有至离世，标''找到对的就忍住不折腾''","source_tier_label":"确证"}],"further_reading":[{"title":"《穷查理宝典》（Poor Charlie''s Almanack）","why":"芒格思想的总集，多元思维格栅与误判心理学的第一手讲稿都在此","type":"original"},{"title":"芒格《人类误判心理学》1995哈佛演讲","why":"约二十多种偏误清单与 Lollapalooza 术语的直接出处，一篇读懂他的''避错''内核","type":"讲稿"},{"title":"Janet Lowe《Damn Right!》（中译《查理·芒格传》）","why":"想看他真实决策与1973–74回撤等''决策时刻''的权威传记","type":"biography"},{"title":"Alice Schroeder《滚雪球》","why":"从巴菲特视角侧写芒格，理解二人互补与''质量优于价格''的转向","type":"biography"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/munger.png","avatar_thumb":"/advisors/portraits/munger.png","domain":"商业","person_id":"P-munger","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '8c8229e7c7abfb9c58497906b67b2af509c0e353dc977a4e78d89aa1d63f6774', 67, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('napoleon', 'P-napoleon', '拿破仑', 'strategy', '拿破仑 · 军政决断思维框架卡', '18世纪末—19世纪（1769—1821）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '集中优势兵力于决定点 · 速度与机动', '/advisors/portraits/napoleon.png', '/advisors/portraits/napoleon.png', 5, 0, '{"schema_version":1,"card_id":"napoleon","name":"拿破仑","title":"拿破仑 · 军政决断思维框架卡","era":"18世纪末—19世纪（1769—1821）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"集中优势兵力于决定点","definition":"不平摊兵力，把主力快速集结于战场上能决定胜负的那一点，在局部造成压倒性优势再击破之","source":"拿破仑战法核心；约米尼《战争艺术概论》归纳其\"决定点\"原则","source_tier":"secondary","mechanism":"输入=一个对抗战场 → 处理=不平摊兵力、把主力快速集结于能决定胜负的那一点、局部造压倒性优势 → 输出=击破决定点","trigger":"资源有限、容易处处平摊用力时","modern_transfer":"别平摊资源——把主力集中砸向那个真正决定胜负的点，局部绝对优势胜过全线平庸","architecture":{"type":"matrix","components":["识别决定点","主力快速集结","局部造绝对优势","击破之"]},"strategy_card_image":"kb-assets/napoleon/model-1.png"},{"name":"速度与机动","definition":"以远超对手的行军速度分进合击，打乱其部署、各个击破，让时间成为己方武器","source":"1805乌尔姆战役大迂回、奥斯特里茨快速集结","source_tier":"secondary","mechanism":"输入=对手的部署 → 处理=以远超对手的行军速度分进合击、打乱其部署各个击破 → 输出=让时间成为己方武器","trigger":"能比对手更快、想抢在其集结前时","modern_transfer":"比对手更快——以机动速度抢时间、在他集结前分而胜之，慢即失机","architecture":{"type":"flow","components":["侦知对手部署","高速分进","合击其弱","各个击破"]},"strategy_card_image":"kb-assets/napoleon/model-2.png"},{"name":"士气与荣誉激励","definition":"用荣誉、勋章、亲身在场和宏大叙事点燃部队精神力量；他视精神对物质为三比一","source":"拿破仑名言''精神之于物质，三比一''；荣誉军团勋章制度","source_tier":"secondary","mechanism":"输入=一支队伍 → 处理=用荣誉/勋章/亲身在场/宏大叙事点燃精神力量（视精神对物质为三比一）→ 输出=可经营的战力","trigger":"需要点燃队伍精神力量时","modern_transfer":"队伍的精神力量是可经营的战力——荣誉、意义、你本人的在场，精神先于物质","architecture":{"type":"hierarchy","components":["评士气状态","授荣誉/勋章","亲身在场","宏大叙事点燃"]},"strategy_card_image":"kb-assets/napoleon/model-3.png"},{"name":"制度法典化","definition":"把胜利成果固化为可长存的制度与法典，让秩序不依赖个人而靠规则延续——武功须以文治固定","source":"《拿破仑法典》(1804)","source_tier":"primary","mechanism":"输入=一次胜利/成果 → 处理=把它固化为可长存的制度与法典、让秩序靠规则而非个人延续 → 输出=不依赖个人的秩序","trigger":"打下成果后、想让它长久而非人走茶凉时","modern_transfer":"真正长久的胜利是把成果固化成不依赖你个人的制度/规则——武功须以文治封存","architecture":{"type":"hierarchy","components":["取得成果","提炼为规则","编纂成制度/法典","秩序靠规则延续"]},"strategy_card_image":"kb-assets/napoleon/model-4.png"},{"name":"抓住机会窗口","definition":"在革命动荡的权力真空与战机稍纵即逝处果断出手，以一个动作攫取主动；机会主义的精准","source":"雾月政变(1799)夺权","source_tier":"secondary","mechanism":"输入=一个动荡/真空的局势 → 处理=在权力真空与稍纵即逝的战机处果断出手、以一个动作攫取主动 → 输出=精准的机会主义","trigger":"巨变/真空期、机会窗口稍纵即逝时","modern_transfer":"巨变与真空期机会窗口稍纵即逝——识别它并果断攫取，胜过在旧秩序里循序渐进","architecture":{"type":"flow","components":["识别动荡/真空","判断窗口期","果断出手","攫取主动"]},"strategy_card_image":"kb-assets/napoleon/model-5.png"}],"decision_principles":["集中不分散：主力压向决定点，局部造绝对优势（决定点原则，B）","快于敌人：以机动速度抢时间、各个击破（乌尔姆/奥斯特里茨，B）","先固制度再图扩张：胜利要落成法典才长久（《拿破仑法典》，A）","精神先于物质：士气与荣誉是可经营的战力（三比一之喻，B）","机会来时果断攫取：权力真空处先下手（雾月政变，B）"],"inquiry_questions":["你的兵力(资源)是在平摊，还是集中砸向那个真正决定胜负的点？","你能不能比对手更快？如果速度翻倍，能不能在他集结前就分而胜之？","你打下的东西，有没有固化成不依赖你个人的制度/规则？还是人走茶凉？","你队伍的精神力量你经营了吗——荣誉、意义、你本人的在场？","现在是不是一个稍纵即逝的机会窗口？错过它还会再来吗？"],"value_priorities":["集中于决定点 ＞ 处处设防/平均用力（局部绝对优势胜过全线平庸）","速度与主动 ＞ 稳妥的慢（时间是武器，慢即失机）","不依赖个人的制度 ＞ 一次性的军事胜利（法典比战功长久(但其帝国扩张本身却高度依赖他个人，构成内在矛盾)）","扩张与荣耀 ＞ 见好就收的节制（此偏好成就其崛起，也直接导致征俄过顶点而崩(其盲区)）"],"blind_spots":["不知节制、越过进攻顶点：1812征俄以60万大军深入、补给与寒冬拖垮，几乎全军覆没——其''扩张优先''的偏好缺乏止损阀（史实，B）","帝国高度系于个人天才：制度法典虽存，但军政扩张依赖其本人，本人一败/一退则联盟反扑、体系崩解（史实推断，B）","圣赫勒拿口述/回忆(《拿破仑回忆录》类)是失势后自我辩护与塑造，对其动机与决策的自述须打折，不可当客观史实（史料批判，A/B）","胜利的路径依赖：屡胜养成对决战与机动的过度自信，遇到不与其决战的消耗战略(西班牙游击、俄国焦土)即失灵（学术分析，B）"],"applicable_domains":["战略","领导力","危机应对","竞争博弈"],"match_tags":["战略","领导力","危机应对","竞争博弈","直觉决断","对抗性思维","系统分析","近代欧洲"],"linked_cases":["napoleon-c1","napoleon-c2","napoleon-c3","napoleon-c4"],"life_tags":[{"tag":"颁拿破仑法典","tier":"secondary"},{"tag":"加冕称帝","tier":"secondary"},{"tag":"兵败滑铁卢","tier":"secondary"},{"tag":"远征俄国惨败","tier":"secondary"}],"voice_profile":{"notes":"简洁果断的命令体；格言警句；诉诸荣誉与激情；宏大叙事"},"references":[{"ref_id":"napoleon-s1","title":"约米尼《战争艺术概论》","locator":"对拿破仑\"集中于决定点\"原则的归纳","source_tier":"secondary","supports_models":["集中优势兵力于决定点","速度与机动"],"note":"同时代参谋的理论归纳，二手"},{"ref_id":"napoleon-s2","title":"权威拿破仑战史(乌尔姆/奥斯特里茨/征俄)","locator":"1805乌尔姆大迂回、奥斯特里茨会战、1812征俄","source_tier":"secondary","supports_models":["速度与机动","集中优势兵力于决定点"],"supports_cases":["napoleon-c1","napoleon-c3"],"note":"多源战史交叉印证，个人指挥角色有据→确证"},{"ref_id":"napoleon-s3","title":"《拿破仑法典》(Code civil, 1804)","locator":"法典文本及立法史","source_tier":"primary","supports_models":["制度法典化"],"supports_cases":["napoleon-c2"],"note":"一手制度文本，本卡历史性最硬条目"},{"ref_id":"napoleon-s4","title":"荣誉军团勋章制度(1802) / 传世名言","locator":"荣誉军团设立；\"精神物质三比一\"之喻","source_tier":"secondary","supports_models":["士气与荣誉激励"],"note":"制度史实为确证；名言为传为其语、细节存疑"},{"ref_id":"napoleon-s5","title":"雾月政变(1799)史料","locator":"雾月十八日政变记载","source_tier":"secondary","supports_models":["抓住机会窗口"],"supports_cases":["napoleon-c4"],"note":"多源信史"}],"material_type":"rich","reasoning_skeleton":{"signature":"把主力集中砸向决定胜负的那一点、以速度抢在对手集结前各个击破；用荣誉与在场经营士气，抓住稍纵即逝的机会窗口果断出手，再把胜利固化成不依赖个人的制度","steps":[{"invoke":"抓住机会窗口","action":"先判断当下是不是稍纵即逝的机会/真空，是则果断攫取主动、别在旧秩序里循序渐进"},{"invoke":"集中优势兵力于决定点","action":"别平摊，把主力集中砸向那个真正决定胜负的点，局部造绝对优势"},{"invoke":"速度与机动","action":"以远超对手的速度分进合击、抢在其集结前各个击破，让时间成为武器"},{"invoke":"士气与荣誉激励","action":"用荣誉、意义、本人在场经营队伍的精神力量——精神先于物质"},{"invoke":"制度法典化","action":"把胜利成果固化成不依赖你个人的制度/法典，让它比战功长久"}],"contrast":"与克劳塞维茨互为镜像（克氏正是研究拿破仑战争而写《战争论》）：拿破仑是''集中决定点 + 速度 + 决战''的实践巅峰，克劳塞维茨把它理论化、却也用''进攻顶点/防御强于进攻''预言了拿破仑征俄之败——拿破仑教你怎么打赢决战，克氏提醒你打赢后别冲过顶点（见克劳塞维茨卡）。与孙子不同：拿破仑追求决战速胜，孙子慎战、兵贵胜不贵久——征俄正撞上孙子的告诫（见孙子卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"napoleon-c1","note":"用户''资源有限、该平摊还是集中''时，以奥斯特里茨三皇会战类比：他故意示弱让出普拉岑高地诱联军分兵，待其中路削弱即集中全力突击该决定点、拦腰斩断，以局部绝对优势取全局（多源信史，个人指挥确证）"},{"source":"case","case_id":"napoleon-c3","note":"用户''我一路顺、要不要继续扩张/深入''时，以远征俄国惨败类比（反面镜子）：他低估补给线、焦土战略与寒冬、占莫斯科后仍迟迟不撤，约60万大军生还者寥寥——屡胜养成的''必能决战取胜''路径依赖，遇消耗与纵深、又无止损阀就是灾难（多源确证）"}]},"further_reading":[{"title":"安德鲁·罗伯茨《拿破仑大帝》(Napoleon the Great)","why":"现代权威传记，依其亲笔信件重估其军政决策，平衡圣赫勒拿自辩式回忆的失真","type":"biography"},{"title":"约米尼《战争艺术概论》","why":"同时代参谋对拿破仑战法（集中于决定点、内线机动）的系统归纳，看其战术原则","type":"解读"},{"title":"《拿破仑法典》(Code civil des Français, 1804)","why":"他历史性最硬的遗产，看''把胜利固化成不依赖个人的制度''如何流传至今","type":"original"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/napoleon.png","avatar_thumb":"/advisors/portraits/napoleon.png","domain":"战略","person_id":"P-napoleon","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '114b453d36d4ca64986717dd3aa0fe27ea0d7f0928c53896b235a6ad46872638', 68, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('newton', 'P-newton', '艾萨克·牛顿', 'science', '牛顿 · 公理化思维框架卡', '17—18世纪（1643—1727）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '公理化数学演绎 · 不杜撰假设', '/advisors/portraits/newton.png', '/advisors/portraits/newton.png', 5, 0, '{"schema_version":1,"card_id":"newton","name":"艾萨克·牛顿","title":"牛顿 · 公理化思维框架卡","era":"17—18世纪（1643—1727）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"公理化数学演绎","definition":"把一个领域压缩成几条精确定律/公理，再用数学把全部后果严格推导出来","source":"《自然哲学的数学原理》","source_tier":"primary","mechanism":"输入=一个领域杂乱无章、靠散点经验 → 处理=把它压缩成几条精确定律/公理、再用数学把全部后果严格推导出来 → 输出=少数公理+严格演绎统摄全局(《原理》建在三定律上)","trigger":"要把一个杂乱领域系统化时","modern_transfer":"把一个领域压缩成几条精确的定律/公理、再用严格的逻辑/数学把全部后果推导出来——少数公理+严格演绎，胜过大量散点经验(牛顿《原理》整部建在三条运动定律上)","architecture":{"type":"hierarchy","components":["一个领域杂乱靠散点经验","压缩成几条精确公理","用数学严格推导全部后果","少数公理统摄全局"]},"strategy_card_image":"kb-assets/newton/model-1.png"},{"name":"不杜撰假设","definition":"能精确描述一条可靠规律，就先用它；不为\"它到底是什么\"强行编一个原因","source":"《原理》总释「我不杜撰假设」","source_tier":"primary","mechanism":"输入=对没看清的东西、急于编一个''它到底是什么''的解释 → 处理=能精确描述一条可靠规律就先用它、不为本质强行编原因 → 输出=宁可说''我不知道它是什么''也把规律写准(我不杜撰假设)","trigger":"面对一个能描述规律、但本质不明的现象时","modern_transfer":"能精确描述一条可靠的规律、就先用它——别为''它到底是什么''强行编一个原因；宁可说''我还不知道它的本质''、也要把它的规律写准(牛顿''我不杜撰假设'')","architecture":{"type":"flow","components":["对没看清的东西急于编解释","能描述规律就先用","不为本质硬编原因","把规律写准"]},"strategy_card_image":"kb-assets/newton/model-2.png"},{"name":"统一普遍化","definition":"找那条同时管住日常与天上的同一规律——苹果落地与月球绕行服从同一引力","source":"《原理》万有引力定律","source_tier":"primary","mechanism":"输入=每个现象配一套单独的解释 → 处理=找那条同时管住日常与宏大的同一规律(苹果落地与月球绕行同一引力) → 输出=同一规律统摄多现象(威力之源)","trigger":"面对一组看似无关的现象时","modern_transfer":"找那条能同时解释平凡现象与宏大现象的''同一规律''——苹果落地与月球绕行服从同一引力；别给每个现象单独编一套解释(牛顿万有引力)","architecture":{"type":"hierarchy","components":["每个现象单独一套解释","找一条同一规律","同时管住日常与宏大","同一规律统摄多现象"]},"strategy_card_image":"kb-assets/newton/model-3.png"},{"name":"分析-综合","definition":"先把现象拆解为分力/成分（分析），再重新组合以预测（综合）","source":"《光学》疑问31论方法","source_tier":"primary","mechanism":"输入=面对复杂现象、一团乱 → 处理=先把现象拆解为分力/成分(分析)、再重新组合以预测(综合) → 输出=拆开算清再拼回验证(棱镜分解白光再合成)","trigger":"面对复杂现象、要理解并预测时","modern_transfer":"先把复杂现象拆解为可分别处理的分力/成分(分析)、再把它们重新组合起来预测与验证(综合)——拆开算清、再拼回去看(牛顿用棱镜把白光分解为光谱、再合成白光)","architecture":{"type":"loop","components":["面对复杂现象一团乱","拆解为分力成分分析","重新组合以预测综合","拆开算清再拼回验证"]},"strategy_card_image":"kb-assets/newton/model-4.png"},{"name":"持续专注钻透","definition":"靠\"把它不断放在心上\"死磕一个问题，直到它自己裂开","source":"其被问及如何发现引力时的回答（经转述）","source_tier":"secondary","mechanism":"输入=问题暂时无解、浅尝辄止就换 → 处理=靠''把它不断放在心上''死磕一个问题、直到它自己裂开 → 输出=持续专注钻透","trigger":"认准一个真问题、但它暂时无解时","modern_transfer":"认准一个真问题、就靠''把它不断放在心上''持续死磕、直到它自己裂开——别被它暂时无解吓退(牛顿自言发现引力靠''持续不断地想它'')","architecture":{"type":"flow","components":["问题暂时无解浅尝辄止","把它不断放在心上","死磕直到它裂开","持续专注钻透"]},"strategy_card_image":"kb-assets/newton/model-5.png"}],"decision_principles":["先定义清楚、立几条公理，再让结论从公理严格推出来","能描述清楚规律就先用，别为没看清的''本质''硬编一个解释","找那条能同时解释平凡现象和宏大现象的同一规律","把复杂现象拆成可分别处理的分量，再重新拼回去验证","认准一个真问题就持续死磕，别被它暂时无解吓退"],"inquiry_questions":["这件事的''公理''是什么？哪几条是你愿意当地基、不再退让的？","你是在描述一条可靠规律，还是在给一个你其实没看清的东西硬编原因？","有没有一条同一规律，能同时解释这个小现象和那个大现象？","能不能把它拆成几个可以分开算清的部分，再合起来看？","这个问题你是真盯住了，还是浅尝辄止就换了？"],"value_priorities":["可精确描述的规律 ＞ 听起来圆满的因果故事（宁可说\"我不知道引力是什么\"、也要把它的定律写准）","少数公理+严格演绎 ＞ 大量散点经验（整部《原理》就建在三条定律上）","同一规律统摄多现象 ＞ 每个现象一套解释（天上地下同一引力、是其威力之源）"],"blind_spots":["把强大的方法用到缺乏检验反馈的领域：数十年投入炼金术与圣经年代学，多无成果（其手稿/Keynes 评述，A/B）。","刻薄记仇、不容异见：与胡克、莱布尼茨、弗拉姆斯蒂德的争斗激烈，是糟糕的合作者（书信/传记，B）。","''绝对时空''被当作不证自明的前提，后被相对论推翻——其框架也有未察觉的隐藏假设（学术分析，B）。","极度保密、回避发表，加剧了优先权纷争（传记，B）。"],"applicable_domains":["创新研发","探索未知","认知偏误与理性决策"],"match_tags":["创新研发","探索未知","认知偏误与理性决策","第一性原理","系统分析","批判思辨","近代欧洲"],"linked_cases":["newton-c1","newton-c2","newton-c3","newton-c4"],"life_tags":[{"tag":"著数学原理","tier":"primary"},{"tag":"创微积分","tier":"secondary"},{"tag":"提万有引力","tier":"primary"},{"tag":"研光的色散","tier":"secondary"}],"voice_profile":{"notes":"严谨精确、重数学演绎；惜言、不轻下断语；专注执着；孤高难处"},"references":[{"ref_id":"newton-s1","title":"牛顿《自然哲学的数学原理》","locator":"定义与运动公理、万有引力、总释\"我不杜撰假设\"","source_tier":"primary","supports_models":["公理化数学演绎","不杜撰假设","统一普遍化"],"supports_cases":["newton-c1","newton-c2"],"note":"一手·原著"},{"ref_id":"newton-s2","title":"牛顿《光学》","locator":"棱镜分光、Query 31 论分析-综合","source_tier":"primary","supports_models":["分析-综合"],"supports_cases":["newton-c3"],"note":"一手·原著"},{"ref_id":"newton-s3","title":"同时代人转述/传记","locator":"「by thinking on it continually」；炼金术/争斗/保密等","source_tier":"secondary","supports_models":["持续专注钻透"],"supports_cases":["newton-c4"],"note":"二手·转述与传记（确切措辞待核）"}],"material_type":"rich","reasoning_skeleton":{"signature":"把一个领域压缩成几条精确公理、用严格演绎推出全部后果(公理化数学演绎)；能描述清规律就先用、别为没看清的本质硬编原因(不杜撰假设)；找那条同时管住日常与宏大的同一规律(统一普遍化)；把复杂现象拆成分量算清再拼回验证(分析-综合)；认准真问题就持续死磕直到它裂开(持续专注钻透)","steps":[{"invoke":"公理化数学演绎","action":"这件事的''公理''是什么？哪几条是你愿意当地基、不再退让的？"},{"invoke":"不杜撰假设","action":"你是在描述一条可靠规律，还是在给一个你其实没看清的东西硬编原因？"},{"invoke":"统一普遍化","action":"有没有一条同一规律，能同时解释这个小现象和那个大现象？"},{"invoke":"分析-综合","action":"能不能把它拆成几个可以分开算清的部分，再合起来看？"},{"invoke":"持续专注钻透","action":"这个问题你是真盯住了，还是浅尝辄止就换了？"}],"contrast":"与爱因斯坦不同(关键差异·同为物理学革命者)：**牛顿把''绝对时空''当作不证自明的前提、用公理化数学演绎统摄经典力学**；**爱因斯坦恰恰追问牛顿没察觉的隐藏假设(同时性/绝对时空)、以''追问不变量''与思想实验重构时空**——牛顿建公理体系、爱因斯坦质疑公理本身的隐藏前提(见爱因斯坦卡)；事实上爱因斯坦的相对论正推翻了牛顿的绝对时空。与达尔文不同：达尔文靠''变异-选择''的机制解释生命、且''反对意见优先''；牛顿靠''公理-演绎+统一普遍化''(见达尔文卡)。与费曼不同：费曼重直觉图像与亲手验证；牛顿重公理化的严格演绎(见费曼卡)。【射程/盲区】牛顿之道在''公理化、不杜撰假设、统一普遍化、分析-综合、持续钻透''极有力，但①把强大的方法用到缺乏检验反馈的领域(数十年投入炼金术与圣经年代学、多无成果)；②刻薄记仇、不容异见(与胡克/莱布尼茨/弗拉姆斯蒂德的激烈争斗)、是糟糕的合作者；③''绝对时空''被当作不证自明的前提、后被相对论推翻——其框架也有未察觉的隐藏假设；④极度保密、回避发表、加剧优先权纷争。适用创新研发/探索未知/认知偏误与理性决策；不适用人际关系/谈判/表达说服。"},"persona_anchor":{"primary":[{"source":"case","case_id":"newton-c1","note":"用户''面对一个杂乱、靠一堆零散经验在应付的领域''时，以牛顿《原理》类比：他把整个力学压缩成三条运动定律(公理)、再用数学把行星运动到潮汐的全部后果严格推导出来——少数精确公理+严格演绎，远胜大量散点经验（《原理》建在三定律上为其原著明载→确证）"},{"source":"case","case_id":"newton-c2","note":"用户''给每个现象单独编一套解释、看不到背后的统一''时，以牛顿万有引力类比：他看出苹果落地与月球绕行服从''同一条''引力定律——找那条能同时解释平凡与宏大现象的同一规律，是洞察力之源（万有引力为《原理》第3卷所载→确证）"}]},"further_reading":[{"title":"牛顿《自然哲学的数学原理》","why":"公理化数学演绎、统一普遍化(万有引力)、\"我不杜撰假设\"的一手出处（A）","type":"original"},{"title":"牛顿《光学》","why":"分析-综合方法（Query 31）与棱镜分光实验（A）","type":"original"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/newton.png","avatar_thumb":"/advisors/portraits/newton.png","domain":"科学","person_id":"P-newton","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '9d12d8ebb9348ea16aa6eaf3b2cbfd91da299b5675880aab8d7bec440dcb8a54', 69, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('ohno', 'P-ohno', '大野耐一', 'business', '大野耐一 · 丰田生产方式与精益思维框架卡', '现代（1912—1990）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '消除浪费 · 准时化', '/advisors/portraits/ohno.png', '/advisors/portraits/ohno.png', 5, 0, '{"schema_version":1,"card_id":"ohno","name":"大野耐一","title":"大野耐一 · 丰田生产方式与精益思维框架卡","era":"现代（1912—1990）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"消除浪费","definition":"用\"这一步有没有创造价值\"重新审视每个环节，识别并消除一切不创造价值的浪费（muda）","source":"大野耐一《丰田生产方式》","source_tier":"primary","mechanism":"输入=默认很多环节是必要的 → 处理=用''是否创造价值''审视每个环节、识别并消除七大浪费 → 输出=只留创造价值的活动(消除muda)","trigger":"要提升效率/精简流程时","modern_transfer":"用''这一步到底有没有创造价值''去重新审视每一个环节——识别并消除一切不创造价值的浪费(过量生产、等待、搬运、库存、多余动作、过度加工、缺陷);只留下真正创造价值的活动(大野耐一的''消除浪费muda'')","architecture":{"type":"flow","components":["别默认环节都必要","用是否创造价值审视每步","识别并消除七大浪费","只留创造价值的活动"]},"strategy_card_image":"kb-assets/ohno/model-1.png"},{"name":"准时化","definition":"由下游的实际需求\"拉动\"上游，只在需要的时候、生产需要的量，用拉动取代推动（JIT）","source":"大野耐一《丰田生产方式》","source_tier":"primary","mechanism":"输入=按预测大批量生产、囤大量库存 → 处理=由下游的实际需求拉动上游、只在需要时生产需要的量 → 输出=用拉动消除库存与过量生产(JIT)","trigger":"安排生产/供应/工作流时","modern_transfer":"别按预测大批量生产、囤一堆库存——由下游的实际需求''拉动''上游、只在需要的时候、生产需要的量、用拉动取代推动(大野耐一的''准时化Just-in-Time'')","architecture":{"type":"flow","components":["别按预测大批量囤库存","由下游实际需求拉动上游","只在需要时生产需要的量","用拉动消除库存与过量"]},"strategy_card_image":"kb-assets/ohno/model-2.png"},{"name":"自働化","definition":"让流程/机器一发现异常就自动停下，把问题当场暴露解决，绝不让缺陷流到下游（jidoka）","source":"大野耐一《丰田生产方式》","source_tier":"primary","mechanism":"输入=出了问题继续跑、让缺陷流到下游 → 处理=让流程一发现异常就自动停下、暴露问题、当场解决 → 输出=问题不被掩盖、就地根治(自働化)","trigger":"流程中出现异常/缺陷时","modern_transfer":"让流程/机器一发现异常就自动停下、把问题当场暴露出来解决——绝不让缺陷流到下游(大野耐一发扬的''自働化jidoka''、带人字旁的''働''强调人的智慧);问题暴露比掩盖好","architecture":{"type":"flow","components":["别让问题继续跑缺陷流下游","一发现异常就自动停下","暴露问题当场解决","问题就地根治"]},"strategy_card_image":"kb-assets/ohno/model-3.png"},{"name":"现地现物","definition":"别坐办公室靠报告/想象做判断，亲自到现场（现地）、看真实的实物（现物）、基于事实判断","source":"丰田生产方式\"现地现物\"理念","source_tier":"secondary","mechanism":"输入=坐在办公室靠报告/想象做判断 → 处理=亲自到现场(现地)、看真实的实物(现物)、基于事实判断 → 输出=判断扎根真实现场","trigger":"要判断一个现场问题时","modern_transfer":"别坐在办公室靠报告和想象做判断——亲自到现场(现地)、看真实的实物与实况(现物)、基于亲眼所见的事实做判断(丰田的''现地现物genchi genbutsu'')","architecture":{"type":"flow","components":["别靠报告想象判断","亲自到现场现地","看真实的实物现物","基于事实判断"]},"strategy_card_image":"kb-assets/ohno/model-4.png"},{"name":"五个为什么","definition":"遇到问题连问五次\"为什么\"，一层层刨到根本原因，再根治那个根因，而非只治表面症状","source":"大野耐一\"5个为什么\"","source_tier":"primary","mechanism":"输入=只解决表面症状、问题反复 → 处理=连问五次''为什么''、一层层刨到根本原因、根治它 → 输出=根治根因而非表面(5 whys)","trigger":"遇到一个反复出现的问题时","modern_transfer":"遇到问题别只治表面症状——连问五次''为什么''、一层层往下刨到根本原因、再根治那个根因(大野耐一的''5个为什么'');问一次是症状、问五次见根因","architecture":{"type":"hierarchy","components":["别只治表面症状","连问五次为什么","一层层刨到根本原因","根治根因而非表面"]},"strategy_card_image":"kb-assets/ohno/model-5.png"}],"decision_principles":["用''有没有创造价值''审视每步，识别并消除一切浪费","由下游需求拉动上游，只在需要时生产需要的量（用拉动取代推动）","一发现异常就停下、暴露问题当场解决，不让缺陷流到下游","亲自到现场看真实的实物，基于事实而非报告/想象判断","连问五次''为什么''，刨到根本原因再根治"],"inquiry_questions":["这个流程里哪些步骤其实没创造价值、是可以消除的浪费？","你是按预测大批量囤库存，还是由实际需求拉动、只在需要时做需要的量？","出了异常你是让它继续跑，还是立刻停下暴露问题当场解决？","你是坐办公室靠报告判断，还是亲自到现场看真实的实物？","这个问题你是治了表面，还是连问五次为什么刨到了根本原因？"],"value_priorities":["只留创造价值的活动 ＞ 默认环节都必要（消除七大浪费（muda））","拉动式准时生产 ＞ 推动式大批量囤库存（只在需要时做需要的量）","暴露并根治问题 ＞ 让缺陷流到下游（自働化、一异常就停）"],"blind_spots":["JIT的''零库存''使供应链对中断极其脆弱（疫情/灾害一断供就停线），须权衡韧性（史实，B）。","精益体系诞生于大规模重复制造，对小批量、高度不确定或创意型工作未必直接适用（原理推断，B）。","极致消除浪费若用力过猛，会把必要的冗余与缓冲也砍掉、反而脆弱（原理推断，B）。","TPS的成功依赖长期的组织文化与全员参与，不是照搬几个工具就能成（原理推断，B）。"],"applicable_domains":["组织管理","资源调度","创业","长期规划"],"match_tags":["组织管理","资源调度","创业","长期规划","系统分析","极简主义","务实渐进","现当代东亚"],"linked_cases":["ohno-c1","ohno-c2","ohno-c3","ohno-c4"],"life_tags":[{"tag":"创丰田生产方式","tier":"primary"},{"tag":"设计看板法","tier":"secondary"},{"tag":"提七大浪费","tier":"primary"},{"tag":"创准时化生产","tier":"primary"}],"voice_profile":{"notes":"务实严谨、就事论事；痴迷消除浪费；重现场与事实；刨根问底"},"references":[{"ref_id":"ohno-s1","title":"大野耐一《丰田生产方式》","locator":"七大浪费、准时化、自働化、5个为什么","source_tier":"primary","supports_models":["消除浪费","准时化","自働化","五个为什么"],"supports_cases":["ohno-c1","ohno-c2","ohno-c3","ohno-c4"],"note":"一手·原著"},{"ref_id":"ohno-s2","title":"精益生产（Lean）相关研究","locator":"现地现物、TPS的全球应用","source_tier":"secondary","supports_models":["现地现物"],"note":"二手·研究（理念另见其一手论述）"}],"material_type":"rich","reasoning_skeleton":{"signature":"用''是否创造价值''审视每步、识别并消除一切浪费(消除浪费muda)；由下游需求拉动上游、只在需要时生产需要的量(准时化JIT)；一发现异常就停下暴露问题当场解决、不让缺陷流走(自働化jidoka)；亲自到现场看真实实物基于事实判断(现地现物)；连问五次为什么刨到根本原因(五个为什么)","steps":[{"invoke":"消除浪费","action":"这个流程里哪些步骤其实没创造价值、是可以消除的浪费？"},{"invoke":"准时化","action":"你是按预测大批量囤库存、还是由实际需求拉动、只在需要时做需要的量？"},{"invoke":"自働化","action":"出了异常你是让它继续跑、还是立刻停下暴露问题当场解决？"},{"invoke":"现地现物","action":"你是坐办公室靠报告判断、还是亲自到现场看真实的实物？"},{"invoke":"五个为什么","action":"这个问题你是治了表面、还是连问五次为什么刨到了根本原因？"}],"contrast":"与福特不同(关键差异·同为制造业大师·但恰相反)：**福特是''流水线、大批量、推动式生产''——靠规模化的同一动作把单位成本压到最低**；**大野耐一的丰田生产方式(TPS)恰恰是对福特大批量模式的超越——''拉动式、消除浪费、小批量柔性、暴露问题''**——福特用大批量推动降本、大野用拉动与消除浪费实现柔性与品质(见福特卡)。与王永庆不同：王永庆是''追根究底+成本极致''的精细成本管理；大野耐一是''消除浪费+JIT+自働化''的一整套精益生产体系(见王永庆卡)。【射程/盲区】大野之道(精益/TPS)在''消除浪费、准时化、自働化、现地现物、5个为什么''极有力，但①JIT的''零库存''使供应链对中断极其脆弱(疫情/灾害一断供就停线、须权衡韧性);②精益体系诞生于大规模重复制造、对小批量、高度不确定或创意型工作未必直接适用;③极致消除浪费若用力过猛、会把必要的冗余与缓冲也砍掉、反而脆弱;④TPS的成功也依赖长期的组织文化与全员参与、不是照搬几个工具就能成。适用组织管理/资源调度/创业/长期规划;不适用投资/谈判。"},"persona_anchor":{"primary":[{"source":"case","case_id":"ohno-c1","note":"用户''流程冗长、效率低、却觉得每个环节都''必要''''时，以大野耐一消除浪费类比：他用''这一步到底有没有创造价值''去审视每个环节、识别并消除七大浪费(过量生产、等待、搬运、库存、多余动作、过度加工、缺陷)、只留下真正创造价值的活动——很多''必要''其实是浪费（消除浪费muda为大野《丰田生产方式》核心→确证）"},{"source":"case","case_id":"ohno-c4","note":"用户''一个问题反复出现、每次都只治了表面''时，以大野耐一''5个为什么''类比：遇到问题连问五次''为什么''、一层层往下刨到根本原因、再去根治那个根因——问一次只是症状、问五次才见根因（5个为什么为大野《丰田生产方式》所述→确证）"}]},"further_reading":[{"title":"大野耐一《丰田生产方式》(Toyota Production System)","why":"消除浪费、准时化、自働化、5个为什么的一手论述（A）","type":"original"},{"title":"精益生产（Lean）相关研究","why":"TPS被提炼为\"精益生产\"在全球各行业的应用（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/ohno.png","avatar_thumb":"/advisors/portraits/ohno.png","domain":"商业","person_id":"P-ohno","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '011638ba51af397f0693e5c7eaa4e9b1c40ff5730c20f0d743cb9c9e84560c18', 70, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('orwell', 'P-orwell', '乔治·奥威尔', 'writing', '奥威尔 · 清晰语言与政治写作思维框架卡', '20世纪（1903—1950）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '清晰语言对抗操纵 · 写作六规则', '/advisors/portraits/orwell.png', '/advisors/portraits/orwell.png', 5, 0, '{"schema_version":1,"card_id":"orwell","name":"乔治·奥威尔","title":"奥威尔 · 清晰语言与政治写作思维框架卡","era":"20世纪（1903—1950）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"清晰语言对抗操纵","definition":"模糊、抽象、套话式的语言是欺骗与操纵的工具——用具体、清晰、直白的语言把话说清，是抵抗被操纵、也是不自欺的前提","source":"奥威尔《政治与英语》","source_tier":"primary","mechanism":"输入=模糊/抽象/套话的语言被用来欺骗与操纵 → 处理=用具体、清晰、直白的语言把话说清 → 输出=抵抗被操纵、也不自欺","trigger":"面对模糊套话、或要把话说清时","modern_transfer":"模糊、抽象、套话式的语言是欺骗与操纵的工具——用具体、清晰、直白的语言把话说清、是抵抗被操纵、也是不自欺的前提(尤其警惕用大词掩盖具体的事)","architecture":{"type":"flow","components":["识别模糊抽象套话","换成具体清晰直白","把话说清","抵抗操纵不自欺"]},"strategy_card_image":"kb-assets/orwell/model-1.png"},{"name":"写作六规则","definition":"写/说之前过一遍\"减法\"：能删的词就删、能用短词不用长词、能用具体不用抽象、避开陈词滥调——把表达削到最清晰有力","source":"奥威尔《政治与英语》（六条写作规则）","source_tier":"primary","mechanism":"输入=表达冗长、抽象、套话、不清 → 处理=过一遍减法(能删就删/短词代长词/具体代抽象/避陈词) → 输出=表达削到最清晰有力","trigger":"写/说之前、想表达清晰时","modern_transfer":"写/说之前过一遍''减法''：能删的词就删、能用短词不用长词、能用具体不用抽象、避开陈词滥调——把表达削到最清晰有力(奥威尔的写作规则)","architecture":{"type":"flow","components":["过一遍减法","能删就删短词代长词","具体代抽象避陈词","削到最清晰有力"]},"strategy_card_image":"kb-assets/orwell/model-2.png"},{"name":"诚实直面不适的真相","definition":"不回避、不粉饰令人不适的真相——尤其是对自己所属的阵营也保持诚实，看见什么说什么","source":"奥威尔的写作伦理（批判斯大林主义 / 《我为何写作》）","source_tier":"primary","mechanism":"输入=回避/粉饰令人不适的真相、尤其对自己阵营 → 处理=不回避不粉饰、对自己所属阵营也保持诚实、看见什么说什么 → 输出=智识诚实(哪怕得罪自己人)","trigger":"真相令人不适、尤其涉及自己阵营时","modern_transfer":"不回避、不粉饰令人不适的真相——尤其是对自己所属的阵营也保持诚实、看见什么说什么(奥威尔作为社会主义者却公开批判斯大林主义)；智识诚实常意味着得罪自己人","architecture":{"type":"flow","components":["真相令人不适","不回避不粉饰","对自己阵营也诚实","看见什么说什么"]},"strategy_card_image":"kb-assets/orwell/model-3.png"},{"name":"具象化抽象","definition":"把抽象的概念或危险、用一个具体可感的场景或形象讲出来——让人\"看见\"而非只是\"听说\"","source":"奥威尔《一九八四》《动物农场》","source_tier":"primary","mechanism":"输入=抽象的概念/危险讲不清、没人真当回事 → 处理=用一个具体可感的场景或形象把它讲出来 → 输出=让人''看见''而非只''听说''(老大哥/动物农场)","trigger":"要把抽象概念/危险讲得可感时","modern_transfer":"把抽象的概念或危险、用一个具体可感的场景或形象讲出来(老大哥/动物农场)——让人''看见''而非只是''听说''，抽象的警告才真正有力","architecture":{"type":"flow","components":["抽象概念讲不清","找一个具体可感的场景或形象","把抽象具象化","让人看见而非听说"]},"strategy_card_image":"kb-assets/orwell/model-4.png"},{"name":"警惕语言腐败","definition":"警惕语言的腐败——含糊、委婉、口号化的语言会反过来腐蚀思想本身；守护精确的语言就是守护清醒的思想","source":"奥威尔《政治与英语》《一九八四》（新话）","source_tier":"primary","mechanism":"输入=以为语言只是表达工具、含糊点没关系 → 处理=警惕语言的腐败会反过来腐蚀思想本身(新话) → 输出=守护精确语言=守护清醒思想","trigger":"语言被含糊化/口号化/委婉化时","modern_transfer":"警惕语言的腐败——含糊、委婉、口号化的语言不只是表达问题、它会反过来腐蚀思想本身(新话:词没了、相关的思想也想不出来了)；守护精确的语言就是守护清醒的思想","architecture":{"type":"hierarchy","components":["别以为语言只是工具","看到语言腐败腐蚀思想","守护精确的语言","守护清醒的思想"]},"strategy_card_image":"kb-assets/orwell/model-5.png"}],"decision_principles":["模糊套话是操纵工具——用具体清晰的语言把话说清，抵抗操纵也不自欺","写说前过一遍减法：能删就删、短词代长词、具体代抽象、避陈词","不回避不粉饰不适的真相，尤其对自己阵营也诚实","把抽象的危险用具体场景/形象讲出，让人''看见''","警惕语言腐败会腐蚀思想——守护精确语言即守护清醒思想"],"inquiry_questions":["你(或对方)是在用具体清晰的话说事，还是用模糊的大词/套话掩盖具体真相？","这段表达能不能再做减法？哪些词能删、哪些长词能换短、哪些抽象能换具体？","有没有一个令人不适、尤其对你自己阵营不利的真相，你在回避或粉饰？","这个抽象的概念/危险，能不能用一个具体可感的场景或形象让人''看见''？","这里的含糊/委婉/口号化语言，是不是在悄悄腐蚀对问题的清醒思考？"],"value_priorities":["具体清晰 ＞ 模糊抽象的大词（清晰语言抵抗操纵、也防自欺）","智识诚实 ＞ 阵营的方便（对自己人也诚实、看见什么说什么）","精确的语言 ＞ 含糊口号化的便利（语言腐败会腐蚀思想本身）"],"blind_spots":["其''清晰语言''标准主要针对说理性/政治性文字，对诗歌、实验文学、某些修辞性表达未必适用（原理推断，B）。","奥威尔本人也承认自己违反过这些规则——规则是理想与提醒，而非铁律（其自陈，B）。","〔慎〕奥威尔晚年曾向英国一政府机构提交一份他认为亲苏的人物名单（the ''list''），此举与其反极权立场的张力是其争议点（史实，B，客观标注）。","''清晰=真实''有其限度——清晰的语言同样可以被用于高效的操纵与煽动（原理推断，B）。"],"applicable_domains":["表达说服","价值与伦理","认知偏误与理性决策"],"match_tags":["表达说服","价值与伦理","认知偏误与理性决策","批判思辨","极简主义","第一性原理","现当代欧洲"],"linked_cases":["orwell-c1","orwell-c2","orwell-c3"],"life_tags":[{"tag":"著一九八四","tier":"primary"},{"tag":"著动物农场","tier":"primary"},{"tag":"参西班牙内战","tier":"secondary"},{"tag":"著缅甸岁月","tier":"primary"}],"voice_profile":{"notes":"清晰直白、反对浮夸；冷峻诚实、不留情面；关切政治与真相；以具体反对抽象"},"references":[{"ref_id":"orwell-s1","title":"奥威尔《政治与英语》","locator":"政治语言批判、清晰语言、六条写作规则","source_tier":"primary","supports_models":["清晰语言对抗操纵","写作六规则","警惕语言腐败"],"supports_cases":["orwell-c1"],"note":"一手·随笔名篇"},{"ref_id":"orwell-s2","title":"奥威尔《一九八四》《动物农场》","locator":"老大哥/新话/双重思想；动物农场寓言","source_tier":"primary","supports_models":["具象化抽象","警惕语言腐败"],"supports_cases":["orwell-c2","orwell-c3"],"note":"一手·代表作"},{"ref_id":"orwell-s3","title":"奥威尔《我为何写作》及传记","locator":"写作伦理、批判斯大林主义、晚年争议","source_tier":"primary","supports_models":["诚实直面不适的真相"],"supports_cases":["orwell-c3"],"note":"一手随笔+二手传记"}],"material_type":"rich","reasoning_skeleton":{"signature":"模糊套话是操纵工具、用具体清晰的语言把话说清以抵抗操纵(清晰语言对抗操纵)；写说前过一遍减法、能删就删短词代长词具体代抽象(写作六规则)；不回避不粉饰不适的真相、对自己阵营也诚实(诚实直面不适的真相)；把抽象的危险用具体场景形象讲出让人看见(具象化抽象)；警惕语言腐败会腐蚀思想、守护精确语言即守护清醒思想(警惕语言腐败)","steps":[{"invoke":"清晰语言对抗操纵","action":"你(或对方)是在用具体清晰的话说事，还是在用模糊的大词/套话掩盖具体的真相？"},{"invoke":"写作六规则","action":"这段表达能不能再做减法？哪些词能删、哪些长词能换短、哪些抽象能换具体？"},{"invoke":"诚实直面不适的真相","action":"有没有一个令人不适、尤其对你自己阵营不利的真相，你在回避或粉饰？"},{"invoke":"具象化抽象","action":"这个抽象的概念/危险，能不能用一个具体可感的场景或形象让人''看见''？"},{"invoke":"警惕语言腐败","action":"这里的含糊/委婉/口号化语言，是不是在悄悄腐蚀对问题的清醒思考？"}],"contrast":"与马克吐温不同(关键差异·同为创作传播)：**马克吐温以''讽刺/幽默/通俗化/共情叙事''打动大众**；**奥威尔以''清晰语言对抗操纵/政治写作/智识诚实''抵抗欺骗**——吐温是幽默共情的大众叙事、奥威尔是清晰诚实的政治抵抗(见马克吐温卡)。与狄更斯不同：狄更斯以''社会叙事+连载悬念+人物群像''唤起对社会问题的共情；奥威尔更聚焦语言清晰与极权批判(见狄更斯卡)。【射程/盲区·〔慎〕】奥威尔之道在''把话说清、抵抗语言操纵、诚实面对真相、具象化警示''极有力，但①其''清晰语言''标准主要针对说理/政治文字、对诗歌/实验文学未必适用；②他本人也承认违反过这些规则、规则是理想而非铁律；③〔慎〕其晚年曾向政府机构提交一份亲苏人物名单、与其反极权立场的张力是其争议点；④''清晰=真实''有限度、清晰的语言也可被用于有效操纵。适用表达说服/价值与伦理/认知偏误与理性决策；不适用投资/危机应对。"},"persona_anchor":{"primary":[{"source":"case","case_id":"orwell-c1","note":"用户''被一堆漂亮的大词/套话绕晕、或想把一件事说清却越说越虚''时，以奥威尔《政治与英语》类比：他剖析政治语言如何用含糊抽象的大词掩盖具体的暴行、并提出''能删就删、短词代长词、具体代抽象、避陈词''的减法规则——把表达削到最清晰，是抵抗操纵也是不自欺（《政治与英语》为奥威尔名篇→确证）"},{"source":"case","case_id":"orwell-c2","note":"用户''想把一个抽象的危险/趋势讲得让人真正警醒''时，以《一九八四》类比：奥威尔用老大哥、新话、双重思想等具体形象、把''极权''这一抽象危险变成可感的故事——让人''看见''而非只''听说''（《一九八四》为奥威尔代表作→确证）"}]},"further_reading":[{"title":"奥威尔《政治与英语》《我为何写作》","why":"清晰语言/写作规则/写作伦理的一手出处（随笔）","type":"original"},{"title":"奥威尔《一九八四》《动物农场》","why":"以具象故事呈现极权与语言腐败（新话）的代表作","type":"original"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/orwell.png","avatar_thumb":"/advisors/portraits/orwell.png","domain":"创作","person_id":"P-orwell","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '042b2a756df9e3b8252b53f007791f3d5a9b0f1ab592d68e7d18d0389efffefe', 71, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('pericles', 'P-pericles', '伯里克利', 'governance', '伯里克利 · 民主治理与文化软实力思维框架卡', '古希腊（约前495—前429）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '公民参与的民主治理 · 任人唯能不唯出身', '/advisors/portraits/pericles.png', '/advisors/portraits/pericles.png', 5, 0, '{"schema_version":1,"card_id":"pericles","name":"伯里克利","title":"伯里克利 · 民主治理与文化软实力思维框架卡","era":"古希腊（约前495—前429）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"公民参与的民主治理","definition":"让相关的人广泛参与决策，以公开的辩论和多数的同意来推进——参与本身激发归属感与责任感、决策也更有合法性","source":"伯里克利推动的雅典民主","source_tier":"secondary","mechanism":"输入=少数人闭门决策、众人无归属 → 处理=让相关的人广泛参与、以公开辩论和多数同意推进 → 输出=参与激发归属与合法性(公民参与)","trigger":"要做一个涉及众人的决策、考虑如何凝聚时","modern_transfer":"让相关的人广泛参与决策、以公开的辩论和多数的同意来推进——参与本身激发归属感与责任感、决策也更有合法性(伯里克利的雅典民主)〔但也有多数暴政与民粹之险、见盲区〕","architecture":{"type":"flow","components":["别让少数人闭门决策众人无归属","让相关的人广泛参与","以公开辩论和多数同意推进","参与激发归属与合法性"]},"strategy_card_image":"kb-assets/pericles/model-1.png"},{"name":"任人唯能不唯出身","definition":"用人、给机会，看的是才能与贡献，而非出身、门第、背景——让有能力的普通人也能上升","source":"伯里克利时代的雅典用人","source_tier":"secondary","mechanism":"输入=用人看出身门第背景 → 处理=看才能与贡献、给有能力的普通人机会 → 输出=能者上升(任人唯能)","trigger":"用人/给机会时","modern_transfer":"用人、给机会、看的是才能与贡献、而非出身、门第、背景——让有能力的普通人也能上升(伯里克利时代的雅典''不因贫穷或出身埋没人才'')","architecture":{"type":"flow","components":["别用人看出身门第背景","看才能与贡献","给有能力的普通人机会","能者上升"]},"strategy_card_image":"kb-assets/pericles/model-2.png"},{"name":"投资文化软实力","definition":"别只投硬实力——大力投资文化、公共空间、艺术与精神象征，把组织的声望、认同与凝聚力做出来","source":"伯里克利大建帕特农神庙","source_tier":"secondary","mechanism":"输入=只投硬实力、忽视精神象征 → 处理=大力投资文化、公共空间、艺术与精神象征 → 输出=声望认同凝聚力(文化软实力)","trigger":"要提升组织的声望与凝聚力时","modern_transfer":"别只投硬实力——大力投资文化、公共空间、艺术与精神象征(如标志性建筑)、把组织的声望、认同与凝聚力做出来(伯里克利大建帕特农神庙、使雅典成为文化中心)","architecture":{"type":"flow","components":["别只投硬实力忽视精神象征","大力投资文化公共空间与艺术","建精神象征与标志性建筑","做出声望认同与凝聚力"]},"strategy_card_image":"kb-assets/pericles/model-3.png"},{"name":"扬长避短的战略","definition":"基于自己真正的优势（而非对手的优势）来制定战略——发挥所长、回避所短，不被对手拖入你不利的战场","source":"伯里克利的伯罗奔尼撒战争战略","source_tier":"secondary","mechanism":"输入=被对手拖入你不利的战场 → 处理=基于自己真正的优势制定战略、发挥所长回避所短 → 输出=不被拖入不利战场(扬长避短)","trigger":"制定战略、面对强项不同的对手时","modern_transfer":"基于自己真正的优势(而非对手的优势)来制定战略——发挥所长、回避所短、不被对手拖入你不利的战场(伯里克利凭雅典海军优势、坚守城防、避免与斯巴达陆军决战)〔但其战略也因大瘟疫等未竟全功、见盲区〕","architecture":{"type":"flow","components":["别被对手拖入你不利的战场","基于自己真正的优势制定战略","发挥所长回避所短","不被拖入不利战场"]},"strategy_card_image":"kb-assets/pericles/model-4.png"},{"name":"以理性演说凝聚共识","definition":"用条理清晰、有远见、诉诸共同价值与荣誉的演说，去凝聚共识、提振人心","source":"伯里克利\"国殇演说\"","source_tier":"primary","mechanism":"输入=靠煽动或命令 → 处理=用条理、远见、诉诸共同价值与荣誉的演说凝聚共识 → 输出=共识与人心(理性演说)","trigger":"危机/重大时刻要凝聚共识、提振人心时","modern_transfer":"用条理清晰、有远见、诉诸共同价值与荣誉的演说去凝聚共识、提振人心(伯里克利著名的''国殇演说''颂扬雅典的民主与精神、激励城邦)","architecture":{"type":"flow","components":["别靠煽动或命令","用条理清晰有远见的演说","诉诸共同价值与荣誉","凝聚共识提振人心"]},"strategy_card_image":"kb-assets/pericles/model-5.png"}],"decision_principles":["让相关的人广泛参与、以公开辩论和多数同意推进（但防多数暴政、民粹）","用人看才能与贡献，而非出身、门第、背景","别只投硬实力，也投文化、象征与声望这些软实力","基于自己的优势制定战略，不被对手拖入不利的战场","用诉诸共同价值与荣誉的理性演说凝聚共识"],"inquiry_questions":["这个决策，你是少数人闭门定、还是让相关的人广泛参与、以公开辩论与多数同意推进？","你用人、给机会，看的是才能与贡献、还是出身门第背景？","你是只投硬实力、还是也大力投资文化、象征与声望这些软实力？","你的战略是基于自己的优势、还是被对手拖进了你不利的战场？","你是靠煽动或命令、还是用诉诸共同价值与荣誉的理性演说凝聚共识？"],"value_priorities":["广泛参与的合法性 ＞ 少数人闭门决策（雅典直接民主（但有多数暴政之险））","才能与贡献 ＞ 出身门第背景（不因贫穷或出身埋没人才）","文化软实力 ＞ 只投硬实力（帕特农神庙、文化中心）"],"blind_spots":["雅典的''民主''限于成年男性公民、奴隶/妇女/外邦人无政治权利——其''民主''有重大的历史局限（史，B，客观标注）。","直接民主也有多数暴政、民粹、易被煽动者操纵之险（伯里克利之后的雅典即如此）（史/政治学，B）。","其守城避战的战略遇上大瘟疫（伯里克利本人也死于瘟疫）而受重创、未竟全功（史，B）。","大兴土木、文化投资也伴随挪用提洛同盟金库的争议（史，B，客观标注）。"],"applicable_domains":["领导力","危机应对","表达说服"],"match_tags":["领导力","危机应对","表达说服","攻心共识","系统分析","制度法治思维","古代欧洲"],"linked_cases":["pericles-c1","pericles-c2","pericles-c3","pericles-c4"],"life_tags":[{"tag":"主政黄金时代","tier":"secondary"},{"tag":"营建帕特农","tier":"secondary"},{"tag":"倡雅典民主","tier":"secondary"},{"tag":"致阵亡将士辞","tier":"secondary"}],"voice_profile":{"notes":"睿智从容、富远见；重民主与公民精神；重文化与荣誉；善于演说"},"references":[{"ref_id":"pericles-s1","title":"修昔底德《伯罗奔尼撒战争史》","locator":"国殇演说、战略、雅典民主","source_tier":"primary","supports_models":["以理性演说凝聚共识","扬长避短的战略","公民参与的民主治理","任人唯能不唯出身"],"supports_cases":["pericles-c3","pericles-c4"],"note":"一手记述（修昔底德有润色）"},{"ref_id":"pericles-s2","title":"古希腊史","locator":"雅典民主、帕特农建设、文化黄金时代","source_tier":"secondary","supports_models":["公民参与的民主治理","投资文化软实力","任人唯能不唯出身"],"supports_cases":["pericles-c1","pericles-c2"],"note":"二手·史"}],"material_type":"rich","reasoning_skeleton":{"signature":"让相关的人广泛参与以公开辩论与多数同意推进(公民参与的民主治理)；用人看才能与贡献而非出身门第(任人唯能不唯出身)；大力投资文化公共空间与精神象征做声望凝聚力(投资文化软实力)；基于自己的优势制定战略避免被拖入不利战场(扬长避短的战略)；用诉诸共同价值与荣誉的理性演说凝聚共识(以理性演说凝聚共识)","steps":[{"invoke":"公民参与的民主治理","action":"这个决策，你是少数人闭门定、还是让相关的人广泛参与、以公开辩论与多数同意推进？"},{"invoke":"任人唯能不唯出身","action":"你用人、给机会，看的是才能与贡献、还是出身门第背景？"},{"invoke":"投资文化软实力","action":"你是只投硬实力、还是也大力投资文化、象征与声望这些软实力？"},{"invoke":"扬长避短的战略","action":"你的战略是基于自己的优势、还是被对手拖进了你不利的战场？"},{"invoke":"以理性演说凝聚共识","action":"你是靠煽动或命令、还是用诉诸共同价值与荣誉的理性演说凝聚共识？"}],"contrast":"与华盛顿不同(关键差异·同涉民主/制度)：**华盛顿是''主动放弃权力、拒绝称王、确立和平交接、让制度先于个人''(以放权立制)**；**伯里克利是''推动公民广泛参与的直接民主、投资文化软实力、以演说凝聚''(以参与和文化立国)**——华盛顿重''限制权力的制度交接''、伯里克利重''公民参与的民主活力与文化''(见华盛顿卡)。与李世民不同：李世民是''君主纳谏的贤明君主制'';伯里克利是''公民直接参与的民主制''——一个是开明的君主纳谏、一个是公民的直接参与(见李世民卡)。【射程/盲区·历史诚实·重点】伯里克利之道在''公民参与、任人唯能、文化软实力、扬长避短、理性演说''极有力，但①雅典的''民主''限于成年男性公民、奴隶/妇女/外邦人无政治权利、有重大历史局限;②直接民主也有多数暴政、民粹、易被煽动操纵之险;③其守城避战战略遇大瘟疫(他本人也死于瘟疫)而受重创、未竟全功;④大兴土木、文化投资也伴随挪用提洛同盟金库的争议。适用领导力/危机应对/表达说服;不适用投资/认知偏误与理性决策。"},"persona_anchor":{"primary":[{"source":"case","case_id":"pericles-c2","note":"用户''想提升组织的声望、认同与凝聚力、却只盯着硬指标(营收/规模)''时，以伯里克利投资文化软实力类比：他在雅典大规模兴建帕特农神庙等公共建筑、大力投资文化与艺术、使雅典成为希腊的文化中心、极大提升了城邦的声望与凝聚力——别只投硬实力、也要投文化、象征与精神(帕特农建设为史实→确证)〔惟其文化投资伴随挪用同盟金库的争议、客观标注〕"},{"source":"case","case_id":"pericles-c3","note":"用户''在重大/危难时刻、要凝聚人心、提振士气''时，以伯里克利国殇演说类比：他在阵亡将士葬礼上发表著名演说、以条理清晰、诉诸雅典共同的民主精神与荣誉去激励城邦——用诉诸共同价值与荣誉的理性演说凝聚共识、而非煽动或命令(国殇演说载于修昔底德→确证)"}]},"further_reading":[{"title":"修昔底德《伯罗奔尼撒战争史》","why":"伯里克利的演说、战略与雅典民主的一手记述（A/B）","type":"史/原典"},{"title":"古希腊史","why":"伯里克利时代雅典民主与文化黄金时代的史述（B）","type":"史"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/pericles.png","avatar_thumb":"/advisors/portraits/pericles.png","domain":"治理","person_id":"P-pericles","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'e7df782ee06992acffe65fb5e38fb63eda8648277b9c37721b632e62899c4fa0', 72, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('plato', 'P-plato', '柏拉图', 'philosophy', '柏拉图 · 理念论与辩证法思维框架卡', '古希腊（约前428—前348）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '理念论 · 洞穴喻', '/advisors/portraits/plato.png', '/advisors/portraits/plato.png', 5, 0, '{"schema_version":1,"card_id":"plato","name":"柏拉图","title":"柏拉图 · 理念论与辩证法思维框架卡","era":"古希腊（约前428—前348）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"理念论","definition":"透过纷繁变动的现象，去追问那个更本质、更稳定、永恒的\"原型/本质\"（理念Form）","source":"柏拉图《理想国》《斐多》","source_tier":"primary","mechanism":"输入=停在变动的具体表象 → 处理=透过现象追问那个更本质、永恒的''原型/本质''(理念) → 输出=把握背后的本质(理念论)","trigger":"想把握一个事物的本质时","modern_transfer":"透过纷繁变动的现象、去追问那个更本质、更稳定的''原型/本质''(理念Form)——别停在具体表象、把握背后那个''什么使它成为它''的本质(柏拉图理念论)","architecture":{"type":"hierarchy","components":["别停在变动的具体表象","透过现象追问","那个更本质永恒的原型理念","把握背后的本质"]},"strategy_card_image":"kb-assets/plato/model-1.png"},{"name":"洞穴喻","definition":"警惕你可能被困在自己的\"认知洞穴\"里、把眼前的影子当成全部真实，主动挣脱成见走出去看真相","source":"柏拉图《理想国》洞穴喻","source_tier":"primary","mechanism":"输入=把眼前的影子当成全部真实 → 处理=警惕被困在认知洞穴里、主动挣脱习惯成见走出去 → 输出=看到更大的真相(洞穴喻)","trigger":"怀疑自己的认知可能受限时","modern_transfer":"警惕你可能被困在自己的''认知洞穴''里、把眼前的影子当成全部真实——主动挣脱习惯与成见、走出去看更大的真相(柏拉图洞穴喻)","architecture":{"type":"flow","components":["别把眼前的影子当全部真实","警惕被困在认知洞穴","主动挣脱习惯与成见","走出去看更大的真相"]},"strategy_card_image":"kb-assets/plato/model-2.png"},{"name":"辩证法","definition":"真理在不断的提问、反驳、辨析中层层逼近——用对话式的诘问去检验和提炼一个观念","source":"柏拉图对话录","source_tier":"primary","mechanism":"输入=独断地下结论 → 处理=通过不断的提问、反驳、辨析层层逼近真理 → 输出=经诘问检验提炼的观念(辩证法)","trigger":"要检验/提炼一个观念时","modern_transfer":"真理在不断的提问、反驳、辨析中层层逼近——用对话式的诘问去检验和提炼一个观念、而非独断地下结论(柏拉图辩证法、承自苏格拉底)","architecture":{"type":"loop","components":["别独断地下结论","通过不断的提问反驳辨析","层层逼近真理","经诘问检验提炼的观念"]},"strategy_card_image":"kb-assets/plato/model-3.png"},{"name":"灵魂三分与正义","definition":"一个系统由不同部分组成（如理性/激情/欲望），让各部分各守其分、由最该主导的（理性）统领，秩序即正义","source":"柏拉图《理想国》","source_tier":"primary","mechanism":"输入=系统内各部分越位混乱 → 处理=让各部分(理性/激情/欲望)各守其分、由最该主导的(理性)统领 → 输出=各司其职秩序即正义(灵魂三分)","trigger":"要让一个系统(人/组织)有序时","modern_transfer":"一个系统(人或组织)由不同部分组成(如理性/激情/欲望)、让各部分各守其分、由最该主导的部分(理性)来统领——各司其职、秩序即''正义''(柏拉图灵魂三分、推及城邦)","architecture":{"type":"hierarchy","components":["别让系统各部分越位混乱","让各部分各守其分","由最该主导的理性统领","各司其职秩序即正义"]},"strategy_card_image":"kb-assets/plato/model-4.png"},{"name":"哲学王","definition":"一件事最该交给的，是真正懂它、看到了根本的人，而非最渴望权位或最会争的人","source":"柏拉图《理想国》","source_tier":"primary","mechanism":"输入=把事交给最渴望权位或最会争的人 → 处理=交给真正懂它、看到了根本的人 → 输出=由智慧者主事(哲学王)","trigger":"决定一件事该交给谁主事时","modern_transfer":"一件事最该交给的、是真正懂它、看到了根本的人、而非最渴望权位或最会争的人(''哲学王''、柏拉图)〔但现实中难实现、且潜藏精英专制风险、见盲区〕","architecture":{"type":"flow","components":["别交给最渴望权位或最会争的人","找真正懂它的人","交给看到了根本的人","由智慧者主事"]},"strategy_card_image":"kb-assets/plato/model-5.png"}],"decision_principles":["透过现象追问那个更本质、永恒的原型/本质（理念）","警惕被困认知洞穴、挣脱成见、走出去看更大的真相","用对话式的诘问检验提炼观念，而非独断下结论","让系统各部分各守其分、由最该主导的部分统领","把事交给真正懂它的人，而非最会争权的人"],"inquiry_questions":["你停在了具体表象、还是追问了那个''什么使它成为它''的本质？","你会不会被困在自己的认知洞穴里、把眼前的影子当成了全部真实？","你是独断地下了结论、还是用提问反驳辨析去检验提炼它？","这个系统里各部分各守其分吗、是由最该主导的部分在统领吗？","这件事你交给了真正懂它的人、还是最渴望权位/最会争的人？"],"value_priorities":["永恒的本质理念 ＞ 变动的现象表象（理念是更真实的实在）","挣脱成见看真相 ＞ 把影子当全部真实（洞穴喻）","由真正懂的人主事 ＞ 由最会争权的人主事（哲学王（但现实难实现））"],"blind_spots":["理念论（现象背后有永恒理型）是一种形而上学立场，被亚里士多德等批评为''割裂了理念与具体事物''、可能脱离经验（学术，B）。","''哲学王''式的理想国在现实中极难实现，且''由少数智者统治''潜藏精英专制与压制的风险（政治哲学批评，B，客观标注）。","灵魂三分/理性统领可能压抑了激情与欲望的正当作用（原理推断，B）。","偏重对永恒、本质、理念的追求，对变动不居的经验世界与实务相对轻视（原理推断，B）。"],"applicable_domains":["认知偏误与理性决策","价值与伦理","领导力"],"match_tags":["认知偏误与理性决策","价值与伦理","领导力","第一性原理","批判思辨","系统分析","古代欧洲"],"linked_cases":["plato-c1","plato-c2","plato-c3","plato-c4"],"life_tags":[{"tag":"著理想国","tier":"primary"},{"tag":"创雅典学园","tier":"secondary"},{"tag":"提理念论","tier":"primary"},{"tag":"倡哲人王治","tier":"primary"}],"voice_profile":{"notes":"思辨高远、追求理型；善用比喻与对话；重理性与秩序；理想主义"},"references":[{"ref_id":"plato-s1","title":"柏拉图《理想国》《斐多》等对话录","locator":"理念论、洞穴喻、辩证法、灵魂三分、哲学王","source_tier":"primary","supports_models":["理念论","洞穴喻","辩证法","灵魂三分与正义","哲学王"],"supports_cases":["plato-c1","plato-c2","plato-c3","plato-c4"],"note":"一手·对话录"},{"ref_id":"plato-s2","title":"古希腊哲学研究","locator":"理念论、柏拉图与亚里士多德之别","source_tier":"secondary","supports_models":["理念论","灵魂三分与正义"],"note":"二手·研究"}],"material_type":"textual","reasoning_skeleton":{"signature":"透过现象追问那个更本质永恒的原型(理念论)；警惕被困认知洞穴、挣脱成见看更大真相(洞穴喻)；用对话式诘问层层逼近真理而非独断(辩证法)；让系统各部分各守其分由理性统领(灵魂三分与正义)；把事交给真正懂的人而非最会争的人(哲学王)","steps":[{"invoke":"理念论","action":"你停在了具体表象、还是追问了那个''什么使它成为它''的本质？"},{"invoke":"洞穴喻","action":"你会不会被困在自己的认知洞穴里、把眼前的影子当成了全部真实？"},{"invoke":"辩证法","action":"你是独断地下了结论、还是用提问反驳辨析去检验提炼它？"},{"invoke":"灵魂三分与正义","action":"这个系统里各部分各守其分吗、是由最该主导的部分在统领吗？"},{"invoke":"哲学王","action":"这件事你交给了真正懂它的人、还是最渴望权位/最会争的人？"}],"contrast":"与亚里士多德不同(关键差异·师徒却分流·西方哲学两大路径)：**柏拉图主''理念在彼岸的理型世界''、向上超越、重演绎与数学、轻经验**；**亚里士多德(柏拉图的学生)主''形式内在于具体事物''、重经验观察与归纳、把理念拉回到现实事物中**——一个向上追理型、一个向下究事物(见亚里士多德卡)。与苏格拉底不同：苏格拉底重''诘问、自知无知、追问定义''(不立体系);柏拉图(苏格拉底的学生)承其辩证法、却发展出庞大的理念论体系(见苏格拉底卡)。【射程/盲区】柏拉图之道在''理念论、洞穴喻、辩证法、灵魂三分、哲学王''极有力(尤其追本质、破成见、检验观念)，但①理念论被亚里士多德等批为''割裂了理念与具体事物''、可能脱离经验;②''哲学王''式理想国现实中极难实现、''由少数智者统治''潜藏精英专制与压制的风险;③灵魂三分/理性统领可能压抑激情与欲望的正当作用;④偏重永恒本质、对变动的经验世界与实务相对轻视。适用认知偏误与理性决策/价值与伦理/领导力;不适用投资/危机应对。"},"persona_anchor":{"primary":[{"source":"case","case_id":"plato-c1","note":"用户''被一个事物纷繁多变的表象绕晕、抓不住要领''时，以柏拉图理念论类比：透过纷繁变动的现象、去追问那个更本质、更稳定的''原型/本质''(理念)——别停在具体表象、把握背后那个''什么使它成为它''的本质;变的是现象、不变的是理念（理念论为柏拉图《理想国》《斐多》核心→确证）"},{"source":"case","case_id":"plato-c2","note":"用户''笃定地以为自己看到的就是全部真实、却可能被环境与成见局限''时，以柏拉图洞穴喻类比：洞穴里的人把墙上的影子当成真实、直到有人挣脱锁链走出洞穴才见到真正的世界——警惕你可能被困在自己的''认知洞穴''里、主动挣脱习惯与成见、走出去看更大的真相（洞穴喻为柏拉图《理想国》核心→确证）"}]},"further_reading":[{"title":"柏拉图《理想国》《斐多》等对话录","why":"理念论、洞穴喻、辩证法、灵魂三分、哲学王的一手出处（A）","type":"original"},{"title":"古希腊哲学研究","why":"对柏拉图理念论及其与亚里士多德之别的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/plato.png","avatar_thumb":"/advisors/portraits/plato.png","domain":"哲学","person_id":"P-plato","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '3725dabd8310209fda50d924a74e9feac41453ec81ea469cdab5687a9d311b23', 73, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('qijiguang', 'P-qijiguang', '戚继光', 'strategy', '戚继光 · 练兵建军与阵法协同思维框架卡', '明（1528—1588）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '募兵练兵成军 · 阵法与协同', '/advisors/portraits/qijiguang.png', '/advisors/portraits/qijiguang.png', 5, 0, '{"schema_version":1,"card_id":"qijiguang","name":"戚继光","title":"戚继光 · 练兵建军与阵法协同思维框架卡","era":"明（1528—1588）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"募兵练兵成军","definition":"没有现成可用的好队伍时，亲自招募合适的人，用一套严格系统的训练，从零打造一支真正有战斗力的队伍","source":"戚继光招募义乌兵、练成\"戚家军\"","source_tier":"secondary","mechanism":"输入=将就用现成的不堪用的队伍 → 处理=亲自招募合适的人、用严格系统的训练从零打造有战斗力的新军 → 输出=真正能打的队伍(募兵练兵)","trigger":"没有现成可用的好队伍时","modern_transfer":"没有现成可用的好队伍时、别将就——亲自招募合适的人、用一套严格系统的训练、从零打造一支真正有战斗力的队伍(戚继光招募义乌兵、练成''戚家军'')","architecture":{"type":"flow","components":["别将就用现成不堪用的队伍","亲自招募合适的人","用严格系统的训练","从零打造真正能打的队伍"]},"strategy_card_image":"kb-assets/qijiguang/model-1.png"},{"name":"阵法与协同","definition":"别让成员各自为战——设计一套清晰的\"阵法\"（分工与配合机制），让不同技能的人各司其职、彼此掩护协同","source":"戚继光的鸳鸯阵","source_tier":"secondary","mechanism":"输入=成员各自为战、不配合 → 处理=设计清晰的阵法(分工与配合机制)、让不同技能的人各司其职协同 → 输出=团队配合发挥最大战力(阵法协同)","trigger":"要让一个团队协同作战时","modern_transfer":"别让成员各自为战——设计一套清晰的''阵法''(分工与配合机制)、让不同技能的人在小队里各司其职、彼此掩护协同、以团队配合发挥最大战力(戚继光的鸳鸯阵、不同兵器分工)","architecture":{"type":"matrix","components":["别让成员各自为战不配合","设计清晰的阵法分工与配合机制","让不同技能的人各司其职彼此掩护","以团队配合发挥最大战力"]},"strategy_card_image":"kb-assets/qijiguang/model-2.png"},{"name":"严明纪律赏罚","definition":"用极其严明、清晰、说到做到的纪律与赏罚，把一群普通人锻造成令行禁止、敢打硬仗的队伍","source":"戚继光的严格治军","source_tier":"secondary","mechanism":"输入=纪律松弛、令不行禁不止 → 处理=以极严明清晰说到做到的纪律与赏罚、锻造令行禁止的队伍 → 输出=纪律即战斗力根基(严明纪律)","trigger":"要把一群普通人锻造成劲旅时","modern_transfer":"用极其严明、清晰、说到做到的纪律与赏罚、把一群普通人锻造成令行禁止、敢打硬仗的队伍——纪律是战斗力的根基(戚继光的严格治军)","architecture":{"type":"hierarchy","components":["别让纪律松弛令不行禁不止","以极严明清晰说到做到的纪律与赏罚","锻造令行禁止的队伍","纪律是战斗力的根基"]},"strategy_card_image":"kb-assets/qijiguang/model-3.png"},{"name":"因地因敌制宜","definition":"别套用通用的打法——针对你具体的对手特点与战场环境，量身定制你的战法、组织与工具","source":"戚继光因敌制器","source_tier":"secondary","mechanism":"输入=套用通用打法 → 处理=针对具体对手特点与战场环境、量身定制战法组织工具 → 输出=量身定制(因敌制宜)","trigger":"面对特定对手与环境时","modern_transfer":"别套用通用的打法——针对你具体的对手特点与战场环境、量身定制你的战法、组织与工具(戚继光针对倭寇与江南水乡定制鸳鸯阵与兵器、北调御蒙古又改制车营)","architecture":{"type":"flow","components":["别套用通用的打法","针对具体对手特点与战场环境","量身定制战法组织与工具","因地因敌制宜"]},"strategy_card_image":"kb-assets/qijiguang/model-4.png"},{"name":"著书立制传承","definition":"把摸索出的有效经验，系统化、文本化为可传承、可复制的\"操典/手册\"，让成功不依赖个人、可被复制与传承","source":"戚继光《纪效新书》《练兵实纪》","source_tier":"primary","mechanism":"输入=成功只系于个人、难复制 → 处理=把有效经验系统化文本化为可传承可复制的操典 → 输出=成功可复制传承(著书立制)","trigger":"要让成功不依赖个人、可复制传承时","modern_transfer":"把你摸索出的有效经验、系统化、文本化为可传承、可复制的''操典/手册''——让成功不依赖个人、可被复制与传承(戚继光著《纪效新书》《练兵实纪》)","architecture":{"type":"flow","components":["别让成功只系于个人难复制","把有效经验系统化文本化","为可传承可复制的操典手册","让成功不依赖个人可复制传承"]},"strategy_card_image":"kb-assets/qijiguang/model-5.png"}],"decision_principles":["没有好队伍时，亲自招募、严格训练，从零打造有战斗力的队伍","设计清晰的阵法（分工与配合），让不同技能的人协同作战","用极严明、说到做到的纪律与赏罚，锻造令行禁止的队伍","针对具体对手与环境，量身定制战法、组织与工具","把有效经验系统化为可传承的操典，让成功可复制"],"inquiry_questions":["没有现成好队伍时，你是将就、还是亲自招募、严格训练、从零打造？","你的团队是各自为战、还是有清晰的阵法让不同技能的人协同？","你的纪律与赏罚是松弛、还是极严明、清晰、说到做到？","你是套用通用打法、还是针对具体对手与环境量身定制？","你的成功只系于你个人、还是已系统化为可传承、可复制的操典？"],"value_priorities":["练成的新军 ＞ 将就的旧兵（募义乌兵、戚家军）","协同的阵法 ＞ 各自为战（鸳鸯阵）","可传承的操典 ＞ 系于个人的成功（《纪效新书》）"],"blind_spots":["戚继光的''练兵成军''极依赖统帅个人的能力、精力与资源投入，难以简单复制（原理推断，B）。","严明纪律与高度组织化的体系，在强调灵活、自主、创新的场景下可能过于刚性（原理推断，B）。","戚家军的强大也部分依赖其特定的对手（倭寇）与战场，未必通用（原理推断，B）。","戚继光在官场需依附张居正等，其成就受制于政治环境（史，B，点到为止）。"],"applicable_domains":["组织管理","竞争博弈","危机应对"],"match_tags":["组织管理","竞争博弈","危机应对","系统分析","务实渐进","制度法治思维","古代东亚"],"linked_cases":["qijiguang-c1","qijiguang-c2","qijiguang-c3","qijiguang-c4"],"life_tags":[{"tag":"组建戚家军","tier":"secondary"},{"tag":"荡平倭寇","tier":"secondary"},{"tag":"著纪效新书","tier":"primary"},{"tag":"著练兵实纪","tier":"primary"}],"voice_profile":{"notes":"务实严整、治军如铁；重训练与阵法；因敌制宜；系统化传承"},"references":[{"ref_id":"qijiguang-s1","title":"戚继光《纪效新书》《练兵实纪》、《明史·戚继光传》","locator":"募兵练兵、鸳鸯阵、治军、因敌制宜、著书立制","source_tier":"primary","supports_models":["募兵练兵成军","阵法与协同","严明纪律赏罚","因地因敌制宜","著书立制传承"],"supports_cases":["qijiguang-c1","qijiguang-c2","qijiguang-c3","qijiguang-c4"],"note":"一手/二手·兵书与史传"},{"ref_id":"qijiguang-s2","title":"戚继光与明代军事研究","locator":"建军、阵法、抗倭","source_tier":"secondary","supports_models":["募兵练兵成军","阵法与协同"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"没有好队伍时亲自招募严格训练从零打造有战斗力的队伍(募兵练兵成军)；设计清晰的阵法让不同技能的人各司其职协同(阵法与协同)；用极严明说到做到的纪律与赏罚锻造令行禁止的队伍(严明纪律赏罚)；针对具体对手与环境量身定制战法组织工具(因地因敌制宜)；把有效经验系统化为可传承可复制的操典(著书立制传承)","steps":[{"invoke":"募兵练兵成军","action":"没有现成好队伍时，你是将就、还是亲自招募、严格训练、从零打造？"},{"invoke":"阵法与协同","action":"你的团队是各自为战、还是有清晰的阵法让不同技能的人协同？"},{"invoke":"严明纪律赏罚","action":"你的纪律与赏罚是松弛、还是极严明、清晰、说到做到？"},{"invoke":"因地因敌制宜","action":"你是套用通用打法、还是针对具体对手与环境量身定制？"},{"invoke":"著书立制传承","action":"你的成功只系于你个人、还是已系统化为可传承、可复制的操典？"}],"contrast":"与孙子不同(关键差异)：**孙子是''兵法的原理总纲''(知彼知己、不战而屈人之兵、势、诡道——抽象的战争智慧)**；**戚继光是''练兵建军的实操体系''(募兵、阵法、纪律、定制、操典——从零造一支强军的工程)**——孙子讲''怎么想''、戚继光讲''怎么把一支队伍练出来''(见孙子卡)。与韩信不同：韩信是''用兵的奇谋''(背水一战、出其不意——临阵的灵活);戚继光是''练兵的体系''(把普通人练成劲旅的系统工程)——一个用兵、一个练兵(见韩信卡)。与拿破仑不同：拿破仑靠''集中兵力、机动、个人统帅天才'';戚继光靠''严格训练、阵法协同、纪律与操典''(见拿破仑卡)。【射程/盲区】戚继光之道在''募兵练兵、阵法协同、严明纪律、因敌制宜、著书立制''极有力(尤其建军、组织、训练)，但①其''练兵成军''极依赖统帅个人的能力精力与资源、难简单复制;②严明纪律与高度组织化在需灵活自主创新的场景下可能过刚;③戚家军的强大也部分依赖特定对手与战场、未必通用;④其成就受制于政治环境。适用组织管理/竞争博弈/危机应对;不适用创作/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"qijiguang-c1","note":"用户''手头没有一支能打的队伍、现成的人不堪用、又不甘将就''时，以戚继光募兵练兵类比：明代卫所兵腐败不堪用、戚继光索性弃之不用、亲自到义乌招募淳朴勇悍的矿工与农民、用一套严格系统的训练从零练成了威震天下的''戚家军'';没有现成好队伍时别将就——亲自招募合适的人、严格训练、从零打造一支真正能打的队伍（募义乌兵练成戚家军为史实→确证）"},{"source":"case","case_id":"qijiguang-c2","note":"用户''团队成员各有所长却各自为战、配合不起来、形不成合力''时，以戚继光鸳鸯阵类比：他设计了''鸳鸯阵''——盾牌手、狼筅手、长枪手、短刀手等不同兵器的士兵在一个小队里分工明确、彼此掩护协同;设计一套清晰的''阵法''(分工与配合机制)、让不同技能的人各司其职、协同作战、以团队配合发挥最大战力（鸳鸯阵为史实→确证）"}]},"further_reading":[{"title":"戚继光《纪效新书》《练兵实纪》、《明史·戚继光传》","why":"募兵练兵、鸳鸯阵、治军、因敌制宜、著书立制的出处（A/B）","type":"兵书/史传"},{"title":"戚继光与明代军事研究","why":"对其建军、阵法与抗倭的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/qijiguang.png","avatar_thumb":"/advisors/portraits/qijiguang.png","domain":"战略","person_id":"P-qijiguang","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'f7a3fc74d9c94cb3b3486cb3eb089b6a9ff5d91dd0711393584081647853678c', 74, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('rockefeller', 'P-rockefeller', '约翰·D·洛克菲勒', 'business', '约翰·D·洛克菲勒 · 行业整合与成本霸权思维框架卡', '19–20世纪（1839–1937）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '横向整合 · 纵向一体化', '/advisors/portraits/rockefeller.png', '/advisors/portraits/rockefeller.png', 5, 0, '{"schema_version":1,"card_id":"rockefeller","name":"约翰·D·洛克菲勒","title":"约翰·D·洛克菲勒 · 行业整合与成本霸权思维框架卡","era":"19–20世纪（1839–1937）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"横向整合","definition":"收购/联合同行(炼油厂)消灭无序价格战，把分散行业整合为一体，以规模与协同压成本、掌控定价","source":"标准石油史/传记","source_tier":"secondary","mechanism":"输入=分散血战、产能过剩的同质行业 → 处理=先建成本优势，再给对手''被收编或被挤垮''二选一 → 输出=把无序竞争收拢成统一规模与定价权","trigger":"行业产能过剩、价格血战、利润微薄且玩家分散时","modern_transfer":"身处打价格战的红海，与其继续混战，不如用成本/资本优势整合对手(并购或联合)，把无序竞争变成自己掌控的规模与定价权","architecture":{"type":"hierarchy","components":["识别血战行业","建立成本优势","给对手二选一","收编成统一规模"]},"strategy_card_image":"kb-assets/rockefeller/model-1.png"},{"name":"纵向一体化","definition":"向上下游延伸自建油罐车、管道、桶厂、仓储，掌控全链条、消除中间环节、压成本筑壁垒","source":"标准石油史/传记","source_tier":"secondary","mechanism":"输入=被某环节(运费/中间商)卡脖子 → 处理=向上下游自建该环节、串联全链 → 输出=全链条掌控，既降本又把命运攥在自己手里","trigger":"某关键环节总受制于人、被卡脖子、利润被中间环节吃掉时","modern_transfer":"当业务关键环节总被别人卡(供应商/渠道/平台)，自己把它做了——掌控全链条不只降本，更是消除受制点、筑起壁垒","architecture":{"type":"flow","components":["定位受制环节","自建该环节","串联全链条","消除中间商"]},"strategy_card_image":"kb-assets/rockefeller/model-2.png"},{"name":"极致成本效率","definition":"对每分成本斤斤计较，把成本做到行业最低，用低成本在价格战中碾压并收编对手","source":"传记","source_tier":"secondary","mechanism":"输入=同质化、打价格战的行业 → 处理=把每一分成本拆开抠到行业最低 → 输出=最厚的安全垫、可持续低价收编对手","trigger":"产品同质化、打价格战、谁成本低谁活下来的行业","modern_transfer":"在同质化红海，把每一分成本做到行业最低本身就是最难被复制的护城河——成本领先=价格战里最厚的安全垫","architecture":{"type":"loop","components":["拆解每分成本","抠到行业最低","价格战中碾压","低价收编对手"]},"strategy_card_image":"kb-assets/rockefeller/model-3.png"},{"name":"现金与隐忍","definition":"保持充裕现金、不动声色，趁对手在萧条/油价低谷虚弱时低价收编；冷静、有耐心、不被情绪带","source":"传记","source_tier":"secondary","mechanism":"输入=行业周期性波动 → 处理=平时保现金、不动声色，专挑对手在低谷最虚弱时出手 → 输出=逆周期低价收编、把波动变成整合机会","trigger":"行业周期性波动、对手在萧条/低谷中虚弱时","modern_transfer":"现金+耐心是逆周期收购的弹药；别人最绝望时，正是有准备者以最低价完成整合的时刻——别在高点冲动，备好弹药等低谷","architecture":{"type":"loop","components":["平时保现金","不动声色蓄势","等对手低谷","低价收编"]},"strategy_card_image":"kb-assets/rockefeller/model-4.png"},{"name":"系统性慈善","definition":"晚年把巨富以科学化、机构化方式系统捐赠(大学、医学、基金会)，追求根本性而非零散施舍","source":"洛克菲勒回忆/慈善记述","source_tier":"primary","mechanism":"输入=巨额资源 + 零散施舍难有根本影响 → 处理=机构化、科学化、瞄准根本问题地投放 → 输出=结构性的长期回报","trigger":"要做善事/做长期投入、但想避免零散撒钱低效时","modern_transfer":"做善事/长期投入也要讲方法论——与其零散撒钱，不如机构化、瞄准根本问题(创办机构而非施舍)，让每分投入产生结构性长期回报","architecture":{"type":"hierarchy","components":["拒绝零散撒钱","机构化","瞄准根本问题","求结构性回报"]},"strategy_card_image":"kb-assets/rockefeller/model-5.png"}],"decision_principles":["把无序竞争整合成有序的规模（B）","掌控全产业链，消除受制于人的环节（B）","成本做到行业最低，用低成本碾压（B）","保持现金，趁对手虚弱时低价收编（B）","冷静隐忍，不被情绪和虚荣带节奏（B）","施善要科学化、机构化、求根本（A/B）"],"inquiry_questions":["这个行业的混乱无序，能被整合成规模吗？","你的链条上，哪一环最容易被别人卡住？","你的成本，是不是行业里最低的？","对手最虚弱的时刻到了吗，你有现金吗？"],"value_priorities":["秩序与规模 ＞ 无序竞争（整合胜过混战）","全链条掌控 ＞ 受制中间环节（纵向一体化）","长期现金与耐心 ＞ 一时意气（隐忍待时）","成本领先 ＞ 价格虚高（低成本是终极武器）"],"blind_spots":["其整合手段(铁路回扣、挤压对手)被判垄断、1911年标准石油被反垄断拆分，方法的合法性与公共代价是重大争议（史实，A/B）","极致掌控与秘密行事，在重透明、强监管、重协作共识的现代环境会触礁（原理推断，B）","成本/规模思维长于整合既有行业，未必擅长从0到1的技术创新（原理推断，B）"],"applicable_domains":["商业模式与护城河","资源调度","竞争博弈","战略","长期规划"],"match_tags":["商业模式与护城河","资源调度","竞争博弈","系统分析","长期主义","对抗性思维","近代北美"],"linked_cases":["rockefeller-c1","rockefeller-c2","rockefeller-c3","rockefeller-c4","rockefeller-c5"],"life_tags":[{"tag":"创标准石油","tier":"secondary"},{"tag":"设洛氏基金会","tier":"secondary"},{"tag":"捐建芝大","tier":"secondary"},{"tag":"缔石油托拉斯","tier":"secondary"}],"voice_profile":{"notes":"冷静寡言、克制；笃信秩序与节俭；虔诚而坚硬"},"references":[{"ref_id":"rockefeller-s1","title":"洛克菲勒回忆与慈善记述（含基金会档案）","locator":"慈善理念与机构化捐赠相关段落","source_tier":"primary","supports_models":["系统性慈善"],"supports_cases":["rockefeller-c5"],"note":"含其自述成分，慈善理念部分一手"},{"ref_id":"rockefeller-s2","title":"切尔诺《Titan》传记 + 塔贝尔《标准石油史》","locator":"克利夫兰整合、纵向一体化、成本、逆周期收编、1911拆分相关章节；焊点细节待核验","source_tier":"secondary","supports_models":["横向整合","纵向一体化","极致成本效率","现金与隐忍"],"supports_cases":["rockefeller-c1","rockefeller-c2","rockefeller-c3","rockefeller-c4"],"note":"第三方权威传记与调查史"}],"material_type":"rich","reasoning_skeleton":{"signature":"把分散血战的行业看成可整合的规模——先把成本抠到行业最低，再用成本优势横向收编对手、纵向自建受制环节；平时保现金、专挑对手低谷逆周期收编；财富则机构化系统投放","steps":[{"invoke":"极致成本效率","action":"先问：你的成本是不是行业最低？把每一分成本拆开抠到最低——这是价格战里活下来的安全垫"},{"invoke":"横向整合","action":"在产能过剩、血战的行业，用成本优势给对手''被收编或被挤垮''，把无序竞争收拢成规模与定价权"},{"invoke":"纵向一体化","action":"哪个环节总被别人卡（运费/中间商/渠道）？自己把它做了，掌控全链条、消除受制点、筑壁垒"},{"invoke":"现金与隐忍","action":"平时保现金、不动声色；专挑对手在萧条/低谷最虚弱时低价收编，把行业波动变成自己的机会"},{"invoke":"系统性慈善","action":"财富/长期投入要机构化、瞄准根本问题，求结构性长期回报，而非零散施舍"}],"contrast":"与卡内基不同：二者都是镀金时代''做大''巨头、都重成本与逆周期，但卡内基靠**钢铁的成本会计与技术升级(贝塞麦法)纵向打穿一条产业链**做到最低成本，是''把一条链做到极致便宜''；洛克菲勒靠**横向收编整个石油行业、掌控定价权**做大，是''把整个行业收拢成一体并掌定价''（见卡内基卡）。与贝索斯不同：亚马逊也追规模+低成本+纵向整合，但靠**飞轮与客户体验驱动增长**；洛克菲勒是**靠收编对手消灭竞争、掌控定价的整合垄断**（已被1911反垄断拆分，作盲区，见贝索斯卡）。【射程边界】洛长于整合既有红海行业、成本与资本博弈；**不长于从0到1技术创新**（那是特斯拉/爱迪生射程）、亦不适用强监管重透明的治理决策。"},"persona_anchor":{"primary":[{"source":"case","case_id":"rockefeller-c1","note":"用户''身处产能过剩、价格血战的行业要不要继续混战''时，以横向整合·克利夫兰整合类比：借成本优势在数周内对同城对手''要么被收购、要么被挤垮''，把无序竞争收拢成规模（整合行为由《标准石油史》与多方传记印证→确证）"},{"source":"case","case_id":"rockefeller-c2","note":"用户''某关键环节总被别人卡脖子怎么办''时，以纵向一体化·自建油罐车队/管道/桶厂类比：把受制环节自己做了，全链条掌控既降本又消除受制点（纵向一体化与约九成炼油份额见多方史料→确证）"}]},"further_reading":[{"title":"切尔诺《Titan：洛克菲勒传》","why":"权威全景传记，整合手段、成本、逆周期、慈善与1911拆分皆有","type":"biography"},{"title":"塔贝尔《标准石油史》","why":"同时代调查史，对其整合手段(回扣/挤压)的批判性记录","type":"解读"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/rockefeller.png","avatar_thumb":"/advisors/portraits/rockefeller.png","domain":"商业","person_id":"P-rockefeller","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'bf3b39fd7fd3b4445fec749acce42cab225c6651454782415cd5dea110a10020', 75, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('saladin', 'P-saladin', '萨拉丁', 'governance', '萨拉丁 · 团结分裂与宽容领导思维框架卡', '中世纪（1137—1193）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '团结分裂的力量 · 宽容与气度服人', '/advisors/portraits/saladin.png', '/advisors/portraits/saladin.png', 5, 0, '{"schema_version":1,"card_id":"saladin","name":"萨拉丁","title":"萨拉丁 · 团结分裂与宽容领导思维框架卡","era":"中世纪（1137—1193）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"团结分裂的力量","definition":"面对一个强大的共同对手/目标，先把原本分裂、各自为政、甚至内斗的各方，围绕共同的大义团结起来、拧成一股绳——内部的团结是对外取胜的前提","source":"萨拉丁统一分裂的穆斯林各势力","source_tier":"secondary","mechanism":"输入=各方分裂内斗、对强敌各自为政 → 处理=围绕共同大义把分裂各方团结成合力 → 输出=内部团结是对外取胜前提(团结分裂)","trigger":"面对强大共同对手、内部却分裂时","modern_transfer":"面对一个强大的共同对手/目标、先把原本分裂、各自为政、甚至内斗的各方、围绕共同的大义团结起来、拧成一股绳——内部的团结是对外取胜的前提(萨拉丁统一了分裂的穆斯林各势力)","architecture":{"type":"flow","components":["别让各方分裂内斗对强敌各自为政","围绕共同的大义","把分裂各方团结成合力","内部团结是对外取胜的前提"]},"strategy_card_image":"kb-assets/saladin/model-1.png"},{"name":"宽容与气度服人","definition":"以宽容、仁慈、信守承诺、不赶尽杀绝的气度对待对手与他人——赢得的不只是一时的胜利，更是包括对手在内的长久尊重与人心","source":"萨拉丁攻占耶路撒冷后的宽待","source_tier":"secondary","mechanism":"输入=对对手赶尽杀绝、睚眦必报 → 处理=以宽容仁慈信守承诺的气度对待对手他人 → 输出=赢得包括敌人的长久尊重(宽容服人)","trigger":"如何对待对手与失败者时","modern_transfer":"以宽容、仁慈、信守承诺、不赶尽杀绝的气度对待对手与他人——赢得的不只是一时的胜利、更是包括对手在内的长久尊重与人心(萨拉丁占领耶路撒冷后善待俘虏与平民、其骑士风度连敌人都敬重)〔但宽容须以实力为后盾、见盲区〕","architecture":{"type":"flow","components":["别对对手赶尽杀绝睚眦必报","以宽容仁慈信守承诺的气度","对待对手与他人","赢得包括对手在内的长久尊重"]},"strategy_card_image":"kb-assets/saladin/model-2.png"},{"name":"以共同信念凝聚","definition":"高举一个超越个人、小团体私利的共同信念、使命或\"大义\"，作为凝聚众人的旗帜——人会为一个超越自己的意义而团结奋斗","source":"萨拉丁的共同信念","source_tier":"secondary","mechanism":"输入=只靠私利或强制凝聚人 → 处理=高举超越个人部族私利的共同信念大义作旗帜 → 输出=为超越自己的意义而团结(共同信念)","trigger":"要凝聚一群人时","modern_transfer":"高举一个超越个人、小团体私利的共同信念、使命或''大义''、作为凝聚众人的旗帜——人会为一个超越自己的意义而团结奋斗(萨拉丁以收复失地的共同信念凝聚人心)","architecture":{"type":"hierarchy","components":["别只靠私利或强制凝聚人","高举超越个人部族私利的共同信念大义","作为凝聚众人的旗帜","人为超越自己的意义而团结"]},"strategy_card_image":"kb-assets/saladin/model-3.png"},{"name":"坚韧与长期经营","definition":"面对强大的目标，不急于一时之功——以极大的耐心、坚韧、长期的经营，一步步积累实力与威望，等待真正的时机成熟","source":"萨拉丁多年经营才收复耶路撒冷","source_tier":"secondary","mechanism":"输入=急于一时之功 → 处理=以极大耐心坚韧长期经营、一步步积累实力威望、等时机 → 输出=时机成熟才成事(坚韧长期)","trigger":"面对强大目标、要不要急于求成时","modern_transfer":"面对强大的目标、不急于一时之功——以极大的耐心、坚韧、长期的经营、一步步积累实力与威望、等待真正的时机成熟(萨拉丁经营多年、才在哈丁战役大胜后收复耶路撒冷)","architecture":{"type":"flow","components":["别急于一时之功","以极大的耐心坚韧长期经营","一步步积累实力与威望","等待真正的时机成熟"]},"strategy_card_image":"kb-assets/saladin/model-4.png"},{"name":"以身作则的节制","definition":"领袖以身作则——自身简朴、节制、与众人同甘苦，把资源用于共同的事业与对他人的施予，而非自己的挥霍享受","source":"萨拉丁个人极为简朴","source_tier":"secondary","mechanism":"输入=领袖挥霍享受、与众人脱节 → 处理=自身简朴节制与众同甘苦、把财富用于事业与施予 → 输出=节制本身是感召力(以身作则节制)","trigger":"作为领袖如何自处时","modern_transfer":"领袖以身作则——自身简朴、节制、与众人同甘苦、把资源用于共同的事业与对他人的施予、而非自己的挥霍享受;这种节制本身就是巨大的感召力(萨拉丁个人极为简朴、死时几乎没有留下遗产)","architecture":{"type":"flow","components":["别领袖挥霍享受与众人脱节","自身简朴节制与众同甘苦","把资源用于共同的事业与对他人的施予","节制本身是巨大的感召力"]},"strategy_card_image":"kb-assets/saladin/model-5.png"}],"decision_principles":["面对强大对手，先把分裂、内斗的各方围绕共同大义团结起来（内部团结是取胜前提）","以宽容、仁慈、信守承诺的气度对待对手，赢得长久的尊重（但须以实力为后盾）","高举超越私利的共同信念，作为凝聚众人的旗帜","不急于一时之功，以耐心、坚韧、长期经营积累实力，等待时机成熟","领袖自身简朴、节制、与众同甘苦，把资源用于事业与施予"],"inquiry_questions":["面对强大对手，你是任由内部分裂内斗、还是把各方围绕共同大义团结起来？","你对待对手是赶尽杀绝、还是以宽容、信守承诺的气度赢得长久尊重？","你凝聚人靠的是私利/强制、还是一个超越私利的共同信念？","你是急于一时之功、还是以耐心、坚韧长期经营、等待时机成熟？","作为领袖你是挥霍享受、还是简朴节制、与众同甘苦？"],"value_priorities":["团结的合力 ＞ 分裂的内斗（统一穆斯林各势力）","长久的尊重 ＞ 赶尽杀绝（善待耶路撒冷（但须以实力为后盾））","节制的感召 ＞ 挥霍的脱节（个人简朴、死时几无遗产）"],"blind_spots":["萨拉丁的''宽容''也建立在强大实力与政治智慧之上——纯粹的善良无实力支撑、未必能服人（原理推断，B）。","其建立的阿尤布王朝在他死后迅速分裂——高度依赖其个人威望，未能建立稳固持久的制度传承（史，B，客观标注）。","历史叙事（尤其西方浪漫化的''骑士萨拉丁''）有美化、理想化的成分，真实的他也是铁腕的征服者（学术，B，客观标注）。","其成功也依赖特定的历史时机（如十字军内部的矛盾与分裂）（原理推断，B）。"],"applicable_domains":["领导力","危机应对","竞争博弈"],"match_tags":["领导力","危机应对","竞争博弈","攻心共识","利他取向","长期主义","古代中东"],"linked_cases":["saladin-c1","saladin-c2","saladin-c3","saladin-c4"],"life_tags":[{"tag":"收复耶路撒冷","tier":"secondary"},{"tag":"哈丁大捷","tier":"secondary"},{"tag":"抗十字军","tier":"secondary"},{"tag":"建阿尤布王朝","tier":"secondary"}],"voice_profile":{"notes":"宽厚坚毅、气度恢宏；重团结与信念；宽容而有实力；简朴自持"},"references":[{"ref_id":"saladin-s1","title":"萨拉丁传记及十字军东征史（含阿拉伯与西方史料）","locator":"团结诸方、宽容、共同信念、坚韧、节制","source_tier":"secondary","supports_models":["团结分裂的力量","宽容与气度服人","以共同信念凝聚","坚韧与长期经营","以身作则的节制"],"supports_cases":["saladin-c1","saladin-c2","saladin-c3","saladin-c4"],"note":"二手·史与传记"},{"ref_id":"saladin-s2","title":"十字军与中世纪中东史研究","locator":"萨拉丁、历史叙事（含浪漫化成分）","source_tier":"secondary","supports_models":["团结分裂的力量","宽容与气度服人"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"面对强大共同对手先把分裂内斗的各方围绕共同大义团结成合力(团结分裂的力量)；以宽容仁慈信守承诺的气度对待对手赢得包括敌人在内的长久尊重(宽容与气度服人)；高举超越个人部族私利的共同信念作为凝聚众人的旗帜(以共同信念凝聚)；不急于一时之功以耐心坚韧长期经营积累实力等待时机(坚韧与长期经营)；领袖自身简朴节制与众同甘苦把资源用于事业与施予(以身作则的节制)","steps":[{"invoke":"团结分裂的力量","action":"面对强大对手，你是任由内部分裂内斗、还是把各方围绕共同大义团结起来？"},{"invoke":"宽容与气度服人","action":"你对待对手是赶尽杀绝、还是以宽容、信守承诺的气度赢得长久尊重？"},{"invoke":"以共同信念凝聚","action":"你凝聚人靠的是私利/强制、还是一个超越私利的共同信念？"},{"invoke":"坚韧与长期经营","action":"你是急于一时之功、还是以耐心、坚韧长期经营、等待时机成熟？"},{"invoke":"以身作则的节制","action":"作为领袖你是挥霍享受、还是简朴节制、与众同甘苦？"}],"contrast":"与林肯不同(关键差异)：**林肯弥合的是''一国内部''的分裂(南北内战)、靠道德、宽容与宪政重建联邦**；**萨拉丁团结的是''对抗共同外敌''的分裂诸方(穆斯林各势力)、靠共同信念、个人威望与宽容气度**——林肯偏''内部弥合与制度''、萨拉丁偏''对外团结与个人感召''(见林肯卡)。与曼德拉不同(同涉宽容/和解)：曼德拉的宽容是''化解种族对立、推动和解与原谅''(放下仇恨、共建未来);萨拉丁的宽容是''征服者对失败者的气度''(以宽容服人、赢得尊重)——一个是和解者、一个是征服者的气度(见曼德拉卡)。【射程/盲区·历史诚实】萨拉丁之道在''团结分裂、宽容服人、共同信念、坚韧长期、以身作则''极有力(尤其团结、领导、危机)，但①其''宽容''也建立在强大实力之上、纯粹善良无实力支撑未必服人;②其阿尤布王朝在他死后迅速分裂、高度依赖个人威望、未建立稳固制度传承、客观标注;③历史叙事(尤其西方浪漫化的''骑士萨拉丁'')有美化成分、真实的他也是铁腕征服者、客观标注;④成功也依赖特定历史时机(十字军内部矛盾)。适用领导力/危机应对/竞争博弈;不适用投资/创作。"},"persona_anchor":{"primary":[{"source":"case","case_id":"saladin-c1","note":"用户''面对一个强大的共同对手/目标、自己这边却派系林立、各自为政、甚至内斗''时，以萨拉丁团结诸方类比：他面对强大的十字军、首先做的不是急着开战、而是把原本分裂、彼此攻伐的埃及、叙利亚等穆斯林势力、围绕''收复失地''的共同大义、一步步统一、团结起来、拧成一股绳;面对强敌、先求内部的团结——内部团结是对外取胜的前提（统一穆斯林诸势力为史实→确证）"},{"source":"case","case_id":"saladin-c2","note":"用户''在胜利/占上风时、纠结要不要对失败的对手赶尽杀绝、以绝后患''时，以萨拉丁善待耶路撒冷类比：1187年他收复耶路撒冷后、并未像当年十字军屠城那样报复、而是善待俘虏与平民、允许赎身、信守承诺——其宽容与骑士风度连他的敌人(包括理查一世)都为之敬重;以宽容、仁慈、信守承诺的气度对待对手、赢得的是包括敌人在内的长久尊重〔但宽容须以实力为后盾〕（善待耶路撒冷为史实→确证）"}]},"further_reading":[{"title":"萨拉丁传记及十字军东征史（含阿拉伯与西方史料）","why":"团结诸方、宽容、共同信念、坚韧、节制的史述（B）","type":"史/传记"},{"title":"十字军与中世纪中东史研究","why":"对萨拉丁及其历史叙事（含浪漫化成分）的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/saladin.png","avatar_thumb":"/advisors/portraits/saladin.png","domain":"治理","person_id":"P-saladin","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '5a929e5c3f5e71c5eeba2ebee614cdba9c229aaaa2acf640e9fdc0df1d137fd2', 76, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('schweitzer', 'P-schweitzer', '史怀哲', 'history', '史怀哲 · 人生转向与伦理践行框架卡', '现代（1875–1965）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '敬畏生命 · 行动还债', '/advisors/portraits/schweitzer.png', '/advisors/portraits/schweitzer.png', 5, 0, '{"schema_version":1,"card_id":"schweitzer","name":"史怀哲","title":"史怀哲 · 人生转向与伦理践行框架卡","era":"现代（1875–1965）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"敬畏生命","definition":"伦理的根本是对一切生命的敬畏：善＝保存与促进生命，恶＝毁坏与阻碍生命；把道德关怀扩展到所有生灵","source":"史怀哲《文化哲学》《敬畏生命》","source_tier":"primary","mechanism":"输入=在一堆具体伦理规则里打转、缺统一依据 → 处理=确立一条统摄全局的根本原则(对一切生命的敬畏:善=保存促进、恶=毁坏阻碍) → 输出=上面的判断有了统一地基","trigger":"面对伦理/价值判断、缺统一依据时","modern_transfer":"与其在一堆具体规则里打转，不如找一条能统摄全局的根本原则——一旦有了这个地基，上面的判断就有统一依据(他的是''对一切生命的敬畏'')","architecture":{"type":"hierarchy","components":["找统摄全局的根本原则","善=保存促进生命","恶=毁坏阻碍生命","判断有统一地基"]},"strategy_card_image":"kb-assets/schweitzer/model-1.png"},{"name":"行动还债","definition":"把自己拥有的才能、教育、好运视为欠下的债，用直接的、亲手的服务去偿还，而非委托式的抽象慈善","source":"史怀哲《我的生活与思想》","source_tier":"primary","mechanism":"输入=拥有才能/教育/好运 → 处理=把它视为欠下的债、用亲手直接的服务反复偿还(非委托式抽象慈善) → 输出=以反复的承担兑现责任","trigger":"拥有得多、想真正兑现责任时","modern_transfer":"把你拥有的才能、教育、好运当作欠下的债，用亲手的、直接的服务去偿还，而非委托式的捐钱呼吁——而且这是反复的选择，不是一次壮举","architecture":{"type":"loop","components":["视好运为债","亲手直接服务","反复选择承担","兑现亏欠"]},"strategy_card_image":"kb-assets/schweitzer/model-2.png"},{"name":"以生命为论证","definition":"不满足于书写或宣讲伦理，坚持把信念活出来——让自己的一生本身成为论证，而非靠言辞说服","source":"史怀哲《我的生活与思想》","source_tier":"primary","mechanism":"输入=想让人相信一个信念 → 处理=不靠言辞说服、把信念活成自己的一生作为论证 → 输出=人格示范力远超论著(但门槛极高、常人不可复制)","trigger":"想让人真正相信你的信念时","modern_transfer":"想让别人相信你的信念，最有力的不是论证，而是把它活出来——用你怎么过这一生去示范你主张的东西（诚实：这种圣徒式标准对常人不可复制）","architecture":{"type":"flow","components":["不靠言辞说服","把信念活成一生","以人格示范","论证力超言辞"]},"strategy_card_image":"kb-assets/schweitzer/model-3.png"},{"name":"预定的转向","definition":"给人生预设一个转折点：先在某领域积累成就到某年龄，再把后半生整体转向另一更高的志业","source":"史怀哲《我的生活与思想》","source_tier":"primary","mechanism":"输入=人生想转向更高志业 → 处理=给人生预设一个转折点(先在某领域积累到某年龄、再整体转向) → 输出=计划好的(而非被迫的)人生重启","trigger":"想做重大人生转向时","modern_transfer":"重大人生转向可以是''计划好的''而非被迫——先在一个领域积累到位、给自己设一个明确转折点，到点就把后半生整体投向更想成就的志业","architecture":{"type":"flow","components":["先在某领域积累成就","预设转折点与年龄","到点整体转向","后半生投更高志业"]},"strategy_card_image":"kb-assets/schweitzer/model-4.png"},{"name":"多能归一用","definition":"不让多领域才能各自分散，而让它们共同服务于一个目的（如以管风琴演奏所得资助丛林医院）","source":"史怀哲《我的生活与思想》及传记","source_tier":"primary","mechanism":"输入=多领域才能各自分散 → 处理=让它们共同服务一个目的(以演奏所得资助医院) → 输出=多种能力协同养活一个使命","trigger":"转向新志业、手上有多种分散技能时","modern_transfer":"转向新志业不必抛弃旧本事——让你过去积累的所有技能都收拢来为新目的''供血''，一个人的多种能力可以协同养活一个使命","architecture":{"type":"hierarchy","components":["盘点分散的多种才能","收拢指向一个目的","旧本事为新使命供血","协同养活使命"]},"strategy_card_image":"kb-assets/schweitzer/model-5.png"}],"decision_principles":["把伦理关怀扩展到一切生命，凡损害生命者需有正当理由","拥有得越多，欠的债越重——用亲手的行动去还","别只论证你的信念，把它活成你的一生","可以先积累、后转向：给自己一个计划好的人生重启点","让你所有的本事都指向同一个目的，而非各自为战"],"inquiry_questions":["你的选择，是促进了生命，还是损害了它？","你拥有的才能与好运，你打算怎么''还''这笔债？","你是在论证你的信念，还是真的把它活出来了？","你有没有给人生设一个计划好的转向点？现在到了吗？","你那些分散的本事，能不能都收拢来服务一个目的？"],"value_priorities":["亲手的直接行动 ＞ 委托式的抽象善意（亲身去做比捐钱/呼吁更能兑现责任，也代价更大）","活出来的伦理 ＞ 论证出来的伦理（一生作为论证胜过千言；但门槛极高）","对一切生命的敬畏 ＞ 只对人类的关怀（把道德圈扩到所有生灵，即便不便）"],"blind_spots":["其在非洲的工作带有殖民时代的家长式态度（曾以''非洲人是我的兄弟，但是弟弟''等表述）——以今日视角看，善行与对当地人的居高临下并存，是显著的历史争议（史实/后殖民批评，B，客观标注，〔慎〕）","''以生命为论证''标准极高、近乎圣徒式，对普通人不具可操作性，易沦为道德崇高化而非可学方法（原理推断，B）","''敬畏生命''在生命相互冲突时（如治病需杀灭病菌）缺乏清晰取舍规则，他本人也承认这一两难（其著作自陈，B）","强调个人直接牺牲式行动，对需制度化、可持续、规模化的方案（公共卫生体系建设）着力较少（与行动还债同源，原理推断，B）"],"applicable_domains":["价值与伦理","人生抉择","修身自省","职业发展"],"match_tags":["价值与伦理","人生抉择","修身自省","利他取向","第一性原理","长期主义","现当代欧洲"],"linked_cases":["schweitzer-c1","schweitzer-c2","schweitzer-c3","schweitzer-c4","schweitzer-c5"],"life_tags":[{"tag":"赴非洲行医","tier":"secondary"},{"tag":"建非洲医院","tier":"secondary"},{"tag":"获诺贝尔奖","tier":"secondary"},{"tag":"倡敬畏生命","tier":"primary"}],"voice_profile":{"notes":"庄重、近乎布道；伦理诉求强烈；以亲身经历佐证；谦抑中带道德坚定"},"references":[{"ref_id":"schweitzer-s1","title":"史怀哲《我的生活与思想》（Out of My Life and Thought）","locator":"立志转向、敬畏生命、演奏筹资、以生命为论证诸段","source_tier":"primary","supports_models":["预定的转向","敬畏生命","多能归一用","以生命为论证"],"supports_cases":["schweitzer-c1","schweitzer-c2","schweitzer-c3"],"note":"自传·自述，含回溯建构/润色"},{"ref_id":"schweitzer-s2","title":"史怀哲《文化哲学》/《敬畏生命》著述","locator":"敬畏生命伦理体系阐述","source_tier":"primary","supports_models":["敬畏生命"],"note":"本人哲学著述"},{"ref_id":"schweitzer-s3","title":"权威史怀哲传记","locator":"行动还债、以生命为论证、多次往返坚守诸段","source_tier":"secondary","supports_models":["行动还债","以生命为论证"],"supports_cases":["schweitzer-c4","schweitzer-c5"],"note":"二手传记"},{"ref_id":"schweitzer-s4","title":"史怀哲巴赫研究及管风琴演奏/唱片记录","locator":"巴赫研究著述、管风琴录音/音乐会筹资记录","source_tier":"primary","supports_models":["多能归一用"],"supports_cases":["schweitzer-c3"],"note":"一手作品/记录"}],"material_type":"rich","reasoning_skeleton":{"signature":"找一条统摄全局的根本原则当伦理地基(他的是敬畏生命)；把才能好运当债、用亲手直接的服务反复偿还；不靠言辞、把信念活成一生作为论证；人生转向可计划——先积累、设转折点、到点整体转向；让多种本事都收拢为一个目的供血","steps":[{"invoke":"敬畏生命","action":"你的选择，是促进了生命，还是损害了它？(先找一条能统摄判断的根本原则)"},{"invoke":"行动还债","action":"你拥有的才能与好运，你打算怎么''还''这笔债？用亲手行动还、且反复地还"},{"invoke":"预定的转向","action":"你有没有给人生设一个计划好的转向点？现在到了吗？"},{"invoke":"多能归一用","action":"你那些分散的本事，能不能都收拢来服务一个目的、为它供血？"},{"invoke":"以生命为论证","action":"你是在论证你的信念，还是真的把它活出来了？(诚实：圣徒式标准对常人不可复制)"}],"contrast":"与曼德拉不同(关键差异)：二者都是高道德感召的历史人物，但**曼德拉是政治和解者——靠''宽恕优于报复、化敌为伙、象征性姿态''把对手转化为合作者、完成政治转型**；**史怀哲是伦理践行者——靠''一条根本原则(敬畏生命)+亲手还债+把信念活成一生''的个人伦理示范**(见曼德拉卡)。与司马迁等历史域人物区分：史怀哲内核是''计划好的人生转向+以生命为论证''的践行方法。【射程/盲区·反鸡汤】不给''无私奉献圣徒鸡汤''、给可操作方法；但诚实标注：①〔慎〕其在非洲带殖民时代家长式态度(''非洲人是我兄弟、但是弟弟'')、善行与居高临下并存、是显著后殖民争议(客观入盲区、不美化)；②''以生命为论证''圣徒式标准对常人不可复制；③敬畏生命在生命冲突时缺取舍规则。不适用竞争博弈/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"schweitzer-c1","note":"用户''想做重大人生转向、要不要放弃已有成就''时，以30岁转向类比：他已是欧洲卓有声望的神学家/管风琴家，却兑现年轻时的预定转向——30岁起重读医学、38岁取得资格、赴非建医院，转向是计划好的而非被迫（转向事实为传记确证；''21岁立志''心路出自自传含回溯建构，保守取 B）"},{"source":"case","case_id":"schweitzer-c3","note":"用户''转向新事业、旧本事要不要丢''时，以管风琴与巴赫著作筹资养医院类比：他不放弃旧本事、而让它们为新使命供血——回欧洲办音乐会、出版巴赫研究，用所得资助医院（演奏筹资、巴赫著述、医院维持为多源可考→确证）"}]},"further_reading":[{"title":"史怀哲《我的生活与思想》(Out of My Life and Thought)","why":"立志转向、敬畏生命、演奏筹资、以生命为论证诸段（自述含回溯建构）","type":"original"},{"title":"权威史怀哲传记 + 《文化哲学》","why":"行动还债、坚守、敬畏生命伦理体系；殖民争议亦在此核校","type":"biography"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/schweitzer.png","avatar_thumb":"/advisors/portraits/schweitzer.png","domain":"历史","person_id":"P-schweitzer","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '04f06a53fa50d272c6c4b787cf958b0d521167621241852ba3a1419b41146a3f', 77, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('shackleton', 'P-shackleton', '沙克尔顿', 'history', '沙克尔顿 · 绝境领导与求生决策框架卡', '现当代（1874–1922；按代表性时期归档——坚忍号远征1914–17，≥1901）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '目标果断降级 · 士气即资源', '/advisors/portraits/shackleton.png', '/advisors/portraits/shackleton.png', 5, 0, '{"schema_version":1,"card_id":"shackleton","name":"沙克尔顿","title":"沙克尔顿 · 绝境领导与求生决策框架卡","era":"现当代（1874–1922；按代表性时期归档——坚忍号远征1914–17，≥1901）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"目标果断降级","definition":"原目标一旦不可能，立刻放弃它、改锚定新的现实目标（如\"活着回家\"），不为已死的旧目标耗损意志","source":"沙克尔顿《South》","source_tier":"primary","mechanism":"输入=原目标已不可能的处境 → 处理=立刻放弃旧目标、改锚定新的现实目标（如''活着回家''）、不为已死的旧目标耗损意志 → 输出=团队从''失败''转向新任务","trigger":"倾注一切的原目标被现实摧毁时","modern_transfer":"原目标被现实摧毁时别哀悼——当场给团队一个新的现实目标，把''我们失败了''改写成''我们现在要完成这个''","architecture":{"type":"flow","components":["确认旧目标已不可能","当场放弃旧目标","锚定新的现实目标","团队转向新任务"]},"strategy_card_image":"kb-assets/shackleton/model-1.png"},{"name":"士气即资源","definition":"把群体的心理状态当与粮食燃料同等的关键生存资源来主动经营，而非软性点缀","source":"沙克尔顿《South》及船员日记","source_tier":"primary","mechanism":"输入=一个困境中的群体 → 处理=把群体心理状态当与粮食燃料同级的关键生存资源主动经营（routine/仪式/公平/同甘苦）→ 输出=不散的团队","trigger":"看不到尽头、恐惧绝望可能瓦解团队时","modern_transfer":"把士气当头号资源管——定 routine、找乐子、公平分配、领袖与大家同甘苦，让团队''不散''本身就是最重要的工作","architecture":{"type":"hierarchy","components":["视士气为头号资源","维持routine与分工","仪式感/公平分配","领袖同甘苦"]},"strategy_card_image":"kb-assets/shackleton/model-2.png"},{"name":"只走下一程","definition":"把压垮人的全局拆成下一个具体可达的小段，一次只解决眼前这一程，不被终点吓退","source":"沙克尔顿《South》","source_tier":"primary","mechanism":"输入=一个压垮人的全局 → 处理=把它拆成下一个具体可达的小段、一次只解决眼前这一程 → 输出=不被终点吓退","trigger":"被全局/终点吓退、算总账就瘫痪时","modern_transfer":"别算总账——把压垮人的全局拆成''下一程怎么活着到达''，一次只解决眼前这一段","architecture":{"type":"flow","components":["面对压垮人的全局","拆成可达小段","只解决下一程","逐段推进"]},"strategy_card_image":"kb-assets/shackleton/model-3.png"},{"name":"表演性镇定","definition":"领导可见的镇定会设定整个群体的情绪基线；把\"显得有信心\"当职责与工具来执行，而非等情绪到位","source":"沙克尔顿《South》及传记","source_tier":"primary","mechanism":"输入=领导自身的情绪状态 → 处理=把''显得有信心''当职责与工具执行（领导可见的镇定设定群体情绪基线）、而非等情绪到位 → 输出=全队的情绪信号","trigger":"越危急、大家都在看你脸色时","modern_transfer":"越危急领导越要显得镇定——那是给全队的信号；把''显出信心''当职责执行，而非等情绪到位","architecture":{"type":"flow","components":["意识到自己是情绪基线","把显镇定当职责","不等情绪到位主动执行","设定全队信号"]},"strategy_card_image":"kb-assets/shackleton/model-4.png"},{"name":"异见者近身","definition":"把最易散播悲观/动摇的人留在自己身边亲自照看，隔离负面情绪的传染，而非放任或排斥","source":"权威沙克尔顿传记","source_tier":"secondary","mechanism":"输入=团队里最易散播悲观/动摇的人 → 处理=把他留在自己身边亲自照看、隔离负面情绪传染 → 输出=遏制悲观蔓延","trigger":"有人最易传染负面情绪、可能瓦解整体时","modern_transfer":"团队里最负面、最易传染情绪的人，别疏远或惩戒——放在你眼皮底下亲自带，把传染源置于你的影响范围内","architecture":{"type":"hierarchy","components":["识别最易动摇/传染者","留在自己身边","亲自照看与影响","隔离负面扩散"]},"strategy_card_image":"kb-assets/shackleton/model-5.png"}],"decision_principles":["旧目标死了就立刻换新目标，不为已逝的计划哀悼","把士气当头号资源管：定routine、找乐子、不让绝望蔓延","不算总账，只问''下一程怎么活着到达''","越危急，领导越要显得镇定——那是给全队的信号","把最动摇的人放在身边亲自带，别让悲观扩散"],"inquiry_questions":["你原来的目标还可能吗？如果不可能，新的目标该是什么？","这群人的士气现在是资产还是负债？你在主动管它吗？","别想终点——你眼前能活着走完的下一程是什么？","此刻大家在看你的脸色，你显出的是镇定还是慌乱？","队伍里最动摇的人是谁？你把他放在哪？"],"value_priorities":["全员生还（新目标） ＞ 完成原定壮举（旧目标）（旧目标不可能时，保人优先于成就）","士气与凝聚 ＞ 严格的纪律惩戒（绝境中人心散了就全完了，凝聚高于威严）","下一程的当下行动 ＞ 对全局前景的反复推演（算总账只会瘫痪，专注可控的下一步）"],"blind_spots":["其领导术高度依赖''绝境+小团队+生死与共''这一特定情境；常态、大组织、长期官僚环境中未必有效（原理推断，B）","个人英雄式、强依赖领袖魅力与在场，不易制度化或规模化复制（传记分析，B）","探险事业本身在财务/商业上屡屡失败（多次远征负债、商业计划落空）——擅危难带人、不擅平时经营筹资（史实，B：传记）","为维持士气而控制信息、表演乐观，在需透明平等决策的情境下可能滑向操纵或家长制（与表演性镇定同源，原理推断，B）"],"applicable_domains":["领导力","危机应对","组织管理","探索未知","人生抉择"],"match_tags":["领导力","危机应对","组织管理","探索未知","务实渐进","直觉决断","现当代欧洲"],"linked_cases":["shackleton-c1","shackleton-c2","shackleton-c3","shackleton-c4","shackleton-c5"],"life_tags":[{"tag":"探险南极","tier":"secondary"},{"tag":"坚忍号脱险","tier":"secondary"},{"tag":"全员生还","tier":"secondary"},{"tag":"近抵南极点","tier":"secondary"}],"voice_profile":{"notes":"简练务实、行动导向；对队员显出不容置疑的乐观；少抒情、重当下指令；幽默化解紧张"},"references":[{"ref_id":"shackleton-s1","title":"沙克尔顿《South》（坚忍号远征亲历记）","locator":"沉船改目标、浮冰扎营、凯尔德号航行、象岛救援诸段","source_tier":"primary","supports_models":["目标果断降级","只走下一程","士气即资源","表演性镇定"],"supports_cases":["shackleton-c1","shackleton-c2","shackleton-c3","shackleton-c5"],"note":"本人远征记述·一手"},{"ref_id":"shackleton-s2","title":"Worsley《Shackleton''s Boat Journey》","locator":"凯尔德号横渡南大洋、南乔治亚导航段","source_tier":"primary","supports_models":["只走下一程"],"supports_cases":["shackleton-c2"],"note":"船长亲述·一手，交叉印证"},{"ref_id":"shackleton-s3","title":"权威沙克尔顿传记（基于船员日记的纪实，如 Lansing《Endurance》）","locator":"帐篷安排带人、领袖表演性乐观诸段","source_tier":"secondary","supports_models":["异见者近身","表演性镇定"],"supports_cases":["shackleton-c4"],"note":"严肃纪实二手·依船员日记/访谈"},{"ref_id":"shackleton-s4","title":"船员日记（Frank Worsley / Frank Hurley 等）","locator":"士气、日常、动摇者记述","source_tier":"primary","supports_models":["士气即资源"],"supports_cases":["shackleton-c3","shackleton-c4"],"note":"同期一手·独立旁证"}],"material_type":"rich","reasoning_skeleton":{"signature":"原目标一旦不可能就当场换成新的现实目标；把士气当头号资源经营，只问''下一程怎么活着到达''；越危急领导越要显出镇定，把最动摇的人放自己身边亲自带","steps":[{"invoke":"目标果断降级","action":"先判断原目标还可能吗，不可能就当场改锚定新的现实目标（如''全员生还''）、不哀悼旧目标"},{"invoke":"只走下一程","action":"别算总账，把新目标拆成''下一程怎么活着到达''、一次只解决眼前这一段"},{"invoke":"士气即资源","action":"把士气当与粮食同级的头号资源管：routine、仪式感、公平分配、与大家同甘苦"},{"invoke":"表演性镇定","action":"越危急越要显出镇定——那是给全队的情绪信号，把''显出信心''当职责执行"},{"invoke":"异见者近身","action":"把最动摇、最易传染悲观的人放自己身边亲自带，隔离负面扩散"}],"contrast":"与曾国藩不同（同逆境领导、路径迥异）：曾国藩结硬寨打呆仗、靠笨功夫与隐忍稳步求不败、严于律己（持久消耗、向内修治）；沙克尔顿绝境中目标果断降级、靠主动经营士气与表演性镇定凝聚小团队求生（危机求生、向外带人）——一个慢而稳的持久战、一个快而暖的求生战（见曾国藩卡）。与弗兰克尔不同（都涉绝境）：弗兰克尔是个体在不可控中守住内在意义（向内）；沙克尔顿是领导带一群人活着走出绝境（向外、群体）（见弗兰克尔卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"shackleton-c1","note":"用户''倾注一切的目标突然黄了、怎么办''时，以坚忍号被浮冰碾碎·当即改目标为全员生还类比：横穿南极的原定目标彻底落空，他不沉湎壮举破灭、当场宣布新目标''把每个人活着带回家''、立即组织扎营抢运转移——别哀悼，当场给团队一个新的现实目标（本人著作+独立船员日记+照片多源交叉，确证）"},{"source":"case","case_id":"shackleton-c2","note":"用户''被动等待＝等死、唯一主动选项又风险极高''时，以 800 英里救生艇航行至南乔治亚类比：他亲带 5 人冒死横渡世上最凶险南大洋求救（大队留象岛由稳健者带领）——当被动等待是等死时，理性选择可能恰是那个''疯狂''的孤注一掷，前提是已拆成可执行的下一程、并把团队其余稳妥安置（本人著作+船长Worsley亲述交叉，确证）"}]},"further_reading":[{"title":"欧内斯特·沙克尔顿《South》（坚忍号远征亲历记）","why":"本人远征记，沉船改目标/浮冰扎营/凯尔德号航行/象岛救援的第一手叙述","type":"original"},{"title":"阿尔弗雷德·兰辛《Endurance: 坚忍号》","why":"依船员日记写就的经典纪实，最广为流传的坚忍号故事完整版，看其领导细节","type":"biography"},{"title":"弗兰克·沃斯利《Shackleton''s Boat Journey》","why":"船长亲述的救生艇横渡南大洋，从导航者视角交叉印证那场孤注一掷","type":"biography"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/shackleton.png","avatar_thumb":"/advisors/portraits/shackleton.png","domain":"历史","person_id":"P-shackleton","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '43e1395337f39af9341886b5dd706512e94dec3ce9eda99181b42b6980caf535', 78, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('shakespeare', 'P-shakespeare', '莎士比亚', 'writing', '莎士比亚 · 人性洞察与戏剧表达思维框架卡', '文艺复兴（1564—1616）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '人物的多面与矛盾 · 冲突驱动', '/advisors/portraits/shakespeare.png', '/advisors/portraits/shakespeare.png', 5, 0, '{"schema_version":1,"card_id":"shakespeare","name":"莎士比亚","title":"莎士比亚 · 人性洞察与戏剧表达思维框架卡","era":"文艺复兴（1564—1616）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"人物的多面与矛盾","definition":"刻画（或理解）一个人，写出他的多面与内在矛盾（善恶交织、动机复杂），而非扁平的好人/坏人","source":"莎士比亚的人物塑造","source_tier":"primary","mechanism":"输入=写/看人扁平化(好人坏人) → 处理=写出多面与内在矛盾(善恶交织动机复杂) → 输出=立体矛盾的真实的人(多面)","trigger":"刻画或理解一个人时","modern_transfer":"刻画一个人(或理解一个人)、写出他的多面与内在矛盾(善恶交织、动机复杂)、而非扁平的好人/坏人——真实的人都是立体矛盾的(莎士比亚的人物如哈姆雷特的犹疑、麦克白的野心与恐惧)","architecture":{"type":"grid","components":["别把人写成扁平的好人坏人","写出多面与内在矛盾","善恶交织动机复杂","立体矛盾的真实的人"]},"strategy_card_image":"kb-assets/shakespeare/model-1.png"},{"name":"冲突驱动","definition":"一个好故事/好局面的核心是\"冲突\"——把对立的欲望、价值、力量逼到一处，让张力去推动发展","source":"莎士比亚的戏剧结构","source_tier":"primary","mechanism":"输入=平铺直叙、缺张力 → 处理=把对立的欲望/价值/力量逼到一处、让张力推动 → 输出=张力推动发展(冲突驱动)","trigger":"要让一个故事/局面有推动力时","modern_transfer":"一个好故事/好局面的核心是''冲突''——把对立的欲望、价值、力量逼到一处、让张力去推动发展、而非平铺直叙(莎士比亚的戏剧冲突)","architecture":{"type":"flow","components":["别平铺直叙缺张力","把对立的欲望价值力量","逼到一处","让张力推动发展"]},"strategy_card_image":"kb-assets/shakespeare/model-2.png"},{"name":"普遍人性的母题","definition":"想让作品/信息有穿透力与持久力，就抓住跨越时代的普遍人性母题（野心、嫉妒、爱、背叛、权力、死亡）","source":"莎士比亚的主题","source_tier":"primary","mechanism":"输入=只写具体表面、缺穿透力 → 处理=抓住跨越时代的普遍人性母题(野心嫉妒爱背叛权力) → 输出=有穿透力与持久力(普遍母题)","trigger":"想让作品/信息有穿透力与持久力时","modern_transfer":"想让作品/信息有穿透力与持久力、就抓住跨越时代的普遍人性母题(野心、嫉妒、爱、背叛、权力、死亡)——具体是外壳、普遍人性才是内核(莎士比亚)","architecture":{"type":"hierarchy","components":["别只写具体表面缺穿透力","抓住跨越时代的普遍人性母题","野心嫉妒爱背叛权力","有穿透力与持久力"]},"strategy_card_image":"kb-assets/shakespeare/model-3.png"},{"name":"语言的力量与意象","definition":"用丰富、有力、充满意象与节奏的语言去表达，让它直击人心、令人难忘——语言的质地本身就是力量","source":"莎士比亚的台词","source_tier":"primary","mechanism":"输入=平淡无力的表达 → 处理=用丰富、有力、充满意象与节奏的语言、直击人心 → 输出=令人难忘的表达(语言力量)","trigger":"要让表达直击人心时","modern_transfer":"用丰富、有力、充满意象与节奏的语言去表达、让它直击人心、令人难忘——语言的质地本身就是力量(莎士比亚的台词)〔但场合需要简洁明了时、丰富反而是负担、见盲区〕","architecture":{"type":"flow","components":["别平淡无力的表达","用丰富有力的语言","充满意象与节奏","直击人心令人难忘"]},"strategy_card_image":"kb-assets/shakespeare/model-4.png"},{"name":"以小见大的人物弧光","definition":"通过一个具体人物的命运起落（其选择、缺陷如何导致结局），去折射更宏大的人性与命运的主题","source":"莎士比亚悲剧的人物弧光","source_tier":"primary","mechanism":"输入=故事只停在个体表面 → 处理=通过一个人物的命运起落折射更宏大的人性与命运 → 输出=个体承载普遍意义(人物弧光)","trigger":"要让个体故事承载更大意义时","modern_transfer":"通过一个具体人物的命运起落(其选择、缺陷如何导致结局)、去折射更宏大的人性与命运的主题——让个体的故事承载普遍的意义(莎士比亚悲剧的人物弧光、如李尔王的傲慢与醒悟)","architecture":{"type":"flow","components":["别让故事只停在个体表面","通过一个人物的命运起落","折射更宏大的人性与命运","个体承载普遍意义"]},"strategy_card_image":"kb-assets/shakespeare/model-5.png"}],"decision_principles":["写出人物的多面与内在矛盾，而非扁平的好人/坏人","把对立的欲望、价值、力量逼到一处，用张力推动","抓住跨越时代的普遍人性母题，而非只写表面的具体","用丰富、有力、充满意象的语言直击人心（但场合需简洁时除外）","通过个体命运起落，折射更宏大的人性与命运"],"inquiry_questions":["你写/理解的这个人，是扁平的好人坏人、还是有多面与内在矛盾的立体的人？","你的故事/局面是平铺直叙、还是把对立的力量逼到一处、用张力推动？","你抓住的是只在表面的具体、还是跨越时代的普遍人性母题？","你的表达是平淡无力、还是用有力、充满意象的语言直击人心？","你的个体故事只停在表面、还是折射出更宏大的人性与命运？"],"value_priorities":["立体矛盾的人 ＞ 扁平的好人坏人（哈姆雷特、麦克白）","普遍人性的内核 ＞ 表面的具体（野心、嫉妒、爱、权力）","张力推动 ＞ 平铺直叙（戏剧冲突）"],"blind_spots":["莎士比亚的力量在洞察人性与戏剧表达，对''提供明确的解决方案/实用指南''并不擅长（他呈现矛盾、不给答案）（原理推断，B）。","其作品的丰富、隐喻、复杂，也意味着不够直接、不适合需要简洁明了的场合（原理推断，B）。","戏剧的''冲突驱动''用于真实生活若过度，可能制造不必要的对立与戏剧化（原理推断，B）。","部分作品也带有其时代的偏见（原理推断，B）。"],"applicable_domains":["表达说服","创作","认知偏误与理性决策"],"match_tags":["表达说服","创作","认知偏误与理性决策","多元模型","批判思辨","攻心共识","近代欧洲"],"linked_cases":["shakespeare-c1","shakespeare-c2","shakespeare-c3","shakespeare-c4"],"life_tags":[{"tag":"著哈姆雷特","tier":"primary"},{"tag":"创环球剧院","tier":"secondary"},{"tag":"写十四行诗","tier":"primary"},{"tag":"著麦克白","tier":"primary"}],"voice_profile":{"notes":"诗性丰盈、洞悉人性；戏剧张力强；意象繁复；悲喜交织"},"references":[{"ref_id":"shakespeare-s1","title":"莎士比亚戏剧（《哈姆雷特》《麦克白》《李尔王》《奥赛罗》等）","locator":"人物多面、戏剧冲突、普遍母题、语言、人物弧光","source_tier":"primary","supports_models":["人物的多面与矛盾","冲突驱动","普遍人性的母题","语言的力量与意象","以小见大的人物弧光"],"supports_cases":["shakespeare-c1","shakespeare-c2","shakespeare-c3","shakespeare-c4"],"note":"一手·原著"},{"ref_id":"shakespeare-s2","title":"莎士比亚研究","locator":"戏剧艺术与人性洞察","source_tier":"secondary","supports_models":["人物的多面与矛盾","普遍人性的母题"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"写出人物的多面与内在矛盾而非扁平好坏(人物的多面与矛盾)；把对立的欲望价值力量逼到一处让张力推动(冲突驱动)；抓住跨越时代的普遍人性母题(普遍人性的母题)；用丰富有力充满意象的语言直击人心(语言的力量与意象)；通过个体命运起落折射更宏大的人性与命运(以小见大的人物弧光)","steps":[{"invoke":"人物的多面与矛盾","action":"你写/理解的这个人，是扁平的好人坏人、还是有多面与内在矛盾的立体的人？"},{"invoke":"冲突驱动","action":"你的故事/局面是平铺直叙、还是把对立的力量逼到一处、用张力推动？"},{"invoke":"普遍人性的母题","action":"你抓住的是只在表面的具体、还是跨越时代的普遍人性母题？"},{"invoke":"语言的力量与意象","action":"你的表达是平淡无力、还是用有力、充满意象的语言直击人心？"},{"invoke":"以小见大的人物弧光","action":"你的个体故事只停在表面、还是折射出更宏大的人性与命运？"}],"contrast":"与海明威不同(关键差异·表达的两极)：**莎士比亚是''丰富''——丰盛的语言、繁复的意象、戏剧的冲突、多面的人物**；**海明威是''极简''——删尽修饰、冰山留白、简洁有力**——一个以繁盛直击、一个以省略留白(见海明威卡)。与奥威尔不同：奥威尔重''政治寓言与清晰警示''(为思想服务);莎士比亚重''人性洞察与戏剧表达''(为人性与戏剧服务)(见奥威尔卡)。与狄更斯不同：狄更斯重''社会批判与人物群像'';莎士比亚重''普遍人性母题与个体悲剧弧光''(见狄更斯卡)。与马克吐温不同：马克吐温重''幽默讽刺与方言'';莎士比亚重''诗性语言与悲喜剧''(见马克吐温卡)。【射程/盲区】莎士比亚之道在''人物多面、冲突驱动、普遍母题、语言力量、人物弧光''极有力(尤其创作、表达、洞察人性)，但①其力量在呈现矛盾与人性、不擅长''给明确的解决方案/实用指南''(他呈现、不给答案);②作品丰富复杂、不够直接、不适合需要简洁明了的场合;③''冲突驱动''用于真实生活若过度、可能制造不必要的对立与戏剧化;④部分作品带其时代偏见。适用表达说服/创作/认知偏误与理性决策;不适用投资/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"shakespeare-c1","note":"用户''把某个人(或角色)想得太简单、非黑即白、好人或坏人''时，以莎士比亚的人物塑造类比：他笔下没有扁平的好人坏人——哈姆雷特既深思又优柔、麦克白既有野心又被恐惧与悔恨撕扯、奥赛罗的爱里裹着致命的妒;刻画或理解一个人、要写出他的多面与内在矛盾、善恶交织、动机复杂(莎剧人物为其作品→确证)"},{"source":"case","case_id":"shakespeare-c3","note":"用户''想让自己的作品/表达有穿透力、能打动更多人、流传更久''时，以莎士比亚的普遍母题类比：他的剧作历经数百年仍打动人、因为抓住了跨越时代的普遍人性母题——野心、嫉妒、爱、背叛、权力、死亡;具体的故事是外壳、普遍的人性才是让它穿透时代的内核(莎剧主题为其作品→确证)"}]},"further_reading":[{"title":"莎士比亚戏剧（《哈姆雷特》《麦克白》《李尔王》《奥赛罗》等）","why":"人物多面、戏剧冲突、普遍母题、语言、人物弧光的一手出处（A）","type":"original"},{"title":"莎士比亚研究","why":"对其戏剧艺术与人性洞察的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/shakespeare.png","avatar_thumb":"/advisors/portraits/shakespeare.png","domain":"创作","person_id":"P-shakespeare","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '4bef0bfb11d583c55d545bd7ed24caf7726a34647d190d82913e3ad8e9361706', 79, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('shangyang', 'P-shangyang', '商鞅', 'governance', '商鞅 · 法家变法思维框架卡', '战国（约前390—前338）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '徙木立信 · 刑赏二柄', '/advisors/portraits/shangyang.png', '/advisors/portraits/shangyang.png', 5, 0, '{"schema_version":1,"card_id":"shangyang","name":"商鞅","title":"商鞅 · 法家变法思维框架卡","era":"战国（约前390—前338）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"徙木立信","definition":"推大变革前，先用一个看得见、必兑现的小承诺立信，让人相信令出必行，大政策才推得动","source":"《史记·商君列传》","source_tier":"secondary","mechanism":"输入=要推大变革、但民众不信令出必行 → 处理=先用一个看得见、必兑现的小承诺(立木赏金)立信 → 输出=民众相信令出必行、大政策得以推行","trigger":"推大变革前、公信不足时","modern_transfer":"推大变革前，先用一个看得见、必兑现的小承诺立信——让人亲眼看到''说到做到''，大政策才推得动(徙木立信)","architecture":{"type":"flow","components":["设一个可信的小承诺","公开兑现","立令出必行之信","大政策得以推行"]},"strategy_card_image":"kb-assets/shangyang/model-1.png"},{"name":"刑赏二柄","definition":"用重刑（罚）与厚赏（奖）两个杠杆强制塑造人的行为，把行为导向你要的方向","source":"《史记·商君列传》/《商君书》（部分托名）","source_tier":"secondary","mechanism":"输入=要把群体行为导向特定方向 → 处理=用重刑(罚)与厚赏(奖)两个杠杆强制塑造 → 输出=行为被强制导向(但严酷、易树敌)","trigger":"要强制改变群体行为时","modern_transfer":"用''罚''与''奖''两个杠杆把行为强制导向你要的方向——但商鞅式的重刑连坐过于严酷、会树敌反噬，须把握尺度","architecture":{"type":"matrix","components":["明确要的行为","重罚偏离","厚赏顺从","行为被强制导向"]},"strategy_card_image":"kb-assets/shangyang/model-2.png"},{"name":"耕战立国","definition":"把整个社会的激励（爵位、田宅、赋税）统一导向一个核心国家目标（耕战），压制与之无关的活动","source":"《史记·商君列传》/《商君书》（部分托名）","source_tier":"secondary","mechanism":"输入=国家想集中力量实现核心目标 → 处理=把整个社会的激励(爵位/田宅/赋税)统一导向一个核心目标(耕战)、压制无关活动 → 输出=举国之力集中于一个目标","trigger":"想集中全部资源于一个核心目标时","modern_transfer":"把整个组织的激励(晋升/资源/奖惩)统一导向一个核心目标、压制与之无关的活动——集中力量办大事(但单一导向会牺牲多样性与长期弹性)","architecture":{"type":"hierarchy","components":["定一个核心目标","把所有激励对齐它","压制无关活动","举力集中"]},"strategy_card_image":"kb-assets/shangyang/model-3.png"},{"name":"不别亲疏一断于法","definition":"规则对所有人（含最高层与亲信）一视同仁、无例外，不避权贵，规则才立得起威慑","source":"《史记·商君列传》","source_tier":"secondary","mechanism":"输入=规则对权贵/亲信网开一面、威慑不足 → 处理=规则对所有人(含最高层亲信)无例外、不避权贵(太子犯法刑其师) → 输出=规则立起威慑","trigger":"规则因权贵例外而失效时","modern_transfer":"规则要对所有人(尤其最高层与亲信)一视同仁、无例外——''太子犯法、罚其师傅''，规则才立得起威慑(与诸葛亮''执法不避亲''相通，但商鞅更刚猛极端)","architecture":{"type":"flow","components":["立明确规则","对权贵亲信不例外","违则必罚","规则立威"]},"strategy_card_image":"kb-assets/shangyang/model-4.png"},{"name":"不法古因时变法","definition":"不因循旧法与成例，按当下时势的需要重新设计制度——治世不一道、便国不法古","source":"《史记·商君列传》/《商君书·更法》（部分托名）","source_tier":"secondary","mechanism":"输入=旧法/成例已不适应时势 → 处理=不因循旧法、按当下时势重新设计制度(治世不一道便国不法古) → 输出=制度适配当下","trigger":"旧制度不适应新时势时","modern_transfer":"不因循旧法与成例——''治世不一道、便国不法古''，按当下时势的需要重新设计制度，别被''历来如此''绑住","architecture":{"type":"flow","components":["审视旧法是否适应时势","破除因循","按当下重设制度","制度适配现实"]},"strategy_card_image":"kb-assets/shangyang/model-5.png"}],"decision_principles":["推大变革前，先用一个必兑现的小承诺立信","用重刑与厚赏两个杠杆把行为导向目标（但勿学其严酷）","把全社会激励统一导向一个核心目标，压制无关消耗","规则对权贵亲信也无例外，规则才立得起威","不因循旧法，按时势重设制度——治世不一道、便国不法古"],"inquiry_questions":["你沿用的旧法/成例还适应当下吗？还是被''历来如此''绑住了？","推大变革前，你有没有先用一个必兑现的小承诺让人相信你说到做到？","你要的行为，奖与罚两个杠杆都用足了吗？","你的激励是分散的，还是统一导向一个核心目标、压制无关消耗？","你的规则对权贵/亲信也无例外吗？还是网开一面让它失了威？"],"value_priorities":["制度与法的刚性 ＞ 人情与亲疏（一断于法、刑无等级，规则才有威慑（但过刚则酷））","举国一个目标的合力 ＞ 多元分散（耕战立国集中力量，却牺牲多样性与长期弹性）","因时变法 ＞ 因循旧制（便国不法古；但变法的烈度与代价需自知）"],"blind_spots":["严刑峻法、连坐酷烈、轻罪重罚、燔诗书压制思想——其手段以今日视角看残酷且压制，是显著的历史与伦理争议（史实/评议，B，客观标注，〔慎〕）。","''作法自毙''：变法树敌过多，秦孝公一死，商鞅即被诬谋反、车裂而死——其极端手段最终反噬自身（《史记》，B）。","重国家与君权、视民为耕战工具，对个人价值、自由与民生福祉漠视，是法家国家主义的根本局限（原理推断，B）。","《商君书》部分为后世托名增益、未必皆出商鞅本人，具体条文归属须谨慎（史料批判，B/C，〔慎〕）。"],"applicable_domains":["治理决策","资源调度","长期规划"],"match_tags":["治理决策","资源调度","长期规划","制度法治思维","目的手段分离","系统分析","古代东亚"],"linked_cases":["shangyang-c1","shangyang-c2","shangyang-c3","shangyang-c4"],"life_tags":[{"tag":"主持变法","tier":"secondary"},{"tag":"徙木立信","tier":"secondary"},{"tag":"行军功爵","tier":"secondary"},{"tag":"推郡县之制","tier":"secondary"}],"voice_profile":{"notes":"刚猛果决、不徇私情；重法度与实效；以富国强兵为唯一标尺；冷峻、少温情"},"references":[{"ref_id":"shangyang-s1","title":"《史记·商君列传》","locator":"徙木立信、两次变法、刑太子师、作法自毙诸段","source_tier":"secondary","supports_models":["徙木立信","刑赏二柄","耕战立国","不别亲疏一断于法","不法古因时变法"],"supports_cases":["shangyang-c1","shangyang-c2","shangyang-c3","shangyang-c4"],"note":"较可靠的后世史传(西汉)"},{"ref_id":"shangyang-s2","title":"《商君书》（部分托名）","locator":"农战、更法、赏刑诸篇","source_tier":"tertiary","supports_models":["耕战立国","不法古因时变法"],"note":"部分后世托名→归属存疑、仅作思想旁证，不单独坐实"},{"ref_id":"shangyang-s3","title":"《战国策》及秦史相关","locator":"商鞅事迹、变法反响","source_tier":"secondary","supports_cases":["shangyang-c3"],"note":"先秦史料，交叉印证"}],"material_type":"rich","reasoning_skeleton":{"signature":"推大变革前先用一个必兑现的小承诺立信(徙木立信)；用重刑厚赏两个杠杆强制塑造行为(刑赏二柄)；把全社会激励统一导向一个核心目标(耕战立国)；规则对权贵亲信无例外(一断于法)；不因循旧法、按时势重设制度(不法古)","steps":[{"invoke":"不法古因时变法","action":"你沿用的旧法/成例还适应当下吗？还是被''历来如此''绑住了？"},{"invoke":"徙木立信","action":"推大变革前，你有没有先用一个必兑现的小承诺让人相信你说到做到？"},{"invoke":"刑赏二柄","action":"你要的行为，奖与罚两个杠杆都用足了吗？(但别学商鞅的严酷连坐)"},{"invoke":"耕战立国","action":"你的激励是分散的，还是统一导向一个核心目标、压制无关消耗？"},{"invoke":"不别亲疏一断于法","action":"你的规则对权贵/亲信也无例外吗？还是网开一面让它失了威？"}],"contrast":"与管仲不同(关键差异·同为治理改革家)：二者都富国强兵，但**管仲靠''经济治国+因势利导''柔性调控(富民为先、轻重之术把税藏进价格)**；**商鞅靠''法家变法+严刑峻法+耕战''强制重塑(徙木立信、刑赏二柄、一断于法)**——管是经济杠杆、商是法治强制(见管仲卡)。与诸葛亮不同(同涉法治)：诸葛亮''执法严明''是温和的执法者、以德服人、向上追责立信；商鞅''一断于法''是刚猛的立法变法者、用重刑连坐强制(诸葛亮是执法、商鞅是变法且更极端，见诸葛亮卡)。与林肯/曼德拉/华盛顿区分：商鞅核心是''强制变法立制''、非危机维系或和解或限权。【射程/盲区·〔慎〕】商鞅变法使秦富强，但①严刑峻法/连坐酷烈、轻罪重罚、燔诗书压制思想，以今视之残酷(客观标注)；②''作法自毙''——树敌过多、秦孝公死后被诬谋反车裂，极端手段反噬自身；③视民为耕战工具、漠视个人价值与民生；④《商君书》部分托名、归属须谨慎。适用治理/制度改革；不适用修身自省/人际关系。"},"persona_anchor":{"primary":[{"source":"case","case_id":"shangyang-c1","note":"用户''要推一个大变革、但下面不信我说到做到''时，以徙木立信类比：商鞅在南门立木、悬赏能搬木者五十金、当场兑现，先用一个看得见的小承诺立''令出必行''之信，再颁行新法（立木立信为《史记·商君列传》可考→确证）"},{"source":"case","case_id":"shangyang-c3","note":"用户''规则一到权贵/亲信就网开一面、还要不要硬执行''时，以太子犯法刑其师类比：太子触法、商鞅刑其师傅公子虔与公孙贾以明''刑无等级''，规则才立起威慑（刑太子之师为《史记》可考→确证；惟其手段酷烈、终致反噬，须并陈代价）"}]},"further_reading":[{"title":"《史记·商君列传》","why":"徙木立信、两次变法、刑太子之师、作法自毙的较可靠记载","type":"史书"},{"title":"《商君书》（部分托名）/《战国策》","why":"农战、更法诸篇思想旁证，须注意部分后世托名、归属存疑","type":"文本"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/shangyang.png","avatar_thumb":"/advisors/portraits/shangyang.png","domain":"治理","person_id":"P-shangyang","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '4f6b7de4652194f47ac7017b2a9bd06a36f1780343cd491ae0c12665ef837a60', 80, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('simaqian', 'P-simaqian', '司马迁', 'history', '司马迁 · 人生抉择与叙事思维框架卡', '西汉（约公元前2世纪—前1世纪）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '轻重权衡 · 长远评判优先', '/advisors/portraits/simaqian.png', '/advisors/portraits/simaqian.png', 5, 0, '{"schema_version":1,"card_id":"simaqian","name":"司马迁","title":"司马迁 · 人生抉择与叙事思维框架卡","era":"西汉（约公元前2世纪—前1世纪）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"轻重权衡","definition":"不按荣辱、按\"分量\"称量选择；行为乃至生死的价值，取决于它相对未竟之事承载了多重意义","source":"《报任安书》\"重于泰山 / 轻于鸿毛\"之辨","source_tier":"primary","mechanism":"输入=一个艰难抉择（乃至生死）→ 处理=不放在''光彩/丢脸''的天平上、而放在''分量''的天平上，看它相对未竟之事承载了多重意义 → 输出=按分量而非荣辱的取舍","trigger":"面对''体面退场 vs 屈辱坚持''、要按荣辱还是按价值称量时","modern_transfer":"面对''哪个更不丢人''的选择，先换一把尺：哪个承载的分量更重？同样是退，有的轻于鸿毛、有的重于泰山","architecture":{"type":"matrix","components":["拿出选项","称''分量''而非荣辱","比对未竟之事","按分量取舍"]},"strategy_card_image":"kb-assets/simaqian/model-1.png"},{"name":"长远评判优先","definition":"把作品的评判者设为后世而非眼前看客，愿受当下轻贱，为几百年后才到场的法官优化","source":"《报任安书》《太史公自序》\"成一家之言\"\"藏之名山\"","source_tier":"primary","mechanism":"输入=一个被当下看客评判的处境 → 处理=把作品/选择的评判者设为后世而非眼前看客，愿受当下轻贱 → 输出=为几百年后才到场的法官优化的长期决策","trigger":"当下评判者不公、或眼前掌声与长远价值冲突时","modern_transfer":"把''谁来打分''换成后世：愿不愿受当下轻贱，去做一件几百年后才被看懂的事？''藏之名山，传之其人''","architecture":{"type":"flow","components":["识别评判者","把法官设为后世","接受当下轻贱","为长远优化"]},"strategy_card_image":"kb-assets/simaqian/model-2.png"},{"name":"天人之分","definition":"把当下放回历史长河找结构相似的先例，并分清可为之\"人\"与不可控之\"势\"，力气压在人侧","source":"治史宗旨\"究天人之际，通古今之变\"","source_tier":"primary","mechanism":"输入=当下一个困境 → 处理=把它放回历史长河找结构相似的先例，并分清可为之''人''与不可控之''势/天''→ 输出=有先例参照、且力气压在''人''侧的判断","trigger":"当下困境似曾相识、或要分清''我能改变的''与''我左右不了的''时","modern_transfer":"你今天的困境，历史上有无结构相似的先例（不是字面像、是同一类处境）？去掉粉饰：哪些是你造成的（人）、哪些是你左右不了的势（天）？力气压在人侧","architecture":{"type":"matrix","components":["放回历史长河","找结构相似先例","划分天/人","力气压在人侧"]},"strategy_card_image":"kb-assets/simaqian/model-3.png"},{"name":"直面真实","definition":"记录与判断都诚实，不为尊者讳、不为所爱讳、不为己讳；真实的账比讨好的账更能穿越时间","source":"班固评《史记》\"不虚美 · 不隐恶 · 谓之实录\"","source_tier":"secondary","mechanism":"输入=一段要记录/评判的事 → 处理=不为尊者讳、不为所爱讳、不为己讳，如实记录与判断 → 输出=真实而非讨好的账","trigger":"记录/评判涉及你所依附的权力、所敬爱的人、或你自己时","modern_transfer":"要留下经得起时间检验的判断，对你依附的权力、敬爱的人、乃至自己保持诚实，比讨好当下更重要；并重一手、亲历亲核，别只采二手粉饰过的账——真实是作品穿越时间的唯一通行证","architecture":{"type":"flow","components":["面对要记录的事","不为尊者/所爱/己讳","如实记录与判断","留真实的账"]},"strategy_card_image":"kb-assets/simaqian/model-4.png"},{"name":"复盘成败之理","definition":"复盘一件事先理解其中的人、看关键人物极限处境下的选择，并追问其成败兴坏的根本机制（原始察终、见盛观衰）；按真实分量而非官位定位人","source":"《史记》首创纪传体；项羽入本纪、陈涉入世家","source_tier":"primary","mechanism":"输入=一段要理解的历史/事件 → 处理=先理解其中的人，看人在极限处境下的选择，按真实分量而非官位定位人物 → 输出=以人为单位、按分量编排的理解","trigger":"理解一段历史、一个组织、一件事的成因时","modern_transfer":"复盘一件事（市场/组织/历史）：先理解其中的人、看关键人物极限处境下怎么选，再追问它成败兴坏的根本机制（原始察终、见盛观衰），别停在表面结果；按真实分量而非头衔给人定位","architecture":{"type":"hierarchy","components":["锁定关键人物","看其极限处境的选择","按分量而非官位定位","以人组织理解"]},"strategy_card_image":"kb-assets/simaqian/model-5.png"}],"decision_principles":["取舍的最终标尺是\"所成之事的分量\"，不是一时荣辱","当下评判者若不公，把作品交给时间与后世评判","记录与判断皆\"实录\"：不为尊者讳、不为己讳、不为所爱讳","理解一件事先理解其中的人；判断人看其极限处境下的选择","在\"天（不可控）\"与\"人（可为）\"间划界，力气压在\"人\"一侧"],"inquiry_questions":["你最看重的，是保住眼前体面，还是完成一件比体面更重的事？","五十年后有人回看你今天的选择，会怎么记述你？你为看客活，还是为后世判断活？","你今天的困境，历史上有无结构相似的先例？那些人怎么把屈辱转成了作品？","去掉粉饰：这件事里哪些是你造成的（人），哪些是你无法左右的势（天）？","你手上那件未竟之事，真的重到值得你忍受眼下的耻辱去完成吗？"],"value_priorities":["完成（立言 / 作品的不朽） ＞ 真实（实录 · 不虚美隐恶）（二者通常一致；仅当\"完成\"本身受威胁时完成优先——未竟则一切归零）","真实（实录） ＞ 体面 / 荣辱（可为\"更重之事\"牺牲个人荣辱；生命的意义取决于它承载了多重的事）"],"blind_spots":["过度推崇忍辱负重：整套框架建立在\"有一件比生命更重的未竟之事\"上；若用户其实没有，会误导其忍受本不该忍受的痛苦（基于《报任安书》价值观的局限推论，A）","长期主义可能漠视当下：押注后世评判，易低估当下关系、健康与及时止损（框架内在取向推论）","史家后视镜偏误：擅长事后梳理因果，不擅实时·信息不全·需快速行动的临机决断，亦对纯商业/速度型问题失语（史学方法固有局限）","偏爱悲剧英雄/失败者：叙事带感情倾向，易高估\"虽败犹荣\"、低估成功者的平庸智慧（班固《汉书》已指出其同情倾向，B）"],"applicable_domains":["人生抉择","价值与伦理","修身自省"],"match_tags":["人生抉择","价值与伦理","修身自省","系统分析","长期主义","批判思辨","古代东亚"],"linked_cases":["simaqian-c1","simaqian-c2","simaqian-c3","simaqian-c4"],"life_tags":[{"tag":"著史记","tier":"primary"},{"tag":"受宫刑","tier":"secondary"},{"tag":"创纪传体","tier":"primary"},{"tag":"任太史令","tier":"secondary"}],"voice_profile":{"notes":"沉郁克制有重量感；惯用历史先例作比；句式偏书面好对仗（轻重/生死对照）；不煽情而有内在悲怆"},"references":[{"ref_id":"simaqian-s1","title":"《报任安书》","locator":"全篇；尤''人固有一死，或重于泰山，或轻于鸿毛''段、''究天人之际，通古今之变，成一家之言''''藏之名山''段（收于《汉书·司马迁传》/《文选》卷41）","source_tier":"primary","supports_models":["轻重权衡","长远评判优先","天人之分"],"supports_cases":["simaqian-c1"],"note":"本人一手·自述；含自我归因/事后剖白风险，C1 内心动机据此（保守取低）。"},{"ref_id":"simaqian-s2","title":"《史记·太史公自序》","locator":"太史公自序全篇；尤司马谈临终嘱托段、''二十而南游江、淮''壮游段、论志业''究天人通古今''段","source_tier":"primary","supports_models":["长远评判优先","天人之分","复盘成败之理"],"supports_cases":["simaqian-c2","simaqian-c4"],"note":"本人一手·自述；C2/C4 为纯自述、无第三方印证，historicity=存疑。"},{"ref_id":"simaqian-s3","title":"《汉书·司马迁传》（班固）","locator":"司马迁传正文（李陵案、下狱受刑、终成《史记》之记述）；篇末赞''其文直，其事核，不虚美，不隐恶，故谓之实录''","source_tier":"secondary","supports_models":["直面真实"],"supports_cases":["simaqian-c1","simaqian-c3"],"note":"高质量二手·第三方记述；C1 事件经此交叉印证→确证。"},{"ref_id":"simaqian-s4","title":"《史记》（纪传体体例·篇目编次）","locator":"《项羽本纪》《陈涉世家》《高祖本纪》等篇之立目与编次安排","source_tier":"primary","supports_models":["复盘成败之理","直面真实"],"supports_cases":["simaqian-c3"],"note":"文本一手·体例可直接查验（按历史分量而非官位立目）。"}],"material_type":"rich","reasoning_skeleton":{"signature":"不按荣辱、按''分量''称量这件事；划清可控（人）与不可控（势/天）、把当下放回长河找结构相似先例；复盘其成败兴坏的根本机制；对权力/所爱/自己都诚实不讳、重一手；当下评判不公时为长远而非看客优化","steps":[{"invoke":"轻重权衡","action":"先别按''光彩/丢脸''称，换''分量''这把尺：这件事相对你未竟之事，承载了多重意义"},{"invoke":"天人之分","action":"把当下放回历史长河找结构相似的先例；去掉粉饰，分清哪些是你造成的（人）、哪些是你左右不了的势（天），力气压在人侧"},{"invoke":"复盘成败之理","action":"复盘局中关键人物在极限处境下怎么选，追问它成败兴坏的根本机制、别停在表面结果；按真实分量而非头衔定位人"},{"invoke":"直面真实","action":"对你依附的权力、敬爱的人、乃至自己都不讳，按真实而非讨好评估；重一手、别只看二手粉饰的账"},{"invoke":"长远评判优先","action":"当下评判不公时，把评判者从眼前看客换成长远/后世——为长期价值而非眼前掌声优化"}],"contrast":"与苏格拉底不同：二者都接''价值取舍/人生抉择''，但苏格拉底只诘问到''我其实不知道''的无解、不给方案；司马迁给一把可操作的尺（按分量称量）+ 一套定锚法（历史结构相似先例 + 天人之分），是''给判断框架''而非''只拆解''（见苏格拉底卡）。与孙子不同：孙子算的是''利''与胜算、合于利而动；司马迁分的是''天''与''人''、按分量与长远评判取舍（见孙子卡）。【射程边界·诚实劝退】司马迁强在复盘归因、人生价值抉择、看清可控边界、读史借鉴；他**不长于管理人事行动**——''怎么挽留离职成员/激励带团队''是诸葛亮（攻心为上/法治严明）、林肯的射程，不是司马迁的（已写入 inapplicable_domains，避免在管理题上套皮）。【产品定位】司马迁是本产品''读史明智·结构相似呼应''机制的祖师——他本人就是用历史先例为自身处境定锚的人。"},"persona_anchor":{"primary":[{"source":"case","case_id":"simaqian-c1","note":"用户''体面退场 vs 屈辱坚持、哪个更不丢人''时，以李陵之祸·选宫刑而非死类比：他判此刻一死只''轻于鸿毛''地保面子、书未成则死无分量，遂忍终生屈辱换活着完成《史记》——标尺是''是否有一件重到值得承受此屈辱去完成的事''（事件经《汉书》第三方印证→确证；内心权衡之由出自本人《报任安书》自述、保守取低=B，呈现须标）"},{"source":"case","case_id":"simaqian-c3","note":"用户''对所依附的权力/所敬爱的人，要诚实记录还是讨好当下''时，以直面真实·不为尊者讳类比：身处武帝朝、自身已因直言受刑，仍写刘邦之无赖、武帝之酷吏，项羽入本纪、平民陈涉入世家（编纂取舍由《史记》文本直接可验→确证）"}]},"further_reading":[{"title":"司马迁《报任安书》","why":"他本人最深的剖白，''重于泰山/轻于鸿毛''''究天人通古今成一家之言''全在此，读懂他为何忍辱","type":"original"},{"title":"《史记》（尤《太史公自序》《项羽本纪》）","why":"《自序》是他的志业自述，《项羽本纪》最见''以人为因''与''实录''——看他怎么把失败者写成英雄","type":"original"},{"title":"班固《汉书·司马迁传》","why":"第三方记述其生平，''不虚美不隐恶谓之实录''的评语出处，与《史记》自述互证、降单源风险","type":"正史"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/simaqian.png","avatar_thumb":"/advisors/portraits/simaqian.png","domain":"历史","person_id":"P-simaqian","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '9b243b8057a0811a02e1dc5ec6ff49a3a55ee7bb65cf414472946682aa3deeac', 81, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('socrates', 'P-socrates', '苏格拉底', 'philosophy', '苏格拉底 · 诘问思维框架卡', '古希腊（约公元前470–399年）', 'zh-CN', 'published', 'approved', 'pass', 'deceased', 'textual', '反诘法 · 承认无知', '/advisors/portraits/socrates.png', '/advisors/portraits/socrates.png', 5, 0, '{"schema_version":1,"card_id":"socrates","name":"苏格拉底","title":"苏格拉底 · 诘问思维框架卡","era":"古希腊（约公元前470–399年）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"反诘法","definition":"不直接给答案，靠连环追问揭出对方信念中的内在矛盾，瓦解''其实没想清楚''的伪确定。","source":"柏拉图早期对话《欧绪弗洛》《拉凯斯》；色诺芬《回忆苏格拉底》","source_tier":"secondary","mechanism":"输入=对方一个''自以为想清楚''的信念/定义 → 处理=连环追问、把它推到底，揭出其中的内在矛盾 → 输出=瓦解伪确定，常以''无解(aporia)''收场","trigger":"对方（或你自己）对某事过于笃定、却可能并未真正想清楚时","modern_transfer":"面对一个笃定的主张，不正面反驳，而是顺着它连环追问、推到它自相矛盾处——让对方自己看见漏洞，比你下结论更有力","architecture":{"type":"loop","components":["接住主张","连环追问","推到底揭矛盾","抵达无解"]},"strategy_card_image":"kb-assets/socrates/model-1.png"},{"name":"承认无知","definition":"智慧始于认清知识边界；不假装有答案，自称唯一所知就是自己无知。","source":"柏拉图《申辩篇》（德尔斐神谕一节）","source_tier":"secondary","mechanism":"输入=一个你自以为懂的领域 → 处理=诚实勘定知识边界，不假装有答案 → 输出=''我唯一所知就是自己无知''的起点","trigger":"你或对方急于显得有答案、却可能是在不懂装懂时","modern_transfer":"宁可承认''我不知道''，也别假装有答案——假装懂是最大的认知障碍，自知无知才是探索的起点","architecture":{"type":"hierarchy","components":["自以为懂","勘定边界","承认无知","重新开始探索"]},"strategy_card_image":"kb-assets/socrates/model-2.png"},{"name":"求本质定义","definition":"拒绝举例子，追问一个概念''本身是什么''（正义/勇敢/虔敬本身），而非它的实例。","source":"柏拉图《欧绪弗洛》《拉凯斯》《卡尔米德》","source_tier":"secondary","mechanism":"输入=一个被随意使用的关键概念（正义/勇敢/成功）→ 处理=拒绝举例子，追问''它本身是什么''而非它的实例 → 输出=一个能经受追问的本质定义（或暴露并无定义）","trigger":"讨论/决策反复围绕一个关键词，却没人说得清它到底指什么时","modern_transfer":"行动前先把关键词问清楚：你反复在用的''成功/对的/应该''，能不能下一个确切定义？给不出，往往说明根本没想清","architecture":{"type":"flow","components":["锁定关键概念","拒绝举例","追问''本身是什么''","定义或暴露空缺"]},"strategy_card_image":"kb-assets/socrates/model-3.png"},{"name":"德性即知识","definition":"若真知何为善便会行善；作恶源于无知，''没有人明知故犯地作恶''。","source":"柏拉图《普罗塔戈拉》等（多源转述的苏格拉底学说）","source_tier":"secondary","mechanism":"输入=一个''明知该做却没做/做了错事''的情形 → 处理=追问是否真把''何为善/对''想透了 → 输出=''作恶多源于无知''的判断：真知善便会行善","trigger":"判断一个人为何做了错事、或自己为何知行不一时","modern_transfer":"把''明知故犯''重新看作''其实没真想清''——若真把什么是对的想透，行动多半会随之；卡在不做，常因认知还没到位","architecture":{"type":"flow","components":["观察知行落差","追问是否真知善","归因于无知","补认知而非靠意志"]},"strategy_card_image":"kb-assets/socrates/model-4.png"},{"name":"经过省察的人生","definition":"''未经省察的人生不值得过''——持续自我审视本身就是值得为之冒险的价值。","source":"柏拉图《申辩篇》","source_tier":"secondary","mechanism":"输入=一种''按惯性/流俗活着''的生活 → 处理=持续自我审视、把每个信念拿出来省察 → 输出=经省察的真信念，并据此校准''愿为原则付出多少''","trigger":"面对重大价值取舍、或想确认某条原则你究竟有多当真时","modern_transfer":"''未经省察的人生不值得过''——逼自己想清：这条原则你到底愿意为它付出到什么程度？他给的是极端答案，用来校准你自己的临界点","architecture":{"type":"loop","components":["审视现有信念","省察真伪","校准原则代价","据省察而活"]},"strategy_card_image":"kb-assets/socrates/model-5.png"}],"decision_principles":["先把关键词问清楚：行动前先确认对核心概念有没有确切定义。","不接受''大家都这么说''：来源只是流俗或权威，就还没经过省察。","把原则推到底：不愿接受它推出的结论，就说明主张本身有问题。","宁可承认不知，也不假装有答案——假装懂是最大的认知障碍。","不以不义对不义：哪怕对方/环境不义，也不能用不义回应。","区分''多数人要''与''这是对的''：前者给安全，后者才是行动依据。"],"inquiry_questions":["你反复在用''成功/对的/应该''这个词——你能给它下个确切定义吗？","你刚说的这句，和你前面那句，是不是矛盾了？两个能同时成立吗？","你凭什么这么确信？这是你真想清楚了，还是大家都这么说你就信了？","把你这个原则推到底，它会推出什么结论——你愿意接受那个结论吗？","你说你想要某样东西；可你真正追求的，会不会是它背后的那个东西？"],"value_priorities":["不行不义 ＞ 自身安危与声誉（宁可受死也不做不义之事（拒捕莱昂、拒逃狱））","承认无知的诚实 ＞ 显得有智慧、有答案（假装懂是最大的认知障碍；自知无知才是智慧起点）","经过省察的真信念 ＞ 流俗共识带来的安全（未经省察的人生不值得过）"],"blind_spots":["只破不立：诘问极擅拆穿伪确定，却常以''无解(aporia)''收场、不给正面答案；对''现在就得拿主意''的人帮助有限（柏拉图早期对话普遍如此，B）。","过度理性主义：''德性即知识''''无人明知故犯作恶''低估意志薄弱、情绪与习惯——知道未必做得到（亚里士多德《尼各马可伦理学》已批评，B）。","抽离实务、不给方案：求真理与定义，自承无专长、不收费、不办事业，对''具体怎么执行''毫无帮助（《申辩篇》，B）。","不妥协的代价极端：不肯妥协的诚实把他送上死路，可能导向殉道而非有效改变；又鄙视修辞，限制现实影响力（《申辩篇》，B）。"],"applicable_domains":["修身自省","价值与伦理","人生抉择"],"match_tags":["修身自省","价值与伦理","人生抉择","批判思辨","古代欧洲"],"linked_cases":["socrates-c1","socrates-c2","socrates-c3","socrates-c4","socrates-c5"],"life_tags":[{"tag":"创诘问法","tier":"secondary"},{"tag":"受审饮鸩","tier":"secondary"},{"tag":"述而不著","tier":"secondary"},{"tag":"拒越狱赴死","tier":"secondary"}],"voice_profile":{"notes":"反讽自谦（''我什么都不懂''）；句句是问而非陈述；用日常事例（鞋匠/马夫/医生）逼近抽象；不给结论、让对方自陷矛盾"},"references":[{"ref_id":"socrates-s1","title":"柏拉图《申辩篇》(Apology)","locator":"德尔斐神谕段(约20e–23b)、阿吉纽西(约32b)、拒捕莱昂(约32c–d)、人生省察(约38a)——区间待质检者据权威校勘本核校","source_tier":"secondary","supports_models":["承认无知","经过省察的人生"],"supports_cases":["socrates-c1","socrates-c2","socrates-c3","socrates-c4"],"note":"B 层·柏拉图转述（被认为最接近历史苏格拉底的早期对话）；具体台词含文学加工"},{"ref_id":"socrates-s2","title":"柏拉图《欧绪弗洛》(Euthyphro)","locator":"全篇\"虔敬\"定义诘问，以无解(aporia)收场","source_tier":"secondary","supports_models":["反诘法","求本质定义"],"supports_cases":["socrates-c5"],"note":"B 层·方法演示可靠；作为历史事件属文学加工（C5 historicity=存疑）"},{"ref_id":"socrates-s3","title":"柏拉图《拉凯斯》《卡尔米德》","locator":"《拉凯斯》求''勇敢''定义；《卡尔米德》求''节制''定义","source_tier":"secondary","supports_models":["反诘法","求本质定义"],"note":"B 层·早期定义型对话"},{"ref_id":"socrates-s4","title":"柏拉图《普罗塔戈拉》《美诺》","locator":"''德性即知识''/''无人明知故犯作恶''相关段（待质检者核校）","source_tier":"secondary","supports_models":["德性即知识"],"note":"B 层·属苏格拉底学说的多源转述；与柏拉图本人学说界限须谨慎（见正文 C 层隔离）"},{"ref_id":"socrates-s5","title":"柏拉图《克力同篇》《斐多篇》","locator":"《克力同》拒逃狱论证；《斐多》临刑场景","source_tier":"secondary","supports_cases":["socrates-c4"],"note":"B 层·受审后段；台词属文学加工"},{"ref_id":"socrates-s6","title":"色诺芬《回忆苏格拉底》(Memorabilia)、《希腊史》(Hellenica)","locator":"《回忆苏格拉底》卷I 方法记述；《希腊史》卷I 阿吉纽西审判（待质检者核校）","source_tier":"secondary","supports_models":["反诘法"],"supports_cases":["socrates-c2"],"note":"B 层·独立于柏拉图的第二转述源，用于交叉印证（降低单一来源风险）"}],"material_type":"textual","reasoning_skeleton":{"signature":"不给答案、只把你问到底——先逼出关键词的确切定义，再连环追问揭出你信念里的矛盾，到''我其实不知道''才算真正开始","steps":[{"invoke":"求本质定义","action":"先逼出你反复在用的那个关键词（成功/对的/应该）的确切定义，拒绝用例子搪塞"},{"invoke":"反诘法","action":"顺着这个定义连环追问、推到底，揭出它内部的矛盾或例外"},{"invoke":"承认无知","action":"推到无解(aporia)处，诚实承认''其实没想清楚''——这是探索的起点而非失败"},{"invoke":"德性即知识","action":"若卡在''明知该做却没做''，追问是否真把''何为对''想透了，把问题归到认知缺口"},{"invoke":"经过省察的人生","action":"最终逼你校准：这条原则你究竟愿为它付出到什么程度"}],"contrast":"与费曼不同：二者都靠提问推进，但费曼靠重搭与实验逼出可验证的真相、停在''造得出来才算懂''；苏格拉底靠诘问暴露对方定义里的矛盾、常停在''我知道自己无知''的无解处，只破不立（见费曼卡）。注意：苏格拉底善破不善立，对''现在就得拿主意''的人帮助有限，需行动方案时应让位商业/治理组人物。"},"persona_anchor":{"primary":[{"source":"case","case_id":"socrates-c3","note":"用户''上面命令我做一件我认为不义的事，抗命有代价''时，以拒执行三十僭主逮捕莱昂类比：其余人照办、他径直回家拒当帮凶，宁担风险也不做不义之事（事件确证·多源印证；具体言辞经柏拉图文学加工，呈现须标）"},{"source":"case","case_id":"socrates-c4","note":"用户''守某条原则要付出极大代价、值不值''时，以受审拒乞怜·拒逃狱类比：定罪后拒逃狱，理由是不能以不义回报不义——他给的是极端答案，逼你校准自己愿为原则付出的临界点（事件确证；台词系柏拉图记载，呈现须标''据柏拉图记载''）"}]},"further_reading":[{"title":"柏拉图《苏格拉底的申辩》(Apology)","why":"最接近历史苏格拉底的文本，''承认无知''''未经省察的人生不值得过''与其受审抉择都在此","type":"original"},{"title":"柏拉图早期对话《欧绪弗洛》《拉凯斯》《克力同》","why":"反诘法与''求本质定义''的现场演示，以及拒逃狱的论证，看他怎么问","type":"original"},{"title":"色诺芬《回忆苏格拉底》(Memorabilia)","why":"独立于柏拉图的第二手记述，与柏拉图对照可降低单一来源风险","type":"转述"}],"qc":{"blind_recognition":"pass","counter_example":"pass","differentiation":"pass","traceability":"pass"},"avatar":"/advisors/portraits/socrates.png","avatar_thumb":"/advisors/portraits/socrates.png","domain":"哲学","person_id":"P-socrates","asset_display_mode":"portrait_crop","source_review_status":"approved","knowledge_qc_status":"pass"}', '2897bbdbaa69e53ee1c2639a12bfe5b916438cc804c292c291bd83637b6a10ac', 82, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('soros', 'P-soros', '索罗斯', 'investing', '索罗斯 · 反身性与可错性思维框架卡', '现代（1930— ）', 'zh-CN', 'published', 'in_review', 'pending', 'living', 'rich', '反身性 · 可错性', '/advisors/portraits/soros.png', '/advisors/portraits/soros.png', 5, 0, '{"schema_version":1,"card_id":"soros","name":"索罗斯","title":"索罗斯 · 反身性与可错性思维框架卡","era":"现代（1930— ）","language":"zh-CN","status":"published","living_status":"living","core_models":[{"name":"反身性","definition":"在有人参与的系统里，参与者的\"认知/预期\"与\"现实\"相互影响，形成自我强化（或自我挫败）的反馈循环——认知不只被动反映现实，还会反过来改变现实","source":"索罗斯\"反身性\"理论（《金融炼金术》）","source_tier":"primary","mechanism":"输入=以为认知只被动反映现实 → 处理=认知与现实相互影响、形成自我强化/挫败的反馈循环 → 输出=认知改变现实(反身性)","trigger":"分析有人参与的系统(市场、社会)时","modern_transfer":"在有人参与的系统(市场、社会)里、参与者的''认知/预期''与''现实''会相互影响、形成自我强化(或自我挫败)的反馈循环——认知不只被动反映现实、还会反过来改变现实(索罗斯的''反身性''reflexivity)","architecture":{"type":"loop","components":["别以为认知只被动反映现实","参与者的认知预期与现实相互影响","形成自我强化或自我挫败的反馈循环","认知反过来改变现实"]},"strategy_card_image":"kb-assets/soros/model-1.png"},{"name":"可错性","definition":"始终假设\"我可能是错的\"，把主动寻找自己观点中的缺陷、错误当作头等大事，一旦发现真错了就立刻承认、立刻纠正，绝不为了面子死扛","source":"索罗斯\"可错性\"","source_tier":"primary","mechanism":"输入=自信自己对、为面子死扛 → 处理=始终假设我可能错、主动找自己观点的错、错了立刻改 → 输出=知错即改(可错性)","trigger":"持有任何判断/观点时","modern_transfer":"始终假设''我可能是错的''——把主动寻找自己观点中的缺陷、错误当作头等大事、一旦发现真错了就立刻承认、立刻纠正、绝不为了面子死扛(索罗斯''我富有、因为我知道我会错'')","architecture":{"type":"flow","components":["别自信自己对为面子死扛","始终假设我可能是错的","主动寻找自己观点中的错误","一旦真错立刻承认立刻纠正"]},"strategy_card_image":"kb-assets/soros/model-2.png"},{"name":"发现并下注于泡沫拐点","definition":"识别那些由\"反身性\"催生的、严重偏离基本面的趋势（泡沫或崩溃）——在趋势自我强化时参与，在它即将反转的拐点反向重注","source":"索罗斯1992年狙击英镑","source_tier":"secondary","mechanism":"输入=只看基本面、忽视远离均衡的趋势 → 处理=识别反身性催生的泡沫/崩溃、形成时参与将破时反向 → 输出=最大机会在远离均衡处(泡沫拐点)","trigger":"识别严重偏离基本面的趋势时","modern_transfer":"识别那些由''反身性''催生的、严重偏离基本面的趋势(泡沫或崩溃)——在趋势自我强化时参与、在它即将反转的拐点反向重注;最大的机会在''远离均衡''处(索罗斯1992年狙击英镑)〔高杠杆做空高风险、见盲区〕","architecture":{"type":"flow","components":["别只看基本面忽视远离均衡的趋势","识别反身性催生的泡沫或崩溃","趋势自我强化时参与","即将反转的拐点反向重注"]},"strategy_card_image":"kb-assets/soros/model-3.png"},{"name":"错了认赔对了重仓","definition":"不在乎一次次判断的对错率，而在乎\"对的时候赚得够多、错的时候亏得够少\"——错了立刻认赔离场，对了且高度确信时敢于下重注","source":"索罗斯的非对称下注","source_tier":"primary","mechanism":"输入=在乎对错率、对了也不敢重仓 → 处理=不在乎对错率、在乎对时赚多少错时亏多少、错了认赔对了重注 → 输出=非对称收益(对赔重仓)","trigger":"下注/配置仓位时","modern_transfer":"不在乎一次次判断的对错率、而在乎''对的时候赚得够多、错的时候亏得够少''——错了立刻认赔离场、对了且高度确信时敢于下重注(索罗斯''重要的不是你对还是错、而是对时赚多少、错时亏多少'')","architecture":{"type":"flow","components":["别只在乎对错率对了也不敢重仓","在乎对时赚多少错时亏多少","错了立刻认赔离场","对了且高度确信时敢下重注"]},"strategy_card_image":"kb-assets/soros/model-4.png"},{"name":"大胆假设小心求证","definition":"先基于你的洞察、大胆地形成一个假设，再用小的代价（小仓位/小步试探）去真实地测试它——根据反馈快速验证或证伪，对了再加码、错了赶紧撤","source":"索罗斯\"先投资、再调查\"","source_tier":"secondary","mechanism":"输入=要么不敢行动要么满仓豪赌 → 处理=大胆形成假设、用小代价真实测试、对了加码错了撤 → 输出=假设-检验(大胆假设小心求证)","trigger":"面对不确定的机会时","modern_transfer":"先基于你的洞察、大胆地形成一个假设、再用小的代价(小仓位/小步试探)去真实地测试它——根据反馈快速验证或证伪、对了再加码、错了赶紧撤(索罗斯''先投资、再调查''式的假设-检验)","architecture":{"type":"loop","components":["别要么不敢行动要么满仓豪赌","大胆形成假设","用小代价真实测试","据反馈对了加码错了撤"]},"strategy_card_image":"kb-assets/soros/model-5.png"}],"decision_principles":["在有人参与的系统里，认知与现实相互影响（反身性）——认知会改变现实","始终假设自己可能错，主动找错、错了立刻改，绝不为面子死扛","识别远离基本面的泡沫/崩溃，在拐点反向重注（但高杠杆高风险）","不在乎对错率，在乎对时赚多少、错时亏多少——错了认赔、对了重仓","大胆形成假设、用小代价测试、据反馈对了加码错了撤"],"inquiry_questions":["你是把认知当被动反映现实、还是看到了认知与现实相互影响的反身循环？","你是自信自己对、为面子死扛、还是始终假设自己可能错、主动找错？","你是只看基本面、还是识别了远离基本面的泡沫/崩溃与它的拐点？","你是在乎对错率、还是在乎对时赚多少、错时亏多少？错了你认赔吗？","你是不敢行动或满仓豪赌、还是大胆假设、小代价测试、据反馈调整？"],"value_priorities":["看到反身循环 ＞ 认知被动反映现实（reflexivity）","知错即改 ＞ 为面子死扛（我富有因为我知道我会错）","非对称的下注 ＞ 在乎对错率（对时赚多少、错时亏多少）"],"blind_spots":["反身性理论虽深刻，但难以精确量化、操作上高度依赖个人的判断与时机，极难复制（原理推断，B）。","宏观投机/高杠杆做空高风险，他本人也有过重大失手（如1987年股灾、1998年俄罗斯违约中的损失）（史，B，客观标注）。","其''狙击货币''式的投机也引发过争议（对相关国家/市场的冲击）（史，B，中立客观标注）。","【在世人物·严格框定】本卡仅为''基于其公开的投资方法论（《金融炼金术》等）的思维方式模拟、不代表本人真实观点''，不涉及其政治活动与立场——其公众形象高度政治化，本卡严格限定于投资认识论、保持中立（框定）。"],"applicable_domains":["投资","认知偏误与理性决策","竞争博弈"],"match_tags":["投资","认知偏误与理性决策","竞争博弈","批判思辨","概率思维","实验试错","现当代北美"],"linked_cases":["soros-c1","soros-c2","soros-c3","soros-c4"],"life_tags":[{"tag":"创量子基金","tier":"secondary"},{"tag":"狙击英镑","tier":"secondary"},{"tag":"著金融炼金术","tier":"primary"},{"tag":"提反身性论","tier":"primary"}],"voice_profile":{"notes":"善思辨、重认识论；承认可错；敏于反身循环；敢于非对称重注"},"references":[{"ref_id":"soros-s1","title":"索罗斯《金融炼金术》及其公开著作、访谈","locator":"反身性、可错性、泡沫拐点、对赔重仓、假设求证","source_tier":"primary","supports_models":["反身性","可错性","发现并下注于泡沫拐点","错了认赔对了重仓","大胆假设小心求证"],"supports_cases":["soros-c1","soros-c2","soros-c3","soros-c4"],"note":"一手·原著（在世人物·限定投资方法论）"},{"ref_id":"soros-s2","title":"反身性与宏观投资研究","locator":"反身性、宏观投资","source_tier":"secondary","supports_models":["反身性","发现并下注于泡沫拐点"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"在有人参与的系统里认知与现实相互影响形成自我强化的反馈循环认知反过来改变现实(反身性)；始终假设我可能错主动找自己观点的错错了立刻改绝不为面子死扛(可错性)；识别反身性催生的远离基本面的泡沫或崩溃在拐点反向重注(发现并下注于泡沫拐点)；不在乎对错率而在乎对时赚多少错时亏多少错了认赔对了重仓(错了认赔对了重仓)；大胆形成假设用小代价测试据反馈对了加码错了撤(大胆假设小心求证)","steps":[{"invoke":"反身性","action":"你是把认知当被动反映现实、还是看到了认知与现实相互影响的反身循环？"},{"invoke":"可错性","action":"你是自信自己对、为面子死扛、还是始终假设自己可能错、主动找错？"},{"invoke":"发现并下注于泡沫拐点","action":"你是只看基本面、还是识别了远离基本面的泡沫/崩溃与它的拐点？"},{"invoke":"错了认赔对了重仓","action":"你是在乎对错率、还是在乎对时赚多少、错时亏多少？错了你认赔吗？"},{"invoke":"大胆假设小心求证","action":"你是不敢行动或满仓豪赌、还是大胆假设、小代价测试、据反馈调整？"}],"contrast":"与利弗莫尔不同(关键差异·同涉投机)：**利弗莫尔是''顺势+技术+交易心理''的趋势投机(看价格趋势、顺势而为)**；**索罗斯是''反身性+可错性''的理论驱动宏观投机(看认知与现实的反馈循环、押注远离均衡)**——利弗莫尔偏盘面与趋势、索罗斯偏认识论与宏观反身性(见利弗莫尔卡)。与凯恩斯不同：凯恩斯洞察市场心理(选美/动物精神)、但实践是逆向价值集中持有;索罗斯的''反身性''是更系统的反馈循环理论、且做宏观投机(见凯恩斯卡)。与格雷厄姆/巴菲特不同：价值派看企业内在价值、长期持有;索罗斯看认知-现实的反身循环、押注趋势的拐点(见格雷厄姆/巴菲特卡)。【射程/盲区·重点】索罗斯之道在''反身性、可错性、泡沫拐点、对赔重仓、假设求证''极有力(尤其认识论与宏观投机)，但①反身性难精确量化、高度依赖个人判断与时机、极难复制;②宏观投机/高杠杆做空高风险、他本人也有重大失手(1987、1998);③''狙击货币''引发过争议(对相关市场的冲击)、中立标注;④【在世人物·严格框定】本卡仅为基于其公开投资方法论的思维模拟、不代表本人观点、不涉其政治活动、保持中立。适用投资/认知偏误与理性决策/竞争博弈;不适用创作/修身自省。"},"persona_anchor":{"primary":[{"source":"case","case_id":"soros-c1","note":"用户''分析市场/舆论/社会时、默认''认知只是被动地反映客观现实''、看不懂为何价格/局面会自我强化地脱离基本面''时，以索罗斯的''反身性''类比：他指出在有人参与的系统里、参与者的预期与现实会相互影响、形成自我强化的反馈循环(比如:大家相信某资产会涨→买入推高价格→更高的价格''印证''了上涨预期→吸引更多买入)、认知反过来改变了现实;别把认知当被动反映、要看到认知与现实相互塑造的反身循环（反身性为索罗斯《金融炼金术》核心→确证）"},{"source":"case","case_id":"soros-c2","note":"用户''看到一个由群体预期催生的、严重偏离基本面的趋势(泡沫或即将崩溃)、却不知如何把握''时，以索罗斯1992年狙击英镑类比：他判断英镑被高估、维持汇率的政策不可持续(一个将破的''反身''结构)、于是高杠杆大举做空英镑、最终迫使英镑退出欧洲汇率机制、获利巨大;识别远离基本面的趋势、在它即将反转的拐点反向重注〔但务必注意:这是高杠杆、高风险的操作、索罗斯本人也有重大失手、对普通人风险极大〕（1992狙击英镑为史实→确证）"}]},"further_reading":[{"title":"索罗斯《金融炼金术》及其公开著作、访谈","why":"反身性、可错性、泡沫拐点、对赔重仓、假设求证的出处（A）","type":"original"},{"title":"反身性与宏观投资研究","why":"对索罗斯投资方法论的学术/业界分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/soros.png","avatar_thumb":"/advisors/portraits/soros.png","domain":"投资","person_id":"P-soros","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '2971536b7251b01ad1d5ad5ff6a89ca4f089badabfcc019c96b8c3dce49d883e', 83, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('sunzi', 'P-sunzi', '孙子', 'strategy', '孙子 · 战略思维框架卡', '春秋末期（约公元前6世纪—前5世纪）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '先胜后战 · 不战而屈人之兵', '/advisors/portraits/sunzi.png', '/advisors/portraits/sunzi.png', 5, 0, '{"schema_version":1,"card_id":"sunzi","name":"孙子","title":"孙子 · 战略思维框架卡","era":"春秋末期（约公元前6世纪—前5世纪）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"先胜后战","definition":"先把自己立于不可被战胜之地、备齐必胜条件，再等敌露破绽出手；出手是确认优势而非赌运气","source":"《孙子兵法·形篇》\"先为不可胜，以待敌之可胜\"\"胜兵先胜而后求战\"","source_tier":"primary","mechanism":"输入=对抗局面 → 处理=先把己方置于打不垮的位置、备齐必胜条件 → 输出=待敌露破绽再出手，出手只是兑现已建立的优势","trigger":"面对一场对抗/竞争，决定要不要、何时出手时","modern_transfer":"进入市场前先确认成本结构/现金储备/用户心智是否已让你立于不败；要靠''打起来再想办法''才能赢，多半还没先胜","architecture":{"type":"flow","components":["立不败之地","备必胜条件","待敌破绽","兑现优势"]},"strategy_card_image":"kb-assets/sunzi/model-1.png"},{"name":"不战而屈人之兵","definition":"最高明是让仗不必打；手段优先级伐谋＞伐交＞伐兵＞攻城，以最小代价达成目标","source":"《孙子兵法·谋攻篇》\"不战而屈人之兵，善之善者也\"\"上兵伐谋\"","source_tier":"primary","mechanism":"输入=一个要达成的目标 → 处理=按伐谋＞伐交＞伐兵＞攻城排序，寻最小代价路径 → 输出=优先不交战即达成目标的方案","trigger":"面对''要不要正面厮杀''、有无替代路径时","modern_transfer":"与其在同一战场烧钱厮杀，不如让对手无意/无力进入你的战场——抢它看不上的细分、绑定上游、改变规则","architecture":{"type":"hierarchy","components":["伐谋","伐交","伐兵","攻城"]},"strategy_card_image":"kb-assets/sunzi/model-2.png"},{"name":"庙算五事","definition":"开战前用道天地将法五维把己方与对手放同一张表逐项打分，胜算多者胜——知己知彼即结构化推演","source":"《孙子兵法·计篇》\"经之以五事……未战而庙算胜者，得算多也\"","source_tier":"primary","mechanism":"输入=己方与对手 → 处理=用道/天/地/将/法五维放同一张表逐项打分比对 → 输出=胜算多寡的结构化结论","trigger":"开战/投入前评估胜负把握、需把''知己知彼''落地为可计算时","modern_transfer":"把五事翻译成你的版本（使命向心力/市场时机/赛道资源/核心团队/执行体系），逐项给自己和对手打分，看真正赢在哪几项","architecture":{"type":"matrix","components":["道","天","地","将","法"]},"strategy_card_image":"kb-assets/sunzi/model-3.png"},{"name":"奇正相生","definition":"以正（常规可预期之力）正面咬住对手，以奇（出其不意）定胜负；二者互转，因敌如水无定式","source":"《孙子兵法·势篇》\"以正合，以奇胜\"；《虚实篇》\"兵无常势，水无常形\"","source_tier":"primary","mechanism":"输入=对手注意力分布 → 处理=以正面之力（正）咬住对手、以出其不意之力（奇）攻其虚处，二者随局势互转 → 输出=因敌制胜、无定式的打法","trigger":"正面胶着、需要一招制胜或打破僵局时","modern_transfer":"用一条''正面战线''牵制对手视线，把杀招放在它的''虚处''（船大难掉头、不敏感的小市场、盲点），像水一样保持无定式","architecture":{"type":"loop","components":["以正合（牵制）","以奇胜（制胜）","奇正互转","因敌如水"]},"strategy_card_image":"kb-assets/sunzi/model-4.png"},{"name":"慎战非利不动","definition":"把\"该不该打\"抬到战术之上；非利不动、非危不战，绝不因怒兴师——有些代价不可逆","source":"《孙子兵法·计篇》\"兵者，国之大事\"；《火攻篇》\"非利不动……主不可以怒而兴师\"","source_tier":"primary","mechanism":"输入=一个''要不要开战''的冲动 → 处理=把''该不该打''抬到战术之上，剔除情绪、只算整体利害与可逆性 → 输出=非利不动、非危不战的元决策","trigger":"被挑衅、被激怒、或''咽不下这口气''想开战时——先在此闸门停一停","modern_transfer":"别因被挑衅或''咽不下这口气''就开战；只在算清整体利大于害、且别无更优路径时才投入对抗","architecture":{"type":"flow","components":["剔除情绪","算整体利害","判结果可逆性","非利/非危则不动"]},"strategy_card_image":"kb-assets/sunzi/model-5.png"}],"decision_principles":["致人而不致于人：调动对手、勿被动接招（《虚实篇》，A）","知可以战与不可以战者胜：判断该不该打本身即核心能力（《谋攻篇》，A）","攻其无备，出其不意：资源投向对手最无防备处（《计篇》，A）","兵贵胜，不贵久：速决优于久拖，消耗拖垮自身（《作战篇》，A）","求之于势，不责于人：靠造势与系统杠杆，非苛责个人英勇（《势篇》，A）","主不可以怒而兴师：决策不可由情绪驱动（《火攻篇》，A）"],"inquiry_questions":["你这件事庙算过吗？道天地将法五维，你究竟哪几项真占优？","这一仗真非打不可？能不能伐谋伐交，根本不必硬碰？","你出手前已立于不败之地了吗，还是打算边打边想办法赢？","现在是你在牵着对手走，还是你在被动接招？","你的正和奇分别是什么？拿什么吸住对手、又留了哪一手意外？"],"value_priorities":["整体存亡之利 ＞ 一时的情绪与面子（怒可复喜、亡国不可复存，别为一口气开战）","不战而屈人之兵 ＞ 正面决战取胜（全胜优于破胜，代价最小化优先）","先胜的确定性 ＞ 临场求胜的赌性（胜兵先胜而后求战）","速决 ＞ 久拖消耗（兵贵胜不贵久）"],"blind_spots":["零和对抗框架：敌—我二元博弈语言，会把需长期共赢/培育生态的合作误读成对抗，倾向算计而非共建（思想史分析，B）","重谋略轻组织建设：擅长打赢一仗，不擅长建成能持续打胜仗的组织；育人/文化/制度着墨极少（《孙子兵法》文本范围所限，A）","信息可得性的乐观假设：知彼知己/庙算预设敌情可侦可算，高度不确定环境下''算''反造虚假确定感（学界对其方法论局限的讨论，B）","不追问目的与价值：只答如何以最小代价达成目标，不答该不该追求此目标（《孙子兵法》通篇为工具理性，A）"],"applicable_domains":["战略","竞争博弈","风险评估","谈判","资源调度","危机应对"],"match_tags":["战略","竞争博弈","风险评估","谈判","系统分析","对抗性思维","风险规避","古代东亚"],"linked_cases":["sunzi-c1","sunzi-c2"],"life_tags":[{"tag":"著孙子兵法","tier":"primary"},{"tag":"论不战屈兵","tier":"primary"},{"tag":"论知己知彼","tier":"primary"},{"tag":"论上兵伐谋","tier":"primary"}],"voice_profile":{"notes":"格言式短句；对仗排比；克制不煽情；以自然为喻（水火风山）"},"references":[{"ref_id":"sunzi-s1","title":"《孙子兵法·形篇》","locator":"形篇 \"先为不可胜，以待敌之可胜\" / \"胜兵先胜而后求战\" 段","source_tier":"primary","supports_models":["先胜后战"],"note":"原典一手"},{"ref_id":"sunzi-s2","title":"《孙子兵法·谋攻篇》","locator":"谋攻篇 \"不战而屈人之兵\" / \"上兵伐谋，其次伐交，其次伐兵，其下攻城\" 段","source_tier":"primary","supports_models":["不战而屈人之兵"],"note":"原典一手"},{"ref_id":"sunzi-s3","title":"《孙子兵法·计篇》","locator":"计篇 \"经之以五事\" / \"未战而庙算胜者，得算多也\" 段；及 \"兵者，国之大事\" 句","source_tier":"primary","supports_models":["庙算五事","慎战非利不动"],"note":"原典一手；计篇同时支撑庙算与慎战二模型"},{"ref_id":"sunzi-s4","title":"《孙子兵法·势篇》《虚实篇》","locator":"势篇 \"以正合，以奇胜\" \"奇正相生\"；虚实篇 \"兵无常势，水无常形\" 段","source_tier":"primary","supports_models":["奇正相生"],"note":"原典一手"},{"ref_id":"sunzi-s5","title":"《孙子兵法·火攻篇》","locator":"火攻篇 \"非利不动，非得不用，非危不战\" / \"主不可以怒而兴师\" 段","source_tier":"primary","supports_models":["慎战非利不动"],"note":"原典一手；与计篇共同支撑慎战模型"},{"ref_id":"sunzi-s6","title":"《史记·孙子吴起列传》","locator":"吴宫教战段 \"以兵法见于吴王阖庐……约束既布，乃设鈇钺\"","source_tier":"secondary","supports_cases":["sunzi-c1"],"note":"二手；成书晚孙子约三百年，孙武其人/此事真实性学界存疑（historicity=存疑），呈现须作\"史载/相传\""},{"ref_id":"sunzi-s7","title":"《左传·定公四年》《史记》（柏举之战 / 吴师入郢）","locator":"《左传》定公四年柏举之战；《史记·吴太伯世家》入郢段","source_tier":"primary","supports_cases":["sunzi-c2"],"note":"战役为信史(tier A)；孙武个人谋划缺可靠一手记载，C2 作为\"孙子个人决策案例\"historicity=存疑(disputed)，本条仅作时代实践背景、不附会为其个人决策"}],"material_type":"textual","reasoning_skeleton":{"signature":"先问该不该打、再算五维胜负——先立于不败，能不打就不打，要打则以正合以奇胜","steps":[{"invoke":"慎战非利不动","action":"先剔除情绪与面子，纯算整体利害与可逆性；非利非危则直接劝退、不进入下一步"},{"invoke":"庙算五事","action":"用道天地将法五维把己方与对手放同一张表逐项打分，看真正占优的是哪几项"},{"invoke":"先胜后战","action":"判断是否已立于不败之地；若仍在''赌''、未先胜，则先去补不败条件而非急于出手"},{"invoke":"不战而屈人之兵","action":"出手前先穷举伐谋/伐交等不交战即达成目标的路径，能不打就不打"},{"invoke":"奇正相生","action":"若必须打，定出''正''（牵制）与''奇''（攻虚），把杀招放在对手虚处"}],"contrast":"与诸葛亮相反：同样面对''条件不足该不该弄险''，孙子主张条件不足即不动（先胜后战/慎战），诸葛亮可在条件不足时以奇险博取主动（见诸葛亮卡''空城/北伐''）。与克劳塞维茨相反：克氏重''决战会战''与''摩擦''，孙子的理想恰是不战而屈人之兵、把胜负前移到开战之前。"},"persona_anchor":{"primary":[{"source":"case","case_id":"sunzi-c2","note":"用户''以小博大、要不要硬碰强敌''时，以柏举之战（吴以小国破强楚、避实击虚速决）作镜子——【须标存疑】战役为信史、孙武个人角色史无明载，呈现作''史载/相传''，不当作孙武确证决断"}],"same_era_case":[{"figure":"伍子胥","relation":"同时代同处境（吴国军政核心，柏举之战主谋者之一）","what":"力主先疲楚误楚、再倾国一击破楚入郢，体现同时代''先胜后战 + 不战屈兵式消耗''的审慎对抗","historicity":"confirmed","source_ref":"《史记·伍子胥列传》卷六十六；《左传·定公四年》柏举之战","note":"非孙子本人 · 同时代印证。柏举之战史家多归主功于伍子胥、夫概等，故以伍子胥作''孙子兵学原理的时代实践镜子''，仅作处境类比，不并入孙子个人决策"}]},"further_reading":[{"title":"《孙子兵法》（中华书局或上海古籍 注译本）","why":"全部五个模型的源头，十三篇不长，读原文最能感受''慎战''与''不战而屈人之兵''的克制内核","type":"original"},{"title":"李零《兵以诈立：我读〈孙子〉》","why":"北大学者逐篇细读，厘清孙子作为''诡道''与''庙算''并存的真面目，去除鸡汤化误读","type":"解读"},{"title":"钮先钟《孙子三论》","why":"从现代战略学视角解读孙子，便于把兵学原理迁移到商业/竞争决策","type":"解读"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/sunzi.png","avatar_thumb":"/advisors/portraits/sunzi.png","domain":"战略","person_id":"P-sunzi","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '741ad35aa1e93ee59e9b05566ed6c627570a70d27322325586862fd06907e199', 84, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('sushi', 'P-sushi', '苏轼', 'history', '苏轼 · 逆境自处与心态转化框架卡', '北宋（1037–1101）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '变不变之辨 · 此心安处', '/advisors/portraits/sushi.png', '/advisors/portraits/sushi.png', 5, 0, '{"schema_version":1,"card_id":"sushi","name":"苏轼","title":"苏轼 · 逆境自处与心态转化框架卡","era":"北宋（1037–1101）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"变不变之辨","definition":"遇到失去时主动切换评价的时间尺度：从\"变\"看万物皆一瞬，从\"不变\"看物我皆无尽，以缩放参照系消解执着","source":"《前赤壁赋》","source_tier":"primary","mechanism":"输入=一个失去/得失 → 处理=主动切换评价的时间尺度（从''变''看皆一瞬、从''不变''看皆无尽）、以缩放参照系消解执着 → 输出=当下荣辱变轻","trigger":"遇到失去、被当下得失执着困住时","modern_transfer":"评价得失先选好参照系——放到长时间尺度，多数当下的荣辱都变轻","architecture":{"type":"matrix","components":["面对失去","切换时间尺度","从变/不变两观","消解执着"]},"strategy_card_image":"kb-assets/sushi/model-1.png"},{"name":"此心安处","definition":"把内心安定与外部境遇解耦：不等环境变好才安心，而是先在此处安顿身心，环境随之可处","source":"《定风波》二阕","source_tier":"primary","mechanism":"输入=一个不可改的境遇 → 处理=把内心安定与外部境遇解耦、先在此处安顿身心 → 输出=环境随之可处","trigger":"境遇不可改、又在等环境变好才肯安心时","modern_transfer":"别等环境变好才安心——先在此处安顿身心，把贬地活成故乡，安顿是就地做出来的","architecture":{"type":"flow","components":["遇不可改境遇","解耦安心与环境","就地安顿身心","环境随之可处"]},"strategy_card_image":"kb-assets/sushi/model-2.png"},{"name":"即事实干","definition":"受挫时不纠结抽象的不公，转而对眼前最近、可着手的具体事下手，用行动把困境缩小到可处理","source":"《宋史·苏轼传》（垦荒东坡、知杭州筑堤）","source_tier":"secondary","mechanism":"输入=受挫的处境 → 处理=不纠结抽象的不公、转而对眼前最近可着手的具体事下手 → 输出=把困境缩小到可处理","trigger":"受挫、容易空耗于怨愤申辩时","modern_transfer":"与其论辩不公，不如向眼前要一件最近、能着手改善的具体小事，把困境缩小到可处理","architecture":{"type":"flow","components":["受挫","放下抽象不公","锁定最近可着手事","行动缩小困境"]},"strategy_card_image":"kb-assets/sushi/model-3.png"},{"name":"旷达含悲","definition":"不靠否认痛苦换取平静；让真实的悲伤与超然并存，承认无常的同时不被其击垮","source":"《江城子·乙卯正月二十日夜记梦》","source_tier":"primary","mechanism":"输入=真实的痛苦 → 处理=不靠否认痛苦换平静、让真实悲伤与超然并存 → 输出=承认无常又不被击垮","trigger":"面对真实哀痛、想假装无事时","modern_transfer":"真正的从容不是假装不痛——允许自己如实哀伤，反而是与痛苦共处、不被吞没的前提","architecture":{"type":"hierarchy","components":["面对真实痛苦","不否认不粉饰","让悲伤与超然并存","承认无常不被击垮"]},"strategy_card_image":"kb-assets/sushi/model-4.png"},{"name":"三家融通","definition":"不做单一思想的纯粹派；同时持儒道释多套价值框架，按处境调用最合用的那一套","source":"《宋史·苏轼传》所载其生平frame切换","source_tier":"secondary","mechanism":"输入=一个处境 → 处理=不做单一思想纯粹派、同时持儒道释多套框架、按处境调用最合用的一套 → 输出=位置变了框架就换","trigger":"处境/位置变化、需切换价值框架时","modern_transfer":"在其位则尽责进取（儒）、失其位则随遇而安（道释）——位置变了框架就换","architecture":{"type":"matrix","components":["识别当前处境","备儒道释多框架","按位置调用","灵活切换"]},"strategy_card_image":"kb-assets/sushi/model-5.png"}],"decision_principles":["境遇不可改时，先安顿此心、再就近做事，不空耗于怨愤","评价得失先选好参照系：放到长时间尺度，多数当下荣辱都变轻","在其位则尽责进取（儒），失其位则随遇而安（道释）——位置变了框架就换","真实的悲伤不必压抑；超然是与悲伤共处，不是假装无事","与其论辩不公，不如把眼前能改善的小事做成（垦荒、修堤、办学）"],"inquiry_questions":["这件让你痛苦的事，放到十年、百年的尺度看，还有这么重吗？","你是在等环境变好才肯安心，还是能先在此处安顿下来？","眼下你最近、最能着手改善的一件具体小事是什么？","这件事你该用''尽责进取''的框架，还是''随遇而安''的框架来看？","你是在否认这份难过，还是能让它和你的从容并存？"],"value_priorities":["此心安顿（内在安定） ＞ 改变外部境遇（境遇常不可控，先安心才有余力做事，非放弃改变）","就近实干 ＞ 申辩不公（改善眼前具体事比论证委屈更能脱困）","含悲的超然 ＞ 强颜的乐观（真旷达不否认痛苦；假乐观会反噬）"],"blind_spots":["超然/随遇而安可能滑向对系统性不公的消极接受——他擅长安顿自身，不擅长也无意组织性地改变制度（乌台诗案后基本退出政治抗争，B：《宋史》本传）","旷达对常人有门槛：其转化能力建立在罕见才学、社会资本与朋友网络上，普通人未必能复制''贬到哪都活得有声有色''（原理推断，B）","偏个人修养与审美式超脱，对需要正面博弈、争取资源、强对抗的处境给不出方法（与即事实干同源：其实干是建设性而非对抗性，原理推断，B）","政治判断反复受挫：新旧党争两头不讨好、屡遭贬谪；其耿直敢言+不站队在权力博弈中是弱点（史实，B：《宋史·苏轼传》）"],"applicable_domains":["修身自省","人生抉择","职业发展","价值与伦理"],"match_tags":["修身自省","人生抉择","价值与伦理","职业发展","多元模型","务实渐进","长期主义","古代东亚"],"linked_cases":["sushi-c1","sushi-c2","sushi-c3","sushi-c4","sushi-c5"],"life_tags":[{"tag":"列唐宋八大家","tier":"secondary"},{"tag":"贬谪黄州","tier":"secondary"},{"tag":"作赤壁赋","tier":"primary"},{"tag":"开创豪放词","tier":"secondary"}],"voice_profile":{"notes":"旷达中见洒脱；善用自然意象作比（江月/烟雨/荔枝）；雅俗兼备、亦庄亦谐；情理交融不矫饰"},"references":[{"ref_id":"sushi-s1","title":"苏轼《前赤壁赋》","locator":"\"自其变者而观之…物与我皆无尽也\"段","source_tier":"primary","supports_models":["变不变之辨"],"supports_cases":["sushi-c1"],"note":"本人作品·一手"},{"ref_id":"sushi-s2","title":"苏轼《定风波·莫听穿林打叶声》","locator":"\"一蓑烟雨任平生\"\"也无风雨也无晴\"","source_tier":"primary","supports_models":["此心安处"],"supports_cases":["sushi-c1"],"note":"本人作品·一手（黄州沙湖道中遇雨）"},{"ref_id":"sushi-s3","title":"苏轼《定风波·南海归赠王定国侍人寓娘》","locator":"\"此心安处是吾乡\"句","source_tier":"primary","supports_models":["此心安处"],"note":"本人作品·一手；\"此心安处\"语出寓娘、由苏轼记入词中"},{"ref_id":"sushi-s4","title":"苏轼《江城子·乙卯正月二十日夜记梦》","locator":"\"十年生死两茫茫\"全篇","source_tier":"primary","supports_models":["旷达含悲"],"supports_cases":["sushi-c4"],"note":"本人作品·一手（悼亡妻）"},{"ref_id":"sushi-s5","title":"苏轼《食荔支二首》","locator":"\"日啖荔枝三百颗，不辞长作岭南人\"","source_tier":"primary","supports_models":["此心安处"],"supports_cases":["sushi-c2"],"note":"本人作品·一手（惠州）"},{"ref_id":"sushi-s6","title":"《宋史·苏轼传》","locator":"乌台诗案、谪黄州躬耕、知杭州浚西湖筑堤、贬惠州儋州诸段","source_tier":"secondary","supports_models":["即事实干","三家融通"],"supports_cases":["sushi-c1","sushi-c2","sushi-c3"],"note":"正史二手；事件主体多源印证"},{"ref_id":"sushi-s7","title":"传为苏轼《猪肉颂》及黄州生活记载","locator":"\"待他自熟莫催他，火候足时他自美\"；《东坡志林》及传记相关","source_tier":"secondary","supports_models":["即事实干"],"supports_cases":["sushi-c5"],"note":"归属/系年存疑；东坡肉起源多后世附会"}],"material_type":"rich","reasoning_skeleton":{"signature":"境遇不可改时先安顿此心、再向眼前要一件能着手的小事；评价得失先把参照系放到长时间尺度；真实的悲伤不压抑，按位置在''尽责进取''与''随遇而安''间换框架","steps":[{"invoke":"此心安处","action":"先别等环境变好，在此处安顿身心、把当下活成''家''"},{"invoke":"变不变之辨","action":"把这件痛苦事放到十年/百年尺度看，多数当下荣辱都变轻"},{"invoke":"即事实干","action":"别空耗于怨愤申辩，向眼前要一件最近、能着手改善的具体小事"},{"invoke":"三家融通","action":"判断该用''尽责进取（儒）''还是''随遇而安（道释）''的框架——位置变了框架就换"},{"invoke":"旷达含悲","action":"不否认痛苦，让真实的悲伤与从容并存"}],"contrast":"与司马迁不同（同安顿苦难、东方两路对照）：司马迁按''分量''称量、忍辱为后世立言、用历史先例定锚（向外完成事业）；苏轼向内切换参照系与心境、随遇而安、把贬地活成故乡（向内和解）（见司马迁卡）。与曾国藩不同（同逆境、互补不重复）：曾国藩向外硬撑、结硬寨隐忍稳取；苏轼向内和解、旷达超脱（见曾国藩卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"sushi-c1","note":"用户''被外力打到谷底、又无法立即翻身''时，以乌台诗案后谪黄州·''东坡''的诞生类比：他不沉溺冤屈与恐惧，求得废营地''东坡''亲自垦荒、自号东坡居士、就地重建生活，同时以《赤壁赋》《定风波》完成心态转化——安顿不是等来的、是就地做出来的（《宋史》信史 + 本人作品）"},{"source":"case","case_id":"sushi-c4","note":"用户''我该不该压住这份难过、强装无事''时，以悼亡妻《江城子》类比：他不回避也不粉饰，写''十年生死两茫茫，不思量，自难忘''——真旷达不是假装不痛，允许自己如实哀伤，才是与痛苦共处而不被吞没的前提（作品存世，确证/A）"}]},"further_reading":[{"title":"苏轼诗词文选（《前后赤壁赋》《定风波》《江城子》等）","why":"变不变之辨/此心安处/旷达含悲的第一手出处，读其本人如何在黄州把谷底活成巅峰","type":"original"},{"title":"林语堂《苏东坡传》","why":"最广为流传的苏轼传记，叙其一生贬谪与旷达，适合先建立整体形象","type":"biography"},{"title":"《宋史·苏轼传》","why":"乌台诗案、贬黄州躬耕、知杭州筑堤、贬惠儋诸事的史实主干来源","type":"正史"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/sushi.png","avatar_thumb":"/advisors/portraits/sushi.png","domain":"历史","person_id":"P-sushi","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '61c3f5d37b5cd6bd452c44211c8d0a330b1a9d87043598ee5f7f1b6f91a8789b', 85, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('tankahkee', 'P-tankahkee', '陈嘉庚', 'business', '陈嘉庚 · 实业兴学与家国担当思维框架卡', '现代（1874—1961）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '实业为手段公益为目的 · 诚信为本', '/advisors/portraits/tankahkee.png', '/advisors/portraits/tankahkee.png', 5, 0, '{"schema_version":1,"card_id":"tankahkee","name":"陈嘉庚","title":"陈嘉庚 · 实业兴学与家国担当思维框架卡","era":"现代（1874—1961）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"实业为手段公益为目的","definition":"把实业/赚钱当作手段而非终极目的，把商业成功转化为教育与社会这一更长远的目的","source":"陈嘉庚《南侨回忆录》及兴学史","source_tier":"primary","mechanism":"输入=把赚钱当终极目的 → 处理=把实业当手段、把商业成功转化为教育与社会这一更长远的目的 → 输出=以商业成就公共事业","trigger":"思考事业的终极目的时","modern_transfer":"把实业/赚钱当作手段、而非终极目的——把商业的成功转化为更长远的目的(教育、社会);商业成果服务于一个超越赚钱的事业(陈嘉庚以实业反哺、创办厦门大学与集美学校)","architecture":{"type":"hierarchy","components":["别把赚钱当终极目的","把实业当手段","把商业成功转化为教育与社会","以商业成就公共事业"]},"strategy_card_image":"kb-assets/tankahkee/model-1.png"},{"name":"诚信为本","definition":"经商以诚信立身，宁可自己吃亏也不负承诺——信誉是你最大的资本","source":"陈嘉庚经商信条","source_tier":"primary","mechanism":"输入=为短期利益失信 → 处理=以诚信立身、宁亏自己不负承诺、信誉是最大资本 → 输出=以诚信赢得长期信任","trigger":"面对''守信吃亏 vs 失信得利''时","modern_transfer":"经商以诚信立身、宁可自己吃亏也不负承诺——信誉是你最大的资本、失信一次就毁了根基(陈嘉庚以诚信著称于南洋商界)","architecture":{"type":"flow","components":["别为短期利益失信","以诚信立身","宁亏自己不负承诺","以诚信赢得长期信任"]},"strategy_card_image":"kb-assets/tankahkee/model-2.png"},{"name":"抓住时代机遇","definition":"看准时代正在兴起的产业机遇、果断进入并做大，别守着旧业不放、也别盲目跟风","source":"陈嘉庚从米业转向橡胶业的史实","source_tier":"primary","mechanism":"输入=守着旧业不放或盲目跟风 → 处理=看准时代的产业机遇、果断进入、做大 → 输出=踩对时代的赛道","trigger":"面对一个新兴的时代机遇时","modern_transfer":"看准时代正在兴起的产业机遇、果断进入并做大——别守着旧业不放、也别盲目跟风(陈嘉庚抓住南洋橡胶业的兴起、从米业转向橡胶做成巨头)〔但行业有周期与风险、见盲区〕","architecture":{"type":"flow","components":["别守着旧业不放或盲目跟风","看准时代兴起的产业机遇","果断进入并做大","踩对时代的赛道"]},"strategy_card_image":"kb-assets/tankahkee/model-3.png"},{"name":"家国担当超越小我","definition":"把自己放进一个更大的共同体（社会、民族），为更长远的公共利益担当，别只算个人/企业的小账","source":"陈嘉庚倾资兴学、支持抗战的史实","source_tier":"primary","mechanism":"输入=只算个人/企业的小账 → 处理=把自己放进更大的共同体(民族/社会)、为更长远的公共利益担当 → 输出=以超越小我成就更大事业","trigger":"在''个人利益''与''更大共同体''间取舍时","modern_transfer":"把自己放进一个更大的共同体(社会、民族)、为更长远的公共利益担当——别只算个人或企业的小账;超越小我、反而成就更大的事业与意义(陈嘉庚倾资兴学、抗战时组织南洋华侨支援)","architecture":{"type":"hierarchy","components":["别只算个人企业的小账","把自己放进更大的共同体","为更长远的公共利益担当","以超越小我成就更大事业"]},"strategy_card_image":"kb-assets/tankahkee/model-4.png"},{"name":"俭以养德表率","definition":"自己极度节俭，把省下与赚到的钱投入更有价值的地方，以身作则——财富的意义在用对地方","source":"陈嘉庚自奉极俭、散财兴学","source_tier":"primary","mechanism":"输入=有钱就奢靡享受 → 处理=自己极度节俭、把省下与赚到的投入更有价值处、以身作则 → 输出=俭以养德、财富用于更有价值处","trigger":"如何对待自己的财富与生活时","modern_transfer":"自己极度节俭、把省下来与赚到的钱投入更有价值的地方(公益/教育)、以身作则——''俭以养德''、财富的意义在用对地方、而非奢靡享受(陈嘉庚自奉极俭、却散尽家财办学)","architecture":{"type":"flow","components":["别有钱就奢靡享受","自己极度节俭","把钱投入更有价值处","俭以养德以身作则"]},"strategy_card_image":"kb-assets/tankahkee/model-5.png"}],"decision_principles":["把实业当手段、把商业成功转化为教育与社会这一更长远的目的","经商以诚信立身、宁可自己吃亏也不负承诺","看准时代正在兴起的产业机遇、果断进入做大（但行业有风险）","把自己放进更大的共同体、为更长远的公共利益担当","自己极度节俭、把钱投入更有价值的地方、以身作则"],"inquiry_questions":["你把赚钱当终极目的、还是当成就一个更长远事业的手段？","守信会吃亏、失信能得利时，你是守住信誉、还是为短期利益失信？","你是守着旧业不放、还是看准了时代正在兴起的产业机遇？","你只算个人/企业的小账、还是为更大的共同体担当？","你有钱就奢靡享受、还是节俭把钱投入更有价值的地方？"],"value_priorities":["实业为手段、公益为目的 ＞ 赚钱为终极目的（以实业反哺、创办厦大与集美）","诚信立身 ＞ 短期失信得利（信誉是最大的资本）","超越小我的担当 ＞ 个人/企业的小账（倾资兴学、支持抗战）"],"blind_spots":["''倾资兴学''的极致投入以个人有强烈使命与相当财力为前提，普通经营者难照搬到那种程度（原理推断，B）。","''实业为手段''若处理不当、过度地把企业资源转向公益，也可能危及企业本身的持续（史实，B；陈嘉庚企业曾因经济萧条叠加持续办学投入而受困）。","''抓住时代机遇''（橡胶）也伴随行业周期与风险，并非每次押注都成（原理推断，B）。","其家国情怀诞生于特定的历史与民族语境，其具体形式未必能直接套用于今天的经营（原理推断，B）。"],"applicable_domains":["创业","长期规划","价值与伦理"],"match_tags":["创业","长期规划","价值与伦理","利他取向","长期主义","务实渐进","现当代东亚"],"linked_cases":["tankahkee-c1","tankahkee-c2","tankahkee-c3","tankahkee-c4"],"life_tags":[{"tag":"创办厦门大学","tier":"secondary"},{"tag":"办集美学村","tier":"secondary"},{"tag":"组南侨机工","tier":"secondary"},{"tag":"倾资兴学","tier":"secondary"}],"voice_profile":{"notes":"朴实诚恳、重信义；家国情怀深厚；自奉极俭；倾尽所有办教育"},"references":[{"ref_id":"tankahkee-s1","title":"陈嘉庚《南侨回忆录》","locator":"实业、兴学、抗战支援、诚信经营、自奉极俭","source_tier":"primary","supports_models":["实业为手段公益为目的","诚信为本","抓住时代机遇","家国担当超越小我","俭以养德表率"],"supports_cases":["tankahkee-c1","tankahkee-c2","tankahkee-c3","tankahkee-c4"],"note":"一手·回忆录"},{"ref_id":"tankahkee-s2","title":"厦门大学、集美学校校史","locator":"倾资兴学的实践","source_tier":"secondary","supports_models":["实业为手段公益为目的"],"supports_cases":["tankahkee-c1"],"note":"二手·校史"}],"material_type":"rich","reasoning_skeleton":{"signature":"把实业当手段、把商业成功转化为教育与社会这一更长远的目的(实业为手段公益为目的)；以诚信立身、宁亏自己不负承诺(诚信为本)；看准时代的产业机遇果断进入做大(抓住时代机遇)；把自己放进更大的共同体为公共利益担当(家国担当超越小我)；自己极度节俭把钱投入更有价值处(俭以养德表率)","steps":[{"invoke":"实业为手段公益为目的","action":"你把赚钱当终极目的、还是当成就一个更长远事业的手段？"},{"invoke":"诚信为本","action":"守信会吃亏、失信能得利时，你是守住信誉、还是为短期利益失信？"},{"invoke":"抓住时代机遇","action":"你是守着旧业不放、还是看准了时代正在兴起的产业机遇？"},{"invoke":"家国担当超越小我","action":"你只算个人/企业的小账、还是为更大的共同体担当？"},{"invoke":"俭以养德表率","action":"你有钱就奢靡享受、还是节俭把钱投入更有价值的地方？"}],"contrast":"与卡内基不同(关键差异·同涉慈善公益)：**卡内基是''先靠钢铁赚到巨富、晚年再做慈善''(''财富的福音''、后置的慈善)**；**陈嘉庚是''实业从一开始就以反哺教育与民族为目的、且贯穿始终的家国担当''**——卡内基是赚够再捐、陈嘉庚是边赚边倾注、把企业彻底当成兴学的手段(见卡内基卡)。与稻盛和夫不同：稻盛是''敬天爱人+作为人何谓正确''的经营哲学;陈嘉庚是''实业为手段、教育为目的''的兴学家国(见稻盛和夫卡)。与松下幸之助不同：松下是''企业是社会公器(企业本身服务社会)'';陈嘉庚更进一步、把企业成果直接倾注于办学与民族(见松下卡)。【射程/盲区】陈嘉庚之道在''实业兴学、诚信、抓机遇、家国担当、俭以养德''极有力，但①''倾资兴学''的极致投入以个人有强烈使命与相当财力为前提、普通经营者难照搬到那种程度;②过度把企业资源转向公益也可能危及企业本身的持续(陈嘉庚企业曾因萧条叠加持续办学而受困);③抓机遇(橡胶)也伴随行业周期与风险;④其家国情怀诞生于特定历史民族语境、具体形式未必能直接套用于今天。适用创业/长期规划/价值与伦理;不适用投资/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"tankahkee-c1","note":"用户''把赚钱当成了唯一目的、却感到空虚或没有更大的意义''时，以陈嘉庚实业兴学类比：他把办实业当手段、把赚到的钱倾注于创办厦门大学与集美学校这一更长远的事业——把商业的成功转化为超越赚钱的目的、反而成就了更大的意义（陈嘉庚倾资兴学为史实与其《南侨回忆录》所载→确证）"},{"source":"case","case_id":"tankahkee-c2","note":"用户''面对一个守信会吃亏、失信能占便宜的选择''时，以陈嘉庚诚信为本类比：他以诚信著称于南洋商界、宁可自己吃亏也不负承诺——信誉是最大的资本、失信一次就毁了根基（陈嘉庚诚信经商为史实→确证）"}]},"further_reading":[{"title":"陈嘉庚《南侨回忆录》","why":"实业、兴学、抗战支援、诚信经营的一手回忆（A）","type":"原著/回忆录"},{"title":"厦门大学、集美学校校史","why":"陈嘉庚倾资兴学的实践记录（B）","type":"校史"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/tankahkee.png","avatar_thumb":"/advisors/portraits/tankahkee.png","domain":"商业","person_id":"P-tankahkee","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'e18d36e4b279fa0a60d0dcf7fe5ca22a759fcf2d1b707ea84734cb2c30a041f7', 86, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('templeton', 'P-templeton', '约翰·邓普顿', 'investing', '邓普顿 · 全球逆向价值投资思维框架卡', '20世纪（1912—2008）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '极度悲观点买入 · 全球分散搜寻便宜', '/advisors/portraits/templeton.png', '/advisors/portraits/templeton.png', 5, 0, '{"schema_version":1,"card_id":"templeton","name":"约翰·邓普顿","title":"邓普顿 · 全球逆向价值投资思维框架卡","era":"20世纪（1912—2008）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"极度悲观点买入","definition":"在市场最悲观、人人恐惧抛售的极点买入，因为那时价格最低、未来回报最高","source":"邓普顿\"在极度悲观点买入\"投资格言及实践","source_tier":"secondary","mechanism":"输入=想买在低点、但人人恐惧抛售时不敢买 → 处理=在市场最悲观、人人恐惧抛售的极点买入 → 输出=以最低价买入、未来回报最高","trigger":"市场最悲观、人人恐惧抛售时","modern_transfer":"在市场最悲观、人人恐惧抛售的极点买入——那时价格最低、未来回报最高(''在极度悲观点买入'')；但要确认是恐慌错杀、而非真的基本面崩坏","architecture":{"type":"flow","components":["等市场到极度悲观点","人人恐惧抛售","此时买入","以最低价进场"]},"strategy_card_image":"kb-assets/templeton/model-1.png"},{"name":"全球分散搜寻便宜","definition":"不局限于本国市场，在全球范围搜寻被低估的便宜优质资产，哪里便宜买哪里","source":"邓普顿全球投资实践（全球投资先驱）","source_tier":"secondary","mechanism":"输入=只盯本国市场、错过更便宜的机会 → 处理=不局限于本国、在全球范围搜寻被低估的便宜优质资产 → 输出=哪里便宜买哪里、机会集更大","trigger":"寻找便宜优质资产、不应限于本土时","modern_transfer":"别只盯本国市场——在全球范围搜寻被低估的便宜优质资产、哪里便宜买哪里(邓普顿是全球投资先驱)；但需跨市场的知识与对汇率/政治风险的认识","architecture":{"type":"matrix","components":["跳出本国市场","全球扫描被低估资产","哪里便宜买哪里","机会集更大"]},"strategy_card_image":"kb-assets/templeton/model-2.png"},{"name":"与众不同才能超额","definition":"想取得超越平均的回报，就必须做与大众不同的事——买大家都买的，只能得到大众的平均结果","source":"邓普顿\"与众不同才能超越平均\"投资理念","source_tier":"secondary","mechanism":"输入=想跑赢市场、却跟着大众买 → 处理=认清买大家都买的只能得平均、必须做与大众不同的事 → 输出=与众不同才有超越平均的机会","trigger":"想取得超越平均的回报时","modern_transfer":"想取得超越平均的回报，就必须做与大众不同的事——买大家都买的，只能得到大众的平均结果(但''不同''必须基于独立判断、不是为不同而不同)","architecture":{"type":"flow","components":["认清随大众得平均","独立判断","做与大众不同的事","才有超额机会"]},"strategy_card_image":"kb-assets/templeton/model-3.png"},{"name":"比较价值买最便宜","definition":"持续比较所有可选资产的\"价格相对价值\"，买最便宜的那个，并在别处出现更便宜的优质标的时换仓","source":"邓普顿比较价值、全球择优的投资方法","source_tier":"secondary","mechanism":"输入=持有''还不错''的资产、但别处有更便宜的 → 处理=持续比较所有可选资产的''价格相对价值''、买最便宜的、出现更便宜标的时换仓 → 输出=资金永远在''价格相对价值最低''处","trigger":"配置/持有资产、需在多标的间选择时","modern_transfer":"持续比较所有可选资产的''价格相对价值''、买最便宜的那个，并在别处出现更便宜的优质标的时换仓——别因''还不错''就守着不动","architecture":{"type":"matrix","components":["比较所有标的价格相对价值","买最便宜的","出现更便宜的就换仓","资金永在最低估处"]},"strategy_card_image":"kb-assets/templeton/model-4.png"},{"name":"警惕这次不一样","definition":"警惕\"这次不一样\"的想法——历史的繁荣与恐慌模式很少真的改变，别被它骗去追高或恐慌","source":"邓普顿\"投资里最贵的四个字是''这次不同''\"","source_tier":"secondary","mechanism":"输入=市场狂热/恐慌、有人说''这次不一样'' → 处理=警惕''这次不一样''、历史的繁荣恐慌模式很少真改变 → 输出=不被''这次不同''骗去追高或恐慌","trigger":"市场极端、有人鼓吹''这次不一样''时","modern_transfer":"警惕''这次不一样''的想法——投资里最贵的四个字就是''这次不同''；历史的繁荣与恐慌模式很少真的改变，别被它骗去追高或恐慌","architecture":{"type":"flow","components":["听到这次不一样","对照历史繁荣恐慌模式","警惕模式很少真变","不被骗去追高或恐慌"]},"strategy_card_image":"kb-assets/templeton/model-5.png"}],"decision_principles":["在市场最悲观、人人恐惧抛售的极点买入（确认是恐慌错杀）","别只盯本国，全球搜寻被低估的便宜优质资产","想跑赢就必须做与大众不同的事——随大众只能得平均","持续比较各资产的价格相对价值，买最便宜的、可换仓","警惕''这次不一样''，历史的繁荣恐慌模式很少真变"],"inquiry_questions":["你想跑赢市场，可你买的是不是大家都在买的？","现在是众人恐惧抛售的悲观点吗？这是恐慌错杀还是真的基本面崩坏？","你只盯本国市场吗？全球范围内有没有更便宜的优质资产？","你手上的标的，是''价格相对价值''最低的那个吗？别处有没有更便宜的可换？","有人在说''这次不一样''吗？对照历史，这个繁荣/恐慌的模式真的变了吗？"],"value_priorities":["极度悲观点的低价 ＞ 随大流的安全感（行情在绝望中诞生；但需确认是错杀）","全球比较的最便宜 ＞ 守着本土\"还不错\"（哪里便宜买哪里、出现更便宜的就换）","独立而与众不同 ＞ 随大众得平均（「不同」须基于独立判断、非为不同而不同）"],"blind_spots":["''在悲观点买入''极难执行——''最悲观点''往往事后才清晰，过早抄底会被深套（择时风险，B）。","全球投资需跨市场的知识与信息，且有汇率、政治、信息不对称风险，个人投资者难以复制（原理推断，B）。","做空高估资产（如1999科技股）风险极高、时机错了损失可能无限（其方法的高风险面，B）。","极度逆向需要逆人性的强大心理纪律与孤独承受力，常人难以长期坚持（原理推断，B）。"],"applicable_domains":["投资","长期规划","风险评估"],"match_tags":["投资","长期规划","风险评估","逆向思考","长期主义","多元模型","现当代北美"],"linked_cases":["templeton-c1","templeton-c2","templeton-c3"],"life_tags":[{"tag":"创邓普顿基金","tier":"secondary"},{"tag":"大萧条抄底","tier":"secondary"},{"tag":"设邓普顿奖","tier":"secondary"},{"tag":"首倡全球投资","tier":"secondary"}],"voice_profile":{"notes":"冷静逆向、不随大流；全球视野；乐观长期但严守纪律；节俭自律、独立判断"},"references":[{"ref_id":"templeton-s1","title":"邓普顿《投资成功的16条法则》及投资格言","locator":"极度悲观点、与众不同、比较价值、这次不一样诸条","source_tier":"secondary","supports_models":["极度悲观点买入","与众不同才能超额","比较价值买最便宜","警惕这次不一样"],"note":"一手理念（格言/法则汇编）"},{"ref_id":"templeton-s2","title":"Lauren Templeton《邓普顿教你逆向投资》","locator":"二战买便宜股、全球投资、做空泡沫诸案例","source_tier":"secondary","supports_models":["极度悲观点买入","全球分散搜寻便宜"],"supports_cases":["templeton-c1","templeton-c2","templeton-c3"],"note":"二手·方法与案例系统梳理"},{"ref_id":"templeton-s3","title":"邓普顿投资生涯/邓普顿基金记载","locator":"全球投资实践、各经典操作","source_tier":"secondary","supports_models":["全球分散搜寻便宜"],"supports_cases":["templeton-c1","templeton-c2","templeton-c3"],"note":"二手·生涯与实践佐证"}],"material_type":"rich","reasoning_skeleton":{"signature":"在市场最悲观、人人恐惧抛售的极点买入(极度悲观点)；别只盯本国、全球搜寻被低估的便宜优质资产；想跑赢就必须做与大众不同的事；持续比较所有标的的价格相对价值、买最便宜的、出现更便宜的就换仓；警惕''这次不一样''、历史模式很少真变","steps":[{"invoke":"与众不同才能超额","action":"你想跑赢市场，可你买的是不是大家都在买的？(随大众只能得平均)"},{"invoke":"极度悲观点买入","action":"现在是众人恐惧抛售的悲观点吗？这是恐慌错杀还是真的基本面崩坏？"},{"invoke":"全球分散搜寻便宜","action":"你只盯本国市场吗？全球范围内有没有更便宜的优质资产？"},{"invoke":"比较价值买最便宜","action":"你手上的标的，是''价格相对价值''最低的那个吗？别处有没有更便宜的可换？"},{"invoke":"警惕这次不一样","action":"有人在说''这次不一样''吗？对照历史，这个繁荣/恐慌的模式真的变了吗？"}],"contrast":"与格雷厄姆不同(关键差异·同为价值投资)：**格雷厄姆重''安全边际+定量+清算价值''、多在本土市场买便宜的普通公司**；**邓普顿重''极度悲观点+全球搜寻+比较价值''、是全球逆向价值的先驱**——格雷厄姆是本土定量价值、邓普顿是全球逆向价值(见格雷厄姆卡)。与费雪不同：费雪是成长投资(闲聊法+定性+长持卓越成长)；邓普顿是逆向价值(悲观点+全球便宜)——一个买卓越成长、一个买极度便宜(见费雪卡)。与巴菲特/芒格区分：巴菲特重护城河+长期、芒格重多元格栅；邓普顿更纯粹逆向+全球。【射程/盲区】邓普顿法在''全球逆向捡便宜''极有效，但①''在悲观点买入''极难执行、''最悲观点''事后才清晰、过早抄底会被套(择时风险)；②全球投资需跨市场知识、有汇率/政治/信息不对称风险、个人难复制；③做空高估资产(如1999科技股)风险极高；④极度逆向需逆人性的心理纪律与孤独、常人难坚持。适用投资/长期规划/风险评估；不适用危机应对/表达说服。"},"persona_anchor":{"primary":[{"source":"case","case_id":"templeton-c1","note":"用户''人人恐慌抛售时不敢买、想等''更明朗''''时，以邓普顿二战买便宜股类比：1939 二战爆发、市场极度恐慌，他反而借钱买入纽交所每股低于 1 美元的上百只股票，数年后大赚——在极度悲观点买入(惟须确认是恐慌错杀)（二战买便宜股为其投资生涯著名史实→确证）"},{"source":"case","case_id":"templeton-c3","note":"用户''市场狂热、人人说''这次不一样''、要不要跟''时，以邓普顿 2000 做空科技泡沫类比：互联网泡沫顶峰、他逆势做空一篮子高估科技股、警惕''这次不一样''、随后泡沫破裂获利——历史的狂热模式很少真改变（做空科技泡沫为其晚年著名操作→确证；惟做空风险极高、须并陈）"}]},"further_reading":[{"title":"邓普顿《投资成功的16条法则》及其投资格言","why":"极度悲观点、与众不同、这次不一样等一手理念","type":"原则"},{"title":"Lauren Templeton《邓普顿教你逆向投资》","why":"全球逆向价值方法与经典案例的系统梳理","type":"biography"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/templeton.png","avatar_thumb":"/advisors/portraits/templeton.png","domain":"投资","person_id":"P-templeton","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '965e9f3a7de06308abaf9f297d43320d4048af9706ad3f34a8e4a92a550b6783', 87, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('tesla', 'P-tesla', '特斯拉', 'innovation', '特斯拉 · 创新与第一性原理思维框架卡', '19世纪末–20世纪中（1856–1943）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'legendary', '旋转磁场原理 · 系统级押注交流', '/advisors/portraits/tesla.png', '/advisors/portraits/tesla.png', 5, 0, '{"schema_version":1,"card_id":"tesla","name":"特斯拉","title":"特斯拉 · 创新与第一性原理思维框架卡","era":"19世纪末–20世纪中（1856–1943）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"旋转磁场原理","definition":"从交流电可产生旋转磁场的物理本质出发设计电机，而非在直流框架内修补改良","source":"多相交流系统专利(1888)","source_tier":"primary","mechanism":"输入=旧框架下卡住的瓶颈 → 处理=不在旧框架内修补、回到问题的物理/第一性本质、据此重起一套 → 输出=更对的新方案而非更好的补丁","trigger":"旧方案在框架内反复修补仍卡瓶颈时","modern_transfer":"别在旧框架里打补丁——回到问题的物理/底层本质，往往能重起一套更对的方案","architecture":{"type":"flow","components":["识别旧框架瓶颈","回到物理本质","据本质重起一套","得更对方案"]},"strategy_card_image":"kb-assets/tesla/model-1.png"},{"name":"系统级押注交流","definition":"不在直流框架内修补，押注整套交流发电—输电—电机系统，赌长远的物理优势","source":"西屋授权与尼亚加拉电站（传记）","source_tier":"secondary","mechanism":"输入=一个比当下方案物理更优、却被唱衰的长远路线 → 处理=不在主流框架内改良、押注整套系统、承受短期对抗 → 输出=赌长远的结构性优势","trigger":"一个底层物理更优、但当下被唱衰/成本更高的整套路线","modern_transfer":"押注一个当下被唱衰、但底层更优的整套方案，承受短期对抗，赌的是长远的结构性优势","architecture":{"type":"hierarchy","components":["识别更优长远路线","押注整套系统非单点","承受短期对抗","赌结构性优势"]},"strategy_card_image":"kb-assets/tesla/model-2.png"},{"name":"远超时代目标","definition":"把目标设在当下不可能、但物理上不排除的远处（无线输电等），以愿景牵引而非渐进改良","source":"沃登克里夫无线输电计划（传记）","source_tier":"secondary","mechanism":"输入=一个目标设定 → 处理=把目标设在当下不可能、物理却允许的远处、以愿景牵引而非渐进改良 → 输出=被愿景牵引的方向（须挂资源现实）","trigger":"在''渐进小改良''与''设一个物理允许的远大目标''之间选择时","modern_transfer":"把目标设在当下不可能、物理上却不排除的远处，用愿景牵引方向——但务必挂上能支撑它的资源，否则烂尾","architecture":{"type":"flow","components":["设物理允许的远目标","愿景牵引方向","须挂资源约束","牵引而非渐进"]},"strategy_card_image":"kb-assets/tesla/model-3.png"},{"name":"心智预演","definition":"（据其自述）动手前于脑中完整构建并运转装置、反复调试到无误，再造实物，省去物理试错","source":"自传《My Inventions》自述","source_tier":"primary","mechanism":"输入=一个待造的装置/方案 → 处理=（据其自述）动手前在脑中完整构建并运转、反复调试到无误 → 输出=减少物理试错的预演（须防高估脑中模拟可靠性）","trigger":"物理试错昂贵、动手前想先预演故障点时","modern_transfer":"动手前尽量在头脑/纸面把方案完整跑一遍、预演它会坏在哪——能省大量真实试错，但别高估脑中模拟的可靠性","architecture":{"type":"loop","components":["脑中构建装置","完整运转","找故障点反复调试","再造实物"]},"strategy_card_image":"kb-assets/tesla/model-4.png"},{"name":"想象力优先","definition":"相信清晰构想本身是最大资产，资源应服务于构想；此为其力量、亦为其失败之源","source":"自传与权威传记","source_tier":"secondary","mechanism":"输入=构想与现实资源的关系 → 处理=把清晰构想当最大资产、让资源服务于构想 → 输出=构想驱动（失衡则脱离资源约束、为其失败之源）","trigger":"在''先有清晰构想''与''先看现实资源约束''之间定主次时","modern_transfer":"把清晰的构想当最大资产、让资源服务于它——这是创造力之源；但构想压过资源约束时，就会变成你失败的根源","architecture":{"type":"hierarchy","components":["视构想为最大资产","资源服务于构想","构想统领方向","警惕脱离资源"]},"strategy_card_image":"kb-assets/tesla/model-5.png"}],"decision_principles":["遇到旧框架的瓶颈，别在框架内修补，从物理本质重起一套（旋转磁场，A）","押注长远的物理优势，哪怕当下成本更高、被唱衰（交流系统，B）","把目标设在当下不可能、物理却允许的远处，用愿景牵引（无线输电，B）","动手前先在脑中把它完整运转一遍、找出会坏在哪（心智预演·自述，A）"],"inquiry_questions":["你是在旧方案上修补，还是回到物理本质、可以重起一套更对的？","你这个目标，是当下的小改良，还是物理上允许、却没人敢设的远处？","动手之前，你能在脑子里把它完整运转、预演出它会坏在哪吗？","你为这个构想配的资源和商业落地，跟得上你的想象吗？"],"value_priorities":["物理本质上更优的方案 ＞ 当下更易落地更省钱的方案（赌长远物理优势（交流胜直流））","远大愿景的牵引 ＞ 渐进改良的稳妥（目标设在物理允许的远处）","构想的纯粹与完整 ＞ 商业妥协与短期变现（既是其力量、也是其失败之源）"],"blind_spots":["商业化变现弱：屡屡技术领先却生意出局（交流专利收益、沃登克里夫融资失败），不擅把发明变成持续生意（Carlson 传记，B）","愿景过度外推、脱离资源约束：沃登克里夫等目标远超当时工程与资金可支撑，导致烂尾（传记，B）","不善人际/谈判/结盟：与投资人(摩根)、合作者关系处理失当，缺乏长期绑定支持者的能力（传记，B）","晚年宣称缺乏验证：晚年部分公开宣称缺可验证证据，须与其确证的工程成就严格分层（相关自由能/死光属C层传说）（史料，B）"],"applicable_domains":["创新研发","探索未知","长期规划"],"match_tags":["创新研发","探索未知","风险评估","第一性原理","直觉决断","近代北美"],"linked_cases":["tesla-c1","tesla-c2","tesla-c3","tesla-c4","tesla-c5","tesla-c6"],"life_tags":[{"tag":"创交流电系统","tier":"secondary"},{"tag":"设特斯拉线圈","tier":"secondary"},{"tag":"建尼亚加拉站","tier":"secondary"},{"tag":"研无线输电","tier":"secondary"}],"voice_profile":{"notes":"视觉化具象描述；对未来的笃定宣告；诗性而宏大；轻商业重愿景"},"references":[{"ref_id":"tesla-s1","title":"W. Bernard Carlson《Tesla: Inventor of the Electrical Age》(2013)","locator":"交流系统章、沃登克里夫章","source_tier":"secondary","supports_models":["系统级押注交流","远超时代目标","想象力优先"],"supports_cases":["tesla-c2","tesla-c4"],"note":"权威学术传记"},{"ref_id":"tesla-s2","title":"特斯拉多相交流系统专利(1888, US381968 等)","locator":"专利文本","source_tier":"primary","supports_models":["旋转磁场原理"],"supports_cases":["tesla-c1"],"note":"一手专利"},{"ref_id":"tesla-s3","title":"《My Inventions》(特斯拉自传, 1919)","locator":"自述章","source_tier":"primary","supports_models":["心智预演","想象力优先"],"supports_cases":["tesla-c3"],"note":"一手自述；自述类、有记忆/夸饰风险"},{"ref_id":"tesla-s4","title":"后世流行文化/坊间传说（无一手）","locator":"—","source_tier":"tertiary","supports_cases":["tesla-c5","tesla-c6"],"note":"神化与网络叙事，仅作对照、非史实"}],"material_type":"legendary","reasoning_skeleton":{"signature":"遇瓶颈不在旧框架修补、回物理本质重起一套；把目标设在物理允许的远处用愿景牵引、并押注整套系统赌长远；动手前在脑中预演故障——但务必把愿景挂上能支撑它的资源","steps":[{"invoke":"旋转磁场原理","action":"先问这是要在旧框架里打补丁、还是回到物理本质重起一套更对的"},{"invoke":"远超时代目标","action":"把目标设在当下不可能、物理却允许的远处，用愿景牵引方向"},{"invoke":"系统级押注交流","action":"若押注更优路线，押整套系统、承受短期对抗，赌长远结构性优势"},{"invoke":"心智预演","action":"动手前在脑中/纸面把方案完整跑一遍、预演它会坏在哪"},{"invoke":"想象力优先","action":"以清晰构想为最大资产牵引资源——但务必挂上能支撑它的资源现实，否则烂尾"}],"contrast":"与爱迪生相反（电流之战两路、同域近邻必拉开）：爱迪生靠海量系统化试错 + 商业化落地 + 专利运营把发明变成持续生意；特斯拉靠第一性原理回物理本质重起、愿景牵引远目标，但商业化弱、屡屡技术领先却生意出局（见爱迪生卡）。与马斯克不同（都第一性原理 + 远大愿景）：马斯克把第一性原理用于成本拆解 + 目标驱动、并配工程组织与资本运作落地；特斯拉强于物理构想、弱于资源与商业绑定——同样的远见，一个把愿景挂上了资源、一个脱离资源而烂尾（见马斯克卡，待建）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"tesla-c1","note":"用户''在旧框架里反复打补丁、要不要推倒重来''时，以从旋转磁场重做电机类比：主流（含爱迪生）在直流框架内修补换向器缺陷，他不修补、回到交流可产生旋转磁场的物理本质、设计无换向器的多相交流感应电机——回物理本质重起胜过更好的补丁（多相交流专利一手 A + Carlson 传记交叉，确证）"},{"source":"case","case_id":"tesla-c4","note":"用户''我有个远大愿景、要不要全押''时，以沃登克里夫无线输电塔烂尾类比（反面镜子）：目标远超当时工程与资金可支撑、资金断裂后仍难收束，最终停建拆除、财务声誉俱损——愿景设得再远，也要挂上能支撑它的资源（Carlson 传记，确证）"}]},"further_reading":[{"title":"W. Bernard Carlson《Tesla: Inventor of the Electrical Age》(2013)","why":"目前最严谨的学术传记，把旋转磁场/交流系统/沃登克里夫放回史实脉络，剥离神化","type":"biography"},{"title":"尼古拉·特斯拉《My Inventions》(自传, 1919)","why":"本人自述工作法（含''心智预演''），但属自述、有记忆与夸饰风险，须与确证工程成就分层读","type":"biography"},{"title":"吉尔·琼斯《Empires of Light》","why":"电流之战的多方（爱迪生/西屋/特斯拉）博弈全景，破''天才被反派偷走一切''的二元神话","type":"解读"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/tesla.png","avatar_thumb":"/advisors/portraits/tesla.png","domain":"创新","person_id":"P-tesla","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '90be55872e856bd0d6d1048f9ba1e9456898da723f9dbfb3f0be9e37b12e92fd', 88, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('tolstoy', 'P-tolstoy', '托尔斯泰', 'writing', '托尔斯泰 · 心灵辩证法与史诗全景思维框架卡', '近代（1828—1910）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '心灵辩证法 · 史诗全景', '/advisors/portraits/tolstoy.png', '/advisors/portraits/tolstoy.png', 5, 0, '{"schema_version":1,"card_id":"tolstoy","name":"托尔斯泰","title":"托尔斯泰 · 心灵辩证法与史诗全景思维框架卡","era":"近代（1828—1910）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"心灵辩证法","definition":"深入一个人的内心，细致呈现其思想与情感如何流动、矛盾、一点点转变的过程，而非只给一个静态的结论","source":"托尔斯泰的心理描写","source_tier":"primary","mechanism":"输入=只给静态的结论 → 处理=深入内心、细致呈现思想情感如何流动矛盾转变的过程 → 输出=动态的内心真实(心灵辩证法)","trigger":"要刻画/理解一个人的内心时","modern_transfer":"深入一个人(或角色)的内心、细致呈现其思想与情感如何流动、矛盾、一点点转变的过程——而非只给一个静态的结论(托尔斯泰的''心灵辩证法'')","architecture":{"type":"flow","components":["别只给静态的结论","深入内心","细致呈现思想情感如何流动矛盾转变","动态的内心真实"]},"strategy_card_image":"kb-assets/tolstoy/model-1.png"},{"name":"史诗全景","definition":"把无数个体的命运编织进一幅宏大的历史/社会全景里，让个体与时代相互映照——既见树木、又见整片森林","source":"托尔斯泰《战争与和平》","source_tier":"primary","mechanism":"输入=只见个体或只见时代、割裂 → 处理=把无数个体命运编织进宏大的历史社会全景、个体与时代交织 → 输出=既见树木又见森林(史诗全景)","trigger":"要呈现/理解个体与宏大背景的关系时","modern_transfer":"把无数个体的命运编织进一幅宏大的历史/社会全景里、让个体与时代相互映照——既见树木、又见整片森林(托尔斯泰《战争与和平》的史诗结构)","architecture":{"type":"hierarchy","components":["别只见个体或只见时代割裂","把无数个体命运","编织进宏大的历史社会全景","个体与时代相互映照"]},"strategy_card_image":"kb-assets/tolstoy/model-2.png"},{"name":"道德与意义的追问","definition":"始终追问那些根本问题——\"这是对的吗\"\"什么是善\"\"意义何在\"，让工作有道德的重量与深度，而非只是技巧","source":"托尔斯泰的道德追问","source_tier":"primary","mechanism":"输入=只关注技巧、回避根本问题 → 处理=始终追问''这对吗''''什么是善''''意义何在'' → 输出=道德的重量与深度(道德追问)","trigger":"做事/创作、要有深度而非只有技巧时","modern_transfer":"在做事/创作时始终追问那些根本问题——''这是对的吗''''什么是善''''意义何在''、让你的工作有道德的重量与深度、而非只是技巧(托尔斯泰的道德追问)〔但道德说教过度会压过艺术本身、见盲区〕","architecture":{"type":"flow","components":["别只关注技巧回避根本问题","始终追问这对吗什么是善","意义何在","道德的重量与深度"]},"strategy_card_image":"kb-assets/tolstoy/model-3.png"},{"name":"平凡中的真实","definition":"在最平凡的日常细节、最普通的人身上，去发现深刻的真实与人性——伟大常藏在平凡里，而非只在戏剧性的大事件中","source":"托尔斯泰的现实主义","source_tier":"primary","mechanism":"输入=只在戏剧性大事件中找意义 → 处理=在最平凡的日常细节、最普通的人身上发现深刻的真实与人性 → 输出=伟大藏在平凡里(平凡真实)","trigger":"要发现真实与人性时","modern_transfer":"在最平凡的日常细节、最普通的人身上、去发现深刻的真实与人性——伟大常藏在平凡里、而非只在戏剧性的大事件中(托尔斯泰的现实主义)","architecture":{"type":"flow","components":["别只在戏剧性大事件中找意义","在最平凡的日常细节","最普通的人身上","发现深刻的真实与人性"]},"strategy_card_image":"kb-assets/tolstoy/model-4.png"},{"name":"返璞归真","definition":"剥去虚饰、矫情与人为的复杂，追求质朴、本真、贴近根本的生活与表达","source":"托尔斯泰晚年的追求","source_tier":"primary","mechanism":"输入=堆砌虚饰矫情人为的复杂 → 处理=剥去虚饰、追求质朴本真贴近根本的生活与表达 → 输出=返璞归真(返璞归真)","trigger":"要追求本真、剥离虚饰时","modern_transfer":"剥去虚饰、矫情与人为的复杂、追求质朴、本真、贴近根本的生活与表达——返璞归真(托尔斯泰晚年的追求)〔但其极端化(几乎否定一切文明、艺术)也有争议、见盲区〕","architecture":{"type":"flow","components":["别堆砌虚饰矫情人为的复杂","剥去虚饰","追求质朴本真","贴近根本的生活与表达"]},"strategy_card_image":"kb-assets/tolstoy/model-5.png"}],"decision_principles":["深入内心，细致呈现思想情感的流动与转变，而非只给静态结论","把个体命运编织进宏大全景，让个体与时代相互映照","始终追问''对不对''''什么是善''''意义何在''，给工作道德的重量","在最平凡的日常与普通人身上，发现深刻的真实与人性","剥去虚饰与人为的复杂，追求质朴、本真（但勿极端到否定一切）"],"inquiry_questions":["你是只给静态的结论、还是细致呈现内心思想情感如何流动、矛盾、转变？","你是只见个体或只见时代、还是把个体命运编织进宏大全景、让二者映照？","你是只关注技巧、还是追问''对不对''''什么是善''''意义何在''？","你是只在戏剧性大事件中找意义、还是在平凡日常与普通人身上发现真实？","你是堆砌虚饰与人为的复杂、还是剥去虚饰、追求质朴本真？"],"value_priorities":["流动的内心真实 ＞ 静态的结论（心灵辩证法）","道德的重量与深度 ＞ 只有技巧（追问善与意义（但勿说教过度））","平凡中的真实 ＞ 只看戏剧性大事（现实主义）"],"blind_spots":["托尔斯泰晚年的''返璞归真''与道德主义走向极端，几乎否定一切文明、艺术（包括他自己的伟大作品），有失偏颇（学术，B，客观标注）。","其史诗全景式的繁复、宏大，不适合需要简洁、聚焦的表达（原理推断，B）。","其强烈的道德说教倾向，有时压过了艺术本身（文学批评，B）。","其个人生活（尤其家庭）与其宣扬的理想之间有巨大张力（史，B，点到为止）。"],"applicable_domains":["创作","表达说服","修身自省"],"match_tags":["创作","表达说服","修身自省","系统分析","批判思辨","利他取向","近代欧洲"],"linked_cases":["tolstoy-c1","tolstoy-c2","tolstoy-c3","tolstoy-c4"],"life_tags":[{"tag":"著战争与和平","tier":"primary"},{"tag":"著安娜卡列宁","tier":"primary"},{"tag":"晚年出走","tier":"secondary"},{"tag":"著复活一书","tier":"primary"}],"voice_profile":{"notes":"深邃宏大、洞察心灵；道德重量厚；细密真实；晚年趋于质朴"},"references":[{"ref_id":"tolstoy-s1","title":"托尔斯泰《战争与和平》《安娜·卡列尼娜》《复活》《忏悔录》","locator":"心灵辩证法、史诗全景、道德追问、平凡真实、返璞归真","source_tier":"primary","supports_models":["心灵辩证法","史诗全景","道德与意义的追问","平凡中的真实","返璞归真"],"supports_cases":["tolstoy-c1","tolstoy-c2","tolstoy-c3","tolstoy-c4"],"note":"一手·原著"},{"ref_id":"tolstoy-s2","title":"托尔斯泰研究","locator":"现实主义、心理描写、道德思想","source_tier":"secondary","supports_models":["心灵辩证法","道德与意义的追问"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"深入内心细致呈现思想情感如何流动矛盾转变而非只给静态结论(心灵辩证法)；把无数个体命运编织进宏大的历史社会全景让个体与时代映照(史诗全景)；始终追问对不对什么是善意义何在给工作道德的重量(道德与意义的追问)；在平凡日常与普通人身上发现深刻的真实与人性(平凡中的真实)；剥去虚饰与人为的复杂追求质朴本真(返璞归真)","steps":[{"invoke":"心灵辩证法","action":"你是只给静态的结论、还是细致呈现内心思想情感如何流动、矛盾、转变？"},{"invoke":"史诗全景","action":"你是只见个体或只见时代、还是把个体命运编织进宏大全景、让二者映照？"},{"invoke":"道德与意义的追问","action":"你是只关注技巧、还是追问''对不对''''什么是善''''意义何在''？"},{"invoke":"平凡中的真实","action":"你是只在戏剧性大事件中找意义、还是在平凡日常与普通人身上发现真实？"},{"invoke":"返璞归真","action":"你是堆砌虚饰与人为的复杂、还是剥去虚饰、追求质朴本真？"}],"contrast":"与海明威不同(关键差异·繁与简)：**托尔斯泰是''史诗全景的繁复''——宏大、细密、把无数个体编入时代全景**；**海明威是''冰山的极简''——省略、留白、删尽修饰**——一个以繁复的全景包容、一个以极简的留白暗示(见海明威卡)。与莎士比亚不同：莎士比亚以''戏剧冲突与诗性语言''呈现人性;托尔斯泰以''心灵辩证法与道德追问''呈现人性——一个戏剧化、一个心理化与道德化(见莎士比亚卡)。与狄更斯不同：狄更斯重''社会批判、人物典型、讽刺'';托尔斯泰重''心灵辩证法、史诗全景、道德追问''——一个外部社会批判、一个内部心灵与道德(见狄更斯卡)。【射程/盲区】托尔斯泰之道在''心灵辩证法、史诗全景、道德追问、平凡真实、返璞归真''极有力(尤其深刻的现实主义与道德深度)，但①其晚年''返璞归真''与道德主义走向极端、几乎否定一切文明艺术、有失偏颇;②史诗全景的繁复宏大、不适合需要简洁聚焦的表达;③强烈的道德说教有时压过艺术本身;④其个人生活与所宣扬的理想之间有巨大张力。适用创作/表达说服/修身自省;不适用投资/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"tolstoy-c1","note":"用户''刻画或理解一个人时、只能给出一个静态的标签或结论(他是个好人/坏人/纠结的人)、抓不住其内心的流动''时，以托尔斯泰''心灵辩证法''类比：他不满足于给人物贴标签、而是细致地呈现一个人的思想与情感如何一点点流动、矛盾、挣扎、转变的全过程(如安娜内心的挣扎、聂赫留朵夫的良心觉醒);深入内心、呈现动态的转变过程、而非静态的结论（''心灵辩证法''为车尔尼雪夫斯基对其评价→确证）"},{"source":"case","case_id":"tolstoy-c2","note":"用户''想呈现/理解一件事时、只盯着个体、或只盯着宏大背景、二者割裂''时，以托尔斯泰《战争与和平》的史诗全景类比：他把众多个体的命运(安德烈、皮埃尔、娜塔莎)编织进拿破仑战争的宏大历史全景里、让个体与时代相互映照——既见一个个鲜活的人(树木)、又见整个时代的洪流(森林)（《战争与和平》史诗结构为其作品→确证）"}]},"further_reading":[{"title":"托尔斯泰《战争与和平》《安娜·卡列尼娜》《复活》《忏悔录》","why":"心灵辩证法、史诗全景、道德追问、平凡真实、返璞归真的一手出处（A）","type":"original"},{"title":"托尔斯泰研究","why":"对其现实主义、心理描写与道德思想的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/tolstoy.png","avatar_thumb":"/advisors/portraits/tolstoy.png","domain":"创作","person_id":"P-tolstoy","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '823c2238aa649bd346f1d3bd149537e4175f78b5dccd6736f67312fe40951cb0', 89, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('turing', 'P-turing', '艾伦·图灵', 'science', '图灵 · 可计算思维框架卡', '20世纪（1912–1954）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '化归为机械步骤 · 操作性定义', '/advisors/portraits/turing.png', '/advisors/portraits/turing.png', 5, 0, '{"schema_version":1,"card_id":"turing","name":"艾伦·图灵","title":"图灵 · 可计算思维框架卡","era":"20世纪（1912–1954）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"化归为机械步骤","definition":"把一个任务拆成简单机器能逐步执行的明确规则；拆不出来，就问它是否根本不可计算。","source":"1936《论可计算数》图灵机","source_tier":"primary","mechanism":"输入=一个任务不知能否自动化/真正理解 → 处理=拆成简单机器能逐步执行的明确规则；拆不出就问它是否根本不可计算 → 输出=可机械执行的明确性(或照见其极限)","trigger":"想真正理解或自动化一件事时","modern_transfer":"想真正理解或自动化一件事，先把它拆成明确的、可逐步执行的规则——拆不出来，往往说明你还没真想清楚，或它根本不可计算","architecture":{"type":"flow","components":["拆成简单步骤","明确每条规则","机器可逐步执行","拆不出则问可计算性"]},"strategy_card_image":"kb-assets/turing/model-1.png"},{"name":"操作性定义","definition":"概念无法定义时，用一个可测的行为判据替代它——别问''能否思考''，问''能否表现得无法区分''。","source":"1950《计算机器与智能》模仿游戏","source_tier":"primary","mechanism":"输入=一个概念无法定义、争论陷入泥潭 → 处理=用一个可测的行为判据替代它(别问能否X、问能否表现得无法区分) → 输出=绕开定义之争、争论可推进","trigger":"概念定义不清、争论难推进时","modern_transfer":"当一个概念怎么定义都吵不清时，把它换成一个可观测、可判定的行为测试——别问''能否思考''，问''能否表现得无法区分''","architecture":{"type":"flow","components":["识别无法定义的概念","换成可测行为判据","用行为测试回答","绕开定义之争"]},"strategy_card_image":"kb-assets/turing/model-2.png"},{"name":"承认计算极限","definition":"有些问题原理上无算法可解（停机问题）；认清不可判定的边界，及时停手。","source":"1936论文对判定问题的否证","source_tier":"primary","mechanism":"输入=一个难题在硬耗 → 处理=先判断它有没有可能原理上无解(停机问题)、认清不可判定边界 → 输出=及时止损、不在无解问题上耗","trigger":"动手前 / 在硬问题上久耗时","modern_transfer":"动手前先判断：这问题有没有可能原理上就无解？认清不可判定的边界、及时停手，别在天生走不通的路上耗","architecture":{"type":"flow","components":["动手前评估可解性","判断是否原理无解","认清不可判定边界","及时止损"]},"strategy_card_image":"kb-assets/turing/model-3.png"},{"name":"通用机抽象","definition":"造一台能读他机描述、模拟任何其他机器的''通用机''，胜过造一堆专用机。","source":"1936论文通用图灵机","source_tier":"primary","mechanism":"输入=为每个任务造专用工具、无法通用 → 处理=造一台能读他机描述、模拟任何机器的通用机(程序即数据) → 输出=一个可配置成任意工具的通用底座","trigger":"面对多样需求、想要可复用底座时","modern_transfer":"别为每个具体需求造专用工具，找那个能被''描述''重新配置成任意工具的通用底座——程序即数据","architecture":{"type":"hierarchy","components":["识别多样专用需求","抽象出通用底座","让它读描述配置","一机模拟万机"]},"strategy_card_image":"kb-assets/turing/model-4.png"},{"name":"抓可利用的规律性","definition":"攻坚不只靠纯理论——抓住对手操作中的固定模式与弱点（cribs），逆推突破口。","source":"二战布莱切利园破译工作","source_tier":"secondary","mechanism":"输入=攻坚硬问题/组合爆炸、纯穷举不可行 → 处理=抓住对手操作中的固定模式与弱点(cribs)、逆推 → 输出=把搜索空间砍到可处理","trigger":"面对组合爆炸/硬问题、穷举不可行时","modern_transfer":"面对组合爆炸的难题，别穷举——找系统/对手里可预期的固定模式与弱点，用它把搜索空间砍到可处理","architecture":{"type":"flow","components":["放弃纯穷举","找固定模式与弱点","逆推突破口","砍小搜索空间"]},"strategy_card_image":"kb-assets/turing/model-5.png"}],"decision_principles":["想真正理解或自动化一件事，先把它拆成明确的、可逐步执行的规则。","概念说不清时，换成一个可观测的行为判据来回答。","动手前先判断：这问题有没有可能根本无解？无解就别耗。","别为每个具体任务造专用工具，找那个能配置成任意工具的通用底座。","攻坚硬问题，先找对手/系统里可利用的固定规律和弱点。"],"inquiry_questions":["你这任务，能不能拆成一步步明确、机器都能照做的规则？哪一步拆不动？","你纠结的这个概念定义不清——有没有一个可观测的行为判据能替它回答？","这个问题，有没有可能原理上就无解？你确认过它可解吗？","你是在造一堆专用方案，还是能找到一个可复用的通用底座？","对手/系统里有没有反复出现的固定模式，可以当突破口？"],"value_priorities":["可机械执行的明确性 ＞ 含糊但好听的整体描述（讲不清成步骤，就是还没真想清楚）","可测的行为判据 ＞ 无法定义的''本质''之争（用''模仿游戏''绕开''机器能否思考''的死结）","认清极限后止损 ＞ 在不可判定问题上硬耗（停机问题告诉你：有些路天生走不通）"],"blind_spots":["行为等价≠内在理解：模仿游戏只测外在表现，不触及理解/体验本身（Searle中文屋等批评，B）。","形式-计算视角低估具身、直觉与社会性认知——难以形式化的部分易被忽略（学术分析，B）。","对机器智能进展过度乐观，时间表预估偏激进（其1950论文预测，A）。"],"applicable_domains":["创新研发","探索未知","认知偏误与理性决策"],"match_tags":["创新研发","探索未知","认知偏误与理性决策","第一性原理","逆向思考","系统分析","现当代欧洲"],"linked_cases":["turing-c1","turing-c2","turing-c3","turing-c4","turing-c5"],"life_tags":[{"tag":"提图灵机","tier":"primary"},{"tag":"破解恩尼格玛","tier":"secondary"},{"tag":"设图灵测试","tier":"primary"},{"tag":"奠基计算理论","tier":"secondary"}],"voice_profile":{"notes":"精确、拆解到可执行步骤；用具体机器/游戏作模型；直白、少修辞"},"references":[{"ref_id":"turing-s1","title":"《论可计算数，及其对判定问题的应用》","locator":"1936；图灵机定义、通用机、判定问题否证","source_tier":"primary","supports_models":["化归为机械步骤","承认计算极限","通用机抽象"],"supports_cases":["turing-c1","turing-c4"],"note":"一手·可计算性奠基论文"},{"ref_id":"turing-s2","title":"《计算机器与智能》(Computing Machinery and Intelligence)","locator":"1950，Mind 期刊；模仿游戏","source_tier":"primary","supports_models":["操作性定义"],"supports_cases":["turing-c3"],"note":"一手·图灵测试原文"},{"ref_id":"turing-s3","title":"《形态发生的化学基础》","locator":"1952；反应-扩散模型","source_tier":"primary","supports_cases":["turing-c5"],"note":"一手·数理生物学"},{"ref_id":"turing-s4","title":"Andrew Hodges《Alan Turing: The Enigma》","locator":"1983；布莱切利园相关章节（待质检者核校页码）","source_tier":"secondary","supports_models":["抓可利用的规律性"],"supports_cases":["turing-c2"],"note":"B层·标准传记，确证破译并厘清团队归属"}],"material_type":"rich","reasoning_skeleton":{"signature":"想理解或自动化一件事先拆成机器可逐步执行的明确规则(拆不出就问可计算性)；概念吵不清时换成可观测的行为判据；动手前先判断它是否原理上无解、及时止损；别造专用工具、找可配置成任意工具的通用底座；攻坚组合爆炸别穷举、抓可利用的固定模式","steps":[{"invoke":"化归为机械步骤","action":"你这任务能不能拆成一步步明确、机器都能照做的规则？哪一步拆不动？"},{"invoke":"承认计算极限","action":"这问题有没有可能原理上就无解？你确认过它可解吗？(无解就别耗)"},{"invoke":"操作性定义","action":"你纠结的这个概念定义不清——有没有一个可观测的行为判据能替它回答？"},{"invoke":"通用机抽象","action":"你是在造一堆专用方案，还是能找到一个可复用的通用底座？"},{"invoke":"抓可利用的规律性","action":"对手/系统里有没有反复出现的固定模式，可以当突破口、把搜索空间砍小？"}],"contrast":"与爱因斯坦不同(关键差异)：爱因斯坦靠**物理第一性原理+思想实验**追问''世界底层为何如此''；图灵靠**把问题抽象成形式可计算模型(图灵机/可判定性)**追问''什么可被机械计算、边界在哪''——爱是物理原理、图是计算形式(见爱因斯坦卡)。与达尔文不同：达尔文靠**经验观察的耐心累积**；图灵靠**形式化与机械化拆解**(见达尔文卡)。【射程/盲区】其强项是把问题形式化、机械化；对''人''这套软系统不擅长(模仿游戏只测外在表现、不触及理解本身,Searle中文屋批评)、低估具身/直觉/社会性认知、对机器智能时间表过度乐观。不适用人际/表达说服/组织管理。〔尊严处理：图灵因性取向受迫害与早逝属社会不公、非其个人盲区，涉及时应客观、有尊严地陈述。〕"},"persona_anchor":{"primary":[{"source":"case","case_id":"turing-c3","note":"用户''一个概念怎么定义都吵不清、争论卡死''时，以模仿游戏类比：他把不可定义的''机器能否思考''换成可操作判据——若机器在对话中无法被区分于人就算通过，绕开定义之争让争论得以推进（1950论文原文→确证）"},{"source":"case","case_id":"turing-c1","note":"用户''这件事到底能不能自动化、有没有边界''时，以图灵机与判定问题类比：他用图灵机给''可计算''下精确定义，并据此证明不存在能判定一切的通用算法——把模糊问题化为机械步骤、顺带照见极限（1936论文原文→确证）"}]},"further_reading":[{"title":"图灵《计算机器与智能》(1950) + 《论可计算数》(1936)","why":"图灵测试与可计算性的一手原文","type":"original"},{"title":"Andrew Hodges《Alan Turing: The Enigma》(1983)","why":"标准传记，确证破译并厘清团队归属、客观记述其生平","type":"biography"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/turing.png","avatar_thumb":"/advisors/portraits/turing.png","domain":"科学","person_id":"P-turing","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '9d77809f720ee6042e74dc13337dfddb4cc4b214c3ecfcfb5b239cb56c6e5685', 90, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('twain', 'P-twain', '马克·吐温', 'writing', '马克·吐温 · 讽刺与通俗叙事思维框架卡', '19世纪（1835—1910）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '讽刺幽默作批判 · 通俗口语化', '/advisors/portraits/twain.png', '/advisors/portraits/twain.png', 5, 0, '{"schema_version":1,"card_id":"twain","name":"马克·吐温","title":"马克·吐温 · 讽刺与通俗叙事思维框架卡","era":"19世纪（1835—1910）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"讽刺幽默作批判","definition":"把尖锐的批判包进幽默与讽刺里——人会笑着接受一个用说教会被抵触的观点，幽默是让批判穿透防御的载体","source":"马克·吐温《镀金时代》及讽刺随笔","source_tier":"primary","mechanism":"输入=尖锐的批判直接说会被抵触/防御 → 处理=把批判包进幽默与讽刺里、让人笑着接受 → 输出=批判穿透防御被接受","trigger":"要传递尖锐批判、怕被抵触时","modern_transfer":"把尖锐的批判包进幽默与讽刺里——人会笑着接受一个用说教会被抵触的观点；幽默是让批判穿透防御的载体(但别让笑声稀释了严肃)","architecture":{"type":"flow","components":["尖锐批判易被抵触","包进幽默讽刺","让人笑着接受","批判穿透防御"]},"strategy_card_image":"kb-assets/twain/model-1.png"},{"name":"通俗口语化","definition":"用大众真实的口语/方言来写，而非端着的书面雅言——贴近普通人的语言，作品才能真正抵达大众、有生命力","source":"马克·吐温《哈克贝利·费恩历险记》（方言口语）","source_tier":"primary","mechanism":"输入=端着的书面雅言、离普通人远 → 处理=用大众真实的口语/方言来写、贴近普通人 → 输出=作品抵达大众、有生命力","trigger":"想让表达抵达大众时","modern_transfer":"用大众真实的口语/方言来写、而非端着的书面雅言——贴近普通人的语言，作品才能真正抵达大众、有生命力(《哈克》用方言口语)","architecture":{"type":"flow","components":["别端着书面雅言","用大众口语方言","贴近普通人语言","抵达大众"]},"strategy_card_image":"kb-assets/twain/model-2.png"},{"name":"共情视角","definition":"借一个底层/孩子/局外人的\"天真\"眼睛来看世界——这个视角既能照出社会的虚伪、又能唤起读者的共情","source":"马克·吐温《哈克贝利·费恩历险记》（哈克的视角）","source_tier":"primary","mechanism":"输入=直接议论难唤起共情、看不到社会虚伪 → 处理=借一个底层/孩子/局外人的天真眼睛看世界 → 输出=既照出社会虚伪、又唤起共情(哈克的眼睛)","trigger":"要照出社会虚伪/唤起共情时","modern_transfer":"借一个底层/孩子/局外人的眼睛来看世界——这个''天真''的视角既能照出社会的虚伪、又能唤起读者的共情(哈克看奴隶制)","architecture":{"type":"flow","components":["别直接议论","借底层孩子局外人的天真视角","照出社会虚伪","唤起共情"]},"strategy_card_image":"kb-assets/twain/model-3.png"},{"name":"具体细节胜过说教","definition":"用具体的人物、场景与细节去\"showing\"，而非抽象的\"telling\"说教——别说\"她很害怕\"，让她当场尖叫给读者看","source":"马克·吐温论写作","source_tier":"primary","mechanism":"输入=抽象的telling说教、读者无感 → 处理=用具体的人物/场景/细节去showing → 输出=读者看见而非被说教(别说她害怕、让她尖叫)","trigger":"想打动读者而非说教时","modern_transfer":"用具体的人物、场景与细节去''showing''、而非抽象的''telling''说教——别说''她很害怕''、让她当场尖叫给读者看；具体永远比议论有力","architecture":{"type":"flow","components":["别抽象telling说教","用具体人物场景细节","showing给读者看","读者看见而非被说教"]},"strategy_card_image":"kb-assets/twain/model-4.png"},{"name":"精炼有力","definition":"砍掉多余的修饰、追求最精准有力的那个词与表达——\"对的词\"与\"差不多对的词\"之间，是闪电与萤火虫之别","source":"马克·吐温论用词","source_tier":"primary","mechanism":"输入=表达冗余、用了''差不多对''的词 → 处理=砍掉多余修饰、追求最精准有力的那个词 → 输出=对的词(闪电vs萤火虫之别)","trigger":"打磨表达、追求精准时","modern_transfer":"砍掉多余的修饰、追求最精准有力的那个词与表达——''对的词''与''差不多对的词''之间、是闪电与萤火虫之别","architecture":{"type":"flow","components":["砍掉多余修饰","在对的词与差不多对的词间","选最精准有力的","闪电而非萤火虫"]},"strategy_card_image":"kb-assets/twain/model-5.png"}],"decision_principles":["把尖锐批判包进幽默讽刺，让人笑着接受而非被说教抵触","用大众真实的口语/方言写，贴近普通人才抵达大众","借底层/孩子/局外人的天真视角，照出虚伪又唤起共情","用具体场景''showing''，别抽象''telling''说教","追求''对的词''而非''差不多对的词''——闪电与萤火虫之别"],"inquiry_questions":["你能不能借一个底层/孩子/局外人的眼睛来讲这件事？那个''天真''的视角会照出什么？","你要传递的尖锐观点，能不能包进幽默讽刺里、让人笑着接受、而非被说教抵触？","你用的是端着的书面雅言、还是普通人真实的口语？哪种更能抵达受众？","你是在抽象议论(''她很害怕'')、还是用具体场景让读者''看见''(''让她尖叫'')？","这里用的是''对的词''、还是''差不多对的词''？能不能换上那个精准的？"],"value_priorities":["幽默讽刺的穿透 ＞ 正面说教的抵触（人会笑着接受、却抵触说教）","大众的口语 ＞ 端着的雅言（贴近普通人语言才有生命力）","具体的 showing ＞ 抽象的 telling（别说她害怕、让她尖叫）"],"blind_spots":["幽默/讽刺可能稀释严肃议题、或被误读为纯娱乐，削弱批判的明确性（原理推断，B）。","〔慎〕其作品（尤《哈克贝利·费恩》）使用了当时具冒犯性的种族用语，虽用于批判奴隶制，但在当代引发持续争议与教学争论（史实/评议，B，客观标注）。","通俗口语化的成功依赖作者对方言/大众语言的精准把握，模仿不当会流于油滑或失真（原理推断，B）。","马克·吐温本人在商业投资上屡屡失败、曾因此破产，其商业判断与文学才华不相称（史实，B）。"],"applicable_domains":["表达说服","创作表达","价值与伦理"],"match_tags":["表达说服","创作表达","价值与伦理","攻心共识","批判思辨","极简主义","近代北美"],"linked_cases":["twain-c1","twain-c2","twain-c3"],"life_tags":[{"tag":"著顽童历险记","tier":"primary"},{"tag":"著汤姆索亚","tier":"primary"},{"tag":"当河轮领航员","tier":"secondary"},{"tag":"著王子与贫儿","tier":"primary"}],"voice_profile":{"notes":"幽默诙谐、亦庄亦谐；辛辣讽刺、举重若轻；贴近大众的口语；外冷内热、悲悯人性"},"references":[{"ref_id":"twain-s1","title":"马克·吐温《哈克贝利·费恩历险记》《汤姆·索亚历险记》","locator":"哈克方言口语、天真视角、具体场景叙事","source_tier":"primary","supports_models":["通俗口语化","共情视角","具体细节胜过说教"],"supports_cases":["twain-c1"],"note":"一手·代表作"},{"ref_id":"twain-s2","title":"马克·吐温《镀金时代》及讽刺随笔/演讲","locator":"讽刺贪婪腐败","source_tier":"primary","supports_models":["讽刺幽默作批判"],"supports_cases":["twain-c2"],"note":"一手·讽刺作品"},{"ref_id":"twain-s3","title":"马克·吐温论写作（书信/随笔/自传）","locator":"对的词、showing 与 telling","source_tier":"primary","supports_models":["精炼有力","具体细节胜过说教"],"supports_cases":["twain-c3"],"note":"一手·写作 craft"}],"material_type":"rich","reasoning_skeleton":{"signature":"把尖锐批判包进幽默讽刺、让人笑着接受(讽刺幽默作批判)；用大众口语方言写、贴近普通人才抵达大众(通俗口语化)；借底层/孩子/局外人的天真视角看、照出虚伪又唤共情(共情视角)；用具体人物场景showing而非抽象说教telling(具体细节胜过说教)；砍掉多余、追求最精准有力的那个词(精炼有力)","steps":[{"invoke":"共情视角","action":"你能不能借一个底层/孩子/局外人的眼睛来讲这件事？那个''天真''的视角会照出什么、唤起什么？"},{"invoke":"讽刺幽默作批判","action":"你要传递的尖锐观点，能不能包进幽默讽刺里、让人笑着接受、而非被说教抵触？"},{"invoke":"通俗口语化","action":"你用的是端着的书面雅言、还是普通人真实的口语？哪种更能抵达你的受众？"},{"invoke":"具体细节胜过说教","action":"你是在抽象议论(''她很害怕'')、还是用具体场景让读者''看见''(''让她尖叫'')？"},{"invoke":"精炼有力","action":"这里用的是''对的词''、还是''差不多对的词''？能不能砍掉多余、换上那个精准的？"}],"contrast":"与奥威尔不同(关键差异·同为创作传播)：**奥威尔以''清晰语言对抗操纵/政治写作/智识诚实''抵抗欺骗、冷峻直白**；**马克吐温以''讽刺幽默/通俗口语/共情视角''打动大众、举重若轻**——奥威尔是清晰诚实的政治抵抗、吐温是幽默共情的大众叙事(见奥威尔卡)。与狄更斯不同：狄更斯以''社会叙事+连载悬念+人物群像''的宏大结构唤起对社会问题的共情；吐温更靠幽默讽刺+方言+局外人视角、更轻盈尖刻(见狄更斯卡)。【射程/盲区·〔慎〕】吐温之道在''用幽默讲批判、用方言抵达大众、用天真视角照虚伪''极有力，但①幽默/讽刺可能稀释严肃议题、或被误读为纯娱乐；②〔慎〕其作品(尤《哈克》)使用了当时具冒犯性的种族用语、虽为批判奴隶制、但在当代引发争议与教学争论；③通俗口语化依赖对方言的精准把握、模仿不当会流于油滑失真。适用表达说服/创作表达/价值与伦理；不适用投资/危机应对。"},"persona_anchor":{"primary":[{"source":"case","case_id":"twain-c1","note":"用户''想批判一种社会虚伪、又不想板着脸说教''时，以《哈克贝利·费恩》类比：吐温借少年哈克的天真视角与方言口语、让读者透过一个孩子的眼睛看到奴隶制的荒谬与吉姆的人性——天真视角既照出虚伪、又唤起共情，比直接议论有力（《哈克》为吐温代表作→确证）"},{"source":"case","case_id":"twain-c2","note":"用户''要批评贪婪/腐败/浮夸、怕太尖锐被抵触''时，以吐温讽刺《镀金时代》类比：他用幽默讽刺包裹对镀金时代贪婪与腐败的尖锐批判、让人笑着接受——幽默是让批判穿透防御的载体（《镀金时代》为吐温与共同作者所著、并由其命名一个时代→确证）"}]},"further_reading":[{"title":"马克·吐温《哈克贝利·费恩历险记》《汤姆·索亚历险记》","why":"方言口语、天真视角、共情叙事的一手代表作","type":"original"},{"title":"马克·吐温《镀金时代》及论写作的随笔/书信/自传","why":"讽刺批判与\"对的词\"等写作craft的一手出处","type":"original"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/twain.png","avatar_thumb":"/advisors/portraits/twain.png","domain":"创作","person_id":"P-twain","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '93f24f02f0f1e5269db9de52e94bd809471addf1db058034f3c862ef7d687e44', 91, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('vonneumann', 'P-vonneumann', '约翰·冯·诺依曼', 'science', '冯·诺依曼 · 形式化思维框架卡', '20世纪（1903—1957）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '形式化优先 · 极小化极大', '/advisors/portraits/vonneumann.png', '/advisors/portraits/vonneumann.png', 5, 0, '{"schema_version":1,"card_id":"vonneumann","name":"约翰·冯·诺依曼","title":"冯·诺依曼 · 形式化思维框架卡","era":"20世纪（1903—1957）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"形式化优先","definition":"先把混乱问题翻译成精确的数学结构/公理，再求解——结构对了，解法自现","source":"《量子力学的数学基础》等","source_tier":"primary","mechanism":"输入=混乱问题、在含糊状态下硬解 → 处理=先把它翻译成精确的数学结构/公理、再求解 → 输出=结构对了解法自现","trigger":"面对混乱/含糊的问题时","modern_transfer":"动手前先把混乱的问题翻译成一个精确的形式结构/公理、再去求解——结构立清楚了、解法自然浮现；别在含糊状态下硬解(冯诺依曼把量子力学公理化为希尔伯特空间)","architecture":{"type":"flow","components":["混乱问题别在含糊下硬解","翻译成精确的数学结构公理","再去求解","结构对了解法自现"]},"strategy_card_image":"kb-assets/vonneumann/model-1.png"},{"name":"极小化极大","definition":"对抗局面里假设对手会走最优一手，先把\"最坏情况下的最大损失\"压到最小","source":"1928极小化极大定理；1944《博弈论与经济行为》","source_tier":"primary","mechanism":"输入=对抗局面、赌对手会失误或走常招 → 处理=假设对手会走最优一手、先把''最坏情况下的最大损失''压到最小 → 输出=先保最坏情况不崩(minimax)","trigger":"对抗/博弈局面、要做决策时","modern_transfer":"对抗局面里、假设对手会走''最优''的一手、先把''最坏情况下的最大损失''压到最小——别赌对手失误或走常招(冯诺依曼极小化极大定理)","architecture":{"type":"flow","components":["对抗局面别赌对手失误","假设对手走最优一手","把最坏情况的最大损失压到最小","先保最坏情况不崩"]},"strategy_card_image":"kb-assets/vonneumann/model-2.png"},{"name":"通用架构抽象","definition":"把程序与数据都放进同一存储、机器可重配置——造通用底座而非一堆专用件","source":"1945《EDVAC报告初稿》","source_tier":"primary","mechanism":"输入=为每个需求堆专用件 → 处理=造一个可重配置的通用底座(程序与数据放进同一存储、机器可重配置) → 输出=通用底座而非一堆专用件(存储程序架构)","trigger":"要造一个系统/方案时","modern_transfer":"造一个可被重配置成多种用途的''通用底座''、而非为每个需求堆一堆专用件——把程序与数据放进同一存储、机器可重配置(冯诺依曼存储程序架构、现代计算机的基础)","architecture":{"type":"hierarchy","components":["别为每个需求堆专用件","程序与数据放进同一存储","机器可重配置","造通用底座"]},"strategy_card_image":"kb-assets/vonneumann/model-3.png"},{"name":"跨域结构迁移","definition":"同一套数学结构常能解不同领域的问题——把它从量子搬到经济、计算、生物","source":"其横跨QM/经济/计算/自复制的工作","source_tier":"primary","mechanism":"输入=换个领域就从零开始 → 处理=同一套数学结构常能解不同领域的问题、把它从一个域搬到另一个域 → 输出=结构迁移解新领域(从量子到经济到计算)","trigger":"进入一个新领域时","modern_transfer":"进入新领域前先问：我手上有没有现成的某套数学结构、能直接搬来套这个新问题？——同一套结构常能解不同领域的问题(冯诺依曼把结构从量子搬到经济、计算、自复制)","architecture":{"type":"flow","components":["换个领域别从零开始","看手上现成的数学结构","把它从一个域搬到另一个域","结构迁移解新领域"]},"strategy_card_image":"kb-assets/vonneumann/model-4.png"},{"name":"数值模拟","definition":"解析啃不动时，用随机抽样大量模拟去逼近答案（蒙特卡洛）","source":"蒙特卡洛方法（与Ulam，1940s末）","source_tier":"primary","mechanism":"输入=解析解啃不动、卡死 → 处理=用随机抽样大量模拟去逼近答案(蒙特卡洛) → 输出=用模拟逼近解析啃不动的答案","trigger":"解析解啃不动时","modern_transfer":"解析地想不通、啃不动时、改用大量的随机抽样模拟去逼近答案(冯诺依曼与Ulam的蒙特卡洛方法、用于曼哈顿计划的中子扩散)","architecture":{"type":"flow","components":["解析解啃不动卡死","改用随机抽样","大量模拟","逼近答案"]},"strategy_card_image":"kb-assets/vonneumann/model-5.png"}],"decision_principles":["动手前先把问题翻译成精确的形式结构，别在含糊状态下硬解","对抗决策中，按对手的最优应对来规划，而非他大概会怎么走","造可重配置的通用系统，别为每个需求堆专用件","解析解啃不动时，改用大量随机模拟去逼近","换个领域前先问：这里能不能套用我已掌握的某套数学结构？"],"inquiry_questions":["你这问题，能不能先翻译成一个精确的形式结构？哪部分还是含糊的？","如果这是对抗局面，对手的最优一手是什么？你按那个规划了吗？","你在造专用方案，还是一个能被重配置成多种用途的通用底座？","解析地想不通的话，能不能用大量模拟去逼近答案？","你手上有没有现成的数学结构，能直接搬来套这个新领域？"],"value_priorities":["精确形式化 ＞ 直觉式的含糊把握（结构没立清楚、再聪明的求解都悬空）","按对手最优应对规划 ＞ 赌对手会失误或走常招（极小化极大的底色——先保最坏情况不崩）","通用可重配置 ＞ 一事一造的专用方案（存储程序架构正是这一取向的产物）"],"blind_spots":["极小化极大假设完全理性的对手——真实的人与局面更乱，过度理性化会误判（学术分析，B）。","把一切问题数学化的倾向：有些问题（价值、意义、人心）抗拒形式化，硬套会失真（学术分析，B）。","〔慎〕冷战核战略上的鹰派立场极具争议——其博弈式理性推出过''预防性打击''之类令人不安的结论（史料，B，客观标注）。","才华横溢的速度有时取代了深掘：广度惊人，但少见对单一问题的长期独钻（传记，B）。"],"applicable_domains":["创新研发","竞争博弈","风险评估"],"match_tags":["创新研发","竞争博弈","风险评估","系统分析","对抗性思维","多元模型","现当代北美"],"linked_cases":["vonneumann-c1","vonneumann-c2","vonneumann-c3","vonneumann-c4"],"life_tags":[{"tag":"创冯氏架构","tier":"secondary"},{"tag":"奠基博弈论","tier":"primary"},{"tag":"参曼哈顿计划","tier":"secondary"},{"tag":"研细胞自动机","tier":"secondary"}],"voice_profile":{"notes":"极快、形式化、抽象；纵横多领域；冷峻理性；好以数学结构看世界"},"references":[{"ref_id":"vonneumann-s1","title":"冯·诺依曼《量子力学的数学基础》","locator":"量子力学的希尔伯特空间公理化","source_tier":"primary","supports_models":["形式化优先"],"supports_cases":["vonneumann-c1"],"note":"一手·原著"},{"ref_id":"vonneumann-s2","title":"极小化极大定理 / 《博弈论与经济行为》","locator":"minimax、零和博弈","source_tier":"primary","supports_models":["极小化极大","跨域结构迁移"],"supports_cases":["vonneumann-c2"],"note":"一手·定理/原著"},{"ref_id":"vonneumann-s3","title":"1945《EDVAC报告初稿》","locator":"存储程序架构","source_tier":"primary","supports_models":["通用架构抽象"],"supports_cases":["vonneumann-c3"],"note":"一手·报告"},{"ref_id":"vonneumann-s4","title":"蒙特卡洛方法（与Ulam）","locator":"随机模拟、曼哈顿计划中子扩散","source_tier":"primary","supports_models":["数值模拟","跨域结构迁移"],"supports_cases":["vonneumann-c4"],"note":"一手·方法"}],"material_type":"rich","reasoning_skeleton":{"signature":"动手前先把混乱问题翻译成精确的形式结构再求解(形式化优先)；对抗局面假设对手走最优、先把最坏情况的最大损失压到最小(极小化极大)；造可重配置的通用底座而非一堆专用件(通用架构抽象)；同一套数学结构搬到不同领域(跨域结构迁移)；解析啃不动时用大量随机模拟逼近(数值模拟)","steps":[{"invoke":"形式化优先","action":"你这问题，能不能先翻译成一个精确的形式结构？哪部分还是含糊的？"},{"invoke":"极小化极大","action":"如果这是对抗局面，对手的最优一手是什么？你按那个规划了吗？"},{"invoke":"通用架构抽象","action":"你在造专用方案，还是一个能被重配置成多种用途的通用底座？"},{"invoke":"跨域结构迁移","action":"你手上有没有现成的数学结构，能直接搬来套这个新领域？"},{"invoke":"数值模拟","action":"解析地想不通的话，能不能用大量模拟去逼近答案？"}],"contrast":"与图灵不同(关键差异·计算机科学的两位奠基者)：**图灵是''可计算性的理论''——用通用图灵机界定''什么可被机械计算''、是抽象的数学理论**；**冯诺依曼是''形式化+工程化的通用架构''——把存储程序架构落成可造的通用计算机、并横跨博弈论/数值模拟**——图灵立理论边界、冯诺依曼造通用底座与跨域应用(见图灵卡)。与牛顿不同：牛顿公理化自然规律；冯诺依曼形式化+跨域结构迁移(见牛顿卡)。与爱因斯坦/费曼区分：他们是物理直觉/思想实验；冯诺依曼是形式化+博弈+模拟。【射程/盲区·〔慎〕】冯诺依曼之道在''形式化、极小化极大、通用架构、跨域迁移、数值模拟''极有力，但①极小化极大假设完全理性的对手、真实的人与局面更乱、过度理性化会误判；②把一切问题数学化的倾向、有些问题(价值、意义、人心)抗拒形式化、硬套会失真；③〔慎〕其冷战核战略上的鹰派立场极具争议、其博弈式理性推出过''预防性打击''之类令人不安的结论(客观标注)；④才华横溢的速度有时取代了深掘、广度惊人但少见对单一问题的长期独钻。适用创新研发/竞争博弈/风险评估；不适用价值与伦理/修身自省/人际关系。"},"persona_anchor":{"primary":[{"source":"case","case_id":"vonneumann-c1","note":"用户''在一个含糊混乱的问题上凭直觉硬解、绕不出来''时，以冯诺依曼把量子力学公理化类比：他把当时各说各话的量子力学翻译成希尔伯特空间的精确数学结构、结构一立清楚、许多问题迎刃而解——动手前先把混乱问题形式化、结构对了解法自现（《量子力学的数学基础》1932 为其原著→确证）"},{"source":"case","case_id":"vonneumann-c2","note":"用户''在一个对抗局面里、赌对手会失误或走常招''时，以冯诺依曼极小化极大类比：他证明在零和对抗中、应假设对手走最优一手、先把''最坏情况下的最大损失''压到最小——别赌对手犯错、先保最坏情况不崩（极小化极大定理1928、《博弈论与经济行为》1944 为其工作→确证）"}]},"further_reading":[{"title":"冯·诺依曼《量子力学的数学基础》《博弈论与经济行为》(与摩根斯特恩)","why":"形式化优先、极小化极大的一手出处（A）","type":"original"},{"title":"1945《EDVAC报告初稿》、蒙特卡洛方法","why":"通用架构抽象（存储程序）、数值模拟的一手出处（A）","type":"原著/报告"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/vonneumann.png","avatar_thumb":"/advisors/portraits/vonneumann.png","domain":"科学","person_id":"P-vonneumann","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '62841330ff48d1320a5c2e30c3ffe0014d0ad0776a6d09ae3c3e316057c2deab', 92, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('walton', 'P-walton', '山姆·沃尔顿', 'business', '山姆·沃尔顿 · 天天低价与下沉扎根思维框架卡', '现代（1918—1992）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '天天低价 · 极致成本控制', '/advisors/portraits/walton.png', '/advisors/portraits/walton.png', 5, 0, '{"schema_version":1,"card_id":"walton","name":"山姆·沃尔顿","title":"山姆·沃尔顿 · 天天低价与下沉扎根思维框架卡","era":"现代（1918—1992）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"天天低价","definition":"不靠忽高忽低的促销噱头，而是持续把价格压到最低、薄利多销，让顾客信任\"每天都是低价\"","source":"沃尔顿《Made in America》及沃尔玛EDLP","source_tier":"primary","mechanism":"输入=靠促销/高低价游戏吸引顾客 → 处理=持续把价格压到最低、薄利多销、让顾客信任''每天都是低价'' → 输出=以持续低价赢得长期信任与规模(EDLP)","trigger":"要赢得顾客长期信任/做零售定价时","modern_transfer":"别靠忽高忽低的促销噱头——持续把价格压到最低、薄利多销、让顾客信任''每天都是低价''(EDLP, Everyday Low Price);用稳定的低价赢得长期信任与规模(沃尔玛核心)","architecture":{"type":"flow","components":["别靠促销高低价游戏","持续把价格压到最低","薄利多销","让顾客信任每天都是低价"]},"strategy_card_image":"kb-assets/walton/model-1.png"},{"name":"极致成本控制","definition":"把每一分运营成本抠到极致，把省下的钱让利给顾客——低成本支撑低价的飞轮","source":"沃尔顿《Made in America》","source_tier":"primary","mechanism":"输入=成本松散、加价高 → 处理=把每一分运营成本抠到极致、把省下的让利给顾客 → 输出=低成本支撑低价的飞轮","trigger":"要支撑低价/建成本优势时","modern_transfer":"把每一分运营成本抠到极致、把省下来的钱让利给顾客——低成本才能支撑低价、低价带来规模、规模又压低成本(沃尔顿本人极度节俭、连办公室都很简朴)","architecture":{"type":"loop","components":["别让成本松散加价高","把每分成本抠到极致","省下的让利给顾客","低成本支撑低价的飞轮"]},"strategy_card_image":"kb-assets/walton/model-2.png"},{"name":"农村包围城市","definition":"避开大对手，先在他们看不上的小镇/下沉市场扎根，做到密集再向外扩张","source":"沃尔玛早期扩张史","source_tier":"primary","mechanism":"输入=去大城市跟巨头正面硬拼 → 处理=避开大对手、先在被忽视的小镇/下沉市场扎根、做到密集再扩张 → 输出=在对手看不上的地方坐大","trigger":"面对强大对手、选市场切入点时","modern_transfer":"别一上来就去大城市跟巨头正面硬拼——避开大对手、先在他们看不上的小镇/下沉市场扎根、做到密集再向外扩张(沃尔玛早期专攻被忽视的美国小镇、避开西尔斯等巨头)","architecture":{"type":"flow","components":["别去大城市跟巨头硬拼","避开大对手","先在被忽视的小镇扎根","做密集再向外扩张"]},"strategy_card_image":"kb-assets/walton/model-3.png"},{"name":"亲临一线巡店","definition":"不只坐总部看报表，亲自跑遍一线门店、在现场看、向员工和竞争对手学，好点子立刻抄","source":"沃尔顿《Made in America》","source_tier":"primary","mechanism":"输入=坐在总部看报表决策 → 处理=亲自跑遍一线门店、在现场看、向员工和对手学、好点子立刻抄 → 输出=决策扎根一线、快速学习复制","trigger":"要做零售/运营决策、了解一线时","modern_transfer":"别只坐在总部看报表——亲自跑遍一线门店、在现场看、向员工和竞争对手学、好点子立刻抄过来(沃尔顿一生不停巡店、连竞争对手的店也仔细逛)","architecture":{"type":"flow","components":["别只在总部看报表","亲自跑遍一线门店","向员工和对手学","好点子立刻抄复制"]},"strategy_card_image":"kb-assets/walton/model-4.png"},{"name":"善待同事激励","definition":"把一线员工当\"同事(associates)\"，给利润分享与参与感，让一线有主人翁意识","source":"沃尔顿《Made in America》","source_tier":"primary","mechanism":"输入=把一线员工当纯成本/执行工具 → 处理=把员工称为''同事''、利润分享、让一线有主人翁感 → 输出=一线的主动性(但实践有争议、见盲区)","trigger":"要激发一线积极性时","modern_transfer":"把一线员工当''同事(associates)''、给利润分享与参与感、让他们有主人翁意识——一线的积极性是零售的关键(沃尔顿的理念);〔但沃尔玛实际的劳工待遇有争议、见盲区〕","architecture":{"type":"flow","components":["别把一线员工当纯成本","把员工称为同事","给利润分享与参与感","让一线有主人翁意识"]},"strategy_card_image":"kb-assets/walton/model-5.png"}],"decision_principles":["别靠促销噱头，持续把价格压到最低、让顾客信任每天都是低价","把每分成本抠到极致，把省下的让利给顾客","避开大对手，先在被忽视的小镇扎根、做密集再扩张","亲自跑一线、向员工和对手学，好点子立刻抄","把一线员工当同事、给参与感与主人翁意识"],"inquiry_questions":["你是靠忽高忽低的促销噱头，还是持续把价格压到最低让顾客信任每天都是低价？","你的成本是松散的，还是每一分都抠到极致、把省下的让利给顾客？","你是一上来就去大城市跟巨头硬拼，还是先在他们看不上的地方扎根坐大？","你是坐在总部看报表，还是亲自跑一线、向员工和对手学好点子立刻抄？","你把一线员工当纯成本，还是当同事给参与感与主人翁意识？"],"value_priorities":["持续天天低价 ＞ 忽高忽低的促销噱头（EDLP用稳定低价赢得长期信任）","避开巨头下沉扎根 ＞ 去大城市正面硬拼（先在被忽视的小镇坐大）","亲临一线学习 ＞ 总部看报表（连对手店也逛、好点子立刻抄）"],"blind_spots":["〔注意〕沃尔玛的实际劳工待遇（低薪、反工会等）广受批评，与''善待同事''的理念存在张力，本卡客观标注（史实，B）。","沃尔玛的扩张对许多小镇本地零售业造成冲击（''Walmart effect''），有显著的社会争议（史实，B，客观标注）。","''天天低价+极致成本''的打法以巨大的规模与议价权为前提，小企业难照搬（原理推断，B）。","其线下零售模式在电商时代受到根本挑战，同一套打法未必长青（原理推断，B）。"],"applicable_domains":["创业","组织管理","资源调度"],"match_tags":["创业","组织管理","资源调度","务实渐进","逆向思考","实验试错","现当代北美"],"linked_cases":["walton-c1","walton-c2","walton-c3","walton-c4"],"life_tags":[{"tag":"创办沃尔玛","tier":"secondary"},{"tag":"推天天平价","tier":"secondary"},{"tag":"著富甲美国","tier":"primary"},{"tag":"创山姆会员店","tier":"secondary"}],"voice_profile":{"notes":"朴实节俭、接地气；对成本与价格极敏感；亲临一线、好学好抄；重一线员工"},"references":[{"ref_id":"walton-s1","title":"山姆·沃尔顿《Made in America》","locator":"天天低价、极致成本、下沉小镇、亲临巡店、善待同事","source_tier":"primary","supports_models":["天天低价","极致成本控制","农村包围城市","亲临一线巡店","善待同事激励"],"supports_cases":["walton-c1","walton-c2","walton-c3","walton-c4"],"note":"一手·自传"},{"ref_id":"walton-s2","title":"沃尔玛（Walmart）企业史","locator":"早期专攻小镇、规模扩张","source_tier":"secondary","supports_models":["农村包围城市"],"supports_cases":["walton-c2"],"note":"二手·企业史"}],"material_type":"rich","reasoning_skeleton":{"signature":"别靠促销噱头、持续把价格压到最低让顾客信任每天都是低价(天天低价)；把每分成本抠到极致、省下的让利给顾客(极致成本控制)；避开大对手先在被忽视的小镇扎根做密集再扩张(农村包围城市)；亲自跑遍一线向员工和对手学好点子立刻抄(亲临一线巡店)；把员工当同事给利润分享与主人翁感(善待同事激励)","steps":[{"invoke":"天天低价","action":"你是靠忽高忽低的促销噱头、还是持续把价格压到最低让顾客信任每天都是低价？"},{"invoke":"极致成本控制","action":"你的成本是松散的、还是每一分都抠到极致、把省下的让利给顾客？"},{"invoke":"农村包围城市","action":"你是一上来就去大城市跟巨头硬拼、还是先在他们看不上的地方扎根坐大？"},{"invoke":"亲临一线巡店","action":"你是坐在总部看报表、还是亲自跑一线、向员工和对手学好点子立刻抄？"},{"invoke":"善待同事激励","action":"你把一线员工当纯成本、还是当同事给参与感与主人翁意识？"}],"contrast":"与贝索斯不同(关键差异·同为零售/低价/规模巨头)：**贝索斯是''电商+飞轮+长期主义+客户痴迷''、线上的无限货架与数据驱动**；**沃尔顿是''线下实体零售+天天低价(EDLP)+下沉小镇+亲临巡店''、线下的密集网点与一线学习**——一个线上飞轮、一个线下扎根(见贝索斯卡)。与洛克菲勒不同：洛克菲勒是石油的运营垄断与成本控制；沃尔顿是零售的EDLP+下沉(见洛克菲勒卡)。与福特不同：福特是制造业的流水线规模化降本；沃尔顿是零售业的供应链与门店规模化降本(见福特卡)。【射程/盲区·〔注意〕】沃尔顿之道在''天天低价、极致成本、下沉扎根、亲临一线、善待同事''极有力，但①〔注意〕沃尔玛实际劳工待遇(低薪/反工会)广受批评、与''善待同事''理念存在张力；②沃尔玛扩张对小镇本地零售造成冲击(''Walmart effect'')、有显著社会争议；③''天天低价+极致成本''以巨大规模与议价权为前提、小企业难照搬；④其线下模式在电商时代受根本挑战、同套打法未必长青。适用创业/组织管理/资源调度；不适用投资/创新研发。"},"persona_anchor":{"primary":[{"source":"case","case_id":"walton-c1","note":"用户''纠结要不要靠促销噱头忽高忽低地刺激销量''时，以沃尔顿天天低价类比：沃尔玛不玩忽高忽低的促销、而是持续把价格压到最低、让顾客信任''每天都是低价''(EDLP)——用稳定的低价赢得长期信任与规模，比促销噱头更扎实（EDLP为沃尔顿《Made in America》所述→确证）"},{"source":"case","case_id":"walton-c2","note":"用户''一上来就想去最大的市场跟最强的对手正面硬拼''时，以沃尔顿农村包围城市类比：沃尔玛早期专攻被西尔斯等巨头忽视的美国小镇、在那里把网点做密集、坐大之后再向外扩张——先在对手看不上的地方扎根（沃尔玛早期专攻小镇为其史实→确证）"}]},"further_reading":[{"title":"山姆·沃尔顿《Made in America》","why":"天天低价、极致成本、下沉小镇、亲临巡店、善待同事的一手自传（A）","type":"original"},{"title":"沃尔玛（Walmart）企业史","why":"早期专攻小镇、规模扩张的记录（B）","type":"企业史"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/walton.png","avatar_thumb":"/advisors/portraits/walton.png","domain":"商业","person_id":"P-walton","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '554117bac562df26f06c17d76fbd420cf287084f2c0fcaa59601b39135452035', 93, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('wanganshi', 'P-wanganshi', '王安石', 'governance', '王安石 · 理财变法与制度创新思维框架卡', '北宋（1021—1086）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '理财为先 · 制度性理财创新', '/advisors/portraits/wanganshi.png', '/advisors/portraits/wanganshi.png', 5, 0, '{"schema_version":1,"card_id":"wanganshi","name":"王安石","title":"王安石 · 理财变法与制度创新思维框架卡","era":"北宋（1021—1086）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"理财为先","definition":"一个组织积弱的根本往往在\"钱\"（经济与财政）没理顺，把开源、理财、把资源用活作为改革的核心抓手","source":"王安石变法主张","source_tier":"secondary","mechanism":"输入=组织积弱却只在人事或空谈上打转 → 处理=把开源、理财、把资源用活作为改革的核心抓手 → 输出=抓住积弱的根本(理财为先)","trigger":"诊断一个组织积弱的根本时","modern_transfer":"一个组织积弱的根本、往往在''钱''(经济与财政)没理顺——把开源、理财、把资源用活作为改革的核心抓手、而非只在人事或空谈上打转(王安石''理财为方今先急'')","architecture":{"type":"hierarchy","components":["别只在人事或空谈上打转","看清积弱的根本常在经济财政","把开源理财把资源用活","作为改革的核心抓手"]},"strategy_card_image":"kb-assets/wanganshi/model-1.png"},{"name":"制度性理财创新","definition":"用\"设计新制度\"的办法去解决资源问题（如青苗法以官贷抑高利贷、募役法以钱代役），靠制度创新而非临时摊派去开源、抑兼并","source":"王安石新法","source_tier":"secondary","mechanism":"输入=靠临时摊派或旧办法开源 → 处理=设计新制度(青苗以官贷抑高利贷、募役以钱代役)把财理活、抑兼并 → 输出=靠制度创新开源(制度性理财创新)","trigger":"要用制度的办法解决资源问题时","modern_transfer":"用''设计新制度''的办法去解决资源问题(如青苗法以官贷抑民间高利贷、募役法以钱代役)——靠制度创新而非临时摊派去开源、把资源从兼并者手里释放出来(王安石新法)〔但新制度在执行中极易走样、变成扰民、见盲区〕","architecture":{"type":"hierarchy","components":["别靠临时摊派或旧办法开源","设计新制度抑兼并","青苗以官贷抑高利贷募役以钱代役","靠制度创新把财理活"]},"strategy_card_image":"kb-assets/wanganshi/model-2.png"},{"name":"不畏人言果决变法","definition":"重大变革必招非议与阻力——\"天变不足畏、祖宗不足法、人言不足恤\"，不被舆论、惯例、成见绑住，果决推行","source":"王安石\"三不足\"","source_tier":"secondary","mechanism":"输入=被舆论、惯例、成见绑住而不敢改 → 处理=''天变不足畏、祖宗不足法、人言不足恤''、顶住非议果决推行 → 输出=改革推得动(不畏人言)","trigger":"重大变革招致非议与阻力时","modern_transfer":"重大变革必招非议与阻力——''天变不足畏、祖宗不足法、人言不足恤''、不被舆论、惯例、成见绑住、果决地推行你认准的改革(王安石三不足)〔但''不恤人言''也易刚愎自用、听不进真正的反对、见盲区〕","architecture":{"type":"flow","components":["别被舆论惯例成见绑住不敢改","天变不足畏祖宗不足法","人言不足恤","顶住非议果决推行"]},"strategy_card_image":"kb-assets/wanganshi/model-3.png"},{"name":"做大蛋糕而非分蛋糕","definition":"解决\"钱不够\"，与其只在存量上抠，不如\"因天下之力以生天下之财\"，靠把经济的盘子做大来增加财富","source":"王安石经济增长思路","source_tier":"secondary","mechanism":"输入=只在存量上抠、与民争利 → 处理=''因天下之力以生天下之财''、靠把经济做大来增加财富 → 输出=靠增量而非存量(做大蛋糕)","trigger":"面对''钱不够''、在增量与存量间取舍时","modern_transfer":"解决''钱不够''、与其只在存量上抠、不如''因天下之力以生天下之财''——靠发展、靠把经济的盘子做大来增加财富(王安石的经济增长思路)〔但实践中若变成国家垄断经营、也可能与民争利、见盲区〕","architecture":{"type":"flow","components":["别只在存量上抠与民争利","因天下之力以生天下之财","靠把经济做大","靠增量增加财富"]},"strategy_card_image":"kb-assets/wanganshi/model-4.png"},{"name":"系统配套的整体变法","definition":"重大改革是多个方面相互配套的系统工程（财政、军事、教育、科举），别只动一个点，要成体系地配套推进","source":"熙宁变法的系统性","source_tier":"secondary","mechanism":"输入=只动一个点、其他不配套 → 处理=财政、军事、教育、科举多方面相互配套地系统推进 → 输出=成体系的变法(系统配套)","trigger":"推一项牵涉多方面的大改革时","modern_transfer":"重大改革是多个方面相互配套的系统工程(王安石新法同时涉财政、军事保甲、教育科举)——别只动一个点、要成体系地配套推进〔但战线过宽、配套失调、操之过急也是其失败原因之一、见盲区〕","architecture":{"type":"hierarchy","components":["别只动一个点其他不配套","财政军事教育科举多方面","相互配套地系统推进","成体系的整体变法"]},"strategy_card_image":"kb-assets/wanganshi/model-5.png"}],"decision_principles":["组织积弱的根本常在经济财政，把理财作为改革的核心抓手","用设计新制度的办法开源、抑兼并（但防执行走样扰民）","顶住非议果决推行认准的改革（但别刚愎到听不进反对）","靠把盘子做大而非只在存量上抠（但防与民争利）","成体系地配套推进多方面改革（但防战线过宽、操之过急）"],"inquiry_questions":["这个组织积弱的根本，是不是''钱''（经济财政）没理顺？你抓住这个核心了吗？","你是靠临时摊派、还是靠设计新制度的办法去开源、把资源用活？","面对非议与阻力，你是被舆论成见绑住、还是顶住果决推行？（但别刚愎到听不进反对）","你是只在存量上抠、还是想办法把盘子做大来增加财富？","你是只动一个点、还是多方面相互配套地系统推进？（但防战线过宽）"],"value_priorities":["理财开源、把资源用活 ＞ 只在人事空谈上打转（理财为方今先急）","制度创新开源 ＞ 临时摊派（青苗、募役（但执行易走样））","做大盘子的增量 ＞ 只抠存量（因天下之力以生天下之财）"],"blind_spots":["新法理想良善、但执行中严重走样：青苗法等被地方官变成强制摊派、扰民、与民争利，背离了抑兼并惠民的初衷（史，B，客观标注）。","用人失察：变法被一些投机者借以聚敛、所托非人（史，B）。","''不恤人言''易刚愎自用、听不进合理的反对，激化了新旧党争、贻害深远（史，B，客观标注）。","战线过宽、操之过急、配套失调，也是变法受挫的重要原因（史，B）。"],"applicable_domains":["组织管理","长期规划","危机应对"],"match_tags":["组织管理","长期规划","危机应对","制度法治思维","系统分析","对抗性思维","古代东亚"],"linked_cases":["wanganshi-c1","wanganshi-c2","wanganshi-c3","wanganshi-c4"],"life_tags":[{"tag":"行熙宁变法","tier":"secondary"},{"tag":"行青苗法","tier":"secondary"},{"tag":"列唐宋八大家","tier":"secondary"},{"tag":"行募役法","tier":"secondary"}],"voice_profile":{"notes":"刚毅果决、自信执着；重理财与制度；锐意进取；不畏非议（亦失之刚愎）"},"references":[{"ref_id":"wanganshi-s1","title":"《宋史·王安石传》","locator":"理财为先、青苗募役、三不足、熙宁变法","source_tier":"secondary","supports_models":["理财为先","制度性理财创新","不畏人言果决变法","做大蛋糕而非分蛋糕","系统配套的整体变法"],"supports_cases":["wanganshi-c1","wanganshi-c2","wanganshi-c3","wanganshi-c4"],"note":"二手·史传"},{"ref_id":"wanganshi-s2","title":"王安石变法研究","locator":"新法成效、执行走样、党争","source_tier":"secondary","supports_models":["制度性理财创新","系统配套的整体变法"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"诊断组织积弱的根本在经济财政、把理财当核心抓手(理财为先)；用设计新制度的办法理财抑兼并(制度性理财创新)；不被舆论惯例成见绑住果决推行(不畏人言果决变法)；靠把经济做大而非只在存量上抠(做大蛋糕而非分蛋糕)；多方面相互配套地系统推进(系统配套的整体变法)","steps":[{"invoke":"理财为先","action":"这个组织积弱的根本，是不是''钱''（经济财政）没理顺？你抓住这个核心了吗？"},{"invoke":"制度性理财创新","action":"你是靠临时摊派、还是靠设计新制度的办法去开源、把资源用活？"},{"invoke":"不畏人言果决变法","action":"面对非议与阻力，你是被舆论成见绑住、还是顶住果决推行？（但别刚愎到听不进反对）"},{"invoke":"做大蛋糕而非分蛋糕","action":"你是只在存量上抠、还是想办法把盘子做大来增加财富？"},{"invoke":"系统配套的整体变法","action":"你是只动一个点、还是多方面相互配套地系统推进？（但防战线过宽）"}],"contrast":"与商鞅不同(关键差异·同为变法者)：**商鞅是''彻底重构社会的法家变法''(军功爵、什伍连坐、立法立信、严刑峻法)**；**王安石是''以经济财政为核心的制度创新变法''(理财为先、青苗募役市易、做大蛋糕)**——商鞅重构社会秩序与法度、王安石主攻经济财政与理财(见商鞅卡)。与张居正不同：张居正是''在既有体制内的行政整顿''(考成法绩效问责、一条鞭简化、整顿吏治);王安石是''主动设计新经济制度的变法''(理财创新、触动既得、引发党争)——张居正整顿运转、王安石创设新制(见张居正卡)。与管仲不同：管仲是''盐铁专营、通商富国的实操'';王安石是''青苗募役等制度性理财创新''(见管仲卡)。【射程/盲区·历史诚实·重点】王安石之道在''理财为先、制度性理财创新、不畏人言、做大蛋糕、系统配套''极有力(尤其改革的魄力与制度创新)，但①新法理想良善、执行中严重走样:青苗法等被变成强制摊派、扰民、与民争利、背离初衷;②用人失察、变法被投机者借以聚敛;③''不恤人言''易刚愎自用、激化新旧党争、贻害深远;④战线过宽、操之过急、配套失调。适用组织管理/长期规划/危机应对;不适用创作/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"wanganshi-c2","note":"用户''想解决一个资源/钱的问题、但只会靠临时摊派或旧办法''时，以王安石制度性理财创新类比：他用''设计新制度''的办法理财——青苗法以官府低息贷款抑制民间高利贷盘剥、募役法以交钱代替服劳役;靠制度创新而非临时摊派去开源、把资源从兼并者手里释放出来〔但须警惕:这些新法在执行中严重走样、变成强制摊派扰民，制度设计还要顾及执行〕（青苗募役为《宋史》及熙宁变法史所载→确证）"},{"source":"case","case_id":"wanganshi-c3","note":"用户''认准了一项改革、却被''祖宗成法''''舆论非议''''恐惹麻烦''绑住手脚''时，以王安石''三不足''类比：''天变不足畏、祖宗不足法、人言不足恤''——别被舆论、惯例、成见绑住、果决地推行你认准的改革〔但务必区分:''不恤人言''不等于听不进合理的反对;王安石正因刚愎、激化党争而埋下败因，果决与纳谏要并存〕（三不足为王安石名言、《宋史》所载→确证）"}]},"further_reading":[{"title":"《宋史·王安石传》","why":"理财为先、青苗募役、三不足、熙宁变法的史述（B）","type":"史传"},{"title":"王安石变法研究","why":"对新法成效、执行走样与党争的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/wanganshi.png","avatar_thumb":"/advisors/portraits/wanganshi.png","domain":"治理","person_id":"P-wanganshi","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'd60cf054b5e87591efb13dcfbfecf2fefca4ea85d3b6dc47e18c039e9d1175cb', 94, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('wangyangming', 'P-wangyangming', '王阳明', 'philosophy', '王阳明 · 知行合一心学思维框架卡', '明（1472—1529）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '知行合一 · 致良知', '/advisors/portraits/wangyangming.png', '/advisors/portraits/wangyangming.png', 5, 0, '{"schema_version":1,"card_id":"wangyangming","name":"王阳明","title":"王阳明 · 知行合一心学思维框架卡","era":"明（1472—1529）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"知行合一","definition":"把\"知\"与\"行\"当一体——真正的知必然导向行，知而不行只是未知；用行动来检验和完成认知","source":"《传习录》（知是行之始、行是知之成）","source_tier":"primary","mechanism":"输入=知道却不做、把知与行分成两截 → 处理=把''知''与''行''当一体、真正的知必然导向行、用行动检验完成认知 → 输出=知行合一(知而不行只是未知)","trigger":"知道却迟迟不行动时","modern_transfer":"把''知''与''行''当一体——真正的知必然导向行动，知道了却不做、其实是还没真懂；用行动去检验和完成你的认知(知是行之始、行是知之成)","architecture":{"type":"loop","components":["别把知行分两截","真知必导向行","用行动检验认知","知行合一"]},"strategy_card_image":"kb-assets/wangyangming/model-1.png"},{"name":"致良知","definition":"遇事回到内心本有的是非直觉（良知）、剥除私欲与外界的遮蔽、依这份清明的判断而行","source":"《传习录》（致良知）","source_tier":"primary","mechanism":"输入=遇事被私欲/外界干扰、看不清该怎么做 → 处理=回到内心本有的是非直觉(良知)、剥除私欲遮蔽、依良知而行 → 输出=依内心清明的是非判断行动","trigger":"遇事难抉择、被私欲外界干扰时","modern_transfer":"遇事回到内心本有的是非直觉(良知)、剥除私欲与外界的遮蔽、依这份清明的判断而行——很多时候你其实知道什么是对的、只是被遮住了(致良知)","architecture":{"type":"flow","components":["遇事回到内心","剥除私欲遮蔽","显出良知判断","依良知而行"]},"strategy_card_image":"kb-assets/wangyangming/model-2.png"},{"name":"事上磨练","definition":"心性与能力要在具体的事务、困境中磨练，而非静坐空想——在事上练，才长真本事","source":"《传习录》（人须在事上磨练）","source_tier":"primary","mechanism":"输入=只静坐空想、不在实事中练 → 处理=心性与能力要在具体事务、困境中磨练 → 输出=在事上练才长真本事(而非纸上谈兵)","trigger":"想提升心性/能力、却只空想时","modern_transfer":"心性与能力要在具体的事务、困境中磨练、而非静坐空想——''人须在事上磨练做功夫乃有益''；在事上练，才长真本事","architecture":{"type":"flow","components":["别只静坐空想","投入具体事务困境","在事上磨练心性能力","长出真本事"]},"strategy_card_image":"kb-assets/wangyangming/model-3.png"},{"name":"心即理","definition":"答案与准则不在外部权威或繁琐考据里、而在你自己的本心——向内求、而非一味向外逐求标准答案","source":"《传习录》《年谱》（心即理 / 龙场悟道）","source_tier":"primary","mechanism":"输入=一味向外部权威/繁琐考据求标准答案 → 处理=答案与准则在自己本心、向内求而非向外逐 → 输出=回到本心找根本依据(不外逐)","trigger":"一味向外求标准答案时","modern_transfer":"答案与准则不在外部权威或繁琐考据里、而在你自己的本心——向内求、而非一味向外逐求标准答案(心即理、心外无理)","architecture":{"type":"hierarchy","components":["别一味向外逐求","回到自己本心","在心中求理与准则","不假外部权威"]},"strategy_card_image":"kb-assets/wangyangming/model-4.png"},{"name":"破心中贼难","definition":"外在的困难（山中贼）好破，内心的私欲杂念（心中贼）难破——把功夫真正下在克治自己的内心上","source":"王阳明书信（破山中贼易、破心中贼难）","source_tier":"primary","mechanism":"输入=只对付外在困难、忽视内心的私欲杂念 → 处理=认清真正难破的是内心的私欲杂念(心中贼)、把功夫下在克治内心 → 输出=克治内心才是根本","trigger":"面对困难、尤其内心私欲作祟时","modern_transfer":"外在的困难(山中贼)好破、内心的私欲杂念(心中贼)难破——把功夫真正下在克治自己的内心上，那才是根本(''破山中贼易、破心中贼难'')","architecture":{"type":"hierarchy","components":["认清外难易破内贼难破","私欲杂念是真敌人","把功夫下在克治内心","破心中贼才是根本"]},"strategy_card_image":"kb-assets/wangyangming/model-5.png"}],"decision_principles":["把知与行当一体——知而不行，只是未知","遇事回到内心良知、剥除私欲遮蔽，依良知而行","心性能力在具体事务困境中磨练，而非静坐空想","答案与准则向内求，而非一味向外逐求标准答案","真正难破的是内心私欲杂念，把功夫下在克治内心"],"inquiry_questions":["遇到这事，剥开私欲与外界干扰，你内心那份是非直觉其实怎么说？","你说你''知道''，可你做了吗？知而不行，其实是还没真懂","你是在静坐空想，还是在具体的事和困境里真刀真枪地磨练？","你是一味向外部权威/标准答案逐求，还是回到自己本心找根本依据？","外在的困难之外，真正难破的是不是你内心的私欲杂念？"],"value_priorities":["知行合一的真知 ＞ 知而不行的空知（知是行之始、行是知之成）","事上磨练 ＞ 静坐空想（在事上练才长真本事）","克治内心（破心中贼） ＞ 只对付外在困难（破山中贼易、破心中贼难）"],"blind_spots":["致良知/心即理高度依赖个人内心的''良知''判断、缺乏外部客观标准，易流于主观或被自我合理化（思想评议，B）。","其心学被后世某些末流引向空疏狂禅（只谈本心、束书不观）——王阳明本人重事功，但流派易走偏（思想史，B）。","《传习录》部分为弟子记录的语录体、字句经整理（书信部分为本人手笔、较可靠）（史料，B）。","知行合一在复杂专业领域，仅凭良知与行动不足以替代专业知识与方法（原理推断，B）。"],"applicable_domains":["修身自省","领导力","危机应对","价值与伦理"],"match_tags":["修身自省","领导力","危机应对","价值与伦理","第一性原理","务实渐进","直觉决断","古代东亚"],"linked_cases":["wangyangming-c1","wangyangming-c2","wangyangming-c3"],"life_tags":[{"tag":"创心学","tier":"primary"},{"tag":"倡知行合一","tier":"primary"},{"tag":"平宁王叛","tier":"secondary"},{"tag":"龙场悟道","tier":"secondary"}],"voice_profile":{"notes":"简切有力、直指本心；重实行实功；既是大儒又能事功；破除繁琐、贵在笃行"},"references":[{"ref_id":"wangyangming-s1","title":"《传习录》","locator":"知行合一、致良知、事上磨练、心即理、破心中贼诸条（语录+书信）","source_tier":"primary","supports_models":["知行合一","致良知","事上磨练","心即理","破心中贼难"],"supports_cases":["wangyangming-c1","wangyangming-c3"],"note":"一手·语录体含本人书信；语录部分经弟子整理"},{"ref_id":"wangyangming-s2","title":"《王阳明年谱》","locator":"龙场悟道、平宁王之乱","source_tier":"secondary","supports_models":["心即理"],"supports_cases":["wangyangming-c1","wangyangming-c2"],"note":"二手·生平年谱"},{"ref_id":"wangyangming-s3","title":"《明史·王守仁传》","locator":"平宁王之乱、事功","source_tier":"secondary","supports_models":["知行合一"],"supports_cases":["wangyangming-c2"],"note":"二手·正史纪传"}],"material_type":"rich","reasoning_skeleton":{"signature":"把知与行当一体、真知必导向行、知而不行只是未知(知行合一)；遇事回到内心良知、剥除私欲遮蔽依良知而行(致良知)；心性能力在具体事务困境中磨练而非空想(事上磨练)；答案与准则向内求而非一味外逐(心即理)；真正难破的是内心私欲杂念、把功夫下在克治内心(破心中贼难)","steps":[{"invoke":"致良知","action":"遇到这事，剥开私欲与外界干扰，你内心那份是非直觉(良知)其实怎么说？"},{"invoke":"知行合一","action":"你说你''知道''，可你做了吗？知而不行，其实是还没真懂"},{"invoke":"事上磨练","action":"你是在静坐空想，还是在具体的事和困境里真刀真枪地磨练？"},{"invoke":"心即理","action":"你是一味向外部权威/标准答案逐求，还是回到自己本心找根本依据？"},{"invoke":"破心中贼难","action":"外在的困难之外，真正难破的是不是你内心的私欲杂念？功夫下在那了吗？"}],"contrast":"与孔子不同(关键差异·同为儒家)：**孔子是入世伦理秩序的原典(正名/忠恕/修己/中庸)**；**王阳明是心学的实践方法论(知行合一/致良知/事上磨练/向内求)**——孔子立伦理规范、王阳明给''如何在行动与内心上做功夫''的操作法(见孔子卡)。与老子不同：老子是无为辩证、顺自然不强为；王阳明是积极有为、在事上磨练、知行合一(见老子卡)。与苏格拉底不同：苏格拉底用诘问助产、向外辩证求真；王阳明向内求、致良知(一个外向诘问、一个内向求理)(见苏格拉底卡)。与马可奥勒留/庄子区分：奥勒留斯多葛控制二分、庄子齐物逍遥；王阳明知行合一心学。【射程/盲区】王阳明心学在''打通知与行、在事上磨练、克治内心''极有力(他本人既是大儒又能平宁王之乱)，但①致良知/心即理高度依赖个人内心判断、缺外部客观标准、易流于主观或自我合理化；②其心学末流易引向空疏狂禅(只谈本心、束书不观)；③知行合一在复杂专业领域、仅凭良知与行动不足以替代专业知识。适用修身自省/领导力/危机应对/价值与伦理；不适用投资/创新研发。"},"persona_anchor":{"primary":[{"source":"case","case_id":"wangyangming-c1","note":"用户''一味向外求标准答案/权威、却越求越乱''时，以龙场悟道类比：王阳明被贬贵州龙场绝境中悟''圣人之道、吾性自足、向之求理于事物者误也''——答案与准则在自己本心、向内求而非一味外逐（龙场悟道为《年谱》《传习录》明载→确证）"},{"source":"case","case_id":"wangyangming-c2","note":"用户''光想/光说不做、或临大事手足无措''时，以平定宁王之乱类比：王阳明以少胜多、四十余日平朱宸濠叛乱——把心学之''知''落到果决之''行''、知行合一、临危致良知而决（平宁王之乱为《明史》明载→确证）"}]},"further_reading":[{"title":"《传习录》","why":"知行合一/致良知/事上磨练/心即理的一手出处（语录+本人书信）","type":"原典"},{"title":"《王阳明年谱》《明史·王守仁传》","why":"龙场悟道、平宁王之乱等生平事功的可靠记载","type":"史料"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/wangyangming.png","avatar_thumb":"/advisors/portraits/wangyangming.png","domain":"哲学","person_id":"P-wangyangming","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'f6b7b4b6d19d1a003c699939463844fdbece0ac940f743d7fe371a6cda3103df', 95, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('wangyongqing', 'P-wangyongqing', '王永庆', 'business', '王永庆 · 瘦鹅理论与追根究底思维框架卡', '现代（1917—2008）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '瘦鹅理论 · 追根究底', '/advisors/portraits/wangyongqing.png', '/advisors/portraits/wangyongqing.png', 5, 0, '{"schema_version":1,"card_id":"wangyongqing","name":"王永庆","title":"王永庆 · 瘦鹅理论与追根究底思维框架卡","era":"现代（1917—2008）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"瘦鹅理论","definition":"身处逆境时像熬过饥荒的瘦鹅一样忍耐，先把基础养好、积蓄实力，等环境好转再一举壮大","source":"王永庆经营理念","source_tier":"secondary","mechanism":"输入=逆境中急于求成或自暴自弃 → 处理=像瘦鹅熬过饥荒、忍耐、把基础/体质养好、积蓄实力、等环境好转 → 输出=环境一好转就迅速壮大","trigger":"身处逆境/环境恶劣时","modern_transfer":"身处逆境、环境恶劣时——像熬过饥荒的瘦鹅一样忍耐、先把基础和体质养好、积蓄实力、等环境好转再一举壮大；别在逆境中急于求成或自暴自弃(王永庆瘦鹅理论)〔前提:逆境会过去、见盲区〕","architecture":{"type":"flow","components":["逆境中别急于求成或自弃","像瘦鹅一样忍耐","把基础养好积蓄实力","环境好转再一举壮大"]},"strategy_card_image":"kb-assets/wangyongqing/model-1.png"},{"name":"追根究底","definition":"凡事追根究底，一层层刨到问题最根部的原因，点点滴滴求合理化，止于至善","source":"王永庆管理风格","source_tier":"secondary","mechanism":"输入=问题只看表面、浅尝辄止 → 处理=凡事追根究底、一层层刨到最根部的原因、点点滴滴求合理化 → 输出=挖到根因、持续改善(止于至善)","trigger":"面对一个问题/低效环节时","modern_transfer":"凡事追根究底——一层层刨到问题最根部的原因、把每个环节点点滴滴地求合理化、不满足于表面的解决(王永庆''追根究底、止于至善''的管理风格)","architecture":{"type":"hierarchy","components":["别看表面就算了","一层层刨到最根部原因","点点滴滴求合理化","持续改善止于至善"]},"strategy_card_image":"kb-assets/wangyongqing/model-2.png"},{"name":"压力管理","definition":"给目标和团队设定高标准、持续加压、追问到底，用压力把潜力逼出来","source":"王永庆\"午餐汇报\"等管理实践","source_tier":"secondary","mechanism":"输入=目标松、不施压、潜力没逼出来 → 处理=设定高目标、持续加压、追问到底 → 输出=用压力逼出潜力与极限","trigger":"要逼出团队/自己的潜力时","modern_transfer":"给目标和团队设定高标准、持续加压、追问到底——用压力把潜力逼出来(王永庆著名的''午餐汇报''层层追问)；但须把握度、过度施压也会反噬(见盲区)","architecture":{"type":"flow","components":["别让目标松不施压","设定高目标持续加压","追问到底","用压力逼出潜力"]},"strategy_card_image":"kb-assets/wangyongqing/model-3.png"},{"name":"垂直整合","definition":"从上游原料到下游产品一条龙自己整合，掌控全产业链的成本与质量","source":"台塑集团石化全产业链","source_tier":"secondary","mechanism":"输入=只做产业链一环、受制于上下游 → 处理=从上游原料到下游产品一条龙自己做、掌控全链条 → 输出=控制全链条的成本与质量","trigger":"受制于上下游、想掌控成本质量时","modern_transfer":"从上游原料到下游产品一条龙自己整合、掌控全产业链——不受制于上下游、把全链条的成本与质量握在自己手里(王永庆把台塑做成石化全产业链)","architecture":{"type":"hierarchy","components":["别只做一环受制于上下游","从上游到下游一条龙整合","掌控全产业链","控制全链条成本与质量"]},"strategy_card_image":"kb-assets/wangyongqing/model-4.png"},{"name":"成本极致合理化","definition":"把每一分成本抠到极致，每个环节点点滴滴地求合理化，点滴累积成巨大的成本优势","source":"王永庆成本管理","source_tier":"secondary","mechanism":"输入=成本粗放、不抠细节 → 处理=把每一分成本抠到极致、每个环节点点滴滴合理化 → 输出=点滴合理化累积成巨大成本优势","trigger":"要建立成本竞争力时","modern_transfer":"把成本一分一厘抠到极致、每个环节都点点滴滴地求合理化——这些点滴的合理化累积起来、就是巨大的成本优势与''价廉物美''(王永庆的成本管理)","architecture":{"type":"flow","components":["别让成本粗放","把每一分成本抠到极致","每个环节点滴求合理化","累积成成本优势"]},"strategy_card_image":"kb-assets/wangyongqing/model-5.png"}],"decision_principles":["身处逆境时像瘦鹅一样忍耐、积蓄实力，等环境好转再一举壮大","凡事追根究底，刨到问题最根部，点点滴滴求合理化","给目标和团队设高标准、持续加压逼出潜力（但把握度）","从上游到下游一条龙整合，掌控全产业链的成本与质量","把成本一分一厘抠到极致，点滴合理化累积成优势"],"inquiry_questions":["身处逆境，你是急于求成/自暴自弃，还是像瘦鹅一样忍耐、积蓄实力等环境好转？","这个问题，你是看了表面就算了，还是追根究底刨到了最根部？","你给目标和团队设的标准够高、加的压够逼出潜力吗？（但别过度）","你是受制于上下游，还是把全链条整合到自己手里？","你的成本是粗放的，还是一分一厘抠到极致、点滴求合理化？"],"value_priorities":["忍耐积蓄待时 ＞ 逆境中急于求成或自弃（瘦鹅熬过饥荒、一旦有食立刻肥壮）","追根究底 ＞ 表面解决浅尝辄止（止于至善、点点滴滴求合理化）","掌控全产业链 ＞ 受制于上下游（台塑石化全产业链）"],"blind_spots":["瘦鹅理论以''逆境会过去、环境终会好转''为前提；若环境持续恶化或行业根本性衰退，一味忍耐积蓄反而错失转型时机（原理推断，B）。","压力管理过度会导致团队高压、健康受损与人才流失，须把握度（原理推断，B）。","其追根究底+成本极致的精细管理在制造业极有效，对需要快速试错/高容错的创新行业未必适用（原理推断，B）。","〔注意〕台塑的扩张也伴随一些环境与公共议题争议（如部分环保争议），本卡客观标注（B）。"],"applicable_domains":["创业","组织管理","长期规划"],"match_tags":["创业","组织管理","长期规划","系统分析","务实渐进","长期主义","现当代东亚"],"linked_cases":["wangyongqing-c1","wangyongqing-c2","wangyongqing-c3","wangyongqing-c4"],"life_tags":[{"tag":"创办台塑","tier":"secondary"},{"tag":"建长庚医院","tier":"secondary"},{"tag":"推瘦鹅理论","tier":"secondary"},{"tag":"白手起家米店","tier":"secondary"}],"voice_profile":{"notes":"勤俭务实、追根究底；韧性极强；对成本斤斤计较；严格要求、压力管理"},"references":[{"ref_id":"wangyongqing-s1","title":"王永庆传记与经营语录","locator":"瘦鹅理论、追根究底、午餐汇报、成本管理","source_tier":"secondary","supports_models":["瘦鹅理论","追根究底","压力管理","成本极致合理化"],"supports_cases":["wangyongqing-c1","wangyongqing-c2","wangyongqing-c3"],"note":"二手·传记/语录"},{"ref_id":"wangyongqing-s2","title":"台塑集团企业史","locator":"石化全产业链垂直整合","source_tier":"secondary","supports_models":["垂直整合"],"supports_cases":["wangyongqing-c4"],"note":"二手·企业史"}],"material_type":"rich","reasoning_skeleton":{"signature":"逆境中像瘦鹅一样忍耐、积蓄实力待环境好转(瘦鹅理论)；凡事追根究底刨到最根部、点点滴滴求合理化(追根究底)；设定高目标持续加压逼出潜力(压力管理)；从上游到下游一条龙整合掌控全链条(垂直整合)；把成本抠到极致、点滴合理化累积成优势(成本极致合理化)","steps":[{"invoke":"瘦鹅理论","action":"身处逆境，你是急于求成/自暴自弃，还是像瘦鹅一样忍耐、积蓄实力等环境好转？"},{"invoke":"追根究底","action":"这个问题，你是看了表面就算了，还是追根究底刨到了最根部？"},{"invoke":"压力管理","action":"你给目标和团队设的标准够高、加的压够逼出潜力吗？（但别过度）"},{"invoke":"垂直整合","action":"你是受制于上下游，还是把全链条整合到自己手里？"},{"invoke":"成本极致合理化","action":"你的成本是粗放的，还是一分一厘抠到极致、点滴求合理化？"}],"contrast":"与卡内基不同(关键差异·同重垂直整合)：**卡内基是''钢铁的垂直整合+规模制造+成本领先''的西方实业巨头**；**王永庆在石化垂直整合之外、更带着''瘦鹅理论(逆境韧性)+追根究底+压力管理''的华人精细管理风格**——同样垂直整合、王永庆多了一套东方式的韧性与点滴合理化(见卡内基卡)。与洛克菲勒不同：洛克菲勒是石油的运营垄断与成本控制；王永庆是石化全产业链+瘦鹅韧性(见洛克菲勒卡)。与松下幸之助不同：松下是''自来水哲学(低价普及)+水坝经营+事业部制''；王永庆是''瘦鹅理论+追根究底+成本极致''(见松下卡)。与稻盛和夫不同：稻盛是''阿米巴+敬天爱人''的哲学派；王永庆是''追根究底+成本合理化''的精细实干派(见稻盛和夫卡)。【射程/盲区】王永庆之道在''瘦鹅韧性、追根究底、压力管理、垂直整合、成本极致''极有力，但①瘦鹅理论以''逆境会过去''为前提、若环境持续恶化或行业根本性衰退、一味忍耐反而错失转型；②压力管理过度会致团队高压、健康受损与人才流失；③其精细管理在制造业极有效、对需快速试错/高容错的创新行业未必适用；④〔注意〕台塑扩张也伴随一些环境与公共议题争议。适用创业/组织管理/长期规划；不适用投资/谈判。"},"persona_anchor":{"primary":[{"source":"case","case_id":"wangyongqing-c1","note":"用户''身处逆境、环境恶劣、急得想冒进或想放弃''时，以王永庆瘦鹅理论类比：瘦鹅能忍饥、把体质底子养着、一旦有食立刻肥壮——逆境中别急于求成或自暴自弃、先忍耐、把基础和实力积蓄好、等环境好转再一举壮大（瘦鹅理论为王永庆经营理念→确证；惟以''逆境会过去''为前提）"},{"source":"case","case_id":"wangyongqing-c2","note":"用户''遇到问题只看表面、浅尝辄止就放过''时，以王永庆追根究底类比：他凡事一层层刨到问题最根部的原因、把每个环节点点滴滴地求合理化、追求''止于至善''——别满足于表面的解决（追根究底为王永庆管理风格→确证）"}]},"further_reading":[{"title":"王永庆传记与经营语录","why":"瘦鹅理论、追根究底、午餐汇报、成本管理的记述（B）","type":"传记/语录"},{"title":"台塑集团企业史","why":"石化全产业链垂直整合的实践记录（B）","type":"企业史"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/wangyongqing.png","avatar_thumb":"/advisors/portraits/wangyongqing.png","domain":"商业","person_id":"P-wangyongqing","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '54dbcc6b379b3fefd65ed7fd59e32f2cb4d60bcd65b3b888ac46c7f12381a8ec', 96, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('washington', 'P-washington', '乔治·华盛顿', 'governance', '华盛顿 · 限权与立制思维框架卡', '18世纪（1732—1799）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '主动交权立先例 · 我所行皆成先例', '/advisors/portraits/washington.png', '/advisors/portraits/washington.png', 5, 0, '{"schema_version":1,"card_id":"washington","name":"乔治·华盛顿","title":"华盛顿 · 限权与立制思维框架卡","era":"18世纪（1732—1799）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"主动交权立先例","definition":"在你本可继续掌权时主动放权，用自己的退出立下\"权力有限、可和平交接\"的先例","source":"华盛顿辞职/退隐相关一手文献及传记","source_tier":"secondary","mechanism":"输入=你本可继续掌权、但权力集中会成坏先例 → 处理=在能掌权时主动放权 → 输出=确立''权力有限、和平交接''的制度先例","trigger":"你本可继续掌权、但想立可持续制度时","modern_transfer":"在你本可继续掌权时主动放权——用自己的退出立下''权力有限、可和平交接''的先例，这比任何制度条文都更有说服力(辞总司令、两届即退)","architecture":{"type":"flow","components":["本可继续掌权","主动放权","立权力有限的先例","制度得以确立"]},"strategy_card_image":"kb-assets/washington/model-1.png"},{"name":"我所行皆成先例","definition":"当你是某事的\"第一个\"时，意识到你的每个行为都会成为后人遵循的范式，刻意审慎地立好先例","source":"华盛顿书信（\"行走在无人走过的土地上\"）","source_tier":"primary","mechanism":"输入=你是某事的''第一个''、无前例可循 → 处理=意识到你的每个行为都会成为后人遵循的范式、刻意立好先例 → 输出=用行为立下好的制度范式","trigger":"你是''第一个''、行为会被后人援引时","modern_transfer":"当你是''第一个''时，意识到你的每个行为都会成为后人遵循的范式——''我行走在无人走过的土地上''，所以刻意、审慎地用行为立下好先例","architecture":{"type":"flow","components":["意识到自己是第一个","每个行为都立范式","审慎刻意立好先例","范式被后人遵循"]},"strategy_card_image":"kb-assets/washington/model-2.png"},{"name":"超党派黏合","definition":"在分歧的各方之上做一个中立的、各方都接受的黏合点，用超党派姿态维系团结","source":"华盛顿内阁用人及告别演说（警告党争）","source_tier":"secondary","mechanism":"输入=组织内有对立派系、随时可能分裂 → 处理=自身超脱派争、做各方都接受的中立团结点(内阁纳对立双方) → 输出=用超党派姿态维系团结","trigger":"组织内派系对立、易分裂时","modern_transfer":"在分歧的各方之上做一个中立的、各方都接受的黏合点——把对立双方都纳进来(如内阁同时用对立两派)、自身超脱党争，用超党派姿态维系团结","architecture":{"type":"hierarchy","components":["识别对立派系","自身超脱派争","把各方纳入并平衡","做中立团结点"]},"strategy_card_image":"kb-assets/washington/model-3.png"},{"name":"克制立威","definition":"权威不靠扩张权力、而靠主动的自我约束赢得——越是在能夺权时克制不夺，威信越高","source":"纽堡兵变及交还军权相关史实/传记","source_tier":"secondary","mechanism":"输入=有机会扩权/夺权(被劝进/兵变) → 处理=靠主动的自我约束而非扩张权力赢威信、拒绝夺权 → 输出=越克制不夺权、威信越高","trigger":"有机会扩权但想赢长久威信时","modern_transfer":"权威不靠扩张权力、而靠主动的自我约束赢得——越是在能夺权时克制不夺(拒绝纽堡兵变、交还军权)，威信反而越高","architecture":{"type":"flow","components":["面对扩权机会","主动自我约束","拒绝夺权","以克制赢威信"]},"strategy_card_image":"kb-assets/washington/model-4.png"},{"name":"制度高于个人","definition":"主动让位给规则与机构，个人不凌驾制度——哪怕威望足以称王，也把权威交给制度而非自己","source":"拒绝王冠/告别演说相关史实","source_tier":"secondary","mechanism":"输入=个人威望足以凌驾规则/机构 → 处理=主动让位给规则与机构、个人不凌驾制度(拒王冠) → 输出=制度而非个人成为权威之源","trigger":"个人威望足以凌驾制度时","modern_transfer":"让位给规则与机构、个人不凌驾制度——哪怕你的威望足以称王，也把权威交给制度而非自己(拒绝王冠、和平移交)，制度才能比任何个人活得更久","architecture":{"type":"hierarchy","components":["个人威望足以凌驾","主动让位给制度","个人不凌驾规则","制度成权威之源"]},"strategy_card_image":"kb-assets/washington/model-5.png"}],"decision_principles":["在你本可继续掌权时主动放权，立可交接的先例","作为''第一个''，刻意用行为立好后人遵循的范式","在对立各方之上做中立的团结黏合点","靠自我约束而非扩权赢威信——能夺而不夺","让位给制度，个人不凌驾规则与机构"],"inquiry_questions":["你是不是某件事的''第一个''？你现在的每个行为都会成为后人援引的范式了吗？","你本可继续掌权，要不要主动放权、立一个''权力有限可交接''的先例？","你有机会扩权/夺权时，克制不夺、靠自我约束赢威信，是不是更长久？","面对对立派系，你能不能超脱党争、做各方都接受的中立团结点？","你的威望会不会凌驾了规则与机构？要不要把权威交给制度而非自己？"],"value_priorities":["制度的可持续 ＞ 个人的权位（主动放权立先例，制度比个人活得久）","克制与放权 ＞ 扩张权力（能夺而不夺，靠自我约束赢威信）","超党派的团结 ＞ 一派之胜（做中立黏合点维系团结（高度极化时未必可行））"],"blind_spots":["作为奴隶主，其毕生倡导的''自由''与蓄奴实践之间存在根本矛盾，是其遗产的重大道德污点（史实，B，客观标注，〔慎〕）。","其超党派的中立与个人威望，部分依赖其独特的历史时机与声望，未必可简单复制；在高度极化、必须选边的情境下，''超党派''未必可行（原理推断，B）。","主动放权在''权力真空会被野心者填补''的情境下有风险——其模式的成立依赖一个尚能托住的制度环境（原理推断，B）。","军事上并非战术天才（多次战役失利），其历史地位更多源于政治判断、坚韧与人格，而非战场指挥（史实，B）。"],"applicable_domains":["治理决策","领导力","长期规划"],"match_tags":["治理决策","领导力","长期规划","制度法治思维","长期主义","务实渐进","近代北美"],"linked_cases":["washington-c1","washington-c2","washington-c3","washington-c4"],"life_tags":[{"tag":"统帅大陆军","tier":"secondary"},{"tag":"任首任总统","tier":"secondary"},{"tag":"主持制宪","tier":"secondary"},{"tag":"发表告别演说","tier":"primary"}],"voice_profile":{"notes":"庄重克制、有分寸感；重荣誉与责任；审慎、不揽权；以身作则胜于雄辩"},"references":[{"ref_id":"washington-s1","title":"华盛顿《告别演说》及书信","locator":"''untrodden ground''、警告党争与外国纠葛、两届退段","source_tier":"primary","supports_models":["我所行皆成先例","超党派黏合","制度高于个人"],"supports_cases":["washington-c3"],"note":"一手·本人文本"},{"ref_id":"washington-s2","title":"Ron Chernow《Washington：A Life》及标准传记","locator":"辞职交权、纽堡兵变、内阁用人、蓄奴诸章","source_tier":"secondary","supports_models":["主动交权立先例","克制立威"],"supports_cases":["washington-c1","washington-c2","washington-c4"],"note":"B层·权威传记"},{"ref_id":"washington-s3","title":"美国建国史/一手文献集","locator":"辞职、两届退、和平移交相关","source_tier":"secondary","supports_models":["主动交权立先例","制度高于个人"],"supports_cases":["washington-c1","washington-c3"],"note":"建国史料，多源交叉"}],"material_type":"rich","reasoning_skeleton":{"signature":"在你本可继续掌权时主动放权立先例；意识到作为''第一个''你的每个行为都立范式、刻意立好先例；在对立各方之上做中立黏合点；靠自我约束而非扩权赢威信；让位给制度、个人不凌驾规则","steps":[{"invoke":"我所行皆成先例","action":"你是不是某件事的''第一个''？意识到你现在的每个行为都会成为后人援引的范式了吗？"},{"invoke":"主动交权立先例","action":"你本可继续掌权，要不要主动放权、立一个''权力有限可交接''的先例？"},{"invoke":"克制立威","action":"你有机会扩权/夺权时，克制不夺、靠自我约束赢威信，是不是更长久？"},{"invoke":"超党派黏合","action":"面对对立派系，你能不能超脱党争、做各方都接受的中立团结点？"},{"invoke":"制度高于个人","action":"你的威望会不会凌驾了规则与机构？要不要把权威交给制度而非自己？"}],"contrast":"与林肯不同(关键差异·同为治理/建国领袖)：**林肯在内战危机中以灵活手段维系联邦统一(目的坚定手段灵活)**；**华盛顿在建国之初以主动交权、立先例、克制不夺权来确立制度(自我限权建国)**——林肯是危机维系、华盛顿是立制限权(见林肯卡)。与曼德拉不同：曼德拉是转型期''和解换稳定+化敌为伙''；华盛顿是''主动放权+立先例''的限权建国(见曼德拉卡)。与俾斯麦不同(同为政治领袖)：俾斯麦是''现实政治+铁血+操控均势''为强权服务、扩张权力；华盛顿恰相反——靠克制与放权立威(见俾斯麦卡)。与管仲/商鞅区分：二者重富国强兵之术；华盛顿重权力的自我约束与制度先例。【射程/盲区】华盛顿之道适用于''立制/确立可持续治理''的情境；但①其威信部分依赖其独特的个人声望与历史时机、未必可简单复制；②作为奴隶主，''自由''实践与蓄奴的矛盾是其遗产的重大污点(客观标注，〔慎〕)；③超党派中立在高度极化、必须选边时未必可行；④主动放权在权力真空会被野心者填补时有风险。适用治理/领导/制度建设；不适用纯竞争博弈/创新研发。"},"persona_anchor":{"primary":[{"source":"case","case_id":"washington-c1","note":"用户''手握大权、功成名就后该不该主动放手''时，以辞去大陆军总司令类比：1783 战争胜利、他本可挟军威自重，却主动辞去总司令、把军权交还大陆会议、解甲归田，立下''军权服从文官、权力可交接''的先例（辞职交权为可考史实→确证）"},{"source":"case","case_id":"washington-c3","note":"用户''我威望正隆、要不要再干一任/恋栈''时，以两届即退类比：他在仍可连任、众望所归之际拒绝第三任、和平移交权力，亲手立下''两届为限''的传统(后成宪法惯例)，把权威交给制度而非个人（两届退、和平移交为可考史实→确证）"}]},"further_reading":[{"title":"Ron Chernow《Washington：A Life》(2010)","why":"权威全景传记，军权交还、立制限权、人格与蓄奴矛盾","type":"biography"},{"title":"华盛顿《告别演说》及书信","why":"''untrodden ground''、警告党争与外国纠葛、宪政立场一手文本","type":"原始文献"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/washington.png","avatar_thumb":"/advisors/portraits/washington.png","domain":"治理","person_id":"P-washington","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'f5c427ae902627d0eea81495610d1311106e3482ae6318495ad7f0b2d83275c2', 97, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('wuqi', 'P-wuqi', '吴起', 'strategy', '吴起 · 同甘共苦与在德不在险思维框架卡', '战国（前440—前381）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '与士卒同甘共苦 · 文德武备并重·在德不在险', '/advisors/portraits/wuqi.png', '/advisors/portraits/wuqi.png', 5, 0, '{"schema_version":1,"card_id":"wuqi","name":"吴起","title":"吴起 · 同甘共苦与在德不在险思维框架卡","era":"战国（前440—前381）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"与士卒同甘共苦","definition":"带队伍要与成员同甘共苦、设身处地关心他们、以身作则——你真心待他们，他们才肯为你效死力","source":"吴起为士卒吮疽","source_tier":"secondary","mechanism":"输入=将领高高在上、不顾士卒 → 处理=与成员同甘共苦、设身处地关心、以身作则 → 输出=换取效死力(同甘共苦)","trigger":"带一支队伍、要赢得真心追随时","modern_transfer":"带队伍、要与成员同甘共苦、设身处地关心他们、以身作则——你真心待他们、他们才肯为你效死力(吴起亲为士卒吮吸脓疮、与士卒同衣食同甘苦)〔须真心而非手段、见盲区〕","architecture":{"type":"flow","components":["别将领高高在上不顾士卒","与成员同甘共苦","设身处地关心以身作则","换取士卒效死力"]},"strategy_card_image":"kb-assets/wuqi/model-1.png"},{"name":"文德武备并重·在德不在险","definition":"一个组织/国家的安危，根本在内部的人心、治理与凝聚（文德），而非只靠外在的天险、护城河或武力（武备）","source":"吴起\"在德不在险\"","source_tier":"primary","mechanism":"输入=只靠外在的天险护城河武力、忽视内部人心 → 处理=看清安危根本在内部的人心治理(文德) → 输出=德是根本(在德不在险)","trigger":"判断一个组织的安危根本何在时","modern_transfer":"一个组织/国家的安危、根本在内部的人心、治理与凝聚(文德)、而非只靠外在的天险、护城河或武力(武备)——''在德不在险''(吴起);两者并重、但德是根本","architecture":{"type":"hierarchy","components":["别只靠外在的天险护城河武力","看清安危根本在内部","在人心治理与凝聚文德","德是根本在德不在险"]},"strategy_card_image":"kb-assets/wuqi/model-2.png"},{"name":"因敌制胜的料敌","definition":"别用一套打法对所有对手——先详细分析这个具体对手的特点、习性与弱点，再因敌制定专门的取胜之策","source":"吴起《吴子·料敌》","source_tier":"primary","mechanism":"输入=用一套打法对所有对手 → 处理=详析这个具体对手的特点习性弱点、因敌制策 → 输出=因敌制胜(料敌)","trigger":"面对不同的具体对手时","modern_transfer":"别用一套打法对所有对手——先详细分析这个具体对手的特点、习性与弱点、再因敌制定专门的取胜之策(吴起《吴子·料敌》详析不同敌人之策)","architecture":{"type":"flow","components":["别用一套打法对所有对手","详析这个具体对手的特点习性弱点","因敌制定专门的取胜之策","因敌制胜"]},"strategy_card_image":"kb-assets/wuqi/model-3.png"},{"name":"法治治军赏罚必信","definition":"以严明的法度、清晰且必信（说到做到）的赏罚来治理队伍——令必行、禁必止；赏罚的\"必信\"比\"轻重\"更重要","source":"吴起治军","source_tier":"secondary","mechanism":"输入=赏罚随意、说话不算 → 处理=以严明法度、清晰且必信的赏罚治军、令行禁止 → 输出=必信比轻重更重要(法治治军)","trigger":"要治理一支队伍、立威信时","modern_transfer":"以严明的法度、清晰且必信(说到做到)的赏罚来治理队伍——令必行、禁必止;赏罚的''必信''比赏罚的''轻重''更重要(吴起治军)","architecture":{"type":"hierarchy","components":["别赏罚随意说话不算","以严明法度清晰且必信的赏罚","令必行禁必止","赏罚的必信比轻重更重要"]},"strategy_card_image":"kb-assets/wuqi/model-4.png"},{"name":"选练精兵","definition":"与其追求人多，不如把队伍训练成真正精锐、训练有素、能以一当十的\"精兵\"","source":"吴起选练魏武卒","source_tier":"secondary","mechanism":"输入=只追求人多 → 处理=选拔训练精锐、把队伍练成能以一当十的精兵 → 输出=精兵制胜(选练精兵)","trigger":"要打造一支高战力的队伍时","modern_transfer":"与其追求人多、不如把队伍训练成真正精锐、训练有素、能以一当十的''精兵''(吴起选练''魏武卒''、以精兵制胜)〔但精兵的选拔标准与维持成本也高、见盲区〕","architecture":{"type":"flow","components":["别只追求人多","选拔训练精锐","把队伍练成能以一当十","以精兵制胜"]},"strategy_card_image":"kb-assets/wuqi/model-5.png"}],"decision_principles":["与成员同甘共苦、设身处地关心、以身作则，换取真心追随（须真心）","组织的安危根本在内部人心与治理（文德），而非只靠外在天险（在德不在险）","详析具体对手的特点与弱点，因敌制定专门的取胜之策","以严明法度、必信（说到做到）的赏罚治理，赏罚的''必信''比''轻重''更重要","与其人多，不如把队伍练成能以一当十的精兵"],"inquiry_questions":["你是高高在上、还是与成员同甘共苦、设身处地关心、以身作则？","你的安危是只靠外在的天险/护城河/武力、还是根本在内部的人心与治理？","你是用一套打法对所有对手、还是详析具体对手的特点与弱点因敌制策？","你的赏罚是随意、还是严明且必信（说到做到）？","你是只追求人多、还是把队伍练成能以一当十的精兵？"],"value_priorities":["内部人心为根本 ＞ 只靠外在天险（在德不在险）","必信的赏罚 ＞ 随意说话不算（赏罚必信比轻重更重要）","以一当十的精兵 ＞ 只追求人多（魏武卒）"],"blind_spots":["吴起本人''刻薄少恩''、为功名不择手段（传杀妻求将、母死不奔丧——多有争议与传说成分），个人德行历来有争议（史，B，客观标注、含传说成分）。","''与士卒同甘共苦''若只是手段而非真心，终会被看穿（原理推断，B）。","选练精兵的高标准与成本，不适合资源有限或需要快速扩张的场景（原理推断，B）。","吴起在魏、楚均因功高震主、触动既得利益而不得善终（楚国变法后被旧贵族射杀）（史，B）。"],"applicable_domains":["组织管理","竞争博弈","领导力"],"match_tags":["组织管理","竞争博弈","领导力","攻心共识","制度法治思维","务实渐进","古代东亚"],"linked_cases":["wuqi-c1","wuqi-c2","wuqi-c3","wuqi-c4"],"life_tags":[{"tag":"著吴子兵法","tier":"primary"},{"tag":"守西河郡","tier":"secondary"},{"tag":"变法于楚","tier":"secondary"},{"tag":"创练魏武卒","tier":"secondary"}],"voice_profile":{"notes":"治军严整、与士同甘；重人心与文德；料敌制胜；刚毅而争议"},"references":[{"ref_id":"wuqi-s1","title":"《吴子》、《史记·孙子吴起列传》","locator":"同甘共苦、在德不在险、料敌、法治治军、选练精兵","source_tier":"primary","supports_models":["与士卒同甘共苦","文德武备并重·在德不在险","因敌制胜的料敌","法治治军赏罚必信","选练精兵"],"supports_cases":["wuqi-c1","wuqi-c2","wuqi-c3","wuqi-c4"],"note":"一手/二手·兵书与史传"},{"ref_id":"wuqi-s2","title":"先秦兵家研究","locator":"吴起军事思想、生平争议","source_tier":"secondary","supports_models":["与士卒同甘共苦","文德武备并重·在德不在险"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"与成员同甘共苦设身处地关心以身作则换取效死力(与士卒同甘共苦)；组织安危根本在内部人心治理文德而非只靠外在天险(文德武备并重在德不在险)；详析具体对手特点弱点因敌制定专门取胜之策(因敌制胜的料敌)；以严明法度必信的赏罚治理令行禁止(法治治军赏罚必信)；与其人多不如练成能以一当十的精兵(选练精兵)","steps":[{"invoke":"与士卒同甘共苦","action":"你是高高在上、还是与成员同甘共苦、设身处地关心、以身作则？"},{"invoke":"文德武备并重·在德不在险","action":"你的安危是只靠外在的天险/护城河/武力、还是根本在内部的人心与治理？"},{"invoke":"因敌制胜的料敌","action":"你是用一套打法对所有对手、还是详析具体对手的特点与弱点因敌制策？"},{"invoke":"法治治军赏罚必信","action":"你的赏罚是随意、还是严明且必信（说到做到）？"},{"invoke":"选练精兵","action":"你是只追求人多、还是把队伍练成能以一当十的精兵？"}],"contrast":"与戚继光不同(关键差异·同为治军建军)：**戚继光重''募兵、阵法、操典的工程''(从零招募训练、设计鸳鸯阵、著兵书——建军的系统流程)**；**吴起重''将与士卒的关系与内部人心''(与士卒同甘共苦、在德不在险——带兵的人心维度)**——戚继光偏''练兵的工程''、吴起偏''带兵的人心与文德''(见戚继光卡)。与孙子不同：孙子是抽象的兵法原理总纲;吴起《吴子》更重具体的治军、料敌、带兵之道(见孙子卡)。与韩信不同：韩信重''临阵用兵的奇谋'';吴起重''治军带兵与文德武备''(见韩信卡)。【射程/盲区·〔慎〕】吴起之道在''同甘共苦、在德不在险、料敌、法治治军、选练精兵''极有力(尤其带兵、治军、凝聚人心)，但①吴起本人''刻薄少恩''、为功名不择手段(杀妻求将等多有争议与传说成分)、个人德行历来有争议、客观标注;②''同甘共苦''若只是手段而非真心终会被看穿;③选练精兵的高标准与成本不适合资源有限或需快速扩张的场景;④其在魏、楚均因功高震主、触动既得利益不得善终。适用组织管理/竞争博弈/领导力;不适用创作/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"wuqi-c1","note":"用户''想赢得团队真心的追随与效力、却高高在上、与成员有距离''时，以吴起同甘共苦类比：他身为大将、却与最底层的士卒同吃同住、有士卒生了脓疮、他竟亲自用嘴为其吮吸脓血;与成员同甘共苦、设身处地关心他们、以身作则、你真心待他们、他们才肯为你效死力（吴起吮疽为《史记》载→确证；惟须真心而非手段）"},{"source":"case","case_id":"wuqi-c2","note":"用户''以为自己的安全靠的是外在的壁垒(资源/护城河/规模/天险)、却忽视了内部的人心与治理''时，以吴起''在德不在险''类比：魏武侯夸山河险固可恃、吴起却说一个国家的安危''在德不在险''——若内部失德、人心离散、再险的山河也保不住;组织的安危根本在内部的人心、治理与凝聚(文德)、而非只靠外在的天险与武力（''在德不在险''为《史记》载吴起之论→确证）"}]},"further_reading":[{"title":"《吴子》、《史记·孙子吴起列传》","why":"同甘共苦、在德不在险、料敌、法治治军、选练精兵的出处（A/B）","type":"兵书/史传"},{"title":"先秦兵家研究","why":"对吴起军事思想与生平争议的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/wuqi.png","avatar_thumb":"/advisors/portraits/wuqi.png","domain":"战略","person_id":"P-wuqi","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '9c07e5fbe737717259610c010b178b9080e7d33a3fe42b41c951924707aa9806', 98, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('xuanzang', 'P-xuanzang', '玄奘', 'history', '玄奘 · 求真溯源与极致坚持思维框架卡', '唐（602—664）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'legendary', '求真溯源 · 断退之志', '/advisors/portraits/xuanzang.png', '/advisors/portraits/xuanzang.png', 5, 0, '{"schema_version":1,"card_id":"xuanzang","name":"玄奘","title":"玄奘 · 求真溯源与极致坚持思维框架卡","era":"唐（602—664）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"求真溯源","definition":"当二手材料彼此矛盾、残缺时，不在错本上无休止争辩，而是亲赴源头取权威原典，从根上解决分歧","source":"《大唐西域记》《大慈恩寺三藏法师传》","source_tier":"primary","mechanism":"输入=二手材料彼此矛盾残缺、在错本上争辩无解 → 处理=不争副本、亲赴源头取权威原典、从根上解决分歧 → 输出=回源头定分歧","trigger":"二手材料矛盾、争论无解时","modern_transfer":"当二手材料彼此矛盾、残缺、争论无解时，别在错本上无休止争辩——回到源头取权威原典、从根上解决分歧(玄奘西行求原典)","architecture":{"type":"hierarchy","components":["二手材料矛盾残缺","别在错本上争辩","亲赴源头取原典","从根上定分歧"]},"strategy_card_image":"kb-assets/xuanzang/model-1.png"},{"name":"断退之志","definition":"用\"宁向西一步死、不向东一步生\"式的预先承诺，把退路从选项中删除，逼自己只能向目标前进","source":"《大慈恩寺三藏法师传》","source_tier":"secondary","mechanism":"输入=给自己留退路、容易半途退缩 → 处理=用预先承诺把退路从选项中删除 → 输出=逼自己只能向目标前进","trigger":"重大目标上、易半途退缩时","modern_transfer":"在重大目标上、用预先承诺把退路从选项中删除——''宁向西一步死、不向东一步生''，逼自己只能向前(玄奘莫贺延碛断水立誓)；但前提是目标确实值得","architecture":{"type":"flow","components":["给自己留退路易退缩","预先承诺删除退路","把退路从选项中拿掉","逼自己只能向前"]},"strategy_card_image":"kb-assets/xuanzang/model-2.png"},{"name":"以学折服","definition":"在陌生环境靠真本事而非身份立信——把一门学问钻到能折服对手与权威的深度，以实力赢得尊重","source":"《大慈恩寺三藏法师传》","source_tier":"secondary","mechanism":"输入=在陌生环境靠身份/头衔立信、立不住 → 处理=把一门学问钻到能折服对手与权威的深度、以实力赢得尊重 → 输出=靠真本事立信(而非头衔)","trigger":"在陌生场合需立信时","modern_transfer":"在陌生环境靠真本事而非身份立信——把一门学问/技能钻到能折服对手与权威的深度、以实力赢得尊重(玄奘曲女城无遮大会无人能难)","architecture":{"type":"hierarchy","components":["别靠头衔立信","把一门学问钻到极深","深到能折服权威","以实力赢得尊重"]},"strategy_card_image":"kb-assets/xuanzang/model-3.png"},{"name":"完成先于荣耀","definition":"功成名就时拒绝随之而来的高位荣宠，把余生投回最初真正要完成的工作本身","source":"《大慈恩寺三藏法师传》《旧唐书》","source_tier":"secondary","mechanism":"输入=功成名就时被高位荣宠吸引、偏离正事 → 处理=拒绝随之而来的荣宠、把余生投回最初真正要完成的工作 → 输出=完成最初的正事(荣耀只是副产品)","trigger":"功成名就、面对荣宠诱惑时","modern_transfer":"功成名就时拒绝随之而来的高位荣宠、把余生投回最初真正要完成的工作本身——荣耀是副产品、未竟的正事才是目的(玄奘归国拒辅政、专心译经)","architecture":{"type":"flow","components":["功成面对荣宠诱惑","拒绝高位荣宠","把余生投回最初正事","完成才是目的"]},"strategy_card_image":"kb-assets/xuanzang/model-4.png"},{"name":"实录见闻","definition":"把所历所见如实精确记录（地理、风物、制度），区分亲见与传闻，不夸饰附会，使记录可被后人查验","source":"《大唐西域记》","source_tier":"primary","mechanism":"输入=记录夸饰附会、亲见与传闻混淆 → 处理=如实精确记录(地理/风物/制度)、区分亲见与传闻、不夸饰 → 输出=可被后人查验的实录","trigger":"记录见闻/经历时","modern_transfer":"把所历所见如实精确记录(地理/风物/制度)、区分''亲见''与''传闻''、不夸饰附会——使记录可被后人查验(《大唐西域记》分''亲践''与''传闻'')","architecture":{"type":"flow","components":["记录易夸饰附会","如实精确记录","区分亲见与传闻","可被后人查验"]},"strategy_card_image":"kb-assets/xuanzang/model-5.png"}],"decision_principles":["二手材料打架时，别争副本，回到源头取原典","重大目标上预先断掉退路，逼自己只能向前（前提：目标值得）","在陌生场合靠把学问钻深来立信，不靠头衔","功成时拒荣宠，把余生还给最初的正事","所见所历如实精确记录，区分亲见与传闻，不夸饰附会"],"inquiry_questions":["你争的这件事，是不是在一堆有问题的二手材料上打转？源头在哪？","你给自己留了退路吗？如果断掉退路、只能向前，你会怎么做？","在这个陌生场合，你靠的是头衔，还是真能拿出的本事？","你功成之后，是去享受荣宠，还是回去完成最初真正的事？","你记录的，是亲眼所见，还是道听途说的附会？区分了吗？"],"value_priorities":["回源头取真 ＞ 在错本上争辩（副本之争无解、原典才能定分歧）","完成最初的正事 ＞ 功成后的荣宠高位（荣耀是副产品、未竟的正事才是目的）","如实记录 ＞ 夸饰附会以动人（可查验的实录、价值远过动人的传奇）"],"blind_spots":["其方法以''有一个明确、值得倾尽一生的终极目标''为前提；目标模糊或多元者套用''断退路、极致坚持''反而危险（原理推断，B）。","''回源头''代价极高（九死一生），多数现实问题不值也不需如此极端的溯源（原理推断，B）。","框架偏求真求知、个人修证，对世俗的资源博弈、组织管理、利益协调着力少（原理推断，B）。","〔传奇〕经《西游记》高度神化，大众认知的''唐僧''（怯懦被动、靠徒弟保护）与史实玄奘（坚毅果决、独行求法）差距极大，易张冠李戴（史实/文学分层，C/B，客观标注）。"],"applicable_domains":["探索未知","学习与认知","人生抉择","价值与伦理"],"match_tags":["探索未知","学习与认知","人生抉择","价值与伦理","批判思辨","第一性原理","长期主义","古代东亚"],"linked_cases":["xuanzang-c1","xuanzang-c2","xuanzang-c3","xuanzang-c4"],"life_tags":[{"tag":"西行取经","tier":"secondary"},{"tag":"主持译经","tier":"primary"},{"tag":"著大唐西域记","tier":"primary"},{"tag":"求学那烂陀","tier":"secondary"}],"voice_profile":{"notes":"庄重精严、重义理；记述精确不夸饰；求真意志强烈；谦敬而坚毅"},"references":[{"ref_id":"xuanzang-s1","title":"玄奘/辩机《大唐西域记》","locator":"全书体例及序（分亲践与传闻）","source_tier":"primary","supports_models":["求真溯源","实录见闻"],"note":"一手·地理见闻录"},{"ref_id":"xuanzang-s2","title":"慧立/彦悰《大慈恩寺三藏法师传》","locator":"西行缘起、莫贺延碛断水、那烂陀/曲女城、归国译经","source_tier":"secondary","supports_models":["求真溯源","断退之志","以学折服","完成先于荣耀"],"supports_cases":["xuanzang-c1","xuanzang-c2","xuanzang-c3","xuanzang-c4"],"note":"二手·可靠传记（含传记润色）"},{"ref_id":"xuanzang-s3","title":"《旧唐书》","locator":"玄奘归国、太宗劝其辅政、专心译经","source_tier":"secondary","supports_models":["完成先于荣耀"],"note":"二手·正史"}],"material_type":"legendary","reasoning_skeleton":{"signature":"二手材料矛盾无解时回源头取原典、从根上定分歧(求真溯源)；重大目标上预先删除退路、逼自己只能向前(断退之志)；在陌生环境靠把学问钻深而非头衔立信(以学折服)；功成时拒荣宠、把余生还给最初的正事(完成先于荣耀)；所见如实精确记录、区分亲见与传闻不夸饰(实录见闻)","steps":[{"invoke":"求真溯源","action":"你争的这件事，是不是在一堆有问题的二手材料上打转？源头在哪？"},{"invoke":"断退之志","action":"你给自己留了退路吗？如果断掉退路、只能向前，你会怎么做？(前提:目标确实值得)"},{"invoke":"以学折服","action":"在这个陌生场合，你靠的是头衔，还是真能拿出的本事？"},{"invoke":"完成先于荣耀","action":"你功成之后，是去享受荣宠，还是回去完成最初真正的事？"},{"invoke":"实录见闻","action":"你记录的，是亲眼所见，还是道听途说的附会？区分了吗？"}],"contrast":"与张骞不同(关键差异·同为西行探索)：**张骞凿空是''开路+战略情报''、国家使命驱动**；**玄奘西行是''求法取原典''、求真与宗教使命驱动**——张骞开通道与情报、玄奘求真知(见张骞卡)。与鉴真不同(同为唐代佛教高僧/跨海传播)：鉴真是''六次东渡、屡败屡战把律宗传到日本''(向外传法)；玄奘是''西行求原典、把真知取回来''(向内求真)——一个传出去、一个取回来(见鉴真卡)。与徐霞客不同：徐霞客是''纯粹兴趣驱动的实地考察+纠正地理''；玄奘是''求真溯源+断退极致坚持''、宗教求知使命(见徐霞客卡)。【射程/盲区·〔传奇〕】玄奘之道在''回源头求真、极致坚持、靠实力立信、完成先于荣耀''极有力，但①其方法以''有一个明确、值得倾尽一生的终极目标''为前提、目标模糊者套''断退路''反而危险；②''回源头''代价极高(九死一生)、多数现实问题不值也不需如此极端溯源；③框架偏求真求知与个人修证、对世俗资源博弈/组织管理着力少；④〔传奇〕经《西游记》高度神化、大众认知的''唐僧''(怯懦被动靠徒弟)与史实玄奘(坚毅果决独行)差距极大、易张冠李戴。适用探索未知/学习与认知/人生抉择/价值与伦理；不适用竞争博弈/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"xuanzang-c2","note":"用户''给自己留太多退路、重大目标上总半途退缩''时，以玄奘莫贺延碛断水立誓类比：他在大漠失水、九死一生之际立誓''宁向西一步死、不向东一步生''、把退路从选项中删除、逼自己只能向前——但前提是目标确实值得倾尽一生（莫贺延碛断水续行为《大慈恩寺三藏法师传》所载→事件确证；具体誓语含传记润色）"},{"source":"case","case_id":"xuanzang-c1","note":"用户''在一堆彼此矛盾的二手材料上空耗争辩''时，以玄奘决意西行求原典类比：汉地佛经译本彼此矛盾、争论无解，他不在错本上空耗、决意亲赴天竺取权威原典、从根上解决分歧（西行求原典为信史→确证；惟须分史实玄奘与《西游记》神化的''唐僧''）"}]},"further_reading":[{"title":"玄奘/辩机《大唐西域记》","why":"实录见闻、区分亲践与传闻的一手地理见闻录（A）","type":"original"},{"title":"慧立/彦悰《大慈恩寺三藏法师传》","why":"西行缘起、断退立誓、求学折服、归国译经的可靠传记（B）","type":"biography"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/xuanzang.png","avatar_thumb":"/advisors/portraits/xuanzang.png","domain":"历史","person_id":"P-xuanzang","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '92fab372e48d9ad3b87cd4a7d7e0b0856869acfb09d41cd6ca81621edb50e11a', 99, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('xunzi', 'P-xunzi', '荀子', 'philosophy', '荀子 · 性恶化性与隆礼重法思维框架卡', '战国（约前313—前238）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '性恶化性起伪 · 隆礼重法', '/advisors/portraits/xunzi.png', '/advisors/portraits/xunzi.png', 5, 0, '{"schema_version":1,"card_id":"xunzi","name":"荀子","title":"荀子 · 性恶化性与隆礼重法思维框架卡","era":"战国（约前313—前238）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"性恶化性起伪","definition":"承认人有自利、趋恶的一面，靠后天的教化、规则与刻意努力（\"伪\"）去矫正改造","source":"《荀子·性恶》《劝学》","source_tier":"primary","mechanism":"输入=指望天生的善 → 处理=承认人有自利趋恶的一面、靠后天的教化/规则/刻意努力(''伪'')矫正改造 → 输出=靠后天塑造更好的人(化性起伪)","trigger":"判断如何改造人/团队/自己时","modern_transfer":"别指望天生的善——承认人有自利、趋恶的一面、靠后天的教化、规则与刻意努力(''化性起伪'')去塑造更好的人/团队/自己(荀子性恶)〔与孟子性善恰相反〕","architecture":{"type":"flow","components":["别指望天生的善","承认人有自利趋恶的一面","靠后天教化规则与刻意努力","化性起伪塑造更好的人"]},"strategy_card_image":"kb-assets/xunzi/model-1.png"},{"name":"隆礼重法","definition":"用清晰的规范（礼）与制度（法）去规约人的行为，让群体有序","source":"《荀子·礼论》《王制》","source_tier":"primary","mechanism":"输入=放任人的自利、群体无序 → 处理=用清晰的规范(礼)与制度(法)规约行为 → 输出=把自利的人组织成秩序(隆礼重法)","trigger":"要让一个群体有序运转时","modern_transfer":"用清晰的规范(礼)与制度(法)去规约人的行为、让群体有序——制度与规范是把自利的人组织成秩序的关键(荀子隆礼重法)","architecture":{"type":"hierarchy","components":["别放任人的自利无序","用清晰的规范礼","用制度法规约行为","把自利的人组织成秩序"]},"strategy_card_image":"kb-assets/xunzi/model-2.png"},{"name":"天人之分","definition":"把\"客观规律（天）\"与\"你能努力的部分（人）\"分开，认清规律、尽人事，甚至\"制天命而用之\"","source":"《荀子·天论》","source_tier":"primary","mechanism":"输入=把成败归于天命/运气 → 处理=把''客观规律(天)''与''你能努力的部分(人)''分开、认清规律尽人事 → 输出=尽力做好能控制的、掌握规律为我所用","trigger":"面对成败、区分''命与人事''时","modern_transfer":"把''客观规律(天)''与''你能努力的部分(人)''分开——别把成败归于天命或运气;认清规律、尽力做好你能控制的、甚至''制天命而用之''(掌握规律为我所用)(荀子明于天人之分)","architecture":{"type":"hierarchy","components":["别把成败归于天命运气","把客观规律与能努力的分开","认清规律尽人事","制天命而用之"]},"strategy_card_image":"kb-assets/xunzi/model-3.png"},{"name":"学不可以已","definition":"把学习与自我改造当作终身不能停的事，靠持续的积累——天赋不足可以靠积累补","source":"《荀子·劝学》","source_tier":"primary","mechanism":"输入=觉得天赋不足或学到一定就停 → 处理=把学习与自我改造当终身不停的事、靠持续积累 → 输出=以积累补天赋(学不可以已)","trigger":"面对长期成长/天赋焦虑时","modern_transfer":"把学习与自我改造当作终身不能停的事、靠持续的积累(''不积跬步无以至千里''''锲而不舍、金石可镂'')——天赋不足可以靠积累补(荀子《劝学》)","architecture":{"type":"flow","components":["别觉得天赋不足或学到一定就停","把学习与自我改造当终身不停","靠持续的积累锲而不舍","以积累补天赋"]},"strategy_card_image":"kb-assets/xunzi/model-4.png"},{"name":"虚壹而静","definition":"求知/判断时让心保持\"虚（不被成见塞满）、专一、宁静（不被躁动干扰）\"，心不蔽才能客观认识","source":"《荀子·解蔽》","source_tier":"primary","mechanism":"输入=带着成见/躁动/分心去判断 → 处理=让心保持''虚(不被成见塞满)、专一、宁静(不被躁动干扰)'' → 输出=心不蔽才能客观认识(虚壹而静)","trigger":"求知/判断、要客观认识事物时","modern_transfer":"求知/判断时让心保持''虚(不被先入成见塞满)、专一(壹)、宁静(不被躁动干扰)''——心不蔽、才能客观地认识事物(荀子《解蔽》虚壹而静)","architecture":{"type":"flow","components":["别带着成见躁动分心判断","让心虚不被成见塞满","专一并宁静","心不蔽才能客观认识"]},"strategy_card_image":"kb-assets/xunzi/model-5.png"}],"decision_principles":["承认人有自利的一面，靠后天的规则与努力去改造（化性起伪）","用清晰的规范（礼）与制度（法）把自利的人组织成秩序","把客观规律与你能努力的分开，认清规律、尽人事","把学习改造当终身不停的事，靠积累补天赋","判断时让心虚、专一、宁静，心不蔽才能客观认识"],"inquiry_questions":["你是指望天生的善、还是承认人有自利的一面、靠后天的规则与努力去改造？","你是放任人的自利、还是用清晰的规范与制度把群体组织成秩序？","你是把成败归于天命/运气、还是认清规律、尽力做好你能控制的？","你是觉得天赋不足就停、还是把学习改造当终身不停的事靠积累？","你判断时，心是被成见躁动塞满、还是保持虚、专一、宁静？"],"value_priorities":["后天的化性起伪 ＞ 指望天生的善（人之性恶、其善者伪也（与孟子恰相反））","礼法的秩序 ＞ 放任的自利（隆礼重法、明分使群）","尽人事、用规律 ＞ 归成败于天命（明于天人之分、制天命而用之）"],"blind_spots":["性恶论可能过度低估人的善与内在动机；若只靠外在规约/矫正、忽略激发内在的认同，效果有限（原理推断/学术，B）。","隆礼重法的''礼''有其特定时代的等级内容，未必都适用于今天（学术，B）。","其思想经弟子韩非、李斯走向了法家的极端（严刑峻法）；荀子本人虽不至此，但其''性恶+重法''的取向客观上为之埋下伏笔（学术史，B，客观标注）。","偏重后天塑造与规约，对''人的自发创造与自由''着力少（原理推断，B）。"],"applicable_domains":["组织管理","修身自省","认知偏误与理性决策"],"match_tags":["组织管理","修身自省","认知偏误与理性决策","批判思辨","制度法治思维","务实渐进","古代东亚"],"linked_cases":["xunzi-c1","xunzi-c2","xunzi-c3","xunzi-c4"],"life_tags":[{"tag":"著荀子","tier":"primary"},{"tag":"倡性恶论","tier":"primary"},{"tag":"任稷下祭酒","tier":"secondary"},{"tag":"倡天行有常","tier":"primary"}],"voice_profile":{"notes":"条理严密、说理透彻；务实冷静；重后天努力与制度；不尚空谈天命"},"references":[{"ref_id":"xunzi-s1","title":"《荀子》","locator":"性恶、隆礼重法、天人之分、劝学、解蔽","source_tier":"primary","supports_models":["性恶化性起伪","隆礼重法","天人之分","学不可以已","虚壹而静"],"supports_cases":["xunzi-c1","xunzi-c2","xunzi-c3","xunzi-c4"],"note":"一手·原典"},{"ref_id":"xunzi-s2","title":"荀子与先秦儒法思想研究","locator":"性恶、隆礼重法与法家的关系","source_tier":"secondary","supports_models":["性恶化性起伪","隆礼重法"],"note":"二手·研究"}],"material_type":"textual","reasoning_skeleton":{"signature":"承认人有自利趋恶的一面、靠后天教化规则努力去改造(性恶化性起伪)；用礼与法规约行为把自利的人组织成秩序(隆礼重法)；把客观规律与你能努力的分开、认清规律尽人事(天人之分)；把学习改造当终身不停的事靠积累(学不可以已)；让心虚壹而静才能客观认识(虚壹而静)","steps":[{"invoke":"性恶化性起伪","action":"你是指望天生的善、还是承认人有自利的一面、靠后天的规则与努力去改造？"},{"invoke":"隆礼重法","action":"你是放任人的自利、还是用清晰的规范与制度把群体组织成秩序？"},{"invoke":"天人之分","action":"你是把成败归于天命/运气、还是认清规律、尽力做好你能控制的？"},{"invoke":"学不可以已","action":"你是觉得天赋不足就停、还是把学习改造当终身不停的事靠积累？"},{"invoke":"虚壹而静","action":"你判断时，心是被成见躁动塞满、还是保持虚、专一、宁静？"}],"contrast":"与孟子不同(关键差异·同论人性·恰相反)：**孟子主''性善''、靠''扩充本有的四端''(相信并激发天生的善)**；**荀子主''性恶''、靠''化性起伪''(用后天的教化、规则、努力去矫正改造)**——一个性善靠扩充、一个性恶靠矫正(见孟子卡)。与韩非子不同(师承却分流)：**韩非把性恶推到底、归于''法术势''的强制控制**；**荀子虽主性恶、但归于''隆礼''、仍有儒家用礼乐教化人的理想(用礼来化性、而非纯靠权势赏罚)**(见韩非子卡)。与孔子不同：孔子较少正面论人性、重''仁与正名'';荀子明确''性恶''并系统讲''隆礼重法、天人之分、劝学''(见孔子卡)。【射程/盲区】荀子之道在''化性起伪、隆礼重法、天人之分、劝学、虚壹而静''极有力(尤其制度、教育、认识论)，但①性恶论可能过度低估人的善与内在动机、只靠外在规约而忽略激发内在认同则效果有限;②隆礼的''礼''有特定时代的等级内容、未必都适用于今天;③其''性恶+重法''取向经韩非李斯走向了法家极端、客观上埋下伏笔;④偏重后天塑造与规约、对人的自发创造与自由着力少。适用组织管理/修身自省/认知偏误与理性决策;不适用投资/创作。"},"persona_anchor":{"primary":[{"source":"case","case_id":"xunzi-c1","note":"用户''寄望于人/团队天生就好、结果失望、或不知如何改造''时，以荀子化性起伪类比：荀子说''人之性恶、其善者伪也''——别指望天生的善、承认人有自利趋恶的一面、靠后天的教化、规则与刻意的努力(''化性起伪'')去把人/团队/自己塑造得更好;善是''做''出来的、不是天生的（性恶化性起伪为《荀子·性恶》所载→确证；与孟子性善恰相反）"},{"source":"case","case_id":"xunzi-c4","note":"用户''觉得自己天赋不够、或学到一定程度就松懈了''时，以荀子劝学类比：''学不可以已''、''不积跬步无以至千里''、''锲而不舍、金石可镂''——把学习与自我改造当作终身不能停的事、靠持续的积累、天赋不足可以靠积累补（《劝学》为《荀子》所载→确证）"}]},"further_reading":[{"title":"《荀子》","why":"性恶、隆礼重法、天人之分、劝学、解蔽的一手出处（A）","type":"原典"},{"title":"荀子与先秦儒法思想研究","why":"对性恶、隆礼重法及其与法家关系的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/xunzi.png","avatar_thumb":"/advisors/portraits/xunzi.png","domain":"哲学","person_id":"P-xunzi","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '74ea83379195e4166c9425dce6da6b2ef42565be7604f954c1ca050a92615460', 100, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('xuxiake', 'P-xuxiake', '徐霞客', 'history', '徐霞客 · 亲历实测与求知人生思维框架卡', '明（1587—1641）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '亲历实测 · 为知而活', '/advisors/portraits/xuxiake.png', '/advisors/portraits/xuxiake.png', 5, 0, '{"schema_version":1,"card_id":"xuxiake","name":"徐霞客","title":"徐霞客 · 亲历实测与求知人生思维框架卡","era":"明（1587—1641）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"亲历实测","definition":"不信纸上现成结论，凡存疑必亲赴实地考察、实测验证，以一手观察推翻或确证受传的\"权威\"说法","source":"《徐霞客游记》","source_tier":"primary","mechanism":"输入=纸上现成结论存疑、却照搬 → 处理=凡存疑必亲赴实地考察、实测验证、以一手观察推翻或确证''权威''说法 → 输出=用一手实测定真伪(而非照搬纸上)","trigger":"面对存疑的''权威结论''时","modern_transfer":"别照搬纸上现成结论——凡存疑必亲赴实地、实测验证，以一手观察去推翻或确证那个''权威''说法(徐霞客实测推翻''岷山导江''、考定金沙江为长江正源)","architecture":{"type":"flow","components":["纸上结论存疑","亲赴实地考察","一手实测验证","据此推翻或确证"]},"strategy_card_image":"kb-assets/xuxiake/model-1.png"},{"name":"为知而活","definition":"把人生投向求知/探索本身，主动脱离功名仕途的既定成功阶梯，为兴趣与真知而非地位而活","source":"《徐霞客游记》及传述","source_tier":"secondary","mechanism":"输入=被功名仕途的既定成功阶梯套住 → 处理=把人生投向求知/探索本身、主动脱离既定阶梯、为兴趣与真知而活 → 输出=为真正好奇的事而活(而非地位)","trigger":"在''为功名''与''为求知''间抉择时","modern_transfer":"把人生投向你真正好奇的求知/探索本身、而非被功名地位的既定成功阶梯套住——为兴趣与真知而活(徐霞客主动出走科举、终身远游求知)〔前提:有相当家底、无生计之忧〕","architecture":{"type":"flow","components":["被既定成功阶梯套住","主动脱离阶梯","投向求知探索本身","为真知而非地位活"]},"strategy_card_image":"kb-assets/xuxiake/model-2.png"},{"name":"日记式采集","definition":"以逐日精确的记录把游历变成系统的数据采集（地形、水文、岩石、道里），让见闻可累积、可考据","source":"《徐霞客游记》","source_tier":"primary","mechanism":"输入=游历见闻零散、不可累积考据 → 处理=以逐日精确的记录把游历变成系统的数据采集(地形/水文/岩石/道里) → 输出=见闻可累积、可考据(成数据而非奇闻)","trigger":"游历/接触大量一手观察时","modern_transfer":"以逐日精确的记录、把你的见闻/经历变成系统的数据采集(地形、水文、岩石、道里…)——让一手观察可累积、可考据，而非随看随忘(《徐霞客游记》逐日体例)","architecture":{"type":"flow","components":["见闻零散难考据","逐日精确记录","变成系统数据采集","可累积可考据"]},"strategy_card_image":"kb-assets/xuxiake/model-3.png"},{"name":"穷究到源","definition":"不在方便处止步，凡探必究到底——溯河必至源头、入洞必探到尽处，追问到事物的真正尽端","source":"《徐霞客游记》","source_tier":"primary","mechanism":"输入=在方便处止步、不追到底 → 处理=凡探必究到底、溯河必至源头、入洞必探到尽处、追问到真正尽端 → 输出=追到真正源头/尽处才有真发现","trigger":"探究一件事、想在方便处止步时","modern_transfer":"凡探究就追到底、不在方便处止步——溯河必至源头、入洞必探到尽处，追问到事物的真正尽端(徐霞客溯江穷源)；不到尽头不罢休，才有真发现","architecture":{"type":"flow","components":["别在方便处止步","凡探必追到底","溯河至源入洞至尽","追到真正尽端"]},"strategy_card_image":"kb-assets/xuxiake/model-4.png"},{"name":"实地归纳规律","definition":"不止于记录孤立的单点，从大量一手实测中横向比较、归纳出普遍的规律","source":"《徐霞客游记》（西南岩溶/喀斯特地貌系统观察）","source_tier":"primary","mechanism":"输入=只记录孤立的单点、不归纳规律 → 处理=从大量一手实测中横向比较、归纳出普遍的规律 → 输出=从一手数据归纳出规律(而非止于单点)","trigger":"积累大量一手观察、想提炼规律时","modern_transfer":"别止于记录孤立的单点——从大量一手实测中横向比较、归纳出普遍的规律(徐霞客对西南岩溶/喀斯特地貌的系统观察与归纳)；一手数据的真正价值在归纳出规律","architecture":{"type":"hierarchy","components":["别止于孤立单点","横向比较大量一手数据","归纳出普遍规律","一手数据升为规律"]},"strategy_card_image":"kb-assets/xuxiake/model-5.png"}],"decision_principles":["纸上结论存疑，就亲赴实地实测验证、据此推翻或确证","为求知本身而活，不为功名套住自己（前提：衡量生计约束）","把见闻逐日精确记录，让它成为可考的数据","凡探究就追到底，不在方便处止步","从大量一手实测中归纳出普遍规律，不止于记录单点"],"inquiry_questions":["这个''权威结论''你亲自验证过，还是只是照搬纸上？","你是探到了真正的源头/尽处，还是在半路方便处就停了？","你的见闻有没有被系统记录下来、可供日后查考？","你是止于记录孤立的单点，还是从大量观察里归纳出了普遍规律？","你是为功名地位活，还是为你真正好奇的事活？"],"value_priorities":["一手实测 ＞ 纸上权威结论（亲历推翻\"岷山导江\"、考定金沙江）","求知本身 ＞ 功名仕途（主动出走科举、为探索而活）","穷究到源 ＞ 方便处止步（不到尽头不罢休、才有真发现）"],"blind_spots":["''为兴趣出走仕途''以个人有相当家底、无生计之忧为前提，对需养家糊口者不具普适性（史实/原理推断，B）。","偏个人化的实地求知与记录，对需要协作、组织、资源调度的大型探索（如郑和式国家工程）着力少（原理推断，B）。","纯求知导向，对成果的应用转化与影响他人着力少（其游记生前未广传、身后才显价值）（史实，B）。","''亲历实测''代价高、耗时长，多数日常结论不值也不需如此极端的亲证（原理推断，B）。"],"applicable_domains":["探索未知","学习与认知","人生抉择","修身自省"],"match_tags":["探索未知","学习与认知","人生抉择","批判思辨","实验试错","第一性原理","古代东亚"],"linked_cases":["xuxiake-c1","xuxiake-c2","xuxiake-c3","xuxiake-c4"],"life_tags":[{"tag":"游历山川","tier":"secondary"},{"tag":"著霞客游记","tier":"primary"},{"tag":"探长江源","tier":"secondary"},{"tag":"辨岩溶地貌","tier":"secondary"}],"voice_profile":{"notes":"精确写实、富地理细节；好奇心炽烈；亲历口吻、第一人称；不慕荣利"},"references":[{"ref_id":"xuxiake-s1","title":"《徐霞客游记》","locator":"考辨长江正源、溯江穷源探洞、岩溶系统观察、逐日体例","source_tier":"primary","supports_models":["亲历实测","日记式采集","穷究到源","实地归纳规律"],"supports_cases":["xuxiake-c2","xuxiake-c3","xuxiake-c4"],"note":"一手·地理考察记"},{"ref_id":"xuxiake-s2","title":"徐霞客生平传述/年谱","locator":"弃科举、终身远游求知","source_tier":"secondary","supports_models":["为知而活"],"supports_cases":["xuxiake-c1"],"note":"二手·生平"}],"material_type":"rich","reasoning_skeleton":{"signature":"纸上结论存疑就亲赴实地实测验证、据此推翻或确证(亲历实测)；为真正好奇的求知本身而活、不被功名阶梯套住(为知而活)；逐日精确记录把见闻变成可累积可考据的数据采集(日记式采集)；凡探必追到真正尽端、不在方便处止步(穷究到源)；从大量一手实测归纳出普遍规律、不止于单点(实地归纳规律)","steps":[{"invoke":"亲历实测","action":"这个''权威结论''你亲自验证过，还是只是照搬纸上？"},{"invoke":"穷究到源","action":"你是探到了真正的源头/尽处，还是在半路方便处就停了？"},{"invoke":"日记式采集","action":"你的见闻有没有被系统记录下来、可供日后查考？"},{"invoke":"实地归纳规律","action":"你是止于记录孤立的单点，还是从大量观察里归纳出了普遍规律？"},{"invoke":"为知而活","action":"你是为功名地位活，还是为你真正好奇的事活？〔前提:衡量你的生计约束〕"}],"contrast":"与玄奘不同(关键差异·同为探索/求真)：**玄奘求真溯源是''回知识源头取原典''、宗教与求知使命驱动、九死一生的极致溯源**；**徐霞客是''纯粹兴趣驱动的实地考察+纠正地理记载''、为求知本身而活**——玄奘有终极宗教目标、徐霞客为好奇心本身(见玄奘卡)。与张骞/郑和不同：张骞凿空、郑和远航都是国家使命驱动的''工程''(开路/船队)；徐霞客是个人化、兴趣驱动的实地求知(见张骞/郑和卡)。【射程/盲区】徐霞客之道在''亲历实测破权威、穷究到源、把见闻变数据、归纳规律''极有力，但①''为兴趣出走仕途''以个人有相当家底、无生计之忧为前提、对需养家糊口者不普适；②偏个人化的实地求知与记录、对需协作组织资源调度的大型探索(郑和式国家工程)着力少；③纯求知导向、对成果的应用转化与影响他人着力少(其游记生前未广传、身后才显价值)。适用探索未知/学习与认知/人生抉择/修身自省；不适用组织管理/竞争博弈。"},"persona_anchor":{"primary":[{"source":"case","case_id":"xuxiake-c2","note":"用户''照搬一个没亲自验证过的''权威结论''''时，以徐霞客考辨长江正源类比：他不信''岷山导江''的旧说、亲赴西南实地考察、考定金沙江才是长江正源——凡存疑必亲赴实测、以一手观察推翻或确证权威说法（考辨长江正源为《徐霞客游记》明载→确证）"},{"source":"case","case_id":"xuxiake-c1","note":"用户''被功名/既定成功阶梯套住、想为自己真正好奇的事而活又不敢''时，以徐霞客弃科举类比：他主动脱离科举仕途的既定阶梯、把一生投向地理考察与求知本身——为兴趣与真知而活（弃科举远游为传述与《游记》自述→确证；惟此以有家底、无生计之忧为前提）"}]},"further_reading":[{"title":"《徐霞客游记》","why":"亲历实测、逐日采集、穷究到源、岩溶归纳的一手地理考察记（A）","type":"original"},{"title":"徐霞客生平传述/年谱","why":"弃科举、终身远游求知的生平","type":"传述"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/xuxiake.png","avatar_thumb":"/advisors/portraits/xuxiake.png","domain":"历史","person_id":"P-xuxiake","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'fb24c0a4d756d2e6bb76e2d820149a1161be4cdda96963d8e00293338c3b7cec', 101, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('yuefei', 'P-yuefei', '岳飞', 'strategy', '岳飞 · 严明治军与信念领导思维框架卡', '南宋（1103—1142）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '严明的纪律即战斗力 · 以信念与表率带兵', '/advisors/portraits/yuefei.png', '/advisors/portraits/yuefei.png', 5, 0, '{"schema_version":1,"card_id":"yuefei","name":"岳飞","title":"岳飞 · 严明治军与信念领导思维框架卡","era":"南宋（1103—1142）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"严明的纪律即战斗力","definition":"以极严明、说到做到、甚至严苛的纪律约束你的队伍，对外秋毫无犯（\"冻死不拆屋、饿死不掳掠\"）——铁的纪律既铸就战斗力，也赢得人心","source":"岳家军的纪律","source_tier":"secondary","mechanism":"输入=队伍扰民松散无纪律 → 处理=以极严明说到做到甚至严苛的纪律约束、对外秋毫无犯 → 输出=纪律铸战力赢人心(纪律即战斗力)","trigger":"要约束、带好一支队伍时","modern_transfer":"以极严明、说到做到、甚至严苛的纪律约束你的队伍、对外秋毫无犯(''冻死不拆屋、饿死不掳掠'')——铁的纪律既铸就战斗力、也赢得人心(岳家军的纪律、''撼山易、撼岳家军难'')","architecture":{"type":"hierarchy","components":["别让队伍扰民松散无纪律","以极严明说到做到甚至严苛的纪律约束","对外秋毫无犯冻死不拆屋饿死不掳掠","铁的纪律既铸战力也赢人心"]},"strategy_card_image":"kb-assets/yuefei/model-1.png"},{"name":"以信念与表率带兵","definition":"用一个崇高的、超越个人的信念（使命感），加上你自己身先士卒、与成员同甘共苦的表率——凝聚出一支愿意为之死战不退的队伍","source":"岳飞\"精忠报国\"与身先士卒","source_tier":"secondary","mechanism":"输入=只靠命令利诱带队 → 处理=以崇高信念加身先士卒同甘苦的表率凝聚 → 输出=死战不退的队伍(信念表率)","trigger":"要凝聚一支有战斗意志的队伍时","modern_transfer":"用一个崇高的、超越个人的信念(使命感)、加上你自己身先士卒、与成员同甘共苦的表率——凝聚出一支愿意为之死战不退的队伍(岳飞以''精忠报国''与身先士卒带出岳家军)","architecture":{"type":"hierarchy","components":["别只靠命令利诱带队","用崇高的超越个人的信念","加上自己身先士卒与成员同甘共苦的表率","凝聚出愿为之死战不退的队伍"]},"strategy_card_image":"kb-assets/yuefei/model-2.png"},{"name":"联合民间的力量","definition":"别只靠自己的正规力量——主动去联合、联结那些分散的、民间的、敌后的\"同盟力量\"，把它们编织成一张能呼应、配合你的网络，形成合力","source":"岳飞\"连结河朔\"","source_tier":"secondary","mechanism":"输入=只靠自己的正规力量 → 处理=主动联合敌后分散的民间力量编成呼应网络 → 输出=形成合力(连结河朔)","trigger":"力量不足、需扩大同盟时","modern_transfer":"别只靠自己的正规力量——主动去联合、联结那些分散的、民间的、敌后的''同盟力量''、把它们编织成一张能呼应、配合你的网络、形成合力(岳飞''连结河朔''、联络北方义军)","architecture":{"type":"matrix","components":["别只靠自己的正规力量","主动联合分散的民间的敌后的同盟力量","编织成能呼应配合你的网络","形成合力"]},"strategy_card_image":"kb-assets/yuefei/model-3.png"},{"name":"运用之妙存乎一心","definition":"别死守阵法、教条、成法——这些只是基础；真正的高明在于根据瞬息万变的实际，灵活地运用它们，\"运用之妙、存乎一心\"","source":"岳飞论阵法","source_tier":"secondary","mechanism":"输入=死守阵法教条成法 → 处理=根据瞬息万变的实际灵活运用不拘泥 → 输出=运用之妙存乎一心(灵活运用)","trigger":"面对具体多变的战况/局面时","modern_transfer":"别死守阵法、教条、成法——这些只是基础;真正的高明在于根据瞬息万变的实际、灵活地运用它们、''运用之妙、存乎一心''(岳飞论阵法)","architecture":{"type":"flow","components":["别死守阵法教条成法","这些只是基础","根据瞬息万变的实际灵活地运用它们","运用之妙存乎一心"]},"strategy_card_image":"kb-assets/yuefei/model-4.png"},{"name":"清廉担当不惜身","definition":"以\"不爱钱、不惜死\"的清廉与担当立身——不为个人的财货、私利、安危所动，把使命与责任放在前面；这种纯粹本身就是凝聚力与威望的来源","source":"岳飞\"文官不爱钱、武官不惜死\"","source_tier":"secondary","mechanism":"输入=为个人财货私利安危所动 → 处理=以不爱钱不惜死的清廉担当立身把使命责任放前面 → 输出=纯粹是凝聚力威望来源(清廉担当)","trigger":"面对私利与安危的考验时","modern_transfer":"以''不爱钱、不惜死''的清廉与担当立身——不为个人的财货、私利、安危所动、把使命与责任放在前面;这种纯粹本身就是凝聚力与威望的来源(岳飞''文官不爱钱、武官不惜死、天下太平矣'')〔但过于刚直、不善自保、也是其悲剧之一、见盲区〕","architecture":{"type":"hierarchy","components":["别为个人财货私利安危所动","以不爱钱不惜死的清廉与担当立身","把使命与责任放在前面","这种纯粹本身就是凝聚力与威望的来源"]},"strategy_card_image":"kb-assets/yuefei/model-5.png"}],"decision_principles":["以极严明、说到做到的纪律约束队伍、对外秋毫无犯（纪律即战斗力）","用崇高的信念加身先士卒的表率，凝聚一支死战不退的队伍","别只靠自己，主动联结分散的同盟力量、编成呼应的网络","别死守成法，根据瞬息万变的实际灵活运用、''运用之妙存乎一心''","以''不爱钱、不惜死''的清廉担当立身（但也别过刚而不善自保）"],"inquiry_questions":["你的队伍是松散扰民、还是有极严明、说到做到、对外秋毫无犯的纪律？","你是只靠命令利诱、还是用信念加身先士卒的表率凝聚队伍？","你是只靠自己的正规力量、还是主动联结了分散的同盟、编成网络？","你是死守成法、还是根据实际灵活运用、''运用之妙存乎一心''？","你是为私利安危所动、还是以''不爱钱、不惜死''的清廉担当立身（但别过刚）？"],"value_priorities":["纪律铸战力赢人心 ＞ 松散扰民（冻死不拆屋、饿死不掳掠）","信念与表率 ＞ 只靠命令利诱（精忠报国、身先士卒）","清廉与担当 ＞ 为私利安危所动（文官不爱钱、武官不惜死）"],"blind_spots":["岳飞过于刚直、忠于其信念，不善于政治上的自保与权衡，终被以''莫须有''的罪名冤杀于风波亭——刚直而不善自保是其悲剧（史，B，客观标注、点到为止）。","其''精忠''高度系于特定的君臣、家国伦理框架，迁移到现代语境需审慎转化（原理推断，B）。","其极致严苛的纪律，在不需要如此的场景下可能过刚、不近人情（原理推断，B）。","宋金战和的历史评价复杂，本卡聚焦其治军与领导的可迁移方法，不渲染特定的历史/民族叙事（说明，B）。"],"applicable_domains":["领导力","组织管理","竞争博弈"],"match_tags":["领导力","组织管理","竞争博弈","攻心共识","制度法治思维","长期主义","古代东亚"],"linked_cases":["yuefei-c1","yuefei-c2","yuefei-c3","yuefei-c4"],"life_tags":[{"tag":"统领岳家军","tier":"secondary"},{"tag":"郾城大捷","tier":"secondary"},{"tag":"风波亭遇害","tier":"secondary"},{"tag":"收复襄阳","tier":"secondary"}],"voice_profile":{"notes":"刚正忠勇、治军如铁；以信念凝聚；清廉担当；运用之妙"},"references":[{"ref_id":"yuefei-s1","title":"《宋史·岳飞传》及岳飞研究","locator":"严明纪律、信念表率、连结河朔、运用之妙、清廉担当","source_tier":"secondary","supports_models":["严明的纪律即战斗力","以信念与表率带兵","联合民间的力量","运用之妙存乎一心","清廉担当不惜身"],"supports_cases":["yuefei-c1","yuefei-c2","yuefei-c3","yuefei-c4"],"note":"二手·史与研究"},{"ref_id":"yuefei-s2","title":"宋代军事与岳飞研究","locator":"治军、领导、历史评价","source_tier":"secondary","supports_models":["严明的纪律即战斗力","以信念与表率带兵"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"以极严明说到做到甚至严苛的纪律约束队伍对外秋毫无犯铁的纪律既铸战力也赢人心(严明的纪律即战斗力)；用崇高的超越个人的信念加身先士卒同甘共苦的表率凝聚死战不退的队伍(以信念与表率带兵)；别只靠自己主动联结分散的民间的敌后的同盟力量编成呼应的网络形成合力(联合民间的力量)；别死守成法根据瞬息万变的实际灵活运用运用之妙存乎一心(运用之妙存乎一心)；以不爱钱不惜死的清廉与担当立身把使命与责任放在前面(清廉担当不惜身)","steps":[{"invoke":"严明的纪律即战斗力","action":"你的队伍是松散扰民、还是有极严明、说到做到、对外秋毫无犯的纪律？"},{"invoke":"以信念与表率带兵","action":"你是只靠命令利诱、还是用信念加身先士卒的表率凝聚队伍？"},{"invoke":"联合民间的力量","action":"你是只靠自己的正规力量、还是主动联结了分散的同盟、编成网络？"},{"invoke":"运用之妙存乎一心","action":"你是死守成法、还是根据实际灵活运用、''运用之妙存乎一心''？"},{"invoke":"清廉担当不惜身","action":"你是为私利安危所动、还是以''不爱钱、不惜死''的清廉担当立身（但别过刚）？"}],"contrast":"与戚继光不同(关键差异)：**戚继光重''募兵、严格训练、阵法操典(鸳鸯阵)、著书立制''的系统化建军工程**；**岳飞重''极严明的纪律(冻死不拆屋)、精忠报国的信念、连结河朔联合民间''的纪律与信念领导**——戚继光偏建军的工程与制度、岳飞偏纪律与信念的凝聚(见戚继光卡)。与吴起不同(同重带兵)：吴起重''与士卒同甘共苦(吮疽)、在德不在险、料敌'';岳飞重''铁的纪律、精忠的信念、清廉的担当''——吴起以同甘共苦换死力、岳飞以纪律加信念铸劲旅(见吴起卡)。与韩信不同：韩信重临阵奇谋(背水一战);岳飞重治军、纪律与信念(见韩信卡)。与曹操不同：曹操重军政经一体的权谋;岳飞重纯粹的纪律、信念与清廉(见曹操卡)。【射程/盲区·历史诚实·重点】岳飞之道在''严明纪律、信念表率、连结民间、运用之妙、清廉担当''极有力(尤其领导、治军、组织)，但①他过于刚直、不善政治自保、终被以''莫须有''冤杀于风波亭、刚直而不善自保是其悲剧、客观标注点到为止;②其''精忠''高度系于特定君臣家国伦理框架、迁移到现代需审慎转化;③极致严苛的纪律在不需如此处可能过刚不近人情;④宋金战和历史评价复杂、本卡聚焦可迁移的治军领导方法、不渲染特定历史/民族叙事。适用领导力/组织管理/竞争博弈;不适用投资/创作。"},"persona_anchor":{"primary":[{"source":"case","case_id":"yuefei-c1","note":"用户''带一支队伍/团队、纪律松散、甚至滋扰、损害了外部(客户/群众/合作方)的利益、口碑很差''时，以岳家军的纪律类比：岳飞治军极严、定下''冻死不拆屋、饿死不掳掠''的铁律、对百姓秋毫无犯——这既让岳家军赢得了民心、也锤炼出''撼山易、撼岳家军难''的强大战斗力;以极严明、说到做到、甚至严苛的纪律约束队伍、对外秋毫无犯、铁的纪律既铸就战斗力、也赢得人心（岳家军纪律为《宋史》载→确证）"},{"source":"case","case_id":"yuefei-c2","note":"用户''想带出一支真正有凝聚力、有战斗意志的队伍、却只会用命令、KPI、奖金、带不出那股劲''时，以岳飞带兵类比：他靠的是''精忠报国''这一崇高的、超越个人私利的信念、加上自己身先士卒、与士卒同甘共苦的表率——凝聚出一支愿意为之死战不退的岳家军;用一个崇高的、超越个人的信念、加上你自己身先士卒、与成员同甘共苦的表率、去凝聚队伍（岳飞精忠报国与身先士卒为《宋史》载→确证）"}]},"further_reading":[{"title":"《宋史·岳飞传》及岳飞研究","why":"严明纪律、信念表率、连结河朔、运用之妙、清廉担当的史述（B）","type":"史/传记"},{"title":"宋代军事与岳飞研究","why":"对岳飞治军、领导及其历史评价的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/yuefei.png","avatar_thumb":"/advisors/portraits/yuefei.png","domain":"战略","person_id":"P-yuefei","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '8775116731cb8b37511c00f20c04af44759aa17d8f21052cad25beccbe31d16b', 102, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('zengguofan', 'P-zengguofan', '曾国藩', 'history', '曾国藩 · 求稳致胜与自我修治框架卡', '晚清（1811–1872）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '结硬寨打呆仗 · 尚拙', '/advisors/portraits/zengguofan.png', '/advisors/portraits/zengguofan.png', 5, 0, '{"schema_version":1,"card_id":"zengguofan","name":"曾国藩","title":"曾国藩 · 求稳致胜与自我修治框架卡","era":"晚清（1811–1872）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"结硬寨打呆仗","definition":"不取巧、不浪战；用深沟高垒等笨办法把自己立于不败，靠结构性优势稳步碾压，先求不败再求胜","source":"曾国藩奏稿/批牍论兵","source_tier":"primary","mechanism":"输入=一个对抗局面 → 处理=不取巧不浪战、用深沟高垒等笨办法把自己立于不败、靠结构性优势稳步碾压 → 输出=先求不败再求胜","trigger":"面对比你强或势均力敌的对手、有赌奇招诱惑时","modern_transfer":"面对强敌别赌奇招——用''笨''办法把自己立于不败（控风险/断补给/慢消耗），让时间与结构优势替你赢","architecture":{"type":"hierarchy","components":["先求不败","深沟高垒控风险","断敌补给","以稳制变慢消耗"]},"strategy_card_image":"kb-assets/zengguofan/model-1.png"},{"name":"尚拙","definition":"在崇尚机巧的环境里反向押注\"笨功夫+诚实\"，相信至拙能胜至巧——慢而扎实胜过快而取巧","source":"《曾国藩家书》论拙诚","source_tier":"primary","mechanism":"输入=崇尚机巧的环境 → 处理=反向押注''笨功夫+诚实''、相信至拙能胜至巧 → 输出=慢而扎实胜过快而取巧","trigger":"周围都在抄近路、取巧时","modern_transfer":"在崇尚机巧处反向押注笨功夫+诚实——笨功夫可累积、可信任，机巧脆弱不可持续","architecture":{"type":"matrix","components":["识别取巧风气","反向选笨功夫","重诚实可累积","弃脆弱机巧"]},"strategy_card_image":"kb-assets/zengguofan/model-2.png"},{"name":"日课省察","definition":"把修身从模糊愿望变成每日书面记账：逐日记录并检讨自己的过失，用可累积的纠错代替空泛立志","source":"《曾国藩日记》（日课）","source_tier":"primary","mechanism":"输入=一个想改的毛病/想修的身 → 处理=把修身从模糊愿望变成每日书面记账、逐日记录检讨过失 → 输出=可累积的纠错","trigger":"想改根深蒂固的毛病、空泛立志屡屡反复时","modern_transfer":"想改根深蒂固的毛病靠''下决心''没用——把它变成每天写下来、可检查的功课，以日常记账替代一次性发愿","architecture":{"type":"loop","components":["立每日功课","逐日书面记录","严厉检讨过失","可累积纠错"]},"strategy_card_image":"kb-assets/zengguofan/model-3.png"},{"name":"莫问收获但问耕耘","definition":"把努力与即时回报解耦：只专注把当下该做的耕耘做到位，不被收成焦虑左右，让结果自然累积","source":"《曾国藩家书》","source_tier":"primary","mechanism":"输入=一项需长期投入的事 → 处理=把努力与即时回报解耦、只专注当下耕耘、不被收成焦虑左右 → 输出=结果自然累积","trigger":"被收成焦虑/即时回报困住时","modern_transfer":"把焦虑从结果移回过程——只专注把当下该做的做到位，让结果自然累积","architecture":{"type":"flow","components":["解耦努力与回报","专注当下耕耘","放下收成焦虑","让结果自然累积"]},"strategy_card_image":"kb-assets/zengguofan/model-4.png"},{"name":"打脱牙和血吞","definition":"受挫受辱时不外露、不报复性反扑；把委屈咽下、隐忍徐图，以\"缓\"化解\"急\"，留有用之身再起","source":"《曾国藩家书》","source_tier":"primary","mechanism":"输入=受挫受辱的处境 → 处理=不外露不报复性反扑、把委屈咽下隐忍徐图、以缓化急 → 输出=留有用之身再起","trigger":"受挫受辱、想急着扳回来时","modern_transfer":"受挫受辱时别急着报复性翻盘——把羞辱咽下、不带情绪地隐忍徐图，留有用之身再起","architecture":{"type":"flow","components":["遭受挫辱","不外露不反扑","隐忍以缓化急","留身徐图再起"]},"strategy_card_image":"kb-assets/zengguofan/model-5.png"}],"decision_principles":["求稳不求奇：先把自己立于不败之地，再图进取","遇挫不急于翻盘，打脱牙和血吞，徐图再起","修身靠每日记账式省察，不靠一时发愿","只问耕耘不问收获，把焦虑从结果移回过程","用人取''拙诚''重于''机巧''，宁用扎实笨人不用浮滑巧人"],"inquiry_questions":["你现在是想赢，还是先确保自己不败？","这件事你是在取巧抄近路，还是肯下笨功夫？","受了这挫折，你是急着扳回来，还是能先把牙和血吞下、徐图再起？","你每天有没有一处地方，把自己的过失如实记下来检讨？","你是在焦虑收成，还是在专心耕耘？"],"value_priorities":["结构性的稳（不败） ＞ 取巧的快（速胜）（不败可控，速胜常是赌；先立不败之地）","拙诚（笨而实） ＞ 机巧（巧而滑）（笨功夫可累积、可信任；机巧脆弱不可持续）","过程（耕耘） ＞ 结果焦虑（收获）（控制过程、放下收成，反而走得更远）"],"blind_spots":["尚拙求稳在需果断冒险、快速创新、抢时间窗的场景会贻误战机——擅持久消耗战、不擅闪电奇袭与高风险创业（与结硬寨同源，原理推断，B）","极端自我压抑与隐忍可能损身心、滑向过度自责——其日记长期自我苛责，晚年身心俱疲（自述类，B/日记，存润色与自我审查偏差）","立场保守、维护既有秩序：作为镇压太平天国的清廷重臣，其''忠''与时代局限不可回避；框架服务于秩序维稳，对需颠覆性变革的处境不适用（历史评价争议，B，客观标注）","用人重''拙诚''可能错失有真才而锋芒外露之人（与尚拙同源，原理推断，B）"],"applicable_domains":["组织管理","领导力","修身自省","长期规划","职业发展"],"match_tags":["组织管理","修身自省","长期规划","领导力","务实渐进","风险规避","长期主义","近代东亚"],"linked_cases":["zengguofan-c1","zengguofan-c2","zengguofan-c3","zengguofan-c4","zengguofan-c5"],"life_tags":[{"tag":"创建湘军","tier":"secondary"},{"tag":"平定太平天国","tier":"secondary"},{"tag":"道光进士","tier":"secondary"},{"tag":"兴办洋务实业","tier":"secondary"}],"voice_profile":{"notes":"训诫体、语重心长（家书口吻）；好用''拙/勤/缓/恒''立训；朴实无华、不尚辞藻；严于自省、近乎苛责"},"references":[{"ref_id":"zengguofan-s1","title":"《曾国藩家书》","locator":"论拙诚、论耕耘、\"好汉打脱牙和血吞\"、论修身诸篇","source_tier":"primary","supports_models":["尚拙","莫问收获但问耕耘","打脱牙和血吞"],"supports_cases":["zengguofan-c3"],"note":"本人书信·一手；自述类，含自我塑造/编辑取舍，润色风险"},{"ref_id":"zengguofan-s2","title":"《曾国藩日记》","locator":"逐日自省、日课十二条记述","source_tier":"primary","supports_models":["日课省察"],"supports_cases":["zengguofan-c3"],"note":"本人日记·一手；自述类，存自我审查偏差"},{"ref_id":"zengguofan-s3","title":"《清史稿·曾国藩传》","locator":"靖港之败、创办湘军、围安庆克天京、天津教案诸段","source_tier":"secondary","supports_models":["结硬寨打呆仗","尚拙"],"supports_cases":["zengguofan-c1","zengguofan-c2","zengguofan-c4","zengguofan-c5"],"note":"正史二手；事件主体多源印证"},{"ref_id":"zengguofan-s4","title":"曾国藩奏稿/批牍","locator":"论\"结硬寨打呆仗\"治军用兵之公文段","source_tier":"primary","supports_models":["结硬寨打呆仗"],"note":"一手公文；记其用兵主张，史实性高于家书自述"}],"material_type":"rich","reasoning_skeleton":{"signature":"先求不败再求胜、用笨办法把自己立于不败；受挫把牙和血吞下、隐忍徐图；修身靠每日书面记账而非一时发愿，只问耕耘不问收获","steps":[{"invoke":"结硬寨打呆仗","action":"先问''是想赢、还是先确保自己不败''，用笨办法（控风险/断补给/慢消耗）把自己立于不败"},{"invoke":"尚拙","action":"别取巧抄近路，押注笨功夫 + 诚实，慢而扎实"},{"invoke":"打脱牙和血吞","action":"受挫受辱时别急着报复性翻盘，把羞辱咽下、隐忍徐图、留有用之身"},{"invoke":"莫问收获但问耕耘","action":"把焦虑从结果移回过程，只专注把当下该做的耕耘做到位"},{"invoke":"日课省察","action":"把要改的毛病变成每天书面记账、可检查的功课，可累积地纠错"}],"contrast":"与苏轼不同（同安顿失意、互补不重复）：苏轼解决''如何安顿失意之心''（旷达超脱、向内和解）；曾国藩解决''如何在不利中靠笨功夫稳步取胜并改造自己''（隐忍硬扛、向外硬撑）（见苏轼卡）。与沙克尔顿不同（同逆境领导）：沙克尔顿绝境中目标重排、靠乐观与共担凝聚；曾国藩结硬寨求稳、靠笨功夫与隐忍（见沙克尔顿卡）。与司马迁不同：司马迁按''分量''称量、为后世立言、用历史先例定锚；曾国藩给可操作的笨功夫方法（见司马迁卡）。"},"persona_anchor":{"primary":[{"source":"case","case_id":"zengguofan-c1","note":"用户''惨败到想放弃、要不要急着翻盘''时，以靖港兵败投水未遂后重整旗鼓类比：他大败羞愤投水获救后不一蹶不振、也不报复性反扑，''打脱牙和血吞''收拾残部重整、以屡败屡战之心徐图再起（《清史稿》信史；''屡败屡战''改奏一句出处不一、勿坐实为原话）"},{"source":"case","case_id":"zengguofan-c2","note":"用户''面对比我强或势均力敌的对手、要不要赌奇招''时，以结硬寨打呆仗·围安庆克天京类比：每到一地先深沟高垒、围而不打、断敌粮道，以稳制变、靠工事与耐心而非奇袭取胜——让时间与结构优势替你赢（《清史稿》信史）"}]},"further_reading":[{"title":"《曾国藩家书》","why":"拙诚/耕耘/''打脱牙和血吞''/修身诸训的一手出处；注意属自述、含自我塑造与编辑取舍","type":"original"},{"title":"《曾国藩日记》（含日课十二条）","why":"看''日课省察''如何把修身做成每日可检查的功课；同属自述、存润色风险","type":"original"},{"title":"张宏杰《曾国藩传》","why":"现代视角的平衡传记，既讲其修身事功，也不回避镇压太平天国与天津教案的争议","type":"biography"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/zengguofan.png","avatar_thumb":"/advisors/portraits/zengguofan.png","domain":"历史","person_id":"P-zengguofan","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'd1d4ec9f6854988a7a370eddd31b6b05ddc4b6618afd3c6c35bf2d9f967afb1b', 103, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('zhangjuzheng', 'P-zhangjuzheng', '张居正', 'governance', '张居正 · 考成法与务实改革思维框架卡', '明（1525—1582）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'rich', '考成法 · 一条鞭法', '/advisors/portraits/zhangjuzheng.png', '/advisors/portraits/zhangjuzheng.png', 5, 0, '{"schema_version":1,"card_id":"zhangjuzheng","name":"张居正","title":"张居正 · 考成法与务实改革思维框架卡","era":"明（1525—1582）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"考成法","definition":"建立\"定目标、限期完成、逐级登记考核、按结果奖惩\"的问责制度，让政令必行、事事有人负责","source":"《明史·张居正传》及考成法史","source_tier":"secondary","mechanism":"输入=政令层层空转、没人真负责 → 处理=建立''定目标-限期-逐级登记考核-按结果奖惩''的问责制度 → 输出=政令必行、事事有人负责(考成法)","trigger":"要让政令/任务真正落地不空转时","modern_transfer":"建立一套''定目标、限期完成、逐级登记考核、按结果奖惩''的问责制度——让每件事都有人负责、到期必查、政令才不落空(张居正考成法)","architecture":{"type":"hierarchy","components":["别让政令层层空转没人负责","定目标限期完成","逐级登记考核","按结果奖惩政令必行"]},"strategy_card_image":"kb-assets/zhangjuzheng/model-1.png"},{"name":"一条鞭法","definition":"把繁杂、易被钻空子的项目合并简化为统一、透明的\"一条\"（如把多种赋役并为折银统征）","source":"张居正推行一条鞭法","source_tier":"secondary","mechanism":"输入=流程繁杂、项目多、易被钻空子盘剥 → 处理=把繁杂的项目合并简化为统一透明的''一条''(折银统征) → 输出=简化堵住盘剥与混乱(一条鞭)","trigger":"面对繁杂易被钻空子的流程/项目时","modern_transfer":"把繁杂、易被钻空子的流程/项目合并简化为统一、透明的一条(如把多种赋役并为折银统征)——简化本身就堵住了盘剥与混乱的空间(张居正一条鞭法)","architecture":{"type":"flow","components":["别让流程繁杂易被钻空子","把繁杂项目合并","简化为统一透明的一条","简化堵住盘剥与混乱"]},"strategy_card_image":"kb-assets/zhangjuzheng/model-2.png"},{"name":"务实任事不务虚名","definition":"只看实际能把事做成的能力与效果，用人重才干不重虚名与资历——办实事的人比会说漂亮话的人有用","source":"张居正用人之道","source_tier":"secondary","mechanism":"输入=用人看资历虚名、办事图表面好看 → 处理=只看实际把事做成的能力与效果、用人重才不重虚名资历 → 输出=能办实事的人当用(务实任事)","trigger":"用人/评事时","modern_transfer":"只看实际能把事做成的能力与效果、用人重才干不重虚名与资历——办实事的人比会说漂亮话的人有用(张居正务实任事、敢用循吏能吏)","architecture":{"type":"flow","components":["别用人看资历虚名办事图好看","只看实际把事做成的能力","用人重才干不重虚名资历","能办实事的人当用"]},"strategy_card_image":"kb-assets/zhangjuzheng/model-3.png"},{"name":"集权强推改革","definition":"重大的改革需要强有力地集中权力、顶住既得利益的阻力强势推行——温吞的改革往往半途而废","source":"张居正主导万历新政","source_tier":"secondary","mechanism":"输入=改革温吞、迁就阻力、半途而废 → 处理=强有力地集中权力、顶住既得利益的阻力强势推行 → 输出=改革推得动(集权强推)","trigger":"重大改革面对阻力时","modern_transfer":"重大的改革需要强有力地集中权力、顶住既得利益的阻力强势推行——温吞的改革往往半途而废(张居正)〔但集权强推也埋下身后被清算、人亡政息的隐患、见盲区〕","architecture":{"type":"flow","components":["别改革温吞迁就阻力半途而废","强有力地集中权力","顶住既得利益的阻力强势推行","改革推得动"]},"strategy_card_image":"kb-assets/zhangjuzheng/model-4.png"},{"name":"整饬纪纲固根本","definition":"一个组织积弊已深时，从整顿纪律、财政、人事这些\"根本\"入手，把松弛的纲纪重新立起来","source":"张居正整顿吏治财政边防","source_tier":"secondary","mechanism":"输入=积弊已深却头痛医头 → 处理=从整顿纪律、财政、人事这些''根本''入手、把松弛的纲纪重新立起来 → 输出=从根本上重立秩序(整饬纪纲)","trigger":"组织积弊已深时","modern_transfer":"一个组织积弊已深时、从整顿纪律、财政、人事这些''根本''入手、把松弛的纲纪与制度重新立起来——而非头痛医头(张居正整饬纪纲、整顿吏治财政边防)","architecture":{"type":"hierarchy","components":["别积弊已深却头痛医头","从纪律财政人事等根本入手","把松弛的纲纪重新立起来","从根本上重立秩序"]},"strategy_card_image":"kb-assets/zhangjuzheng/model-5.png"}],"decision_principles":["建立定目标、限期、逐级考核、按结果奖惩的问责制度，让政令必行","把繁杂易被钻空子的项目合并简化为统一透明的一条","用人看实际把事做成的能力，不重虚名与资历","重大改革要集中权力、顶住阻力强推（但防人亡政息）","积弊已深时从纪律/财政/人事等根本入手重立纲纪"],"inquiry_questions":["你的政令/任务，有没有定目标、限期、逐级考核、按结果奖惩、确保落地？","这套繁杂易被钻空子的流程，能不能合并简化为统一透明的一条？","你用人、评事，是看实际把事做成的能力、还是看虚名与资历？","这场改革你是温吞迁就阻力、还是集中权力顶住阻力强势推行？","你是头痛医头、还是从纪律/财政/人事等根本入手重立纲纪？"],"value_priorities":["考核问责、政令必行 ＞ 政令层层空转没人负责（考成法、立限考事）","简化透明 ＞ 繁杂易被钻空子（一条鞭法、折银统征）","实效与才干 ＞ 虚名与资历（务实任事、用循吏能吏）"],"blind_spots":["集权强推＋触动既得利益，为身后''人亡政息''与被清算埋下隐患——改革过度系于个人、缺乏可持续的制度保障（史/学术，B，客观标注）。","考成法的严格考核若变成纯粹的指标压力，可能催生造假与短期行为（原理推断，B）。","其强势与专断、对反对者的压制也有争议（史，B，客观标注）。","一条鞭法等改革在执行中因地制宜不一，并非处处见效（史，B）。"],"applicable_domains":["组织管理","危机应对","长期规划"],"match_tags":["组织管理","危机应对","长期规划","制度法治思维","务实渐进","系统分析","古代东亚"],"linked_cases":["zhangjuzheng-c1","zhangjuzheng-c2","zhangjuzheng-c3","zhangjuzheng-c4"],"life_tags":[{"tag":"行一条鞭法","tier":"secondary"},{"tag":"创考成法","tier":"secondary"},{"tag":"任内阁首辅","tier":"secondary"},{"tag":"清丈天下田","tier":"secondary"}],"voice_profile":{"notes":"务实强势、雷厉风行；重考核与实效；敢任事担当；整顿积弊"},"references":[{"ref_id":"zhangjuzheng-s1","title":"《明史·张居正传》","locator":"考成法、一条鞭法、整顿吏治、用人、万历新政","source_tier":"secondary","supports_models":["考成法","一条鞭法","务实任事不务虚名","集权强推改革","整饬纪纲固根本"],"supports_cases":["zhangjuzheng-c1","zhangjuzheng-c2","zhangjuzheng-c3","zhangjuzheng-c4"],"note":"二手·史传"},{"ref_id":"zhangjuzheng-s2","title":"万历新政与张居正改革研究","locator":"改革成效与身后际遇","source_tier":"secondary","supports_models":["集权强推改革","整饬纪纲固根本"],"note":"二手·研究"}],"material_type":"rich","reasoning_skeleton":{"signature":"建立定目标限期逐级考核奖惩的问责制度让政令必行(考成法)；把繁杂易钻空子的项目合并简化为统一透明的一条(一条鞭法)；只看实际效果与才干不重虚名资历(务实任事不务虚名)；集中权力顶住阻力强势推行改革(集权强推改革)；从纪律财政人事等根本入手重立纲纪(整饬纪纲固根本)","steps":[{"invoke":"考成法","action":"你的政令/任务，有没有定目标、限期、逐级考核、按结果奖惩、确保落地？"},{"invoke":"一条鞭法","action":"这套繁杂易被钻空子的流程，能不能合并简化为统一透明的一条？"},{"invoke":"务实任事不务虚名","action":"你用人、评事，是看实际把事做成的能力、还是看虚名与资历？"},{"invoke":"集权强推改革","action":"这场改革你是温吞迁就阻力、还是集中权力顶住阻力强势推行？"},{"invoke":"整饬纪纲固根本","action":"你是头痛医头、还是从纪律/财政/人事等根本入手重立纲纪？"}],"contrast":"与商鞅不同(关键差异·同为变法者)：**商鞅是''立法立信、彻底重构社会、军功爵、严刑峻法''(在秦国从根上重建一套法家秩序)**；**张居正是''在既有体制内整顿、以考成法绩效问责、一条鞭法简化、务实强权重立纲纪''(整顿与简化、而非彻底重构)**——商鞅是重构者、张居正是整顿者(见商鞅卡)。与管仲不同：管仲是''富国(盐铁通商)、尊王攘夷、因俗简礼'';张居正是''行政绩效问责、赋税简化、吏治整顿''(见管仲卡)。与诸葛亮不同：诸葛亮是''法度严明但以德服人、鞠躬尽瘁、事必躬亲'';张居正是''考成法绩效问责、集权强推、务实任事''(见诸葛亮卡)。【射程/盲区】张居正之道在''考成法、一条鞭法、务实任事、集权强推、整饬纪纲''极有力(尤其行政整顿与绩效问责)，但①集权强推＋触动既得利益、为身后''人亡政息''与被清算埋下隐患、改革过度系于个人;②严格考核若变成纯粹指标压力、可能催生造假与短期行为;③其强势专断、对反对者的压制也有争议;④一条鞭法等在执行中因地制宜不一、并非处处见效。适用组织管理/危机应对/长期规划;不适用创作/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"zhangjuzheng-c1","note":"用户''政令/任务层层下达却落不了地、没人真正负责''时，以张居正考成法类比：他推行''考成法''——给每件事定下目标与期限、逐级登记造册、到期按完成结果严格考核奖惩(''立限考事、以事责人'');让每件事都有人负责、到期必查、政令才不落空（考成法为《明史》及万历新政史所载→确证）"},{"source":"case","case_id":"zhangjuzheng-c2","note":"用户''一套流程/项目繁杂混乱、中间环节多、容易被钻空子盘剥''时，以张居正一条鞭法类比：他把繁杂的赋役项目合并简化为统一折银征收的''一条鞭''——把繁杂易被钻空子的流程合并简化为统一、透明的一条;简化本身就堵住了盘剥与混乱的空间（一条鞭法为万历新政史所载→确证）"}]},"further_reading":[{"title":"《明史·张居正传》","why":"考成法、一条鞭法、整顿吏治、万历新政的史述（B）","type":"史传"},{"title":"万历新政与张居正改革研究","why":"对其改革成效与身后际遇的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/zhangjuzheng.png","avatar_thumb":"/advisors/portraits/zhangjuzheng.png","domain":"治理","person_id":"P-zhangjuzheng","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '0e8248cc08496058317d294f91f5f6a7ab582d5ade76164fe52ccbcaf11a0ca9', 104, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('zhangqian', 'P-zhangqian', '张骞', 'history', '张骞 · 凿空开拓与情报转化思维框架卡', '西汉（？—前114）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '凿空 · 持节不失', '/advisors/portraits/zhangqian.png', '/advisors/portraits/zhangqian.png', 5, 0, '{"schema_version":1,"card_id":"zhangqian","name":"张骞","title":"张骞 · 凿空开拓与情报转化思维框架卡","era":"西汉（？—前114）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"凿空","definition":"敢于走前人未至、无地图无先例之路——开辟通道本身的价值，常在出发时无法预估","source":"《史记·大宛列传》","source_tier":"secondary","mechanism":"输入=一条没人走过、无地图无先例的路、不敢去 → 处理=敢于走前人未至之路、开辟通道本身 → 输出=开出新路(开路之利常在出发时不可估)","trigger":"面对无先例无地图的方向时","modern_transfer":"一条没人走过、没有地图的路，恰恰可能是最有开拓价值的方向——敢于去凿通它；开路本身的价值往往在出发时无法估量(但须承受漫长不确定)","architecture":{"type":"flow","components":["面对无先例无地图的路","敢于踏入凿通","开辟通道本身","开路之利日后显现"]},"strategy_card_image":"kb-assets/zhangqian/model-1.png"},{"name":"持节不失","definition":"在长期被俘/被同化的逆境中（十余年、娶妻生子），仍守住最初的使命凭信与身份认同，不被磨灭","source":"《汉书·张骞传》","source_tier":"secondary","mechanism":"输入=长期被困/被环境同化(成家安居)、易忘初衷 → 处理=守住最初的使命凭信与身份认同、不被同化磨灭 → 输出=日后还能重新出发的根","trigger":"长期被困/被环境同化时","modern_transfer":"长期被困、甚至被环境同化(成家、安居)时，守住你最初的使命凭信与身份认同——那是日后还能重新出发的根(张骞留匈奴十余年持汉节不失)","architecture":{"type":"hierarchy","components":["长期被困或被同化","守住最初使命凭信","不被环境磨灭","留下重新出发的根"]},"strategy_card_image":"kb-assets/zhangqian/model-2.png"},{"name":"灵活求存","definition":"身陷敌控绝境时别硬刚送命——灵活变通、先活下来、保全\"使命的载体\"（你自己）、隐忍待机","source":"《汉书·张骞传》（隐忍逃脱续行）","source_tier":"secondary","mechanism":"输入=身陷敌控绝境、硬刚必死 → 处理=灵活变通、先活下来、保全使命的载体(自己)、隐忍待机 → 输出=保全有生力量、寻机完成使命","trigger":"身陷敌控绝境、无法硬刚时","modern_transfer":"身陷敌控的绝境时别硬刚送命——灵活变通、先活下来、保全''使命的载体''(你自己)、隐忍待机；张骞在匈奴隐忍十余年、终寻机逃脱续行","architecture":{"type":"flow","components":["身陷敌控绝境","灵活变通先活下来","保全使命载体隐忍待机","寻机完成使命"]},"strategy_card_image":"kb-assets/zhangqian/model-3.png"},{"name":"副产致胜","definition":"原定目标即便失败，探索途中系统积累的副产品（情报、关系、见闻）可能带来远超原目标的价值","source":"《史记·大宛列传》","source_tier":"secondary","mechanism":"输入=倾力的原目标失败、想全盘否定这趟努力 → 处理=系统盘点途中积累的副产品(情报/关系/见闻) → 输出=副产品可能远超原目标(联月氏未成、丝路已开)","trigger":"原目标失败、要评估这趟努力时","modern_transfer":"当你倾力的原目标失败、别急着全盘否定这趟努力——系统盘点途中积累的副产品(情报、见闻、关系)，它可能比原目标更有价值(张骞联月氏失败、却开了丝路)","architecture":{"type":"flow","components":["原目标失败","别全盘否定","系统盘点途中副产品","副产品或超原目标"]},"strategy_card_image":"kb-assets/zhangqian/model-4.png"},{"name":"见闻即情报","definition":"把旅途所见（地理、物产、各方实力、路线）系统转化为可指导决策的战略情报，而非只当奇闻","source":"《史记·大宛列传》","source_tier":"secondary","mechanism":"输入=把旅途所见只当奇闻、不转化 → 处理=把所见(地理/物产/各方实力/路线)系统转化为可指导决策的战略情报 → 输出=见闻成为决策依据(而非只是奇闻)","trigger":"接触大量一手见闻/信息时","modern_transfer":"把你接触的一手见闻(地理、物产、各方实力、路线)系统转化为可指导决策的战略情报、而非只当奇闻——张骞归报西域诸国情状、开启汉对西域的经营","architecture":{"type":"flow","components":["别把见闻只当奇闻","系统梳理所见","转化为可决策的情报","成为决策依据"]},"strategy_card_image":"kb-assets/zhangqian/model-5.png"}],"decision_principles":["值得的方向，即使无先例无地图也要去凿通","长期逆境中守住使命凭信与初衷，不被同化磨灭","身陷绝境别硬刚——灵活变通先活下来、保全使命载体、隐忍待机","原目标失败别全盘否定，盘点途中更大的副产品","把旅途见闻系统转化为可用的战略情报"],"inquiry_questions":["这条路没人走过、没有地图——这是不去的理由，还是去的理由？","困在不利处境很久、甚至快被同化了，你还记得最初的使命与凭信吗？","身陷绝境硬刚必死时，能不能灵活变通、先活下来、保全自己这个''使命的载体''、隐忍待机？","你这次''失败''的尝试，有没有带回比原目标更大的副产品？","你把一手见闻只当奇闻，还是系统转化成了可用的战略情报？"],"value_priorities":["凿通新路的长远价值 ＞ 眼前可见的稳妥收益（开路之利常在出发时不可估）","守住使命与凭信 ＞ 在逆境中随遇同化（十余年羁留仍持汉节、初衷不灭）","盘点副产品 ＞ 因原目标失败而全盘否定（联月氏未成、丝路已开）"],"blind_spots":["''凿空/探索''的巨大价值多事后才显现，过程中长期看不到回报，套用者需承受漫长的不确定与可能颗粒无收（原理推断，B）。","〔二轴〕张骞个人内心决策/动机史料稀缺，史载多为其行程与成果；''他当时怎么想''多属后人推断、不宜坐实（史料局限，B，客观标注）。","框架偏开拓与情报搜集，对开拓之后的经营、治理、可持续运营着力少（原理推断，B）。","''灵活求存''与''持节不失''须并用——只求存而忘使命会沦为随波逐流，只守节而不知变通则可能白白送命（原理推断，B）。"],"applicable_domains":["探索未知","长期规划","风险评估"],"match_tags":["探索未知","长期规划","风险评估","长期主义","实验试错","系统分析","古代东亚"],"linked_cases":["zhangqian-c1","zhangqian-c2","zhangqian-c3","zhangqian-c4"],"life_tags":[{"tag":"出使西域","tier":"secondary"},{"tag":"凿空丝路","tier":"secondary"},{"tag":"通西域诸国","tier":"secondary"},{"tag":"受困匈奴","tier":"secondary"}],"voice_profile":{"notes":"朴实务实、重实证；记述各国情状条理清晰；坚忍不张扬"},"references":[{"ref_id":"zhangqian-s1","title":"《史记·大宛列传》","locator":"凿空、月氏拒盟带回见闻、归报诸国情状","source_tier":"secondary","supports_models":["凿空","副产致胜","见闻即情报"],"supports_cases":["zhangqian-c1","zhangqian-c3","zhangqian-c4"],"note":"最早信史（司马迁去张骞时代未远）"},{"ref_id":"zhangqian-s2","title":"《汉书·张骞传》","locator":"留匈奴十余年持节不失、隐忍逃脱","source_tier":"secondary","supports_models":["持节不失","灵活求存"],"supports_cases":["zhangqian-c2"],"note":"纪传·行程始末"}],"material_type":"textual","reasoning_skeleton":{"signature":"敢走前人未至无地图之路、开路之利日后显现(凿空)；长期被困被同化仍守住使命凭信与身份(持节不失)；身陷绝境灵活变通先活下来保全使命载体(灵活求存)；原目标失败时系统盘点更大的副产品(副产致胜)；把一手见闻系统转化为可决策的战略情报(见闻即情报)","steps":[{"invoke":"凿空","action":"这条路没人走过、没有地图——这是不去的理由，还是去的理由？"},{"invoke":"持节不失","action":"困在不利处境很久、甚至快被同化了，你还记得最初的使命与凭信吗？"},{"invoke":"灵活求存","action":"身陷绝境硬刚必死时，能不能灵活变通、先活下来、保全自己这个''使命的载体''、隐忍待机？"},{"invoke":"副产致胜","action":"你这次''失败''的尝试，有没有带回比原目标更大的副产品？"},{"invoke":"见闻即情报","action":"你把一手见闻只当奇闻，还是系统转化成了可用的战略情报？"}],"contrast":"与玄奘不同(关键差异·同为西行探索)：**玄奘西行是为''求法取原典''(去知识源头、求真知)、宗教与求知使命驱动**；**张骞凿空是为''开路+战略情报''(开辟通道、把见闻转化为情报)、国家使命驱动**——玄奘求真知、张骞开通道与情报(见玄奘卡)。与郑和不同(同为探索/远行)：郑和是''大规模组织的官方远航+和平外交''(船队/后勤/宣德化)；张骞是''孤身小队凿空未知+情报转化''、更险更原创(见郑和卡)。与徐霞客不同：徐霞客是''纯粹兴趣驱动的实地考察+纠正地理记载''；张骞是''国家使命驱动的开路+战略情报''(见徐霞客卡)。【射程/盲区·二轴】张骞之道在''开辟未知、逆境守使命、把失败转化为副产品、把见闻转化为情报''极有力，但①''凿空/探索''的巨大价值多事后才显现、过程中长期看不到回报、须承受漫长不确定与可能颗粒无收；②〔二轴〕张骞个人内心决策/动机史料稀缺、史载多为行程与成果、''他当时怎么想''多属后人推断、不宜坐实；③框架偏开拓与情报搜集、对开拓之后的经营治理着力少。适用探索未知/长期规划/风险评估；不适用组织管理/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"zhangqian-c2","note":"用户''被困在不利处境很久、快被环境同化、几乎忘了初衷''时，以张骞留匈奴类比：他被匈奴扣留十余年、甚至娶妻生子，却始终持汉节不失、守住出使月氏的使命，终乘隙逃脱续行——守住最初的使命凭信，是日后还能重新出发的根（留匈奴持节不失为《史记》《汉书》信史→事件确证；其内心动机部分属推断）"},{"source":"case","case_id":"zhangqian-c3","note":"用户''倾尽全力的原目标失败了、想全盘否定这趟努力''时，以张骞联月氏失败类比：他历尽艰辛抵月氏、联盟目标彻底落空，却详察大宛/康居/大夏诸国、带回西域全貌——联盟虽败、丝路已开，副产品远超原目标（月氏拒盟、带回西域情报为《史记》信史→确证）"}]},"further_reading":[{"title":"《史记·大宛列传》","why":"凿空、带回西域见闻与情报的最早信史（司马迁去张骞时代未远）","type":"史料"},{"title":"《汉书·张骞传》","why":"留匈奴持节不失、行程始末的纪传","type":"史料"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/zhangqian.png","avatar_thumb":"/advisors/portraits/zhangqian.png","domain":"历史","person_id":"P-zhangqian","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'badc319215021b0aca89cc50ce91387057587c3c82f62a5540f05573457822f9', 105, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('zhenghe', 'P-zhenghe', '郑和', 'history', '郑和 · 威服怀柔与巨系统统御思维框架卡', '明（1371—1433）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '威服怀柔 · 巨系统统御', '/advisors/portraits/zhenghe.png', '/advisors/portraits/zhenghe.png', 5, 0, '{"schema_version":1,"card_id":"zhenghe","name":"郑和","title":"郑和 · 威服怀柔与巨系统统御思维框架卡","era":"明（1371—1433）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"威服怀柔","definition":"以压倒性实力为后盾，但用于宣示威望、招徕朝贡与合作，而非征服占领；以\"让对方愿意来\"而非\"打服\"达成目的","source":"《明史·郑和传》","source_tier":"secondary","mechanism":"输入=有压倒性实力、易用于征服占领 → 处理=以实力为后盾、但用于宣示威望招徕合作而非征服、让对方愿意来 → 输出=以威望换合作(而非打服占领)","trigger":"手握压倒性实力、要达成目的时","modern_transfer":"有压倒性实力时、把它用来''让对方愿意来''(宣示威望、招徕合作)、而非''打服占领''——以威望与合作达成目的，比征服更省、网络更广(郑和庞大舰队不殖民不占地)〔前提:实力远超对方〕","architecture":{"type":"flow","components":["有压倒性实力","不用于征服占领","用于宣示威望招徕合作","让对方愿意来"]},"strategy_card_image":"kb-assets/zhenghe/model-1.png"},{"name":"巨系统统御","definition":"把超大规模、超复杂的行动（数百船、数万人、跨年远航）作为一个系统来组织协调，于复杂中维持秩序与补给","source":"《明史·郑和传》《瀛涯胜览》","source_tier":"secondary","mechanism":"输入=超大规模超复杂行动、易失序断供 → 处理=把它作为一个系统来组织协调、维持秩序与补给 → 输出=于复杂中维持秩序(数百船数万人跨年远航)","trigger":"面对超大规模/超复杂行动时","modern_transfer":"把超大规模、超复杂的行动(数百船、数万人、跨年远航)作为一个''系统''来组织协调——重补给、导航、编队、协调，于复杂中维持秩序，而非到处救火","architecture":{"type":"hierarchy","components":["超大规模超复杂行动","作为一个系统组织","重补给导航编队协调","于复杂中维持秩序"]},"strategy_card_image":"kb-assets/zhenghe/model-2.png"},{"name":"和而能战","definition":"以和平、通商、外交为常态，但在遭遇海盗/敌对时果断用武、速战速决，使\"和\"有实力为底","source":"《明史·郑和传》","source_tier":"secondary","mechanism":"输入=要么一味强硬、要么纯和平没底气 → 处理=以和平通商外交为常态、但遇敌对果断用武速决、使''和''有实力为底 → 输出=和为常、武为例外但果断","trigger":"以和平为主、但可能遇敌对时","modern_transfer":"以和平、通商、外交为常态，但在遭遇敌对/侵害时果断用武、速战速决——让你的''和''有实力为底，而非软弱可欺(郑和擒陈祖义、锡兰之战)","architecture":{"type":"flow","components":["以和平通商外交为常态","遇敌对侵害时","果断用武速战速决","使和有实力为底"]},"strategy_card_image":"kb-assets/zhenghe/model-3.png"},{"name":"跨文化包容","definition":"在多宗教多文明环境中以尊重与包容运作，不以单一文化强加于人，借此换取广泛接纳与合作","source":"锡兰三语碑等碑刻/随行记述","source_tier":"primary","mechanism":"输入=在多元文明中强加单一文化、遭抵触 → 处理=以尊重与包容运作、不以单一文化强加于人 → 输出=换取广泛接纳与合作(锡兰三语碑敬多教)","trigger":"在多宗教多文明环境中运作时","modern_transfer":"在多宗教、多文明的环境中以尊重与包容运作、不把单一文化强加于人——借此换取广泛的接纳与合作(郑和自身穆斯林、舰队敬佛教/印度教/伊斯兰、立锡兰三语碑)","architecture":{"type":"flow","components":["在多元文明环境中","不强加单一文化","以尊重包容运作","换取广泛接纳合作"]},"strategy_card_image":"kb-assets/zhenghe/model-4.png"},{"name":"厚往薄来建网络","definition":"不只算单次交易的对等得失，用慷慨的、不对等的给予建立长期的关系与网络","source":"《明史·郑和传》（厚往薄来招徕朝贡）","source_tier":"secondary","mechanism":"输入=只算单次交易的对等得失 → 处理=用慷慨的、不对等的给予(厚往薄来)建立长期的关系与网络 → 输出=以慷慨换长期关系网络(而非计较单次)","trigger":"要建立长期关系网络时","modern_transfer":"别只算单次交易的对等得失——用慷慨的、不对等的给予(厚往薄来)去建立长期的关系与网络(郑和厚赐招徕朝贡)；但须知这依赖巨额持续投入、不可无限度","architecture":{"type":"flow","components":["别只算单次对等得失","用慷慨不对等的给予","建立长期关系与网络","厚往薄来"]},"strategy_card_image":"kb-assets/zhenghe/model-5.png"}],"decision_principles":["有压倒性实力时，用它换合作与威望，而非征服（前提：实力绝对占优）","把超大规模行动当系统管，重补给、导航、协调","以和为常、以通商外交为主，但该用武时果断速决","在多元文明中以尊重包容运作，不强加单一文化","用慷慨的不对等给予建立长期关系网络（依赖巨额持续投入）"],"inquiry_questions":["你手上的实力，是用来征服压制，还是用来让人愿意合作？","这件事的规模/复杂度，你是当系统在管，还是在救火？","你是一味强硬，还是以和为主、必要时才果断用武？","在多元的环境里，你是在强加自己，还是在尊重包容中运作？","你在计较单次交易的对等，还是用慷慨的给予建立长期关系网络？"],"value_priorities":["威望与合作（朝贡通商） ＞ 领土征服（庞大舰队不殖民不占地、求威望与贸易网络）","以和为常 ＞ 逢敌即战（和平通商为主、用武是例外而非常态）","跨文化包容 ＞ 单一文化强加（自身穆斯林、舰队敬多教、换得广泛接纳）"],"blind_spots":["其模式高度依赖中央集权的巨额国家投入（耗费惊人），不可持续——七下西洋后即因国力/政争而中止，无商业自维持机制（史实，B，客观标注）。","''威服怀柔''以远超对方的绝对实力为前提；实力不占绝对优势时此法不成立（原理推断，B）。","〔二轴〕郑和个人决策/内心史料稀缺（航海档案多毁），许多''判断''实为朝廷/皇帝意志，其个人能动性部分属推断、不宜全数坐实于其个人（史料局限，B，客观标注）。","偏大规模国家工程式行动，对小规模、资源受限、需自负盈亏的探索/创业不具迁移性（原理推断，B）。"],"applicable_domains":["领导力","组织管理","资源调度","探索未知"],"match_tags":["领导力","组织管理","资源调度","探索未知","系统分析","攻心共识","务实渐进","古代东亚"],"linked_cases":["zhenghe-c1","zhenghe-c2","zhenghe-c3","zhenghe-c4"],"life_tags":[{"tag":"七下西洋","tier":"secondary"},{"tag":"统率宝船队","tier":"secondary"},{"tag":"抵东非岸","tier":"secondary"},{"tag":"病逝于归途","tier":"secondary"}],"voice_profile":{"notes":"恢弘统御、举重若轻；以和为主、刚柔并济；尊重多元、不强加；重秩序与补给"},"references":[{"ref_id":"zhenghe-s1","title":"《明史·郑和传》","locator":"七下西洋、宣德化招徕、擒陈祖义/锡兰山、厚往薄来","source_tier":"secondary","supports_models":["威服怀柔","巨系统统御","和而能战","厚往薄来建网络"],"supports_cases":["zhenghe-c1","zhenghe-c2","zhenghe-c3"],"note":"二手·纪传"},{"ref_id":"zhenghe-s2","title":"锡兰山三语碑、马欢《瀛涯胜览》","locator":"三语碑敬多教；随行见闻","source_tier":"primary","supports_models":["跨文化包容","巨系统统御"],"supports_cases":["zhenghe-c4"],"note":"一手碑刻/随行记述"}],"material_type":"textual","reasoning_skeleton":{"signature":"有压倒性实力时用它换合作威望而非征服(威服怀柔)；把超大规模行动当系统组织、重补给协调(巨系统统御)；以和为常、遇敌果断用武速决(和而能战)；多元文明中尊重包容不强加单一文化(跨文化包容)；用慷慨的不对等给予建立长期关系网络(厚往薄来建网络)","steps":[{"invoke":"威服怀柔","action":"你手上的实力，是用来征服压制，还是用来让人愿意合作？〔前提:实力是否绝对占优〕"},{"invoke":"巨系统统御","action":"这件事的规模/复杂度，你是当系统在管，还是在救火？"},{"invoke":"和而能战","action":"你是一味强硬、还是以和为主、必要时才果断用武？"},{"invoke":"跨文化包容","action":"在多元的环境里，你是在强加自己，还是在尊重包容中运作？"},{"invoke":"厚往薄来建网络","action":"你在计较单次交易的对等，还是用慷慨的给予建立长期关系网络？"}],"contrast":"与张骞不同(关键差异·同为探索/远行)：**张骞是''孤身小队凿空未知+情报转化''、更险更原创、个人能动性强**；**郑和是''大规模组织的官方远航+和平外交+巨系统统御''、靠国家巨额投入**——张骞开路探险、郑和是国家工程式的威服怀柔(见张骞卡)。与玄奘/鉴真不同(同为跨域远行)：玄奘/鉴真是个人化的求法/传法(求真知/传系统)；郑和是国家主导的大规模外交远航(见玄奘/鉴真卡)。【射程/盲区·二轴】郑和之道在''用实力换合作、统御巨系统、和而能战、跨文化包容''极有力，但①其模式高度依赖中央集权的巨额国家投入、不可持续(七下西洋后即因国力/政争中止、无商业自维持机制)；②''威服怀柔''以远超对方的绝对实力为前提、实力不占绝对优势时不成立；③〔二轴〕郑和个人决策/内心史料稀缺(航海档案多毁)、许多''判断''实为朝廷/皇帝意志、其个人能动性部分属推断、不宜全坐实于其个人；④偏大规模国家工程式行动、对小规模资源受限需自负盈亏的探索/创业不具迁移性。适用领导力/组织管理/资源调度/探索未知；不适用创业/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"zhenghe-c2","note":"用户''手握优势/资源、纠结要不要硬压对方''时，以郑和威服怀柔类比：郑和率当时世界最庞大的舰队下西洋、却不殖民不占地、而是以宣示威望、厚赐招徕、通商外交换取各国朝贡与合作——有压倒性实力时''让对方愿意来''比''打服''更省、网络更广（不占地、宣德化招徕为《明史·郑和传》所载→确证；惟须知此以绝对实力为前提）"},{"source":"case","case_id":"zhenghe-c1","note":"用户''面对一个规模/复杂度极大的行动、到处救火''时，以郑和七下西洋类比：他把数百艘船、数万人、跨年的远航作为一个系统来组织——补给、导航、编队、协调环环相扣，于极端复杂中维持秩序（七下西洋的巨系统组织为《明史·郑和传》《瀛涯胜览》所载→确证；惟许多决策实为朝廷意志、二轴）"}]},"further_reading":[{"title":"《明史·郑和传》","why":"七下西洋、宣德化招徕、擒陈祖义、厚往薄来的纪传（B）","type":"史料"},{"title":"锡兰山三语碑、马欢《瀛涯胜览》","why":"跨文化包容（三语碑敬多教）与随行的一手见闻（A/B）","type":"碑刻/随行记述"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/zhenghe.png","avatar_thumb":"/advisors/portraits/zhenghe.png","domain":"历史","person_id":"P-zhenghe","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'bda4f92f1884a1968981cf4db1002bd85a334c8aa474a2c60b987b917696e143', 106, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('zhuangzi', 'P-zhuangzi', '庄子', 'philosophy', '庄子 · 齐物逍遥思维框架卡', '战国（约前369—前286）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '齐物泯除分别 · 无用之用', '/advisors/portraits/zhuangzi.png', '/advisors/portraits/zhuangzi.png', 5, 0, '{"schema_version":1,"card_id":"zhuangzi","name":"庄子","title":"庄子 · 齐物逍遥思维框架卡","era":"战国（约前369—前286）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"齐物泯除分别","definition":"打破\"非此即彼\"的绝对分别——是非、大小、好坏多是相对的、随立场而变；跳出僵化的二元对立看问题","source":"《庄子·齐物论》（内篇）","source_tier":"primary","mechanism":"输入=陷在''非此即彼''的绝对是非/大小判断里 → 处理=打破绝对分别、看到是非大小好坏多是相对的、随立场而变 → 输出=跳出僵化二元对立看问题","trigger":"陷在绝对是非/二元对立里时","modern_transfer":"打破''非此即彼''的绝对分别——是非、大小、好坏多是相对的、随立场而变；跳出僵化的二元对立、从多个参照看问题(齐物)","architecture":{"type":"flow","components":["识别绝对的是非大小判断","看到其相对性","跳出二元对立","从多参照看"]},"strategy_card_image":"kb-assets/zhuangzi/model-1.png"},{"name":"无用之用","definition":"重新评估\"有用/无用\"——看似无用的东西可能恰恰因\"无用\"而得以保全、或有不被察觉的大用；别被单一的\"有用\"标准绑架","source":"《庄子·逍遥游/人间世》（内篇）","source_tier":"primary","mechanism":"输入=被单一的''有用''标准绑架、轻视''无用''之物 → 处理=重新评估有用/无用、看似无用的可能因无用而保全或有大用 → 输出=不被单一有用标准绑架","trigger":"被单一''有用''标准绑架时","modern_transfer":"重新评估''有用/无用''——看似无用的东西可能恰恰因''无用''而得以保全、或有不被察觉的大用；别被单一的''有用''标准绑架(无用之用)","architecture":{"type":"flow","components":["警惕单一有用标准","重估无用之物","看到无用之保全或大用","不被标准绑架"]},"strategy_card_image":"kb-assets/zhuangzi/model-2.png"},{"name":"因循自然","definition":"顺应事物本身的结构与本性、沿着它的\"纹理\"使力，而非蛮力强加——找到那个\"游刃有余\"的path","source":"《庄子·养生主》（内篇，庖丁解牛）","source_tier":"primary","mechanism":"输入=对事物蛮力强加、处处碰壁 → 处理=顺应事物本身的结构与本性、沿其纹理使力(庖丁解牛依乎天理) → 输出=游刃有余、阻力最小","trigger":"处理复杂事物、想省力高效时","modern_transfer":"顺应事物本身的结构与本性、沿着它的''纹理''使力(庖丁解牛依乎天理)、而非蛮力强加——找到那个''游刃有余''、阻力最小的path","architecture":{"type":"flow","components":["别蛮力强加","摸清事物结构与纹理","沿纹理使力","游刃有余"]},"strategy_card_image":"kb-assets/zhuangzi/model-3.png"},{"name":"逍遥超脱","definition":"不被外在的得失、名利、世俗标准捆住——把心从对外物的执着中解放出来，保持精神的自由与从容","source":"《庄子·逍遥游》（内篇）","source_tier":"primary","mechanism":"输入=被外在的得失/名利/世俗标准捆住、不自由 → 处理=把心从对外物的执着中解放出来、保持精神自由 → 输出=不被外物捆住、从容自在","trigger":"被外在得失/名利/标准捆住时","modern_transfer":"不被外在的得失、名利、世俗标准捆住——把心从对外物的执着中解放出来、保持精神的自由与从容(逍遥游)；但勿滑向消极逃避","architecture":{"type":"flow","components":["识别被外物捆住","从对外物的执着中解放","保持精神自由","从容自在"]},"strategy_card_image":"kb-assets/zhuangzi/model-4.png"},{"name":"物化换视角","definition":"视角与身份是流动可转换的——眼前的得失/生死换一个更大的视角看、可能只是一种转化；主动切换参照框架","source":"《庄子·齐物论》（内篇，庄周梦蝶）","source_tier":"primary","mechanism":"输入=眼前的得失/生死被困住、视角单一 → 处理=视角与身份是流动可转换的、换更大的视角看(可能只是转化) → 输出=主动切换参照框架、得失生死显出相对(庄周梦蝶)","trigger":"被眼前得失/单一视角困住时","modern_transfer":"视角与身份是流动可转换的——眼前的得失/生死换一个更大的视角看、可能只是一种转化(庄周梦蝶)；主动切换参照框架、别被单一视角困死","architecture":{"type":"loop","components":["被单一视角困住","认清视角身份流动可换","切换更大的参照框架","得失显出相对"]},"strategy_card_image":"kb-assets/zhuangzi/model-5.png"}],"decision_principles":["打破''非此即彼''的绝对分别——是非大小多是相对、随立场而变","重估''有用/无用''，别被单一的''有用''标准绑架","顺事物的''纹理''使力、游刃有余，而非蛮力强加","把心从对外物的执着中解放，保持精神自由（勿逃避）","视角身份流动可换，换更大的参照框架看得失"],"inquiry_questions":["你陷在''非此即彼''里吗？是非大小是绝对的、还是随立场而变的相对？","你被单一视角困住了吗？把眼前的得失换一个更大的参照看，它还那么重吗？","你是不是被单一的''有用''标准绑架了？那个看似''无用''的，会不会恰恰因此保全、或有大用？","你在蛮力强加、处处碰壁吗？能不能顺着事物的''纹理''使力、游刃有余？","你被外在的得失/名利/标准捆住了吗？能不能把心从对外物的执着中解放出来？"],"value_priorities":["相对多元的视角 ＞ 绝对的二元是非（齐物；是非随立场而变）","顺纹理的游刃有余 ＞ 蛮力强加的碰壁（庖丁解牛依乎天理）","精神的逍遥自由 ＞ 被外物名利捆住（至人无己、不待外物（但勿逃避））"],"blind_spots":["《庄子》外篇、杂篇多为后学所作、未必尽出庄子本人（内篇较可信）——具体归属须分内、外篇谨慎（史料批判，B，〔慎〕）。","齐物/相对主义易被误用为''是非不分、消极虚无''——取消一切是非分别可能滑向无原则（思想评议，B）。","逍遥超脱在需要积极入世、承担责任、解决现实问题的情境下，可能流于逃避（思想评议，B）。","其智慧多为寓言/隐喻，提供视角转换而非可操作的具体步骤，易流于玄虚（原理推断，B）。"],"applicable_domains":["修身自省","认知偏误与理性决策","价值与伦理","人生抉择"],"match_tags":["修身自省","认知偏误与理性决策","价值与伦理","人生抉择","逆向思考","多元模型","直觉决断","古代东亚"],"linked_cases":["zhuangzi-c1","zhuangzi-c2","zhuangzi-c3"],"life_tags":[{"tag":"著庄子","tier":"primary"},{"tag":"论逍遥游","tier":"primary"},{"tag":"喻庄周梦蝶","tier":"primary"},{"tag":"喻庖丁解牛","tier":"primary"}],"voice_profile":{"notes":"汪洋恣肆、多用寓言；想象瑰奇、不拘绳墨；超然物外、好为相对之论；幽默而深刻"},"references":[{"ref_id":"zhuangzi-s1","title":"《庄子》（内篇）","locator":"齐物论(齐物/庄周梦蝶)、逍遥游(逍遥/无用)、养生主(庖丁解牛)、人间世(散木)","source_tier":"primary","supports_models":["齐物泯除分别","无用之用","因循自然","逍遥超脱","物化换视角"],"supports_cases":["zhuangzi-c1","zhuangzi-c2","zhuangzi-c3"],"note":"一手·内篇多庄子本人（思想确证；寓言非史实）"},{"ref_id":"zhuangzi-s2","title":"《庄子》（外篇、杂篇）","locator":"进一步阐发齐物/因循/无用等","source_tier":"secondary","supports_models":["因循自然","无用之用"],"note":"外杂篇多后学所作→归属存疑、仅作思想旁证"},{"ref_id":"zhuangzi-s3","title":"《史记·老子韩非列传》（庄子部分）","locator":"庄子生平","source_tier":"secondary","supports_models":["逍遥超脱"],"note":"后世史传，生平甚简"}],"material_type":"textual","reasoning_skeleton":{"signature":"打破非此即彼的绝对分别、看到是非大小的相对性、跳出二元对立(齐物)；重估有用/无用、看似无用可能因无用而保全或有大用(无用之用)；顺应事物结构与纹理使力、游刃有余(因循自然)；把心从对外物的执着中解放、保持精神自由(逍遥)；视角身份流动可换、换更大的参照框架看得失(物化)","steps":[{"invoke":"齐物泯除分别","action":"你陷在''非此即彼''里吗？是非大小是绝对的、还是随立场而变的相对？换个参照会怎样？"},{"invoke":"物化换视角","action":"你被单一视角困住了吗？把眼前的得失换一个更大的参照框架看，它还那么重吗？"},{"invoke":"无用之用","action":"你是不是被单一的''有用''标准绑架了？那个看似''无用''的，会不会恰恰因此保全、或有大用？"},{"invoke":"因循自然","action":"你在蛮力强加、处处碰壁吗？能不能顺着事物的''纹理''使力、找到游刃有余的path？"},{"invoke":"逍遥超脱","action":"你被外在的得失/名利/标准捆住了吗？能不能把心从对外物的执着中解放出来？"}],"contrast":"与老子不同(关键差异·同为道家)：**老子重''无为/辩证/守弱/知止''、更偏治理与处世的实践智慧**；**庄子重''齐物/逍遥/相对/物化''、是个人精神的超脱与自由、相对主义**——老子是处世辩证、庄子是精神逍遥(见老子卡)。与马可奥勒留尤须分(都谈超脱外物)：奥勒留''控制二分''是理性区分可控不可控、积极尽责；庄子''齐物''是消解是非分别、相对主义地逍遥——奥勒留是理性区分、庄子是消解分别(见马可奥勒留卡)。与孔子/王阳明区分：孔子入世伦理秩序、王阳明知行心学(积极有为)；庄子是齐物逍遥(超脱相对)。【射程/盲区·〔慎〕】庄子在''破除执念、转换视角、重估价值、顺势省力''极有洞察，但①〔慎〕《庄子》外杂篇多后学所作、未必尽出庄子本人(内篇较可信)、归属须分内外篇谨慎；②齐物/相对主义易被误用为''是非不分、消极虚无''；③逍遥超脱在需积极入世、承担责任、解决现实问题时可能流于逃避；④其智慧多为寓言隐喻、提供视角转换而非可操作步骤、易流于玄虚。适用修身自省/认知偏误与理性决策/价值与伦理/人生抉择；不适用竞争博弈/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"zhuangzi-c1","note":"用户''处理复杂的事处处碰壁、用蛮力硬刚''时，以庖丁解牛类比：庖丁解牛十九年刀刃如新、因其''依乎天理、批大郤、导大窾''——顺着牛体本身的结构与缝隙下刀、游刃有余，而非蛮力砍骨（庖丁解牛为《庄子·养生主》内篇寓言、文本确证；惟系寓言非史实事件、historicity 存疑、取其义理）"},{"source":"case","case_id":"zhuangzi-c3","note":"用户''被眼前一时的得失/身份困死、钻牛角尖''时，以庄周梦蝶类比：庄子梦为蝴蝶、醒后不知是周梦蝶还是蝶梦周——视角与身份本是流动可转换的，把眼前的得失换一个更大的参照看、可能只是一种''物化''转化（庄周梦蝶为《庄子·齐物论》内篇寓言、文本确证；系寓言非史实、historicity 存疑）"}]},"further_reading":[{"title":"《庄子》（内篇为主）","why":"齐物论/逍遥游/养生主等内篇是齐物/逍遥/因循自然的一手出处（内篇多庄子本人、外杂篇后学）","type":"原典"},{"title":"《史记·老子韩非列传》（庄子部分）","why":"庄子生平的传世记载（甚简）","type":"史料"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/zhuangzi.png","avatar_thumb":"/advisors/portraits/zhuangzi.png","domain":"哲学","person_id":"P-zhuangzi","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '1d4d5e683b035595551cc04dffd26538537cbea16f28f7d5d6f41efeae0430ce', 107, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('zhugeliang', 'P-zhugeliang', '诸葛亮', 'governance', '诸葛亮 · 战略治理思维框架卡', '东汉末—三国（181—234）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'legendary', '隆中对式顶层战略 · 联弱抗强', '/advisors/portraits/zhugeliang.png', '/advisors/portraits/zhugeliang.png', 5, 0, '{"schema_version":1,"card_id":"zhugeliang","name":"诸葛亮","title":"诸葛亮 · 战略治理思维框架卡","era":"东汉末—三国（181—234）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"隆中对式顶层战略","definition":"一无所有时即给出多阶段蓝图：先取何地、联谁抗谁、内修什么、什么条件才进下一步——预先承诺的条件式路线图","source":"《三国志·诸葛亮传》载隆中对全文；《前出师表》\"三顾\"互证","source_tier":"secondary","mechanism":"输入=一个长期目标（哪怕此刻一无所有）→ 处理=倒推出多阶段路线（先取何地→联谁抗谁→内修什么→何条件进下一步）→ 输出=带触发条件的多阶段蓝图","trigger":"起步阶段、资源稀缺、需要一张能装下机会的总框架时","modern_transfer":"做战略前先回答''终局是什么、分几步、每步靠什么、什么条件才进下一步''；创业最怕的不是没机会，是没有装机会的框架","architecture":{"type":"flow","components":["定终局","取根基","结盟与内修","触发条件","进下一阶段"]},"strategy_card_image":"kb-assets/zhugeliang/model-1.png"},{"name":"联弱抗强","definition":"联合次强共抗最强，绝不让两弱被逐个击破；比拼的是力量结构而非绝对实力","source":"《三国志》隆中对\"外结好孙权\"；亮使吴促成孙刘联盟之实践","source_tier":"secondary","mechanism":"输入=多方力量格局 → 处理=识别最强者，联合次强结成结构性制衡，绝不让两弱被逐个击破 → 输出=改变力量结构而非拼绝对实力的方案","trigger":"面对一个绝对强者、正面硬刚等于自杀时","modern_transfer":"市场有绝对老大时，正面硬刚往往是自杀；联合老二老三、改变力量结构，才是弱者的活路","architecture":{"type":"matrix","components":["识别最强","联合次强","阻止各个击破","结构性制衡"]},"strategy_card_image":"kb-assets/zhugeliang/model-2.png"},{"name":"攻心为上","definition":"治理优于征服；目标是不必反复驻军的持久稳定，宁费周折换真心归附，优化长期稳态而非眼前战果","source":"《三国志·马谡传》裴注引《襄阳记》\"攻心为上，攻城为下\"；南征史载","source_tier":"secondary","mechanism":"输入=一个需要制服的对象 → 处理=权衡''征服''与''归附''的长期成本，宁费周折换真心 → 输出=优化长期稳态（不必反复驻军）而非眼前战果的方案","trigger":"当''打赢''会留下一个长期记恨、伺机反扑的对手时","modern_transfer":"当赢会制造一个长期记恨、伺机反扑的对手（被压服的合伙人、被碾过的下属），攻城不如攻心——争取真买入比拿下一城更省后患","architecture":{"type":"flow","components":["评征服代价","评归附收益","取长期稳态","攻心优先"]},"strategy_card_image":"kb-assets/zhugeliang/model-3.png"},{"name":"法治严明","definition":"赏罚必信、执法不避亲贵，且规则约束到自己与最亲近之人才立得住；向上追责反而立信","source":"《三国志·诸葛亮传》斩马谡、自贬三等及陈寿评\"用心平而劝戒明\"","source_tier":"secondary","mechanism":"输入=一次违规（哪怕涉及亲信或自己）→ 处理=赏罚必信、执法不避亲贵，并向上追究领导者本人之责 → 输出=规则约束到自己与最亲近之人、由此立信","trigger":"规则第一次被核心人物或自己触犯时","modern_transfer":"规则若不能约束领导者本人和亲信，就约束不了任何人；向上追责（而非只罚下面）最立信","architecture":{"type":"flow","components":["违规发生","赏罚必信","不避亲贵","向上追责","规则立信"]},"strategy_card_image":"kb-assets/zhugeliang/model-4.png"},{"name":"谨慎稳健不弄险","definition":"用兵以稳为本步步为营，明拒奇险之计；治戎为长奇谋为短——既是其长也是其短","source":"《三国志》陈寿评\"治戎为长，奇谋为短\"；《魏延传》注引《魏略》拒子午谷","source_tier":"secondary","mechanism":"输入=一个有高风险高回报奇招的局面 → 处理=以稳为本步步为营，评估失败的不可逆性，明拒过险之计 → 输出=低方差、可控但可能错失奇胜的稳健路线","trigger":"面对''要不要弄险博一把''、尤其事关全局存亡时","modern_transfer":"稳健、低方差的打法最适合守住一个脆弱的局面；但若你本就是结构弱势的一方，永不弄险可能等于''选择慢性失败''——既是其长也是其短","architecture":{"type":"flow","components":["识别奇险之计","评失败可逆性","步步为营","拒过险","求稳"]},"strategy_card_image":"kb-assets/zhugeliang/model-5.png"}],"decision_principles":["先内修政理、再图外攻：根基稳固优先于扩张（隆中对，B）","用人唯才、执法不避亲贵、赏罚必信（《三国志》陈寿评，B）","事关全局者宁稳勿险（拒子午谷奇谋，B；亦其争议所在）","亲历亲核、以身作则（《三国志》注引，B；优点亦是其致命盲区）","得人心者得长治：攻城不如攻心（南征''攻心为上''，B）"],"inquiry_questions":["你有''隆中对''吗？能一次说清终局、分几步、每步靠什么、什么条件才进下一步？","这件事要的是打赢，还是长治久安？赢了却留个长期反抗你的对手，划算吗？","这盘棋谁最强？你是不是在硬碰它？能不能联合次强做结构性制衡？","你的规则，约束得了你自己和你最亲的人吗？","你现在该求稳还是该弄险？你输得起、耗得起，还是不赌就只能慢慢输？"],"value_priorities":["兴复汉室的使命/正统 ＞ 一时一地的利害得失（使命可驱至\"知其不可而为之\"——是其精神，也是其战略困境（与孙子\"非利不动\"相反））","长治久安、根基稳固 ＞ 速胜、冒险扩张（内修政理优先于外攻）","制度法治与公平 ＞ 人情亲疏（斩马谡、自贬三等）","确定性、可控 ＞ 高回报高风险的赌（拒子午谷奇谋）"],"blind_spots":["事必躬亲、不善授权：罚二十以上皆亲览，司马懿断''食少事烦，其能久乎''；积劳早逝、梯队未成，身后蜀汉人才断层（《三国志》注引，B）","过度谨慎、错失奇险：结构弱势方一味求稳可能等于保证缓慢失败；拒子午谷或放弃了唯一现实胜机（《魏延传》注引及后世千年之辩，B）","以攻代守的战略困境：以小国之力屡次北伐消耗强魏，近乎''知其不可而为之''，使命承诺压过冷算账（《三国志》北伐记载，B）","用人偶有失察：违众拔马谡守街亭，而刘备临终明告''马谡言过其实，不可大用''（《三国志》，B）"],"applicable_domains":["战略","治理决策","组织管理","领导力","长期规划","危机应对"],"match_tags":["战略","治理决策","组织管理","长期规划","制度法治思维","攻心共识","长期主义","古代东亚"],"linked_cases":["zhugeliang-c1","zhugeliang-c2","zhugeliang-c3","zhugeliang-c4","zhugeliang-c5","zhugeliang-c6","zhugeliang-c7"],"life_tags":[{"tag":"隆中对策","tier":"secondary"},{"tag":"作出师表","tier":"primary"},{"tag":"五次北伐","tier":"secondary"},{"tag":"平定南中","tier":"secondary"}],"voice_profile":{"notes":"恳切庄重；条理缜密；以理服人不煽情；忠悃溢于言表"},"references":[{"ref_id":"zhugeliang-s1","title":"《三国志·蜀书·诸葛亮传》（隆中对）","locator":"隆中对全文段 \"自董卓已来……则霸业可成，汉室可兴矣\"","source_tier":"secondary","supports_models":["隆中对式顶层战略","联弱抗强"],"supports_cases":["zhugeliang-c1","zhugeliang-c2"],"note":"正史，最高史料权重；隆中对同时支撑顶层战略与联弱抗强二模型及C1/C2"},{"ref_id":"zhugeliang-s2","title":"《前出师表》","locator":"\"臣本布衣……三顾臣于草庐之中\" 段","source_tier":"primary","supports_models":["隆中对式顶层战略"],"supports_cases":["zhugeliang-c1"],"note":"诸葛亮本人文字，一手；与S1互证\"三顾\"与隆中对"},{"ref_id":"zhugeliang-s3","title":"《三国志·蜀书·马良(马谡)传》裴松之注引《襄阳记》","locator":"\"用兵之道，攻心为上，攻城为下；心战为上，兵战为下\" 句","source_tier":"secondary","supports_models":["攻心为上"],"supports_cases":["zhugeliang-c3"],"note":"正史裴注；攻心为上原始出处"},{"ref_id":"zhugeliang-s4","title":"《三国志·蜀书·诸葛亮传》（南征 / 斩马谡 / 陈寿总评）","locator":"\"三年春，亮率众南征，其秋悉平\"；\"戮谡以谢众……请自贬三等\"；陈寿评 \"刑政虽峻而无怨\" \"治戎为长，奇谋为短\"","source_tier":"secondary","supports_models":["法治严明","谨慎稳健不弄险","攻心为上"],"supports_cases":["zhugeliang-c3","zhugeliang-c4"],"note":"正史；本传同段落支撑法治、稳健、攻心三模型及C3/C4"},{"ref_id":"zhugeliang-s5","title":"《三国志·蜀书·魏延传》注引《魏略》","locator":"\"延每随亮出，辄欲请兵万人……亮制而不许\"（子午谷之议）","source_tier":"secondary","supports_models":["谨慎稳健不弄险"],"supports_cases":["zhugeliang-c5"],"note":"正史裴注；拒子午谷为稳健模型与C5的核心依据。historicity=存疑（争议在\"若行结果\"）"},{"ref_id":"zhugeliang-s6","title":"《汉晋春秋》《华阳国志·南中志》（七擒七纵）","locator":"七纵七擒孟获记载","source_tier":"tertiary","supports_cases":["zhugeliang-c3"],"note":"次级史料/后世放大；仅作C3\"七擒\"细节的存疑出处，南征主体史实另见S4"},{"ref_id":"zhugeliang-s7","title":"《三国演义》第95回 + 裴松之注引郭冲《条亮五事》","locator":"演义第95回空城计；郭冲第三事及裴注驳斥","source_tier":"tertiary","supports_cases":["zhugeliang-c6"],"note":"演义/已被裴注驳斥之传说；仅支撑C6演义对照条目，不支撑任何core_model"},{"ref_id":"zhugeliang-s8","title":"《三国演义》第46回 + 《三国志·吴主传》注引《魏略》","locator":"演义第46回草船借箭；《魏略》孙权濡须受箭事","source_tier":"tertiary","supports_cases":["zhugeliang-c7"],"note":"演义+张冠李戴；仅支撑C7演义对照条目，不支撑任何core_model"}],"material_type":"legendary","reasoning_skeleton":{"signature":"终局先行、根基优先——宁稳勿险，制度先约束自己，赢人心胜于赢城池","steps":[{"invoke":"隆中对式顶层战略","action":"先画出终局与多阶段路线：先取什么根基、什么条件才进下一步，不追零散机会"},{"invoke":"联弱抗强","action":"看清谁最强，联合次强做结构性制衡，绝不正面硬刚最强者"},{"invoke":"攻心为上","action":"凡涉及制服对象，先问要的是打赢还是长治久安，优先争取真心归附"},{"invoke":"法治严明","action":"立规则并让它约束到自己与最亲信，违规向上追责以立信"},{"invoke":"谨慎稳健不弄险","action":"面对高风险奇招，以稳为本评估不可逆性，事关全局者宁稳勿险"}],"contrast":"与孙子相反：同样面对''弱势方该不该弄险''，孙子''非利不动''、条件不足即不动；诸葛亮在使命驱动下可''知其不可而为之''，以小国之力屡次北伐——使命承诺压过冷算账（见孙子卡）。注意：诸葛亮自身风格是第5步''求稳''，演义里的''空城计/草船借箭''式弄险恰与其真实风格相反，不入骨架。"},"persona_anchor":{"primary":[{"source":"case","case_id":"zhugeliang-c1","note":"用户''我刚起步、一无所有，该追机会还是先定战略''时，以隆中对类比：一无所有时即给出终局先行、条件触发的多阶段蓝图（正史/确证，《三国志》载全文+《出师表》互证）"},{"source":"case","case_id":"zhugeliang-c4","note":"用户''亲信/自己犯了错，规则要不要照办''时，以斩马谡·自贬三等类比：规则约束到爱将与自己才立得住，向上追责反而立信（正史/确证）"}]},"further_reading":[{"title":"陈寿《三国志·蜀书·诸葛亮传》（含裴松之注）","why":"正史的诸葛亮在此，连陈寿''治戎为长，奇谋为短''的总评都在；裴注更逐条辨正传说","type":"正史"},{"title":"诸葛亮《前出师表》《后出师表》","why":"他本人的文字，''三顾''''鞠躬尽瘁''的第一手出处，最见其恳切与战略困境","type":"original"},{"title":"易中天《品三国》","why":"通俗梳理正史与《三国演义》的出入，帮用户把''神算诸葛''还原成真实的谨慎治理者","type":"解读"}],"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/zhugeliang.png","avatar_thumb":"/advisors/portraits/zhugeliang.png","domain":"治理","person_id":"P-zhugeliang","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', 'cce8655b9599279ba90336bbf5735955cb465c00a3b02fbe418d46f150f8868e', 108, '2026-07-19T09:41:47.055Z');
INSERT INTO advisors (card_id, person_id, name, domain_id, title, era, language, bundle_status, source_status, knowledge_qc_status, living_status, material_type, insight, avatar_url, portrait_url, strategy_card_expected, strategy_card_available, profile_json, content_sha256, display_order, imported_at) VALUES ('zhuxi', 'P-zhuxi', '朱熹', 'philosophy', '朱熹 · 格物穷理与理一分殊思维框架卡', '南宋（1130—1200）', 'zh-CN', 'published', 'in_review', 'pending', 'deceased', 'textual', '格物致知 · 理一分殊', '/advisors/portraits/zhuxi.png', '/advisors/portraits/zhuxi.png', 5, 0, '{"schema_version":1,"card_id":"zhuxi","name":"朱熹","title":"朱熹 · 格物穷理与理一分殊思维框架卡","era":"南宋（1130—1200）","language":"zh-CN","status":"published","living_status":"deceased","core_models":[{"name":"格物致知","definition":"一件一件具体事物地去探究它的\"理\"（格物），不断积累，直到某天豁然贯通——而非空想或顿悟","source":"朱熹《大学章句》补传","source_tier":"primary","mechanism":"输入=空想或指望顿悟 → 处理=一件一件具体事物地探究它的''理''(格物)、不断积累 → 输出=由积累而豁然贯通的真知(格物致知)","trigger":"想真正弄懂一个领域时","modern_transfer":"想真正懂一个领域、就一件一件具体事物地去探究它的道理(格物)、不断积累、直到某天豁然贯通——而非空想或指望顿悟(朱熹格物致知)","architecture":{"type":"hierarchy","components":["别空想或指望顿悟","一件一件具体探究事物的理","不断积累","用力之久豁然贯通"]},"strategy_card_image":"kb-assets/zhuxi/model-1.png"},{"name":"理一分殊","definition":"万物各有各的具体道理（分殊），但又归于同一个根本的原理（理一）——既钻进具体、又把握根本","source":"朱熹理学","source_tier":"primary","mechanism":"输入=只见树木(陷在具体)或只见森林(空谈根本) → 处理=既钻进万物各自的具体之理(分殊)、又把握统摄全局的同一根本之理(理一) → 输出=具体与根本兼得(理一分殊)","trigger":"在''具体细节''与''统摄全局''间需兼顾时","modern_transfer":"万事万物各有各的具体道理(分殊)、但又归于同一个根本的原理(理一)——既要钻进具体、又要把握那个统摄全局的根本;别只见树木或只见森林(朱熹理一分殊)","architecture":{"type":"hierarchy","components":["别只见树木或只见森林","钻进万物各自的具体之理分殊","把握统摄全局的同一根本之理理一","具体与根本兼得"]},"strategy_card_image":"kb-assets/zhuxi/model-2.png"},{"name":"存天理去人欲","definition":"用\"正当的道理/公义（天理）\"去节制\"过度的私欲（人欲）\"，让欲望服从于更高的道理与节度","source":"朱熹《朱子语类》","source_tier":"primary","mechanism":"输入=放纵过度的私欲 → 处理=用''正当的道理/公义(天理)''去节制''过度的私欲(人欲)'' → 输出=欲望服从于更高的道理与节度","trigger":"面对私欲与公义/正道冲突时","modern_transfer":"用''正当的道理/公义(天理)''去节制''过度的私欲(人欲)''——不是禁绝一切欲望、而是让欲望服从于更高的道理与节度(朱熹存天理去人欲)〔注意:勿误读为禁欲、朱熹反对的是''过度''之欲、见盲区〕","architecture":{"type":"flow","components":["别放纵过度的私欲","用正当的道理公义天理","节制过度的私欲人欲","欲望服从于更高的道理与节度"]},"strategy_card_image":"kb-assets/zhuxi/model-3.png"},{"name":"读书穷理之法","definition":"循序渐进（由易到难）、熟读精思（读透想透）、虚心涵泳（放下成见沉浸体会）——系统的治学方法","source":"《朱子读书法》","source_tier":"primary","mechanism":"输入=乱读、囫囵吞枣、带成见 → 处理=循序渐进、熟读精思、虚心涵泳的系统方法 → 输出=有方法的治学(读书法)","trigger":"要系统学一门东西时","modern_transfer":"治学读书要有方法:循序渐进(由易到难、打牢基础)、熟读精思(读透想透、不囫囵吞枣)、虚心涵泳(放下成见、沉浸体会)——系统的方法胜过乱读(朱熹读书法)","architecture":{"type":"flow","components":["别乱读囫囵吞枣带成见","循序渐进由易到难","熟读精思读透想透","虚心涵泳放下成见"]},"strategy_card_image":"kb-assets/zhuxi/model-4.png"},{"name":"居敬穷理","definition":"一边格物穷理（向外求知）、一边以\"敬\"（专注、收敛、不放纵）涵养内心（向内修养），内外并进","source":"朱熹\"居敬穷理\"","source_tier":"primary","mechanism":"输入=只向外求知或只向内静坐、偏废 → 处理=一边格物穷理(向外)、一边以''敬''涵养内心(向内)、内外并进 → 输出=知与养相济(居敬穷理)","trigger":"求知与修养如何并进时","modern_transfer":"一边格物穷理(向外求知)、一边以''敬''(专注、收敛、不散漫放纵)涵养内心(向内修养)——内外并进、知与养相济、别偏废(朱熹居敬穷理)","architecture":{"type":"flow","components":["别只向外求知或只向内静坐","一边格物穷理向外求知","一边以敬涵养内心向内修养","内外并进知与养相济"]},"strategy_card_image":"kb-assets/zhuxi/model-5.png"}],"decision_principles":["一件一件具体探究事物的理、靠积累直到豁然贯通，而非空想顿悟","既钻进万物各自的具体之理，又把握统摄全局的根本之理","用正当的道理节制过度的私欲（非禁欲）","治学要有方法：循序渐进、熟读精思、虚心涵泳","向外格物与向内主敬并进，知与养相济"],"inquiry_questions":["你是空想/指望顿悟、还是一件一件具体地探究事物的理、靠积累贯通？","你是只陷在具体、还是也把握了那个统摄全局的根本之理？","这件事里，是过度的私欲在主导、还是正当的道理与节度在主导？","你学东西是乱读囫囵、还是循序渐进、熟读精思、虚心涵泳？","你是只向外求知或只向内静坐、还是内外并进、知与养相济？"],"value_priorities":["格物积累而贯通 ＞ 空想或指望顿悟（用力之久、一旦豁然贯通）","具体与根本兼得 ＞ 只见树木或只见森林（理一分殊）","道理节制的欲望 ＞ 放纵过度的私欲（存天理去人欲（非禁欲））"],"blind_spots":["〔注意〕''存天理去人欲''后世常被误读、僵化为压抑正当欲望与情感的禁欲教条——朱熹本意是节制''过度''之欲、非禁绝一切欲望（学术，B，客观标注）。","格物致知''即物穷理''被王阳明批评为''向外驰求、析心与理为二''，可能流于支离、忘了切己的体认（学术·心学批评，B）。","其理学体系庞大严密，后世易流于教条与僵化、束缚思想（学术史，B）。","偏重读书穷理与道德涵养，对实务/技术/事功的探究相对其体系是次要的（原理推断，B）。"],"applicable_domains":["认知偏误与理性决策","修身自省","长期规划"],"match_tags":["认知偏误与理性决策","修身自省","长期规划","系统分析","批判思辨","务实渐进","古代东亚"],"linked_cases":["zhuxi-c1","zhuxi-c2","zhuxi-c3","zhuxi-c4"],"life_tags":[{"tag":"集理学大成","tier":"secondary"},{"tag":"注四书章句","tier":"primary"},{"tag":"创书院学规","tier":"secondary"},{"tag":"倡格物致知","tier":"primary"}],"voice_profile":{"notes":"严谨缜密、体系宏大；重积累与方法；向外格物；持守道德"},"references":[{"ref_id":"zhuxi-s1","title":"朱熹《四书章句集注》《朱子语类》《朱子读书法》","locator":"格物致知、理一分殊、存天理去人欲、读书法、居敬穷理","source_tier":"primary","supports_models":["格物致知","理一分殊","存天理去人欲","读书穷理之法","居敬穷理"],"supports_cases":["zhuxi-c1","zhuxi-c2","zhuxi-c3","zhuxi-c4"],"note":"一手·著述/语录"},{"ref_id":"zhuxi-s2","title":"宋明理学研究","locator":"程朱理学、朱陆之辨","source_tier":"secondary","supports_models":["格物致知","存天理去人欲"],"note":"二手·研究"}],"material_type":"textual","reasoning_skeleton":{"signature":"一件一件具体探究事物的理、积累到豁然贯通(格物致知)；既钻进万物各自的理又把握统摄全局的根本(理一分殊)；用正当的道理节制过度的私欲(存天理去人欲)；循序渐进熟读精思虚心涵泳(读书穷理之法)；一边向外格物一边以敬向内涵养(居敬穷理)","steps":[{"invoke":"格物致知","action":"你是空想/指望顿悟、还是一件一件具体地探究事物的理、靠积累贯通？"},{"invoke":"理一分殊","action":"你是只陷在具体、还是也把握了那个统摄全局的根本之理？"},{"invoke":"存天理去人欲","action":"这件事里，是过度的私欲在主导、还是正当的道理与节度在主导？"},{"invoke":"读书穷理之法","action":"你学东西是乱读囫囵、还是循序渐进、熟读精思、虚心涵泳？"},{"invoke":"居敬穷理","action":"你是只向外求知或只向内静坐、还是内外并进、知与养相济？"}],"contrast":"与王阳明不同(关键差异·理学与心学的核心对立)：**朱熹主''理在物''、''格物致知''——理在万事万物中、要一件件向外探究积累(向外格物穷理)**；**王阳明主''心即理''、''致良知、知行合一''——理就在本心、要向内致良知(向内求理)**——朱熹向外格物、王阳明向内致良知;王阳明正是批评朱熹''格物''向外驰求、析心与理为二(见王阳明卡)。与孔孟不同：孔孟重''仁/性善/仁政''的直接道德;朱熹把儒学构建成''理-气-性-格物''的庞大形上学体系(见孔子/孟子卡)。【射程/盲区】朱熹之道在''格物致知、理一分殊、存天理去人欲、读书法、居敬穷理''极有力(尤其系统治学与道德修养)，但①〔注意〕''存天理去人欲''后世常被误读僵化为禁欲教条、朱熹本意是节制''过度''之欲非禁绝一切欲望;②''即物穷理''被王阳明批为向外驰求、可能流于支离、忘了切己体认;③其理学体系庞大、后世易流于教条僵化束缚思想;④偏重读书穷理与道德涵养、对实务/技术/事功相对次要。适用认知偏误与理性决策/修身自省/长期规划;不适用竞争博弈/投资。"},"persona_anchor":{"primary":[{"source":"case","case_id":"zhuxi-c1","note":"用户''想真正弄懂一个领域、却总想走捷径、靠空想或指望灵光一现''时，以朱熹格物致知类比：''即凡天下之物、莫不因其已知之理而益穷之''——一件一件具体事物地去探究它的道理、不断积累、''用力之久、而一旦豁然贯通'';真正的通透是踏实格物积累出来的、不是顿悟出来的（格物致知为朱熹《大学章句》补传所载→确证）"},{"source":"case","case_id":"zhuxi-c4","note":"用户''读书学习抓不住要领、囫囵吞枣、效率低''时，以朱熹读书法类比：循序渐进(由易到难打牢基础)、熟读精思(读透想透)、虚心涵泳(放下成见沉浸体会)——治学读书要有系统的方法、胜过乱读（朱熹读书法为《朱子读书法》所载→确证）"}]},"further_reading":[{"title":"朱熹《四书章句集注》《朱子语类》","why":"格物致知、理一分殊、存天理去人欲、读书法、居敬穷理的一手出处（A）","type":"original"},{"title":"宋明理学研究","why":"对程朱理学及其与陆王心学之辨的学术分析（B）","type":"研究"}],"self_check":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"qc":{"blind_recognition":"pending","counter_example":"pending","differentiation":"pending","traceability":"pending"},"avatar":"/advisors/portraits/zhuxi.png","avatar_thumb":"/advisors/portraits/zhuxi.png","domain":"哲学","person_id":"P-zhuxi","asset_display_mode":"portrait_crop","source_review_status":"in_review","knowledge_qc_status":"pending"}', '3c6ddfa7ff91b4e003f863467f59d3f9675017bc169d439db8b2eb785a6b6871', 109, '2026-07-19T09:41:47.055Z');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('orwell-c1', 'orwell', '写《政治与英语》·立清晰写作规则（1946）', '战时与战后政治语言充斥含糊抽象的大词、委婉语，用以掩盖暴行（如"绥靖""转移人口"），思想随之含混。', '奥威尔写《政治与英语》剖析这种语言堕落、指出含糊语言与含混思想互为因果，并提出一套"减法"写作规则（删词、短词、具体、避陈词）。', '该文成英语写作与政治语言批判的经典，"清晰语言抵抗操纵"的理念影响深远。', '被漂亮的大词与套话绕晕、或想把事说清却越说越虚时——做减法、用具体清晰直白的语言，是抵抗操纵、也是不自欺。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"orwell-c1","status":"published","title_period":"写《政治与英语》·立清晰写作规则（1946）","dilemma_constraints":"战时与战后政治语言充斥含糊抽象的大词、委婉语，用以掩盖暴行（如\"绥靖\"\"转移人口\"），思想随之含混。","key_judgment":"奥威尔写《政治与英语》剖析这种语言堕落、指出含糊语言与含混思想互为因果，并提出一套\"减法\"写作规则（删词、短词、具体、避陈词）。","model_invoked":["清晰语言对抗操纵"],"outcome":"该文成英语写作与政治语言批判的经典，\"清晰语言抵抗操纵\"的理念影响深远。","transferable_lesson":"被漂亮的大词与套话绕晕、或想把事说清却越说越虚时——做减法、用具体清晰直白的语言，是抵抗操纵、也是不自欺。","source_tier":"primary","source_note":"《政治与英语》为奥威尔1946名篇→确证（一手随笔A）。","historicity":"confirmed","linked_cards":["orwell"],"tags":["表达说服","认知偏误与理性决策"],"advisor_id":"orwell"}', 'dad08af0e88025bf5154a4ae6c5091448de553536da8a07941162881d725c752');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('orwell-c2', 'orwell', '写《一九八四》·具象化极权（1949）', '「极权主义」是抽象概念，泛泛警告难以让人真正警醒、当回事。', '奥威尔用老大哥、电幕、新话、双重思想、"2+2=5"等一系列具体可感的形象，把极权的运作变成一个让人身临其境的故事。', '《一九八四》成20世纪最有影响的反乌托邦小说，"老大哥""新话"等成通用语汇。', '想让抽象的危险真正警醒人，把它用一个具体可感的场景与形象讲出来——让人"看见"，比泛泛说理有力得多。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"orwell-c2","status":"published","title_period":"写《一九八四》·具象化极权（1949）","dilemma_constraints":"「极权主义」是抽象概念，泛泛警告难以让人真正警醒、当回事。","key_judgment":"奥威尔用老大哥、电幕、新话、双重思想、\"2+2=5\"等一系列具体可感的形象，把极权的运作变成一个让人身临其境的故事。","model_invoked":["具象化抽象"],"outcome":"《一九八四》成20世纪最有影响的反乌托邦小说，\"老大哥\"\"新话\"等成通用语汇。","transferable_lesson":"想让抽象的危险真正警醒人，把它用一个具体可感的场景与形象讲出来——让人\"看见\"，比泛泛说理有力得多。","source_tier":"primary","source_note":"《一九八四》为奥威尔1949代表作→确证（一手作品A）。","historicity":"confirmed","linked_cards":["orwell"],"tags":["表达说服","创作表达"],"advisor_id":"orwell"}', 'eb539d4317764d3fa3b75469ee59f260347f95f144b50dd2e2e0dc936956dd25');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('orwell-c3', 'orwell', '写《动物农场》·对自己阵营的诚实（1945）', '奥威尔本人是社会主义者，但目睹斯大林主义对革命理想的背叛；批判它会得罪左翼同道、且时值英苏同盟、出版屡遭阻。', '他仍坚持写《动物农场》、以寓言讽刺斯大林主义对革命的背叛——对自己所属阵营也保持诚实、看见什么说什么。', '《动物农场》成讽刺极权的经典；其"对自己人也诚实"的智识诚实成为其精神标志。', '智识诚实最难的一关，是对自己所属的阵营也说真话——不因立场方便而回避或粉饰令人不适的真相。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"orwell-c3","status":"published","title_period":"写《动物农场》·对自己阵营的诚实（1945）","dilemma_constraints":"奥威尔本人是社会主义者，但目睹斯大林主义对革命理想的背叛；批判它会得罪左翼同道、且时值英苏同盟、出版屡遭阻。","key_judgment":"他仍坚持写《动物农场》、以寓言讽刺斯大林主义对革命的背叛——对自己所属阵营也保持诚实、看见什么说什么。","model_invoked":["诚实直面不适的真相"],"outcome":"《动物农场》成讽刺极权的经典；其\"对自己人也诚实\"的智识诚实成为其精神标志。","transferable_lesson":"智识诚实最难的一关，是对自己所属的阵营也说真话——不因立场方便而回避或粉饰令人不适的真相。","source_tier":"primary","source_note":"《动物农场》及奥威尔批判斯大林主义为确证（一手作品A）；出版受阻等细节史载。","historicity":"confirmed","linked_cards":["orwell"],"tags":["价值与伦理","表达说服"],"advisor_id":"orwell"}', '7cab591c07e5d917e25e8e89de4930fd071f197f838ffb8da5908b5b1a621fa6');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tolstoy-c1', 'tolstoy', '「心灵辩证法」·内心的流动（托尔斯泰作品）', '如何真实、深刻地刻画一个人的内心世界。', '托尔斯泰以"心灵辩证法"细致呈现人物思想与情感的流动、矛盾、转变（如安娜的挣扎、聂赫留朵夫的觉醒），而非静态标签。', '「心灵辩证法」成为现实主义心理描写的高峰。', '深入内心、细致呈现思想情感如何流动、矛盾、转变的过程，而非只给静态的结论。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"tolstoy-c1","status":"published","title_period":"「心灵辩证法」·内心的流动（托尔斯泰作品）","dilemma_constraints":"如何真实、深刻地刻画一个人的内心世界。","key_judgment":"托尔斯泰以\"心灵辩证法\"细致呈现人物思想与情感的流动、矛盾、转变（如安娜的挣扎、聂赫留朵夫的觉醒），而非静态标签。","model_invoked":["心灵辩证法"],"outcome":"「心灵辩证法」成为现实主义心理描写的高峰。","transferable_lesson":"深入内心、细致呈现思想情感如何流动、矛盾、转变的过程，而非只给静态的结论。","source_tier":"primary","source_note":"「心灵辩证法」为车尔尼雪夫斯基对托尔斯泰的评价、其作品特征→确证（一手作品/二手评论A/B）。","historicity":"confirmed","linked_cards":["tolstoy"],"tags":["创作","修身自省"],"advisor_id":"tolstoy"}', '0299c622ede9ce7b2efbc1b0f01a476ae2a9836a6b98fb6c87b044e6fc26237b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tolstoy-c2', 'tolstoy', '《战争与和平》·史诗全景（1869）', '如何同时呈现个体命运与宏大的历史。', '托尔斯泰在《战争与和平》中把众多个体的命运编织进拿破仑战争的历史全景，让个体与时代相互映照。', '《战争与和平》成为世界文学史诗的典范。', '把无数个体的命运编织进宏大的历史/社会全景，让个体与时代相互映照——既见树木、又见森林。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"tolstoy-c2","status":"published","title_period":"《战争与和平》·史诗全景（1869）","dilemma_constraints":"如何同时呈现个体命运与宏大的历史。","key_judgment":"托尔斯泰在《战争与和平》中把众多个体的命运编织进拿破仑战争的历史全景，让个体与时代相互映照。","model_invoked":["史诗全景"],"outcome":"《战争与和平》成为世界文学史诗的典范。","transferable_lesson":"把无数个体的命运编织进宏大的历史/社会全景，让个体与时代相互映照——既见树木、又见森林。","source_tier":"primary","source_note":"《战争与和平》的史诗结构为其作品→确证（一手A）。","historicity":"confirmed","linked_cards":["tolstoy"],"tags":["创作"],"advisor_id":"tolstoy"}', '244e97a0fdfba460f6d80b3c9722f8e133d0db49e7486e517f6cb10781a4a4ec');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tolstoy-c3', 'tolstoy', '《忏悔录》与道德追问·道德与意义的追问（晚期）', '名利双收之后，托尔斯泰陷入对生命意义的深刻危机。', '托尔斯泰在《忏悔录》等中执着追问"人应该怎样活""什么是善""生命的意义"，为其作品与人生注入道德重量。', '托尔斯泰的道德追问深刻影响了后世（包括甘地等），但其道德主义后期也趋于极端。', '始终追问"对不对""什么是善""意义何在"，让工作有道德的重量与深度——但勿让道德说教压过本身。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"tolstoy-c3","status":"published","title_period":"《忏悔录》与道德追问·道德与意义的追问（晚期）","dilemma_constraints":"名利双收之后，托尔斯泰陷入对生命意义的深刻危机。","key_judgment":"托尔斯泰在《忏悔录》等中执着追问\"人应该怎样活\"\"什么是善\"\"生命的意义\"，为其作品与人生注入道德重量。","model_invoked":["道德与意义的追问"],"outcome":"托尔斯泰的道德追问深刻影响了后世（包括甘地等），但其道德主义后期也趋于极端。","transferable_lesson":"始终追问\"对不对\"\"什么是善\"\"意义何在\"，让工作有道德的重量与深度——但勿让道德说教压过本身。","source_tier":"primary","source_note":"托尔斯泰的道德追问为《忏悔录》及其思想→确证（一手A）。","historicity":"confirmed","linked_cards":["tolstoy"],"tags":["修身自省","价值与伦理"],"advisor_id":"tolstoy"}', '70b496dcabe9e7776162b088451062b7d666c5bc2a2cd1feb42160364bed5019');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tolstoy-c4', 'tolstoy', '日常与普通人的真实·平凡中的真实（《安娜·卡列尼娜》等）', '深刻的真实与人性，到哪里去发现。', '托尔斯泰以极其细致的笔触，在日常生活、普通人的喜怒哀乐中发现深刻的真实与人性。', '托尔斯泰的现实主义达到了对日常真实刻画的极高水平。', '在最平凡的日常细节、最普通的人身上发现深刻的真实与人性——伟大常藏在平凡里。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"tolstoy-c4","status":"published","title_period":"日常与普通人的真实·平凡中的真实（《安娜·卡列尼娜》等）","dilemma_constraints":"深刻的真实与人性，到哪里去发现。","key_judgment":"托尔斯泰以极其细致的笔触，在日常生活、普通人的喜怒哀乐中发现深刻的真实与人性。","model_invoked":["平凡中的真实"],"outcome":"托尔斯泰的现实主义达到了对日常真实刻画的极高水平。","transferable_lesson":"在最平凡的日常细节、最普通的人身上发现深刻的真实与人性——伟大常藏在平凡里。","source_tier":"primary","source_note":"托尔斯泰对日常真实的描写为其作品特征→确证（一手A）。","historicity":"confirmed","linked_cards":["tolstoy"],"tags":["创作","修身自省"],"advisor_id":"tolstoy"}', '0c1ed17e426e85f0606faddd25e2370b467d1e2bc89fa2d5968a74bb254993e3');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('caoxueqin-c1', 'caoxueqin', '「草蛇灰线，伏延千里」·伏笔结构（《红楼梦》）', '如何让一部宏大的作品前后呼应、浑然一体。', '曹雪芹在《红楼梦》中处处埋下伏笔（判词、谶语、细节），前后遥相照应，形成"草蛇灰线、伏延千里"的精密结构。', '《红楼梦》的精密结构成为中国小说艺术的高峰，经得起反复推敲。', '在前面埋下看似不起眼的伏笔、让它在后文遥相照应——使整体浑然一体、经得起推敲。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"caoxueqin-c1","status":"published","title_period":"「草蛇灰线，伏延千里」·伏笔结构（《红楼梦》）","dilemma_constraints":"如何让一部宏大的作品前后呼应、浑然一体。","key_judgment":"曹雪芹在《红楼梦》中处处埋下伏笔（判词、谶语、细节），前后遥相照应，形成\"草蛇灰线、伏延千里\"的精密结构。","model_invoked":["草蛇灰线伏延千里"],"outcome":"《红楼梦》的精密结构成为中国小说艺术的高峰，经得起反复推敲。","transferable_lesson":"在前面埋下看似不起眼的伏笔、让它在后文遥相照应——使整体浑然一体、经得起推敲。","source_tier":"primary","source_note":"草蛇灰线的伏笔结构为《红楼梦》→确证（一手A）。","historicity":"confirmed","linked_cards":["caoxueqin"],"tags":["创作"],"advisor_id":"caoxueqin"}', 'a377973316039ccba1bb09c418e88b35034eabcd070be04843d1cdb0dd62d069');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('caoxueqin-c2', 'caoxueqin', '「假作真时真亦假」·真假虚实的辩证（《红楼梦》）', '如何在虚构与写实之间表达更深的真实。', '曹雪芹以"假作真时真亦假，无为有处有还无"、太虚幻境等，在真与假、虚与实的交织中表达更深的真实。', '《红楼梦》的真假虚实辩证成为其哲学深度的体现。', '善用真与假、虚与实的交织——有时虚构/表象里藏着比写实更深的真实。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"caoxueqin-c2","status":"published","title_period":"「假作真时真亦假」·真假虚实的辩证（《红楼梦》）","dilemma_constraints":"如何在虚构与写实之间表达更深的真实。","key_judgment":"曹雪芹以\"假作真时真亦假，无为有处有还无\"、太虚幻境等，在真与假、虚与实的交织中表达更深的真实。","model_invoked":["真假虚实的辩证"],"outcome":"《红楼梦》的真假虚实辩证成为其哲学深度的体现。","transferable_lesson":"善用真与假、虚与实的交织——有时虚构/表象里藏着比写实更深的真实。","source_tier":"primary","source_note":"真假虚实为《红楼梦》→确证（一手A）。","historicity":"confirmed","linked_cards":["caoxueqin"],"tags":["创作"],"advisor_id":"caoxueqin"}', 'd4d670122c2e992a6a48c65e96a7283b698a132f28b13d97f3d4548822df4fa0');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('caoxueqin-c3', 'caoxueqin', '数百人物的群像·群像与个体命运（《红楼梦》）', '如何塑造一大群鲜活而不雷同的人物。', '曹雪芹塑造了数百个性格各异、栩栩如生的人物（黛玉、宝钗、王熙凤等），每个人的命运都与贾府的兴衰相连。', '《红楼梦》的人物群像成为中国文学塑造人物的典范。', '让每个人都有鲜明独特的个性、又让其命运与整体的命运相连——群像与整体共振。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"caoxueqin-c3","status":"published","title_period":"数百人物的群像·群像与个体命运（《红楼梦》）","dilemma_constraints":"如何塑造一大群鲜活而不雷同的人物。","key_judgment":"曹雪芹塑造了数百个性格各异、栩栩如生的人物（黛玉、宝钗、王熙凤等），每个人的命运都与贾府的兴衰相连。","model_invoked":["群像与个体命运"],"outcome":"《红楼梦》的人物群像成为中国文学塑造人物的典范。","transferable_lesson":"让每个人都有鲜明独特的个性、又让其命运与整体的命运相连——群像与整体共振。","source_tier":"primary","source_note":"人物群像为《红楼梦》→确证（一手A）。","historicity":"confirmed","linked_cards":["caoxueqin"],"tags":["创作"],"advisor_id":"caoxueqin"}', '63e8cf015486419267a0fa87de13f476ae5952647b978826a9ffaa60861c8117');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('caoxueqin-c4', 'caoxueqin', '贾府由盛转衰映照时代·以家族兴衰映照时代（《红楼梦》）', '如何让一个家族的故事承载时代的意义。', '曹雪芹通过贾府这一钟鸣鼎食之家的由盛转衰，折射出整个时代与社会的命运。', '《红楼梦》以家族映时代，成为一部"封建社会的百科全书"。', '通过一个小单位（家族/组织）的兴衰起落，折射更宏大的社会与时代——以一隅见全局。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"caoxueqin-c4","status":"published","title_period":"贾府由盛转衰映照时代·以家族兴衰映照时代（《红楼梦》）","dilemma_constraints":"如何让一个家族的故事承载时代的意义。","key_judgment":"曹雪芹通过贾府这一钟鸣鼎食之家的由盛转衰，折射出整个时代与社会的命运。","model_invoked":["以家族兴衰映照时代"],"outcome":"《红楼梦》以家族映时代，成为一部\"封建社会的百科全书\"。","transferable_lesson":"通过一个小单位（家族/组织）的兴衰起落，折射更宏大的社会与时代——以一隅见全局。","source_tier":"primary","source_note":"贾府映时代为《红楼梦》主题→确证（一手A）。","historicity":"confirmed","linked_cards":["caoxueqin"],"tags":["创作"],"advisor_id":"caoxueqin"}', 'f44967c81b9278a2649b2ef99654f75e1ea2c989c972ba6415c0b363c55ffa3d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hemingway-c1', 'hemingway', '「冰山理论」·省略的力量（《午后之死》）', '如何让文字以最少的篇幅产生最大的力量。', '海明威提出"冰山理论"——露出水面的只有八分之一，其余的深意藏在水下，靠省略让读者自己感受。', '「冰山理论」成为现代简洁文学的重要美学，影响深远。', '不必把什么都说尽——只呈现八分之一、把更深的含义藏在水面下、让对方自己感受（但留白要适度）。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hemingway-c1","status":"published","title_period":"「冰山理论」·省略的力量（《午后之死》）","dilemma_constraints":"如何让文字以最少的篇幅产生最大的力量。","key_judgment":"海明威提出\"冰山理论\"——露出水面的只有八分之一，其余的深意藏在水下，靠省略让读者自己感受。","model_invoked":["冰山理论"],"outcome":"「冰山理论」成为现代简洁文学的重要美学，影响深远。","transferable_lesson":"不必把什么都说尽——只呈现八分之一、把更深的含义藏在水面下、让对方自己感受（但留白要适度）。","source_tier":"primary","source_note":"冰山理论为海明威《午后之死》所提→确证（一手A）。","historicity":"confirmed","linked_cards":["hemingway"],"tags":["表达说服","创作"],"advisor_id":"hemingway"}', '357f65933d09a7dff8cefb326b26b8ac72856ebb0d13a50d2c473d040388037f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hemingway-c2', 'hemingway', '简洁、电报式的文风·简洁有力的表达（海明威作品）', '如何用语言达到最大的力量与真实。', '海明威删去一切多余的形容与修饰，用简短、具体、有力的句子，形成独特的简洁文风。', '海明威的简洁文风深刻影响了20世纪的文学。', '删去一切多余的形容、副词与修饰，用简短、具体、有力的句子——简洁本身就是力量。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hemingway-c2","status":"published","title_period":"简洁、电报式的文风·简洁有力的表达（海明威作品）","dilemma_constraints":"如何用语言达到最大的力量与真实。","key_judgment":"海明威删去一切多余的形容与修饰，用简短、具体、有力的句子，形成独特的简洁文风。","model_invoked":["简洁有力的表达"],"outcome":"海明威的简洁文风深刻影响了20世纪的文学。","transferable_lesson":"删去一切多余的形容、副词与修饰，用简短、具体、有力的句子——简洁本身就是力量。","source_tier":"primary","source_note":"海明威的简洁文风为其作品特征→确证（一手A）。","historicity":"confirmed","linked_cards":["hemingway"],"tags":["表达说服","创作"],"advisor_id":"hemingway"}', 'e9bee6bf7ba9027cfac2d4425b2be37887e8d23ad3dd4283d988111e11227d54');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hemingway-c3', 'hemingway', '「人可以被毁灭，但不能被打败」·重压下的优雅（《老人与海》）', '人在注定失败的困境中应以何种姿态自处。', '海明威在《老人与海》中塑造了虽败犹荣的老人，体现"重压下的优雅"——"人可以被毁灭，但不能被打败"。', '《老人与海》获普利策奖、助其获诺贝尔文学奖，"重压下的优雅"成其标志性主题。', '在压力、困境甚至注定的失败面前，保持尊严、镇定与不被击垮的风度。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hemingway-c3","status":"published","title_period":"「人可以被毁灭，但不能被打败」·重压下的优雅（《老人与海》）","dilemma_constraints":"人在注定失败的困境中应以何种姿态自处。","key_judgment":"海明威在《老人与海》中塑造了虽败犹荣的老人，体现\"重压下的优雅\"——\"人可以被毁灭，但不能被打败\"。","model_invoked":["重压下的优雅"],"outcome":"《老人与海》获普利策奖、助其获诺贝尔文学奖，\"重压下的优雅\"成其标志性主题。","transferable_lesson":"在压力、困境甚至注定的失败面前，保持尊严、镇定与不被击垮的风度。","source_tier":"primary","source_note":"「重压下的优雅」为海明威主题、《老人与海》→确证（一手A）。","historicity":"confirmed","linked_cards":["hemingway"],"tags":["修身自省","表达说服"],"advisor_id":"hemingway"}', 'dedb3e401717dec40dd1b9dacf36759c36925e237bff088efd5e6e08f6ec8f8d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hemingway-c4', 'hemingway', '以亲历追求真实·写你真正懂的真实的（海明威创作观）', '写作如何获得真正的力量与可信。', '海明威主张写自己真正经历、真正懂的东西（他曾任战地记者、亲历战争与狩猎），追求最本质的真实——"写你知道的最真实的那个句子"。', '海明威以亲历的真实赋予作品强大的力量与可信度。', '只写（只做）你真正经历过、真正懂的东西，追求最本质的真实与诚实。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hemingway-c4","status":"published","title_period":"以亲历追求真实·写你真正懂的真实的（海明威创作观）","dilemma_constraints":"写作如何获得真正的力量与可信。","key_judgment":"海明威主张写自己真正经历、真正懂的东西（他曾任战地记者、亲历战争与狩猎），追求最本质的真实——\"写你知道的最真实的那个句子\"。","model_invoked":["写你真正懂的真实的"],"outcome":"海明威以亲历的真实赋予作品强大的力量与可信度。","transferable_lesson":"只写（只做）你真正经历过、真正懂的东西，追求最本质的真实与诚实。","source_tier":"primary","source_note":"海明威以亲历追求真实的创作观为其文论→确证（一手A）。","historicity":"confirmed","linked_cards":["hemingway"],"tags":["创作","修身自省"],"advisor_id":"hemingway"}', '817cd281595d7d0fa888ae52ff4c052f215b324a9dc419b7ac11f4b64fc14c19');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('dickens-c1', 'dickens', '写《雾都孤儿》·把社会问题写成揪心故事（1837—1839）', '济贫院、童工、贫困与犯罪是抽象的社会问题，泛泛揭露难以让公众真正在乎、推动改变。', '狄更斯把这些问题装进孤儿奥利弗的揪心命运里、让读者透过一个孩子的遭遇在情感上"在乎"，从而关注整个社会问题。', '《雾都孤儿》引发广泛社会关注，推动了对济贫制度与童工问题的公众讨论与改良。', '要让人真正在乎一个抽象的社会问题，把它装进一个有血有肉、令人揪心的人物故事里——故事比统计数字更能唤起共情与改变。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"dickens-c1","status":"published","title_period":"写《雾都孤儿》·把社会问题写成揪心故事（1837—1839）","dilemma_constraints":"济贫院、童工、贫困与犯罪是抽象的社会问题，泛泛揭露难以让公众真正在乎、推动改变。","key_judgment":"狄更斯把这些问题装进孤儿奥利弗的揪心命运里、让读者透过一个孩子的遭遇在情感上\"在乎\"，从而关注整个社会问题。","model_invoked":["社会议题叙事"],"outcome":"《雾都孤儿》引发广泛社会关注，推动了对济贫制度与童工问题的公众讨论与改良。","transferable_lesson":"要让人真正在乎一个抽象的社会问题，把它装进一个有血有肉、令人揪心的人物故事里——故事比统计数字更能唤起共情与改变。","source_tier":"primary","source_note":"《雾都孤儿》为狄更斯名作、其社会影响为史载→确证（一手作品A）。","historicity":"confirmed","linked_cards":["dickens"],"tags":["表达说服","价值与伦理"],"advisor_id":"dickens"}', '00775f667eed1bdd9efeea73fed89684258800953346263a69c9f8e43e0c7a97');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('dickens-c2', 'dickens', '首创长篇连载·每期留悬念（其创作生涯）', '长篇内容如何维持读者数月乃至数年的持续追读、不致中途流失。', '狄更斯以月刊/周刊连载发表小说、每一期结尾都设一个悬念或钩子，用节奏与悬念牢牢牵住读者。', '其连载小说万人空巷（如读者守候《老古玩店》小耐尔的结局），开创了连载叙事的范式。', '内容太长留不住人时，按分期节奏组织、每期结尾留一个悬念钩子——用节奏与悬念让人迫不及待等下一期。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"dickens-c2","status":"published","title_period":"首创长篇连载·每期留悬念（其创作生涯）","dilemma_constraints":"长篇内容如何维持读者数月乃至数年的持续追读、不致中途流失。","key_judgment":"狄更斯以月刊/周刊连载发表小说、每一期结尾都设一个悬念或钩子，用节奏与悬念牢牢牵住读者。","model_invoked":["连载悬念"],"outcome":"其连载小说万人空巷（如读者守候《老古玩店》小耐尔的结局），开创了连载叙事的范式。","transferable_lesson":"内容太长留不住人时，按分期节奏组织、每期结尾留一个悬念钩子——用节奏与悬念让人迫不及待等下一期。","source_tier":"primary","source_note":"狄更斯首创并以连载悬念著称为文学史所载→确证。","historicity":"confirmed","linked_cards":["dickens"],"tags":["表达说服","创作表达"],"advisor_id":"dickens"}', '06269d6f7b1a901367a37f75c2495154f0a0b190c4c5631cf3898cfa4bbf6a59');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('dickens-c3', 'dickens', '童年苦难入文·《大卫·科波菲尔》（1849—1850）', '狄更斯幼年因父亲负债入狱、自己被迫在鞋油作坊做童工，这段屈辱经历是其难言之痛。', '他把这段亲历的苦难与观察化入半自传的《大卫·科波菲尔》等作品，赋予笔下的贫困与童工以不可替代的真实感。', '《大卫·科波菲尔》成其最具自传色彩、也最深情的作品之一；亲历使其社会描写格外真切有力。', '把自己真实经历过的苦难与细节转化为创作素材——亲历过的情感与细节，写出来才有不可替代的真实感与力量。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"dickens-c3","status":"published","title_period":"童年苦难入文·《大卫·科波菲尔》（1849—1850）","dilemma_constraints":"狄更斯幼年因父亲负债入狱、自己被迫在鞋油作坊做童工，这段屈辱经历是其难言之痛。","key_judgment":"他把这段亲历的苦难与观察化入半自传的《大卫·科波菲尔》等作品，赋予笔下的贫困与童工以不可替代的真实感。","model_invoked":["亲身体验入文"],"outcome":"《大卫·科波菲尔》成其最具自传色彩、也最深情的作品之一；亲历使其社会描写格外真切有力。","transferable_lesson":"把自己真实经历过的苦难与细节转化为创作素材——亲历过的情感与细节，写出来才有不可替代的真实感与力量。","source_tier":"primary","source_note":"狄更斯童年负债监狱/童工经历化入《大卫·科波菲尔》为公认→确证（一手作品+传记A/B）。","historicity":"confirmed","linked_cards":["dickens"],"tags":["创作表达","价值与伦理"],"advisor_id":"dickens"}', 'f613c3dc41691a6ddac41ace52f40fbd8e41b0253b4d089a488914f8bb5b3c5a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('shakespeare-c1', 'shakespeare', '多面立体的人物·人物的多面与矛盾（莎剧）', '如何刻画真实、有深度、令人信服的人物。', '莎士比亚塑造的人物充满多面与内在矛盾——哈姆雷特的犹疑、麦克白的野心与恐惧、奥赛罗的爱与妒，而非扁平的好人坏人。', '莎剧人物成为文学史上最深刻、最有生命力的形象。', '刻画（或理解）一个人，写出他的多面与内在矛盾——真实的人都是立体矛盾的。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"shakespeare-c1","status":"published","title_period":"多面立体的人物·人物的多面与矛盾（莎剧）","dilemma_constraints":"如何刻画真实、有深度、令人信服的人物。","key_judgment":"莎士比亚塑造的人物充满多面与内在矛盾——哈姆雷特的犹疑、麦克白的野心与恐惧、奥赛罗的爱与妒，而非扁平的好人坏人。","model_invoked":["人物的多面与矛盾"],"outcome":"莎剧人物成为文学史上最深刻、最有生命力的形象。","transferable_lesson":"刻画（或理解）一个人，写出他的多面与内在矛盾——真实的人都是立体矛盾的。","source_tier":"primary","source_note":"莎剧人物塑造为其作品→确证（一手A）。","historicity":"confirmed","linked_cards":["shakespeare"],"tags":["创作","认知偏误与理性决策"],"advisor_id":"shakespeare"}', '224085aa562a6582189171a0d507f2ac20e728c75e06584d4db338ca0e4f66d3');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('shakespeare-c2', 'shakespeare', '对立力量的冲突·冲突驱动（莎剧）', '如何让戏剧/故事有强大的推动力。', '莎士比亚以对立的欲望、价值、力量的冲突推动剧情（如哈姆雷特复仇之志与犹疑之性的内在冲突）。', '戏剧冲突成为莎剧强大张力的来源。', '把对立的欲望、价值、力量逼到一处、用张力去推动发展，而非平铺直叙。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"shakespeare-c2","status":"published","title_period":"对立力量的冲突·冲突驱动（莎剧）","dilemma_constraints":"如何让戏剧/故事有强大的推动力。","key_judgment":"莎士比亚以对立的欲望、价值、力量的冲突推动剧情（如哈姆雷特复仇之志与犹疑之性的内在冲突）。","model_invoked":["冲突驱动"],"outcome":"戏剧冲突成为莎剧强大张力的来源。","transferable_lesson":"把对立的欲望、价值、力量逼到一处、用张力去推动发展，而非平铺直叙。","source_tier":"primary","source_note":"莎剧的戏剧冲突为其作品→确证（一手A）。","historicity":"confirmed","linked_cards":["shakespeare"],"tags":["创作","表达说服"],"advisor_id":"shakespeare"}', 'bd272f068b5a1812093e324b12135c37cf18038f2ce96073a01c3fc2021db3f9');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('shakespeare-c3', 'shakespeare', '永恒的人性母题·普遍人性的母题（莎剧）', '如何让作品超越时代、持久打动人。', '莎士比亚的剧作抓住了跨越时代的普遍人性母题——野心、嫉妒、爱、背叛、权力、死亡。', '莎剧历经数百年仍在全世界上演、打动人心。', '抓住跨越时代的普遍人性母题——具体是外壳、普遍人性才是穿透时代的内核。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"shakespeare-c3","status":"published","title_period":"永恒的人性母题·普遍人性的母题（莎剧）","dilemma_constraints":"如何让作品超越时代、持久打动人。","key_judgment":"莎士比亚的剧作抓住了跨越时代的普遍人性母题——野心、嫉妒、爱、背叛、权力、死亡。","model_invoked":["普遍人性的母题"],"outcome":"莎剧历经数百年仍在全世界上演、打动人心。","transferable_lesson":"抓住跨越时代的普遍人性母题——具体是外壳、普遍人性才是穿透时代的内核。","source_tier":"primary","source_note":"莎剧的永恒主题为其作品→确证（一手A）。","historicity":"confirmed","linked_cards":["shakespeare"],"tags":["表达说服","创作"],"advisor_id":"shakespeare"}', 'fcaf7506e20274ea804434a04e0ab5203b158c417441c0e350e47cf7a83b7109');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('shakespeare-c4', 'shakespeare', '悲剧的人物弧光·以小见大（《李尔王》《麦克白》）', '如何让一个个体的故事承载宏大的意义。', '莎士比亚通过人物的命运起落（李尔王的傲慢与醒悟、麦克白的野心与毁灭），折射出宏大的人性与命运主题。', '莎剧的悲剧弧光成为以个体折射普遍的典范。', '通过一个具体人物的命运起落（选择、缺陷如何导致结局），折射更宏大的人性与命运。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"shakespeare-c4","status":"published","title_period":"悲剧的人物弧光·以小见大（《李尔王》《麦克白》）","dilemma_constraints":"如何让一个个体的故事承载宏大的意义。","key_judgment":"莎士比亚通过人物的命运起落（李尔王的傲慢与醒悟、麦克白的野心与毁灭），折射出宏大的人性与命运主题。","model_invoked":["以小见大的人物弧光"],"outcome":"莎剧的悲剧弧光成为以个体折射普遍的典范。","transferable_lesson":"通过一个具体人物的命运起落（选择、缺陷如何导致结局），折射更宏大的人性与命运。","source_tier":"primary","source_note":"莎剧悲剧的人物弧光为其作品→确证（一手A）。","historicity":"confirmed","linked_cards":["shakespeare"],"tags":["创作","修身自省"],"advisor_id":"shakespeare"}', '3255360eff8587348873861704b03dbd5208e4089283743c54da09c09579480d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hugo-c1', 'hugo', '「美丑对照」·卡西莫多（《巴黎圣母院》）', '如何强烈地凸显内在的美与外在的丑、表象与本质的反差。', '雨果以"美丑对照"塑造卡西莫多（外丑内美）与克洛德（外尊内恶），在强烈反差中凸显各自的力量。', '「美丑对照」成为雨果浪漫主义的标志性手法。', '把美与丑、崇高与卑劣强烈地并置、对照——在鲜明的反差中凸显各自的力量。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hugo-c1","status":"published","title_period":"「美丑对照」·卡西莫多（《巴黎圣母院》）","dilemma_constraints":"如何强烈地凸显内在的美与外在的丑、表象与本质的反差。","key_judgment":"雨果以\"美丑对照\"塑造卡西莫多（外丑内美）与克洛德（外尊内恶），在强烈反差中凸显各自的力量。","model_invoked":["美丑对照"],"outcome":"「美丑对照」成为雨果浪漫主义的标志性手法。","transferable_lesson":"把美与丑、崇高与卑劣强烈地并置、对照——在鲜明的反差中凸显各自的力量。","source_tier":"primary","source_note":"美丑对照为雨果《巴黎圣母院》原则→确证（一手A）。","historicity":"confirmed","linked_cards":["hugo"],"tags":["创作","表达说服"],"advisor_id":"hugo"}', '239a169b9c22df5133324cfc1fc5fa0a5385caaf82cbc25c6ded4fc2a1d461eb');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hugo-c2', 'hugo', '为底层受苦者立传·为弱者与受苦者发声（《悲惨世界》）', '文学应把目光投向谁。', '雨果在《悲惨世界》中把笔触给予社会最底层、被损害的人（冉阿让、芳汀），为没有声音的人发声。', '《悲惨世界》成为为底层与人道发声的不朽之作。', '把关注、同情与表达，给予最弱小、最受苦、被忽视与被损害的人。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hugo-c2","status":"published","title_period":"为底层受苦者立传·为弱者与受苦者发声（《悲惨世界》）","dilemma_constraints":"文学应把目光投向谁。","key_judgment":"雨果在《悲惨世界》中把笔触给予社会最底层、被损害的人（冉阿让、芳汀），为没有声音的人发声。","model_invoked":["为弱者与受苦者发声"],"outcome":"《悲惨世界》成为为底层与人道发声的不朽之作。","transferable_lesson":"把关注、同情与表达，给予最弱小、最受苦、被忽视与被损害的人。","source_tier":"primary","source_note":"《悲惨世界》写底层受苦者为其作品→确证（一手A）。","historicity":"confirmed","linked_cards":["hugo"],"tags":["价值与伦理","创作"],"advisor_id":"hugo"}', '3c02282c5f884f51cf7ac054471eb624cc1a3ed1035f806f983aa8a0b2bb5868');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hugo-c3', 'hugo', '冉阿让的救赎·人道主义的信念（《悲惨世界》）', '人性在苦难与冷酷中是否还能向善。', '雨果让被苦役变得凶狠的冉阿让，被主教米里哀以德报怨彻底感化、从此向善，体现对人性向善与救赎的信念。', '冉阿让的救赎成为人道主义文学的经典象征。', '即使在最黑暗、最绝望处，也保有对人性之善与救赎之可能的信念。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hugo-c3","status":"published","title_period":"冉阿让的救赎·人道主义的信念（《悲惨世界》）","dilemma_constraints":"人性在苦难与冷酷中是否还能向善。","key_judgment":"雨果让被苦役变得凶狠的冉阿让，被主教米里哀以德报怨彻底感化、从此向善，体现对人性向善与救赎的信念。","model_invoked":["人道主义的信念"],"outcome":"冉阿让的救赎成为人道主义文学的经典象征。","transferable_lesson":"即使在最黑暗、最绝望处，也保有对人性之善与救赎之可能的信念。","source_tier":"primary","source_note":"冉阿让的救赎为《悲惨世界》→确证（一手A）。","historicity":"confirmed","linked_cards":["hugo"],"tags":["价值与伦理","修身自省"],"advisor_id":"hugo"}', '1f3f50ed5b9f0be43d665a9031e6649ff2c033956207a0b7ba8c635ddeeb5e0d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hugo-c4', 'hugo', '借个体命运拷问社会·把个体故事接入宏大议题（《悲惨世界》）', '如何让个体的故事承载对社会的批判与思考。', '雨果借冉阿让的命运，拷问法律的僵硬、贫困的根源与人性，把个体故事接入宏大的社会议题。', '《悲惨世界》以个体命运承载了对19世纪法国社会的深刻批判。', '通过一个具体个体的命运故事，承载并推动对宏大社会议题（不公、贫困、法律）的关注。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hugo-c4","status":"published","title_period":"借个体命运拷问社会·把个体故事接入宏大议题（《悲惨世界》）","dilemma_constraints":"如何让个体的故事承载对社会的批判与思考。","key_judgment":"雨果借冉阿让的命运，拷问法律的僵硬、贫困的根源与人性，把个体故事接入宏大的社会议题。","model_invoked":["把个体故事接入宏大的社会议题"],"outcome":"《悲惨世界》以个体命运承载了对19世纪法国社会的深刻批判。","transferable_lesson":"通过一个具体个体的命运故事，承载并推动对宏大社会议题（不公、贫困、法律）的关注。","source_tier":"primary","source_note":"借冉阿让命运拷问社会为《悲惨世界》主题→确证（一手A）。","historicity":"confirmed","linked_cards":["hugo"],"tags":["价值与伦理","创作"],"advisor_id":"hugo"}', 'b426220b5e6b8bc93358ab4abcebcc0529a9819b020cd8b10431ca53a8847041');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('twain-c1', 'twain', '写《哈克贝利·费恩历险记》（1884）', '要批判奴隶制与社会虚伪，但正面说教既枯燥又易招抵触、难以打动人。', '吐温以少年哈克的方言口语第一人称叙事、借一个孩子的"天真"视角，让读者透过哈克的眼睛自己"看见"奴隶制的荒谬与逃奴吉姆的人性。', '《哈克贝利·费恩》被誉为美国文学的奠基之作，以天真视角与方言叙事开创了新的批判与共情方式。', '要批判一种虚伪、又不想板着脸说教时，借一个孩子/局外人的天真视角让读者自己"看见"——既照出虚伪、又唤起共情。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"twain-c1","status":"published","title_period":"写《哈克贝利·费恩历险记》（1884）","dilemma_constraints":"要批判奴隶制与社会虚伪，但正面说教既枯燥又易招抵触、难以打动人。","key_judgment":"吐温以少年哈克的方言口语第一人称叙事、借一个孩子的\"天真\"视角，让读者透过哈克的眼睛自己\"看见\"奴隶制的荒谬与逃奴吉姆的人性。","model_invoked":["共情视角"],"outcome":"《哈克贝利·费恩》被誉为美国文学的奠基之作，以天真视角与方言叙事开创了新的批判与共情方式。","transferable_lesson":"要批判一种虚伪、又不想板着脸说教时，借一个孩子/局外人的天真视角让读者自己\"看见\"——既照出虚伪、又唤起共情。","source_tier":"primary","source_note":"《哈克贝利·费恩历险记》为吐温1884代表作→确证（一手作品A）。","historicity":"confirmed","linked_cards":["twain"],"tags":["创作表达","价值与伦理"],"advisor_id":"twain"}', '95a100647013e107931169ce9f2b6eefaa1079cd2ba758b31e03041140349447');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('twain-c2', 'twain', '讽刺《镀金时代》·批判贪婪腐败（1873及其后）', '战后美国财富狂热、投机与政治腐败盛行；正面抨击难有穿透力。', '吐温（与共同作者）写《镀金时代》、并以一系列讽刺随笔与演讲、用幽默讽刺包裹对贪婪与腐败的尖锐批判。', '「镀金时代」成为那个浮华而腐败时代的代名词；其幽默讽刺成穿透人心的批判利器。', '要批评贪婪、浮夸或腐败而怕太尖锐被抵触时，把批判包进幽默讽刺里——人会笑着接受一个被说教就会抵触的观点。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"twain-c2","status":"published","title_period":"讽刺《镀金时代》·批判贪婪腐败（1873及其后）","dilemma_constraints":"战后美国财富狂热、投机与政治腐败盛行；正面抨击难有穿透力。","key_judgment":"吐温（与共同作者）写《镀金时代》、并以一系列讽刺随笔与演讲、用幽默讽刺包裹对贪婪与腐败的尖锐批判。","model_invoked":["讽刺幽默作批判"],"outcome":"「镀金时代」成为那个浮华而腐败时代的代名词；其幽默讽刺成穿透人心的批判利器。","transferable_lesson":"要批评贪婪、浮夸或腐败而怕太尖锐被抵触时，把批判包进幽默讽刺里——人会笑着接受一个被说教就会抵触的观点。","source_tier":"primary","source_note":"《镀金时代》及吐温讽刺随笔为确证（一手作品A）；该书与共同作者合著。","historicity":"confirmed","linked_cards":["twain"],"tags":["表达说服","价值与伦理"],"advisor_id":"twain"}', 'f55f141ab2bdfa19ff28e8bd18f166922c384116d0579f5c305e748c2fb190fb');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('twain-c3', 'twain', '论"对的词"与"差不多对的词"（论写作）', '写作中常满足于"差不多对"的词、表达因此松垮无力。', '吐温强调用词的精准——"对的词"与"差不多对的词"之间，是闪电与萤火虫之别；砍掉多余、追求那个精准有力的词。', '这一用词观成写作的经典准则，影响无数写作者。', '别满足于"差不多对"的词——砍掉多余、找到那个精准有力的"对的词"，表达的力量天差地别（闪电 vs 萤火虫）。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"twain-c3","status":"published","title_period":"论\"对的词\"与\"差不多对的词\"（论写作）","dilemma_constraints":"写作中常满足于\"差不多对\"的词、表达因此松垮无力。","key_judgment":"吐温强调用词的精准——\"对的词\"与\"差不多对的词\"之间，是闪电与萤火虫之别；砍掉多余、追求那个精准有力的词。","model_invoked":["精炼有力"],"outcome":"这一用词观成写作的经典准则，影响无数写作者。","transferable_lesson":"别满足于\"差不多对\"的词——砍掉多余、找到那个精准有力的\"对的词\"，表达的力量天差地别（闪电 vs 萤火虫）。","source_tier":"primary","source_note":"吐温论\"对的词\"与\"差不多对的词\"为其论写作名言→确证（一手A）。","historicity":"confirmed","linked_cards":["twain"],"tags":["表达说服","创作表达"],"advisor_id":"twain"}', 'c67fcceeb5ea73d5f63ea0fda06c996ecbad43e7cee7e2f6992a079ffbcacc84');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('engelbart-c1', 'engelbart', '提出增强人类智力框架（1962报告）', '当时计算机被视为大型计算/自动化机器；他要论证一条几乎无人理解的方向——计算机用来放大人的智能。', '从如何提升人类解决复杂问题的能力出发，提出 H-LAM/T 协同进化框架，把计算机定位为思维放大器。', '1962年报告成为人机交互与个人计算的思想奠基，影响深远。', '重大方向常来自重设问题本身——不是机器能替我们做什么，而是机器能让我们变得多强。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"engelbart-c1","status":"published","title_period":"提出增强人类智力框架（1962报告）","dilemma_constraints":"当时计算机被视为大型计算/自动化机器；他要论证一条几乎无人理解的方向——计算机用来放大人的智能。","key_judgment":"从如何提升人类解决复杂问题的能力出发，提出 H-LAM/T 协同进化框架，把计算机定位为思维放大器。","model_invoked":["增强人类智力"],"outcome":"1962年报告成为人机交互与个人计算的思想奠基，影响深远。","transferable_lesson":"重大方向常来自重设问题本身——不是机器能替我们做什么，而是机器能让我们变得多强。","source_tier":"primary","source_note":"1962报告为一手公开文献(A)。","historicity":"confirmed","linked_cards":["engelbart"],"tags":["创新研发","学习与认知"],"advisor_id":"engelbart"}', '49eb14144773f659e7176349bbf3d5b78f0a888b7c5487aec818457f1fd7ed4f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('engelbart-c2', 'engelbart', '所有演示之母（1968年旧金山）', '他的增强智力理念抽象、难被理解与资助；行业尚无个人交互式计算的概念。', '不再分块讲解，一次性现场演示鼠标、超文本、屏上协作编辑、视频会议等未来的工作方式。', '这场演示后被称为所有演示之母，预示了此后数十年的个人计算与协作。', '当愿景太超前、讲不清时，一次让人亲眼看见未来怎么运转的完整演示，比任何论证都更能传递与说服。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"engelbart-c2","status":"published","title_period":"所有演示之母（1968年旧金山）","dilemma_constraints":"他的增强智力理念抽象、难被理解与资助；行业尚无个人交互式计算的概念。","key_judgment":"不再分块讲解，一次性现场演示鼠标、超文本、屏上协作编辑、视频会议等未来的工作方式。","model_invoked":["看得见的整体演示"],"outcome":"这场演示后被称为所有演示之母，预示了此后数十年的个人计算与协作。","transferable_lesson":"当愿景太超前、讲不清时，一次让人亲眼看见未来怎么运转的完整演示，比任何论证都更能传递与说服。","source_tier":"primary","source_note":"1968演示有完整录像存档(A)。","historicity":"confirmed","linked_cards":["engelbart"],"tags":["创新研发","表达说服"],"advisor_id":"engelbart"}', '75f63f3e2ef14b4b3743dbaf5c5a8bf22713560ce8f55f89d0dd9fd532a53b58');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('engelbart-c3', 'engelbart', '发明鼠标作为人机交互器（约1964）', '当时缺乏直观高效的屏上指点方式；须从怎样让人最省力操控屏上对象出发设计。', '从人机协同的需求出发，设计出滚轮定位的指点装置（鼠标），服务于增强交互而非炫技。', '鼠标(1970年获专利)成为个人计算的标准交互器。', '好工具源自先想清人要更省力地做什么动作，再倒推器械——工具服务于人的方法，而非反过来。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"engelbart-c3","status":"published","title_period":"发明鼠标作为人机交互器（约1964）","dilemma_constraints":"当时缺乏直观高效的屏上指点方式；须从怎样让人最省力操控屏上对象出发设计。","key_judgment":"从人机协同的需求出发，设计出滚轮定位的指点装置（鼠标），服务于增强交互而非炫技。","model_invoked":["人工具协同进化"],"outcome":"鼠标(1970年获专利)成为个人计算的标准交互器。","transferable_lesson":"好工具源自先想清人要更省力地做什么动作，再倒推器械——工具服务于人的方法，而非反过来。","source_tier":"primary","source_note":"鼠标专利为一手(A)；Bardini 传记交叉印证(B)。","historicity":"confirmed","linked_cards":["engelbart"],"tags":["创新研发","学习与认知"],"advisor_id":"engelbart"}', '86a5386921773c1f5ae7a097218a27ab6f7a29af6103d51a00385e533d1f484a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('engelbart-c4', 'engelbart', '在ARC实验室实践自举（1960s–70s）', '团队既要开发增强工具、又要靠这些工具提升自身——存在用未成熟工具做事的张力。', '坚持用自己开发中的系统(NLS)开展工作，让团队的改进能力对自身复利累积。', 'ARC成为多项交互技术的孵化地，但自举方法学在更大范围难复制。', '让你的改进工具反过来改进你做改进的能力，是复利式进步的引擎；但要承受用半成品做事的早期成本。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"engelbart-c4","status":"published","title_period":"在ARC实验室实践自举（1960s–70s）","dilemma_constraints":"团队既要开发增强工具、又要靠这些工具提升自身——存在用未成熟工具做事的张力。","key_judgment":"坚持用自己开发中的系统(NLS)开展工作，让团队的改进能力对自身复利累积。","model_invoked":["自举"],"outcome":"ARC成为多项交互技术的孵化地，但自举方法学在更大范围难复制。","transferable_lesson":"让你的改进工具反过来改进你做改进的能力，是复利式进步的引擎；但要承受用半成品做事的早期成本。","source_tier":"secondary","source_note":"ARC与NLS实践为信史(B/多源)。","historicity":"confirmed","linked_cards":["engelbart"],"tags":["创新研发","组织管理"],"advisor_id":"engelbart"}', '960a37e6b0b6b87e63cbadc86b1d57a0b1590f2ca836d2ac03796804f96ab0b5');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('engelbart-c5', 'engelbart', '愿景领先却让他人收割商业化（1970s后）', '其原型领先十余年，但他不擅、也无意把它打磨成可普及产品；资助与组织支持渐失。', '（反面教材）专注理念与原型，未能把成果产品化、普及化，商业化由施乐PARC、苹果等承接。', '鼠标/图形交互等经他人商业化后改变世界，他本人长期处于边缘、资助困难。', '领先的愿景若没有配套的产品化与传播，红利会被更擅长落地的人收割——远见需要落地与说服来兑现。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"engelbart-c5","status":"published","title_period":"愿景领先却让他人收割商业化（1970s后）","dilemma_constraints":"其原型领先十余年，但他不擅、也无意把它打磨成可普及产品；资助与组织支持渐失。","key_judgment":"（反面教材）专注理念与原型，未能把成果产品化、普及化，商业化由施乐PARC、苹果等承接。","model_invoked":["增强人类智力"],"outcome":"鼠标/图形交互等经他人商业化后改变世界，他本人长期处于边缘、资助困难。","transferable_lesson":"领先的愿景若没有配套的产品化与传播，红利会被更擅长落地的人收割——远见需要落地与说服来兑现。","source_tier":"secondary","source_note":"其成果由他人商业化、本人长期边缘为史实(B/多源)。本条为重理念轻落地盲区的现实印证。","historicity":"confirmed","linked_cards":["engelbart"],"tags":["商业模式与护城河","职业发展"],"advisor_id":"engelbart"}', '72b3728f77f5bc34b0eeadcefa75b5c7f42adc25581c2be56bc69e0078910548');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('goddard-c1', 'goddard', '发表《抵达极高空的方法》（1919）', '火箭能否在真空中工作当时受质疑；须用理论严谨论证可行性，缺乏可参照成例。', '以物理与数学推演火箭在真空中的可行性与所需条件，把上极高空变成可计算的工程问题。', '论文奠定现代火箭理论基础之一；但也引来公众误解与嘲讽。', '把一个被当作幻想的目标，先用理论严谨地证明其可行边界，是让它从空想变成工程的第一步。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"goddard-c1","status":"published","title_period":"发表《抵达极高空的方法》（1919）","dilemma_constraints":"火箭能否在真空中工作当时受质疑；须用理论严谨论证可行性，缺乏可参照成例。","key_judgment":"以物理与数学推演火箭在真空中的可行性与所需条件，把上极高空变成可计算的工程问题。","model_invoked":["理论实验闭环"],"outcome":"论文奠定现代火箭理论基础之一；但也引来公众误解与嘲讽。","transferable_lesson":"把一个被当作幻想的目标，先用理论严谨地证明其可行边界，是让它从空想变成工程的第一步。","source_tier":"primary","source_note":"1919论文为一手公开文献(A)。","historicity":"confirmed","linked_cards":["goddard"],"tags":["创新研发","探索未知"],"advisor_id":"goddard"}', 'd54c458a221f913da89ee4e32e9a561a3f67de770b28dbabd5b3b7e42cc0ff62');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('goddard-c2', 'goddard', '顶着《纽约时报》的嘲讽继续（1920及之后）', '1920年《纽约时报》社论嘲讽其连基础物理都不懂（误以为火箭在真空中无法推进）；舆论压力大。', '不公开论战，以实验数据为准绳，默默继续推进火箭研究。', '多年后火箭升空印证其正确；《纽约时报》于1969年阿波罗发射之际正式刊文更正。', '当你手里有可验证的数据、而否定你的只是权威的想当然时，最好的回应不是争辩，而是把事做出来让事实说话。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"goddard-c2","status":"published","title_period":"顶着《纽约时报》的嘲讽继续（1920及之后）","dilemma_constraints":"1920年《纽约时报》社论嘲讽其连基础物理都不懂（误以为火箭在真空中无法推进）；舆论压力大。","key_judgment":"不公开论战，以实验数据为准绳，默默继续推进火箭研究。","model_invoked":["不理嘲笑坚持"],"outcome":"多年后火箭升空印证其正确；《纽约时报》于1969年阿波罗发射之际正式刊文更正。","transferable_lesson":"当你手里有可验证的数据、而否定你的只是权威的想当然时，最好的回应不是争辩，而是把事做出来让事实说话。","source_tier":"secondary","source_note":"1920社论与1969更正均为可查报刊记录(B)；社论原意呈现宜引述其大意、不逐字坐实措辞。","historicity":"confirmed","linked_cards":["goddard"],"tags":["风险评估","修身自省"],"advisor_id":"goddard"}', 'a5abe978b039e0a6e34d419cffba327444857dc46b320bc7054f170eb67f3d60');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('goddard-c3', 'goddard', '发射首枚液体燃料火箭（1926年3月16日，马萨诸塞奥本）', '固体燃料性能受限；液体燃料更难（泵、冷却、点火、控制）、无成例，且资源有限。', '押注液体燃料路线，自制液氧/汽油火箭，完成人类首次液体燃料火箭飞行。', '1926年火箭升空数秒、飞行数十英尺——人类首枚液体燃料火箭，航天工程起点之一。', '当现有路线触到性能天花板时，转向更难但上限更高的新路线，哪怕第一步只飞了几十英尺，也是一个新范式的起点。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"goddard-c3","status":"published","title_period":"发射首枚液体燃料火箭（1926年3月16日，马萨诸塞奥本）","dilemma_constraints":"固体燃料性能受限；液体燃料更难（泵、冷却、点火、控制）、无成例，且资源有限。","key_judgment":"押注液体燃料路线，自制液氧/汽油火箭，完成人类首次液体燃料火箭飞行。","model_invoked":["押注液体燃料"],"outcome":"1926年火箭升空数秒、飞行数十英尺——人类首枚液体燃料火箭，航天工程起点之一。","transferable_lesson":"当现有路线触到性能天花板时，转向更难但上限更高的新路线，哪怕第一步只飞了几十英尺，也是一个新范式的起点。","source_tier":"primary","source_note":"1926液体火箭试验为信史(A/多源)。","historicity":"confirmed","linked_cards":["goddard"],"tags":["创新研发","探索未知"],"advisor_id":"goddard"}', '0125d85fc7a8cad0e770af9b2030c3905f7260dbc81b7a89d24a1fed3d20f66f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('goddard-c4', 'goddard', '液体推进与多级火箭专利（1914起）', '上太空是一个无法一次解决的巨问题，须拆解为可独立工程化的子系统。', '把火箭拆成液体推进、多级分离等可独立工程化的子问题，逐项申请专利、逐项攻关。', '其液体推进与多级火箭专利成为后世火箭工程的基础构件。', '面对一口吃不下的巨大目标，把它拆成可独立攻克、可复用的子系统，是把幻想变成工程的通法。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"goddard-c4","status":"published","title_period":"液体推进与多级火箭专利（1914起）","dilemma_constraints":"上太空是一个无法一次解决的巨问题，须拆解为可独立工程化的子系统。","key_judgment":"把火箭拆成液体推进、多级分离等可独立工程化的子问题，逐项申请专利、逐项攻关。","model_invoked":["模块化攻关"],"outcome":"其液体推进与多级火箭专利成为后世火箭工程的基础构件。","transferable_lesson":"面对一口吃不下的巨大目标，把它拆成可独立攻克、可复用的子系统，是把幻想变成工程的通法。","source_tier":"primary","source_note":"专利为一手(A)。","historicity":"confirmed","linked_cards":["goddard"],"tags":["创新研发","资源调度"],"advisor_id":"goddard"}', '3f6400a51583376511a7a94d93e37f37be1c8d11608be881dd48148de369ca8b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('goddard-c5', 'goddard', '极端保密与孤立推进的代价（1930s）', '他高度保密、偏好独自/小圈子工作，少发表、少合作。', '（反面教材）以保密保护领先，拒绝广泛协作与公开，长期单打独斗。', '限制了人才汇聚与影响放大；协作化的德国火箭团队在工程规模上后来居上。', '保密能护住一时领先，却切断了协作与人才的复利——在需大规模工程协作的领域，过度保密反而拖慢自己。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"goddard-c5","status":"published","title_period":"极端保密与孤立推进的代价（1930s）","dilemma_constraints":"他高度保密、偏好独自/小圈子工作，少发表、少合作。","key_judgment":"（反面教材）以保密保护领先，拒绝广泛协作与公开，长期单打独斗。","model_invoked":["不理嘲笑坚持"],"outcome":"限制了人才汇聚与影响放大；协作化的德国火箭团队在工程规模上后来居上。","transferable_lesson":"保密能护住一时领先，却切断了协作与人才的复利——在需大规模工程协作的领域，过度保密反而拖慢自己。","source_tier":"secondary","source_note":"其保密风格与影响见多部传记(B)。本条为其独自坚持特质用过头的反面教材；德国团队对比宜客观、不渲染。","historicity":"confirmed","linked_cards":["goddard"],"tags":["组织管理","探索未知"],"advisor_id":"goddard"}', 'f1e0942afd7c85a576d9c9cadef64741068ae8b365b57247afef6302e04067cc');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('edison-c1', 'edison', '白炽灯灯丝的海量筛选（约1879–1880）', '要做出能持久、可量产、成本可控的白炽灯；候选材料近乎无穷，理论无法直接给出答案。', '不赌单一材料，组织团队系统化试验大量材料（碳化竹丝等），以规模化试错筛出可行解。', '找到可用灯丝、白炽灯走向商用，奠定其电灯事业。', '当理论给不出答案、候选近乎无穷时，把问题拆成可测变量、以有组织的规模化试错逼近，比空等灵感快。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"edison-c1","status":"published","title_period":"白炽灯灯丝的海量筛选（约1879–1880）","dilemma_constraints":"要做出能持久、可量产、成本可控的白炽灯；候选材料近乎无穷，理论无法直接给出答案。","key_judgment":"不赌单一材料，组织团队系统化试验大量材料（碳化竹丝等），以规模化试错筛出可行解。","model_invoked":["系统化试错"],"outcome":"找到可用灯丝、白炽灯走向商用，奠定其电灯事业。","transferable_lesson":"当理论给不出答案、候选近乎无穷时，把问题拆成可测变量、以有组织的规模化试错逼近，比空等灵感快。","source_tier":"secondary","source_note":"灯丝筛选见多部权威传记与实验室记录(B)；具体材料数目呈现宜用大量/上千种等约数。","historicity":"confirmed","linked_cards":["edison"],"tags":["创新研发","风险评估"],"advisor_id":"edison"}', '35aaed68273819bf2282d96ffaa6c0c274d1e936c72667f091add5b0e25b1dc4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('edison-c2', 'edison', '造整套供电系统·珍珠街电站（1882）', '单造灯泡形不成生意——没有发电、布线、计费标准灯就卖不出去；须押注一个尚不存在的完整系统。', '同时开发发电机、配电网、计费与安装标准，自建纽约珍珠街中央电站，把电灯做成整套系统。', '珍珠街电站点亮曼哈顿部分街区，确立中央供电＋终端用电的商业范式。', '真正的壁垒常不在最聪明的部件，而在你是否把它运转所需的整套系统一起建起来，让对手无单点可替代。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"edison-c2","status":"published","title_period":"造整套供电系统·珍珠街电站（1882）","dilemma_constraints":"单造灯泡形不成生意——没有发电、布线、计费标准灯就卖不出去；须押注一个尚不存在的完整系统。","key_judgment":"同时开发发电机、配电网、计费与安装标准，自建纽约珍珠街中央电站，把电灯做成整套系统。","model_invoked":["占领整个系统"],"outcome":"珍珠街电站点亮曼哈顿部分街区，确立中央供电＋终端用电的商业范式。","transferable_lesson":"真正的壁垒常不在最聪明的部件，而在你是否把它运转所需的整套系统一起建起来，让对手无单点可替代。","source_tier":"secondary","source_note":"珍珠街电站为信史(B/多源)。","historicity":"confirmed","linked_cards":["edison"],"tags":["创新研发","商业模式与护城河"],"advisor_id":"edison"}', '9b674e4553ea95cfd2852624d3d6bb521acb276d0753a2bab0de777e16533844');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('edison-c3', 'edison', '建门洛帕克发明工厂（1876起）', '个人灵感不可规模化、不可预期；要把出发明变成可持续、可预期的产出。', '建立配备专职研究员、技工与设备的工业化实验室，分工协作、流水推进，把发明本身工厂化。', '门洛帕克成为现代工业研发实验室原型，高产出留声机、电灯等。', '想让偶发突破变成可持续产出，要把创造过程组织化——建流程、配团队、给设备，而非依赖个别天才的灵光。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"edison-c3","status":"published","title_period":"建门洛帕克发明工厂（1876起）","dilemma_constraints":"个人灵感不可规模化、不可预期；要把出发明变成可持续、可预期的产出。","key_judgment":"建立配备专职研究员、技工与设备的工业化实验室，分工协作、流水推进，把发明本身工厂化。","model_invoked":["发明工厂"],"outcome":"门洛帕克成为现代工业研发实验室原型，高产出留声机、电灯等。","transferable_lesson":"想让偶发突破变成可持续产出，要把创造过程组织化——建流程、配团队、给设备，而非依赖个别天才的灵光。","source_tier":"secondary","source_note":"门洛帕克实验室为信史(B)。","historicity":"confirmed","linked_cards":["edison"],"tags":["组织管理","创新研发"],"advisor_id":"edison"}', '51d50c8ee1b1410992ef346699616efb8931851ff49bf592f14fb5dc8d42633e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('edison-c4', 'edison', '留声机的发明与公开演示（1877）', '一个全新、无人预期的产品（能录放人声），公众与资本对其价值毫无概念。', '迅速做出可当场演示的样机，用亲耳听见复述人声的现场效果，直接征服观众与媒体。', '留声机轰动一时，门洛帕克奇才声名大噪，赢得资本与关注。', '面对一个别人没有概念的新东西，一次让人当场亲历的演示，比任何说明都更能瞬间建立认知与信任。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"edison-c4","status":"published","title_period":"留声机的发明与公开演示（1877）","dilemma_constraints":"一个全新、无人预期的产品（能录放人声），公众与资本对其价值毫无概念。","key_judgment":"迅速做出可当场演示的样机，用亲耳听见复述人声的现场效果，直接征服观众与媒体。","model_invoked":["快速可见演示"],"outcome":"留声机轰动一时，门洛帕克奇才声名大噪，赢得资本与关注。","transferable_lesson":"面对一个别人没有概念的新东西，一次让人当场亲历的演示，比任何说明都更能瞬间建立认知与信任。","source_tier":"secondary","source_note":"留声机发明为信史(B/多源)。","historicity":"confirmed","linked_cards":["edison"],"tags":["创新研发","表达说服"],"advisor_id":"edison"}', 'eb1cc01d7cc24174a566764ca3981cf7674ab49844284c765817c3754a04fa1b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('edison-c5', 'edison', '电流之战：死守直流的代价（约1887–1893）', '交流(AC)在远距离输电上明显优于他重金投入的直流(DC)；承认对手更优意味着否定自己的巨额沉没投资。', '（反面教材）拒绝转向AC，发动舆论战渲染交流危险，力保DC。', 'AC最终在西屋/特斯拉体系下胜出成为主流，爱迪生此役技术上站错边、声誉受损。', '当更优方案威胁到你的巨额沉没投入时，死守加抹黑往往是用沉没成本绑架未来——区分我投了很多与它仍然是对的。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"edison-c5","status":"published","title_period":"电流之战：死守直流的代价（约1887–1893）","dilemma_constraints":"交流(AC)在远距离输电上明显优于他重金投入的直流(DC)；承认对手更优意味着否定自己的巨额沉没投资。","key_judgment":"（反面教材）拒绝转向AC，发动舆论战渲染交流危险，力保DC。","model_invoked":["占领整个系统"],"outcome":"AC最终在西屋/特斯拉体系下胜出成为主流，爱迪生此役技术上站错边、声誉受损。","transferable_lesson":"当更优方案威胁到你的巨额沉没投入时，死守加抹黑往往是用沉没成本绑架未来——区分我投了很多与它仍然是对的。","source_tier":"secondary","source_note":"电流之战为信史(B/多源)；具体手段呈现宜客观、不渲染。本条为占领整个系统模型用过头的反面教材。","historicity":"confirmed","linked_cards":["edison"],"tags":["风险评估","竞争博弈"],"advisor_id":"edison"}', '5d3c7d0076826ab959aec69a0140a14df0a3cc65fcd7958c3f9841951dc163e0');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tesla-c1', 'tesla', '从旋转磁场重做电机（多相交流系统，1880s）', '直流电机有换向器等固有缺陷；主流（含爱迪生）在直流框架内修补，整个行业押注直流。', '不在直流框架内改良，回到交流电可产生旋转磁场的物理本质，设计无换向器的多相交流感应电机。', '取得多相交流系统专利(1888)，经西屋授权，成为现代电力系统基础。', '当所有人都在旧框架内修补瓶颈时，回到问题的物理本质往往能重起一套更对的方案，而不是更好的补丁。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"tesla-c1","status":"published","title_period":"从旋转磁场重做电机（多相交流系统，1880s）","dilemma_constraints":"直流电机有换向器等固有缺陷；主流（含爱迪生）在直流框架内修补，整个行业押注直流。","key_judgment":"不在直流框架内改良，回到交流电可产生旋转磁场的物理本质，设计无换向器的多相交流感应电机。","model_invoked":["旋转磁场原理"],"outcome":"取得多相交流系统专利(1888)，经西屋授权，成为现代电力系统基础。","transferable_lesson":"当所有人都在旧框架内修补瓶颈时，回到问题的物理本质往往能重起一套更对的方案，而不是更好的补丁。","source_tier":"primary","source_note":"多相交流专利为一手(A)、信史；Carlson 传记交叉印证(B)。","historicity":"confirmed","linked_cards":["tesla"],"tags":["创新研发","风险评估"],"advisor_id":"tesla"}', 'f37a7e425c754ac104cec9fb93041368e0d81f1f988e33749ab23835d24ad789');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tesla-c2', 'tesla', '押注交流系统、与西屋结盟（约1888–1893）', '交流当时被爱迪生阵营渲染为危险；选择交流意味着与强大的直流阵营对抗、前途未卜。', '坚持交流的长远物理优势，授权专利给西屋，共同推进交流标准。', '交流在尼亚加拉电站等落地，最终成为主流供电标准。', '押注一个当下被唱衰、但底层物理更优的方案，需承受短期对抗，赌的是长远的结构性优势。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"tesla-c2","status":"published","title_period":"押注交流系统、与西屋结盟（约1888–1893）","dilemma_constraints":"交流当时被爱迪生阵营渲染为危险；选择交流意味着与强大的直流阵营对抗、前途未卜。","key_judgment":"坚持交流的长远物理优势，授权专利给西屋，共同推进交流标准。","model_invoked":["系统级押注交流"],"outcome":"交流在尼亚加拉电站等落地，最终成为主流供电标准。","transferable_lesson":"押注一个当下被唱衰、但底层物理更优的方案，需承受短期对抗，赌的是长远的结构性优势。","source_tier":"secondary","source_note":"交流胜出与尼亚加拉电站为信史(B/多源)；电流之战涉西屋等多方，呈现勿独归一人。","historicity":"confirmed","linked_cards":["tesla"],"tags":["竞争博弈","长期规划"],"advisor_id":"tesla"}', '5f44d935112537d709865a4da79afc26168cda3f4016bc30440b5305eed675d7');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tesla-c3', 'tesla', '在脑中造好机器再动手（其自述工作法）', '物理试错昂贵耗时；他自述具有罕见的视觉化能力。', '（据其自述）动手前于脑中完整构建并运转装置、反复调试，再造实物。', '（据其自述）减少了物理原型反复；该说法成为其传奇的一部分。', '动手前尽量在头脑/纸面把方案完整跑一遍、预演故障点，能省下大量真实试错——但要警惕高估脑中模拟的可靠性。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"tesla-c3","status":"published","title_period":"在脑中造好机器再动手（其自述工作法）","dilemma_constraints":"物理试错昂贵耗时；他自述具有罕见的视觉化能力。","key_judgment":"（据其自述）动手前于脑中完整构建并运转装置、反复调试，再造实物。","model_invoked":["心智预演"],"outcome":"（据其自述）减少了物理原型反复；该说法成为其传奇的一部分。","transferable_lesson":"动手前尽量在头脑/纸面把方案完整跑一遍、预演故障点，能省下大量真实试错——但要警惕高估脑中模拟的可靠性。","source_tier":"primary","source_note":"出自自传《My Inventions》(A·自述)；完全在脑中无误运转属本人单方叙述、无第三方可验证，按自述类记存疑，呈现加据其自述。","historicity":"disputed","linked_cards":["tesla"],"tags":["创新研发","修身自省"],"advisor_id":"tesla"}', '4198fa05602464474917ee42b4af7e425184838ce2037549bc5641f27205da5e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tesla-c4', 'tesla', '沃登克里夫无线输电的烂尾（1901–1906）', '他要建全球无线输电塔，目标远超当时工程与资金可支撑；资金主要靠摩根。', '（反面教材）坚持超前愿景、不顾资源与商业可行性，融资断裂后仍难收束。', '项目融资断裂、停建，最终拆除；特斯拉财务与声誉受重创。', '愿景设得再远，也要与可支撑它的资源、资金、工程现实挂钩——脱离资源约束的远大目标常以烂尾收场。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"tesla-c4","status":"published","title_period":"沃登克里夫无线输电的烂尾（1901–1906）","dilemma_constraints":"他要建全球无线输电塔，目标远超当时工程与资金可支撑；资金主要靠摩根。","key_judgment":"（反面教材）坚持超前愿景、不顾资源与商业可行性，融资断裂后仍难收束。","model_invoked":["远超时代目标"],"outcome":"项目融资断裂、停建，最终拆除；特斯拉财务与声誉受重创。","transferable_lesson":"愿景设得再远，也要与可支撑它的资源、资金、工程现实挂钩——脱离资源约束的远大目标常以烂尾收场。","source_tier":"secondary","source_note":"沃登克里夫停建拆除为信史(B/多源)。本条为远超时代目标模型脱离资源约束的反面教材。","historicity":"confirmed","linked_cards":["tesla"],"tags":["风险评估","长期规划"],"advisor_id":"tesla"}', 'e0230bfd37d5d5a6e8533951d7d48ab0156f7b8d89948d96ea268bddaf300ab2');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tesla-c5', 'tesla', '自由能与死光传说（后世神化对照条目）', '（传说语境）后世流传特斯拉掌握免费无限能源、定向能武器等。', '—（传说，非可考决策）', '成为流行文化中被压制的天才神话的核心素材。', '把被神化的传说与可考的工程成就分开——前者是文化想象，不能当作其真实方法或史实。', 'tertiary', 'legendary', 'published', '{"schema_version":1,"case_id":"tesla-c5","status":"published","title_period":"自由能与死光传说（后世神化对照条目）","dilemma_constraints":"（传说语境）后世流传特斯拉掌握免费无限能源、定向能武器等。","key_judgment":"—（传说，非可考决策）","model_invoked":[],"outcome":"成为流行文化中被压制的天才神话的核心素材。","transferable_lesson":"把被神化的传说与可考的工程成就分开——前者是文化想象，不能当作其真实方法或史实。","source_tier":"tertiary","source_note":"自由能/死光无可靠一手证据、属后世神化与流行文化演绎(C/传说)；仅作正史vs神话分层的对照条目，model_invoked置空、不挂真实模型。","historicity":"legendary","linked_cards":["tesla"],"tags":["探索未知"],"advisor_id":"tesla"}', 'e6a9de22f3040c88b64d8b62f936e0833aa774246e31902431d2b91ea19ddce1');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tesla-c6', 'tesla', '爱迪生偷走一切叙事（网络神话对照条目）', '（传说语境）流行叙事把爱迪生塑造成偷走特斯拉成果的反派。', '—（传说/简化叙事，非可考决策）', '成为网络上广为流传的善恶对立叙事。', '真实的电流之战是多方（爱迪生、西屋、特斯拉）的技术与商业博弈，远比天才被反派偷走一切的二元神话复杂——警惕被简化的英雄/反派叙事。', 'tertiary', 'legendary', 'published', '{"schema_version":1,"case_id":"tesla-c6","status":"published","title_period":"爱迪生偷走一切叙事（网络神话对照条目）","dilemma_constraints":"（传说语境）流行叙事把爱迪生塑造成偷走特斯拉成果的反派。","key_judgment":"—（传说/简化叙事，非可考决策）","model_invoked":[],"outcome":"成为网络上广为流传的善恶对立叙事。","transferable_lesson":"真实的电流之战是多方（爱迪生、西屋、特斯拉）的技术与商业博弈，远比天才被反派偷走一切的二元神话复杂——警惕被简化的英雄/反派叙事。","source_tier":"tertiary","source_note":"爱迪生偷走一切为高度简化的网络神话(C/传说)；史实上交流胜出涉西屋等多方。仅作对照、不当史实。","historicity":"legendary","linked_cards":["tesla"],"tags":["竞争博弈"],"advisor_id":"tesla"}', '8e06af0698a6fe150af3c3eadc3bf0a090668b848940e855804db7b14927d46f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('disney-c1', 'disney', '押身家做首部动画长片《白雪公主》（1934–1937）', '业界普遍认为观众坐不住90分钟动画（迪士尼的蠢事），预算严重超支、抵押身家。', '不顾唱衰，押上工作室与个人身家，坚持做出首部彩色动画长片，逐格打磨情感与角色。', '《白雪公主》1937年大获成功，开创动画长片产业。', '当一次跃迁被普遍唱衰、但你看准了底层趋势时，敢押身家做别人认为不可能的那一档，回报可能是开创一个品类。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"disney-c1","status":"published","title_period":"押身家做首部动画长片《白雪公主》（1934–1937）","dilemma_constraints":"业界普遍认为观众坐不住90分钟动画（迪士尼的蠢事），预算严重超支、抵押身家。","key_judgment":"不顾唱衰，押上工作室与个人身家，坚持做出首部彩色动画长片，逐格打磨情感与角色。","model_invoked":["押注式跃迁"],"outcome":"《白雪公主》1937年大获成功，开创动画长片产业。","transferable_lesson":"当一次跃迁被普遍唱衰、但你看准了底层趋势时，敢押身家做别人认为不可能的那一档，回报可能是开创一个品类。","source_tier":"secondary","source_note":"《白雪公主》制作与迪士尼的蠢事绰号为信史(B/权威传记)。","historicity":"confirmed","linked_cards":["disney"],"tags":["创新研发","风险评估"],"advisor_id":"disney"}', 'e0f2e73460bb1ed374cf4748dbf25877d7f200a874b6d93a7c4708f987d9c6f0');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('disney-c2', 'disney', '用同步声做《汽船威利》（1928）', '默片向有声转型期，动画加同步声技术与协调难度大、无成例。', '押注声音让观众更沉浸，做出首批画面与声音精确同步的动画短片。', '《汽船威利》成为有声动画里程碑，米老鼠一炮而红。', '引入新技术的判断标准不是它新不新，而是它能不能让观众的体验更深——技术服务于体验。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"disney-c2","status":"published","title_period":"用同步声做《汽船威利》（1928）","dilemma_constraints":"默片向有声转型期，动画加同步声技术与协调难度大、无成例。","key_judgment":"押注声音让观众更沉浸，做出首批画面与声音精确同步的动画短片。","model_invoked":["技术服务体验"],"outcome":"《汽船威利》成为有声动画里程碑，米老鼠一炮而红。","transferable_lesson":"引入新技术的判断标准不是它新不新，而是它能不能让观众的体验更深——技术服务于体验。","source_tier":"secondary","source_note":"《汽船威利》同步声为信史(B/多源)。","historicity":"confirmed","linked_cards":["disney"],"tags":["创新研发","表达说服"],"advisor_id":"disney"}', 'a8428d1a0fe44e4a21d0fd686b1416b230aa966ee23e5f1b665c45399e31b922');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('disney-c3', 'disney', '投入多平面摄影机做纵深感（约1937）', '平面动画缺乏景深，沉浸感受限；新设备昂贵、回报不确定。', '投资研发多平面摄影机，分层拍摄制造立体纵深，为体验质量买单。', '多平面摄影显著提升画面纵深，成为其动画质感标志。', '为体验深一层而做的看似昂贵的技术投入，往往构成别人难以追赶的质感壁垒。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"disney-c3","status":"published","title_period":"投入多平面摄影机做纵深感（约1937）","dilemma_constraints":"平面动画缺乏景深，沉浸感受限；新设备昂贵、回报不确定。","key_judgment":"投资研发多平面摄影机，分层拍摄制造立体纵深，为体验质量买单。","model_invoked":["技术服务体验"],"outcome":"多平面摄影显著提升画面纵深，成为其动画质感标志。","transferable_lesson":"为体验深一层而做的看似昂贵的技术投入，往往构成别人难以追赶的质感壁垒。","source_tier":"secondary","source_note":"多平面摄影机为信史(B)。","historicity":"confirmed","linked_cards":["disney"],"tags":["创新研发","商业模式与护城河"],"advisor_id":"disney"}', '0be717493f720d9cf6b596edef47b6c041807ca3046db45f92b8de6d1498ef60');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('disney-c4', 'disney', '建迪士尼乐园·整合式沉浸体验（1955）', '当时游乐园形象廉价杂乱；他要做故事化、全程掌控、无断点的沉浸空间，无成例、资金紧张。', '把故事、空间、技术、运营、服务整合成一个无缝闭环，掌控每个触点，开创主题乐园。', '迪士尼乐园1955年开幕，开创主题乐园品类，成为体验经济范本。', '强壁垒常来自把分散的触点整合成一个别人难以复制的无缝体验闭环，而非某个单点的强。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"disney-c4","status":"published","title_period":"建迪士尼乐园·整合式沉浸体验（1955）","dilemma_constraints":"当时游乐园形象廉价杂乱；他要做故事化、全程掌控、无断点的沉浸空间，无成例、资金紧张。","key_judgment":"把故事、空间、技术、运营、服务整合成一个无缝闭环，掌控每个触点，开创主题乐园。","model_invoked":["整合式体验"],"outcome":"迪士尼乐园1955年开幕，开创主题乐园品类，成为体验经济范本。","transferable_lesson":"强壁垒常来自把分散的触点整合成一个别人难以复制的无缝体验闭环，而非某个单点的强。","source_tier":"secondary","source_note":"迪士尼乐园为信史(B/多源)。","historicity":"confirmed","linked_cards":["disney"],"tags":["创新研发","商业模式与护城河"],"advisor_id":"disney"}', '3b8a3d164094a1000f82a3cf7aa0bed3d0c0544f13ff0a4826f6559682b689b1');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('disney-c5', 'disney', '1941年动画师大罢工（盲区案例）', '工作室扩张、薪酬与署名争议累积；他视工作室为大家庭，难以接受员工集体对抗。', '（反面教材）以家长式立场低估员工诉求，罢工激化、关系破裂。', '大罢工重创工作室氛围，部分核心人才离开，成为其管理盲区的标志事件。', '把一切纳入我的掌控/我的家庭的整合心态，用在体验上是优势、用在人身上会变成对人诉求的迟钝——对体验可掌控，对人需协商。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"disney-c5","status":"published","title_period":"1941年动画师大罢工（盲区案例）","dilemma_constraints":"工作室扩张、薪酬与署名争议累积；他视工作室为大家庭，难以接受员工集体对抗。","key_judgment":"（反面教材）以家长式立场低估员工诉求，罢工激化、关系破裂。","model_invoked":["整合式体验"],"outcome":"大罢工重创工作室氛围，部分核心人才离开，成为其管理盲区的标志事件。","transferable_lesson":"把一切纳入我的掌控/我的家庭的整合心态，用在体验上是优势、用在人身上会变成对人诉求的迟钝——对体验可掌控，对人需协商。","source_tier":"secondary","source_note":"1941动画师罢工为信史(B/多源)。本条为其整合掌控心态用在人身上的反面教材。","historicity":"confirmed","linked_cards":["disney"],"tags":["组织管理","人际关系"],"advisor_id":"disney"}', '1100cc545c3508ee417b5db35f180eb339f43b823b7cb1b3dadd469931d62957');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('schweitzer-c1', 'schweitzer', '30岁转向·弃学术艺术赴非行医（1905决定/1913赴非）', '已是欧洲卓有声望的神学家/哲学家/管风琴家/巴赫权威，前途光明；但21岁即private决心：享受学术艺术到30岁，之后献身直接服务。30岁后决定赴非行医，意味弃全部声望、从头读医学院、家人反对。', '兑现年轻时的预定转向——30岁起重读医学（读到38岁取得行医资格），1913年携妻赴法属赤道非洲兰巴雷内建医院行医。', '在兰巴雷内建丛林医院行医数十年；其"放弃一切去服务"成20世纪著名人生转向范例，后获诺贝尔和平奖。', '重大人生转向可以是"计划好的"而非被迫——先在一个领域积累到位、给自己设一个明确转折点，到点就把后半生整体投向更想成就的志业。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"schweitzer-c1","status":"published","title_period":"30岁转向·弃学术艺术赴非行医（1905决定/1913赴非）","dilemma_constraints":"已是欧洲卓有声望的神学家/哲学家/管风琴家/巴赫权威，前途光明；但21岁即private决心：享受学术艺术到30岁，之后献身直接服务。30岁后决定赴非行医，意味弃全部声望、从头读医学院、家人反对。","key_judgment":"兑现年轻时的预定转向——30岁起重读医学（读到38岁取得行医资格），1913年携妻赴法属赤道非洲兰巴雷内建医院行医。","model_invoked":["预定的转向"],"outcome":"在兰巴雷内建丛林医院行医数十年；其\"放弃一切去服务\"成20世纪著名人生转向范例，后获诺贝尔和平奖。","transferable_lesson":"重大人生转向可以是\"计划好的\"而非被迫——先在一个领域积累到位、给自己设一个明确转折点，到点就把后半生整体投向更想成就的志业。","source_tier":"secondary","source_note":"转向事实确证（传记B）；\"21岁立志\"之心路出自自传（A·自述），含回溯性建构。保守取低=B。","historicity":"confirmed","linked_cards":["schweitzer"],"tags":["人生抉择","职业发展"],"advisor_id":"schweitzer"}', '84bb2d5e9315f0f9fa760360c29e43eac527b9ee5c70a62959d4e0e923f486a6');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('schweitzer-c2', 'schweitzer', '提出"敬畏生命"伦理（1915）', '一战期间，史怀哲在非洲苦寻一个能统摄伦理的根本原则，长期不得其解，深感欧洲文明的伦理基础正在崩塌。', '据其自述，于溯河途中"敬畏生命"一词豁然涌现——他确立：伦理的根本是对一切生命的敬畏，善即保存促进生命、恶即毁坏阻碍生命。', '敬畏生命成其毕生伦理基石与世界性伦理命题，影响环境伦理、动物伦理等领域。', '与其在一堆具体规则里打转，不如去找一条能统摄全局的根本原则；一旦找到这个"地基"，上面的判断就有了统一依据。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"schweitzer-c2","status":"published","title_period":"提出\"敬畏生命\"伦理（1915）","dilemma_constraints":"一战期间，史怀哲在非洲苦寻一个能统摄伦理的根本原则，长期不得其解，深感欧洲文明的伦理基础正在崩塌。","key_judgment":"据其自述，于溯河途中\"敬畏生命\"一词豁然涌现——他确立：伦理的根本是对一切生命的敬畏，善即保存促进生命、恶即毁坏阻碍生命。","model_invoked":["敬畏生命"],"outcome":"敬畏生命成其毕生伦理基石与世界性伦理命题，影响环境伦理、动物伦理等领域。","transferable_lesson":"与其在一堆具体规则里打转，不如去找一条能统摄全局的根本原则；一旦找到这个\"地基\"，上面的判断就有了统一依据。","source_tier":"primary","source_note":"河上顿悟的戏剧性场景出自其自述/回忆（A·自述）、含叙事润色，标存疑；该伦理命题之提出与传播本身为公开可考事实（确证）。","historicity":"disputed","linked_cards":["schweitzer"],"tags":["价值与伦理","修身自省"],"advisor_id":"schweitzer"}', '7a8ce2f27601280836c6485a0d431f336b8941853f0e822102c13b722afde1e8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('schweitzer-c3', 'schweitzer', '以管风琴与巴赫著作筹资养医院（终身）', '在非洲办医院需持续资金物资，而他身处偏远、并无财源。', '他不放弃旧本事，而让它们为新使命服务——回欧洲办管风琴音乐会、出版巴赫研究与唱片，用所得资助兰巴雷内医院。', '医院得以长期维持运转；其多重身份（医生/音乐家/学者/作家）共同服务于一个目的。', '转向新志业不必抛弃旧本事——让你过去积累的所有技能都收拢来为新目的"供血"，一个人的多种能力可以协同养活一个使命。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"schweitzer-c3","status":"published","title_period":"以管风琴与巴赫著作筹资养医院（终身）","dilemma_constraints":"在非洲办医院需持续资金物资，而他身处偏远、并无财源。","key_judgment":"他不放弃旧本事，而让它们为新使命服务——回欧洲办管风琴音乐会、出版巴赫研究与唱片，用所得资助兰巴雷内医院。","model_invoked":["多能归一用"],"outcome":"医院得以长期维持运转；其多重身份（医生/音乐家/学者/作家）共同服务于一个目的。","transferable_lesson":"转向新志业不必抛弃旧本事——让你过去积累的所有技能都收拢来为新目的\"供血\"，一个人的多种能力可以协同养活一个使命。","source_tier":"primary","source_note":"演奏筹资、巴赫著述、医院维持为多源可考事实→确证。","historicity":"confirmed","linked_cards":["schweitzer"],"tags":["资源调度","职业发展"],"advisor_id":"schweitzer"}', 'ec26ffd4b6ed2349cbfc51c82b65cf1577afd87d98a71ecee3aea72c82440c39');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('schweitzer-c4', 'schweitzer', '以一生而非言辞作为伦理论证（终身）', '作为伦理思想家，他大可继续在欧洲著书宣讲；但他认为光说不做的伦理是空的。', '他选择"让我的一生成为我的论证"——不靠雄辩说服世人，而用几十年丛林行医的实际生命去示范他所信的伦理。', '其人格与一生的示范力远超其论著的说服力，使"敬畏生命"具道德感召力；但也因门槛极高而难被普通人效法。', '想让别人相信你的信念，最有力的不是论证，而是把它活出来——用你怎么过这一生去示范你主张的东西。（诚实：这种圣徒式标准对常人不可复制。）', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"schweitzer-c4","status":"published","title_period":"以一生而非言辞作为伦理论证（终身）","dilemma_constraints":"作为伦理思想家，他大可继续在欧洲著书宣讲；但他认为光说不做的伦理是空的。","key_judgment":"他选择\"让我的一生成为我的论证\"——不靠雄辩说服世人，而用几十年丛林行医的实际生命去示范他所信的伦理。","model_invoked":["以生命为论证"],"outcome":"其人格与一生的示范力远超其论著的说服力，使\"敬畏生命\"具道德感召力；但也因门槛极高而难被普通人效法。","transferable_lesson":"想让别人相信你的信念，最有力的不是论证，而是把它活出来——用你怎么过这一生去示范你主张的东西。（诚实：这种圣徒式标准对常人不可复制。）","source_tier":"secondary","source_note":"其一生行迹为信史→确证。其殖民时代家长式态度争议见 blind_spots，客观标注、不美化。","historicity":"confirmed","linked_cards":["schweitzer"],"tags":["价值与伦理","人生抉择"],"advisor_id":"schweitzer"}', '82a52be1ee3375a8b07d0374154182b9a977e5298b49ab7d361c1c15c5b2a9ef');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('schweitzer-c5', 'schweitzer', '反复重返非洲坚守医院（一战后、二战后多次往返）', '每次因筹资/战争/健康回欧洲，他都可选择留在舒适、有声望的欧洲安度晚年；兰巴雷内条件艰苦、医院屡因战乱受损。', '他一次次放弃欧洲安逸、重返非洲重建并坚守医院，把"偿还亏欠"贯彻到底，直至90岁高龄仍在兰巴雷内。', '兰巴雷内医院在他坚守下延续数十年；他以一生反复的抉择兑现了"用亲手行动还债"的信念。', '这种"还债式"的责任不是一次性壮举，而是反复的选择——每一次可以选舒适却仍选回到承担，才真正兑现那份亏欠感。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"schweitzer-c5","status":"published","title_period":"反复重返非洲坚守医院（一战后、二战后多次往返）","dilemma_constraints":"每次因筹资/战争/健康回欧洲，他都可选择留在舒适、有声望的欧洲安度晚年；兰巴雷内条件艰苦、医院屡因战乱受损。","key_judgment":"他一次次放弃欧洲安逸、重返非洲重建并坚守医院，把\"偿还亏欠\"贯彻到底，直至90岁高龄仍在兰巴雷内。","model_invoked":["行动还债"],"outcome":"兰巴雷内医院在他坚守下延续数十年；他以一生反复的抉择兑现了\"用亲手行动还债\"的信念。","transferable_lesson":"这种\"还债式\"的责任不是一次性壮举，而是反复的选择——每一次可以选舒适却仍选回到承担，才真正兑现那份亏欠感。","source_tier":"secondary","source_note":"多次往返坚守为信史→确证。","historicity":"confirmed","linked_cards":["schweitzer"],"tags":["价值与伦理","人生抉择"],"advisor_id":"schweitzer"}', 'ced5daa4b2c0294b79dcf04463bd72ddf595101206f02259929c77414311f493');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('simaqian-c1', 'simaqian', '李陵之祸 · 选择宫刑而非死（约前99–98）', '为李陵辩护触怒武帝，定"诬罔"死罪。死罪三选一：伏死/赎钱五十万/宫刑；家贫无力赎、无人相救。父托与已动笔的《史记》未竟——体面赴死，还是受奇耻大辱而活？', '选择宫刑，以终生屈辱换活着完成《史记》。逻辑：此刻一死只"轻于鸿毛"地保面子，书未成则死无分量；为重于生命的未竟之事忍辱苟活。', '受刑后任中书令，忍辱完成《史记》一百三十篇——中国第一部纪传体通史；个人受终生屈辱，作品不朽。', '面对"体面退场vs屈辱坚持"，标尺不是哪个更不丢人，而是"是否有一件重到值得承受此屈辱去完成的事"。有，屈辱只是过程；没有，也许该体面离开。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"simaqian-c1","status":"published","title_period":"李陵之祸 · 选择宫刑而非死（约前99–98）","dilemma_constraints":"为李陵辩护触怒武帝，定\"诬罔\"死罪。死罪三选一：伏死/赎钱五十万/宫刑；家贫无力赎、无人相救。父托与已动笔的《史记》未竟——体面赴死，还是受奇耻大辱而活？","key_judgment":"选择宫刑，以终生屈辱换活着完成《史记》。逻辑：此刻一死只\"轻于鸿毛\"地保面子，书未成则死无分量；为重于生命的未竟之事忍辱苟活。","model_invoked":["轻重权衡"],"outcome":"受刑后任中书令，忍辱完成《史记》一百三十篇——中国第一部纪传体通史；个人受终生屈辱，作品不朽。","transferable_lesson":"面对\"体面退场vs屈辱坚持\"，标尺不是哪个更不丢人，而是\"是否有一件重到值得承受此屈辱去完成的事\"。有，屈辱只是过程；没有，也许该体面离开。","source_tier":"secondary","source_note":"事件（辩护→定罪→受刑→完成《史记》）见《汉书·司马迁传》(B)第三方交叉印证→确证；内心\"轻重\"权衡之由出自本人《报任安书》(A·自述)，含自我归因风险。保守取低=B。","historicity":"confirmed","linked_cards":["simaqian"],"tags":["人生抉择","价值与伦理"],"advisor_id":"simaqian"}', '638f3796b2b4aff4a54a70ce722ba8105c72c0d7a24cc08e4f9efc3431242c7e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('simaqian-c2', 'simaqian', '继承父志 · 接过《史记》之命（约前110）', '父司马谈任太史令，毕生欲修通史而未竟，临终执手泣嘱务必完成。修史耗尽一生、无即时回报；接下意味把整个人生绑定在一件可能看不到尽头的事上。', '郑重领命，将完成《史记》立为人生志业（立言）；父丧后约三年继任太史令，正式承接其事。', '此承诺成为日后绝境（宫刑）中仍选择活下去的根本理由——先有重于泰山之事，后来的屈辱才有承受意义。', '一个足够重的长期承诺，会在你未来遭遇绝境时成为"为什么还要撑下去"的锚。先有"值得为之的事"，绝境中的选择才有依凭。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"simaqian-c2","status":"published","title_period":"继承父志 · 接过《史记》之命（约前110）","dilemma_constraints":"父司马谈任太史令，毕生欲修通史而未竟，临终执手泣嘱务必完成。修史耗尽一生、无即时回报；接下意味把整个人生绑定在一件可能看不到尽头的事上。","key_judgment":"郑重领命，将完成《史记》立为人生志业（立言）；父丧后约三年继任太史令，正式承接其事。","model_invoked":["长远评判优先"],"outcome":"此承诺成为日后绝境（宫刑）中仍选择活下去的根本理由——先有重于泰山之事，后来的屈辱才有承受意义。","transferable_lesson":"一个足够重的长期承诺，会在你未来遭遇绝境时成为\"为什么还要撑下去\"的锚。先有\"值得为之的事\"，绝境中的选择才有依凭。","source_tier":"primary","source_note":"父临终泣嘱情景与领命仅见本人《史记·太史公自序》(A·自述)，无第三方交叉印证、存自述润色风险→historicity 存疑（继任太史令一事可考，B）。","historicity":"disputed","linked_cards":["simaqian"],"tags":["人生抉择","长期规划"],"advisor_id":"simaqian"}', '3ac5682106896d1f01d4e7b1d546661b4a41948e6450a1602330f63be5d99a8a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('simaqian-c3', 'simaqian', '实录 · 不为尊者讳（《史记》写作中）', '身处武帝朝、自身已因直言受刑；政治高压下写当朝与开国之事，最安全是歌功颂德、隐恶扬善——但他要写的是"实录"。', '坚持不虚美、不隐恶：写刘邦雄才也不讳其无赖残忍，录武帝功也书其求仙酷吏；项羽入"本纪"、平民陈涉入"世家"，按历史分量而非官位排笔法。', '《史记》获后世"实录"之誉（班固语），成信史典范；对汉室的直笔亦成其政治上的进一步风险。', '要留下"经得起时间检验"的记录/作品/判断，对你所依附的权力、所敬爱的人保持诚实，比讨好当下更重要——真实是作品穿越时间的唯一通行证。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"simaqian-c3","status":"published","title_period":"实录 · 不为尊者讳（《史记》写作中）","dilemma_constraints":"身处武帝朝、自身已因直言受刑；政治高压下写当朝与开国之事，最安全是歌功颂德、隐恶扬善——但他要写的是\"实录\"。","key_judgment":"坚持不虚美、不隐恶：写刘邦雄才也不讳其无赖残忍，录武帝功也书其求仙酷吏；项羽入\"本纪\"、平民陈涉入\"世家\"，按历史分量而非官位排笔法。","model_invoked":["直面真实"],"outcome":"《史记》获后世\"实录\"之誉（班固语），成信史典范；对汉室的直笔亦成其政治上的进一步风险。","transferable_lesson":"要留下\"经得起时间检验\"的记录/作品/判断，对你所依附的权力、所敬爱的人保持诚实，比讨好当下更重要——真实是作品穿越时间的唯一通行证。","source_tier":"primary","source_note":"编纂取舍（项羽入本纪、陈涉入世家、不虚美隐恶）由《史记》文本(A)直接可验→确证；\"实录\"之评见《汉书》班固赞(B)。","historicity":"confirmed","linked_cards":["simaqian"],"tags":["表达说服","价值与伦理"],"advisor_id":"simaqian"}', '0c782dd9b1a45c2ed79acb00dcdf040f4e76d306f8ca9298e38719aa3f9a470f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('simaqian-c4', 'simaqian', '壮游天下 · 实地考据（约前126前后）', '修史若只靠宫廷藏书易失之纸面。年轻的司马迁面临方法选择：闭门读典籍，还是亲历山川、访遗老、踏勘历史现场？', '自二十岁起壮游天下：南至江淮会稽沅湘、北涉汶泗，访孔子遗风、观楚汉战场，采口碑考遗迹，"读万卷书"与"行万里路"结合。', '《史记》多处记述带亲历的现场感与细节真实，叙事生动可信，是其兼具史学与文学价值的重要原因之一。', '要真正理解一件事（市场/组织/历史），别只看二手报告——去现场、找当事人、采一手信息。判断质量取决于信息的层级。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"simaqian-c4","status":"published","title_period":"壮游天下 · 实地考据（约前126前后）","dilemma_constraints":"修史若只靠宫廷藏书易失之纸面。年轻的司马迁面临方法选择：闭门读典籍，还是亲历山川、访遗老、踏勘历史现场？","key_judgment":"自二十岁起壮游天下：南至江淮会稽沅湘、北涉汶泗，访孔子遗风、观楚汉战场，采口碑考遗迹，\"读万卷书\"与\"行万里路\"结合。","model_invoked":["直面真实"],"outcome":"《史记》多处记述带亲历的现场感与细节真实，叙事生动可信，是其兼具史学与文学价值的重要原因之一。","transferable_lesson":"要真正理解一件事（市场/组织/历史），别只看二手报告——去现场、找当事人、采一手信息。判断质量取决于信息的层级。","source_tier":"primary","source_note":"壮游经历出自本人《史记·太史公自序》(A·自述)，史界多采信、《史记》内证可旁佐，然行程细节属自述、缺独立第三方→historicity 存疑。","historicity":"disputed","linked_cards":["simaqian"],"tags":["探索未知","学习与认知"],"advisor_id":"simaqian"}', '5dfde52710ca712404bc081a095dfeae5b9ce8a0fa6643164a93b54b2e66419e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('columbus-c1', 'columbus', '游说多国王室约8年·锲而不舍推销愿景（1480s—1492）', '「向西航行到亚洲」的设想不被多数人看好、缺乏资助。', '哥伦布先后向葡萄牙、西班牙等多国王室反复游说、屡遭拒绝与搁置，前后约8年不放弃，终获西班牙王室资助。', '哥伦布终于争取到了远航的资助。', '为一个不被看好的设想，不屈不挠地向一个个潜在支持者反复游说、争取——被拒多次也不放弃。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"columbus-c1","status":"published","title_period":"游说多国王室约8年·锲而不舍推销愿景（1480s—1492）","dilemma_constraints":"「向西航行到亚洲」的设想不被多数人看好、缺乏资助。","key_judgment":"哥伦布先后向葡萄牙、西班牙等多国王室反复游说、屡遭拒绝与搁置，前后约8年不放弃，终获西班牙王室资助。","model_invoked":["锲而不舍推销愿景"],"outcome":"哥伦布终于争取到了远航的资助。","transferable_lesson":"为一个不被看好的设想，不屈不挠地向一个个潜在支持者反复游说、争取——被拒多次也不放弃。","source_tier":"secondary","source_note":"哥伦布游说多国王室约8年终获资助为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["columbus"],"tags":["创新","竞争博弈"],"advisor_id":"columbus"}', '1b8fa6637e639df82058224a78c4e3056da1a729c0618b5598d577bda281b0c2');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('columbus-c2', 'columbus', '1492年横渡大西洋·敢于驶向未知（1492）', '当时无人横渡过这片未知的大洋，风险与不确定极大。', '哥伦布敢于率船队驶离熟悉的海岸、横渡完全未知的大西洋，最终到达了美洲。', '哥伦布的航行开启了"大航海"与新旧大陆的接触，但也开启了对美洲的殖民、给原住民带来深重灾难（须正视、不美化）。', '敢于在别人都说不可能时驶向未知——但其判断建立在错误估算上、且其"发现"酿成殖民灾难，须客观正视。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"columbus-c2","status":"published","title_period":"1492年横渡大西洋·敢于驶向未知（1492）","dilemma_constraints":"当时无人横渡过这片未知的大洋，风险与不确定极大。","key_judgment":"哥伦布敢于率船队驶离熟悉的海岸、横渡完全未知的大西洋，最终到达了美洲。","model_invoked":["敢于驶向未知"],"outcome":"哥伦布的航行开启了\"大航海\"与新旧大陆的接触，但也开启了对美洲的殖民、给原住民带来深重灾难（须正视、不美化）。","transferable_lesson":"敢于在别人都说不可能时驶向未知——但其判断建立在错误估算上、且其\"发现\"酿成殖民灾难，须客观正视。","source_tier":"secondary","source_note":"哥伦布1492年横渡大西洋为史实→确证（二手B；其殖民影响须严肃正视）。","historicity":"confirmed","linked_cards":["columbus"],"tags":["创新","危机应对"],"advisor_id":"columbus"}', 'd4874cd90a42d1986743529d2eea6817be65922fc1bd8abc4f78e09565299a7a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('columbus-c3', 'columbus', '船员动摇时坚持西行·信念坚定与稳住人心（1492航程中）', '航程远超预期、迟迟不见陆地、船员恐惧几近哗变。', '哥伦布稳住动摇的人心、说服船员再航行几天，不久便发现了陆地。', '坚持到了最后，终于发现陆地。', '认定方向后坚定行动、在同伴动摇时稳住人心、再坚持一下——但要分清坚定与固执。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"columbus-c3","status":"published","title_period":"船员动摇时坚持西行·信念坚定与稳住人心（1492航程中）","dilemma_constraints":"航程远超预期、迟迟不见陆地、船员恐惧几近哗变。","key_judgment":"哥伦布稳住动摇的人心、说服船员再航行几天，不久便发现了陆地。","model_invoked":["信念坚定与稳住人心"],"outcome":"坚持到了最后，终于发现陆地。","transferable_lesson":"认定方向后坚定行动、在同伴动摇时稳住人心、再坚持一下——但要分清坚定与固执。","source_tier":"secondary","source_note":"哥伦布船员动摇时坚持为史述→确证（二手B）。","historicity":"confirmed","linked_cards":["columbus"],"tags":["危机应对","领导力"],"advisor_id":"columbus"}', 'd0df0687eed6a575ca028781983ddd3078148468bb4db5430c3cc80a3573b0e0');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('columbus-c4', 'columbus', '宣告发现、争取后续航行·把握并放大机会（1493起）', '一次发现如何变成持续的事业。', '哥伦布回程后迅速宣告其"发现"、确立功劳与封赏，并争取到了后续的多次航行。', '哥伦布共进行了四次航行；但他至死误以为到达的是亚洲，且后续航行是殖民的开端（须正视）。', '敏锐意识到机会的价值、迅速宣告、确立、争取资源去放大它——但也要看清机会的真实性质。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"columbus-c4","status":"published","title_period":"宣告发现、争取后续航行·把握并放大机会（1493起）","dilemma_constraints":"一次发现如何变成持续的事业。","key_judgment":"哥伦布回程后迅速宣告其\"发现\"、确立功劳与封赏，并争取到了后续的多次航行。","model_invoked":["把握并放大机会"],"outcome":"哥伦布共进行了四次航行；但他至死误以为到达的是亚洲，且后续航行是殖民的开端（须正视）。","transferable_lesson":"敏锐意识到机会的价值、迅速宣告、确立、争取资源去放大它——但也要看清机会的真实性质。","source_tier":"secondary","source_note":"哥伦布宣告发现、四次航行为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["columbus"],"tags":["创新","竞争博弈"],"advisor_id":"columbus"}', '179f1ab5214759bd4817d947f07ca73874c12dc153570cd85a9baf9a86159ec2');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('frankl-c1', 'frankl', '留维也纳陪父母·不逃往美国（1941）', '已获赴美签证（可逃离迫害、续事业），但年迈父母无法同行、必留维也纳面对厄运；签证有期，机会稍纵即逝。自保事业，还是留下陪父母？', '在犹疑中，他以父亲从被砸毁的犹太会堂带回、刻有十诫"孝敬父母"残字的大理石片为指引，决定放弃签证、留维也纳陪父母。', '他留下，后与家人一同被捕入集中营；父母、妻、兄弟均遇难，唯他幸存。他从未后悔此抉择，这段经历亦成其意义理论的源头。', '面对"自保前程 vs 守护所爱"的抉择，意义疗法不给标准答案，而让你问：哪个选择让你成为你认可的自己？有时放弃机会去守护一个人，本身就是意义。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"frankl-c1","status":"published","title_period":"留维也纳陪父母·不逃往美国（1941）","dilemma_constraints":"已获赴美签证（可逃离迫害、续事业），但年迈父母无法同行、必留维也纳面对厄运；签证有期，机会稍纵即逝。自保事业，还是留下陪父母？","key_judgment":"在犹疑中，他以父亲从被砸毁的犹太会堂带回、刻有十诫\"孝敬父母\"残字的大理石片为指引，决定放弃签证、留维也纳陪父母。","model_invoked":["自我超越"],"outcome":"他留下，后与家人一同被捕入集中营；父母、妻、兄弟均遇难，唯他幸存。他从未后悔此抉择，这段经历亦成其意义理论的源头。","transferable_lesson":"面对\"自保前程 vs 守护所爱\"的抉择，意义疗法不给标准答案，而让你问：哪个选择让你成为你认可的自己？有时放弃机会去守护一个人，本身就是意义。","source_tier":"primary","source_note":"大理石残片的戏剧性细节出自其自述/回忆（A·自述），含记忆与叙事润色风险；放弃赴美、留维也纳陪父母之大方向有传记佐证（B）。","historicity":"disputed","linked_cards":["frankl"],"tags":["人生抉择","价值与伦理"],"advisor_id":"frankl"}', '19597c339c51d7760627e1a4f831e628b629d729c3d38a42727b049290ba3d02');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('frankl-c2', 'frankl', '集中营中守住"选择态度的自由"（1942–1945）', '被囚集中营，丧失一切——亲人、自由、姓名（被编号）、尊严，每日面对死亡与极端非人待遇；外部处境彻底不可控。', '他意识到纵使一切被剥夺，仍有一样无人能夺——在既定处境中选择态度的自由；他刻意守护内在精神自由，观察记录囚徒心理，把苦难当可被赋予意义的对象。', '这一认识使他在绝境中精神不溃散；战后凝结为《活出生命的意义》，影响全球数千万人。', '当外部一切被夺走、你什么都改不了时，仍有最后一样属于你：选择以何种态度面对它。守住这一点，绝境就夺不走你的全部。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"frankl-c2","status":"published","title_period":"集中营中守住\"选择态度的自由\"（1942–1945）","dilemma_constraints":"被囚集中营，丧失一切——亲人、自由、姓名（被编号）、尊严，每日面对死亡与极端非人待遇；外部处境彻底不可控。","key_judgment":"他意识到纵使一切被剥夺，仍有一样无人能夺——在既定处境中选择态度的自由；他刻意守护内在精神自由，观察记录囚徒心理，把苦难当可被赋予意义的对象。","model_invoked":["刺激回应之隙"],"outcome":"这一认识使他在绝境中精神不溃散；战后凝结为《活出生命的意义》，影响全球数千万人。","transferable_lesson":"当外部一切被夺走、你什么都改不了时，仍有最后一样属于你：选择以何种态度面对它。守住这一点，绝境就夺不走你的全部。","source_tier":"primary","source_note":"回忆录系本人事后书写，含叙事建构与意义赋予的回溯性润色；集中营之存在与暴行为信史（确证），但其个人心理历程之具体叙述属自述、标存疑。","historicity":"disputed","linked_cards":["frankl"],"tags":["修身自省","价值与伦理"],"advisor_id":"frankl"}', 'a1f506926dd9ceae3f607f83678c9314e46ab4971b165e374d039fdbd4723bc8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('frankl-c3', 'frankl', '靠"未来要做的事"撑过最绝望时刻（营中）', '集中营某段最绝望、几近放弃的时刻（疾病、饥饿、看不到尽头），求生意志濒临崩溃。', '他强迫自己想象未来——想象战后站在讲台上向听众讲授"集中营心理学"这门课；以一个具体未来任务作为"为何而活"的锚，把自己从当下绝望中拉出。', '这一未来指向帮他熬过最黑暗的时刻；战后他果真完成了这一"任务"（创立意义疗法、著书、全球讲学）。', '在看不到尽头的苦难里，给自己设一个具体的未来任务或承诺——一个"等我出去要去做的事"——用未来的why把自己从当下绝望里拽出来。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"frankl-c3","status":"published","title_period":"靠\"未来要做的事\"撑过最绝望时刻（营中）","dilemma_constraints":"集中营某段最绝望、几近放弃的时刻（疾病、饥饿、看不到尽头），求生意志濒临崩溃。","key_judgment":"他强迫自己想象未来——想象战后站在讲台上向听众讲授\"集中营心理学\"这门课；以一个具体未来任务作为\"为何而活\"的锚，把自己从当下绝望中拉出。","model_invoked":["为何而活"],"outcome":"这一未来指向帮他熬过最黑暗的时刻；战后他果真完成了这一\"任务\"（创立意义疗法、著书、全球讲学）。","transferable_lesson":"在看不到尽头的苦难里，给自己设一个具体的未来任务或承诺——一个\"等我出去要去做的事\"——用未来的why把自己从当下绝望里拽出来。","source_tier":"primary","source_note":"自述类·回忆录，含回溯性润色，标存疑。","historicity":"disputed","linked_cards":["frankl"],"tags":["修身自省","人生抉择"],"advisor_id":"frankl"}', 'c0a5f23c41655d687daac317ddd3fdd1951409d8836bbb4c4dca8716c60b000d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('frankl-c4', 'frankl', '创立意义疗法·把苦难转为助人体系（战后）', '战后失去几乎全部至亲、自身带巨大创伤；他可沉于悲痛仇恨，也可把经历转化为别的东西。', '他选择把集中营的极端经验提炼为助人理论——意义疗法，系统阐述意义来源与寻找方法，并发展矛盾意向、去反思等临床技术帮助他人。', '《活出生命的意义》成20世纪最有影响力的著作之一；意义疗法成存在主义心理治疗重要流派，帮助无数人。', '把你受过的苦转化为能帮到别人的东西，是赋予苦难意义的最有力方式之一——苦难本身没有意义，但你对它采取的"转化"态度可以创造意义。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"frankl-c4","status":"published","title_period":"创立意义疗法·把苦难转为助人体系（战后）","dilemma_constraints":"战后失去几乎全部至亲、自身带巨大创伤；他可沉于悲痛仇恨，也可把经历转化为别的东西。","key_judgment":"他选择把集中营的极端经验提炼为助人理论——意义疗法，系统阐述意义来源与寻找方法，并发展矛盾意向、去反思等临床技术帮助他人。","model_invoked":["自我超越"],"outcome":"《活出生命的意义》成20世纪最有影响力的著作之一；意义疗法成存在主义心理治疗重要流派，帮助无数人。","transferable_lesson":"把你受过的苦转化为能帮到别人的东西，是赋予苦难意义的最有力方式之一——苦难本身没有意义，但你对它采取的\"转化\"态度可以创造意义。","source_tier":"primary","source_note":"意义疗法的创立与传播为公开学术/出版事实→确证（与C1–C3回忆录自述存疑形成二轴对照）。","historicity":"confirmed","linked_cards":["frankl"],"tags":["价值与伦理","修身自省"],"advisor_id":"frankl"}', '0d69e5c8edfba50ab0a27e9b3450bafee988ac7f2dffc44b199ca9f345f666c9');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('frankl-c5', 'frankl', '矛盾意向法的临床运用', '患者受某种焦虑/恐惧困扰（如越怕出汗越出汗、越怕失眠越失眠），陷"害怕症状—症状加重"恶性循环，常规劝慰无效。', '他反其道而行，指导患者主动去"意愿"那个所怕之事（如"你尽量让自己多出汗给大家看"），用幽默与悖论打断恐惧—强化的循环。', '许多患者预期性焦虑迅速缓解；矛盾意向成意义疗法标志性技术，被纳入认知行为治疗的发展脉络。', '当你越害怕某反应它就越发生时（失眠、脸红、出汗、口吃），试着反向"邀请"它发生——一旦不再抗拒，恐惧驱动的循环就松开了。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"frankl-c5","status":"published","title_period":"矛盾意向法的临床运用","dilemma_constraints":"患者受某种焦虑/恐惧困扰（如越怕出汗越出汗、越怕失眠越失眠），陷\"害怕症状—症状加重\"恶性循环，常规劝慰无效。","key_judgment":"他反其道而行，指导患者主动去\"意愿\"那个所怕之事（如\"你尽量让自己多出汗给大家看\"），用幽默与悖论打断恐惧—强化的循环。","model_invoked":["矛盾意向"],"outcome":"许多患者预期性焦虑迅速缓解；矛盾意向成意义疗法标志性技术，被纳入认知行为治疗的发展脉络。","transferable_lesson":"当你越害怕某反应它就越发生时（失眠、脸红、出汗、口吃），试着反向\"邀请\"它发生——一旦不再抗拒，恐惧驱动的循环就松开了。","source_tier":"primary","source_note":"矛盾意向技术及其临床应用为可考的学术事实→确证（方法演示型案例）。","historicity":"confirmed","linked_cards":["frankl"],"tags":["修身自省","学习与认知"],"advisor_id":"frankl"}', 'c958a4578ccfb42fe928e4c73579776d599603a3339d0260ee302de29e4da615');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhangqian-c1', 'zhangqian', '受命出使月氏·踏入未知（前138）', '汉武帝欲联月氏夹击匈奴，但月氏远在西域、道路全经匈奴控制区、无人知其确切所在、九死一生。', '张骞应募持节出使，率百余人踏入完全未知、敌控的西域。', '开启通往西域的第一次官方探索，史称"凿空"。', '一条没人走过、没有地图的路，恰恰可能是最有开拓价值的方向——开路本身的价值，往往在出发时无法估量。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhangqian-c1","status":"published","title_period":"受命出使月氏·踏入未知（前138）","dilemma_constraints":"汉武帝欲联月氏夹击匈奴，但月氏远在西域、道路全经匈奴控制区、无人知其确切所在、九死一生。","key_judgment":"张骞应募持节出使，率百余人踏入完全未知、敌控的西域。","model_invoked":["凿空"],"outcome":"开启通往西域的第一次官方探索，史称\"凿空\"。","transferable_lesson":"一条没人走过、没有地图的路，恰恰可能是最有开拓价值的方向——开路本身的价值，往往在出发时无法估量。","source_tier":"secondary","source_note":"出使月氏为信史（《史记》《汉书》）；司马迁去张骞时代未远，记述可信。","historicity":"confirmed","linked_cards":["zhangqian"],"tags":["探索未知","长期规划"],"advisor_id":"zhangqian"}', '819ff17d7322dc7a4ff4083243061ced0fe3a6f4316313ce58b3ea387f9d9f8a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhangqian-c2', 'zhangqian', '匈奴羁留十余年·持节不失、隐忍求存（前138起）', '出使途中即被匈奴俘获、扣留十余年，匈奴给他娶妻生子以羁縻同化。', '他灵活隐忍、先在匈奴活下来，却始终保留汉节、不忘出使月氏的使命，寻机逃脱继续西行。', '终乘隙逃离匈奴、继续西行抵达月氏（虽月氏已无意东返）。', '长期被困、甚至被环境同化（成家、安居）时，守住你最初的使命凭信与身份认同——同时灵活求存、先活下来保全自己，是日后还能重新出发的根。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhangqian-c2","status":"published","title_period":"匈奴羁留十余年·持节不失、隐忍求存（前138起）","dilemma_constraints":"出使途中即被匈奴俘获、扣留十余年，匈奴给他娶妻生子以羁縻同化。","key_judgment":"他灵活隐忍、先在匈奴活下来，却始终保留汉节、不忘出使月氏的使命，寻机逃脱继续西行。","model_invoked":["持节不失"],"outcome":"终乘隙逃离匈奴、继续西行抵达月氏（虽月氏已无意东返）。","transferable_lesson":"长期被困、甚至被环境同化（成家、安居）时，守住你最初的使命凭信与身份认同——同时灵活求存、先活下来保全自己，是日后还能重新出发的根。","source_tier":"secondary","source_note":"羁留/逃脱为信史；娶妻生子等细节史载，个别心理属推断（二轴：事件确证、动机存推断）。","historicity":"confirmed","linked_cards":["zhangqian"],"tags":["探索未知","风险评估"],"advisor_id":"zhangqian"}', '9a439b1b3b772a93fa6c623cf5e29069781d14278aa2ebff48f30189c4ef0c14');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhangqian-c3', 'zhangqian', '月氏拒盟·原目标失败但带回西域全貌', '历尽艰辛抵达月氏，月氏已西迁安居、无意再与匈奴为敌，联盟目标彻底失败。', '不因空手而沮丧放弃，转而详察大宛、康居、大夏、月氏诸国的地理、风物、实力，带回汉廷前所未有的西域全貌。', '联盟虽败，其情报却开启了汉对西域的经营与丝绸之路——副产品远超原目标。', '当你倾力的原目标失败，别急着全盘否定这趟努力——系统盘点途中积累的副产品（情报、见闻、关系），它可能比原目标更有价值。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhangqian-c3","status":"published","title_period":"月氏拒盟·原目标失败但带回西域全貌","dilemma_constraints":"历尽艰辛抵达月氏，月氏已西迁安居、无意再与匈奴为敌，联盟目标彻底失败。","key_judgment":"不因空手而沮丧放弃，转而详察大宛、康居、大夏、月氏诸国的地理、风物、实力，带回汉廷前所未有的西域全貌。","model_invoked":["副产致胜"],"outcome":"联盟虽败，其情报却开启了汉对西域的经营与丝绸之路——副产品远超原目标。","transferable_lesson":"当你倾力的原目标失败，别急着全盘否定这趟努力——系统盘点途中积累的副产品（情报、见闻、关系），它可能比原目标更有价值。","source_tier":"secondary","source_note":"月氏拒盟、带回西域情报为信史。","historicity":"confirmed","linked_cards":["zhangqian"],"tags":["探索未知","风险评估"],"advisor_id":"zhangqian"}', '136b5fb3ff451d38d3e49a6e4ba3f0dbc9fbc45567570494e33271b887296bef');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhangqian-c4', 'zhangqian', '归报西域诸国情状·见闻转化为经营情报（前126后）', '历经十三年才返汉、随行百余人仅余二人；如何让这趟惨重的远行真正产生价值。', '张骞向汉廷系统归报大宛、康居、大夏、月氏诸国的地理、物产、实力与路线，把旅途见闻转化为可指导决策的战略情报。', '这套情报成汉经营西域、再通西南夷与开丝绸之路的依据，影响深远。', '别把一手见闻只当奇闻——把地理、物产、各方实力、路线系统转化为可指导决策的情报，一趟远行的真正价值才落得实。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhangqian-c4","status":"published","title_period":"归报西域诸国情状·见闻转化为经营情报（前126后）","dilemma_constraints":"历经十三年才返汉、随行百余人仅余二人；如何让这趟惨重的远行真正产生价值。","key_judgment":"张骞向汉廷系统归报大宛、康居、大夏、月氏诸国的地理、物产、实力与路线，把旅途见闻转化为可指导决策的战略情报。","model_invoked":["见闻即情报"],"outcome":"这套情报成汉经营西域、再通西南夷与开丝绸之路的依据，影响深远。","transferable_lesson":"别把一手见闻只当奇闻——把地理、物产、各方实力、路线系统转化为可指导决策的情报，一趟远行的真正价值才落得实。","source_tier":"secondary","source_note":"归报西域诸国情状为《史记·大宛列传》信史→确证。","historicity":"confirmed","linked_cards":["zhangqian"],"tags":["探索未知","长期规划"],"advisor_id":"zhangqian"}', '6491677ae62f0474cc3db4b39bd7f60cdcacd6a75c21d03aa61c1b87080458c4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('xuxiake-c1', 'xuxiake', '弃科举·立志远游（青年）', '明代士人正途是科举入仕、追求功名；偏离即被视为不务正业。', '徐霞客无意功名，主动脱离科举仕途的既定阶梯，把一生投向地理考察与求知本身。', '终身远游三十余年，成中国古代最伟大的地理学家、旅行家之一。', '被功名/既定成功阶梯套住时，为你真正好奇的事而活——但须诚实衡量自己的生计约束（其前提是有家底、无生计之忧）。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"xuxiake-c1","status":"published","title_period":"弃科举·立志远游（青年）","dilemma_constraints":"明代士人正途是科举入仕、追求功名；偏离即被视为不务正业。","key_judgment":"徐霞客无意功名，主动脱离科举仕途的既定阶梯，把一生投向地理考察与求知本身。","model_invoked":["为知而活"],"outcome":"终身远游三十余年，成中国古代最伟大的地理学家、旅行家之一。","transferable_lesson":"被功名/既定成功阶梯套住时，为你真正好奇的事而活——但须诚实衡量自己的生计约束（其前提是有家底、无生计之忧）。","source_tier":"secondary","source_note":"弃科举、终身远游为传述与《游记》自述→确证。","historicity":"confirmed","linked_cards":["xuxiake"],"tags":["人生抉择","探索未知"],"advisor_id":"xuxiake"}', 'b49f2bbfb47a7085ab27be078939980e212bf9b3f72afefaed67032d849dc169');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('xuxiake-c2', 'xuxiake', '考辨长江正源·推翻"岷山导江"（西南考察）', '古来《禹贡》"岷山导江"之说被奉为权威，长江正源被普遍误认为岷江。', '徐霞客不信纸上旧说，亲赴西南实地考察金沙江与岷江，据一手实测考定金沙江才是长江正源、推翻"岷山导江"。', '其考辨纠正了千余年的地理误说，是中国地理学的重要贡献。', '别照搬没亲自验证过的"权威结论"——凡存疑必亲赴实地实测，以一手观察去推翻或确证它。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"xuxiake-c2","status":"published","title_period":"考辨长江正源·推翻\"岷山导江\"（西南考察）","dilemma_constraints":"古来《禹贡》\"岷山导江\"之说被奉为权威，长江正源被普遍误认为岷江。","key_judgment":"徐霞客不信纸上旧说，亲赴西南实地考察金沙江与岷江，据一手实测考定金沙江才是长江正源、推翻\"岷山导江\"。","model_invoked":["亲历实测"],"outcome":"其考辨纠正了千余年的地理误说，是中国地理学的重要贡献。","transferable_lesson":"别照搬没亲自验证过的\"权威结论\"——凡存疑必亲赴实地实测，以一手观察去推翻或确证它。","source_tier":"primary","source_note":"考辨长江正源为《徐霞客游记》明载→确证（一手A）。","historicity":"confirmed","linked_cards":["xuxiake"],"tags":["探索未知","学习与认知"],"advisor_id":"xuxiake"}', '7a7224980072bf38b28f142eaec1d97b6ca4209141ad737e2aaf0bc44895ccfd');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('xuxiake-c3', 'xuxiake', '溯江穷源·探洞测绘（多次考察）', '考察中常可在方便处止步、得个大概即可；但那样得不到真正的发现。', '徐霞客凡探必究到底——溯河必至源头、入洞必探到尽处，哪怕艰险也追问到事物的真正尽端。', '其穷究式考察带来大量精确而深入的一手地理发现。', '凡探究就追到底、不在方便处止步——追到真正的源头/尽处，才有真发现。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"xuxiake-c3","status":"published","title_period":"溯江穷源·探洞测绘（多次考察）","dilemma_constraints":"考察中常可在方便处止步、得个大概即可；但那样得不到真正的发现。","key_judgment":"徐霞客凡探必究到底——溯河必至源头、入洞必探到尽处，哪怕艰险也追问到事物的真正尽端。","model_invoked":["穷究到源"],"outcome":"其穷究式考察带来大量精确而深入的一手地理发现。","transferable_lesson":"凡探究就追到底、不在方便处止步——追到真正的源头/尽处，才有真发现。","source_tier":"primary","source_note":"溯江穷源、探洞测绘为《徐霞客游记》记述→确证。","historicity":"confirmed","linked_cards":["xuxiake"],"tags":["探索未知","学习与认知"],"advisor_id":"xuxiake"}', '4b131404d1fd13bcf49f82d6318ecea4aebd1d948a117542b1f47b957619c630');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('xuxiake-c4', 'xuxiake', '西南岩溶系统观察·归纳地貌规律（西南考察）', '西南遍布奇异的岩溶（喀斯特）地貌，零散记录只是奇观、难成知识。', '徐霞客对大量岩溶地貌作系统的实地观察与横向比较，归纳其类型与成因规律，而非止于记录单点奇观。', '他对岩溶地貌的系统观察与归纳，是世界岩溶地貌学的早期重要记录。', '别止于记录孤立的单点——从大量一手观察中横向比较、归纳出普遍规律，一手数据的真正价值才显现。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"xuxiake-c4","status":"published","title_period":"西南岩溶系统观察·归纳地貌规律（西南考察）","dilemma_constraints":"西南遍布奇异的岩溶（喀斯特）地貌，零散记录只是奇观、难成知识。","key_judgment":"徐霞客对大量岩溶地貌作系统的实地观察与横向比较，归纳其类型与成因规律，而非止于记录单点奇观。","model_invoked":["实地归纳规律"],"outcome":"他对岩溶地貌的系统观察与归纳，是世界岩溶地貌学的早期重要记录。","transferable_lesson":"别止于记录孤立的单点——从大量一手观察中横向比较、归纳出普遍规律，一手数据的真正价值才显现。","source_tier":"primary","source_note":"对西南岩溶地貌的系统观察归纳为《徐霞客游记》所载→确证。","historicity":"confirmed","linked_cards":["xuxiake"],"tags":["探索未知","学习与认知"],"advisor_id":"xuxiake"}', 'ed14d315b350f98f09f38ddb2ac21f9054898682186771589b9c1b40344a8fbd');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mandela-c1', 'mandela', '狱中学南非荷兰语、研究对手（罗本岛1964–1982）', '被判终身监禁、囚于罗本岛，与外界隔绝、受狱方（多为白人阿非利卡人）严密控制，处于绝对弱势。', '主动学习南非荷兰语、研读阿非利卡人历史与文化，理解狱卒与对手的心理诉求，在狱中与狱方建立某种相互尊重，把牢狱变成理解对手的"课堂"。', '这种对对手的深刻理解为日后与白人政权谈判、推动和平转型奠定基础；部分狱卒态度转变。', '在绝对劣势下要赢一个强大对手，先放下敌意去深入了解他——学他的语言、读他的历史、懂他的恐惧；理解是日后说服与和解的前提。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mandela-c1","status":"published","title_period":"狱中学南非荷兰语、研究对手（罗本岛1964–1982）","dilemma_constraints":"被判终身监禁、囚于罗本岛，与外界隔绝、受狱方（多为白人阿非利卡人）严密控制，处于绝对弱势。","key_judgment":"主动学习南非荷兰语、研读阿非利卡人历史与文化，理解狱卒与对手的心理诉求，在狱中与狱方建立某种相互尊重，把牢狱变成理解对手的\"课堂\"。","model_invoked":["学敌赢敌"],"outcome":"这种对对手的深刻理解为日后与白人政权谈判、推动和平转型奠定基础；部分狱卒态度转变。","transferable_lesson":"在绝对劣势下要赢一个强大对手，先放下敌意去深入了解他——学他的语言、读他的历史、懂他的恐惧；理解是日后说服与和解的前提。","source_tier":"secondary","source_note":"学Afrikaans、研究对手为多源可考；内心动机部分自述，但行为有第三方佐证→确证。","historicity":"confirmed","linked_cards":["mandela"],"tags":["领导力","谈判"],"advisor_id":"mandela"}', '4621fa0bd41f1928a66584740f9622e10fd090ed92dc8c401d05661bad315900');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mandela-c2', 'mandela', '从狱中开启与政府秘密谈判（1980年代后期）', '反隔离斗争陷僵局、暴力升级、国家濒临内战；曼德拉仍在狱中，党内强硬派反对与"敌人"谈判，谈判可能被视为出卖。', '他判断续抗将两败俱伤，遂冒被指叛卖之险，主动从狱中秘密接触政府开启谈判——在根本目标（终结隔离、多数人统治）不让步前提下，把手段从对抗切换为谈判。', '谈判最终促成其获释、解除党禁、和平过渡到1994年首次多种族大选；避免了全面内战。', '当对抗陷入两败俱伤的僵局，在不放弃根本目标的前提下，主动把手段从"斗"切换为"谈"——哪怕要承受"妥协"的骂名。守住目标，手段可以换。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mandela-c2","status":"published","title_period":"从狱中开启与政府秘密谈判（1980年代后期）","dilemma_constraints":"反隔离斗争陷僵局、暴力升级、国家濒临内战；曼德拉仍在狱中，党内强硬派反对与\"敌人\"谈判，谈判可能被视为出卖。","key_judgment":"他判断续抗将两败俱伤，遂冒被指叛卖之险，主动从狱中秘密接触政府开启谈判——在根本目标（终结隔离、多数人统治）不让步前提下，把手段从对抗切换为谈判。","model_invoked":["守标活法"],"outcome":"谈判最终促成其获释、解除党禁、和平过渡到1994年首次多种族大选；避免了全面内战。","transferable_lesson":"当对抗陷入两败俱伤的僵局，在不放弃根本目标的前提下，主动把手段从\"斗\"切换为\"谈\"——哪怕要承受\"妥协\"的骂名。守住目标，手段可以换。","source_tier":"primary","source_note":"谈判进程为信史（多源），本人自述+史料交叉印证→确证。","historicity":"confirmed","linked_cards":["mandela"],"tags":["谈判","治理决策"],"advisor_id":"mandela"}', '6ad0ce9d5bd9b92028006d6ccc6bac705f4ce7e26955f8a84df4a667e51621bb');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mandela-c3', 'mandela', '当选后推动种族和解·真相与和解委员会（1994–）', '1994当选总统，国家深陷数十年仇恨与暴力创伤；黑人多数有清算诉求、白人少数恐报复，稍有不慎即滑向内战或经济崩溃（白人技术官僚/资本出逃）。', '选择和解而非清算——保留白人公务员、设"真相与和解委员会"（以坦白换特赦、揭真相而非审判报复）、主动安抚白人恐惧，把国家稳定置于即时正义之上。', '南非避免内战与族群报复、实现相对平稳的政权过渡；但也被批评以牺牲经济正义/清算为代价（见盲区）。', '在剧烈对立后的转型期，"和解换稳定"常优于"清算换分裂"——主动安抚失势一方的恐惧，把共同体存续置于即时报复欲之上。（诚实：和解有其代价，未必带来实质正义。）', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mandela-c3","status":"published","title_period":"当选后推动种族和解·真相与和解委员会（1994–）","dilemma_constraints":"1994当选总统，国家深陷数十年仇恨与暴力创伤；黑人多数有清算诉求、白人少数恐报复，稍有不慎即滑向内战或经济崩溃（白人技术官僚/资本出逃）。","key_judgment":"选择和解而非清算——保留白人公务员、设\"真相与和解委员会\"（以坦白换特赦、揭真相而非审判报复）、主动安抚白人恐惧，把国家稳定置于即时正义之上。","model_invoked":["战略性和解"],"outcome":"南非避免内战与族群报复、实现相对平稳的政权过渡；但也被批评以牺牲经济正义/清算为代价（见盲区）。","transferable_lesson":"在剧烈对立后的转型期，\"和解换稳定\"常优于\"清算换分裂\"——主动安抚失势一方的恐惧，把共同体存续置于即时报复欲之上。（诚实：和解有其代价，未必带来实质正义。）","source_tier":"secondary","source_note":"和解政策与真相委员会为信史→确证；其代价争议客观入 blind_spots。","historicity":"confirmed","linked_cards":["mandela"],"tags":["治理决策","领导力"],"advisor_id":"mandela"}', 'f036cbdc51bc4664b36c45c4cf14d4331cf7cb998fa6103dff5a94965f869aff');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mandela-c4', 'mandela', '1995橄榄球世界杯·穿跳羚队球衣（1995）', '橄榄球（跳羚队）长期是白人象征、黑人多视其为隔离标志；1995世界杯在南非举办，族群隔阂仍深。', '曼德拉刻意身穿跳羚队队长球衣、亲临决赛为这支"白人球队"加油，把白人象征转化为全民团结符号，以一个姿态向白人释放善意、向黑人示范宽容。', '南非夺冠之夜黑白民众共庆，成国家和解的标志性时刻；一件球衣转动了整个国家的情绪。', '一个精心选择的象征性姿态，有时比千言万语更能转动群体情绪——找到对立双方都在意的那个符号，用一个动作把"他们的"变成"我们的"。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mandela-c4","status":"published","title_period":"1995橄榄球世界杯·穿跳羚队球衣（1995）","dilemma_constraints":"橄榄球（跳羚队）长期是白人象征、黑人多视其为隔离标志；1995世界杯在南非举办，族群隔阂仍深。","key_judgment":"曼德拉刻意身穿跳羚队队长球衣、亲临决赛为这支\"白人球队\"加油，把白人象征转化为全民团结符号，以一个姿态向白人释放善意、向黑人示范宽容。","model_invoked":["象征政治"],"outcome":"南非夺冠之夜黑白民众共庆，成国家和解的标志性时刻；一件球衣转动了整个国家的情绪。","transferable_lesson":"一个精心选择的象征性姿态，有时比千言万语更能转动群体情绪——找到对立双方都在意的那个符号，用一个动作把\"他们的\"变成\"我们的\"。","source_tier":"secondary","source_note":"公开事件、多源可考→确证。","historicity":"confirmed","linked_cards":["mandela"],"tags":["领导力","治理决策"],"advisor_id":"mandela"}', '87d5976f7eff368e0623036c1bfd45a4497e8e7c9b3cf4eb9a713853060c62c3');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mandela-c5', 'mandela', '拒绝有条件释放·守目标不动摇（1985）', '1985年政府提出：只要公开放弃武装斗争即可获释。坐牢已逾二十年、自由近在眼前，但接受意味着原则上低头、背弃运动。', '他拒绝有条件释放，公开声明：囚徒不能签契约、只有自由的人才能谈判；在根本政治权利未达成前，宁继续坐牢也不以放弃斗争换个人自由。', '他又坐约五年牢，但守住道义与谈判主动权；最终以更有利条件无条件获释，赢得国内外更大威望。', '当自由/胜利以"放弃原则"为代价摆在面前时，以更长时间尺度衡量：守住根本原则、宁可再忍一程，往往比急着脱身更能赢得最终的主动。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mandela-c5","status":"published","title_period":"拒绝有条件释放·守目标不动摇（1985）","dilemma_constraints":"1985年政府提出：只要公开放弃武装斗争即可获释。坐牢已逾二十年、自由近在眼前，但接受意味着原则上低头、背弃运动。","key_judgment":"他拒绝有条件释放，公开声明：囚徒不能签契约、只有自由的人才能谈判；在根本政治权利未达成前，宁继续坐牢也不以放弃斗争换个人自由。","model_invoked":["长线耐心"],"outcome":"他又坐约五年牢，但守住道义与谈判主动权；最终以更有利条件无条件获释，赢得国内外更大威望。","transferable_lesson":"当自由/胜利以\"放弃原则\"为代价摆在面前时，以更长时间尺度衡量：守住根本原则、宁可再忍一程，往往比急着脱身更能赢得最终的主动。","source_tier":"primary","source_note":"1985拒绝有条件释放及公开声明为信史→确证。","historicity":"confirmed","linked_cards":["mandela"],"tags":["人生抉择","领导力"],"advisor_id":"mandela"}', '25a23803939e587123935c6ee5b8b75691b24bba697bccb6614f8c6c5d1875db');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zengguofan-c1', 'zengguofan', '靖港兵败投水未遂后重整旗鼓（1854）', '初建湘军，靖港之战大败，曾国藩羞愤投水自尽（被部下救起）；声誉、士气、前途俱跌谷底，朝中讥讽、地方排挤。', '不一蹶不振、也不急于报复性反扑；"打脱牙和血吞"，收拾残部重整训练，以屡败屡战之心徐图再起。', '湘军重整后渐成劲旅，终成平定太平天国的主力。', '惨败到想放弃时，分水岭不是"能否立刻翻盘"，而是"能否把羞辱咽下、不带情绪地重整再来"。把"屡战屡败"心态换成"屡败屡战"，剩下的交给时间。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zengguofan-c1","status":"published","title_period":"靖港兵败投水未遂后重整旗鼓（1854）","dilemma_constraints":"初建湘军，靖港之战大败，曾国藩羞愤投水自尽（被部下救起）；声誉、士气、前途俱跌谷底，朝中讥讽、地方排挤。","key_judgment":"不一蹶不振、也不急于报复性反扑；\"打脱牙和血吞\"，收拾残部重整训练，以屡败屡战之心徐图再起。","model_invoked":["打脱牙和血吞"],"outcome":"湘军重整后渐成劲旅，终成平定太平天国的主力。","transferable_lesson":"惨败到想放弃时，分水岭不是\"能否立刻翻盘\"，而是\"能否把羞辱咽下、不带情绪地重整再来\"。把\"屡战屡败\"心态换成\"屡败屡战\"，剩下的交给时间。","source_tier":"secondary","source_note":"靖港败、投水获救、重整为信史（《清史稿》B）；流传甚广的\"屡败屡战\"改奏一句出处不一、宜存疑，呈现勿坐实为原话。","historicity":"confirmed","linked_cards":["zengguofan"],"tags":["危机应对","修身自省"],"advisor_id":"zengguofan"}', 'a4a99aa153f0e3400af725c1f3c51bf7b14b91855c5e09d85a1b0bf3695f397d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zengguofan-c2', 'zengguofan', '结硬寨打呆仗·围安庆、克天京（1860–1864）', '面对劲敌太平军，湘军兵力机动未必占优，强攻坚城风险极大。', '不浪战、不贪奇功；每到一地先深沟高垒、围而不打、断敌粮道，以稳制变，靠工事与耐心而非奇袭取胜。', '以稳扎稳打逐步绞杀太平军，终克天京；此战法成其军事思想标志。', '面对比你强或势均力敌的对手，别赌奇招；用"笨"办法把自己立于不败（控风险、断补给、慢消耗），让时间与结构优势替你赢。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zengguofan-c2","status":"published","title_period":"结硬寨打呆仗·围安庆、克天京（1860–1864）","dilemma_constraints":"面对劲敌太平军，湘军兵力机动未必占优，强攻坚城风险极大。","key_judgment":"不浪战、不贪奇功；每到一地先深沟高垒、围而不打、断敌粮道，以稳制变，靠工事与耐心而非奇袭取胜。","model_invoked":["结硬寨打呆仗"],"outcome":"以稳扎稳打逐步绞杀太平军，终克天京；此战法成其军事思想标志。","transferable_lesson":"面对比你强或势均力敌的对手，别赌奇招；用\"笨\"办法把自己立于不败（控风险、断补给、慢消耗），让时间与结构优势替你赢。","source_tier":"secondary","source_note":"围安庆/克天京为信史（《清史稿》B）；战法为其确凿主张（奏稿A）。镇压太平天国之历史争议见 blind_spots，本案聚焦方法可迁移性，不美化战争。","historicity":"confirmed","linked_cards":["zengguofan"],"tags":["战略","组织管理"],"advisor_id":"zengguofan"}', '73f2d056506bf3667e072909b73e47d70a1ccfee72aa345cbfd2198f80d6dc9a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zengguofan-c3', 'zengguofan', '立"日课"·数十年写日记自审', '早年自认气质偏躁、有诸多习气（傲、言多等），欲改而苦无章法，空泛立志屡屡反复。', '师法理学立"日课"——每日以楷书写日记，逐日记录并严厉检讨过失（日课十二条：主敬/静坐/早起/读书不二/谨言等），把修身做成可累积、可检查的每日功课。', '数十年坚持，气质习性逐步改造，成后世"修身"的著名范本（家书、日记广为流传）。', '想改掉根深蒂固的毛病，靠"下决心"没用；把它变成每天写下来、可检查的功课——以可累积的日常记账，替代一次性的发愿。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"zengguofan-c3","status":"published","title_period":"立\"日课\"·数十年写日记自审","dilemma_constraints":"早年自认气质偏躁、有诸多习气（傲、言多等），欲改而苦无章法，空泛立志屡屡反复。","key_judgment":"师法理学立\"日课\"——每日以楷书写日记，逐日记录并严厉检讨过失（日课十二条：主敬/静坐/早起/读书不二/谨言等），把修身做成可累积、可检查的每日功课。","model_invoked":["日课省察"],"outcome":"数十年坚持，气质习性逐步改造，成后世\"修身\"的著名范本（家书、日记广为流传）。","transferable_lesson":"想改掉根深蒂固的毛病，靠\"下决心\"没用；把它变成每天写下来、可检查的功课——以可累积的日常记账，替代一次性的发愿。","source_tier":"primary","source_note":"自述类（日记/家书系本人书写，一手 A）；其自我评述含自我塑造、编辑取舍与形象经营，按自述特例标 historicity 存疑、存润色风险。","historicity":"disputed","linked_cards":["zengguofan"],"tags":["修身自省","学习与认知"],"advisor_id":"zengguofan"}', '05c78d0da274b804efcdd67a31e8fa089fb6f1cd0a76caed36f5ee1398795603');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zengguofan-c4', 'zengguofan', '查办天津教案的两难妥协（1870）', '津民疑教堂拐杀儿童而焚堂、杀死多名外人教士；列强陈兵索赔索命。清廷令重病的曾国藩查办，陷"对外避战求全 vs 对内顺应民意"的死局。', '权衡国力悬殊、力避开战，采对外妥协（惩办涉案民众、赔款、道歉）以"和"保全大局。', '避免了即时对外战争，但处置被国内舆论痛斥"卖国"、大失民心，曾国藩声誉重创、内心痛苦，不久病逝。', '有时所有选项都坏，你只能在"灾难"与"屈辱"间选代价较小者；选了就要承受随之而来的骂名与内伤——这种"没有好结局的决策"是身居高位者的常态。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zengguofan-c4","status":"published","title_period":"查办天津教案的两难妥协（1870）","dilemma_constraints":"津民疑教堂拐杀儿童而焚堂、杀死多名外人教士；列强陈兵索赔索命。清廷令重病的曾国藩查办，陷\"对外避战求全 vs 对内顺应民意\"的死局。","key_judgment":"权衡国力悬殊、力避开战，采对外妥协（惩办涉案民众、赔款、道歉）以\"和\"保全大局。","model_invoked":["打脱牙和血吞"],"outcome":"避免了即时对外战争，但处置被国内舆论痛斥\"卖国\"、大失民心，曾国藩声誉重创、内心痛苦，不久病逝。","transferable_lesson":"有时所有选项都坏，你只能在\"灾难\"与\"屈辱\"间选代价较小者；选了就要承受随之而来的骂名与内伤——这种\"没有好结局的决策\"是身居高位者的常态。","source_tier":"secondary","source_note":"天津教案及曾国藩查办为信史（《清史稿》B）。客观呈现历史争议、不美化，与 blind_spot 3 呼应。","historicity":"confirmed","linked_cards":["zengguofan"],"tags":["危机应对","治理决策"],"advisor_id":"zengguofan"}', 'b5d7445959a62d887dad306f22dd5dbc191813cb9f4158ca77213b4c7227d687');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zengguofan-c5', 'zengguofan', '创建湘军·"书生带兵"另起炉灶（1853起）', '太平军势大，清廷正规军（绿营）腐败无力。曾国藩以在籍侍郎办团练，无现成军队、无体制兵权，须从零建一支能打的军队。', '不沿用绿营旧制，另起炉灶建"湘军"——以同乡/师生/亲族纽带为骨架，选"拙诚"读书人为将、招朴实山农为兵，重忠义训练与饷银保障。', '湘军成晚清最有战斗力的武装，奠定其事功基础；"书生带兵"的用人与组织模式影响深远。', '当现有体制烂到不能用，与其在旧框架里修补，不如另起炉灶、按你信得过的原则（可靠的人、扎实的纽带、清晰的激励）重建一个小而硬的新组织。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zengguofan-c5","status":"published","title_period":"创建湘军·\"书生带兵\"另起炉灶（1853起）","dilemma_constraints":"太平军势大，清廷正规军（绿营）腐败无力。曾国藩以在籍侍郎办团练，无现成军队、无体制兵权，须从零建一支能打的军队。","key_judgment":"不沿用绿营旧制，另起炉灶建\"湘军\"——以同乡/师生/亲族纽带为骨架，选\"拙诚\"读书人为将、招朴实山农为兵，重忠义训练与饷银保障。","model_invoked":["尚拙"],"outcome":"湘军成晚清最有战斗力的武装，奠定其事功基础；\"书生带兵\"的用人与组织模式影响深远。","transferable_lesson":"当现有体制烂到不能用，与其在旧框架里修补，不如另起炉灶、按你信得过的原则（可靠的人、扎实的纽带、清晰的激励）重建一个小而硬的新组织。","source_tier":"secondary","source_note":"创建湘军为信史（《清史稿》B）。","historicity":"confirmed","linked_cards":["zengguofan"],"tags":["组织管理","领导力"],"advisor_id":"zengguofan"}', '792183e6acea40d9f898f8914438834b489804ee4b4df7a3bf45c65eab221cae');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('shackleton-c1', 'shackleton', '坚忍号被浮冰碾碎·当即改目标为全员生还（1915）', '坚忍号在威德尔海被浮冰围困十月后终遭挤压碎裂沉没；横穿南极的原定目标彻底落空；28人困浮冰、远离救援、补给有限、严冬将至。', '不沉湎壮举破灭，当场宣布新目标——把每个人活着带回家；立即组织扎营、抢运物资、规划向最近陆地（象岛）转移。', '全队心理迅速从"探险失败"转向"求生任务"；最终28人无一死亡。', '倾注一切的原目标被现实摧毁时，最关键一步不是哀悼，而是当场给团队一个新的现实目标——把"我们失败了"立刻改写成"我们现在要完成这个"。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"shackleton-c1","status":"published","title_period":"坚忍号被浮冰碾碎·当即改目标为全员生还（1915）","dilemma_constraints":"坚忍号在威德尔海被浮冰围困十月后终遭挤压碎裂沉没；横穿南极的原定目标彻底落空；28人困浮冰、远离救援、补给有限、严冬将至。","key_judgment":"不沉湎壮举破灭，当场宣布新目标——把每个人活着带回家；立即组织扎营、抢运物资、规划向最近陆地（象岛）转移。","model_invoked":["目标果断降级"],"outcome":"全队心理迅速从\"探险失败\"转向\"求生任务\"；最终28人无一死亡。","transferable_lesson":"倾注一切的原目标被现实摧毁时，最关键一步不是哀悼，而是当场给团队一个新的现实目标——把\"我们失败了\"立刻改写成\"我们现在要完成这个\"。","source_tier":"primary","source_note":"沉船、全员生还有本人著作+独立船员日记+Hurley照片多源交叉印证→确证（区别于纯自述存疑）。","historicity":"confirmed","linked_cards":["shackleton"],"tags":["危机应对","领导力"],"advisor_id":"shackleton"}', '22c09c6f8759dd02cdc2ac385b5153ae49178a8b075ae69dada6388a21fbc5ba');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('shackleton-c2', 'shackleton', '800英里救生艇航行至南乔治亚岛（1916）', '全队漂到荒无人烟的象岛，无人知其位置、不会有救援经过；唯一生路是乘改装小艇横渡1300公里世上最凶险南大洋求救，成功率极低、失败即全员等死。', '亲带5人冒死出海（大队留象岛由稳健者带领），以一次高风险孤注一掷换全队生机；航行16天靠Worsley天文导航奇迹般抵达。', '5人抵南乔治亚，再徒步翻越无人穿越的雪山到捕鲸站；最终组织救援，象岛22人全部获救。', '当被动等待＝等死、唯一主动选项又风险极高时，理性选择可能恰是那个"疯狂"的孤注一掷——前提是已把它拆成可执行的下一程、并把团队其余部分稳妥安置。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"shackleton-c2","status":"published","title_period":"800英里救生艇航行至南乔治亚岛（1916）","dilemma_constraints":"全队漂到荒无人烟的象岛，无人知其位置、不会有救援经过；唯一生路是乘改装小艇横渡1300公里世上最凶险南大洋求救，成功率极低、失败即全员等死。","key_judgment":"亲带5人冒死出海（大队留象岛由稳健者带领），以一次高风险孤注一掷换全队生机；航行16天靠Worsley天文导航奇迹般抵达。","model_invoked":["只走下一程"],"outcome":"5人抵南乔治亚，再徒步翻越无人穿越的雪山到捕鲸站；最终组织救援，象岛22人全部获救。","transferable_lesson":"当被动等待＝等死、唯一主动选项又风险极高时，理性选择可能恰是那个\"疯狂\"的孤注一掷——前提是已把它拆成可执行的下一程、并把团队其余部分稳妥安置。","source_tier":"primary","source_note":"本人著作+船长Worsley亲述交叉印证→确证。","historicity":"confirmed","linked_cards":["shackleton"],"tags":["危机应对","探索未知"],"advisor_id":"shackleton"}', 'a7e329dbb3c526c9292b1fc166a7c98846a9260a4f21ae3f9f79660787c43dc1');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('shackleton-c3', 'shackleton', '浮冰扎营期主动经营士气（1915–1916）', '数月困守浮冰，前途未卜、严寒单调、恐惧绝望随时可能瓦解团队；一旦人心散乱或崩溃，全员必死。', '把维持士气当头等任务——坚持作息与分工routine、组织唱歌球赛庆节、领袖与队员同甘苦地公平分食、亲自观察每人情绪、刻意营造"会回家"的氛围。', '团队在两年绝境中始终未崩溃、未死一人；其士气管理被后世领导力研究反复引用。', '在看不到尽头的困境里，让团队"不散"本身就是最重要的工作——routine、公平、仪式感、领袖与大家同甘苦，是把恐惧挡在外面的具体手段。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"shackleton-c3","status":"published","title_period":"浮冰扎营期主动经营士气（1915–1916）","dilemma_constraints":"数月困守浮冰，前途未卜、严寒单调、恐惧绝望随时可能瓦解团队；一旦人心散乱或崩溃，全员必死。","key_judgment":"把维持士气当头等任务——坚持作息与分工routine、组织唱歌球赛庆节、领袖与队员同甘苦地公平分食、亲自观察每人情绪、刻意营造\"会回家\"的氛围。","model_invoked":["士气即资源"],"outcome":"团队在两年绝境中始终未崩溃、未死一人；其士气管理被后世领导力研究反复引用。","transferable_lesson":"在看不到尽头的困境里，让团队\"不散\"本身就是最重要的工作——routine、公平、仪式感、领袖与大家同甘苦，是把恐惧挡在外面的具体手段。","source_tier":"primary","source_note":"本人著作+多船员日记交叉印证→确证。","historicity":"confirmed","linked_cards":["shackleton"],"tags":["组织管理","领导力"],"advisor_id":"shackleton"}', '503dc6b8184d043f5d20b9145957651760f6f744912e588b9e926206efc15e30');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('shackleton-c4', 'shackleton', '把最动摇者留在自己帐篷（浮冰期）', '队伍里几个情绪消极、易散播怨气悲观的人，若放任在普通帐篷会传染、瓦解整体士气。', '刻意把这些最可能动摇军心的人安排在自己帐篷、由自己亲自照看与影响，隔离负面情绪扩散。', '有效遏制悲观蔓延，保持整体凝聚。', '团队里最负面、最易传染情绪的人，与其疏远或惩戒，不如放在你眼皮底下亲自带——把传染源置于你的影响范围内，比让它在角落发酵更安全。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"shackleton-c4","status":"published","title_period":"把最动摇者留在自己帐篷（浮冰期）","dilemma_constraints":"队伍里几个情绪消极、易散播怨气悲观的人，若放任在普通帐篷会传染、瓦解整体士气。","key_judgment":"刻意把这些最可能动摇军心的人安排在自己帐篷、由自己亲自照看与影响，隔离负面情绪扩散。","model_invoked":["异见者近身"],"outcome":"有效遏制悲观蔓延，保持整体凝聚。","transferable_lesson":"团队里最负面、最易传染情绪的人，与其疏远或惩戒，不如放在你眼皮底下亲自带——把传染源置于你的影响范围内，比让它在角落发酵更安全。","source_tier":"secondary","source_note":"细节多见于传记/船员回忆，多源一致→确证。","historicity":"confirmed","linked_cards":["shackleton"],"tags":["组织管理","领导力"],"advisor_id":"shackleton"}', '01ec3bd725656a63750ed0c1ebc20ff0aba27bddf5d5c0dfef8c046c593c94f2');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('shackleton-c5', 'shackleton', '四次返航·不放弃象岛队员直到全员获救（1916）', '抵南乔治亚求救后，象岛仍困22人；南极浮冰阻断航路，前三次返航救援均被浮冰逼退，时间拖长、队员生死未卜。', '死咬"全员生还"新目标不放，借不同船只一次次重返，直到第四次穿过浮冰、把象岛22人全部接出。', '1916年8月第四次成功，象岛22人全获救；远征28人无一死亡，成探险史最著名的"失败的成功"。', '一旦把新目标定为"不丢下任何一个人"，就要执行到底——失败几次不等于放弃，换条路再来，直到兑现你对团队的承诺。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"shackleton-c5","status":"published","title_period":"四次返航·不放弃象岛队员直到全员获救（1916）","dilemma_constraints":"抵南乔治亚求救后，象岛仍困22人；南极浮冰阻断航路，前三次返航救援均被浮冰逼退，时间拖长、队员生死未卜。","key_judgment":"死咬\"全员生还\"新目标不放，借不同船只一次次重返，直到第四次穿过浮冰、把象岛22人全部接出。","model_invoked":["目标果断降级"],"outcome":"1916年8月第四次成功，象岛22人全获救；远征28人无一死亡，成探险史最著名的\"失败的成功\"。","transferable_lesson":"一旦把新目标定为\"不丢下任何一个人\"，就要执行到底——失败几次不等于放弃，换条路再来，直到兑现你对团队的承诺。","source_tier":"primary","source_note":"多源信史→确证。","historicity":"confirmed","linked_cards":["shackleton"],"tags":["危机应对","领导力"],"advisor_id":"shackleton"}', '58cc8d78f0cba764f39e67ef66c0f3435f7396327e49d64676f43b0a48b85199');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('helenkeller-c1', 'helenkeller', '井房"水"的顿悟·命名即钥匙（幼年）', '又盲又聋的海伦困在无名的混沌中、无法把手势与事物对应起来、屡屡崩溃。', '沙利文在水泵下让流水冲过她一只手、同时在她另一只手心拼写"water"——她忽然懂得这个词指的就是那清凉的流动之物，名字与事物对接上了。', '这一顿悟打开了她整个语言与概念的世界，当天她又学会了几十个词。', '被一团模糊卡住时，先给它一个清晰的名字/定义——一个名字就是通向整个概念世界的钥匙、是理解与掌控的入口。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"helenkeller-c1","status":"published","title_period":"井房\"水\"的顿悟·命名即钥匙（幼年）","dilemma_constraints":"又盲又聋的海伦困在无名的混沌中、无法把手势与事物对应起来、屡屡崩溃。","key_judgment":"沙利文在水泵下让流水冲过她一只手、同时在她另一只手心拼写\"water\"——她忽然懂得这个词指的就是那清凉的流动之物，名字与事物对接上了。","model_invoked":["命名即钥匙"],"outcome":"这一顿悟打开了她整个语言与概念的世界，当天她又学会了几十个词。","transferable_lesson":"被一团模糊卡住时，先给它一个清晰的名字/定义——一个名字就是通向整个概念世界的钥匙、是理解与掌控的入口。","source_tier":"primary","source_note":"井房\"水\"顿悟为海伦《我的生活故事》明载→确证（一手自传A）。","historicity":"confirmed","linked_cards":["helenkeller"],"tags":["学习与认知","逆境应对"],"advisor_id":"helenkeller"}', '5cb37230011c475c021934447efaec819e1e229f4949652a4aa327739c346fc8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('helenkeller-c2', 'helenkeller', '以触/嗅/振动感知世界·替代通道（一生）', '视觉与听觉这两个主要感官通道完全被堵死。', '海伦不空等不可能恢复的视听，而是系统地用触觉、嗅觉、振动等尚可用的通道重建对世界的感知（如以手指触喉感受言语振动）。', '她以替代通道建立起异常丰富的世界感知，并写成《我生活的世界》。', '当主要通道被堵死，别盯着缺失的、空等它恢复——系统地用尚可用的通道重建感知，把还能用的用到极致。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"helenkeller-c2","status":"published","title_period":"以触/嗅/振动感知世界·替代通道（一生）","dilemma_constraints":"视觉与听觉这两个主要感官通道完全被堵死。","key_judgment":"海伦不空等不可能恢复的视听，而是系统地用触觉、嗅觉、振动等尚可用的通道重建对世界的感知（如以手指触喉感受言语振动）。","model_invoked":["替代通道"],"outcome":"她以替代通道建立起异常丰富的世界感知，并写成《我生活的世界》。","transferable_lesson":"当主要通道被堵死，别盯着缺失的、空等它恢复——系统地用尚可用的通道重建感知，把还能用的用到极致。","source_tier":"primary","source_note":"以触/嗅/振动感知世界为海伦《我生活的世界》所述→确证（一手A）。","historicity":"confirmed","linked_cards":["helenkeller"],"tags":["逆境应对","学习与认知"],"advisor_id":"helenkeller"}', 'edc55e7911e495f52f8d623d1e1775055e4594dbe1924b9fa7ea869278ca4976');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('helenkeller-c3', 'helenkeller', '与安妮·沙利文长期协作·互赖即杠杆（一生）', '又盲又聋使许多事独力无法完成；社会常把这种依赖视为无能。', '海伦不把对沙利文的依赖当耻辱，而是把它当作放大自己的杠杆与协作，借由这一"中介"完成了从识字到大学（拉德克利夫学院）的全部学业与写作。', '她成为首位获得文学学士学位的盲聋人、并以写作影响世界。', '把必要的依赖与帮助当作放大自己的杠杆、而非耻辱——主动编排能帮你的人，去触及你独力够不到的高度。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"helenkeller-c3","status":"published","title_period":"与安妮·沙利文长期协作·互赖即杠杆（一生）","dilemma_constraints":"又盲又聋使许多事独力无法完成；社会常把这种依赖视为无能。","key_judgment":"海伦不把对沙利文的依赖当耻辱，而是把它当作放大自己的杠杆与协作，借由这一\"中介\"完成了从识字到大学（拉德克利夫学院）的全部学业与写作。","model_invoked":["互赖即杠杆"],"outcome":"她成为首位获得文学学士学位的盲聋人、并以写作影响世界。","transferable_lesson":"把必要的依赖与帮助当作放大自己的杠杆、而非耻辱——主动编排能帮你的人，去触及你独力够不到的高度。","source_tier":"primary","source_note":"与沙利文的长期协作、完成大学学业为海伦自传与书信所载→确证（一手A）。","historicity":"confirmed","linked_cards":["helenkeller"],"tags":["逆境应对","修身自省"],"advisor_id":"helenkeller"}', 'beb99671881f0048bd7b3cf1b46d573d09b68731c2d8cc3768adc12c74805325');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('helenkeller-c4', 'helenkeller', '投身盲聋权益与社会倡导·经验公共化（成年后）', '个人虽已克服障碍，但千万同类仍困于无援的处境。', '海伦把自己的困境与经验转化为公共倡导的平台，投身盲聋人权益与更广泛的社会倡导，为同类争取系统性的改变。', '她成为影响深远的社会活动家，推动了对盲聋人群的关注与权益改善。', '把个人的困境与经验转化为为同类发声的公共行动——从"我如何自处"走向"为一群人争取系统性改变"，影响从一人扩到一群。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"helenkeller-c4","status":"published","title_period":"投身盲聋权益与社会倡导·经验公共化（成年后）","dilemma_constraints":"个人虽已克服障碍，但千万同类仍困于无援的处境。","key_judgment":"海伦把自己的困境与经验转化为公共倡导的平台，投身盲聋人权益与更广泛的社会倡导，为同类争取系统性的改变。","model_invoked":["经验公共化"],"outcome":"她成为影响深远的社会活动家，推动了对盲聋人群的关注与权益改善。","transferable_lesson":"把个人的困境与经验转化为为同类发声的公共行动——从\"我如何自处\"走向\"为一群人争取系统性改变\"，影响从一人扩到一群。","source_tier":"secondary","source_note":"投身盲聋权益与社会倡导为权威传记与倡导史料所载→确证（二手B）。","historicity":"confirmed","linked_cards":["helenkeller"],"tags":["价值与伦理","逆境应对"],"advisor_id":"helenkeller"}', '8a5d61792ace4b026918ef94bc5ada1fb6726062afd5664e3ea0359cda61e81c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('xuanzang-c1', 'xuanzang', '决意西行求法·违禁出境（627/629）', '汉地佛经译本彼此矛盾、义理不明、残缺甚多，争论无解；但唐初禁百姓私自出境，西行即违禁、且九死一生。', '不在错乱译本上空耗，决意亲赴天竺求原典；在未获官方过所的情况下，毅然"冒越宪章、私往天竺"，孤身西行。', '开启十余年西行求法，终取回大量原典、奠定其译经事业。', '在一堆彼此矛盾的二手材料上空耗争辩时，回到源头取权威原典——从根上解决分歧，胜过在副本上无休止争辩。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"xuanzang-c1","status":"published","title_period":"决意西行求法·违禁出境（627/629）","dilemma_constraints":"汉地佛经译本彼此矛盾、义理不明、残缺甚多，争论无解；但唐初禁百姓私自出境，西行即违禁、且九死一生。","key_judgment":"不在错乱译本上空耗，决意亲赴天竺求原典；在未获官方过所的情况下，毅然\"冒越宪章、私往天竺\"，孤身西行。","model_invoked":["求真溯源"],"outcome":"开启十余年西行求法，终取回大量原典、奠定其译经事业。","transferable_lesson":"在一堆彼此矛盾的二手材料上空耗争辩时，回到源头取权威原典——从根上解决分歧，胜过在副本上无休止争辩。","source_tier":"secondary","source_note":"西行求法、违禁出境为信史（《大慈恩寺三藏法师传》等）；惟须分史实玄奘与《西游记》神化形象（二轴：事件确证、文学神化分层）。","historicity":"confirmed","linked_cards":["xuanzang"],"tags":["探索未知","学习与认知"],"advisor_id":"xuanzang"}', 'c3b9adf8f79a3c0a84e8d6d532a5dbc06cc1b1c1daa004891b00a78745caa588');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('xuanzang-c2', 'xuanzang', '莫贺延碛断水立誓·断退之志', '穿越莫贺延碛（八百里流沙）时失水、几乎渴死，向东退回有生路、向西前行可能死。', '立誓"宁向西一步死、不向东一步生"，断掉退路、继续西行，终脱险。', '凭此决绝意志穿越大漠、续行求法。', '重大目标上、若目标确实值得，用预先承诺把退路从选项中删除——逼自己只能向前，往往是穿越最艰难一段的关键。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"xuanzang-c2","status":"published","title_period":"莫贺延碛断水立誓·断退之志","dilemma_constraints":"穿越莫贺延碛（八百里流沙）时失水、几乎渴死，向东退回有生路、向西前行可能死。","key_judgment":"立誓\"宁向西一步死、不向东一步生\"，断掉退路、继续西行，终脱险。","model_invoked":["断退之志"],"outcome":"凭此决绝意志穿越大漠、续行求法。","transferable_lesson":"重大目标上、若目标确实值得，用预先承诺把退路从选项中删除——逼自己只能向前，往往是穿越最艰难一段的关键。","source_tier":"secondary","source_note":"莫贺延碛断水续行为《大慈恩寺三藏法师传》所载→事件确证；具体誓语含传记润色。","historicity":"confirmed","linked_cards":["xuanzang"],"tags":["探索未知","人生抉择"],"advisor_id":"xuanzang"}', '0c675c9d71aa69beb427f31b854f17de08fabfffba7640936d037129ea4f37c3');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('xuanzang-c3', 'xuanzang', '那烂陀求学·曲女城无遮大会以学折服（641前后）', '作为外来僧人，在佛学最高殿堂那烂陀及天竺学界，如何赢得尊重与认可。', '不靠身份、靠把佛学钻到极深——在曲女城无遮大会上立论、十八日无人能难，以真才实学折服天竺学界。', '名震天竺、获极高礼遇，以实力而非头衔赢得尊重。', '在陌生场合、靠把一门学问/技能钻到能折服权威的深度来立信——实力赢得的尊重，远比头衔牢靠。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"xuanzang-c3","status":"published","title_period":"那烂陀求学·曲女城无遮大会以学折服（641前后）","dilemma_constraints":"作为外来僧人，在佛学最高殿堂那烂陀及天竺学界，如何赢得尊重与认可。","key_judgment":"不靠身份、靠把佛学钻到极深——在曲女城无遮大会上立论、十八日无人能难，以真才实学折服天竺学界。","model_invoked":["以学折服"],"outcome":"名震天竺、获极高礼遇，以实力而非头衔赢得尊重。","transferable_lesson":"在陌生场合、靠把一门学问/技能钻到能折服权威的深度来立信——实力赢得的尊重，远比头衔牢靠。","source_tier":"secondary","source_note":"那烂陀求学、曲女城无遮大会为《大慈恩寺三藏法师传》所载→确证；个别盛况细节或有传记夸饰。","historicity":"confirmed","linked_cards":["xuanzang"],"tags":["学习与认知","价值与伦理"],"advisor_id":"xuanzang"}', '2fa29a4d71718d45e48b884ff98a8ec35ab0475b546dc5a3046cfedd08ecdf43');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('xuanzang-c4', 'xuanzang', '归国拒辅政·专心译经（645后）', '玄奘归国后声誉日隆，唐太宗曾劝其还俗辅政、授以高位荣宠。', '拒绝还俗辅政，把余生全部投入译经这件最初真正要完成的事——译出大量经论，建立中国佛教译经的高峰。', '译经事业成其毕生最大贡献，影响汉传佛教深远。', '功成名就、荣宠当前时，拒绝偏离、把余生投回你最初真正要完成的正事——荣耀是副产品，未竟的正事才是目的。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"xuanzang-c4","status":"published","title_period":"归国拒辅政·专心译经（645后）","dilemma_constraints":"玄奘归国后声誉日隆，唐太宗曾劝其还俗辅政、授以高位荣宠。","key_judgment":"拒绝还俗辅政，把余生全部投入译经这件最初真正要完成的事——译出大量经论，建立中国佛教译经的高峰。","model_invoked":["完成先于荣耀"],"outcome":"译经事业成其毕生最大贡献，影响汉传佛教深远。","transferable_lesson":"功成名就、荣宠当前时，拒绝偏离、把余生投回你最初真正要完成的正事——荣耀是副产品，未竟的正事才是目的。","source_tier":"secondary","source_note":"归国拒辅政、专心译经为《大慈恩寺三藏法师传》《旧唐书》所载→确证。","historicity":"confirmed","linked_cards":["xuanzang"],"tags":["人生抉择","价值与伦理"],"advisor_id":"xuanzang"}', '2c02ab6a68c023c029e20a919f23c32ab7b241422f3a93403f42158817605ca6');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('sushi-c1', 'sushi', '乌台诗案后谪黄州·"东坡"的诞生（1080）', '因诗文被构陷"谤讪朝廷"下狱（乌台诗案），几死；获释贬黄州团练副使（虚职、不得签书公事、近流放），俸薄、前途尽毁、惊魂未定。', '不沉溺冤屈与恐惧，求得城东废营地"东坡"亲自垦荒、自号东坡居士，就地重建生活；同时作《赤壁赋》《定风波》以"变不变之辨""一蓑烟雨任平生"完成心态转化。', '黄州时期成其文学与思想巅峰（前后赤壁赋、寒食帖等皆作于此）；在最低谷活出最高创造力。', '被外力打到谷底又无法立即翻身时，先停止反刍冤屈，向眼前要一块"能亲手耕种的地"——把生活重建在此刻能掌控的最小单元上。安顿不是等来的，是就地做出来的。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"sushi-c1","status":"published","title_period":"乌台诗案后谪黄州·\"东坡\"的诞生（1080）","dilemma_constraints":"因诗文被构陷\"谤讪朝廷\"下狱（乌台诗案），几死；获释贬黄州团练副使（虚职、不得签书公事、近流放），俸薄、前途尽毁、惊魂未定。","key_judgment":"不沉溺冤屈与恐惧，求得城东废营地\"东坡\"亲自垦荒、自号东坡居士，就地重建生活；同时作《赤壁赋》《定风波》以\"变不变之辨\"\"一蓑烟雨任平生\"完成心态转化。","model_invoked":["此心安处"],"outcome":"黄州时期成其文学与思想巅峰（前后赤壁赋、寒食帖等皆作于此）；在最低谷活出最高创造力。","transferable_lesson":"被外力打到谷底又无法立即翻身时，先停止反刍冤屈，向眼前要一块\"能亲手耕种的地\"——把生活重建在此刻能掌控的最小单元上。安顿不是等来的，是就地做出来的。","source_tier":"secondary","source_note":"下狱、贬黄州、垦荒东坡为信史（《宋史》B，多源印证）；心态转化之表述出自本人诗文（A·作品）。保守取低=B。","historicity":"confirmed","linked_cards":["sushi"],"tags":["人生抉择","修身自省"],"advisor_id":"sushi"}', 'd21a4599e5ca735b885c98722de7159036d8f3dada829e729942c849eafdfe5c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('sushi-c2', 'sushi', '再贬惠州、儋州·"长作岭南人"（1094–1100）', '年近六旬，新党再起，一贬惠州（岭南瘴疠）、再贬儋州（海南，当时近绝域、"非人所居"），生还希望渺茫，近乎流放至死地。', '仍以随遇而安应对——惠州写"日啖荔枝三百颗，不辞长作岭南人"，把贬地当故乡；儋州办学、教化、与土人结交，自得其乐。', '在最恶劣绝域保全了精神完整与创造力，于儋州著书育人；后遇赦北归。"此心安处是吾乡"成后世逆境自处的精神范式。', '被放逐到无法选择的处境，与其当作"临时受难、等着回去"，不如当作"现在的家"来经营——把贬地活成故乡，绝境就不再是绝境。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"sushi-c2","status":"published","title_period":"再贬惠州、儋州·\"长作岭南人\"（1094–1100）","dilemma_constraints":"年近六旬，新党再起，一贬惠州（岭南瘴疠）、再贬儋州（海南，当时近绝域、\"非人所居\"），生还希望渺茫，近乎流放至死地。","key_judgment":"仍以随遇而安应对——惠州写\"日啖荔枝三百颗，不辞长作岭南人\"，把贬地当故乡；儋州办学、教化、与土人结交，自得其乐。","model_invoked":["此心安处"],"outcome":"在最恶劣绝域保全了精神完整与创造力，于儋州著书育人；后遇赦北归。\"此心安处是吾乡\"成后世逆境自处的精神范式。","transferable_lesson":"被放逐到无法选择的处境，与其当作\"临时受难、等着回去\"，不如当作\"现在的家\"来经营——把贬地活成故乡，绝境就不再是绝境。","source_tier":"secondary","source_note":"贬惠州/儋州为信史（《宋史》B）；\"日啖荔枝\"出本人作品（A）。保守取低=B。","historicity":"confirmed","linked_cards":["sushi"],"tags":["人生抉择","修身自省"],"advisor_id":"sushi"}', 'c1965b917d2b7ae9ee255eafb03978358757afe55e13957e5f49435836208fc9');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('sushi-c3', 'sushi', '知杭州·疏浚西湖筑苏堤（1089–1091）', '出知杭州，西湖长期淤塞、葑草蔓生、水利废弛，害灌溉航运民生；财力人力有限。', '不空谈，主持疏浚西湖，以挖出的葑泥筑贯通南北长堤（后世"苏堤"），既解水利又便交通，并以工代赈疏导民力。', '西湖水利大改善，苏堤成千年地标；展示其"在其位即就近把具体事做成"的建设性实干（儒家担当一面）。', '有资源、在其位时，把抽象的"治理"落成一两件看得见、惠及多数人的具体工程——做成的实事比再多议论更能立信、留痕。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"sushi-c3","status":"published","title_period":"知杭州·疏浚西湖筑苏堤（1089–1091）","dilemma_constraints":"出知杭州，西湖长期淤塞、葑草蔓生、水利废弛，害灌溉航运民生；财力人力有限。","key_judgment":"不空谈，主持疏浚西湖，以挖出的葑泥筑贯通南北长堤（后世\"苏堤\"），既解水利又便交通，并以工代赈疏导民力。","model_invoked":["即事实干"],"outcome":"西湖水利大改善，苏堤成千年地标；展示其\"在其位即就近把具体事做成\"的建设性实干（儒家担当一面）。","transferable_lesson":"有资源、在其位时，把抽象的\"治理\"落成一两件看得见、惠及多数人的具体工程——做成的实事比再多议论更能立信、留痕。","source_tier":"secondary","source_note":"浚西湖筑堤为信史（《宋史》B）。与C1/C2\"随遇而安\"对照，体现\"三家融通\"按位置切换框架。","historicity":"confirmed","linked_cards":["sushi"],"tags":["治理决策","资源调度"],"advisor_id":"sushi"}', '876731deeb6805ca3430a25e2e834be8daa0568da9e383fdcd81bc2afb3d981f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('sushi-c4', 'sushi', '悼亡妻·《江城子》（1075，密州）', '原配王弗早逝十年，苏轼于密州任上深陷丧偶之痛，旧情难遣。', '不回避也不粉饰悲伤，写"十年生死两茫茫，不思量，自难忘"，把哀恸如实道出。', '成中国悼亡词巅峰之一；佐证其旷达非麻木或否认，而是能容纳真实哀痛的清醒。', '真正的从容不是假装不痛；允许自己如实地哀伤，反而是与痛苦共处、不被吞没的前提。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"sushi-c4","status":"published","title_period":"悼亡妻·《江城子》（1075，密州）","dilemma_constraints":"原配王弗早逝十年，苏轼于密州任上深陷丧偶之痛，旧情难遣。","key_judgment":"不回避也不粉饰悲伤，写\"十年生死两茫茫，不思量，自难忘\"，把哀恸如实道出。","model_invoked":["旷达含悲"],"outcome":"成中国悼亡词巅峰之一；佐证其旷达非麻木或否认，而是能容纳真实哀痛的清醒。","transferable_lesson":"真正的从容不是假装不痛；允许自己如实地哀伤，反而是与痛苦共处、不被吞没的前提。","source_tier":"primary","source_note":"作品存世（A·一手）；王弗早逝为史实。","historicity":"confirmed","linked_cards":["sushi"],"tags":["人际关系","修身自省"],"advisor_id":"sushi"}', '7489ede51924c38d3b24f5a9143404a7f70314f27be1dcb4b93668c8ae4d7760');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('sushi-c5', 'sushi', '黄州苦中作乐·研《猪肉颂》（约1080–1084）', '黄州俸薄、生活拮据；当地猪肉价贱却"富者不肯吃、贫者不解煮"。', '亲研慢火煨炖之法，作《猪肉颂》"待他自熟莫催他，火候足时他自美"，把清贫日子过出滋味（后世"东坡肉"）。', '物质匮乏中创造出生活乐趣与饮食文化遗产；是"即事实干+随遇而安"在最日常层面的体现。', '改善处境不必从大处着手——把每天必须面对的最琐碎之事（如吃饭）认真做好、做出乐趣，本身就是对困境的一种反制。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"sushi-c5","status":"published","title_period":"黄州苦中作乐·研《猪肉颂》（约1080–1084）","dilemma_constraints":"黄州俸薄、生活拮据；当地猪肉价贱却\"富者不肯吃、贫者不解煮\"。","key_judgment":"亲研慢火煨炖之法，作《猪肉颂》\"待他自熟莫催他，火候足时他自美\"，把清贫日子过出滋味（后世\"东坡肉\"）。","model_invoked":["即事实干"],"outcome":"物质匮乏中创造出生活乐趣与饮食文化遗产；是\"即事实干+随遇而安\"在最日常层面的体现。","transferable_lesson":"改善处境不必从大处着手——把每天必须面对的最琐碎之事（如吃饭）认真做好、做出乐趣，本身就是对困境的一种反制。","source_tier":"secondary","source_note":"《猪肉颂》系年与归属学界有争议、东坡肉起源多属后世附会——故标存疑；呈现宜加\"传为苏轼\"限定。二轴示例：作品归属存疑而非战役角色存疑。","historicity":"disputed","linked_cards":["sushi"],"tags":["修身自省","资源调度"],"advisor_id":"sushi"}', 'b55dac0f9c13818c97d5660cc4a2dadb994ba7b9e2bdf9c4a4805df47488fea7');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('fanli-c1', 'fanli', '灭吴辞越·功成身退（越灭吴后）', '范蠡辅佐越王勾践灭吴、复国雪耻，功业达于顶点，正是受赏封赐之时。', '他不恋栈功名权位，引"蜚鸟尽、良弓藏；狡兔死、走狗烹"主动辞越离去，避开功成后的清算。', '全身而退、另谋新生；而留下的文种终遭勾践赐死，反衬其先见。', '事业达顶点、风险开始反转时，主动在临界点离场——顶点往往就是危点，退比恋栈更智。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"fanli-c1","status":"published","title_period":"灭吴辞越·功成身退（越灭吴后）","dilemma_constraints":"范蠡辅佐越王勾践灭吴、复国雪耻，功业达于顶点，正是受赏封赐之时。","key_judgment":"他不恋栈功名权位，引\"蜚鸟尽、良弓藏；狡兔死、走狗烹\"主动辞越离去，避开功成后的清算。","model_invoked":["功成身退"],"outcome":"全身而退、另谋新生；而留下的文种终遭勾践赐死，反衬其先见。","transferable_lesson":"事业达顶点、风险开始反转时，主动在临界点离场——顶点往往就是危点，退比恋栈更智。","source_tier":"secondary","source_note":"灭吴辞越为《史记·越世家》信史→确证；具体引语含传记色彩。","historicity":"confirmed","linked_cards":["fanli"],"tags":["人生抉择","风险评估"],"advisor_id":"fanli"}', '1ce60cb2721fa05edc6579ebe3f3afb2b8dcad6c50c483f05f1a5696c7001f0d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('fanli-c2', 'fanli', '评勾践本性·识人定去留', '功成之后，是留下享受封赏、还是离去；关键在所辅之君功成后会如何待功臣。', '范蠡观勾践之本性，断其"长颈鸟喙、可共患难、不可共乐"，预判功成必遭清算，据此决意离去并劝文种同走。', '范蠡去而得全、文种留而被赐死——其识人之准成千古鉴戒。', '要不要继续跟某个上位者干，先看透他的本性、预判功成之后他会怎么待你——据此定去留，别等清算才走。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"fanli-c2","status":"published","title_period":"评勾践本性·识人定去留","dilemma_constraints":"功成之后，是留下享受封赏、还是离去；关键在所辅之君功成后会如何待功臣。","key_judgment":"范蠡观勾践之本性，断其\"长颈鸟喙、可共患难、不可共乐\"，预判功成必遭清算，据此决意离去并劝文种同走。","model_invoked":["识人定去留"],"outcome":"范蠡去而得全、文种留而被赐死——其识人之准成千古鉴戒。","transferable_lesson":"要不要继续跟某个上位者干，先看透他的本性、预判功成之后他会怎么待你——据此定去留，别等清算才走。","source_tier":"secondary","source_note":"范蠡评勾践、辞越为《史记·越世家》所载→事件确证；评语具体措辞含传记色彩。","historicity":"confirmed","linked_cards":["fanli"],"tags":["人生抉择","风险评估"],"advisor_id":"fanli"}', '6f40eb065fcb487572dbfccdd4f9cc8daeddd08659265dc607c9d8be285fb83a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('fanli-c3', 'fanli', '更名陶朱公·彻底重启经商（辞越后）', '一个功成名就的政治家如何安放余生——守着旧荣光，还是另起炉灶。', '范蠡抛弃旧身份、更名（鸱夷子皮/陶朱公）、迁居经商，从零建立全新的事业，敢于否定过去的成功。', '据《史记·货殖列传》等，他经商再致巨富，被后世奉为"商圣"。', '敢于抛掉一个成功的旧身份、从头再来——敢否定过去的成功，才有第二、第三次大成。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"fanli-c3","status":"published","title_period":"更名陶朱公·彻底重启经商（辞越后）","dilemma_constraints":"一个功成名就的政治家如何安放余生——守着旧荣光，还是另起炉灶。","key_judgment":"范蠡抛弃旧身份、更名（鸱夷子皮/陶朱公）、迁居经商，从零建立全新的事业，敢于否定过去的成功。","model_invoked":["彻底重启"],"outcome":"据《史记·货殖列传》等，他经商再致巨富，被后世奉为\"商圣\"。","transferable_lesson":"敢于抛掉一个成功的旧身份、从头再来——敢否定过去的成功，才有第二、第三次大成。","source_tier":"secondary","source_note":"更名迁居见《史记》；经商致巨富多见《货殖列传》概述与后世传述、细节含传奇→判存疑（二轴：身份转换可考、致富细节传述）。","historicity":"disputed","linked_cards":["fanli"],"tags":["人生抉择","职业发展"],"advisor_id":"fanli"}', '13a10ade5effca713bb451279034e4ab8824b72ffca62f4ff29a412b628ea10f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('fanli-c4', 'fanli', '用计然之策·待时而动经商（经商时期）', '经商如何获利——追高跟风者常追涨杀跌、买在高点。', '范蠡用计然之策、顺供需与价格周期反向布局："旱则资舟、水则资车""贵上极则反贱"，贱买贵卖、提前备未来之需。', '据传以此致富；其周期反向之道成中国古代经商智慧的代表。', '别追高跟风——看清供需与价格的周期、反向布局，在别人未动时先备好未来之需（但高度依赖对周期的准确把握）。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"fanli-c4","status":"published","title_period":"用计然之策·待时而动经商（经商时期）","dilemma_constraints":"经商如何获利——追高跟风者常追涨杀跌、买在高点。","key_judgment":"范蠡用计然之策、顺供需与价格周期反向布局：\"旱则资舟、水则资车\"\"贵上极则反贱\"，贱买贵卖、提前备未来之需。","model_invoked":["待时而动"],"outcome":"据传以此致富；其周期反向之道成中国古代经商智慧的代表。","transferable_lesson":"别追高跟风——看清供需与价格的周期、反向布局，在别人未动时先备好未来之需（但高度依赖对周期的准确把握）。","source_tier":"secondary","source_note":"计然之策见《史记·货殖列传》；其经商应用与致富含后世传述成分→判存疑（理念可考、应用细节传述）。","historicity":"disputed","linked_cards":["fanli"],"tags":["投资","风险评估"],"advisor_id":"fanli"}', '603ec6518d09d2c9af60902ee1f97b28f1dcb2355b654cc7d7628b095c1b7c0c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhenghe-c1', 'zhenghe', '七下西洋·统御巨系统（1405—1433）', '数百艘船、两三万人、跨年的远洋航行，补给、导航、编队、人员协调任何一环失序都可能全盘崩溃。', '郑和把这一超大规模行动作为一个系统来组织——分工编队、统筹补给与导航，于极端复杂中维持秩序，七次往返。', '完成人类航海史上空前规模的七下西洋，抵达东南亚、南亚、西亚乃至东非。', '面对规模/复杂度极大的行动，别到处救火——把它当作一个系统来组织，重补给、导航、协调，于复杂中维持秩序。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhenghe-c1","status":"published","title_period":"七下西洋·统御巨系统（1405—1433）","dilemma_constraints":"数百艘船、两三万人、跨年的远洋航行，补给、导航、编队、人员协调任何一环失序都可能全盘崩溃。","key_judgment":"郑和把这一超大规模行动作为一个系统来组织——分工编队、统筹补给与导航，于极端复杂中维持秩序，七次往返。","model_invoked":["巨系统统御"],"outcome":"完成人类航海史上空前规模的七下西洋，抵达东南亚、南亚、西亚乃至东非。","transferable_lesson":"面对规模/复杂度极大的行动，别到处救火——把它当作一个系统来组织，重补给、导航、协调，于复杂中维持秩序。","source_tier":"secondary","source_note":"七下西洋的规模与组织为《明史·郑和传》《瀛涯胜览》所载→确证；惟具体决策多为朝廷意志（二轴）。","historicity":"confirmed","linked_cards":["zhenghe"],"tags":["组织管理","资源调度"],"advisor_id":"zhenghe"}', 'e05ec1eb688ec57e4095fc7863b54e4877efc68f78fdd8bc275bbf66036b0d82');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhenghe-c2', 'zhenghe', '宣德化、不占地·威服怀柔（七下西洋期间）', '率当时世界最强舰队远抵各国，完全有能力以武力征服占领。', '郑和不殖民、不占地，而是以宣示威望、厚赐招徕、通商外交换取各国朝贡与合作。', '建立了广泛的朝贡贸易与外交网络，以威望与合作而非征服达成目的。', '有压倒性实力时，把它用来"让对方愿意来"（宣示威望、招徕合作），而非"打服占领"——以威望换合作更省、网络更广（前提：实力绝对占优）。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhenghe-c2","status":"published","title_period":"宣德化、不占地·威服怀柔（七下西洋期间）","dilemma_constraints":"率当时世界最强舰队远抵各国，完全有能力以武力征服占领。","key_judgment":"郑和不殖民、不占地，而是以宣示威望、厚赐招徕、通商外交换取各国朝贡与合作。","model_invoked":["威服怀柔"],"outcome":"建立了广泛的朝贡贸易与外交网络，以威望与合作而非征服达成目的。","transferable_lesson":"有压倒性实力时，把它用来\"让对方愿意来\"（宣示威望、招徕合作），而非\"打服占领\"——以威望换合作更省、网络更广（前提：实力绝对占优）。","source_tier":"secondary","source_note":"不占地、宣德化招徕朝贡为《明史·郑和传》所载→确证。","historicity":"confirmed","linked_cards":["zhenghe"],"tags":["领导力","探索未知"],"advisor_id":"zhenghe"}', 'efe9cba6ce6bc90b231d90a0e89346040000df4d75a0925ea70f9ed99b05abe1');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhenghe-c3', 'zhenghe', '擒陈祖义、锡兰山之战·和而能战（七下西洋期间）', '远航中遭遇海盗陈祖义、锡兰山等地的敌对武力，纯靠和平无以自保。', '郑和以和平通商为常态，但在遭遇敌对时果断用武、速战速决（擒海盗陈祖义、平锡兰之乱），使"和"有实力为底。', '以果断而有限的武力震慑了敌对势力，保障了航路与和平外交的常态。', '以和平、通商为常态，但遭遇敌对/侵害时果断用武、速战速决——让你的"和"有实力为底，而非软弱可欺。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhenghe-c3","status":"published","title_period":"擒陈祖义、锡兰山之战·和而能战（七下西洋期间）","dilemma_constraints":"远航中遭遇海盗陈祖义、锡兰山等地的敌对武力，纯靠和平无以自保。","key_judgment":"郑和以和平通商为常态，但在遭遇敌对时果断用武、速战速决（擒海盗陈祖义、平锡兰之乱），使\"和\"有实力为底。","model_invoked":["和而能战"],"outcome":"以果断而有限的武力震慑了敌对势力，保障了航路与和平外交的常态。","transferable_lesson":"以和平、通商为常态，但遭遇敌对/侵害时果断用武、速战速决——让你的\"和\"有实力为底，而非软弱可欺。","source_tier":"secondary","source_note":"擒陈祖义、锡兰山之战为《明史·郑和传》所载→确证。","historicity":"confirmed","linked_cards":["zhenghe"],"tags":["领导力","风险评估"],"advisor_id":"zhenghe"}', 'b454c6e019959f613113e1e490a3d0f8a674eb3b9ff9117cfdf0a1f83d043416');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhenghe-c4', 'zhenghe', '锡兰山立三语碑·跨文化包容（1409）', '所历各地多宗教、多文明并存，强加单一信仰必招抵触。', '郑和（自身为穆斯林）在锡兰立三语碑，分别敬奉佛教、印度教、伊斯兰，以尊重包容运作而非强加单一文化。', '以尊重多元的姿态换取了广泛的接纳与合作。', '在多宗教、多文明的环境中以尊重与包容运作、不强加单一文化——借此换取广泛的接纳与合作。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhenghe-c4","status":"published","title_period":"锡兰山立三语碑·跨文化包容（1409）","dilemma_constraints":"所历各地多宗教、多文明并存，强加单一信仰必招抵触。","key_judgment":"郑和（自身为穆斯林）在锡兰立三语碑，分别敬奉佛教、印度教、伊斯兰，以尊重包容运作而非强加单一文化。","model_invoked":["跨文化包容"],"outcome":"以尊重多元的姿态换取了广泛的接纳与合作。","transferable_lesson":"在多宗教、多文明的环境中以尊重与包容运作、不强加单一文化——借此换取广泛的接纳与合作。","source_tier":"primary","source_note":"锡兰山三语碑为存世碑刻实物→确证（一手A）。","historicity":"confirmed","linked_cards":["zhenghe"],"tags":["领导力","价值与伦理"],"advisor_id":"zhenghe"}', 'b8849645ee9a03f0a0b3da62fd56b6d6bf03a875665d1feebfe1168dac64027a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('jianzhen-c1', 'jianzhen', '应荣叡普照之请·受托东渡（742）', '日本僧荣叡、普照远来恳请鉴真东渡日本传授戒律；东渡风险极大、九死一生，弟子多畏难。', '鉴真以"为是法事，何惜身命"应允、决意亲自东渡，把这一值得的请托看得重于个人安危。', '由此开启历十二年、六次的东渡传法历程。', '面对一个真正值得的远方请托，把它看得重于个人安危、受请即全力赴之——前提是这使命确实值得、而非被裹挟。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"jianzhen-c1","status":"published","title_period":"应荣叡普照之请·受托东渡（742）","dilemma_constraints":"日本僧荣叡、普照远来恳请鉴真东渡日本传授戒律；东渡风险极大、九死一生，弟子多畏难。","key_judgment":"鉴真以\"为是法事，何惜身命\"应允、决意亲自东渡，把这一值得的请托看得重于个人安危。","model_invoked":["受托即赴"],"outcome":"由此开启历十二年、六次的东渡传法历程。","transferable_lesson":"面对一个真正值得的远方请托，把它看得重于个人安危、受请即全力赴之——前提是这使命确实值得、而非被裹挟。","source_tier":"secondary","source_note":"应请东渡、\"为是法事何惜身命\"为《唐大和上东征传》所载→确证（具体语句含传记色彩）。","historicity":"confirmed","linked_cards":["jianzhen"],"tags":["人生抉择","价值与伦理"],"advisor_id":"jianzhen"}', '5465ec1f3d23ff02548e07e346d90bd38bbd152e7769fce4f7b45e54d0d63d1e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('jianzhen-c2', 'jianzhen', '六次东渡·前五次失败（742—753）', '东渡屡遭风浪、官方阻拦、船毁人散，前五次皆告失败，弟子病亡、损失惨重。', '鉴真把每一次失败当作必经的工序而非终点，每次失败后修整人、船、物资再来，前后历十二年、第六次终于成功抵日。', '第六次东渡成功，成中日文化交流史上的丰碑。', '同一目标反复失败时，把失败当工序而非终点、修整再来试到成功——但须知极致坚持代价惨重，不是"坚持必胜"的励志模板。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"jianzhen-c2","status":"published","title_period":"六次东渡·前五次失败（742—753）","dilemma_constraints":"东渡屡遭风浪、官方阻拦、船毁人散，前五次皆告失败，弟子病亡、损失惨重。","key_judgment":"鉴真把每一次失败当作必经的工序而非终点，每次失败后修整人、船、物资再来，前后历十二年、第六次终于成功抵日。","model_invoked":["屡败屡试"],"outcome":"第六次东渡成功，成中日文化交流史上的丰碑。","transferable_lesson":"同一目标反复失败时，把失败当工序而非终点、修整再来试到成功——但须知极致坚持代价惨重，不是\"坚持必胜\"的励志模板。","source_tier":"secondary","source_note":"六次东渡、前五次失败为《唐大和上东征传》所载→确证。","historicity":"confirmed","linked_cards":["jianzhen"],"tags":["人生抉择","领导力"],"advisor_id":"jianzhen"}', '1a2533eef024c919bca82390afb7f8503d64d1085368400054ee1480f9a08df4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('jianzhen-c3', 'jianzhen', '双目失明仍东渡·志不随损（东渡途中）', '在屡次东渡的磨难与疾病中，鉴真双目失明——对一位传法者是极重大的损失。', '他没有因失明放弃东渡传法的核心目标，把使命与个人能力/状态解耦、继续东渡。', '终在失明之后成功东渡、抵日传法。', '遭遇重大损失时，把使命与个人能力/状态解耦——核心目标不因损失而动摇放弃。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"jianzhen-c3","status":"published","title_period":"双目失明仍东渡·志不随损（东渡途中）","dilemma_constraints":"在屡次东渡的磨难与疾病中，鉴真双目失明——对一位传法者是极重大的损失。","key_judgment":"他没有因失明放弃东渡传法的核心目标，把使命与个人能力/状态解耦、继续东渡。","model_invoked":["志不随损"],"outcome":"终在失明之后成功东渡、抵日传法。","transferable_lesson":"遭遇重大损失时，把使命与个人能力/状态解耦——核心目标不因损失而动摇放弃。","source_tier":"secondary","source_note":"鉴真失明仍东渡为《唐大和上东征传》所载→确证。","historicity":"confirmed","linked_cards":["jianzhen"],"tags":["人生抉择","价值与伦理"],"advisor_id":"jianzhen"}', '88c09b508b6e894ab4f1e98aa930a759449affd850a3af606b75e1f93449325f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('jianzhen-c4', 'jianzhen', '携系统东渡·登坛授戒、建唐招提寺（753后）', '在异国真正建立戒律正统，不能只靠一个人、也不能遥寄文本。', '鉴真携弟子、工匠、典籍、佛像、药物等一整套系统东渡，亲登东大寺戒坛为天皇及僧众授戒、并建唐招提寺。', '把律宗与唐代文化、医药、建筑等整套系统在日本生根，影响深远。', '远行传播要带走一整套可移植的系统（人才/技艺/典籍/制度）、并亲身到场建立正统——这样才能在异地真正生根，而非只带自己或遥寄代理。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"jianzhen-c4","status":"published","title_period":"携系统东渡·登坛授戒、建唐招提寺（753后）","dilemma_constraints":"在异国真正建立戒律正统，不能只靠一个人、也不能遥寄文本。","key_judgment":"鉴真携弟子、工匠、典籍、佛像、药物等一整套系统东渡，亲登东大寺戒坛为天皇及僧众授戒、并建唐招提寺。","model_invoked":["传系统非己"],"outcome":"把律宗与唐代文化、医药、建筑等整套系统在日本生根，影响深远。","transferable_lesson":"远行传播要带走一整套可移植的系统（人才/技艺/典籍/制度）、并亲身到场建立正统——这样才能在异地真正生根，而非只带自己或遥寄代理。","source_tier":"secondary","source_note":"携弟子工匠典籍东渡、登坛授戒、建唐招提寺为《唐大和上东征传》及日本史料所载→确证。","historicity":"confirmed","linked_cards":["jianzhen"],"tags":["领导力","学习与认知"],"advisor_id":"jianzhen"}', '2873622a073f3c95b87979d6743f0206c2df17460ce6a0db923291140f89cc06');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('aristotle-c1', 'aristotle', '创立形式逻辑·三段论（《工具论》）', '如何保证推理的有效、从前提可靠地得到结论。', '亚里士多德系统创立了形式逻辑，以"三段论"等有效推理形式，保证从真前提必得真结论。', '形式逻辑成西方理性思维的基石，沿用两千余年。', '把推理拆成清晰的有效形式、检查每一步是否成立——别让结论从站不住的前提或跳跃的逻辑里溜出来。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"aristotle-c1","status":"published","title_period":"创立形式逻辑·三段论（《工具论》）","dilemma_constraints":"如何保证推理的有效、从前提可靠地得到结论。","key_judgment":"亚里士多德系统创立了形式逻辑，以\"三段论\"等有效推理形式，保证从真前提必得真结论。","model_invoked":["逻辑三段论"],"outcome":"形式逻辑成西方理性思维的基石，沿用两千余年。","transferable_lesson":"把推理拆成清晰的有效形式、检查每一步是否成立——别让结论从站不住的前提或跳跃的逻辑里溜出来。","source_tier":"primary","source_note":"三段论为亚里士多德《工具论》→确证（一手A）。","historicity":"confirmed","linked_cards":["aristotle"],"tags":["认知偏误与理性决策","组织管理"],"advisor_id":"aristotle"}', 'c527b24664b3da1f000283979445d8ff7606374bf459fe98f7e33f829b6cd905');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('aristotle-c2', 'aristotle', '博物学与经验观察·经验归纳（动物志等）', '知识应从思辨演绎、还是从经验观察中来。', '亚里士多德大量进行实地的观察与记录（如对动物的考察），从经验中归纳，区别于其师柏拉图的理念演绎。', '亚里士多德奠定了重经验观察的传统，被视为博物学与多门学科的开创者。', '从大量具体的观察与经验中归纳出规律，知识要扎根于对现实的考察——而非只从抽象原理演绎。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"aristotle-c2","status":"published","title_period":"博物学与经验观察·经验归纳（动物志等）","dilemma_constraints":"知识应从思辨演绎、还是从经验观察中来。","key_judgment":"亚里士多德大量进行实地的观察与记录（如对动物的考察），从经验中归纳，区别于其师柏拉图的理念演绎。","model_invoked":["经验归纳"],"outcome":"亚里士多德奠定了重经验观察的传统，被视为博物学与多门学科的开创者。","transferable_lesson":"从大量具体的观察与经验中归纳出规律，知识要扎根于对现实的考察——而非只从抽象原理演绎。","source_tier":"primary","source_note":"亚里士多德重经验观察、博物学为史实→确证（一手/二手A/B；部分具体结论后被证伪，已入盲区）。","historicity":"confirmed","linked_cards":["aristotle"],"tags":["认知偏误与理性决策"],"advisor_id":"aristotle"}', '3e09a68a3cc300710b24d2245479400d9a8f721914c126b59166ea6df4519d82');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('aristotle-c3', 'aristotle', '「中道」·德性在于避免两极（《尼各马可伦理学》）', '何为德性、如何在行为中把握恰当。', '亚里士多德提出"中道"——德性是避免"过度"与"不及"两个极端、因情境而定的恰当中点（如勇敢在鲁莽与怯懦之间）。', '「中道」成西方德性伦理学的核心概念。', '避免"过度"与"不及"两个极端、找到那个因情境而定的恰当中点——但并非所有事都有中道。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"aristotle-c3","status":"published","title_period":"「中道」·德性在于避免两极（《尼各马可伦理学》）","dilemma_constraints":"何为德性、如何在行为中把握恰当。","key_judgment":"亚里士多德提出\"中道\"——德性是避免\"过度\"与\"不及\"两个极端、因情境而定的恰当中点（如勇敢在鲁莽与怯懦之间）。","model_invoked":["中道"],"outcome":"「中道」成西方德性伦理学的核心概念。","transferable_lesson":"避免\"过度\"与\"不及\"两个极端、找到那个因情境而定的恰当中点——但并非所有事都有中道。","source_tier":"primary","source_note":"中道为亚里士多德《尼各马可伦理学》→确证（一手A）。","historicity":"confirmed","linked_cards":["aristotle"],"tags":["价值与伦理","修身自省"],"advisor_id":"aristotle"}', '4f1fca79d6f4b573b76beb5a08d45b58204654030d24de42baca902b55e41567');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('aristotle-c4', 'aristotle', '四因说·质料/形式/动力/目的（《物理学》《形而上学》）', '如何透彻地解释一个事物"为什么是这样"。', '亚里士多德以"四因"解释事物——质料因、形式因、动力因、目的因，尤重"目的因"（它朝向什么）。', '「四因说」成理解事物的经典框架（其中目的论后在近代自然科学中被摒弃）。', '从质料/形式/动力/目的四个角度透彻理解一个事物——尤其别漏了"它为了什么"。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"aristotle-c4","status":"published","title_period":"四因说·质料/形式/动力/目的（《物理学》《形而上学》）","dilemma_constraints":"如何透彻地解释一个事物\"为什么是这样\"。","key_judgment":"亚里士多德以\"四因\"解释事物——质料因、形式因、动力因、目的因，尤重\"目的因\"（它朝向什么）。","model_invoked":["四因说"],"outcome":"「四因说」成理解事物的经典框架（其中目的论后在近代自然科学中被摒弃）。","transferable_lesson":"从质料/形式/动力/目的四个角度透彻理解一个事物——尤其别漏了\"它为了什么\"。","source_tier":"primary","source_note":"四因说为亚里士多德《物理学》《形而上学》→确证（一手A；目的论的科学地位后变，已入盲区客观标注）。","historicity":"confirmed","linked_cards":["aristotle"],"tags":["认知偏误与理性决策","价值与伦理"],"advisor_id":"aristotle"}', '71d2513eae33728cbc8be0d223a910479567bf443be6d1f8a7a1290d94797471');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mozi-c1', 'mozi', '「兼相爱、交相利」·兼爱交相利（《兼爱》）', '天下混乱、相攻相害，根源何在、如何解。', '墨子认为乱起于"不相爱"，主张"兼相爱、交相利"——无差别地爱人、并让爱落到互相的实际利益上。', '「兼爱」成墨家的核心主张，与儒家的差等之爱形成鲜明对立。', '把关怀更普遍无差别地分配、并让它落到互相的实际利益上——爱与利结合才可持续（但须权衡可行性）。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mozi-c1","status":"published","title_period":"「兼相爱、交相利」·兼爱交相利（《兼爱》）","dilemma_constraints":"天下混乱、相攻相害，根源何在、如何解。","key_judgment":"墨子认为乱起于\"不相爱\"，主张\"兼相爱、交相利\"——无差别地爱人、并让爱落到互相的实际利益上。","model_invoked":["兼爱"],"outcome":"「兼爱」成墨家的核心主张，与儒家的差等之爱形成鲜明对立。","transferable_lesson":"把关怀更普遍无差别地分配、并让它落到互相的实际利益上——爱与利结合才可持续（但须权衡可行性）。","source_tier":"primary","source_note":"兼爱、交相利为《墨子·兼爱》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["mozi"],"tags":["价值与伦理","组织管理"],"advisor_id":"mozi"}', 'a13d288ec78249271c862b6df84ab7d4a6f3cd91aeb48b0200e1e57986be6687');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mozi-c2', 'mozi', '止楚攻宋·非攻与实力自卫（战国）', '楚国将以公输般所造的攻城器械攻打宋国。', '墨子长途奔走赶赴楚国，以高超的守城之术与公输般模拟攻防、九拒其攻，并陈明利害，终止住了楚攻宋。', '墨子成功阻止了一场侵略战争，"非攻"与精于守城并行的理念广为流传。', '反对主动去侵害别人，但要靠强大的防御实力让对方不敢侵犯你——"非攻"不等于无防备。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mozi-c2","status":"published","title_period":"止楚攻宋·非攻与实力自卫（战国）","dilemma_constraints":"楚国将以公输般所造的攻城器械攻打宋国。","key_judgment":"墨子长途奔走赶赴楚国，以高超的守城之术与公输般模拟攻防、九拒其攻，并陈明利害，终止住了楚攻宋。","model_invoked":["非攻与实力自卫"],"outcome":"墨子成功阻止了一场侵略战争，\"非攻\"与精于守城并行的理念广为流传。","transferable_lesson":"反对主动去侵害别人，但要靠强大的防御实力让对方不敢侵犯你——\"非攻\"不等于无防备。","source_tier":"primary","source_note":"止楚攻宋为《墨子·公输》所载→确证（一手A；细节属传述）。","historicity":"confirmed","linked_cards":["mozi"],"tags":["组织管理","价值与伦理"],"advisor_id":"mozi"}', '56cfb12e4bfd4827c0e92d33530873832e03a13397a35938d2bb61f6443a2d2c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mozi-c3', 'mozi', '「三表法」·检验主张（《非命上》）', '如何判断一个主张（如"有命论"）是否成立。', '墨子提出"三表"——本之于古者圣王之事、原之于百姓耳目之实、用之于刑政是否合国家百姓人民之利，作为检验言论的三条标准。', '「三表法」是中国早期重视经验与效用的检验方法，墨家逻辑的重要部分。', '判断一个说法用三尺——有历史先例吗、合大众经验吗、用起来有实效吗。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mozi-c3","status":"published","title_period":"「三表法」·检验主张（《非命上》）","dilemma_constraints":"如何判断一个主张（如\"有命论\"）是否成立。","key_judgment":"墨子提出\"三表\"——本之于古者圣王之事、原之于百姓耳目之实、用之于刑政是否合国家百姓人民之利，作为检验言论的三条标准。","model_invoked":["三表法"],"outcome":"「三表法」是中国早期重视经验与效用的检验方法，墨家逻辑的重要部分。","transferable_lesson":"判断一个说法用三尺——有历史先例吗、合大众经验吗、用起来有实效吗。","source_tier":"primary","source_note":"三表法为《墨子·非命上》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["mozi"],"tags":["认知偏误与理性决策","价值与伦理"],"advisor_id":"mozi"}', '983fc2708b2fbf1f12df81d19b53c2626c9640d5978497360522aeb0b029c636');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mozi-c4', 'mozi', '节用、节葬、非乐·节用尚实（《节用》等）', '当时厚葬久丧、礼乐铺张，耗费大量人力物力。', '墨子主张"节用""节葬""非乐"，反对一切不带来实际效用的浪费与铺张，一切以实用为准。', '节用尚实成墨家务实的标志，但也因否定礼乐文饰而受儒家批评。', '去掉一切不带来实际效用的浪费与繁文缛节、把资源投到有实效处——但极端节用也会否定情感与审美的价值。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mozi-c4","status":"published","title_period":"节用、节葬、非乐·节用尚实（《节用》等）","dilemma_constraints":"当时厚葬久丧、礼乐铺张，耗费大量人力物力。","key_judgment":"墨子主张\"节用\"\"节葬\"\"非乐\"，反对一切不带来实际效用的浪费与铺张，一切以实用为准。","model_invoked":["节用尚实"],"outcome":"节用尚实成墨家务实的标志，但也因否定礼乐文饰而受儒家批评。","transferable_lesson":"去掉一切不带来实际效用的浪费与繁文缛节、把资源投到有实效处——但极端节用也会否定情感与审美的价值。","source_tier":"primary","source_note":"节用、节葬、非乐为《墨子》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["mozi"],"tags":["价值与伦理","组织管理"],"advisor_id":"mozi"}', 'a1bc4ca906c3d72a76d1da0d6575d203a58716dd5bb6bb488aaa0a12d5bf0323');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('confucius-c1', 'confucius', '必也正名乎（《论语·子路》）', '子路问：若卫君请您从政、您先做什么？当时卫国名分紊乱（父子争位）、政事难理。', '孔子答"必也正名乎"——先正名分：名不正则言不顺、言不顺则事不成；要理政、先把名实理顺。', '「正名」成儒家治理的根本前提之一，影响后世「名实相符」的秩序观。', '事情乱、不知从何抓起时，先理顺每个角色/概念的名分与定义——名实相符了，言行与秩序才有依据。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"confucius-c1","status":"published","title_period":"必也正名乎（《论语·子路》）","dilemma_constraints":"子路问：若卫君请您从政、您先做什么？当时卫国名分紊乱（父子争位）、政事难理。","key_judgment":"孔子答\"必也正名乎\"——先正名分：名不正则言不顺、言不顺则事不成；要理政、先把名实理顺。","model_invoked":["正名"],"outcome":"「正名」成儒家治理的根本前提之一，影响后世「名实相符」的秩序观。","transferable_lesson":"事情乱、不知从何抓起时，先理顺每个角色/概念的名分与定义——名实相符了，言行与秩序才有依据。","source_tier":"secondary","source_note":"「必也正名乎」为《论语·子路》明载→确证；惟《论语》系弟子后学追记、字句语境经整理。","historicity":"confirmed","linked_cards":["confucius"],"tags":["领导力","组织管理"],"advisor_id":"confucius"}', '6ff0334141de492e4e985017c961d1fda3771239227c38e31efdb23be2d5db3c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('confucius-c2', 'confucius', '闻斯行诸·因材施教（《论语·先进》）', '子路与冉有先后问同一个问题"闻斯行诸（听到就该去做吗）"，公西华不解为何同问得相反答案。', '孔子答子路"有父兄在、不可贸然行"（抑其好勇冒进），答冉有"闻斯行之"（进其退缩犹疑）——同问因人而异。', '「闻斯行诸」成因材施教的经典例证，体现教育/带人须按对象特质区别对待。', '同一个问题对不同的人该给不同的答案——好勇的要抑、退缩的要进，按各人资质性格因材施教、不一刀切。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"confucius-c2","status":"published","title_period":"闻斯行诸·因材施教（《论语·先进》）","dilemma_constraints":"子路与冉有先后问同一个问题\"闻斯行诸（听到就该去做吗）\"，公西华不解为何同问得相反答案。","key_judgment":"孔子答子路\"有父兄在、不可贸然行\"（抑其好勇冒进），答冉有\"闻斯行之\"（进其退缩犹疑）——同问因人而异。","model_invoked":["因材施教"],"outcome":"「闻斯行诸」成因材施教的经典例证，体现教育/带人须按对象特质区别对待。","transferable_lesson":"同一个问题对不同的人该给不同的答案——好勇的要抑、退缩的要进，按各人资质性格因材施教、不一刀切。","source_tier":"secondary","source_note":"闻斯行诸为《论语·先进》明载→确证。","historicity":"confirmed","linked_cards":["confucius"],"tags":["组织管理","修身自省"],"advisor_id":"confucius"}', '69e54076a1c809363ecc74c041c3a6116058bf24798f606fbff9bd85f7959313');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('confucius-c3', 'confucius', '修己以安人（《论语·宪问》）', '子路问怎样才算君子；如何由个人修养通达治理他人。', '孔子答"修己以敬→修己以安人→修己以安百姓"——治人先治己、由修养自身层层推及安顿他人。', '「修己安人」成儒家「内圣外王」的核心逻辑，影响后世修身与治理观。', '想影响他人或治理，先从修养自己开始——其身正、不令而行；以身作则比发号施令更有效。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"confucius-c3","status":"published","title_period":"修己以安人（《论语·宪问》）","dilemma_constraints":"子路问怎样才算君子；如何由个人修养通达治理他人。","key_judgment":"孔子答\"修己以敬→修己以安人→修己以安百姓\"——治人先治己、由修养自身层层推及安顿他人。","model_invoked":["修己以安人"],"outcome":"「修己安人」成儒家「内圣外王」的核心逻辑，影响后世修身与治理观。","transferable_lesson":"想影响他人或治理，先从修养自己开始——其身正、不令而行；以身作则比发号施令更有效。","source_tier":"secondary","source_note":"修己以安人/安百姓为《论语·宪问》明载→确证。","historicity":"confirmed","linked_cards":["confucius"],"tags":["领导力","修身自省"],"advisor_id":"confucius"}', '11ea43c42821e6545bf5a0fd4e3a968518b30f8aa769e246461303c81702e461');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mengzi-c1', 'mengzi', '孺子将入井之恻隐·性善四端（《公孙丑上》）', '人性究竟是善是恶，关乎如何看待与对待人。', '孟子以"今人乍见孺子将入于井，皆有怵惕恻隐之心"为例，论证人本有恻隐、羞恶、辞让、是非"四端"，扩充之即成仁义礼智。', '「性善四端」成孟子思想的核心，深刻影响了中国的人性论与教育观。', '相信并激发人本有的善与潜能（四端）、而非一上来就假定人性本恶去防范压制（但对人性恶也需制度防范）。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mengzi-c1","status":"published","title_period":"孺子将入井之恻隐·性善四端（《公孙丑上》）","dilemma_constraints":"人性究竟是善是恶，关乎如何看待与对待人。","key_judgment":"孟子以\"今人乍见孺子将入于井，皆有怵惕恻隐之心\"为例，论证人本有恻隐、羞恶、辞让、是非\"四端\"，扩充之即成仁义礼智。","model_invoked":["性善四端"],"outcome":"「性善四端」成孟子思想的核心，深刻影响了中国的人性论与教育观。","transferable_lesson":"相信并激发人本有的善与潜能（四端）、而非一上来就假定人性本恶去防范压制（但对人性恶也需制度防范）。","source_tier":"primary","source_note":"四端说为《孟子·公孙丑上》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["mengzi"],"tags":["价值与伦理","修身自省"],"advisor_id":"mengzi"}', '2548f847585467e737c69e595dae96c53e87ba1c7e8f23a37755f04917bdb8a7');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mengzi-c2', 'mengzi', '「得民心者得天下」·仁政得民心（《离娄上》）', '君主如何才能真正得天下、长治久安。', '孟子主张行仁政、得民心——"得其民，斯得天下矣"，反对靠强力压服。', '仁政与民本思想成儒家政治哲学的核心主张之一。', '靠善待、保护、满足你服务的对象去赢得真心拥护——"得民心者得天下"，而非靠强力压服。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mengzi-c2","status":"published","title_period":"「得民心者得天下」·仁政得民心（《离娄上》）","dilemma_constraints":"君主如何才能真正得天下、长治久安。","key_judgment":"孟子主张行仁政、得民心——\"得其民，斯得天下矣\"，反对靠强力压服。","model_invoked":["仁政得民心"],"outcome":"仁政与民本思想成儒家政治哲学的核心主张之一。","transferable_lesson":"靠善待、保护、满足你服务的对象去赢得真心拥护——\"得民心者得天下\"，而非靠强力压服。","source_tier":"primary","source_note":"「得民心」说为《孟子·离娄上》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["mengzi"],"tags":["领导力","价值与伦理"],"advisor_id":"mengzi"}', '028ded0a15b76cc328928711896f336d0878901fe29fcd2b61e1fe81d011b444');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mengzi-c3', 'mengzi', '「我善养吾浩然之气」·浩然之气（《公孙丑上》）', '人如何获得一种强大、不被外物撼动的内在底气。', '孟子提出"浩然之气"——靠长期"配义与道"的积累养成，至大至刚，不能靠一时血气或揠苗助长。', '「浩然之气」成中国士人精神修养的重要追求。', '靠长期做合乎道义的事积累、养出至大至刚、不被外物撼动的精神底气——不能靠一时血气。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mengzi-c3","status":"published","title_period":"「我善养吾浩然之气」·浩然之气（《公孙丑上》）","dilemma_constraints":"人如何获得一种强大、不被外物撼动的内在底气。","key_judgment":"孟子提出\"浩然之气\"——靠长期\"配义与道\"的积累养成，至大至刚，不能靠一时血气或揠苗助长。","model_invoked":["浩然之气"],"outcome":"「浩然之气」成中国士人精神修养的重要追求。","transferable_lesson":"靠长期做合乎道义的事积累、养出至大至刚、不被外物撼动的精神底气——不能靠一时血气。","source_tier":"primary","source_note":"浩然之气说为《孟子·公孙丑上》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["mengzi"],"tags":["修身自省","价值与伦理"],"advisor_id":"mengzi"}', '69e0d2d4da36c419cdd7e6a139c0ed9d14ea1008f4c11ab8e55fdf83754a0d48');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mengzi-c4', 'mengzi', '「王何必曰利」·义利之辨（《梁惠王上》）', '梁惠王问孟子有何对自己国家"有利"之策。', '孟子答"王何必曰利？亦有仁义而已矣"，把"义（该不该）"置于"利（划不划算）"之上。', '「义利之辨」成儒家价值排序的经典命题。', '在"义（该不该）"与"利（划不划算）"冲突时把义置于利之上——有些底线不能用利益衡量。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mengzi-c4","status":"published","title_period":"「王何必曰利」·义利之辨（《梁惠王上》）","dilemma_constraints":"梁惠王问孟子有何对自己国家\"有利\"之策。","key_judgment":"孟子答\"王何必曰利？亦有仁义而已矣\"，把\"义（该不该）\"置于\"利（划不划算）\"之上。","model_invoked":["义利之辨"],"outcome":"「义利之辨」成儒家价值排序的经典命题。","transferable_lesson":"在\"义（该不该）\"与\"利（划不划算）\"冲突时把义置于利之上——有些底线不能用利益衡量。","source_tier":"primary","source_note":"义利之辨为《孟子·梁惠王上》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["mengzi"],"tags":["价值与伦理","修身自省"],"advisor_id":"mengzi"}', '573bb11228cb6184fec42b0c373541d3ce4516eb74712daad4d5088c32c8d4e2');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhuangzi-c1', 'zhuangzi', '庖丁解牛·依乎天理（《庄子·养生主》寓言）', '一般厨工解牛、刀刃因砍骨而频繁折损；如何省力而持久地处理复杂的结构。', '庖丁解牛"依乎天理、批大郤、导大窾"——顺着牛体本身的筋骨缝隙与结构下刀、避开硬骨，故刀刃十九年如新、游刃有余。', '「庖丁解牛」成顺应规律、游刃有余的经典寓言，喻处事当循其本然结构、不蛮力强加。', '处理复杂的事别蛮力硬刚——摸清它本身的结构与"纹理"、沿着缝隙使力，才能游刃有余、省力而持久。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"zhuangzi-c1","status":"published","title_period":"庖丁解牛·依乎天理（《庄子·养生主》寓言）","dilemma_constraints":"一般厨工解牛、刀刃因砍骨而频繁折损；如何省力而持久地处理复杂的结构。","key_judgment":"庖丁解牛\"依乎天理、批大郤、导大窾\"——顺着牛体本身的筋骨缝隙与结构下刀、避开硬骨，故刀刃十九年如新、游刃有余。","model_invoked":["因循自然"],"outcome":"「庖丁解牛」成顺应规律、游刃有余的经典寓言，喻处事当循其本然结构、不蛮力强加。","transferable_lesson":"处理复杂的事别蛮力硬刚——摸清它本身的结构与\"纹理\"、沿着缝隙使力，才能游刃有余、省力而持久。","source_tier":"primary","source_note":"庖丁解牛为《庄子·养生主》内篇寓言、文本内容确证；惟系寓言、非史实事件，故作为\"决策案例\"判 historicity 存疑（寓言、取义理）。","historicity":"disputed","linked_cards":["zhuangzi"],"tags":["修身自省","认知偏误与理性决策"],"advisor_id":"zhuangzi"}', '58a7371ab0360e5482c9bab2a4a0a84c9d9bd965c10b5e849415c78b0894f8fc');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhuangzi-c2', 'zhuangzi', '无用之大树·不材得终天年（《庄子·人间世/逍遥游》寓言）', '世人皆以"有用"为贵、争相成材、却因"有用"而早被砍伐取用。', '庄子借"散木/大樗"立论——正因其"不材无用"、匠人不顾，反得以不被砍伐、终其天年；"无用"恰是其大用（全生）。', '「无用之用」成重估价值标准的经典寓言，喻别被单一「有用」标准绑架。', '别被单一的"有用"标准绑架——看似"无用"的，可能恰恰因此得以保全、或有不被察觉的大用。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"zhuangzi-c2","status":"published","title_period":"无用之大树·不材得终天年（《庄子·人间世/逍遥游》寓言）","dilemma_constraints":"世人皆以\"有用\"为贵、争相成材、却因\"有用\"而早被砍伐取用。","key_judgment":"庄子借\"散木/大樗\"立论——正因其\"不材无用\"、匠人不顾，反得以不被砍伐、终其天年；\"无用\"恰是其大用（全生）。","model_invoked":["无用之用"],"outcome":"「无用之用」成重估价值标准的经典寓言，喻别被单一「有用」标准绑架。","transferable_lesson":"别被单一的\"有用\"标准绑架——看似\"无用\"的，可能恰恰因此得以保全、或有不被察觉的大用。","source_tier":"primary","source_note":"散木/大樗为《庄子》(逍遥游/人间世)寓言、文本确证；系寓言非史实事件→historicity 存疑（取义理）。","historicity":"disputed","linked_cards":["zhuangzi"],"tags":["价值与伦理","人生抉择"],"advisor_id":"zhuangzi"}', 'd81bf69f715f014cc5744e5c56d5a2c1bcb3c962bcdeceb39b006aedbf90ac7e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhuangzi-c3', 'zhuangzi', '庄周梦蝶·物化（《庄子·齐物论》寓言）', '人执着于固定的身份与眼前的得失、视角单一、难以超脱。', '庄子梦为蝴蝶、栩栩然忘其为周；醒后不知是周梦蝶、还是蝶梦周——以"物化"点出视角与身份本是流动可转换的。', '「庄周梦蝶」成视角转换、破除我执的千古名喻。', '别被单一视角与一时身份困死——视角是流动可换的，把眼前的得失换一个更大的参照看，往往只是一种转化。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"zhuangzi-c3","status":"published","title_period":"庄周梦蝶·物化（《庄子·齐物论》寓言）","dilemma_constraints":"人执着于固定的身份与眼前的得失、视角单一、难以超脱。","key_judgment":"庄子梦为蝴蝶、栩栩然忘其为周；醒后不知是周梦蝶、还是蝶梦周——以\"物化\"点出视角与身份本是流动可转换的。","model_invoked":["物化换视角"],"outcome":"「庄周梦蝶」成视角转换、破除我执的千古名喻。","transferable_lesson":"别被单一视角与一时身份困死——视角是流动可换的，把眼前的得失换一个更大的参照看，往往只是一种转化。","source_tier":"primary","source_note":"庄周梦蝶为《庄子·齐物论》内篇寓言、文本确证；系寓言非史实事件→historicity 存疑（取义理）。","historicity":"disputed","linked_cards":["zhuangzi"],"tags":["修身自省","认知偏误与理性决策"],"advisor_id":"zhuangzi"}', 'b2ad52ae43067113fec1a78f525175adc0b2964fd37ece729ad1ebb895518b55');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('kant-c1', 'kant', '定言令式·绝对律令（《道德形而上学奠基》）', '道德的根据何在、如何判断一个行为是否道德。', '康德提出"定言令式"——"要只按照你同时能够意愿它成为普遍法则的准则去行动"，以可普遍化作为道德的检验。', '绝对律令成义务论伦理学的核心，深刻影响了西方道德哲学。', '判断一个做法对不对，问"如果所有人都这么做这准则还成立吗"——只按你愿意它成为普遍法则的原则行动。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"kant-c1","status":"published","title_period":"定言令式·绝对律令（《道德形而上学奠基》）","dilemma_constraints":"道德的根据何在、如何判断一个行为是否道德。","key_judgment":"康德提出\"定言令式\"——\"要只按照你同时能够意愿它成为普遍法则的准则去行动\"，以可普遍化作为道德的检验。","model_invoked":["绝对律令"],"outcome":"绝对律令成义务论伦理学的核心，深刻影响了西方道德哲学。","transferable_lesson":"判断一个做法对不对，问\"如果所有人都这么做这准则还成立吗\"——只按你愿意它成为普遍法则的原则行动。","source_tier":"primary","source_note":"定言令式为康德《道德形而上学奠基》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["kant"],"tags":["价值与伦理","修身自省"],"advisor_id":"kant"}', 'ae7ea77d0474efe18a23b63ff5e373c82b0ac2916f8f8b06cb88964c328803be');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('kant-c2', 'kant', '「人是目的」·不可仅把人当手段（《道德形而上学奠基》）', '在追求目标时，如何对待他人。', '康德主张"人是目的"——要永远把人（包括自己）当作目的，而绝不仅仅当作手段。', '「人是目的」成现代人权与尊严观念的重要哲学根据。', '永远把人（包括你自己）当作"目的"、而不仅仅是实现别的目标的"工具"——这是不可逾越的底线。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"kant-c2","status":"published","title_period":"「人是目的」·不可仅把人当手段（《道德形而上学奠基》）","dilemma_constraints":"在追求目标时，如何对待他人。","key_judgment":"康德主张\"人是目的\"——要永远把人（包括自己）当作目的，而绝不仅仅当作手段。","model_invoked":["人是目的"],"outcome":"「人是目的」成现代人权与尊严观念的重要哲学根据。","transferable_lesson":"永远把人（包括你自己）当作\"目的\"、而不仅仅是实现别的目标的\"工具\"——这是不可逾越的底线。","source_tier":"primary","source_note":"「人是目的」为康德《道德形而上学奠基》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["kant"],"tags":["价值与伦理","领导力"],"advisor_id":"kant"}', '8f10e716b35e5b3d40cf87b8f519d2d399b055480ff173a64d479518581fc02e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('kant-c3', 'kant', '「哥白尼式革命」·认识论转向（《纯粹理性批判》）', '我们的知识如何可能、认识与对象的关系是什么。', '康德提出"哥白尼式革命"——不是我们的认识符合对象，而是对象符合我们先天的认识形式（时空、范畴）。', '这一转向重塑了认识论，开启了德国古典哲学。', '别只盯着对象、先反思你用来认识它的框架本身——很多东西是被你的认知框架塑造的。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"kant-c3","status":"published","title_period":"「哥白尼式革命」·认识论转向（《纯粹理性批判》）","dilemma_constraints":"我们的知识如何可能、认识与对象的关系是什么。","key_judgment":"康德提出\"哥白尼式革命\"——不是我们的认识符合对象，而是对象符合我们先天的认识形式（时空、范畴）。","model_invoked":["哥白尼式转向"],"outcome":"这一转向重塑了认识论，开启了德国古典哲学。","transferable_lesson":"别只盯着对象、先反思你用来认识它的框架本身——很多东西是被你的认知框架塑造的。","source_tier":"primary","source_note":"「哥白尼式革命」为康德《纯粹理性批判》核心→确证（一手A）。","historicity":"confirmed","linked_cards":["kant"],"tags":["认知偏误与理性决策","修身自省"],"advisor_id":"kant"}', '4f4e122a2d35d7a09b5a6104f16e6bc35230063dfe4a77d546f7b685d0b118e5');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('kant-c4', 'kant', '二律背反·理性的界限（《纯粹理性批判》）', '理性能否解答"宇宙有无开端""有无自由意志"等终极问题。', '康德指出，理性在超出经验的范围时会陷入"二律背反"——正题与反题都能被同样有力地证明，说明这类问题超出了理性的合法界限。', '「二律背反」划定了理性的合法界限，是康德「批判」的关键。', '理性推到超出经验的范围、常会陷入"正反都能自圆其说"的矛盾——警惕在没有经验可检验的地方独断下结论。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"kant-c4","status":"published","title_period":"二律背反·理性的界限（《纯粹理性批判》）","dilemma_constraints":"理性能否解答\"宇宙有无开端\"\"有无自由意志\"等终极问题。","key_judgment":"康德指出，理性在超出经验的范围时会陷入\"二律背反\"——正题与反题都能被同样有力地证明，说明这类问题超出了理性的合法界限。","model_invoked":["二律背反"],"outcome":"「二律背反」划定了理性的合法界限，是康德「批判」的关键。","transferable_lesson":"理性推到超出经验的范围、常会陷入\"正反都能自圆其说\"的矛盾——警惕在没有经验可检验的地方独断下结论。","source_tier":"primary","source_note":"「二律背反」为康德《纯粹理性批判》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["kant"],"tags":["认知偏误与理性决策","价值与伦理"],"advisor_id":"kant"}', 'ec5b49bf9f917db8182d822960a6b52d40b3795c779aed5a6dfa8a68948084f1');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhuxi-c1', 'zhuxi', '「用力之久，豁然贯通」·格物致知（《大学章句》补传）', '如何获得真正的、贯通的知识。', '朱熹补《大学》格物致知传，主张"即物而穷其理"，一件件探究、积累，"至于用力之久，而一旦豁然贯通"。', '「格物致知」成程朱理学的认识论核心，强调积累与渐进。', '一件一件具体地探究事物的理、靠积累直到豁然贯通——而非空想或指望顿悟。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhuxi-c1","status":"published","title_period":"「用力之久，豁然贯通」·格物致知（《大学章句》补传）","dilemma_constraints":"如何获得真正的、贯通的知识。","key_judgment":"朱熹补《大学》格物致知传，主张\"即物而穷其理\"，一件件探究、积累，\"至于用力之久，而一旦豁然贯通\"。","model_invoked":["格物致知"],"outcome":"「格物致知」成程朱理学的认识论核心，强调积累与渐进。","transferable_lesson":"一件一件具体地探究事物的理、靠积累直到豁然贯通——而非空想或指望顿悟。","source_tier":"primary","source_note":"格物补传为朱熹《大学章句》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["zhuxi"],"tags":["认知偏误与理性决策","长期规划"],"advisor_id":"zhuxi"}', 'fdbe500b34aec2d19a70e4ab8539069bf03638a724b3b8676cd00dc19a2931d4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhuxi-c2', 'zhuxi', '「理一分殊」·万物统体一太极（朱熹理学）', '万物纷繁各异，与那个根本的"理"是什么关系。', '朱熹以"理一分殊"统摄——万物各具其理（分殊），又同归于一个根本之理（理一），如"月映万川"。', '「理一分殊」成理学贯通「一与多」的核心命题。', '既要钻进万物各自的具体道理，又要把握那个统摄全局的根本之理——别只见树木或只见森林。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhuxi-c2","status":"published","title_period":"「理一分殊」·万物统体一太极（朱熹理学）","dilemma_constraints":"万物纷繁各异，与那个根本的\"理\"是什么关系。","key_judgment":"朱熹以\"理一分殊\"统摄——万物各具其理（分殊），又同归于一个根本之理（理一），如\"月映万川\"。","model_invoked":["理一分殊"],"outcome":"「理一分殊」成理学贯通「一与多」的核心命题。","transferable_lesson":"既要钻进万物各自的具体道理，又要把握那个统摄全局的根本之理——别只见树木或只见森林。","source_tier":"primary","source_note":"「理一分殊」为朱熹理学核心命题→确证（一手A）。","historicity":"confirmed","linked_cards":["zhuxi"],"tags":["认知偏误与理性决策","修身自省"],"advisor_id":"zhuxi"}', 'd79fdb08ef8f5250ac46f4776709ca2fe90382197ea92b9b54c389f3b9c1f630');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhuxi-c3', 'zhuxi', '「存天理、去人欲」·节制过度之欲（《朱子语类》）', '人的私欲若放纵，会蔽塞正当的道理。', '朱熹主张"存天理、去人欲"——用正当的道理节制过度的私欲（其本义为节制"过度"之欲，非禁绝一切欲望，如"饮食者天理也，要求美味人欲也"）。', '「存天理去人欲」成理学修养论的核心，但后世常被误读为禁欲。', '用正当的道理节制过度的私欲、让欲望服从于更高的道理与节度——不是禁绝一切欲望。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhuxi-c3","status":"published","title_period":"「存天理、去人欲」·节制过度之欲（《朱子语类》）","dilemma_constraints":"人的私欲若放纵，会蔽塞正当的道理。","key_judgment":"朱熹主张\"存天理、去人欲\"——用正当的道理节制过度的私欲（其本义为节制\"过度\"之欲，非禁绝一切欲望，如\"饮食者天理也，要求美味人欲也\"）。","model_invoked":["存天理去人欲"],"outcome":"「存天理去人欲」成理学修养论的核心，但后世常被误读为禁欲。","transferable_lesson":"用正当的道理节制过度的私欲、让欲望服从于更高的道理与节度——不是禁绝一切欲望。","source_tier":"primary","source_note":"「存天理去人欲」为《朱子语类》所载→确证（一手A；后世误读为禁欲、已入盲区客观标注）。","historicity":"confirmed","linked_cards":["zhuxi"],"tags":["修身自省","价值与伦理"],"advisor_id":"zhuxi"}', '8e6f75f0b2d5a4bc8e16f8b8e49e29822c2875895e6532f8a7721674bc1229a5');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhuxi-c4', 'zhuxi', '循序渐进、熟读精思·读书法（《朱子读书法》）', '读书治学如何才能真正有得。', '朱熹总结出系统的读书法——循序渐进、熟读精思、虚心涵泳、切己体察、著紧用力、居敬持志。', '「朱子读书法」成中国治学方法的经典。', '治学要有方法——循序渐进、熟读精思、虚心涵泳，系统的方法胜过乱读。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhuxi-c4","status":"published","title_period":"循序渐进、熟读精思·读书法（《朱子读书法》）","dilemma_constraints":"读书治学如何才能真正有得。","key_judgment":"朱熹总结出系统的读书法——循序渐进、熟读精思、虚心涵泳、切己体察、著紧用力、居敬持志。","model_invoked":["读书穷理之法"],"outcome":"「朱子读书法」成中国治学方法的经典。","transferable_lesson":"治学要有方法——循序渐进、熟读精思、虚心涵泳，系统的方法胜过乱读。","source_tier":"primary","source_note":"读书法为朱熹所论、后人辑为《朱子读书法》→确证（一手/二手A/B）。","historicity":"confirmed","linked_cards":["zhuxi"],"tags":["认知偏误与理性决策","长期规划"],"advisor_id":"zhuxi"}', 'a237fec450663944a27182c0ff4fb723bb32a633a94776d31c3cc596118b8f1b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('plato-c1', 'plato', '理念论·可感事物是理念的摹本（《理想国》《斐多》）', '可感世界纷繁变动，真正稳定、真实的知识从何而来。', '柏拉图提出"理念（Form）"——现象背后有更真实、永恒的理型，可感事物只是其摹本，真知是对理念的把握。', '理念论成西方形而上学的奠基，深刻影响了后世哲学。', '透过纷繁变动的现象、追问那个更本质、更稳定的"原型/本质"——别停在具体表象。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"plato-c1","status":"published","title_period":"理念论·可感事物是理念的摹本（《理想国》《斐多》）","dilemma_constraints":"可感世界纷繁变动，真正稳定、真实的知识从何而来。","key_judgment":"柏拉图提出\"理念（Form）\"——现象背后有更真实、永恒的理型，可感事物只是其摹本，真知是对理念的把握。","model_invoked":["理念论"],"outcome":"理念论成西方形而上学的奠基，深刻影响了后世哲学。","transferable_lesson":"透过纷繁变动的现象、追问那个更本质、更稳定的\"原型/本质\"——别停在具体表象。","source_tier":"primary","source_note":"理念论为柏拉图《理想国》《斐多》核心思想→确证（一手A）。","historicity":"confirmed","linked_cards":["plato"],"tags":["认知偏误与理性决策","价值与伦理"],"advisor_id":"plato"}', 'dd6aa3342d08f1807e38eb7a93544c10b0e8a6c3e8547d2d09e2123ef3bf0db2');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('plato-c2', 'plato', '洞穴之喻·挣脱认知的洞穴（《理想国》）', '人如何意识到并超越自己认知的局限。', '柏拉图以"洞穴之喻"——被锁的囚徒把墙上影子当真实，唯有挣脱走出洞穴才能见到真正的世界与太阳（善的理念）。', '「洞穴喻」成关于认知局限与启蒙的经典隐喻。', '警惕被困在自己的"认知洞穴"里、把眼前影子当全部真实——挣脱成见、走出去看更大的真相。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"plato-c2","status":"published","title_period":"洞穴之喻·挣脱认知的洞穴（《理想国》）","dilemma_constraints":"人如何意识到并超越自己认知的局限。","key_judgment":"柏拉图以\"洞穴之喻\"——被锁的囚徒把墙上影子当真实，唯有挣脱走出洞穴才能见到真正的世界与太阳（善的理念）。","model_invoked":["洞穴喻"],"outcome":"「洞穴喻」成关于认知局限与启蒙的经典隐喻。","transferable_lesson":"警惕被困在自己的\"认知洞穴\"里、把眼前影子当全部真实——挣脱成见、走出去看更大的真相。","source_tier":"primary","source_note":"洞穴喻为柏拉图《理想国》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["plato"],"tags":["认知偏误与理性决策","修身自省"],"advisor_id":"plato"}', 'd458fe769ac2a83c55e94a758165b1fd73a8ecb499c527e6251b075192b48813');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('plato-c3', 'plato', '对话式诘问·辩证法（柏拉图对话录）', '如何逼近真理、检验一个观念是否站得住。', '柏拉图继承苏格拉底的诘问法，以对话中不断的提问、反驳、辨析（辩证法）层层逼近真理。', '辩证法成西方理性论辩与求真的重要传统。', '用对话式的提问、反驳、辨析去检验和提炼一个观念，层层逼近真理，而非独断下结论。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"plato-c3","status":"published","title_period":"对话式诘问·辩证法（柏拉图对话录）","dilemma_constraints":"如何逼近真理、检验一个观念是否站得住。","key_judgment":"柏拉图继承苏格拉底的诘问法，以对话中不断的提问、反驳、辨析（辩证法）层层逼近真理。","model_invoked":["辩证法"],"outcome":"辩证法成西方理性论辩与求真的重要传统。","transferable_lesson":"用对话式的提问、反驳、辨析去检验和提炼一个观念，层层逼近真理，而非独断下结论。","source_tier":"primary","source_note":"辩证法贯穿柏拉图对话录→确证（一手A）。","historicity":"confirmed","linked_cards":["plato"],"tags":["认知偏误与理性决策","价值与伦理"],"advisor_id":"plato"}', '6b3130990f8da83d7d53403ef70f99cdc330518cd05bb7ada320e782dc5adedf');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('plato-c4', 'plato', '理想国·灵魂三分与哲学王（《理想国》）', '一个正义的人/城邦应如何构成、由谁治理。', '柏拉图主张灵魂分理性/激情/欲望、各守其分由理性统领即"正义"；推及城邦，应由真正有智慧的"哲学王"治理。', '「理想国」成西方政治哲学的奠基性构想（也长期受关于精英统治的争议）。', '让系统各部分各守其分、由最该主导的部分统领；把事交给真正懂它的人——但须知"哲学王"式构想现实中难实现、有精英专制之险。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"plato-c4","status":"published","title_period":"理想国·灵魂三分与哲学王（《理想国》）","dilemma_constraints":"一个正义的人/城邦应如何构成、由谁治理。","key_judgment":"柏拉图主张灵魂分理性/激情/欲望、各守其分由理性统领即\"正义\"；推及城邦，应由真正有智慧的\"哲学王\"治理。","model_invoked":["灵魂三分与正义"],"outcome":"「理想国」成西方政治哲学的奠基性构想（也长期受关于精英统治的争议）。","transferable_lesson":"让系统各部分各守其分、由最该主导的部分统领；把事交给真正懂它的人——但须知\"哲学王\"式构想现实中难实现、有精英专制之险。","source_tier":"primary","source_note":"灵魂三分、哲学王为柏拉图《理想国》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["plato"],"tags":["领导力","价值与伦理"],"advisor_id":"plato"}', 'ff88c8ffedf679b270995f3cbdc26f48ee7a3b2caa4544676107cc88341f1eff');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wangyangming-c1', 'wangyangming', '龙场悟道（1508，贵州龙场）', '王阳明因得罪权宦刘瑾被贬贵州龙场驿（蛮荒瘴疠之地），处绝境、生死一线，旧学（向外格物穷理）于此无所凭依。', '绝境中大悟"圣人之道、吾性自足、向之求理于事物者误也"——理不在外物、而在本心；确立"心即理"。', '龙场悟道成阳明心学的起点，由此开出知行合一、致良知之教，影响东亚思想数百年。', '越是一味向外部权威与标准答案逐求、越求越乱时，不妨回到自己的本心找根本依据——理往往不在外、而在心。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wangyangming-c1","status":"published","title_period":"龙场悟道（1508，贵州龙场）","dilemma_constraints":"王阳明因得罪权宦刘瑾被贬贵州龙场驿（蛮荒瘴疠之地），处绝境、生死一线，旧学（向外格物穷理）于此无所凭依。","key_judgment":"绝境中大悟\"圣人之道、吾性自足、向之求理于事物者误也\"——理不在外物、而在本心；确立\"心即理\"。","model_invoked":["心即理"],"outcome":"龙场悟道成阳明心学的起点，由此开出知行合一、致良知之教，影响东亚思想数百年。","transferable_lesson":"越是一味向外部权威与标准答案逐求、越求越乱时，不妨回到自己的本心找根本依据——理往往不在外、而在心。","source_tier":"secondary","source_note":"龙场悟道为《年谱》《传习录》所载；其顿悟心路含本人自述，但被贬龙场与思想转向为信史→确证（事实确证、顿悟心路含自述）。","historicity":"confirmed","linked_cards":["wangyangming"],"tags":["修身自省","探索未知"],"advisor_id":"wangyangming"}', '468cd7804712cfff896e941088ffa740e22f0bb003ddd0ffa284706b3d1e9698');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wangyangming-c2', 'wangyangming', '平定宁王朱宸濠之乱（1519）', '宁王朱宸濠起兵叛乱、来势汹汹；王阳明手中无朝廷正规大军、须临机调集、以弱当强。', '他果决用兵、虚实疑兵、攻其必救（直捣南昌），把心学的"知"落为果决之"行"、临危依良知而决，四十余日即平定叛乱。', '以少胜多、迅速平乱，成其"知行合一"用于事功的典范，世称其"立德立功立言"三不朽。', '真正的"知"必落为果决的"行"——临大事时，把认知化为坚决的行动、依内心清明的判断而决，知行合一才见真章。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wangyangming-c2","status":"published","title_period":"平定宁王朱宸濠之乱（1519）","dilemma_constraints":"宁王朱宸濠起兵叛乱、来势汹汹；王阳明手中无朝廷正规大军、须临机调集、以弱当强。","key_judgment":"他果决用兵、虚实疑兵、攻其必救（直捣南昌），把心学的\"知\"落为果决之\"行\"、临危依良知而决，四十余日即平定叛乱。","model_invoked":["知行合一"],"outcome":"以少胜多、迅速平乱，成其\"知行合一\"用于事功的典范，世称其\"立德立功立言\"三不朽。","transferable_lesson":"真正的\"知\"必落为果决的\"行\"——临大事时，把认知化为坚决的行动、依内心清明的判断而决，知行合一才见真章。","source_tier":"secondary","source_note":"平宁王之乱为《明史·王守仁传》等明载→确证。","historicity":"confirmed","linked_cards":["wangyangming"],"tags":["危机应对","领导力"],"advisor_id":"wangyangming"}', 'daf1d837986c77ea57d66a59997a37c26628d07732a0f22e1ba4a442ad38f885');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wangyangming-c3', 'wangyangming', '破山中贼易、破心中贼难（剿匪时书信）', '王阳明奉命剿平南赣等地山贼，外在的"山中贼"虽顽却可平；但他点出更难的另一层。', '他在致弟子书中言"破山中贼易、破心中贼难"——外在之敌好破，内心的私欲杂念才是最难克治的根本。', '「破心中贼难」成阳明心学修养论的名言，把功夫指向克治自己的内心。', '外在的困难再难也可破，真正难破的是你内心的私欲与杂念——把根本功夫下在克治自己的内心上。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wangyangming-c3","status":"published","title_period":"破山中贼易、破心中贼难（剿匪时书信）","dilemma_constraints":"王阳明奉命剿平南赣等地山贼，外在的\"山中贼\"虽顽却可平；但他点出更难的另一层。","key_judgment":"他在致弟子书中言\"破山中贼易、破心中贼难\"——外在之敌好破，内心的私欲杂念才是最难克治的根本。","model_invoked":["破心中贼难"],"outcome":"「破心中贼难」成阳明心学修养论的名言，把功夫指向克治自己的内心。","transferable_lesson":"外在的困难再难也可破，真正难破的是你内心的私欲与杂念——把根本功夫下在克治自己的内心上。","source_tier":"primary","source_note":"「破山中贼易、破心中贼难」出王阳明本人书信→确证（本人手笔A）。","historicity":"confirmed","linked_cards":["wangyangming"],"tags":["修身自省","价值与伦理"],"advisor_id":"wangyangming"}', '4c866d0bec3733357394a517c62c4ea4ec4c54e93d2f8854a963ca2c13edfeef');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('laozi-c1', 'laozi', '治大国若烹小鲜（《道德经》命题）', '治理者常因急于求成而频繁干预、政令朝令夕改，反而扰动民生、坏了事。', '老子提出"治大国若烹小鲜"——治国如煎小鱼、不可频繁翻动；以"无为"减少不必要的人为干预、顺民之自然。', '「无为而治」成道家治理观的核心，影响后世「与民休息」（如汉初黄老之治）的实践。', '管得太多、折腾太频反而坏事——克制干预冲动、顺事物自身势头、减少不必要的操作，少干预反而成事。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"laozi-c1","status":"published","title_period":"治大国若烹小鲜（《道德经》命题）","dilemma_constraints":"治理者常因急于求成而频繁干预、政令朝令夕改，反而扰动民生、坏了事。","key_judgment":"老子提出\"治大国若烹小鲜\"——治国如煎小鱼、不可频繁翻动；以\"无为\"减少不必要的人为干预、顺民之自然。","model_invoked":["无为而治"],"outcome":"「无为而治」成道家治理观的核心，影响后世「与民休息」（如汉初黄老之治）的实践。","transferable_lesson":"管得太多、折腾太频反而坏事——克制干预冲动、顺事物自身势头、减少不必要的操作，少干预反而成事。","source_tier":"primary","source_note":"命题出《道德经》、文本内容确证；惟老子其人与《道德经》作者、成书年代均存争议，故归属判存疑（文本确证、作者存疑）。","historicity":"disputed","linked_cards":["laozi"],"tags":["治理决策","修身自省"],"advisor_id":"laozi"}', '28e322fd992b55ffa50654de6248e073928c91a9a18c4d7f61929bd4c5b69fab');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('laozi-c2', 'laozi', '江海为百谷王·善下处弱（《道德经》命题）', '人常以为居高争强才能制胜，鄙弃示弱处下。', '老子以"江海所以能为百谷王者、以其善下之"立论——守弱处下、以柔克刚，柔弱反而能容纳、能持久、能胜刚强。', '「柔弱胜刚强」「上善若水」成处世与谋略的经典智慧，影响极广。', '别一味争强好胜、硬碰硬——守弱处下、以柔克刚，柔软低位反而更能容纳、更持久、更有韧性。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"laozi-c2","status":"published","title_period":"江海为百谷王·善下处弱（《道德经》命题）","dilemma_constraints":"人常以为居高争强才能制胜，鄙弃示弱处下。","key_judgment":"老子以\"江海所以能为百谷王者、以其善下之\"立论——守弱处下、以柔克刚，柔弱反而能容纳、能持久、能胜刚强。","model_invoked":["柔弱胜刚强"],"outcome":"「柔弱胜刚强」「上善若水」成处世与谋略的经典智慧，影响极广。","transferable_lesson":"别一味争强好胜、硬碰硬——守弱处下、以柔克刚，柔软低位反而更能容纳、更持久、更有韧性。","source_tier":"primary","source_note":"命题出《道德经》、文本确证；老子其人与成书存疑，归属判存疑。","historicity":"disputed","linked_cards":["laozi"],"tags":["认知偏误与理性决策","修身自省"],"advisor_id":"laozi"}', '9e8614d2065ac32a1686d4711ddd72f49dfb63d448b996432ba20bc8269ae40a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('laozi-c3', 'laozi', '持而盈之不如其已·知止（《道德经》命题）', '人常贪多求满、把事做到极致而不知停，终致盈满则溢、招损反噬。', '老子提出"持而盈之、不如其已"——与其把杯子倒到满溢，不如及早停手；知足知止、留余地，方能不殆。', '「知足不辱、知止不殆」成道家处世的重要准则，警示盈满之祸。', '别贪多求满、奔向极端——知道在哪里停下、留点余地，知止知足反而避开危险与反噬。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"laozi-c3","status":"published","title_period":"持而盈之不如其已·知止（《道德经》命题）","dilemma_constraints":"人常贪多求满、把事做到极致而不知停，终致盈满则溢、招损反噬。","key_judgment":"老子提出\"持而盈之、不如其已\"——与其把杯子倒到满溢，不如及早停手；知足知止、留余地，方能不殆。","model_invoked":["知止不殆"],"outcome":"「知足不辱、知止不殆」成道家处世的重要准则，警示盈满之祸。","transferable_lesson":"别贪多求满、奔向极端——知道在哪里停下、留点余地，知止知足反而避开危险与反噬。","source_tier":"primary","source_note":"命题出《道德经》、文本确证；老子其人与成书存疑，归属判存疑。","historicity":"disputed","linked_cards":["laozi"],"tags":["长期规划","修身自省"],"advisor_id":"laozi"}', 'c2a213f9e4be7fa7fe8e9b90e59e270f6ace5942043fe65de1ad1e09e07bda26');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('socrates-c1', 'socrates', '德尔斐神谕与''我知道我无知''（雅典，约公元前5世纪）', '神谕称无人比他更有智慧；他自认无知，困惑于其含义。盲信或斥为荒谬都太省事。', '既不盲从也不否定，而是动手检验——遍访被公认有智慧的人（政治家/诗人/工匠），用诘问发现他们并不真懂自己所宣称的。', '得出''我的智慧只在于我知道自己无知''；也因此得罪大批权贵，埋下受审种子。', '面对一个权威断言，既不盲从也不全盘否定，而是动手去检验它——检验过程本身常比答案更有价值。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"socrates-c1","status":"published","title_period":"德尔斐神谕与''我知道我无知''（雅典，约公元前5世纪）","dilemma_constraints":"神谕称无人比他更有智慧；他自认无知，困惑于其含义。盲信或斥为荒谬都太省事。","key_judgment":"既不盲从也不否定，而是动手检验——遍访被公认有智慧的人（政治家/诗人/工匠），用诘问发现他们并不真懂自己所宣称的。","model_invoked":["反诘法"],"outcome":"得出''我的智慧只在于我知道自己无知''；也因此得罪大批权贵，埋下受审种子。","transferable_lesson":"面对一个权威断言，既不盲从也不全盘否定，而是动手去检验它——检验过程本身常比答案更有价值。","source_tier":"secondary","source_note":"出自柏拉图《申辩篇》（B，转述），色诺芬亦提及；神谕情节的字面真实性有学界争议，经柏拉图框定，故 historicity 记存疑。","historicity":"disputed","linked_cards":["socrates"],"tags":["探索未知","修身自省"],"advisor_id":"socrates"}', 'c2f3f9e13e1c2c147ad851f52a3499311e4de2b5de73e1ad49c8e561b67ca8ab');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('socrates-c2', 'socrates', '阿吉纽西审判：拒绝附议非法表决（公元前406年）', '公众情绪汹涌，要把打了胜仗却未及时救人的将领们合并一次性处死——违反法律程序；他恰任当值主席团成员，附议最安全。', '他一人拒绝把这个非法动议付诸表决，顶着群情压力坚持程序正当。', '动议最终仍被通过、将领被处死；但他守住了自己的原则。', '当多数人的情绪要求你做一件你判断为错的事时，''随大流''的安全往往是用放弃原则换来的——区分''大家都要''与''这是对的''。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"socrates-c2","status":"published","title_period":"阿吉纽西审判：拒绝附议非法表决（公元前406年）","dilemma_constraints":"公众情绪汹涌，要把打了胜仗却未及时救人的将领们合并一次性处死——违反法律程序；他恰任当值主席团成员，附议最安全。","key_judgment":"他一人拒绝把这个非法动议付诸表决，顶着群情压力坚持程序正当。","model_invoked":["德性即知识"],"outcome":"动议最终仍被通过、将领被处死；但他守住了自己的原则。","transferable_lesson":"当多数人的情绪要求你做一件你判断为错的事时，''随大流''的安全往往是用放弃原则换来的——区分''大家都要''与''这是对的''。","source_tier":"secondary","source_note":"阿吉纽西事件为有据史实；他作为唯一异议主席团成员的角色见柏拉图《申辩篇》与色诺芬记载（B，多源），史实性较强。","historicity":"confirmed","linked_cards":["socrates"],"tags":["治理决策","价值与伦理"],"advisor_id":"socrates"}', '917569c3bee262e6e07d07bb1335c892a09678b93a978156459359d8e1347517');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('socrates-c3', 'socrates', '拒执行三十僭主逮捕莱昂之命（约公元前404年）', '僭主政权命他在内五人去逮捕无辜的莱昂（意在株连、拉人下水）；抗命有生命危险。', '其余人照办，他径直回家，拒绝参与他视为不义之事，宁担风险也不做帮凶。', '若非政权不久后倒台，他很可能因此送命；此事成为他''始终不做不义之事''的明证。', '服从一个不义的命令，责任并不会因''是被命令的''而转移；有些底线即使有代价也不能越。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"socrates-c3","status":"published","title_period":"拒执行三十僭主逮捕莱昂之命（约公元前404年）","dilemma_constraints":"僭主政权命他在内五人去逮捕无辜的莱昂（意在株连、拉人下水）；抗命有生命危险。","key_judgment":"其余人照办，他径直回家，拒绝参与他视为不义之事，宁担风险也不做帮凶。","model_invoked":["德性即知识"],"outcome":"若非政权不久后倒台，他很可能因此送命；此事成为他''始终不做不义之事''的明证。","transferable_lesson":"服从一个不义的命令，责任并不会因''是被命令的''而转移；有些底线即使有代价也不能越。","source_tier":"secondary","source_note":"见柏拉图《申辩篇》，色诺芬与安多基德斯亦有旁证（B，多源印证），史实性较强。","historicity":"confirmed","linked_cards":["socrates"],"tags":["治理决策","价值与伦理"],"advisor_id":"socrates"}', '4e9a01305247371dcdc0c87630d0591b4def42e0db1672c3ad8497b88e0dfdb9');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('socrates-c4', 'socrates', '受审：拒绝乞怜、拒绝逃狱（公元前399年）', '被控不敬神、败坏青年，面临死刑；他大可求饶、提议流放，或判后由朋友安排逃狱保命。', '庭上不卑不亢、不放弃审视生活的使命；定罪后拒绝逃狱，理由是不能以不义（违背城邦法律）回报不义。', '被判死刑，从容饮鸩；成为西方哲学史上''为信念赴死''的原型。', '可迁移的不是''去死''，而是先想清''我这条原则到底愿意为它付出到什么程度''——他给的是极端答案，逼你校准自己的临界点。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"socrates-c4","status":"published","title_period":"受审：拒绝乞怜、拒绝逃狱（公元前399年）","dilemma_constraints":"被控不敬神、败坏青年，面临死刑；他大可求饶、提议流放，或判后由朋友安排逃狱保命。","key_judgment":"庭上不卑不亢、不放弃审视生活的使命；定罪后拒绝逃狱，理由是不能以不义（违背城邦法律）回报不义。","model_invoked":["经过省察的人生"],"outcome":"被判死刑，从容饮鸩；成为西方哲学史上''为信念赴死''的原型。","transferable_lesson":"可迁移的不是''去死''，而是先想清''我这条原则到底愿意为它付出到什么程度''——他给的是极端答案，逼你校准自己的临界点。","source_tier":"secondary","source_note":"受审与处死为确证史实；具体庭辩言辞见柏拉图《申辩篇》《克力同篇》《斐多篇》，属其文学加工（B），呈现具体台词时须加''据柏拉图记载''。","historicity":"confirmed","linked_cards":["socrates"],"tags":["价值与伦理","人生抉择"],"advisor_id":"socrates"}', '56381bd41e08f218d3ff324fdd247c2da814a86986d4f57afe55a7c6cd40c15a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('socrates-c5', 'socrates', '欧绪弗洛：''什么是虔敬''（方法演示型 · 受审前夕）', '欧绪弗洛正要去告自己的父亲，自信这是''虔敬''之举；苏格拉底想知道''虔敬''到底是什么。', '不接受对方举的例子，反复追问''虔敬本身是什么''；每给一个定义就用诘问揭出矛盾（如''虔敬即诸神所喜''——但诸神彼此意见相左）。', '对话以''无解(aporia)''告终——欧绪弗洛答不上来、借故离开；苏格拉底没有给出正面答案。', '一个你''想当然''在用的关键概念，一旦被要求精确定义就会露出破绽；先把概念问清楚常比急着行动更重要——但也要看到诘问善破不善立，可能让你停在困惑里。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"socrates-c5","status":"published","title_period":"欧绪弗洛：''什么是虔敬''（方法演示型 · 受审前夕）","dilemma_constraints":"欧绪弗洛正要去告自己的父亲，自信这是''虔敬''之举；苏格拉底想知道''虔敬''到底是什么。","key_judgment":"不接受对方举的例子，反复追问''虔敬本身是什么''；每给一个定义就用诘问揭出矛盾（如''虔敬即诸神所喜''——但诸神彼此意见相左）。","model_invoked":["求本质定义"],"outcome":"对话以''无解(aporia)''告终——欧绪弗洛答不上来、借故离开；苏格拉底没有给出正面答案。","transferable_lesson":"一个你''想当然''在用的关键概念，一旦被要求精确定义就会露出破绽；先把概念问清楚常比急着行动更重要——但也要看到诘问善破不善立，可能让你停在困惑里。","source_tier":"secondary","source_note":"柏拉图对话《欧绪弗洛》。作为''诘问法如何运作''的方法演示可靠；作为具体历史事件则属柏拉图文学加工，呈现时应作''方法示意''而非史实，故 historicity 记存疑。","historicity":"disputed","linked_cards":["socrates"],"tags":["修身自省","学习与认知"],"advisor_id":"socrates"}', 'c8b1c282d8dd67d1d4879097f022ce72b1a134a9c71bdbf6673e4570d863cd2f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('xunzi-c1', 'xunzi', '「人之性恶，其善者伪也」·性恶化性起伪（《性恶》）', '孟子言性善，荀子持相反立场——人性究竟如何、善从何来。', '荀子主张"性恶"，认为人天生有趋利、好声色之欲，"善"是靠后天的"伪"（教化、礼法、努力）化性而成。', '「性恶论」与孟子「性善论」并列，成中国人性论的两大对立传统。', '别指望天生的善——承认人有自利的一面、靠后天的教化、规则与刻意努力去塑造更好的人。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"xunzi-c1","status":"published","title_period":"「人之性恶，其善者伪也」·性恶化性起伪（《性恶》）","dilemma_constraints":"孟子言性善，荀子持相反立场——人性究竟如何、善从何来。","key_judgment":"荀子主张\"性恶\"，认为人天生有趋利、好声色之欲，\"善\"是靠后天的\"伪\"（教化、礼法、努力）化性而成。","model_invoked":["性恶化性起伪"],"outcome":"「性恶论」与孟子「性善论」并列，成中国人性论的两大对立传统。","transferable_lesson":"别指望天生的善——承认人有自利的一面、靠后天的教化、规则与刻意努力去塑造更好的人。","source_tier":"primary","source_note":"性恶、化性起伪为《荀子·性恶》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["xunzi"],"tags":["修身自省","组织管理"],"advisor_id":"xunzi"}', '328a4e8dd03fa2ced416b04e6fa600f09288603f81eb21bc5622ef514cb0a960');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('xunzi-c2', 'xunzi', '隆礼重法、明分使群·隆礼重法（《礼论》《王制》）', '人若放任自利、争夺无度，群体如何有序。', '荀子主张以"礼"（规范）与"法"（制度）规约人、"明分使群"——明确名分职分、使群体有序协作。', '隆礼重法成荀子政治思想的核心，影响了后世的礼法传统。', '用清晰的规范与制度去规约人、把自利的人组织成有序的群体。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"xunzi-c2","status":"published","title_period":"隆礼重法、明分使群·隆礼重法（《礼论》《王制》）","dilemma_constraints":"人若放任自利、争夺无度，群体如何有序。","key_judgment":"荀子主张以\"礼\"（规范）与\"法\"（制度）规约人、\"明分使群\"——明确名分职分、使群体有序协作。","model_invoked":["隆礼重法"],"outcome":"隆礼重法成荀子政治思想的核心，影响了后世的礼法传统。","transferable_lesson":"用清晰的规范与制度去规约人、把自利的人组织成有序的群体。","source_tier":"primary","source_note":"隆礼重法、明分使群为《荀子》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["xunzi"],"tags":["组织管理","价值与伦理"],"advisor_id":"xunzi"}', '1c4512d3bd9e9e25a42e41693345d9f76c2b518fe18add84bd100f260b84d782');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('xunzi-c3', 'xunzi', '「制天命而用之」·天人之分（《天论》）', '人们常把成败、吉凶归于天命与神意。', '荀子提出"明于天人之分"——天有其规律、人有其职分，反对把人事归于天命，主张"制天命而用之"，掌握规律为人所用。', '「天人之分」是中国思想中难得的、强调认识与利用客观规律的理性传统。', '把客观规律与你能努力的部分分开——认清规律、尽人事、甚至掌握规律为我所用，别把成败归于天命。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"xunzi-c3","status":"published","title_period":"「制天命而用之」·天人之分（《天论》）","dilemma_constraints":"人们常把成败、吉凶归于天命与神意。","key_judgment":"荀子提出\"明于天人之分\"——天有其规律、人有其职分，反对把人事归于天命，主张\"制天命而用之\"，掌握规律为人所用。","model_invoked":["天人之分"],"outcome":"「天人之分」是中国思想中难得的、强调认识与利用客观规律的理性传统。","transferable_lesson":"把客观规律与你能努力的部分分开——认清规律、尽人事、甚至掌握规律为我所用，别把成败归于天命。","source_tier":"primary","source_note":"「明于天人之分」「制天命而用之」为《荀子·天论》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["xunzi"],"tags":["认知偏误与理性决策","修身自省"],"advisor_id":"xunzi"}', '27617ec7411e153a467d590a35946738965e875dc2a9a42e4a43781d0c805622');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('xunzi-c4', 'xunzi', '「学不可以已」·劝学（《劝学》）', '人如何弥补天资、不断精进。', '荀子在《劝学》中强调"学不可以已"、靠持续积累——"不积跬步，无以至千里""锲而不舍，金石可镂"。', '《劝学》成中国劝学传统的经典名篇。', '把学习与自我改造当终身不停的事、靠持续的积累——天赋不足可以靠积累补。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"xunzi-c4","status":"published","title_period":"「学不可以已」·劝学（《劝学》）","dilemma_constraints":"人如何弥补天资、不断精进。","key_judgment":"荀子在《劝学》中强调\"学不可以已\"、靠持续积累——\"不积跬步，无以至千里\"\"锲而不舍，金石可镂\"。","model_invoked":["学不可以已"],"outcome":"《劝学》成中国劝学传统的经典名篇。","transferable_lesson":"把学习与自我改造当终身不停的事、靠持续的积累——天赋不足可以靠积累补。","source_tier":"primary","source_note":"《劝学》为《荀子》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["xunzi"],"tags":["修身自省","长期规划"],"advisor_id":"xunzi"}', 'a9c17c4a20ecbd4aab4c8619e94606f2e72a326e6228b1140ab89a7ad520d6a4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hanfeizi-c1', 'hanfeizi', '「法者，布之于百姓」·法（《有度》《定法》）', '国家治理若全凭君主个人好恶，则法度不立、赏罚无常。', '韩非主张以"法"治国——公开、明确、记于图籍、布于百姓、对所有人一致，取代人治。', '「法」成法家治国的核心，深刻影响了中国的制度传统。', '用公开、明确、对所有人一致的规则/制度来治理，而非靠领导者个人的好恶与德行。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hanfeizi-c1","status":"published","title_period":"「法者，布之于百姓」·法（《有度》《定法》）","dilemma_constraints":"国家治理若全凭君主个人好恶，则法度不立、赏罚无常。","key_judgment":"韩非主张以\"法\"治国——公开、明确、记于图籍、布于百姓、对所有人一致，取代人治。","model_invoked":["法"],"outcome":"「法」成法家治国的核心，深刻影响了中国的制度传统。","transferable_lesson":"用公开、明确、对所有人一致的规则/制度来治理，而非靠领导者个人的好恶与德行。","source_tier":"primary","source_note":"「法」的论述为《韩非子》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["hanfeizi"],"tags":["组织管理","危机应对"],"advisor_id":"hanfeizi"}', 'e93a2bffae23e8c23ef6458aa300109a81503b25303963e9aba7e850bda7157e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hanfeizi-c2', 'hanfeizi', '「势位足以屈人」·势（《难势》）', '同样的人，凭什么能令众人服从。', '韩非在《难势》中论"势"——贤德不足以服众，而"势位"（位置与权力）足以屈人，强调善用位置之势。', '「势」成法家「法术势」三要素之一，揭示了权力与位置的作用。', '善用你所处位置与形势本身赋予的力量——同样的人，有势与无势效果天差地别。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hanfeizi-c2","status":"published","title_period":"「势位足以屈人」·势（《难势》）","dilemma_constraints":"同样的人，凭什么能令众人服从。","key_judgment":"韩非在《难势》中论\"势\"——贤德不足以服众，而\"势位\"（位置与权力）足以屈人，强调善用位置之势。","model_invoked":["势"],"outcome":"「势」成法家「法术势」三要素之一，揭示了权力与位置的作用。","transferable_lesson":"善用你所处位置与形势本身赋予的力量——同样的人，有势与无势效果天差地别。","source_tier":"primary","source_note":"「势」的论述为《韩非子·难势》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["hanfeizi"],"tags":["竞争博弈","组织管理"],"advisor_id":"hanfeizi"}', '96d30e71ad5858c06134713ee224f2b5a7cff75994827810739b5ac3f5ddd564');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hanfeizi-c3', 'hanfeizi', '「二柄」·赏罚驱动（《二柄》）', '君主如何有效地控制和驱动臣下。', '韩非提出"二柄"——刑（罚）与德（赏），假定人趋利避害，用清晰的赏罚来驱动，而非指望道德。', '「二柄」成法家以利害驱动人的经典工具。', '假定人趋利避害、自利行事，用清晰的利害（赏罚）机制来驱动，而非指望道德说教（但勿忽视道德能动）。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hanfeizi-c3","status":"published","title_period":"「二柄」·赏罚驱动（《二柄》）","dilemma_constraints":"君主如何有效地控制和驱动臣下。","key_judgment":"韩非提出\"二柄\"——刑（罚）与德（赏），假定人趋利避害，用清晰的赏罚来驱动，而非指望道德。","model_invoked":["性恶趋利避害"],"outcome":"「二柄」成法家以利害驱动人的经典工具。","transferable_lesson":"假定人趋利避害、自利行事，用清晰的利害（赏罚）机制来驱动，而非指望道德说教（但勿忽视道德能动）。","source_tier":"primary","source_note":"「二柄」为《韩非子·二柄》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["hanfeizi"],"tags":["组织管理","竞争博弈"],"advisor_id":"hanfeizi"}', '70122f8164a9a4d51947efb407f0c219ae92a08f00c2c6fee33f6a57e177b5a3');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hanfeizi-c4', 'hanfeizi', '「循名而责实」·形名参验（《二柄》《主道》）', '臣下常以空言邀功、君主难辨其实。', '韩非主张"循名而责实"——按其职责/承诺（名）考核其实际结果（实），名实相符才赏、不符则罚。', '「循名责实」成中国古代考核与问责思想的重要内容。', '按对方"承诺/职责（名）"考核他"实际做到的（实）"、名实相符才赏——别被空话蒙蔽。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hanfeizi-c4","status":"published","title_period":"「循名而责实」·形名参验（《二柄》《主道》）","dilemma_constraints":"臣下常以空言邀功、君主难辨其实。","key_judgment":"韩非主张\"循名而责实\"——按其职责/承诺（名）考核其实际结果（实），名实相符才赏、不符则罚。","model_invoked":["循名责实"],"outcome":"「循名责实」成中国古代考核与问责思想的重要内容。","transferable_lesson":"按对方\"承诺/职责（名）\"考核他\"实际做到的（实）\"、名实相符才赏——别被空话蒙蔽。","source_tier":"primary","source_note":"「循名责实」为《韩非子》原文→确证（一手A）。","historicity":"confirmed","linked_cards":["hanfeizi"],"tags":["组织管理","认知偏误与理性决策"],"advisor_id":"hanfeizi"}', 'aa3ef7883c3d9b3a986e50b50507bbf76ab483083aa155cea93932578060f9d4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('marcus-c1', 'marcus', '多瑙河前线军营写《沉思录》（在位后期，行军途中）', '身为皇帝兼统帅，长年在多瑙河前线指挥对日耳曼部族的战争，戎马倥偬、重压之下身心俱疲。', '他在军营中以希腊文写下给自己的札记（《沉思录》），每日自省、把功夫落在"专注当下本分、控制可控、接受不可控"上。', '《沉思录》成斯多葛哲学的传世经典；他在重压下以斯多葛功夫支撑自己尽责到终。', '越是被重压与纷乱牵扯，越要把心收回到"此刻这件该做的事"上——你能真正掌握的只有当下。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"marcus-c1","status":"published","title_period":"多瑙河前线军营写《沉思录》（在位后期，行军途中）","dilemma_constraints":"身为皇帝兼统帅，长年在多瑙河前线指挥对日耳曼部族的战争，戎马倥偬、重压之下身心俱疲。","key_judgment":"他在军营中以希腊文写下给自己的札记（《沉思录》），每日自省、把功夫落在\"专注当下本分、控制可控、接受不可控\"上。","model_invoked":["着眼当下尽责"],"outcome":"《沉思录》成斯多葛哲学的传世经典；他在重压下以斯多葛功夫支撑自己尽责到终。","transferable_lesson":"越是被重压与纷乱牵扯，越要把心收回到\"此刻这件该做的事\"上——你能真正掌握的只有当下。","source_tier":"primary","source_note":"《沉思录》成于行军途中、为自省札记，公认→确证（一手文本A）。","historicity":"confirmed","linked_cards":["marcus"],"tags":["修身自省","危机应对"],"advisor_id":"marcus"}', '262a9dba7131ef2408fac8427762c50c8279ee600d75696f45ebcebd48dff4c9');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('marcus-c2', 'marcus', '治下安东尼瘟疫与马科曼尼战争（在位期间）', '其治下罗马接连遭遇大瘟疫（安东尼瘟疫，死者无数）与北方部族的长期战争，国力与民生承受巨大冲击。', '他不为不可控的疫情与战局所击垮，而以斯多葛"控制二分"分清可控（自己的判断、决策与履职）与不可控（天灾与战局），在可控处尽责到底。', '在天灾人祸交迫中维系帝国运转、坚守皇帝职责直至病逝于前线。', '天灾人祸交迫、一堆事都管不了时，分清可控与不可控——把精力全押在你能影响的判断与行动上，对不可控坦然接受、不内耗。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"marcus-c2","status":"published","title_period":"治下安东尼瘟疫与马科曼尼战争（在位期间）","dilemma_constraints":"其治下罗马接连遭遇大瘟疫（安东尼瘟疫，死者无数）与北方部族的长期战争，国力与民生承受巨大冲击。","key_judgment":"他不为不可控的疫情与战局所击垮，而以斯多葛\"控制二分\"分清可控（自己的判断、决策与履职）与不可控（天灾与战局），在可控处尽责到底。","model_invoked":["控制二分法"],"outcome":"在天灾人祸交迫中维系帝国运转、坚守皇帝职责直至病逝于前线。","transferable_lesson":"天灾人祸交迫、一堆事都管不了时，分清可控与不可控——把精力全押在你能影响的判断与行动上，对不可控坦然接受、不内耗。","source_tier":"secondary","source_note":"安东尼瘟疫、马科曼尼战争及其坚守履职为罗马史所载→确证。","historicity":"confirmed","linked_cards":["marcus"],"tags":["危机应对","领导力"],"advisor_id":"marcus"}', '91595f066b2b0e908e9fb44ad2ff68c2f6e377660998bac2f60d43e788d35f9b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('marcus-c3', 'marcus', '对 Avidius Cassius 叛乱的克制处理（175）', '东方将领 Avidius Cassius 误传马可奥勒留病逝而自立为帝、发动叛乱；不久 Cassius 被部下所杀。', '马可奥勒留主张宽待——不愿扩大株连、对 Cassius 的家属与党羽从宽，以理性与克制处理而非泄愤报复。', '叛乱平息后未演成大规模清洗；其克制宽宥与斯多葛的理性自持相一致。', '遭遇背叛与冒犯时，剥除愤怒的主观渲染、客观看待事情本身，以理性克制处理，往往比泄愤报复更稳更高。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"marcus-c3","status":"published","title_period":"对 Avidius Cassius 叛乱的克制处理（175）","dilemma_constraints":"东方将领 Avidius Cassius 误传马可奥勒留病逝而自立为帝、发动叛乱；不久 Cassius 被部下所杀。","key_judgment":"马可奥勒留主张宽待——不愿扩大株连、对 Cassius 的家属与党羽从宽，以理性与克制处理而非泄愤报复。","model_invoked":["客观看待"],"outcome":"叛乱平息后未演成大规模清洗；其克制宽宥与斯多葛的理性自持相一致。","transferable_lesson":"遭遇背叛与冒犯时，剥除愤怒的主观渲染、客观看待事情本身，以理性克制处理，往往比泄愤报复更稳更高。","source_tier":"secondary","source_note":"Avidius Cassius 叛乱及马可奥勒留的克制处理为罗马史所载→确证（具体宽宥细节史料或有出入、主干确证）。","historicity":"confirmed","linked_cards":["marcus"],"tags":["价值与伦理","领导力"],"advisor_id":"marcus"}', '41b1b3250e29bc081fcaf46b84311fb4088a83a737b5cb795c7b9a7c714bddb1');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('jobs-c1', 'jobs', '1997年回归用2×2矩阵砍产品线', '他回归时苹果濒临破产、亏损超10亿、产品线杂乱有十几条、资源分散', '在白板画2×2矩阵(消费/专业×桌面/便携)，宣布只做4款核心产品、当即砍掉约70%其余产品', '次年(1998)即扭亏为盈；极致聚焦成为苹果复兴与此后所有产品决策的底层逻辑（A/B）', '组织濒危时，救命的常不是再加一个新项目，而是有勇气砍掉大多数''还不错''、把全部资源压向少数极致', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"jobs-c1","status":"published","title_period":"1997年回归用2×2矩阵砍产品线","dilemma_constraints":"他回归时苹果濒临破产、亏损超10亿、产品线杂乱有十几条、资源分散","key_judgment":"在白板画2×2矩阵(消费/专业×桌面/便携)，宣布只做4款核心产品、当即砍掉约70%其余产品","model_invoked":["聚焦即说不"],"outcome":"次年(1998)即扭亏为盈；极致聚焦成为苹果复兴与此后所有产品决策的底层逻辑（A/B）","transferable_lesson":"组织濒危时，救命的常不是再加一个新项目，而是有勇气砍掉大多数''还不错''、把全部资源压向少数极致","source_tier":"secondary","source_note":"1997回归、2×2矩阵、砍约70%产品、1998扭亏见多方报道与艾萨克森传记（A/B）；具体款数表述各源略异","historicity":"confirmed","linked_cards":["jobs"],"tags":["创业","危机应对"],"advisor_id":"jobs"}', 'a3e911faa35909f86c577e7114ff144a15964bc64c2aa579000351b6081eca4d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('jobs-c2', 'jobs', '2007年发布iPhone', '当时智能手机以键盘+触控笔为主流、运营商主导终端，苹果毫无手机经验、且要自我蚕食热卖的iPod', '押注全触控、软硬件一体整合的多点触控手机，不做市场调研、按自己对体验的判断重新定义手机', 'iPhone重新定义智能手机、开创App生态，成为史上最成功产品之一（A/B）', '颠覆性产品常要敢于自我蚕食、并端到端掌控体验；用户不会在调研里告诉你他们想要还不存在的东西', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"jobs-c2","status":"published","title_period":"2007年发布iPhone","dilemma_constraints":"当时智能手机以键盘+触控笔为主流、运营商主导终端，苹果毫无手机经验、且要自我蚕食热卖的iPod","key_judgment":"押注全触控、软硬件一体整合的多点触控手机，不做市场调研、按自己对体验的判断重新定义手机","model_invoked":["软硬一体整合"],"outcome":"iPhone重新定义智能手机、开创App生态，成为史上最成功产品之一（A/B）","transferable_lesson":"颠覆性产品常要敢于自我蚕食、并端到端掌控体验；用户不会在调研里告诉你他们想要还不存在的东西","source_tier":"secondary","source_note":"iPhone 2007发布、全触控/软硬一体见公开记录与传记（A/B）","historicity":"confirmed","linked_cards":["jobs"],"tags":["创新研发","商业模式与护城河"],"advisor_id":"jobs"}', 'd6b183a507fbd915ddc0fbac2bd81a8116aab66fb92c400c07aa84ad1150eb54');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('jobs-c3', 'jobs', '1985年被逐出自己创立的苹果', '因专横作风与权力斗争，他被自己参与创立的苹果排挤出局，事业与声誉重挫', '离开后创立NeXT、并买下并培育皮克斯；十余年后苹果收购NeXT，他得以回归——但代价是惨痛人际教训', '皮克斯《玩具总动员》大获成功、NeXT技术成为日后Mac系统基石；1997回归苹果（A/B）', '反例：天才的偏执若不加约束会变成专横、把人都得罪光；放逐期的沉淀，有时是回归前必经的修炼', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"jobs-c3","status":"published","title_period":"1985年被逐出自己创立的苹果","dilemma_constraints":"因专横作风与权力斗争，他被自己参与创立的苹果排挤出局，事业与声誉重挫","key_judgment":"离开后创立NeXT、并买下并培育皮克斯；十余年后苹果收购NeXT，他得以回归——但代价是惨痛人际教训","model_invoked":["完美主义"],"outcome":"皮克斯《玩具总动员》大获成功、NeXT技术成为日后Mac系统基石；1997回归苹果（A/B）","transferable_lesson":"反例：天才的偏执若不加约束会变成专横、把人都得罪光；放逐期的沉淀，有时是回归前必经的修炼","source_tier":"secondary","source_note":"1985被逐、NeXT/皮克斯、1997回归见艾萨克森传记等（A/B）；为反例案例","historicity":"confirmed","linked_cards":["jobs"],"tags":["人生抉择","人际关系"],"advisor_id":"jobs"}', '059895aa9fc287b0a37fcba46e7a272a809a68eb29978c1cd117b32db701ee36');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('jobs-c4', 'jobs', '坚持连看不见的内部也要完美', '初代Macintosh等产品中，团队认为用户看不到的内部电路板布局无需美观、不值得花成本', '他坚持连机箱内部、电路板都要排布优美，理由是真正的工匠对看不见的背面也一视同仁', '这种对极致细节的偏执，塑造了苹果产品标志性的工艺与设计文化（A/B）', '对看不见之处的较真，决定了一件作品的''品''；用户感受得到那种整体的用心，即便说不出在哪', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"jobs-c4","status":"published","title_period":"坚持连看不见的内部也要完美","dilemma_constraints":"初代Macintosh等产品中，团队认为用户看不到的内部电路板布局无需美观、不值得花成本","key_judgment":"他坚持连机箱内部、电路板都要排布优美，理由是真正的工匠对看不见的背面也一视同仁","model_invoked":["完美主义"],"outcome":"这种对极致细节的偏执，塑造了苹果产品标志性的工艺与设计文化（A/B）","transferable_lesson":"对看不见之处的较真，决定了一件作品的''品''；用户感受得到那种整体的用心，即便说不出在哪","source_tier":"secondary","source_note":"内部也要美观的理念见艾萨克森传记（B）及乔布斯公开言论（A）","historicity":"confirmed","linked_cards":["jobs"],"tags":["创新研发","修身自省"],"advisor_id":"jobs"}', 'a244f9759c57dbc17846f1310a36948b600ae45a5ce02f4aa9e1ad0f636e9094');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('jobs-c5', 'jobs', '不靠市场调研创造iPod/iTunes', '数字音乐混乱、盗版盛行，没人通过调研要求一个''1000首歌装进口袋''的整合软硬件+商店方案', '不做用户调研，按自己对体验的判断打造iPod+iTunes软硬件+音乐商店一体方案，主动创造需求', 'iPod+iTunes重塑音乐产业、成为苹果走向移动时代的关键一跃（A/B）', '真正的创新往往不是回答用户已说出的需求，而是造出一个他们见到才知道离不开的东西', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"jobs-c5","status":"published","title_period":"不靠市场调研创造iPod/iTunes","dilemma_constraints":"数字音乐混乱、盗版盛行，没人通过调研要求一个''1000首歌装进口袋''的整合软硬件+商店方案","key_judgment":"不做用户调研，按自己对体验的判断打造iPod+iTunes软硬件+音乐商店一体方案，主动创造需求","model_invoked":["创造需求"],"outcome":"iPod+iTunes重塑音乐产业、成为苹果走向移动时代的关键一跃（A/B）","transferable_lesson":"真正的创新往往不是回答用户已说出的需求，而是造出一个他们见到才知道离不开的东西","source_tier":"secondary","source_note":"iPod/iTunes、''不做市场调研''见公开记录与传记（A/B）","historicity":"confirmed","linked_cards":["jobs"],"tags":["创新研发","表达说服"],"advisor_id":"jobs"}', '17443163ca1ee7ca5206908fbbcc2632791e8e9aee79bf4682db08f341e9dbe6');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('carnegie-c1', 'carnegie', '把成本会计做到极致', '钢铁是重资产、同质化的规模行业，谁成本低谁赢，但当时多数厂连每道工序真实成本都不清楚', '引入极其精细的成本会计、逐道工序核算单位成本，信奉''盯住成本，利润自然会来''，据此定价与改进', '对成本的透彻掌握让卡内基钢铁始终是成本最低者，在周期波动中持续碾压对手（A/B）', '先把每道工序的真实单位成本搞清楚，再谈竞争；看不清成本的人，是在蒙着眼睛打价格战', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"carnegie-c1","status":"published","title_period":"把成本会计做到极致","dilemma_constraints":"钢铁是重资产、同质化的规模行业，谁成本低谁赢，但当时多数厂连每道工序真实成本都不清楚","key_judgment":"引入极其精细的成本会计、逐道工序核算单位成本，信奉''盯住成本，利润自然会来''，据此定价与改进","model_invoked":["成本即一切"],"outcome":"对成本的透彻掌握让卡内基钢铁始终是成本最低者，在周期波动中持续碾压对手（A/B）","transferable_lesson":"先把每道工序的真实单位成本搞清楚，再谈竞争；看不清成本的人，是在蒙着眼睛打价格战","source_tier":"secondary","source_note":"精细成本会计、''盯成本利润自来''为卡内基著名理念，见自传与传记（A/B）","historicity":"confirmed","linked_cards":["carnegie"],"tags":["资源调度","商业模式与护城河"],"advisor_id":"carnegie"}', '06ebd82f73ad3cec443f2c033feac43fb872c87aa647a0d8caf5eee9a535ace5');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('carnegie-c2', 'carnegie', '萧条期逆势扩产、引进贝塞麦工艺', '经济萧条时同行纷纷收缩、设备与建厂成本骤降，但前景不明、扩张风险大', '他偏在萧条时低价买地建厂、引进贝塞麦炼钢新工艺扩大产能，赌复苏后以更低成本更大产能通吃', '逆周期+新技术让卡内基钢铁在复苏期产能与成本双重领先，成长为美国最大钢铁帝国（A/B）', '别人恐惧收缩时，正是用更低成本上产能、换新技术的窗口；周期低谷是有准备者扩张的黄金时机', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"carnegie-c2","status":"published","title_period":"萧条期逆势扩产、引进贝塞麦工艺","dilemma_constraints":"经济萧条时同行纷纷收缩、设备与建厂成本骤降，但前景不明、扩张风险大","key_judgment":"他偏在萧条时低价买地建厂、引进贝塞麦炼钢新工艺扩大产能，赌复苏后以更低成本更大产能通吃","model_invoked":["逆周期扩张"],"outcome":"逆周期+新技术让卡内基钢铁在复苏期产能与成本双重领先，成长为美国最大钢铁帝国（A/B）","transferable_lesson":"别人恐惧收缩时，正是用更低成本上产能、换新技术的窗口；周期低谷是有准备者扩张的黄金时机","source_tier":"secondary","source_note":"逆周期扩张、引进贝塞麦工艺见多方传记与史料（A/B）","historicity":"confirmed","linked_cards":["carnegie"],"tags":["长期规划","危机应对"],"advisor_id":"carnegie"}', '5e4c746fa9bac0680bbe5a46efa8db4989b04d71f5291ecb8aebbf9dc2f59b8a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('carnegie-c3', 'carnegie', '构建矿-焦-运-钢全链条', '钢厂利润受制于铁矿、焦炭与运输等上游，价格与供应不稳', '向上游整合铁矿、煤焦、运输(铁路/船队)，打造从原料到成品的全链条自有体系，消除中间利润', '全链条自有使其成本与供应稳定可控、议价力极强，进一步拉开与对手的成本差距（A/B）', '把利润被别人拿走、又最易卡你脖子的上游环节收进来，既稳成本又稳供应，是规模制造的护城河', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"carnegie-c3","status":"published","title_period":"构建矿-焦-运-钢全链条","dilemma_constraints":"钢厂利润受制于铁矿、焦炭与运输等上游，价格与供应不稳","key_judgment":"向上游整合铁矿、煤焦、运输(铁路/船队)，打造从原料到成品的全链条自有体系，消除中间利润","model_invoked":["纵向一体化"],"outcome":"全链条自有使其成本与供应稳定可控、议价力极强，进一步拉开与对手的成本差距（A/B）","transferable_lesson":"把利润被别人拿走、又最易卡你脖子的上游环节收进来，既稳成本又稳供应，是规模制造的护城河","source_tier":"secondary","source_note":"矿-焦-运-钢纵向一体化见多方史料与传记（B）","historicity":"confirmed","linked_cards":["carnegie"],"tags":["资源调度","商业模式与护城河"],"advisor_id":"carnegie"}', 'c88864513ade845a2e029a18d716a9ba21eaee40430f18e1f6c1a927a52e03b7');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('carnegie-c4', 'carnegie', '1892年Homestead罢工血案', '他标榜善待工人、支持工会，却又要压低Homestead钢厂工资以保成本竞争力；自己人在欧洲', '为压成本默许削减工资、并授权Frick强硬对抗工会；Frick锁厂、雇平克顿武装，酿成流血冲突', '冲突致多人死亡、工会被击垮，钢铁工运受挫数十年；卡内基''工人之友''声誉严重受损(反例)（A/B）', '反例：把成本/效率推到极致而无视人的代价，会反噬声誉与信任；标榜的价值观一旦与行动背离，伤害更深', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"carnegie-c4","status":"published","title_period":"1892年Homestead罢工血案","dilemma_constraints":"他标榜善待工人、支持工会，却又要压低Homestead钢厂工资以保成本竞争力；自己人在欧洲","key_judgment":"为压成本默许削减工资、并授权Frick强硬对抗工会；Frick锁厂、雇平克顿武装，酿成流血冲突","model_invoked":["成本即一切"],"outcome":"冲突致多人死亡、工会被击垮，钢铁工运受挫数十年；卡内基''工人之友''声誉严重受损(反例)（A/B）","transferable_lesson":"反例：把成本/效率推到极致而无视人的代价，会反噬声誉与信任；标榜的价值观一旦与行动背离，伤害更深","source_tier":"primary","source_note":"1892 Homestead罢工、Frick镇压、卡内基在欧洲并支持Frick见多方权威史料（A/B）；为反例案例","historicity":"confirmed","linked_cards":["carnegie"],"tags":["人际关系","危机应对"],"advisor_id":"carnegie"}', '75b5c419d3307ba7a1fdb224df51ca167c75337559fa73b2a3c1b6cab9a1d23f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('carnegie-c5', 'carnegie', '1901年售出钢铁帝国、践行《财富的福音》', '1901年他65岁、想退休，并面临''巨富该如何处置''的人生命题', '以4.8亿美元把公司卖给摩根、并入美国钢铁，余生按《财富的福音》系统捐出大部分财富给图书馆与教育', '他成为当时世界首富，又捐出约3.5亿美元(建数千座图书馆等)，''富而死者耻''成现代慈善奠基理念（A/B）', '财富的终点不是占有而是托管；趁在世用方法论把它投向教育与公共善，比留给后代或守财致死更有价值', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"carnegie-c5","status":"published","title_period":"1901年售出钢铁帝国、践行《财富的福音》","dilemma_constraints":"1901年他65岁、想退休，并面临''巨富该如何处置''的人生命题","key_judgment":"以4.8亿美元把公司卖给摩根、并入美国钢铁，余生按《财富的福音》系统捐出大部分财富给图书馆与教育","model_invoked":["财富的福音"],"outcome":"他成为当时世界首富，又捐出约3.5亿美元(建数千座图书馆等)，''富而死者耻''成现代慈善奠基理念（A/B）","transferable_lesson":"财富的终点不是占有而是托管；趁在世用方法论把它投向教育与公共善，比留给后代或守财致死更有价值","source_tier":"primary","source_note":"1901以约4.8亿美元售予摩根成美国钢铁、《财富的福音》1889、捐约3.5亿见多方权威史料（A/B）","historicity":"confirmed","linked_cards":["carnegie"],"tags":["价值与伦理","长期规划"],"advisor_id":"carnegie"}', 'a0463b8337c35862c04a2684aa3978844fb8486091aee58ac7e2a73832ad1054');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('luzuofu-c1', 'luzuofu', '创办民生公司·实业救国（1925起）', '内忧外患、民族工业孱弱，卢作孚想以实业为国家与社会做点根本的事。', '卢作孚以"实业救国"为念创办民生公司，把办实业当作建设社会、振兴民族的手段，而非纯粹赚钱。', '民生公司成中国近代著名民族航运企业，卢作孚以实业服务于社会建设。', '把办实业、办企业当作救国与建设社会的手段、而非纯粹赚钱——企业可以是改造社会的工具（但须量力）。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"luzuofu-c1","status":"published","title_period":"创办民生公司·实业救国（1925起）","dilemma_constraints":"内忧外患、民族工业孱弱，卢作孚想以实业为国家与社会做点根本的事。","key_judgment":"卢作孚以\"实业救国\"为念创办民生公司，把办实业当作建设社会、振兴民族的手段，而非纯粹赚钱。","model_invoked":["实业救国"],"outcome":"民生公司成中国近代著名民族航运企业，卢作孚以实业服务于社会建设。","transferable_lesson":"把办实业、办企业当作救国与建设社会的手段、而非纯粹赚钱——企业可以是改造社会的工具（但须量力）。","source_tier":"secondary","source_note":"卢作孚以\"实业救国\"创办民生公司为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["luzuofu"],"tags":["创业","长期规划"],"advisor_id":"luzuofu"}', 'bbe1bc1413f07b90c3a935fd4773655401e0a0a7e156be447a871834c25f1794');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('luzuofu-c2', 'luzuofu', '统一川江航运、收回内河航运权·化零为整（1920s—1930s）', '川江上中国小航运公司一盘散沙、互相杀价、被把持内河航运的外国公司各个击破。', '卢作孚以民生公司为核心，把分散内斗的中国航运力量整合统一、形成合力，从外国公司手中收回了内河航运权。', '民生公司统一了川江航运，成中国民族航运业自强的标志。', '当同行一盘散沙、被强敌各个击破时——把分散内斗的力量整合统一、形成合力去对抗。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"luzuofu-c2","status":"published","title_period":"统一川江航运、收回内河航运权·化零为整（1920s—1930s）","dilemma_constraints":"川江上中国小航运公司一盘散沙、互相杀价、被把持内河航运的外国公司各个击破。","key_judgment":"卢作孚以民生公司为核心，把分散内斗的中国航运力量整合统一、形成合力，从外国公司手中收回了内河航运权。","model_invoked":["化零为整统一航运"],"outcome":"民生公司统一了川江航运，成中国民族航运业自强的标志。","transferable_lesson":"当同行一盘散沙、被强敌各个击破时——把分散内斗的力量整合统一、形成合力去对抗。","source_tier":"secondary","source_note":"卢作孚统一川江航运、收回内河航运权为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["luzuofu"],"tags":["组织管理","创业"],"advisor_id":"luzuofu"}', '45efa3d781b508bbeac13c431eebed60971711cecf24160caa09538357235f41');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('luzuofu-c3', 'luzuofu', '北碚乡村现代化建设·乡村现代化试验（1927起）', '北碚原是匪患丛生、落后的地方；如何把"改造社会"落到实处。', '卢作孚以北碚为试验田，系统地建设教育、经济、文化、卫生、基础设施，把它建成乡村现代化的样板。', '北碚从匪患之地变成著名的乡村现代化示范，影响深远。', '别空谈改造——选一个地方当试验田、系统地建设、做出一个可复制的示范。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"luzuofu-c3","status":"published","title_period":"北碚乡村现代化建设·乡村现代化试验（1927起）","dilemma_constraints":"北碚原是匪患丛生、落后的地方；如何把\"改造社会\"落到实处。","key_judgment":"卢作孚以北碚为试验田，系统地建设教育、经济、文化、卫生、基础设施，把它建成乡村现代化的样板。","model_invoked":["乡村现代化试验"],"outcome":"北碚从匪患之地变成著名的乡村现代化示范，影响深远。","transferable_lesson":"别空谈改造——选一个地方当试验田、系统地建设、做出一个可复制的示范。","source_tier":"secondary","source_note":"卢作孚建设北碚为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["luzuofu"],"tags":["长期规划","组织管理"],"advisor_id":"luzuofu"}', '85b02535424769231d03950f180c7842ba9010c786281193cc7a1a83b07a8618');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('luzuofu-c4', 'luzuofu', '指挥宜昌大撤退·化危为机的组织动员（1938）', '抗战时数万人员与大量战略物资积压宜昌、长江将进入枯水期、日军迫近，撤运看似不可能。', '卢作孚以卓越的组织调度、分段接力的方式，用约40天抢运完成了人员与战略物资的撤退。', '宜昌大撤退抢运出大量人员与工业物资，被誉为"中国实业界的敦刻尔克"。', '危难关头、千头万绪、看似不可能时——以卓越的组织、调度、分段接力把任务拆解执行、化不可能为可能。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"luzuofu-c4","status":"published","title_period":"指挥宜昌大撤退·化危为机的组织动员（1938）","dilemma_constraints":"抗战时数万人员与大量战略物资积压宜昌、长江将进入枯水期、日军迫近，撤运看似不可能。","key_judgment":"卢作孚以卓越的组织调度、分段接力的方式，用约40天抢运完成了人员与战略物资的撤退。","model_invoked":["化危为机的组织动员"],"outcome":"宜昌大撤退抢运出大量人员与工业物资，被誉为\"中国实业界的敦刻尔克\"。","transferable_lesson":"危难关头、千头万绪、看似不可能时——以卓越的组织、调度、分段接力把任务拆解执行、化不可能为可能。","source_tier":"secondary","source_note":"卢作孚指挥宜昌大撤退为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["luzuofu"],"tags":["危机应对","组织管理"],"advisor_id":"luzuofu"}', '1750810fcab332e1ffb662fba916b53024145f9f40a91b74bf112b44085ec9be');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('chanel-c1', 'chanel', '小黑裙与简洁设计·简约即奢华（1920s）', '当时的高级女装以繁复的装饰、蕾丝、紧身堆砌为奢华标志。', '香奈儿反其道而行，用简洁的剪裁、线条与质感创造高级感，推出了至今经典的"小黑裙"。', '「简约即奢华」重新定义了现代时尚的高级感，小黑裙成永恒经典。', '别以为奢华=繁复堆砌——去掉多余装饰、用简洁的剪裁与质感创造高级感（less is more）。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"chanel-c1","status":"published","title_period":"小黑裙与简洁设计·简约即奢华（1920s）","dilemma_constraints":"当时的高级女装以繁复的装饰、蕾丝、紧身堆砌为奢华标志。","key_judgment":"香奈儿反其道而行，用简洁的剪裁、线条与质感创造高级感，推出了至今经典的\"小黑裙\"。","model_invoked":["简约即奢华"],"outcome":"「简约即奢华」重新定义了现代时尚的高级感，小黑裙成永恒经典。","transferable_lesson":"别以为奢华=繁复堆砌——去掉多余装饰、用简洁的剪裁与质感创造高级感（less is more）。","source_tier":"secondary","source_note":"香奈儿的简约设计与小黑裙为时尚史所载→确证（二手B）。","historicity":"confirmed","linked_cards":["chanel"],"tags":["创新研发","表达说服"],"advisor_id":"chanel"}', 'cada1c31f51eb9d5e65bd1f3cd11fbe4685e4ad21ad0661b7823fd6028bc315b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('chanel-c2', 'chanel', '用针织、裤装解放女装·解放束缚（1910s—1920s）', '当时女性被紧身胸衣等繁复束缚的着装规范所困、行动极不自由。', '香奈儿打破旧规范，用针织面料、裤装、宽松剪裁，让女性穿得舒适、实用、自由。', '香奈儿的设计解放了女性着装，深刻影响了现代女装的方向。', '看到一个束缚人却被默认的旧规范——打破它、用舒适自由的设计解放使用者，解放本身就是最大的吸引力。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"chanel-c2","status":"published","title_period":"用针织、裤装解放女装·解放束缚（1910s—1920s）","dilemma_constraints":"当时女性被紧身胸衣等繁复束缚的着装规范所困、行动极不自由。","key_judgment":"香奈儿打破旧规范，用针织面料、裤装、宽松剪裁，让女性穿得舒适、实用、自由。","model_invoked":["解放束缚"],"outcome":"香奈儿的设计解放了女性着装，深刻影响了现代女装的方向。","transferable_lesson":"看到一个束缚人却被默认的旧规范——打破它、用舒适自由的设计解放使用者，解放本身就是最大的吸引力。","source_tier":"secondary","source_note":"香奈儿以针织/裤装解放女装为时尚史所载→确证（二手B）。","historicity":"confirmed","linked_cards":["chanel"],"tags":["创新研发","创业"],"advisor_id":"chanel"}', 'd606b33dfb026eeef6bce84307d2f89425ec37446414e72bb4598d1fa442ac6c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('chanel-c3', 'chanel', '香奈儿本人即品牌·把自己活成品牌（毕生）', '一个时尚品牌如何获得独一无二、难以模仿的灵魂。', '香奈儿把自己独立、反叛、追求自由与品味的生活方式与态度，活成了Chanel品牌的化身与最佳代言。', '香奈儿本人的传奇与态度，赋予了Chanel难以复制的品牌灵魂。', '把你自己的生活方式、形象、态度活成品牌的化身——但须知这高度依赖个人魅力、难以被普通人或团队复制。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"chanel-c3","status":"published","title_period":"香奈儿本人即品牌·把自己活成品牌（毕生）","dilemma_constraints":"一个时尚品牌如何获得独一无二、难以模仿的灵魂。","key_judgment":"香奈儿把自己独立、反叛、追求自由与品味的生活方式与态度，活成了Chanel品牌的化身与最佳代言。","model_invoked":["把自己活成品牌"],"outcome":"香奈儿本人的传奇与态度，赋予了Chanel难以复制的品牌灵魂。","transferable_lesson":"把你自己的生活方式、形象、态度活成品牌的化身——但须知这高度依赖个人魅力、难以被普通人或团队复制。","source_tier":"secondary","source_note":"香奈儿以自身定义品牌为其传记所载→确证（二手B）。","historicity":"confirmed","linked_cards":["chanel"],"tags":["表达说服","创业"],"advisor_id":"chanel"}', 'b115370136d32dacb16be3041f1dac4ff3addf68e5de117c6b1c8419296c0c02');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('chanel-c4', 'chanel', '「潮流易逝、风格永存」·经典抗潮流（设计理念）', '时尚行业普遍追逐速朽的当季潮流。', '香奈儿追求超越一季流行的"经典"与永恒风格，留下了小黑裙、No.5香水、菱格纹等能用很多年的经典。', '香奈儿的经典设计历久弥新，印证了"潮流易逝、风格永存"。', '别只追逐速朽的当季潮流——追求超越一季的"经典"与永恒风格、做能用很多年的东西。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"chanel-c4","status":"published","title_period":"「潮流易逝、风格永存」·经典抗潮流（设计理念）","dilemma_constraints":"时尚行业普遍追逐速朽的当季潮流。","key_judgment":"香奈儿追求超越一季流行的\"经典\"与永恒风格，留下了小黑裙、No.5香水、菱格纹等能用很多年的经典。","model_invoked":["经典抗潮流"],"outcome":"香奈儿的经典设计历久弥新，印证了\"潮流易逝、风格永存\"。","transferable_lesson":"别只追逐速朽的当季潮流——追求超越一季的\"经典\"与永恒风格、做能用很多年的东西。","source_tier":"secondary","source_note":"「潮流易逝、风格永存」为香奈儿名言→确证（具体措辞有流传版本）。","historicity":"confirmed","linked_cards":["chanel"],"tags":["表达说服","长期规划"],"advisor_id":"chanel"}', 'b3c87e4cbfcc79ed8ab808a00ed2f1cd4b38fdd77f1770b2feb399b344853e73');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('ohno-c1', 'ohno', '识别并消除七大浪费·消除浪费（丰田生产方式）', '制造现场中大量环节被默认为"必要"，效率难以根本提升。', '大野耐一以"是否创造价值"为尺，系统地识别并消除七大浪费（过量生产、等待、搬运、库存、动作、加工、缺陷）。', '消除浪费成丰田生产方式（TPS）与全球"精益生产"的核心，大幅提升了效率与品质。', '用"这一步有没有创造价值"重新审视每个环节、识别并消除一切浪费——很多"必要"其实是浪费。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"ohno-c1","status":"published","title_period":"识别并消除七大浪费·消除浪费（丰田生产方式）","dilemma_constraints":"制造现场中大量环节被默认为\"必要\"，效率难以根本提升。","key_judgment":"大野耐一以\"是否创造价值\"为尺，系统地识别并消除七大浪费（过量生产、等待、搬运、库存、动作、加工、缺陷）。","model_invoked":["消除浪费"],"outcome":"消除浪费成丰田生产方式（TPS）与全球\"精益生产\"的核心，大幅提升了效率与品质。","transferable_lesson":"用\"这一步有没有创造价值\"重新审视每个环节、识别并消除一切浪费——很多\"必要\"其实是浪费。","source_tier":"primary","source_note":"消除七大浪费为大野《丰田生产方式》核心→确证（一手A）。","historicity":"confirmed","linked_cards":["ohno"],"tags":["组织管理","资源调度"],"advisor_id":"ohno"}', 'c527add0b1037e499c5f9d36d587f9f638d5e98451c0e5d0bdfc358cf763b723');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('ohno-c2', 'ohno', '准时化(JIT)与拉动式生产·受超市启发（丰田生产方式）', '按预测大批量生产导致大量库存积压、浪费严重。', '大野耐一受美国超市"按货架被取走才补货"的启发，建立由下游需求拉动上游的准时化（JIT）生产与看板系统。', '准时化大幅削减了库存与过量生产，成TPS的支柱之一。', '由下游的实际需求"拉动"上游、只在需要时生产需要的量——用拉动取代推动，消除库存与过量。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"ohno-c2","status":"published","title_period":"准时化(JIT)与拉动式生产·受超市启发（丰田生产方式）","dilemma_constraints":"按预测大批量生产导致大量库存积压、浪费严重。","key_judgment":"大野耐一受美国超市\"按货架被取走才补货\"的启发，建立由下游需求拉动上游的准时化（JIT）生产与看板系统。","model_invoked":["准时化"],"outcome":"准时化大幅削减了库存与过量生产，成TPS的支柱之一。","transferable_lesson":"由下游的实际需求\"拉动\"上游、只在需要时生产需要的量——用拉动取代推动，消除库存与过量。","source_tier":"primary","source_note":"准时化、看板、受超市启发为大野《丰田生产方式》所述→确证（一手A）。","historicity":"confirmed","linked_cards":["ohno"],"tags":["资源调度","组织管理"],"advisor_id":"ohno"}', 'b0c4d8b2aab83f9d52579f2683b22b68c45d0b4223f1bf1803d99218d32fa575');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('ohno-c3', 'ohno', '自働化·一异常就停、暴露问题（丰田生产方式）', '出了问题继续生产，会让缺陷流到下游、积重难返。', '大野耐一发扬"自働化（jidoka）"——让流程/机器一发现异常就自动停下、把问题当场暴露并解决，绝不让缺陷流走。', '自働化使问题被及时暴露和根治、保障了品质，成TPS的另一支柱。', '一发现异常就停下、暴露问题当场解决、不让缺陷流到下游——问题暴露比掩盖好。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"ohno-c3","status":"published","title_period":"自働化·一异常就停、暴露问题（丰田生产方式）","dilemma_constraints":"出了问题继续生产，会让缺陷流到下游、积重难返。","key_judgment":"大野耐一发扬\"自働化（jidoka）\"——让流程/机器一发现异常就自动停下、把问题当场暴露并解决，绝不让缺陷流走。","model_invoked":["自働化"],"outcome":"自働化使问题被及时暴露和根治、保障了品质，成TPS的另一支柱。","transferable_lesson":"一发现异常就停下、暴露问题当场解决、不让缺陷流到下游——问题暴露比掩盖好。","source_tier":"primary","source_note":"自働化(jidoka)为大野《丰田生产方式》所述→确证（一手A）。","historicity":"confirmed","linked_cards":["ohno"],"tags":["组织管理","资源调度"],"advisor_id":"ohno"}', 'b4e633b52d1553663348b229e837d8f90c087f2a56c1bd6c0a5f3316d2d4ae56');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('ohno-c4', 'ohno', '「五个为什么」·刨到根本原因（丰田生产方式）', '问题反复出现，因为每次只解决了表面症状。', '大野耐一要求遇到问题连问五次"为什么"，一层层刨到根本原因，再去根治那个根因。', '「5个为什么」成根因分析的经典方法，被全球各行业广泛采用。', '遇到问题连问五次"为什么"、刨到根本原因再根治——问一次是症状、问五次见根因。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"ohno-c4","status":"published","title_period":"「五个为什么」·刨到根本原因（丰田生产方式）","dilemma_constraints":"问题反复出现，因为每次只解决了表面症状。","key_judgment":"大野耐一要求遇到问题连问五次\"为什么\"，一层层刨到根本原因，再去根治那个根因。","model_invoked":["五个为什么"],"outcome":"「5个为什么」成根因分析的经典方法，被全球各行业广泛采用。","transferable_lesson":"遇到问题连问五次\"为什么\"、刨到根本原因再根治——问一次是症状、问五次见根因。","source_tier":"primary","source_note":"「5个为什么」为大野《丰田生产方式》所述→确证（一手A）。","historicity":"confirmed","linked_cards":["ohno"],"tags":["组织管理","认知偏误与理性决策"],"advisor_id":"ohno"}', 'fc4c78e75738e31f472939754e5633e58bd373a0625c00721386c86109b63fd9');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('walton-c1', 'walton', '坚持"天天低价"(EDLP)·薄利多销（沃尔玛经营）', '零售业普遍靠忽高忽低的促销来刺激销量、顾客难以建立稳定信任。', '沃尔顿不玩促销噱头，而是持续把价格压到最低、薄利多销，让顾客相信"在沃尔玛每天都是低价"。', '「天天低价」成沃尔玛的核心战略，赢得了顾客的长期信任与巨大规模。', '别靠忽高忽低的促销——持续把价格压到最低、让顾客信任"每天都是低价"，用稳定低价赢得长期信任与规模。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"walton-c1","status":"published","title_period":"坚持\"天天低价\"(EDLP)·薄利多销（沃尔玛经营）","dilemma_constraints":"零售业普遍靠忽高忽低的促销来刺激销量、顾客难以建立稳定信任。","key_judgment":"沃尔顿不玩促销噱头，而是持续把价格压到最低、薄利多销，让顾客相信\"在沃尔玛每天都是低价\"。","model_invoked":["天天低价"],"outcome":"「天天低价」成沃尔玛的核心战略，赢得了顾客的长期信任与巨大规模。","transferable_lesson":"别靠忽高忽低的促销——持续把价格压到最低、让顾客信任\"每天都是低价\"，用稳定低价赢得长期信任与规模。","source_tier":"primary","source_note":"天天低价(EDLP)为沃尔顿《Made in America》所述→确证（一手A）。","historicity":"confirmed","linked_cards":["walton"],"tags":["创业","组织管理"],"advisor_id":"walton"}', '69e38868799e111e744a1c7b4ba2d020e37a059795d8fd3b24bbbc5ecbd31452');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('walton-c2', 'walton', '专攻被忽视的小镇·农村包围城市（沃尔玛早期）', '大城市已被西尔斯等零售巨头占据，正面硬拼胜算渺茫。', '沃尔顿把沃尔玛先开在被巨头忽视的美国小镇、在那里把网点做密集，坐大之后再向外扩张。', '沃尔玛在小镇市场避开了巨头、迅速坐大，最终成全美乃至全球最大的零售商。', '别一上来就去大城市跟巨头硬拼——先在他们看不上的小镇/下沉市场扎根、做密集再扩张。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"walton-c2","status":"published","title_period":"专攻被忽视的小镇·农村包围城市（沃尔玛早期）","dilemma_constraints":"大城市已被西尔斯等零售巨头占据，正面硬拼胜算渺茫。","key_judgment":"沃尔顿把沃尔玛先开在被巨头忽视的美国小镇、在那里把网点做密集，坐大之后再向外扩张。","model_invoked":["农村包围城市"],"outcome":"沃尔玛在小镇市场避开了巨头、迅速坐大，最终成全美乃至全球最大的零售商。","transferable_lesson":"别一上来就去大城市跟巨头硬拼——先在他们看不上的小镇/下沉市场扎根、做密集再扩张。","source_tier":"primary","source_note":"沃尔玛早期专攻小镇、避开巨头为史实→确证。","historicity":"confirmed","linked_cards":["walton"],"tags":["创业","资源调度"],"advisor_id":"walton"}', '8691dc46135831e8baa049af6c55b9cc515c14d7df1372db486c7b6ce3e78429');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('walton-c3', 'walton', '一生不停巡店、向对手学·亲临一线（毕生）', '零售运营的细节难以从总部报表中完全把握。', '沃尔顿一生不停地亲自跑各地门店、在现场观察、向员工请教，甚至仔细逛竞争对手的店、把好点子立刻抄过来。', '这种扎根一线的学习与快速复制，使沃尔玛持续吸收最佳实践、保持运营领先。', '别只坐总部看报表——亲自跑一线、向员工和竞争对手学、好点子立刻抄过来。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"walton-c3","status":"published","title_period":"一生不停巡店、向对手学·亲临一线（毕生）","dilemma_constraints":"零售运营的细节难以从总部报表中完全把握。","key_judgment":"沃尔顿一生不停地亲自跑各地门店、在现场观察、向员工请教，甚至仔细逛竞争对手的店、把好点子立刻抄过来。","model_invoked":["亲临一线巡店"],"outcome":"这种扎根一线的学习与快速复制，使沃尔玛持续吸收最佳实践、保持运营领先。","transferable_lesson":"别只坐总部看报表——亲自跑一线、向员工和竞争对手学、好点子立刻抄过来。","source_tier":"primary","source_note":"沃尔顿一生巡店、逛对手店学习为其自传所述→确证（一手A）。","historicity":"confirmed","linked_cards":["walton"],"tags":["组织管理","创业"],"advisor_id":"walton"}', '64d71b42b450901d54d7851e365a8171de1090113654672bfe97cca3d34d7696');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('walton-c4', 'walton', '把员工称"同事"、利润分享·善待同事激励（沃尔玛文化）', '零售一线员工易被当作纯成本与执行工具、缺乏积极性。', '沃尔顿把员工称为"同事(associates)"、推行利润分享与参与，希望让一线有主人翁意识与积极性。', '这一理念是沃尔玛文化的一部分；但须注意沃尔玛实际的劳工待遇也广受批评、与此理念存在张力（见盲区）。', '把一线员工当"同事"、给参与感与主人翁意识，能激发一线的积极性——但理念须真正落到待遇上、否则只是口号。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"walton-c4","status":"published","title_period":"把员工称\"同事\"、利润分享·善待同事激励（沃尔玛文化）","dilemma_constraints":"零售一线员工易被当作纯成本与执行工具、缺乏积极性。","key_judgment":"沃尔顿把员工称为\"同事(associates)\"、推行利润分享与参与，希望让一线有主人翁意识与积极性。","model_invoked":["善待同事激励"],"outcome":"这一理念是沃尔玛文化的一部分；但须注意沃尔玛实际的劳工待遇也广受批评、与此理念存在张力（见盲区）。","transferable_lesson":"把一线员工当\"同事\"、给参与感与主人翁意识，能激发一线的积极性——但理念须真正落到待遇上、否则只是口号。","source_tier":"primary","source_note":"「associates」与利润分享理念为沃尔顿自传所述→确证；惟实际劳工待遇有争议（已入盲区，客观标注）。","historicity":"confirmed","linked_cards":["walton"],"tags":["组织管理","领导力"],"advisor_id":"walton"}', '2234c4fb1b7a2dca2008ba8ca7d0c4625f8311c7a7f9e9587dd82cc0fec1cebe');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('buffett-c1', 'buffett', '1963–64年美国运通色拉油丑闻抄底', '色拉油欺诈案使运通股价腰斩、市场担心其承担巨额赔付濒临崩塌；当时是其合伙基金的极大风险敞口', '实地确认顾客仍照常使用运通卡与旅行支票、消费特许权未损，判断恐慌过度，重仓至组合40%上限', '运通股价数年内大涨，成为其合伙人时代回报最高的单笔之一，约占组合40%（A）', '市场因一次性丑闻恐慌时，若核心特许权未损，恐慌就是机会；先去现场验证基本盘，别只看股价', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"buffett-c1","status":"published","title_period":"1963–64年美国运通色拉油丑闻抄底","dilemma_constraints":"色拉油欺诈案使运通股价腰斩、市场担心其承担巨额赔付濒临崩塌；当时是其合伙基金的极大风险敞口","key_judgment":"实地确认顾客仍照常使用运通卡与旅行支票、消费特许权未损，判断恐慌过度，重仓至组合40%上限","model_invoked":["贪婪恐惧反向"],"outcome":"运通股价数年内大涨，成为其合伙人时代回报最高的单笔之一，约占组合40%（A）","transferable_lesson":"市场因一次性丑闻恐慌时，若核心特许权未损，恐慌就是机会；先去现场验证基本盘，别只看股价","source_tier":"primary","source_note":"运通跌幅、40%仓位见巴菲特1968年合伙人信（A）及传记（B）","historicity":"confirmed","linked_cards":["buffett"],"tags":["投资","商业模式与护城河"],"advisor_id":"buffett"}', '08ee48943e795bdd48fe590be9a061c621573a4f0fa4d1ded70c2d5730346fb4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('buffett-c2', 'buffett', '1962–65年接管伯克希尔纺织（自认最大错误）', '他本只想低价买入这家衰落纺织厂、待回购套利了结；CEO在回购报价上''砍了八分之一''令他恼火', '出于赌气而非理性，反而大举买入、夺取控制权并撤换CEO，把资本套进一个夕阳产业', '纺织业务苦撑至1985年关闭；他估算若当初把资本投入保险，伯克希尔市值可翻倍（机会成本约2000亿）（A）', '反例：赌气与自尊驱动的决策代价极大；再小的情绪羞辱，也别让它替你配置资本', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"buffett-c2","status":"published","title_period":"1962–65年接管伯克希尔纺织（自认最大错误）","dilemma_constraints":"他本只想低价买入这家衰落纺织厂、待回购套利了结；CEO在回购报价上''砍了八分之一''令他恼火","key_judgment":"出于赌气而非理性，反而大举买入、夺取控制权并撤换CEO，把资本套进一个夕阳产业","model_invoked":["贪婪恐惧反向"],"outcome":"纺织业务苦撑至1985年关闭；他估算若当初把资本投入保险，伯克希尔市值可翻倍（机会成本约2000亿）（A）","transferable_lesson":"反例：赌气与自尊驱动的决策代价极大；再小的情绪羞辱，也别让它替你配置资本","source_tier":"primary","source_note":"''砍了八分之一''、赌气接管、''愚蠢至极''与约2000亿机会成本估算均见其本人访谈/股东信（A）及洛温斯坦传记（B）；为反例案例","historicity":"confirmed","linked_cards":["buffett"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"buffett"}', 'e2b968095e3a0c4342844588c975d9d9e62b8df3f02178edd33e452bd320c90f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('buffett-c3', 'buffett', '1967年收购国民赔偿保险（浮存金引擎）', '纺织主业现金流枯竭、资本无处增值；需为伯克希尔找到能持续产生低成本长期资金的新引擎', '收购国民赔偿保险公司，把保费''浮存金''（先收后赔的暂存资金）当作近乎免费的长期投资本金', '保险浮存金成为伯克希尔数十年扩张的核心资金来源，奠定其''保险+资本配置''的复利机器（A/B）', '真正的杠杆不一定是借债——找到能持续、低成本占用他人资金的结构，再把它配置到高回报处', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"buffett-c3","status":"published","title_period":"1967年收购国民赔偿保险（浮存金引擎）","dilemma_constraints":"纺织主业现金流枯竭、资本无处增值；需为伯克希尔找到能持续产生低成本长期资金的新引擎","key_judgment":"收购国民赔偿保险公司，把保费''浮存金''（先收后赔的暂存资金）当作近乎免费的长期投资本金","model_invoked":["浮存金与配置"],"outcome":"保险浮存金成为伯克希尔数十年扩张的核心资金来源，奠定其''保险+资本配置''的复利机器（A/B）","transferable_lesson":"真正的杠杆不一定是借债——找到能持续、低成本占用他人资金的结构，再把它配置到高回报处","source_tier":"primary","source_note":"1967年收购、浮存金机制见伯克希尔股东信（A）及传记（B）","historicity":"confirmed","linked_cards":["buffett"],"tags":["投资","商业模式与护城河"],"advisor_id":"buffett"}', '76105b72c08990b0dbc63850f9f48fa06173cbf51fdecdf000d1d6ca68bd5302');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('buffett-c4', 'buffett', '2008年金融危机逆向出手', '金融危机中市场极度恐慌、优质金融机构急需资本、前景晦暗不明，多数人在抛售', '判断美国经济长期向上、恐慌过度，向高盛、通用电气等注资优先股拿高息加认股权，并公开发文''我在买入美国''', '这些危机投资获得丰厚回报，成为''别人恐惧时贪婪''的标志性实践（A/B）', '系统性恐慌中，手握现金、判断长期基本盘未变的人，能以极优条款向最急需者提供资本', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"buffett-c4","status":"published","title_period":"2008年金融危机逆向出手","dilemma_constraints":"金融危机中市场极度恐慌、优质金融机构急需资本、前景晦暗不明，多数人在抛售","key_judgment":"判断美国经济长期向上、恐慌过度，向高盛、通用电气等注资优先股拿高息加认股权，并公开发文''我在买入美国''","model_invoked":["贪婪恐惧反向"],"outcome":"这些危机投资获得丰厚回报，成为''别人恐惧时贪婪''的标志性实践（A/B）","transferable_lesson":"系统性恐慌中，手握现金、判断长期基本盘未变的人，能以极优条款向最急需者提供资本","source_tier":"primary","source_note":"高盛/GE优先股条款、''Buy American''纽约时报评论见公开记录（A/B）","historicity":"confirmed","linked_cards":["buffett"],"tags":["投资","危机应对"],"advisor_id":"buffett"}', '9735e29bb31a148c6a412cca1f8f302c7bead0d0bb059b4744ba151e89e959fe');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('buffett-c5', 'buffett', '2016年起重仓苹果（突破科技回避）', '他与芒格长期回避科技股、自认不懂；但苹果已是高黏性消费品牌而非纯科技公司', '把苹果重新归类为拥有极强用户黏性与生态护城河的消费特许权，跨出科技回避、建成其最大持仓之一', '苹果成为伯克希尔最大、最赚钱的股票持仓之一；显示其框架能随认知更新而演进（A/B）', '回避不懂的领域是纪律，但当一项''新事物''本质落进你懂的旧框架（消费特许权）时，要敢重新归类', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"buffett-c5","status":"published","title_period":"2016年起重仓苹果（突破科技回避）","dilemma_constraints":"他与芒格长期回避科技股、自认不懂；但苹果已是高黏性消费品牌而非纯科技公司","key_judgment":"把苹果重新归类为拥有极强用户黏性与生态护城河的消费特许权，跨出科技回避、建成其最大持仓之一","model_invoked":["经济护城河"],"outcome":"苹果成为伯克希尔最大、最赚钱的股票持仓之一；显示其框架能随认知更新而演进（A/B）","transferable_lesson":"回避不懂的领域是纪律，但当一项''新事物''本质落进你懂的旧框架（消费特许权）时，要敢重新归类","source_tier":"primary","source_note":"苹果持仓与其''消费特许权''定性见伯克希尔披露及巴菲特公开访谈（A/B）","historicity":"confirmed","linked_cards":["buffett"],"tags":["投资","商业模式与护城河"],"advisor_id":"buffett"}', '228da7a445a4f6ab12d93f5eec9caeb77230a3036a95484a31da636da07fb22a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('morgan-c1', 'morgan', '组建美国钢铁·资本整合重组（1901）', '美国钢铁业由卡内基钢铁等多家激烈竞争，价格战与重复建设损耗巨大。', '摩根出资约 4.8 亿美元买下卡内基钢铁并整合多家钢铁企业，组建美国钢铁公司(US Steel)——史上第一家市值超十亿美元的公司。', '以资本整合换来了行业秩序与空前规模，但也成反托拉斯与垄断争议的标志。', '行业分散、过度竞争、整体受损时，用资本把分散的玩家整合成有秩序的大组织——但须警惕这滑向垄断、抑制创新。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"morgan-c1","status":"published","title_period":"组建美国钢铁·资本整合重组（1901）","dilemma_constraints":"美国钢铁业由卡内基钢铁等多家激烈竞争，价格战与重复建设损耗巨大。","key_judgment":"摩根出资约 4.8 亿美元买下卡内基钢铁并整合多家钢铁企业，组建美国钢铁公司(US Steel)——史上第一家市值超十亿美元的公司。","model_invoked":["资本整合重组"],"outcome":"以资本整合换来了行业秩序与空前规模，但也成反托拉斯与垄断争议的标志。","transferable_lesson":"行业分散、过度竞争、整体受损时，用资本把分散的玩家整合成有秩序的大组织——但须警惕这滑向垄断、抑制创新。","source_tier":"secondary","source_note":"组建US Steel为史实→确证（金额/过程见传记，个别动机属重构）。","historicity":"confirmed","linked_cards":["morgan"],"tags":["资源调度","组织管理"],"advisor_id":"morgan"}', '72313cda15ac8b0e93527f36227d31e5813d9e30b29d13988d9867cd5c3875e4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('morgan-c2', 'morgan', '1907年大恐慌救市·危机中挺身组织救援（1907）', '1907年银行挤兑、金融恐慌蔓延，当时美国尚无中央银行、无人能统筹救援。', '摩根把纽约主要银行家召集到自己的图书馆、甚至锁门不让离开，逼各方共同出资、凑齐救援资金，止住了系统性挤兑。', '凭个人威望与组织力止住了1907年恐慌，此事也直接推动了后来美联储的创建。', '系统性危机、各方观望自保时，若你是有威望的中枢，把各方锁在一起、组织共同救援直到凑齐资源。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"morgan-c2","status":"published","title_period":"1907年大恐慌救市·危机中挺身组织救援（1907）","dilemma_constraints":"1907年银行挤兑、金融恐慌蔓延，当时美国尚无中央银行、无人能统筹救援。","key_judgment":"摩根把纽约主要银行家召集到自己的图书馆、甚至锁门不让离开，逼各方共同出资、凑齐救援资金，止住了系统性挤兑。","model_invoked":["危机中挺身组织救援"],"outcome":"凭个人威望与组织力止住了1907年恐慌，此事也直接推动了后来美联储的创建。","transferable_lesson":"系统性危机、各方观望自保时，若你是有威望的中枢，把各方锁在一起、组织共同救援直到凑齐资源。","source_tier":"secondary","source_note":"1907年摩根组织救市为史实→确证（锁门等细节见传记记述）。","historicity":"confirmed","linked_cards":["morgan"],"tags":["危机应对","资源调度"],"advisor_id":"morgan"}', '468f9fcf940f2d393a7103a495fac1ab853f41ce67efc6caf8533646b232551f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('morgan-c3', 'morgan', '普约委员会作证·信用即资产（1912）', '国会调查"金钱托拉斯"，质询摩根放贷与控制的依据。', '摩根作证称，决定是否给一个人信贷，首要看的是他的品格与信用、而非金钱或财产——"我不信任的人，拿全世界的债券也借不到我的钱"。', '这段证词成其"信用立身"哲学的经典表述。', '把品格与信用当合作的首要前提、而非只看抵押品与数字——你自己的信用，也是你最大的资产。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"morgan-c3","status":"published","title_period":"普约委员会作证·信用即资产（1912）","dilemma_constraints":"国会调查\"金钱托拉斯\"，质询摩根放贷与控制的依据。","key_judgment":"摩根作证称，决定是否给一个人信贷，首要看的是他的品格与信用、而非金钱或财产——\"我不信任的人，拿全世界的债券也借不到我的钱\"。","model_invoked":["信用即资产"],"outcome":"这段证词成其\"信用立身\"哲学的经典表述。","transferable_lesson":"把品格与信用当合作的首要前提、而非只看抵押品与数字——你自己的信用，也是你最大的资产。","source_tier":"primary","source_note":"普约委员会证词为一手记录→确证。","historicity":"confirmed","linked_cards":["morgan"],"tags":["投资","组织管理"],"advisor_id":"morgan"}', '5458978f9d4f4b1f021860a1e0cd7057218b27d3bdcacb64bf0ca2b7a10df2d6');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('morgan-c4', 'morgan', '董事会网络与"金钱托拉斯"·关系网络控制（19世纪末—20世纪初）', '如何在不全资拥有众多企业的情况下，对一大批铁路、银行、企业施加影响与控制。', '摩根通过让合伙人出任各大公司董事、并以"共同利益"协调，建立起一张覆盖众多企业的影响与控制网络。', '形成了巨大的金融影响力，也招致"金钱托拉斯"之讥与反垄断审视。', '不必全资拥有——靠董事会席位与人脉建立影响网络；但须警惕权力过度集中是其阴暗面。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"morgan-c4","status":"published","title_period":"董事会网络与\"金钱托拉斯\"·关系网络控制（19世纪末—20世纪初）","dilemma_constraints":"如何在不全资拥有众多企业的情况下，对一大批铁路、银行、企业施加影响与控制。","key_judgment":"摩根通过让合伙人出任各大公司董事、并以\"共同利益\"协调，建立起一张覆盖众多企业的影响与控制网络。","model_invoked":["关系网络控制"],"outcome":"形成了巨大的金融影响力，也招致\"金钱托拉斯\"之讥与反垄断审视。","transferable_lesson":"不必全资拥有——靠董事会席位与人脉建立影响网络；但须警惕权力过度集中是其阴暗面。","source_tier":"secondary","source_note":"摩根的董事会网络与\"金钱托拉斯\"质疑为史实→确证。","historicity":"confirmed","linked_cards":["morgan"],"tags":["组织管理","资源调度"],"advisor_id":"morgan"}', '6c137461f57b98625484c2b21c182f2c540852ae94383c9770a8656dfa80582d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('honda-c1', 'honda', '一生以工程师自居·亲自蹲车间（毕生）', '企业做大后，创始人很容易脱离技术一线、转为纯管理。', '本田始终以工程师自居、亲自下场蹲在车间解决技术难题，把技术钻到底、用实打实的技术说话。', '本田技研以过硬的发动机技术（如CVCC低污染发动机）立足世界。', '做技术/产品就亲自下场、把技术钻到底、用实打实的技术说话，而非脱离一线靠管理指挥。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"honda-c1","status":"published","title_period":"一生以工程师自居·亲自蹲车间（毕生）","dilemma_constraints":"企业做大后，创始人很容易脱离技术一线、转为纯管理。","key_judgment":"本田始终以工程师自居、亲自下场蹲在车间解决技术难题，把技术钻到底、用实打实的技术说话。","model_invoked":["技术第一亲手实干"],"outcome":"本田技研以过硬的发动机技术（如CVCC低污染发动机）立足世界。","transferable_lesson":"做技术/产品就亲自下场、把技术钻到底、用实打实的技术说话，而非脱离一线靠管理指挥。","source_tier":"secondary","source_note":"本田以工程师自居、亲自蹲车间为传记/语录所载→确证。","historicity":"confirmed","linked_cards":["honda"],"tags":["创新研发","领导力"],"advisor_id":"honda"}', 'f126c76b3a42e422d45584101dacdc1433df44e20e3996804f36ad6b2e877e0c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('honda-c2', 'honda', '「成功是99%的失败堆出来的」·不怕失败的试错（毕生）', '技术突破要经历大量失败，怕失败就不敢试。', '本田把失败当作通往成功的必经之路——"我所谓的成功、是由99%的失败堆出来的"，在大量失败中快速试错迭代。', '这种不怕失败的试错精神成本田技术创新的底色。', '把失败当通往成功的必经之路、快速试错迭代——别怕失败（但须知试错代价高、非"失败越多越好"）。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"honda-c2","status":"published","title_period":"「成功是99%的失败堆出来的」·不怕失败的试错（毕生）","dilemma_constraints":"技术突破要经历大量失败，怕失败就不敢试。","key_judgment":"本田把失败当作通往成功的必经之路——\"我所谓的成功、是由99%的失败堆出来的\"，在大量失败中快速试错迭代。","model_invoked":["不怕失败的试错"],"outcome":"这种不怕失败的试错精神成本田技术创新的底色。","transferable_lesson":"把失败当通往成功的必经之路、快速试错迭代——别怕失败（但须知试错代价高、非\"失败越多越好\"）。","source_tier":"secondary","source_note":"「99%失败」为本田著名语→确证。","historicity":"confirmed","linked_cards":["honda"],"tags":["创新研发","创业"],"advisor_id":"honda"}', '322d378f5722d88b6327c3f1e22f0f3c7b2f5488534c9c75797d9dfae37c192a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('honda-c3', 'honda', '征战曼岛TT与F1·挑战极限立品牌（1950s—1960s起）', '一家年轻的日本摩托/汽车厂如何向世界证明自己的技术实力。', '本田公开宣言并实现征战世界最高难度的曼岛TT摩托车赛、随后进军F1，用赛场的硬实力证明技术。', '赛场胜利极大地立起了本田的技术品牌与世界声誉。', '到最高难度的擂台上用硬实力证明自己、而非靠说辞——挑战极限的胜利最能立品牌（但耗资巨大、须有实力支撑）。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"honda-c3","status":"published","title_period":"征战曼岛TT与F1·挑战极限立品牌（1950s—1960s起）","dilemma_constraints":"一家年轻的日本摩托/汽车厂如何向世界证明自己的技术实力。","key_judgment":"本田公开宣言并实现征战世界最高难度的曼岛TT摩托车赛、随后进军F1，用赛场的硬实力证明技术。","model_invoked":["挑战极限立品牌"],"outcome":"赛场胜利极大地立起了本田的技术品牌与世界声誉。","transferable_lesson":"到最高难度的擂台上用硬实力证明自己、而非靠说辞——挑战极限的胜利最能立品牌（但耗资巨大、须有实力支撑）。","source_tier":"secondary","source_note":"本田征战曼岛TT、进军F1为企业史所载→确证。","historicity":"confirmed","linked_cards":["honda"],"tags":["创新研发","领导力"],"advisor_id":"honda"}', '2835f32574160f0c526eb4c0c0c8a81112f990df83143297542f6579610e473f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('honda-c4', 'honda', '与藤泽武夫的搭档·专业分工授权（1949起）', '本田痴迷技术、却不擅长经营与财务，企业需要有人补上这一块。', '本田认清自己最强的是技术，把经营、财务、销售全权交给搭档藤泽武夫，两人各专所长、配合数十年。', '技术（本田）与经营（藤泽）的黄金搭档，成本田崛起的关键。', '认清自己最强的那一块、把自己不擅长的放心交给真正专业的人——各专所长、合力远强于一个人硬撑全部。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"honda-c4","status":"published","title_period":"与藤泽武夫的搭档·专业分工授权（1949起）","dilemma_constraints":"本田痴迷技术、却不擅长经营与财务，企业需要有人补上这一块。","key_judgment":"本田认清自己最强的是技术，把经营、财务、销售全权交给搭档藤泽武夫，两人各专所长、配合数十年。","model_invoked":["专业分工授权"],"outcome":"技术（本田）与经营（藤泽）的黄金搭档，成本田崛起的关键。","transferable_lesson":"认清自己最强的那一块、把自己不擅长的放心交给真正专业的人——各专所长、合力远强于一个人硬撑全部。","source_tier":"secondary","source_note":"本田与藤泽武夫的分工搭档为史实→确证。","historicity":"confirmed","linked_cards":["honda"],"tags":["领导力","创业"],"advisor_id":"honda"}', '5c7e5472e89be6008a224c8054543b02b0c3a312c2e936396897ee7cd562aa94');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('matsushita-c1', 'matsushita', '提出"自来水哲学"·普及消除匮乏（1932）', '当时优质工业品仍是少数人才用得起的稀缺品。', '松下提出企业的使命是像自来水一样、把优质物资大量、低价地供给大众、让人人都用得起，以此消除贫困。', '「自来水哲学」成松下经营的根本理念，驱动了优质家电的普及。', '把优质的产品/服务像自来水一样大量、低价地供给大众、以"普及"消除匮乏——好东西的价值在普及、而非做成稀缺特权。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"matsushita-c1","status":"published","title_period":"提出\"自来水哲学\"·普及消除匮乏（1932）","dilemma_constraints":"当时优质工业品仍是少数人才用得起的稀缺品。","key_judgment":"松下提出企业的使命是像自来水一样、把优质物资大量、低价地供给大众、让人人都用得起，以此消除贫困。","model_invoked":["自来水哲学"],"outcome":"「自来水哲学」成松下经营的根本理念，驱动了优质家电的普及。","transferable_lesson":"把优质的产品/服务像自来水一样大量、低价地供给大众、以\"普及\"消除匮乏——好东西的价值在普及、而非做成稀缺特权。","source_tier":"primary","source_note":"自来水哲学为松下1932年宣言→确证（一手A）。","historicity":"confirmed","linked_cards":["matsushita"],"tags":["创业","领导力"],"advisor_id":"matsushita"}', '1b9624e65b529c60f3437fdbbe2b89d42aa6154a754d5082cd86c89005bf9bc7');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('matsushita-c2', 'matsushita', '倡"水坝式经营"·留有余裕（战后）', '企业普遍把资金、设备、人力用到极限、一遇波动便难以为继。', '松下主张像水坝蓄水一样、在资金、设备、人力上都留出余裕、不满负荷运转，以备不时之需。', '「水坝式经营」成松下稳健经营的代表理念，使企业更能抵御波动。', '像水坝蓄水一样留有余裕、不满负荷运转——有缓冲才能应对波动与不时之需，别把弦绷到极限。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"matsushita-c2","status":"published","title_period":"倡\"水坝式经营\"·留有余裕（战后）","dilemma_constraints":"企业普遍把资金、设备、人力用到极限、一遇波动便难以为继。","key_judgment":"松下主张像水坝蓄水一样、在资金、设备、人力上都留出余裕、不满负荷运转，以备不时之需。","model_invoked":["水坝式经营"],"outcome":"「水坝式经营」成松下稳健经营的代表理念，使企业更能抵御波动。","transferable_lesson":"像水坝蓄水一样留有余裕、不满负荷运转——有缓冲才能应对波动与不时之需，别把弦绷到极限。","source_tier":"primary","source_note":"水坝式经营为松下经营论述→确证（一手A）。","historicity":"confirmed","linked_cards":["matsushita"],"tags":["长期规划","组织管理"],"advisor_id":"matsushita"}', '3bb208db140f0367822cf0950d4e4ce96ebf10e61733b510fe5fe2786f482161');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('matsushita-c3', 'matsushita', '率先推行事业部制·分权经营（1933起）', '企业随业务扩张而集权臃肿、反应迟钝。', '松下把公司分成多个独立核算的事业部、分权经营、各自对自己的利润负责，是日本最早的事业部制实践之一。', '事业部制带来了分权的敏捷与责任感，成现代企业组织的重要范式。', '组织变大、集权臃肿反应迟钝时，把它分成独立核算的事业部、分权经营、各负其责——分权带来敏捷与责任感。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"matsushita-c3","status":"published","title_period":"率先推行事业部制·分权经营（1933起）","dilemma_constraints":"企业随业务扩张而集权臃肿、反应迟钝。","key_judgment":"松下把公司分成多个独立核算的事业部、分权经营、各自对自己的利润负责，是日本最早的事业部制实践之一。","model_invoked":["事业部制"],"outcome":"事业部制带来了分权的敏捷与责任感，成现代企业组织的重要范式。","transferable_lesson":"组织变大、集权臃肿反应迟钝时，把它分成独立核算的事业部、分权经营、各负其责——分权带来敏捷与责任感。","source_tier":"primary","source_note":"松下率先推行事业部制为经营史所载→确证（A/B）。","historicity":"confirmed","linked_cards":["matsushita"],"tags":["组织管理","领导力"],"advisor_id":"matsushita"}', '9d75f1a88213100d9fdec6e7612e0fbaf3a176af0a39e2bf579e5840dc8efa3c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('matsushita-c4', 'matsushita', '「企业是社会公器」与素直之心·根本理念（毕生）', '企业经营容易把利润当作唯一目的、把判断被成见与私心扭曲。', '松下把企业定位为"为社会服务的公器"、利润是把事做对的结果；晚年又极推崇以坦诚虚心、不带成见的"素直之心"如实看事物。', '这两条理念成松下经营哲学的精神内核，影响广泛。', '把企业看作为社会服务的公器、利润是结果而非唯一目的；并以坦诚虚心、不带成见的素直之心如实看事物、做对判断。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"matsushita-c4","status":"published","title_period":"「企业是社会公器」与素直之心·根本理念（毕生）","dilemma_constraints":"企业经营容易把利润当作唯一目的、把判断被成见与私心扭曲。","key_judgment":"松下把企业定位为\"为社会服务的公器\"、利润是把事做对的结果；晚年又极推崇以坦诚虚心、不带成见的\"素直之心\"如实看事物。","model_invoked":["企业是社会公器"],"outcome":"这两条理念成松下经营哲学的精神内核，影响广泛。","transferable_lesson":"把企业看作为社会服务的公器、利润是结果而非唯一目的；并以坦诚虚心、不带成见的素直之心如实看事物、做对判断。","source_tier":"primary","source_note":"「企业是社会公器」与素直之心为松下著述/理念→确证（一手A）；惟实践中需防其沦为口号（已入盲区）。","historicity":"confirmed","linked_cards":["matsushita"],"tags":["领导力","价值与伦理"],"advisor_id":"matsushita"}', 'f9ff92c976ed7ba076b121af772c81f9b17fd19ca7d447e72b9c3ba3e1e8f627');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('munger-c1', 'munger', '1972年收购喜诗糖果（投资范式转移）', '此前奉行格雷厄姆烟蒂式投资，只买远低于清算价的便宜货。喜诗要价约2500万美元，约为其有形净资产（约800万）的三倍多，按旧标准属太贵', '看到要害不是贵不贵，而是喜诗有品牌定价权和约25%有形资产回报率，是能年年提价的好生意；力主为伟大生意付合理高价，并说服巴菲特出手', '成为伯克希尔梦想生意原型，数十年现金流远超买价，并改变巴菲特此后的资本配置哲学（A）', '生意有真实定价权或护城河时，死抠账面便宜会错过真正的复利；先判断生意质量，再谈价格', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"munger-c1","status":"published","title_period":"1972年收购喜诗糖果（投资范式转移）","dilemma_constraints":"此前奉行格雷厄姆烟蒂式投资，只买远低于清算价的便宜货。喜诗要价约2500万美元，约为其有形净资产（约800万）的三倍多，按旧标准属太贵","key_judgment":"看到要害不是贵不贵，而是喜诗有品牌定价权和约25%有形资产回报率，是能年年提价的好生意；力主为伟大生意付合理高价，并说服巴菲特出手","model_invoked":["多元思维格栅"],"outcome":"成为伯克希尔梦想生意原型，数十年现金流远超买价，并改变巴菲特此后的资本配置哲学（A）","transferable_lesson":"生意有真实定价权或护城河时，死抠账面便宜会错过真正的复利；先判断生意质量，再谈价格","source_tier":"primary","source_note":"收购价与财务数据见巴菲特1983年致股东信（A）；芒格推动范式转移见《Fortune》1988及权威传记（B）","historicity":"confirmed","linked_cards":["munger"],"tags":["投资","商业模式与护城河"],"advisor_id":"munger"}', '8672fea104a3fa474117034f4e8544aa20d39f1a2d51f85e3282c61edc2edb10');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('munger-c2', 'munger', '1973–74年合伙基金深度回撤', '芒格打法极度集中（重仓蓝筹印花、New America Fund），时而加杠杆。1973–74大熊市中组合按市价连续两年各跌约31%，两年累计近乎腰斩', '区分市价暂时下跌与内在价值永久损失，判断持仓价值未腰斩、坚持不在底部割肉；但意识到替外部出资人管钱、报告账面亏损的压力远大于管理自有资金', '1975年组合反弹约73%、全期年化仍跑赢道指；但因回撤致出资人流失，他于1975/76年清盘退资（B）', '集中加杠杆是高回报的来源也是深度回撤的代价；这套打法对波动承受力与是否对外部资金负责要求极高，须分清市价波动与价值毁灭', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"munger-c2","status":"published","title_period":"1973–74年合伙基金深度回撤","dilemma_constraints":"芒格打法极度集中（重仓蓝筹印花、New America Fund），时而加杠杆。1973–74大熊市中组合按市价连续两年各跌约31%，两年累计近乎腰斩","key_judgment":"区分市价暂时下跌与内在价值永久损失，判断持仓价值未腰斩、坚持不在底部割肉；但意识到替外部出资人管钱、报告账面亏损的压力远大于管理自有资金","model_invoked":["误判心理学"],"outcome":"1975年组合反弹约73%、全期年化仍跑赢道指；但因回撤致出资人流失，他于1975/76年清盘退资（B）","transferable_lesson":"集中加杠杆是高回报的来源也是深度回撤的代价；这套打法对波动承受力与是否对外部资金负责要求极高，须分清市价波动与价值毁灭","source_tier":"secondary","source_note":"无公开年报；连续两年约31%回撤与''出资人赎回致1975/76年清盘''均有独立B层传记记载（Janet Lowe《Damn Right!》、Alice Schroeder《滚雪球》及多家财经媒体），非孤证、非仅芒格自述，故historicity判确证；芒格本人亦多次公开复述（A）","historicity":"confirmed","linked_cards":["munger"],"tags":["投资","风险评估","认知偏误与理性决策"],"advisor_id":"munger"}', '0d091867e3188590165e5f448db497cead508ef90f2a3add94bef094f9ff5fe5');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('munger-c3', 'munger', '2008年投资比亚迪（能力圈延伸）', '巴菲特与芒格长期回避科技与汽车这类难懂的重资本行业；比亚迪当时在美国几乎无人知晓，技术细节他们也看不太透', '经信任的投资人李录了解比亚迪，把判断权重放在管理层质量上、认定王传福是罕见实干家；据此跨出老办法的舒适区力主投资约2.3亿美元，并说服谨慎的巴菲特', '成为伯克希尔最成功的海外投资之一；芒格2023年称这是他对伯克希尔唯一一次、却最大的一次贡献（A）', '在看不清的领域，找到并信任真正懂行、利益与你一致的人本身就是能力圈延伸；生意与领导者足够卓越时敢破自己的规则，但须判断有据且能长期持有', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"munger-c3","status":"published","title_period":"2008年投资比亚迪（能力圈延伸）","dilemma_constraints":"巴菲特与芒格长期回避科技与汽车这类难懂的重资本行业；比亚迪当时在美国几乎无人知晓，技术细节他们也看不太透","key_judgment":"经信任的投资人李录了解比亚迪，把判断权重放在管理层质量上、认定王传福是罕见实干家；据此跨出老办法的舒适区力主投资约2.3亿美元，并说服谨慎的巴菲特","model_invoked":["能力圈与太难堆"],"outcome":"成为伯克希尔最成功的海外投资之一；芒格2023年称这是他对伯克希尔唯一一次、却最大的一次贡献（A）","transferable_lesson":"在看不清的领域，找到并信任真正懂行、利益与你一致的人本身就是能力圈延伸；生意与领导者足够卓越时敢破自己的规则，但须判断有据且能长期持有","source_tier":"primary","source_note":"投资金额、约10%股权及引荐人李录见主流财经媒体（B）；其本人评价见2023年Daily Journal年会公开发言（A）","historicity":"confirmed","linked_cards":["munger"],"tags":["投资","创新研发"],"advisor_id":"munger"}', '1dbc982c769ea991aa6db4fdeb3237a30d86733291a991eb57de1e8cefc24d52');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('munger-c4', 'munger', '2021年UCSB无窗宿舍争议（盲区·反例）', '他捐资2亿美元、附带条件须严格按其蓝图建造一栋11层、约4500床位、约94%单人卧室无窗的宿舍；理念是卧室小而无窗能逼学生走出房间社交', '坚信自己逼出社交的第一性推理优于建筑常识与采光对健康的大量证据；面对顾问建筑师辞职抗议，公开反唇相讥、斥反对者为白痴，并预言全美高校会争相效仿', '方案引发全国性批评，校方最终于2023年放弃该设计（B）', '反例：极强的自洽推理一旦越出能力圈又拒听领域专家与反证，就会从洞察滑向傲慢——用他自己的框架看，这件事本该放进太难堆', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"munger-c4","status":"published","title_period":"2021年UCSB无窗宿舍争议（盲区·反例）","dilemma_constraints":"他捐资2亿美元、附带条件须严格按其蓝图建造一栋11层、约4500床位、约94%单人卧室无窗的宿舍；理念是卧室小而无窗能逼学生走出房间社交","key_judgment":"坚信自己逼出社交的第一性推理优于建筑常识与采光对健康的大量证据；面对顾问建筑师辞职抗议，公开反唇相讥、斥反对者为白痴，并预言全美高校会争相效仿","model_invoked":["逆向思维"],"outcome":"方案引发全国性批评，校方最终于2023年放弃该设计（B）","transferable_lesson":"反例：极强的自洽推理一旦越出能力圈又拒听领域专家与反证，就会从洞察滑向傲慢——用他自己的框架看，这件事本该放进太难堆","source_tier":"secondary","source_note":"反例案例。捐赠条件、设计参数、建筑师辞职见Santa Barbara Independent、CNN、Architectural Record等主流媒体（B）；芒格对设计与批评者的表态为其公开受访言论（A）","historicity":"confirmed","linked_cards":["munger"],"tags":["组织管理","认知偏误与理性决策"],"advisor_id":"munger"}', '3b5bfb4347f3a894762688f59f6c9b41025608d300eb80f4bf18de7f3d320920');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('munger-c5', 'munger', '1997年起长期持有Costco', '价值投资者常受诱惑——估值已高就卖出、或换更便宜的标的；Costco长期估值不低', '判断Costco是极少数兼具会员忠诚度、极致低价飞轮、优秀且正直管理层的伟大生意，把它当作找到对的生意就坐着不动的典范，长期持有、公开表示永不卖出一股', '成为他在伯克希尔之外最钟爱、持有最久的公司之一（任董事约27年，持有至离世）（A/B）', '真正稀缺的不是找到好生意，而是找到后忍住不折腾；对高质量复利资产，频繁交易往往是回报的敌人——前提是你对质量的判断确实过硬', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"munger-c5","status":"published","title_period":"1997年起长期持有Costco","dilemma_constraints":"价值投资者常受诱惑——估值已高就卖出、或换更便宜的标的；Costco长期估值不低","key_judgment":"判断Costco是极少数兼具会员忠诚度、极致低价飞轮、优秀且正直管理层的伟大生意，把它当作找到对的生意就坐着不动的典范，长期持有、公开表示永不卖出一股","model_invoked":["能力圈与太难堆"],"outcome":"成为他在伯克希尔之外最钟爱、持有最久的公司之一（任董事约27年，持有至离世）（A/B）","transferable_lesson":"真正稀缺的不是找到好生意，而是找到后忍住不折腾；对高质量复利资产，频繁交易往往是回报的敌人——前提是你对质量的判断确实过硬","source_tier":"primary","source_note":"1997年起任Costco董事见Costco投资者关系披露（A/B）；芒格对Costco的长期评价见其历年年会公开发言（A）；媒体报道（B）","historicity":"confirmed","linked_cards":["munger"],"tags":["投资","长期规划"],"advisor_id":"munger"}', 'a5e1aaa43807fd606d0e09af3a86bbcdd061312ef95cec436e38235aa49e277d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('graham-c1', 'graham', '1948年投资GEICO（其最大盈利）', 'GEICO是高估值成长型保险股，且买50%股权需把约25%资金压在一只票上——同时违反他不买成长股、不集中两条铁律', '看到GEICO股价仍低于账面、且低成本直销有护城河，判断值得破例重仓并出任董事长', '1948年71.2万美元购50%股权，至1972年增至逾4亿美元，贡献超过其余所有投资之和（A）', '再严的纪律也要为真正看清的卓越机会留破例空间；但破例须基于看清价值，而非冲动', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"graham-c1","status":"published","title_period":"1948年投资GEICO（其最大盈利）","dilemma_constraints":"GEICO是高估值成长型保险股，且买50%股权需把约25%资金压在一只票上——同时违反他不买成长股、不集中两条铁律","key_judgment":"看到GEICO股价仍低于账面、且低成本直销有护城河，判断值得破例重仓并出任董事长","model_invoked":["内在价值"],"outcome":"1948年71.2万美元购50%股权，至1972年增至逾4亿美元，贡献超过其余所有投资之和（A）","transferable_lesson":"再严的纪律也要为真正看清的卓越机会留破例空间；但破例须基于看清价值，而非冲动","source_tier":"primary","source_note":"投资额、股权与增值见格雷厄姆-纽曼记录及多家研究复述（A/B）；''破自己规则''为公认事实","historicity":"confirmed","linked_cards":["graham"],"tags":["投资","商业模式与护城河"],"advisor_id":"graham"}', 'e9e0000f6b67bb1088957366824ca99de08fa59162c2dd6ae01809a1c68d025c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('graham-c2', 'graham', '1929–1932年大崩盘濒临破产', '崩盘前持仓乐观且有杠杆，1929–32年股灾中基金连年重挫、个人财富几近赔光，面临是否离场转行', '选择活下来、不放弃证券分析，把惨痛教训提炼为''安全边际''，并于1934年与多德合著《证券分析》', '基金1929–32年间大幅回撤（约七成），其后逐步恢复；''安全边际''成为价值投资基石（A/B）', '毁灭性回撤教你最深一课——把容错缓冲置于追求收益之前，先确保任何单次失误都死不了', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"graham-c2","status":"published","title_period":"1929–1932年大崩盘濒临破产","dilemma_constraints":"崩盘前持仓乐观且有杠杆，1929–32年股灾中基金连年重挫、个人财富几近赔光，面临是否离场转行","key_judgment":"选择活下来、不放弃证券分析，把惨痛教训提炼为''安全边际''，并于1934年与多德合著《证券分析》","model_invoked":["安全边际"],"outcome":"基金1929–32年间大幅回撤（约七成），其后逐步恢复；''安全边际''成为价值投资基石（A/B）","transferable_lesson":"毁灭性回撤教你最深一课——把容错缓冲置于追求收益之前，先确保任何单次失误都死不了","source_tier":"secondary","source_note":"崩盘损失为公认史实，具体回撤比例各来源略有出入（约七成）；《证券分析》1934年出版可考（A）","historicity":"confirmed","linked_cards":["graham"],"tags":["投资","风险评估"],"advisor_id":"graham"}', 'f62e751b9eb1578ed9e7649fc4686e5e2d450d10be7913f6b92b491a2f0ceea4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('graham-c3', 'graham', '1926–1928年北方管道公司维权', '他从监管申报里发现北方管道公司握有远超其市值的隐藏流动资产（铁路债券等），但管理层囤积不分配', '发起股东维权、争取董事席位，逼公司把超额资产派发给股东，把隐藏价值显性化', '维权成功，公司向股东分配大量超额资产；成为以基本面挖隐藏价值并促其释放的早期范例（B）', '价值不仅要算出来，有时还要主动促其释放；公开披露文件里常藏着市场忽略的硬资产', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"graham-c3","status":"published","title_period":"1926–1928年北方管道公司维权","dilemma_constraints":"他从监管申报里发现北方管道公司握有远超其市值的隐藏流动资产（铁路债券等），但管理层囤积不分配","key_judgment":"发起股东维权、争取董事席位，逼公司把超额资产派发给股东，把隐藏价值显性化","model_invoked":["内在价值"],"outcome":"维权成功，公司向股东分配大量超额资产；成为以基本面挖隐藏价值并促其释放的早期范例（B）","transferable_lesson":"价值不仅要算出来，有时还要主动促其释放；公开披露文件里常藏着市场忽略的硬资产","source_tier":"secondary","source_note":"见格雷厄姆回忆录《The Memoirs of the Dean of Wall Street》及传记；具体数字待质检者据原文核验","historicity":"confirmed","linked_cards":["graham"],"tags":["投资","风险评估"],"advisor_id":"graham"}', 'a87c2f33e61ecd8852df275c32f4e2beca7283bb97dd4ce67c957a1e41b4fa97');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('graham-c4', 'graham', '1976年晚年简化选股主张', '晚年面对日益高效的市场，他重新审视自己一生倚重的精细个股分析是否仍值得', '公开表示不再主张繁复的个股深度分析，转推简单、可规则化的分散买入低估股标准', '这一晚年转向被价值投资界反复引用，呼应其''多数人应做防御型投资者''的一贯主张（B）', '方法要随环境复盘迭代；当复杂手艺的边际收益下降，简单稳健的规则往往更适合多数人', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"graham-c4","status":"published","title_period":"1976年晚年简化选股主张","dilemma_constraints":"晚年面对日益高效的市场，他重新审视自己一生倚重的精细个股分析是否仍值得","key_judgment":"公开表示不再主张繁复的个股深度分析，转推简单、可规则化的分散买入低估股标准","model_invoked":["防御型投资"],"outcome":"这一晚年转向被价值投资界反复引用，呼应其''多数人应做防御型投资者''的一贯主张（B）","transferable_lesson":"方法要随环境复盘迭代；当复杂手艺的边际收益下降，简单稳健的规则往往更适合多数人","source_tier":"secondary","source_note":"晚年观点见1976年《金融分析师杂志》访谈；具体表述待质检者据原文核验","historicity":"confirmed","linked_cards":["graham"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"graham"}', 'bd2011dbd75a62be8f2dee2607c71f6a944a45d13331a798d3b89155db32b78a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('graham-c5', 'graham', '1920年代杜邦-通用汽车套利', '他发现杜邦的市值几乎只反映其持有的通用汽车股份，市场完全忽略杜邦自身庞大的化工主业价值', '做多被低估的杜邦、同时做空通用汽车对冲，押注两者价差终将回归合理', '价差收敛、套利获利；成为''市场会无视显而易见之事''的经典价值发现案例（B）', '市场常对明摆着的事实定价失灵；把一项资产拆开看清各部分价值，差价就是机会', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"graham-c5","status":"published","title_period":"1920年代杜邦-通用汽车套利","dilemma_constraints":"他发现杜邦的市值几乎只反映其持有的通用汽车股份，市场完全忽略杜邦自身庞大的化工主业价值","key_judgment":"做多被低估的杜邦、同时做空通用汽车对冲，押注两者价差终将回归合理","model_invoked":["内在价值"],"outcome":"价差收敛、套利获利；成为''市场会无视显而易见之事''的经典价值发现案例（B）","transferable_lesson":"市场常对明摆着的事实定价失灵；把一项资产拆开看清各部分价值，差价就是机会","source_tier":"secondary","source_note":"见格雷厄姆回忆录与传记；具体年份与盈利数字待质检者据原文核验","historicity":"confirmed","linked_cards":["graham"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"graham"}', 'bc98d45417a2e1559d5b0e385f7c62f3ba54a84a513783df5756b97009a5e21e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('rockefeller-c1', 'rockefeller', '1872年''克利夫兰大屠杀''', '炼油业产能过剩、价格战惨烈、利润微薄；标准石油虽强但远未主导，同城对手林立', '借铁路回扣的成本优势，在数周内对克利夫兰对手''要么被收购、要么被挤垮''，迅速吞并大部分同城炼油厂', '数周内收编当地约二十余家炼厂中的大多数，奠定标准石油的行业整合霸权（A/B）', '在产能过剩、价格血战的行业，靠成本优势整合对手、把无序竞争收拢成规模，往往比继续混战更值钱', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"rockefeller-c1","status":"published","title_period":"1872年''克利夫兰大屠杀''","dilemma_constraints":"炼油业产能过剩、价格战惨烈、利润微薄；标准石油虽强但远未主导，同城对手林立","key_judgment":"借铁路回扣的成本优势，在数周内对克利夫兰对手''要么被收购、要么被挤垮''，迅速吞并大部分同城炼油厂","model_invoked":["横向整合"],"outcome":"数周内收编当地约二十余家炼厂中的大多数，奠定标准石油的行业整合霸权（A/B）","transferable_lesson":"在产能过剩、价格血战的行业，靠成本优势整合对手、把无序竞争收拢成规模，往往比继续混战更值钱","source_tier":"secondary","source_note":"1872克利夫兰整合、铁路回扣见塔贝尔《标准石油史》与多方传记（B）；''大屠杀''为后世通称","historicity":"confirmed","linked_cards":["rockefeller"],"tags":["竞争博弈","商业模式与护城河"],"advisor_id":"rockefeller"}', '417fef78714fe2a05fbe675de394daa767bb8b6fd03e280da4ac4404f5cc98f9');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('rockefeller-c2', 'rockefeller', '自建油罐车、管道与桶厂', '炼油利润受制于铁路运费与上下游环节，易被铁路与中间商卡脖子', '向上下游延伸自建油罐车队、输油管道、制桶与仓储，掌控全链条、消除受制环节并进一步压低成本', '全链条掌控使标准石油成本远低于对手、议价力极强，巅峰期控制全美约九成炼油（A/B）', '当某个环节总被别人卡住，自己把它做了；掌控全链条不只降本，更是把命运攥在自己手里', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"rockefeller-c2","status":"published","title_period":"自建油罐车、管道与桶厂","dilemma_constraints":"炼油利润受制于铁路运费与上下游环节，易被铁路与中间商卡脖子","key_judgment":"向上下游延伸自建油罐车队、输油管道、制桶与仓储，掌控全链条、消除受制环节并进一步压低成本","model_invoked":["纵向一体化"],"outcome":"全链条掌控使标准石油成本远低于对手、议价力极强，巅峰期控制全美约九成炼油（A/B）","transferable_lesson":"当某个环节总被别人卡住，自己把它做了；掌控全链条不只降本，更是把命运攥在自己手里","source_tier":"secondary","source_note":"纵向一体化、约九成炼油份额见多方史料与传记（A/B）；具体比例随年份浮动","historicity":"confirmed","linked_cards":["rockefeller"],"tags":["资源调度","商业模式与护城河"],"advisor_id":"rockefeller"}', '30fba3001526791fd8091ec8d9a5083576f77580401b0b1e6ab136fe15e42f4b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('rockefeller-c3', 'rockefeller', '数油桶焊点的成本痴迷', '在微利的炼油业，谁的成本更低谁就能在价格战中活下来', '对成本斤斤计较到极致——据传连封一只油桶的焊点能否从40点减到39点都要算，把成本压到行业最低', '极致的成本控制让标准石油在价格战中始终有最厚的安全垫，能持续低价收编对手（A/B）', '在同质化、打价格战的行业，把每一分成本抠到行业最低，本身就是最难被复制的竞争力', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"rockefeller-c3","status":"published","title_period":"数油桶焊点的成本痴迷","dilemma_constraints":"在微利的炼油业，谁的成本更低谁就能在价格战中活下来","key_judgment":"对成本斤斤计较到极致——据传连封一只油桶的焊点能否从40点减到39点都要算，把成本压到行业最低","model_invoked":["极致成本效率"],"outcome":"极致的成本控制让标准石油在价格战中始终有最厚的安全垫，能持续低价收编对手（A/B）","transferable_lesson":"在同质化、打价格战的行业，把每一分成本抠到行业最低，本身就是最难被复制的竞争力","source_tier":"secondary","source_note":"焊点轶事广为流传但多为后世叙述、细节难精确考证，按轶事判例标存疑；成本痴迷本身确证（B）","historicity":"disputed","linked_cards":["rockefeller"],"tags":["资源调度","商业模式与护城河"],"advisor_id":"rockefeller"}', 'de51a8182f8a9be1b4691ebee8562c8c48271b872188161b8d7ef04730ba342e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('rockefeller-c4', 'rockefeller', '趁油价低谷与萧条低价收编', '石油价格剧烈波动、周期性萧条让大量小炼厂陷入困境', '平时保持充裕现金、不动声色，专挑对手在油价低谷/萧条中最虚弱时，以低价把它们收编进来', '逆周期收编让标准石油以低成本不断扩张，把行业波动变成自己整合的机会（A/B）', '现金+耐心是逆周期收购的弹药；别人最绝望时，正是有准备者以最低价完成整合的时刻', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"rockefeller-c4","status":"published","title_period":"趁油价低谷与萧条低价收编","dilemma_constraints":"石油价格剧烈波动、周期性萧条让大量小炼厂陷入困境","key_judgment":"平时保持充裕现金、不动声色，专挑对手在油价低谷/萧条中最虚弱时，以低价把它们收编进来","model_invoked":["现金与隐忍"],"outcome":"逆周期收编让标准石油以低成本不断扩张，把行业波动变成自己整合的机会（A/B）","transferable_lesson":"现金+耐心是逆周期收购的弹药；别人最绝望时，正是有准备者以最低价完成整合的时刻","source_tier":"secondary","source_note":"逆周期收编、保持现金与隐忍性格见多方传记（B）","historicity":"confirmed","linked_cards":["rockefeller"],"tags":["竞争博弈","危机应对"],"advisor_id":"rockefeller"}', '64f58334bd9682c65e07db36e14e5261db7b791044e512e583f8e0a3ce53fbd8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('rockefeller-c5', 'rockefeller', '晚年开创科学化系统慈善', '积累巨富并背负垄断恶名，零散施舍难有根本性影响', '晚年把财富以''机构化、科学化''方式系统捐赠——创办大学、资助医学研究与公共卫生、设立基金会，求根本改变', '其慈善深刻推动了美国高等教育与现代医学；但1911年标准石油仍被反垄断拆分(反例语境)（A/B）', '做善事也要讲方法论：与其零散撒钱，不如机构化、瞄准根本问题，让每分投入产生结构性的长期回报', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"rockefeller-c5","status":"published","title_period":"晚年开创科学化系统慈善","dilemma_constraints":"积累巨富并背负垄断恶名，零散施舍难有根本性影响","key_judgment":"晚年把财富以''机构化、科学化''方式系统捐赠——创办大学、资助医学研究与公共卫生、设立基金会，求根本改变","model_invoked":["系统性慈善"],"outcome":"其慈善深刻推动了美国高等教育与现代医学；但1911年标准石油仍被反垄断拆分(反例语境)（A/B）","transferable_lesson":"做善事也要讲方法论：与其零散撒钱，不如机构化、瞄准根本问题，让每分投入产生结构性的长期回报","source_tier":"secondary","source_note":"系统化慈善(大学/医学/基金会)、1911反垄断拆分见多方史料（A/B）","historicity":"confirmed","linked_cards":["rockefeller"],"tags":["价值与伦理","长期规划"],"advisor_id":"rockefeller"}', '9327655ce9de934e9826c6ac30604f8a76c2a8b044b90976b343d71b358e2861');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wangyongqing-c1', 'wangyongqing', '从卖米起家·瘦鹅理论（青年）', '王永庆早年家贫、从一家小米店做起，资源与环境都极为艰难。', '他在逆境中不急不弃、像瘦鹅一样忍耐、把基础（精细的卖米服务、信誉、积蓄）养好，等机会来临再扩张。', '从小米店一步步积蓄，最终建立起庞大的台塑企业王国。', '身处逆境时像瘦鹅一样忍耐、积蓄实力、等环境好转再一举壮大——别在逆境中急于求成或自暴自弃。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wangyongqing-c1","status":"published","title_period":"从卖米起家·瘦鹅理论（青年）","dilemma_constraints":"王永庆早年家贫、从一家小米店做起，资源与环境都极为艰难。","key_judgment":"他在逆境中不急不弃、像瘦鹅一样忍耐、把基础（精细的卖米服务、信誉、积蓄）养好，等机会来临再扩张。","model_invoked":["瘦鹅理论"],"outcome":"从小米店一步步积蓄，最终建立起庞大的台塑企业王国。","transferable_lesson":"身处逆境时像瘦鹅一样忍耐、积蓄实力、等环境好转再一举壮大——别在逆境中急于求成或自暴自弃。","source_tier":"secondary","source_note":"王永庆卖米起家与瘦鹅理论为其传记/理念所载→确证（个别细节有流传版本）。","historicity":"confirmed","linked_cards":["wangyongqing"],"tags":["创业","长期规划"],"advisor_id":"wangyongqing"}', '03d95ae535033c3ce0bdf5eece71598cfdbbeb794bac819e724a5f1aa877aedc');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wangyongqing-c2', 'wangyongqing', '「追根究底、止于至善」·精细管理（台塑时期）', '大企业管理中，许多问题容易被表面处理、积弊难除。', '王永庆凡事追根究底、一层层刨到最根部的原因，把每个环节点点滴滴地求合理化，并把成本抠到极致。', '这套追根究底+成本极致的精细管理，使台塑获得了强大的成本竞争力。', '凡事追根究底、刨到问题最根部、点点滴滴求合理化——不满足于表面的解决。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wangyongqing-c2","status":"published","title_period":"「追根究底、止于至善」·精细管理（台塑时期）","dilemma_constraints":"大企业管理中，许多问题容易被表面处理、积弊难除。","key_judgment":"王永庆凡事追根究底、一层层刨到最根部的原因，把每个环节点点滴滴地求合理化，并把成本抠到极致。","model_invoked":["追根究底"],"outcome":"这套追根究底+成本极致的精细管理，使台塑获得了强大的成本竞争力。","transferable_lesson":"凡事追根究底、刨到问题最根部、点点滴滴求合理化——不满足于表面的解决。","source_tier":"secondary","source_note":"「追根究底、止于至善」为王永庆管理理念→确证。","historicity":"confirmed","linked_cards":["wangyongqing"],"tags":["组织管理","创业"],"advisor_id":"wangyongqing"}', '3c492aed66c3ebbe18fdd140641ead05a551ba8c794172450221f73eb3ef5c81');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wangyongqing-c3', 'wangyongqing', '「午餐汇报」·压力管理（台塑时期）', '如何让主管们不断逼出潜力、把管理做到极致。', '王永庆以著名的"午餐汇报"——边吃边层层追问主管的数据与改善，施加高强度压力、追问到底。', '高压追问逼出了主管的潜力与极致的管理细节，但也以压力大著称。', '给目标和团队设高标准、持续加压、追问到底，用压力逼出潜力——但须把握度，过度施压也会反噬。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wangyongqing-c3","status":"published","title_period":"「午餐汇报」·压力管理（台塑时期）","dilemma_constraints":"如何让主管们不断逼出潜力、把管理做到极致。","key_judgment":"王永庆以著名的\"午餐汇报\"——边吃边层层追问主管的数据与改善，施加高强度压力、追问到底。","model_invoked":["压力管理"],"outcome":"高压追问逼出了主管的潜力与极致的管理细节，但也以压力大著称。","transferable_lesson":"给目标和团队设高标准、持续加压、追问到底，用压力逼出潜力——但须把握度，过度施压也会反噬。","source_tier":"secondary","source_note":"王永庆\"午餐汇报\"为其管理实践所载→确证。","historicity":"confirmed","linked_cards":["wangyongqing"],"tags":["组织管理","领导力"],"advisor_id":"wangyongqing"}', '4c8c41858969910c2b478b6020dacfb7debd23ef0a9ed945603ba4249785d3bc');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wangyongqing-c4', 'wangyongqing', '台塑石化全产业链·垂直整合（台塑扩张）', '塑胶加工受制于上游石化原料的供应与价格。', '王永庆把台塑从塑胶加工一路向上游整合、建起从石化原料到塑胶产品的全产业链，掌控全链条。', '台塑成横跨石化全产业链的庞大集团，掌握了全链条的成本与质量。', '从上游到下游一条龙整合、掌控全产业链——不受制于上下游，把全链条的成本与质量握在手里。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wangyongqing-c4","status":"published","title_period":"台塑石化全产业链·垂直整合（台塑扩张）","dilemma_constraints":"塑胶加工受制于上游石化原料的供应与价格。","key_judgment":"王永庆把台塑从塑胶加工一路向上游整合、建起从石化原料到塑胶产品的全产业链，掌控全链条。","model_invoked":["垂直整合"],"outcome":"台塑成横跨石化全产业链的庞大集团，掌握了全链条的成本与质量。","transferable_lesson":"从上游到下游一条龙整合、掌控全产业链——不受制于上下游，把全链条的成本与质量握在手里。","source_tier":"secondary","source_note":"台塑石化全产业链垂直整合为企业史所载→确证。","historicity":"confirmed","linked_cards":["wangyongqing"],"tags":["组织管理","长期规划"],"advisor_id":"wangyongqing"}', 'b16b93a5f5cec19cedee1041ff141cba60ffdb8d0b560a7f983a8fbc5b404c57');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('morita-c1', 'morita', '坚持做Walkman·创造市场（1979）', '内部与市场调研普遍质疑——一个不能录音、只能放音的小机器会有人买吗？', '盛田坚信用户还不知道自己渴望"随时随地听音乐"，不顾调研的反对，坚持把随身听Walkman做出来推向市场。', 'Walkman开创了个人随身音乐这一全新品类、风靡全球、成Sony标志性产品。', '消费者说不出还不存在的东西——有时要用出色的产品去创造他们还不知道自己想要的需求（但这风险极高、并非所有"没人要"都是明珠）。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"morita-c1","status":"published","title_period":"坚持做Walkman·创造市场（1979）","dilemma_constraints":"内部与市场调研普遍质疑——一个不能录音、只能放音的小机器会有人买吗？","key_judgment":"盛田坚信用户还不知道自己渴望\"随时随地听音乐\"，不顾调研的反对，坚持把随身听Walkman做出来推向市场。","model_invoked":["创造市场而非跟随调研"],"outcome":"Walkman开创了个人随身音乐这一全新品类、风靡全球、成Sony标志性产品。","transferable_lesson":"消费者说不出还不存在的东西——有时要用出色的产品去创造他们还不知道自己想要的需求（但这风险极高、并非所有\"没人要\"都是明珠）。","source_tier":"primary","source_note":"盛田力主Walkman、不顾调研反对为其自传《Made in Japan》所载→确证（一手A）。","historicity":"confirmed","linked_cards":["morita"],"tags":["创新研发","创业"],"advisor_id":"morita"}', 'b5dea70218d601af76d86165f3c18e34aa5a878a820899d6aa0cdb85c8b65c74');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('morita-c2', 'morita', '拒绝美国贴牌大单·品牌优先（早期）', 'Sony早年弱小、一家美国公司开出大额订单、但要求贴他们的品牌。', '盛田拒绝了这笔诱人的快钱，坚持要用Sony自己的品牌，哪怕初期更难、更慢。', 'Sony坚守自有品牌、最终成全球知名品牌——自有品牌成其长期价值之根。', '拒绝贴牌代工的快钱、坚持打自己的品牌——哪怕初期更难，自有品牌才是长期价值的根。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"morita-c2","status":"published","title_period":"拒绝美国贴牌大单·品牌优先（早期）","dilemma_constraints":"Sony早年弱小、一家美国公司开出大额订单、但要求贴他们的品牌。","key_judgment":"盛田拒绝了这笔诱人的快钱，坚持要用Sony自己的品牌，哪怕初期更难、更慢。","model_invoked":["品牌优先拒代工"],"outcome":"Sony坚守自有品牌、最终成全球知名品牌——自有品牌成其长期价值之根。","transferable_lesson":"拒绝贴牌代工的快钱、坚持打自己的品牌——哪怕初期更难，自有品牌才是长期价值的根。","source_tier":"primary","source_note":"盛田拒美国贴牌大单为其自传《Made in Japan》所载→确证（一手A）。","historicity":"confirmed","linked_cards":["morita"],"tags":["创业","长期规划"],"advisor_id":"morita"}', '290568752e1db09c7e6c9b6254410931832f66356a0c76e835c1bd82fd1a9670');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('morita-c3', 'morita', '提出"全球本土化"·全球经营深度本地化（Sony全球化）', '日本企业全球化时，常面临"全球统一"与"贴合当地"的两难。', '盛田提出"global localization（全球本土化）"——全球经营，但在各国深度本地化、用当地人才、贴合当地需求。', 'Sony以全球本土化的方式成功扎根欧美等市场，成全球化经营的典范。', '全球经营但深度本地化——既不是纯本国、也不是全球一刀切。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"morita-c3","status":"published","title_period":"提出\"全球本土化\"·全球经营深度本地化（Sony全球化）","dilemma_constraints":"日本企业全球化时，常面临\"全球统一\"与\"贴合当地\"的两难。","key_judgment":"盛田提出\"global localization（全球本土化）\"——全球经营，但在各国深度本地化、用当地人才、贴合当地需求。","model_invoked":["全球本土化"],"outcome":"Sony以全球本土化的方式成功扎根欧美等市场，成全球化经营的典范。","transferable_lesson":"全球经营但深度本地化——既不是纯本国、也不是全球一刀切。","source_tier":"primary","source_note":"盛田提出\"global localization\"为其理念与Sony实践→确证（一手A）。","historicity":"confirmed","linked_cards":["morita"],"tags":["领导力","长期规划"],"advisor_id":"morita"}', '5753d6709e5940d4867dc1d7293a7c87cb153e26e7eb039e76aee18ce11b6925');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('morita-c4', 'morita', '率先推晶体管收音机等新品类·敢为天下先（1950s起）', '新品类无人验证、先行风险大、跟随更稳。', '盛田与井深大率先把晶体管用于消费电子、做出便携晶体管收音机，并持续抢做特丽珑、Walkman等新品类。', 'Sony以一系列开创性产品确立了创新先锋的地位（同时也担了先行风险、有成有败）。', '率先做别人不敢做的新品类、承担先行风险——先行者吃到开创红利，但也常成"先烈"。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"morita-c4","status":"published","title_period":"率先推晶体管收音机等新品类·敢为天下先（1950s起）","dilemma_constraints":"新品类无人验证、先行风险大、跟随更稳。","key_judgment":"盛田与井深大率先把晶体管用于消费电子、做出便携晶体管收音机，并持续抢做特丽珑、Walkman等新品类。","model_invoked":["敢为天下先"],"outcome":"Sony以一系列开创性产品确立了创新先锋的地位（同时也担了先行风险、有成有败）。","transferable_lesson":"率先做别人不敢做的新品类、承担先行风险——先行者吃到开创红利，但也常成\"先烈\"。","source_tier":"primary","source_note":"Sony率先推晶体管收音机、特丽珑、Walkman为史实→确证。","historicity":"confirmed","linked_cards":["morita"],"tags":["创新研发","创业"],"advisor_id":"morita"}', '7d72b25a50d4a1558d6b8762e3b36cb6aa9787ed3739fc91ce77cd24169a65f4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('ford-c1', 'ford', '1908年推出Model T''为大众造车''', '当时汽车是富人奢侈品、价格高昂，行业普遍只面向最有钱的少数人', '他立志''为大众造一辆车''，用单一车型Model T主打可靠、简单、可负担，瞄准普通人而非富人', 'Model T售价从约850美元一路降到300美元以下，到1918年全美半数汽车是Model T（A/B）', '把一件只有富人买得起的东西，重新设计成普通人也能拥有的，往往打开的是一个远比高端更大的市场', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"ford-c1","status":"published","title_period":"1908年推出Model T''为大众造车''","dilemma_constraints":"当时汽车是富人奢侈品、价格高昂，行业普遍只面向最有钱的少数人","key_judgment":"他立志''为大众造一辆车''，用单一车型Model T主打可靠、简单、可负担，瞄准普通人而非富人","model_invoked":["大众化使命"],"outcome":"Model T售价从约850美元一路降到300美元以下，到1918年全美半数汽车是Model T（A/B）","transferable_lesson":"把一件只有富人买得起的东西，重新设计成普通人也能拥有的，往往打开的是一个远比高端更大的市场","source_tier":"secondary","source_note":"1908 Model T、''为大众造车''、降价至300美元以下、1918半数车为T型见多方史料（A/B）","historicity":"confirmed","linked_cards":["ford"],"tags":["创业","商业模式与护城河"],"advisor_id":"ford"}', 'bee82cb3b71b9f606cc1bd4caa2812fffa284b1964c71b63137cb39aa159a60f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('ford-c2', 'ford', '1913年启用移动装配流水线', 'Model T需求暴涨但产能跟不上、装配耗时长、用工流动率极高(曾达380%)', '借鉴屠宰场''拆解线''，让底盘在传送带上连续移动、工人各守一道标准化工序，把装配拆成数十步', '底盘装配时间从约12.5小时降到93分钟，成本骤降、Model T加速普及，重塑全球制造业（A/B）', '别让人围着活转，让活流向人；把复杂工作拆成标准化的连续工序，效率会有数量级的跃升', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"ford-c2","status":"published","title_period":"1913年启用移动装配流水线","dilemma_constraints":"Model T需求暴涨但产能跟不上、装配耗时长、用工流动率极高(曾达380%)","key_judgment":"借鉴屠宰场''拆解线''，让底盘在传送带上连续移动、工人各守一道标准化工序，把装配拆成数十步","model_invoked":["移动流水线"],"outcome":"底盘装配时间从约12.5小时降到93分钟，成本骤降、Model T加速普及，重塑全球制造业（A/B）","transferable_lesson":"别让人围着活转，让活流向人；把复杂工作拆成标准化的连续工序，效率会有数量级的跃升","source_tier":"secondary","source_note":"1913流水线、底盘12.5小时→93分钟、借鉴屠宰场见多方史料（A/B）","historicity":"confirmed","linked_cards":["ford"],"tags":["创新研发","资源调度"],"advisor_id":"ford"}', '1236f1b1c76e5417d3b55cd9d575547571bb5fcbc5642ec1cb30c2841efbc7d8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('ford-c3', 'ford', '1914年宣布5美元日薪', '流水线枯燥、流动率畸高(为维持约1.4万人一年要招约5.2万人)，招工与培训成本惊人', '1914年1月把日薪从约2.34美元/9小时翻倍到5美元/8小时(以''利润分享''名义)，逆向用高工资稳住队伍', '流动率与招工成本骤降、工人买得起自家车、并推动全行业涨薪，被视为助美国工人进入中产（A/B）', '工资不只是成本——付得高于行业，能换回稳定的队伍、买得起你产品的顾客，甚至整个市场的扩大', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"ford-c3","status":"published","title_period":"1914年宣布5美元日薪","dilemma_constraints":"流水线枯燥、流动率畸高(为维持约1.4万人一年要招约5.2万人)，招工与培训成本惊人","key_judgment":"1914年1月把日薪从约2.34美元/9小时翻倍到5美元/8小时(以''利润分享''名义)，逆向用高工资稳住队伍","model_invoked":["高工资逻辑"],"outcome":"流动率与招工成本骤降、工人买得起自家车、并推动全行业涨薪，被视为助美国工人进入中产（A/B）","transferable_lesson":"工资不只是成本——付得高于行业，能换回稳定的队伍、买得起你产品的顾客，甚至整个市场的扩大","source_tier":"secondary","source_note":"1914.1.5 五美元日薪、2.34→5美元、流动率380%/招5.2万维持1.4万见多方史料（A/B）","historicity":"confirmed","linked_cards":["ford"],"tags":["组织管理","商业模式与护城河"],"advisor_id":"ford"}', 'b47e0ff23e331a91a5177a278428a2b92c5771d9423a5ade979ce77ee01423c2');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('ford-c4', 'ford', '固守Model T被通用超越', 'Model T大获成功后，消费者开始要更多颜色、款式与升级，通用汽车以多车型/年度改款进攻', '他过度迷信单一车型与标准化(''随你什么颜色，只要是黑的'')，长期拒绝大改Model T', '市场份额被通用反超，福特被迫于1927年停产Model T、慌忙换代，付出沉重代价(反例)（A/B）', '反例：曾经制胜的极致标准化，若变成对变化的拒绝，就会从护城河变成陷阱；没有产品能永远不更新', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"ford-c4","status":"published","title_period":"固守Model T被通用超越","dilemma_constraints":"Model T大获成功后，消费者开始要更多颜色、款式与升级，通用汽车以多车型/年度改款进攻","key_judgment":"他过度迷信单一车型与标准化(''随你什么颜色，只要是黑的'')，长期拒绝大改Model T","model_invoked":["标准化简化"],"outcome":"市场份额被通用反超，福特被迫于1927年停产Model T、慌忙换代，付出沉重代价(反例)（A/B）","transferable_lesson":"反例：曾经制胜的极致标准化，若变成对变化的拒绝，就会从护城河变成陷阱；没有产品能永远不更新","source_tier":"secondary","source_note":"固守Model T、被通用超越、1927停产见多方史料（B）；''只要是黑的''为其名言（A）；为反例案例","historicity":"confirmed","linked_cards":["ford"],"tags":["创新研发","竞争博弈"],"advisor_id":"ford"}', '707e7ae096d2edc9c784bc2722283afbc7c0983510d25f50abdf1f9e956677d2');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('ford-c5', 'ford', '建River Rouge全链条工厂', '整车依赖外部钢铁、橡胶、玻璃等供应，受制于人且成本不稳', '建造River Rouge超级工厂、并向上游延伸矿山/橡胶园/钢铁，追求从原料到整车的全链条自有', 'River Rouge成为当时世界最大、最一体化的工业综合体，掌控供应与成本(但也僵化)（A/B）', '把关键供应攥在自己手里能稳成本、稳供应；但一体化做到极致也会变重、变僵，要警惕灵活性的丧失', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"ford-c5","status":"published","title_period":"建River Rouge全链条工厂","dilemma_constraints":"整车依赖外部钢铁、橡胶、玻璃等供应，受制于人且成本不稳","key_judgment":"建造River Rouge超级工厂、并向上游延伸矿山/橡胶园/钢铁，追求从原料到整车的全链条自有","model_invoked":["纵向一体化"],"outcome":"River Rouge成为当时世界最大、最一体化的工业综合体，掌控供应与成本(但也僵化)（A/B）","transferable_lesson":"把关键供应攥在自己手里能稳成本、稳供应；但一体化做到极致也会变重、变僵，要警惕灵活性的丧失","source_tier":"secondary","source_note":"River Rouge、向上游一体化见多方史料（B）","historicity":"confirmed","linked_cards":["ford"],"tags":["资源调度","商业模式与护城河"],"advisor_id":"ford"}', '4e5816c9a3b642a8a1d3567a5062a1aa48c4bf3a37b250c6152431dfecc1c285');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('inamori-c1', 'inamori', '1959年27岁创立京瓷', '一个被原公司排挤的年轻陶瓷技术员，靠少数支持者凑钱创业，既无资金也无管理经验', '以''追求全体员工物质与精神幸福''为经营目的、''作为人何谓正确''为判断基准，把做人原则当经营原则', '京瓷成长为全球500强、长期高盈利；''利他/做人正确''的经营哲学经此奠基（A/B）', '把''作为人何谓正确''这种朴素做人原则直接当作经营与决策的最高基准，反而能穿越复杂局面', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"inamori-c1","status":"published","title_period":"1959年27岁创立京瓷","dilemma_constraints":"一个被原公司排挤的年轻陶瓷技术员，靠少数支持者凑钱创业，既无资金也无管理经验","key_judgment":"以''追求全体员工物质与精神幸福''为经营目的、''作为人何谓正确''为判断基准，把做人原则当经营原则","model_invoked":["利他经营"],"outcome":"京瓷成长为全球500强、长期高盈利；''利他/做人正确''的经营哲学经此奠基（A/B）","transferable_lesson":"把''作为人何谓正确''这种朴素做人原则直接当作经营与决策的最高基准，反而能穿越复杂局面","source_tier":"secondary","source_note":"京瓷1959创立、经营目的见稻盛著述（A）与传记（B）","historicity":"confirmed","linked_cards":["inamori"],"tags":["创业","领导力"],"advisor_id":"inamori"}', '9f29dacb900ec4bafa65342e43abe796188a23243ff5beeafbcf381ad51734f3');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('inamori-c2', 'inamori', '1984年创办第二电电挑战NTT垄断', '要进入由国企NTT垄断、技术与资本门槛极高的通信业，几乎无人看好；他反复拷问自己的动机', '连续数月每晚自问''动机至善、私心了无吗''，确认是为降低国民通信费而非私利后才决定入局', 'DDI（后并入KDDI）成为日本第二大通信商；''动机至善''的自我拷问成为其重大决策范式（A/B）', '做重大且诱人的决定前，先连续追问自己的动机是否纯粹；私心一旦混入，判断就会变形', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"inamori-c2","status":"published","title_period":"1984年创办第二电电挑战NTT垄断","dilemma_constraints":"要进入由国企NTT垄断、技术与资本门槛极高的通信业，几乎无人看好；他反复拷问自己的动机","key_judgment":"连续数月每晚自问''动机至善、私心了无吗''，确认是为降低国民通信费而非私利后才决定入局","model_invoked":["敬天爱人"],"outcome":"DDI（后并入KDDI）成为日本第二大通信商；''动机至善''的自我拷问成为其重大决策范式（A/B）","transferable_lesson":"做重大且诱人的决定前，先连续追问自己的动机是否纯粹；私心一旦混入，判断就会变形","source_tier":"secondary","source_note":"DDI 1984创立、''动机至善私心了无''的反复自问见稻盛著述（A）与传记（B）","historicity":"confirmed","linked_cards":["inamori"],"tags":["创业","价值与伦理"],"advisor_id":"inamori"}', 'e26b1591ee48deedd3e61a1cea1c217b64c03daaab719ea2b83db2de1837b36e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('inamori-c3', 'inamori', '2010年78岁零薪重建破产日航', '78岁、航空业门外汉，受政府之邀重建刚破产、积重难返的日航，舆论普遍判定必二次破产', '零薪出任董事长，用京瓷哲学改造价值观、推行阿米巴独立核算、并忍痛裁员约三分之一', '次年即扭亏为盈、成为全球利润率最高航司，约2年7个月后(2012.9)重新上市（A/B）', '扭转庞大僵化组织，靠的是先改人心与价值观、再用''人人核算损益''的机制让每个人成为经营者', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"inamori-c3","status":"published","title_period":"2010年78岁零薪重建破产日航","dilemma_constraints":"78岁、航空业门外汉，受政府之邀重建刚破产、积重难返的日航，舆论普遍判定必二次破产","key_judgment":"零薪出任董事长，用京瓷哲学改造价值观、推行阿米巴独立核算、并忍痛裁员约三分之一","model_invoked":["阿米巴经营"],"outcome":"次年即扭亏为盈、成为全球利润率最高航司，约2年7个月后(2012.9)重新上市（A/B）","transferable_lesson":"扭转庞大僵化组织，靠的是先改人心与价值观、再用''人人核算损益''的机制让每个人成为经营者","source_tier":"secondary","source_note":"2010破产、78岁零薪、阿米巴、裁员1/3、次年扭亏、2012.9重新上市见多方报道与稻盛著述（A/B）","historicity":"confirmed","linked_cards":["inamori"],"tags":["组织管理","危机应对"],"advisor_id":"inamori"}', 'deb0e81aade95a77d6d25b0dfa2c5de858482580a8d3ed34330ebe12a58048bd');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('inamori-c4', 'inamori', '提出''人生·工作方程式''', '如何解释为何有能力、有热情的人也会失败，又如何指导人做出根本性的人生选择', '提出结果=思维方式×热情×能力，并强调思维方式可为负值——方向(心性)错了，越有能力热情越是灾难', '该方程式成为其哲学的核心公式、被广泛传播，用于个人与组织的根本性自我校准（A/B）', '评估一个人或一项事业，先看方向(思维方式)正负，再谈能力与热情；负方向上的才华是放大的破坏力', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"inamori-c4","status":"published","title_period":"提出''人生·工作方程式''","dilemma_constraints":"如何解释为何有能力、有热情的人也会失败，又如何指导人做出根本性的人生选择","key_judgment":"提出结果=思维方式×热情×能力，并强调思维方式可为负值——方向(心性)错了，越有能力热情越是灾难","model_invoked":["人生方程式"],"outcome":"该方程式成为其哲学的核心公式、被广泛传播，用于个人与组织的根本性自我校准（A/B）","transferable_lesson":"评估一个人或一项事业，先看方向(思维方式)正负，再谈能力与热情；负方向上的才华是放大的破坏力","source_tier":"primary","source_note":"人生方程式见稻盛《活法》等著述（A）","historicity":"confirmed","linked_cards":["inamori"],"tags":["修身自省","学习与认知"],"advisor_id":"inamori"}', 'bbe4dd5211863a0eeb47dab28966d17e514f41122525ae4c715f88de33134788');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('inamori-c5', 'inamori', '用''极致努力''啃下技术难关', '京瓷早期接到远超自身技术水平的精密陶瓷订单，几乎不可能按期达到客户苛刻规格', '以''付出不亚于任何人的努力''与''燃烧的斗魂''，吃住在车间反复试制、把每个细节做到极致直到达标', '京瓷靠这种极致投入与高品质赢得客户信任、打开局面；''极致努力''成为其立身之本（A/B）', '在能力暂时不足时，''付出不亚于任何人的努力''和把细节做到极致，往往能把不可能拖成可能', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"inamori-c5","status":"published","title_period":"用''极致努力''啃下技术难关","dilemma_constraints":"京瓷早期接到远超自身技术水平的精密陶瓷订单，几乎不可能按期达到客户苛刻规格","key_judgment":"以''付出不亚于任何人的努力''与''燃烧的斗魂''，吃住在车间反复试制、把每个细节做到极致直到达标","model_invoked":["极致努力"],"outcome":"京瓷靠这种极致投入与高品质赢得客户信任、打开局面；''极致努力''成为其立身之本（A/B）","transferable_lesson":"在能力暂时不足时，''付出不亚于任何人的努力''和把细节做到极致，往往能把不可能拖成可能","source_tier":"secondary","source_note":"极致努力/燃烧斗魂理念见稻盛著述（A）；早期技术攻坚见传记（B）；具体订单细节待核验","historicity":"confirmed","linked_cards":["inamori"],"tags":["组织管理","创新研发"],"advisor_id":"inamori"}', '1b001c2d999eb78a78b22d818780fc6e8a251c58e6cf83a4bbad470f18123a17');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bezos-c1', 'bezos', '1994年用''后悔最小化''创立亚马逊', '他在华尔街D.E.Shaw有高薪稳定前途；要不要辞职去做''网上卖书''的高风险创业，年中辞职还要放弃可观奖金', '用后悔最小化框架：想象80岁回望，错过参与互联网浪潮会比创业失败更让他后悔，于是辞职创业', '创立亚马逊，最终成为全球最大电商与云计算公司之一；后悔最小化成为其标志决策法（A/B）', '面对重大不可逆抉择，把时间拉到生命终点回望，往往能盖过短期的恐惧与机会成本算计', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bezos-c1","status":"published","title_period":"1994年用''后悔最小化''创立亚马逊","dilemma_constraints":"他在华尔街D.E.Shaw有高薪稳定前途；要不要辞职去做''网上卖书''的高风险创业，年中辞职还要放弃可观奖金","key_judgment":"用后悔最小化框架：想象80岁回望，错过参与互联网浪潮会比创业失败更让他后悔，于是辞职创业","model_invoked":["后悔最小化"],"outcome":"创立亚马逊，最终成为全球最大电商与云计算公司之一；后悔最小化成为其标志决策法（A/B）","transferable_lesson":"面对重大不可逆抉择，把时间拉到生命终点回望，往往能盖过短期的恐惧与机会成本算计","source_tier":"primary","source_note":"后悔最小化框架与创立经过见贝索斯多次公开访谈/演讲及报道（A/B）","historicity":"confirmed","linked_cards":["bezos"],"tags":["创业","人生抉择"],"advisor_id":"bezos"}', '670b944013a7bbc4b2f894a7d5b28ebf9ea123e95542f4010f366759827c2451');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bezos-c2', 'bezos', '2006年把内部基础设施变成AWS', '云计算尚无市场、华尔街不解为何零售公司要做IT基础设施，短期拖累利润', '判断弹性计算/存储是普惠刚需，把亚马逊自用的基础设施对外开放成业务，长期下注、忍受当期不被理解', 'AWS成为云计算开创者与亚马逊最赚钱的业务、利润支柱；验证''长期+客户刚需''的下注逻辑（A/B）', '最大的机会常藏在你自己被迫解决的痛点里；若它是普遍刚需，就把内部能力产品化、长期投入', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bezos-c2","status":"published","title_period":"2006年把内部基础设施变成AWS","dilemma_constraints":"云计算尚无市场、华尔街不解为何零售公司要做IT基础设施，短期拖累利润","key_judgment":"判断弹性计算/存储是普惠刚需，把亚马逊自用的基础设施对外开放成业务，长期下注、忍受当期不被理解","model_invoked":["长期主义"],"outcome":"AWS成为云计算开创者与亚马逊最赚钱的业务、利润支柱；验证''长期+客户刚需''的下注逻辑（A/B）","transferable_lesson":"最大的机会常藏在你自己被迫解决的痛点里；若它是普遍刚需，就把内部能力产品化、长期投入","source_tier":"primary","source_note":"AWS 2006推出、源自内部基础设施见亚马逊致股东信及公开记述（A/B）","historicity":"confirmed","linked_cards":["bezos"],"tags":["创新研发","商业模式与护城河"],"advisor_id":"bezos"}', '1d2e6103aa1721446f5d0f64512910ac5d0c5d4f41f20cb7ae713dba4aba39c2');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bezos-c3', 'bezos', '2014年Fire Phone失败（保持Day 1的实验）', '亚马逊押注自研高端手机切入移动入口，与苹果/三星正面竞争，自身硬件经验有限、风险高', '把它当作一次大胆实验推向市场；失败后不归咎个人，奉行''失败与发明是连体双胞胎、失败规模要随公司增长''', '2014年减记约1.7亿美元（含约8300万滞销库存）；团队与经验转入Echo/Alexa，最终大获成功（A/B）', '敢做会失败的大实验是创新的代价；关键是失败后不羞辱，把学到的东西迁移到下一次发明', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bezos-c3","status":"published","title_period":"2014年Fire Phone失败（保持Day 1的实验）","dilemma_constraints":"亚马逊押注自研高端手机切入移动入口，与苹果/三星正面竞争，自身硬件经验有限、风险高","key_judgment":"把它当作一次大胆实验推向市场；失败后不归咎个人，奉行''失败与发明是连体双胞胎、失败规模要随公司增长''","model_invoked":["Day 1哲学"],"outcome":"2014年减记约1.7亿美元（含约8300万滞销库存）；团队与经验转入Echo/Alexa，最终大获成功（A/B）","transferable_lesson":"敢做会失败的大实验是创新的代价；关键是失败后不羞辱，把学到的东西迁移到下一次发明","source_tier":"primary","source_note":"约1.7亿减记/约8300万库存见2014公开披露（B）；''失败与发明连体''见2018致股东信（A）；为反例案例","historicity":"confirmed","linked_cards":["bezos"],"tags":["创新研发","危机应对"],"advisor_id":"bezos"}', 'c45be90917b14b546da1afac12c4cb7318213ce01a70a27213861153f198f68e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bezos-c4', 'bezos', '坚持保留负面用户评论', '早期允许用户发负面书评，供应商/出版商抗议''你靠卖书赚钱，为何让人唱衰商品''', '判断亚马逊赚的是''帮客户做更好购买决策''的钱、而非''卖货''的钱，坚持保留真实负面评论', '真实评论体系增强了客户信任与平台黏性、成为电商标配；体现''痴迷客户而非短期卖方利益''（A/B）', '当短期卖方利益与长期客户信任冲突时，站在客户一边；信任本身是最深的护城河', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bezos-c4","status":"published","title_period":"坚持保留负面用户评论","dilemma_constraints":"早期允许用户发负面书评，供应商/出版商抗议''你靠卖书赚钱，为何让人唱衰商品''","key_judgment":"判断亚马逊赚的是''帮客户做更好购买决策''的钱、而非''卖货''的钱，坚持保留真实负面评论","model_invoked":["客户痴迷"],"outcome":"真实评论体系增强了客户信任与平台黏性、成为电商标配；体现''痴迷客户而非短期卖方利益''（A/B）","transferable_lesson":"当短期卖方利益与长期客户信任冲突时，站在客户一边；信任本身是最深的护城河","source_tier":"secondary","source_note":"保留负面评论的决策见《一网打尽》等记述及报道（B）；客户痴迷理念见致股东信（A）","historicity":"confirmed","linked_cards":["bezos"],"tags":["商业模式与护城河","创业"],"advisor_id":"bezos"}', '623d52d2fa82eaae6242e5ccbb2afdc93d9cc4a119cdec1e6a6e0f1ab11511ff');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bezos-c5', 'bezos', '''不同意但执行''放行Amazon Studios项目', '面对一个他个人并不看好的内容项目，团队却有信心；僵持会拖慢可逆的双向门决策', '他明确表态''我不同意，但我承诺全力支持''，把决策权交给更有信念的团队，快速放行', '项目得以快速推进；''不同意但执行''成为其广为引用的高速决策原则（A）', '可逆决策上，与其为说服彼此而僵持，不如''不同意但执行''，用速度换迭代，错了再回头', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bezos-c5","status":"published","title_period":"''不同意但执行''放行Amazon Studios项目","dilemma_constraints":"面对一个他个人并不看好的内容项目，团队却有信心；僵持会拖慢可逆的双向门决策","key_judgment":"他明确表态''我不同意，但我承诺全力支持''，把决策权交给更有信念的团队，快速放行","model_invoked":["单双向门决策"],"outcome":"项目得以快速推进；''不同意但执行''成为其广为引用的高速决策原则（A）","transferable_lesson":"可逆决策上，与其为说服彼此而僵持，不如''不同意但执行''，用速度换迭代，错了再回头","source_tier":"primary","source_note":"''disagree and commit''范例见2016年致股东信（A）","historicity":"confirmed","linked_cards":["bezos"],"tags":["组织管理","治理决策"],"advisor_id":"bezos"}', '2aa9ef4c24db8d8e896ed5cf3c2a50188371d2a11f7285d42ed45cf6c313ef1b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tankahkee-c1', 'tankahkee', '倾资创办厦大与集美·实业为手段公益为目的（1910s—1920s起）', '陈嘉庚以橡胶等实业致富，可选择守财享福，但他另有所图。', '陈嘉庚把实业当作手段，把赚到的钱倾注于创办厦门大学、集美学校等教育事业，把商业成功转化为更长远的目的。', '陈嘉庚创办了厦门大学、集美学村等，泽被后世，成"华侨旗帜、民族光辉"。', '把实业/赚钱当作手段、而非终极目的——把商业成功转化为更长远的目的（教育、社会），反而成就更大的意义。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"tankahkee-c1","status":"published","title_period":"倾资创办厦大与集美·实业为手段公益为目的（1910s—1920s起）","dilemma_constraints":"陈嘉庚以橡胶等实业致富，可选择守财享福，但他另有所图。","key_judgment":"陈嘉庚把实业当作手段，把赚到的钱倾注于创办厦门大学、集美学校等教育事业，把商业成功转化为更长远的目的。","model_invoked":["实业为手段公益为目的"],"outcome":"陈嘉庚创办了厦门大学、集美学村等，泽被后世，成\"华侨旗帜、民族光辉\"。","transferable_lesson":"把实业/赚钱当作手段、而非终极目的——把商业成功转化为更长远的目的（教育、社会），反而成就更大的意义。","source_tier":"primary","source_note":"陈嘉庚创办厦大、集美为史实与其《南侨回忆录》所载→确证（一手A）。","historicity":"confirmed","linked_cards":["tankahkee"],"tags":["创业","价值与伦理"],"advisor_id":"tankahkee"}', 'a4f8c3816677160bfe34a0718ace5b13b0693faeb417f5c5c6b6b040ca0f6bf2');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tankahkee-c2', 'tankahkee', '以诚信立身南洋商界·诚信为本（经商历程）', '商海起伏，守信常意味着自己吃亏。', '陈嘉庚以诚信立身，宁可自己吃亏也不负承诺，把信誉当作最大的资本。', '陈嘉庚以诚信著称于南洋商界，赢得了长期的信任与声誉。', '经商以诚信立身、宁可自己吃亏也不负承诺——信誉是你最大的资本，失信一次就毁了根基。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"tankahkee-c2","status":"published","title_period":"以诚信立身南洋商界·诚信为本（经商历程）","dilemma_constraints":"商海起伏，守信常意味着自己吃亏。","key_judgment":"陈嘉庚以诚信立身，宁可自己吃亏也不负承诺，把信誉当作最大的资本。","model_invoked":["诚信为本"],"outcome":"陈嘉庚以诚信著称于南洋商界，赢得了长期的信任与声誉。","transferable_lesson":"经商以诚信立身、宁可自己吃亏也不负承诺——信誉是你最大的资本，失信一次就毁了根基。","source_tier":"primary","source_note":"陈嘉庚以诚信著称为史实→确证（一手/二手A/B）。","historicity":"confirmed","linked_cards":["tankahkee"],"tags":["价值与伦理","创业"],"advisor_id":"tankahkee"}', 'bbd971c4f6fabd4d48daec9cfc2962e1508e46ad8062abeec619e30842130ab8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tankahkee-c3', 'tankahkee', '从米业转向橡胶业·抓住时代机遇（早期）', '南洋经济格局变迁，米业之外，橡胶业正在兴起。', '陈嘉庚看准南洋橡胶业兴起的时代机遇，果断进入并做大，成为橡胶业巨头。', '陈嘉庚凭橡胶业积累了巨大财富，为其后来的兴学奠定了基础。', '看准时代正在兴起的产业机遇、果断进入并做大——但须知行业有周期与风险，并非每次押注都成。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"tankahkee-c3","status":"published","title_period":"从米业转向橡胶业·抓住时代机遇（早期）","dilemma_constraints":"南洋经济格局变迁，米业之外，橡胶业正在兴起。","key_judgment":"陈嘉庚看准南洋橡胶业兴起的时代机遇，果断进入并做大，成为橡胶业巨头。","model_invoked":["抓住时代机遇"],"outcome":"陈嘉庚凭橡胶业积累了巨大财富，为其后来的兴学奠定了基础。","transferable_lesson":"看准时代正在兴起的产业机遇、果断进入并做大——但须知行业有周期与风险，并非每次押注都成。","source_tier":"primary","source_note":"陈嘉庚抓住橡胶业机遇为史实→确证。","historicity":"confirmed","linked_cards":["tankahkee"],"tags":["创业","长期规划"],"advisor_id":"tankahkee"}', 'aa6cd4d69befc3cddd87746778d5a850f5af915a8767176836c8617e93aa7234');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('tankahkee-c4', 'tankahkee', '抗战时期组织南洋华侨支援·家国担当（抗战时期）', '民族危亡之际，海外华侨可选择置身事外。', '陈嘉庚把自己放进民族这一更大的共同体，组织南洋华侨筹款、出力支援抗战，担当公共大义。', '陈嘉庚成为南洋华侨支援抗战的旗帜性人物。', '把自己放进一个更大的共同体、为更长远的公共利益担当——超越小我，反而成就更大的事业与意义。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"tankahkee-c4","status":"published","title_period":"抗战时期组织南洋华侨支援·家国担当（抗战时期）","dilemma_constraints":"民族危亡之际，海外华侨可选择置身事外。","key_judgment":"陈嘉庚把自己放进民族这一更大的共同体，组织南洋华侨筹款、出力支援抗战，担当公共大义。","model_invoked":["家国担当超越小我"],"outcome":"陈嘉庚成为南洋华侨支援抗战的旗帜性人物。","transferable_lesson":"把自己放进一个更大的共同体、为更长远的公共利益担当——超越小我，反而成就更大的事业与意义。","source_tier":"primary","source_note":"陈嘉庚抗战时组织南洋华侨支援为史实与其《南侨回忆录》所载→确证（一手A）。","historicity":"confirmed","linked_cards":["tankahkee"],"tags":["价值与伦理","长期规划"],"advisor_id":"tankahkee"}', 'c6d5f2f904cf4c34de79e267418462db30c42bd37b5f882f2f866ad855aa90db');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('kroc-c1', 'kroc', '把麦当劳做成可复制的标准系统·标准化可复制（1950s起）', '麦当劳兄弟的一家店很成功，但成功难以在别处复刻、品质难统一。', '克洛克把麦当劳的运营拆解成一套可精确复制的标准流程（出餐时间、清洁、品质、服务都量化到标准QSC），让任何地方都能复刻同样品质。', '标准化体系使麦当劳得以在全球大规模复制、保持品质统一。', '把一家成功的店/业务拆解成一套可精确复制的标准流程——这样任何地方、任何人都能复刻出同样的品质。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"kroc-c1","status":"published","title_period":"把麦当劳做成可复制的标准系统·标准化可复制（1950s起）","dilemma_constraints":"麦当劳兄弟的一家店很成功，但成功难以在别处复刻、品质难统一。","key_judgment":"克洛克把麦当劳的运营拆解成一套可精确复制的标准流程（出餐时间、清洁、品质、服务都量化到标准QSC），让任何地方都能复刻同样品质。","model_invoked":["标准化可复制"],"outcome":"标准化体系使麦当劳得以在全球大规模复制、保持品质统一。","transferable_lesson":"把一家成功的店/业务拆解成一套可精确复制的标准流程——这样任何地方、任何人都能复刻出同样的品质。","source_tier":"primary","source_note":"麦当劳标准化体系为克洛克《Grinding It Out》所述→确证（一手A）。","historicity":"confirmed","linked_cards":["kroc"],"tags":["创业","组织管理"],"advisor_id":"kroc"}', '8454211d7d93ef28e06e94627978efdbaf2c54c43ca5d516e6e7ba5dfd4ce51f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('kroc-c2', 'kroc', '做成特许经营系统·卖系统而非卖产品（麦当劳扩张）', '如何让麦当劳的模式快速、大规模地扩张。', '克洛克意识到麦当劳真正可规模化的不是汉堡、而是一套"可加盟的成功餐厅系统"，把系统本身做成特许经营的产品。', '特许经营系统驱动麦当劳成全球最大的连锁餐饮之一。', '看清你真正卖的是一套可复制、可加盟的"成功系统"、而非只是产品——把系统本身变成可规模化的产品。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"kroc-c2","status":"published","title_period":"做成特许经营系统·卖系统而非卖产品（麦当劳扩张）","dilemma_constraints":"如何让麦当劳的模式快速、大规模地扩张。","key_judgment":"克洛克意识到麦当劳真正可规模化的不是汉堡、而是一套\"可加盟的成功餐厅系统\"，把系统本身做成特许经营的产品。","model_invoked":["卖系统而非卖产品"],"outcome":"特许经营系统驱动麦当劳成全球最大的连锁餐饮之一。","transferable_lesson":"看清你真正卖的是一套可复制、可加盟的\"成功系统\"、而非只是产品——把系统本身变成可规模化的产品。","source_tier":"primary","source_note":"麦当劳特许经营模式为史实与克洛克自传所载→确证。","historicity":"confirmed","linked_cards":["kroc"],"tags":["创业","长期规划"],"advisor_id":"kroc"}', '4ae62b3d5d5247ed6c8176672be4487927d98cd04d58d11838a5ee032695093e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('kroc-c3', 'kroc', '不盘剥加盟商、靠共同成长·加盟双赢共生（麦当劳模式）', '许多特许经营靠卖货给加盟商赚差价、与加盟商利益对立。', '克洛克坚持不靠盘剥加盟商赚差价，而是让加盟商先赚到钱、麦当劳靠与加盟商共同成长（及地产模式）来盈利。', '加盟商与总部的双赢共生成麦当劳体系长期稳健的基础。', '别靠压榨加盟商赚差价——让加盟商先成功、你靠与他们共同成长来盈利；加盟商成功，你才成功。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"kroc-c3","status":"published","title_period":"不盘剥加盟商、靠共同成长·加盟双赢共生（麦当劳模式）","dilemma_constraints":"许多特许经营靠卖货给加盟商赚差价、与加盟商利益对立。","key_judgment":"克洛克坚持不靠盘剥加盟商赚差价，而是让加盟商先赚到钱、麦当劳靠与加盟商共同成长（及地产模式）来盈利。","model_invoked":["加盟双赢共生"],"outcome":"加盟商与总部的双赢共生成麦当劳体系长期稳健的基础。","transferable_lesson":"别靠压榨加盟商赚差价——让加盟商先成功、你靠与他们共同成长来盈利；加盟商成功，你才成功。","source_tier":"primary","source_note":"克洛克的加盟双赢理念与地产模式为其自传/麦当劳史所载→确证。","historicity":"confirmed","linked_cards":["kroc"],"tags":["组织管理","长期规划"],"advisor_id":"kroc"}', 'edbb55fa6c5af5a12c7775eb9aa22063691bd9d45903fadcbe01de1e2adf204d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('kroc-c4', 'kroc', '52岁抓住麦当劳、靠坚持成就帝国·永不言弃（1954起）', '克洛克半生做推销员、52岁仍未成大业，年龄与过往都不被看好。', '克洛克52岁时抓住麦当劳的机会、靠坚持不懈把它一步步做成全球帝国，坚信"世上没有什么能取代坚持"。', '克洛克以晚年的坚持成就了麦当劳，成"大器晚成"与"坚持"的代名词。', '别因起步晚或自觉没天赋就放弃——靠坚持不懈把一件事做到底，坚持的复利大于天赋、教育与天才。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"kroc-c4","status":"published","title_period":"52岁抓住麦当劳、靠坚持成就帝国·永不言弃（1954起）","dilemma_constraints":"克洛克半生做推销员、52岁仍未成大业，年龄与过往都不被看好。","key_judgment":"克洛克52岁时抓住麦当劳的机会、靠坚持不懈把它一步步做成全球帝国，坚信\"世上没有什么能取代坚持\"。","model_invoked":["永不言弃的大器晚成"],"outcome":"克洛克以晚年的坚持成就了麦当劳，成\"大器晚成\"与\"坚持\"的代名词。","transferable_lesson":"别因起步晚或自觉没天赋就放弃——靠坚持不懈把一件事做到底，坚持的复利大于天赋、教育与天才。","source_tier":"primary","source_note":"克洛克52岁创业与\"坚持\"名言为其自传所载→确证。","historicity":"confirmed","linked_cards":["kroc"],"tags":["创业","修身自省"],"advisor_id":"kroc"}', '6281a8747a2484ce472d6bed1ce3a5fdd4c5c42c25f9c76b5729615efd2e721a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('alexander-c1', 'alexander', '高加米拉会战·击破波斯主力（前331）', '大流士三世据平原集结远多于己的波斯大军、择地利布战车骑兵，欲以数量碾压。', '（据古典史家）以斜行阵诱波斯阵线拉开缺口，亲率伙友骑兵直插大流士所在的中军缺口，迫其先逃而全军溃。', '波斯主力崩溃、大流士败逃，波斯帝国实质瓦解，亚历山大入主亚洲。', '与数量占优的对手决战，不平推、而是制造并扑向其指挥中枢的缺口——打垮"头"比消耗"身"更快瓦解全局。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"alexander-c1","status":"published","title_period":"高加米拉会战·击破波斯主力（前331）","dilemma_constraints":"大流士三世据平原集结远多于己的波斯大军、择地利布战车骑兵，欲以数量碾压。","key_judgment":"（据古典史家）以斜行阵诱波斯阵线拉开缺口，亲率伙友骑兵直插大流士所在的中军缺口，迫其先逃而全军溃。","model_invoked":["亲冲锋陷阵"],"outcome":"波斯主力崩溃、大流士败逃，波斯帝国实质瓦解，亚历山大入主亚洲。","transferable_lesson":"与数量占优的对手决战，不平推、而是制造并扑向其指挥中枢的缺口——打垮\"头\"比消耗\"身\"更快瓦解全局。","source_tier":"secondary","source_note":"会战为信史(B)；但亚历山大个人战术细节(斜行阵、直冲中军)出阿里安/普鲁塔克等后世史家(去其数百年)追述、含解读与美化，按\"个人指挥角色非一手记载→historicity存疑\"判例标存疑——与韩信(《史记》近世一手详载→确证)恰成对照。","historicity":"disputed","linked_cards":["alexander"],"tags":["战略","竞争博弈"],"advisor_id":"alexander"}', '4336bcc9b3d5fd69bdd97d3885c557fef228cefd570cb7cdf2c255b4ba2170c8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('alexander-c2', 'alexander', '推行东西融合·苏萨集体婚礼（前324）', '征服波斯后疆域辽阔、族群多元，纯靠马其顿武力无法长治；如何稳固统治。', '娶波斯贵族女、令数千马其顿将士与波斯女子集体成婚、采波斯朝仪、起用波斯人——以融合换认同。', '短期推进整合，但触怒重视马其顿本位的旧部、激化矛盾(后有军队不满)。', '征服之后，靠融合与吸纳被征服者的人才制度比纯压制更可持续；但推行太快、伤了自己核心团队的认同，会反噬。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"alexander-c2","status":"published","title_period":"推行东西融合·苏萨集体婚礼（前324）","dilemma_constraints":"征服波斯后疆域辽阔、族群多元，纯靠马其顿武力无法长治；如何稳固统治。","key_judgment":"娶波斯贵族女、令数千马其顿将士与波斯女子集体成婚、采波斯朝仪、起用波斯人——以融合换认同。","model_invoked":["文化融合统治"],"outcome":"短期推进整合，但触怒重视马其顿本位的旧部、激化矛盾(后有军队不满)。","transferable_lesson":"征服之后，靠融合与吸纳被征服者的人才制度比纯压制更可持续；但推行太快、伤了自己核心团队的认同，会反噬。","source_tier":"secondary","source_note":"融合政策与苏萨婚礼为多源古典记载(B)；具体规模数字与动机解读经后世史家加工，按角色细节非一手判存疑，政策主干无重大争议、呈现宜概述。","historicity":"disputed","linked_cards":["alexander"],"tags":["治理决策","领导力"],"advisor_id":"alexander"}', '322e764d6ea278f5708d7baa0917e0c3a8577e1271a2a31609dcd93c2edd1177');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('alexander-c3', 'alexander', '比阿斯河畔部下哗变·被迫回师（前326）', '连续远征至印度河流域、士卒厌战思归，亚历山大仍欲继续东进。', '（消极判例）坚持扩张、欲渡比阿斯河再进，遭全军拒绝前进的哗变，被迫违愿回师。', '被迫掉头西返，东征至此而止；不久(前323)于巴比伦病逝，帝国随即分裂。', '再强的进取心也有边界——当团队身心俱疲、目标已远超共识，硬推扩张会撞上"自己人"的极限。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"alexander-c3","status":"published","title_period":"比阿斯河畔部下哗变·被迫回师（前326）","dilemma_constraints":"连续远征至印度河流域、士卒厌战思归，亚历山大仍欲继续东进。","key_judgment":"（消极判例）坚持扩张、欲渡比阿斯河再进，遭全军拒绝前进的哗变，被迫违愿回师。","model_invoked":["以速度与气势压制"],"outcome":"被迫掉头西返，东征至此而止；不久(前323)于巴比伦病逝，帝国随即分裂。","transferable_lesson":"再强的进取心也有边界——当团队身心俱疲、目标已远超共识，硬推扩张会撞上\"自己人\"的极限。","source_tier":"secondary","source_note":"哗变与回师为多源古典记载(B)；现场对话与动机经后世史家叙述加工，按非一手判存疑；事件主干(部下拒进、被迫回师)无重大争议。本条作其\"无止境扩张/不知节制\"盲区的案例体现。","historicity":"disputed","linked_cards":["alexander"],"tags":["危机应对","领导力"],"advisor_id":"alexander"}', '49a51f3f3dd937c5e4a44796eb7fb5152daee80356f0f5423cc87e2d8e826992');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('clausewitz-c1', 'clausewitz', '亲历耶拿-奥尔施泰特惨败被俘（1806）', '作为奥古斯特亲王副官随旧式普军迎战拿破仑；普军体制僵化、指挥迟钝，败局非其所能左右。', '他个人未握决策权（仅副官）；真正的"判断"发生在战后——把这场惨败作为毕生反思素材，提炼出摩擦、政治从属、改革必要性。', '普军于耶拿-奥尔施泰特崩溃、他成两万五千俘虏之一；此败与战后反思成为《战争论》与普鲁士军改的思想原点。', '最深的方法论常诞生于亲历的失败——关键不在当时能否左右败局，而在事后是否把失败拆解成可迁移的原理。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"clausewitz-c1","status":"published","title_period":"亲历耶拿-奥尔施泰特惨败被俘（1806）","dilemma_constraints":"作为奥古斯特亲王副官随旧式普军迎战拿破仑；普军体制僵化、指挥迟钝，败局非其所能左右。","key_judgment":"他个人未握决策权（仅副官）；真正的\"判断\"发生在战后——把这场惨败作为毕生反思素材，提炼出摩擦、政治从属、改革必要性。","model_invoked":["摩擦"],"outcome":"普军于耶拿-奥尔施泰特崩溃、他成两万五千俘虏之一；此败与战后反思成为《战争论》与普鲁士军改的思想原点。","transferable_lesson":"最深的方法论常诞生于亲历的失败——关键不在当时能否左右败局，而在事后是否把失败拆解成可迁移的原理。","source_tier":"primary","source_note":"战役与其被俘身份为确证事实(战役信史A、其副官角色有记载)；惟\"此役直接催生其理论\"属合理的思想史归因、非单一文献明断，呈现为\"战后反思之原点\"即可，不夸大其战场作用。","historicity":"confirmed","linked_cards":["clausewitz"],"tags":["危机应对","战略"],"advisor_id":"clausewitz"}', '7eb59328915c90e666c18e96d06510c4ee09f2a451a1beee3a588385c7ce095a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('clausewitz-c2', 'clausewitz', '促成《陶罗根协定》的参谋斡旋（1812）', '因反对普鲁士被迫附庸拿破仑，他愤而转入俄军任参谋；如何在普王仍附法的政治僵局中，推动普军倒戈抗法。', '以俄方联络参谋身份参与斡旋，促成普鲁士约克军团与俄军停战的《陶罗根协定》——这正是"军事服从政治目的、用谈判达成战略转向"的亲身实践。', '《陶罗根协定》(1812)成为普鲁士脱离法国、转入反法同盟的转折点之一。', '决定全局的有时不是一场会战，而是一纸改变阵营结构的协定——军事价值最终由它服务的政治转向来兑现。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"clausewitz-c2","status":"published","title_period":"促成《陶罗根协定》的参谋斡旋（1812）","dilemma_constraints":"因反对普鲁士被迫附庸拿破仑，他愤而转入俄军任参谋；如何在普王仍附法的政治僵局中，推动普军倒戈抗法。","key_judgment":"以俄方联络参谋身份参与斡旋，促成普鲁士约克军团与俄军停战的《陶罗根协定》——这正是\"军事服从政治目的、用谈判达成战略转向\"的亲身实践。","model_invoked":["战争是政治的延续"],"outcome":"《陶罗根协定》(1812)成为普鲁士脱离法国、转入反法同盟的转折点之一。","transferable_lesson":"决定全局的有时不是一场会战，而是一纸改变阵营结构的协定——军事价值最终由它服务的政治转向来兑现。","source_tier":"secondary","source_note":"协定本身为信史(B)；但克劳塞维茨在其中的个人作用，史料表述从\"参与联络\"到\"部分促成\"不一、无法精确量化其份额——按\"事件信史/个人角色无精确一手量化→historicity存疑\"判例标存疑，呈现用\"参与促成\"而非\"主导\"。","historicity":"disputed","linked_cards":["clausewitz"],"tags":["战略","谈判"],"advisor_id":"clausewitz"}', '5af6830e7093ee4beebae9d9470e9ef3f9d78a982ab12efeaf0226085c21fa3d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('clausewitz-c3', 'clausewitz', '（传说对照·不可当史实）耶拿前"画破敌图"', '（传说情节）耶拿会战前，年轻的克劳塞维茨即看出普军布阵之误，绘制了一张如何击败拿破仑的作战图。', '（传说情节）其图后作为战利品落入拿破仑之手。', '（传说情节）用以渲染其"少年神算"。', '仅作"后世神化如何生成"的反面教材：真实的克劳塞维茨当时只是被俘的副官，其价值在思想而非"未卜先知"。', 'tertiary', 'legendary', 'published', '{"schema_version":1,"case_id":"clausewitz-c3","status":"published","title_period":"（传说对照·不可当史实）耶拿前\"画破敌图\"","dilemma_constraints":"（传说情节）耶拿会战前，年轻的克劳塞维茨即看出普军布阵之误，绘制了一张如何击败拿破仑的作战图。","key_judgment":"（传说情节）其图后作为战利品落入拿破仑之手。","model_invoked":[],"outcome":"（传说情节）用以渲染其\"少年神算\"。","transferable_lesson":"仅作\"后世神化如何生成\"的反面教材：真实的克劳塞维茨当时只是被俘的副官，其价值在思想而非\"未卜先知\"。","source_tier":"tertiary","source_note":"明确为19世纪传说(C)、非史实；呈现一切处须带\"（传说）\"。model_invoked=null（C层不入model闭环），sources(S6)仅supports到本case_id、不指任何core_model。用于警示\"勿以神化失真其真实形象\"。","historicity":"legendary","linked_cards":["clausewitz"],"tags":["危机应对"],"advisor_id":"clausewitz"}', '9b57ac7aa8b9833b63793f8266d2f0f5a370f3c3fb222b0e320d065b4933da87');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('caesar-c1', 'caesar', '渡卢比孔河进军罗马（前49年）', '元老院命其交兵权、否则为公敌；交则任人宰割，不交即内战、且违法越界。', '率军渡过卢比孔河(行省与本土的法定边界)进军罗马，以不可逆的既成事实逼摊牌，传"骰子已掷"。', '引爆内战，凯撒最终击败庞培、掌控罗马。', '当僵局只剩两个坏选项时，一个一旦做出就不可逆的动作能夺回主动——但你要认下它的全部代价。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"caesar-c1","status":"published","title_period":"渡卢比孔河进军罗马（前49年）","dilemma_constraints":"元老院命其交兵权、否则为公敌；交则任人宰割，不交即内战、且违法越界。","key_judgment":"率军渡过卢比孔河(行省与本土的法定边界)进军罗马，以不可逆的既成事实逼摊牌，传\"骰子已掷\"。","model_invoked":["制造既成事实"],"outcome":"引爆内战，凯撒最终击败庞培、掌控罗马。","transferable_lesson":"当僵局只剩两个坏选项时，一个一旦做出就不可逆的动作能夺回主动——但你要认下它的全部代价。","source_tier":"secondary","source_note":"渡河进军为信史(B)；惟\"骰子已掷\"原话与诸多细节出后世史家(苏维托尼乌斯/普鲁塔克)、有文学加工，故金句类细节historicity存疑，事件主干确证、呈现区分\"史实(渡河进军)\"与\"传为其言(骰子已掷)\"。","historicity":"disputed","linked_cards":["caesar"],"tags":["战略","危机应对"],"advisor_id":"caesar"}', '577248de4a08c58c48bbbc786d3b511f02021fa5e13f4704f5ae4958d76d479c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('caesar-c2', 'caesar', '阿莱西亚围城·内外双重包围（前52年）', '围困维钦托利于阿莱西亚时，遭高卢援军内外夹击，兵力居劣、腹背受敌。', '修内外双重环形工事(对城围困、对援军防御)，并在危急处亲临前线督战。', '罗马军以少胜多、破援军并迫维钦托利投降，奠定高卢征服。', '腹背受敌时，与其分兵犹豫，不如用工事把战场结构固定下来、再把主将的存在投到最危处稳住人心。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"caesar-c2","status":"published","title_period":"阿莱西亚围城·内外双重包围（前52年）","dilemma_constraints":"围困维钦托利于阿莱西亚时，遭高卢援军内外夹击，兵力居劣、腹背受敌。","key_judgment":"修内外双重环形工事(对城围困、对援军防御)，并在危急处亲临前线督战。","model_invoked":["亲临一线"],"outcome":"罗马军以少胜多、破援军并迫维钦托利投降，奠定高卢征服。","transferable_lesson":"腹背受敌时，与其分兵犹豫，不如用工事把战场结构固定下来、再把主将的存在投到最危处稳住人心。","source_tier":"primary","source_note":"出凯撒亲撰《高卢战记》(一手A，但属自述)；战役为信史，惟兵力对比与己方英勇程度有自我美化倾向，按\"自述→historicity存疑\"判例标存疑；呈现宜加\"据凯撒自述\"。","historicity":"disputed","linked_cards":["caesar"],"tags":["战略","危机应对"],"advisor_id":"caesar"}', '3c2a202cad8063ee3c17512d8194a61cc92df4a57ae11fcfd02fd5fc9d9e8a0d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('caesar-c3', 'caesar', '内战宽赦政策（clementia Caesaris，前49—前45）', '内战中如何处置大批庞培派降者与政敌——赶尽杀绝可除后患却结死仇，宽赦则留隐患。', '推行宽赦(clementia)，对多数降者免死、甚至起用，以宽容塑造正当性与号召力。', '短期赢得名声与归附、加速统一；长期埋隐患——多名被赦者参与刺杀。', '宽待败者能把敌人转为资源、赢得人心，但别误以为宽赦等于安全：它降低对抗、却不消除根本利益冲突。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"caesar-c3","status":"published","title_period":"内战宽赦政策（clementia Caesaris，前49—前45）","dilemma_constraints":"内战中如何处置大批庞培派降者与政敌——赶尽杀绝可除后患却结死仇，宽赦则留隐患。","key_judgment":"推行宽赦(clementia)，对多数降者免死、甚至起用，以宽容塑造正当性与号召力。","model_invoked":["宽恕政策"],"outcome":"短期赢得名声与归附、加速统一；长期埋隐患——多名被赦者参与刺杀。","transferable_lesson":"宽待败者能把敌人转为资源、赢得人心，但别误以为宽赦等于安全：它降低对抗、却不消除根本利益冲突。","source_tier":"secondary","source_note":"宽赦政策为多源记载之史实(B，确证)；具体个案细节略有出入但政策主干无重大争议。","historicity":"confirmed","linked_cards":["caesar"],"tags":["领导力","危机应对"],"advisor_id":"caesar"}', '4ecf95642b745261d0ee916372a1323403d73d888d326612b3e0ed16a20b9ae8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('caesar-c4', 'caesar', '遇刺于元老院（前44年3月15日）', '集大权于一身、被疑图王，触动共和派与元老集团根本利益。', '（消极判例）忽视多次预警、解散私人卫队、过度自信于威望与宽赦所积的人心。', '在元老院被以布鲁图斯为首的共和派刺杀身亡。', '把合法性透支到极限、又解除自我保护时，个人威望挡不住被你越过的体制反扑——成就你的特质过头即是杀你的特质。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"caesar-c4","status":"published","title_period":"遇刺于元老院（前44年3月15日）","dilemma_constraints":"集大权于一身、被疑图王，触动共和派与元老集团根本利益。","key_judgment":"（消极判例）忽视多次预警、解散私人卫队、过度自信于威望与宽赦所积的人心。","model_invoked":["制造既成事实"],"outcome":"在元老院被以布鲁图斯为首的共和派刺杀身亡。","transferable_lesson":"把合法性透支到极限、又解除自我保护时，个人威望挡不住被你越过的体制反扑——成就你的特质过头即是杀你的特质。","source_tier":"secondary","source_note":"刺杀为多源记载之确证史实(B)；部分预兆细节(占卜师警告等)有文学渲染、不作史实依据，事件主干确证。","historicity":"confirmed","linked_cards":["caesar"],"tags":["领导力","危机应对"],"advisor_id":"caesar"}', 'e9e00941ac9d2319f85bdf8ba79502d767008c5414fc20a4d4e58a1f64baf58f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wuqi-c1', 'wuqi', '为士卒吮疽·与士卒同甘共苦（吴起带兵）', '如何让士卒真心效死。', '吴起身为大将，与最底层士卒同衣食、共甘苦，甚至亲为生疽的士卒吮吸脓血，以真心换取士卒效死。', '士卒感其恩、皆愿为之效死，吴起所率之军战斗力极强。', '与成员同甘共苦、设身处地关心、以身作则——你真心待他们，他们才肯为你效死力。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wuqi-c1","status":"published","title_period":"为士卒吮疽·与士卒同甘共苦（吴起带兵）","dilemma_constraints":"如何让士卒真心效死。","key_judgment":"吴起身为大将，与最底层士卒同衣食、共甘苦，甚至亲为生疽的士卒吮吸脓血，以真心换取士卒效死。","model_invoked":["与士卒同甘共苦"],"outcome":"士卒感其恩、皆愿为之效死，吴起所率之军战斗力极强。","transferable_lesson":"与成员同甘共苦、设身处地关心、以身作则——你真心待他们，他们才肯为你效死力。","source_tier":"secondary","source_note":"吴起吮疽为《史记·孙子吴起列传》载→确证（二手B）。","historicity":"confirmed","linked_cards":["wuqi"],"tags":["领导力","组织管理"],"advisor_id":"wuqi"}', 'ca9ace0a34ae492f699898921e7d8a0094260022523d5f6e8e8ab95ac0201760');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wuqi-c2', 'wuqi', '「在德不在险」·文德武备并重（对魏武侯）', '一个国家的安危究竟靠什么。', '魏武侯夸山河之险可恃，吴起以"在德不在险"对——若内部失德、人心离散，再险的山河也保不住。', '「在德不在险」成为中国政治军事思想的名论。', '组织的安危根本在内部的人心、治理与凝聚（文德），而非只靠外在的天险与武力。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wuqi-c2","status":"published","title_period":"「在德不在险」·文德武备并重（对魏武侯）","dilemma_constraints":"一个国家的安危究竟靠什么。","key_judgment":"魏武侯夸山河之险可恃，吴起以\"在德不在险\"对——若内部失德、人心离散，再险的山河也保不住。","model_invoked":["文德武备并重·在德不在险"],"outcome":"「在德不在险」成为中国政治军事思想的名论。","transferable_lesson":"组织的安危根本在内部的人心、治理与凝聚（文德），而非只靠外在的天险与武力。","source_tier":"primary","source_note":"「在德不在险」为《史记》载吴起之论→确证（一手/二手A/B）。","historicity":"confirmed","linked_cards":["wuqi"],"tags":["领导力","组织管理"],"advisor_id":"wuqi"}', '95350d96c2b979e335508a2787e20397438d87bbc246689caab645f9de36ae46');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wuqi-c3', 'wuqi', '《吴子·料敌》·因敌制胜的料敌（《吴子》）', '如何针对不同的对手取胜。', '吴起在《吴子·料敌》中详细分析了不同国家军队的特点、习性与弱点，因敌制定不同的取胜之策。', '《吴子》的料敌之论成为兵家因敌制胜的典范。', '详细分析具体对手的特点、习性与弱点，再因敌制定专门的取胜之策——别用一套打法对所有对手。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wuqi-c3","status":"published","title_period":"《吴子·料敌》·因敌制胜的料敌（《吴子》）","dilemma_constraints":"如何针对不同的对手取胜。","key_judgment":"吴起在《吴子·料敌》中详细分析了不同国家军队的特点、习性与弱点，因敌制定不同的取胜之策。","model_invoked":["因敌制胜的料敌"],"outcome":"《吴子》的料敌之论成为兵家因敌制胜的典范。","transferable_lesson":"详细分析具体对手的特点、习性与弱点，再因敌制定专门的取胜之策——别用一套打法对所有对手。","source_tier":"primary","source_note":"《吴子·料敌》为吴起兵书→确证（一手A）。","historicity":"confirmed","linked_cards":["wuqi"],"tags":["竞争博弈","组织管理"],"advisor_id":"wuqi"}', 'c97a97021503cdc5207e207f0320f2a0f46df729438f441498d0eb8bb5222943');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wuqi-c4', 'wuqi', '选练"魏武卒"·选练精兵（吴起在魏）', '如何打造一支战斗力极强的军队。', '吴起在魏国选拔、训练"魏武卒"——以严格的标准选练精锐，以精兵制胜，使魏国一时称霸。', '魏武卒成为战国初期的精锐劲旅，助魏国强盛。', '与其追求人多，不如把队伍训练成真正精锐、能以一当十的精兵——但精兵的标准与成本也高。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wuqi-c4","status":"published","title_period":"选练\"魏武卒\"·选练精兵（吴起在魏）","dilemma_constraints":"如何打造一支战斗力极强的军队。","key_judgment":"吴起在魏国选拔、训练\"魏武卒\"——以严格的标准选练精锐，以精兵制胜，使魏国一时称霸。","model_invoked":["选练精兵"],"outcome":"魏武卒成为战国初期的精锐劲旅，助魏国强盛。","transferable_lesson":"与其追求人多，不如把队伍训练成真正精锐、能以一当十的精兵——但精兵的标准与成本也高。","source_tier":"secondary","source_note":"吴起选练魏武卒为史述→确证（二手B）。","historicity":"confirmed","linked_cards":["wuqi"],"tags":["组织管理","竞争博弈"],"advisor_id":"wuqi"}', 'a135ea0d4b4befeb8f22980e4f1f0f0d3e2cb615709b2641945d8e39ea0221c8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('sunzi-c1', 'sunzi', '吴宫教战·斩美姬立军令（相传约前512年）', '以宫中美人180人试演军阵，阖闾两名宠姬带头嬉笑不听号令；孙武须在君王面前确立令行禁止，否则兵法无从被证明。', '三令五申仍不从，遂斩两名队长（吴王宠姬），称"将在军，君命有所不受"，拒阖闾求情；再演众人肃然。', '阖闾痛失爱姬仍认其能用兵，任为将（《史记》）。', '规则权威在其第一次被挑战时确立；对带头破坏规则的核心人物妥协，等于宣告规则作废——但立威代价真实，需权衡。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"sunzi-c1","status":"published","title_period":"吴宫教战·斩美姬立军令（相传约前512年）","dilemma_constraints":"以宫中美人180人试演军阵，阖闾两名宠姬带头嬉笑不听号令；孙武须在君王面前确立令行禁止，否则兵法无从被证明。","key_judgment":"三令五申仍不从，遂斩两名队长（吴王宠姬），称\"将在军，君命有所不受\"，拒阖闾求情；再演众人肃然。","model_invoked":["先胜后战"],"outcome":"阖闾痛失爱姬仍认其能用兵，任为将（《史记》）。","transferable_lesson":"规则权威在其第一次被挑战时确立；对带头破坏规则的核心人物妥协，等于宣告规则作废——但立威代价真实，需权衡。","source_tier":"secondary","source_note":"仅见《史记·孙子吴起列传》(B)，成书晚孙子约三百年，孙武其人/此事真实性学界存疑；呈现须作\"史载/相传\"，不可当铁板史实。","historicity":"disputed","linked_cards":["sunzi"],"tags":["危机应对","组织管理"],"advisor_id":"sunzi"}', 'd77e8ab177e69f935b58baac32876f114ca160aac95a12968d19c6c9d1198b78');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('sunzi-c2', 'sunzi', '柏举之战·吴师入郢（前506年）', '吴以相对小国之力远征强楚，实力悬殊。', '（史载/相传）避实击虚、以奇兵长驱直入、速战速决——惟孙武在此役的个人角色史无明载。', '吴军大破楚军、一度攻占郢都，为春秋著名以弱胜强战例（《左传》《史记》载战役本身）。', '以小博大不靠硬实力对拼，靠速度、出其不意与避实击虚。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"sunzi-c2","status":"published","title_period":"柏举之战·吴师入郢（前506年）","dilemma_constraints":"吴以相对小国之力远征强楚，实力悬殊。","key_judgment":"（史载/相传）避实击虚、以奇兵长驱直入、速战速决——惟孙武在此役的个人角色史无明载。","model_invoked":["奇正相生"],"outcome":"吴军大破楚军、一度攻占郢都，为春秋著名以弱胜强战例（《左传》《史记》载战役本身）。","transferable_lesson":"以小博大不靠硬实力对拼，靠速度、出其不意与避实击虚。","source_tier":"primary","source_note":"战役本身为信史(A/B，《左传》确载)；但孙武在此役的具体谋划缺可靠一手记载，史家多归主功于伍子胥、夫概等。故作为\"孙子个人决策案例\"其可信度为存疑(disputed)——战役是史实、孙子之角色是相传。本条只作\"兵学原理的时代实践背景\"，呈现须加\"史载/相传\"限定、不附会为孙武个人决策。source_tier 维持 A（指战役本身的史料层级），historicity=存疑（指本人角色），二轴正交、各表其义。","historicity":"disputed","linked_cards":["sunzi"],"tags":["战略","竞争博弈"],"advisor_id":"sunzi"}', 'a559975d5209da8c01200b900cb9d2fa705035d68921a64290d3b48468c0329b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('yuefei-c1', 'yuefei', '岳家军"冻死不拆屋"·严明的纪律即战斗力（南宋抗金）', '乱世中军队易滋扰百姓、失去民心与战力。', '岳飞治军极严，定下"冻死不拆屋、饿死不掳掠"的铁律，对百姓秋毫无犯，铸就了"撼山易、撼岳家军难"的劲旅。', '岳家军以纪律严明、战力强悍著称，深得民心。', '以极严明、说到做到的纪律约束队伍、对外秋毫无犯——纪律既铸战力、也赢人心。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"yuefei-c1","status":"published","title_period":"岳家军\"冻死不拆屋\"·严明的纪律即战斗力（南宋抗金）","dilemma_constraints":"乱世中军队易滋扰百姓、失去民心与战力。","key_judgment":"岳飞治军极严，定下\"冻死不拆屋、饿死不掳掠\"的铁律，对百姓秋毫无犯，铸就了\"撼山易、撼岳家军难\"的劲旅。","model_invoked":["严明的纪律即战斗力"],"outcome":"岳家军以纪律严明、战力强悍著称，深得民心。","transferable_lesson":"以极严明、说到做到的纪律约束队伍、对外秋毫无犯——纪律既铸战力、也赢人心。","source_tier":"secondary","source_note":"岳家军纪律为《宋史》载→确证（二手B）。","historicity":"confirmed","linked_cards":["yuefei"],"tags":["领导力","组织管理"],"advisor_id":"yuefei"}', '9e80325dea9d6421f04cc270ee0c7258b5ed8a95abaad1b30b0c51b733fb4041');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('yuefei-c2', 'yuefei', '「精忠报国」与身先士卒·以信念与表率带兵（南宋抗金）', '如何带出一支有战斗意志、死战不退的队伍。', '岳飞以"精忠报国"的崇高信念，加上身先士卒、与士卒同甘共苦的表率，凝聚出愿为之死战的岳家军。', '岳家军士气高昂、上下用命，屡建战功。', '用崇高的信念加身先士卒的表率，凝聚一支死战不退的队伍。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"yuefei-c2","status":"published","title_period":"「精忠报国」与身先士卒·以信念与表率带兵（南宋抗金）","dilemma_constraints":"如何带出一支有战斗意志、死战不退的队伍。","key_judgment":"岳飞以\"精忠报国\"的崇高信念，加上身先士卒、与士卒同甘共苦的表率，凝聚出愿为之死战的岳家军。","model_invoked":["以信念与表率带兵"],"outcome":"岳家军士气高昂、上下用命，屡建战功。","transferable_lesson":"用崇高的信念加身先士卒的表率，凝聚一支死战不退的队伍。","source_tier":"secondary","source_note":"岳飞精忠报国与身先士卒为《宋史》载→确证（二手B）。","historicity":"confirmed","linked_cards":["yuefei"],"tags":["领导力","组织管理"],"advisor_id":"yuefei"}', 'fa6364a03ce920cfeae9f4f65b0bac2d8381019dbc64f96a65b5d0eca2e1a46b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('yuefei-c3', 'yuefei', '「连结河朔」联络义军·联合民间的力量（北伐期间）', '仅靠正规军难以收复广大失地。', '岳飞推行"连结河朔"之策，主动联络北方敌后的民间义军、武装，把分散的抵抗力量联结成呼应北伐的网络。', '「连结河朔」扩大了抗金的合力，对北伐形成呼应。', '别只靠自己的正规力量——主动联结分散的同盟力量，编成能呼应、配合你的网络。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"yuefei-c3","status":"published","title_period":"「连结河朔」联络义军·联合民间的力量（北伐期间）","dilemma_constraints":"仅靠正规军难以收复广大失地。","key_judgment":"岳飞推行\"连结河朔\"之策，主动联络北方敌后的民间义军、武装，把分散的抵抗力量联结成呼应北伐的网络。","model_invoked":["联合民间的力量"],"outcome":"「连结河朔」扩大了抗金的合力，对北伐形成呼应。","transferable_lesson":"别只靠自己的正规力量——主动联结分散的同盟力量，编成能呼应、配合你的网络。","source_tier":"secondary","source_note":"岳飞\"连结河朔\"为《宋史》载→确证（二手B）。","historicity":"confirmed","linked_cards":["yuefei"],"tags":["竞争博弈","组织管理"],"advisor_id":"yuefei"}', '4db6b1f0e68a9246478311b1a4f7a598b1382cebd233988b70172fd1c4531242');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('yuefei-c4', 'yuefei', '「文官不爱钱、武官不惜死」与风波亭·清廉担当不惜身（1142）', '身处复杂的政治与战和之争中。', '岳飞以"文官不爱钱、武官不惜死"的清廉与担当立身，不为私利安危所动；但也因过于刚直、不善政治自保，终被以"莫须有"罪名冤杀于风波亭。', '岳飞的清廉与担当为后世景仰，但其刚直不善自保亦酿成悲剧（本卡点到为止、不渲染）。', '以"不爱钱、不惜死"的清廉担当立身——但也要懂得必要的自保与权衡，别过刚而折。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"yuefei-c4","status":"published","title_period":"「文官不爱钱、武官不惜死」与风波亭·清廉担当不惜身（1142）","dilemma_constraints":"身处复杂的政治与战和之争中。","key_judgment":"岳飞以\"文官不爱钱、武官不惜死\"的清廉与担当立身，不为私利安危所动；但也因过于刚直、不善政治自保，终被以\"莫须有\"罪名冤杀于风波亭。","model_invoked":["清廉担当不惜身"],"outcome":"岳飞的清廉与担当为后世景仰，但其刚直不善自保亦酿成悲剧（本卡点到为止、不渲染）。","transferable_lesson":"以\"不爱钱、不惜死\"的清廉担当立身——但也要懂得必要的自保与权衡，别过刚而折。","source_tier":"secondary","source_note":"岳飞名言及风波亭冤案为《宋史》载→确证（二手B；个人结局点到为止、不渲染）。","historicity":"confirmed","linked_cards":["yuefei"],"tags":["领导力","修身自省"],"advisor_id":"yuefei"}', '006037bf90b6e95039fad57058c666560c275b3c1d36e101f95402715e665042');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('qijiguang-c1', 'qijiguang', '募义乌兵、练成戚家军·募兵练兵成军（嘉靖年间）', '明代卫所兵腐败、怯弱、不堪用，难御倭寇。', '戚继光弃用旧兵，亲赴义乌招募淳朴勇悍的矿工农民，用严格系统的训练，从零练成威震天下的"戚家军"。', '「戚家军」成为抗倭主力，连战连捷、几乎荡平东南倭患。', '没有现成好队伍时，亲自招募合适的人、严格训练，从零打造一支真正能打的队伍。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"qijiguang-c1","status":"published","title_period":"募义乌兵、练成戚家军·募兵练兵成军（嘉靖年间）","dilemma_constraints":"明代卫所兵腐败、怯弱、不堪用，难御倭寇。","key_judgment":"戚继光弃用旧兵，亲赴义乌招募淳朴勇悍的矿工农民，用严格系统的训练，从零练成威震天下的\"戚家军\"。","model_invoked":["募兵练兵成军"],"outcome":"「戚家军」成为抗倭主力，连战连捷、几乎荡平东南倭患。","transferable_lesson":"没有现成好队伍时，亲自招募合适的人、严格训练，从零打造一支真正能打的队伍。","source_tier":"secondary","source_note":"募义乌兵练成戚家军为《明史》及戚继光著作所载→确证（二手B）。","historicity":"confirmed","linked_cards":["qijiguang"],"tags":["组织管理","危机应对"],"advisor_id":"qijiguang"}', '710ce145c61f55f41249b8d87d5cf93d61ed09af6d120005e8d88578ec3036e0');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('qijiguang-c2', 'qijiguang', '创鸳鸯阵·阵法与协同（抗倭战争）', '倭寇凶悍、单兵作战明军吃亏，需以协同取胜。', '戚继光创"鸳鸯阵"，让盾牌、狼筅、长枪、短刀等不同兵器的士兵分工协同、彼此掩护，以小队配合克敌。', '鸳鸯阵大大提升了戚家军的战斗力，成为抗倭利器。', '设计清晰的"阵法"（分工与配合机制），让不同技能的人各司其职、协同作战。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"qijiguang-c2","status":"published","title_period":"创鸳鸯阵·阵法与协同（抗倭战争）","dilemma_constraints":"倭寇凶悍、单兵作战明军吃亏，需以协同取胜。","key_judgment":"戚继光创\"鸳鸯阵\"，让盾牌、狼筅、长枪、短刀等不同兵器的士兵分工协同、彼此掩护，以小队配合克敌。","model_invoked":["阵法与协同"],"outcome":"鸳鸯阵大大提升了戚家军的战斗力，成为抗倭利器。","transferable_lesson":"设计清晰的\"阵法\"（分工与配合机制），让不同技能的人各司其职、协同作战。","source_tier":"primary","source_note":"鸳鸯阵为戚继光《纪效新书》所载→确证（一手A）。","historicity":"confirmed","linked_cards":["qijiguang"],"tags":["组织管理","竞争博弈"],"advisor_id":"qijiguang"}', 'c5ecb5594ebf9c768ac24986e457b272971e61deacdc321e7699fc2ce9d8531f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('qijiguang-c3', 'qijiguang', '严明治军·严明纪律赏罚（抗倭练兵）', '把一群普通农民矿工锻造成劲旅，靠什么。', '戚继光以极严明的纪律、连坐、赏罚分明治军，把普通人锻造成令行禁止、敢打硬仗的队伍。', '戚家军纪律严明、战斗力极强，成为传奇。', '用极严明、清晰、说到做到的纪律与赏罚，把普通人锻造成令行禁止的队伍——纪律是战斗力的根基。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"qijiguang-c3","status":"published","title_period":"严明治军·严明纪律赏罚（抗倭练兵）","dilemma_constraints":"把一群普通农民矿工锻造成劲旅，靠什么。","key_judgment":"戚继光以极严明的纪律、连坐、赏罚分明治军，把普通人锻造成令行禁止、敢打硬仗的队伍。","model_invoked":["严明纪律赏罚"],"outcome":"戚家军纪律严明、战斗力极强，成为传奇。","transferable_lesson":"用极严明、清晰、说到做到的纪律与赏罚，把普通人锻造成令行禁止的队伍——纪律是战斗力的根基。","source_tier":"secondary","source_note":"戚继光严明治军为史述→确证（二手B）。","historicity":"confirmed","linked_cards":["qijiguang"],"tags":["组织管理"],"advisor_id":"qijiguang"}', 'e0ed2adde77b1d6df41bf2112c1b3c0dd97f279cc37092cfea11d171f0b5f4ee');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('qijiguang-c4', 'qijiguang', '著《纪效新书》《练兵实纪》·著书立制传承（练兵经验系统化）', '如何让练兵建军的经验不随个人而失传。', '戚继光把练兵、作战、阵法、兵器的经验系统化、文本化为《纪效新书》《练兵实纪》等兵书，使之可传承、可复制。', '戚继光的兵书成为明清重要的军事经典，影响深远。', '把有效经验系统化、文本化为可传承、可复制的"操典/手册"，让成功不依赖个人、可被复制传承。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"qijiguang-c4","status":"published","title_period":"著《纪效新书》《练兵实纪》·著书立制传承（练兵经验系统化）","dilemma_constraints":"如何让练兵建军的经验不随个人而失传。","key_judgment":"戚继光把练兵、作战、阵法、兵器的经验系统化、文本化为《纪效新书》《练兵实纪》等兵书，使之可传承、可复制。","model_invoked":["著书立制传承"],"outcome":"戚继光的兵书成为明清重要的军事经典，影响深远。","transferable_lesson":"把有效经验系统化、文本化为可传承、可复制的\"操典/手册\"，让成功不依赖个人、可被复制传承。","source_tier":"primary","source_note":"《纪效新书》《练兵实纪》为戚继光著作→确证（一手A）。","historicity":"confirmed","linked_cards":["qijiguang"],"tags":["组织管理","长期规划"],"advisor_id":"qijiguang"}', '25b48bcb207b6524ab31e251cf8f2136027c34e7b6c9dd48ed524830ab6887b5');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('napoleon-c1', 'napoleon', '奥斯特里茨战役（三皇会战，1805）', '面对俄奥联军兵力占优；须诱敌、择点、在决定性一刻集中突破。', '故意示弱让出普拉岑高地诱敌分兵，待联军中路削弱即集中突击该决定点，拦腰斩断。', '法军大胜俄奥联军，奥斯特里茨成其军事生涯巅峰战例。', '主动示弱让出诱饵、引对手分散，再把全部力量砸向那个被削弱的决定点——以局部绝对优势取全局。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"napoleon-c1","status":"published","title_period":"奥斯特里茨战役（三皇会战，1805）","dilemma_constraints":"面对俄奥联军兵力占优；须诱敌、择点、在决定性一刻集中突破。","key_judgment":"故意示弱让出普拉岑高地诱敌分兵，待联军中路削弱即集中突击该决定点，拦腰斩断。","model_invoked":["集中优势兵力于决定点"],"outcome":"法军大胜俄奥联军，奥斯特里茨成其军事生涯巅峰战例。","transferable_lesson":"主动示弱让出诱饵、引对手分散，再把全部力量砸向那个被削弱的决定点——以局部绝对优势取全局。","source_tier":"secondary","source_note":"战役及拿破仑亲自指挥为多源信史(B，确证)——此为\"个人指挥角色有可靠记载→可确证\"，与''仅事件信史而角色无据''者区分；细节战术意图部分有后世解读、不影响主干。","historicity":"confirmed","linked_cards":["napoleon"],"tags":["战略","竞争博弈"],"advisor_id":"napoleon"}', '3c2777b88b5d00e69964e5294a7892bd58bb0d0fbe9318c6dc394135dc60c77b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('napoleon-c2', 'napoleon', '颁行《拿破仑法典》（1804）', '革命后法国法律混乱、各地习惯法割裂；如何把革命成果与新秩序固定下来、超越个人统治。', '主持编纂统一民法典，确立法律面前平等、私有财产、契约自由等，使秩序靠规则而非靠人延续。', '《拿破仑法典》成为现代大陆法系基石，影响远超其帝国寿命、流传至今。', '真正长久的胜利不是赢一场仗，而是把成果固化成不依赖你个人的制度——武功须以文治封存。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"napoleon-c2","status":"published","title_period":"颁行《拿破仑法典》（1804）","dilemma_constraints":"革命后法国法律混乱、各地习惯法割裂；如何把革命成果与新秩序固定下来、超越个人统治。","key_judgment":"主持编纂统一民法典，确立法律面前平等、私有财产、契约自由等，使秩序靠规则而非靠人延续。","model_invoked":["制度法典化"],"outcome":"《拿破仑法典》成为现代大陆法系基石，影响远超其帝国寿命、流传至今。","transferable_lesson":"真正长久的胜利不是赢一场仗，而是把成果固化成不依赖你个人的制度——武功须以文治封存。","source_tier":"primary","source_note":"法典文本与其推动编纂为确证史实(一手A)；这是本卡历史性最硬的一条。","historicity":"confirmed","linked_cards":["napoleon"],"tags":["治理决策","长期规划"],"advisor_id":"napoleon"}', '5058cb2a99dfd5d849a6ba97e07097e407ebcc01559b604518569b63b738b1c9');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('napoleon-c3', 'napoleon', '远征俄国惨败（1812）', '俄国退出大陆封锁体系；拿破仑欲以一场决战逼俄屈服，率约60万大军深入。', '（消极判例）坚持深入、追求决战，低估补给线、焦土战略与寒冬；占莫斯科后仍迟迟不撤。', '俄军坚壁清野、避免决战，法军在严寒与补给崩溃中撤退，约60万大军生还者寥寥，帝国由盛转衰。', '屡胜会养成"必能决战取胜"的路径依赖；遇到不与你决战、用消耗和纵深拖你过顶点的对手，扩张优先而无止损阀就是灾难。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"napoleon-c3","status":"published","title_period":"远征俄国惨败（1812）","dilemma_constraints":"俄国退出大陆封锁体系；拿破仑欲以一场决战逼俄屈服，率约60万大军深入。","key_judgment":"（消极判例）坚持深入、追求决战，低估补给线、焦土战略与寒冬；占莫斯科后仍迟迟不撤。","model_invoked":["速度与机动"],"outcome":"俄军坚壁清野、避免决战，法军在严寒与补给崩溃中撤退，约60万大军生还者寥寥，帝国由盛转衰。","transferable_lesson":"屡胜会养成\"必能决战取胜\"的路径依赖；遇到不与你决战、用消耗和纵深拖你过顶点的对手，扩张优先而无止损阀就是灾难。","source_tier":"secondary","source_note":"征俄惨败为多源信史(B，确证)；具体伤亡数字各史略有出入但量级与结局无争议。本条作其\"不知节制/越过进攻顶点\"盲区的案例体现。","historicity":"confirmed","linked_cards":["napoleon"],"tags":["战略","危机应对"],"advisor_id":"napoleon"}', '2d29d0b2ec7e4448c904cb9be9c5f1385aad1bc7e5216c3fc5a8c529d5610054');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('napoleon-c4', 'napoleon', '雾月政变夺权（1799）', '督政府腐败无能、政局动荡、存在权力真空；如何从将领跃为最高统治者。', '抓住政局危机窗口，联合势力发动雾月十八日政变，解散督政府、建立执政府自任第一执政。', '攫取最高权力，开启执政府—帝国时代。', '巨变与真空期，机会窗口稍纵即逝；识别它并果断攫取，胜过在旧秩序里循序渐进。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"napoleon-c4","status":"published","title_period":"雾月政变夺权（1799）","dilemma_constraints":"督政府腐败无能、政局动荡、存在权力真空；如何从将领跃为最高统治者。","key_judgment":"抓住政局危机窗口，联合势力发动雾月十八日政变，解散督政府、建立执政府自任第一执政。","model_invoked":["抓住机会窗口"],"outcome":"攫取最高权力，开启执政府—帝国时代。","transferable_lesson":"巨变与真空期，机会窗口稍纵即逝；识别它并果断攫取，胜过在旧秩序里循序渐进。","source_tier":"secondary","source_note":"政变为多源信史(B，确证)；其个人主导角色有可靠记载。","historicity":"confirmed","linked_cards":["napoleon"],"tags":["战略","危机应对"],"advisor_id":"napoleon"}', 'a945b5921d7a5031d294a6947d8332765b5401166a4724d0a502ebc673a2473c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('caocao-c1', 'caocao', '连发《求贤令》·唯才是举不拘品行（建安年间）', '乱世争雄、人才匮乏，而传统用人重门第、名节。', '曹操连发《求贤令》，公开主张"唯才是举"，用人不拘出身、资历、品行，哪怕"不仁不孝"只要有真本事就用。', '曹操麾下聚集了大批人才（谋士武将），为其成就霸业奠定基础（但只看才不看德也有隐患）。', '用人不拘出身、资历、品行的瑕疵，只要有真本事、能办成事就大胆用——但须知只看才不看德有隐患。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"caocao-c1","status":"published","title_period":"连发《求贤令》·唯才是举不拘品行（建安年间）","dilemma_constraints":"乱世争雄、人才匮乏，而传统用人重门第、名节。","key_judgment":"曹操连发《求贤令》，公开主张\"唯才是举\"，用人不拘出身、资历、品行，哪怕\"不仁不孝\"只要有真本事就用。","model_invoked":["唯才是举不拘品行"],"outcome":"曹操麾下聚集了大批人才（谋士武将），为其成就霸业奠定基础（但只看才不看德也有隐患）。","transferable_lesson":"用人不拘出身、资历、品行的瑕疵，只要有真本事、能办成事就大胆用——但须知只看才不看德有隐患。","source_tier":"primary","source_note":"《求贤令》为曹操所发→确证（一手A）。","historicity":"confirmed","linked_cards":["caocao"],"tags":["组织管理","竞争博弈"],"advisor_id":"caocao"}', '2c7166dda110c2f08b9637e2614a0c6a4678b8b821f18634beaa13e892f3dbc5');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('caocao-c2', 'caocao', '推行屯田·屯田固本（建安元年起）', '群雄逐鹿、军粮匮乏，谁有稳定的物质基础谁能持久。', '曹操推行"屯田制"，组织士兵与流民耕种，自给军粮、夯实经济与后勤的根基。', '屯田解决了军粮问题，为曹操统一北方打下了坚实的物质基础。', '别只顾扩张、忽视根基——以"屯田"式办法夯实资源、粮草、现金流的基础，根基稳了才能持久。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"caocao-c2","status":"published","title_period":"推行屯田·屯田固本（建安元年起）","dilemma_constraints":"群雄逐鹿、军粮匮乏，谁有稳定的物质基础谁能持久。","key_judgment":"曹操推行\"屯田制\"，组织士兵与流民耕种，自给军粮、夯实经济与后勤的根基。","model_invoked":["屯田固本"],"outcome":"屯田解决了军粮问题，为曹操统一北方打下了坚实的物质基础。","transferable_lesson":"别只顾扩张、忽视根基——以\"屯田\"式办法夯实资源、粮草、现金流的基础，根基稳了才能持久。","source_tier":"secondary","source_note":"曹操推行屯田为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["caocao"],"tags":["组织管理","长期规划"],"advisor_id":"caocao"}', '22b9c8f3898cb1b5a4ae1620fa7f4a11313d5e46be3f41b927e416065d91ea0c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('caocao-c3', 'caocao', '迎汉献帝、奉天子以令不臣·挟天子以令诸侯（196）', '群雄并起，谁能占据道义与法理的制高点。', '曹操迎汉献帝至许都，"奉天子以令不臣"，借汉室正统的名义号令、征伐，使自己师出有名、占据主动。', '曹操借天子之名占据了政治主动，在群雄中取得了正当性优势（权谋色彩重、历来有争议）。', '抢占道义、法理、正统的制高点，借被广泛承认的名义行事，使自己师出有名——但权谋色彩重、须客观看待。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"caocao-c3","status":"published","title_period":"迎汉献帝、奉天子以令不臣·挟天子以令诸侯（196）","dilemma_constraints":"群雄并起，谁能占据道义与法理的制高点。","key_judgment":"曹操迎汉献帝至许都，\"奉天子以令不臣\"，借汉室正统的名义号令、征伐，使自己师出有名、占据主动。","model_invoked":["挟天子以令诸侯"],"outcome":"曹操借天子之名占据了政治主动，在群雄中取得了正当性优势（权谋色彩重、历来有争议）。","transferable_lesson":"抢占道义、法理、正统的制高点，借被广泛承认的名义行事，使自己师出有名——但权谋色彩重、须客观看待。","source_tier":"secondary","source_note":"曹操迎汉献帝为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["caocao"],"tags":["竞争博弈","组织管理"],"advisor_id":"caocao"}', '8b955fb352e62a23fb46ec62ca1434215573d1f16e1403b95a8e010b5991c1c5');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('caocao-c4', 'caocao', '「割发代首」·赏罚分明令行禁止（行军途中）', '军令如何对所有人（包括主帅）一视同仁。', '曹操曾下令行军不得践踏麦田，自己的马受惊踏了麦田，他便"割发代首"自罚，以示法度对自己也一视同仁。', '曹操以严明法度（含自罚）治军，令行禁止（虽"割发代首"也含权变色彩）。', '以严明法度、赏罚分明治理，规则面前包括自己一视同仁、令行禁止。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"caocao-c4","status":"published","title_period":"「割发代首」·赏罚分明令行禁止（行军途中）","dilemma_constraints":"军令如何对所有人（包括主帅）一视同仁。","key_judgment":"曹操曾下令行军不得践踏麦田，自己的马受惊踏了麦田，他便\"割发代首\"自罚，以示法度对自己也一视同仁。","model_invoked":["赏罚分明令行禁止"],"outcome":"曹操以严明法度（含自罚）治军，令行禁止（虽\"割发代首\"也含权变色彩）。","transferable_lesson":"以严明法度、赏罚分明治理，规则面前包括自己一视同仁、令行禁止。","source_tier":"secondary","source_note":"「割发代首」载于《曹瞒传》等、流传甚广但史源可靠性有争议→存疑（二手B，故事性强）。","historicity":"disputed","linked_cards":["caocao"],"tags":["组织管理"],"advisor_id":"caocao"}', '4ff404cabc0d800e28837c994434fcf005ffc2d93a7438097256bedb4391b3a9');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lijing-c1', 'lijing', '论奇正相生·奇正相生（《李卫公问对》）', '如何把孙子"奇正"的原理讲透、用活。', '李靖在《问对》中精微地展开"奇正相生、循环无端"——以正合、以奇胜，且奇正相互转化、变化无穷，使敌莫测。', '《问对》对奇正的辨析成为中国兵学的经典，深化了孙子。', '别把常规与奇招割裂固定——让二者相互转化、循环无穷，使对手摸不透。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lijing-c1","status":"published","title_period":"论奇正相生·奇正相生（《李卫公问对》）","dilemma_constraints":"如何把孙子\"奇正\"的原理讲透、用活。","key_judgment":"李靖在《问对》中精微地展开\"奇正相生、循环无端\"——以正合、以奇胜，且奇正相互转化、变化无穷，使敌莫测。","model_invoked":["奇正相生"],"outcome":"《问对》对奇正的辨析成为中国兵学的经典，深化了孙子。","transferable_lesson":"别把常规与奇招割裂固定——让二者相互转化、循环无穷，使对手摸不透。","source_tier":"primary","source_note":"论奇正相生为《李卫公问对》→确证（一手A；《问对》传世，少数学者疑其成书，主流视为李靖兵学）。","historicity":"confirmed","linked_cards":["lijing"],"tags":["竞争博弈"],"advisor_id":"lijing"}', '5df0b9e90a513e5bb66a931adb4df7977f29df0f378792efa6f64fd7f6a82ae4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lijing-c2', 'lijing', '论虚实·避实击虚（《李卫公问对》）', '力量应当用在何处。', '李靖深谙孙子"避实而击虚"，主张集中力量打击敌人空虚、薄弱、无备之处，避其坚实。', '避实击虚成为李靖用兵的核心原则之一。', '别正面硬撼最坚实处——集中力量打击空虚、薄弱、无备之处，用强点打弱点。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lijing-c2","status":"published","title_period":"论虚实·避实击虚（《李卫公问对》）","dilemma_constraints":"力量应当用在何处。","key_judgment":"李靖深谙孙子\"避实而击虚\"，主张集中力量打击敌人空虚、薄弱、无备之处，避其坚实。","model_invoked":["避实击虚"],"outcome":"避实击虚成为李靖用兵的核心原则之一。","transferable_lesson":"别正面硬撼最坚实处——集中力量打击空虚、薄弱、无备之处，用强点打弱点。","source_tier":"primary","source_note":"论虚实为《李卫公问对》→确证（一手A）。","historicity":"confirmed","linked_cards":["lijing"],"tags":["竞争博弈","组织管理"],"advisor_id":"lijing"}', '95ff624d0760cbfad5876604b6f15819768b517d96063fdb879d1208852aebd0');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lijing-c3', 'lijing', '平萧铣、定突厥·料敌于先、因情用兵（唐初战争）', '实战中如何以充分的研判与灵活的用兵取胜。', '李靖平萧铣（趁江水暴涨出其不意）、奇袭东突厥（雪夜袭定襄），均以充分料敌、因情用兵、出其不意取胜。', '李靖为唐朝平定南方、击灭东突厥，战功赫赫。', '战前充分研判、先胜而后求战，并根据具体情境灵活用兵、出其不意。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lijing-c3","status":"published","title_period":"平萧铣、定突厥·料敌于先、因情用兵（唐初战争）","dilemma_constraints":"实战中如何以充分的研判与灵活的用兵取胜。","key_judgment":"李靖平萧铣（趁江水暴涨出其不意）、奇袭东突厥（雪夜袭定襄），均以充分料敌、因情用兵、出其不意取胜。","model_invoked":["料敌于先·庙算先胜"],"outcome":"李靖为唐朝平定南方、击灭东突厥，战功赫赫。","transferable_lesson":"战前充分研判、先胜而后求战，并根据具体情境灵活用兵、出其不意。","source_tier":"secondary","source_note":"李靖平萧铣、灭东突厥为《旧唐书》载→确证（二手B）。","historicity":"confirmed","linked_cards":["lijing"],"tags":["竞争博弈","危机应对"],"advisor_id":"lijing"}', 'c62b1b6e3ad390ce4e152f0ca0d14524edea98276f333dfaa214811ab4255e73');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lijing-c4', 'lijing', '雪夜奇袭定襄·示形动敌（630灭东突厥）', '如何出其不意地击破强敌。', '李靖趁东突厥麻痹松懈，以精骑雪夜奇袭定襄，出其不意、一举击破，体现示形（使敌松懈）、动敌、奇袭。', '雪夜奇袭定襄大获成功，加速了东突厥的灭亡。', '主动制造对手的松懈与误判、出其不意地行动、掌握主动——但诡道用不当会反受其害。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lijing-c4","status":"published","title_period":"雪夜奇袭定襄·示形动敌（630灭东突厥）","dilemma_constraints":"如何出其不意地击破强敌。","key_judgment":"李靖趁东突厥麻痹松懈，以精骑雪夜奇袭定襄，出其不意、一举击破，体现示形（使敌松懈）、动敌、奇袭。","model_invoked":["示形动敌"],"outcome":"雪夜奇袭定襄大获成功，加速了东突厥的灭亡。","transferable_lesson":"主动制造对手的松懈与误判、出其不意地行动、掌握主动——但诡道用不当会反受其害。","source_tier":"secondary","source_note":"雪夜奇袭定襄为《旧唐书》载→确证（二手B）。","historicity":"confirmed","linked_cards":["lijing"],"tags":["竞争博弈","危机应对"],"advisor_id":"lijing"}', '4554a8165329dc52297835094f48eec6474ad1b4fc7068c06b2fa649204e2fb5');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('moltke-c1', 'moltke', '打造普鲁士总参谋部·总参谋部制度（19世纪中）', '工业时代的大规模战争，远超个人统帅所能掌控。', '毛奇把普鲁士总参谋部建成现代军事指挥的核心——一批专业参谋负责研究、计划、推演、动员与后勤，使指挥科学化、制度化。', '普鲁士总参谋部成为现代军队参谋制度的样板，助普鲁士赢得多场战争。', '别让一切系于个人天才——建立专业的参谋/智囊团队，让决策与执行科学化、制度化。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"moltke-c1","status":"published","title_period":"打造普鲁士总参谋部·总参谋部制度（19世纪中）","dilemma_constraints":"工业时代的大规模战争，远超个人统帅所能掌控。","key_judgment":"毛奇把普鲁士总参谋部建成现代军事指挥的核心——一批专业参谋负责研究、计划、推演、动员与后勤，使指挥科学化、制度化。","model_invoked":["总参谋部制度"],"outcome":"普鲁士总参谋部成为现代军队参谋制度的样板，助普鲁士赢得多场战争。","transferable_lesson":"别让一切系于个人天才——建立专业的参谋/智囊团队，让决策与执行科学化、制度化。","source_tier":"secondary","source_note":"毛奇建设普鲁士总参谋部为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["moltke"],"tags":["组织管理","长期规划"],"advisor_id":"moltke"}', 'c9ef8dc844f18d29b037ac6ff3b26dae7292bfc6fc50619d53ad2b20b3f8df94');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('moltke-c2', 'moltke', '推行任务式指挥·任务式指挥（普鲁士军事改革）', '大规模、快速变化的战场，事事请示会贻误战机。', '毛奇推行"任务式指挥（Auftragstaktik）"——上级只下达目标与意图，把"怎么做"的决断权下放给前线，让最了解情况的人临机决断。', '任务式指挥成为现代军事指挥的重要原则，也影响了现代管理（授权）。', '上级只明确目标与意图，把"具体怎么做"的决断权下放给最了解一线情况的人——但须以下级的素质与训练为前提。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"moltke-c2","status":"published","title_period":"推行任务式指挥·任务式指挥（普鲁士军事改革）","dilemma_constraints":"大规模、快速变化的战场，事事请示会贻误战机。","key_judgment":"毛奇推行\"任务式指挥（Auftragstaktik）\"——上级只下达目标与意图，把\"怎么做\"的决断权下放给前线，让最了解情况的人临机决断。","model_invoked":["任务式指挥"],"outcome":"任务式指挥成为现代军事指挥的重要原则，也影响了现代管理（授权）。","transferable_lesson":"上级只明确目标与意图，把\"具体怎么做\"的决断权下放给最了解一线情况的人——但须以下级的素质与训练为前提。","source_tier":"secondary","source_note":"毛奇推行任务式指挥为史述→确证（二手B）。","historicity":"confirmed","linked_cards":["moltke"],"tags":["组织管理","竞争博弈"],"advisor_id":"moltke"}', 'a86a24a29c1bd32add4e1e74bcd221e0328a2700b7b9f86b605c27fff870af5a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('moltke-c3', 'moltke', '率先用铁路快速动员·用好新技术（普奥、普法战争）', '如何把分散的军队快速集结到战场。', '毛奇率先把铁路系统地用于军队的快速动员与集结、用电报指挥，把工业时代的新技术纳入战争。', '普鲁士凭借铁路动员的速度优势，在普奥、普法战争中抢得先机。', '率先把时代的新技术（铁路、电报）系统纳入运作——用新技术解决动员、协调、速度，获得对手没有的优势。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"moltke-c3","status":"published","title_period":"率先用铁路快速动员·用好新技术（普奥、普法战争）","dilemma_constraints":"如何把分散的军队快速集结到战场。","key_judgment":"毛奇率先把铁路系统地用于军队的快速动员与集结、用电报指挥，把工业时代的新技术纳入战争。","model_invoked":["用好新技术"],"outcome":"普鲁士凭借铁路动员的速度优势，在普奥、普法战争中抢得先机。","transferable_lesson":"率先把时代的新技术（铁路、电报）系统纳入运作——用新技术解决动员、协调、速度，获得对手没有的优势。","source_tier":"secondary","source_note":"毛奇率先用铁路动员为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["moltke"],"tags":["竞争博弈","组织管理"],"advisor_id":"moltke"}', '7a4c432a21870d69bf9066e2ced9e8439fb7647f04a7b205da9c41d4c3995cf5');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('moltke-c4', 'moltke', '色当会战·分进合击（1870普法战争）', '如何以分散的部队对法军形成合围。', '毛奇以"分进合击"——各部分散行军机动，在色当会合、形成合围，一举围歼法军主力、俘虏拿破仑三世。', '色当会战大获全胜，是分进合击的经典战例（但其成功依赖可靠的协调）。', '分散行动以保持灵活与速度、在关键的时间地点会合形成合力——但须以可靠的协调与通讯为前提。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"moltke-c4","status":"published","title_period":"色当会战·分进合击（1870普法战争）","dilemma_constraints":"如何以分散的部队对法军形成合围。","key_judgment":"毛奇以\"分进合击\"——各部分散行军机动，在色当会合、形成合围，一举围歼法军主力、俘虏拿破仑三世。","model_invoked":["分进合击"],"outcome":"色当会战大获全胜，是分进合击的经典战例（但其成功依赖可靠的协调）。","transferable_lesson":"分散行动以保持灵活与速度、在关键的时间地点会合形成合力——但须以可靠的协调与通讯为前提。","source_tier":"secondary","source_note":"色当会战的分进合击为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["moltke"],"tags":["竞争博弈","危机应对"],"advisor_id":"moltke"}', '1e3b1b1f37d227578236d2a4a2d323541b09ec213d0de525a143e93efab2d18d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hannibal-c1', 'hannibal', '坎尼会战·双重包围全歼罗马军（前216）', '面对兵力占优的罗马大军(约八万)，须以少胜多且求歼灭而非击溃。', '（据古典史家）以中央新月阵故意示弱后撤、诱罗马军深入，两翼步兵与优势骑兵合拢，对罗马军实施双重包围。', '罗马军遭近乎全歼(伤亡数万)，坎尼成为军事史上"包围歼灭战"的永恒范例，被后世反复研究。', '当目标是彻底解决而非暂时击退时，用"中央示弱诱敌深入、两翼合围"把对手的兵力优势变成被包饺子的劣势。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"hannibal-c1","status":"published","title_period":"坎尼会战·双重包围全歼罗马军（前216）","dilemma_constraints":"面对兵力占优的罗马大军(约八万)，须以少胜多且求歼灭而非击溃。","key_judgment":"（据古典史家）以中央新月阵故意示弱后撤、诱罗马军深入，两翼步兵与优势骑兵合拢，对罗马军实施双重包围。","model_invoked":["包围歼灭"],"outcome":"罗马军遭近乎全歼(伤亡数万)，坎尼成为军事史上\"包围歼灭战\"的永恒范例，被后世反复研究。","transferable_lesson":"当目标是彻底解决而非暂时击退时，用\"中央示弱诱敌深入、两翼合围\"把对手的兵力优势变成被包饺子的劣势。","source_tier":"secondary","source_note":"坎尼会战为信史(B，罗马惨败有多源记载)；惟汉尼拔个人战术布置细节出波利比乌斯/李维等后世史家(且李维为罗马方)，含解读与塑造，按\"个人指挥非一手记载→historicity存疑\"判例标存疑——与韩信《史记》一手→确证对照。","historicity":"disputed","linked_cards":["hannibal"],"tags":["战略","竞争博弈"],"advisor_id":"hannibal"}', '321048dd34191f0a9647d93bc80799301bf5dcbd074f1499719ea38bbb51ca9e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hannibal-c2', 'hannibal', '翻越阿尔卑斯·奇袭意大利（前218）', '罗马海陆占优、严防常规进攻路线；如何把战火烧到罗马本土。', '（据古典史家）率大军、辎重与战象翻越被认为不可逾越的阿尔卑斯山，从罗马毫无防备的北方突入意大利。', '虽翻山损失惨重，却以战略奇袭突入意大利本土、夺得战争主动，连战连捷。', '走对手判定"绝无可能"的路线，代价巨大但能换来对方完全没有防备的战略主动——奇袭的价值常抵得过沿途的惨重损耗。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"hannibal-c2","status":"published","title_period":"翻越阿尔卑斯·奇袭意大利（前218）","dilemma_constraints":"罗马海陆占优、严防常规进攻路线；如何把战火烧到罗马本土。","key_judgment":"（据古典史家）率大军、辎重与战象翻越被认为不可逾越的阿尔卑斯山，从罗马毫无防备的北方突入意大利。","model_invoked":["出敌意料的战略机动"],"outcome":"虽翻山损失惨重，却以战略奇袭突入意大利本土、夺得战争主动，连战连捷。","transferable_lesson":"走对手判定\"绝无可能\"的路线，代价巨大但能换来对方完全没有防备的战略主动——奇袭的价值常抵得过沿途的惨重损耗。","source_tier":"secondary","source_note":"翻越阿尔卑斯入意大利为信史(B)；具体路线、损失数字、战象数目古典史家记载不一、含传奇放大，按非一手判存疑，事件主干确证、细节存疑。","historicity":"disputed","linked_cards":["hannibal"],"tags":["战略","危机应对"],"advisor_id":"hannibal"}', '9b355b6363b40b13210837e9d28f8e1bc682e7e4ef2402278e2e8bc75d6f29f8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hannibal-c3', 'hannibal', '扎马会战败于西庇阿·战略困局显现（前202）', '罗马改采费边持久消耗、并由西庇阿反攻迦太基本土，汉尼拔被召回本土决战。', '（消极判例）擅长的决战包围战法在西庇阿(师其法而改良)与罗马骑兵优势前失效；本国后援与战略支撑不足。', '扎马战败，第二次布匿战争迦太基失败——战役全胜者输掉了整场战争。', '战役层面的连胜，弥补不了战略与后方的系统性短板；当对手学会你的打法、又不跟你决战时，单一战术天才会被整体实力拖垮。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"hannibal-c3","status":"published","title_period":"扎马会战败于西庇阿·战略困局显现（前202）","dilemma_constraints":"罗马改采费边持久消耗、并由西庇阿反攻迦太基本土，汉尼拔被召回本土决战。","key_judgment":"（消极判例）擅长的决战包围战法在西庇阿(师其法而改良)与罗马骑兵优势前失效；本国后援与战略支撑不足。","model_invoked":["包围歼灭"],"outcome":"扎马战败，第二次布匿战争迦太基失败——战役全胜者输掉了整场战争。","transferable_lesson":"战役层面的连胜，弥补不了战略与后方的系统性短板；当对手学会你的打法、又不跟你决战时，单一战术天才会被整体实力拖垮。","source_tier":"secondary","source_note":"扎马会战与迦太基战败为信史(B)；个人战术细节出后世史家，按非一手判存疑；结局(战败)确证。本条作其\"战役天才/战略困局\"盲区的案例体现。","historicity":"disputed","linked_cards":["hannibal"],"tags":["战略","危机应对"],"advisor_id":"hannibal"}', 'c56d1b52abf7026377974a2cfb9c95ec4641ce240bb9ccfb56f2077c04e56172');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hanxin-c1', 'hanxin', '井陉之战·背水一战（汉高祖三年，前204）', '率新募之兵数万，越井陉狭道攻赵二十万守军，地形与兵力皆极不利。', '夜遣两千轻骑持赤帜抄赵空营换旗断后；万人背水列阵诱赵倾巢而出；正奇夹击。', '大破赵军、斩陈馀、擒赵王歇，以万余劣势兵力胜二十万，名震天下。', '兵力悬殊时，用"违反常识但精确设计的绝境"逼出己方死战、麻痹对手轻敌，再以奇兵抄其空虚——劣势可被结构设计逆转。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hanxin-c1","status":"published","title_period":"井陉之战·背水一战（汉高祖三年，前204）","dilemma_constraints":"率新募之兵数万，越井陉狭道攻赵二十万守军，地形与兵力皆极不利。","key_judgment":"夜遣两千轻骑持赤帜抄赵空营换旗断后；万人背水列阵诱赵倾巢而出；正奇夹击。","model_invoked":["奇正并用·背水设伏"],"outcome":"大破赵军、斩陈馀、擒赵王歇，以万余劣势兵力胜二十万，名震天下。","transferable_lesson":"兵力悬殊时，用\"违反常识但精确设计的绝境\"逼出己方死战、麻痹对手轻敌，再以奇兵抄其空虚——劣势可被结构设计逆转。","source_tier":"primary","source_note":"《史记·淮阴侯列传》详载韩信个人指挥与战后自释，一手(A)、historicity确证——此为\"个人指挥角色有可靠一手记载→确证\"，区别于亚历山大/汉尼拔等依赖后世史家追述者。","historicity":"confirmed","linked_cards":["hanxin"],"tags":["战略","竞争博弈"],"advisor_id":"hanxin"}', 'ebbed81ebffe10df01c5d6d200dc53d87391c86ceba56a65b7099a9bf835c5b5');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hanxin-c2', 'hanxin', '暗度陈仓·还定三秦（汉元年，前206）', '刘邦被封汉中、栈道已烧，欲东出争天下而无明路，章邯等三秦王扼守。', '（传统归于韩信之谋）明修栈道以示无东出之意、麻痹对手，暗中绕道陈仓奇袭，出其不意还定三秦。', '汉军迅速平定三秦，取得东出争霸的根据地。', '用一个显眼而缓慢的"正面动作"吸引对手注意，真正的主力从它毫无防备的方向切入。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"hanxin-c2","status":"published","title_period":"暗度陈仓·还定三秦（汉元年，前206）","dilemma_constraints":"刘邦被封汉中、栈道已烧，欲东出争天下而无明路，章邯等三秦王扼守。","key_judgment":"（传统归于韩信之谋）明修栈道以示无东出之意、麻痹对手，暗中绕道陈仓奇袭，出其不意还定三秦。","model_invoked":["避实击虚·攻其无备"],"outcome":"汉军迅速平定三秦，取得东出争霸的根据地。","transferable_lesson":"用一个显眼而缓慢的\"正面动作\"吸引对手注意，真正的主力从它毫无防备的方向切入。","source_tier":"secondary","source_note":"还定三秦为信史(B)；惟\"明修栈道、暗度陈仓\"作为韩信个人具体谋略的精确归属，史载不如井陉详确、含后世戏剧化，按二轴判存疑；事件确证、计谋归属存疑，呈现宜加\"传为韩信之谋\"。","historicity":"disputed","linked_cards":["hanxin"],"tags":["战略","竞争博弈"],"advisor_id":"hanxin"}', 'ce5eecf356c210a90fe78150501f71acf6f0018dbfb153936b29aa393dde4771');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hanxin-c3', 'hanxin', '潍水之战·囊沙半渡击龙且（汉高祖四年，前203）', '与楚将龙且、齐军隔潍水对峙，楚军兵众且轻敌。', '命人以万余沙囊壅塞上游断流，引龙且半渡来追时决堤放水，将楚军拦腰冲断、半渡而击。', '龙且战死、齐楚联军大败，韩信平齐，奠定其"功高"地位。', '制造一个对手看不见的变量(上游断流)，诱其在你预设的不利时刻(半渡)行动，再一举倾覆。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hanxin-c3","status":"published","title_period":"潍水之战·囊沙半渡击龙且（汉高祖四年，前203）","dilemma_constraints":"与楚将龙且、齐军隔潍水对峙，楚军兵众且轻敌。","key_judgment":"命人以万余沙囊壅塞上游断流，引龙且半渡来追时决堤放水，将楚军拦腰冲断、半渡而击。","model_invoked":["避实击虚·攻其无备"],"outcome":"龙且战死、齐楚联军大败，韩信平齐，奠定其\"功高\"地位。","transferable_lesson":"制造一个对手看不见的变量(上游断流)，诱其在你预设的不利时刻(半渡)行动，再一举倾覆。","source_tier":"primary","source_note":"《史记》详载韩信潍水之谋与指挥，一手(A)、historicity确证。","historicity":"confirmed","linked_cards":["hanxin"],"tags":["战略","危机应对"],"advisor_id":"hanxin"}', '2132602c0ff03922ef89a53b1cd45bdcd0d42b92b8f3d1ea2fbe55ff7f3120ce');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('hanxin-c4', 'hanxin', '功高不善自处·终遭诱杀（汉高祖十一年，前196）', '灭楚后功高震主，由楚王贬淮阴侯、被疑谋反；在君臣猜忌中进退失据。', '（消极判例）军事上算无遗策，政治上却在"反与不反"间犹豫、又轻信入宫，终被吕后与萧何诱入长乐宫钟室。', '被吕后诱杀于长乐宫钟室，夷三族；"成也萧何，败也萧何""兔死狗烹"由此而来。', '一个领域的极致天才，可能在另一个领域(政治/人际)极度幼稚；能算赢所有的仗，未必算得清自己的处境。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"hanxin-c4","status":"published","title_period":"功高不善自处·终遭诱杀（汉高祖十一年，前196）","dilemma_constraints":"灭楚后功高震主，由楚王贬淮阴侯、被疑谋反；在君臣猜忌中进退失据。","key_judgment":"（消极判例）军事上算无遗策，政治上却在\"反与不反\"间犹豫、又轻信入宫，终被吕后与萧何诱入长乐宫钟室。","model_invoked":["置之死地而后生"],"outcome":"被吕后诱杀于长乐宫钟室，夷三族；\"成也萧何，败也萧何\"\"兔死狗烹\"由此而来。","transferable_lesson":"一个领域的极致天才，可能在另一个领域(政治/人际)极度幼稚；能算赢所有的仗，未必算得清自己的处境。","source_tier":"primary","source_note":"《史记》载其结局，一手(A)、确证；\"反状\"之有无史家有议，但被诱杀于钟室、夷族之结局为确证，本条作其\"军事天才/政治幼稚\"盲区的案例体现。","historicity":"confirmed","linked_cards":["hanxin"],"tags":["危机应对","人际关系"],"advisor_id":"hanxin"}', '6b691c15a525d92f0655bf504090f127f00bce100dabec370bf002a962800f2f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('keynes-c1', 'keynes', '「选美比赛」之喻·选美理论（《通论》1936）', '如何理解由大众预期驱动的金融市场。', '凯恩斯以报纸"选美比赛"作喻——参赛者要赢，选的不是自己认为最美的，而是大家认为大家会选的，揭示市场是"预测大众的预测"。', '「选美理论」成为理解市场心理与博弈的经典洞见。', '在大众博弈里，赢的关键是判断"大多数人会认为什么是好的"，即预测大众的预测——但易陷入无穷猜测。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"keynes-c1","status":"published","title_period":"「选美比赛」之喻·选美理论（《通论》1936）","dilemma_constraints":"如何理解由大众预期驱动的金融市场。","key_judgment":"凯恩斯以报纸\"选美比赛\"作喻——参赛者要赢，选的不是自己认为最美的，而是大家认为大家会选的，揭示市场是\"预测大众的预测\"。","model_invoked":["选美理论"],"outcome":"「选美理论」成为理解市场心理与博弈的经典洞见。","transferable_lesson":"在大众博弈里，赢的关键是判断\"大多数人会认为什么是好的\"，即预测大众的预测——但易陷入无穷猜测。","source_tier":"primary","source_note":"「选美比赛」之喻为凯恩斯《通论》→确证（一手A）。","historicity":"confirmed","linked_cards":["keynes"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"keynes"}', '186b03a25482ffbd013400751654aaa1acb0d3f28fa3ff85a0ca2ab0cb279db5');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('keynes-c2', 'keynes', '后期转向逆向价值投资·逆向投资（1930s）', '面对市场的恐慌与狂热，如何取舍。', '凯恩斯后期转向逆向、价值导向——在大众悲观时买入、狂热时谨慎，独立于群众情绪。', '凯恩斯后期的逆向价值投资取得了远好于早期投机的回报。', '大众恐慌时找机会、狂热时谨慎，敢于与群众的情绪反向。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"keynes-c2","status":"published","title_period":"后期转向逆向价值投资·逆向投资（1930s）","dilemma_constraints":"面对市场的恐慌与狂热，如何取舍。","key_judgment":"凯恩斯后期转向逆向、价值导向——在大众悲观时买入、狂热时谨慎，独立于群众情绪。","model_invoked":["逆向投资"],"outcome":"凯恩斯后期的逆向价值投资取得了远好于早期投机的回报。","transferable_lesson":"大众恐慌时找机会、狂热时谨慎，敢于与群众的情绪反向。","source_tier":"secondary","source_note":"凯恩斯后期逆向价值投资为投资史记述→确证（二手B）。","historicity":"confirmed","linked_cards":["keynes"],"tags":["投资"],"advisor_id":"keynes"}', 'ce566d6ee57ca3a382b6deb823a3283997b76c6e8db23e7fb6418b75960cc42f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('keynes-c3', 'keynes', '集中投资少数股票·能力圈集中持有（1930s—40s）', '资金应分散还是集中。', '凯恩斯后期主张并实践集中投资——把资金集中到少数自己深入了解、有把握的股票上、长期持有。', '凯恩斯管理的剑桥国王学院基金以集中投资取得了出色的长期回报。', '集中投到你真正了解、有把握的少数标的上、长期持有，而非盲目分散——但集中放大波动。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"keynes-c3","status":"published","title_period":"集中投资少数股票·能力圈集中持有（1930s—40s）","dilemma_constraints":"资金应分散还是集中。","key_judgment":"凯恩斯后期主张并实践集中投资——把资金集中到少数自己深入了解、有把握的股票上、长期持有。","model_invoked":["能力圈集中持有"],"outcome":"凯恩斯管理的剑桥国王学院基金以集中投资取得了出色的长期回报。","transferable_lesson":"集中投到你真正了解、有把握的少数标的上、长期持有，而非盲目分散——但集中放大波动。","source_tier":"secondary","source_note":"凯恩斯后期集中投资为投资史记述→确证（二手B）。","historicity":"confirmed","linked_cards":["keynes"],"tags":["投资"],"advisor_id":"keynes"}', 'a750d41382a72010ecea40785aecc15d9042b65ca6702cc3c66d6c9c3c36137f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('keynes-c4', 'keynes', '早期投机巨亏、几近破产·教训（1920s）', '凯恩斯早期热衷宏观择时与货币、商品投机。', '凯恩斯早期凭宏观判断做货币与商品投机，曾遭巨亏、几近破产，惨痛教训促使他后期转向集中价值投资。', '早期投机的失败让凯恩斯深刻认识到市场的非理性（动物精神）与择时之难，转向更稳健的路线。', '承认市场由"动物精神"驱动、择时极难——投机路线高风险，凯恩斯本人的巨亏就是教训。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"keynes-c4","status":"published","title_period":"早期投机巨亏、几近破产·教训（1920s）","dilemma_constraints":"凯恩斯早期热衷宏观择时与货币、商品投机。","key_judgment":"凯恩斯早期凭宏观判断做货币与商品投机，曾遭巨亏、几近破产，惨痛教训促使他后期转向集中价值投资。","model_invoked":["承认动物精神"],"outcome":"早期投机的失败让凯恩斯深刻认识到市场的非理性（动物精神）与择时之难，转向更稳健的路线。","transferable_lesson":"承认市场由\"动物精神\"驱动、择时极难——投机路线高风险，凯恩斯本人的巨亏就是教训。","source_tier":"secondary","source_note":"凯恩斯早期投机巨亏为投资史记述→确证（二手B）。","historicity":"confirmed","linked_cards":["keynes"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"keynes"}', 'a27168b8d86551f7aae79261bdba7a87566c7bcf8b0c5da504a769a9ef76e4c9');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('livermore-c1', 'livermore', '1929年大崩盘前做空·顺势而为、市场心理（1929）', '1929年市场狂热到极点，多数人沉醉于牛市。', '利弗莫尔读懂了极度贪婪后的危险、顺着即将逆转的大势提前大举做空，在1929年大崩盘中获利据称达上亿美元。', '利弗莫尔在1929年崩盘中达到其交易生涯的巅峰、获利巨大。', '读懂大众情绪、在极度贪婪后顺着逆转的大势做、别逆势硬扛——但这要极高的判断与纪律。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"livermore-c1","status":"published","title_period":"1929年大崩盘前做空·顺势而为、市场心理（1929）","dilemma_constraints":"1929年市场狂热到极点，多数人沉醉于牛市。","key_judgment":"利弗莫尔读懂了极度贪婪后的危险、顺着即将逆转的大势提前大举做空，在1929年大崩盘中获利据称达上亿美元。","model_invoked":["顺势而为"],"outcome":"利弗莫尔在1929年崩盘中达到其交易生涯的巅峰、获利巨大。","transferable_lesson":"读懂大众情绪、在极度贪婪后顺着逆转的大势做、别逆势硬扛——但这要极高的判断与纪律。","source_tier":"secondary","source_note":"利弗莫尔1929年做空获利为投资史记述→确证（二手B；具体获利数额有不同说法）。","historicity":"confirmed","linked_cards":["livermore"],"tags":["投资","竞争博弈"],"advisor_id":"livermore"}', 'ca81a5720192afc1eafd4ff51e060ea0cba01d5f175deb110a010da4ab374828');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('livermore-c2', 'livermore', '「截断亏损、让利润奔跑」·交易铁律（利弗莫尔交易观）', '交易中如何处理亏损与盈利。', '利弗莫尔一生奉行"截断亏损、让利润奔跑"——做错果断止损、绝不摊平，做对让利润奔跑。', '这条铁律成为交易风控的金科玉律，被无数交易者奉为圭臬。', '做错果断止损、绝不死扛摊平；做对让利润奔跑——而非扛着亏损、却兑现微利。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"livermore-c2","status":"published","title_period":"「截断亏损、让利润奔跑」·交易铁律（利弗莫尔交易观）","dilemma_constraints":"交易中如何处理亏损与盈利。","key_judgment":"利弗莫尔一生奉行\"截断亏损、让利润奔跑\"——做错果断止损、绝不摊平，做对让利润奔跑。","model_invoked":["截断亏损让利润奔跑"],"outcome":"这条铁律成为交易风控的金科玉律，被无数交易者奉为圭臬。","transferable_lesson":"做错果断止损、绝不死扛摊平；做对让利润奔跑——而非扛着亏损、却兑现微利。","source_tier":"primary","source_note":"「截断亏损、让利润奔跑」为利弗莫尔交易思想→确证（一手/二手A/B）。","historicity":"confirmed","linked_cards":["livermore"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"livermore"}', '2875cca8732acef42059d76a3e4d5f7bab461f58e4b53eb68fb3aecce126ab85');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('livermore-c3', 'livermore', '「赚大钱靠等待」·等待关键点（利弗莫尔交易观）', '交易者总有频繁出手的冲动。', '利弗莫尔强调赚大钱"靠的是等待"——大部分时间按兵不动，只在确认的"关键点"重仓出击。', '「赚大钱靠等待」成为交易耐心与时机的经典训诫。', '别频繁冲动行动，耐心等待真正确认的"关键时机"（信号明确、胜率高）才重手出击。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"livermore-c3","status":"published","title_period":"「赚大钱靠等待」·等待关键点（利弗莫尔交易观）","dilemma_constraints":"交易者总有频繁出手的冲动。","key_judgment":"利弗莫尔强调赚大钱\"靠的是等待\"——大部分时间按兵不动，只在确认的\"关键点\"重仓出击。","model_invoked":["等待关键点"],"outcome":"「赚大钱靠等待」成为交易耐心与时机的经典训诫。","transferable_lesson":"别频繁冲动行动，耐心等待真正确认的\"关键时机\"（信号明确、胜率高）才重手出击。","source_tier":"primary","source_note":"「赚大钱靠等待」为利弗莫尔交易思想→确证（一手/二手A/B）。","historicity":"confirmed","linked_cards":["livermore"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"livermore"}', '186d080ae23baee7be25a0f5bf72c5e7e99f57707ca76c9915b0c4525a85a08a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('livermore-c4', 'livermore', '数次大起大落·投机的高风险（其交易生涯）', '投机的回报与风险并存。', '利弗莫尔一生数次赚得巨富、又数次破产——他的天才与他的破产同样说明：投机/杠杆的回报极高、风险也极高。', '利弗莫尔数次大起大落、晚年潦倒、结局令人唏嘘——再高的技巧也保证不了长久的平安。', '投机/杠杆即使对顶尖高手也是高风险——纪律与风控是命门，对普通人风险极大、须极度审慎。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"livermore-c4","status":"published","title_period":"数次大起大落·投机的高风险（其交易生涯）","dilemma_constraints":"投机的回报与风险并存。","key_judgment":"利弗莫尔一生数次赚得巨富、又数次破产——他的天才与他的破产同样说明：投机/杠杆的回报极高、风险也极高。","model_invoked":["截断亏损让利润奔跑"],"outcome":"利弗莫尔数次大起大落、晚年潦倒、结局令人唏嘘——再高的技巧也保证不了长久的平安。","transferable_lesson":"投机/杠杆即使对顶尖高手也是高风险——纪律与风控是命门，对普通人风险极大、须极度审慎。","source_tier":"secondary","source_note":"利弗莫尔数次破产、晚年潦倒为史实→确证（二手B；个人结局点到为止、不渲染）。","historicity":"confirmed","linked_cards":["livermore"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"livermore"}', 'cdf6d477381989b69786f56ef9cab715583c4edc7e294fbebc647c08a0dea0e2');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bogle-c1', 'bogle', '创立低成本指数基金·成本是确定的敌人（1976起）', '主动基金收费高昂、长期多数跑输市场。', '博格创立了第一只面向散户的低成本指数基金，把费率压到极低，靠"省下的费用"长期跑赢多数主动基金。', '低成本指数基金深刻改变了投资业，为普通投资者省下巨额费用。', '成本是唯一确定侵蚀收益的东西——把能控制的成本压到最低，锁定确定的相对优势。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bogle-c1","status":"published","title_period":"创立低成本指数基金·成本是确定的敌人（1976起）","dilemma_constraints":"主动基金收费高昂、长期多数跑输市场。","key_judgment":"博格创立了第一只面向散户的低成本指数基金，把费率压到极低，靠\"省下的费用\"长期跑赢多数主动基金。","model_invoked":["成本是确定的敌人"],"outcome":"低成本指数基金深刻改变了投资业，为普通投资者省下巨额费用。","transferable_lesson":"成本是唯一确定侵蚀收益的东西——把能控制的成本压到最低，锁定确定的相对优势。","source_tier":"primary","source_note":"博格创立低成本指数基金为投资史→确证（一手/二手A/B）。","historicity":"confirmed","linked_cards":["bogle"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"bogle"}', '004e0125ef7c224b707a117a57ad51c1eefda7f0bdc33d76f0e164f6d51b3951');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bogle-c2', 'bogle', '「别找针、买草垛」·买下整个草垛（其理念）', '散户费力选股选基，常挑错还付高费。', '博格主张"别在草垛里找针、买下整个草垛"——与其挑赢家，不如买下整个市场（指数），稳拿平均回报。', '指数化"买草垛"成为被动投资的核心理念，长期赢过多数主动。', '别挑赢家（大概率挑错），直接"买下整个草垛"、拿整体的平均回报。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bogle-c2","status":"published","title_period":"「别找针、买草垛」·买下整个草垛（其理念）","dilemma_constraints":"散户费力选股选基，常挑错还付高费。","key_judgment":"博格主张\"别在草垛里找针、买下整个草垛\"——与其挑赢家，不如买下整个市场（指数），稳拿平均回报。","model_invoked":["买下整个草垛"],"outcome":"指数化\"买草垛\"成为被动投资的核心理念，长期赢过多数主动。","transferable_lesson":"别挑赢家（大概率挑错），直接\"买下整个草垛\"、拿整体的平均回报。","source_tier":"primary","source_note":"博格\"别找针、买草垛\"为其著作→确证（一手A）。","historicity":"confirmed","linked_cards":["bogle"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"bogle"}', '05f039a48a50ccc1bd6237dda891d33d4b4f6f5e85be8fc9e0e15d496c237037');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bogle-c3', 'bogle', '先锋的"共同所有"结构·把客户利益放第一（1974）', '基金公司常把自身利润置于投资者利益之上。', '博格把先锋（Vanguard）设计成由其管理的基金（即投资者）共同所有，把利润以更低费率的形式让给投资者，而非外部股东。', '这一结构使先锋持续降费、赢得投资者信任，但博格本人也因此没有像其他基金巨头那样致富。', '把服务对象的真实利益放在自己牟利之前——长期赢得信任（但也要正视其理想主义的代价）。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bogle-c3","status":"published","title_period":"先锋的\"共同所有\"结构·把客户利益放第一（1974）","dilemma_constraints":"基金公司常把自身利润置于投资者利益之上。","key_judgment":"博格把先锋（Vanguard）设计成由其管理的基金（即投资者）共同所有，把利润以更低费率的形式让给投资者，而非外部股东。","model_invoked":["把客户利益放第一"],"outcome":"这一结构使先锋持续降费、赢得投资者信任，但博格本人也因此没有像其他基金巨头那样致富。","transferable_lesson":"把服务对象的真实利益放在自己牟利之前——长期赢得信任（但也要正视其理想主义的代价）。","source_tier":"primary","source_note":"先锋共同所有结构为公司史→确证（一手/二手A/B）。","historicity":"confirmed","linked_cards":["bogle"],"tags":["投资","价值与伦理"],"advisor_id":"bogle"}', 'bb213c9f2d0b1c9b506b7680348437c37cef3529c31fbb81db46b018d31b12fe');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bogle-c4', 'bogle', '反对频繁交易、倡长期持有·长期复利与坚守（其理念）', '投资者易被短期波动与择时诱惑打乱。', '博格反对频繁交易与择时，倡导买入并长期坚守、相信时间与复利的力量。', '长期坚守的理念帮助无数普通投资者避免了择时与频繁交易的损耗。', '相信时间与复利、买入并长期坚守，别被短期波动与择时打乱节奏。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bogle-c4","status":"published","title_period":"反对频繁交易、倡长期持有·长期复利与坚守（其理念）","dilemma_constraints":"投资者易被短期波动与择时诱惑打乱。","key_judgment":"博格反对频繁交易与择时，倡导买入并长期坚守、相信时间与复利的力量。","model_invoked":["长期复利与坚守"],"outcome":"长期坚守的理念帮助无数普通投资者避免了择时与频繁交易的损耗。","transferable_lesson":"相信时间与复利、买入并长期坚守，别被短期波动与择时打乱节奏。","source_tier":"secondary","source_note":"博格倡长期持有为投资史→确证（二手B）。","historicity":"confirmed","linked_cards":["bogle"],"tags":["投资"],"advisor_id":"bogle"}', 'c56311e51c6d85ded777c0cb552d0ac4b130970b658e2ee46ed655f48c512550');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lynch-c1', 'lynch', '「投资你了解的」·投资你了解的（其投资哲学）', '普通投资者如何与专业机构竞争。', '林奇主张从日常生活、工作、消费中发现好公司——普通人在熟悉的领域常比专家更早发现机会（但仍须做功课）。', '「投资你了解的」成为大众投资者最广为人知的理念之一。', '从你真正了解、有切身体会的领域发现机会——但"了解产品"不等于"了解生意"，仍须做功课。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lynch-c1","status":"published","title_period":"「投资你了解的」·投资你了解的（其投资哲学）","dilemma_constraints":"普通投资者如何与专业机构竞争。","key_judgment":"林奇主张从日常生活、工作、消费中发现好公司——普通人在熟悉的领域常比专家更早发现机会（但仍须做功课）。","model_invoked":["投资你了解的"],"outcome":"「投资你了解的」成为大众投资者最广为人知的理念之一。","transferable_lesson":"从你真正了解、有切身体会的领域发现机会——但\"了解产品\"不等于\"了解生意\"，仍须做功课。","source_tier":"primary","source_note":"「投资你了解的」为林奇著作→确证（一手A）。","historicity":"confirmed","linked_cards":["lynch"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"lynch"}', 'a7a18c83247f8913c5c8c7c768292f697b4e3286167dd91f4c040ff709e7d4c4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lynch-c2', 'lynch', '「合理价格的成长股(GARP)」·成长股与合理价格（其方法）', '只买便宜的、还是只追高成长的。', '林奇找"盈利持续成长、而价格相对其成长性还合理"的公司，用PEG等衡量成长与价格的平衡。', 'GARP成为成长投资的重要方法。', '别只买便宜或只追高成长——找成长且价格相对成长性还合理的公司。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lynch-c2","status":"published","title_period":"「合理价格的成长股(GARP)」·成长股与合理价格（其方法）","dilemma_constraints":"只买便宜的、还是只追高成长的。","key_judgment":"林奇找\"盈利持续成长、而价格相对其成长性还合理\"的公司，用PEG等衡量成长与价格的平衡。","model_invoked":["成长股与合理价格"],"outcome":"GARP成为成长投资的重要方法。","transferable_lesson":"别只买便宜或只追高成长——找成长且价格相对成长性还合理的公司。","source_tier":"primary","source_note":"林奇的GARP为其著作→确证（一手A）。","historicity":"confirmed","linked_cards":["lynch"],"tags":["投资"],"advisor_id":"lynch"}', '87226a1429f6d8ea29dd38726124eccfe767244fb0da38c8bab6a674c572ec20');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lynch-c3', 'lynch', '执掌麦哲伦基金的辉煌业绩·寻找十倍股（1977—1990）', '如何取得超额回报。', '林奇执掌富达麦哲伦基金期间取得了卓越的长期业绩，靠的正是发掘并长期持有大量"十倍股"。', '林奇成为传奇基金经理（麦哲伦基金年化回报极高）。', '找到真正的好公司就敢于长期持有，让"十倍股"充分成长——一两只就能拉动全局。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lynch-c3","status":"published","title_period":"执掌麦哲伦基金的辉煌业绩·寻找十倍股（1977—1990）","dilemma_constraints":"如何取得超额回报。","key_judgment":"林奇执掌富达麦哲伦基金期间取得了卓越的长期业绩，靠的正是发掘并长期持有大量\"十倍股\"。","model_invoked":["寻找十倍股"],"outcome":"林奇成为传奇基金经理（麦哲伦基金年化回报极高）。","transferable_lesson":"找到真正的好公司就敢于长期持有，让\"十倍股\"充分成长——一两只就能拉动全局。","source_tier":"secondary","source_note":"林奇执掌麦哲伦基金的业绩为投资史→确证（二手B；具体数字有不同口径）。","historicity":"confirmed","linked_cards":["lynch"],"tags":["投资"],"advisor_id":"lynch"}', 'f50907c289c30c07d25e6684fb46dcf7b1e9680fc5495949f4c7b3b8ee2cbb43');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lynch-c4', 'lynch', '极勤奋的亲自调研·亲自做功课调研（其工作方式）', '选股靠什么。', '林奇以极勤奋的亲自调研著称——大量研究公司基本面、财报、业务，甚至实地走访，把"故事"核实清楚。', '勤奋的调研是林奇业绩的基石（也说明其方法的高门槛）。', '别只听故事——亲自研究基本面、财报、业务，把事实核实清楚。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lynch-c4","status":"published","title_period":"极勤奋的亲自调研·亲自做功课调研（其工作方式）","dilemma_constraints":"选股靠什么。","key_judgment":"林奇以极勤奋的亲自调研著称——大量研究公司基本面、财报、业务，甚至实地走访，把\"故事\"核实清楚。","model_invoked":["亲自做功课调研"],"outcome":"勤奋的调研是林奇业绩的基石（也说明其方法的高门槛）。","transferable_lesson":"别只听故事——亲自研究基本面、财报、业务，把事实核实清楚。","source_tier":"primary","source_note":"林奇的勤奋调研为其著作及投资史→确证（一手/二手A/B）。","historicity":"confirmed","linked_cards":["lynch"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"lynch"}', '022df00f98accc4a0a0ad73c537bf627a301141054a98b86593f1fe7076aed80');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('soros-c1', 'soros', '「反身性」理论·反身性（《金融炼金术》1987）', '古典经济学假设市场趋向均衡、价格反映基本面，但现实常非如此。', '索罗斯提出"反身性"——参与者的认知与市场现实相互影响、形成自我强化的反馈循环，价格不只反映基本面、还反过来改变基本面。', '「反身性」成为理解金融市场（与社会过程）非均衡、自我强化动态的重要框架。', '在有人参与的系统里，认知与现实相互塑造、形成反身循环——别把认知当被动反映。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"soros-c1","status":"published","title_period":"「反身性」理论·反身性（《金融炼金术》1987）","dilemma_constraints":"古典经济学假设市场趋向均衡、价格反映基本面，但现实常非如此。","key_judgment":"索罗斯提出\"反身性\"——参与者的认知与市场现实相互影响、形成自我强化的反馈循环，价格不只反映基本面、还反过来改变基本面。","model_invoked":["反身性"],"outcome":"「反身性」成为理解金融市场（与社会过程）非均衡、自我强化动态的重要框架。","transferable_lesson":"在有人参与的系统里，认知与现实相互塑造、形成反身循环——别把认知当被动反映。","source_tier":"primary","source_note":"「反身性」为索罗斯《金融炼金术》核心→确证（一手A）。","historicity":"confirmed","linked_cards":["soros"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"soros"}', 'e48afd2a6f116375b372f0e25c21f7d2600bafdf489435d2089e262739b0d9fb');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('soros-c2', 'soros', '1992年狙击英镑·发现并下注于泡沫拐点（1992）', '英镑维持在欧洲汇率机制的高位，但其政策被认为不可持续。', '索罗斯判断英镑被高估、汇率政策将崩，于是高杠杆大举做空英镑，最终迫使英镑退出欧洲汇率机制。', '索罗斯据称获利约十亿美元、被称"打垮英格兰银行的人"（但这是高杠杆、高风险操作）。', '识别远离基本面的趋势、在它即将反转的拐点反向重注——但这是高杠杆、高风险，对普通人风险极大。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"soros-c2","status":"published","title_period":"1992年狙击英镑·发现并下注于泡沫拐点（1992）","dilemma_constraints":"英镑维持在欧洲汇率机制的高位，但其政策被认为不可持续。","key_judgment":"索罗斯判断英镑被高估、汇率政策将崩，于是高杠杆大举做空英镑，最终迫使英镑退出欧洲汇率机制。","model_invoked":["发现并下注于泡沫拐点"],"outcome":"索罗斯据称获利约十亿美元、被称\"打垮英格兰银行的人\"（但这是高杠杆、高风险操作）。","transferable_lesson":"识别远离基本面的趋势、在它即将反转的拐点反向重注——但这是高杠杆、高风险，对普通人风险极大。","source_tier":"secondary","source_note":"1992年索罗斯做空英镑为史实→确证（二手B；获利数额有不同说法）。","historicity":"confirmed","linked_cards":["soros"],"tags":["投资","竞争博弈"],"advisor_id":"soros"}', 'a528e33632e0ec096c0838f4fa34903c8ee5f318e260498e20f398f3e9d6a374');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('soros-c3', 'soros', '「我富有，因为我知道我会错」·可错性（其投资哲学）', '投资者常因不愿承认错误而死扛亏损。', '索罗斯把"承认自己会错、并主动寻找自己的错误"作为投资的核心——一旦发现错了就立刻纠正，绝不为面子死扛。', '「可错性」是索罗斯长期生存与成功的认识论基石。', '始终假设自己可能错、主动找错、错了立刻改——绝不为面子死扛。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"soros-c3","status":"published","title_period":"「我富有，因为我知道我会错」·可错性（其投资哲学）","dilemma_constraints":"投资者常因不愿承认错误而死扛亏损。","key_judgment":"索罗斯把\"承认自己会错、并主动寻找自己的错误\"作为投资的核心——一旦发现错了就立刻纠正，绝不为面子死扛。","model_invoked":["可错性"],"outcome":"「可错性」是索罗斯长期生存与成功的认识论基石。","transferable_lesson":"始终假设自己可能错、主动找错、错了立刻改——绝不为面子死扛。","source_tier":"primary","source_note":"「可错性」为索罗斯公开阐述的投资哲学→确证（一手A）。","historicity":"confirmed","linked_cards":["soros"],"tags":["认知偏误与理性决策","投资"],"advisor_id":"soros"}', '745ac8ddbc4cc932ff3485a6aef72f2823b32f8bc6efedce2260b4a470439e42');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('soros-c4', 'soros', '重大失手与高风险·宏观投机的风险（如1987、1998）', '宏观投机/高杠杆并非稳赚。', '索罗斯亦有过重大失手（如1987年股灾、1998年俄罗斯违约中的损失）——其方法是高风险的，连他本人也会大亏。', '索罗斯的失手说明：宏观投机/高杠杆是高风险的，"错了认赔"的纪律是命门，对普通人风险极大。', '高杠杆宏观投机即使对顶尖高手也是高风险——错了立刻认赔的纪律是命门，普通人须极度审慎。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"soros-c4","status":"published","title_period":"重大失手与高风险·宏观投机的风险（如1987、1998）","dilemma_constraints":"宏观投机/高杠杆并非稳赚。","key_judgment":"索罗斯亦有过重大失手（如1987年股灾、1998年俄罗斯违约中的损失）——其方法是高风险的，连他本人也会大亏。","model_invoked":["错了认赔对了重仓"],"outcome":"索罗斯的失手说明：宏观投机/高杠杆是高风险的，\"错了认赔\"的纪律是命门，对普通人风险极大。","transferable_lesson":"高杠杆宏观投机即使对顶尖高手也是高风险——错了立刻认赔的纪律是命门，普通人须极度审慎。","source_tier":"secondary","source_note":"索罗斯的重大失手为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["soros"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"soros"}', 'af94649aa70c289085d60cf257c237e9b429efd5492e3f8b8bf935932a2f7b04');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('fisher-c1', 'fisher', '以闲聊法调研企业质地（其投资生涯方法）', '财报只反映过去的数字、难以判断一家公司管理层的真实质量、研发后劲与竞争地位等"软质地"。', '费雪系统地向目标公司的客户、供应商、竞争对手乃至离职员工广泛交谈、交叉印证，拼出财报之外的真实质地（即"闲聊法"Scuttlebutt）。', '这套调研法使他能在数字之外识别真正卓越的成长企业，成其选股的核心方法、影响后世成长投资。', '要真正看懂一家公司，别只盯财报——向产业链各方广泛打听、交叉印证，拼出数字背后的真实质地。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"fisher-c1","status":"published","title_period":"以闲聊法调研企业质地（其投资生涯方法）","dilemma_constraints":"财报只反映过去的数字、难以判断一家公司管理层的真实质量、研发后劲与竞争地位等\"软质地\"。","key_judgment":"费雪系统地向目标公司的客户、供应商、竞争对手乃至离职员工广泛交谈、交叉印证，拼出财报之外的真实质地（即\"闲聊法\"Scuttlebutt）。","model_invoked":["闲聊法调研"],"outcome":"这套调研法使他能在数字之外识别真正卓越的成长企业，成其选股的核心方法、影响后世成长投资。","transferable_lesson":"要真正看懂一家公司，别只盯财报——向产业链各方广泛打听、交叉印证，拼出数字背后的真实质地。","source_tier":"primary","source_note":"闲聊法为费雪《怎样选择成长股》明载的核心方法→确证。","historicity":"confirmed","linked_cards":["fisher"],"tags":["投资","风险评估"],"advisor_id":"fisher"}', 'f0417b66f73411c96fddfc99c925aefd598433284ff8674e317aa2804cfe9b71');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('fisher-c2', 'fisher', '长期持有摩托罗拉等卓越成长股（数十年）', '持有期间股价必有起伏、账面利润时现，短期获利了结的诱惑始终存在。', '费雪一旦确认是真正卓越的成长企业（如摩托罗拉），便长期持有数十年、不为短期波动或账面利润而卖出。', '长期复利使其在少数卓越企业上获得巨大回报；"找到卓越就长期持有"成成长投资的核心信条。', '找到真正卓越的成长企业后，最大的错误往往是过早卖出——长期持有、让复利发挥作用。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"fisher-c2","status":"published","title_period":"长期持有摩托罗拉等卓越成长股（数十年）","dilemma_constraints":"持有期间股价必有起伏、账面利润时现，短期获利了结的诱惑始终存在。","key_judgment":"费雪一旦确认是真正卓越的成长企业（如摩托罗拉），便长期持有数十年、不为短期波动或账面利润而卖出。","model_invoked":["长期持有优质成长"],"outcome":"长期复利使其在少数卓越企业上获得巨大回报；\"找到卓越就长期持有\"成成长投资的核心信条。","transferable_lesson":"找到真正卓越的成长企业后，最大的错误往往是过早卖出——长期持有、让复利发挥作用。","source_tier":"primary","source_note":"费雪长期持有摩托罗拉等为其著作与投资生涯所载→确证。","historicity":"confirmed","linked_cards":["fisher"],"tags":["投资","长期规划"],"advisor_id":"fisher"}', '26a022c90ce40f77118dc0b89dbdab5b7b1dcb225d846e9a95a1e8db0a79de83');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('fisher-c3', 'fisher', '集中持有少数深入了解的卓越企业（其组合理念）', '主流观念主张分散以降风险，但过度分散会把对卓越企业的深度认知优势摊薄。', '费雪反对过度分散，主张把资金集中在少数自己真正深入了解的卓越企业上，以深度认知换取超额回报。', '其集中策略在他深度了解的少数卓越企业上放大了回报；成其与"广撒网"截然不同的组合理念。', '与其分散到一堆你并不真正了解的平庸标的，不如把资源集中在少数你真正吃透的卓越对象上——前提是你确实吃得够透。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"fisher-c3","status":"published","title_period":"集中持有少数深入了解的卓越企业（其组合理念）","dilemma_constraints":"主流观念主张分散以降风险，但过度分散会把对卓越企业的深度认知优势摊薄。","key_judgment":"费雪反对过度分散，主张把资金集中在少数自己真正深入了解的卓越企业上，以深度认知换取超额回报。","model_invoked":["集中而非分散"],"outcome":"其集中策略在他深度了解的少数卓越企业上放大了回报；成其与\"广撒网\"截然不同的组合理念。","transferable_lesson":"与其分散到一堆你并不真正了解的平庸标的，不如把资源集中在少数你真正吃透的卓越对象上——前提是你确实吃得够透。","source_tier":"primary","source_note":"费雪集中持有理念为其《怎样选择成长股》所载→确证。","historicity":"confirmed","linked_cards":["fisher"],"tags":["投资","风险评估"],"advisor_id":"fisher"}', '9840534b0cd43597ad8e952e498f73fed01d14592652b935ee3d27bb250711f7');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('dalio-c1', 'dalio', '1982年的惨痛失败与反思·痛苦加反思等于进步（1982起）', '达里奥1982年公开看错市场，几乎让公司破产、自己一度一无所有。', '达里奥把这次惨痛失败当作最宝贵的一课、深刻反思，由此建立起严谨的风险原则与决策系统，重建了桥水。', '这次失败的反思成为达里奥与桥水后来成功的转折点。', '把痛苦、失败当成学习的信号、直面并反思它背后的教训——痛苦 + 反思 = 进步。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"dalio-c1","status":"published","title_period":"1982年的惨痛失败与反思·痛苦加反思等于进步（1982起）","dilemma_constraints":"达里奥1982年公开看错市场，几乎让公司破产、自己一度一无所有。","key_judgment":"达里奥把这次惨痛失败当作最宝贵的一课、深刻反思，由此建立起严谨的风险原则与决策系统，重建了桥水。","model_invoked":["痛苦加反思等于进步"],"outcome":"这次失败的反思成为达里奥与桥水后来成功的转折点。","transferable_lesson":"把痛苦、失败当成学习的信号、直面并反思它背后的教训——痛苦 + 反思 = 进步。","source_tier":"primary","source_note":"1982年失败与反思为达里奥《原则》自述→确证（一手A）。","historicity":"confirmed","linked_cards":["dalio"],"tags":["认知偏误与理性决策","组织管理"],"advisor_id":"dalio"}', 'e1d983ecef3454c16aaa1905aa7ce776208e5bded78529cee9fca54e4c3e59c9');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('dalio-c2', 'dalio', '桥水的"极度透明"文化·极度求真与极度透明（桥水）', '如何让一个组织持续做出高质量的决策、不被掩盖问题所害。', '达里奥在桥水建立"极度求真、极度透明"的文化，鼓励所有人坦诚地把问题、分歧摆到台面上（甚至记录、评分）。', '这套文化助桥水做出了出色的决策，但也以严苛、不适著称、对多数组织水土不服。', '追求极度真实与透明、把问题摆到台面上说——但须知执行极难、须因地制宜。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"dalio-c2","status":"published","title_period":"桥水的\"极度透明\"文化·极度求真与极度透明（桥水）","dilemma_constraints":"如何让一个组织持续做出高质量的决策、不被掩盖问题所害。","key_judgment":"达里奥在桥水建立\"极度求真、极度透明\"的文化，鼓励所有人坦诚地把问题、分歧摆到台面上（甚至记录、评分）。","model_invoked":["极度求真与极度透明"],"outcome":"这套文化助桥水做出了出色的决策，但也以严苛、不适著称、对多数组织水土不服。","transferable_lesson":"追求极度真实与透明、把问题摆到台面上说——但须知执行极难、须因地制宜。","source_tier":"primary","source_note":"桥水\"极度透明\"文化为达里奥《原则》→确证（一手A；其争议已入盲区）。","historicity":"confirmed","linked_cards":["dalio"],"tags":["组织管理"],"advisor_id":"dalio"}', 'c3792e13cda7ec9cb1c2c668d34324c89a25339009c5dbe4f126a360c73dbd18');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('dalio-c3', 'dalio', '把经验写成《原则》·把原则写下来系统化（其方法）', '如何让经验沉淀、可复用、可传承。', '达里奥把几十年投资与管理的经验，一条条提炼成明确的"原则"、写下来、系统化（成书与软件），遇到同类情况就照原则办。', '《原则》成为风靡全球的方法论著作，桥水亦将原则工具化。', '把经验提炼成明确的"原则"、写下来系统化，让同类情况有章可循——但别僵化成教条。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"dalio-c3","status":"published","title_period":"把经验写成《原则》·把原则写下来系统化（其方法）","dilemma_constraints":"如何让经验沉淀、可复用、可传承。","key_judgment":"达里奥把几十年投资与管理的经验，一条条提炼成明确的\"原则\"、写下来、系统化（成书与软件），遇到同类情况就照原则办。","model_invoked":["把原则写下来系统化"],"outcome":"《原则》成为风靡全球的方法论著作，桥水亦将原则工具化。","transferable_lesson":"把经验提炼成明确的\"原则\"、写下来系统化，让同类情况有章可循——但别僵化成教条。","source_tier":"primary","source_note":"达里奥系统化《原则》为其著作→确证（一手A）。","historicity":"confirmed","linked_cards":["dalio"],"tags":["组织管理","认知偏误与理性决策"],"advisor_id":"dalio"}', '0339db3170f9617cfdcda1fe277916258d5651a1fa28fb092cd583df29bf9c58');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('dalio-c4', 'dalio', '「可信度加权」决策·可信度加权的决策（桥水）', '集体决策中如何兼顾民主与专业、避免一言堂或平庸的多数。', '达里奥推行"可信度加权"——决策时按每个人在该具体问题上的可信度（过往记录、推理质量）加权其意见，而非一人一票或老板拍板。', '「可信度加权」是桥水「创意择优(idea meritocracy)」的核心机制。', '集体决策按各人在该问题上的"可信度"加权意见，而非一人一票或一言堂。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"dalio-c4","status":"published","title_period":"「可信度加权」决策·可信度加权的决策（桥水）","dilemma_constraints":"集体决策中如何兼顾民主与专业、避免一言堂或平庸的多数。","key_judgment":"达里奥推行\"可信度加权\"——决策时按每个人在该具体问题上的可信度（过往记录、推理质量）加权其意见，而非一人一票或老板拍板。","model_invoked":["可信度加权的决策"],"outcome":"「可信度加权」是桥水「创意择优(idea meritocracy)」的核心机制。","transferable_lesson":"集体决策按各人在该问题上的\"可信度\"加权意见，而非一人一票或一言堂。","source_tier":"primary","source_note":"「可信度加权」为达里奥《原则》→确证（一手A）。","historicity":"confirmed","linked_cards":["dalio"],"tags":["组织管理","认知偏误与理性决策"],"advisor_id":"dalio"}', '2b04dc7ef0abccb00cd84f5f869713f245380e4e0055dec127382ec27eed1d13');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('templeton-c1', 'templeton', '二战爆发借钱买便宜股（1939）', '1939年二战爆发，市场极度恐慌、几乎人人抛售；但恐慌也把许多股票砸到极低价。', '邓普顿反其道而行，借钱买入纽约证交所每股价格低于1美元的104只股票（几乎不加挑选地买入这一篮子极便宜股）。', '数年后多数股票大幅回升，他获利数倍，奠定其逆向投资声名。', '人人恐惧抛售、价格被砸到极低的悲观点，往往是回报最高的买入时机——前提是确认这是恐慌错杀而非基本面崩坏。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"templeton-c1","status":"published","title_period":"二战爆发借钱买便宜股（1939）","dilemma_constraints":"1939年二战爆发，市场极度恐慌、几乎人人抛售；但恐慌也把许多股票砸到极低价。","key_judgment":"邓普顿反其道而行，借钱买入纽约证交所每股价格低于1美元的104只股票（几乎不加挑选地买入这一篮子极便宜股）。","model_invoked":["极度悲观点买入"],"outcome":"数年后多数股票大幅回升，他获利数倍，奠定其逆向投资声名。","transferable_lesson":"人人恐惧抛售、价格被砸到极低的悲观点，往往是回报最高的买入时机——前提是确认这是恐慌错杀而非基本面崩坏。","source_tier":"secondary","source_note":"1939二战买便宜股为邓普顿投资生涯著名史实→确证。","historicity":"confirmed","linked_cards":["templeton"],"tags":["投资","风险评估"],"advisor_id":"templeton"}', '3d2fe33ad34caf8df7e745a3dee4e8d84f5ff900c674e99b9d097ff0d896b220');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('templeton-c2', 'templeton', '全球投资先驱·早期布局日本（1960年代起）', '当时美国投资者普遍只投本国市场，海外尤其亚洲市场被忽视、信息匮乏。', '邓普顿率先把目光投向全球，早在1960年代就大举投资当时被严重低估、尚未被国际投资者重视的日本市场。', '日本市场其后长期上涨，他获得丰厚回报；其全球投资理念开创了一个时代。', '别把视野局限在本国——在全球范围搜寻被低估的便宜优质资产，机会集会大得多（但需跨市场的知识与风险认识）。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"templeton-c2","status":"published","title_period":"全球投资先驱·早期布局日本（1960年代起）","dilemma_constraints":"当时美国投资者普遍只投本国市场，海外尤其亚洲市场被忽视、信息匮乏。","key_judgment":"邓普顿率先把目光投向全球，早在1960年代就大举投资当时被严重低估、尚未被国际投资者重视的日本市场。","model_invoked":["全球分散搜寻便宜"],"outcome":"日本市场其后长期上涨，他获得丰厚回报；其全球投资理念开创了一个时代。","transferable_lesson":"别把视野局限在本国——在全球范围搜寻被低估的便宜优质资产，机会集会大得多（但需跨市场的知识与风险认识）。","source_tier":"secondary","source_note":"邓普顿率先全球投资、早期布局日本为其投资史所载→确证。","historicity":"confirmed","linked_cards":["templeton"],"tags":["投资","长期规划"],"advisor_id":"templeton"}', '8a906d73767eba9b8219bc089f23965c34ec8ff3369c00bbe0521646a54f3353');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('templeton-c3', 'templeton', '2000互联网泡沫顶峰做空科技股（1999—2000）', '1999年互联网泡沫狂热、科技股估值离谱，人人鼓吹"新经济、这次不一样"。', '邓普顿判断这是典型的狂热泡沫、"这次不一样"是幻觉，逆势做空一篮子高估的科技股。', '泡沫随后破裂，其做空获利丰厚；印证"这次不一样"往往是最贵的幻觉。', '当市场狂热、人人说"这次不一样"时，对照历史——繁荣与恐慌的模式很少真的改变，别被幻觉骗去追高。（诚实：做空时机风险极高。）', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"templeton-c3","status":"published","title_period":"2000互联网泡沫顶峰做空科技股（1999—2000）","dilemma_constraints":"1999年互联网泡沫狂热、科技股估值离谱，人人鼓吹\"新经济、这次不一样\"。","key_judgment":"邓普顿判断这是典型的狂热泡沫、\"这次不一样\"是幻觉，逆势做空一篮子高估的科技股。","model_invoked":["警惕这次不一样"],"outcome":"泡沫随后破裂，其做空获利丰厚；印证\"这次不一样\"往往是最贵的幻觉。","transferable_lesson":"当市场狂热、人人说\"这次不一样\"时，对照历史——繁荣与恐慌的模式很少真的改变，别被幻觉骗去追高。（诚实：做空时机风险极高。）","source_tier":"secondary","source_note":"邓普顿2000年前后做空高估科技股为其晚年著名操作→确证。","historicity":"confirmed","linked_cards":["templeton"],"tags":["投资","认知偏误与理性决策"],"advisor_id":"templeton"}', 'abdbcb6b670d3f814a452ce245ada962d6bc4fe1aadd4ca30c2cc93c9745f3c7');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('churchill-c1', 'churchill', '至暗时刻绝不投降·绝不屈服（1940）', '1940年法国沦陷、英国独自面对纳粹德国，国内亦有主和声音。', '丘吉尔以"我们绝不投降"的坚定意志拒绝妥协，稳住了举国抗战的人心。', '英国挺过了最危急的阶段（不列颠空战等），成为反法西斯的中流砥柱。', '在最黑暗、看似必败的时刻、绝不轻言放弃——用坚定的决心稳住人心、撑到转机（但须与"确实该止损"区分）。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"churchill-c1","status":"published","title_period":"至暗时刻绝不投降·绝不屈服（1940）","dilemma_constraints":"1940年法国沦陷、英国独自面对纳粹德国，国内亦有主和声音。","key_judgment":"丘吉尔以\"我们绝不投降\"的坚定意志拒绝妥协，稳住了举国抗战的人心。","model_invoked":["绝不屈服的意志"],"outcome":"英国挺过了最危急的阶段（不列颠空战等），成为反法西斯的中流砥柱。","transferable_lesson":"在最黑暗、看似必败的时刻、绝不轻言放弃——用坚定的决心稳住人心、撑到转机（但须与\"确实该止损\"区分）。","source_tier":"secondary","source_note":"丘吉尔1940年的抗战意志为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["churchill"],"tags":["危机应对","领导力"],"advisor_id":"churchill"}', '16030c185ff20c388bc9128f58c1f42db7c739681116de29d44f8fa353e04347');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('churchill-c2', 'churchill', '「热血、辛劳、眼泪与汗水」·言语动员（1940起）', '战时需要凝聚全民意志、维持士气。', '丘吉尔以一系列真诚有力、既坦诚艰难又给人希望的演讲，动员和鼓舞了英国民众。', '丘吉尔的演讲成为战时鼓舞人心的力量，本人后获诺贝尔文学奖。', '在危机中用真诚、有力、既坦诚困难又给人希望的语言去凝聚人心、动员士气——语言本身就是力量。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"churchill-c2","status":"published","title_period":"「热血、辛劳、眼泪与汗水」·言语动员（1940起）","dilemma_constraints":"战时需要凝聚全民意志、维持士气。","key_judgment":"丘吉尔以一系列真诚有力、既坦诚艰难又给人希望的演讲，动员和鼓舞了英国民众。","model_invoked":["言语动员人心"],"outcome":"丘吉尔的演讲成为战时鼓舞人心的力量，本人后获诺贝尔文学奖。","transferable_lesson":"在危机中用真诚、有力、既坦诚困难又给人希望的语言去凝聚人心、动员士气——语言本身就是力量。","source_tier":"secondary","source_note":"丘吉尔战时演讲为史实→确证（二手B；具体措辞有原文）。","historicity":"confirmed","linked_cards":["churchill"],"tags":["表达说服","领导力"],"advisor_id":"churchill"}', 'ce41dbb7dfd26e59a68f4680fe6b09b0b980c547c946300b303bd4b5e5e4e40f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('churchill-c3', 'churchill', '反对绥靖·直面纳粹威胁（1930s）', '二战前，英国主流对纳粹德国采取绥靖政策。', '丘吉尔在二战前即坚决反对绥靖、警告纳粹的威胁，主张早做准备、敢于直面。', '事实证明绥靖未能阻止战争，丘吉尔的警告被验证。', '对真实的、正在壮大的威胁，要早识别、敢直面，别靠一味的妥协退让换一时的安宁——绥靖只会喂大它。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"churchill-c3","status":"published","title_period":"反对绥靖·直面纳粹威胁（1930s）","dilemma_constraints":"二战前，英国主流对纳粹德国采取绥靖政策。","key_judgment":"丘吉尔在二战前即坚决反对绥靖、警告纳粹的威胁，主张早做准备、敢于直面。","model_invoked":["直面而非绥靖"],"outcome":"事实证明绥靖未能阻止战争，丘吉尔的警告被验证。","transferable_lesson":"对真实的、正在壮大的威胁，要早识别、敢直面，别靠一味的妥协退让换一时的安宁——绥靖只会喂大它。","source_tier":"secondary","source_note":"丘吉尔反对绥靖为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["churchill"],"tags":["危机应对","竞争博弈"],"advisor_id":"churchill"}', '4a752b51de4e88248564d248ca0d5003b0a738cb500948b78114573e28baae0b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('churchill-c4', 'churchill', '为抗德联合美苏·联合（二战）', '英国独力难支，需要盟友，但苏联与英国意识形态对立。', '丘吉尔为对抗纳粹这一主要威胁，放下意识形态成见，与苏联结盟、并极力争取美国参战。', '同盟国的联合最终击败了纳粹德国。', '为了对抗当前最主要的威胁，可以放下成见、与次要的对手甚至旧敌联手——分清主次矛盾。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"churchill-c4","status":"published","title_period":"为抗德联合美苏·联合（二战）","dilemma_constraints":"英国独力难支，需要盟友，但苏联与英国意识形态对立。","key_judgment":"丘吉尔为对抗纳粹这一主要威胁，放下意识形态成见，与苏联结盟、并极力争取美国参战。","model_invoked":["联合一切可联合"],"outcome":"同盟国的联合最终击败了纳粹德国。","transferable_lesson":"为了对抗当前最主要的威胁，可以放下成见、与次要的对手甚至旧敌联手——分清主次矛盾。","source_tier":"secondary","source_note":"丘吉尔联苏抗德为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["churchill"],"tags":["竞争博弈","危机应对"],"advisor_id":"churchill"}', '9e0b012b7b49e50b3bb69f0e496d8d050d4b9f9570f0147706405bb79ac3b56b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('pericles-c1', 'pericles', '推进雅典民主·公民参与（公元前5世纪中）', '城邦治理由谁参与、如何获得广泛的支持与活力。', '伯里克利推动并巩固了雅典的直接民主，扩大公民参与，使公民广泛参与公共事务的决策。', '雅典民主在伯里克利时代达到鼎盛，城邦活力空前。', '让相关的人广泛参与决策、以公开辩论和多数同意推进——参与本身激发归属与合法性（但防多数暴政）。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"pericles-c1","status":"published","title_period":"推进雅典民主·公民参与（公元前5世纪中）","dilemma_constraints":"城邦治理由谁参与、如何获得广泛的支持与活力。","key_judgment":"伯里克利推动并巩固了雅典的直接民主，扩大公民参与，使公民广泛参与公共事务的决策。","model_invoked":["公民参与的民主治理"],"outcome":"雅典民主在伯里克利时代达到鼎盛，城邦活力空前。","transferable_lesson":"让相关的人广泛参与决策、以公开辩论和多数同意推进——参与本身激发归属与合法性（但防多数暴政）。","source_tier":"secondary","source_note":"伯里克利推进雅典民主为史述→确证（二手B）。","historicity":"confirmed","linked_cards":["pericles"],"tags":["领导力"],"advisor_id":"pericles"}', 'c160136aa449dc6b88f7fd307c3c750cf9ab7fcbd0f42478fdd5b6acd3fbe6d7');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('pericles-c2', 'pericles', '大建帕特农神庙·投资文化软实力（公元前5世纪中）', '如何提升雅典的声望、凝聚力与文化地位。', '伯里克利主持了以帕特农神庙为代表的大规模公共建设，大力投资文化艺术，使雅典成为希腊的文化中心。', '雅典成为古希腊的文化与艺术中心，声望与凝聚力大增（但伴随挪用同盟金库的争议）。', '别只投硬实力——大力投资文化、公共空间、精神象征，把组织的声望、认同与凝聚力做出来。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"pericles-c2","status":"published","title_period":"大建帕特农神庙·投资文化软实力（公元前5世纪中）","dilemma_constraints":"如何提升雅典的声望、凝聚力与文化地位。","key_judgment":"伯里克利主持了以帕特农神庙为代表的大规模公共建设，大力投资文化艺术，使雅典成为希腊的文化中心。","model_invoked":["投资文化软实力"],"outcome":"雅典成为古希腊的文化与艺术中心，声望与凝聚力大增（但伴随挪用同盟金库的争议）。","transferable_lesson":"别只投硬实力——大力投资文化、公共空间、精神象征，把组织的声望、认同与凝聚力做出来。","source_tier":"secondary","source_note":"伯里克利主持帕特农建设为史实→确证（二手B；挪用同盟金库的争议已入盲区）。","historicity":"confirmed","linked_cards":["pericles"],"tags":["领导力","长期规划"],"advisor_id":"pericles"}', '2a3e6a2112e0b6b1f69aae90d221a99505174bc24963e346e0f0d2fb73e85ba8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('pericles-c3', 'pericles', '「国殇演说」·以理性演说凝聚共识（伯罗奔尼撒战争初）', '战争伤亡之际，需要凝聚人心、提振士气、申明价值。', '伯里克利在阵亡将士葬礼上发表著名的"国殇演说"，以条理清晰、诉诸雅典共同的民主精神与荣誉，激励城邦。', '「国殇演说」成西方政治演说的典范（载于修昔底德），凝聚了雅典的精神。', '用条理清晰、诉诸共同价值与荣誉的理性演说去凝聚共识、提振人心——而非靠煽动或命令。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"pericles-c3","status":"published","title_period":"「国殇演说」·以理性演说凝聚共识（伯罗奔尼撒战争初）","dilemma_constraints":"战争伤亡之际，需要凝聚人心、提振士气、申明价值。","key_judgment":"伯里克利在阵亡将士葬礼上发表著名的\"国殇演说\"，以条理清晰、诉诸雅典共同的民主精神与荣誉，激励城邦。","model_invoked":["以理性演说凝聚共识"],"outcome":"「国殇演说」成西方政治演说的典范（载于修昔底德），凝聚了雅典的精神。","transferable_lesson":"用条理清晰、诉诸共同价值与荣誉的理性演说去凝聚共识、提振人心——而非靠煽动或命令。","source_tier":"primary","source_note":"国殇演说载于修昔底德《伯罗奔尼撒战争史》→确证（一手记述A；修昔底德有润色）。","historicity":"confirmed","linked_cards":["pericles"],"tags":["表达说服","领导力"],"advisor_id":"pericles"}', 'aedb8d432d1c525c2e8015c77b07393c7937c947b654728e3e46641cf480d35c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('pericles-c4', 'pericles', '守城避战的战略·扬长避短（伯罗奔尼撒战争）', '雅典海军强、陆军不及斯巴达，如何应战。', '伯里克利凭雅典的海军优势，主张坚守城防、避免与斯巴达陆军正面决战，发挥所长、回避所短。', '战略本身合理，但雅典随后暴发大瘟疫（伯里克利本人也病逝），战略未能竟全功。', '基于自己真正的优势制定战略、不被对手拖入不利的战场——但须知意外（如瘟疫）也可能使战略受挫。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"pericles-c4","status":"published","title_period":"守城避战的战略·扬长避短（伯罗奔尼撒战争）","dilemma_constraints":"雅典海军强、陆军不及斯巴达，如何应战。","key_judgment":"伯里克利凭雅典的海军优势，主张坚守城防、避免与斯巴达陆军正面决战，发挥所长、回避所短。","model_invoked":["扬长避短的战略"],"outcome":"战略本身合理，但雅典随后暴发大瘟疫（伯里克利本人也病逝），战略未能竟全功。","transferable_lesson":"基于自己真正的优势制定战略、不被对手拖入不利的战场——但须知意外（如瘟疫）也可能使战略受挫。","source_tier":"secondary","source_note":"伯里克利的守城避战战略为史述→确证（二手B）。","historicity":"confirmed","linked_cards":["pericles"],"tags":["竞争博弈","危机应对"],"advisor_id":"pericles"}', 'd8bd090611f50a5b95f0ff2b87a4b87f8f1251b80adfa9ba8f38bbc67a67887d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bismarck-c1', 'bismarck', '埃姆斯密电·促成普法战争（1870）', '德意志统一需击败法国、但普鲁士不愿担"侵略者"之名；若主动宣战则失道义、易招他国干涉。', '（〔慎〕操纵手段）俾斯麦删改埃姆斯密电、措辞激怒法国，使法国先行宣战，普鲁士遂以"被侵略"之名应战、师出有名。', '普法战争普鲁士大胜、德意志帝国成立、完成统一；但其操纵手段亦是道德争议焦点。', '要行动又怕担"挑起者"之名时，可制造让对手先动手的局面把正当性放己方——但要清醒：这是操纵，道德上高度可议，须自省底线。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bismarck-c1","status":"published","title_period":"埃姆斯密电·促成普法战争（1870）","dilemma_constraints":"德意志统一需击败法国、但普鲁士不愿担\"侵略者\"之名；若主动宣战则失道义、易招他国干涉。","key_judgment":"（〔慎〕操纵手段）俾斯麦删改埃姆斯密电、措辞激怒法国，使法国先行宣战，普鲁士遂以\"被侵略\"之名应战、师出有名。","model_invoked":["制造正当性的时机"],"outcome":"普法战争普鲁士大胜、德意志帝国成立、完成统一；但其操纵手段亦是道德争议焦点。","transferable_lesson":"要行动又怕担\"挑起者\"之名时，可制造让对手先动手的局面把正当性放己方——但要清醒：这是操纵，道德上高度可议，须自省底线。","source_tier":"secondary","source_note":"埃姆斯密电删改、激法宣战、普法战争为可考史实→确证；本条手段冷酷、〔慎〕客观标注、非主张效法。","historicity":"confirmed","linked_cards":["bismarck"],"tags":["战略","竞争博弈"],"advisor_id":"bismarck"}', '57b5a35ce760367e5b69589d8c3c207bd0ddfb370c9afeb40fdc92c2ef508568');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bismarck-c2', 'bismarck', '普奥战争后宽待奥地利（1866）', '普奥战争普鲁士大胜，军方与舆论欲乘胜重创、羞辱奥地利；但过度羞辱会结下死仇、招致长期敌对。', '俾斯麦力排众议、主张宽待奥地利——不割其本土、不过度羞辱，为日后把奥地利拉为伙伴（后之德奥同盟）留余地。', '奥地利未结死仇，日后成德奥同盟伙伴；"胜而不骄、留对手余地"成其有限目标外交的范例。', '打赢了别把对手往死里压——设有限目标、见好就收、给战败方留体面，他日后可能成为你的伙伴而非死敌。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bismarck-c2","status":"published","title_period":"普奥战争后宽待奥地利（1866）","dilemma_constraints":"普奥战争普鲁士大胜，军方与舆论欲乘胜重创、羞辱奥地利；但过度羞辱会结下死仇、招致长期敌对。","key_judgment":"俾斯麦力排众议、主张宽待奥地利——不割其本土、不过度羞辱，为日后把奥地利拉为伙伴（后之德奥同盟）留余地。","model_invoked":["见好就收有限目标"],"outcome":"奥地利未结死仇，日后成德奥同盟伙伴；\"胜而不骄、留对手余地\"成其有限目标外交的范例。","transferable_lesson":"打赢了别把对手往死里压——设有限目标、见好就收、给战败方留体面，他日后可能成为你的伙伴而非死敌。","source_tier":"secondary","source_note":"普奥战后宽待奥地利、为德奥同盟铺垫为可考史实→确证。","historicity":"confirmed","linked_cards":["bismarck"],"tags":["谈判","战略"],"advisor_id":"bismarck"}', 'e709c007588883e928b851c34b71abdce43fbf375e471dc9781fac5741188b6d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bismarck-c3', 'bismarck', '复杂同盟体系·孤立法国（1871–1890）', '统一后的德国地处欧洲中央、四邻环伺，最忌法国联合他国（尤其俄国）形成两线夹击的反德联盟。', '俾斯麦构建三皇同盟、德奥同盟、《再保险条约》等环环相扣的同盟体系，通过结盟与分化把法国孤立、维持对德有利的均势。', '在其当政期间德国安全、欧洲大体维持均势、法国被孤立；但体系极复杂、高度依赖其个人操控。', '处在多方力量中央、最怕被联合围攻时，用环环相扣的结盟与分化把对手孤立、维持对你有利的平衡——但越精巧的均势越依赖操控者本人。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bismarck-c3","status":"published","title_period":"复杂同盟体系·孤立法国（1871–1890）","dilemma_constraints":"统一后的德国地处欧洲中央、四邻环伺，最忌法国联合他国（尤其俄国）形成两线夹击的反德联盟。","key_judgment":"俾斯麦构建三皇同盟、德奥同盟、《再保险条约》等环环相扣的同盟体系，通过结盟与分化把法国孤立、维持对德有利的均势。","model_invoked":["操控均势"],"outcome":"在其当政期间德国安全、欧洲大体维持均势、法国被孤立；但体系极复杂、高度依赖其个人操控。","transferable_lesson":"处在多方力量中央、最怕被联合围攻时，用环环相扣的结盟与分化把对手孤立、维持对你有利的平衡——但越精巧的均势越依赖操控者本人。","source_tier":"secondary","source_note":"三皇同盟、德奥同盟、再保险条约为可考史实→确证。","historicity":"confirmed","linked_cards":["bismarck"],"tags":["战略","竞争博弈"],"advisor_id":"bismarck"}', '2fcff8c595259bef0d352c63145e75e29db95bf5dad80cc6928490d895bfee39');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bismarck-c4', 'bismarck', '被威廉二世罢免·体系难继（1890）', '（消极判例）新皇威廉二世欲亲政、与俾斯麦在内外政策上冲突；俾斯麦的复杂体系全系于其个人。', '（反噬/局限）1890年俾斯麦被威廉二世罢免，其精巧的同盟体系无人能续——继任者放弃《再保险条约》、德俄疏远。', '同盟体系迅速崩坏、欧洲重新分裂为对立阵营，间接通向第一次世界大战的格局。', '一套高度依赖你个人技巧、未制度化的精巧体系，会在你离场后迅速崩坏——再高明的操控，若不能传承与制度化，终究脆弱。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bismarck-c4","status":"published","title_period":"被威廉二世罢免·体系难继（1890）","dilemma_constraints":"（消极判例）新皇威廉二世欲亲政、与俾斯麦在内外政策上冲突；俾斯麦的复杂体系全系于其个人。","key_judgment":"（反噬/局限）1890年俾斯麦被威廉二世罢免，其精巧的同盟体系无人能续——继任者放弃《再保险条约》、德俄疏远。","model_invoked":["操控均势"],"outcome":"同盟体系迅速崩坏、欧洲重新分裂为对立阵营，间接通向第一次世界大战的格局。","transferable_lesson":"一套高度依赖你个人技巧、未制度化的精巧体系，会在你离场后迅速崩坏——再高明的操控，若不能传承与制度化，终究脆弱。","source_tier":"secondary","source_note":"俾斯麦被罢免、再保险条约失效、欧洲格局演变为可考史实→确证；本条作其\"体系依赖个人、难制度化\"盲区的案例体现。","historicity":"confirmed","linked_cards":["bismarck"],"tags":["战略","危机应对"],"advisor_id":"bismarck"}', 'b394a9bd9ab28d448dd9c325528ccb7c7d75d1102948bf33b2d193b7f4817611');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('washington-c1', 'washington', '辞去大陆军总司令·交还军权（1783）', '独立战争胜利，华盛顿手握军队与崇高威望，当时不乏拥его称王/掌权之议；若揽权或可成新的统治者。', '他主动辞去大陆军总司令、把军权交还大陆会议、解甲归田——拒绝以军威自重，立下"军权服从文官、权力可交接"的先例。', '此举震动世界（连对手乔治三世都为之惊叹），为美国"军队服从文官、权力和平交接"奠定根本范式。', '在你本可凭借实力与威望继续掌权时主动放手，立下的先例比任何说教都更有力——克制本身就是最高的权威。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"washington-c1","status":"published","title_period":"辞去大陆军总司令·交还军权（1783）","dilemma_constraints":"独立战争胜利，华盛顿手握军队与崇高威望，当时不乏拥его称王/掌权之议；若揽权或可成新的统治者。","key_judgment":"他主动辞去大陆军总司令、把军权交还大陆会议、解甲归田——拒绝以军威自重，立下\"军权服从文官、权力可交接\"的先例。","model_invoked":["主动交权立先例"],"outcome":"此举震动世界（连对手乔治三世都为之惊叹），为美国\"军队服从文官、权力和平交接\"奠定根本范式。","transferable_lesson":"在你本可凭借实力与威望继续掌权时主动放手，立下的先例比任何说教都更有力——克制本身就是最高的权威。","source_tier":"secondary","source_note":"辞职交权为多源可考史实→确证。","historicity":"confirmed","linked_cards":["washington"],"tags":["治理决策","领导力"],"advisor_id":"washington"}', '1932a170f02e5c05ddab296e8dbdbf7a3f1244322b7beebb66387de40bee402e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('washington-c2', 'washington', '平息纽堡兵变·拒绝以军夺权（1783）', '战争末期，军饷拖欠，部分军官在纽堡密谋以武力胁迫国会、甚至有拥华盛顿掌权之意；军队哗变一触即发。', '他亲赴军官集会、动之以情晓之以理平息哗变，明确拒绝以军队对抗文官政府或夺取权力，把军队的不满导回合法渠道。', '纽堡阴谋平息，避免了军事政变；华盛顿"能夺权而不夺"的克制使其威信达到顶点。', '当部下/形势把夺权的机会送到你面前，主动克制、拒绝越界，反而比攫取更能赢得长久的威信与正当性。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"washington-c2","status":"published","title_period":"平息纽堡兵变·拒绝以军夺权（1783）","dilemma_constraints":"战争末期，军饷拖欠，部分军官在纽堡密谋以武力胁迫国会、甚至有拥华盛顿掌权之意；军队哗变一触即发。","key_judgment":"他亲赴军官集会、动之以情晓之以理平息哗变，明确拒绝以军队对抗文官政府或夺取权力，把军队的不满导回合法渠道。","model_invoked":["克制立威"],"outcome":"纽堡阴谋平息，避免了军事政变；华盛顿\"能夺权而不夺\"的克制使其威信达到顶点。","transferable_lesson":"当部下/形势把夺权的机会送到你面前，主动克制、拒绝越界，反而比攫取更能赢得长久的威信与正当性。","source_tier":"secondary","source_note":"纽堡事件及华盛顿平息哗变为可考史实→确证。","historicity":"confirmed","linked_cards":["washington"],"tags":["危机应对","领导力"],"advisor_id":"washington"}', 'd15660f7bfb0ce31872ee9688f42052df76c75f326436399bc5707d311425a82');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('washington-c3', 'washington', '拒绝第三任·和平移交权力（1796–1797）', '两届总统任满，他仍众望所归、连任几无悬念；当时并无任期限制，恋栈合情合理。', '他拒绝第三任、发表《告别演说》、和平移交权力给继任者，亲手立下"两届为限"的传统，把权威交给制度而非个人。', '「两届传统」成为美国政治惯例（后入宪法修正案）；和平移交权力成宪政基石。', '在你威望最盛、最可恋栈时主动退场，把权威交给制度而非个人——制度因此能比任何个人活得更久。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"washington-c3","status":"published","title_period":"拒绝第三任·和平移交权力（1796–1797）","dilemma_constraints":"两届总统任满，他仍众望所归、连任几无悬念；当时并无任期限制，恋栈合情合理。","key_judgment":"他拒绝第三任、发表《告别演说》、和平移交权力给继任者，亲手立下\"两届为限\"的传统，把权威交给制度而非个人。","model_invoked":["制度高于个人"],"outcome":"「两届传统」成为美国政治惯例（后入宪法修正案）；和平移交权力成宪政基石。","transferable_lesson":"在你威望最盛、最可恋栈时主动退场，把权威交给制度而非个人——制度因此能比任何个人活得更久。","source_tier":"secondary","source_note":"两届退、告别演说、和平移交为可考史实→确证。","historicity":"confirmed","linked_cards":["washington"],"tags":["治理决策","长期规划"],"advisor_id":"washington"}', '219d1f5fa706105fb8e21854d6a2a5f7cbc28ec027f331e682c44c7ad2309ba8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('washington-c4', 'washington', '内阁并用汉密尔顿与杰斐逊（任内）', '建国之初，联邦党(汉密尔顿)与民主共和派(杰斐逊)理念尖锐对立，党争已现，国家有分裂之虞。', '他在内阁同时重用对立的汉密尔顿与杰斐逊、自身超脱党派之上，做各方都能接受的中立黏合点，以平衡维系团结。', '在其任内对立两派尚能共事、国家根基得以稳固；但其卸任后党争加剧（亦说明此模式依赖其个人威望）。', '面对尖锐对立的派系，把双方都纳进来、自身超脱党争、做中立的平衡点，能在草创期维系团结——但这高度依赖你超党派的威望。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"washington-c4","status":"published","title_period":"内阁并用汉密尔顿与杰斐逊（任内）","dilemma_constraints":"建国之初，联邦党(汉密尔顿)与民主共和派(杰斐逊)理念尖锐对立，党争已现，国家有分裂之虞。","key_judgment":"他在内阁同时重用对立的汉密尔顿与杰斐逊、自身超脱党派之上，做各方都能接受的中立黏合点，以平衡维系团结。","model_invoked":["超党派黏合"],"outcome":"在其任内对立两派尚能共事、国家根基得以稳固；但其卸任后党争加剧（亦说明此模式依赖其个人威望）。","transferable_lesson":"面对尖锐对立的派系，把双方都纳进来、自身超脱党争、做中立的平衡点，能在草创期维系团结——但这高度依赖你超党派的威望。","source_tier":"secondary","source_note":"内阁并用两人、华盛顿超党派姿态为可考史实→确证。","historicity":"confirmed","linked_cards":["washington"],"tags":["领导力","治理决策"],"advisor_id":"washington"}', 'd162534123a22cdb9998a51a7929b9941b9c270f1242ecd8b8311173ad9ad01d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('shangyang-c1', 'shangyang', '立木南门·徙木立信（变法前）', '新法将行，但秦民久惯旧俗、疑朝令夕改、不信新法会被认真执行；强推恐令不行。', '在国都南门立一根木、悬赏能将其搬到北门者重金，待有人照做即当场兑现五十金，先以一个看得见的小承诺立"令出必行"之信。', '秦民由此相信令出必行，新法得以推行；"徙木立信"成立公信的经典。', '要让人相信你将认真兑现大政策，先用一个小而确定、当众兑现的承诺立信——信用是大变革的前提。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"shangyang-c1","status":"published","title_period":"立木南门·徙木立信（变法前）","dilemma_constraints":"新法将行，但秦民久惯旧俗、疑朝令夕改、不信新法会被认真执行；强推恐令不行。","key_judgment":"在国都南门立一根木、悬赏能将其搬到北门者重金，待有人照做即当场兑现五十金，先以一个看得见的小承诺立\"令出必行\"之信。","model_invoked":["徙木立信"],"outcome":"秦民由此相信令出必行，新法得以推行；\"徙木立信\"成立公信的经典。","transferable_lesson":"要让人相信你将认真兑现大政策，先用一个小而确定、当众兑现的承诺立信——信用是大变革的前提。","source_tier":"secondary","source_note":"立木立信为《史记·商君列传》可考→确证。","historicity":"confirmed","linked_cards":["shangyang"],"tags":["治理决策","表达说服"],"advisor_id":"shangyang"}', '7350e45cd61b6a43d306b3171106b9044dfee43e751ea2ea5fa265d383c320ac');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('shangyang-c2', 'shangyang', '两次变法·耕战富秦（前356、前350）', '秦国地处西陲、相对落后，欲在列国争雄中崛起，需在短期内把国力集中拉升。', '推行两次变法：废井田开阡陌、奖励耕织、按军功授爵（军功爵制）、什伍连坐、抑商重农——把全社会激励统一导向"耕战"。', '秦国国力军力大增，为日后统一六国奠定制度基础；但严刑峻法亦埋下争议与反噬。', '把整个组织的激励统一导向一个核心目标，能在短期内集中爆发力量——但单一导向也牺牲了多样性与长期弹性，且手段过刚会埋下反噬。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"shangyang-c2","status":"published","title_period":"两次变法·耕战富秦（前356、前350）","dilemma_constraints":"秦国地处西陲、相对落后，欲在列国争雄中崛起，需在短期内把国力集中拉升。","key_judgment":"推行两次变法：废井田开阡陌、奖励耕织、按军功授爵（军功爵制）、什伍连坐、抑商重农——把全社会激励统一导向\"耕战\"。","model_invoked":["耕战立国"],"outcome":"秦国国力军力大增，为日后统一六国奠定制度基础；但严刑峻法亦埋下争议与反噬。","transferable_lesson":"把整个组织的激励统一导向一个核心目标，能在短期内集中爆发力量——但单一导向也牺牲了多样性与长期弹性，且手段过刚会埋下反噬。","source_tier":"secondary","source_note":"两次变法、军功爵、连坐、富强为《史记》多源可考→确证；惟《商君书》具体条文部分托名、细节存疑。","historicity":"confirmed","linked_cards":["shangyang"],"tags":["治理决策","资源调度"],"advisor_id":"shangyang"}', 'aaa3d8cf3a732e171d8b126e0d5e24733046f61f4d5d6f08a52d72519fe038d1');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('shangyang-c3', 'shangyang', '太子犯法·刑其师傅（变法立威）', '新法初行即遭抵触，太子（储君）触犯新法；若因其尊贵而免，则法不立、新政崩。', '太子不可施刑，遂刑其师傅公子虔、黥其师公孙贾，以明"刑无等级、不避权贵"，使法令威慑及于最高层。', '新法威信大立、秦人不敢犯；但也因严酷得罪权贵（公子虔等），为日后反噬埋下祸根。', '规则一旦对最高层与亲信网开一面就形同虚设——对权贵不例外才立得起威；但要清楚：这样做会树敌，须评估代价。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"shangyang-c3","status":"published","title_period":"太子犯法·刑其师傅（变法立威）","dilemma_constraints":"新法初行即遭抵触，太子（储君）触犯新法；若因其尊贵而免，则法不立、新政崩。","key_judgment":"太子不可施刑，遂刑其师傅公子虔、黥其师公孙贾，以明\"刑无等级、不避权贵\"，使法令威慑及于最高层。","model_invoked":["不别亲疏一断于法"],"outcome":"新法威信大立、秦人不敢犯；但也因严酷得罪权贵（公子虔等），为日后反噬埋下祸根。","transferable_lesson":"规则一旦对最高层与亲信网开一面就形同虚设——对权贵不例外才立得起威；但要清楚：这样做会树敌，须评估代价。","source_tier":"secondary","source_note":"刑公子虔、黥公孙贾为《史记·商君列传》可考→确证。","historicity":"confirmed","linked_cards":["shangyang"],"tags":["治理决策","制度法治"],"advisor_id":"shangyang"}', '4ab78edfeef9a9baed230e1b97a494ed267b78c4cf9d64d2dd54b8effde8734f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('shangyang-c4', 'shangyang', '作法自毙·车裂而死（前338）', '（消极判例）秦孝公死、太子（秦惠文王）即位，商鞅因变法树敌过多、尤遭旧贵族（公子虔等）忌恨。', '（反噬）商鞅出逃，途中欲投宿却因自己定的"无验者不得留宿"之法而不得，终被诬谋反、车裂而死。', '商鞅身死族灭，但其制度多被秦延续；"作法自毙"成其极端手段反噬自身的著名教训。', '用过刚的刑罚强制立威，会在你失去靠山时反噬自身——制度的烈度若只靠强权支撑、不留缓冲与人心，终会回头伤你。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"shangyang-c4","status":"published","title_period":"作法自毙·车裂而死（前338）","dilemma_constraints":"（消极判例）秦孝公死、太子（秦惠文王）即位，商鞅因变法树敌过多、尤遭旧贵族（公子虔等）忌恨。","key_judgment":"（反噬）商鞅出逃，途中欲投宿却因自己定的\"无验者不得留宿\"之法而不得，终被诬谋反、车裂而死。","model_invoked":["刑赏二柄"],"outcome":"商鞅身死族灭，但其制度多被秦延续；\"作法自毙\"成其极端手段反噬自身的著名教训。","transferable_lesson":"用过刚的刑罚强制立威，会在你失去靠山时反噬自身——制度的烈度若只靠强权支撑、不留缓冲与人心，终会回头伤你。","source_tier":"secondary","source_note":"商鞅之死、车裂为《史记·商君列传》可考→确证；\"投宿不得\"细节含史家叙事色彩、主干确证。","historicity":"confirmed","linked_cards":["shangyang"],"tags":["治理决策","危机应对"],"advisor_id":"shangyang"}', 'e514f13de537b3bb5022f82fe9145751f5283aa111f288dfd2c154c657439450');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('augustus-c1', 'augustus', '拒绝国王称号、自称"第一公民"·实权而非虚名（公元前27年起）', '凯撒因被疑图谋王位而遇刺，扎眼的头衔意味着危险。', '屋大维吸取凯撒教训，拒绝"国王""独裁官"等刺激性称号，只谦称"第一公民（Princeps）"，把刺眼的名分让出、实权牢牢在握。', '屋大维避免了凯撒的下场，平稳地掌握了实权、开创元首制。', '追求实际的权力与控制、而非扎眼的头衔与虚名——刻意放低名分、避免成为众矢之的。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"augustus-c1","status":"published","title_period":"拒绝国王称号、自称\"第一公民\"·实权而非虚名（公元前27年起）","dilemma_constraints":"凯撒因被疑图谋王位而遇刺，扎眼的头衔意味着危险。","key_judgment":"屋大维吸取凯撒教训，拒绝\"国王\"\"独裁官\"等刺激性称号，只谦称\"第一公民（Princeps）\"，把刺眼的名分让出、实权牢牢在握。","model_invoked":["实权而非虚名"],"outcome":"屋大维避免了凯撒的下场，平稳地掌握了实权、开创元首制。","transferable_lesson":"追求实际的权力与控制、而非扎眼的头衔与虚名——刻意放低名分、避免成为众矢之的。","source_tier":"secondary","source_note":"屋大维拒国王称号、自称Princeps为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["augustus"],"tags":["组织管理","竞争博弈"],"advisor_id":"augustus"}', '8a6277ac5a02ccd883f16fe9ca3d5c90fd5c69e7906e2c2da4d78fe26d2c435d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('augustus-c2', 'augustus', '「恢复共和」之名行元首制之实·旧瓶装新酒（公元前27年）', '罗马有深厚的共和传统、痛恨王政与独裁，公开称帝必激起反抗。', '奥古斯都名义上"恢复共和"、保留元老院等共和形式与传统，实则把军权、财权、人事集于元首一身。', '奥古斯都以共和的外壳平稳地建立了个人集权的元首制，减少了变革的阻力（但实为对共和的精致架空）。', '保留旧制度的外壳与传统、同时悄悄注入新实质，比公开砸碎旧瓶阻力小——但须知这也含架空与蒙蔽之嫌。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"augustus-c2","status":"published","title_period":"「恢复共和」之名行元首制之实·旧瓶装新酒（公元前27年）","dilemma_constraints":"罗马有深厚的共和传统、痛恨王政与独裁，公开称帝必激起反抗。","key_judgment":"奥古斯都名义上\"恢复共和\"、保留元老院等共和形式与传统，实则把军权、财权、人事集于元首一身。","model_invoked":["旧瓶装新酒"],"outcome":"奥古斯都以共和的外壳平稳地建立了个人集权的元首制，减少了变革的阻力（但实为对共和的精致架空）。","transferable_lesson":"保留旧制度的外壳与传统、同时悄悄注入新实质，比公开砸碎旧瓶阻力小——但须知这也含架空与蒙蔽之嫌。","source_tier":"secondary","source_note":"奥古斯都\"恢复共和\"之名行元首制之实为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["augustus"],"tags":["组织管理","竞争博弈"],"advisor_id":"augustus"}', '5bfbf2b8f3c5dc2fb06206e7c5194b70a31104f9951ce04ed511b9e9eeb6bdc4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('augustus-c3', 'augustus', '以一连串合法授权逐步集权·渐进积累（公元前1世纪末）', '一次性攫取全部权力会招致警惕与反弹。', '屋大维不急于一步到位，而是以执政官、保民官权、最高统帅权等一连串看似合法的授权，逐步把大权集于一身。', '屋大维以温和、合法的渐进方式集中了权力，降低了反弹。', '别急于一步到位——分步、以一个个看似合理合法的名义逐渐积累，让每一步都显得温和、最终水到渠成。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"augustus-c3","status":"published","title_period":"以一连串合法授权逐步集权·渐进积累（公元前1世纪末）","dilemma_constraints":"一次性攫取全部权力会招致警惕与反弹。","key_judgment":"屋大维不急于一步到位，而是以执政官、保民官权、最高统帅权等一连串看似合法的授权，逐步把大权集于一身。","model_invoked":["渐进积累而非一步到位"],"outcome":"屋大维以温和、合法的渐进方式集中了权力，降低了反弹。","transferable_lesson":"别急于一步到位——分步、以一个个看似合理合法的名义逐渐积累，让每一步都显得温和、最终水到渠成。","source_tier":"secondary","source_note":"屋大维以一连串合法授权逐步集权为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["augustus"],"tags":["组织管理","竞争博弈"],"advisor_id":"augustus"}', '96d5182a07ac294d22eca308e1a14b4155ed3bf3127fd654c16902fc5ea53cb2');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('augustus-c4', 'augustus', '开创"罗马和平"·制度建设固长治（公元前27—公元14）', '如何把一己之权威转化为长久的秩序与基业。', '奥古斯都建立了元首制的行政、常备军、财政税制等制度，开创了约二百年的"罗马和平（Pax Romana）"。', '罗马进入长期的稳定与繁荣，奥古斯都"接手砖城、留下大理石城"。', '把一时的个人权威与胜利转化为可持续的制度与秩序——制度才能长治久安（但其私授继承也埋下后世暴君隐患）。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"augustus-c4","status":"published","title_period":"开创\"罗马和平\"·制度建设固长治（公元前27—公元14）","dilemma_constraints":"如何把一己之权威转化为长久的秩序与基业。","key_judgment":"奥古斯都建立了元首制的行政、常备军、财政税制等制度，开创了约二百年的\"罗马和平（Pax Romana）\"。","model_invoked":["制度建设固长治"],"outcome":"罗马进入长期的稳定与繁荣，奥古斯都\"接手砖城、留下大理石城\"。","transferable_lesson":"把一时的个人权威与胜利转化为可持续的制度与秩序——制度才能长治久安（但其私授继承也埋下后世暴君隐患）。","source_tier":"secondary","source_note":"奥古斯都开创罗马和平、建立制度为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["augustus"],"tags":["长期规划","组织管理"],"advisor_id":"augustus"}', '6b563cebdd1abee815e53a278d52baedc92e11582d8c4fae8d2edc12133a1f51');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhangjuzheng-c1', 'zhangjuzheng', '推行考成法·绩效问责（万历初年）', '明中后期吏治松弛、政令空转、官员推诿。', '张居正推行"考成法"，立限考事、以事责人，逐级登记考核、按结果奖惩，使政令必行。', '考成法大大提高了行政效率，是万历新政的核心举措之一。', '建立定目标、限期、逐级考核、按结果奖惩的问责制度——让每件事都有人负责、到期必查、政令不落空。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhangjuzheng-c1","status":"published","title_period":"推行考成法·绩效问责（万历初年）","dilemma_constraints":"明中后期吏治松弛、政令空转、官员推诿。","key_judgment":"张居正推行\"考成法\"，立限考事、以事责人，逐级登记考核、按结果奖惩，使政令必行。","model_invoked":["考成法"],"outcome":"考成法大大提高了行政效率，是万历新政的核心举措之一。","transferable_lesson":"建立定目标、限期、逐级考核、按结果奖惩的问责制度——让每件事都有人负责、到期必查、政令不落空。","source_tier":"secondary","source_note":"考成法为《明史》及万历新政史所载→确证（二手B）。","historicity":"confirmed","linked_cards":["zhangjuzheng"],"tags":["组织管理","长期规划"],"advisor_id":"zhangjuzheng"}', '5795ce45504ac9e3e7acdcd4fad47266e70ac11b384cc6327e5bcac909048637');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhangjuzheng-c2', 'zhangjuzheng', '推行一条鞭法·赋役简化（万历年间）', '明代赋役名目繁杂、征收混乱、盘剥空间大。', '张居正推行"一条鞭法"，把繁杂的赋役合并、折银统一征收，简化了征收、压缩了盘剥空间。', '一条鞭法简化了赋役制度，是中国赋税史上的重要改革。', '把繁杂、易被钻空子的项目合并简化为统一、透明的一条——简化本身就堵住了盘剥与混乱。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhangjuzheng-c2","status":"published","title_period":"推行一条鞭法·赋役简化（万历年间）","dilemma_constraints":"明代赋役名目繁杂、征收混乱、盘剥空间大。","key_judgment":"张居正推行\"一条鞭法\"，把繁杂的赋役合并、折银统一征收，简化了征收、压缩了盘剥空间。","model_invoked":["一条鞭法"],"outcome":"一条鞭法简化了赋役制度，是中国赋税史上的重要改革。","transferable_lesson":"把繁杂、易被钻空子的项目合并简化为统一、透明的一条——简化本身就堵住了盘剥与混乱。","source_tier":"secondary","source_note":"一条鞭法为万历新政史所载→确证（二手B；其推行有前期基础与地区差异）。","historicity":"confirmed","linked_cards":["zhangjuzheng"],"tags":["组织管理","长期规划"],"advisor_id":"zhangjuzheng"}', '27279767aed64bb9cb99bcd490b5eb90fc259fbdcb41569679406f0063c11426');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhangjuzheng-c3', 'zhangjuzheng', '重用循吏能吏·务实任事（执政期间）', '用人若重资历、虚名、门第，则难得办实事之人。', '张居正用人重实际才干与政绩，敢用能办实事的循吏能吏，不拘虚名资历。', '张居正麾下聚集了一批能臣，新政得以有力推行。', '只看实际把事做成的能力与效果、用人重才干不重虚名与资历——办实事的人比会说漂亮话的人有用。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhangjuzheng-c3","status":"published","title_period":"重用循吏能吏·务实任事（执政期间）","dilemma_constraints":"用人若重资历、虚名、门第，则难得办实事之人。","key_judgment":"张居正用人重实际才干与政绩，敢用能办实事的循吏能吏，不拘虚名资历。","model_invoked":["务实任事不务虚名"],"outcome":"张居正麾下聚集了一批能臣，新政得以有力推行。","transferable_lesson":"只看实际把事做成的能力与效果、用人重才干不重虚名与资历——办实事的人比会说漂亮话的人有用。","source_tier":"secondary","source_note":"张居正务实用人为史述→确证（二手B）。","historicity":"confirmed","linked_cards":["zhangjuzheng"],"tags":["组织管理"],"advisor_id":"zhangjuzheng"}', '1f9ae51025ff5b23ea15e17d66703f305f76ed99836a029d985a14fba014870f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhangjuzheng-c4', 'zhangjuzheng', '集权主导万历新政·集权强推（万历初年）', '改革必触动既得利益、阻力极大。', '张居正以内阁首辅之位集权，顶住阻力强势推行万历新政；但其身后即遭清算、新政多被废止。', '万历新政一度使明朝中兴，但张居正死后即被清算、人亡政息，暴露了改革过度系于个人之弊。', '重大改革需集中权力顶住阻力强推——但须知集权强推也埋下身后被清算、人亡政息的隐患，改革需可持续的制度保障。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhangjuzheng-c4","status":"published","title_period":"集权主导万历新政·集权强推（万历初年）","dilemma_constraints":"改革必触动既得利益、阻力极大。","key_judgment":"张居正以内阁首辅之位集权，顶住阻力强势推行万历新政；但其身后即遭清算、新政多被废止。","model_invoked":["集权强推改革"],"outcome":"万历新政一度使明朝中兴，但张居正死后即被清算、人亡政息，暴露了改革过度系于个人之弊。","transferable_lesson":"重大改革需集中权力顶住阻力强推——但须知集权强推也埋下身后被清算、人亡政息的隐患，改革需可持续的制度保障。","source_tier":"secondary","source_note":"万历新政及张居正身后被清算为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["zhangjuzheng"],"tags":["组织管理","危机应对"],"advisor_id":"zhangjuzheng"}', '5d748548c1ce1b0c1333c5b21c61dce6dbf28c82a4a91a1965525fbaa40d1929');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('degaulle-c1', 'degaulle', '创建"自由法国"·危亡中坚持正统（1940）', '1940年法国战败、维希政府向纳粹投降，法国看似已亡。', '戴高乐流亡伦敦，发表广播号召抵抗，坚称自己代表"真正的法国"，举起"自由法国"的旗帜。', '「自由法国」成为法国抵抗的旗帜，戴高乐保住了法国的法统与战后地位。', '当组织危亡、官方已放弃投降时，挺身而出、坚持代表它真正的精神与正统、把火种与希望保住。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"degaulle-c1","status":"published","title_period":"创建\"自由法国\"·危亡中坚持正统（1940）","dilemma_constraints":"1940年法国战败、维希政府向纳粹投降，法国看似已亡。","key_judgment":"戴高乐流亡伦敦，发表广播号召抵抗，坚称自己代表\"真正的法国\"，举起\"自由法国\"的旗帜。","model_invoked":["危亡中坚持正统"],"outcome":"「自由法国」成为法国抵抗的旗帜，戴高乐保住了法国的法统与战后地位。","transferable_lesson":"当组织危亡、官方已放弃投降时，挺身而出、坚持代表它真正的精神与正统、把火种与希望保住。","source_tier":"secondary","source_note":"戴高乐创建自由法国为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["degaulle"],"tags":["危机应对","领导力"],"advisor_id":"degaulle"}', 'fb3668ef02e089b47b1b6bb89aba0c79a4d41acbd9f433810c67f8ebb6b52d32');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('degaulle-c2', 'degaulle', '坚持法国独立地位·独立自主（战时与战后）', '法国战时依赖盟友、战后处于美苏两强格局中。', '戴高乐即便依赖盟友，仍坚持法国的独立立场与尊严（如战后发展独立核力量、一度退出北约军事一体化指挥）。', '戴高乐为法国赢得了相对独立的国际地位与尊严。', '即使弱小也坚持自主的立场与尊严、不轻易做强者的附庸——独立的人格才赢得真正的尊重。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"degaulle-c2","status":"published","title_period":"坚持法国独立地位·独立自主（战时与战后）","dilemma_constraints":"法国战时依赖盟友、战后处于美苏两强格局中。","key_judgment":"戴高乐即便依赖盟友，仍坚持法国的独立立场与尊严（如战后发展独立核力量、一度退出北约军事一体化指挥）。","model_invoked":["独立自主不做附庸"],"outcome":"戴高乐为法国赢得了相对独立的国际地位与尊严。","transferable_lesson":"即使弱小也坚持自主的立场与尊严、不轻易做强者的附庸——独立的人格才赢得真正的尊重。","source_tier":"secondary","source_note":"戴高乐的独立外交为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["degaulle"],"tags":["竞争博弈","领导力"],"advisor_id":"degaulle"}', '7640cafd406fe4fdeab0d6888b16eae430199c077dad189a0c0ee43222033c4d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('degaulle-c3', 'degaulle', '超越党派以国家为念·超党派（战后）', '战后法国党派林立、纷争不休。', '戴高乐以国家整体与长远利益为念，自居于党派纷争之上，扮演国家统合者的角色。', '戴高乐成为法国国家统合的象征性人物。', '站在派系纷争之上、以整体的、长远的利益为依归——当裁判而非当球员。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"degaulle-c3","status":"published","title_period":"超越党派以国家为念·超党派（战后）","dilemma_constraints":"战后法国党派林立、纷争不休。","key_judgment":"戴高乐以国家整体与长远利益为念，自居于党派纷争之上，扮演国家统合者的角色。","model_invoked":["超越党派的整体利益"],"outcome":"戴高乐成为法国国家统合的象征性人物。","transferable_lesson":"站在派系纷争之上、以整体的、长远的利益为依归——当裁判而非当球员。","source_tier":"secondary","source_note":"戴高乐超党派的国家立场为史述→确证（二手B）。","historicity":"confirmed","linked_cards":["degaulle"],"tags":["领导力","长期规划"],"advisor_id":"degaulle"}', '4fd5f8601fa42e1aa35e4b7c93ea2339f1999317f06ec96ba16c37da7b000837');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('degaulle-c4', 'degaulle', '创建第五共和·重塑制度（1958）', '第四共和议会乱政、决策瘫痪、阿尔及利亚危机加剧。', '戴高乐主导制定新宪法、建立强化总统权力的第五共和，终结了议会乱政、提升了决策效率。', '第五共和延续至今，但其强总统制也长期引发关于集权的争议。', '旧制度失灵时，不在旧框架里修补、而是重新设计一套更能集中决策、更能办事的新制度——但须防集权削弱制衡。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"degaulle-c4","status":"published","title_period":"创建第五共和·重塑制度（1958）","dilemma_constraints":"第四共和议会乱政、决策瘫痪、阿尔及利亚危机加剧。","key_judgment":"戴高乐主导制定新宪法、建立强化总统权力的第五共和，终结了议会乱政、提升了决策效率。","model_invoked":["重塑制度以匹配现实"],"outcome":"第五共和延续至今，但其强总统制也长期引发关于集权的争议。","transferable_lesson":"旧制度失灵时，不在旧框架里修补、而是重新设计一套更能集中决策、更能办事的新制度——但须防集权削弱制衡。","source_tier":"secondary","source_note":"戴高乐创建第五共和为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["degaulle"],"tags":["危机应对","长期规划"],"advisor_id":"degaulle"}', 'b9da549872267a4dd99c2e5cd1a73daccc8344e28f711d19dde541b6a7c42aad');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lishimin-c1', 'lishimin', '纳魏徵直谏·以人为镜（贞观年间）', '魏徵屡次当面犯颜直谏、甚至顶撞太宗，触怒龙颜；若以威权压制，则再无人敢言、自陷偏信。', '太宗多能克制怒气、纳魏徵之谏，视其为镜子；魏徵死后叹"以铜为镜可正衣冠、以古为镜可知兴替、以人为镜可明得失"。', '贞观一朝以善纳谏著称，决策多得纠偏；"兼听则明、以人为镜"成纳谏的千古标杆。', '位置越高越要主动留住敢当面说你不对的人——把逆耳之言当镜子，最怕的不是有人反对你，而是没人敢反对你。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lishimin-c1","status":"published","title_period":"纳魏徵直谏·以人为镜（贞观年间）","dilemma_constraints":"魏徵屡次当面犯颜直谏、甚至顶撞太宗，触怒龙颜；若以威权压制，则再无人敢言、自陷偏信。","key_judgment":"太宗多能克制怒气、纳魏徵之谏，视其为镜子；魏徵死后叹\"以铜为镜可正衣冠、以古为镜可知兴替、以人为镜可明得失\"。","model_invoked":["兼听则明"],"outcome":"贞观一朝以善纳谏著称，决策多得纠偏；\"兼听则明、以人为镜\"成纳谏的千古标杆。","transferable_lesson":"位置越高越要主动留住敢当面说你不对的人——把逆耳之言当镜子，最怕的不是有人反对你，而是没人敢反对你。","source_tier":"secondary","source_note":"魏徵直谏、君臣纳谏、\"以人为镜\"之叹为正史与《贞观政要》可考→确证；惟《贞观政要》后人编、部分对话经润色，措辞细节存润色。","historicity":"confirmed","linked_cards":["lishimin"],"tags":["治理决策","领导力"],"advisor_id":"lishimin"}', '8f930b108c9e87d4361175c300136a8cc1e81f519a51af63b3c9741856a0294c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lishimin-c2', 'lishimin', '房谋杜断·知人善任（贞观年间）', '治国需谋划与决断两种不同才能，少有人兼备；若求全责备，则人才难用。', '太宗用房玄龄之"善谋"、杜如晦之"善断"，使二人谋断相成、各尽其才，不以一短弃人。', '「房谋杜断」成知人善任、用人之长的典范，贞观人才济济、政事修明。', '别要求每个人都全能——找出各人的长处、让善谋的去谋、善断的去断，长短互补比求全责备更高效。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lishimin-c2","status":"published","title_period":"房谋杜断·知人善任（贞观年间）","dilemma_constraints":"治国需谋划与决断两种不同才能，少有人兼备；若求全责备，则人才难用。","key_judgment":"太宗用房玄龄之\"善谋\"、杜如晦之\"善断\"，使二人谋断相成、各尽其才，不以一短弃人。","model_invoked":["知人善任"],"outcome":"「房谋杜断」成知人善任、用人之长的典范，贞观人才济济、政事修明。","transferable_lesson":"别要求每个人都全能——找出各人的长处、让善谋的去谋、善断的去断，长短互补比求全责备更高效。","source_tier":"secondary","source_note":"房谋杜断、太宗用人之长为正史可考→确证。","historicity":"confirmed","linked_cards":["lishimin"],"tags":["组织管理","领导力"],"advisor_id":"lishimin"}', '9593df5895d9e3eae60a5d925ae63c236a9b6c1520d0ea235a40574871143cc3');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lishimin-c3', 'lishimin', '以隋亡为戒·居安思危戒奢（贞观前中期）', '唐承隋乱而立，国力初复；若因开国之盛而骄奢，恐重蹈隋炀帝速亡之覆辙。', '太宗常与群臣论隋亡之鉴、纳魏徵"水能载舟亦能覆舟"之论，戒奢以俭、轻徭薄赋、警惕民心向背。', '贞观之治休养生息、轻徭薄赋，国力渐盛、民生渐安；居安思危成其治世根基。', '越是顺风顺水、开局大好，越要以前人的覆亡为戒、警惕人心向背——水能载舟、亦能覆舟。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lishimin-c3","status":"published","title_period":"以隋亡为戒·居安思危戒奢（贞观前中期）","dilemma_constraints":"唐承隋乱而立，国力初复；若因开国之盛而骄奢，恐重蹈隋炀帝速亡之覆辙。","key_judgment":"太宗常与群臣论隋亡之鉴、纳魏徵\"水能载舟亦能覆舟\"之论，戒奢以俭、轻徭薄赋、警惕民心向背。","model_invoked":["居安思危载舟覆舟"],"outcome":"贞观之治休养生息、轻徭薄赋，国力渐盛、民生渐安；居安思危成其治世根基。","transferable_lesson":"越是顺风顺水、开局大好，越要以前人的覆亡为戒、警惕人心向背——水能载舟、亦能覆舟。","source_tier":"secondary","source_note":"以隋亡为戒、戒奢、\"载舟覆舟\"论为正史与《贞观政要》可考→确证；具体对话措辞含《贞观政要》润色。","historicity":"confirmed","linked_cards":["lishimin"],"tags":["治理决策","长期规划"],"advisor_id":"lishimin"}', 'e9b1ed09eabeabdf3838718e77e5a799281d6575c69a13aa91aa3a49bb19c95f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lishimin-c4', 'lishimin', '晚年纳谏渐少·征高句丽失利（贞观后期）', '（消极判例）随着功业鼎盛、年事渐高，太宗渐生骄怠，纳谏不如初年，并执意远征高句丽。', '（反例）晚年听谏渐少、修宫室渐奢、不顾劝阻远征高句丽，魏徵已逝、直言渐稀。', '征高句丽未竟全功、损耗国力；"善始者实繁、克终者盖寡"——其虚心纳谏未能贯彻始终。', '善始易、善终难——再善于纳谏的人，也可能在成功与年长中渐渐听不进逆耳之言；把纳谏贯彻始终，比一时虚心更难。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lishimin-c4","status":"published","title_period":"晚年纳谏渐少·征高句丽失利（贞观后期）","dilemma_constraints":"（消极判例）随着功业鼎盛、年事渐高，太宗渐生骄怠，纳谏不如初年，并执意远征高句丽。","key_judgment":"（反例）晚年听谏渐少、修宫室渐奢、不顾劝阻远征高句丽，魏徵已逝、直言渐稀。","model_invoked":["兼听则明"],"outcome":"征高句丽未竟全功、损耗国力；\"善始者实繁、克终者盖寡\"——其虚心纳谏未能贯彻始终。","transferable_lesson":"善始易、善终难——再善于纳谏的人，也可能在成功与年长中渐渐听不进逆耳之言；把纳谏贯彻始终，比一时虚心更难。","source_tier":"secondary","source_note":"晚年纳谏渐少、征高句丽失利为正史可考→确证；本条作其\"克终者盖寡\"盲区的案例体现。","historicity":"confirmed","linked_cards":["lishimin"],"tags":["治理决策","危机应对"],"advisor_id":"lishimin"}', 'd3cbaa07039c460c7559e9194b3bd44cd564d285da351bda57e9d77c23d765dc');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lincoln-c1', 'lincoln', '组建"政敌内阁"（1860–61）', '初当选、资历浅、被党内大佬轻视；可选顺从亲信组阁求安稳，或起用曾与己争位、各怀心思的强人。', '起用西华德、蔡斯、贝茨等竞争对手入阁，宁要一个吵闹但强大的核心，不要一群应声虫。', '内阁虽时有龃龉，却汇聚最强才干，助其驾驭战争与党争。', '用认知多样性和强反对者对冲自身盲区，胜过用顺从者包围自己换取舒适。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lincoln-c1","status":"published","title_period":"组建\"政敌内阁\"（1860–61）","dilemma_constraints":"初当选、资历浅、被党内大佬轻视；可选顺从亲信组阁求安稳，或起用曾与己争位、各怀心思的强人。","key_judgment":"起用西华德、蔡斯、贝茨等竞争对手入阁，宁要一个吵闹但强大的核心，不要一群应声虫。","model_invoked":["纳政敌入核心"],"outcome":"内阁虽时有龃龉，却汇聚最强才干，助其驾驭战争与党争。","transferable_lesson":"用认知多样性和强反对者对冲自身盲区，胜过用顺从者包围自己换取舒适。","source_tier":"secondary","source_note":"史实，见严肃史学对林肯组阁的权威研究（B）；叙述细节有学术加工但主干确证。","historicity":"confirmed","linked_cards":["lincoln"],"tags":["领导力","组织管理"],"advisor_id":"lincoln"}', '30657366c09d29c06b0d4bd41d3a6749e4d4fafa6e07223167de1355cc41bb20');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lincoln-c2', 'lincoln', '解放宣言押后待时（1862）', '既想推动解放又恐时机不当；若在军事失利中发布，会被视为绝望之举而失效，且恐失去边境蓄奴州。', '压下已拟好的宣言，等到安提塔姆战役止住颓势后（1862年9月）才发布预备宣言。', '宣言以"胜势"而非"败势"姿态出台，政治与军事效果大增。', '对的决定要在对的时点出手；正确但时机未熟的行动，可能因姿态不对而失败。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lincoln-c2","status":"published","title_period":"解放宣言押后待时（1862）","dilemma_constraints":"既想推动解放又恐时机不当；若在军事失利中发布，会被视为绝望之举而失效，且恐失去边境蓄奴州。","key_judgment":"压下已拟好的宣言，等到安提塔姆战役止住颓势后（1862年9月）才发布预备宣言。","model_invoked":["待时而动"],"outcome":"宣言以\"胜势\"而非\"败势\"姿态出台，政治与军事效果大增。","transferable_lesson":"对的决定要在对的时点出手；正确但时机未熟的行动，可能因姿态不对而失败。","source_tier":"secondary","source_note":"史实，见史学界对解放宣言时机的研究（B）；西华德进言\"待胜再发\"亦有载。","historicity":"confirmed","linked_cards":["lincoln"],"tags":["危机应对","治理决策"],"advisor_id":"lincoln"}', '361791f2ae90327a45430ec56be21137c8362c18ad67e859546882cbd58e923c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lincoln-c3', 'lincoln', '致格里利公开信（1862.8）', '废奴派公开施压要求立即解放；林肯须既不背弃反奴信念、又不动摇"保全联邦"这一战时至高目标。', '公开申明此役至高目标是拯救联邦；救联邦若需解放则解放、若需不解放则不解放——以目标统御手段。', '既稳住了战时联盟，又为日后按时机推进解放留出空间。', '把唯一至高目标设为不可妥协的硬约束，其余手段、时机、姿态都当作可调整的变量。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lincoln-c3","status":"published","title_period":"致格里利公开信（1862.8）","dilemma_constraints":"废奴派公开施压要求立即解放；林肯须既不背弃反奴信念、又不动摇\"保全联邦\"这一战时至高目标。","key_judgment":"公开申明此役至高目标是拯救联邦；救联邦若需解放则解放、若需不解放则不解放——以目标统御手段。","model_invoked":["目的坚定·手段灵活"],"outcome":"既稳住了战时联盟，又为日后按时机推进解放留出空间。","transferable_lesson":"把唯一至高目标设为不可妥协的硬约束，其余手段、时机、姿态都当作可调整的变量。","source_tier":"primary","source_note":"一手，1862年8月22日致霍勒斯·格里利公开信原文（A）。","historicity":"confirmed","linked_cards":["lincoln"],"tags":["治理决策","长期规划"],"advisor_id":"lincoln"}', 'bc0afdedf918e8f3421ef36283de8e095b702effcf1af12e401c3583dfb70440');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lincoln-c4', 'lincoln', '致米德将军的"冷信"未发（1863.7）', '葛底斯堡大胜后米德未乘胜追歼撤退的李军、错失早结束战争之机；林肯极度愤怒、提笔痛斥。', '写下措辞严厉的责备信后，将其压下、终未寄出，文末自注"未发、未署名"。', '避免在盛怒下折损一位仍需倚重的将领，保全了关系与大局。', '把宣泄情绪与做出决定切开——怒时可写下来，但压一压、别让怒气替你拍板。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lincoln-c4","status":"published","title_period":"致米德将军的\"冷信\"未发（1863.7）","dilemma_constraints":"葛底斯堡大胜后米德未乘胜追歼撤退的李军、错失早结束战争之机；林肯极度愤怒、提笔痛斥。","key_judgment":"写下措辞严厉的责备信后，将其压下、终未寄出，文末自注\"未发、未署名\"。","model_invoked":["冷信不发"],"outcome":"避免在盛怒下折损一位仍需倚重的将领，保全了关系与大局。","transferable_lesson":"把宣泄情绪与做出决定切开——怒时可写下来，但压一压、别让怒气替你拍板。","source_tier":"primary","source_note":"一手，该信存于林肯文件、带其\"never sent, or signed\"批注（A）。","historicity":"confirmed","linked_cards":["lincoln"],"tags":["危机应对","领导力"],"advisor_id":"lincoln"}', '0ef42aef26d7df043b5241b6ddbf445f2a7f20ddc87dea2b213685355bacd973');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lincoln-c5', 'lincoln', '第二任就职演说·定调和解（1865.3）', '内战胜利在望，北方多有清算南方之声；如何为战后重建定下基调，决定国家能否真正缝合。', '以"对任何人不怀恶意、对所有人心怀宽厚"为纲，把战后导向和解而非报复。', '为重建立下宽厚基调（惜其旋即遇刺，未及亲手落实）。', '冲突收尾时，赢得一个还能共处的局面，往往比赢得一场彻底的清算更重要。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lincoln-c5","status":"published","title_period":"第二任就职演说·定调和解（1865.3）","dilemma_constraints":"内战胜利在望，北方多有清算南方之声；如何为战后重建定下基调，决定国家能否真正缝合。","key_judgment":"以\"对任何人不怀恶意、对所有人心怀宽厚\"为纲，把战后导向和解而非报复。","model_invoked":["以叙事赋予意义"],"outcome":"为重建立下宽厚基调（惜其旋即遇刺，未及亲手落实）。","transferable_lesson":"冲突收尾时，赢得一个还能共处的局面，往往比赢得一场彻底的清算更重要。","source_tier":"primary","source_note":"一手，1865年3月第二任就职演说原文（A）。","historicity":"confirmed","linked_cards":["lincoln"],"tags":["领导力","长期规划"],"advisor_id":"lincoln"}', '73febeaac06a53c910a60a43abbcbc41c638b6d1c93641c1f7423892a031421e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('lincoln-c6', 'lincoln', '战时中止人身保护令（1861起）', '战争威胁联邦存续，常规法律程序被认为妨碍镇压叛乱与间谍；但中止人身保护令在宪法上极具争议。', '为保全联邦，下令在特定区域中止人身保护令、扩大军事拘押，越过常规宪法边界。', '短期强化了战时控制，但开创争议先例，当时及后世持续批评。', '当一切手段都服从单一至高目标时，最容易为该目标合理化本不该跨越的边界——这正是该模型的风险面。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"lincoln-c6","status":"published","title_period":"战时中止人身保护令（1861起）","dilemma_constraints":"战争威胁联邦存续，常规法律程序被认为妨碍镇压叛乱与间谍；但中止人身保护令在宪法上极具争议。","key_judgment":"为保全联邦，下令在特定区域中止人身保护令、扩大军事拘押，越过常规宪法边界。","model_invoked":["目的坚定·手段灵活"],"outcome":"短期强化了战时控制，但开创争议先例，当时及后世持续批评。","transferable_lesson":"当一切手段都服从单一至高目标时，最容易为该目标合理化本不该跨越的边界——这正是该模型的风险面。","source_tier":"secondary","source_note":"史实，见宪法史与林肯研究（B）；Ex parte Merryman 争议有载。本条同时是 blind_spots①在案例中的体现。","historicity":"confirmed","linked_cards":["lincoln"],"tags":["治理决策","危机应对"],"advisor_id":"lincoln"}', 'a2969f2a09540f2ddc305bbc2ce35ceb863c2c214e87325793cca4d96612638c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wanganshi-c1', 'wanganshi', '「理财为方今先急」·理财为先（熙宁变法）', '北宋"积贫积弱"、财政困窘、冗官冗兵。', '王安石认为变法的核心在理财——"理财为方今先急"，主张开源、把资源用活，而非只在节流或人事上打转。', '王安石以理财为核心推动了熙宁变法，一度增加了国家财政收入。', '组织积弱的根本常在"钱"没理顺——把开源、理财、把资源用活作为改革的核心抓手。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wanganshi-c1","status":"published","title_period":"「理财为方今先急」·理财为先（熙宁变法）","dilemma_constraints":"北宋\"积贫积弱\"、财政困窘、冗官冗兵。","key_judgment":"王安石认为变法的核心在理财——\"理财为方今先急\"，主张开源、把资源用活，而非只在节流或人事上打转。","model_invoked":["理财为先"],"outcome":"王安石以理财为核心推动了熙宁变法，一度增加了国家财政收入。","transferable_lesson":"组织积弱的根本常在\"钱\"没理顺——把开源、理财、把资源用活作为改革的核心抓手。","source_tier":"secondary","source_note":"「理财为方今先急」为王安石主张、《宋史》所载→确证（二手B）。","historicity":"confirmed","linked_cards":["wanganshi"],"tags":["组织管理","长期规划"],"advisor_id":"wanganshi"}', 'b717e54ebf7816e67e927318680e7284aadfd893b3173b3035ebb3993974a2ae');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wanganshi-c2', 'wanganshi', '青苗法、募役法·制度性理财创新（熙宁年间）', '民间高利贷盘剥、差役繁重，财政与民生两困。', '王安石设计青苗法（官府低息贷款抑高利贷）、募役法（以钱代役）等新制度，靠制度创新理财、抑兼并。', '新法设计初衷良善、一度见效，但在执行中严重走样（青苗法被变成强制摊派、扰民），引发巨大争议。', '用设计新制度的办法去开源、抑兼并——但须知制度在执行中极易走样，设计还要顾及执行与监督。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wanganshi-c2","status":"published","title_period":"青苗法、募役法·制度性理财创新（熙宁年间）","dilemma_constraints":"民间高利贷盘剥、差役繁重，财政与民生两困。","key_judgment":"王安石设计青苗法（官府低息贷款抑高利贷）、募役法（以钱代役）等新制度，靠制度创新理财、抑兼并。","model_invoked":["制度性理财创新"],"outcome":"新法设计初衷良善、一度见效，但在执行中严重走样（青苗法被变成强制摊派、扰民），引发巨大争议。","transferable_lesson":"用设计新制度的办法去开源、抑兼并——但须知制度在执行中极易走样，设计还要顾及执行与监督。","source_tier":"secondary","source_note":"青苗法、募役法及其执行走样为《宋史》及变法史所载→确证（二手B）。","historicity":"confirmed","linked_cards":["wanganshi"],"tags":["组织管理","危机应对"],"advisor_id":"wanganshi"}', 'a6126e09a385d50eed8262514ea30b8820513fa6a7620a9b84c3087fed4c0dec');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wanganshi-c3', 'wanganshi', '「三不足」·不畏人言（熙宁变法）', '变法招致守旧势力与舆论的强烈反对。', '王安石以"天变不足畏、祖宗不足法、人言不足恤"的"三不足"精神，顶住非议、果决推行变法。', '「三不足」体现了改革的魄力，但其「不恤人言」也使他听不进合理反对、激化了新旧党争。', '顶住非议、不被成见绑住、果决推行认准的改革——但"不恤人言"不等于听不进合理的反对，果决与纳谏要并存。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wanganshi-c3","status":"published","title_period":"「三不足」·不畏人言（熙宁变法）","dilemma_constraints":"变法招致守旧势力与舆论的强烈反对。","key_judgment":"王安石以\"天变不足畏、祖宗不足法、人言不足恤\"的\"三不足\"精神，顶住非议、果决推行变法。","model_invoked":["不畏人言果决变法"],"outcome":"「三不足」体现了改革的魄力，但其「不恤人言」也使他听不进合理反对、激化了新旧党争。","transferable_lesson":"顶住非议、不被成见绑住、果决推行认准的改革——但\"不恤人言\"不等于听不进合理的反对，果决与纳谏要并存。","source_tier":"secondary","source_note":"「三不足」为王安石名言、《宋史》所载→确证（二手B）。","historicity":"confirmed","linked_cards":["wanganshi"],"tags":["组织管理","危机应对"],"advisor_id":"wanganshi"}', '093621fbbf8075ebe0b2edb7e263c84958702f9a04c3ac1409ea342783abb24d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('wanganshi-c4', 'wanganshi', '熙宁变法的系统性与受挫·系统配套（熙宁—元丰）', '北宋积弊涉及财政、军事、人才多个方面。', '王安石的新法是涉及财政（青苗/募役/市易）、军事（保甲/保马）、教育科举（太学三舍/改科举）的系统工程；但战线过宽、操之过急、用人失察、党争激烈，终致受挫。', '熙宁变法是中国史上著名的系统性改革，但因执行走样与党争，成效与评价历来争议极大、最终多被废止。', '重大改革要成体系地配套推进——但战线过宽、操之过急、配套失调、用人失察，都会使系统变法走向反面。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"wanganshi-c4","status":"published","title_period":"熙宁变法的系统性与受挫·系统配套（熙宁—元丰）","dilemma_constraints":"北宋积弊涉及财政、军事、人才多个方面。","key_judgment":"王安石的新法是涉及财政（青苗/募役/市易）、军事（保甲/保马）、教育科举（太学三舍/改科举）的系统工程；但战线过宽、操之过急、用人失察、党争激烈，终致受挫。","model_invoked":["系统配套的整体变法"],"outcome":"熙宁变法是中国史上著名的系统性改革，但因执行走样与党争，成效与评价历来争议极大、最终多被废止。","transferable_lesson":"重大改革要成体系地配套推进——但战线过宽、操之过急、配套失调、用人失察，都会使系统变法走向反面。","source_tier":"secondary","source_note":"熙宁变法的系统性与受挫为史实→确证（二手B；评价历来有争议）。","historicity":"confirmed","linked_cards":["wanganshi"],"tags":["组织管理","长期规划"],"advisor_id":"wanganshi"}', 'fe663cf833acd4e0f7906374f8fa8d2cd46663d6805d302b7e1a7ed6c8bf5e59');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('guanzhong-c1', 'guanzhong', '相齐·通货积财富国强兵（约前685起）', '齐国欲图强争霸，却需大量财源养兵兴政；若直接重税，恐伤民、激民怨、损根本。', '不靠直接重税，而推"官山海"(盐铁专营)、以轻重之术调控物价与货币，把财政负担藏进必需品的流通中，同时"富民"安农。', '齐国国力大增、府库充实，为齐桓公称霸奠定经济基础；其经济治国之术影响后世。', '要为大目标筹资又不想伤根本，与其直接加税，不如用价格与专营等经济杠杆，把成本"藏"进必需品的流通里。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"guanzhong-c1","status":"published","title_period":"相齐·通货积财富国强兵（约前685起）","dilemma_constraints":"齐国欲图强争霸，却需大量财源养兵兴政；若直接重税，恐伤民、激民怨、损根本。","key_judgment":"不靠直接重税，而推\"官山海\"(盐铁专营)、以轻重之术调控物价与货币，把财政负担藏进必需品的流通中，同时\"富民\"安农。","model_invoked":["轻重之术"],"outcome":"齐国国力大增、府库充实，为齐桓公称霸奠定经济基础；其经济治国之术影响后世。","transferable_lesson":"要为大目标筹资又不想伤根本，与其直接加税，不如用价格与专营等经济杠杆，把成本\"藏\"进必需品的流通里。","source_tier":"secondary","source_note":"富齐强齐、通货积财为《史记·管晏列传》《国语·齐语》可考→确证；惟\"轻重诸术\"之具体文本多见《管子》、部分后世托名，文本细节存疑、事实主干确证。","historicity":"confirmed","linked_cards":["guanzhong"],"tags":["治理决策","资源调度"],"advisor_id":"guanzhong"}', '1c685fbf939a52a359ca048d90abd903be576ad6ae31619b63836344a0cf2ad4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('guanzhong-c2', 'guanzhong', '佐齐桓公"尊王攘夷"·九合诸侯（前7世纪中）', '齐虽强，但若以武力强压诸侯，名不正、易招群起而攻；如何名正言顺地取得诸侯领导权。', '打出"尊周王、攘夷狄"的大义旗号，以维护周室与华夏共同体的名义会盟诸侯，把齐的领导诉求接到一个各方都认的更高目标上。', '齐桓公九合诸侯、一匡天下，成春秋首霸；管仲"尊王攘夷"成借大义成霸业的经典。', '实力够了还要"名正"，借一个各方都认的大义旗号站位，比赤裸裸的强压更能凝聚与服众。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"guanzhong-c2","status":"published","title_period":"佐齐桓公\"尊王攘夷\"·九合诸侯（前7世纪中）","dilemma_constraints":"齐虽强，但若以武力强压诸侯，名不正、易招群起而攻；如何名正言顺地取得诸侯领导权。","key_judgment":"打出\"尊周王、攘夷狄\"的大义旗号，以维护周室与华夏共同体的名义会盟诸侯，把齐的领导诉求接到一个各方都认的更高目标上。","model_invoked":["借大义旗号取领导"],"outcome":"齐桓公九合诸侯、一匡天下，成春秋首霸；管仲\"尊王攘夷\"成借大义成霸业的经典。","transferable_lesson":"实力够了还要\"名正\"，借一个各方都认的大义旗号站位，比赤裸裸的强压更能凝聚与服众。","source_tier":"secondary","source_note":"九合诸侯、首霸、尊王攘夷为《史记》《左传》可考→确证。","historicity":"confirmed","linked_cards":["guanzhong"],"tags":["治理决策","领导力"],"advisor_id":"guanzhong"}', 'a72092e59d71cca201d8b2b033dd6273e449a2c564cb86ac081dab2deb51e96b');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('guanzhong-c3', 'guanzhong', '相地衰征·四民分业改革（相齐期间）', '旧税制与社会编制粗放，征税不均、各业混杂技艺难精，国力难以系统提升。', '推"相地而衰征"(按土地肥瘠分等征税)使负担公平，并令"四民分业定居"(士农工商分区聚居、世代专精)以积累技艺。', '税负趋公平、各业渐专精，齐国治理与生产效率系统提升。', '制度设计要按实际条件差别化、让专业各归其位、经验代际累积，系统效率才上得去。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"guanzhong-c3","status":"published","title_period":"相地衰征·四民分业改革（相齐期间）","dilemma_constraints":"旧税制与社会编制粗放，征税不均、各业混杂技艺难精，国力难以系统提升。","key_judgment":"推\"相地而衰征\"(按土地肥瘠分等征税)使负担公平，并令\"四民分业定居\"(士农工商分区聚居、世代专精)以积累技艺。","model_invoked":["因地制宜差别化"],"outcome":"税负趋公平、各业渐专精，齐国治理与生产效率系统提升。","transferable_lesson":"制度设计要按实际条件差别化、让专业各归其位、经验代际累积，系统效率才上得去。","source_tier":"secondary","source_note":"「相地衰征」「四民分业」见《国语·齐语》，主干可考；惟具体制度细节经后世(《管子》等)整理增益、部分托名，故制度细节判存疑、改革方向确证。","historicity":"disputed","linked_cards":["guanzhong"],"tags":["治理决策","长期规划"],"advisor_id":"guanzhong"}', '8429b8fed2902a56fa5ff4b0054a6959deaf0a0d08dff3c16f95e218146ecf29');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('saladin-c1', 'saladin', '统一分裂的穆斯林诸势力·团结分裂的力量（12世纪）', '面对强大的十字军，穆斯林各势力却分裂、内斗。', '萨拉丁先以政治与军事手段，把分裂、各自为政的埃及、叙利亚等势力围绕共同的大义统一、团结起来，形成对十字军的合力。', '萨拉丁建立阿尤布王朝、统一了对抗十字军的力量，为收复失地奠定基础。', '面对强大对手，先把分裂、内斗的各方围绕共同大义团结起来——内部团结是对外取胜的前提。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"saladin-c1","status":"published","title_period":"统一分裂的穆斯林诸势力·团结分裂的力量（12世纪）","dilemma_constraints":"面对强大的十字军，穆斯林各势力却分裂、内斗。","key_judgment":"萨拉丁先以政治与军事手段，把分裂、各自为政的埃及、叙利亚等势力围绕共同的大义统一、团结起来，形成对十字军的合力。","model_invoked":["团结分裂的力量"],"outcome":"萨拉丁建立阿尤布王朝、统一了对抗十字军的力量，为收复失地奠定基础。","transferable_lesson":"面对强大对手，先把分裂、内斗的各方围绕共同大义团结起来——内部团结是对外取胜的前提。","source_tier":"secondary","source_note":"萨拉丁统一穆斯林诸势力为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["saladin"],"tags":["领导力","竞争博弈"],"advisor_id":"saladin"}', '63f49b50e032535556f03c6ffa091ec5aacab2abc7acab403fe9cb7c4541b9f0');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('saladin-c2', 'saladin', '收复耶路撒冷后的宽待·宽容与气度服人（1187）', '胜利后，如何对待战败的对手与城中的平民。', '萨拉丁1187年收复耶路撒冷后，并未屠城报复，而是善待俘虏与平民、允许赎身、信守承诺，其宽容与骑士风度连敌人都敬重。', '萨拉丁以宽容赢得了包括对手在内的长久尊重，成为骑士精神的象征。', '以宽容、仁慈、信守承诺的气度对待对手，赢得长久的尊重——但宽容须以实力为后盾。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"saladin-c2","status":"published","title_period":"收复耶路撒冷后的宽待·宽容与气度服人（1187）","dilemma_constraints":"胜利后，如何对待战败的对手与城中的平民。","key_judgment":"萨拉丁1187年收复耶路撒冷后，并未屠城报复，而是善待俘虏与平民、允许赎身、信守承诺，其宽容与骑士风度连敌人都敬重。","model_invoked":["宽容与气度服人"],"outcome":"萨拉丁以宽容赢得了包括对手在内的长久尊重，成为骑士精神的象征。","transferable_lesson":"以宽容、仁慈、信守承诺的气度对待对手，赢得长久的尊重——但宽容须以实力为后盾。","source_tier":"secondary","source_note":"萨拉丁善待耶路撒冷为史实→确证（二手B；西方叙事有浪漫化成分、已入盲区）。","historicity":"confirmed","linked_cards":["saladin"],"tags":["领导力","价值与伦理"],"advisor_id":"saladin"}', 'a531d3558d6b650124e5720859baeb9a9024aaaf1bf3a54abe3d91846ac4e6a8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('saladin-c3', 'saladin', '哈丁战役与长期经营·坚韧与长期经营（1187）', '收复失地是强大而长远的目标，不可能一蹴而就。', '萨拉丁以多年的耐心经营、积累实力与威望，终在1187年哈丁战役中大败十字军主力，进而收复耶路撒冷。', '哈丁战役是十字军国家由盛转衰的转折，萨拉丁的长期经营终见成效。', '面对强大的目标，不急于一时之功——以耐心、坚韧、长期经营积累实力，等待时机成熟。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"saladin-c3","status":"published","title_period":"哈丁战役与长期经营·坚韧与长期经营（1187）","dilemma_constraints":"收复失地是强大而长远的目标，不可能一蹴而就。","key_judgment":"萨拉丁以多年的耐心经营、积累实力与威望，终在1187年哈丁战役中大败十字军主力，进而收复耶路撒冷。","model_invoked":["坚韧与长期经营"],"outcome":"哈丁战役是十字军国家由盛转衰的转折，萨拉丁的长期经营终见成效。","transferable_lesson":"面对强大的目标，不急于一时之功——以耐心、坚韧、长期经营积累实力，等待时机成熟。","source_tier":"secondary","source_note":"哈丁战役为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["saladin"],"tags":["竞争博弈","长期规划"],"advisor_id":"saladin"}', '2c0f50cc1a8e91fb4ac7c732cbd8d320fbc7ef8cc08781e367b7b52ccf3c9f22');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('saladin-c4', 'saladin', '个人简朴、慷慨施予·以身作则的节制（其一生）', '身为统治者，如何对待财富与自身。', '萨拉丁个人生活极为简朴、节制，把财富慷慨地用于事业与施予他人，据载他死时几乎没有留下私人遗产。', '萨拉丁以身作则的简朴与慷慨，赢得了巨大的个人威望与感召力。', '领袖自身简朴、节制、与众同甘苦，把资源用于共同的事业与施予——节制本身就是巨大的感召力。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"saladin-c4","status":"published","title_period":"个人简朴、慷慨施予·以身作则的节制（其一生）","dilemma_constraints":"身为统治者，如何对待财富与自身。","key_judgment":"萨拉丁个人生活极为简朴、节制，把财富慷慨地用于事业与施予他人，据载他死时几乎没有留下私人遗产。","model_invoked":["以身作则的节制"],"outcome":"萨拉丁以身作则的简朴与慷慨，赢得了巨大的个人威望与感召力。","transferable_lesson":"领袖自身简朴、节制、与众同甘苦，把资源用于共同的事业与施予——节制本身就是巨大的感召力。","source_tier":"secondary","source_note":"萨拉丁个人简朴、死时几无遗产为史述→确证（二手B）。","historicity":"confirmed","linked_cards":["saladin"],"tags":["领导力","修身自省"],"advisor_id":"saladin"}', '4d4203d42c7ca64d6ac56b5112f7e2b2c7ae17bd931d23fc29d02b0ff7126646');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhugeliang-c1', 'zhugeliang', '隆中对（建安十二年·207）', '刘备屡败、无尺寸根据地；曹操据北方、孙权据江东，弱者如何在强者夹缝立足并图天下。', '提出三阶段战略——跨有荆益为根基→外结孙权内修政理→待天下有变两路北伐。', '成蜀汉立国总纲领，刘备据此取荆益、成三分之势（《三国志》）。', '弱势起步者最该先有一张写明终局、分步与触发条件的蓝图，而非追逐零散机会。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhugeliang-c1","status":"published","title_period":"隆中对（建安十二年·207）","dilemma_constraints":"刘备屡败、无尺寸根据地；曹操据北方、孙权据江东，弱者如何在强者夹缝立足并图天下。","key_judgment":"提出三阶段战略——跨有荆益为根基→外结孙权内修政理→待天下有变两路北伐。","model_invoked":["隆中对式顶层战略"],"outcome":"成蜀汉立国总纲领，刘备据此取荆益、成三分之势（《三国志》）。","transferable_lesson":"弱势起步者最该先有一张写明终局、分步与触发条件的蓝图，而非追逐零散机会。","source_tier":"secondary","source_note":"《三国志·诸葛亮传》载隆中对全文(B)；《前出师表》\"三顾臣于草庐之中\"自述互证(A)。","historicity":"confirmed","linked_cards":["zhugeliang"],"tags":["战略","长期规划"],"advisor_id":"zhugeliang"}', '49d89003d34d0b50fcb9b2834a410a3e84b246f918118b170eb6151b3ef83411');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhugeliang-c2', 'zhugeliang', '联吴抗曹·出使东吴（建安十三年·208，赤壁前）', '曹操南下、刘备新败，独力无以抗衡最强者。', '亲赴东吴说孙权联合抗曹，促成孙刘联盟。', '孙刘联军赤壁大破曹操，奠定三分（《三国志》）。', '最强者当前，联合次强做结构性制衡，胜于各自硬拼。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhugeliang-c2","status":"published","title_period":"联吴抗曹·出使东吴（建安十三年·208，赤壁前）","dilemma_constraints":"曹操南下、刘备新败，独力无以抗衡最强者。","key_judgment":"亲赴东吴说孙权联合抗曹，促成孙刘联盟。","model_invoked":["联弱抗强"],"outcome":"孙刘联军赤壁大破曹操，奠定三分（《三国志》）。","transferable_lesson":"最强者当前，联合次强做结构性制衡，胜于各自硬拼。","source_tier":"secondary","source_note":"《三国志·诸葛亮传》载亮使吴说权(B)。⚠️同役的\"草船借箭/借东风/舌战群儒\"均为《三国演义》(C)，见 C6/C7，不可混入本条当史实。","historicity":"confirmed","linked_cards":["zhugeliang"],"tags":["战略","谈判"],"advisor_id":"zhugeliang"}', '24f1f836b185691950d4c9bfe1dbebe8e40e662ee7b1fed2c6c08cf91bbaae94');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhugeliang-c3', 'zhugeliang', '南征攻心·平南中（建兴三年·225）', '南中叛乱，强力镇压则需长期驻军、反复生乱，牵制北伐国力。', '以攻心为上，争取真心归附而非单纯军事征服。', '南中平定，为其后北伐解除后顾之忧（《三国志》）。', '当"打赢"会留下长期反抗你的对手时，赢得人心比攻下城池更省后患。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"zhugeliang-c3","status":"published","title_period":"南征攻心·平南中（建兴三年·225）","dilemma_constraints":"南中叛乱，强力镇压则需长期驻军、反复生乱，牵制北伐国力。","key_judgment":"以攻心为上，争取真心归附而非单纯军事征服。","model_invoked":["攻心为上"],"outcome":"南中平定，为其后北伐解除后顾之忧（《三国志》）。","transferable_lesson":"当\"打赢\"会留下长期反抗你的对手时，赢得人心比攻下城池更省后患。","source_tier":"secondary","source_note":"南征确为史实(B，《三国志》\"其秋悉平\")；但\"七纵七擒孟获\"的戏剧化细节出次级史料《汉晋春秋》《华阳国志》、属后世放大(C)。整条保守取低、历史性判存疑；呈现须标\"（七擒七纵为传说放大）\"。","historicity":"disputed","linked_cards":["zhugeliang"],"tags":["治理决策","危机应对"],"advisor_id":"zhugeliang"}', '7d1f0896df8d7e6f7bd47e49620d71d5ea6365e335392d084b114389297dacb8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhugeliang-c4', 'zhugeliang', '街亭之败·斩马谡·自贬三等（建兴六年·228，一伐）', '亲信马谡违节度致街亭失守、北伐受挫；如何处置爱将、如何面对自身举荐用人之责。', '依军法斩马谡以谢众，并上疏自请贬官三等，承担用人之责。', '军纪重申；陈寿评"用心平而劝戒明"故刑政虽峻而无怨（《三国志》）。', '规则若不能约束领导者本人与其亲信，就约束不了任何人；向上追责反而立信。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"zhugeliang-c4","status":"published","title_period":"街亭之败·斩马谡·自贬三等（建兴六年·228，一伐）","dilemma_constraints":"亲信马谡违节度致街亭失守、北伐受挫；如何处置爱将、如何面对自身举荐用人之责。","key_judgment":"依军法斩马谡以谢众，并上疏自请贬官三等，承担用人之责。","model_invoked":["法治严明"],"outcome":"军纪重申；陈寿评\"用心平而劝戒明\"故刑政虽峻而无怨（《三国志》）。","transferable_lesson":"规则若不能约束领导者本人与其亲信，就约束不了任何人；向上追责反而立信。","source_tier":"secondary","source_note":"《三国志·诸葛亮传》《马谡传》确载(B)；刘备临终评马谡\"言过其实，不可大用\"亦载。注：演义\"空城计\"被安在此次北伐，系虚构，见 C6。","historicity":"confirmed","linked_cards":["zhugeliang"],"tags":["组织管理","领导力"],"advisor_id":"zhugeliang"}', '5ce9ca8bfc2731e84f280a141e4fc401bc61916b9354c20e1242e001ca1deaa6');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhugeliang-c5', 'zhugeliang', '拒子午谷奇谋（一伐前后·228）', '魏延献策亲率精兵出子午谷奇袭长安，或可速取关中，但风险极高、败则全军尽墨。', '诸葛亮以其过于弄险"制而不许"，坚持出陇右、步步为营的稳妥路线。', '北伐求稳未能速胜；该决策成后世"稳健vs弄险"千年之争（《魏延传》注）。', '稳健能保全脆弱局面，但结构弱势方若永不弄险，可能等于选择缓慢失败——该不该赌要看输不输得起。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"zhugeliang-c5","status":"published","title_period":"拒子午谷奇谋（一伐前后·228）","dilemma_constraints":"魏延献策亲率精兵出子午谷奇袭长安，或可速取关中，但风险极高、败则全军尽墨。","key_judgment":"诸葛亮以其过于弄险\"制而不许\"，坚持出陇右、步步为营的稳妥路线。","model_invoked":["谨慎稳健不弄险"],"outcome":"北伐求稳未能速胜；该决策成后世\"稳健vs弄险\"千年之争（《魏延传》注）。","transferable_lesson":"稳健能保全脆弱局面，但结构弱势方若永不弄险，可能等于选择缓慢失败——该不该赌要看输不输得起。","source_tier":"secondary","source_note":"《三国志·魏延传》注引《魏略》载魏延有此议、亮不许(B)；至于\"若行则长安必下\"仅为假设性推演、不可断言成败，故历史性判存疑（争议在结果而非提议本身）。","historicity":"disputed","linked_cards":["zhugeliang"],"tags":["战略","风险评估"],"advisor_id":"zhugeliang"}', '76a5a119a0c27344b9b434010743b1af24bd0213738eae21df8bcd9173f1155e');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhugeliang-c6', 'zhugeliang', '（演义对照·不可当史实）空城计', '（演义情节）司马懿大军压境，城中无兵。', '（演义情节）大开城门、焚香抚琴，疑兵退敌。', '（演义情节）司马懿疑有伏兵而退。', '可作"虚张声势/利用对手对你既有认知"的文学化谈资，但严禁当作诸葛亮真实决策——其真实风格恰恰是不弄险。', 'tertiary', 'legendary', 'published', '{"schema_version":1,"case_id":"zhugeliang-c6","status":"published","title_period":"（演义对照·不可当史实）空城计","dilemma_constraints":"（演义情节）司马懿大军压境，城中无兵。","key_judgment":"（演义情节）大开城门、焚香抚琴，疑兵退敌。","model_invoked":[],"outcome":"（演义情节）司马懿疑有伏兵而退。","transferable_lesson":"可作\"虚张声势/利用对手对你既有认知\"的文学化谈资，但严禁当作诸葛亮真实决策——其真实风格恰恰是不弄险。","source_tier":"tertiary","source_note":"《三国演义》(C)；源出郭冲《条亮五事》，已被裴松之注逐条驳斥（司马懿其时不在阳平等）。正史无此事，呈现一切处必带\"（演义）\"，仅供代入感，不得当事实论据。model_invoked 已置空并标注，B-5 须识别为 C 层演义条目、豁免 model 闭环校验。","historicity":"legendary","linked_cards":["zhugeliang"],"tags":["危机应对"],"advisor_id":"zhugeliang"}', '5dbed3d2277bc54daa12e2af5a0d51f37001f0f5a0c368de0f450317ae7dbcc3');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('zhugeliang-c7', 'zhugeliang', '（演义对照·不可当史实）草船借箭', '（演义情节）周瑜限期造箭十万。', '（演义情节）以草船借大雾向曹军"借箭"。', '（演义情节）满载箭矢而归。', '可作"借势/借力"的文学化比喻，严禁当史实。', 'tertiary', 'legendary', 'published', '{"schema_version":1,"case_id":"zhugeliang-c7","status":"published","title_period":"（演义对照·不可当史实）草船借箭","dilemma_constraints":"（演义情节）周瑜限期造箭十万。","key_judgment":"（演义情节）以草船借大雾向曹军\"借箭\"。","model_invoked":[],"outcome":"（演义情节）满载箭矢而归。","transferable_lesson":"可作\"借势/借力\"的文学化比喻，严禁当史实。","source_tier":"tertiary","source_note":"《三国演义》(C)；史载\"草船受箭\"类事属孙权（建安十八年濡须，《魏略》载）、且非\"设计借箭\"本意。既非诸葛亮所为亦非历史\"借箭\"，张冠李戴+文学加工双重失真，必带\"（演义）\"。model_invoked 已置空，B-5 须识别为 C 层演义条目、豁免 model 闭环校验。","historicity":"legendary","linked_cards":["zhugeliang"],"tags":["危机应对"],"advisor_id":"zhugeliang"}', 'cd2b52e0baaffed2f17aa8215d8fcf87fc9ec095b47cac33653c93d74fe0aa00');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('vonneumann-c1', 'vonneumann', '量子力学的数学基础·形式化优先（1932）', '早期量子力学有矩阵力学与波动力学等多套形式、彼此关系不清、数学基础含糊。', '冯诺依曼把量子力学翻译成希尔伯特空间上的精确数学结构、给出统一而严格的公理化基础。', '《量子力学的数学基础》成量子力学严格数学化的奠基之作。', '面对含糊混乱的问题，动手前先把它翻译成一个精确的形式结构——结构立清楚了、解法自然浮现。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"vonneumann-c1","status":"published","title_period":"量子力学的数学基础·形式化优先（1932）","dilemma_constraints":"早期量子力学有矩阵力学与波动力学等多套形式、彼此关系不清、数学基础含糊。","key_judgment":"冯诺依曼把量子力学翻译成希尔伯特空间上的精确数学结构、给出统一而严格的公理化基础。","model_invoked":["形式化优先"],"outcome":"《量子力学的数学基础》成量子力学严格数学化的奠基之作。","transferable_lesson":"面对含糊混乱的问题，动手前先把它翻译成一个精确的形式结构——结构立清楚了、解法自然浮现。","source_tier":"primary","source_note":"《量子力学的数学基础》(1932)为其原著→确证（一手A）。","historicity":"confirmed","linked_cards":["vonneumann"],"tags":["创新研发","认知偏误与理性决策"],"advisor_id":"vonneumann"}', '59c8a77f617a05467fb79927d189abe559693a9f6035025dfe4bc3f8e253e498');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('vonneumann-c2', 'vonneumann', '极小化极大定理·博弈论（1928 / 1944）', '对抗性决策缺乏严格的理论——如何在对手也会理性应对时做最优选择。', '冯诺依曼证明极小化极大定理：在零和对抗中应假设对手走最优一手、把"最坏情况下的最大损失"压到最小；后与摩根斯特恩合著《博弈论与经济行为》奠定博弈论。', '博弈论成为经济学、战略、计算等领域的基础理论。', '对抗局面里，按对手的"最优应对"规划、先把最坏情况下的最大损失压到最小——别赌对手会失误。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"vonneumann-c2","status":"published","title_period":"极小化极大定理·博弈论（1928 / 1944）","dilemma_constraints":"对抗性决策缺乏严格的理论——如何在对手也会理性应对时做最优选择。","key_judgment":"冯诺依曼证明极小化极大定理：在零和对抗中应假设对手走最优一手、把\"最坏情况下的最大损失\"压到最小；后与摩根斯特恩合著《博弈论与经济行为》奠定博弈论。","model_invoked":["极小化极大"],"outcome":"博弈论成为经济学、战略、计算等领域的基础理论。","transferable_lesson":"对抗局面里，按对手的\"最优应对\"规划、先把最坏情况下的最大损失压到最小——别赌对手会失误。","source_tier":"primary","source_note":"极小化极大定理(1928)、《博弈论与经济行为》(1944)为其工作→确证（一手A）。","historicity":"confirmed","linked_cards":["vonneumann"],"tags":["竞争博弈","风险评估"],"advisor_id":"vonneumann"}', 'c2c445223b28eb939cadc0e026c465255e7178d302f5b36aae77021a0a9e1ffc');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('vonneumann-c3', 'vonneumann', 'EDVAC报告·存储程序通用架构（1945）', '早期计算机为特定任务硬接线、改一个任务要重接线路、极不通用。', '冯诺依曼在《EDVAC报告初稿》中提出把程序与数据都放进同一存储、机器可重配置的存储程序架构——造一个通用底座。', '「冯·诺依曼架构」成现代通用计算机的基础。', '造一个可被重配置成多种用途的通用底座、而非为每个需求堆专用件——通用性来自架构的抽象。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"vonneumann-c3","status":"published","title_period":"EDVAC报告·存储程序通用架构（1945）","dilemma_constraints":"早期计算机为特定任务硬接线、改一个任务要重接线路、极不通用。","key_judgment":"冯诺依曼在《EDVAC报告初稿》中提出把程序与数据都放进同一存储、机器可重配置的存储程序架构——造一个通用底座。","model_invoked":["通用架构抽象"],"outcome":"「冯·诺依曼架构」成现代通用计算机的基础。","transferable_lesson":"造一个可被重配置成多种用途的通用底座、而非为每个需求堆专用件——通用性来自架构的抽象。","source_tier":"primary","source_note":"1945 EDVAC报告对存储程序结构的论述→确证（一手A；其与莫奇利/埃克特团队的贡献归属有学术讨论）。","historicity":"confirmed","linked_cards":["vonneumann"],"tags":["创新研发","探索未知"],"advisor_id":"vonneumann"}', 'd84b6d06ca079054529b7337d00cd2a04c1b9904ce49af39e5d6d3cf9e003b42');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('vonneumann-c4', 'vonneumann', '蒙特卡洛方法·数值模拟（1940s末，与Ulam）', '曼哈顿计划中子扩散等问题解析求解极其困难、啃不动。', '冯诺依曼与乌拉姆提出蒙特卡洛方法——用大量随机抽样模拟去逼近解析啃不动的答案。', '蒙特卡洛成科学计算中处理复杂问题的通用利器。', '解析地啃不动时，改用大量随机抽样模拟去逼近答案——模拟能解析所不能解。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"vonneumann-c4","status":"published","title_period":"蒙特卡洛方法·数值模拟（1940s末，与Ulam）","dilemma_constraints":"曼哈顿计划中子扩散等问题解析求解极其困难、啃不动。","key_judgment":"冯诺依曼与乌拉姆提出蒙特卡洛方法——用大量随机抽样模拟去逼近解析啃不动的答案。","model_invoked":["数值模拟"],"outcome":"蒙特卡洛成科学计算中处理复杂问题的通用利器。","transferable_lesson":"解析地啃不动时，改用大量随机抽样模拟去逼近答案——模拟能解析所不能解。","source_tier":"primary","source_note":"蒙特卡洛方法（与Ulam、曼哈顿计划）为其工作→确证（一手A）。","historicity":"confirmed","linked_cards":["vonneumann"],"tags":["创新研发","风险评估"],"advisor_id":"vonneumann"}', '21591ee430c487192258e1448414d9e42209b9285f383bd1b6477fa3292ff361');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('turing-c1', 'turing', '图灵机与判定问题（1936）', '希尔伯特之问：是否存在一个机械程序，能判定任意数学命题的真假（Entscheidungsproblem）？需先把''机械程序''本身定义清楚。', '他用''图灵机''给''可计算''下了精确定义，并据此证明：不存在能判定一切的通用算法（停机问题不可解）。', '奠定可计算性理论，划出''机器能做''与''原理上做不到''的边界。', '把模糊的''能不能自动做''问题，先化为''能否写成机械步骤''，往往顺带也照见了它的极限。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"turing-c1","status":"published","title_period":"图灵机与判定问题（1936）","dilemma_constraints":"希尔伯特之问：是否存在一个机械程序，能判定任意数学命题的真假（Entscheidungsproblem）？需先把''机械程序''本身定义清楚。","key_judgment":"他用''图灵机''给''可计算''下了精确定义，并据此证明：不存在能判定一切的通用算法（停机问题不可解）。","model_invoked":["化归为机械步骤"],"outcome":"奠定可计算性理论，划出''机器能做''与''原理上做不到''的边界。","transferable_lesson":"把模糊的''能不能自动做''问题，先化为''能否写成机械步骤''，往往顺带也照见了它的极限。","source_tier":"primary","source_note":"1936《论可计算数》原文（A），确证。","historicity":"confirmed","linked_cards":["turing"],"tags":["创新研发","认知偏误与理性决策"],"advisor_id":"turing"}', 'b65c107a1760fb8b1fb6aaa0d9d4e1f385b59eb399b21556aff5f22054944f59');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('turing-c2', 'turing', '破译Enigma与Bombe（二战·布莱切利园）', '德军Enigma密码组合天文数字，逐一穷举不可行；需在海量可能中找到突破口。', '不硬碰穷举，而是抓住报文中可预期的固定片段(cribs)与操作规律，设计Bombe机器大幅缩小搜索空间。', '显著加速了对Enigma的破译，对战局影响深远。', '面对组合爆炸的难题，别穷举——找系统里可预期的固定模式，用它把搜索空间砍到可处理。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"turing-c2","status":"published","title_period":"破译Enigma与Bombe（二战·布莱切利园）","dilemma_constraints":"德军Enigma密码组合天文数字，逐一穷举不可行；需在海量可能中找到突破口。","key_judgment":"不硬碰穷举，而是抓住报文中可预期的固定片段(cribs)与操作规律，设计Bombe机器大幅缩小搜索空间。","model_invoked":["抓可利用的规律性"],"outcome":"显著加速了对Enigma的破译，对战局影响深远。","transferable_lesson":"面对组合爆炸的难题，别穷举——找系统里可预期的固定模式，用它把搜索空间砍到可处理。","source_tier":"secondary","source_note":"破译为确证史实，但属大团队成果（波兰Rejewski等奠基、Welchman等协作）；图灵的具体贡献为Bombe设计与Banburismus，呈现时勿独归一人（Hodges传记，B）。","historicity":"confirmed","linked_cards":["turing"],"tags":["竞争博弈","危机应对"],"advisor_id":"turing"}', '64fdcb5083c1f2661f90bde3dd4d35d0610b4d5b9d5aebb8f0799608cc69cef7');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('turing-c3', 'turing', '模仿游戏：重新定义''机器能否思考''（1950）', '''机器能否思考''之问陷于''思考''一词无法定义的泥潭，争论难有进展。', '他把不可定义的本质问题，换成一个可操作的判据：若机器在对话中无法被区分于人，就算通过——绕开定义之争。', '''图灵测试''成为人工智能的奠基性判据与持久议题。', '当一个概念怎么定义都吵不清时，把它换成一个可观测、可判定的行为测试，争论就能推进。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"turing-c3","status":"published","title_period":"模仿游戏：重新定义''机器能否思考''（1950）","dilemma_constraints":"''机器能否思考''之问陷于''思考''一词无法定义的泥潭，争论难有进展。","key_judgment":"他把不可定义的本质问题，换成一个可操作的判据：若机器在对话中无法被区分于人，就算通过——绕开定义之争。","model_invoked":["操作性定义"],"outcome":"''图灵测试''成为人工智能的奠基性判据与持久议题。","transferable_lesson":"当一个概念怎么定义都吵不清时，把它换成一个可观测、可判定的行为测试，争论就能推进。","source_tier":"primary","source_note":"1950《计算机器与智能》原文（A），确证。","historicity":"confirmed","linked_cards":["turing"],"tags":["认知偏误与理性决策","创新研发"],"advisor_id":"turing"}', '24147212192df7e914f1696a6f32199377251432373dc6e4ebd85ee3dd24a973');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('turing-c4', 'turing', '通用图灵机：一台机器模拟万机（1936）', '若每个计算任务都要造一台专用机器，无法通用，也无法理解计算的统一本质。', '他构造''通用图灵机''：只要给它另一台机器的描述（程序），它就能模拟那台机器——程序即数据。', '成为''存储程序''通用计算机的理论原型，奠定现代计算机的根本架构思想。', '与其为每个需求造专用工具，不如造一个可被''描述''重新配置成任意工具的通用底座。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"turing-c4","status":"published","title_period":"通用图灵机：一台机器模拟万机（1936）","dilemma_constraints":"若每个计算任务都要造一台专用机器，无法通用，也无法理解计算的统一本质。","key_judgment":"他构造''通用图灵机''：只要给它另一台机器的描述（程序），它就能模拟那台机器——程序即数据。","model_invoked":["通用机抽象"],"outcome":"成为''存储程序''通用计算机的理论原型，奠定现代计算机的根本架构思想。","transferable_lesson":"与其为每个需求造专用工具，不如造一个可被''描述''重新配置成任意工具的通用底座。","source_tier":"primary","source_note":"1936论文通用机构造（A），确证。","historicity":"confirmed","linked_cards":["turing"],"tags":["创新研发","探索未知"],"advisor_id":"turing"}', 'cb8879612091dcfbf76c2dc0878909a383ed5d745816dbb58b08f97bcec11433');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('turing-c5', 'turing', '形态发生：把生物图案化为可计算过程（1952）', '生物体上的斑纹/条纹等图案如何自发形成？当时缺乏机械化的解释路径。', '他用反应-扩散的数学模型，把图案形成化归为一组可计算的化学动力学过程。', '《形态发生的化学基础》开创了数理生物学的一支，影响延续至今。', '面对''看似有机、说不清''的复杂现象，试着把它化归为一组可计算的规则，往往就能下手了。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"turing-c5","status":"published","title_period":"形态发生：把生物图案化为可计算过程（1952）","dilemma_constraints":"生物体上的斑纹/条纹等图案如何自发形成？当时缺乏机械化的解释路径。","key_judgment":"他用反应-扩散的数学模型，把图案形成化归为一组可计算的化学动力学过程。","model_invoked":["化归为机械步骤"],"outcome":"《形态发生的化学基础》开创了数理生物学的一支，影响延续至今。","transferable_lesson":"面对''看似有机、说不清''的复杂现象，试着把它化归为一组可计算的规则，往往就能下手了。","source_tier":"primary","source_note":"1952《形态发生的化学基础》原文（A），确证。","historicity":"confirmed","linked_cards":["turing"],"tags":["创新研发","探索未知"],"advisor_id":"turing"}', 'b226a9fa5fa441b48992fb2ec21c36bd842957584fff4157a5b10dc03c17c113');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mendel-c1', 'mendel', '豌豆杂交的定量统计·定量统计找规律（1856—1863）', '遗传现象此前只有定性、模糊的描述。', '孟德尔亲手种植、统计了大量豌豆杂交后代的性状，从数字中发现了精确的、可重复的比例（如3:1）。', '精确的比例揭示了遗传的规律，奠定了遗传学的定量基础。', '别满足于定性的"差不多"——大量计数、用数字与比例发现精确、可重复的规律。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mendel-c1","status":"published","title_period":"豌豆杂交的定量统计·定量统计找规律（1856—1863）","dilemma_constraints":"遗传现象此前只有定性、模糊的描述。","key_judgment":"孟德尔亲手种植、统计了大量豌豆杂交后代的性状，从数字中发现了精确的、可重复的比例（如3:1）。","model_invoked":["定量统计找规律"],"outcome":"精确的比例揭示了遗传的规律，奠定了遗传学的定量基础。","transferable_lesson":"别满足于定性的\"差不多\"——大量计数、用数字与比例发现精确、可重复的规律。","source_tier":"primary","source_note":"孟德尔豌豆统计3:1为遗传学史→确证（一手A）。","historicity":"confirmed","linked_cards":["mendel"],"tags":["创新","认知偏误与理性决策"],"advisor_id":"mendel"}', '05c4a41f775e005f04eac6531cba8a60cfd8b9b9dba76b0e2c073fbb79c37eb7');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mendel-c2', 'mendel', '选豌豆、一次追踪一个性状·控制变量的简化实验（其实验设计）', '遗传是极复杂的整体，如何下手研究。', '孟德尔选了性状清晰、易控制的豌豆，一次只追踪一个性状、排除干扰，把复杂的遗传问题简化到可解。', '简化的实验设计是孟德尔成功的关键之一。', '选简单、可控的"模型系统"，一次只研究一个变量，把复杂问题简化到可解。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mendel-c2","status":"published","title_period":"选豌豆、一次追踪一个性状·控制变量的简化实验（其实验设计）","dilemma_constraints":"遗传是极复杂的整体，如何下手研究。","key_judgment":"孟德尔选了性状清晰、易控制的豌豆，一次只追踪一个性状、排除干扰，把复杂的遗传问题简化到可解。","model_invoked":["控制变量的简化实验"],"outcome":"简化的实验设计是孟德尔成功的关键之一。","transferable_lesson":"选简单、可控的\"模型系统\"，一次只研究一个变量，把复杂问题简化到可解。","source_tier":"primary","source_note":"孟德尔的实验设计为其著作→确证（一手A）。","historicity":"confirmed","linked_cards":["mendel"],"tags":["创新"],"advisor_id":"mendel"}', 'e80e5e3a818caaa9c31d035fc7466217ee94fe8fe4c44a70b9161f1804298082');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mendel-c3', 'mendel', '假设"遗传因子"·假设看不见的因子（1865）', '如何解释观察到的遗传规律。', '孟德尔大胆假设背后存在看不见的、离散的"遗传因子"（基因）在成对传递，并用它成功解释和预测杂交结果。', '「遗传因子」的假设是基因概念的源头，是遗传学的基石。', '大胆假设背后存在看不见的、离散的"基本单位"在起作用，用它解释和预测——哪怕还看不到它。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mendel-c3","status":"published","title_period":"假设\"遗传因子\"·假设看不见的因子（1865）","dilemma_constraints":"如何解释观察到的遗传规律。","key_judgment":"孟德尔大胆假设背后存在看不见的、离散的\"遗传因子\"（基因）在成对传递，并用它成功解释和预测杂交结果。","model_invoked":["假设看不见的因子"],"outcome":"「遗传因子」的假设是基因概念的源头，是遗传学的基石。","transferable_lesson":"大胆假设背后存在看不见的、离散的\"基本单位\"在起作用，用它解释和预测——哪怕还看不到它。","source_tier":"primary","source_note":"孟德尔的遗传因子假设为遗传学史→确证（一手A）。","historicity":"confirmed","linked_cards":["mendel"],"tags":["创新","认知偏误与理性决策"],"advisor_id":"mendel"}', 'c439e539a905b705432cd20899359add8965fca934882aed79a6a1d7e3ad69dc');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('mendel-c4', 'mendel', '生前被忽视、35年后被重新发现·坚持不被理解的真理（1866—1900）', '划时代的发现却完全不被当时学界理解、重视。', '孟德尔的遗传定律1866年发表后几乎无人理睬，他默默坚守；直到他去世约16年（发表约35年）后的1900年才被重新发现。', '重新发现后，孟德尔被尊为遗传学之父（但他生前未见此荣誉）。', '即使一时完全不被理解——只要建立在扎实证据上，就坚信它的价值（但也要反思如何更好地传播）。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"mendel-c4","status":"published","title_period":"生前被忽视、35年后被重新发现·坚持不被理解的真理（1866—1900）","dilemma_constraints":"划时代的发现却完全不被当时学界理解、重视。","key_judgment":"孟德尔的遗传定律1866年发表后几乎无人理睬，他默默坚守；直到他去世约16年（发表约35年）后的1900年才被重新发现。","model_invoked":["坚持不被理解的真理"],"outcome":"重新发现后，孟德尔被尊为遗传学之父（但他生前未见此荣誉）。","transferable_lesson":"即使一时完全不被理解——只要建立在扎实证据上，就坚信它的价值（但也要反思如何更好地传播）。","source_tier":"secondary","source_note":"孟德尔生前被忽视、1900年被重新发现为遗传学史→确证（二手B）。","historicity":"confirmed","linked_cards":["mendel"],"tags":["修身自省","创新"],"advisor_id":"mendel"}', '04afc0f0bb4765e9366fc03eb6f87795194f63ea60c740f5c69db7ed02515d0a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('curie-c1', 'curie', '从数吨矿渣中提纯镭·极致严谨的实验（1898—1902）', '要证明并得到"镭"这种新元素，需无可辩驳的实物与数据。', '居里夫人以极严谨、精确、可重复的化学分离与测量，从数吨沥青铀矿渣中提纯出约0.1克的镭。', '镭的提纯确证了放射性新元素，居里夫人因此（与丈夫等）获诺贝尔奖。', '别靠猜想或大概——以极严谨、精确、可重复的实验与数据说话。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"curie-c1","status":"published","title_period":"从数吨矿渣中提纯镭·极致严谨的实验（1898—1902）","dilemma_constraints":"要证明并得到\"镭\"这种新元素，需无可辩驳的实物与数据。","key_judgment":"居里夫人以极严谨、精确、可重复的化学分离与测量，从数吨沥青铀矿渣中提纯出约0.1克的镭。","model_invoked":["极致严谨的实验"],"outcome":"镭的提纯确证了放射性新元素，居里夫人因此（与丈夫等）获诺贝尔奖。","transferable_lesson":"别靠猜想或大概——以极严谨、精确、可重复的实验与数据说话。","source_tier":"secondary","source_note":"居里夫人提纯镭为科学史→确证（二手B）。","historicity":"confirmed","linked_cards":["curie"],"tags":["创新","认知偏误与理性决策"],"advisor_id":"curie"}', '816d26c3511c7e3285bbfc7fe14266c77043f59a9f720073bd0dc3ce2dd09570');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('curie-c2', 'curie', '简陋棚屋中数年苦功·苦功与坚韧（1898—1902）', '提纯镭是极繁重、枯燥、漫长的体力与脑力苦功。', '居里夫妇在简陋棚屋中、用大锅熬煮搅拌数吨矿渣、历经数年的苦功，才提炼出微量的镭。', '超常的坚韧使他们完成了别人难以坚持的工作。', '重大成果要熬过极繁重漫长的苦功，以超常坚韧做到底——别指望捷径（但要量力）。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"curie-c2","status":"published","title_period":"简陋棚屋中数年苦功·苦功与坚韧（1898—1902）","dilemma_constraints":"提纯镭是极繁重、枯燥、漫长的体力与脑力苦功。","key_judgment":"居里夫妇在简陋棚屋中、用大锅熬煮搅拌数吨矿渣、历经数年的苦功，才提炼出微量的镭。","model_invoked":["苦功与坚韧"],"outcome":"超常的坚韧使他们完成了别人难以坚持的工作。","transferable_lesson":"重大成果要熬过极繁重漫长的苦功，以超常坚韧做到底——别指望捷径（但要量力）。","source_tier":"secondary","source_note":"居里夫人棚屋提镭的艰苦为科学史→确证（二手B）。","historicity":"confirmed","linked_cards":["curie"],"tags":["修身自省","创新"],"advisor_id":"curie"}', '46adc2a5033d86fd9c5b01c3a0ad0db743c871bc6b04364f8e51004d160abe45');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('curie-c3', 'curie', '推断放射性是原子的属性·大胆假设新现象（1898）', '铀盐使空气导电的异常现象，无法用已知化学解释。', '居里夫人大胆假设这种"放射性"不是化学反应，而是原子本身的一种全新属性，并据此去追究、发现了钋和镭。', '这一洞察开启了对放射性与原子结构的研究，是现代物理的里程碑。', '面对反常现象，大胆假设它背后是全新未知的东西、并去追究它——别硬塞进旧框架。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"curie-c3","status":"published","title_period":"推断放射性是原子的属性·大胆假设新现象（1898）","dilemma_constraints":"铀盐使空气导电的异常现象，无法用已知化学解释。","key_judgment":"居里夫人大胆假设这种\"放射性\"不是化学反应，而是原子本身的一种全新属性，并据此去追究、发现了钋和镭。","model_invoked":["大胆假设新现象"],"outcome":"这一洞察开启了对放射性与原子结构的研究，是现代物理的里程碑。","transferable_lesson":"面对反常现象，大胆假设它背后是全新未知的东西、并去追究它——别硬塞进旧框架。","source_tier":"secondary","source_note":"居里夫人对放射性的洞察为科学史→确证（二手B）。","historicity":"confirmed","linked_cards":["curie"],"tags":["创新","认知偏误与理性决策"],"advisor_id":"curie"}', 'b6cb11be2c6735557562c18de02282e96825db53b0f8ac8984e4641ee3e4e5da');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('curie-c4', 'curie', '放弃镭的提纯专利·纯粹的求知而非名利（1900s）', '镭的提纯方法极具商业价值，可申请专利获利。', '居里夫人认为科学应造福人类、放弃了镭提纯方法的专利，让全世界都能用——纯粹为求知与公益，而非名利。', '这一选择体现了她纯粹的科学精神，但也使她一生科研经费与生活清贫。', '让纯粹的求知与对意义本身的追求来驱动——但也要正视其清贫的代价。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"curie-c4","status":"published","title_period":"放弃镭的提纯专利·纯粹的求知而非名利（1900s）","dilemma_constraints":"镭的提纯方法极具商业价值，可申请专利获利。","key_judgment":"居里夫人认为科学应造福人类、放弃了镭提纯方法的专利，让全世界都能用——纯粹为求知与公益，而非名利。","model_invoked":["纯粹的求知而非名利"],"outcome":"这一选择体现了她纯粹的科学精神，但也使她一生科研经费与生活清贫。","transferable_lesson":"让纯粹的求知与对意义本身的追求来驱动——但也要正视其清贫的代价。","source_tier":"secondary","source_note":"居里夫人放弃镭专利为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["curie"],"tags":["修身自省","价值与伦理"],"advisor_id":"curie"}', 'bb0198ebf1c641d112608dac8d3143c4bb7c5cb9c4cd5e112572baf0f91fa519');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('faraday-c1', 'faraday', '用"力线/场"把握电磁·用物理图像而非公式思考（其电磁研究）', '如何把握看不见的电磁作用（而法拉第不懂高深数学）。', '法拉第创造性地用"力线""场"这种直观的物理图像，去想象、把握看不见的电磁作用，虽不用数学却抓住了本质。', '「场」成为现代物理的核心概念（后由麦克斯韦数学化）。', '不一定靠公式——用一个直观的"物理图像"去把握抽象的事物，好的图像能让你"看见"本质。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"faraday-c1","status":"published","title_period":"用\"力线/场\"把握电磁·用物理图像而非公式思考（其电磁研究）","dilemma_constraints":"如何把握看不见的电磁作用（而法拉第不懂高深数学）。","key_judgment":"法拉第创造性地用\"力线\"\"场\"这种直观的物理图像，去想象、把握看不见的电磁作用，虽不用数学却抓住了本质。","model_invoked":["用物理图像而非公式思考"],"outcome":"「场」成为现代物理的核心概念（后由麦克斯韦数学化）。","transferable_lesson":"不一定靠公式——用一个直观的\"物理图像\"去把握抽象的事物，好的图像能让你\"看见\"本质。","source_tier":"primary","source_note":"法拉第的力线/场为物理学史→确证（一手/二手A/B）。","historicity":"confirmed","linked_cards":["faraday"],"tags":["创新","认知偏误与理性决策"],"advisor_id":"faraday"}', 'e7f1fa8b9b9f9189336f0b4f691ad0675109b562cbdf6e2db7ff3b1bc8d25966');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('faraday-c2', 'faraday', '发现电磁感应·转换视角问反问题（1831）', '已知"电生磁"，那"磁"能不能"生电"。', '法拉第反过来执着追问"磁能不能生电"，经反复实验发现了"磁生电"（电磁感应），奠定了发电机原理。', '电磁感应的发现是电气时代的基石之一。', '已知"A能产生B"，就反过来追问"B能不能产生A"——发现藏在被忽略的逆命题里。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"faraday-c2","status":"published","title_period":"发现电磁感应·转换视角问反问题（1831）","dilemma_constraints":"已知\"电生磁\"，那\"磁\"能不能\"生电\"。","key_judgment":"法拉第反过来执着追问\"磁能不能生电\"，经反复实验发现了\"磁生电\"（电磁感应），奠定了发电机原理。","model_invoked":["转换视角问反问题"],"outcome":"电磁感应的发现是电气时代的基石之一。","transferable_lesson":"已知\"A能产生B\"，就反过来追问\"B能不能产生A\"——发现藏在被忽略的逆命题里。","source_tier":"primary","source_note":"法拉第发现电磁感应为物理学史→确证（一手/二手A/B）。","historicity":"confirmed","linked_cards":["faraday"],"tags":["创新","认知偏误与理性决策"],"advisor_id":"faraday"}', '73669d215fdd540b99c7907eb5126099285d17a2fc82524b6213de281fe32ce0');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('faraday-c3', 'faraday', '海量精巧实验·以实验追问自然（其一生）', '结论靠什么立足。', '法拉第一生做了海量精巧设计的实验，一切结论都建立在亲手做的、可重复的实验之上。', '法拉第成为实验物理的典范，《电学实验研究》传世。', '别停留空想——亲手做巧妙实验向现实提问、让数据给答案。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"faraday-c3","status":"published","title_period":"海量精巧实验·以实验追问自然（其一生）","dilemma_constraints":"结论靠什么立足。","key_judgment":"法拉第一生做了海量精巧设计的实验，一切结论都建立在亲手做的、可重复的实验之上。","model_invoked":["以实验追问自然"],"outcome":"法拉第成为实验物理的典范，《电学实验研究》传世。","transferable_lesson":"别停留空想——亲手做巧妙实验向现实提问、让数据给答案。","source_tier":"primary","source_note":"法拉第的实验研究为其著作→确证（一手A）。","historicity":"confirmed","linked_cards":["faraday"],"tags":["创新"],"advisor_id":"faraday"}', '13be9b0e41199ca822b23d7899769c46db91a7eed646c8b2c37cf316eef93d00');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('faraday-c4', 'faraday', '装订学徒自学成才·出身寒微而自学不辍（其早年）', '出身贫寒、缺乏正规教育。', '法拉第出身贫寒、当过书籍装订学徒，靠在装订时阅读、自学与极强的好奇勤奋，一步步成为顶尖科学家。', '法拉第以真才实学跻身科学殿堂，成为自学成才的典范。', '别因出身、学历、资源不足自限——靠自学、好奇与真才实学立身。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"faraday-c4","status":"published","title_period":"装订学徒自学成才·出身寒微而自学不辍（其早年）","dilemma_constraints":"出身贫寒、缺乏正规教育。","key_judgment":"法拉第出身贫寒、当过书籍装订学徒，靠在装订时阅读、自学与极强的好奇勤奋，一步步成为顶尖科学家。","model_invoked":["出身寒微而自学不辍"],"outcome":"法拉第以真才实学跻身科学殿堂，成为自学成才的典范。","transferable_lesson":"别因出身、学历、资源不足自限——靠自学、好奇与真才实学立身。","source_tier":"secondary","source_note":"法拉第装订学徒自学成才为史实→确证（二手B）。","historicity":"confirmed","linked_cards":["faraday"],"tags":["修身自省","创新"],"advisor_id":"faraday"}', 'e301199ce6443076497d478d386c200e2af9aba06ec63e623bc212f367d8ad88');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('einstein-c1', 'einstein', '狭义相对论：质疑''同时''的绝对性（1905）', '麦克斯韦电磁理论要求光速恒定，与伽利略相对性（速度可叠加）直接冲突；主流靠''以太''等辅助假设勉强调和。', '不调和矛盾，而放弃一个没人质疑的隐藏前提——''同时''对所有人绝对；以光速恒定为不变量重建时空。', '导出时间膨胀、同时的相对性，统一了力学与电磁学，成为现代物理基石。', '两个都验证过的东西打架时，真正要放弃的往往是你从没想过去质疑的那个隐藏假设。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"einstein-c1","status":"published","title_period":"狭义相对论：质疑''同时''的绝对性（1905）","dilemma_constraints":"麦克斯韦电磁理论要求光速恒定，与伽利略相对性（速度可叠加）直接冲突；主流靠''以太''等辅助假设勉强调和。","key_judgment":"不调和矛盾，而放弃一个没人质疑的隐藏前提——''同时''对所有人绝对；以光速恒定为不变量重建时空。","model_invoked":["把矛盾推到底"],"outcome":"导出时间膨胀、同时的相对性，统一了力学与电磁学，成为现代物理基石。","transferable_lesson":"两个都验证过的东西打架时，真正要放弃的往往是你从没想过去质疑的那个隐藏假设。","source_tier":"primary","source_note":"出自1905年论文《论动体的电动力学》（A，原文）；理论与发表确证。","historicity":"confirmed","linked_cards":["einstein"],"tags":["创新研发","认知偏误与理性决策"],"advisor_id":"einstein"}', 'd29ecd29b3eb9af918cdd08661dd0d22f553c3e5f9bd947f80e600d03e5900fc');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('einstein-c2', 'einstein', '等效原理：''最幸福的念头''（1907）', '如何把引力纳入相对论？牛顿的''超距引力''与相对论的有限速度不相容，缺一个切入口。', '由一个设想顿悟：自由下落的人感觉不到自身重量→引力与加速度在局部不可区分（等效原理），由此通向广义相对论。', '等效原理成为广义相对论的支点，最终给出''引力即时空弯曲''的几何理论。', '一个干净的设想情境，能把抽象难题压缩成一个你直觉就能抓住的核心洞见。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"einstein-c2","status":"published","title_period":"等效原理：''最幸福的念头''（1907）","dilemma_constraints":"如何把引力纳入相对论？牛顿的''超距引力''与相对论的有限速度不相容，缺一个切入口。","key_judgment":"由一个设想顿悟：自由下落的人感觉不到自身重量→引力与加速度在局部不可区分（等效原理），由此通向广义相对论。","model_invoked":["思想实验"],"outcome":"等效原理成为广义相对论的支点，最终给出''引力即时空弯曲''的几何理论。","transferable_lesson":"一个干净的设想情境，能把抽象难题压缩成一个你直觉就能抓住的核心洞见。","source_tier":"primary","source_note":"''最幸福的念头''系其本人回顾性自述（A·自述），顿悟时刻细节无第三方可核，按自述判例 historicity 记存疑；等效原理与广义相对论本身确证。","historicity":"disputed","linked_cards":["einstein"],"tags":["创新研发","探索未知"],"advisor_id":"einstein"}', '99e7f74069bdff3a3f600a0b9a8a72c053ab2a4ce3025da7e68c1168a3137e12');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('einstein-c3', 'einstein', '广义相对论的日食验证（1915提出·1919验证）', '广义相对论给出反直觉预言：引力使星光弯曲、偏折量是牛顿值的两倍——一个可被观测一票否决的硬预言。', '以理论做出大胆、精确、可证伪的预言（星光偏折、水星近日点进动），把理论命运押在能被实测推翻的预测上。', '1919年爱丁顿日食观测证实星光偏折，广义相对论一夜成名。', '真有底气的理论敢给出能被一票否决的预言，并主动把自己交给实验去检验。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"einstein-c3","status":"published","title_period":"广义相对论的日食验证（1915提出·1919验证）","dilemma_constraints":"广义相对论给出反直觉预言：引力使星光弯曲、偏折量是牛顿值的两倍——一个可被观测一票否决的硬预言。","key_judgment":"以理论做出大胆、精确、可证伪的预言（星光偏折、水星近日点进动），把理论命运押在能被实测推翻的预测上。","model_invoked":["原理性理论"],"outcome":"1919年爱丁顿日食观测证实星光偏折，广义相对论一夜成名。","transferable_lesson":"真有底气的理论敢给出能被一票否决的预言，并主动把自己交给实验去检验。","source_tier":"primary","source_note":"预言见1915年广义相对论论文（A）；1919年爱丁顿观测见其报告（B），事件确证。","historicity":"confirmed","linked_cards":["einstein"],"tags":["创新研发","风险评估"],"advisor_id":"einstein"}', '399bef84c41d736c0f5f8210400457583a97767a1ae05080af1fc3afc154c07a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('einstein-c4', 'einstein', 'EPR与''上帝不掷骰子''：拒斥量子不确定性（1935）', '量子力学的内禀随机性与非定域性，与他''物理实在应确定、定域''的信念冲突；而量子力学实验上极其成功。', '他选择不接受量子力学为完备，提出EPR论证主张其遗漏了''隐变量''，与玻尔展开数十年论战。', 'EPR反催生了贝尔定理与量子信息；但其核心立场（定域实在）后被贝尔实验证伪，他晚年因此渐被边缘化。', '对一条深信的原理过度忠诚，会让你在证据面前也拒绝更新——再强的直觉也需向实验低头。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"einstein-c4","status":"published","title_period":"EPR与''上帝不掷骰子''：拒斥量子不确定性（1935）","dilemma_constraints":"量子力学的内禀随机性与非定域性，与他''物理实在应确定、定域''的信念冲突；而量子力学实验上极其成功。","key_judgment":"他选择不接受量子力学为完备，提出EPR论证主张其遗漏了''隐变量''，与玻尔展开数十年论战。","model_invoked":["原理性理论"],"outcome":"EPR反催生了贝尔定理与量子信息；但其核心立场（定域实在）后被贝尔实验证伪，他晚年因此渐被边缘化。","transferable_lesson":"对一条深信的原理过度忠诚，会让你在证据面前也拒绝更新——再强的直觉也需向实验低头。","source_tier":"primary","source_note":"EPR论文（1935，A）与玻尔-爱因斯坦论战均有据（A/B）；此为其典型盲区案例，与玻尔卡 P-bohr-C3 互为正反两面。","historicity":"confirmed","linked_cards":["einstein"],"tags":["认知偏误与理性决策","创新研发"],"advisor_id":"einstein"}', '5084075943280f4d1ca1f8558a3c0bd8a5f33958ff74bd3b15debee666b9a8f7');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('einstein-c5', 'einstein', '宇宙学常数：口中''一生最大的错误''（1917）', '广义相对论方程自然推出宇宙在膨胀或收缩，但当时''宇宙静态''是公认前提；两者冲突。', '他没有相信方程、预言一个动态宇宙，反而硬加''宇宙学常数''项把宇宙摁成静态——迁就了当时的成见。', '哈勃1929年发现宇宙膨胀后，他承认加常数是错的；据传称之为''一生最大的错误''。', '当你的方法本身在喊一个反直觉结论时，硬塞一个修正去迁就成见，往往才是真正的错误。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"einstein-c5","status":"published","title_period":"宇宙学常数：口中''一生最大的错误''（1917）","dilemma_constraints":"广义相对论方程自然推出宇宙在膨胀或收缩，但当时''宇宙静态''是公认前提；两者冲突。","key_judgment":"他没有相信方程、预言一个动态宇宙，反而硬加''宇宙学常数''项把宇宙摁成静态——迁就了当时的成见。","model_invoked":["原理性理论"],"outcome":"哈勃1929年发现宇宙膨胀后，他承认加常数是错的；据传称之为''一生最大的错误''。","transferable_lesson":"当你的方法本身在喊一个反直觉结论时，硬塞一个修正去迁就成见，往往才是真正的错误。","source_tier":"primary","source_note":"加入宇宙学常数确证（1917论文，A）；''最大的错误''一语经Gamow转述的自述（B/自述），historicity 记存疑。本案与C2''相信设想''恰成对照：此处他没相信方程。","historicity":"disputed","linked_cards":["einstein"],"tags":["认知偏误与理性决策","创新研发"],"advisor_id":"einstein"}', '4a7f2886f33d3574e7d63492323d917d94a0603db3c67c0d161bea584a42badd');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('newton-c1', 'newton', '写《自然哲学的数学原理》·公理化力学（1687）', '此前天体与地面运动各有零散经验规律，缺乏统一而严格的理论体系。', '牛顿把整个力学压缩成三条运动定律（公理），再用数学严格推导出从行星轨道到潮汐的全部后果。', '《原理》奠定经典力学，成为公理化数学物理的典范。', '面对杂乱的领域，把它压缩成几条精确的公理、再用严格演绎推出全部后果——少数公理胜过大量散点经验。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"newton-c1","status":"published","title_period":"写《自然哲学的数学原理》·公理化力学（1687）","dilemma_constraints":"此前天体与地面运动各有零散经验规律，缺乏统一而严格的理论体系。","key_judgment":"牛顿把整个力学压缩成三条运动定律（公理），再用数学严格推导出从行星轨道到潮汐的全部后果。","model_invoked":["公理化数学演绎"],"outcome":"《原理》奠定经典力学，成为公理化数学物理的典范。","transferable_lesson":"面对杂乱的领域，把它压缩成几条精确的公理、再用严格演绎推出全部后果——少数公理胜过大量散点经验。","source_tier":"primary","source_note":"《原理》建在三条运动定律上为其原著明载→确证（一手A）。","historicity":"confirmed","linked_cards":["newton"],"tags":["创新研发","认知偏误与理性决策"],"advisor_id":"newton"}', '62944a47a7f5c483d3ad2139793c7bc3689f4c3c1595752fb715c81adadf1e01');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('newton-c2', 'newton', '万有引力·统一天地（《原理》第3卷）', '苹果落地与月球绕行历来被视为两类不同的现象。', '牛顿看出二者服从同一条引力定律，用一条"同一规律"统一了地面与天体的运动。', '万有引力定律统一了天上地下的力学，是其威力与洞察之源。', '别给每个现象单独编一套解释——找那条能同时解释平凡与宏大现象的"同一规律"。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"newton-c2","status":"published","title_period":"万有引力·统一天地（《原理》第3卷）","dilemma_constraints":"苹果落地与月球绕行历来被视为两类不同的现象。","key_judgment":"牛顿看出二者服从同一条引力定律，用一条\"同一规律\"统一了地面与天体的运动。","model_invoked":["统一普遍化"],"outcome":"万有引力定律统一了天上地下的力学，是其威力与洞察之源。","transferable_lesson":"别给每个现象单独编一套解释——找那条能同时解释平凡与宏大现象的\"同一规律\"。","source_tier":"primary","source_note":"万有引力为《原理》第3卷所载→确证（一手A）。","historicity":"confirmed","linked_cards":["newton"],"tags":["创新研发","探索未知"],"advisor_id":"newton"}', '789aea9b28de96297a472fc39c43c1fe83d128b2d3bafa3615da63a714a29215');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('newton-c3', 'newton', '棱镜分光·分析-综合（《光学》）', '白光被普遍当作单一、纯粹之物，其本质不明。', '牛顿用棱镜把白光分解为光谱各色（分析），再用棱镜把光谱重新合成白光（综合），证明白光是各色光的组合。', '揭示了白光的复合本质，奠定近代光学。', '把复杂现象先拆成可分别处理的分量（分析）、再重新组合起来预测验证（综合）——拆开算清、再拼回去看。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"newton-c3","status":"published","title_period":"棱镜分光·分析-综合（《光学》）","dilemma_constraints":"白光被普遍当作单一、纯粹之物，其本质不明。","key_judgment":"牛顿用棱镜把白光分解为光谱各色（分析），再用棱镜把光谱重新合成白光（综合），证明白光是各色光的组合。","model_invoked":["分析-综合"],"outcome":"揭示了白光的复合本质，奠定近代光学。","transferable_lesson":"把复杂现象先拆成可分别处理的分量（分析）、再重新组合起来预测验证（综合）——拆开算清、再拼回去看。","source_tier":"primary","source_note":"棱镜分光与论分析-综合方法为《光学》所载→确证（一手A）。","historicity":"confirmed","linked_cards":["newton"],"tags":["创新研发","认知偏误与理性决策"],"advisor_id":"newton"}', '1770688c419441e762ada2143b4cd2bf6955e804c7368a1c1556e3234ec61794');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('newton-c4', 'newton', '持续不断地想它·持续专注钻透（被问发现引力时）', '引力这类深问题暂时无解、易让人浅尝辄止。', '据转述，被问及如何发现引力时，牛顿答以"靠持续不断地想它"——把问题不断放在心上、死磕到它自己裂开。', '长期的专注钻研使其攻克了一系列深层问题。', '认准一个真问题，就靠"把它不断放在心上"持续死磕、直到它裂开——别被它暂时无解吓退。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"newton-c4","status":"published","title_period":"持续不断地想它·持续专注钻透（被问发现引力时）","dilemma_constraints":"引力这类深问题暂时无解、易让人浅尝辄止。","key_judgment":"据转述，被问及如何发现引力时，牛顿答以\"靠持续不断地想它\"——把问题不断放在心上、死磕到它自己裂开。","model_invoked":["持续专注钻透"],"outcome":"长期的专注钻研使其攻克了一系列深层问题。","transferable_lesson":"认准一个真问题，就靠\"把它不断放在心上\"持续死磕、直到它裂开——别被它暂时无解吓退。","source_tier":"secondary","source_note":"「by thinking on it continually」语经同时代人转述、非牛顿亲笔→判存疑（理念广为流传、确切措辞待核）。","historicity":"disputed","linked_cards":["newton"],"tags":["创新研发","修身自省"],"advisor_id":"newton"}', 'bf8908f1c28fb7b5a025f6bfc943fc9c1527e1696b01c9d04e9dac4e6c163f55');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bohr-c1', 'bohr', '提出互补原理·波粒并存（1927科莫演讲）', '光与电子既表现出波动性、又表现出粒子性，二者互斥，物理学界强求单一图景而争执不下。', '玻尔提出互补原理——波与粒子是两套互斥但互补的描述，须并存才能完整把握量子现象，不必也不能消解为单一图景。', '互补原理成为量子力学哥本哈根诠释的核心思想之一。', '遇到两个互斥、却又都说得通的答案，先别强行二选一——有些真相本就需要两套互补的描述并存。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bohr-c1","status":"published","title_period":"提出互补原理·波粒并存（1927科莫演讲）","dilemma_constraints":"光与电子既表现出波动性、又表现出粒子性，二者互斥，物理学界强求单一图景而争执不下。","key_judgment":"玻尔提出互补原理——波与粒子是两套互斥但互补的描述，须并存才能完整把握量子现象，不必也不能消解为单一图景。","model_invoked":["互补原理"],"outcome":"互补原理成为量子力学哥本哈根诠释的核心思想之一。","transferable_lesson":"遇到两个互斥、却又都说得通的答案，先别强行二选一——有些真相本就需要两套互补的描述并存。","source_tier":"primary","source_note":"互补原理为玻尔1927科莫演讲提出→确证（一手A）。","historicity":"confirmed","linked_cards":["bohr"],"tags":["创新研发","认知偏误与理性决策"],"advisor_id":"bohr"}', '4f078fb8dd0f8e6c65ce14dd9aab381caee4cf333ddaadbfe83223aad03f33b5');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bohr-c2', 'bohr', '对应原理·量子还原经典（玻尔原子模型时期）', '全新的量子理论与成熟的经典物理如何衔接、新理论凭什么可信。', '玻尔提出对应原理——量子理论在大量子数/经典适用的极限下，必须能还原出经典物理的结果，新理论才算站得住。', '对应原理成为构建与检验量子理论的重要准则。', '提出新框架时，先检验它在旧框架成立的范围里能不能还原出旧结果——还原得出，新框架才站得住。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bohr-c2","status":"published","title_period":"对应原理·量子还原经典（玻尔原子模型时期）","dilemma_constraints":"全新的量子理论与成熟的经典物理如何衔接、新理论凭什么可信。","key_judgment":"玻尔提出对应原理——量子理论在大量子数/经典适用的极限下，必须能还原出经典物理的结果，新理论才算站得住。","model_invoked":["对应原理"],"outcome":"对应原理成为构建与检验量子理论的重要准则。","transferable_lesson":"提出新框架时，先检验它在旧框架成立的范围里能不能还原出旧结果——还原得出，新框架才站得住。","source_tier":"primary","source_note":"对应原理为玻尔量子论述所提→确证（一手A；确切出处待质检者核校）。","historicity":"confirmed","linked_cards":["bohr"],"tags":["创新研发","认知偏误与理性决策"],"advisor_id":"bohr"}', 'bc05705baa2d375938d806a8b162849fe9df632824485f65f57c6bd16efe4048');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bohr-c3', 'bohr', '玻尔-爱因斯坦论战·以异见磨真理（1927起数十年）', '爱因斯坦以"上帝不掷骰子"等一系列思想实验持续质疑量子力学的完备性。', '玻尔不回避，反而把爱因斯坦这位最强对手的每一次反驳当作磨利自己理解的引擎，逐一回应、深化互补诠释。', '这场数十年的论战成科学史上最富成效的思想交锋之一，极大深化了量子力学的理解。', '主动找一个够强的反对者、把他的反驳当磨刀石——"一个深刻真理的反面，可能是另一个深刻真理"。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bohr-c3","status":"published","title_period":"玻尔-爱因斯坦论战·以异见磨真理（1927起数十年）","dilemma_constraints":"爱因斯坦以\"上帝不掷骰子\"等一系列思想实验持续质疑量子力学的完备性。","key_judgment":"玻尔不回避，反而把爱因斯坦这位最强对手的每一次反驳当作磨利自己理解的引擎，逐一回应、深化互补诠释。","model_invoked":["以对话异见为方法"],"outcome":"这场数十年的论战成科学史上最富成效的思想交锋之一，极大深化了量子力学的理解。","transferable_lesson":"主动找一个够强的反对者、把他的反驳当磨刀石——\"一个深刻真理的反面，可能是另一个深刻真理\"。","source_tier":"secondary","source_note":"玻尔-爱因斯坦论战为科学史所载（Pais 传记等）→确证。","historicity":"confirmed","linked_cards":["bohr"],"tags":["创新研发","认知偏误与理性决策"],"advisor_id":"bohr"}', '9aee6e6b2c35dca9e00126ad95184437553c0c2439116d764aaa53ba7dae677d');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('bohr-c4', 'bohr', '哥本哈根研究所·汇聚共创（1921起）', '量子物理的突破需要持续的思想碰撞，靠单个权威闭门难以为继。', '玻尔创建并主持哥本哈根理论物理研究所，以平等、开放、自由争论的氛围汇聚海森堡、泡利等一代青年才俊。', '研究所成量子力学的世界中心，"哥本哈根精神"催生了大量突破。', '建一个平等、开放、汇聚才俊的环境、让突破在自由碰撞中涌现——而非靠少数权威闭门定论。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"bohr-c4","status":"published","title_period":"哥本哈根研究所·汇聚共创（1921起）","dilemma_constraints":"量子物理的突破需要持续的思想碰撞，靠单个权威闭门难以为继。","key_judgment":"玻尔创建并主持哥本哈根理论物理研究所，以平等、开放、自由争论的氛围汇聚海森堡、泡利等一代青年才俊。","model_invoked":["汇聚共创"],"outcome":"研究所成量子力学的世界中心，\"哥本哈根精神\"催生了大量突破。","transferable_lesson":"建一个平等、开放、汇聚才俊的环境、让突破在自由碰撞中涌现——而非靠少数权威闭门定论。","source_tier":"secondary","source_note":"哥本哈根研究所及其开放风格为科学史所载→确证（二手B）。","historicity":"confirmed","linked_cards":["bohr"],"tags":["创新研发","领导力"],"advisor_id":"bohr"}', '1d6768fee99ffdc9f57d89aeb63016d5a4ff62037e1b59dce86065108ca5488c');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('feynman-c1', 'feynman', '挑战者号 O 形圈冰水演示（1986 罗杰斯委员会）', '调查航天飞机失事，管理层用术语和概率论证淡化原因，调查被官僚话术淹没；费曼作为局外科学家，权威性还被质疑。', '不接受层层包装的解释，直接做一个人人当场看得懂的物理实验——把 O 形圈夹住浸入冰水，证明低温下它失去弹性、几秒回弹不过来。', '当众揭示低温导致密封失效的核心机理；《附录F》批评 NASA 在风险概率上的自欺，留下''大自然骗不了人''。', '当问题被术语和流程裹得看不清时，找一个能当场验证的最底层事实，往往比一百页论证更有杀伤力。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"feynman-c1","status":"published","title_period":"挑战者号 O 形圈冰水演示（1986 罗杰斯委员会）","dilemma_constraints":"调查航天飞机失事，管理层用术语和概率论证淡化原因，调查被官僚话术淹没；费曼作为局外科学家，权威性还被质疑。","key_judgment":"不接受层层包装的解释，直接做一个人人当场看得懂的物理实验——把 O 形圈夹住浸入冰水，证明低温下它失去弹性、几秒回弹不过来。","model_invoked":["重构式理解"],"outcome":"当众揭示低温导致密封失效的核心机理；《附录F》批评 NASA 在风险概率上的自欺，留下''大自然骗不了人''。","transferable_lesson":"当问题被术语和流程裹得看不清时，找一个能当场验证的最底层事实，往往比一百页论证更有杀伤力。","source_tier":"primary","source_note":"关键判断与结果见罗杰斯委员会《附录F》原文及听证记录（A）；传记交叉印证（B）。亦体现不自欺原则。","historicity":"confirmed","linked_cards":["feynman"],"tags":["风险评估","危机应对"],"advisor_id":"feynman"}', '92dfc103357feb35e20c171725e9d58fdbb11da7dc4ace362e66d614771fbe9f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('feynman-c2', 'feynman', '曼哈顿计划：原始理由消失却未重审（1943–45）', '参与造原子弹的初始理由是''赶在纳粹之前''；1944 年底德国败局已定，原始理由其实已经消失。', '（费曼自我批评）他后来坦承当时''没有再想一下''——支撑决定的理由没了，工作却靠惯性继续。', '广岛之后他陷入长期低落；这段经历成为他终身强调''前提变了就要重新检验决定''的源头。', '当初支撑一个决定的理由若已不成立，决定本身必须重新拿出来审，而不是靠惯性滑行。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"feynman-c2","status":"published","title_period":"曼哈顿计划：原始理由消失却未重审（1943–45）","dilemma_constraints":"参与造原子弹的初始理由是''赶在纳粹之前''；1944 年底德国败局已定，原始理由其实已经消失。","key_judgment":"（费曼自我批评）他后来坦承当时''没有再想一下''——支撑决定的理由没了，工作却靠惯性继续。","model_invoked":["不自欺原则"],"outcome":"广岛之后他陷入长期低落；这段经历成为他终身强调''前提变了就要重新检验决定''的源头。","transferable_lesson":"当初支撑一个决定的理由若已不成立，决定本身必须重新拿出来审，而不是靠惯性滑行。","source_tier":"primary","source_note":"出处属本人多次公开自我反思（A 层一手）；但''当时心理活动/是否真未多想''本质是自述、有存疑空间，按 v5 判例（自述类→disputed）记存疑，与 source_tier(A) 正交。呈现须加''据其自述/费曼晚年回顾''等限定语。此案为''不自欺原则''之反面教材（恰是未应用此原则）。","historicity":"disputed","linked_cards":["feynman"],"tags":["人生抉择","认知偏误与理性决策"],"advisor_id":"feynman"}', '716d1b61156b806e17d256934687660421b8afbb248012dabaa85a6fe82b3d31');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('feynman-c3', 'feynman', '摇晃的盘子：靠''玩''走出科研倦怠（约1946–48）', '二战后费曼科研倦怠、自觉''烧完了''，对物理提不起劲，还背着''神童''的期望压力。', '决定不再为''重要''而做物理，只为好玩——出于纯粹好奇去算餐厅里一个晃动盘子的晃动与旋转之比。', '这串''无用''的玩耍式计算把他领回电动力学，最终发展出获诺奖的量子电动力学路径积分表述。', '陷入倦怠或方向迷失时，重新接上''我真正觉得有意思''那根线，常比逼自己做''应该做的事''更能产出突破。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"feynman-c3","status":"published","title_period":"摇晃的盘子：靠''玩''走出科研倦怠（约1946–48）","dilemma_constraints":"二战后费曼科研倦怠、自觉''烧完了''，对物理提不起劲，还背着''神童''的期望压力。","key_judgment":"决定不再为''重要''而做物理，只为好玩——出于纯粹好奇去算餐厅里一个晃动盘子的晃动与旋转之比。","model_invoked":["玩耍式探索"],"outcome":"这串''无用''的玩耍式计算把他领回电动力学，最终发展出获诺奖的量子电动力学路径积分表述。","transferable_lesson":"陷入倦怠或方向迷失时，重新接上''我真正觉得有意思''那根线，常比逼自己做''应该做的事''更能产出突破。","source_tier":"primary","source_note":"出自本人回忆录《别闹了，费曼先生》（A·自述/回忆录，细节或有记忆或润色偏差）；按回忆录特例，historicity 记存疑（无第三方交叉印证可升确证）。","historicity":"disputed","linked_cards":["feynman"],"tags":["职业发展","创新研发"],"advisor_id":"feynman"}', 'e0959f7f35de090566aa405f179ac9e80190ceafe220752d5df5f54b53589dc9');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('feynman-c4', 'feynman', '''降不到大一水平''＝其实没真懂（教学轶事）', 'Goodstein 请费曼准备一节大一新生能听懂的课，解释为何自旋 1/2 粒子服从费米–狄拉克统计。', '他答应了，几天后回来说自己做不到，并补一句——做不到，就说明我们其实并不真的理解它。', '成为''能不能讲给外行听＝能不能算真懂''这一判据的经典出处。', '检验你是否真懂一件事，标准不是能否用术语谈它，而是能否讲到外行也懂——讲不通处就是你的认知缺口。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"feynman-c4","status":"published","title_period":"''降不到大一水平''＝其实没真懂（教学轶事）","dilemma_constraints":"Goodstein 请费曼准备一节大一新生能听懂的课，解释为何自旋 1/2 粒子服从费米–狄拉克统计。","key_judgment":"他答应了，几天后回来说自己做不到，并补一句——做不到，就说明我们其实并不真的理解它。","model_invoked":["重构式理解"],"outcome":"成为''能不能讲给外行听＝能不能算真懂''这一判据的经典出处。","transferable_lesson":"检验你是否真懂一件事，标准不是能否用术语谈它，而是能否讲到外行也懂——讲不通处就是你的认知缺口。","source_tier":"secondary","source_note":"出自 David Goodstein《Feynman''s Lost Lecture》对亲历的记述（B，权威转述）。","historicity":"confirmed","linked_cards":["feynman"],"tags":["学习与认知"],"advisor_id":"feynman"}', 'df07d01bb24ab1710855bb380021a0612276dc31f22efd08ace03262fcd72a4f');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('feynman-c5', 'feynman', '《草包族科学》演讲（1974 加州理工毕业典礼）', '面对科研里普遍存在的''做了一切看似科学的动作、却得不到真知''现象（伪科学、不严谨实验、选择性报告）。', '用''草包族''比喻点破——形式齐全不等于实质有效；并提出科学诚信核心是''拼命找自己可能错在哪、并如实报告''。', '成为科研诚信经典文本，''你绝不能欺骗自己，而你又是最好骗的那个人''被广泛引用。', '判断一项工作/流程是真有效还是徒有其表，看它有没有''主动暴露自己缺陷''的机制；只有形式、没有自我证伪，就是草包族。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"feynman-c5","status":"published","title_period":"《草包族科学》演讲（1974 加州理工毕业典礼）","dilemma_constraints":"面对科研里普遍存在的''做了一切看似科学的动作、却得不到真知''现象（伪科学、不严谨实验、选择性报告）。","key_judgment":"用''草包族''比喻点破——形式齐全不等于实质有效；并提出科学诚信核心是''拼命找自己可能错在哪、并如实报告''。","model_invoked":["草包族判据"],"outcome":"成为科研诚信经典文本，''你绝不能欺骗自己，而你又是最好骗的那个人''被广泛引用。","transferable_lesson":"判断一项工作/流程是真有效还是徒有其表，看它有没有''主动暴露自己缺陷''的机制；只有形式、没有自我证伪，就是草包族。","source_tier":"primary","source_note":"出自 1974 加州理工毕业演讲原文（A）。","historicity":"confirmed","linked_cards":["feynman"],"tags":["认知偏误与理性决策","学习与认知"],"advisor_id":"feynman"}', 'b5a2b41cb67a74f47b95f2a91d3888541a2870b5b872eb48287abd8ba32c1afd');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('darwin-c1', 'darwin', '二十年迟疑与华莱士来信（1858-1859）', '他握着自然选择的想法近二十年迟迟不敢发表，深知它会冲击宗教与学界；又怕证据不够、怕争议。', '直到1858年华莱士独立寄来几乎相同的构想，逼他与华莱士联合发表，次年才出版《物种起源》。', '《物种起源》(1859)出版即售罄，奠定演化论；但也暴露其拖延几乎让他错失优先权。', '耐心攒证据是美德，但过度谨慎会变成拖延——有时是外部压力才逼你把成熟的东西拿出来。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"darwin-c1","status":"published","title_period":"二十年迟疑与华莱士来信（1858-1859）","dilemma_constraints":"他握着自然选择的想法近二十年迟迟不敢发表，深知它会冲击宗教与学界；又怕证据不够、怕争议。","key_judgment":"直到1858年华莱士独立寄来几乎相同的构想，逼他与华莱士联合发表，次年才出版《物种起源》。","model_invoked":["长期渐进累积"],"outcome":"《物种起源》(1859)出版即售罄，奠定演化论；但也暴露其拖延几乎让他错失优先权。","transferable_lesson":"耐心攒证据是美德，但过度谨慎会变成拖延——有时是外部压力才逼你把成熟的东西拿出来。","source_tier":"secondary","source_note":"华莱士来信、林奈学会联合宣读、1859出版均为确证史实（书信/传记，B）。","historicity":"confirmed","linked_cards":["darwin"],"tags":["长期规划","人生抉择"],"advisor_id":"darwin"}', '0585f785be5f4d77817c700b7418588249e9ff68c95b729a259fde97200fc389');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('darwin-c2', 'darwin', '金科玉律：立即记下反对自己的观察', '他发现自己总能记住支持理论的事实，却很快忘掉那些相悖的——记忆本身在帮他自欺。', '立下一条规矩：凡遇与结论相悖的观察，立刻动笔记下，绝不拖到事后（那时早忘了）。', '这条习惯让其论证罕见地经得起反例检验，成为其方法论中最被推崇的一点。', '对抗自我偏见最有效的不是更聪明，而是一条机械规矩：把反对你的证据第一时间固定下来。', 'primary', 'disputed', 'published', '{"schema_version":1,"case_id":"darwin-c2","status":"published","title_period":"金科玉律：立即记下反对自己的观察","dilemma_constraints":"他发现自己总能记住支持理论的事实，却很快忘掉那些相悖的——记忆本身在帮他自欺。","key_judgment":"立下一条规矩：凡遇与结论相悖的观察，立刻动笔记下，绝不拖到事后（那时早忘了）。","model_invoked":["反对意见优先记录"],"outcome":"这条习惯让其论证罕见地经得起反例检验，成为其方法论中最被推崇的一点。","transferable_lesson":"对抗自我偏见最有效的不是更聪明，而是一条机械规矩：把反对你的证据第一时间固定下来。","source_tier":"primary","source_note":"出自《达尔文自传》（A·自述）；按自述判例 historicity 记存疑，但该方法本身可独立验证其价值。","historicity":"disputed","linked_cards":["darwin"],"tags":["认知偏误与理性决策","修身自省"],"advisor_id":"darwin"}', '6eb9ed0e558a93dad9b652722457a5b36f1895c737eb5de1a496856b4faf8b41');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('darwin-c3', 'darwin', '《物种起源》专设''本学说之难点''章', '演化论面临一批尖锐反驳：像眼睛这样的复杂器官，怎么可能由渐变累积而来？', '他不回避，专辟一章把最难的反对意见摆上台面，逐一给出渐进路径的回应。', '这一坦诚处理反而增强了说服力，把批评者最想攻击的点先稳住。', '把你理论最致命的反驳自己先写出来、先回应，比等对手揭短更有力，也更可信。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"darwin-c3","status":"published","title_period":"《物种起源》专设''本学说之难点''章","dilemma_constraints":"演化论面临一批尖锐反驳：像眼睛这样的复杂器官，怎么可能由渐变累积而来？","key_judgment":"他不回避，专辟一章把最难的反对意见摆上台面，逐一给出渐进路径的回应。","model_invoked":["预先直面最强反例"],"outcome":"这一坦诚处理反而增强了说服力，把批评者最想攻击的点先稳住。","transferable_lesson":"把你理论最致命的反驳自己先写出来、先回应，比等对手揭短更有力，也更可信。","source_tier":"primary","source_note":"《物种起源》第6章原文（A），章节确证。","historicity":"confirmed","linked_cards":["darwin"],"tags":["认知偏误与理性决策","表达说服"],"advisor_id":"darwin"}', 'e10de9aa4e599d3362ceb6deff136adb0cb1f8f4a7f4fa02c3b40e9075d279c8');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('darwin-c4', 'darwin', '小猎犬号航行与物种地理变异（1831-1836）', '环球考察中他记录了大量地理变异（加拉帕戈斯的嘲鸫、龟、后经古尔德鉴定的地雀），但当时并未立刻悟出理论。', '靠长期积累这些''同类生物随地点系统变化''的观察，回国后逐步拼出变异-选择的图景。', '航行数据成为演化论的原始素材库；理论是事后多年慢慢成形，而非船上灵光一现。', '重大洞见常不是现场顿悟，而是把大量''看似零散的系统差异''攒够后才浮现——先存数据，别急着下结论。', 'secondary', 'disputed', 'published', '{"schema_version":1,"case_id":"darwin-c4","status":"published","title_period":"小猎犬号航行与物种地理变异（1831-1836）","dilemma_constraints":"环球考察中他记录了大量地理变异（加拉帕戈斯的嘲鸫、龟、后经古尔德鉴定的地雀），但当时并未立刻悟出理论。","key_judgment":"靠长期积累这些''同类生物随地点系统变化''的观察，回国后逐步拼出变异-选择的图景。","model_invoked":["变异-选择-时间"],"outcome":"航行数据成为演化论的原始素材库；理论是事后多年慢慢成形，而非船上灵光一现。","transferable_lesson":"重大洞见常不是现场顿悟，而是把大量''看似零散的系统差异''攒够后才浮现——先存数据，别急着下结论。","source_tier":"secondary","source_note":"航行与标本确证；但''在加拉帕戈斯即悟出演化''属后世神化叙事，''地雀''实由古尔德回国后鉴定——故个人顿悟叙事记存疑（学术分析，B）。","historicity":"disputed","linked_cards":["darwin"],"tags":["探索未知","认知偏误与理性决策"],"advisor_id":"darwin"}', 'f3e37cff86c09b9676fb024003ba0ed4ce29f98b1928c256971e3d63a749bf56');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('darwin-c5', 'darwin', '以家养选育类比自然选择（《物种起源》开篇）', '自然选择不可直接观测（太慢），如何让人信服这个看不见的机制真实存在？', '用人人熟悉的家鸽/家畜选育作类比桥梁：人能在几代间塑造物种，自然在漫长时间里同理可行。', '《物种起源》以''家养下的变异''开篇，用已知机制为陌生机制铺路，大幅降低读者接受门槛。', '要让人接受一个看不见的机制，先借一个他已熟悉、已验证的同类机制搭桥——但要诚实标出类比的边界。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"darwin-c5","status":"published","title_period":"以家养选育类比自然选择（《物种起源》开篇）","dilemma_constraints":"自然选择不可直接观测（太慢），如何让人信服这个看不见的机制真实存在？","key_judgment":"用人人熟悉的家鸽/家畜选育作类比桥梁：人能在几代间塑造物种，自然在漫长时间里同理可行。","model_invoked":["审慎类比迁移"],"outcome":"《物种起源》以''家养下的变异''开篇，用已知机制为陌生机制铺路，大幅降低读者接受门槛。","transferable_lesson":"要让人接受一个看不见的机制，先借一个他已熟悉、已验证的同类机制搭桥——但要诚实标出类比的边界。","source_tier":"primary","source_note":"《物种起源》第1章原文（A），确证。","historicity":"confirmed","linked_cards":["darwin"],"tags":["表达说服","创新研发"],"advisor_id":"darwin"}', '1e0825fdf96a0a6083f1268cf23413973eb144cba60bfce0143d268621e55f69');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('davinci-c1', 'davinci', '解剖人体的精确观察·极致观察（解剖手稿）', '如何真正理解人体（而非依赖古代典籍的成说）。', '达·芬奇亲自解剖了数十具人体，以极精确的直接观察画下肌肉、骨骼、器官，纠正了不少古代成说。', '达·芬奇的解剖手稿在精确性上远超时代，成为艺术与解剖学的瑰宝。', '别依赖书本、权威或想当然——以极细致的直接观察去研究对象的真实细节。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"davinci-c1","status":"published","title_period":"解剖人体的精确观察·极致观察（解剖手稿）","dilemma_constraints":"如何真正理解人体（而非依赖古代典籍的成说）。","key_judgment":"达·芬奇亲自解剖了数十具人体，以极精确的直接观察画下肌肉、骨骼、器官，纠正了不少古代成说。","model_invoked":["极致观察"],"outcome":"达·芬奇的解剖手稿在精确性上远超时代，成为艺术与解剖学的瑰宝。","transferable_lesson":"别依赖书本、权威或想当然——以极细致的直接观察去研究对象的真实细节。","source_tier":"primary","source_note":"达·芬奇解剖观察为其手稿所载→确证（一手A）。","historicity":"confirmed","linked_cards":["davinci"],"tags":["创新","认知偏误与理性决策"],"advisor_id":"davinci"}', '210f91dba54e570d9d34629fad1d846480cbee60bfd10b58e3f40e6e867601c6');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('davinci-c2', 'davinci', '集画家·解剖学家·工程师于一身·艺术与科学交融（其一生）', '艺术与科学、感性与理性，能否打通。', '达·芬奇打通艺术与科学——用解剖知识画更真实的人体、用对光影与自然的观察革新绘画、用工程之眼设计机械，在交叉处迸发创造。', '达·芬奇成为"文艺复兴人"的化身、跨界创造的典范。', '打通看似无关的领域，用一个领域的方法照亮另一个——最大的创造常在交叉处。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"davinci-c2","status":"published","title_period":"集画家·解剖学家·工程师于一身·艺术与科学交融（其一生）","dilemma_constraints":"艺术与科学、感性与理性，能否打通。","key_judgment":"达·芬奇打通艺术与科学——用解剖知识画更真实的人体、用对光影与自然的观察革新绘画、用工程之眼设计机械，在交叉处迸发创造。","model_invoked":["艺术与科学交融"],"outcome":"达·芬奇成为\"文艺复兴人\"的化身、跨界创造的典范。","transferable_lesson":"打通看似无关的领域，用一个领域的方法照亮另一个——最大的创造常在交叉处。","source_tier":"primary","source_note":"达·芬奇的跨界为史实→确证（一手/二手A/B）。","historicity":"confirmed","linked_cards":["davinci"],"tags":["创新","创作"],"advisor_id":"davinci"}', '7dae73e8d4e5ac57019e29f969d9b15d873d380b909c4dc7e9004b06475cc2ee');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('davinci-c3', 'davinci', '据鸟飞设计飞行器·类比自然找原理（飞行手稿）', '人能否飞行、如何设计飞行器。', '达·芬奇长期观察鸟类飞行，从自然的"设计"中类比、提取原理，设计了扑翼机、直升机雏形等飞行器构想。', '其飞行器构想受限于时代动力技术未能实现，但仿生思路极具前瞻性。', '遇难题先看自然怎么解决，从自然的"设计"中类比提取原理、迁移到你的发明。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"davinci-c3","status":"published","title_period":"据鸟飞设计飞行器·类比自然找原理（飞行手稿）","dilemma_constraints":"人能否飞行、如何设计飞行器。","key_judgment":"达·芬奇长期观察鸟类飞行，从自然的\"设计\"中类比、提取原理，设计了扑翼机、直升机雏形等飞行器构想。","model_invoked":["类比自然找原理"],"outcome":"其飞行器构想受限于时代动力技术未能实现，但仿生思路极具前瞻性。","transferable_lesson":"遇难题先看自然怎么解决，从自然的\"设计\"中类比提取原理、迁移到你的发明。","source_tier":"primary","source_note":"达·芬奇据鸟飞设计飞行器为其手稿所载→确证（一手A）。","historicity":"confirmed","linked_cards":["davinci"],"tags":["创新"],"advisor_id":"davinci"}', '9010f436d1c73fc3bd425c678d5646cac8332d52980108597a259b7a77bea0f2');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('davinci-c4', 'davinci', '海量手稿草图·手脑并用画以致知（其手稿）', '如何思考、推演复杂的结构、机械与自然。', '达·芬奇留下海量手稿，用精确的图画思考解剖、机械、水利、植物——画的过程本身就是他理解与设计的过程。', '达·芬奇的手稿成为人类思想史的瑰宝（虽生前多未发表）。', '把抽象想法精确地"画出来"，画的过程就是理解、推演与设计的过程。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"davinci-c4","status":"published","title_period":"海量手稿草图·手脑并用画以致知（其手稿）","dilemma_constraints":"如何思考、推演复杂的结构、机械与自然。","key_judgment":"达·芬奇留下海量手稿，用精确的图画思考解剖、机械、水利、植物——画的过程本身就是他理解与设计的过程。","model_invoked":["手脑并用·画以致知"],"outcome":"达·芬奇的手稿成为人类思想史的瑰宝（虽生前多未发表）。","transferable_lesson":"把抽象想法精确地\"画出来\"，画的过程就是理解、推演与设计的过程。","source_tier":"primary","source_note":"达·芬奇手稿为其遗存→确证（一手A）。","historicity":"confirmed","linked_cards":["davinci"],"tags":["创新","认知偏误与理性决策"],"advisor_id":"davinci"}', '9812a08005387f6d013ffbf32a898a98b8f115a36e846e542da7bf58cb597aa3');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('maxwell-c1', 'maxwell', '一组方程统一电磁光·用数学统一看似无关的现象（《电磁通论》1873）', '电、磁、光此前被当作三种不同的现象分别研究。', '麦克斯韦以一组方程揭示电与磁是同一事物的两面、且光是一种电磁波，把三者统一在同一套底层规律下。', '麦克斯韦方程组是经典物理的巅峰之一，统一了电磁光。', '把看似无关的现象用一套统一框架揭示为同一规律的不同表现——统一比罗列更有力。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"maxwell-c1","status":"published","title_period":"一组方程统一电磁光·用数学统一看似无关的现象（《电磁通论》1873）","dilemma_constraints":"电、磁、光此前被当作三种不同的现象分别研究。","key_judgment":"麦克斯韦以一组方程揭示电与磁是同一事物的两面、且光是一种电磁波，把三者统一在同一套底层规律下。","model_invoked":["用数学统一看似无关的现象"],"outcome":"麦克斯韦方程组是经典物理的巅峰之一，统一了电磁光。","transferable_lesson":"把看似无关的现象用一套统一框架揭示为同一规律的不同表现——统一比罗列更有力。","source_tier":"primary","source_note":"麦克斯韦方程组统一电磁光为物理学史→确证（一手A）。","historicity":"confirmed","linked_cards":["maxwell"],"tags":["创新","认知偏误与理性决策"],"advisor_id":"maxwell"}', 'd7ce9e93926c0bf00bf0a12e67df1e870b8fdae6478a089fab52d211156f7282');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('maxwell-c2', 'maxwell', '把法拉第的"场"数学化·把直觉图像翻译成精确数学（1860s）', '法拉第的"力线/场"是深刻的物理直觉，但缺乏数学形式。', '麦克斯韦把法拉第的直觉图像翻译成一组精确、可计算、可推演的数学方程，严格化并大大拓展了它。', '直觉与数学的结合，催生了完整的电磁理论。', '把停留在直觉的洞察翻译成精确、可计算的语言——直觉提供方向，形式化赋予力量。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"maxwell-c2","status":"published","title_period":"把法拉第的\"场\"数学化·把直觉图像翻译成精确数学（1860s）","dilemma_constraints":"法拉第的\"力线/场\"是深刻的物理直觉，但缺乏数学形式。","key_judgment":"麦克斯韦把法拉第的直觉图像翻译成一组精确、可计算、可推演的数学方程，严格化并大大拓展了它。","model_invoked":["把直觉图像翻译成精确数学"],"outcome":"直觉与数学的结合，催生了完整的电磁理论。","transferable_lesson":"把停留在直觉的洞察翻译成精确、可计算的语言——直觉提供方向，形式化赋予力量。","source_tier":"primary","source_note":"麦克斯韦把法拉第场论数学化为物理学史→确证（一手/二手A/B）。","historicity":"confirmed","linked_cards":["maxwell"],"tags":["创新","认知偏误与理性决策"],"advisor_id":"maxwell"}', '5c205b53e20d8dfbae78e2578b309271fa818a720d567618581fdb162d29734a');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('maxwell-c3', 'maxwell', '由方程预言电磁波·由方程预言未知（1860s—70s）', '理论能否预言尚未被观察到的全新现象。', '麦克斯韦相信方程的内在逻辑，从中推出"电磁波"的存在、并算出其速度等于光速（预言光是电磁波），后由赫兹实验证实。', '电磁波的预言与证实是理论预言力量的经典范例，催生了无线电等。', '相信好方程的内在逻辑，从它推出未观察的预言再验证——理论能预言未知。', 'primary', 'confirmed', 'published', '{"schema_version":1,"case_id":"maxwell-c3","status":"published","title_period":"由方程预言电磁波·由方程预言未知（1860s—70s）","dilemma_constraints":"理论能否预言尚未被观察到的全新现象。","key_judgment":"麦克斯韦相信方程的内在逻辑，从中推出\"电磁波\"的存在、并算出其速度等于光速（预言光是电磁波），后由赫兹实验证实。","model_invoked":["由方程预言未知"],"outcome":"电磁波的预言与证实是理论预言力量的经典范例，催生了无线电等。","transferable_lesson":"相信好方程的内在逻辑，从它推出未观察的预言再验证——理论能预言未知。","source_tier":"primary","source_note":"麦克斯韦预言电磁波、后被赫兹证实为物理学史→确证（一手/二手A/B）。","historicity":"confirmed","linked_cards":["maxwell"],"tags":["创新","认知偏误与理性决策"],"advisor_id":"maxwell"}', '178a19bd0e3a3bf0313f9ea638e86b3ac4517df6a62cb3fa80c3b5bb3b253af4');
INSERT INTO advisor_cases (case_id, advisor_id, title_period, dilemma_constraints, key_judgment, outcome, transferable_lesson, source_tier, historicity, status, case_json, content_sha256) VALUES ('maxwell-c4', 'maxwell', '以"场"简洁把握电磁·抓住本质建简洁模型（其理论）', '如何把复杂的电磁现象简洁普适地把握。', '麦克斯韦以"场"这一简洁、普适的概念把握电磁，而非纠缠于具体的机械以太模型（最终超越了机械模型）。', '「场」成为现代物理的核心概念之一。', '从复杂中抓住本质、建简洁普适的模型，别纠缠机械的临时细节。', 'secondary', 'confirmed', 'published', '{"schema_version":1,"case_id":"maxwell-c4","status":"published","title_period":"以\"场\"简洁把握电磁·抓住本质建简洁模型（其理论）","dilemma_constraints":"如何把复杂的电磁现象简洁普适地把握。","key_judgment":"麦克斯韦以\"场\"这一简洁、普适的概念把握电磁，而非纠缠于具体的机械以太模型（最终超越了机械模型）。","model_invoked":["抓住本质建简洁模型"],"outcome":"「场」成为现代物理的核心概念之一。","transferable_lesson":"从复杂中抓住本质、建简洁普适的模型，别纠缠机械的临时细节。","source_tier":"secondary","source_note":"麦克斯韦的场概念为物理学史→确证（二手B）。","historicity":"confirmed","linked_cards":["maxwell"],"tags":["创新"],"advisor_id":"maxwell"}', '28154d1829fb83091c695a86e24dd7a2d47918be32926b3a52caeeee3e7d179d');
